INSERT INTO schema_migrations VALUES(3,1782613056);
INSERT INTO books VALUES('635722','史蒂夫·乔布斯传（修订版）','沃尔特·艾萨克森','https://cdn.weread.qq.com/weread/cover/39/YueWen_635722/t9_YueWen_635722.jpg',unistr('    史蒂夫·乔布斯有如过山车般精彩的人生和炽热激越的性格成就了一个传奇，一个极具创造力的企业领袖，他追求完美和誓不罢休的激情使个人电脑、动画电影、音乐、手机、平板电脑以及数字出版等六大产业发生了颠覆性变革。2011年，《史蒂夫·乔布斯传》出版；在两年后的今天，我们又推出了修订版。在原有《乔布斯传》的基础上，修订了全部译文，采纳了读者对翻译的众多建议，使得整体译文更加完善，更加精良。此外，修订版一大亮点是新增补作者亲自撰写的后记，描述了乔布斯去世后的相关过程，包括葬礼等，对读者有新的吸引点，也更完美了此部经典著作。\u000a'),'经济理财-商业','2014-03-01 00:00:00',2,557,0,559,100,4,1,1705869444,1705869444,917.0,7796,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300037073','战斗细胞：人体免疫系统奇妙之旅','菲利普·德特玛','https://cdn.weread.qq.com/weread/cover/41/cpPlatform_2JdoEuiGc1YWxtkxq67Dyo/t9_cpPlatform_2JdoEuiGc1YWxtkxq67Dyo.jpg','既直观、轻松，又精准、实用，还不乏时尚、极客的气息，这就是本书呈现给你“免疫”知识的方式。它以故事性的讲解和风格鲜明的插图，描述人体的免疫机制、免疫系统的各组成部分、各类细胞及重要蛋白（抗体、MHC、细胞因子等），与人有关的各种微生物（包括益生菌和各种病原体），以及多方的相互作用，介绍自愈、发炎、流行病、抗菌、抗病毒、寄生虫、过敏、疫苗、癌症、自身免疫性疾病等种种健康议题，帮你过上更为轻松安泰、胸有成竹的现代人生。','医学健康-医学','2022-09-01 00:00:00',0,447,0,447,97,4,1,1714302534,1714302534,936.0,3036,NULL,'海南出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('CB_4S997B96qGVz6al6YD','邓小平时代','傅高义','https://res.weread.qq.com/wrepub/CB_2MWC9UC9NDE46Qu6Px_parsecover',NULL,NULL,'',0,384,0,384,91,4,1,1672127449,1672127449,NULL,NULL,NULL,NULL,NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300039741','高效的无效：行家如何投资与市场如何定价','拉瑟·海耶·佩德森','https://cdn.weread.qq.com/weread/cover/96/cpPlatform_wYodV7Yd3Fhnvjh5h6Hd2h/t9_cpPlatform_wYodV7Yd3Fhnvjh5h6Hd2h.jpg','本书描述了对冲基金的关键交易策略，揭开了主动型投资的神秘面纱。作者将最新的研究成果与现实世界的经典案例以及对顶级对冲基金经理的采访相结合，展示了某些交易策略是如何盈利的，以及为什么有时会亏损。 作者认为市场既非完全高效，也非完全无效，相反，市场的无效足以让基金经理通过交易策略获取利润来补偿其成本，而市场的高效带来的利润不会鼓励额外的积极投资。了解如何在低效的市场中进行交易，为学习金融学提供了一种新的、引人入胜的方法。 本书深入探讨了几个不同的领域：投资管理的基本工具、股票投资策略、宏观投资策略和套利策略，并研究了投资组合选择、风险管理、股票估值和收益曲线逻辑等不同的主题。书中通过对知名对冲基金经理的采访进一步阐释了各类投资方法，他们包括李·安斯利三世、詹姆斯·查诺斯、克利夫·阿斯尼斯、戴维·哈丁、肯·格里芬、戴维·哈丁、约翰·A.保尔森、迈伦·斯科尔斯和乔治·索罗斯。','经济理财-财经','2021-05-31 00:00:00',0,297,0,297,54,2,1,1690966513,1690966513,717.0,43,NULL,'中国人民大学出版社有限公司',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300022098','聪明人的个人成长','史蒂夫·帕弗利纳','https://cdn.weread.qq.com/weread/cover/98/3300022098/t9_3300022098.jpg','本书作者史蒂夫是全球个人成长领域的知名导师，在全球150多个国家及地区拥有读者。本书第一部分介绍个人成长的七个原则，分别是：真实、爱、能量、一体、主导、勇气、清醒自主。在本书第二部分，介绍如何将这七个原则运用在生活中的各个方面，包括习惯、职业、金钱、健康、关系以及心灵。本书不仅让你拥有成长的系统理论，还带你切实解决人生遇到的很多重大问题。','个人成长-励志成长','2022-05-01 00:00:00',6,283,0,289,100,4,1,1708738932,1708738932,812.0,2670,NULL,'机械工业出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('27256052','人生十二法则：直面混乱与痛苦','乔丹·彼得森','https://cdn.weread.qq.com/weread/cover/47/YueWen_27256052/t9_YueWen_27256052.jpg','2018-2019年全球现象级畅销书，长踞52国畅销书排行榜，全球销量超300万册。作者是当今世界最重要的思想家之一，演讲视频累计播放量超过1亿次。读懂十二条法则，解决人生80%的不如意。我对任何事都提不起兴趣怎么办？我处于人生的至暗时刻怎么办？上班让我不快乐怎么办？面对人生中的混乱迷茫，我们真正需要的，不是虚伪的励志、空洞的安慰，而是严父近乎残酷的苛责教诲。在引爆全球的现象级畅销书《人生十二法则》中，著名心理学家乔丹·彼得森将人类数千年来的哲学思考、神话故事中的精神财富与心理学、生物学、神经科学等学科的前沿研究相结合，用12条最基本的人生法则，为我们找到摆脱人生困境的方法。科学作家万维钢老师说：“彼得森这些建议我完全赞同，我希望我儿子长大以后读读彼得森这本书。','心理-积极心理学','2019-11-22 00:00:00',2,281,0,283,85,3,1,1687669760,1687669760,765.0,9003,NULL,'浙江人民出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br','埃隆·马斯克传','【美】沃尔特·艾萨克森','https://res.weread.qq.com/wrepub/CB_1Pi80U81ABef6j76khDGtD5I_parsecover',NULL,NULL,'',0,270,0,270,77,1,1,1713101439,1713101439,NULL,NULL,NULL,'中信出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('42689053','原则：应对变化中的世界秩序','瑞·达利欧','https://cdn.weread.qq.com/weread/cover/53/YueWen_42689053/t9_YueWen_42689053.jpg','自然界的发展是有规律的，而任何事物都按其固有的轨迹运行。人们能够用一定的方法去认识它、体验它、并按照客观规律改造它。从《原则》《债务危机》到《原则：应对变化中的世界秩序》，桥水投资公司创始人瑞·达利欧的研究角度涉及个体、组织、社会和世界。他想揭示的是个体的生活和工作原则、组织机构的运转原则、国家和社会的兴衰原则、世界秩序的变化原则。在这本书中，瑞·达利欧探究的是社会和世界的运行规律和原则，他考察了500年财富和权力的所有重大变化背后反复出现的模式和因果关系。他认为在这些变化背后存在着永恒普适的规律。通过考察许多相互关联的历史事件，可以看到这些变化的典型模式、规律、周期和因果关系，并以此为基础推断未来。达利欧认为，历史通常也是通过相对明确的生命周期、随着一代人向下一代人的过渡而逐步演进的。目前相对财富、权力和世界秩序正在发生典型的巨变，这将对所有国家的每个人都产生深远的影响……这本书的分析和探究建立在达利欧独创的债务大周期、历史大周期的基础之上，揭示的是变化背后的永恒和普遍的力量，以此展望未来，搞清世界的运行原理，总结出永恒普适的原则，从而妥善地应对当前形势。','经济理财-财经','2022-01-01 00:00:00',3,263,0,266,94,3,1,1674129209,1674129209,885.0,5021,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('907574','杂食者的两难','迈克尔·波伦','https://wfqqreader-1252317822.image.myqcloud.com/cover/574/907574/t9_907574.jpg',unistr('作为美国饮食界的引领者，迈克尔·波伦长期关注饮食议题，企图在工业社会与田园自然中寻求调和。在本书中，他以田园调查的方式走访农场、研发室、牧场、食品加工厂和超市，从产地一路追踪到餐桌，如侦探般地揭开现代食品的面貌，追寻现代饮食如何成为人类疾病的来源，给出了杂食者“到底要吃什么”的答案。\u000a'),'生活百科-美食','2017-05-01 00:00:00',0,261,0,261,54,2,1,1678015581,1678015581,768.0,777,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300095033','别对企鹅发火','[美]盖比·卡普','https://cdn.weread.qq.com/weread/cover/76/cpplatform_kppbxavyxwidksjunc481a/t9_cpplatform_kppbxavyxwidksjunc481a1712890394.jpg',unistr('在冲突中剔除情绪就能处理好冲突！帮助你控制自己的情绪，马上成为人际高手高手高高手！轻松又好读\u000a冲突发生时，有的人保持沉默，为了避免矛盾放弃自己的立场；有的人情绪上头，不管对错，就是要吵个你输我赢。本书提供了如何处理冲突的系统性方法，助你控制自己的情绪，处理好冲突：\u000a方法一：别对企鹅发火\u000a企鹅有翅膀，但它不会飞。因为企鹅不会飞而生气是没有用的。我们都有一些比别人进化得慢的领域，你不必为此生气。接受他人本来的样子，包括各种缺点和局限，我们就能掌握主动权，减少冲突。\u000a方法二：使用购物清单语气\u000a在说话时只陈述事实，不要激动、不带情绪、语气平和，就像你让朋友到商店帮你买东西一样。这样你就能专注于传达信息，对方也能够接受你的反馈并理解信息。\u000a方法三：学会倾听\u000a让人感到自己被倾听，是成功化解一切冲突的关键。比对方更准确地重述他们的观点，一旦对方感觉自己被理解了，他们也就能理解你的立场。'),'个人成长-沟通表达','2024-04-01 00:00:00',2,232,0,234,95,2,1,1720067115,1720067115,836.0,191,NULL,'北京日报出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300046899','自在','李筱懿','https://cdn.weread.qq.com/weread/cover/43/cpplatform_sdkytozqkrmkshq3hg87no/t9_cpplatform_sdkytozqkrmkshq3hg87no1674095553.jpg','“自在”是什么？ 那是喜欢自己、找到自己之后特有的样子，是从迷茫到清晰，Z终确信自我存在感与价值感，在自己感兴趣、认为重要和有意义的事情上有所成就的样子。 但，“自在”，并不是一种容易达到的状态。它需要努力，也需要方法、技巧和智慧。不解决现实问题，人很难获得自在。 当李筱懿将过往许多年里，自己经历过的事，对自己有帮助的那些观念、思考、方法，娓娓道来，并整理成一套简单明了的生活哲学和方法论时，她希望，在好读的同时，也能让你充满获得感，有所启发，走向自在与幸福。 这本书并没有长篇大论，内容涵盖作者关于个人成长、职场、社交、沟通、表达、情绪掌控、亲密关系等诸多方面的思考，是她多年来总结并实践的一套方法，希望能够借此帮助读者习得生活的一些智慧，摆脱焦虑，做到不畏、不惑、不乱、不后悔，悠然自在。','个人成长-情绪心灵','2022-12-20 00:00:00',0,228,0,228,100,4,1,1675819951,1675819951,887.0,3204,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('35138325','冯唐成事心法','冯唐','https://cdn.weread.qq.com/weread/cover/22/YueWen_35138325/t9_YueWen_35138325.jpg','他是热爱文艺的管理专家，是精通麦肯锡与曾国藩成事学的商业领袖，是医学博士出身的投资人。10年麦肯锡战略规划经验，5年华润医疗集团创始心得，5年中信资本投资管理启示——冯唐20年持续跨界成事经验，凝结成这本《冯唐成事心法》。冯唐说：“我将自己二十年职业管理生涯中吃过的苦、踩过的雷、翻过的山、见识过的人，总结为‘冯唐成事心法’。”以西方麦肯锡管理方法为经，以中国经典成事智慧为纬，融合冯唐20年职场亲身实践的经验，以冯唐独特观点+方法语录提炼+丰富运用场景+经验案例+实战方法为内容框架，助你在现实中修行，在工作中求法，在沟通中识人，在思考中升级。写给每一个想干事、能干事、持续成大事的人。','经济理财-管理','2020-12-01 00:00:00',0,222,0,222,64,2,1,1703304829,1703304829,793.0,8571,NULL,'北京联合出版公司',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('316675','人性的弱点（大全集）','卡耐基','https://wfqqreader-1252317822.image.myqcloud.com/cover/675/316675/t9_316675.jpg','美国“成人教育之父”戴尔·卡耐基所著的《人性的弱点大全集》，汇集了卡耐基的思想精华和最激动人心的内容，是作者最成功的励志经典，书的唯一目的就是帮助解决所面临的最大问题：如何在日常生活、商务活动与社会交往中与人打交道，并有效地影响他人；如何击败人类的生存之敌——忧虑，以创造一种幸福美好的人生。','个人成长-沟通表达','2010-11-01 00:00:00',2,198,0,200,44,2,1,1675144473,1675144473,830.0,1789,NULL,'立信会计出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('23934823','非对称风险','纳西姆·尼古拉斯·塔勒布','https://wfqqreader-1252317822.image.myqcloud.com/cover/823/23934823/t9_23934823.jpg','约3800年前，《汉谟拉比法典》就向我们传达出一条人类进化的法则——在人与人的交往中建立对称关系，以防止有人转嫁隐藏的“尾部风险”。古往今来，人类的任何一条法律、任何一项教谕，也都是基于“对称性”原则的，但实际上，非对称风险也一直存在于人类历史之中。塔勒布提出，人们在面对非对称风险和外部压力时，只有践行“风险共担”的原则，才能做出正确的决策，以应对现实世界中的不确定性。《非对称风险》这本书共包含四个主题：不确定性以及知识的可靠性；人类事务的对称性原则，包括公平、正义、责任感、相互性；交易中的信息共享；复杂系统中以及在现实世界中的理性。书中的内容可谓是包罗万象：主观动机分析、二手车买卖、道德伦理、契约理论、学术界以及现实世界的学习、康德法则、政府权力、风险科学、知识分子与现实世界的互动、政府责任、社会正义、期权理论、基本人权、狗屎的供应商、神学……','经济理财-财经','2019-01-01 00:00:00',0,188,0,188,92,4,1,1666092309,1666092309,772.0,3446,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('32764984','社会性动物（第12版）','艾略特·阿伦森 乔舒亚·阿伦森','https://wfqqreader-1252317822.image.myqcloud.com/cover/984/32764984/t9_32764984.jpg','社会影响无处不在。我们是如何受到影响的？为什么我们要接受信息，或者换句话说，信息对我们有什么好处？什么样的社会动机使我们容易受到他人的想法、言论和行为的影响？哪些因素会增加或减少社会信息的有效性？哪些因素增加或减少了社会影响力的持久性？一个人是怎样喜欢上另外一个人的？是否通过同样的心理过程，我们选择了普通麦片而不是即食麦片？一个人如何对某个民族、某种宗教或种族群体产生偏见？偏见与喜欢类似？还是恰恰相反，涉及一套完全不同的心理过程？许多人会对诸如此类的问题感兴趣。因为我们都花费了大量的时间与其他人交流——受他人的影响；影响他人；高兴、开心、悲伤、厌恶、沮丧，或者被激怒——我们的天性就是对人们为什么做他们所做的事情提出假设。从这个意义上说，我们每个人都是业余的社会心理学家。尽管大多数业余社会心理学家在与他人互动时会对这些假设进行检验，并达到他们自己的满意程度，但这些偶然的“检验”缺乏细致的科学研究所具有的严谨性和公正性。','心理-心理学研究','2020-05-01 00:00:00',0,176,0,176,26,2,1,1708759050,1708759050,835.0,4236,NULL,'华东师范大学出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('22947638','传习录','[明]王阳明','https://wfqqreader-1252317822.image.myqcloud.com/cover/638/22947638/t9_22947638.jpg','《传习录》是王阳明的问答语录和论学书信集，集中而系统地阐释了阳明心学：心即理、致良知、知行合一的内涵，是一部简明而有代表性的古典哲学著作。它所阐述的修身、养心、处世之道对于现代生活依然有巨大的指导意义，可以说，这是一本充满实践性的生活哲学读本。','哲学宗教-东方哲学','2018-07-01 00:00:00',0,172,0,172,60,2,1,1672283288,1672283288,838.0,306,NULL,'三秦出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300026077','月光落在左手上','余秀华','https://cdn.weread.qq.com/weread/cover/31/cpPlatform_fuLnt2noEFmgyyRQvN8d3a/t9_cpPlatform_fuLnt2noEFmgyyRQvN8d3a.jpg',unistr('本书是余秀华的代表作《月光落在左手上》的全新精装版。《月光落在左手上》2015年出版后获得了众多读者的青睐，这种现象级热销，在诗歌领域引发了一次小浪潮。本次精装版中收录了诗人的140余首作品，包括十余首新作，另收入了记录诗人生活和创作环境的全彩图片。\u000d\u000a本书呈现了诗人对爱情、亲情、日复一日的生活的感悟，带有村庄、土地的朴实气息，混合了女性丰富、敏锐的情感神经。如果你是带着好奇去读余秀华的诗，继而便会被她诗中展现出来的奔放、丰盈、纯净的内心世界席卷，无从抗拒。在现实中，她被贴上“农妇”“诗人”“脑瘫患者”的重重标签，但在诗歌中，她可以抛开这些，尽情倾吐对自由的向往，对于爱情的渴望。就如她所说，“诗歌是什么呢，我不知道，也说不出来，不过是情绪在跳跃，或沉潜。不过是当心灵发出呼唤的时候，它以赤子的姿势到来，不过是一个人摇摇晃晃地在摇摇晃晃的人间走动的时候，它充当了一根拐杖。”'),'文学-现代诗歌','2020-09-01 00:00:00',16,168,0,184,95,4,0,1723525772,1723525772,889.0,3660,NULL,'北京出版集团北京十月文艺出版社',NULL,NULL,1782398781,1);
INSERT INTO books VALUES('651358','中国哲学简史','冯友兰','https://cdn.weread.qq.com/weread/cover/24/YueWen_651358/t9_YueWen_651358.jpg','《中国哲学简史》打通古今中外的相关知识，以宏观开阔的视野对中国哲学进行了深入浅出的、融会贯通的讲解。在有限的篇幅里融入了对中国传统思想、文化、精神、智慧等方面的理解，融会了史与思的智慧结晶，洋溢着人生的智慧与哲人的洞见，寄托着现实的人生关怀。它在世界各地有多种译本，拥有众多的读者，是许多大学中国哲学的通用教材；同样，它也是广大读者学习中国古代文化、借鉴中国传统智慧、启迪现实人生的入门书。它是一部名副其实的可以影响大众一生的文化经典。本书是北京大学出版社独家拥有版权的冯友兰先生亲自指导翻译并认可的唯一版本。','哲学宗教-东方哲学','2013-01-01 00:00:00',0,162,1,163,99,4,1,1659879734,1659879734,888.0,10735,NULL,'北京大学出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300091899','CMake构建实战：项目开发卷','许宏旭','https://cdn.weread.qq.com/weread/cover/21/cpplatform_hgrvh6q168ggeaz5up338a/t9_cpplatform_hgrvh6q168ggeaz5up338a1711450092.jpg','本书主要介绍C和C++程序构建的相关知识，包括直接调用C和C++编译器完成构建的基础内容，以及使用CMake完成项目构建的相关内容。全书先介绍市面上C和C++的主流编译器及其相关命令行工具、Makefile等的使用，抽象出与项目构建相关的概念模型，再介绍CMake脚本语言的基础语法、常用命令等，最后介绍与CMake项目构建相关的内容。本书含有两个实践章节，借助CMake脚本语言，分别构建了快速排序算法程序、手写数字识别库及配套命令行工具。 本书适合有C和C++编程基础，希望了解或应用CMake工具的人阅读，也适合想要构建跨平台C和C++程序的开发人员阅读。','计算机-计算机综合','2024-02-01 00:00:00',2,158,0,160,22,2,1,1728143477,1728143477,744.0,25,NULL,'人民邮电出版社有限公司',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300105051','世界海权博弈史','观雨者','https://cdn.weread.qq.com/weread/cover/10/cpplatform_guhvuxwtjkmbbqebvxhgim/t9_cpplatform_guhvuxwtjkmbbqebvxhgim1720514098.jpg','本书讲述了大航海时代以来海上强国的海权博弈史，以及由此带来的世界格局和国际秩序的演变。对于影响巨大的著名海战，本书详细讲解了当时的时代背景、国际形势、武器装备、战略战术、战斗过程，既波澜壮阔又充满细节，让人身临其境，回味无穷。','历史-世界史','2024-07-17 00:00:00',1,143,0,144,100,4,1,1725456329,1725456329,892.0,1763,NULL,NULL,NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300020372','锻炼','[美]丹尼尔·利伯曼','https://cdn.weread.qq.com/weread/cover/80/cpPlatform_3tKaC95Z1mL61tPJbbGW2F/t9_cpPlatform_3tKaC95Z1mL61tPJbbGW2F.jpg',unistr('我们是为休息而生，还是为跑而生？\u000a跑步会毁了你的膝盖吗?\u000a哪种运动项目蕞适合我？\u000a懒惰是不正常的行为吗？\u000a每晚都需要睡够8个小时吗？\u000a我们可以跑得又快又远吗？\u000a体育等于锻炼吗？\u000a在不算太遥远的过去，我们那些狩猎采集者、农耕者祖先，为了获得足够的食物，每天需要进行数小时的身体活动，偶尔也会为了娱乐或者社交而做游戏或者跳舞，但没人会为了健康而奔跑或者行走几千米。锻炼只是人类进化过程中近期才出现的现象。哈佛大学进化生物学家丹尼尔·利伯曼凭借自己多年在世界各地的研究与经验，向我们讲述为什么我们从未进化出锻炼的本能。\u000a在这本打破神话的书中，利伯曼告诉我们，锻炼，并不是人类的本能。利伯曼从人类学和进化学的角度探讨了我们的身体，破解了关于锻炼的12个谬误，教我们可以正确地对待自己的身体并进行正确的身体活动，帮助那些对锻炼感到焦虑、困惑和纠结的人们把锻炼重新放到正确的位置上。'),'生活百科-体育','2022-06-01 00:00:00',2,129,0,131,26,2,1,1709978421,1709978421,831.0,2060,NULL,'天津科学技术出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('921791','随机漫步的傻瓜','纳西姆·尼古拉斯·塔勒布','https://cdn.weread.qq.com/weread/cover/31/YueWen_921791/t9_YueWen_921791.jpg','塔勒布在《随机漫步的傻瓜》中指出：你的成功不见得是因为比其他人高明，而很可能是运气的结果。《随机漫步的傻瓜》以深刻独到的视角，告诉你这个随机世界的规律和运行方式。随机性虽然无法避免，但我们可以学着接受它。就像在投资市场上，如果一个小概率事件可以带来巨额回报，为什么不在这个事件上持续下注呢？换一种思维方式，做“随机漫步的傻瓜”，我们对人生的了解无疑将大为增进。','经济理财-财经','2012-06-01 00:00:00',0,120,0,120,100,4,1,1664254297,1664254297,731.0,7036,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('33915626','爱的八次约会','约翰·戈特曼 朱莉·施瓦茨·戈特曼 瑞秋·卡尔顿·艾布拉姆斯 道格·艾布拉姆斯','https://cdn.weread.qq.com/weread/cover/61/YueWen_33915626/t9_YueWen_33915626.jpg','我们常听到“相爱容易，相处难”，这话可能道尽不少伴侣的心声，因为，就算两人承诺“我愿意”或者同床共枕，并不代表你真的了解另一半。那么，爱情真的是一场掷硬币的冒险吗？美国婚姻权威约翰·戈特曼博士从多年的临床研究观察到，很少有夫妻或情侣得到指引，学习营造出幸福的生活，这些伴侣们在热恋期后，常常不知道如何对谈、沟通、发问，遇到磨合跟冲突时常常只是越演越烈，最后不得不寻求婚姻治疗师协助。因此，戈特曼博士透过多年的研究，首先找出伴侣生活中最常发生困难和冲突的8个领域：信任、冲突、性爱、金钱、家庭、玩乐与冒险、心灵成长、梦想。接着，戈特曼博士以八个主题，设计八场亲密的约会，每一场约会代表了一种对话的邀请。在特别安排的约会气氛，两人能够建立亲密的交谈，让伴侣与你分享他内心真正的想法。这样的对话让你明白他的信念、行为、想法背后的原因。为何不能好好谈话，还要约会？一场不被小孩、责任、家务打扰的约会才能让谈话深入，需要被了解。每一场约会章节的最后都有约会安排，具体提出这一个主题约会的细节营造，让你们的重要谈话不无聊，不再是争吵、而是一场关系变得更紧密的约会。我们希望八场约会中，你能学到:→99种说出欣赏对方的方式→认识彼此差异的25种问题→了解对方的金钱观→原生家庭如何影响对方金钱观→亲密对话的4种技巧→容易瓦解信任感的4件事→如何一起追求人生乐趣→如何能在安全的状态下说出彼此的性爱观→如何一起在心灵上成长→如何在争吵之后修补关系→梦想对彼此的重要性→关于冲突、性爱、玩乐、金钱观的迷思。','生活百科-情感','2020-09-14 00:00:00',1,119,3,123,99,4,0,1738247092,1738247092,837.0,1811,NULL,'北京日报出版社',NULL,NULL,1782398781,1);
INSERT INTO books VALUES('30179184','操作系统导论','雷姆兹·H.阿帕希杜塞尔 安德莉亚·C.阿帕希杜塞尔','https://cdn.weread.qq.com/weread/cover/71/YueWen_30179184/t9_YueWen_30179184.jpg','这是一本关于现代操作系统的书。全书围绕虚拟化、并发和持久性这3个主要概念展开，介绍了所有现代系统的主要组件（包括调度、虚拟内存管理、磁盘和I/O子系统、文件系统 ）。 本书共50章，分为3个部分，分别讲述虚拟化、并发和持久性的相关内容。本书大部分章节均先提出特定的问题，然后通过书中介绍的技术、算法和思想来解决这些问题。笔者以对话形式引入所介绍的主题概念，行文诙谐幽默却又鞭辟入里，力求帮助读者理解操作系统中虚拟化、并发和持久性的原理。 本书内容全面，并给出了真实可运行的代码（而非伪代码），还提供了相应的练习，适合高等院校相关专业教师教学和高校学生自学。','计算机-计算机综合','2019-06-01 00:00:00',0,98,0,98,10,2,1,1708085848,1708085848,905.0,902,NULL,'人民邮电出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('837618','自控力','凯利·麦格尼格尔','https://cdn.weread.qq.com/weread/cover/9/YueWen_837618/t9_YueWen_837618.jpg','《自控力》是斯坦福大学最受欢迎心理学课程。作者麦格尼格尔教授吸收了心理学、神经学和经济学等学科的最新洞见，为斯坦福大学继续教育项目开设了一门叫做“意志力科学”的课程，参与过这门课程的人称其能够“改变一生”。这门课程就是《自控力》一书的基础。','心理-心理学应用','2012-08-01 00:00:00',0,97,9,106,95,4,1,1657381867,1657381867,813.0,24638,NULL,'印刷工业出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('22791651','《金刚经》说什么','南怀瑾','https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/t9_YueWen_22791651.jpg','本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。','哲学宗教-宗教','2016-04-01 00:00:00',0,89,0,89,44,2,1,1780417937,1780417937,908.0,9762,NULL,'东方出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('837932','穷查理宝典：查理·芒格智慧箴言录（全新增订本）','彼得·考夫曼','https://cdn.weread.qq.com/weread/cover/48/YueWen_837932/t9_YueWen_837932.jpg','他是巴菲特的导师与人生合伙人，他是当今最伟大的投资思想家，他是伯克希尔·哈撒韦51年间19.2%年复合增长率的奇迹缔造者。理解商业社会和投资本质，必读这本书！本书全面收录了查理·芒格的个人传记与投资哲学，以及过去20年来芒格主要的公开演讲和媒体访谈，是每一个投资者不可不读的必备工具书。查理·芒格在商业社会取得了巨大的成功，他的独特思维方式，他对商业伦理的“洁癖”，他对终身学习的强调，可以给我们每一个普通人带来启迪。','个人成长-励志成长','2021-07-01 00:00:00',0,89,0,89,48,2,1,1747100126,1747100126,843.0,29109,NULL,'中信出版集团',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('694341','期权、期货及其他衍生产品（原书第9版）','[加]约翰·赫尔','https://cdn.weread.qq.com/weread/cover/43/YueWen_694341/t9_YueWen_694341.jpg',unistr('本书被誉为金融衍生产品领域的“圣经”。本书对金融衍生品市场中期权与期货的基本理论进行了系统阐述，提供了大量业界事例，主要讲述了期货市场的运作机制、采用期货的对冲策略、远期及期货价格的确定、期权市场运作过程、雇员股票期权的性质、期权交易策略以及信用衍生产品、布莱克-斯科尔斯-默顿模型、希腊值及其运用等。本书与时俱进，书中更新了大量经济数据，带来了最新的市场信息，还特意针对证券化和始于2007年的信用危机展开论述。\u000d\u000a《期权、期货及其他衍生产品(原书第9版)》可作为高等院校经济、金融相关专业教学用书，也可作为金融机构管理者，特别是期权、期货从业人员的参考用书。'),'经济理财-理财','2014-11-01 00:00:00',0,82,0,82,52,2,1,1691475744,1691475744,845.0,182,NULL,'机械工业出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('45369847','打开心智','李睿秋','https://cdn.weread.qq.com/weread/cover/27/YueWen_24434684401178106/t9_YueWen_24434684401178106.jpg','心智，是我们对外部世界的认知和思维方式的集合，决定了人的信念、思考和行动。成长的本质，就是不断用新的认知打破旧的认知，重塑自己的心智模式。深度思考践行者李睿秋，带你探索心智的底层原理，搭建一套行之有效的成长系统，提供情绪、自驱、行动、学习、思考、创造六个方面的提升路径，从而获得更明晰的头脑，更平静的心态和更有主动权的人生——停止精神内耗，应对生活的不确定性和疲惫。走出信息茧房，拥有自主学习力。把自律变成自驱。果断行动，摆脱懒惰、畏难和拖延。构建知识地图，打造终身受用的学习系统。找到个人兴趣所在与立身之本。','个人成长-认知思维','2022-09-01 00:00:00',1,76,0,77,45,2,1,1754124801,1754124801,890.0,4621,NULL,'中信出版集团',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300060305','非暴力沟通（修订版）','马歇尔·卢森堡','https://cdn.weread.qq.com/weread/cover/88/cpplatform_9iwmvppcbjd1kqabdkbe1e/t9_cpplatform_9iwmvppcbjd1kqabdkbe1e1685513342.jpg','马歇尔•卢森堡博士发现了一种沟通方式，依照它来谈话和聆听，能使人们情意相通，和谐相处，这就是“非暴力沟通”。做为一个遵纪守法的好人，也许我们从来没有把谈话和“暴力”扯上关系。不过如果稍微留意一下现实生活中的谈话方式，并且用心体会各种谈话方式给我们的不同感受，我们一定会发现，有些话确实伤人！言语上的指责、嘲讽、否定、说教以及任意打断、拒不回应、随意出口的评价和结论给我们带来的情感和精神上的创伤甚至比肉体的伤害更加令人痛苦。这些无心或有意的语言暴力让人与人变得冷漠、隔膜、敌视。非暴力沟通能够：疗愈内心深处的隐秘伤痛;超越个人心智和情感的局限性;突破那些引发愤怒、沮丧、焦虑等负面情绪的思维方式;用不带伤害的方式化解人际间的冲突;学会建立和谐的生命体验。','心理-心理学应用','2021-05-01 00:00:00',0,73,0,73,52,3,1,1713795671,1713795671,826.0,30022,NULL,'华夏出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('CB_AzO97m9AzGVz6al6YD','李敖电子书大全集[34本合集]','李敖','https://res.weread.qq.com/wrepub/CB_DJz8rL8tq4q56RB6Pw_parsecover',NULL,NULL,'',0,71,0,71,27,1,1,1665156561,1665156561,NULL,NULL,NULL,'epub掌上书苑',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300056625','我笨拙地爱着这个世界（“外卖诗人”王计兵自选集）','王计兵','https://cdn.weread.qq.com/weread/cover/28/cpplatform_3gvqc8yprlbx2wyvepzdwj/t9_cpplatform_3gvqc8yprlbx2wyvepzdwj1682074936.jpg','《我笨拙地爱着这个世界》收录了王计兵亲选的130首诗作。他写生活的困顿、对父母的追忆、对故乡的怀念。质朴平实的文字迸发出惊人的力量。每个身处困境的人，都应该读一读王计兵。','文学-现代诗歌','2023-04-01 00:00:00',0,7,0,7,5,2,1,1719552270,1719552270,876.0,963,NULL,'江苏凤凰文艺出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('25926815','瓦尔登湖（译文经典）','梭罗','https://cdn.weread.qq.com/weread/cover/34/YueWen_25926815/t9_YueWen_25926815.jpg','这是一本宁静、恬淡、充满智慧的书。其中分析生活，批判习俗处，语语惊人，字字闪光，见解独特，耐人寻味。许多篇页是形象描绘，优美细致，像湖水的纯洁透明，像山林的茂密翠绿；也有一些篇页说理透彻，十分精辟。给人启迪。这是一本清新、健康、引人向上的书，对于春天，对于黎明，都有极其动人的描写。这里有大自然给人的澄净的空气，而无工业社会带来的环境污染。读着它，读者自然会感觉到心灵的纯净，精神的升华。','文学-散文杂著','2014-12-01 00:00:00',0,68,0,68,29,2,1,1671595992,1671595992,770.0,320,NULL,'上海译文出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300007102','曾医生让你早知道','普外科曾医生','https://cdn.weread.qq.com/weread/cover/71/cpPlatform_3300007102/t9_cpPlatform_3300007102.jpg','你也许听过这样的健康谣言——  吃大蒜可以杀灭幽门螺杆菌；  爱吃糖容易得糖尿病；  苦瓜能祛湿气；  生病了多喝粥，养胃；  …………  你可能对这些医学常识很陌生——  失温时应该如何自救？  胆囊息肉不做手术会癌变吗？　  癌症都是静悄悄的，警惕这四个标志；  乳房疼痛是乳腺癌吗？其实不疼更可怕；  身体出现“红痣”是肝病的标志吗？  …………  身体健康很重要，不要等生病了才重视健康！  因为缺乏健康常识，人们对伤害自己健康的生活方式不自知，也常常因无法分辨健康谣言而成为受害者。 作为医学博士、普外科主治医师，曾医生决定通过趣味视频和通俗易懂的文字，传播硬核科普，让没有医学知识背景的普通读者也能听懂、看懂。 书中通过饮食禁忌、身体养护、恶性病症、医学常识、健康疑难5大核心内容，讲述75个健康真相，结合生动的插图，让读者易学易懂。早点知道健康隐患和危害，就多一份健康保障。  一本守护全家人健康的实用指南  75个健康真相，破除谣言，远离恶性病症','医学健康-健康','2021-11-01 00:00:00',0,66,0,66,90,4,1,1654529493,1654529493,772.0,1230,NULL,'湖南科学技术出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('25615385','被讨厌的勇气：“自我启发之父”阿德勒的哲学课','岸见一郎 古贺史健','https://wfqqreader-1252317822.image.myqcloud.com/cover/385/25615385/t9_25615385.jpg','一名深陷自卑、无能与不幸福的青年，听到了一名哲人主张的“世界无比单纯，人人都能幸福”便来挑战，两人展开了你来我往的思考和辩论，在一夜一夜过去后，青年开始思考，为什么“所谓的自由，就是被别人讨厌”？问题不在于世界是什么样子，在于你是什么样子。','心理-积极心理学','2017-05-01 00:00:00',3,65,0,68,100,4,1,1595489067,1595489067,868.0,167397,NULL,'机械工业出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('40055543','置身事内：中国政府与经济发展','兰小欢','https://cdn.weread.qq.com/weread/cover/52/YueWen_40055543/t9_YueWen_40055543.jpg','本书是复旦大学经济学院教授兰小欢多年教学与研究内容的凝练，将经济学原理与中国经济发展的实践有机融合，以地方政府投融资为主线，深入浅出地论述了中国经济的发展，广泛采纳各领域学者全新研究成果。全书分上下两篇。上篇解释微观机制，包括地方政府的基本事务、收支、土地融资和开发、投资和债务等；下篇解释这些微观行为与宏观现象的联系，包括城市化和工业化、房价、地区差异、债务风险、国内经济结构失衡、国际贸易冲突等。最后一章通过对中国政治经济体系的论述，作者简明地刻画了地方政府进行经济治理的基本方式，指出中国政府通过深度介入工业化和城市化的进程，在发展经济的同时逐步推动了市场机制的建立和完善。','经济理财-财经','2021-08-01 00:00:00',0,65,0,65,75,2,1,1653221388,1653221388,941.0,56715,NULL,'上海人民出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300064086','与塞涅卡共进早餐：斯多葛哲学的人生艺术','大卫·菲德勒','https://cdn.weread.qq.com/weread/cover/38/cpplatform_hixys3ymuudfmfkqvn6ata/t9_cpplatform_hixys3ymuudfmfkqvn6ata1689243634.jpg',unistr('当人生陷入困境，不妨问一句：哲学家塞涅卡会怎么做？\u000a如何处理和时间的关系\u000a如何克服担忧和焦虑\u000a如何战胜困境\u000a如何在困难和极端财富中生存\u000a如何保持真实并为社会做贡献\u000a给悲伤留一席之地 \u000a斯多葛主义是两千多年前古罗马时期最有影响力的哲学。斯多葛哲学崇尚理性，注重培养人的内在品格，以应对外部世界的不确定性。古罗马政治家、哲学家塞涅卡被认为是斯多葛学派最有才华、最人性化的作家，他教导人们自由而有目的地生活。他历久弥新的作品，是一百多封写给朋友的书信《斯多葛主义者来信》，阐述了如何应对逆境，如何克服悲伤、焦虑和愤怒，如何将挫折转化为成长机会，如何认识友谊的真正本质等重要人生议题。\u000a《与塞涅卡共进早餐》是第一本介绍塞涅卡哲学思想全貌的指南。在这本书中，大卫·菲德勒结合当代人的生活，深入阐释了塞涅卡的哲学思想对当下人生的重要指导作用。事实证明，在过去的两千多年里，人类本性并没有发生太大变化，针对我们今天面临的各种人生困境，斯多葛哲学依然能提供历经时间考验的实用建议。塞涅卡的哲学智慧并非遥不可及，它像每天早晨一杯提神的咖啡，可以融入生活作为一种日常仪式去享受。\u000a我为后代工作，写下一些可能对他们有益的想法。有一些健康的建议，此刻我正在把它们写下来，就像开处方列出有用的药……我正在为其他人指出正确的道路，它们是我因误入歧途而在晚年感到疲惫时才发现的。\u000a——【古罗马】塞涅卡\u000a塞涅卡的时代就是我们的时代。他是我们的同时代人，我们关切着同样的问题。\u000a——大卫·菲德勒'),'哲学宗教-西方哲学','2022-11-01 00:00:00',1,61,0,62,39,2,1,1773811343,1773811343,866.0,640,NULL,'上海社会科学院出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('277781','看见','柴静','https://cdn.weread.qq.com/weread/cover/94/YueWen_277781/t9_YueWen_277781.jpg','柴静十年成长的个人告白，中国社会变迁的备忘。央视知性美女主持柴静首度出书，讲述十年央视生涯。从对新闻一无所知的新人，尝遍失败、迷茫、摔打的滋味，到如今成为央视最受欢迎的女记者和主持人，柴静从未停止反思和追问，柴静说：“你想如何报道一个国家，就要如何报道自己。” 《看见》告诉你柴静何以成为柴静，她经历过什么，思考着什么，又记下了什么。','文学-散文杂著','2013-01-01 00:00:00',1,58,0,59,50,3,1,1730219036,1730219036,864.0,73160,NULL,'广西师范大学出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('29971966','硅谷之火：个人计算机的诞生与衰落（第3版）','迈克尔·斯韦因  保罗·弗赖伯格','https://wfqqreader-1252317822.image.myqcloud.com/cover/966/29971966/t9_29971966.jpg','本书是一部微型计算机发展史，让读者了解整个20世纪以及至21世纪初计算机从兴起到鼎盛直至今天受到平板电脑和手机等电子产品冲击的整个过程，是一本集历史故事与小说风格于一体的硅谷纪传体书籍。最新第3版重新修订了全书内容，增加了计算机发展史上的几位大佬退出舞台后的计算机行业现状分析。','计算机-计算机综合','2019-10-30 00:00:00',1,58,0,59,81,2,1,1739675538,1739675538,823.0,663,NULL,'人民邮电出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300072235','癌症病人怎么吃？（译文科学）','王兴','https://cdn.weread.qq.com/weread/cover/53/cpplatform_wm3aekn4fhyzqdkod8n16s/t9_cpplatform_wm3aekn4fhyzqdkod8n16s1695698283.jpg',unistr('上海三甲医院医生，为中国癌症病人量身定做的饮食指导。\u000b作者王兴从事科普工作多年，是头条、知乎签约作者，拥有众多粉丝，长期受邀担任中央电视台《健康之路》节目明星演示嘉宾。陶勇、罗翔、郑兴东、庞颖、梁文道、刘润联袂推荐！\u000b要做手术，平时吃的药还吃不吃？喝汤真的能大补吗？化疗吃不下东西怎么办？化疗时吃什么才能不脱发？镇痛药会影响伤口愈合吗？怎么吃才能不得癌？\u000d\u000a《癌症病人怎么吃？》希望解决两个问题：怎么吃能少得癌？得了癌应该怎么吃？\u000d\u000a我国每年有450万新发癌症病人，“怎么吃”，是我们在对抗癌症路上最重要的一件事情。不科学的传统饮食观念和民间的谣言使很多患者明明治疗得很成功，却因为饮食出现各种状况。《癌症病人怎么吃？》是上海第一人民医院胸外科主治医生王兴为中国的癌症病人量身定做的饮食指导，它用通俗的语言、真实的病例，帮助癌症病人及家人“吃”过这段晦暗的时光。一日三餐，请好好吃饭！'),'医学健康-健康','2023-09-01 00:00:00',0,56,0,56,68,2,1,1758994719,1758994719,900.0,115,NULL,'上海译文出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('43685146','轻松主义：让关键的事情变得容易做','[美]格雷戈·麦吉沃恩','https://cdn.weread.qq.com/weread/cover/11/YueWen_43685146/t9_YueWen_43685146.jpg','你是否觉得自己：想做出更大的贡献，但缺乏精力？跑得更快了，但没有更接近自己的目标？面对职场内卷，在崩溃的边缘摇摇欲坠？生活中只剩关键的事，时间还是不够用？那么，《轻松主义》就是你的救星！《精要主义》教我们如何摒弃琐碎，直抵精要，只做最重要的事，而《轻松主义》探讨了在摒弃不必要之事后，如何让关键的事变得容易做。全书共分为三个部分，一步步带我们找回轻松状态，采取轻松行动，获得轻松成果。做事太用力不一定是好事，关键是要用好巧劲儿找准节奏。你要更聪明地工作，而不只是更努力地工作，以轻松的状态，轻松的行动，走出轻松人生。','个人成长-人生哲学','2022-03-01 00:00:00',3,55,0,58,35,2,1,1728264078,1728264078,759.0,1398,NULL,'中国财政经济出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('834467','在细雨中呼喊','余华','https://cdn.weread.qq.com/weread/cover/4/yuewen_834467/t9_yuewen_8344671758542700.jpg',unistr('小说以一个孩子的视角讲述了一个家庭的欢乐和苦痛，细腻地刻画了柔弱的母亲如何完成了自己忍受的一生，她唯一爆发出来的愤怒是在弥留之际；名叫孙广财的父亲又是如何骄傲地将自己培养成一名彻头彻尾的无赖，他对待自己的父亲和对待自己的儿子，就像对待自己的绊脚石；家中三兄弟的道路只是短暂地有过重叠，随即就又叉向了各自的方向。无赖的父亲、沉默的母亲、平庸的哥哥、对往事沾沾自喜的祖父……每个不起眼的小人物，都卖力于自己的人生表演。而“我”则在这一出出家庭闹剧中孤独地成长，像小动物一样观察世界，试探同类，艰难地理解家庭、爱和生命的含义。\u000d\u000a叙述者在过去、现在和将来这三个时间维度里自由穿行，将忆记的碎片穿插、结集、拼嵌完整，精妙无比，文学的光芒闪耀四射。这是一部少年心灵成长史，也是一代人的集体记忆。'),'精品小说-社会小说','2023-07-01 00:00:00',0,17,0,17,100,4,1,1664430302,1664430302,861.0,42193,NULL,'北京出版集团北京十月文艺出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300081421','现代C++编程：从入门到实践','乔什·洛斯皮诺索','https://cdn.weread.qq.com/weread/cover/40/cpplatform_4jz9t3fajnqxnbc7igwvfd/t9_cpplatform_4jz9t3fajnqxnbc7igwvfd1702459511.jpg','本书是为中高级程序员设计的，它深入介绍了现代C++的核心。本书分为两大部分：第一部分介绍C++语言的核心，深入讲解从类型和函数到对象生命周期和表达式的所有内容；第二部分介绍C++标准库和Boost库，深入讲解所有可用的高质量、全功能的工具，涵盖了特殊的工具类、数据结构和算法，并介绍了如何操作文件系统和构建通过网络进行通信的高性能程序。本书包含500多个代码样本和近100个练习，可以让你打下坚实的C++基础，助你写出让自己引以为傲的可读性较高、短小精悍且高效的代码。','计算机-编程设计','2023-09-15 00:00:00',0,50,0,50,41,2,1,1754219380,1754219380,658.0,29,NULL,'机械工业出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('852290','未来简史：从智人到智神','尤瓦尔·赫拉利','https://cdn.weread.qq.com/weread/cover/44/YueWen_852290/t9_YueWen_852290.jpg','进入21世纪后，曾经长期威胁人类生存、发展的饥荒和战争基本被攻克，智人面临着新的待办议题：永生不老、幸福快乐和成为具有“神性”的人类。在解决这些新问题的过程中，科学技术的发展将颠覆我们很多当下认为无需佐证的“常识”，比如人文主义所推崇的自由意志将面临严峻挑战，机器将会代替人类做出更明智的选择。 更重要的，当以大数据、人工智能为代表的科学技术发展的日益成熟，人类将面临着从进化到智人以来*的一次改变，绝大部分人将沦为“无价值的群体”，只有少部分人能进化成特质发生改变的“神人”。 未来，人类将面临着三大问题：生物本身就是算法，生命是不断处理数据的过程；意识与智能的分离；拥有大数据积累的外部环境将比我们自己更了解自己。如何看待这三大问题，以及如何采取应对措施，将直接影响着人类未来的发展。','社会文化-社科','2017-01-10 00:00:00',0,47,0,47,100,4,1,1592928859,1592928859,834.0,29071,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('25672236','青年变革者：梁启超（1873—1898）','许知远','https://wfqqreader-1252317822.image.myqcloud.com/cover/236/25672236/t9_25672236.jpg','《青年变革者：梁启超（1873—1898）》是许知远积淀多年的转型之作。梁启超生逢变革时代，他是近代转型的积极参与者，同时又是中国现代思想学术的拓荒者和奠基人。许知远试图将这位伟大人物的思想与性格、希望与挫败，内心挣扎及与同代人的争辩呈现给读者。在搜集、阅读海量史料和研究著作的同时，许知远追寻梁启超的足迹，到其出生地新会、求学地广州，及北京、上海、日本横滨等多地探访历史现场，寻求历史与现实之间隐秘而有韧性的关联，借此展现几代人的焦灼与渴望、勇气与怯懦……','历史-中国近现代','2019-05-01 00:00:00',1,46,0,47,26,2,1,1689736544,1689736544,733.0,888,NULL,'上海人民出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300116432','重塑杏仁核：情绪修复脑科学','[美]凯瑟琳·M. 皮特曼','https://cdn.weread.qq.com/weread/cover/75/cpplatform_f8nqyjadruqecj4euuj6jj/t9_cpplatform_f8nqyjadruqecj4euuj6jj1727434091.jpg',unistr('本书通过追溯焦虑的根源一杏仁核，探讨\u000a了如何有效地管理焦虑。通过设定目标、了解\u000a焦虑产生的两种途径、学习杏仁核的语言以及\u000a以睡眠、运动和饮食等方式调节杏仁核的活\u000a动，读者可以学会控制焦虑。此外，书中还介\u000a绍了如何通过暴露疗法训练杏仁核，以及识别\u000a那些可能激活杏仁核的想法。重新训练你的大\u000a脑，有效地管理焦虑，不仅可以提高生活质\u000a量，还能让我们在面对困难时更加从容，重新\u000a掌握生活的主导权。'),'心理-心理学研究','2024-06-01 00:00:00',2,45,0,47,75,2,1,1769852944,1769852944,844.0,930,NULL,'中国科学技术出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('38395237','认识世界：古代与中世纪哲学','理查德·大卫·普莱希特','https://wfqqreader-1252317822.image.myqcloud.com/cover/237/38395237/t9_38395237.jpg','从西方哲学的发源地美丽的小亚细亚海岸，一直到中世纪后期的修道院和书斋、教堂和大学，一代代著名哲学家轮番登上历史舞台，对世界、对自我、对生活进行着探寻与思考。本书德国当红哲学家普莱希特，专门为大众读者所写的哲学史第一卷，如连载小说一般，将一位位哲学家带到我们眼前，将他们的哲学思考融入故事之中，在轻松的阅读中，帮助我们理解与我们生活密切相关的问题：“什么是好的生活？什么是真理？是否有正义？如果有，它如何可能？生命是否有意义？人在自然和宇宙中居于何种地位？”','哲学宗教-哲学读物','2021-04-01 00:00:00',0,45,0,45,6,2,1,1717187928,1717187928,884.0,95,NULL,'上海人民出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('914697','了凡四训','[明]袁了凡','https://cdn.weread.qq.com/weread/cover/28/YueWen_914697/t9_YueWen_914697.jpg',unistr('    本书由《金刚经修心课》作者费勇教授精心翻译并作序。曾国藩、胡适、稻盛和夫提倡阅读的生活方式手册。明代思想家袁了凡留给子孙的家训，以毕生学识、经历与感悟为根基，谆谆讲授“我命由我不由天”的道理。行善事、得善果——以入世心劝人向善、谋求磊落的生活，堪为一部历久弥新的生活方式手册。\u000a'),'哲学宗教-东方哲学','2017-07-01 00:00:00',0,44,0,44,77,3,1,1696779085,1696779085,809.0,14408,NULL,'三秦出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300177660','专注的真相','李笑来','https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/t9_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg',unistr('中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\u000d\u000a有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。'),'个人成长-励志成长','2024-11-01 00:00:00',0,42,0,42,99,4,1,1782050992,1782050992,834.0,831,NULL,'广东经济出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300070786','好好恋爱','安德鲁·G.马歇尔','https://cdn.weread.qq.com/weread/cover/28/cpplatform_babpsysxq2zbaaviepxxgy/t9_cpplatform_babpsysxq2zbaaviepxxgy1694159377.jpg',unistr('单身生活，熟悉可控；爱情，不是一个人说了算，你选哪一个？\u000a爱对方多一点，还是被爱多一点？\u000a要独立自由，还是有人依恋？\u000a老套的选择题不好选。\u000a趋利避害人之天性，原生家庭的影响，旧恋情的伤口，让我们面对喜欢的人，想好好爱却总彼此伤害。\u000a婚恋专家安德鲁·G.马歇尔带你面对隐秘的心灵创伤，看到自己最想要的，整合心理资源，唤醒爱的智慧与能力，留住值得爱的TA，不再错过幸福！'),'生活百科-情感','2023-01-01 00:00:00',0,32,0,32,100,4,1,1696759321,1696759321,666.0,370,NULL,'中信出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('44000669','梁永安：阅读、游历和爱情','梁永安','https://wfqqreader-1252317822.image.myqcloud.com/cover/669/44000669/t9_44000669.jpg','为什么我们活得那么累？为什么我们越来越茫然？为什么我们甚至开始不知道“我是谁”？我们被指责内卷，又被指责躺平；我们被贩卖孤独，又被推销爱情；我们被推向对立，又被斥为无情……于是有人问，这代年轻人怎么了？可是，我们也想问，我们应该怎样“正确”地生活、自由地生活？年轻是属于阅读、游历和爱情的。复旦大学中文系教授、宝藏老师梁永安在《梁永安：阅读、游历和爱情》中如是说——我对年轻人有两个建议：一，要保持对世界的好奇心；二，要走出自我舒适区，在新的东西里寻找人生。现近代以来，爱情最大的要素就是女性的变化，而很多男性没有跟上女性的思想转变。现在很多年轻人的自由时间被剥夺了，整天“996”，两性之间自然没有很宽松的体验。复旦大学教授梁永安老师从爱情、工作、自我、修养、孤独、社交、人格、艺术、女性文化等具体十五个主题切入当下青年群体的时代症候，期望与青年人一起突破对问题的单一认知，找到新的理解方式，体会到生活的无限可能与多元价值。跟随梁永安，在不确定的时代，做确定的自己。','文学-散文杂著','2022-06-01 00:00:00',0,40,0,40,49,2,1,1662209117,1662209117,814.0,7349,NULL,'北京时代华文书局',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('534286','轻断食：正在横扫全球的瘦身革命','麦克尔·莫斯利 咪咪·史宾赛','https://cdn.weread.qq.com/weread/cover/46/YueWen_534286/t9_YueWen_534286.jpg','轻断食横扫世界各大榜单，畅销美国、英国、日本、法国、意大利……轻断食正在改变全世界！远远不只让你瘦，更获得心灵的自由！翻开本书，立刻开始轻断食，回归自然饮食，从此改变生命！轻断食只是要你回归超自然的饮食状态：每周5天正常饮食，只需2天稍加控制，就能坐享减肥奇迹！轻断食不仅改变饮食习惯，也改造你的心智，比减肥意义更大，变成你的生活方式。轻断食帮你健康瘦身、改善情绪、完善身体状态。轻断食正从根本上改变人们的生命体验。中文版出版五年来，长期位居各大生活类书籍榜单前列。中国大陆指定授权正版。BBC科学纪录片震撼报道。轻断食要求我们不要只思考自己的饮食，也思考摄取的时机。没有复杂的规矩要遵守。做法有弹性，简单明了，执行容易。不用天天跟热量搏斗，完全没有一般节食计划的无趣与挫败，也不会破坏生活的品质。','医学健康-健康','2019-05-01 00:00:00',0,40,0,40,68,2,1,1657897314,1657897314,657.0,11575,NULL,'文汇出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('35666063','3小时快学期权（第二版）','上海证券交易所产品创新中心','https://cdn.weread.qq.com/weread/cover/77/YueWen_35666063/t9_YueWen_35666063.jpg','本书结合了上交所产品创新中心部门数位期权培训讲师多年来丰富的讲课经验，并在传统的培训材料上化繁入简，凝练成“期权交易之独孤九剑”和“期权活用七字诀”，寓教于乐，方便读者记忆和掌握期权知识。第二版在原有的基础上，增加了2019年期权产品新上线的组合保证金和组合行权两大业务的相关知识，同时将增加期权新品种沪深300ETF期权的相关内容，并更新了相关的案例。','经济理财-财经','2020-06-04 00:00:00',0,39,1,40,55,2,1,1654577766,1654577766,850.0,392,NULL,'格致出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('37462156','做一个清醒的现代人','刘擎','https://wfqqreader-1252317822.image.myqcloud.com/cover/156/37462156/t9_37462156.jpg','在当代中国传统文化的纵向传承与外来文化的横向互动中，在这种“纵横交错”的文化背景下，刘擎教授通过发人深省的文字启发我们以理性化的方式来探索世界和自己，思考“人应当信奉什么”“应当怎样生活”“如何理解和应对困境”等诸多问题。这部作品兼具敏锐的历史意识与深切的现实关怀。刘擎教授结合历史、文化、政治、哲学等众多元素，解读社会发展变化、思想的演进，以求大众在面对这个时代时，能够辨析问题与观念的来龙去脉，澄清我们的处境与自我理解，重建对未来的想象。','文学-散文杂著','2021-04-01 00:00:00',0,39,0,39,24,2,1,1661614115,1661614115,754.0,1513,NULL,'湖南文艺出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('29373667','技术的本质（经典版）','布莱恩·阿瑟','https://cdn.weread.qq.com/weread/cover/31/YueWen_29373667/t9_YueWen_29373667.jpg','《技术的本质》（经典版）是布莱恩·阿瑟所创建的一套关于技术产生和进化的系统性理论。本书是打开“技术黑箱”的钥匙，它用平实的语言将技术本质的思想娓娓道来。构建了关于技术的理论体系，阐明了技术的本质及其进化机制。技术思想领域的开创性作品。','科学技术-自然科学','2018-06-07 00:00:00',0,38,0,38,15,2,1,1722753321,1722753321,737.0,895,NULL,'浙江人民出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300151958','王阳明心学入门三步走（全三册）','度阴山','https://cdn.weread.qq.com/weread/cover/76/cpplatform_nkcjju6fvrdgeurscrqqr5/t9_cpplatform_nkcjju6fvrdgeurscrqqr51752030599.jpg',unistr('想要零基础入门王阳明心学，其实就分三步：\u000a第一步：读传记。通过了解王阳明传奇的一生，获得对阳明心学的实感；\u000a第二步：破心贼。学习心即理、知行合一、致良知3大修炼法门，破焦虑、破欲望、破犹豫；\u000a第三步：学原典。学习王阳明毕生所学精华《传习录》，掌握原汁原味的心学智慧。\u000a每一步都是百万级畅销书作者度阴山带着学习，没有晦涩的理论，全是大白话，一读就懂，一点就通。\u000a由浅入深领悟心学智慧，釜底抽薪解决人生困境。'),'哲学宗教-东方哲学','2025-06-01 00:00:00',0,38,0,38,42,2,1,1764641742,1764641742,840.0,893,NULL,'江苏凤凰文艺出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('25449864','人人都懂设计模式：从生活中领悟设计模式（Python实现）','罗伟富','https://cdn.weread.qq.com/weread/cover/68/YueWen_25449864/t9_YueWen_25449864.jpg','设计模式（Design Pattern）是一套被反复使用、多数人知晓、无数工程师实践的代码设计经验的总结，它是面向对象思想的高度提炼和模板化。 本书带你一起从生活的角度思考设计模式，以轻松有趣的小故事开始，由浅入深地讲解每一种模式，思考每一种模式，总结每一种模式！力求用更通俗的语言阐述难懂的概念，用更简单的语法实现复杂的逻辑，用更短小的代码写出强悍的程序！ 使枯燥乏味的概念变得更有乐趣和意义，希望能带给读者一种全新的阅读体验和思考方式。 本书首先讲解了23种经典设计模式，其中19 种在现今的软件开发中常用的设计模式分别用单独的章节进行了详细讲解，剩余设计模式作为一个合集放在一章中进行了讲解；其次讲解了对基础设计模式的衍生，也是各大编程语言中非常重要而常见的各种编程机制，如过滤器模式、对象池技术、回调机制和MVC模式；最后作者结合自身的工作经验和项目积累，分享了他对设计模式、设计原则、项目重构的理解和看法。Python作为AI时代最重要的一种计算机语言，其在各大语言中的排名也逐年上升！本书所有示例代码均用Python编写，将会是国内不可多得的一本用Python来讲解设计模式的书。 本书适合的读者：一线互联网软件开发者、有一定编程基础的IT新人、对设计模式和编程思想感兴趣的人士。','计算机-编程设计','2019-04-01 00:00:00',0,37,0,37,68,2,1,1768024047,1768024047,756.0,156,NULL,'电子工业出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300011992','习惯逃避：你在害怕什么（回避型人格自救手册。拖延、讨好、自卑、社恐的背后，不过是一颗习惯逃避的灵魂。）','李国翠','https://cdn.weread.qq.com/weread/cover/92/3300011992/t9_3300011992.jpg','你是不是这样的人： 每份工作都觉得不满，寄希望于“跳槽改变人生”，于是不停地换工作，可麻烦始终如影随形  总有人把你的善良当成懦弱，把你的慈悲当成迟钝，你却只是默默忍受，还安慰自己宽容可贵  遇到挫折，总以为换个环境，就能让一切变得顺利起来，可挫折总在下一个路口悄悄等着自己…… 习惯逃避的你，必须明白一个道理：麻烦不会因为你暂时逃避而凭空消失，只有学会刻意面对，你才能打开彻底明亮的人生。 本书从“逃避心理”的角度入手，找出我们在生活中习惯逃避的原因，让受困于逃避心理的人们，重拾自信，找到直面人生的勇气。','心理-认知与行为','2020-10-01 00:00:00',0,36,0,36,31,2,1,1693059384,1693059384,737.0,2149,NULL,'天地出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300020163','我的阿勒泰（马伊琍、周依然、于适主演同名电视剧原著）','李娟','https://cdn.weread.qq.com/weread/cover/31/cpplatform_fy7wyg2acrhxq1vu4yvs9y/t9_cpplatform_fy7wyg2acrhxq1vu4yvs9y1714307419.jpg','偏远寂静的阿克哈拉村，缓慢而永恒的喀吾图，沙依横布拉克的夏牧场……“阿勒泰的精灵”李娟以细腻明亮的笔触全景式记录北疆边地美好闪光的时刻。全书分为两辑。第一辑记忆之中（2007-2009），记录了在喀吾图和阿克哈拉村细碎坚忍的生活画面；第二辑角落之中（2002-2006），原生态书写了李娟和母亲及高龄的外婆随牧民迁徙、流动的日常：开杂货铺，当小裁缝，帮往来的牧民车衣裙，去大山深处采野生木耳；春天沙依恒布拉克草原上鼓胀的帐篷，夏季牧场上喧嚣盛大的阿肯弹唱会，入冬后瓷实的迢迢雪路……戈壁、草原、森林、雪山、骏马和牧人，细腻明亮的文字展现了游牧民族在边地深远丰富的生存景观。','精品小说-影视原著','2021-08-01 00:00:00',0,36,0,36,17,2,1,1714544008,1714544008,889.0,35638,NULL,'花城出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('932498','存在主义咖啡馆：自由、存在和杏子鸡尾酒','莎拉·贝克韦尔','https://wfqqreader-1252317822.image.myqcloud.com/cover/498/932498/t9_932498.jpg','巴黎，1933年。三位朋友正坐在蒙帕纳斯大道上的煤气灯酒吧里喝杏子鸡尾酒。其中一个叫雷蒙·阿隆的年轻哲学家，正在向同为哲学家的让-保罗·萨特和西蒙娜·德·波伏娃盛赞一种他在德国发现的新鲜哲学——现象学。就这样，20世纪影响最广泛深远的哲学运动发端了。受到启发的萨特，将现象学与他法式的人文主义情感结合在一起，创立了一门全新的哲学思想——现代存在主义。作者将历史、传记与哲学结合在一起，以史诗般恢弘的视角，激情地讲述了一个充满了斗争、爱情、反抗与背叛的存在主义故事，深入探讨了在今天这个纷争不断、技术驱动的世界里，当我们每个人再次面对有关绝对自由、全球责任与人类真实性的问题时，曾经也受过它们困扰的存在主义者能告诉我们什么。','哲学宗教-哲学读物','2017-12-01 00:00:00',0,36,0,36,4,2,1,1702905829,1702905829,844.0,3082,NULL,'北京联合出版公司',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('32042419','原则：绘本版(汉英对照)','瑞·达利欧','https://wfqqreader-1252317822.image.myqcloud.com/cover/419/32042419/t9_32042419.jpg','时代在经历剧变，没有人能准确预测未来是什么样的，需要什么样的技能和知识。身为父母，就更焦虑于应该如何培养孩子为未来做好准备。 美国桥水投资公司创始人、对冲基金投资人瑞·达利欧，基于自己的生活和工作经历而撰写《原则》一书，仅在中国大陆就畅销超过160万册。他将这本书改编为《原则（绘本版）》，以轻松的形式、平等的姿态，与孩子畅谈人生、成功、成长。他提出的“头脑开放”“进化”“真相是什么”“拥抱现实”等从另一个角度，引领孩子独立思考、虚心接纳不同意见、享受失败、寻找同伴等，从而赋予孩子更大格局、更高视野，以原则拓宽孩子的人生边界，无惧未来挑战。','教育学习-育儿','2020-06-01 00:00:00',0,35,0,35,74,4,1,1673703187,1673703187,768.0,848,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300056202','职场高效阅读：成为高手的实用阅读秘籍','朱晓华','https://cdn.weread.qq.com/weread/cover/13/cpplatform_hkemkz36grotzjcayeklw5/t9_cpplatform_hkemkz36grotzjcayeklw51681897025.jpg',unistr('在不进则退的职场, 读书是职场人提升自我成本低、 效率高的途径。 而职场人要 么觉得没时间读书, 要么看书速度慢, 要么读完记不住内容, 或者无法将书里的内容 用上。 如何解决这些问题? 职场人只能用业余时间读书, 如果照搬市面上流行的专家 或学者的读书方法显然不可行。 \u000d\u000a  \u000d\u000a  身为一位繁忙的创业者, 本书作者多年来仍始终每年读书 180 本以上。 根据亲身 经历和阅读方法的钻研及 500 多名学员和 10 万多名听众的反馈, 本书作者总结出一套 上手难度低、 见效快的科学高效读书法, 助你用尽量少的精力获取尽量多的收益。 \u000d\u000a  \u000d\u000a  本书不仅有逻辑清晰的阅读成效公式和 “预通内外” 四步读书法, 还有经过验证 的快速阅读技巧, 以及阅读内容选择、 碎片化阅读、 精力管理、 高效记忆和个人知识管理等策略和实践心得。书中的实操方法除配说明外, 还有背后认知科学层面深入浅 出的讲解, 尤其重视结合新科技工具的使用。 \u000d\u000a\u000d\u000a  这本干货满满、 有理论支撑、 有实践心得、 有方法、 有技巧、 有随书练习的阅读 指南, 适合每一位寻求成长的职场人阅读。'),'个人成长-认知思维','2023-02-03 00:00:00',0,35,0,35,10,3,1,1722388832,1722388832,811.0,197,NULL,'机械工业出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300116836','复利：全球顶尖投资者的31节认知与决策思维课','[美]高塔姆·拜德','https://cdn.weread.qq.com/weread/cover/59/cpplatform_knz4s3h4cmh2rtb3j3bppu/t9_cpplatform_knz4s3h4cmh2rtb3j3bppu1728370050.jpg',unistr('价值投资不仅仅是一种在股票市场上获得成功的系统。它也是一个智力工具，可以帮助我们更深入地了解世界。在《复利》一书中，价值投资者高塔姆·拜德从其广泛的阅读中构建了一套结合了实践方法、自我修养和商业智慧的全面价值投资哲学。拜德将投资和人生经验提炼成一本综合性的指南，融合了许多杰出人士的策略和智慧，他们的教导经受住了时间的考验。他借鉴了沃伦·巴菲特、查理·芒格和本杰明·格雷厄姆等投资大师以及其他学者的研究成果，巧妙地将他从许多大师那里学到的经验融汇在一起，并详细说明了它们在商业、投资和决策领域的实际应用。作为对价值投资原则的颂扬，这本书还讲述了拜德的个人经历，证明了他的信念：你能做的最好的投资就是投资自己。\u000d\u000a《复利》为所有寻求实用智慧的投资者、投资爱好者和读者提供了珍贵的投资和学习的思考模型。'),'经济理财-理财','2024-08-01 00:00:00',0,34,0,34,9,2,1,1731122949,1731122949,783.0,1106,NULL,NULL,NULL,NULL,1782532955,1);
INSERT INTO books VALUES('34632152','乡村医生','弗兰茨·卡夫卡','https://wfqqreader-1252317822.image.myqcloud.com/cover/152/34632152/t9_34632152.jpg','弗兰茨·卡夫卡（1883—1924），奥地利最伟大的作家之一，影响遍布全世界，被尊为现代派文学大师。出生于奥匈帝国时期的布拉格，曾为保险公司职员，业余从事创作。生前在德语文坛几乎鲜为人知，死后引起世人广泛注意，成为美学、哲学、宗教和社会观念上激烈争论的焦点。本书收入作者最杰出的中短篇小说作品《乡村医生》等。','文学-经典作品','2017-03-22 00:00:00',0,34,0,34,41,2,1,1716785447,1716785447,825.0,209,NULL,'人民文学出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('834465','许三观卖血记','余华','https://cdn.weread.qq.com/weread/cover/2/yuewen_834465/t9_yuewen_8344651758512100.jpg',unistr('《许三观卖血记》是余华继《活着》之后创作的长篇小说，讲述了丝厂工人许三观的卖血经历。他卖血是为了娶亲，是为了救治重病的儿子，是为了郑重款待贵客，是为了不被饿死，是为了生存。但是最终，还是为了爱和生活的尊严。\u000d\u000a当初我写完《活着》的时候，我觉得光写中国人这几十年是如何苦熬过来的好像不够，还应该再写他们是怎么生活过来的，所以写了《许三观卖血记》。——余华'),'精品小说-年代小说','2024-03-01 00:00:00',0,34,0,34,100,4,1,1702069291,1702069291,893.0,119242,NULL,'北京出版集团北京十月文艺出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('40870001','现代C++语言核心特性解析','谢丙堃','https://wfqqreader-1252317822.image.myqcloud.com/cover/1/40870001/t9_40870001.jpg','本书是一本C++进阶图书，全书分为42章，深入探讨了从C++11到C++20引入的核心特性。书中不仅通过大量的实例代码讲解特性的概念和语法，还从编译器的角度分析特性的实现原理，书中还穿插了C++标准委员会制定特性标准时的一些小故事，帮助读者知其然也知其所以然。本书适合因为工作需要学习C++新特性的C++从业者，同样也适合对C++新特性非常感兴趣的C++爱好者。而对于C++初学者来说，也有必要在理解C++基础知识后，通过本书来领略C++的另外一道风景。','计算机-编程设计','2021-09-01 00:00:00',0,33,0,33,7,2,1,1731259038,1731259038,889.0,90,NULL,'人民邮电出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('849878','冰与火之歌（全五卷｜美剧《权力的游戏》原著）','乔治·R.R.马丁','https://cdn.weread.qq.com/weread/cover/8/yuewen_849878/t9_yuewen_8498781681371731.jpg','4月15日美剧《权力的游戏》第八季回归，再掀全球性的“冰与火之歌”热潮。原著《冰与火之歌》系列共15册，是美国“国宝级”幻想文学作品，维斯特洛大陆九大家族的权力斗争史诗。奇幻大师乔治·马丁16年精耕细作成就的文学经典。整个系列没有塑造任何传统意义上的英雄，所有人物都努力尝试去把握自己命运的人类，让我们看到在冰与火这片混乱之下，依然有不变的人性在苦苦地挣扎，任由他们自由而真实地碰撞。','精品小说-玄幻小说','2017-01-01 00:00:00',0,32,0,32,4,3,1,1558494756,1558494756,916.0,7015,NULL,'重庆出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300054736','超越好奇','周鸿祎 范海涛　','https://cdn.weread.qq.com/weread/cover/74/cpplatform_64ezgqqnkux5y5krhg3cu1/t9_cpplatform_64ezgqqnkux5y5krhg3cu11680852693.jpg','本书由360创办人周鸿祎亲自撰写、传记作家范海涛执笔。 它讲述了出身平凡、背景平凡的人脱颖而出的故事。书里更是大量披露了周鸿祎的童年成长经历、学生时代的追梦之旅、碰到现实后的观念转变、企业间的竞争内幕。在这本书里，你会为周鸿祎的敢言所惊讶，对于那些自己做过的傻事、蠢事、争议，他不仅不回避，甚至还给出了大量精彩细节。草根出身、鏖战江湖的周鸿祎创业故事，希望能为初入职场和早期创业的年轻人带来启发。  从好奇开始，在现实中涅槃重生。','人物传记-财经人物','2023-05-01 00:00:00',0,31,0,31,12,2,1,1721094868,1721094868,890.0,1859,NULL,'人民邮电出版社有限公司',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('35148817','性的进化','贾雷德·戴蒙德','https://cdn.weread.qq.com/weread/cover/19/YueWen_35148817/t9_YueWen_35148817.jpg','男性为什么不哺乳？人类为什么会为了享乐而不是生育而性交？为什么只有人类女性会经历更年期？为什么人类男性会成为数不多的照顾后代的哺乳动物之一？……关于人类性征的进化，没有人比贾雷德·戴蒙德更有资格做出解释。本书力图解释人类的性行为是如何演变为现在的模式的，包括女性的绝经期、人类社会中男性的角色、离群性交、为取乐而非传宗接代的性交，以及女性乳房早于发挥喂乳功用时的隆起等。通过一个个有趣的案例，戴蒙德帮助我们梳理了人类性征进化历程的多个方面，写出了一部迷人的、令人惊叹的经典之作。','科学技术-自然科学','2020-12-01 00:00:00',0,31,0,31,34,2,1,1726505070,1726505070,721.0,559,NULL,'天津科学技术出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('635800','人类简史：从动物到上帝','尤瓦尔·赫拉利','https://cdn.weread.qq.com/weread/cover/36/YueWen_635800/t9_YueWen_635800.jpg','引发23个国家版权大战，一部轰动全球的著作！奥巴马、比尔盖茨、扎克伯格等人力荐！由本书改编成的人类简史课程，成为全球诸多知名大学最受欢迎的课程！十万年前，地球上至少有六种不同的人但今日，世界舞台为什么只剩下了我们自己？从只能啃食虎狼吃剩的残骨的猿人，到跃居食物链顶端的智人，从雪维洞穴壁上的原始人手印，到阿姆斯壮踩上月球的脚印，从认知革命、农业革命，到科学革命、生物科技革命，我们如何登上世界舞台成为万物之灵的？从公元前1776年的《汉摩拉比法典》，到1776年的美国独立宣言，从帝国主义、资本主义，到自由主义、消费主义，从兽欲，到物欲，从兽性、人性，到神性，我们了解自己吗？我们过得更快乐吗？我们究竟希望自己得到什么、变成什么？希伯来大学历史系教授，青年怪才尤瓦尔赫拉利，从十万年前有生命迹象，写到21世纪资本、科技交织的人类发展史。不到五百页，就能让你厘清人类历史重大脉络，这是仅有的一部！','历史-世界史','2014-11-26 00:00:00',0,31,0,31,10,3,1,1546522173,1546522173,890.0,29716,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('24235906','早起魔法','杰夫·桑德斯','https://wfqqreader-1252317822.image.myqcloud.com/cover/906/24235906/t9_24235906.jpg','《早起魔法》（THE 5 A.M. MIRACLE）是为精英人士准备的高效生活指南，它适合于任何对生活充满热情并想要获得更好生活的人。通过这本书，读者可以在早起一睁眼就开始为一天的美好活力做好充分准备，获得今天明确目标、随时做好准备采取行动，并最终收获成果。早起魔法的理论建立在一个“金字塔”上，金字塔一共有7层，每一层循序渐进，将早起这一行为和个人的成就及习惯联系起来，最终形成一种贯穿一生的生活方式。（类似于写作领域的《金字塔原理》）。','心理-心理学应用','2018-07-01 00:00:00',0,28,0,28,20,2,1,1668485422,1668485422,597.0,4511,NULL,'机械工业出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300035991','看见情绪价值：接住Ta的情绪，捧住Ta的心','苏菲雅 姚彥宇','https://cdn.weread.qq.com/weread/cover/89/cpPlatform_9zr7vuFVT6kGYEw1eacCcL/t9_cpPlatform_9zr7vuFVT6kGYEw1eacCcL.jpg','作者根据多年的咨询经验，总结出常见的低情绪价值的感情观、认知及行为习惯，并结合原生家庭的知识，分析容易导致一个人长期处于低情绪价值的潜意识心理动力，教给大家完善人格、修炼自身情绪价值的心法。从前意识、潜意识和意识三个层面，扫除导致一个人处于低情绪价值状态的认知障碍、习惯障碍和心理动力阻碍。从底层逻辑出发，建立认知，辅以实例，不仅能让你明白怎么做能让别人觉得跟你相处时舒服，还能让你知行合一地调整自己的认知和行为，从而养成正确的习惯。','生活百科-情感','2022-09-01 00:00:00',0,28,0,28,44,2,1,1697376186,1697376186,782.0,1203,NULL,'中国妇女出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('42568675','C++并发编程实战（第2版）','安东尼·威廉姆斯','https://cdn.weread.qq.com/weread/cover/63/YueWen_42568675/t9_YueWen_42568675.jpg','这是一本介绍C++并发和多线程编程的深度指南。本书从C++标准程序库的各种工具讲起，介绍线程管控、在线程间共享数据、并发操作的同步、C++内存模型和原子操作等内容。同时，本书还介绍基于锁的并发数据结构、无锁数据结构、并发代码，以及高级线程管理、并行算法函数、多线程应用的测试和除错。本书还通过附录及线上资源提供丰富的补充资料，以帮助读者更完整、细致地掌握C++并发编程的知识脉络。 本书适合需要深入了解C++多线程开发的读者，以及使用C++进行各类软件开发的开发人员、测试人员，还可以作为C++线程库的参考工具书。','计算机-编程设计','2021-12-01 00:00:00',0,28,0,28,4,2,1,1739116073,1739116073,683.0,58,NULL,'人民邮电出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300025707','快乐就是哈哈哈哈哈','梁实秋','https://cdn.weread.qq.com/weread/cover/83/cpPlatform_qwnRomc1tNR5nwjojvgZUY/t9_cpPlatform_qwnRomc1tNR5nwjojvgZUY.jpg',unistr('如何在这人间，觅得快乐？\u000d\u000a智者乐水，仁者乐山。雨有雨的趣，晴有晴的妙。小鸟跳跃啄食，猫狗饱食酣睡，哪一样不令人看了觉得快乐？正如梁实秋所言：“良辰美景，赏心乐事，随处皆是。”\u000d\u000a我们寻求的快乐，不是简单的快乐，而是发自内心由衷的欢喜。\u000d\u000a精选38篇梁实秋的生活智慧散文，收录《闲暇》《旅行》《骂人的艺术》《生命与吃药》等名篇，以及《蚊子与苍蝇》《老憨看跳舞》《是热了》《父母的爱》等珍贵文章，详尽展现了一代生活家梁实秋的精神世界与生活志趣：\u000d\u000a知冷暖：一个生动的人，他有喜悦和哀愁。\u000d\u000a得自在：生活，就是要活得热热闹闹。\u000d\u000a爱世间：人生毕竟是非常可爱的啊。\u000d\u000a有态度：我对生活有诸多意见。\u000d\u000a快乐是在心里，不在别处，它是一种积极乐观的生活态度。从快乐出发，通过调动积极的情绪，用更乐观的方式去面对生活，于是快乐和满足也就产生啦！'),'文学-散文杂著','2022-08-01 00:00:00',11,27,0,38,99,4,0,1723776725,1723776725,761.0,3564,NULL,'中国友谊出版公司',NULL,NULL,1782398781,1);
INSERT INTO books VALUES('24129813','显微镜下的大明','马伯庸','https://wfqqreader-1252317822.image.myqcloud.com/cover/813/24129813/t9_24129813.jpg','本书讲述的，是六个深藏于故纸堆中的明代基层政治事件。作者从明代的一系列罕见民间档案文书里，挖掘出这些尘封已久的故事。这些档案是中国历史中绝无仅有的奇迹，它们着眼于平民的政治生活，而且记录极为详尽。在这里，我们能看到朴实的百姓诉求、狡黠的民间智慧、肮脏的胥吏手段、微妙的官场均衡之术，从无数个真实的细节里，展现出一幅极其鲜活的政治生态图景。这六个事件聚焦于一府一县乃至一村之内，记录的是最底层平民的真实政治生活：当遭遇税收不公时，他们如何愤起抗争；当家族权益受到损害时，他们如何兴起诉讼；当政治利益与商业利益发生矛盾，他们如何与官府周旋博弈；当朝廷要求整顿户籍，他们又是如何从中造假牟利……《学霸必须死——徽州丝绢案始末》：万历年间，一项不公正的税收政策在徽州府引发了旷日持久的混乱。乱民、县官、州府、户部、首辅、皇帝等诸多利益集团的博弈之局。《笔与灰的抉择——婺源龙脉保卫战》：婺源县一场持续了六十四年的经济争端，反映了一个县级官员，是如何在重大议题上平衡一县之利害的。《谁动了我的祖庙——杨干院律政风云》：歙县一桩民间庙产争夺案。诉讼双方在这场绵延八年的官司中各展所长，用尽心思，上演了一场精彩绝伦的嘉靖法律大戏。《天下透明——大明第一档案库的前世今生》：一个坐落于后湖（玄武湖）中的冷门机构——大明黄册库从建立到衰败的全过程。了解明代的基层统治，是如何一步步垮掉的。《胥吏的盛宴——彭县小吏舞弊案》：一件小到不能再小的官司，却引来了无数贪婪蚊虫的叮咬。胥吏之恶，被刻画得淋漓尽致。《正统年间的四条冤魂》：四个无辜的清白老百姓，是如何裹挟入朝廷斗争的。作者力图以冷静克制的零度叙事，替那些生于尘埃、死于无闻的蝼蚁之辈作传，转述他们湮没于宏达历史中的声音。想要读懂大明，想要读懂中国古代政治，不可只注目于朝堂，亦要听到最底层的呐喊。在一个个普通人的遭遇中，才蕴藏着最真实的规律。','历史-历史读物','2019-01-01 00:00:00',0,26,0,26,12,2,1,1677559325,1677559325,876.0,30742,NULL,'湖南文艺出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300089952','开始冥想','[法]克里斯托夫·安德烈','https://cdn.weread.qq.com/weread/cover/23/cpplatform_wvwhaafwvh9yhkmxrkvymd/t9_cpplatform_wvwhaafwvh9yhkmxrkvymd1709628757.jpg','这是一本轻巧的冥想实践指南，体量轻盈、内容好懂，适合对冥想有兴趣，但不了解冥想是什么、也不知道如何着手的人。作者以平易的语言介绍了冥想是什么、有什么用，书中随文穿插17个冥想小练习，由易到难、循序渐进，帮助读者在日常生活中随时随地开始冥想。','心理-心理学应用','2024-01-01 00:00:00',0,26,0,26,59,2,1,1730016993,1730016993,868.0,469,NULL,'天津人民出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300069758','京瓷哲学：人生与经营的原点','稻盛和夫','https://cdn.weread.qq.com/weread/cover/11/cpplatform_9itoxynqkle9vfkrfmywhx/t9_cpplatform_9itoxynqkle9vfkrfmywhx1693537582.jpg',unistr('本书浓缩京瓷公司内部教材《京瓷哲学手册》的内容，如今以逐项解说的形式面世。原本仅限于盛和塾塾生、并不外传的公司至宝，集结了稻盛和夫八十多年来经营与人生的智慧，不管是商界人士还是普通读者，皆可从稻盛和夫质朴又强大的活法中获得能量，走向事业经营与人生丰硕充实之路。\u000d\u000a《京瓷哲学：人生与经营的原点》的核心内容就是“作为人，何谓正确？”稻盛和夫认为，如果以这种生活态度来度过人生，每个人的人生都会幸福，以这个准则来经营企业，公司也都会繁荣发展。初次接触稻盛和夫哲学的读者也许会认为：“那么简单的东西就可以把企业经营好吗？” “照这样做，人生就会变美好吗？”“这些不就是从小就已经知道的老生常谈吗？”而正是这套质朴的京瓷哲学，让稻盛和夫引领所创办的京瓷与KDDI两家企业晋身世界500强行列、引领盛和塾中许多原本经营不善的日本中小公司转亏为盈，更以短短两年多时间，就让负债超过两兆日元、破产下市的日航起死回生，而且来年甚至创下日航高利润，创下V型反转轰动全球业界的奇迹。'),'经济理财-财经','2015-09-01 00:00:00',0,25,0,25,8,2,1,1716549424,1716549424,860.0,471,NULL,'东方出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('44966312','斯多葛生活哲学','乔纳斯·萨尔茨格伯','https://wfqqreader-1252317822.image.myqcloud.com/cover/312/44966312/t9_44966312.jpg','遇上挑战时该如何自处？碰到难缠的人要如何应对？在哪里可以找到快乐、获得力量？怎样处理反复出现的令人沮丧的想法？如何看待变故、正视生死？……面对人生中这些不可避免烦扰与难题，如何活得更幸福？两千多年前的斯多葛哲学早已给出了答案。乔纳斯·萨尔茨格伯结合多年来亲身实践斯多葛哲学的经历和体悟，创作了这本非常适合现代人的幸福指南。作者从各种有趣的生活细节出发，介绍了斯多葛哲学的历史沿革、代表人物以及重要观点。同时，本书用55条斯多葛哲学的日常练习，手把手教我们如何驾驭情绪、如何保持敏锐、如何处世为人、如何像斯多葛派哲学家一样游刃有余地掌控人生。在斯多葛哲学的永恒智慧指引下，每个人都能找到幸福之路。','个人成长-人生哲学','2022-08-01 00:00:00',0,25,0,25,7,2,1,1716439073,1716439073,794.0,579,NULL,'台海出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('834466','兄弟','余华','https://cdn.weread.qq.com/weread/cover/3/yuewen_834466/t9_yuewen_8344661758521400.jpg',unistr('《兄弟》讲述了江南小镇两兄弟李光头和宋钢的一生。\u000d\u000a这是两个时代相遇以后出生的小说，连结这两个时代的纽带就是这兄弟两人。\u000d\u000a他们的生活在裂变中裂变，他们的悲喜在爆发中爆发，他们的命运和这两个时代一样天翻地覆。\u000d\u000a李光头是一个混世魔王，我喜欢这个人物。喜欢他的丰富和复杂，这个人物和我们的时代有着千丝万缕的联系，可以说就是我们时代的产物。宋钢是“良心的悲剧”。他一直是别人的影子，先是李光头的影子，再是林红的影子，最后他终于独立了，可是走向了死亡。——余华\u000d\u000a《兄弟》是一部怪诞的绝妙之作，是中国小说家第yi次尝试为当代人创作的一部大众史诗。通过两兄弟的命运沉浮，展示了中国四十年的历史变迁。——《纽约时报》'),'精品小说-年代小说','2022-07-05 00:00:00',0,25,0,25,12,2,1,1691313472,1691313472,814.0,68922,NULL,'北京出版集团北京十月文艺出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300074976','视觉SLAM十四讲：从理论到实践（第2版）','高翔等著','https://cdn.weread.qq.com/weread/cover/44/cpplatform_cvyrhwwnaomk7jci9cmplu/t9_cpplatform_cvyrhwwnaomk7jci9cmplu1697622143.jpg','本书系统介绍了视觉 SLAM（同时定位与地图构建）所需的基本知识与核心算法，既包括数学理论基础，如三维空间的刚体运动、非线性优化，又包括计算机视觉的算法实现，例如多视图几何、回环检测等。此外，我们还提供了大量的实例代码供读者学习研究，从而更深入地掌握这些内容。本书可以作为对 SLAM 感兴趣的研究人员的入门自学材料，也可以作为 SLAM 相关的高校本科生或研究生课程教材使用。','计算机-人工智能','2019-07-01 00:00:00',0,24,1,25,71,2,1,1766578090,1766578090,885.0,73,NULL,'电子工业出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('33091654','精力管理','吉姆·洛尔 托尼·施瓦茨　','https://wfqqreader-1252317822.image.myqcloud.com/cover/654/33091654/t9_33091654.jpg','不是时间不够用，而是精力没管好！我们期待改变的发生，却往往发现自己在原地挣扎。每一天的时间量是固定不变的，但是我们可用的精力的储备和质量却可以改变。认识到这一事实就会让你拥有颠覆生活方式的力量。吉姆洛尔和托尼施瓦茨的全情投入精力训练系统曾帮助他们在高压竞争的环境下取得上佳表现。随后他们又将这一系统成功应用到普通人的精力管理培训中，遵循书中的理念和步骤，你的生活会出现如下变化：轻松调动四种精力源：体能、情感、思维、意志驾驭劳逸结合的生命脉动节奏和精英运动员一样系统发展自己的能力建立起高度精确、积极的精力管理习惯。','个人成长-人在职场','2015-07-01 00:00:00',0,24,0,24,71,2,1,1726567701,1726567701,752.0,5854,NULL,'中国青年出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('CB_BOCFz6G1s6UD6cT6cK','增长黑客：创业公司的用户与收入增长秘籍','范冰','https://res.weread.qq.com/wrepub/CB_1kQ6k66mw9Qa6Uu6U5_parsecover',NULL,NULL,'',0,24,0,24,11,1,1,1668247289,1668247289,NULL,NULL,NULL,'电子工业出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300075810','CPU眼里的C/C++','阿布编程','https://cdn.weread.qq.com/weread/cover/36/cpplatform_ftfswhrgqnpxdd6ho2zn3m/t9_cpplatform_ftfswhrgqnpxdd6ho2zn3m1698637819.jpg','全书共6章，第1章：介绍本书所使用到的主要工具和一些需要心里有数的预备知识；第2章：解析最简单、常用的基础语法，帮助读者适应本书的节奏；第3章：为进阶知识，会从CPU、操作系统的角度，深入分析函数的工作原理和实现细节；第4章：解析经典的C++语法，背后的实现逻辑，并介绍“面向对象”的编程思想及优缺点；第5章：讨论跟操作系统强相关的软件技术，会将所有章节的内容贯穿起来，初步形成一个现代操作系统的运作模型。第6章：我们会讨论一些经典的面试、笔试题，跟读者一起分享工作、学习、求职中的苦与乐。 本书可作为高等院校计算机、自动化及相关专业的本科生或研究生教材，也可供对C/C++工作原理、操纵系统感兴趣的研究人员和工程技术人员阅读参考。','计算机-计算机综合','2023-09-01 00:00:00',0,23,0,23,12,2,1,1747275985,1747275985,817.0,182,NULL,'清华大学出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('39136896','卡片笔记写作法：如何实现从阅读到写作','申克·阿伦斯','https://cdn.weread.qq.com/weread/cover/15/YueWen_39136896/t9_YueWen_39136896.jpg','卢曼的“盒中笔记”通常很简短，因为这些只是他庞大繁杂研究中的索引，等需要时，他会借由这些线头进行延伸思考，然后不断链接知识要点，从而形成自己的知识树。你也可以试试。','文学-语言文字','2021-06-01 00:00:00',1,23,0,24,9,2,1,1704384441,1704384441,734.0,4641,NULL,'人民邮电出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('23523085','人生十论','钱穆','https://cdn.weread.qq.com/weread/cover/88/yuewen_23523085/t9_yuewen_235230851689842913.jpg','《人生十论/钱穆作品系列》汇集了作者讨论人生问题的三次讲演，一为“人生十论”，一为“人生三步骤”，一为“中国人生哲学”。作者从中国传统文化入手，征诸当今潮流风气，探论“心”、“我”、“自由”，“命”、“道”等优选问题，而不离人生日常态度，启发读者追溯本民族文化传统的根源，思考中国人在现代社会安身立命的根本。','哲学宗教-东方哲学','2011-07-01 00:00:00',0,22,0,22,17,2,1,1701244231,1701244231,787.0,1260,NULL,'九州出版社',NULL,NULL,1782532956,0);
INSERT INTO books VALUES('23566637','艺术的故事','房龙','https://wfqqreader-1252317822.image.myqcloud.com/cover/637/23566637/t9_23566637.jpg','在《艺术的故事》一书中，作者房龙以其丰厚的知识底蕴将建筑、雕塑、绘画、戏剧、音乐等艺术门类熔为一炉，将人类迷人而庞杂的艺术和盘托出，从东方写到西方，从上古写至20世纪二三十年代，为我们打开了一扇扇艺术之窗。','艺术-理论','2015-10-01 00:00:00',0,22,0,22,9,2,1,1622044326,1622044326,744.0,417,NULL,'中国妇女出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('621677','情商：为什么情商比智商更重要','丹尼尔·戈尔曼','https://wfqqreader-1252317822.image.myqcloud.com/cover/677/621677/t9_621677.jpg','情商是一种基本生存能力，决定你其它心智能力的表现，也决定你一生的走向与成就。','个人成长-情绪心灵','2010-11-01 00:00:00',0,22,0,22,6,3,1,1614271501,1614271501,751.0,7414,NULL,'中信出版集团',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('35679936','幸福之路（果麦经典）','伯特兰·罗素','https://wfqqreader-1252317822.image.myqcloud.com/cover/936/35679936/t9_35679936.jpg','《幸福之路》是一本写给普通人的经典生活哲理书。全书简明扼要地分为“不幸福的原因”和“幸福的原因”两大部分，不去讲高深的哲理和枯燥的说教，而是直接反思生活中最常破坏幸福感的消极心理因素，如竞争、疲劳、嫉妒、罪恶感、受害妄想等，直接给出获得和提升幸福感的具体生活建议，如通过兴致、情爱、家庭、工作、闲情逸致等。作者给书中的每个观点都提供了真实的人性经验的支撑，和清晰、坦率、真诚的剖析论证；他所开列的药方，也都是亲历亲见，并且实践证明有效提升了他的幸福感，所以具有非常强的可操作性。无数感到苦闷而又不甘忍受的男男女女，完全能够借此明察自身的困境，进而找到突围之路，凭着适当的努力变得幸福。','个人成长-人生哲学','2021-01-01 00:00:00',0,21,0,21,22,2,1,1661061159,1661061159,903.0,4986,NULL,'天津人民出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('43604203','胆囊癌','全志伟 洪德飞主编','https://cdn.weread.qq.com/weread/cover/82/YueWen_43604203/t9_YueWen_43604203.jpg','《胆囊癌》系统介绍了胆囊外科的应用解剖、胆囊的生理与病理生理、胆囊癌的病因学和预防、诊断与鉴别诊断、分期与临床分型、临床病理学、围手术期准备、三维重建技术评估、外科手术治疗、内镜和介入治疗、腹腔镜和达芬奇外科技术、外科手术并发症处理、化学治疗、放射治疗、靶向治疗和免疫治疗、预后及随访；首次提出了“意外胆囊癌”不科学诊断命名的纠正与规范；回顾了胆囊癌的基础研究和临床研究历程，提出了胆囊癌未来的研究方向。','医学健康-医学','2021-08-01 00:00:00',0,21,1,22,87,2,1,1771257936,1771257936,NULL,6,NULL,'人民卫生出版社',NULL,NULL,1782532954,0);
INSERT INTO books VALUES('695233','三体全集（全三册）','刘慈欣','https://cdn.weread.qq.com/weread/cover/80/yuewen_695233/t9_yuewen_6952331740758482.jpg',unistr('【荣获世界科幻大奖“雨果奖”长篇小说奖，约翰·坎贝尔纪念奖，银河奖特别奖。】\u000a每个人的书架上都该有套《三体》！关于宇宙最狂野的想象！就是它！\u000a征服世界的中国科幻神作！包揽九项世界顶级科幻大奖！出版16个语种，横扫30国读者！奥巴马、雷军、马化腾、周鸿祎、潘石屹、扎克伯格……强推！\u000a刘慈欣获得2018年度克拉克想象力贡献社会奖！\u000a刘慈欣是中国科幻小说的最主要代表作家，亚洲首位世界科幻大奖“雨果奖”得主，被誉为中国科幻的领军人物。'),'精品小说-科幻小说','2022-04-01 00:00:00',1,21,0,22,100,4,1,1563298874,1563298874,930.0,293959,NULL,'重庆出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('31808219','卡拉马佐夫兄弟（套装上下册）（陀思妥耶夫斯基文集2015）','陀思妥耶夫斯基','https://cdn.weread.qq.com/weread/cover/28/YueWen_31808219/t9_YueWen_31808219.jpg','本书系俄国大作家陀思妥耶夫斯基代表作之一。小说通过一桩真实的弑父案，描写老卡拉马佐夫同三个儿子即两代人之间的尖锐冲突。老卡拉马佐夫贪婪好色，独占妻子留给儿子们的遗产，并与长子德米特里为一个风流女子争风吃醋。一天黑夜，德米特里疑心自己的情人去跟老头儿幽会，便闯入家园，一怒之下，差点儿把老头儿砸死。他仓皇逃离后，躲在暗中装病的老卡拉马佐夫的私生子斯乜尔加科夫，悄然杀死老爷，造成了一桩震惊全俄的扑朔迷离的血案，从而引发了一连串惊心动魄的事件。作品展示一个错综复杂的社会家庭、道德和人性的悲剧主题，体现了作家一生的最高艺术成就。','文学-外国文学','2014-12-01 00:00:00',0,20,0,20,5,2,1,1693849347,1693849347,935.0,11782,NULL,'上海译文出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('39457314','宇宙','卡尔·萨根','https://cdn.weread.qq.com/weread/cover/54/YueWen_39457314/t9_YueWen_39457314.jpg','《宇宙》由知名天文学家卡尔·萨根所著，是影响深远的一本天文科普名著，是豆瓣9.5分同名传奇纪录片的姊妹篇。《宇宙》一书将科学思辨和人文精神结合，从我们身边的锁事追溯到万物的开端，从浩渺的宇宙视角审视人类自身。作者在天文、生物、化学和地理学之间进行“异花授粉”，将科学与历史、艺术、人类学和哲学交织，向我们描述了宇宙的前生今世，帮助读者拥抱科学，了解人在宇宙中的位置。','科学技术-科学科普','2021-06-01 00:00:00',0,20,0,20,6,2,1,1714400247,1714400247,912.0,4600,NULL,'上海科学技术文献出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('39888201','英语语法分解大全','尹尚远 张莎拉','https://wfqqreader-1252317822.image.myqcloud.com/cover/201/39888201/t9_39888201.jpg','本书作者之一为在韩国社交媒体圈上广受好评的英语老师尹尚远，他独到的讲解方法让众多徘徊在学好英语之外的学生找到了一条新出路。他崇尚“以繁化简、化整为零”的分析思路，对复杂长难句进行详细的拆分，将每一个成分和语法知识一一对应，让读者在理解句子结构和句意的同时，也能深刻理解语法知识，可谓一举多得。另一位作者张莎拉长期担任韩国英语学习节目的策划人，拥有丰富的知识背景，强强联合让英语学习更轻松！','教育学习-外语','2016-05-01 00:00:00',0,20,0,20,3,2,1,1716947457,1716947457,847.0,347,NULL,'江苏科学技术出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('41588195','地铁上的哲学（4册）','[美]苏珊·奈曼 [斯]斯拉沃热·齐泽克 [美]约翰·D·卡普托 [英]巴里·丹顿','https://cdn.weread.qq.com/weread/cover/25/YueWen_41588195/t9_YueWen_41588195.jpg','企鹅出品，豆瓣评分超过8.0，著名欧陆哲学家、批判理论家齐泽克等执笔！哲学能否帮助我们找到一种与屈从妥协无关的成熟状态？《地铁上的哲学》丛书小而易读，由当世顶尖哲学家执笔，依各自专长的思想领域，择定“事件、真理、自我、为什么长大”四大主题，交出最精当、最生动也最富启发的答卷。丛书的每一主题都发端于哲学史，裹挟着先哲赠予的丰厚思想遗产，来到今日思想论争的风眼。频繁迭代的生活方式早已全面改变了我们对诸如真理、自我这样一些最基本问题的想法，身处其中的我们可能习焉不察。本套丛书的哲学家们用各种各样的交通工具（无论真实还是虚拟）作为思想的起始站，带领读者游历与审视现代生活变动永无停歇的实境。','哲学宗教-东方哲学','2016-05-01 00:00:00',0,20,0,20,3,2,1,1719538365,1719538365,806.0,47,NULL,'上海文艺出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('915288','亲密关系','克里斯多福·孟','https://wfqqreader-1252317822.image.myqcloud.com/cover/288/915288/t9_915288.jpg','【感情经营+人际关系+幸福秘方+治愈+自我成长】影响数十万家庭受益！在爱与被爱的过程中，我们都曾经历过痛苦、恐惧，也体验过狂喜与极乐，我们渴望建立永恒真挚的亲密关係，却又害怕再度受伤。本书告诉我们如何穿透自我障碍，用爱酿造幸福秘方——没有人能年复一年地活在火辣、热情、浪漫的亲密关系之中，但我们能在亲密关系的旅途中，学习面对自己最好以及最糟的特质……','个人成长-沟通表达','2015-04-01 00:00:00',0,20,0,20,16,2,1,1624323809,1624323809,766.0,34950,NULL,'湖南文艺出版社',NULL,NULL,1782532956,1);
INSERT INTO books VALUES('3300071182','经纬华夏（历史学家许倬云的集大成之作）','许倬云','https://cdn.weread.qq.com/weread/cover/67/cpplatform_a9sazckznjj4np8ggvaglz/t9_cpplatform_a9sazckznjj4np8ggvaglz1694758919.jpg',unistr('“我要从世界看中国，再从中国看世界。”围绕这一发端，历史学家许倬云以九十高龄迎难而上，八易其稿，结撰出一部华夏文明从成长到成型的“传记”。作者跳脱出中国文化内部演变的叙述，以“大历史”的观看视角与思维方式，对华夏内外的历史互动重新归纳排列，再现了中国大地上人群、族群、文化互动融合的轨迹。\u000a在五千余年的长程叙述中，作者借由对中国地方性文化如何交缠为一，以及中国如何应对来自世界之冲击的细致分析，揭示了华夏文明能够延续至今，并将绵延永在的核心与奥秘，以赤子之心瞻见了一个有根底、有方向的中国。'),'社会文化-文化','2023-08-31 00:00:00',0,19,0,19,13,2,1,1731080448,1731080448,855.0,885,NULL,'南海出版公司',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('906847','富兰克林自传','[美]富兰克林','https://wfqqreader-1252317822.image.myqcloud.com/cover/847/906847/t9_906847.jpg','《富兰克林自传》是美国迄今为止最重要、读者最多的自传作品之一，无论从自传的角度还是从美国思想史的角度来看，都具有划时代的意义。富兰克林以拉家常的方式，把自己成功的经验和失败的教训娓娓道来，整部自传在通俗易懂的叙述中不时会有睿智和哲理的火花，开创了美国传记文学的优良传统，使自传成为一种新的文学体裁。《富兰克林自传》是在读者如饥似渴的等待中出版的，一经问世被一抢而光。世界各地的青年人都希望学习富兰克林成功的秘诀，他们把这部书当成“人生指导”读物。','人物传记-传记综合','2012-12-01 00:00:00',0,19,0,19,10,2,1,1714744549,1714744549,798.0,6937,NULL,'译林出版社',NULL,NULL,1782532955,1);
INSERT INTO books VALUES('3300112218','反逃避心理学','徐小雨','https://cdn.weread.qq.com/weread/cover/92/cpplatform_3p2zfa9tydaywgei4h6nkf/t9_cpplatform_3p2zfa9tydaywgei4h6nkf1724235382.jpg',unistr('每个人都有过想要逃避的时刻，那些看似无法逾越的障碍，让人心生畏惧。然而，逃避并不能解决问题，反而会让人陷入更深的困境。尤其是习惯性逃避的人，会失去解决问题的能力，变得懦弱、胆怯，甚至开始厌弃自己。\u000a本书教你如何克服恐惧心理，帮助你全力跳出习惯性逃避的漩涡，做到勇敢地面对困难和挑战。请记住，逃避就像止痛片，无法根治我们内心的痛处，勇敢面对、不逃避才是真正的“解药”。'),'心理-心理学应用','2024-07-01 00:00:00',0,18,0,18,31,2,1,1745626070,1745626070,692.0,182,NULL,'古吴轩出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300175671','自证预言（翻开本书接好运！）','[英]大卫·罗布森','https://cdn.weread.qq.com/weread/cover/39/cpplatform_rgfjjndwycirf7shb5aqea/t9_cpplatform_rgfjjndwycirf7shb5aqea1762741407.jpg',unistr('相信自己运气好，就会一直运气好！翻开本书，用科学的方法接好运！\u000a50+真实案例，50+科学实验，10套实操方法论，用数据证明相信自己真能带来好运。\u000a只要相信自己每天的运动是高强度的，不去健身房也能瘦\u000a只要相信自己比实际年轻，往往更容易变长寿\u000a相信自己运气好，就会一直运气好！科学验证，真实可信！\u000a自证预言是一种心理学现象，指人会不自觉地按照自己的信念行事，最终令自己的预言发生。\u000a全书50+真实案例，50+科学实验，10套方法论，带你全方位了解“自证预言”的作用和发生机制，了解如何通过改变自己的想法与心态，影响现实，实现自己的目标。\u000a作者大卫·罗布森亲身体验了自证预言的力量有多强大，决定用数据+案例，教你用信念改变现实，用科学的方法接好运！'),'个人成长-人生哲学','2025-09-30 00:00:00',1,18,2,21,14,2,1,1766333813,1766333813,893.0,582,NULL,'天津科学技术出版社',NULL,NULL,1782532954,1);
INSERT INTO books VALUES('3300201761','半小时讲透稀土投资（轻理财）','杨娜','https://cdn.weread.qq.com/weread/cover/82/cpplatform_igyvduqbuqinsjlrcjuqqb/t9_cpplatform_igyvduqbuqinsjlrcjuqqb1776321269.jpg','“稀土，比石油更重要的战略资源，正成为全球地缘博弈的焦点。”新能源汽车、风电、军工——现代工业离不开它，而中国掌控着全球近90%的冶炼产能。价格暴涨暴跌间，无数投资者被收割。这本书用半小时讲透：稀土是什么、谁在主导、需求从哪里来、价格如何波动、有哪些投资渠道（ETF、概念股、定投策略），以及最关键的——如何避开政策、替代、周期三大雷区。无论你是新手还是老手，都能快速建立系统认知，掌握实战操作框架。看懂稀土，就是看懂未来十年的能源与制造大趋势。','经济理财-理财','2026-04-20 00:00:00',0,18,0,18,100,4,1,1777820600,1777820600,803.0,129,NULL,NULL,NULL,NULL,1782532954,1);
