INSERT INTO highlights VALUES('635722_98_8127-8213','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','。你要打造一家再过一两代人仍然屹立不倒的公司。那就是沃尔特·迪士尼、休利特和帕卡德，还有创建英特尔的人所做的。他们创造了传世的公司，而不仅仅是赚了钱。这正是我对苹果的期望。','8127-8213',5,1705868482,1782480561);
INSERT INTO highlights VALUES('635722_98_7945-7969','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','我认为只要鲍尔默还在掌舵，微软就不会有什么起色。','7945-7969',5,1705868438,1782480561);
INSERT INTO highlights VALUES('635722_98_7340-7399','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','要指出微软的不足很容易。他们显然已经丧失了统治地位，已经变得基本上无关紧要。但是我欣赏他们所做的，也了解那有多么困难。','7340-7399',5,1705868353,1782480561);
INSERT INTO highlights VALUES('635722_98_6537-6695','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','有些人说：“消费者想要什么就给他们什么。”但那不是我的方式。我们的责任是提前一步搞清楚他们将来想要什么。我记得亨利·福特曾说过，“如果我最初问消费者他们想要什么，他们应该是会告诉我，‘要一匹更快的马！’”人们不知道想要什么，直到你把它摆在他们面前。正因如此，我从不依靠市场研究。我们的任务是读懂还没落到纸面上的东西。','6537-6695',5,1705868239,1782480561);
INSERT INTO highlights VALUES('635722_98_6361-6411','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','我的激情所在是打造一家可以传世的公司，这家公司里的人动力十足地创造伟大的产品，其他一切都是第二位的。','6361-6411',5,1705868214,1782480561);
INSERT INTO highlights VALUES('635722_98_5988-6051','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','他能够在苹果的DNA中融入设计的敏感、完美主义和想象力，使之很可能，甚至此后几十年，都是在艺术与科技的交汇处成长得最茁壮的公司','5988-6051',5,1705868172,1782480561);
INSERT INTO highlights VALUES('635722_98_5746-5806','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','他的洞见会不期而至，更多地要求直觉而非大脑的处理能力。他像个探路者一样，可以吸收信息，嗅到风中的气味，并对前路先知先觉。','5746-5806',5,1705868131,1782480561);
INSERT INTO highlights VALUES('635722_98_3776-3829','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','乔布斯的极致还表现在他的专注力上。他会设定优先级，把他激光般的注意力对准目标，并把分散精力的事情都过滤掉。','3776-3829',5,1705867883,1782480561);
INSERT INTO highlights VALUES('635722_98_3466-3552','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','他相信他是在为人们提供服务，“人们在忙着做他们最擅长的事情，他们希望我们去做我们最擅长的。他们的生活很繁忙，他们有其他事情要做，而不是去想怎样整合他们的计算机和电子设备。”','3466-3552',5,1705867823,1782480561);
INSERT INTO highlights VALUES('635722_98_2114-2217','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','然而从长期看，乔布斯的模式证明是有一些优势的。当其他计算机制造商都在商品化时，苹果即使以很小的市场份额都能保持极高的利润率。例如在2010年，苹果的收入只占个人电脑市场的7%，但是却获得了营业利润的35%。','2114-2217',5,1705867544,1782480561);
INSERT INTO highlights VALUES('635722_98_1355-1389','635722',98,'第四十二章 遗产：无比辉煌的创新天堂','他把自己看作一个艺术家，他也确实是，所以他纵容自己具有艺术家的性情。','1355-1389',5,1705867422,1782480561);
INSERT INTO highlights VALUES('635722_97_18104-18165','635722',97,'第四十一章 第三回合：暮色下的抗争','可是现在这家公司正处于分裂和毁灭之中，太悲哀了。真希望我能留下更强大的遗产，这样的话，那样的事就永远不会发生在苹果身上。”','18104-18165',5,1705867244,1782480561);
INSERT INTO highlights VALUES('635722_97_16056-16134','635722',97,'第四十一章 第三回合：暮色下的抗争','“我对奥巴马感到失望。”他说，“他的领导力出现问题是因为他不愿意得罪别人或让那些人滚蛋。”他猜到了我在想什么，会心地笑着说：“是的，我就从来没有这种问题。”','16056-16134',5,1705866970,1782480561);
INSERT INTO highlights VALUES('635722_97_15856-15880','635722',97,'第四十一章 第三回合：暮色下的抗争','任何人都可以用这种方式创造出更好的产品，不只是我','15856-15880',5,1705866890,1782480561);
INSERT INTO highlights VALUES('635722_97_13844-13889','635722',97,'第四十一章 第三回合：暮色下的抗争','盖茨说，要改变这一点，计算机和移动设备必须致力于提供更多个性化的课程并提供有启发性的反馈。','13844-13889',5,1705856016,1782480561);
INSERT INTO highlights VALUES('635722_97_12801-12829','635722',97,'第四十一章 第三回合：暮色下的抗争','它们会把你变成微软，导致你生产的产品虽符合要求但不伟大。','12801-12829',5,1705855778,1782480561);
INSERT INTO highlights VALUES('635722_97_12499-12557','635722',97,'第四十一章 第三回合：暮色下的抗争','但是后来我想了想，意识到在我年轻的时候每个人都帮助过我，从比尔·休利特到在惠普工作的邻居。所以我给他回电话说没问题。','12499-12557',5,1705855732,1782480561);
INSERT INTO highlights VALUES('635722_97_12436-12462','635722',97,'第四十一章 第三回合：暮色下的抗争','他询问是否可以过来请教一下做一个好CEO有什么秘诀。','12436-12462',5,1705855711,1782480561);
INSERT INTO highlights VALUES('635722_97_7572-7614','635722',97,'第四十一章 第三回合：暮色下的抗争','总统是个聪明人，可是他一直在向我们解释为什么事情做不成。”他回忆说，“把我气坏了。”','7572-7614',5,1705853895,1782480561);
INSERT INTO highlights VALUES('635722_97_7380-7440','635722',97,'第四十一章 第三回合：暮色下的抗争','轮到乔布斯时，他强调需要有更多训练有素的工程师，建议对任何在美国拿到工程学位的外国留学生都应该颁发签证，让他们留在美国。','7380-7440',5,1705853873,1782480561);
INSERT INTO highlights VALUES('635722_97_7114-7160','635722',97,'第四十一章 第三回合：暮色下的抗争','无论我们的政治理念是什么，我希望你了解，我们来这儿是为了做任何你要求的事情来帮助我们的国家。','7114-7160',5,1705853814,1782480561);
INSERT INTO highlights VALUES('635722_97_6314-6360','635722',97,'第四十一章 第三回合：暮色下的抗争','所有的书、学习资料和测试都应该是数字化的，而且是互动的，为每个学生专门定制，并提供实时反馈。','6314-6360',5,1705853678,1782480561);
INSERT INTO highlights VALUES('635722_97_6197-6229','635722',97,'第四十一章 第三回合：暮色下的抗争','他说，教师应该被当作专业人员对待，而不是工厂组装生产线上的工人。','6197-6229',5,1705853652,1782480561);
INSERT INTO highlights VALUES('635722_97_6007-6111','635722',97,'第四十一章 第三回合：暮色下的抗争','“看你的架势，你就想当一届总统吧。”一开场乔布斯就这样对奥巴马说。否则，他说，奥巴马政府应该对企业更友好一些。他描述了在中国建一家工厂有多么容易，而这在现在的美国几乎是不可能的，主要是由于监管和不必要的成本。','6007-6111',5,1705853632,1782480561);
INSERT INTO highlights VALUES('635722_97_5306-5411','635722',97,'第四十一章 第三回合：暮色下的抗争','“跟很多有非凡天分的人一样，他并不是在所有方面都同样优秀。”她说，“他没有社交风度，不会设身处地替别人着想，但是他高度关注如何发挥人性的作用、让人们获得力量，如何使人类进步，并给人类创造正确的工具去追求进步。”','5306-5411',5,1705853551,1782480561);
INSERT INTO highlights VALUES('635722_97_1056-1114','635722',97,'第四十一章 第三回合：暮色下的抗争','我认为21世纪最大的创新将是生物学与技术的结合。一个新的时代正拉开序幕，就像我在他的年龄时，数字时代正拉开序幕一样。','1056-1114',5,1705852867,1782480561);
INSERT INTO highlights VALUES('635722_96_11251-11268','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','“告诉我，我年轻的时候是什么样子？','11251-11268',5,1705852763,1782480561);
INSERT INTO highlights VALUES('635722_96_11298-11369','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','鲍尔斯尽量诚实地回答了他。“你那时非常冲动，非常难以相处，”她说，“但是你的视野让人折服。你告诉我们，‘过程就是奖励。’结果表明你说得没错。”','11298-11369',5,1705852733,1782480561);
INSERT INTO highlights VALUES('635722_96_10269-10303','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','以前你在哪儿都能见到杏树园，甚至是在街角上，它们是硅谷遗产的一部分。','10269-10303',5,1705852468,1782480561);
INSERT INTO highlights VALUES('635722_96_10001-10040','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','新的设计意味着在整个建筑中将没有一块平直的玻璃。一切都是弧形的并加以无缝连接。','10001-10040',5,1705852417,1782480561);
INSERT INTO highlights VALUES('635722_96_7570-7608','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','我们要把PC和Mac降级为仅仅是一个设备，我们要把数字中枢转移到‘云端’。”','7570-7608',5,1705845461,1782480561);
INSERT INTO highlights VALUES('635722_96_3467-3512','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','而我认识到，“那又他妈的能怎么样呢？”即使是在土耳其，又有哪个孩子会在乎什么土耳其咖啡呢？','3467-3512',5,1705844984,1782480561);
INSERT INTO highlights VALUES('635722_96_2499-2658','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','有三部电影：《唐人街》(Chinatown)、《谍影重重3》(The Bourne Ultimatum)和《玩具总动员3》(Toy Story 3)。','2499-2658',5,1705844658,1782480561);
INSERT INTO highlights VALUES('635722_96_1766-1821','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','真正的创意和简洁来自产品的一体化——硬件、软件，以及内容、保护盖和销售员——而不是让这些部分都开放和各自为政，','1766-1821',5,1705844506,1782480561);
INSERT INTO highlights VALUES('635722_96_1683-1746','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','又一次，他用人文街(Liberal Arts Street)和科技街(Technology Street)交汇的画面结束了演讲','1683-1746',5,1705844489,1782480561);
INSERT INTO highlights VALUES('635722_96_1540-1601','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','这次，苹果改编了Mac上两项最有创造性的应用——GarageBand和iMovie，开发了适用于iPad的版本，功能强大。','1540-1601',5,1705844463,1782480561);
INSERT INTO highlights VALUES('635722_96_755-783','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','那样，保护盖就可以覆盖iPad的正面而无须包裹整个设备。','755-783',5,1705844312,1782480561);
INSERT INTO highlights VALUES('635722_96_713-755','635722',96,'第四十章 飞向太空：云端，飞船，宇宙无限','磁铁的吸引力可以被精确地聚焦在一个锥形区域里，这也许可以用于连接一个可分离的保护盖。','713-755',5,1705844300,1782480561);
INSERT INTO highlights VALUES('635722_95_10668-10730','635722',95,'第三十九章 新的战斗：昔日重现','但事实上，他的表述冷静而直接。他用了四个简短的陈述句：“我们不完美。手机不完美。我们都知道这一点。但是我们想要让用户满意。”','10668-10730',5,1705812080,1782480561);
INSERT INTO highlights VALUES('635722_95_10581-10622','635722',95,'第三十九章 新的战斗：昔日重现','没有卑躬屈膝，也没有道歉，只表示苹果理解这个问题并会尽力改正，这样他就得以平息问题','10581-10622',5,1705812067,1782480561);
INSERT INTO highlights VALUES('635722_95_10024-10097','635722',95,'第三十九章 新的战斗：昔日重现','在回忆这段经历时，乔布斯有些热泪盈眶。“我愿意再经历一次这样的事件，只要想让他有机会看看我工作时的样子。”他说，“他应该看看自己的父亲在做什么。”','10024-10097',5,1705811802,1782480561);
INSERT INTO highlights VALUES('635722_95_9966-10023','635722',95,'第三十九章 新的战斗：昔日重现','这两天你能学到的东西比在商学院两年还多。”他对里德说，“你将会和世界上最优秀的人才共处一室，看看一切是如何运作的。','9966-10023',5,1705811790,1782480561);
INSERT INTO highlights VALUES('635722_95_7780-7827','635722',95,'第三十九章 新的战斗：昔日重现','Mac和iPod的成功，让他们更加坚信自己的信念——了不起的设计能够激发工程师作出超人的壮举。','7780-7827',5,1705811409,1782480561);
INSERT INTO highlights VALUES('635722_95_5495-5528','635722',95,'第三十九章 新的战斗：昔日重现','他是否会认为iPad和‘革命’根本没什么关系？革命的核心是自由。”','5495-5528',5,1705811055,1782480561);
INSERT INTO highlights VALUES('635722_95_3084-3134','635722',95,'第三十九章 新的战斗：昔日重现','我喜欢为整个用户体验负责。我们做这些不是为钱，而是因为我们想要创造伟大的产品，而非安卓这样的垃圾。”','3084-3134',5,1705809592,1782480561);
INSERT INTO highlights VALUES('635722_94_16616-16683','635722',94,'第三十八章 iPad：后PC时代','如果有人订阅了我们的杂志，我们需要知道订阅者是谁，我们需要能够建立与订阅者达成互动的网上社区，我们需要有直接向他们发送续订信息的权力。','16616-16683',5,1705808821,1782480561);
INSERT INTO highlights VALUES('635722_94_15362-15402','635722',94,'第三十八章 iPad：后PC时代','乔布斯曾建议他们月收费定价5美元，然而《纽约时报》最终的定价接近其建议定价的4倍','15362-15402',5,1705808582,1782480561);
INSERT INTO highlights VALUES('635722_94_14531-14571','635722',94,'第三十八章 iPad：后PC时代','不管他们愿不愿意。我认为，他们搞清楚如何对数字内容进行收费，这对整个美国都很重要','14531-14571',5,1705808425,1782480561);
INSERT INTO highlights VALUES('635722_94_14242-14299','635722',94,'第三十八章 iPad：后PC时代','重要的是，出版商担心，在苹果的系统下，他们无法再与订阅用户建立直接联系，无法获取订阅用户的电子邮件地址和信用卡号，','14242-14299',5,1705808411,1782480561);
INSERT INTO highlights VALUES('635722_94_13187-13222','635722',94,'第三十八章 iPad：后PC时代','他们可以在iBook商店中任意设置图书价格，苹果则从销售中提成30%。','13187-13222',5,1705808253,1782480561);
INSERT INTO highlights VALUES('635722_94_12692-12737','635722',94,'第三十八章 iPad：后PC时代','但是应用程序的兴起也意味着牺牲网络的开放性和连接性。应用程序之间不易建立连接，也不易搜索。','12692-12737',5,1705808203,1782480561);
INSERT INTO highlights VALUES('635722_94_12310-12342','635722',94,'第三十八章 iPad：后PC时代','截至2011年6月，苹果公司已向应用程序开发者支付了25亿美元。','12310-12342',5,1705808151,1782480561);
INSERT INTO highlights VALUES('635722_94_12050-12098','635722',94,'第三十八章 iPad：后PC时代','杂志和报纸看到了最后的希望，他们此前一直免费发布电子内容，也许能凭借应用程序对电子内容进行收费，','12050-12098',5,1705808124,1782480561);
INSERT INTO highlights VALUES('635722_94_11957-11978','635722',94,'第三十八章 iPad：后PC时代','应用程序商店在一夜之间创造了一个新的产业。','11957-11978',5,1705808104,1782480561);
INSERT INTO highlights VALUES('635722_94_11481-11568','635722',94,'第三十八章 iPad：后PC时代','乔布斯很快就想到了一个两全其美的好办法。他将允许外部开发人员编写应用程序，但是他们必须遵循严格的标准——接受苹果公司的测试和批准，并且只能通过iTunes商店出售自己的应用。','11481-11568',5,1705808054,1782480561);
INSERT INTO highlights VALUES('635722_94_11302-11344','635722',94,'第三十八章 iPad：后PC时代','他认为其团队没有精力解决授权第三方应用程序开发者所涉及的复杂问题。他希望团队能专注。','11302-11344',5,1705808013,1782480561);
INSERT INTO highlights VALUES('635722_94_10273-10323','635722',94,'第三十八章 iPad：后PC时代','他意识到自己不想偏离自己所谓的苹果的声音。对乔布斯来说，苹果的声音有一系列特质：简单、干净、宣告式。','10273-10323',5,1705807848,1782480561);
INSERT INTO highlights VALUES('635722_94_9541-9596','635722',94,'第三十八章 iPad：后PC时代','乔布斯认为，在未来一年左右的时间里，其他公司会跟风推出平板电脑，而他希望人们记住，iPad才是真正的平板电脑。','9541-9596',5,1705807757,1782480561);
INSERT INTO highlights VALUES('635722_94_5618-5666','635722',94,'第三十八章 iPad：后PC时代','他对iPad的唯一保留意见就是：“虽然它是进行内容消费的好设备，但是对于内容创造并无多大助益。”','5618-5666',5,1705772366,1782480561);
INSERT INTO highlights VALUES('635722_94_2835-2918','635722',94,'第三十八章 iPad：后PC时代','我们没有继续合作的原因有二。一是他们真的很慢，就像蒸汽轮船一样，不是很灵活，而我们习惯快速前进。二是我们不想把什么都教给他们，因为他们可能会把我们的东西卖给竞争对手。','2835-2918',5,1705772007,1782480561);
INSERT INTO highlights VALUES('635722_94_2672-2709','635722',94,'第三十八章 iPad：后PC时代','我们的A4芯片将处理器、显卡、移动操作系统和内存控制都集成于一个芯片之中。','2672-2709',5,1705771973,1782480561);
INSERT INTO highlights VALUES('635722_94_2196-2233','635722',94,'第三十八章 iPad：后PC时代','于是，托尼·法德尔极力主张采用基于ARM的架构，其芯片更为简单，耗电更少。','2196-2233',5,1705771910,1782480561);
