INSERT INTO highlights VALUES('635722_93_858-899','635722',93,'第三十七章 第二回合：癌症复发','部分原因是他切除了大部分胰脏，而胰脏的功能是分泌消化蛋白质和其他营养素所需要的酶。','858-899',5,1705754067,1782480561);
