INSERT INTO highlights VALUES('635722_92_9289-9337','635722',92,'第三十六章 iPhone：三位一体','至2010年底，苹果公司已售出9000万部iPhone，其利润占全球手机市场利润总额的一半以上。','9289-9337',5,1705735339,1782480561);
INSERT INTO highlights VALUES('635722_92_8760-8886','635722',92,'第三十六章 iPhone：三位一体','今天，我们将推出三款这一水准的革命性产品。第一个是宽屏触控式iPod，第二个是一款革命性的手机，第三个是突破性的互联网通信设备。”他又将这句话重复了一遍以示强调，然后他问道：“你们明白了吗？这不是三台独立的设备，而是一台设备，我们称它为iPhone。”','8760-8886',5,1705735261,1782480561);
INSERT INTO highlights VALUES('635722_92_7676-7720','635722',92,'第三十六章 iPhone：三位一体','而这也意味着，必须重新设计制作手机内部的电路板、天线和处理器，但是乔布斯认可了这种改动。','7676-7720',5,1705735090,1782480561);
INSERT INTO highlights VALUES('635722_92_6596-6655','635722',92,'第三十六章 iPhone：三位一体','威克斯的办公室很通风，里面只摆放着一件纪念品画框，写着iPhone推出后乔布斯发来的信息：“如果没有你，我们做不到。”','6596-6655',5,1705734910,1782480561);
INSERT INTO highlights VALUES('635722_92_6111-6153','635722',92,'第三十六章 iPhone：三位一体','“你能闭嘴吗。”威克斯插话道，“让我来给你讲讲科学好吗？”乔布斯吃了一惊，陷入沉默。','6111-6153',5,1705734855,1782480561);
