INSERT INTO highlights VALUES('635722_92_5222-5243','635722',92,'第三十六章 iPhone：三位一体','这种材料是将铝进行酸浴和电镀，使其表面氧化','5222-5243',5,1705734735,1782480561);
INSERT INTO highlights VALUES('635722_92_4685-4740','635722',92,'第三十六章 iPhone：三位一体','当然，图标都是按照乔布斯最喜爱的形状进行设计的，这是比尔·阿特金森为第一款Mac电脑设计的软件形状：圆角矩形。','4685-4740',5,1705734638,1782480561);
INSERT INTO highlights VALUES('635722_92_4586-4624','635722',92,'第三十六章 iPhone：三位一体','解决方案是“移动滑块来解锁”，屏幕上简单有趣的滑块，用来激活处于休眠中的机器','4586-4624',5,1705734614,1782480561);
INSERT INTO highlights VALUES('635722_92_3816-3891','635722',92,'第三十六章 iPhone：三位一体','2005年初，苹果公司悄悄收购了该公司及其全部专利，两位创始人也受雇于苹果。FingerWorks不再将其产品销售给他人，并将新专利归入苹果公司名下。','3816-3891',5,1705734534,1782480561);
INSERT INTO highlights VALUES('635722_92_1422-1474','635722',92,'第三十六章 iPhone：三位一体','乔布斯及其团队十分兴奋，因为他们看到了打造一款自己想用的手机的前景。“这是最好的动力。”乔布斯后来说道。','1422-1474',5,1705733107,1782480561);
INSERT INTO highlights VALUES('635722_91_12150-12178','635722',91,'第三十五章 第一回合：死之警示','“我认为，如果苹果天生能够多一点点合作精神，会非常好。”','12150-12178',5,1705720763,1782480561);
