INSERT INTO highlights VALUES('635722_91_8214-8268','635722',91,'第三十五章 第一回合：死之警示','当年在罗伯特·弗里德兰的农场，他的工作是给苹果树剪枝，以让它们茁壮成长，这一举动后来成为他精简苹果公司的隐喻','8214-8268',5,1705690569,1782480561);
