INSERT INTO highlights VALUES('635722_91_5925-5959','635722',91,'第三十五章 第一回合：死之警示','做他的替补很难，出风头了该死，不出众也该死。库克成功避开了这些危险。','5925-5959',5,1705689264,1782480561);
