INSERT INTO highlights VALUES('635722_86_12287-12388','635722',86,'第三十章 数字中枢：从iTunes到iPod','开关键是没有必要的，从美学和神学的角度来看，开关让人不快。如果一段时间不操作，它会自动进入休眠状态；当你触摸任意按键时，它又会自动“醒来”。但是没有必要专门设定这样一个流程：按下去——等待关机——再见。','12287-12388',5,1705415415,1782480561);
INSERT INTO highlights VALUES('635722_86_11177-11274','635722',86,'第三十章 数字中枢：从iTunes到iPod','“我一直在想怎么浏览播放列表。你不可能按几百次按钮。如果有个转盘岂不是很好？”通过大拇指旋转转盘，你可以滚动所有的歌曲。而且你转的时间越长，列表下拉的速度就越快，所以你可以很容易地浏览几百首歌。','11177-11274',5,1705414605,1782480561);
INSERT INTO highlights VALUES('635722_86_4367-4426','635722',86,'第三十章 数字中枢：从iTunes到iPod','我们是唯一一家掌握硬件、软件、操作系统全部设备的公司。我们能够为用户体验负全部的责任，我们能做到其他公司做不到的事情。','4367-4426',5,1705409325,1782480561);
