INSERT INTO highlights VALUES('635722_86_2600-2676','635722',86,'第三十章 数字中枢：从iTunes到iPod','当所有人都在削减开支的时候，我们反而决定要在情况低迷时继续投资。我们主要会投资在研发上面，发明出一些新东西，一旦低潮期过去，我们就已经领先于竞争对手了。','2600-2676',5,1705398803,1782480561);
