INSERT INTO highlights VALUES('635722_86_1812-1890','635722',86,'第三十章 数字中枢：从iTunes到iPod','人们被卡在这些固有的形式中，就像唱片中某一段固定的凹槽，他们永远无法摆脱出来。当然，有些人天生就有强烈的好奇心，永远有一颗孩子般的心，可惜这样的人太稀少了。','1812-1890',5,1705390515,1782480561);
