INSERT INTO highlights VALUES('635722_85_887-1014','635722',85,'第二十九章 苹果零售店：天才吧和锡耶纳沙石','其中一个候选人热爱设计，他就像是天生的零售商一般拥有孩童般的热情——罗恩·约翰逊(Ron Johnson)当时是塔吉特公司(Target)负责销售规划的副总裁，主要工作是发布外观独特的新产品，比如迈克尔·格雷夫斯(Michael Graves)设计的茶壶','887-1014',5,1705339203,1782480561);
