INSERT INTO highlights VALUES('635722_85_1638-1715','635722',85,'第二十九章 苹果零售店：天才吧和锡耶纳沙石','他认为苹果零售店应该开在繁华街区的购物中心里——那种区域客流大——无论租金有多贵。他说：“我们不能让顾客驱车10英里去看我们的产品，而是要在10步之内。”','1638-1715',5,1705339048,1782480561);
