INSERT INTO highlights VALUES('635722_84_9302-9357','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','乔布斯回答：“我从来没有在期权的问题上坚持过，但是你曾建议说，我最多能拿到公司5%的期权，这就是我现在想要的。','9302-9357',5,1705212261,1782480561);
INSERT INTO highlights VALUES('635722_84_9176-9207','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','但是乔布斯的回应出乎所有人的意料，他想要更多：“2000万份。','9176-9207',5,1705212236,1782480561);
INSERT INTO highlights VALUES('635722_84_7450-7485','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','每一页幻灯片他都要改上六七次。在每一次演讲前，我都会陪他准备几个晚上。','7450-7485',5,1705211927,1782480561);
INSERT INTO highlights VALUES('635722_84_5475-5528','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','所有图标都在屏幕的下方排成一排，当年轻人把鼠标停在某一个图标上时，鼠标就会像放大镜一样把那个图标膨胀变大。','5475-5528',5,1705179976,1782480561);
INSERT INTO highlights VALUES('635722_84_5190-5271','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','我一直把罗伯特·奥本海默(J.Robert Oppenheimer)视为榜样。我知道他在建立原子弹项目小组时的招聘要求。我没有他那么优秀，但这是我渴望达到的目标。','5190-5271',5,1705179897,1782480561);
INSERT INTO highlights VALUES('635722_84_4890-4921','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','对生活中的许多事情来说，“最佳”和“一般”之间大约相差30%。','4890-4921',5,1705179849,1782480561);
INSERT INTO highlights VALUES('635722_84_4956-4986','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','但是当我见到沃兹尼亚克时，我认为他比普通工程师要优秀50倍。','4956-4986',5,1705179845,1782480561);
INSERT INTO highlights VALUES('635722_84_4464-4693','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','因为他坚信，苹果公司的一个巨大优势就是各类资源的整合，从设计、硬件、软件，直到内容。他希望公司的所有部门都能够并行合作。他把这称为“深度合作”(deep collaboration)和“并行工程”(concurrent engineering)。所以，一个产品的开发过程并不是像流水线一样先从工程到设计，再到营销，最后分销；相反，这些部门是同时进行工作的。“我们的方针就是开发高度整合的产品，这也意味着我们的生产过程也必须是通过整合和协作完成的。”乔布斯说。','4464-4693',5,1705179786,1782480561);
INSERT INTO highlights VALUES('635722_84_3885-3921','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','作为一家注重时尚风格的公司，索尼聘请了著名设计师三宅一生为他们设计制服。','3885-3921',5,1705155217,1782480561);
INSERT INTO highlights VALUES('635722_84_3731-3782','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','他看起来非常惭愧地告诉我，在战后，人们都没有衣服穿，所以像索尼这样的公司必须要给员工提供每天的衣物。”','3731-3782',5,1705155193,1782480561);
INSERT INTO highlights VALUES('635722_84_3429-3499','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','到1998年初，乔布斯把两个月的库存期缩短到一个月。然而到了同年9月底，库克已经把库存期缩短到6天；第二年的9月，这个数字已经达到惊人的两天','3429-3499',5,1705154092,1782480561);
INSERT INTO highlights VALUES('635722_84_3211-3299','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','30分钟后，他看着还在桌前坐着的一位运营主管，面无表情地说：“你怎么还没走？”那位主管站起来，没带任何行李，直接开车去了旧金山机场，买了机票飞往中国。他后来成了库克的第一副手。','3211-3299',5,1705154047,1782480561);
INSERT INTO highlights VALUES('635722_84_2991-3032','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','尽管库克也会感到开心，但他一贯的表情就是皱眉，他的幽默感也是一本正经的、不露声色的','2991-3032',5,1705154021,1782480561);
INSERT INTO highlights VALUES('635722_84_2908-2936','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','他在每周日的晚上都要安排电话会议，为下一周的工作做准备。','2908-2936',5,1705154007,1782480561);
INSERT INTO highlights VALUES('635722_84_2860-2907','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','大多数日子里，他都会在凌晨4点半起床，收发邮件，然后去健身房运动一个小时，6点刚过就到达办公室','2860-2907',5,1705153995,1782480561);
INSERT INTO highlights VALUES('635722_84_2704-2738','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','我的直觉告诉我，加入苹果，为一个创意天才工作，这是我这一生唯一的机会','2704-2738',5,1705153975,1782480561);
INSERT INTO highlights VALUES('635722_84_2658-2696','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','在乔布斯首次面试我的5分钟之内，我就决定把谨慎和逻辑都抛在脑后，我要加入苹果','2658-2696',5,1705153969,1782480561);
INSERT INTO highlights VALUES('635722_84_2504-2535','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','库克先是在奥本大学学习工业工程，随后又在杜克大学取得商业学位。','2504-2535',5,1705153951,1782480561);
INSERT INTO highlights VALUES('635722_84_2094-2144','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','1998年，他遇到了蒂姆·库克。当时蒂姆·库克37岁，彬彬有礼，是康柏计算机公司的采购和供应链经理。','2094-2144',5,1705153895,1782480561);
INSERT INTO highlights VALUES('635722_84_1226-1264','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','他还放下了对产品制造过程的控制欲，把从电路板到成品计算机的制造全部外包了出去','1226-1264',5,1705153783,1782480561);
INSERT INTO highlights VALUES('635722_84_1011-1111','635722',84,'第二十八章 CEO：多年之后，疯狂依旧','乔布斯开始投入到一些以细节为导向的很现实的工作里，这让曾经与他共过事的人很惊讶，之前的他充满了奇思妙想，世间的条条框框似乎在他身上毫无约束作用。“他成为了一个经理人，而非之前的身份——行政官或空想家。','1011-1111',5,1705153757,1782480561);
INSERT INTO highlights VALUES('635722_83_8811-8893','635722',83,'第二十七章 iMac：“你好（又见面了）”','它导致了苹果公司无法满足用户想要自己刻录音乐光盘的需求，但是这也恰恰促使苹果公司发挥想象力，大胆地寻找一条越级攀升的道路，直到后来，乔布斯意识到他必须进军音乐市场。','8811-8893',5,1705078262,1782480561);
INSERT INTO highlights VALUES('635722_83_6234-6292','635722',83,'第二十七章 iMac：“你好（又见面了）”','因此，乔布斯特意为这次发布会选择了库比蒂诺市迪安扎社区学院的燧石礼堂(Flint)，这也是举办1984年发布会的地点','6234-6292',5,1705078037,1782480561);
INSERT INTO highlights VALUES('635722_83_5191-5204','635722',83,'第二十七章 iMac：“你好（又见面了）”','‘去他妈的！不够蓝！！！’','5191-5204',5,1705077378,1782480561);
INSERT INTO highlights VALUES('635722_83_2503-2527','635722',83,'第二十七章 iMac：“你好（又见面了）”','他们还在iMac外壳的顶部设计了一个内嵌的提手。','2503-2527',5,1704951221,1782480561);
INSERT INTO highlights VALUES('635722_83_2129-2181','635722',83,'第二十七章 iMac：“你好（又见面了）”','乔布斯一直坚持要让芯片整齐地排列在电路板上，即使它们不会被人们看到也要这么做。但现在，它们能被人看见了。','2129-2181',5,1704951189,1782480561);
INSERT INTO highlights VALUES('635722_83_2016-2062','635722',83,'第二十七章 iMac：“你好（又见面了）”','这就是我们喜欢半透明的原因。虽然有固定的颜色，却又不呆板，可以一眼看到里面，有种调皮的感觉。','2016-2062',5,1704951173,1782480561);
INSERT INTO highlights VALUES('635722_83_1798-1856','635722',83,'第二十七章 iMac：“你好（又见面了）”','然而直到那时，也没有人提出过什么东西让苹果计算机与市面上的其他计算机相比多么与众不同。这一次，乔布斯终于有了新玩意儿','1798-1856',5,1704904329,1782480561);
INSERT INTO highlights VALUES('635722_82_6609-6660','635722',82,'第二十六章 设计原则：乔布斯和艾夫的工作室','要知道，人们会根据封面来评判一本书的好坏——同理，苹果产品漂亮的外部装饰和包装也能说明里面是个好产品。','6609-6660',5,1704901469,1782480561);
INSERT INTO highlights VALUES('635722_82_5222-5280','635722',82,'第二十六章 设计原则：乔布斯和艾夫的工作室','他一进门，就会查看几张桌子上那些正在设计的产品，看看它们是否符合苹果公司的发展战略，并亲手检查每一个产品的演进设计。','5222-5280',5,1704901245,1782480561);
INSERT INTO highlights VALUES('635722_82_4198-4263','635722',82,'第二十六章 设计原则：乔布斯和艾夫的工作室','但对于乔布斯来说，这个过程截然不同。在苹果公司创立之初，乔布斯首先确定了Mac电脑的外壳之后，工程师们才依此制造合适的主板和元件。','4198-4263',5,1704901079,1782480561);
INSERT INTO highlights VALUES('635722_82_3613-3665','635722',82,'第二十六章 设计原则：乔布斯和艾夫的工作室','但是对于我而言，‘设计’一词绝无任何引申含义。设计是一个人工作品的核心灵魂，并最终不断地由外壳表达出来。','3613-3665',5,1704900980,1782480561);
INSERT INTO highlights VALUES('635722_82_3543-3570','635722',82,'第二十六章 设计原则：乔布斯和艾夫的工作室','设计不仅是关于产品的外观，而且必须要反映出产品的精髓。','3543-3570',5,1704900950,1782480561);
INSERT INTO highlights VALUES('635722_82_2046-2053','635722',82,'第二十六章 设计原则：乔布斯和艾夫的工作室','乔吉·乔治亚罗','2046-2053',5,1704861720,1782480561);
INSERT INTO highlights VALUES('635722_81_10258-10301','635722',81,'第二十五章 非同凡想：iCEO乔布斯','在两列的顶端，他写上“消费级”和“专业级”。在两行的标题处，他写上“台式”和“便携”。','10258-10301',5,1704818924,1782480561);
INSERT INTO highlights VALUES('635722_81_10202-10241','635722',81,'第二十五章 非同凡想：iCEO乔布斯','他抓起神奇的记号笔，走向白板，在上面画了一根横线一根竖线，做成一个方形四格表。','10202-10241',5,1704818916,1782480561);
INSERT INTO highlights VALUES('635722_81_8458-8526','635722',81,'第二十五章 非同凡想：iCEO乔布斯','他的核心原则之一就是硬件和软件应该紧密结合。他喜欢控制生活中的方方面面，而对计算机来说，唯一的方式就是制造全套设备，全方面负责用户体验。','8458-8526',5,1704818570,1782480561);
INSERT INTO highlights VALUES('635722_81_8311-8390','635722',81,'第二十五章 非同凡想：iCEO乔布斯','每卖出一台兼容机，苹果收取80美元的授权费，但是这些兼容机并没有让苹果扩大市场，反而挤压了苹果自己的高端计算机销售，而卖出一台苹果电脑的利润能达到500美元。','8311-8390',5,1704818559,1782480561);
INSERT INTO highlights VALUES('635722_81_7310-7404','635722',81,'第二十五章 非同凡想：iCEO乔布斯','我发现有时最好的创新就是你组织一家公司的方式，”他回忆说，“如何建设一家公司，这整个概念都让人着迷。当我有机会回到苹果时我意识到，如果没有这家公司我就毫无价值，因此我决定留下来重新建设它。','7310-7404',5,1704818399,1782480561);
INSERT INTO highlights VALUES('635722_81_5674-5720','635722',81,'第二十五章 非同凡想：iCEO乔布斯','1997年9月16日，乔布斯宣布他将接手这个职务，临时CEO这一名称也自然被缩写成了iCEO','5674-5720',5,1704817506,1782480561);
INSERT INTO highlights VALUES('635722_81_4255-4287','635722',81,'第二十五章 非同凡想：iCEO乔布斯','但是李·克劳有了另一个想法。如果乔布斯自己读这段画外音会怎么样？','4255-4287',5,1704817057,1782480561);
INSERT INTO highlights VALUES('635722_81_2242-2285','635722',81,'第二十五章 非同凡想：iCEO乔布斯','你可以认同他们，反对他们，颂扬或是诋毁他们。但唯独不能漠视他们。因为他们改变了寻常事物','2242-2285',5,1704816715,1782480561);
INSERT INTO highlights VALUES('635722_81_1374-1419','635722',81,'第二十五章 非同凡想：iCEO乔布斯','其创意目的并不是赞美计算机可以做什么，而是赞美富有创造力的人们在计算机的辅助下可以做什么。','1374-1419',5,1704816586,1782480561);
INSERT INTO highlights VALUES('635722_81_1498-1536','635722',81,'第二十五章 非同凡想：iCEO乔布斯','要回想起你是谁的方法之一，就是要想起你的偶像是谁。这就是那次宣传活动的缘起。','1498-1536',5,1704816570,1782480561);
INSERT INTO highlights VALUES('635722_80_20417-20461','635722',80,'第二十四章 复出：此刻的失败者终将胜利','盖茨的脸上露出淡淡的微笑，抑或是傻笑。观众全都惊得目瞪口呆，紧接着嘘声和倒彩声响成一片。','20417-20461',5,1704811262,1782480561);
INSERT INTO highlights VALUES('635722_80_19972-20019','635722',80,'第二十四章 复出：此刻的失败者终将胜利','“比尔，感谢你对这家公司的支持。”穿着短裤的乔布斯蹲在那儿说，“我想世界因为有它会变得更好。”','19972-20019',5,1704811207,1782480561);
INSERT INTO highlights VALUES('635722_80_19201-19259','635722',80,'第二十四章 复出：此刻的失败者终将胜利','比尔一直都对苹果狠不起来。是我们让他进入了应用软件领域。微软的第一批应用软件就是为Mac开发的Excel和Word。','19201-19259',5,1704811102,1782480561);
INSERT INTO highlights VALUES('635722_80_17906-17965','635722',80,'第二十四章 复出：此刻的失败者终将胜利','全场掌声雷动，人们都站起来，满怀敬畏地互相看着，有人还在擦拭脸上的泪水。乔布斯清楚地表明，他和苹果的“我们”是一体的。','17906-17965',5,1704810880,1782480561);
INSERT INTO highlights VALUES('635722_80_17722-17777','635722',80,'第二十四章 复出：此刻的失败者终将胜利','买苹果电脑的人就是有与众不同的思维方式。他们代表了这个世界的创新精神，他们要去改变世界。我们为这种人制造工具。','17722-17777',5,1704810847,1782480561);
INSERT INTO highlights VALUES('635722_80_15816-15888','635722',80,'第二十四章 复出：此刻的失败者终将胜利','坎贝尔曾在哥伦比亚做过橄榄球教练，据乔布斯说，他的伟大天才就是“可以让二流球员发挥出一流水平”。乔布斯告诉他，在苹果，他可以跟一流球员一起工作。','15816-15888',5,1704778354,1782480561);
INSERT INTO highlights VALUES('635722_80_15047-15263','635722',80,'第二十四章 复出：此刻的失败者终将胜利','接下来的时间他们探讨了苹果未来的发展重点。乔布斯雄心勃勃地想建立一家可以长盛不衰的公司，他问马库拉如何实现。马库拉回答说，长盛不衰的公司都知道如何重塑自我。惠普就是在不断这样做：它以生产小仪器起家，后来成为生产计算器的公司，再后来成为生产计算机的公司。“苹果在个人电脑领域被微软挤出了局。”马库拉说，“你必须重塑公司，做点儿其他东西，比如其他消费品或电子设备。你必须化蛹成蝶，完成彻底的蜕变。”乔布斯没多说什么，但是他同意这一观点。','15047-15263',5,1704778179,1782480561);
INSERT INTO highlights VALUES('635722_80_13938-13978','635722',80,'第二十四章 复出：此刻的失败者终将胜利','本应宣告胜利并感谢董事会，乔布斯却继续不满于必须向一个自己并不敬佩的董事会汇报。','13938-13978',5,1704777374,1782480561);
INSERT INTO highlights VALUES('635722_80_12929-12962','635722',80,'第二十四章 复出：此刻的失败者终将胜利','乔布斯给出了正确答案。“产品糟透了！”他嚷道，“它们不再性感了！”','12929-12962',5,1704777224,1782480561);
INSERT INTO highlights VALUES('635722_80_12682-12721','635722',80,'第二十四章 复出：此刻的失败者终将胜利','这样，自从整整12年前7月4日那个周末丧失大权后，乔布斯重新登上了苹果的前台。','12682-12721',5,1704777182,1782480561);
INSERT INTO highlights VALUES('635722_80_10952-10991','635722',80,'第二十四章 复出：此刻的失败者终将胜利','他不喜欢处理复杂的事物，也不想委曲求全，无论是产品、设计还是房子装修，都是如此','10952-10991',5,1704776966,1782480561);
INSERT INTO highlights VALUES('635722_80_7891-7936','635722',80,'第二十四章 复出：此刻的失败者终将胜利','阿梅里奥和斯卡利这样的人都愿意相信，既然乔布斯在向他们施展魅力，就意味着他喜欢和尊重他们。','7891-7936',5,1704729168,1782480561);
INSERT INTO highlights VALUES('635722_80_3506-3541','635722',80,'第二十四章 复出：此刻的失败者终将胜利','乔布斯的第一步动作，就是确保用他从NeXT带来的两个朋友接替她的职责。','3506-3541',5,1704728541,1782480561);
INSERT INTO highlights VALUES('635722_80_2756-2973','635722',80,'第二十四章 复出：此刻的失败者终将胜利','阿梅里奥啰唆了两个多小时，最后终于把所有人都等着为之欢呼的人请上了台。“乔布斯大步跨上舞台，自信而有型，魅力四射，跟阿梅里奥的笨手笨脚形成了鲜明对照。”卡尔顿写道，“即使是猫王归来也不会引起比这更大的轰动。”观众纷纷起立，震耳欲聋的掌声持续了超过一分钟。杂乱无章的10年就此终结。最后，他挥手请大家安静，直入主题。“我们要再创辉煌。”他说，“Mac 10年来没有什么进步，所以Windows赶上来了。我们必须拿出一个更好的操作系统。”','2756-2973',5,1704728417,1782480561);
INSERT INTO highlights VALUES('635722_80_1250-1404','635722',80,'第二十四章 复出：此刻的失败者终将胜利','他既没有埃利森那种明显的消费需求，也没有比尔·盖茨那种投身慈善事业的内在冲动，亦没有那种想看看自己在《福布斯》排行榜上能爬多高的竞争意识。在他那自我意识的需求和个人动力的驱使下，他要通过创造足以令世人敬畏的传奇来获得满足。这实际上包括两个方面：制造不断革新不断变化的伟大产品，以及建立一家有持久生命力的公司。','1250-1404',5,1704728039,1782480561);
INSERT INTO highlights VALUES('635722_80_972-1037','635722',80,'第二十四章 复出：此刻的失败者终将胜利','但是从他1995年步入40岁以后，却成就卓著。那一年《玩具总动员》发行上映，第二年苹果收购NeXT，使他一举重返他当年创建的公司。','972-1037',5,1704727940,1782480561);
INSERT INTO highlights VALUES('635722_79_11368-11450','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','“我一直在想，这将导致我有很多时间不能陪伴家人，也有很多时间不能陪在另一个家——皮克斯。”乔布斯说，“但我想做这件事的唯一原因是，这个世界如果有苹果就会变得更好。”','11368-11450',5,1704727795,1782480561);
INSERT INTO highlights VALUES('635722_79_10556-10695','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰',unistr('我昨晚一夜没睡。”乔布斯回答。\u000a“为什么？出了什么事？”\u000a“我在思考所有要做的事情，还有我们这个交易，都压在了一起。我现在真的很累，想不清楚。不要再问我任何问题了。”'),'10556-10695',5,1704727647,1782480561);
INSERT INTO highlights VALUES('635722_79_10013-10097','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','他们最后买来的是一个大多数人认为做不好CEO的人，因为他对此没什么经验，但他是个才华横溢的家伙，有出色的设计品位和技术品位。他适当地掩饰了疯狂，就被任命为临时CEO了。','10013-10097',5,1704727533,1782480561);
INSERT INTO highlights VALUES('635722_79_9405-9467','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','后来，当乔布斯把他赶出苹果后，阿梅里奥回忆起乔布斯那天的友善，伤感地说：“我痛苦地发现，那只是一个极端复杂人格的一个侧面。”','9405-9467',5,1704727442,1782480561);
INSERT INTO highlights VALUES('635722_79_9177-9276','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','阿梅里奥已经暗下决心，“我要按照自己的逻辑往前推进”，并且“要回避他的人格魅力”。但是在散步过程中，跟其他很多人一样，他完全陷入了乔布斯的“力场”。“我被史蒂夫的旺盛精力和热情吸引住了。”他回忆说。','9177-9276',5,1704727395,1782480561);
INSERT INTO highlights VALUES('635722_79_3932-4025','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','“我会买下苹果，你作为CEO会立即获得25%的股份，我们可以重现它过去的辉煌。”但是乔布斯却表示反对。“我认定我不是那种能做恶意收购的人，”他解释说，“如果他们请我回去，那就不一样了。”','3932-4025',5,1704725898,1782480561);
INSERT INTO highlights VALUES('635722_79_3503-3536','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','微软只是剽窃他人的成果，然后坚持下去，利用它对IBM兼容机的控制。','3503-3536',5,1704725782,1782480561);
INSERT INTO highlights VALUES('635722_79_1472-1525','635722',79,'第二十三章 再度降临 何等野兽，终于等到它的时辰','出乎意料的是，乔布斯当时的一个拥护者竟是让-路易·加西，他曾经取代了乔布斯在苹果的职务，后来也被逐出苹果。','1472-1525',5,1704725510,1782480561);
INSERT INTO highlights VALUES('635722_78_8681-8705','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','他创造了他的时代中最好的两个品牌——苹果和皮克斯','8681-8705',5,1704604187,1782480561);
INSERT INTO highlights VALUES('635722_78_7597-7625','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','我的未来不需要游艇，”他说，“我做这个从来都不是为了钱。','7597-7625',5,1704603997,1782480561);
INSERT INTO highlights VALUES('635722_78_7440-7550','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','当年早些时候，乔布斯还曾经希望把皮克斯卖掉，收回他投资的5000万美元。而股票公开发行第一天结束时，他持有的公司80%的股票价值就已经涨到原来的20多倍，达到惊人的12亿美元，相当于1980年苹果上市时他获得收益的5倍。','7440-7550',5,1704603982,1782480561);
INSERT INTO highlights VALUES('635722_78_7305-7347','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','然而事实证明，发行之成功甚至超出了他最大胆的想象，一举超过网景成为当年最大的IPO。','7305-7347',5,1704603954,1782480561);
INSERT INTO highlights VALUES('635722_78_7039-7082','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','“我意识到，我们必须跟迪士尼重新签合同，这样我们才能建一个电影公司而不是只当个供应商。','7039-7082',5,1704603918,1782480561);
INSERT INTO highlights VALUES('635722_78_1968-2006','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','玩具，它们的使命就是供孩子们玩耍，因此它们的恐惧就是被抛弃或被新的玩具取代。','1968-2006',5,1704528692,1782480561);
INSERT INTO highlights VALUES('635722_78_1642-1775','635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','1991年5月达成的协议是：迪士尼将完全拥有影片及其角色的版权，并控制创作权，可以在任何时候以很少的违约金为代价停掉这部影片，有权利（而无义务）制作皮克斯接下来的两部电影，也有权（不一定跟皮克斯一起）使用该影片的角色制作续集；而皮克斯则获得票房分成的大约12.5%。','1642-1775',5,1704528593,1782480561);
INSERT INTO highlights VALUES('635722_77_9094-9151','635722',77,'第二十一章 有家之人：与家人在一起','尽管乔布斯当时已经再度入主苹果，是一个世界闻名的亿万富翁，他还是没有保镖，也没有住家的佣人，他甚至白天都不锁后门。','9094-9151',5,1704431834,1782480561);
INSERT INTO highlights VALUES('635722_77_9063-9094','635722',77,'第二十一章 有家之人：与家人在一起','盖茨问，他当时正在西雅图附近建造一处66000平方英尺的豪宅。','9063-9094',5,1704431823,1782480561);
INSERT INTO highlights VALUES('635722_77_6238-6255','635722',77,'第二十一章 有家之人：与家人在一起','其中霍莫的妈妈就是用了他妻子的名字','6238-6255',5,1704418377,1782480561);
INSERT INTO highlights VALUES('635722_77_3812-3849','635722',77,'第二十一章 有家之人：与家人在一起','乔布斯回答说，他需要确切地感觉到劳伦可以受得了他过的这种生活以及他这种人。','3812-3849',5,1704416435,1782480561);
INSERT INTO highlights VALUES('635722_77_3736-3770','635722',77,'第二十一章 有家之人：与家人在一起','1990年的第一天，她接受了他的求婚，之后他有几个月都没再提这件事。','3736-3770',5,1704416419,1782480561);
INSERT INTO highlights VALUES('635722_77_3575-3623','635722',77,'第二十一章 有家之人：与家人在一起','史蒂夫会走两个极端，有时高度专注，好像她是宇宙的中心，而有时又表现出冷漠的距离感，专注在工作上。','3575-3623',5,1704416402,1782480561);
INSERT INTO highlights VALUES('635722_77_1095-1141','635722',77,'第二十一章 有家之人：与家人在一起','在停车场追上她说：“不好意思，不是说你赢了彩票，我应该请你吃饭吗？”她大笑。“周六怎么样？”','1095-1141',5,1704348000,1782480561);
INSERT INTO highlights VALUES('635722_77_511-649','635722',77,'第二十一章 有家之人：与家人在一起','聪明，而不自负；足够刚强能承受跟他在一起的压力，又足够超脱能免于争端；受过良好教育，独立，又愿意为他和家庭而做出改变；能适应现实，却又带着点儿超凡脱俗；足够世故知道怎么管理他，又有足够的安全感不用总是管着他；当然最好还是个漂亮苗条的金发美女，平易近人，有幽默感，喜欢有机素食。','511-649',5,1704345682,1782480561);
INSERT INTO highlights VALUES('635722_76_13034-13110','635722',76,'第二十章 凡人：爱就那么回事','她后来回忆，爱上一个如此以自我为中心的人，那种痛苦令人难以置信。深深地关心一个似乎没有能力关心别人的人，那是一种特殊的地狱般的感觉，她不愿任何人去体验。','13034-13110',5,1704294501,1782480561);
INSERT INTO highlights VALUES('635722_76_12985-13013','635722',76,'第二十章 凡人：爱就那么回事','她曾在通向他们卧室的走廊墙壁上写道：“忽视是一种虐待。”','12985-13013',5,1704294480,1782480561);
INSERT INTO highlights VALUES('635722_76_9266-9357','635722',76,'第二十章 凡人：爱就那么回事','还在很小的年纪，莉萨就开始意识到他的饮食癖好反映了一种人生哲学：苦行和极简将会让人更加敏锐。“他相信匮乏即是富足，自律产生喜悦。”她说，“他知道一个大多数人不知道的道理：物极必反。”','9266-9357',5,1704293958,1782480561);
INSERT INTO highlights VALUES('635722_76_8143-8179','635722',76,'第二十章 凡人：爱就那么回事','有一个圣诞节乔布斯曾跟母亲说：“别担心，我的童年很棒。我好好地长大了。”','8143-8179',5,1704293840,1782480561);
INSERT INTO highlights VALUES('635722_76_7965-8006','635722',76,'第二十章 凡人：爱就那么回事','“我觉得没有人真正知道我们到底该在那里做些什么，你干预也是完蛋，不干预也是完蛋。”','7965-8006',5,1704293797,1782480561);
INSERT INTO highlights VALUES('635722_76_6697-6719','635722',76,'第二十章 凡人：爱就那么回事','是真的，他来过，而且他很友善，小费给得很多。','6697-6719',5,1704293601,1782480561);
INSERT INTO highlights VALUES('635722_76_6660-6688','635722',76,'第二十章 凡人：爱就那么回事','所有科技界的成功人士都会去那儿，甚至包括史蒂夫·乔布斯。','6660-6688',5,1704293591,1782480561);
INSERT INTO highlights VALUES('635722_75_11119-11148','635722',75,'第十九章 皮克斯：技术与艺术相遇','“命运似乎诱骗我去做这件事，而这也许是为了把它做得更好。”','11119-11148',5,1704292558,1782480561);
INSERT INTO highlights VALUES('635722_75_6841-6866','635722',75,'第十九章 皮克斯：技术与艺术相遇','皮克斯是在融合艺术与科技，就像Mac曾经做的那样。','6841-6866',5,1704259536,1782480561);
INSERT INTO highlights VALUES('635722_75_6454-6484','635722',75,'第十九章 皮克斯：技术与艺术相遇','台灯爸爸和台灯孩子把一个球推来推去，后来球爆了，小台灯很伤心','6454-6484',5,1704259494,1782480561);
INSERT INTO highlights VALUES('635722_75_6200-6218','635722',75,'第十九章 皮克斯：技术与艺术相遇','拉塞特的办公桌上放着一盏Luxo台灯','6200-6218',5,1704259420,1782480561);
INSERT INTO highlights VALUES('635722_75_5469-5502','635722',75,'第十九章 皮克斯：技术与艺术相遇','也展露出了他的惊人天才——赋予无生命的东西（譬如台灯）以人的个性。','5469-5502',5,1704259310,1782480561);
INSERT INTO highlights VALUES('635722_75_4868-4917','635722',75,'第十九章 皮克斯：技术与艺术相遇','皮克斯的数字动画业务——制作动画短片的团队——最初只是副业，其主要目的是对外展示自己的硬件和软件。','4868-4917',5,1704259256,1782480561);
INSERT INTO highlights VALUES('635722_75_4645-4729','635722',75,'第十九章 皮克斯：技术与艺术相遇','1988年，这套设备首次投入使用，负责制作动画片《小美人鱼》(The Little Mermaid)中的最后一幕','4645-4729',5,1704259230,1782480561);
INSERT INTO highlights VALUES('635722_75_2804-2879','635722',75,'第十九章 皮克斯：技术与艺术相遇','“硅谷的人并不尊重好莱坞的创意特质，而好莱坞的人则认为技术人员是那些只需雇用而无须见面的人。”乔布斯后来说道，“皮克斯则同时尊重好莱坞和硅谷的文化。”','2804-2879',5,1704256156,1782480561);
INSERT INTO highlights VALUES('635722_75_2640-2693','635722',75,'第十九章 皮克斯：技术与艺术相遇','于是我们发出了一套信号——摸鼻子或拽耳朵。如果有人陷入了史蒂夫的现实扭曲力场，我们会用这一招把他拉回现实。','2640-2693',5,1704256065,1782480561);
INSERT INTO highlights VALUES('635722_75_2159-2166','635722',75,'第十九章 皮克斯：技术与艺术相遇','皮克斯图像电脑','2159-2166',5,1704255916,1782480561);
INSERT INTO highlights VALUES('635722_75_1228-1275','635722',75,'第十九章 皮克斯：技术与艺术相遇','不过很快就有了一个折中办法：乔布斯出资购买多数股权，并担任董事长，但由卡特穆尔和史密斯来运营。','1228-1275',5,1704244726,1782480561);
INSERT INTO highlights VALUES('635722_75_1304-1510','635722',75,'第十九章 皮克斯：技术与艺术相遇','“我之所以想收购这个部门，是因为我真的很喜欢计算机图形。”乔布斯后来回忆道，“看到卢卡斯影业电脑部门这些人的时候，我意识到，在融合艺术与技术的领域，他们走在了其他人前面，而这个领域一直都是我的兴趣所在。”乔布斯知道，在未来数年里，计算机将会比现在强大上百倍，他相信这会给动画和逼真的3D图形带来巨大进步。“卢卡斯团队正在研究的问题需要非常强大的计算处理能力，这使我意识到他们必将引领历史。我喜欢这样的发展方向。”','1304-1510',5,1704244710,1782480561);
INSERT INTO highlights VALUES('635722_75_658-666','635722',75,'第十九章 皮克斯：技术与艺术相遇','卢卡斯天行者牧场','658-666',5,1704242346,1782480561);
INSERT INTO highlights VALUES('635722_75_593-634','635722',75,'第十九章 皮克斯：技术与艺术相遇','卡特穆尔当时是乔治·卢卡斯(George Lucas)电影制片厂电脑部门的负责人。','593-634',5,1704242336,1782480561);
INSERT INTO highlights VALUES('635722_74_21331-21364','635722',74,'第十八章 NeXT：自由的普罗米修斯','苏珊·卡雷是NeXT的图形设计师，她为Mac设计了最初的字体和图标','21331-21364',5,1704123582,1782480561);
INSERT INTO highlights VALUES('635722_74_20555-20598','635722',74,'第十八章 NeXT：自由的普罗米修斯','乔布斯希望直到10月份NeXT电脑隆重推出之前，都不让比尔·盖茨知道他与IBM的合作。','20555-20598',5,1704123424,1782480561);
INSERT INTO highlights VALUES('635722_74_20078-20118','635722',74,'第十八章 NeXT：自由的普罗米修斯','尤为意义重大的是，NeXT电脑面向对象的操作系统NeXTSTEP受到了格外关注。','20078-20118',5,1704112618,1782480561);
INSERT INTO highlights VALUES('635722_74_19203-19277','635722',74,'第十八章 NeXT：自由的普罗米修斯','Mac电脑借图形界面推出了革命性的新方法。现在，NeXT通过将面向对象的编程方法与采用光盘为存储介质的功能强大的计算机捆绑起来，正在引领新一轮的革命','19203-19277',5,1704112617,1782480561);
INSERT INTO highlights VALUES('635722_74_13959-14025','635722',74,'第十八章 NeXT：自由的普罗米修斯','到发布时，NeXT电脑还将囊括一部字典、一部百科汇编和一部《牛津引语词典》，这使得NeXT电脑成为实现可搜索式电子书概念的先驱之一。','13959-14025',5,1704098151,1782480561);
INSERT INTO highlights VALUES('635722_74_13176-13273','635722',74,'第十八章 NeXT：自由的普罗米修斯','在大堂的中心，乔布斯委托贝聿铭设计了一段宏伟的楼梯，看上去就像飘浮在空中一样。承建商表示这个设计没法实现，但乔布斯坚持能够做到，最终也确实建成了。多年后，乔布斯把这款楼梯变成了苹果零售店的特色。','13176-13273',5,1704097769,1782480561);
INSERT INTO highlights VALUES('635722_74_6927-6973','635722',74,'第十八章 NeXT：自由的普罗米修斯','仅仅5个月，他就将所有的苹果股票都卖掉了，只留下了1股，这样如果自己愿意，就能参加股东会议。','6927-6973',5,1704085196,1782480561);
INSERT INTO highlights VALUES('635722_74_6409-6464','635722',74,'第十八章 NeXT：自由的普罗米修斯','然而雅达利公司的创始人、10年前便成为乔布斯良师益友的诺兰·布什内尔对《时代》杂志表示，他们会非常想念乔布斯。','6409-6464',5,1704085148,1782480561);
INSERT INTO highlights VALUES('635722_74_2513-2559','635722',74,'第十八章 NeXT：自由的普罗米修斯','尽管乔布斯名义上仍然是该公司的董事长，但自从失去实权后，他就再没有参加过苹果公司的任何会议。','2513-2559',5,1704084628,1782480561);
INSERT INTO highlights VALUES('635722_74_2723-2863','635722',74,'第十八章 NeXT：自由的普罗米修斯','他根据已经准备好的便笺，描述了自己的计划——为高等教育市场开发一款计算机。他承诺，新公司不会同苹果公司存在竞争关系，并且只会带走少数非关键员工。他提出辞去苹果公司董事长一职，但希望仍能与苹果公司合作。乔布斯提议，也许苹果愿意购买其产品的经销权，或者授权新公司的产品使用Mac软件。','2723-2863',5,1704084374,1782480561);
INSERT INTO highlights VALUES('635722_74_1002-1081','635722',74,'第十八章 NeXT：自由的普罗米修斯','“为什么不在计算机上进行模拟实验呢？”乔布斯问道，“这样不仅你自己能够更快地开展实验，而且，终有一天，美国的微生物学新生都会用到保罗·伯格的基因重组软件。”伯','1002-1081',5,1704079970,1782480561);
INSERT INTO highlights VALUES('635722_74_1316-1339','635722',74,'第十八章 NeXT：自由的普罗米修斯','学术研究人员的梦想是拥有一台强大的个人工作站。','1316-1339',5,1704007981,1782480561);
INSERT INTO highlights VALUES('635722_73_30018-30042','635722',73,'第十七章 伊卡洛斯： 凡升起的……','俄罗斯人有了Mac以后就能打印他们所有的报纸了。','30018-30042',5,1704007745,1782480561);
INSERT INTO highlights VALUES('635722_73_29908-29950','635722',73,'第十七章 伊卡洛斯： 凡升起的……','在巴黎的贸易展上，副总统老布什刚刚鼓励过他把计算机引入苏联，以“掀起自下而上的革命”','29908-29950',5,1704007732,1782480561);
INSERT INTO highlights VALUES('635722_73_29615-29721','635722',73,'第十七章 伊卡洛斯： 凡升起的……','尤为难忘的是铺路石，它们都来自托斯卡纳小镇附近费伦佐拉的一家采石场Il Casone。这些石头有着沉静的蓝灰色，颜色饱满悦目。20年后，他决定，大部分大型苹果店的地面就要用来自Il Casone采石场的砂岩铺设。','29615-29721',5,1704007690,1782480561);
INSERT INTO highlights VALUES('635722_73_28158-28191','635722',73,'第十七章 伊卡洛斯： 凡升起的……','乔布斯沮丧地认为，自从《路上的血迹》这张专辑后，迪伦就在走下坡路。','28158-28191',5,1704007464,1782480561);
INSERT INTO highlights VALUES('635722_73_27187-27237','635722',73,'第十七章 伊卡洛斯： 凡升起的……','我还是难以想象，董事会居然赶走了史蒂夫。虽然他有时候会很难相处，但很明显，他是苹果公司的心脏和灵魂。','27187-27237',5,1704007321,1782480561);
INSERT INTO highlights VALUES('635722_73_22354-22396','635722',73,'第十七章 伊卡洛斯： 凡升起的……','乔布斯看上去都快崩溃了。“我想我知道大家的立场了。”他说完冲出了房间。没有人追上去。','22354-22396',5,1704005479,1782480561);
INSERT INTO highlights VALUES('635722_73_13939-14004','635722',73,'第十七章 伊卡洛斯： 凡升起的……','乔布斯这种行为显得很小气，但他之所以如此，部分原因是他知道产品的外观和风格就是产品品牌的一部分，其他人不像乔布斯这样明白这个道理。','13939-14004',5,1704002373,1782480561);
INSERT INTO highlights VALUES('635722_73_12941-13024','635722',73,'第十七章 伊卡洛斯： 凡升起的……','沮丧万分的沃兹尼亚克决定悄然离去，创办一家新公司，制造自己发明的万能遥控器。有了这个装置，用户只需通过几个简单的按钮，就能控制家里的电视机、立体声音响和其他电子设备。','12941-13024',5,1704002240,1782480561);
INSERT INTO highlights VALUES('635722_73_12851-12912','635722',73,'第十七章 伊卡洛斯： 凡升起的……','沃兹尼亚克甚至强迫自己去做一些与性格不相符的事。有一天，他拿起电话打给斯卡利，痛斥他在乔布斯和Mac部门浪费了太多注意力。','12851-12912',5,1704002219,1782480561);
INSERT INTO highlights VALUES('635722_73_10569-10666','635722',73,'第十七章 伊卡洛斯： 凡升起的……','外界越是试图强化你的形象，你就越难继续做一名艺术家，这也是为什么很多艺术家要说，“再见，我得走了，我要疯了，我要离开这里。”然后他们就离开了，在某处休隐。也许之后他们又会重新出现，变得有些不同。','10569-10666',5,1704001758,1782480561);
INSERT INTO highlights VALUES('635722_73_10465-10538','635722',73,'第十七章 伊卡洛斯： 凡升起的……','如果你想让自己的生活过得富有创造性，像艺术家一样，就不能常常回顾过去。不管你做过什么，以前是怎么样，你都必须心甘情愿地接受一切，并将一切抛诸脑后。','10465-10538',5,1704001739,1782480561);
INSERT INTO highlights VALUES('635722_73_10314-10434','635722',73,'第十七章 伊卡洛斯： 凡升起的……','我会永远保持与苹果的关系。我希望这一生，能让自己的生命历程和苹果的命运彼此交错，就像编织一幅挂毯那样。可能我会离开苹果几年，但我终究是会回来的。而这就是我可能想要做的事情。关于我，应该谨记的关键一点就是，我仍然是个学生，我仍然在新兵训练营。','10314-10434',5,1704001728,1782480561);
INSERT INTO highlights VALUES('635722_73_9030-9096','635722',73,'第十七章 伊卡洛斯： 凡升起的……','请柬上写着：“有句古老的印度谚语是这样说的，‘在人生的头30年里，你培养习惯；在后30年，习惯塑造你。’过来跟我庆祝我的30岁吧。”','9030-9096',5,1704001521,1782480561);
INSERT INTO highlights VALUES('635722_73_7132-7200','635722',73,'第十七章 伊卡洛斯： 凡升起的……','乔布斯在绝望之下作出了一个低劣而又不合规矩的决定。他决定在库存的莉萨电脑上安装Mac仿真程序，并作为新产品出售，命名为“Mac XL”。','7132-7200',5,1704001245,1782480561);
INSERT INTO highlights VALUES('635722_73_1888-1928','635722',73,'第十七章 伊卡洛斯： 凡升起的……','Mac的经验告诉我，一流队员只喜欢同一流队员合作，这就意味着你不能容忍二流队员。','1888-1928',5,1704000687,1782480561);
INSERT INTO highlights VALUES('635722_72_9246-9357','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','并不是狭义上的没有品位，而是广义上的，他们没有独到的见解，也不会在产品中注入多少文化……因此，我想自己之所以感到难过并不是因为微软成功了，我对他们的成功没有异议，大部分都是他们应得的。我难过的是，他们做的确实只是三流产品。','9246-9357',5,1704000465,1782480561);
INSERT INTO highlights VALUES('635722_72_9218-9241','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','微软唯一的问题就是他们没有品位，一点儿都没有。','9218-9241',5,1704000457,1782480561);
INSERT INTO highlights VALUES('635722_72_9106-9173','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','虽然一开始微软只做出了一系列粗制滥造的复制品，它最终还是赢得了操作系统之争。这一事实说明世界并非完美：最好、最创新的产品并非总是赢家。','9106-9173',5,1704000448,1782480561);
INSERT INTO highlights VALUES('635722_72_8299-8393','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','微软有权在其即将推出的Windows系统中使用苹果公司的部分图形功能。作为回报，微软同意继续为Mac编写软件，并且在一段时间内，只允许苹果独家使用Excel软件，而不会用于IBM兼容机中。','8299-8393',5,1704000341,1782480561);
INSERT INTO highlights VALUES('635722_72_8036-8129','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','很久，在迪安扎学院来来回回，他们停下一起吃了晚饭，然后又接着往前走。“我们不得不边走边说，但我并不擅长这个，”盖茨说道，“这时候他开始说，‘好吧，好吧，只是你们别搞得太像我们做的东西了。','8036-8129',5,1704000295,1782480561);
INSERT INTO highlights VALUES('635722_72_7881-7959','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','有那么一会儿他几乎都快哭了，就好像在说，‘哦，就让我宣泄一下自己的痛楚吧。’”盖茨则变得非常平静。“别人情绪激动的时候，对我更有利，因为我比较不容易激动。”','7881-7959',5,1704000252,1782480561);
INSERT INTO highlights VALUES('635722_72_7619-7681','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','人此次的交涉也清晰地表明，苹果和微软的共生关系就如两只蝎子跳舞，双方都小心翼翼地周旋，他们知道无论谁出刺都会给双方造成问题。','7619-7681',5,1704000183,1782480561);
INSERT INTO highlights VALUES('635722_72_7479-7537','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','我觉得现在的情况更接近于这样——我们都有个有钱的邻居，叫施乐，我闯进他们家准备偷电视机的时候，发现你已经把它盗走了。','7479-7537',5,1704000161,1782480561);
INSERT INTO highlights VALUES('635722_72_6705-6759','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','因此，1983年11月，盖茨宣布微软计划为IBM个人电脑开发Windows操作系统，此举完全在其权利范围内。','6705-6759',5,1704000029,1782480561);
INSERT INTO highlights VALUES('635722_72_3907-3943','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','盖茨不信，坚持认为必须有某种特殊硬件的支持，光标才会出现这样的移动效果。','3907-3943',5,1703999629,1782480561);
INSERT INTO highlights VALUES('635722_72_3255-3318','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','盖茨签下了合同，除BASIC程序外，还为苹果公司开发图形界面版本的软件——全新的电子表格软件Excel和文字处理程序Word。','3255-3318',5,1703999537,1782480561);
INSERT INTO highlights VALUES('635722_72_3220-3255','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','1982年，苹果公司的年销售额达10亿美元，而微软只有3200万美元。','3220-3255',5,1703999520,1782480561);
INSERT INTO highlights VALUES('635722_72_1780-1806','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','而盖茨有时会无法与人进行眼神接触，但他很富有人情味儿','1780-1806',5,1703999296,1782480561);
INSERT INTO highlights VALUES('635722_72_1394-1475','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','与乔布斯不同，盖茨懂计算机编程。他更务实、更有原则，且拥有很强的分析处理能力；乔布斯则更相信直觉、更浪漫，并且在技术实用化、设计愉悦感和界面友好方面有着更高的天分','1394-1475',5,1703999248,1782480561);
INSERT INTO highlights VALUES('635722_72_1251-1290','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','而是为学校编写排课程序，在这个程序的帮助下，他得以和自己心仪的女孩上同样的课程','1251-1290',5,1703999173,1782480561);
INSERT INTO highlights VALUES('635722_72_969-1032','635722',72,'第十六章 盖茨与乔布斯：当轨道相交','在其发展的头30年中，出现了两位重量级人物，他们都生于1955年，都中途辍学，精力充沛，他们演绎了个人电脑领域的“双星系统”。','969-1032',5,1703999141,1782480561);
INSERT INTO highlights VALUES('635722_71_11359-11427','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','礼堂里一片喧闹，人们又蹦又跳，疯狂地挥舞着拳头。乔布斯缓缓地点了点头，双唇紧闭但笑得很开心，接着他低下头开始哽咽。掌声持续了将近5分钟。','11359-11427',5,1703990240,1782480561);
INSERT INTO highlights VALUES('635722_71_11191-11244','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','我还不习惯公开演讲，但我想要和大家分享自己第一次见到IBM大型机时的感想。千万不要相信一台你搬不动的电脑。','11191-11244',5,1703990205,1782480561);
INSERT INTO highlights VALUES('635722_71_8624-8695','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','乔布斯完全被语音发生器所折服，这个程序能够将文本转变为迷人的电子语音。他决定以此作为演示的一部分：“我要Mac成为第一台可以自我介绍的电脑！”','8624-8695',5,1703989537,1782480561);
INSERT INTO highlights VALUES('635722_71_8054-8142','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','认软件是否存在问题，而大多数同事也和他一样。他们正躺在地板上，昏昏沉沉但又兴奋不已，这时候乔布斯走了进来。“嘿，赶紧起来，还没完呢！”他说道，“我们需要为Mac电脑做一个演示！','8054-8142',5,1703989422,1782480561);
INSERT INTO highlights VALUES('635722_71_6056-6132','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','广告的结尾处，人群惊恐地看着老大哥消失，此时，旁白平静地念道：“1月24日，苹果电脑公司将推出Mac电脑。你将明白为什么1984不会变成《1984》。”','6056-6132',5,1703989179,1782480561);
INSERT INTO highlights VALUES('635722_71_5571-5624','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','乔布斯说要80万美元。在一贯的善意冲动下，沃兹尼亚克立即提出：“好吧，如果你愿意出一半钱，我就付另一半。”','5571-5624',5,1703989102,1782480561);
INSERT INTO highlights VALUES('635722_71_3994-4038','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','然而在内心深处，乔布斯意识到自己正日益摒弃黑客精神。有些人甚至指责乔布斯出卖了黑客精神。','3994-4038',5,1703988917,1782480561);
INSERT INTO highlights VALUES('635722_71_2784-2848','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','过了一会儿，苹果公司位于弗雷蒙的工厂开始生产印有彩色条纹苹果标识的盒子。乔布斯曾称，真正的艺术家总能完成作品，现在他们名副其实。','2784-2848',5,1703988817,1782480561);
INSERT INTO highlights VALUES('635722_71_2002-2053','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','一直以来，乔布斯都将自己想象成一个抗击黑暗势力的反叛者，并从中获取能量。现在，他也这样激发自己的团队。','2002-2053',5,1703988035,1782480561);
INSERT INTO highlights VALUES('635722_71_1845-1901','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','难道让IBM主宰整个电脑产业吗？难道让IBM控制整个信息时代吗？难道乔治·奥威尔在《1984》中的描述会成真吗？','1845-1901',5,1703988022,1782480561);
INSERT INTO highlights VALUES('635722_71_1345-1420','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','但1983年的数据则呈现了大逆转：Apple Ⅱ电脑销量42万台，IBM个人电脑及其同类产品销量130万台，而Apple Ⅲ电脑和莉萨电脑都彻底失败。','1345-1420',5,1703987967,1782480561);
INSERT INTO highlights VALUES('635722_71_1262-1294','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','但是其快速增长的那部分收入则来自为IBM个人电脑编写的操作系统。','1262-1294',5,1703987945,1782480561);
INSERT INTO highlights VALUES('635722_71_1094-1163','635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','要创建新标准并非只作出一点不同的东西就够了，而是需要真正全新且能抓住人们想象力的东西。在我见过的所有机器中，只有Mac电脑符合这一标准。”','1094-1163',5,1703987918,1782480561);
INSERT INTO highlights VALUES('635722_70_10104-10147','635722',70,'第十四章 斯卡利来了：百事挑战','这个决定让他感到他正在失去对自己的产品和公司的掌控，而这就如同把猛虎逼入角落一样危险。','10104-10147',5,1703987831,1782480561);
INSERT INTO highlights VALUES('635722_70_9995-10034','635722',70,'第十四章 斯卡利来了：百事挑战','于是乔布斯向他们承诺：“不用担心，我不会让他得逞的！”但最后还是斯卡利获胜了。','9995-10034',5,1703987814,1782480561);
INSERT INTO highlights VALUES('635722_70_9093-9148','635722',70,'第十四章 斯卡利来了：百事挑战','他正试图管理一家功能紊乱的公司，而他的管理存在一个弱点，那就是他总想取悦别人，而这个问题在乔布斯身上并不存在。','9093-9148',5,1703987646,1782480561);
INSERT INTO highlights VALUES('635722_70_8675-8743','635722',70,'第十四章 斯卡利来了：百事挑战','“我们的世界观、人生观、价值观都不同。”乔布斯说，“他来了几个月之后，我就开始认识到这点。他学东西并不快，而他想提拔的人往往都是些笨蛋。','8675-8743',5,1703987573,1782480561);
INSERT INTO highlights VALUES('635722_70_7886-7955','635722',70,'第十四章 斯卡利来了：百事挑战','乔布斯向斯卡利坦言，他觉得自己年轻的时候就会死去，因此他需要尽快取得成就，在硅谷的历史上留下自己的名字。“我们在这个世界上的时间都很短，”','7886-7955',5,1703982877,1782480561);
INSERT INTO highlights VALUES('635722_70_6993-7020','635722',70,'第十四章 斯卡利来了：百事挑战','“苹果和童子军有什么不同？答案是，童子军有大人管着。”','6993-7020',5,1703935012,1782480561);
INSERT INTO highlights VALUES('635722_70_6245-6293','635722',70,'第十四章 斯卡利来了：百事挑战','他向我抛出了一个问题，让我几天都无法释怀，‘你是想卖一辈子糖水呢，还是想抓住机会来改变世界？’”','6245-6293',5,1703934902,1782480561);
INSERT INTO highlights VALUES('635722_70_4833-4918','635722',70,'第十四章 斯卡利来了：百事挑战','“他是个不可思议的骗子，从头到尾都在装模作样。”他后来说道，“他装作对技术很感兴趣的样子，但其实他并不感兴趣。他是个搞营销的，这就是搞营销的人的本质——靠装模作样赚钱。”','4833-4918',5,1703934683,1782480561);
INSERT INTO highlights VALUES('635722_70_2515-2614','635722',70,'第十四章 斯卡利来了：百事挑战','投资店内营销，让顾客知道苹果公司的产品有丰富他们生活的潜力，从而吸引顾客。','2515-2614',5,1703934262,1782480561);
INSERT INTO highlights VALUES('635722_70_2106-2139','635722',70,'第十四章 斯卡利来了：百事挑战','尽管是在电影明星聚居地长大的，但对他们来说，乔布斯才是真正的名人。','2106-2139',5,1703934194,1782480561);
INSERT INTO highlights VALUES('635722_70_1543-1609','635722',70,'第十四章 斯卡利来了：百事挑战','他们决定不局限在技术高管这个圈子里。他们需要的是一位懂得广告宣传和市场研究的消费产品营销专家，得有大企业人士的风范，能在华尔街吃得开','1543-1609',5,1703934120,1782480561);
INSERT INTO highlights VALUES('635722_70_961-1001','635722',70,'第十四章 斯卡利来了：百事挑战','虽然跃跃欲试，但乔布斯知道自己还没有能力管理公司。他很高傲，但还是有自知之明的。','961-1001',5,1703899083,1782480561);
INSERT INTO highlights VALUES('635722_69_9690-9752','635722',69,'第十三章 制造Mac：过程就是奖励',unistr('史蒂夫，28岁生日快乐。过程就是奖励。\u000a——海盗们贺'),'9690-9752',5,1703863762,1782480561);
INSERT INTO highlights VALUES('635722_69_8909-8939','635722',69,'第十三章 制造Mac：过程就是奖励','真正的艺术家总能完成作品”(Real artists shi','8909-8939',5,1703863606,1782480561);
INSERT INTO highlights VALUES('635722_69_8170-8207','635722',69,'第十三章 制造Mac：过程就是奖励','“过程就是奖励。”(The journey is the reward.)','8170-8207',5,1703863445,1782480561);
INSERT INTO highlights VALUES('635722_69_4375-4424','635722',69,'第十三章 制造Mac：过程就是奖励','但最终，乔布斯并没有登上该杂志封面。《时代》将“计算机”选为了年终刊的主题，并称之为“年度机器”。','4375-4424',5,1703815783,1782480561);
INSERT INTO highlights VALUES('635722_69_3504-3552','635722',69,'第十三章 制造Mac：过程就是奖励','和其他的产品开发者不一样，乔布斯不相信顾客永远是正确的。如果他们抵制使用鼠标的话，那他们就错了。','3504-3552',5,1703815687,1782480561);
INSERT INTO highlights VALUES('635722_69_2371-2407','635722',69,'第十三章 制造Mac：过程就是奖励','如果一台电脑要兼容那些在其他电脑上也能运行的软件，它必定要牺牲一些功能。','2371-2407',5,1703815529,1782480561);
INSERT INTO highlights VALUES('635722_69_1179-1235','635722',69,'第十三章 制造Mac：过程就是奖励','IBM本质上就是最差状态下的微软公司。他们不是创新的力量，而是邪恶的力量。IBM就像AT&T、微软或者谷歌一样。','1179-1239',5,1703815356,1782480561);
INSERT INTO highlights VALUES('635722_69_1108-1141','635722',69,'第十三章 制造Mac：过程就是奖励','他告诉一个采访者，“一旦IBM控制了市场，他们几乎总是会停止创新。','1108-1141',5,1703814619,1782480561);
INSERT INTO highlights VALUES('635722_69_1051-1107','635722',69,'第十三章 制造Mac：过程就是奖励','如果因为某个原因，我们酿下大错，IBM战胜了我们，那我个人的感觉就是，我们将进入计算机领域长达20年的黑暗时代。','1051-1107',5,1703814613,1782480561);
INSERT INTO highlights VALUES('635722_69_956-1010','635722',69,'第十三章 制造Mac：过程就是奖励','乔布斯在整个职业生涯中，都喜欢把自己看作一位对抗邪恶帝国的反抗者，一名与黑暗力量做斗争的绝地战士或佛教武士。','956-1010',5,1703814599,1782480561);
INSERT INTO highlights VALUES('635722_69_873-927','635722',69,'第十三章 制造Mac：过程就是奖励','而当时和苹果公司表现同样出色的康懋达公司、坦迪公司(Tandy)以及奥斯本，则被归入了“不相干公司”的行列。','873-927',5,1703814561,1782480561);
INSERT INTO highlights VALUES('635722_69_771-826','635722',69,'第十三章 制造Mac：过程就是奖励','有一件事展露出了苹果公司狂妄的自信：他们在《华尔街日报》上刊登了一幅整版广告，标题是：“欢迎IBM——真的。”','771-826',5,1703814542,1782480561);
INSERT INTO highlights VALUES('635722_68_9984-10061','635722',68,'第十二章 设计：大道至简','在图纸的正中间找到了一个位置，用小写字母潇洒地签下了自己的名字，然后他以香槟向大家祝酒。“在这样的时刻，他让我们觉得，自己的成果就是艺术品。”阿特金森说。','9984-10061',5,1703814490,1782480561);
INSERT INTO highlights VALUES('635722_68_9795-9839','635722',68,'第十二章 设计：大道至简','于是他拿出一张绘图纸和一支三福笔(Sharpie pen)，让所有人都签上了自己的名字。','9795-9839',5,1703814463,1782480561);
INSERT INTO highlights VALUES('635722_68_8795-8851','635722',68,'第十二章 设计：大道至简','从那时起，所有的苹果产品上都可以见到这句自豪的宣言：加利福尼亚设计(Designed in California','8795-8851',5,1703814311,1782480561);
INSERT INTO highlights VALUES('635722_68_7707-7773','635722',68,'第十二章 设计：大道至简','大约10分钟后，他终于得到了让自己满意的答案。毫无疑问，他的设计出现在了最终问世的Mac上，并在之后15年的时间里一直作为标准使用。','7707-7773',5,1703814128,1782480561);
INSERT INTO highlights VALUES('635722_68_7604-7675','635722',68,'第十二章 设计：大道至简','“史蒂夫·乔布斯自己动手做的计算器程序”。这个程序允许用户改变线条的粗细、按键的大小、阴影、背景及其他属性，从而实现计算器外观的调整和个性化。','7604-7675',5,1703814112,1782480561);
INSERT INTO highlights VALUES('635722_68_7345-7367','635722',68,'第十二章 设计：大道至简','学习的机会有很多，但研发Mac的机会只有一次','7345-7367',5,1703814076,1782480561);
INSERT INTO highlights VALUES('635722_68_7110-7212','635722',68,'第十二章 设计：大道至简','卡雷和阿特金森曾一度抱怨说，乔布斯在标题栏的修改上耗费了他们太多时间，而他们有更重要的事情要做。乔布斯大发脾气。“你能想象一下每天都要看着它是什么感觉吗？”他吼道，“这不是件小事，这是我们必须做好的事！”','7110-7212',5,1703814051,1782480561);
INSERT INTO highlights VALUES('635722_68_6693-6731','635722',68,'第十二章 设计：大道至简','卡雷也开发了图标——例如放置被删除文件的垃圾箱，图标也体现了图形界面的内涵。','6693-6731',5,1703813961,1782480561);
INSERT INTO highlights VALUES('635722_68_6500-6560','635722',68,'第十二章 设计：大道至简','事实上，Mac上各种漂亮的字体，再结合激光打印技术和强大的图形功能，推动了桌面出版产业的诞生，也成为了苹果公司的赢利点。','6500-6560',5,1703813928,1782480561);
INSERT INTO highlights VALUES('635722_68_4552-4577','635722',68,'第十二章 设计：大道至简','也能防止乔布斯坚称自己的某条建议或意见被忽视了。“','4552-4577',5,1703779615,1782480561);
INSERT INTO highlights VALUES('635722_68_2717-2796','635722',68,'第十二章 设计：大道至简','我问他，为什么电脑看上去就像笨重的电视机？为什么你们不把它做得薄一点儿？为什么不做成平板的便携式电脑？”乔布斯回答说，那正是他的目标，只是现在技术还没有成熟。','2717-2796',5,1703779369,1782480561);
INSERT INTO highlights VALUES('635722_68_2025-2102','635722',68,'第十二章 设计：大道至简','他反复强调，苹果公司的产品会是干净而简洁的。“我们会把产品做得光亮又纯净，能展现高科技感，而不是一味使用黑色、黑色、黑色，满是沉重的工业感，就像索尼那样。','2025-2102',5,1703777853,1782480561);
INSERT INTO highlights VALUES('635722_68_1920-1995','635722',68,'第十二章 设计：大道至简','我们要做的，就是让产品科技感十足，然后用上简单干净的包装，让科技感一目了然。我们会把产品放在小包装盒里，让它们看上去纯白漂亮，就像博朗生产的电器一样。','1920-1995',5,1703777839,1782480561);
INSERT INTO highlights VALUES('635722_68_1776-1869','635722',68,'第十二章 设计：大道至简','演讲在一个巨大的音乐帐篷中举行，乔布斯称赞了包豪斯风格的简单朴素，也预言了索尼风格的消亡。“当下工业设计的潮流就是索尼的那种高科技感，要么是金属灰色，要么就涂成黑色，加一些怪异的设计。”','1776-1869',5,1703777817,1782480561);
INSERT INTO highlights VALUES('635722_68_1549-1621','635722',68,'第十二章 设计：大道至简','密斯和格罗皮乌斯宣扬的准则中就包括“上帝就在细节之中”(God is in the details)和“少即是多”(Less is more)。','1549-1621',5,1703777788,1782480561);
INSERT INTO highlights VALUES('635722_68_1507-1524','635722',68,'第十二章 设计：大道至简','设计应该追求简约，同时具有表现精神','1507-1524',5,1703777669,1782480561);
INSERT INTO highlights VALUES('635722_67_7499-7539','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','但我想，如果能把我们两人的风格中和一下的话，结果会比只用史蒂夫的方式要好一点儿。','7499-7539',5,1703754581,1782480561);
INSERT INTO highlights VALUES('635722_67_7309-7361','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','尽管Mac电脑后来被证明是一件伟大的产品，但由于乔布斯的鲁莽干预，它的生产进度已远远落后，预算也严重超支','7309-7361',5,1703754561,1782480561);
INSERT INTO highlights VALUES('635722_67_6947-6978','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','乔布斯认为自己是艺术家，他鼓励设计团队的人也把自己当成艺术家。','6947-6978',5,1703754504,1782480561);
INSERT INTO highlights VALUES('635722_67_6753-6804','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','每天开机都要多用10秒钟，那加起来每年就要浪费大约3亿分钟，而3亿分钟相当于至少100个人的终身寿命。','6753-6804',5,1703754483,1782480561);
INSERT INTO highlights VALUES('635722_67_6674-6710','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','乔布斯问道：“如果能救人一命的话，你愿意想办法让启动时间缩短10秒钟吗？','6674-6710',5,1703754469,1782480561);
INSERT INTO highlights VALUES('635722_67_6361-6420','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','1981年4月，在西海岸电脑展览会上，亚当·奥斯本(Adam Osborne)发布了第一款真正意义上的便携式个人电脑。','6361-6420',5,1703754419,1782480561);
INSERT INTO highlights VALUES('635722_67_6031-6074','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','“我们把‘这是狗屎’解读为一个问句，它真实的意思是，‘告诉我，这为什么是最好的方法？’','6031-6074',5,1703754362,1782480561);
INSERT INTO highlights VALUES('635722_67_5304-5392','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','但如果你平静而自信，如果乔布斯审视你一番后认为你清楚自己在干什么，他就会很尊重你。多年来，无论是在他的私人生活还是职业生涯中，他的核心圈子里聚集的都是真正的强者，而不是谄媚者。','5304-5392',5,1703754219,1782480561);
INSERT INTO highlights VALUES('635722_67_4558-4599','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','安·鲍尔斯(Ann Bowers)成为应对乔布斯的完美主义、任性及强硬性格的专家。','4558-4599',5,1703754165,1782480561);
INSERT INTO highlights VALUES('635722_67_5033-5086','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','他是如此聪慧，也如此缺少爱。他需要一位成熟的、父亲一般的角色的陪伴，鲍勃就是，而我则成为了母亲一样的角色。','5033-5086',5,1703754154,1782480561);
INSERT INTO highlights VALUES('635722_67_4244-4291','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','乔布斯作出这些极端的行为是因为他缺乏情感上的敏感性吗？不，恰恰相反。他的情感理解能力是超强的。','4244-4291',5,1703754070,1782480561);
INSERT INTO highlights VALUES('635722_67_2621-2678','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','乔布斯从没有研究过尼采，但他的天性与尼采的一些思想不谋而合：对权力的渴望，以及“超人”(Überman)的特殊本性','2621-2678',5,1703753859,1782480561);
INSERT INTO highlights VALUES('635722_67_2402-2441','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','现实扭曲力场的根源在于乔布斯内心深处不可动摇的信念：世界上的规则都不适用于他。','2402-2441',5,1703753830,1782480561);
INSERT INTO highlights VALUES('635722_67_1289-1342','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','现实扭曲力场是几种因素的混合物，其中包含了极富魅力的措辞风格、不屈的意志和让现实屈从于自己意图的热切渴望。','1289-1342',5,1703753516,1782480561);
INSERT INTO highlights VALUES('635722_67_1120-1144','635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','那一集中，外星人通过极致的精神力量建造了新世界。','1120-1144',5,1703753492,1782480561);
INSERT INTO highlights VALUES('635722_66_7991-8033','635722',66,'第十章 Mac诞生了：你说你想要一场革命……','斯科特已经变得越来越反复无常。他时而横行霸道、恃强凌弱，时而又会鼓励下属、培养员工。','7991-8033',5,1703753375,1782480561);
INSERT INTO highlights VALUES('635722_66_6555-6619','635722',66,'第十章 Mac诞生了：你说你想要一场革命……','如果他们两眼放光，立刻拿起鼠标开始操作，史蒂夫就会微笑着雇用他们。”安德烈娅·坎宁安回忆说，“他就是想看到他们喊出一声‘哇！’”','6555-6619',5,1703753168,1782480561);
INSERT INTO highlights VALUES('635722_66_2038-2091','635722',66,'第十章 Mac诞生了：你说你想要一场革命……','阿特金森在苹果的服务部门发现了在那里工作的史密斯，惊叹于他随时想出补救方法的能力，于是将他推荐给了拉斯金。','2038-2091',5,1703752153,1782480561);
INSERT INTO highlights VALUES('635722_66_802-872','635722',66,'第十章 Mac诞生了：你说你想要一场革命……','拉斯金是个很有哲学家范儿的人，有时幽默顽皮，有时又呆板沉闷，他学习过计算机科学，教过音乐和视觉艺术，管理过一家室内歌剧院，还组织过街头剧场。','802-872',5,1703751940,1782480561);
INSERT INTO highlights VALUES('635722_66_1188-1258','635722',66,'第十章 Mac诞生了：你说你想要一场革命……','然而拉斯金认为，用女人的名字命名电脑带有性别歧视的意味，所以他更换了项目代号，用的是自己最喜欢的一种苹果的名字：Mac(McIntosh)。','1188-1258',5,1703751896,1782480561);
INSERT INTO highlights VALUES('635722_65_5556-5758','635722',65,'第九章 上市：名利双收','“我上学的时候，20世纪60年代的那股思潮刚过，实用主义、目的性很强的社会风气还没有盛行，”他说，“现在的孩子根本不愿意用理想主义的方式来思考，连接近理想主义都谈不上。他们自然不会让现今的任何哲学问题占用他们太多的时间，因为他们要忙于学习自己的商科专业。”他说，自己那一代人就不一样。“20世纪60年代的理想主义之风仍然影响着我们，我认识的与我年龄相仿的人中，大多数人的心里都永远打上了理想主义的烙印。”','5556-5758',5,1703751805,1782480561);
INSERT INTO highlights VALUES('635722_65_3351-3411','635722',65,'第九章 上市：名利双收','和自己的父亲一样，乔布斯在和供应商讨价还价的时候态度也十分坚定，但他不允许对利润的追求凌驾于他对制造伟大产品的狂热之上。','3351-3411',5,1703737305,1782480561);
INSERT INTO highlights VALUES('635722_65_3240-3278','635722',65,'第九章 上市：名利双收','他出行的时候从不会有浩浩荡荡的随行人员，他也没有个人助理，甚至从未雇过保镖。','3240-3278',5,1703737282,1782480561);
INSERT INTO highlights VALUES('635722_65_3093-3118','635722',65,'第九章 上市：名利双收','不管多么富有，乔布斯居住的房子从来都是朴实低调的，','3097-3122',5,1703737270,1782480561);
INSERT INTO highlights VALUES('635722_65_2815-2892','635722',65,'第九章 上市：名利双收','他是个反对物质主义的嬉皮士，但他把朋友准备免费送出的发明转化成了获利的工具；他是佛教禅宗的狂热信徒，在印度进行过朝圣之旅，但之后又认定创业才是自己的使命。','2815-2892',5,1703737207,1782480561);
INSERT INTO highlights VALUES('635722_65_2647-2670','635722',65,'第九章 上市：名利双收','在25岁这一年，他的身家达到了2.56亿美元。','2647-2670',5,1703737187,1782480561);
INSERT INTO highlights VALUES('635722_65_2481-2562','635722',65,'第九章 上市：名利双收',unistr('特意识到，体系中存在着基本的不公平，他提出了自己的想法：在IPO之前，通过反向竞拍来为股票定价。\u000a'),'2485-2533',5,1703737167,1782480561);
INSERT INTO highlights VALUES('635722_65_2224-2303','635722',65,'第九章 上市：名利双收','一家是传统的华尔街公司摩根士丹利；另一家是旧金山的汉布里克特-奎斯特(Hambrecht & Quist)，这并不是一家传统的投行，当时的服务只针对部分领域。','2224-2307',5,1703737122,1782480561);
INSERT INTO highlights VALUES('635722_65_1811-1855','635722',65,'第九章 上市：名利双收','在苹果的股票公开上市之前，他就把自己期权中的2000份以极低的价格卖给了40名中层员工。','1811-1855',5,1703733878,1782480561);
INSERT INTO highlights VALUES('635722_65_981-1048','635722',65,'第九章 上市：名利双收','丹尼尔·科特基却不在其中。他一直都是乔布斯的挚友，两人一起读大学，一起去印度，一起待在团结农场，一起经历了克里斯安·布伦南的怀孕风波。','981-1048',5,1703729597,1782480561);
INSERT INTO highlights VALUES('635722_64_9194-9254','635722',64,'第八章 施乐和莉萨：图形用户界面','他同时被解除了研发部门副总裁的职务，被任命为董事会的非执行主席，也就是说，他依然代表苹果公司的公众形象，但手中再无实权。','9194-9254',5,1703729516,1782480561);
INSERT INTO highlights VALUES('635722_64_8962-8995','635722',64,'第八章 施乐和莉萨：图形用户界面','乔布斯想要制造面向大众的电脑，操作简单、价格低廉，适合普通人使用。','8962-8995',5,1703729476,1782480561);
INSERT INTO highlights VALUES('635722_64_8652-8686','635722',64,'第八章 施乐和莉萨：图形用户界面','他们还想要一个可以操纵光标向任意方向移动的鼠标，而不仅仅是上下左右。','8652-8686',5,1703673268,1782480561);
INSERT INTO highlights VALUES('635722_64_8559-8577','635722',64,'第八章 施乐和莉萨：图形用户界面','乔布斯还狂热地追求页面滚动的平滑度。','8559-8577',5,1703673254,1782480561);
INSERT INTO highlights VALUES('635722_64_8228-8272','635722',64,'第八章 施乐和莉萨：图形用户界面','制造窗口重叠的假象，需要编写复杂的代码，其中运用到了“区域”(region)这样一个概念','8228-8272',5,1703673185,1782480561);
INSERT INTO highlights VALUES('635722_64_8037-8112','635722',64,'第八章 施乐和莉萨：图形用户界面','阿特金森的伟大功绩之一（时至今日我们已经对它习以为常，感觉不到它的神奇）就是实现了屏幕上窗口间的重叠，这样一来“上面的”窗口就叠在了“下面的”窗口上。','8037-8112',5,1703673160,1782480561);
INSERT INTO highlights VALUES('635722_64_7754-7858','635722',64,'第八章 施乐和莉萨：图形用户界面','屏幕背景色的改变可以实现阿特金森和乔布斯都想要的一个特性：WYSIWYG，这是“所见即所得”(What you see is what you get)的缩写。你在屏幕上看到的是什么样，打印出来就还是什么样。','7754-7858',5,1703673101,1782480561);
INSERT INTO highlights VALUES('635722_64_6741-6786','635722',64,'第八章 施乐和莉萨：图形用户界面','而在苹果工程师们设计出的界面上，用户不仅可以任意拖拽窗口和文件，还可以将它们拖到文件夹中。','6741-6786',5,1703665354,1782480561);
INSERT INTO highlights VALUES('635722_64_6344-6412','635722',64,'第八章 施乐和莉萨：图形用户界面','如同T·S·艾略特(T.S.Eliot)所说的：概念与产物之间投射着一道影子。在创新的过程中，新颖的想法只是一部分，具体执行也同样重要。','6344-6412',5,1703665281,1782480561);
INSERT INTO highlights VALUES('635722_64_6184-6214','635722',64,'第八章 施乐和莉萨：图形用户界面','与其说是苹果公司实施了抢劫，不如说是施乐公司自己酿下了苦果。','6184-6214',5,1703665249,1782480561);
INSERT INTO highlights VALUES('635722_64_5352-5394','635722',64,'第八章 施乐和莉萨：图形用户界面','“你们就坐在一座金矿上啊，”他叫道，“我真不敢相信，施乐竟然没有好好利用这项技术。”','5352-5394',5,1703665075,1782480561);
INSERT INTO highlights VALUES('635722_64_5190-5257','635722',64,'第八章 施乐和莉萨：图形用户界面','阿特金森盯着屏幕检查每一个像素，他靠得如此之近，以至于特斯勒都能感觉到他呼出来的气扑到自己脖子上。乔布斯跳了起来，兴奋地挥舞着胳膊。“','5190-5257',5,1703665059,1782480561);
INSERT INTO highlights VALUES('635722_64_5021-5125','635722',64,'第八章 施乐和莉萨：图形用户界面','阿特金森和其他人都读过施乐PARC发表的论文，所以他们知道自己并没有得到全部信息。乔布斯给施乐风投部门的负责人打电话抱怨，远在康涅狄格的公司总部立刻打来了电话，命令施乐PARC向乔布斯和他的团队展示全部成果。','5021-5125',5,1703665042,1782480561);
INSERT INTO highlights VALUES('635722_64_4867-4930','635722',64,'第八章 施乐和莉萨：图形用户界面','施乐的几个人聚在一起商量了一下，决定向乔布斯展示部分核心技术，但仅仅是一点点。他们同意特斯勒展示一下编程语言Smalltalk','4867-4930',5,1703665013,1782480561);
INSERT INTO highlights VALUES('635722_64_4005-4085','635722',64,'第八章 施乐和莉萨：图形用户界面','施乐的风险投资部门想要参与苹果公司在1979年夏天进行的第二轮融资。乔布斯开出了条件：“如果你们愿意揭开施乐PARC的神秘面纱，我就同意你们投资100万美元。”','4005-4085',5,1703664842,1782480561);
INSERT INTO highlights VALUES('635722_64_3031-3199','635722',64,'第八章 施乐和莉萨：图形用户界面','“预见未来最好的方式就是亲手创造未来”(The best way to predict the future is to invent it)以及“对待软件严肃认真的人，应该制造自己专属的硬件”(People who are serious about software should make their own hardware)。','3031-3199',5,1703664672,1782480561);
INSERT INTO highlights VALUES('635722_64_2582-2687','635722',64,'第八章 施乐和莉萨：图形用户界面','这个项目致力于制造一款廉价的电脑，研发代号为“安妮”(Annie)，开发者名叫杰夫·拉斯金(Jef Raskin)，他曾是位教授，还教过比尔·阿特金森。拉斯金的目标是制造价格低廉、就像家用电器一样的“大众电脑”','2582-2687',5,1703664599,1782480561);
INSERT INTO highlights VALUES('635722_64_2417-2468','635722',64,'第八章 施乐和莉萨：图形用户界面','既然你对这个有这么大的热情，我就给你6天时间来证明我是错的。”阿特金森做到了，从此乔布斯对他很是尊敬。','2417-2468',5,1703664537,1782480561);
INSERT INTO highlights VALUES('635722_64_2121-2171','635722',64,'第八章 施乐和莉萨：图形用户界面','蓬松的头发和长长的胡子并不能掩盖阿特金森脸上的活力，他拥有沃兹的创造天赋和乔布斯追求卓越产品的热情。','2121-2171',5,1703664489,1782480561);
INSERT INTO highlights VALUES('635722_64_1846-1892','635722',64,'第八章 施乐和莉萨：图形用户界面','然而，有一名叫比尔·阿特金森(Bill Atkinson)的程序员给这个项目注入了一些活力。','1846-1892',5,1703664447,1782480561);
INSERT INTO highlights VALUES('635722_64_1581-1627','635722',64,'第八章 施乐和莉萨：图形用户界面','多年以后，当我向乔布斯问起这个名字的时候，他坦率地承认：“这很显然是以我女儿的名字命名的。”','1581-1627',5,1703470181,1782480561);
INSERT INTO highlights VALUES('635722_64_1433-1494','635722',64,'第八章 施乐和莉萨：图形用户界面','他们把这个缩写逆推，得到了“本地集成系统架构”(Local Integrated Systems Architecture','1433-1494',5,1703470147,1782480561);
INSERT INTO highlights VALUES('635722_64_898-951','635722',64,'第八章 施乐和莉萨：图形用户界面','“Apple Ⅲ有点儿像集体狂欢时怀上的孩子，事后大家都头疼得厉害，至于这个野孩子，人人都说不是自己的。”','898-951',5,1703387844,1782480561);
INSERT INTO highlights VALUES('635722_63_4946-4979','635722',63,'第七章 克里斯安和莉萨 被遗弃者……','他戒掉了迷幻药，不再奉行严格的素食主义，也减少了花在禅修上的时间。','4946-4979',5,1703387644,1782480561);
INSERT INTO highlights VALUES('635722_63_2252-2322','635722',63,'第七章 克里斯安和莉萨 被遗弃者……','当乔布斯不想为一件事情分散注意力的时候，他就会完全忽略它，就好像此事完全不存在一样。有时候，他不仅能对别人扭曲现实，甚至也能对自己扭曲现实。','2252-2322',5,1703387342,1782480561);
INSERT INTO highlights VALUES('635722_62_13548-13612','635722',62,'第六章 Apple Ⅱ：新时代的曙光','沃兹尼亚克理应得到历史的铭记，因为是他设计出了Apple Ⅱ中令人赞叹的电路板和相关的操作软件，这是20世纪最伟大的个人发明之一','13548-13612',5,1703386853,1782480561);
INSERT INTO highlights VALUES('635722_62_13488-13547','635722',62,'第六章 Apple Ⅱ：新时代的曙光','在接下来的16年中，各种型号的Apple Ⅱ共售出了接近600万台。相比其他电脑，Apple Ⅱ真正开创了个人电脑产业','13488-13547',5,1703386842,1782480561);
INSERT INTO highlights VALUES('635722_62_12828-12872','635722',62,'第六章 Apple Ⅱ：新时代的曙光','他想让Apple Ⅱ有一年的保修期。这个想法让斯科特目瞪口呆，因为保修期一般只有90天。','12828-12872',5,1703386745,1782480561);
INSERT INTO highlights VALUES('635722_62_9693-9742','635722',62,'第六章 Apple Ⅱ：新时代的曙光','他们展示的是仅有的三台Apple Ⅱ成品，但在周围堆满了空的包装箱，这样就显得他们拥有充足的存货。','9693-9742',5,1703386154,1782480561);
INSERT INTO highlights VALUES('635722_62_9120-9126','635722',62,'第六章 Apple Ⅱ：新时代的曙光','至繁归于至简','9120-9126',5,1703386075,1782480561);
INSERT INTO highlights VALUES('635722_62_8987-9062','635722',62,'第六章 Apple Ⅱ：新时代的曙光','乔布斯还挑选了另一个版本，其中的苹果由六种颜色的水平色条构成，在大地的绿色和天空的蓝色中间夹着另外四种炫丽的颜色，但这一版本的印刷费用也因此大大提高了','8987-9062',5,1703386060,1782480561);
INSERT INTO highlights VALUES('635722_62_8317-8346','635722',62,'第六章 Apple Ⅱ：新时代的曙光','此人只想把乔布斯打发走。之后，乔布斯几乎每天都会打电话来。','8317-8346',5,1703385903,1782480561);
INSERT INTO highlights VALUES('635722_62_7621-7662','635722',62,'第六章 Apple Ⅱ：新时代的曙光','如果我们以创新的、专业的方式展示产品，那么优质的形象也就被灌输到顾客的思想中了。”','7621-7662',5,1703385760,1782480561);
INSERT INTO highlights VALUES('635722_62_7471-7508','635722',62,'第六章 Apple Ⅱ：新时代的曙光','第三点也是同样重要的一点原则，有一个让人困惑的措辞：灌输(impute)。','7471-7508',5,1703385731,1782480561);
INSERT INTO highlights VALUES('635722_62_7427-7441','635722',62,'第六章 Apple Ⅱ：新时代的曙光','第二点是专注(focus)。','7427-7441',5,1703385702,1782480561);
INSERT INTO highlights VALUES('635722_62_7357-7402','635722',62,'第六章 Apple Ⅱ：新时代的曙光','“苹果营销哲学”，其中强调了三点。第一点是共鸣(empathy)，就是紧密结合顾客的感受。','7357-7402',5,1703385694,1782480561);
INSERT INTO highlights VALUES('635722_62_7093-7114','635722',62,'第六章 Apple Ⅱ：新时代的曙光','马库拉对于乔布斯来说，是一个父亲般的人物。','7093-7114',5,1703385662,1782480561);
INSERT INTO highlights VALUES('635722_62_6915-6973','635722',62,'第六章 Apple Ⅱ：新时代的曙光','1977年1月3日，新的公司——苹果电脑有限公司——正式成立了，它买断了9个月前乔布斯和沃兹成立的旧公司的全部股权。','6915-6973',5,1703379804,1782480561);
INSERT INTO highlights VALUES('635722_62_6784-6886','635722',62,'第六章 Apple Ⅱ：新时代的曙光','他说如果沃兹全职加入了苹果，并不一定非要进入管理层，还可以继续当工程师。“那正是我想听到的，”沃兹尼亚克说，“我可以待在组织架构的最底层，当一名普通的工程师。”他给乔布斯打电话，告诉他，自己准备好入伙了。','6784-6886',5,1703379789,1782480561);
INSERT INTO highlights VALUES('635722_62_6617-6662','635722',62,'第六章 Apple Ⅱ：新时代的曙光','这时候沃兹的父亲意识到，利用Apple Ⅱ真的可以狠狠赚上一大笔，于是他站到了乔布斯这边。','6617-6662',5,1703379763,1782480561);
INSERT INTO highlights VALUES('635722_62_5010-5042','635722',62,'第六章 Apple Ⅱ：新时代的曙光','乔布斯见了这三个人，并与其中一个一拍即合——这个人叫迈克·马库拉','5010-5042',5,1703379538,1782480561);
INSERT INTO highlights VALUES('635722_62_4885-4938','635722',62,'第六章 Apple Ⅱ：新时代的曙光','如果你想要我给你投资的话，”瓦伦丁告诉他，“你必须找一个合作伙伴，这个人要了解销售，还要能写商业计划书。”','4885-4938',5,1703379522,1782480561);
INSERT INTO highlights VALUES('635722_62_4569-4589','635722',62,'第六章 Apple Ⅱ：新时代的曙光','红杉资本(Sequoia Capital','4569-4589',5,1703379417,1782480561);
INSERT INTO highlights VALUES('635722_62_4090-4127','635722',62,'第六章 Apple Ⅱ：新时代的曙光','沃兹回忆道，“我知道，像我这样的人最终总是会想出点儿东西来加到电脑上的。”','4090-4127',5,1703379364,1782480561);
INSERT INTO highlights VALUES('635722_62_3638-3666','635722',62,'第六章 Apple Ⅱ：新时代的曙光','现在所有的电脑都使用开关电源，而这都是盗用了罗德的设计。','3638-3666',5,1703379152,1782480561);
INSERT INTO highlights VALUES('635722_62_3472-3569','635722',62,'第六章 Apple Ⅱ：新时代的曙光','霍尔特并没有使用传统的线性电源，而是制造了一个与示波器上使用的相类似的开关电源。这就意味着，在一秒钟之内，通断电的次数不是60次，而是上千次，这样电源存储电能的时间就大大减少，散热量也随之减少。','3472-3569',5,1703379130,1782480561);
INSERT INTO highlights VALUES('635722_62_3206-3235','635722',62,'第六章 Apple Ⅱ：新时代的曙光','计算机内部的风扇有悖于禅意，它们的噪音会让人无法集中精神。','3206-3235',5,1703379054,1782480561);
INSERT INTO highlights VALUES('635722_62_2849-2920','635722',62,'第六章 Apple Ⅱ：新时代的曙光','有一次他在梅西百货的家用电器通道闲逛时，厨艺公司(Cuisinart)的食品加工机触发了他的灵感，他决定要一个光滑的机箱，由轻便的模制塑料制成','2849-2920',5,1703378982,1782480561);
INSERT INTO highlights VALUES('635722_62_2794-2849','635722',62,'第六章 Apple Ⅱ：新时代的曙光','乔布斯并不喜欢这个箱子。他想要的是简单又精致的设计，可以让苹果电脑从那些配有笨重的灰色金属箱的电脑中脱颖而出。','2794-2849',5,1703378972,1782480561);
INSERT INTO highlights VALUES('635722_62_2723-2765','635722',62,'第六章 Apple Ⅱ：新时代的曙光','他的设计结果出来了：一个有机玻璃制成的壳子，附带有金属条以及一扇可以盖住键盘的卷门。','2723-2765',5,1703378951,1782480561);
INSERT INTO highlights VALUES('635722_61_13336-13422','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','罗恩·韦恩为公司设计了商标，他使用维多利亚时代插图小说风格的华丽线描，画的是牛顿坐在一棵树下，边框上还引用了华兹华斯的一句诗：“一个灵魂，永远孤独地航行在陌生的思想海洋。”','13336-13422',5,1703320930,1782480561);
INSERT INTO highlights VALUES('635722_62_812-860','635722',62,'第六章 Apple Ⅱ：新时代的曙光','他决定，下一代的苹果电脑需要自带一个漂亮的箱子和内置键盘，整合其他关键元素，从电源到软件到显示器','812-860',5,1703320825,1782480561);
INSERT INTO highlights VALUES('635722_61_8723-8764','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','所以他请来了朋友罗恩·韦恩，那个曾经开过老虎机公司后来又在雅达利供职的中年工程师。','8723-8764',5,1703317852,1782480561);
INSERT INTO highlights VALUES('635722_61_8268-8306','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','苹果’削弱了‘电脑’这个词的锐气。还有，这能让我们在电话簿上排在雅达利之前。','8268-8306',5,1703314199,1782480561);
INSERT INTO highlights VALUES('635722_61_8214-8267','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','￼。“我那段时间正在吃水果餐，”他解释说，“我刚刚从一个苹果农场回来。这名字听上去有意思，有活力，不吓人。','8215-8267',5,1703314187,1782480561);
INSERT INTO highlights VALUES('635722_61_7452-7510','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','沃兹尼亚克回忆道：“想象一下那种情景我就兴奋，两个最要好的朋友创办一家公司！天哪！我立刻就同意了，我怎么可能拒绝？”','7452-7510',5,1703313925,1782480561);
INSERT INTO highlights VALUES('635722_61_7396-7424','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','“在我们的一生中，至少有这么一次，我们会拥有一家公司。”','7396-7424',5,1703313913,1782480561);
INSERT INTO highlights VALUES('635722_61_7355-7375','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','即使我们赔了钱，我们也能拥有一家公司。”','7355-7375',5,1703313906,1782480561);
INSERT INTO highlights VALUES('635722_61_6728-6823','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','“请大多数业余爱好者们意识到，你们的软件都是偷来的。这公平吗？……你们这样做只会让别人不再愿意编写好的软件。谁能承受得起无偿进行专业的工作？……如果有谁愿意付钱的话，给我来信，我会很感激。”','6728-6823',5,1703313880,1782480561);
INSERT INTO highlights VALUES('635722_61_5774-5833','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','那是历史上第一次，”沃兹尼亚克后来说，“一个人在键盘上按下几个键，然后在面前的屏幕上看到对应的字符立刻被显示了出来。”','5774-5833',5,1703313532,1782480561);
INSERT INTO highlights VALUES('635722_61_5662-5687','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','因为承担不起使用电脑的花费，他所有的代码都是手写的','5662-5687',5,1703313517,1782480561);
INSERT INTO highlights VALUES('635722_61_5080-5165','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','他一直在设计一台终端机，带有键盘和显示器，可以连接到一台小型机上。利用一枚微处理器，他就可以将小型机的一部分性能转移到终端机上，这样终端机就可以变成一台独立的小型台式机。','5080-5165',5,1703313429,1782480561);
INSERT INTO highlights VALUES('635722_61_3413-3431','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','我在那些可靠的工具和器械中看到了上帝','3413-3431',5,1703313344,1782480561);
INSERT INTO highlights VALUES('635722_61_2680-2734','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','有一个人在推动反主流文化人群与黑客的联合中发挥了作用，他就是斯图尔特·布兰德(Stewart Brand)。','2680-2734',5,1703313344,1782480561);
INSERT INTO highlights VALUES('635722_61_3184-3246','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','《全球概览》。创刊号的封面就是那张著名的从太空拍摄的地球照片，副标题是“通往工具之路”。潜在的含义是科技也能成为人类的朋友。','3184-3246',5,1703313051,1782480561);
INSERT INTO highlights VALUES('635722_61_2951-3056','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','“我们这一代的大多数人都将电脑看作集权控制的化身而蔑视它，”布兰德后来写道，“但有一小部分人——也就是后来被称作黑客的人——欣然接受了电脑并开始将它们转变成解放的工具。这一举动后来被证明是通向未来的正确道路。”','2951-3056',5,1703313051,1782480561);
INSERT INTO highlights VALUES('635722_61_1576-1582','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','《全球概览》','1576-1582',5,1703312829,1782480561);
INSERT INTO highlights VALUES('635722_61_1181-1208','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','在这背景下，一系列实现自我、追求心灵启迪的行为风靡一时','1181-1208',5,1703312782,1782480561);
INSERT INTO highlights VALUES('635722_60_12263-12323','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我教他，如果你表现得好像你能做某件事，那就能起作用。我告诉他，你装得好像自己掌控了一切，别人就会以为你真的掌控了一切。”','12263-12323',5,1703312760,1782480561);
INSERT INTO highlights VALUES('635722_61_965-1058','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','参与者包括来自帕洛奥图增强研究中心(Augmentation Research Center)的道格·恩格尔巴特(Doug Engelbart)，他后来参与发明了电脑鼠标以及图形用户界面','965-1058',5,1703312748,1782480561);
INSERT INTO highlights VALUES('635722_61_867-945','635722',61,'第五章 Apple Ⅰ：开机，启动，接入……','这里出现了黑客的亚文化群——云集于此的有资深玩家、电话飞客、电子朋克、业余爱好者以及纯粹的极客——包括那些不愿遵照惠普模式行事的工程师和他们不合群的孩子们。','867-945',5,1703312721,1782480561);
INSERT INTO highlights VALUES('635722_60_11096-11157','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我希望他当时能对我实话实说。如果告诉我他需要那笔钱，他应该知道我肯定会把钱给他的。他是我的朋友，帮助朋友是天经地义的事情。','11096-11157',5,1703312465,1782480561);
INSERT INTO highlights VALUES('635722_60_10601-10647','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','“我觉得我肯定完成不了，但史蒂夫让我相信自己一定可以。”于是他接连4天没有睡觉，完成了任务。','10601-10647',5,1703312406,1782480561);
INSERT INTO highlights VALUES('635722_60_9503-9578','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','这就是日后成为他“现实扭曲力场”个人魅力的美好的一面。“如果你相信他，你就能做成事情，”霍姆斯说，“如果他认为某件事应该发生，那他就会尽力让它发生。”','9503-9578',5,1703312281,1782480561);
INSERT INTO highlights VALUES('635722_60_8196-8239','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','史蒂夫和我都在追求个人成长，所以我想和他一起参加，”科特基说，“但是我没有那么多钱。”','8196-8239',5,1703312094,1782480561);
INSERT INTO highlights VALUES('635722_60_7633-7727','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','他们有时候会讨论乔布斯是否应该完全投身到精神追求中，但乙川弘文不赞成这么做。他说乔布斯可以边工作边进行精神修行。他们两人的关系是深厚的，也是持久的——17年后，乙川弘文主持了乔布斯的婚礼。','7633-7727',5,1703312038,1782480561);
INSERT INTO highlights VALUES('635722_60_6847-6890','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我从禅中学到的真理就是，如果你愿意跋山涉水去见一位导师的话，往往你的身边就会出现一位。','6847-6890',5,1703311911,1782480561);
INSERT INTO highlights VALUES('635722_60_6712-6736','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','你的视界会极大地延伸。你能看到之前看不到的东西。','6712-6736',5,1703310803,1782480561);
INSERT INTO highlights VALUES('635722_60_6301-6349','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','印度乡间的人与我们不同，我们运用思维，而他们运用直觉，他们的直觉比世界上其他地方的人要发达得多。','6301-6349',5,1703310761,1782480561);
INSERT INTO highlights VALUES('635722_60_6142-6200','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','纵观他的一生，他追随并遵循着东方宗教的许多基本戒律，比如对“般若”的强调——通过精神的集中而直观体验到的智慧和认知。','6142-6200',5,1703310745,1782480561);
INSERT INTO highlights VALUES('635722_60_5403-5412','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','他做不到内心的平和','5403-5412',5,1703308907,1782480561);
INSERT INTO highlights VALUES('635722_60_5354-5403','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','这个时候，乔布斯已经不是在寻找传授智慧的导师了，而是在通过苦行体验、克制物欲和返璞归真来寻求觉悟。','5354-5403',5,1703308906,1782480561);
INSERT INTO highlights VALUES('635722_60_5242-5277','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','他给我的头发打上肥皂，然后给我剃了个光头。他告诉我他是在拯救我的健康。','5242-5277',5,1703308788,1782480561);
INSERT INTO highlights VALUES('635722_60_4639-4667','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','乔布斯到达那里的时候，大师已经不在人世了，至少不在今世。','4639-4667',5,1703308579,1782480561);
INSERT INTO highlights VALUES('635722_60_2223-2251','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','除此之外，乔布斯发自内心地欣赏雅达利开发的游戏的简单性。','2223-2251',5,1703308114,1782480561);
INSERT INTO highlights VALUES('635722_60_2150-2193','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','乔布斯通过改进芯片，做出了更有趣的设计和更人性化的人机交互，进而完善了公司的一些游戏。','2150-2193',5,1703308085,1782480561);
INSERT INTO highlights VALUES('635722_60_1885-1915','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我那么耀眼的唯一原因就是，其他人都太糟糕了。”乔布斯回忆说。','1885-1915',5,1703308017,1782480561);
INSERT INTO highlights VALUES('635722_60_1479-1509','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我在他身上看到了一些东西。他非常聪明，富有激情，对技术狂热。','1479-1509',5,1703307966,1782480561);
INSERT INTO highlights VALUES('635722_60_906-939','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','将个人魅力转化为说服力，通过个性的力量进行劝诱、胁迫以及扭曲事实。','906-939',5,1703307888,1782480561);
INSERT INTO highlights VALUES('635722_60_760-817','635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','雅达利的创始人是高大健壮的企业家诺兰·布什内尔(Nolan Bushnell)，此人是个充满魅力、能说会道的梦想家','760-817',5,1703307857,1782480561);
INSERT INTO highlights VALUES('635722_59_10682-10738','635722',59,'第三章 出离：觉悟，修行……','它让我更清楚什么是重要的——创造伟大的发明，而不是赚钱。我应该尽我所能，在历史和人类思想的长河中留下一些东西。”','10682-10738',5,1702747754,1782480561);
INSERT INTO highlights VALUES('635722_59_10073-10116','635722',59,'第三章 出离：觉悟，修行……','在他所有的产品中，科技必定与完美的设计、外观、精致、手感、人性化甚至是浪漫结合在一起。','10073-10116',5,1702747554,1782480561);
INSERT INTO highlights VALUES('635722_59_10116-10132','635722',59,'第三章 出离：觉悟，修行……','他是追求友好图形用户界面的先锋。','10116-10132',5,1702747541,1782480561);
INSERT INTO highlights VALUES('635722_59_9929-10010','635722',59,'第三章 出离：觉悟，修行……','我学到了衬线字体和无衬线字体，怎样在不同的字母组合间调整其间距，以及怎样做出完美的版面设计。这其中所蕴含的美、历史意味和艺术精妙之处是科学无法捕捉的，这让我陶醉。','9929-10010',5,1702747516,1782480561);
INSERT INTO highlights VALUES('635722_59_9891-9905','635722',59,'第三章 出离：觉悟，修行……','这其中有一门书法课非常吸引他','9891-9905',5,1702747503,1782480561);
INSERT INTO highlights VALUES('635722_59_9773-9818','635722',59,'第三章 出离：觉悟，修行……','即使在乔布斯停止交学费之后，达德曼还是允许他旁听课程，并且可以继续待在宿舍和朋友们在一起。','9773-9818',5,1702747495,1782480561);
INSERT INTO highlights VALUES('635722_59_9642-9685','635722',59,'第三章 出离：觉悟，修行……','他并不是真的想离开里德学院，他只是不想再付学费，也不想再去上那些提不起他兴趣的课程了。','9642-9685',5,1702747476,1782480561);
INSERT INTO highlights VALUES('635722_59_9460-9497','635722',59,'第三章 出离：觉悟，修行……','乔布斯后来说，把父母的钱花在了根本不值那么多钱的教育上，他也开始有负罪感。','9460-9497',5,1702747462,1782480561);
INSERT INTO highlights VALUES('635722_59_9013-9100','635722',59,'第三章 出离：觉悟，修行……','“罗伯特总是标榜自己是个精神至上的人，但他越过了从魅力到欺骗的界限。”乔布斯说，“你年轻的时候认识的某个号称精神至上的人最后变成了彻头彻尾的淘金者，这真是件非常奇怪的事情。”','9013-9100',5,1702747398,1782480561);
INSERT INTO highlights VALUES('635722_59_8599-8687','635722',59,'第三章 出离：觉悟，修行……','尽管这个公社最初的目的是成为逃避物质主义的庇护所，但弗里德兰开始像做买卖一样管理公社。他的信徒们被要求砍柴然后出售柴火，生产苹果榨汁机和柴火炉子，参加各种商业活动但得不到报酬。','8599-8687',5,1702747284,1782480561);
INSERT INTO highlights VALUES('635722_59_7411-7518','635722',59,'第三章 出离：觉悟，修行……','弗里德兰教给了史蒂夫现实扭曲力场。”科特基说，“他极富魅力，也会骗人，可以让事态屈从于他的超强意志。他很机智，充满自信，还有一点儿独断专行。史蒂夫对此很是钦佩，他和罗伯特待在一起的时间久了之后，也变成了这个样子。”','7411-7518',5,1702641025,1782480561);
INSERT INTO highlights VALUES('635722_59_6100-6171','635722',59,'第三章 出离：觉悟，修行……','素食主义与佛教禅宗，冥想与灵性，迷幻药与摇滚乐——那个时代寻求自我启迪的校园文化中，这几样标志性的行为，被乔布斯以一种近乎疯狂的方式集于一身。','6100-6171',5,1702640543,1782480561);
INSERT INTO highlights VALUES('635722_59_4742-4774','635722',59,'第三章 出离：觉悟，修行……','我开始意识到，基于直觉的理解和意识，比抽象思维和逻辑分析更为重要','4742-4774',5,1702640317,1782480561);
INSERT INTO highlights VALUES('635722_59_2975-3051','635722',59,'第三章 出离：觉悟，修行……','他的父母开车带他来到波特兰，但他又作出了叛逆的举动：拒绝父母送他进校园。事实上，他甚至连“再见”和“谢谢”都没有说。后来他回想这件事的时候，充满了愧疚：','2975-3051',5,1702640106,1782480561);
INSERT INTO highlights VALUES('635722_59_2828-2929','635722',59,'第三章 出离：觉悟，修行……','那些古老的目标都隐喻着现在——打开心扉、自问心源、脱离尘世(turn on,tune in,drop out)。”许多里德学院的学生把这三条告诫奉为座右铭，学校在20世纪70年代的退学率超过了三分之一。','2828-2929',5,1702640089,1782480561);
INSERT INTO highlights VALUES('635722_59_1897-1969','635722',59,'第三章 出离：觉悟，修行……','乔布斯确实做得很痛苦：“太热了，那些服装又很重，只要在里面待上一会儿，我就会产生揍那些小孩儿的冲动。”“耐心”这个词，从来就与乔布斯沾不上边儿。','1897-1969',1,1702632197,1782480561);
INSERT INTO highlights VALUES('635722_59_902-922','635722',59,'第三章 出离：觉悟，修行……','他经常焦虑不安，好像有无尽的黑暗包围着他','902-922',1,1702631042,1782480561);
INSERT INTO highlights VALUES('635722_59_765-806','635722',59,'第三章 出离：觉悟，修行……','他学会了眼睛一眨不眨地盯着别人，他喜欢在长时间的沉默中断断续续地加入语速极快的讲话','765-806',1,1702631027,1782480561);
INSERT INTO highlights VALUES('635722_58_8297-8399','635722',58,'第二章 奇特的一对：两个史蒂夫','乔布斯认为蓝盒子不该再停留在业余爱好阶段了。他们可以制作然后销售。“我把剩下的元件都集中起来，比如说盒子、电源和数字键盘，然后想出了定价方式。”乔布斯说，这也预示了他日后在创立苹果公司过程中将扮演的角色。','8297-8399',1,1702630518,1782480561);
INSERT INTO highlights VALUES('635722_58_7730-7766','635722',58,'第二章 奇特的一对：两个史蒂夫','这是我设计过的最让我自豪的电路，”他说，“直到今天我仍然觉得难以置信。”','7730-7766',1,1702630436,1782480561);
INSERT INTO highlights VALUES('635722_58_7695-7728','635722',58,'第二章 奇特的一对：两个史蒂夫','在同宿舍一个拥有完美音准感的学生的帮助下，于感恩节之前就完成了制作','7695-7728',1,1702630430,1782480561);
INSERT INTO highlights VALUES('635722_58_4789-4834','635722',58,'第二章 奇特的一对：两个史蒂夫','我们会购买迪伦歌词的小册子，然后熬夜解读这些歌词。迪伦的话可以触动我们心中的创造性思维。”','4789-4834',5,1702569861,1782480561);
INSERT INTO highlights VALUES('635722_58_4377-4439','635722',58,'第二章 奇特的一对：两个史蒂夫','我立刻就喜欢上他了。我比自己的实际年龄要显得更成熟，而沃兹正相反，我们拉平了。沃兹非常聪明，但情商方面却像是我这个年纪的人。','4377-4439',5,1702569813,1782480561);
INSERT INTO highlights VALUES('635722_58_4344-4363','635722',58,'第二章 奇特的一对：两个史蒂夫','沃兹是我见过的第一个比我还懂电子学的人','4344-4363',5,1702569804,1782480561);
INSERT INTO highlights VALUES('635722_58_4269-4333','635722',58,'第二章 奇特的一对：两个史蒂夫','我们有如此多的共同点。一般来说，我很难向别人解释清楚我做的设计，但史蒂夫一下子就听明白了。我喜欢他。他瘦巴巴的，但是充满了活力。','4269-4333',5,1702569798,1782480561);
INSERT INTO highlights VALUES('635722_58_3894-3902','635722',58,'第二章 奇特的一对：两个史蒂夫','比尔·费尔南德斯','3894-3902',5,1702569464,1782480561);
INSERT INTO highlights VALUES('635722_58_2884-2916','635722',58,'第二章 奇特的一对：两个史蒂夫','“搞硬件的人才愿意玩这个游戏，搞软件的都太胆小了。”他这么强调。','2884-2916',5,1702569340,1782480561);
INSERT INTO highlights VALUES('635722_58_2710-2763','635722',58,'第二章 奇特的一对：两个史蒂夫','那是一次难忘的经历。他在里面教其他犯人把通到天花板上风扇的电线接到铁窗上，这样一旦有人碰到就会被电击一下。','2710-2763',5,1702569314,1782480561);
INSERT INTO highlights VALUES('635722_58_2595-2685','635722',58,'第二章 奇特的一对：两个史蒂夫','校长布吕德先生(Mr.Bryld)在装置刚被发现时就被叫到了现场，他一把抓起那个玩意儿，紧贴胸口，抱着它勇敢地跑到了操场，然后把上面的电线拆掉。沃兹强忍着，但还是控制不住笑了出来。','2595-2685',5,1702569290,1782480561);
INSERT INTO highlights VALUES('635722_58_956-1011','635722',58,'第二章 奇特的一对：两个史蒂夫','“我记得他告诉我，工程学是世界上最重要的，”史蒂夫·沃兹尼亚克后来回忆说，“工程学将社会带入了一个新的水平。”','956-1011',5,1702569069,1782480561);
INSERT INTO highlights VALUES('635722_57_18184-18237','635722',57,'第一章 童年：被遗弃与被选择','乔布斯听的一门课日后成为了硅谷传奇的一部分，这就是约翰·麦科勒姆(John McCollum)教授的电子学','18184-18237',5,1702568750,1782480561);
INSERT INTO highlights VALUES('635722_57_17948-18029','635722',57,'第一章 童年：被遗弃与被选择','我爱看《李尔王》。”他还爱读《白鲸》(Moby Dick)和迪伦·托马斯(Dylan Thomas)的诗作','17948-18029',5,1702568713,1782480561);
INSERT INTO highlights VALUES('635722_57_17864-17915','635722',57,'第一章 童年：被遗弃与被选择','高中的最后两年，乔布斯的心智也快速发展，他发现自己既沉浸在极客的电子世界中，又喜欢文学和创造性的尝试。','17864-17915',5,1702568700,1782480561);
INSERT INTO highlights VALUES('635722_57_17559-17591','635722',57,'第一章 童年：被遗弃与被选择','也是在那一年夏天，在他即将升入高中第三年的时候，乔布斯开始抽大麻','17559-17591',5,1702568656,1782480561);
INSERT INTO highlights VALUES('635722_57_17148-17211','635722',57,'第一章 童年：被遗弃与被选择','他会去电子产品的跳蚤市场，比如圣何塞交换大会，为了一块带有值钱芯片的电路板跟人讨价还价，然后把那些芯片卖给哈尔泰克商店的经理。','17148-17211',5,1702568572,1782480561);
INSERT INTO highlights VALUES('635722_57_16676-16724','635722',57,'第一章 童年：被遗弃与被选择','在他高中第二年的时候，周末和暑假他都在一家巨大的电子器材商店哈尔泰克(Haltek)做仓库管理员','16676-16724',5,1702568492,1782480561);
INSERT INTO highlights VALUES('635722_57_15722-15767','635722',57,'第一章 童年：被遗弃与被选择','我很幸运，因为当我还是个孩子的时候，我的父亲以及希斯工具盒都让我相信，我能做出任何东西。”','15722-15767',5,1702399222,1782480561);
INSERT INTO highlights VALUES('635722_57_15606-15649','635722',57,'第一章 童年：被遗弃与被选择','希斯工具盒里面有各种各样用不同颜色编号的插件板和零部件，还有解释其使用原理的操作手册。','15606-15649',5,1702399211,1782480561);
INSERT INTO highlights VALUES('635722_57_15518-15543','635722',57,'第一章 童年：被遗弃与被选择','朗最终把那只令乔布斯魂牵梦萦的碳精麦克风送给了他，','15518-15543',5,1702398850,1782480561);
INSERT INTO highlights VALUES('635722_57_14801-14874','635722',57,'第一章 童年：被遗弃与被选择','乡村生活对史蒂夫毫无吸引力，但有一幅画面却深深刻在了他心上。他看到了一只小牛犊的出生，让他惊讶的是，这只小动物才落地几分钟就挣扎着站起来开始走路。','14801-14874',5,1702398711,1782480561);
INSERT INTO highlights VALUES('635722_57_14956-15009','635722',57,'第一章 童年：被遗弃与被选择','就好像是设计好的一样，动物身体里的某些东西和它大脑里的某些东西在它出生后立刻开始协同作用，而不需要去学习。','14956-15009',5,1702398697,1782480561);
INSERT INTO highlights VALUES('635722_57_14491-14509','635722',57,'第一章 童年：被遗弃与被选择','他的儿子被那种对完美的追求所深深吸引','14491-14509',5,1702398529,1782480561);
INSERT INTO highlights VALUES('635722_57_14410-14435','635722',57,'第一章 童年：被遗弃与被选择','光谱物理公司(Spectra-Physics)工作','14410-14435',5,1702398520,1782480561);
INSERT INTO highlights VALUES('635722_57_14225-14309','635722',57,'第一章 童年：被遗弃与被选择','他反思自己的精神感受时说，宗教应该更多地强调精神体验，而不是一味遵守教条。“当基督教太过基于信仰，而忽略了以耶稣的方式生活或者从耶稣的角度看世界时，它的精髓就消失了，”','14225-14309',5,1702398441,1782480561);
INSERT INTO highlights VALUES('635722_57_13454-13475','635722',57,'第一章 童年：被遗弃与被选择','以及一个面对马路、带卷帘门、设施齐全的车库','13454-13475',5,1702398360,1782480561);
INSERT INTO highlights VALUES('635722_57_13227-13315','635722',57,'第一章 童年：被遗弃与被选择','他们一开始反对，我就告诉他们，如果要我回到克里滕登的话，我就再也不上学了。所以他们就打探了一下最好的学校在哪里，然后倾尽所有，在一个更好的地区花21000美元买下了一座房子。”','13227-13315',5,1702398324,1782480561);
INSERT INTO highlights VALUES('635722_57_12280-12324','635722',57,'第一章 童年：被遗弃与被选择','我用了不到两天就做完交给她了。”几个月之后，他不想再要奖励了：“我只想学习和让她高兴。”','12280-12324',5,1702376165,1782480561);
INSERT INTO highlights VALUES('635722_57_11956-11998','635722',57,'第一章 童年：被遗弃与被选择','他开始展现出性格中的多面性，敏感又偶尔迟钝，易怒而又超然，这也是他以后生活中的状态。','11956-11998',5,1702376128,1782480561);
INSERT INTO highlights VALUES('635722_57_11828-11844','635722',57,'第一章 童年：被遗弃与被选择','如果你提不起他的兴趣，那是你的错','11828-11844',5,1702376110,1782480561);
INSERT INTO highlights VALUES('635722_57_10853-10898','635722',57,'第一章 童年：被遗弃与被选择','保罗和克拉拉是一对很慈爱的父母，他们愿意改变自己的生活来适应这个非常聪明也非常任性的儿子。','10853-10898',5,1702375972,1782480561);
INSERT INTO highlights VALUES('635722_57_10660-10706','635722',57,'第一章 童年：被遗弃与被选择','对我来说是一个重大的时刻。当我意识到自己比父母更聪明时，我为自己有这样的念头而感到异常羞愧。','10660-10706',5,1702375954,1782480561);
INSERT INTO highlights VALUES('635722_57_9770-9861','635722',57,'第一章 童年：被遗弃与被选择','这一绵延40英里的圣克拉拉谷，从南旧金山穿过帕洛奥图，一直延伸到圣何塞，贯穿其中的是该地区的商业主干道“国王大道”(El Camino Real)，这条道路曾经连接着加州的21所教会','9770-9861',5,1702375833,1782480561);
INSERT INTO highlights VALUES('635722_57_9485-9538','635722',57,'第一章 童年：被遗弃与被选择','当时英特尔公司成功地将一个完整的中央处理器蚀刻到了一块芯片上，制成了英特尔4004，他们称之为“微处理器”','9485-9538',1,1702303454,1782480561);
INSERT INTO highlights VALUES('635722_57_9165-9246','635722',57,'第一章 童年：被遗弃与被选择','诺伊斯带走了戈登·摩尔，创办了集成电路公司(Integrated Electronics Corporation)，他们巧妙地将公司简称为“英特尔”(Intel)','9165-9246',1,1702303413,1782480561);
INSERT INTO highlights VALUES('635722_57_9006-9105','635722',57,'第一章 童年：被遗弃与被选择','他麾下的8名工程师——最著名的有罗伯特·诺伊斯(Robert Noyce)和戈登·摩尔(Gordon Moore)——离他而去并创办了仙童半导体公司(Fairchild Semiconductor)','9006-9105',1,1702303398,1782480561);
INSERT INTO highlights VALUES('635722_57_8592-8679','635722',57,'第一章 童年：被遗弃与被选择','斯坦福大学的工程系主任弗雷德里克·特曼(Frederick Terman)在学校拥有的土地上开辟了一座占地700英亩的工业园区，提供给那些可以将学生们的创意商业化的私人企业。','8592-8679',1,1702303332,1782480561);
INSERT INTO highlights VALUES('635722_57_7703-7751','635722',57,'第一章 童年：被遗弃与被选择','这个地区与遍布美国的成千上万个树影稀疏的地区不同的一点是，即便是个一无所长的人也想成为工程师。“','7703-7751',1,1702303120,1782480561);
INSERT INTO highlights VALUES('635722_57_6744-6813','635722',57,'第一章 童年：被遗弃与被选择','乔布斯说，他对埃奇勒建造的房屋的欣赏，激发了他为大众制造设计精良的产品的热情。“我喜欢把很棒的设计和简便的功能融入产品中，而且不会太贵。”','6744-6813',1,1702302972,1782480561);
INSERT INTO highlights VALUES('635722_57_5523-5586','635722',57,'第一章 童年：被遗弃与被选择','老乔布斯说，把柜子和栅栏的背面制作好也十分重要，尽管这些地方人们看不到。“他喜欢追求完美，即使别人看不到的地方他也会很关心。”','5523-5586',1,1702302820,1782480561);
INSERT INTO highlights VALUES('635722_57_4007-4046','635722',57,'第一章 童年：被遗弃与被选择','被遗弃，被选择，很特别，这些概念成为了乔布斯的一部分，也影响了他对自己的看法。','4007-4046',5,1702179417,1782480561);
INSERT INTO highlights VALUES('635722_57_3916-3978','635722',57,'第一章 童年：被遗弃与被选择','直盯着我的眼睛。他们说，‘我们是专门挑的你。’他们两人都这么说，并且放慢语速向我重复这句话。他们一字一顿地说出了每一个字。”','3916-3978',5,1702179408,1782480561);
INSERT INTO highlights VALUES('635722_57_3551-3578','635722',57,'第一章 童年：被遗弃与被选择','乔安妮1962年和钱德里离婚后，过上了梦一般游荡的生活','3551-3578',5,1702179349,1782480561);
INSERT INTO highlights VALUES('635722_57_3198-3232','635722',57,'第一章 童年：被遗弃与被选择','乔布斯夫妇必须承诺设立专款，送这个孩子上大学，并需要在保证书上签字。','3198-3232',5,1702179318,1782480561);
INSERT INTO highlights VALUES('635722_57_2793-2819','635722',57,'第一章 童年：被遗弃与被选择','乔安妮提出了一个要求：领养她孩子的人必须要大学毕业。','2793-2819',5,1702179217,1782480561);
INSERT INTO highlights VALUES('635722_57_2614-2632','635722',57,'第一章 童年：被遗弃与被选择','当年他们都是23岁，但决定先不结婚。','2614-2632',5,1702179192,1782480561);
INSERT INTO highlights VALUES('635722_57_2397-2432','635722',57,'第一章 童年：被遗弃与被选择','阿卜杜勒法塔赫·钱德里就曾被送到一所耶稣会寄宿学校，尽管他是个穆斯林。','2397-2432',5,1702179167,1782480561);
INSERT INTO highlights VALUES('635722_57_1549-1572','635722',57,'第一章 童年：被遗弃与被选择','最后，他辞去了工作，成了一名全职的二手车商人。','1549-1572',5,1702179028,1782480561);
INSERT INTO highlights VALUES('635722_57_1473-1521','635722',57,'第一章 童年：被遗弃与被选择','保罗找到了一份工作——在国际收割机公司(International Harvester)做机械师','1473-1521',5,1702178931,1782480561);
INSERT INTO highlights VALUES('635722_57_1276-1340','635722',57,'第一章 童年：被遗弃与被选择','她有一个很少对外提及的秘密：她曾经结过婚，但她的丈夫在战争中身亡了。所以当她第一次和保罗约会时，心中已经准备好迎接崭新的生活了。','1276-1340',5,1702178622,1782480561);
INSERT INTO highlights VALUES('635722_57_855-887','635722',57,'第一章 童年：被遗弃与被选择','10天以后，1946年3月，保罗与克拉拉订婚，同时也赢了那场赌局','855-887',5,1702176823,1782480561);
INSERT INTO highlights VALUES('635722_57_554-575','635722',57,'第一章 童年：被遗弃与被选择','保罗打赌说他会在两周之内给自己找到一个妻子','554-575',5,1702176774,1782480561);
INSERT INTO highlights VALUES('635722_56_5014-5050','635722',56,'前言 本书是如何诞生的','那光明的创新天堂之旅，始于他的两对父母，以及一个学习如何点石成金的山谷。','5014-5050',5,1702176686,1782480561);
INSERT INTO highlights VALUES('635722_56_4626-4681','635722',56,'前言 本书是如何诞生的','他们所做的并非是针对目标人群的普通产品改进，而是在消费者还没有意识到其需求的时候，就为其提供全新的设备和服务。','4626-4681',5,1702176628,1782480561);
INSERT INTO highlights VALUES('635722_56_4542-4571','635722',56,'前言 本书是如何诞生的','他深知21世纪创造价值的最佳途径就是将创造力与科技结合起来','4542-4571',5,1702176607,1782480561);
INSERT INTO highlights VALUES('635722_56_4378-4432','635722',56,'前言 本书是如何诞生的','2011年8月，在乔布斯即将卸任苹果公司CEO之际，这个在他父母的车库中诞生的公司成为世界上市值最高的公司。','4378-4432',5,1702176585,1782480561);
INSERT INTO highlights VALUES('635722_56_4183-4198','635722',56,'前言 本书是如何诞生的','第七个产业：数字产品零售商店。','4183-4198',5,1702176544,1782480561);
INSERT INTO highlights VALUES('635722_56_4124-4176','635722',56,'前言 本书是如何诞生的','他对完美的狂热以及积极的追求彻底变革了六大产业：个人电脑、动画电影、音乐、移动电话、平板电脑和数字出版。','4124-4176',5,1702175124,1782480561);
INSERT INTO highlights VALUES('635722_56_3384-3417','635722',56,'前言 本书是如何诞生的','现实扭曲力场”(reality distortion field)','3384-3417',5,1702175000,1782480561);
INSERT INTO highlights VALUES('635722_56_3444-3475','635722',56,'前言 本书是如何诞生的','但有些时候，乔布斯则是在向我和他自己编织现实在他头脑中的印象。','3444-3475',5,1702174994,1782480561);
INSERT INTO highlights VALUES('635722_56_2770-2833','635722',56,'前言 本书是如何诞生的','一个具有强烈个性的人身上集合了人文和科学的天赋后所能产生的那种创造力，我相信这种创造力也是在21世纪建立创新型经济的关键因素。','2770-2833',5,1702145139,1782480561);
INSERT INTO highlights VALUES('635722_56_2473-2557','635722',56,'前言 本书是如何诞生的','但他还有一个更重要的目标，那就是像休利特和戴维·帕卡德(David Packard)一样，建立一家充满了革命性创造力的公司，而且这家公司要比惠普更能经受岁月长河的涤荡。','2473-2557',5,1702145091,1782480561);
INSERT INTO highlights VALUES('635722_56_2346-2429','635722',56,'前言 本书是如何诞生的','他先是回忆自己12岁的时候曾经想要做一个频率计数器，当时他在电话簿上查到了惠普的创始人比尔·休利特(Bill Hewlett)的号码，并给他打电话，想要得到一些零部件','2346-2429',5,1702145055,1782480561);
INSERT INTO highlights VALUES('635722_56_1977-2018','635722',56,'前言 本书是如何诞生的','他是在接受癌症手术之前给我打的电话，直到今天他还将此事作为一个秘密，她这么解释道。','1977-2018',5,1702145009,1782480561);
INSERT INTO highlights VALUES('635722_56_1596-1625','635722',56,'前言 本书是如何诞生的','乔布斯回复我说，他希望自己曾经考虑过这一点，但实际上并没有','1596-1625',5,1702144927,1782480561);
INSERT INTO highlights VALUES('635722_56_767-802','635722',56,'前言 本书是如何诞生的','正在着手完成阿尔伯特·爱因斯坦(Albert Einstein)的传记','767-802',5,1702144490,1782480561);
INSERT INTO highlights VALUES('635722_56_730-766','635722',56,'前言 本书是如何诞生的','我刚刚出版了本杰明·富兰克林(Benjamin Franklin)的传记','730-766',5,1702144485,1782480561);
INSERT INTO highlights VALUES('635722_56_569-592','635722',56,'前言 本书是如何诞生的','阿斯彭研究所(Aspen Institute)','569-592',5,1702144462,1782480561);
INSERT INTO highlights VALUES('3300037073_51_1570-1653','3300037073',51,'结语',unistr('它就像是宇宙的一扇窗。一扇揭示周围世界以及你自身奥妙的窗口。能活在世上并拥有一具属于自己的躯体是极其幸运的。\u000a'),'1570-1624',5,1714302534,1782480559);
INSERT INTO highlights VALUES('3300037073_51_1316-1391','3300037073',51,'结语','宇宙很吸引人，但是它并不比生物学更有趣。星体就是一团没有生命的燃烧的气体，最复杂最有趣的行星也不能和细菌试图躲开巨噬细胞攻击的奇妙和惊险景象相提并论。','1316-1391',5,1714302503,1782480559);
INSERT INTO highlights VALUES('3300037073_51_1133-1205','3300037073',51,'结语','免疫学要是能采用更简洁明了的语言并且试着让大众更容易看懂，将会大大有助于这一学科的发展，且远大于其他学科。说到底免疫学的确是最有魅力的学科之一。','1133-1205',5,1714302462,1782480559);
INSERT INTO highlights VALUES('3300037073_50_4655-4724','3300037073',50,'45 新冠疫情','这一章我们就讲到这儿吧。当我写这句话的时候，全世界的人已经开始接种新冠疫苗。要是走运的话，在你读到这句话时，我们的生活应该开始恢复正常了。','4655-4724',1,1714285741,1782480559);
INSERT INTO highlights VALUES('3300037073_50_3388-3447','3300037073',50,'45 新冠疫情','肺部的免疫细胞一般都很小心，因为肺组织非常娇嫩。没有了干扰素的抑制，病毒就能不受限制地增殖，而此时炎症已经在造成损伤。','3388-3447',1,1714285604,1782480559);
INSERT INTO highlights VALUES('3300037073_50_3340-3374','3300037073',50,'45 新冠疫情','对许多人来说，危险正在于此。大量的炎症和活化的免疫细胞会严重损伤肺部','3340-3374',1,1714285594,1782480559);
INSERT INTO highlights VALUES('3300037073_50_2914-2986','3300037073',50,'45 新冠疫情','新冠病毒之所以这么危险，原因之一就是它能终止（或严重延迟）干扰素的释放，但同时被感染的细胞仍然可以释放各种各样的细胞因子，引发炎症，惊动免疫系统','2914-2986',1,1714285528,1782480559);
INSERT INTO highlights VALUES('3300037073_50_2817-2885','3300037073',50,'45 新冠疫情','面对病毒感染，身体的首要反应就是发起化学战，主要包含三方面事项：干扰素干扰并减慢病毒的复制，其他细胞因子会引发炎症，并惊醒其他免疫细胞。','2817-2885',1,1714285484,1782480559);
INSERT INTO highlights VALUES('3300037073_50_2590-2663','3300037073',50,'45 新冠疫情','这种病毒针对的是ACE2这种很特殊又很重要的受体。这种受体有一些关键的功能，尤其和调节血压有关，这意味着体内很多细胞都有这种受体，都可能因此感染。','2590-2663',1,1714285454,1782480559);
INSERT INTO highlights VALUES('3300037073_49_10196-10295','3300037073',49,'44 免疫系统与癌症','另一方面，化疗、手术、放疗都很痛苦。告诉病人你要心态积极才能好起来，实际上是不让病人表达真实的感受。而表达真实的痛苦、得到倾听和关爱是非常重要的，这能帮你缓解恐惧和必经的痛苦治疗带来的强烈负面情绪。','10196-10295',1,1714285149,1782480559);
INSERT INTO highlights VALUES('3300037073_49_9635-9720','3300037073',49,'44 免疫系统与癌症','吸烟者更少患炎性疾病，这单纯是因为炎症反应被调低了，毕竟免疫系统已经迟缓得像吃了甜食的蜗牛了。所以，在患有溃疡性结肠炎等自身免疫性疾病的情况下，吸烟有一定程度的保护作用。','9635-9720',1,1714285073,1782480559);
INSERT INTO highlights VALUES('3300037073_49_9134-9177','3300037073',49,'44 免疫系统与癌症','就算你现在马上就戒烟，免疫系统仍会在此后的一周甚至数月中处于抑制状态，所以戒烟越早越好','9134-9177',1,1714285037,1782480559);
INSERT INTO highlights VALUES('3300037073_49_8657-8693','3300037073',49,'44 免疫系统与癌症','还有一种关键的细胞会受吸烟的严重抑制，变得不够活跃，那就是自然杀伤细胞。','8657-8693',1,1714284933,1782480559);
INSERT INTO highlights VALUES('3300037073_49_8329-8350','3300037073',49,'44 免疫系统与癌症','吸烟者肺部的肺泡巨噬细胞，比不吸烟者多得多','8329-8350',1,1714284885,1782480559);
INSERT INTO highlights VALUES('3300037073_49_8524-8563','3300037073',49,'44 免疫系统与癌症','要是时间足够长，这些久经尼古丁渐染的巨噬细胞会造成大面积肺损伤，生成瘢痕组织。','8524-8563',1,1714284883,1782480559);
INSERT INTO highlights VALUES('3300037073_49_6427-6464','3300037073',49,'44 免疫系统与癌症','演化就是这样，免疫系统尽力摧毁癌组织，同时就是在选择生存能力最强的癌细胞。','6427-6464',5,1714280763,1782480559);
INSERT INTO highlights VALUES('3300037073_49_6149-6173','3300037073',49,'44 免疫系统与癌症','免疫细胞杀死了那些好心公示自己情况很不妙的癌细胞','6149-6173',5,1714280727,1782480559);
INSERT INTO highlights VALUES('3300037073_49_4621-4656','3300037073',49,'44 免疫系统与癌症','所以这颗迷你肿瘤开始偷取身体的营养，方法是指挥生成专为自己供血的血管。','4621-4656',5,1714280528,1782480559);
INSERT INTO highlights VALUES('3300037073_49_4312-4345','3300037073',49,'44 免疫系统与癌症','让我们来了解一下“肿瘤免疫编辑”，免疫系统和癌细胞之间的拉锯、较量','4312-4345',5,1714247045,1782480559);
INSERT INTO highlights VALUES('3300037073_49_4008-4102','3300037073',49,'44 免疫系统与癌症','因为癌症是持续的风险和既有的生存威胁，所以一般而言，人体——或者更准确地说，免疫系统——其实很擅长对付它。几乎可以肯定，就在你读这最后几章的时候，你的免疫细胞就干掉了体内某处的一批癌细胞。','4008-4102',5,1714247021,1782480559);
INSERT INTO highlights VALUES('3300037073_49_3827-3891','3300037073',49,'44 免疫系统与癌症','你或许觉得，演化早就该让这种恶变绝迹，但因为人一般是过了生育年龄才得癌症，所以发展、优化对抗癌症的机制，没有什么演化上的好处。2','3827-3891',5,1714246992,1782480559);
INSERT INTO highlights VALUES('3300037073_49_3125-3156','3300037073',49,'44 免疫系统与癌症','所以第三组必须“堕落”的，是能让细胞通过凋亡而有序自毁的基因。','3125-3156',5,1714246927,1782480559);
INSERT INTO highlights VALUES('3300037073_49_2883-2972','3300037073',49,'44 免疫系统与癌症','第二种关键的突变要发生在修复遗传编码损伤的基因上，这种基因被恰当地叫作“肿瘤抑制基因”。这种基因能提供保护和控制机制，不停地扫描DNA，看有没有异常和复制错误，一旦发现，马上修正','2883-2972',5,1714246908,1782480559);
INSERT INTO highlights VALUES('3300037073_49_2629-2663','3300037073',49,'44 免疫系统与癌症','第一种关键突变发生在“癌基因”中，这种基因监控着癌细胞的生长和增殖。','2629-2663',5,1714246884,1782480559);
INSERT INTO highlights VALUES('3300037073_49_2562-2600','3300037073',49,'44 免疫系统与癌症','细胞要发展成癌症，必须发生适当的突变，使得联合抑制癌症的三种不同机制都失效。','2562-2600',5,1714246882,1782480559);
INSERT INTO highlights VALUES('3300037073_49_1699-1765','3300037073',49,'44 免疫系统与癌症','人体的DNA每时每刻都在受损和改变，平均每个细胞的遗传编码每天都会受几万次损伤，也就是说，一个人每天都会承受总共数亿亿次的微小突变。','1699-1765',5,1714246804,1782480559);
INSERT INTO highlights VALUES('3300037073_49_1315-1348','3300037073',49,'44 免疫系统与癌症','癌细胞却并非十恶不赦。它们并不想要伤害你。实际上它们什么都不想要。','1315-1348',5,1714212429,1782480559);
INSERT INTO highlights VALUES('3300037073_49_1222-1274','3300037073',49,'44 免疫系统与癌症','在世的人中，有近1/4会在一生中患癌，1/6的人会死于癌症。所以基本上，每个人早晚都会认识某个癌症患者。','1222-1274',5,1714212404,1782480559);
INSERT INTO highlights VALUES('3300037073_49_953-1007','3300037073',49,'44 免疫系统与癌症','和长成肿瘤的实体癌不同，还有非实体癌，它们往往起源于骨髓，会影响血液、骨髓、淋巴液、淋巴系统这些“液体”部分','953-1007',5,1714211425,1782480559);
INSERT INTO highlights VALUES('3300037073_49_736-788','3300037073',49,'44 免疫系统与癌症','二者的主要区别在于，良性肿瘤不会像癌细胞一样侵犯其他的组织和器官，而是基本局限在某个部位，形成一个瘤子。','736-788',5,1714211396,1782480559);
INSERT INTO highlights VALUES('3300037073_48_2788-2831','3300037073',48,'43 免疫系统与应激','帮助人们活得快乐、充实，减少抑郁和应激状态，很可能对社会整体的健康水平有相当大的促进。','2788-2831',5,1714211361,1782480559);
INSERT INTO highlights VALUES('3300037073_48_2693-2748','3300037073',48,'43 免疫系统与应激','如果你还在寻找强化免疫系统的办法，那么，消除生活中的应激源，呵护自身心理健康，就是你马上可以做的实实在在的事。','2693-2748',5,1714211340,1782480559);
INSERT INTO highlights VALUES('3300037073_48_2633-2664','3300037073',48,'43 免疫系统与应激','慢性应激对免疫系统要保护的身体所有部位、所有方面都有不利影响。','2633-2664',5,1714211322,1782480559);
INSERT INTO highlights VALUES('3300037073_48_2259-2346','3300037073',48,'43 免疫系统与应激','应激也会导致皮质醇等激素的释放，这些激素会抑制和关闭免疫系统，让免疫系统变弱，在很多方面都不能很好地发挥作用。身体原有的感染或疾病不再能得到有效的控制，人可能会长疱疹，等等。','2259-2346',5,1714211250,1782480559);
INSERT INTO highlights VALUES('3300037073_48_2097-2135','3300037073',48,'43 免疫系统与应激','，慢性炎症和癌症、糖尿病、心脏病及自身免疫性疾病等一系列病症的风险增高有关，','2097-2135',5,1714210946,1782480559);
INSERT INTO highlights VALUES('3300037073_48_2058-2097','3300037073',48,'43 免疫系统与应激','总的说来，慢性应激会干扰身体终止炎症反应的功能，从而导致慢性炎症。前面我们说过','2058-2097',5,1714210941,1782480559);
INSERT INTO highlights VALUES('3300037073_48_1640-1710','3300037073',48,'43 免疫系统与应激','不像应付考试季或者给挑剔的客户做大项目，应激状态会持续几周甚至数月。应激本来只是推动短暂的暴发性行动的机制，现在却变成了持续存在的背景噪声。','1640-1710',5,1714195769,1782480559);
INSERT INTO highlights VALUES('3300037073_48_1451-1484','3300037073',48,'43 免疫系统与应激','心理应激会对免疫功能产生真实而直接的生理影响，而且很多都没有益处。','1451-1484',5,1714195708,1782480559);
INSERT INTO highlights VALUES('3300037073_47_5507-5529','3300037073',47,'42 如何强化免疫系统','其实，有很多人都在无意中抑制自己的免疫功能。','5507-5529',5,1714195546,1782480559);
INSERT INTO highlights VALUES('3300037073_47_5412-5480','3300037073',47,'42 如何强化免疫系统','现在我们知道了，即便对专家而言，提振、增强免疫系统都很复杂；对普通人来说，除了保持健康的生活方式之外，更是别无他法（要么就是不明智的）。','5412-5480',5,1714195530,1782480559);
INSERT INTO highlights VALUES('3300037073_47_2471-2499','3300037073',47,'42 如何强化免疫系统','要是你担心自己缺乏维生素或其他微量元素等，应该去看医生。','2471-2499',5,1714195207,1782480559);
INSERT INTO highlights VALUES('3300037073_47_1584-1642','3300037073',47,'42 如何强化免疫系统','至少目前，没有任何科学方法能证明任何一种触手可得的产品可以强化免疫系统。而且要是有的话，不咨询医生随便吃也会很危险。','1584-1642',5,1714192672,1782480559);
INSERT INTO highlights VALUES('3300037073_47_1460-1531','3300037073',47,'42 如何强化免疫系统','事实上没人知道，哪些种类的细胞，在多少数量和怎样的活化水平下，才能让某一个人的免疫系统在最佳状况下运转。任何宣称知道的人，大概都是想要卖产品。','1460-1531',5,1714192653,1782480559);
INSERT INTO highlights VALUES('3300037073_47_1162-1224','3300037073',47,'42 如何强化免疫系统','免疫系统应该是平衡的，处于稳态，既有一定的攻击性又能保持冷静。','1162-1224',5,1714192635,1782480559);
INSERT INTO highlights VALUES('3300037073_47_986-1060','3300037073',47,'42 如何强化免疫系统','你可能已经明白我的意思了：强化免疫系统不是好主意，都是那些骗你买没用东西的人想出来的！','986-1060',5,1714192618,1782480559);
INSERT INTO highlights VALUES('3300037073_46_6251-6339','3300037073',46,'41 卫生假说和老朋友','从演化角度考虑，现在和过去最重要的区别之一，可能就是现代饮食中所含纤维大大少于过去。纤维是许多有益共生细菌的重要食粮，我们吃的纤维越来越少，也就意味着人体无法供养足够的益生菌。','6251-6339',5,1714192283,1782480559);
INSERT INTO highlights VALUES('3300037073_46_6116-6222','3300037073',46,'41 卫生假说和老朋友','母亲的胸膛皮肤上和乳汁中含有丰富多样的物质，可以滋养新生的微生物组，滋养多种细菌。过去，演化之力会确保新生儿和母亲身上那久经考验的微生物组充分密切接触。剖宫产和欠缺母乳喂养，都和过敏等免疫失调问题的高发生率有关。','6116-6222',5,1714192224,1782480559);
INSERT INTO highlights VALUES('3300037073_46_5978-6066','3300037073',46,'41 卫生假说和老朋友','这样不是很理想，因为顺产时，婴儿会和母亲的阴道中、常常还有粪便中的微生物组亲密接触。出生其实是让身体和免疫系统开始适应微生物的第一步。出生方式不同的小孩，微生物组会有显著差别。','5978-6066',5,1714192201,1782480559);
INSERT INTO highlights VALUES('3300037073_46_5661-5719','3300037073',46,'41 卫生假说和老朋友','就像我们说过的，直到不久前，人类住的房子都还取材于木头、泥巴、茅草等天然材料，材料中都是免疫系统再熟悉不过的微生物。','5661-5719',5,1714192118,1782480559);
INSERT INTO highlights VALUES('3300037073_46_5206-5287','3300037073',46,'41 卫生假说和老朋友','不幸的是（你也可以觉得是幸运），现在大部分人都不再生活在农场里。现在我们周围已经没有了那些和我们共同演化的丰富的微生物生态系统。我们把自己和各种自然环境隔绝了开来','5206-5287',5,1714135055,1782480559);
INSERT INTO highlights VALUES('3300037073_46_4072-4152','3300037073',46,'41 卫生假说和老朋友','这种对人和微生物的关系更微妙的描述有好几种名称，其中“老朋友”假说可能最贴切，它更关注人类的演化。','4072-4152',5,1714052159,1782480559);
INSERT INTO highlights VALUES('3300037073_46_3991-4046','3300037073',46,'41 卫生假说和老朋友','应该说，我们需要接触无害的微生物来训练免疫系统。','3991-4046',5,1714052145,1782480559);
INSERT INTO highlights VALUES('3300037073_46_3160-3215','3300037073',46,'41 卫生假说和老朋友','人们经常把卫生和干净混为一谈，但你要知道，卫生追求的是在关乎健康的关键情况下，从关键的地方刻意去除潜在病原体。','3160-3215',5,1714052024,1782480559);
INSERT INTO highlights VALUES('3300037073_46_2715-2756','3300037073',46,'41 卫生假说和老朋友','随着人类开始农耕并成为城市定居者，我们的生活方式永远地改变了——疾病的种类也变了。','2715-2756',5,1714051964,1782480559);
INSERT INTO highlights VALUES('3300037073_46_2399-2434','3300037073',46,'41 卫生假说和老朋友','演化角度来讲，现代大部分致病性最强的细菌和病毒，对人类来说都是全新的。','2399-2434',5,1714051928,1782480559);
INSERT INTO highlights VALUES('3300037073_46_1918-2006','3300037073',46,'41 卫生假说和老朋友','关于卫生的“直觉性”看法，以及它想象中的危害，没有考虑到人类免疫系统和周遭微小生物的共同演化。几十万年前，人类祖先的免疫系统确实适应他们的生活环境，但那时的情况与今天大不相同。','1918-2006',5,1714009867,1782480559);
INSERT INTO highlights VALUES('3300037073_45_6874-7035','3300037073',45,'40 自身免疫性疾病','树突状细胞要是在淋巴结里传达了“一切正常，你看看吧”这样的信息，其实可以防止自身免疫性疾病的发生。因为它实际上是在搜寻自身反应性T细胞，即那些能通过MHC分子和自身抗原结合的T细胞。树突状细胞如果碰巧发现了哪个自身反应性T细胞，就可以与之结合，阻止它继续作乱。','6874-7035',5,1714009636,1782480559);
INSERT INTO highlights VALUES('3300037073_45_3780-3818','3300037073',45,'40 自身免疫性疾病','墨菲定律”局面：可能出错的地方全都出了错，免疫细胞被激活的所有条件都满足了。','3780-3818',5,1713923313,1782480559);
INSERT INTO highlights VALUES('3300037073_45_3818-3866','3300037073',45,'40 自身免疫性疾病','甚至，情况还会变得更糟！活化的辅助性T细胞开始激活B细胞，而B细胞可以根据自身抗原来进行自我调适','3818-3866',5,1713923303,1782480559);
INSERT INTO highlights VALUES('3300037073_45_2812-2901','3300037073',45,'40 自身免疫性疾病','其实每个T细胞和B细胞的受体，识别抗原的范围要更宽一点。每个受体都很擅长识别某个特定抗原，但也能和其他一些抗原结合。','2812-2901',5,1713878675,1782480559);
INSERT INTO highlights VALUES('3300037073_45_2601-2660','3300037073',45,'40 自身免疫性疾病','对病毒或细菌来说，人体组织就好比一片森林，到处是凶狠的捕猎者在搜寻它们的下落，因此模拟周围环境不被发现是很有效的策略。','2601-2660',5,1713878658,1782480559);
INSERT INTO highlights VALUES('3300037073_45_2232-2257','3300037073',45,'40 自身免疫性疾病','基本是指微生物的抗原和体细胞抗原（自身抗原）很相似','2232-2257',5,1713878620,1782480559);
INSERT INTO highlights VALUES('3300037073_45_2207-2232','3300037073',45,'40 自身免疫性疾病','免疫学家中间有一个比较流行的理论，叫“分子相似”，','2207-2232',5,1713878617,1782480559);
INSERT INTO highlights VALUES('3300037073_45_1884-2113','3300037073',45,'40 自身免疫性疾病',unistr('自身免疫性疾病的发生步骤可能是这样的：\u000a INSERT INTO highlights VALUES('3300037073_44_3164-3218','3300037073',44,'39 免疫系统可能想念寄生虫','全球有数百万人患有自身免疫性疾病。自身免疫性疾病就是，患者的免疫系统把自身当成了异物，当成了必须摧毁的对象。','3164-3218',5,1713680045,1782480559);
INSERT INTO highlights VALUES('3300037073_44_2590-2641','3300037073',44,'39 免疫系统可能想念寄生虫','所以他们的身体不得不适应长期甚至终身感染寄生虫的情况。其中有一项适应策略可能就是上调免疫系统的亢进性。','2590-2641',5,1713679950,1782480559);
INSERT INTO highlights VALUES('3300037073_44_2442-2506','3300037073',44,'39 免疫系统可能想念寄生虫','因此，有科学家表示，发达国家的人不被寄生虫感染，这会让免疫系统觉得很奇怪，因为它现在的演化结果，预设了人体会经常遭遇寄生虫感染。','2442-2506',5,1713679920,1782480559);
INSERT INTO highlights VALUES('3300037073_44_2318-2359','3300037073',44,'39 免疫系统可能想念寄生虫','但也不是所有结果都是坏的：寄生虫也能抑制可以引发炎症、过敏和自身免疫性疾病的机制。','2318-2359',5,1713679898,1782480559);
INSERT INTO highlights VALUES('3300037073_44_1580-1640','3300037073',44,'39 免疫系统可能想念寄生虫','所以第一次认出寄生虫——很可能在身体与外界的交界处——驻扎在皮肤、呼吸道或肠道附近的特殊B细胞会开始生成大量IgE抗体。','1580-1640',5,1713679679,1782480559);
INSERT INTO highlights VALUES('3300037073_44_576-635','3300037073',44,'39 免疫系统可能想念寄生虫','世界上有近300种寄生虫可以感染人类。尽管其中只有十几种广泛传播，但它们仍感染了多达20亿人，占全球总人口的近1/3。','576-635',5,1713679599,1782480559);
INSERT INTO highlights VALUES('3300037073_43_4642-4706','3300037073',43,'38 免疫系统太激进：过敏',unistr('IgE本来的作用应该是这样的：\u000a它们是免疫系统对付大型寄生生物的超级武器'),'4642-4706',5,1713679559,1782480559);
INSERT INTO highlights VALUES('3300037073_43_4344-4505','3300037073',43,'38 免疫系统太激进：过敏','许多哮喘患者都知道，有些过敏反应是慢性而不是一过性的。我们快来认识一下过敏反应的第三位（谢天谢地也是最后一位）支持者：“嗜酸性粒细胞”。这种细胞会确保过敏持续上一阵。嗜酸性粒细胞在体内只有少量，主要位于骨髓中，远离炎症现场。它们会被肥大细胞和嗜碱性粒细胞释放的细胞因子激活，并不慌不忙地自我复制、增殖，然后才加入作战部队。','4344-4505',5,1713679486,1782480559);
INSERT INTO highlights VALUES('3300037073_43_4032-4102','3300037073',43,'38 免疫系统太激进：过敏','烂摊子不是它自己造成的，它还有个同样有害的同伙。肥大细胞一旦活化并脱颗粒，就会释放细胞因子，请求另一种特殊细胞的增援，这就是“嗜碱性粒细胞”','4032-4102',5,1713679176,1782480559);
INSERT INTO highlights VALUES('3300037073_43_3568-3631','3300037073',43,'38 免疫系统太激进：过敏','最可怕的是，组胺会引起呼吸系统的平滑肌收缩，让人呼吸困难甚至无法呼吸。不是外界的空气吸不进来，而是肺部的气体被困住了，难以出去','3568-3631',5,1713679104,1782480559);
INSERT INTO highlights VALUES('3300037073_43_3454-3493','3300037073',43,'38 免疫系统太激进：过敏','如果身体太多部位同时发生过敏反应，可能会导致血压严重下降，仅此一点就足以致命。','3454-3493',5,1713679093,1782480559);
INSERT INTO highlights VALUES('3300037073_43_3209-3280','3300037073',43,'38 免疫系统太激进：过敏','时光流逝，岁月静好，直到有一天你又吃了一堆蟹肉，体内涌入大量过敏原，并与表面盖满了IgE的肥大细胞结合。蓄势待发的过敏炸弹就这样在体内爆炸了。','3209-3280',5,1713679063,1782480559);
INSERT INTO highlights VALUES('3300037073_43_3128-3168','3300037073',43,'38 免疫系统太激进：过敏','而且，肥大细胞表面的抗体几周甚至数月都不会分解——与过敏原的结合使它们更稳定了。','3128-3168',5,1713679054,1782480559);
INSERT INTO highlights VALUES('3300037073_43_3063-3102','3300037073',43,'38 免疫系统太激进：过敏','你可以把“装填弹药”的肥大细胞想象成一块大磁铁，表面吸附着成千上万颗抗体小钉子','3063-3102',5,1713679044,1782480559);
INSERT INTO highlights VALUES('3300037073_43_2931-2972','3300037073',43,'38 免疫系统太激进：过敏','确定的是，肥大细胞可以加剧炎症反应。而且不幸的是，在过敏反应中，它们还会过于卖力。','2931-2972',5,1713679032,1782480559);
INSERT INTO highlights VALUES('3300037073_43_2111-2157','3300037073',43,'38 免疫系统太激进：过敏','过敏原进入人体，可与之结合的B细胞出于某些原因被激活了。B细胞开始生成有针对性的IgE抗体，','2111-2157',5,1713678747,1782480559);
INSERT INTO highlights VALUES('3300037073_43_2649-2765','3300037073',43,'38 免疫系统太激进：过敏','IgE抗体本身不是问题，它们存在的时间不长，几天就代谢掉了。它们要成为问题，需要一种特殊细胞的帮助，那就是生活在皮肤上、呼吸系统和肠道中，并且擅长跟IgE结合的肥大细胞。','2649-2765',5,1713678744,1782480559);
INSERT INTO highlights VALUES('3300037073_43_2026-2056','3300037073',43,'38 免疫系统太激进：过敏','超敏反应一般分两步：初遇（致死的）过敏原；之后还需再次接触。','2026-2056',5,1713678674,1782480559);
INSERT INTO highlights VALUES('3300037073_43_1896-1978','3300037073',43,'38 免疫系统太激进：过敏','生成IgE的是特化的B细胞，它们往往不驻扎在淋巴结中，而是在皮肤、肺部和肠道：在这些地方，它们可以发挥最大威力——本是要对付突破防线的敌人，实际上却主要在误伤人体。','1896-1978',5,1713678666,1782480559);
INSERT INTO highlights VALUES('3300037073_43_1733-1829','3300037073',43,'38 免疫系统太激进：过敏','速发型超敏反应的元凶来自血液，干坏事的是整个免疫系统中最令人头疼的成员：IgE抗体。许多和过敏有关的痛苦都可以归结到IgE抗体头上','1733-1829',5,1713678645,1782480559);
INSERT INTO highlights VALUES('3300037073_43_1352-1401','3300037073',43,'38 免疫系统太激进：过敏','各种程度的花粉症、哮喘和食物过敏是发达国家最常见的速发型超敏反应。基本上，所有东西都可能引起过敏。','1352-1401',5,1713678604,1782480559);
INSERT INTO highlights VALUES('3300037073_43_1239-1289','3300037073',43,'38 免疫系统太激进：过敏','1/5的西方人患有某种过敏，最常见的是“速发型超敏反应”，就是说接触过敏原后几分钟就会出现过敏症状。','1239-1289',5,1713678590,1782480559);
INSERT INTO highlights VALUES('3300037073_43_1046-1090','3300037073',43,'38 免疫系统太激进：过敏','埃博拉病毒吧，感染了这种恶心又恐怖的病毒，也要6天才会死；而过敏发作，15分钟就会没命。','1046-1090',5,1713678571,1782480559);
INSERT INTO highlights VALUES('3300037073_42_5076-5124','3300037073',42,'第4部分 反叛与内战','因为有了科学界和医学界前所未有的巨大努力，对接受了恰当治疗的患者来说，艾滋病已成为可控的慢性病。','5076-5124',5,1713550667,1782480559);
INSERT INTO highlights VALUES('3300037073_42_4717-4780','3300037073',42,'第4部分 反叛与内战','：重度免疫抑制，身体出现“获得性免疫缺陷综合征”，即“艾滋病”。','4717-4780',5,1713550615,1782480559);
INSERT INTO highlights VALUES('3300037073_42_4243-4299','3300037073',42,'第4部分 反叛与内战','是双方的生死较量，可以持续十年甚至更久，却几乎对身体没有任何影响——这也糟糕地使感染者成了病毒库，可以感染他人。','4243-4299',5,1713550530,1782480559);
INSERT INTO highlights VALUES('3300037073_42_3196-3279','3300037073',42,'第4部分 反叛与内战','的遗传变异性处在完全不同的级别上，这就是它如此危险的原因。HIV的遗传编码极易发生复制错误：平均每次复制都会出错。这意味着，单一个细胞里面，就有好多不同的HIV变体。','3196-3279',5,1713550330,1782480559);
INSERT INTO highlights VALUES('3300037073_42_2145-2201','3300037073',42,'第4部分 反叛与内战','但HIV有很多奇招：它不仅仅是通过大量自我复制直到细胞破裂来传播——它小心得多，会努力尽可能延长感染细胞的生命。','2145-2201',5,1713550088,1782480559);
INSERT INTO highlights VALUES('3300037073_42_1215-1382','3300037073',42,'第4部分 反叛与内战',unistr('HIV感染过程有三个阶段：\u000a第一个阶段是急性期。现在认为，树突状细胞属于HIV最先感染和接管的一批细胞。这对病毒来说非常有利，因为树突状细胞在履行职责时，就会把HIV带到细胞的聚会之地：淋巴结大都市中的T细胞约会区。'),'1215-1382',5,1713549953,1782480559);
INSERT INTO highlights VALUES('3300037073_42_656-687','3300037073',42,'第4部分 反叛与内战','作为一个物种来说，我们极其幸运，因为HIV的传染性不是特别强。','656-687',5,1713549576,1782480559);
INSERT INTO highlights VALUES('3300037073_42_515-557','3300037073',42,'第4部分 反叛与内战','HIV。事实上，它影响的不是整个免疫系统，而主要只是非常特殊的一种细胞：辅助性T细胞','515-557',5,1713549537,1782480559);
INSERT INTO highlights VALUES('3300037073_41_7728-7832','3300037073',41,'36 疫苗和人工免疫','群体免疫指的是对某种疾病免疫的人，数量多到该疾病无法传播，在有机会接触易感的人之前就能消亡。问题在于，要让群体免疫策略起效，必须给足够多的人接种，比如对麻疹来说，要95%的人接种疫苗，才能产生有效的群体免疫。','7728-7832',5,1713549485,1782480559);
INSERT INTO highlights VALUES('3300037073_41_7598-7644','3300037073',41,'36 疫苗和人工免疫','如果所有健康条件允许的人都接种某种疫苗，就能形成相应的“群体免疫”，可以保护那些无法接种的人','7598-7644',5,1713549467,1782480559);
INSERT INTO highlights VALUES('3300037073_41_6555-6607','3300037073',41,'36 疫苗和人工免疫','最后，我们也提一下最新型的“mRNA疫苗”。其基本原理非常巧妙：让人体自身细胞生成抗原，供免疫系统识别。','6555-6607',5,1713549359,1782480559);
INSERT INTO highlights VALUES('3300037073_41_6384-6414','3300037073',41,'36 疫苗和人工免疫','比如生产乙型肝炎疫苗，要把病毒DNA的一些部分植入酵母细胞中','6384-6414',5,1713549326,1782480559);
INSERT INTO highlights VALUES('3300037073_41_6188-6263','3300037073',41,'36 疫苗和人工免疫','比灭活疫苗走得更远的是“亚单位疫苗”。它利用的不是完整的病原体，而只是其“亚单位”，或者说是病原体的特定部分（抗原），因此更容易被T细胞和B细胞识别。','6188-6263',5,1713549258,1782480559);
INSERT INTO highlights VALUES('3300037073_41_6085-6129','3300037073',41,'36 疫苗和人工免疫','首先，这些化学物质剂量非常小，通常只会引发局部反应。而没有这些物质，灭活疫苗就不能起效。','6085-6129',5,1713549247,1782480559);
INSERT INTO highlights VALUES('3300037073_41_5631-5661','3300037073',41,'36 疫苗和人工免疫','所以另有一种办法是，在注射前直接杀死病原体，叫“灭活疫苗”。','5631-5661',5,1713549196,1782480559);
INSERT INTO highlights VALUES('3300037073_41_5418-5459','3300037073',41,'36 疫苗和人工免疫','活疫苗当然有其缺点——比如疫苗必须在适当的温度下储存，以免弱化的病毒在接种前死亡。','5418-5459',5,1713549181,1782480559);
INSERT INTO highlights VALUES('3300037073_41_5109-5146','3300037073',41,'36 疫苗和人工免疫','我们今天的麻疹疫苗，所用病毒是在20世纪50年代从一个孩子身上分离得到的。','5109-5146',5,1713549031,1782480559);
INSERT INTO highlights VALUES('3300037073_41_4806-4897','3300037073',41,'36 疫苗和人工免疫','我们能不能想办法，让人在某种程度上染病，但病得非常非常轻？这就是“减毒活疫苗”的原理：注射真的病原体，但致病性大大减轻。','4806-4897',5,1713245967,1782480559);
INSERT INTO highlights VALUES('3300037073_41_3821-3864','3300037073',41,'36 疫苗和人工免疫','怀孕的时候也会发生被动免疫，某些抗体可以通过胎盘进入胎儿体内，让胎儿获得母体的免疫力。','3821-3864',5,1713245870,1782480559);
INSERT INTO highlights VALUES('3300037073_41_3226-3302','3300037073',41,'36 疫苗和人工免疫','生产此类抗体的过程很奇特：人们从毒蛇身上采集毒液，注射进马或兔子这些哺乳动物体内，毒液的剂量在动物可以耐受的范围内，并且慢慢增加，让动物有机会产生免疫力','3226-3302',5,1713245833,1782480559);
INSERT INTO highlights VALUES('3300037073_41_3034-3140','3300037073',41,'36 疫苗和人工免疫',unistr('被有毒的动物咬伤非常危险，因为毒素造成的伤害来势极为迅速，而且只会不断恶化，很多时候根本不可能等上一星期让适应性免疫系统完成工作，因为在这之前人都死掉了。\u000a'),'3034-3111',5,1713245806,1782480559);
INSERT INTO highlights VALUES('3300037073_41_2716-2786','3300037073',41,'36 疫苗和人工免疫','抗体不光能对抗病原体，还能对抗其毒素。在微观世界中，有毒物质其实就是某种分子，它们会扰乱生命的自然过程，或是破坏、溶解一些结构从而造成损伤。','2716-2786',5,1713245752,1782480559);
INSERT INTO highlights VALUES('3300037073_41_2557-2591','3300037073',41,'36 疫苗和人工免疫','被动免疫就是从其他的幸存者身上获得对某疾病或某病原体的免疫力的过程。','2557-2591',5,1713245728,1782480559);
INSERT INTO highlights VALUES('3300037073_41_1235-1285','3300037073',41,'36 疫苗和人工免疫','疫苗接种史的真正开启，是在人们意识到没必要用真的天花病毒进行人痘接种，而可以用更安全的“牛痘”之时。','1235-1285',5,1713228001,1782480559);
INSERT INTO highlights VALUES('3300037073_41_755-791','3300037073',41,'36 疫苗和人工免疫','仅在20世纪，天花就夺走了3亿人的生命，因此，人们迫切地希望能做点什么。','755-791',5,1713227954,1782480559);
INSERT INTO highlights VALUES('3300037073_40_5044-5062','3300037073',40,'35 免疫系统是怎样牢记敌人的','就好像免疫系统突然得了严重的失忆症。','5044-5062',5,1713227795,1782480559);
INSERT INTO highlights VALUES('3300037073_40_4949-4993','3300037073',40,'35 免疫系统是怎样牢记敌人的','免疫系统往往能控制住局面，消灭麻疹病毒。只是感染了麻疹病毒的记忆细胞都死掉了，无法复生。','4949-4993',5,1713227781,1782480559);
INSERT INTO highlights VALUES('3300037073_40_4736-4806','3300037073',40,'35 免疫系统是怎样牢记敌人的','。麻疹患者有很强的传染性，90%易感者只要接近患者，就会被感染。和麻疹患者同处一节地铁车厢或一间教室，又没有打过疫苗的人，都极有可能被感染。','4736-4806',5,1713227751,1782480559);
INSERT INTO highlights VALUES('3300037073_40_4665-4736','3300037073',40,'35 免疫系统是怎样牢记敌人的','麻疹病毒的传染性非常强——比新冠病毒还强得多。和其他许多病毒一样，麻疹病毒会借着咳嗽和打喷嚏形成的飞沫飘散到空气中，并在空气中停留多达两个小时','4665-4736',5,1713227744,1782480559);
INSERT INTO highlights VALUES('3300037073_40_4530-4568','3300037073',40,'35 免疫系统是怎样牢记敌人的','从麻疹感染中恢复的孩子，患上其他疾病的概率更高，因为麻疹病毒会杀死记忆细胞。','4530-4568',5,1713227726,1782480559);
INSERT INTO highlights VALUES('3300037073_40_3573-3618','3300037073',40,'35 免疫系统是怎样牢记敌人的','有些病能破坏免疫记忆，杀死记忆细胞。令人心痛的是，其中有一种病如今又卷土重来，它就是麻疹。','3573-3618',5,1713198729,1782480559);
INSERT INTO highlights VALUES('3300037073_40_2577-2605','3300037073',40,'35 免疫系统是怎样牢记敌人的','剩下的10%会变成“组织驻留记忆T细胞”，成为静默的卫士','2577-2605',5,1713198621,1782480559);
INSERT INTO highlights VALUES('3300037073_40_2071-2158','3300037073',40,'35 免疫系统是怎样牢记敌人的','这还不是全部，还有“记忆B细胞”。它们，什么都不干。这些记忆B细胞被激活后，也待在淋巴结中，只是休息。在漫长的岁月中，它们就这样待着不动，静静地扫描淋巴液，寻找记忆中的抗原。','2071-2158',5,1713198547,1782480559);
INSERT INTO highlights VALUES('3300037073_40_1985-2042','3300037073',40,'35 免疫系统是怎样牢记敌人的','你的每一滴血液中都有13000000000000抗体。13万亿啊。这份蛋白质记忆中，包含着你一生中战胜的所有疾病。','1985-2042',5,1713198529,1782480559);
INSERT INTO highlights VALUES('3300037073_40_1841-1905','3300037073',40,'35 免疫系统是怎样牢记敌人的','生活在骨髓中的长寿命浆细胞可以持续生成一定量的抗体。所以它们的全部职责就是保证体液中时刻都有特定的抗体，能对抗一度战胜过的敌人。','1841-1905',5,1713198517,1782480559);
INSERT INTO highlights VALUES('3300037073_40_1672-1727','3300037073',40,'35 免疫系统是怎样牢记敌人的','B细胞被T细胞激活后，有一部分B细胞就会变成各种类型的记忆细胞，成为会在以后的岁月甚至余生中守护你的鲜活记忆。','1672-1727',5,1713198501,1782480559);
INSERT INTO highlights VALUES('3300037073_40_1410-1473','3300037073',40,'35 免疫系统是怎样牢记敌人的','同样，随着我们老去，越来越多的记忆细胞也无法像它们年轻时工作得那么出色了，或者说它们都退役了，这也让我们在老年阶段更容易生病。','1410-1473',5,1713187326,1782480559);
INSERT INTO highlights VALUES('3300037073_40_1186-1228','3300037073',40,'35 免疫系统是怎样牢记敌人的','人体有近1000亿记忆细胞，它们分布于全身，专注于记录你的患病经历，此外什么都不做。','1186-1228',5,1713187290,1782480559);
INSERT INTO highlights VALUES('3300037073_39_2243-2281','3300037073',39,'34 关闭免疫应答','我们不会再深入更多细节，因为调节性T细胞很复杂，还有许多没有研究清楚的地方。','2243-2281',5,1713178949,1782480559);
INSERT INTO highlights VALUES('3300037073_39_1724-1808','3300037073',39,'34 关闭免疫应答','当然，这其中也有意外，因为人体有一类细胞，能主动关闭免疫防御机制，下调免疫应答，这就是“调节性T细胞”。它们只占T细胞总数的5%，某种意义上可说是“反向辅助性T细胞”。','1724-1808',5,1713178905,1782480559);
INSERT INTO highlights VALUES('3300037073_39_1662-1695','3300037073',39,'34 关闭免疫应答','免疫系统在赢得胜利的同时，就已经开始关停自身了，无需任何中心规划。','1662-1695',5,1713178879,1782480559);
INSERT INTO highlights VALUES('3300037073_39_1544-1587','3300037073',39,'34 关闭免疫应答','整个免疫系统都需要刺激才能持续运行，因此，一旦激活链条停止，免疫应答就会逐渐平息下来。','1544-1587',5,1713178869,1782480559);
INSERT INTO highlights VALUES('3300037073_39_1106-1203','3300037073',39,'34 关闭免疫应答','杀伤性T细胞在自然杀伤细胞的帮助下，开始消灭感染的普通细胞。同时，活化的B细胞化身为浆细胞，释放出千百万的抗体，涌向战场，中和、打击病原体，让它们更容易被清除。这就是“简而言之”的免疫应答过程。','1106-1203',5,1713178835,1782480559);
INSERT INTO highlights VALUES('3300037073_38_5715-5792','3300037073',38,'33 如何清除病毒感染','我们无法生产扰乱病毒各新陈代谢环节的药，比如对付核糖体的药。因为病毒利用的就是人类的核糖体。','5715-5792',5,1713178638,1782480559);
INSERT INTO highlights VALUES('3300037073_38_5643-5697','3300037073',38,'33 如何清除病毒感染','要是我们针对某类能结合这种体细胞受体的病毒来开发药物，那么，这种药物就很可能攻击所有能结合该受体的人体蛋白。','5643-5697',5,1713178612,1782480559);
INSERT INTO highlights VALUES('3300037073_38_5497-5642','3300037073',38,'33 如何清除病毒感染','要在细胞外攻击病毒，就要攻击那些能和体细胞受体结合的病毒蛋白。而这种方法最大、最突出的问题，就是能够抑制病毒蛋白的药物，也会跟人体的许多部分结合。因为病毒要和体细胞受体结合，就必须伪装成人体的一部分，这一部分还要具备某种关键功能','5497-5642',5,1713178592,1782480559);
INSERT INTO highlights VALUES('3300037073_38_5329-5432','3300037073',38,'33 如何清除病毒感染','其实我们有几千种对付病毒感染的药物，但问题是，这些药大部分都很危险，甚至会致人死亡。许多药不到万不得已不能用，只有在病人命悬一线的情况下才能用。','5329-5432',5,1713178553,1782480559);
INSERT INTO highlights VALUES('3300037073_38_4809-4856','3300037073',38,'33 如何清除病毒感染','人类和细菌二者的核糖体尽管功能基本一样，但形状不同，因此四环素能抑制细菌核糖体，而不影响人体细','4809-4856',5,1713178474,1782480559);
INSERT INTO highlights VALUES('3300037073_38_4677-4720','3300037073',38,'33 如何清除病毒感染','你可能还听说过“四环素”，它来自“金色链霉菌”，通过抑制细菌的蛋白质合成而发挥抗菌作用','4677-4720',5,1713178464,1782480559);
INSERT INTO highlights VALUES('3300037073_38_4089-4212','3300037073',38,'33 如何清除病毒感染','为什么就没有治疗流感、普通感冒或新型冠状病毒的特效药？问题根本上在于：病毒和人体细胞太像了。等一下，这是什么意思？我不是说单个病毒本身像人体细胞，而是说病毒可以模仿细胞或是与细胞结合。','4089-4212',5,1713178383,1782480559);
INSERT INTO highlights VALUES('3300037073_38_1828-1857','3300037073',38,'33 如何清除病毒感染','在这一过程中，抗体能与病毒神经氨酸酶结合，从而阻断出芽过程','1828-1857',5,1713102207,1782480559);
INSERT INTO highlights VALUES('3300037073_38_1895-1912','3300037073',38,'33 如何清除病毒感染','这些病毒就像苍蝇被粘在了粘蝇板上。','1895-1912',5,1713102181,1782480559);
INSERT INTO highlights VALUES('3300037073_38_1593-1693','3300037073',38,'33 如何清除病毒感染','病毒表面有和上皮细胞结合的结构，而中和抗体会和这类结构牢牢结合，从而让病毒失去攻击性。病毒被数十抗体覆盖后，就不能侵入细胞，而会变成一团没功能也没有危害的遗传编码和蛋白质，最后还是会被巨噬细胞清除掉。','1593-1693',5,1713102124,1782480559);
INSERT INTO highlights VALUES('3300037073_38_1332-1440','3300037073',38,'33 如何清除病毒感染','成千上万的杀伤性T细胞，装备着能识别甲流病毒的受体，涌入肺部。它们一个个地检查细胞，热情地拥抱后者，从细胞的MHC-Ⅰ展示窗仔细地往里面看，倾听细胞讲述内部蛋白质的故事。一旦发现病毒抗原，它们就会下令让感染细胞自尽。','1332-1440',5,1713102087,1782480559);
INSERT INTO highlights VALUES('3300037073_38_1140-1198','3300037073',38,'33 如何清除病毒感染','成千上万的树突状细胞在战场上取样，它们俘获病毒，再将其撕成碎片，放入自己的MHC-Ⅰ类分子（及MHC-Ⅱ类分子）中。','1140-1198',5,1713102054,1782480559);
INSERT INTO highlights VALUES('3300037073_38_839-874','3300037073',38,'33 如何清除病毒感染','自然杀伤细胞需要两三天才能抵达战场，开始为拼命奋战的免疫细胞分担重任。','839-874',5,1713101929,1782480559);
INSERT INTO highlights VALUES('3300037073_37_3006-3069','3300037073',37,'32 天生杀手','要是发现了太多的压力信号，自然杀伤细胞会把已经承受不住的可怜细胞直接爆头。要是有人形自然杀伤细胞的话，在他们身边你一定要多笑！','3006-3069',5,1713101811,1782480559);
INSERT INTO highlights VALUES('3300037073_37_1347-1469','3300037073',37,'32 天生杀手','别的免疫细胞都是寻找异常的、非自身的东西是否存在，而自然杀伤细胞却是找正常的、自身的东西是否缺失。这叫“自我缺失”假说。','1347-1469',5,1713093694,1782480559);
INSERT INTO highlights VALUES('3300037073_37_1267-1303','3300037073',37,'32 天生杀手','自然杀伤细胞专门搜寻那些不分享内部信息的细胞，弥补了免疫系统的致命漏洞。','1267-1303',5,1713093685,1782480559);
INSERT INTO highlights VALUES('3300037073_37_1211-1261','3300037073',37,'32 天生杀手','所以，自然杀伤细胞只检查一点：细胞有没有展示窗？有？“太好了，请您继续保持。”没有？“请马上自裁！”','1211-1261',5,1713093677,1782480559);
INSERT INTO highlights VALUES('3300037073_37_680-708','3300037073',37,'32 天生杀手','简而言之，它要找两种敌人：被病毒感染的细胞和癌变的细胞。','680-708',5,1713093567,1782480559);
INSERT INTO highlights VALUES('3300037073_37_471-517','3300037073',37,'32 天生杀手','你可以把它想象成这样的年轻人：他们的家族世代都是战斗机飞行员，但他们要违背传统去加入地面部队','471-517',5,1713093494,1782480559);
INSERT INTO highlights VALUES('3300037073_37_391-407','3300037073',37,'32 天生杀手','“天生杀手”自然杀伤细胞很可怕。','391-407',5,1713093488,1782480559);
INSERT INTO highlights VALUES('3300037073_36_3340-3482','3300037073',36,'31 专业杀手：杀伤性T细胞','所以杀伤性T细胞不会这样做，而只是在感染细胞上扎一个洞，传递死亡信号，下达特殊命令：凋亡，就是我们前面提过的细胞有序死亡。这样，病毒微粒仍然完好地包裹在死细胞之内，不会造成进一步破坏，直到路过的巨噬细胞把死细胞的遗体吃掉。','3340-3482',5,1713089881,1782480559);
INSERT INTO highlights VALUES('3300037073_36_2336-2374','3300037073',36,'31 专业杀手：杀伤性T细胞','。这一切靠的都是一个树突状细胞，它带来了适应性免疫系统渴求的各种情报和抗原。','2336-2374',5,1713089778,1782480559);
INSERT INTO highlights VALUES('3300037073_35_4341-4424','3300037073',35,'30 细胞之窗','这也是接受器官移植后，病人只得终身服用强效免疫抑制剂的原因。这是为了尽量不让自体免疫细胞发现异体MHC-Ⅰ类分子并杀死异体细胞。但是这无疑会大大降低病人抗感染的能力。','4341-4424',5,1713089149,1782480559);
INSERT INTO highlights VALUES('3300037073_35_2241-2278','3300037073',35,'30 细胞之窗','在回收蛋白的时候，细胞会随机采集蛋白碎片，转运到细胞膜上，对外部呈现出来。','2241-2278',5,1713054729,1782480559);
INSERT INTO highlights VALUES('3300037073_35_2103-2143','3300037073',35,'30 细胞之窗','所有含有细胞核的体细胞（那就不包括红细胞了）都有MHC-Ⅰ类分子。','2103-2143',5,1713054709,1782480559);
INSERT INTO highlights VALUES('3300037073_35_1623-1644','3300037073',35,'30 细胞之窗','：Ⅰ型主要组织相容性复合体（MHC-Ⅰ）。','1623-1644',5,1713022590,1782480559);
INSERT INTO highlights VALUES('3300037073_34_9538-9571','3300037073',34,'29 化学战：干扰素，干扰起来！','只需想一下，要是免疫细胞出了错，决定杀死正常的组织和器官，会怎么样','9538-9571',5,1712995984,1782480559);
INSERT INTO highlights VALUES('3300037073_34_8755-8796','3300037073',34,'29 化学战：干扰素，干扰起来！','颜色只能反映鼻内炎症的严重程度，不能判断病因。颜色越黄，说明牺牲的中性粒细胞越多。','8755-8796',5,1712995803,1782480559);
INSERT INTO highlights VALUES('3300037073_34_7124-7190','3300037073',34,'29 化学战：干扰素，干扰起来！','简单地说：蛋白质之间的某些化学反应有一个最佳温度区间，在这个温度范围内反应效率最高。发热时体温升高，病原体就只得在最佳区间之外行事。','7124-7190',5,1712995672,1782480559);
INSERT INTO highlights VALUES('3300037073_34_6905-6933','3300037073',34,'29 化学战：干扰素，干扰起来！','发热时，先天性和适应性免疫系统在好些方面都表现得更为出色','6905-6933',5,1712995630,1782480559);
INSERT INTO highlights VALUES('3300037073_34_6178-6222','3300037073',34,'29 化学战：干扰素，干扰起来！','大部分能感染人类的病原体都很适应人体的正常体温，而发热时，更高的体温会让它们过得很痛苦。','6178-6222',5,1712981328,1782480559);
INSERT INTO highlights VALUES('3300037073_34_5826-5890','3300037073',34,'29 化学战：干扰素，干扰起来！','一种产热方式是让人打寒战，即让肌肉会快速收缩，同时产生热作为副产物；另一种是让体表的血管收缩，减少皮肤的热量散失，从而保持热量。','5826-5890',5,1712981278,1782480559);
INSERT INTO highlights VALUES('3300037073_34_5732-5780','3300037073',34,'29 化学战：干扰素，干扰起来！','热原质进入脑内，会和神经细胞发生作用，引发复杂的连锁反应，改变人体的内在恒温设定，从而升高体温。','5732-5780',5,1712883589,1782480559);
INSERT INTO highlights VALUES('3300037073_34_5291-5381','3300037073',34,'29 化学战：干扰素，干扰起来！','大致解释，热原质就是“产生热的物质”，这个名字非常贴切。简单地说，热原质就是引起“发热”的化学物质。发热是系统性的全身反应，它会形成不利于病原体生活的环境，让免疫细胞能更有力地战斗','5291-5381',5,1712883561,1782480559);
INSERT INTO highlights VALUES('3300037073_34_5102-5148','3300037073',34,'29 化学战：干扰素，干扰起来！','中性粒细胞似乎不能有效抵抗病毒，所以它们的作用主要是间接的：它们无所顾忌，可以增强炎症水平。','5102-5148',5,1712883552,1782480559);
INSERT INTO highlights VALUES('3300037073_34_5243-5262','3300037073',34,'29 化学战：干扰素，干扰起来！','于是释放出另一组细胞因子：“热原质”。','5243-5262',5,1712883527,1782480559);
INSERT INTO highlights VALUES('3300037073_34_2641-2655','3300037073',34,'29 化学战：干扰素，干扰起来！','浆细胞样树突状细胞(pDC)','2641-2655',1,1712675135,1782480559);
INSERT INTO highlights VALUES('3300037073_34_2281-2324','3300037073',34,'29 化学战：干扰素，干扰起来！','尽管甲型流感病毒并不总能成功阻止细胞释放干扰素，但它很擅长加以阻挠，为自己争取更多时间','2281-2324',1,1712674758,1782480559);
INSERT INTO highlights VALUES('3300037073_34_2144-2182','3300037073',34,'29 化学战：干扰素，干扰起来！','病毒在注入自己的遗传信息、接管细胞的同时，还准备了一些“病毒‘攻击’蛋白”。','2144-2182',1,1712674734,1782480559);
INSERT INTO highlights VALUES('3300037073_34_1935-1951','3300037073',34,'29 化学战：干扰素，干扰起来！','干扰素可以干扰病毒复制的每一步。','1935-1951',1,1712674549,1782480559);
INSERT INTO highlights VALUES('3300037073_34_1713-1751','3300037073',34,'29 化学战：干扰素，干扰起来！','每时每刻，细胞都在回收和重建细胞内部构件和材料，确保蛋白的形状和功能都正常。','1713-1751',1,1712674284,1782480559);
INSERT INTO highlights VALUES('3300037073_34_1456-1534','3300037073',34,'29 化学战：干扰素，干扰起来！','你可以把干扰素想象成回荡在大街小巷的警示，它呼吁大家锁好大门，再用家具顶住，窗户也要用木板钉上，防备敌军的袭击。干扰素等于是“准备迎接病毒来袭”的确定信号。','1456-1534',5,1712645342,1782480559);
INSERT INTO highlights VALUES('3300037073_34_1249-1320','3300037073',34,'29 化学战：干扰素，干扰起来！','一旦某个细胞发现自己被病毒感染，它马上就会朝周围的细胞和免疫系统紧急释放出一系列细胞因子。这些细胞因子就像看到入侵者站到自己床边后尖叫的平民。','1249-1320',5,1712645207,1782480559);
INSERT INTO highlights VALUES('3300037073_34_962-1006','3300037073',34,'29 化学战：干扰素，干扰起来！','所以，在严重病毒感染时，先天性免疫系统就要和被感染的细胞一起争取世上最宝贵的东西：时间。','962-1006',5,1712645186,1782480559);
INSERT INTO highlights VALUES('3300037073_34_824-873','3300037073',34,'29 化学战：干扰素，干扰起来！','所以病毒感染（或是被能躲进细胞的细菌感染）时，身体急需适应性免疫系统的援助，来赢得清除感染的机会。','824-873',5,1712645168,1782480559);
INSERT INTO highlights VALUES('3300037073_34_801-824','3300037073',34,'29 化学战：干扰素，干扰起来！','先天性免疫系统对付病毒远不像对付细菌那样厉害。','801-824',5,1712645155,1782480559);
INSERT INTO highlights VALUES('3300037073_34_606-671','3300037073',34,'29 化学战：干扰素，干扰起来！','上皮细胞也有一些不同的受体，可以扫描自己的内部，看看有没有危险信号。','606-671',5,1712645136,1782480559);
INSERT INTO highlights VALUES('3300037073_34_524-571','3300037073',34,'29 化学战：干扰素，干扰起来！','上皮细胞有点像民兵。正因为如此，它们也拥有能识别特定结构的受体，和前面讲过的Toll样受体类似','524-571',5,1712645118,1782480559);
INSERT INTO highlights VALUES('3300037073_33_5590-5634','3300037073',33,'28 流感——威力被低估的病毒','感染早期，被感染的细胞会试图警示免疫系统，而病毒会努力让它们噤声，双方就要展开一番搏斗。','5590-5634',5,1712600010,1782480559);
INSERT INTO highlights VALUES('3300037073_33_5344-5409','3300037073',33,'28 流感——威力被低估的病毒','病毒真的很可怕。它们攻击人体最脆弱的环节，躲在普通细胞内部疯狂地增殖，增殖速度远超过任何其他病原体，每个增殖周期都能感染无数细胞。','5344-5409',5,1712599981,1782480559);
INSERT INTO highlights VALUES('3300037073_32_1929-1969','3300037073',32,'27 肺部免疫系统','不过我们确切地知道，大量能感染人的最常见、最致命的病毒，都是通过呼吸系统入侵的。','1929-1969',5,1712594186,1782480559);
INSERT INTO highlights VALUES('3300037073_32_1458-1493','3300037073',32,'27 肺部免疫系统','肺泡巨噬细胞非常沉着冷静，和皮肤上的巨噬细胞相比，要激活它们可难得多。','1458-1493',5,1712594124,1782480559);
INSERT INTO highlights VALUES('3300037073_32_1369-1419','3300037073',32,'27 肺部免疫系统','为了守护肺泡，这里生活着一种非常特殊的巨噬细胞：肺泡巨噬细胞。它的主要职责就是在肺部巡逻，清理垃圾。','1369-1419',5,1712594096,1782480559);
INSERT INTO highlights VALUES('3300037073_32_1214-1280','3300037073',32,'27 肺部免疫系统','黏液都会被不停地排出体外或吞进肚子。但这种机制在肺脏深处发挥不了作用，因为储存气体的“小袋子”肺泡表面不能有黏液，否则人就无法呼吸。','1214-1280',5,1712594082,1782480559);
INSERT INTO highlights VALUES('3300037073_32_992-1050','3300037073',32,'27 肺部免疫系统','肺部的免疫系统必须更谨慎，不能太粗暴。它必须演化成一套平衡的系统：既能赶跑入侵者、清除污染，同时又不能阻碍气体交换。','992-1050',5,1712593609,1782480559);
INSERT INTO highlights VALUES('3300037073_32_755-786','3300037073',32,'27 肺部免疫系统','空气中还可能有大量的植物花粉、夹杂螨虫排泄物的室内灰尘等过敏原','755-786',5,1712572316,1782480559);
INSERT INTO highlights VALUES('3300037073_32_393-478','3300037073',32,'27 肺部免疫系统','把肺比作气球是很有趣，但事实上，肺并不是两个大气球，而更像是两块有很多坑洼空隙的厚海绵。肺部负责气体交换的部分有很大的表面积，超过120平方米——是皮肤表面积的60多倍。','393-478',5,1712572252,1782480559);
INSERT INTO highlights VALUES('3300037073_32_507-545','3300037073',32,'27 肺部免疫系统','而这一大片区域都会和环境不停接触，因为人每天都会吸入十几、二十立方米的空气。','507-545',5,1712572249,1782480559);
INSERT INTO highlights VALUES('3300037073_31_5224-5243','3300037073',31,'26 病毒是什么？','大部分致病病毒的主要入侵点：呼吸道黏膜','5224-5243',5,1712572119,1782480559);
INSERT INTO highlights VALUES('3300037073_31_4972-5013','3300037073',31,'26 病毒是什么？','病毒个头更小，自身没有新陈代谢，不会释放化学废物供免疫细胞识别，所以比细菌更难发现','4972-5013',5,1712460839,1782480559);
INSERT INTO highlights VALUES('3300037073_31_4414-4493','3300037073',31,'26 病毒是什么？','致病的病毒非常擅长躲避免疫系统，因为它们有绝招：繁殖得无比快。这也意味着，没有什么变异或突变能快过病毒。在这方面，病毒可以说没有对手，因为它大大咧咧，毫不在乎','4414-4493',5,1712460796,1782480559);
INSERT INTO highlights VALUES('3300037073_31_4102-4152','3300037073',31,'26 病毒是什么？','有了外壳的病毒会通过出芽的方式离开宿主细胞，也就是说它会“掐下”一点细胞膜，作为自己的另一重保护壳。','4102-4152',5,1712460749,1782480559);
INSERT INTO highlights VALUES('3300037073_31_4014-4073','3300037073',31,'26 病毒是什么？','通常8到72小时后，细胞的物质就全部被变成了病毒的组件，进而被组装成新的病毒，直到整个细胞被几百到几万个新生病毒占据。','4014-4073',5,1712460734,1782480559);
INSERT INTO highlights VALUES('3300037073_31_3468-3511','3300037073',31,'26 病毒是什么？','为达到这一目的，它们利用了一个所有细胞共有、生物绝无可能护卫周全的弱点：它们攻击受体。','3468-3511',5,1712460682,1782480559);
INSERT INTO highlights VALUES('3300037073_31_3224-3256','3300037073',31,'26 病毒是什么？','它们其实就是飘在环境中的微粒，完全靠运气等着撞到倒霉的宿主身上。','3224-3256',5,1711944908,1782480559);
INSERT INTO highlights VALUES('3300037073_31_763-831','3300037073',31,'26 病毒是什么？','有些科学家认为病毒是生命涌现的必经阶段，有些则认为约在15亿年前，某种远古细菌没有往复杂的方向演化，而是选取了变简单的路径，于是成了病毒','763-831',5,1711944809,1782480559);
INSERT INTO highlights VALUES('3300037073_30_4719-4778','3300037073',30,'25 奇特的肠道免疫系统','粪便移植背后的基本思路就是这样，这其实并不是什么创新。有证据表明，几千年前，服食动物粪便就已经是治疗胃肠疾病的方法了。','4719-4778',5,1711944688,1782480559);
INSERT INTO highlights VALUES('3300037073_30_4187-4222','3300037073',30,'25 奇特的肠道免疫系统','肠道就相当于拥有了超快速的免疫筛查，可以持续地密切监测肠道的细菌组成。','4187-4222',5,1711944600,1782480559);
INSERT INTO highlights VALUES('3300037073_30_4046-4079','3300037073',30,'25 奇特的肠道免疫系统','肠道有一种名为“派尔集合淋巴结”的特殊淋巴结，它们直接长在肠道上。','4046-4079',5,1711944580,1782480559);
INSERT INTO highlights VALUES('3300037073_30_3582-3668','3300037073',30,'25 奇特的肠道免疫系统','IgA可以穿过上皮细胞的屏障，大量进入黏膜层；它们也不会激活补体系统，不会引发炎症，这两点对肠道来说都很重要。','3582-3668',5,1711944416,1782480559);
INSERT INTO highlights VALUES('3300037073_30_3525-3553','3300037073',30,'25 奇特的肠道免疫系统','除此以外，肠道还有特殊的B细胞，它们只生成大量的IgA，','3525-3553',5,1711944407,1782480559);
INSERT INTO highlights VALUES('3300037073_30_3385-3435','3300037073',30,'25 奇特的肠道免疫系统','将来解开谜题的人定能获得诺贝尔奖：树突状细胞怎么知道它采样的细菌是危险的病原体，还是无害的共生细菌？','3385-3435',5,1711944360,1782480559);
INSERT INTO highlights VALUES('3300037073_30_3263-3305','3300037073',30,'25 奇特的肠道免疫系统','大量树突状细胞直接待在上皮细胞下面，将长触手从上皮细胞之间挤过去，直接伸入肠道黏液。','3263-3305',5,1711944341,1782480559);
INSERT INTO highlights VALUES('3300037073_30_3135-3221','3300037073',30,'25 奇特的肠道免疫系统','守卫肠道的巨噬细胞有两个特点：一、很擅长吞噬细菌；二、不会释放召集中性粒细胞进而引发炎症的细胞因子。这里的巨噬细胞更像是无声的杀手，不慌不忙地吃掉越界的细菌，不会大呼小叫。','3135-3221',5,1711944199,1782480559);
INSERT INTO highlights VALUES('3300037073_30_2946-2993','3300037073',30,'25 奇特的肠道免疫系统','腹泻不仅会使大便呈水样，还会损伤负责从食物中吸收营养的、敏感纤薄的上皮层，并迅速导致重度脱水。','2946-2993',5,1711944157,1782480559);
INSERT INTO highlights VALUES('3300037073_30_2900-2946','3300037073',30,'25 奇特的肠道免疫系统','若非有绝对的必要，免疫系统会极力避免引发炎症，因为炎症会让肠道产生大量多余的液体，造成腹泻。','2900-2946',5,1711944136,1782480559);
INSERT INTO highlights VALUES('3300037073_30_2790-2871','3300037073',30,'25 奇特的肠道免疫系统','上皮细胞下面还有第三层，“固有层”，这里是肠道免疫系统的大本营。在紧贴着黏膜表面的固有层之内，有特殊的巨噬细胞、B细胞和树突状细胞随时待命，等着收拾那些不速之客。','2790-2871',5,1711944113,1782480559);
INSERT INTO highlights VALUES('3300037073_30_2586-2640','3300037073',30,'25 奇特的肠道免疫系统','和肺部相似，肠道的上皮层也只有一个细胞那么厚。','2586-2640',5,1711944070,1782480559);
INSERT INTO highlights VALUES('3300037073_30_2478-2529','3300037073',30,'25 奇特的肠道免疫系统','肠道的黏液层很薄，且要有一定的通透性，好让食物中的营养物质通过，要是第一层保护太厚，你可能就要饿死了。','2478-2529',5,1711944041,1782480559);
INSERT INTO highlights VALUES('3300037073_30_2248-2314','3300037073',30,'25 奇特的肠道免疫系统','细菌可不是人类真正的朋友，它们不知道什么约定，也不会去遵守任何东西。而肠道面积辽阔，细菌多得惊人，时刻都有一些共生细菌侵入肠道内壁。','2248-2314',5,1711943995,1782480559);
INSERT INTO highlights VALUES('3300037073_30_1865-1986','3300037073',30,'25 奇特的肠道免疫系统','几百万年以前，人类祖先和某些微生物种类做了个脆弱的约定：人允许它们住在温暖的肠道里，并提供源源不断的食物；作为交换，这些微生物负责分解人类自己无法分解的碳水化合物，并生成人体自身不能合成的维生素。肠道细菌就像租客一样，生成的营养物质就是租金。','1865-1986',5,1711943954,1782480559);
INSERT INTO highlights VALUES('3300037073_30_1318-1351','3300037073',30,'25 奇特的肠道免疫系统','肠道沼泽国的免疫系统就有点像瑞士，它要用自己的方式来完成许多任务。','1318-1351',5,1711943844,1782480559);
INSERT INTO highlights VALUES('3300037073_29_3577-3642','3300037073',29,'第3部分 恶意接管','肺部黏膜和肠道黏膜有着完全不同的功能，而女性生殖道黏膜的功能又大不一样。根据不同部位黏膜特化情况的不同，相应的免疫系统也各有特点。','3577-3642',5,1711943738,1782480559);
INSERT INTO highlights VALUES('3300037073_29_3236-3262','3300037073',29,'第3部分 恶意接管','上皮细胞的任务之一，就是借助细胞膜上的纤毛让黏液流动','3236-3262',5,1711943690,1782480559);
INSERT INTO highlights VALUES('3300037073_29_3352-3390','3300037073',29,'第3部分 恶意接管','我们在一生中会吞下相当多的黏液，虽然听起来可能有点恶心，但这种机制很是有用。','3352-3390',5,1711943674,1782480559);
INSERT INTO highlights VALUES('3300037073_29_3133-3163','3300037073',29,'第3部分 恶意接管','它们特别擅长激活免疫系统，以及释放特殊的细胞因子以请求支援。','3133-3163',5,1711943632,1782480559);
INSERT INTO highlights VALUES('3300037073_29_3096-3133','3300037073',29,'第3部分 恶意接管','上皮细胞可不好对付。它们尽管不是真正的免疫细胞，但也发挥着重要的防御作用：','3096-3133',5,1711943624,1782480559);
INSERT INTO highlights VALUES('3300037073_29_2788-2842','3300037073',29,'第3部分 恶意接管','比如，你是否想过，胃里有那么多胃酸，你为什么没事？因为胃黏膜就是一层屏障，能保护胃壁细胞，令其不与胃酸接触。','2788-2842',5,1711943573,1782480559);
INSERT INTO highlights VALUES('3300037073_29_2722-2759','3300037073',29,'第3部分 恶意接管','大多数部位的黏液都富含杀伤力强大的IgA抗体。所以黏液层本身就不是宜居之地','2722-2759',5,1711943551,1782480559);
INSERT INTO highlights VALUES('3300037073_29_2531-2566','3300037073',29,'第3部分 恶意接管','湿滑的黏液发挥着几方面的作用。最显见的，它是一道阻止外敌入侵的物理屏障','2531-2566',5,1711888945,1782480559);
INSERT INTO highlights VALUES('3300037073_29_2198-2272','3300037073',29,'第3部分 恶意接管','沼泽之国动用的第一道防线就是它本身的黏液层。黏液是细胞分泌的黏滑的物质，有点像水凝胶。','2198-2272',5,1711888765,1782480559);
INSERT INTO highlights VALUES('3300037073_29_1996-2051','3300037073',29,'第3部分 恶意接管','针对入侵的第一项反制措施，就是把黏膜变成不适合危险微生物生存的死亡之地。为此，黏膜动用了一系列不同的防御系统。','1996-2051',5,1711888742,1782480559);
INSERT INTO highlights VALUES('3300037073_29_1785-1845','3300037073',29,'第3部分 恶意接管','黏膜处的免疫系统不能像其他部位一样有攻击性，否则这些负责气体和营养交换的部位会遭到严重破坏，从而影响正常生活甚至造成死亡','1785-1845',5,1711888721,1782480559);
INSERT INTO highlights VALUES('3300037073_29_1514-1569','3300037073',29,'第3部分 恶意接管','这使得这些部位的免疫系统有着格外艰巨的职责，要维持平衡更是难上加难——因为沼泽之国的免疫系统要有一定的宽容度。','1514-1569',5,1711888682,1782480559);
INSERT INTO highlights VALUES('3300037073_29_757-824','3300037073',29,'第3部分 恶意接管','事实上，绝大部分的病原体入侵都发生在这些内外交界之处，包括从口腔一直到肛门的消化道，还有通向和外界进行交换的“洞穴系统”的多分支管道。','757-824',5,1711888585,1782480559);
INSERT INTO highlights VALUES('3300037073_28_5651-5705','3300037073',28,'23 抗体','因此B细胞不会固定只生成一类抗体——它们总是先生成IgM，而在辅助性T细胞的请求和鼓励下，会改产其他类抗体。','5651-5705',5,1711860835,1782480559);
INSERT INTO highlights VALUES('3300037073_28_5265-5295','3300037073',28,'23 抗体','它原本的目标是抵御寄生虫、特别是蠕虫这样的巨型敌人造成的感染','5265-5295',5,1711860798,1782480559);
INSERT INTO highlights VALUES('3300037073_28_4979-5027','3300037073',28,'23 抗体','除了保护和清理肠道，IgA也能够保护婴儿。妈妈在喂养母乳时，会经奶水给孩子提供大量的IgA抗体。','4979-5027',5,1711860753,1782480559);
INSERT INTO highlights VALUES('3300037073_28_4931-4961','3300037073',28,'23 抗体','粪便的1/3其实都是细菌，都是在废物向远端移动中被裹挟进来的','4931-4961',5,1711860730,1782480559);
INSERT INTO highlights VALUES('3300037073_28_4210-4278','3300037073',28,'23 抗体','IgG的另一个特色是，唯有此种抗体能经胎盘由母体传入胎儿的血流。这能保护胎儿免受母体遭遇的病毒感染，而且这种保护作用还能持续到出生以后。','4210-4278',5,1711860495,1782480559);
INSERT INTO highlights VALUES('3300037073_28_2225-2255','3300037073',28,'23 抗体','先天性免疫系统负责作战，而适应性系统让进攻更快、更准、更狠。','2225-2255',5,1711860046,1782480559);
INSERT INTO highlights VALUES('3300037073_28_1819-1859','3300037073',28,'23 抗体','没有抗体，就像用湿漉漉的手去拧泡菜罐头瓶一样；有了抗体，就相当于把手擦干了去拧。','1819-1859',5,1711859943,1782480559);
INSERT INTO highlights VALUES('3300037073_28_1480-1501','3300037073',28,'23 抗体','抗体有两只钳子，所以就能同时抓住两个敌人，','1480-1501',5,1711859881,1782480559);
INSERT INTO highlights VALUES('3300037073_28_1195-1225','3300037073',28,'23 抗体','如果是病毒感染的话，抗体会直接中和病毒，让它们无法再感染细胞','1195-1225',5,1711859649,1782480559);
INSERT INTO highlights VALUES('3300037073_28_907-921','3300037073',28,'23 抗体','钳子用来御敌，尾端用来结盟。','907-921',5,1711859620,1782480559);
INSERT INTO highlights VALUES('3300037073_28_689-811','3300037073',28,'23 抗体','抗体一旦和抗原结合，就再也不会放手——抗体就是小龙虾形状的微小蛋白，特别擅长抓住其所针对的敌人不放，因为，就像上一章简单提过的，它们就是B细胞受体，所以在人体内有着最强的抗原结合力。','689-811',5,1711859545,1782480559);
INSERT INTO highlights VALUES('3300037073_28_551-605','3300037073',28,'23 抗体','某种意义上，抗体和补体有点像，都是游离的微小蛋白质；不过两者有一项巨大的区别：补体蛋白没有针对性，而抗体有。','551-605',5,1711859526,1782480559);
INSERT INTO highlights VALUES('3300037073_28_389-459','3300037073',28,'23 抗体','抗体是免疫系统最厉害、针对性最强的武器之一。它们由B细胞生成，本身杀伤力并不大，不过是能黏附抗原的蛋白质小块而已。但它们黏附抗原的效率极高。','389-459',5,1711859504,1782480559);
INSERT INTO highlights VALUES('3300037073_27_2636-2698','3300037073',27,'22 T细胞和B细胞的共舞','这就是办法之一：让免疫系统拥有能迅速自我复制的细胞，有明确的目标并能对其做出快速适应，能不断改良武器直至完美。','2636-2698',5,1711858691,1782480559);
INSERT INTO highlights VALUES('3300037073_27_2095-2174','3300037073',27,'22 T细胞和B细胞的共舞','继续用烹饪作比的话，辅助性T细胞就像是从餐厅走来后厨的美食评论家，对厨师大加赞许、亲个不停。而这一番鼓励，肯定让B细胞更有动力改进菜品。这样就进入了良性循环。','2095-2174',5,1711858591,1782480559);
INSERT INTO highlights VALUES('3300037073_27_1200-1274','3300037073',27,'22 T细胞和B细胞的共舞','每次B细胞收到辅助性T细胞的阳性信号，就会开始一轮有目的的突变。这个过程叫“体细胞超变”（也叫“亲和力成熟”），我们后面再也不会用这些拗口的字眼了。','1200-1274',5,1711858528,1782480559);
INSERT INTO highlights VALUES('3300037073_27_803-873','3300037073',27,'22 T细胞和B细胞的共舞','于是免疫系统这样办：先尽快生产出凑合的抗体，但也用一套精妙的系统来微调、改进这些抗体，让它们变成近乎完美的抗敌武器。这一过程，始于一番舞蹈。','803-873',5,1711858405,1782480559);
INSERT INTO highlights VALUES('3300037073_26_9303-9347','3300037073',26,'21 军工厂和狙击枪','浆细胞开始生成真正的抗体。它每秒可以释放多达2000个抗体，进入淋巴液、血液和组织液当中','9303-9347',5,1711858405,1782480559);
INSERT INTO highlights VALUES('3300037073_26_9007-9273','3300037073',26,'21 军工厂和狙击枪','满足了双重认证并充分活化的B细胞开始发生变化。这一刻它已经等了太久。它开始肿胀膨大，变成几乎原来的两倍，化身为B细胞的最终形态：浆细胞。','9007-9075',5,1711858272,1782480559);
INSERT INTO highlights VALUES('3300037073_26_8420-8491','3300037073',26,'21 军工厂和狙击枪','第四步：一个活化的B细胞呈递几百个不同抗原（小香肠段）；它还要遇到一个T细胞，后者要能识别这些小抗原中的一个，才能成为B细胞的第二步激活信号。','8420-8491',5,1711858205,1782480559);
INSERT INTO highlights VALUES('3300037073_26_8332-8391','3300037073',26,'21 军工厂和狙击枪','第三步：B细胞把大块抗原（火鸡腿）分解成几十甚至几百片小抗原（香肠大小），再借助MHC-Ⅱ分子（热狗面包）来呈递抗原。','8332-8391',5,1711858195,1782480559);
INSERT INTO highlights VALUES('3300037073_26_8155-8303','3300037073',26,'21 军工厂和狙击枪','第二步：同时，树突状细胞要在战场上吞噬敌人，将它们分解成抗原（香肠），把抗原夹在表面的MHC-Ⅱ分子（面包）中，再前往淋巴结中的T细胞约会平台。在这里，树突状细胞要找到某种辅助性T细胞，它能借助特定的T细胞受体识别抗原（吃掉夹在面包中的香肠）。找到后，相应的辅助性T细胞会活化，开始大量自我复制。','8155-8303',5,1711858096,1782480559);
INSERT INTO highlights VALUES('3300037073_26_7997-8126','3300037073',26,'21 军工厂和狙击枪','第一步：战事不可避免，敌人的尸体作为大块抗原（火鸡腿），就要流经淋巴结。淋巴结中有B细胞，它带有特定的受体，要和抗原结合。如果死去的敌人被补体覆盖，那么结合会容易得多。B细胞会因之活化，大量自我复制，生成初级抗体；但如果没有下一步，这些B细胞一天内就会死去。','7997-8126',5,1711858065,1782480559);
INSERT INTO highlights VALUES('3300037073_26_4642-4682','3300037073',26,'21 军工厂和狙击枪','在感染初期，树突状细胞还没有大批抵达淋巴结、激活辅助T细胞时，这些机制尤其重要。','4642-4682',5,1711813679,1782480559);
INSERT INTO highlights VALUES('3300037073_26_4485-4519','3300037073',26,'21 军工厂和狙击枪','你可以把抗原上的补体蛋白想象成酱汁，它能让火鸡腿在B细胞尝来更觉美味','4485-4519',5,1711813630,1782480559);
INSERT INTO highlights VALUES('3300037073_26_4406-4437','3300037073',26,'21 军工厂和狙击枪','若遇到补体蛋白结合抗原的情况，B细胞的活化效率会提高100倍。','4406-4437',5,1711813611,1782480559);
INSERT INTO highlights VALUES('3300037073_26_4268-4301','3300037073',26,'21 军工厂和狙击枪','B细胞不仅能识别死去的细菌抗原，它还具有能识别补体蛋白的特殊受体。','4268-4301',5,1711813607,1782480559);
INSERT INTO highlights VALUES('3300037073_26_3787-3810','3300037073',26,'21 军工厂和狙击枪','细胞和T细胞能识别的抗原在大小尺寸方面很是不同','3787-3810',5,1711813290,1782480559);
INSERT INTO highlights VALUES('3300037073_26_3285-3332','3300037073',26,'21 军工厂和狙击枪','这些B细胞置身淋巴液当中，其表面的受体也充分接触这些液态信息流，筛滤、辨别来自组织的抗原和碎片','3285-3332',5,1711813232,1782480559);
INSERT INTO highlights VALUES('3300037073_26_3146-3201','3300037073',26,'21 军工厂和狙击枪','。如此，淋巴液就像是在你全身流动的液态信息载体。','3146-3201',5,1711813204,1782480559);
INSERT INTO highlights VALUES('3300037073_26_3109-3146','3300037073',26,'21 军工厂和狙击枪','。身体有感染时，淋巴液会运载所有死细菌的碎片，其中许多的表面覆盖着补体蛋白','3109-3146',5,1711813200,1782480559);
INSERT INTO highlights VALUES('3300037073_26_2921-2948','3300037073',26,'21 军工厂和狙击枪','但体液如果不断聚集，组织是会破裂的，所以必须排出一部分','2921-2948',5,1711813167,1782480559);
INSERT INTO highlights VALUES('3300037073_26_1975-2020','3300037073',26,'21 军工厂和狙击枪','B细胞威力太大，要激活它们必须严格满足双重认证，分别由先天性免疫系统和适应性免疫系统做出。','1975-2020',5,1711812941,1782480559);
INSERT INTO highlights VALUES('3300037073_26_1696-1731','3300037073',26,'21 军工厂和狙击枪','它们混合并重排一些基因片段，以使将来生产的B细胞受体能和特定的抗原结合','1696-1731',5,1711812863,1782480559);
INSERT INTO highlights VALUES('3300037073_26_1209-1286','3300037073',26,'21 军工厂和狙击枪','抗体黏附在B细胞表面，起着B细胞受体的作用，即它们能够结合抗原并激活B细胞。B细胞一旦活化，就会生产并泌出大量新的抗体来攻击敌人——可以多达每秒2000个','1209-1286',5,1711812809,1782480559);
INSERT INTO highlights VALUES('3300037073_26_1045-1147','3300037073',26,'21 军工厂和狙击枪','简而言之，抗体就是B细胞的受体。抗体长得有点像小龙虾，作用好似狙击枪，专为结合特定抗原、打击特定敌人而打造，会宛如正中眉心一般精准打击病原体。','1045-1147',5,1711812788,1782480559);
INSERT INTO highlights VALUES('3300037073_26_970-1006','3300037073',26,'21 军工厂和狙击枪','使B细胞卓尔不群、敌友皆惧的，是它们能生成免疫系统最强大的特化武器：抗体','970-1006',5,1711812720,1782480559);
INSERT INTO highlights VALUES('3300037073_26_844-941','3300037073',26,'21 军工厂和狙击枪','和T细胞一样，所有的B细胞表面都附着有至少几亿到几十亿的受体，针对的是数百万不同抗原，且每个B细胞都拥有识别某一特定抗原的特定受体。','844-941',5,1711812694,1782480559);
INSERT INTO highlights VALUES('3300037073_25_4764-4804','3300037073',25,'20 唤醒适应性免疫系统：T细胞','还有另一组辅助性T细胞，它们马上要做的事甚至更为重要：激活你能调用的最强效武器。','4764-4804',5,1711812581,1782480559);
INSERT INTO highlights VALUES('3300037073_25_4510-4534','3300037073',25,'20 唤醒适应性免疫系统：T细胞','记忆T细胞识别旧敌的速度比先天性免疫系统还快得多','4510-4534',5,1711812550,1782480559);
INSERT INTO highlights VALUES('3300037073_25_4373-4480','3300037073',25,'20 唤醒适应性免疫系统：T细胞','一俟赢得战役，辅助性T细胞的最后使命就是像大部分免疫细胞那样自我毁灭，避免伤到人体。但其中一小部分不会。有些辅助性T细胞会变成“记忆T细胞”。每次你听说你对某种病免疫，意思都是，你体内有记住了特定敌人的记忆T细胞。','4373-4480',5,1711812354,1782480559);
INSERT INTO highlights VALUES('3300037073_25_4174-4219','3300037073',25,'20 唤醒适应性免疫系统：T细胞','而辅助性T细胞可以一遍遍地重设定时器：只要还有危险，它们就会不断激活疲惫不堪的巨噬细胞战士','4174-4219',5,1711812151,1782480559);
INSERT INTO highlights VALUES('3300037073_25_4128-4152','3300037073',25,'20 唤醒适应性免疫系统：T细胞','疯狂杀敌的巨噬细胞体内有定时器，时间一到就会凋亡','4128-4152',5,1711812142,1782480559);
INSERT INTO highlights VALUES('3300037073_25_2723-2798','3300037073',25,'20 唤醒适应性免疫系统：T细胞','想一想，你就会觉得这很合理——巨噬细胞就是危险的猛兽，要决心完全释放它的威力，必须经过再三考虑。要是它们一有感染就变身为战斗狂魔，身体可是会严重受损的','2723-2798',5,1711784553,1782480559);
INSERT INTO highlights VALUES('3300037073_25_2302-2334','3300037073',25,'20 唤醒适应性免疫系统：T细胞','因此免疫系统现在就有了几千个具有此种受体、专门针对特定敌人的细胞','2302-2334',5,1711784444,1782480559);
INSERT INTO highlights VALUES('3300037073_25_2251-2273','3300037073',25,'20 唤醒适应性免疫系统：T细胞','几小时内，就有了几千个同样的活化辅助性T细胞','2251-2273',5,1711784432,1782480559);
INSERT INTO highlights VALUES('3300037073_25_2173-2213','3300037073',25,'20 唤醒适应性免疫系统：T细胞','活化的辅助性T细胞离开激活它的树突状细胞，迁移到淋巴结的其他部分，开始自我克隆。','2173-2213',5,1711784408,1782480559);
INSERT INTO highlights VALUES('3300037073_25_2056-2089','3300037073',25,'20 唤醒适应性免疫系统：T细胞','要协助击退感染，辅助性T细胞不能孤身一个，所以它的首要任务就是增殖','2056-2089',5,1711784359,1782480559);
INSERT INTO highlights VALUES('3300037073_25_1605-1704','3300037073',25,'20 唤醒适应性免疫系统：T细胞','另外细胞走得很快。T细胞一天就能走遍全身的淋巴高速路网——设想一下在人类尺度这是什么概念，相当于每天从纽约开车到洛杉矶，还要在沿途几百处城镇和服务区停下来打听看有没有人特意在找你。T细胞就是这么做的','1605-1704',5,1711783343,1782480559);
INSERT INTO highlights VALUES('3300037073_25_504-566','3300037073',25,'20 唤醒适应性免疫系统：T细胞','首先，T细胞的种类就不少，有辅助性T细胞、杀伤性T细胞和调节性T细胞，每一种都还能特化成不同的亚类，以对付每种可能存在的感染','504-566',5,1711783101,1782480559);
INSERT INTO highlights VALUES('3300037073_24_5520-5545','3300037073',24,'19 信息盛宴：抗原呈递','我们就是觉得有不同免疫系统的潜在对象闻起来更性感。','5520-5545',5,1711782388,1782480559);
INSERT INTO highlights VALUES('3300037073_24_5312-5380','3300037073',24,'19 信息盛宴：抗原呈递','MHC分子的形状会影响身体分泌的一些特殊分子，我们从他人的体味中会无意识地接受这些信息，因此你可以用自己独特的气味传递免疫系统类型的信息','5312-5380',5,1711782315,1782480559);
INSERT INTO highlights VALUES('3300037073_24_4881-4925','3300037073',24,'19 信息盛宴：抗原呈递','负责编码MHC分子的基因，是人类基因库中多样性最丰富的，因此每个人的MHC分子都迥然不同','4881-4925',5,1711782243,1782480559);
INSERT INTO highlights VALUES('3300037073_24_4986-5079','3300037073',24,'19 信息盛宴：抗原呈递','不同类型的MHC会更擅长或更不擅长呈递不同的抗原，比如有的类型会特别擅长呈递特定的病毒抗原，而另一种会擅长呈递某种细菌抗原。这对人类这一物种来说非常有用，使得人类很难被单一种病原体消灭。','4986-5079',5,1711782239,1782480559);
INSERT INTO highlights VALUES('3300037073_24_4770-4832','3300037073',24,'19 信息盛宴：抗原呈递','免疫系统需要持续的刺激才能保持活化状态，而发送来自战场的实时消息和信息的定期自行删除，可以让免疫系统做出强度刚好合适的应答。','4770-4832',5,1711782121,1782480559);
INSERT INTO highlights VALUES('3300037073_24_4441-4484','3300037073',24,'19 信息盛宴：抗原呈递','它自杀时，也会抹除从战场收集来的过时信息。这种信息抹除是免疫系统自我调节的另一种机制。','4441-4484',5,1711782064,1782480559);
INSERT INTO highlights VALUES('3300037073_24_4108-4140','3300037073',24,'19 信息盛宴：抗原呈递','实际情况很可能是，免疫系统很容易活化的那些动物，最后都没活下来。','4108-4140',5,1711781932,1782480559);
INSERT INTO highlights VALUES('3300037073_24_3260-3321','3300037073',24,'19 信息盛宴：抗原呈递','你可以把第二个信号想象成树突状细胞的轻吻。这是另一个确认信号，再次明确告诉了辅助性T细胞：“是真的，你真的、恰当地活化了！','3260-3321',5,1711781824,1782480559);
INSERT INTO highlights VALUES('3300037073_24_3155-3186','3300037073',24,'19 信息盛宴：抗原呈递','树突状细胞居然从几十亿淋巴细胞中找到了完美匹配的辅助性T细胞！','3155-3186',5,1711781790,1782480559);
INSERT INTO highlights VALUES('3300037073_24_2085-2136','3300037073',24,'19 信息盛宴：抗原呈递','抗原只有包裹在MHC-Ⅱ类分子中呈递过来，辅助性T细胞才能识别，或者说，辅助性T细胞只吃夹成热狗的香肠','2085-2136',5,1711781662,1782480559);
INSERT INTO highlights VALUES('3300037073_24_1791-1803','3300037073',24,'19 信息盛宴：抗原呈递','Ⅱ型主要组织相容性复合体','1791-1803',5,1711781599,1782480559);
INSERT INTO highlights VALUES('3300037073_24_1615-1700','3300037073',24,'19 信息盛宴：抗原呈递','浑身涂满敌人内脏后，树突状细胞就经过淋巴系统把抗原呈递给适应性免疫细胞，或者更确切地说，呈递给辅助性T细胞。','1615-1700',5,1711781573,1782480559);
INSERT INTO highlights VALUES('3300037073_24_1014-1047','3300037073',24,'19 信息盛宴：抗原呈递','这时就轮到长着章鱼般的触手、体型庞大、相貌丑陋的树突状细胞出场了。','1014-1047',5,1711781513,1782480559);
INSERT INTO highlights VALUES('3300037073_24_930-944','3300037073',24,'19 信息盛宴：抗原呈递','答案就是，通过“抗原呈递”。','930-944',5,1711781153,1782480559);
INSERT INTO highlights VALUES('3300037073_24_715-804','3300037073',24,'19 信息盛宴：抗原呈递','发生感染时，免疫系统会决定要启动哪些针对性防御，程度要如何。适应性与先天性免疫系统会通力合作，一起从几十亿T细胞中找出有所需受体、能对付此种感染的少数，再快速制造更多同样的细胞。','715-804',5,1711781068,1782480559);
INSERT INTO highlights VALUES('3300037073_23_3766-3845','3300037073',23,'18 胸腺——杀手大学','胸腺功能的缺失是老年人比年轻人体弱，容易感染、患病、患癌的重要原因之一。为什么要这样呢？因为大自然不青睐不再拥有繁殖能力的人类，因此没有演化压力来让人活得更久','3766-3845',5,1711771547,1782480559);
INSERT INTO highlights VALUES('3300037073_23_3580-3622','3300037073',23,'18 胸腺——杀手大学','但可惜，杀手大学已经在关停过程中了。胸腺在幼儿期就会开始萎缩，到青春期后退化得更快。','3580-3622',5,1711771526,1782480559);
INSERT INTO highlights VALUES('3300037073_23_2707-2743','3300037073',23,'18 胸腺——杀手大学','第二项测试叫“正向选择”：教练细胞会查看T细胞是否擅长识别合作细胞的受体','2707-2743',5,1711771321,1782480559);
INSERT INTO highlights VALUES('3300037073_23_2426-2644','3300037073',23,'18 胸腺——杀手大学','第一项测试主要是确保T细胞能够生成有效的T细胞受体。这就像在普通的学校里，老师要确保学生都带了笔记本和学习材料——唯一的不同是，T细胞学生要是忘了，可没机会回家拿，而会被一枪爆头。','2426-2516',5,1711771271,1782480559);
INSERT INTO highlights VALUES('3300037073_23_2209-2228','3300037073',23,'18 胸腺——杀手大学','超过7%的美国人患有自身免疫性疾病。不','2209-2228',5,1711771219,1782480559);
INSERT INTO highlights VALUES('3300037073_23_1896-1994','3300037073',23,'18 胸腺——杀手大学','但这种办法也有个致命缺陷：受体种类这么多，肯定有很多T细胞的受体能和自体细胞的蛋白结合。这不是理论上的威胁，而是真实存在的病因，能引发一系列严重的疾病，叫“自身免疫性疾病”，几百万人正饱受其折磨。','1896-1994',5,1711771177,1782480559);
INSERT INTO highlights VALUES('3300037073_23_753-949','3300037073',23,'18 胸腺——杀手大学','一些最强大最重要的适应性免疫细胞就在这里接受教育和训练：它们就是T细胞。','753-789',1,1711730525,1782480559);
INSERT INTO highlights VALUES('3300037073_23_671-703','3300037073',23,'18 胸腺——杀手大学','胸腺长得很无聊，毫无吸引力，就像两坨疙疙瘩瘩的老鸡胸肉拼在一起。','671-703',1,1711730503,1782480559);
INSERT INTO highlights VALUES('3300037073_22_3638-3726','3300037073',22,'17 烹饪美味的受体菜谱','：生成如此多样受体的妙招，也让适应性免疫细胞对身体构成了巨大的威胁。毕竟，又有什么能让免疫细胞不去生成识别“自身”的受体，把自身的一部分当成抗原呢？有的，那就是它们所受的训练。','3638-3726',1,1711730429,1782480559);
INSERT INTO highlights VALUES('3300037073_22_3257-3337','3300037073',22,'17 烹饪美味的受体菜谱','从原理上说，适应性免疫细胞也是这样利用基因片段的。它选取不同的基因片段随机组合，并重复这个过程，再随机加入或删去一些部分，用得到的基因来编码几十亿种不同的受体。','3257-3337',1,1711730358,1782480559);
INSERT INTO highlights VALUES('3300037073_22_1082-1142','3300037073',22,'17 烹饪美味的受体菜谱','我再重复一遍：你体内当下就有识别全宇宙每种可能抗原的潜能。','1082-1142',1,1711729800,1782480559);
INSERT INTO highlights VALUES('3300037073_21_1528-1606','3300037073',21,'16 宇宙最大图书馆','现在，你体内至少有一个专门的细胞，用来对付黑死病、各种流感、冠状病毒甚至100年后火星上可能出现的首个致病菌。你已经为全宇宙每种可能存在的微生物做好了准备。','1528-1606',1,1711729394,1782480559);
INSERT INTO highlights VALUES('3300037073_21_1489-1527','3300037073',21,'16 宇宙最大图书馆','新生儿体内预装着几亿不同的免疫细胞——其中一些负责应对此生可能遇到的每种威胁','1489-1527',1,1711729373,1782480559);
INSERT INTO highlights VALUES('3300037073_21_1147-1174','3300037073',21,'16 宇宙最大图书馆','一些危险的细菌已经演化出了多种躲避免疫系统攻击的妙招，','1147-1174',5,1711712384,1782480559);
INSERT INTO highlights VALUES('3300037073_21_651-741','3300037073',21,'16 宇宙最大图书馆','想想看，人类仅仅为了养育一个后代、复制自己的几十万亿细胞，就要付出多大的努力。首先你要找到另一尊肉山，对方还要喜欢你。然后经过一番身体的艰难舞动，才可能让来自双方的生殖细胞融合。接','651-741',5,1711712298,1782480559);
INSERT INTO highlights VALUES('3300037073_20_2565-2617','3300037073',20,'15 超级武器降临','此番磨难对你来说不过是一点小小的不便，对几百万细胞来说却是生死鏖战。它们尽到了自己的职责，舍身保护了你。','2565-2617',5,1711684154,1782480559);
INSERT INTO highlights VALUES('3300037073_20_2265-2292','3300037073',20,'15 超级武器降临','第一项任务就是发出信号刺激普通细胞生长，好让伤口愈合。','2265-2292',5,1711684079,1782480559);
INSERT INTO highlights VALUES('3300037073_20_1396-1461','3300037073',20,'15 超级武器降临','如果说补体是用棍棒和利爪武装起来的武士，抗体就是带狙击枪的杀手。现在，它们的目标就是打击感染部位的特定这一种细菌，让后者缴械投降。','1396-1461',5,1711683820,1782480559);
INSERT INTO highlights VALUES('3300037073_20_1171-1260','3300037073',20,'15 超级武器降临',unistr('此番情景在战场上到处上演，因为辅助性T细胞在疲惫的士兵耳边念了神奇的咒语，鼓舞它们振作精神，带着更强的战力重新对付细菌。\u000a'),'1171-1231',5,1711683795,1782480559);
INSERT INTO highlights VALUES('3300037073_20_1032-1068','3300037073',20,'15 超级武器降临','随后，它径直朝疲惫的巨噬细胞跑去，用特殊的细胞因子轻声说出了它想说的消息','1032-1068',5,1711683761,1782480559);
INSERT INTO highlights VALUES('3300037073_20_908-916','3300037073',20,'15 超级武器降临','是辅助性T细胞！','908-916',5,1711683726,1782480559);
INSERT INTO highlights VALUES('3300037073_20_545-625','3300037073',20,'15 超级武器降临','战场上一片狼藉，全是组织细胞和免疫细胞的尸体、中性粒细胞发射的胞外陷阱（就是那些看起来像网的自杀式陷阱）、细菌产生的毒素和废物、信号分子，以及消耗后的补体蛋白。','545-625',5,1711683673,1782480559);
INSERT INTO highlights VALUES('3300037073_20_406-448','3300037073',20,'15 超级武器降临','带着战场快照和信息的第一批树突状细胞已经离开了好几天，这对细胞来说简直是好几个世纪。','406-448',5,1711683648,1782480559);
INSERT INTO highlights VALUES('3300037073_19_4059-4110','3300037073',19,'14 高速路和大都市','如果扁桃体太亢奋，过度工作，就可能发生慢性炎症并且肿大，这会带来一系列不适，有时还使得手术切除成为必要','4059-4110',5,1711637815,1782480559);
INSERT INTO highlights VALUES('3300037073_19_3979-4030','3300037073',19,'14 高速路和大都市','在幼年时期训练免疫系统，让它能识别安全的食物种类，不对它们报以免疫反应；发现有入侵者时，能够制造武器。','3979-4030',5,1711637801,1782480559);
INSERT INTO highlights VALUES('3300037073_19_3535-3560','3300037073',19,'14 高速路和大都市','肝脏、普通淋巴结还有骨髓可以接替脾脏的大部分工作。','3535-3560',5,1711637748,1782480559);
INSERT INTO highlights VALUES('3300037073_19_2941-2980','3300037073',19,'14 高速路和大都市','不过脾脏可不仅仅是受伤时可资依靠的紧急血库，它还是免疫细胞的聚集地、“兵营”。','2941-2980',5,1711637690,1782480559);
INSERT INTO highlights VALUES('3300037073_19_2808-2912','3300037073',19,'14 高速路和大都市','。另外，脾脏中存有一点紧急血液储备，约有一茶杯的量，在发生意外、身体需要额外的血量时，这点血就弥足珍贵。还有，25%到30%的红细胞和25%的血小板（还记得这些能愈合伤口的细胞碎片吗）也储存在脾脏里以备急用。','2808-2912',5,1711637683,1782480559);
INSERT INTO highlights VALUES('3300037073_19_2040-2075','3300037073',19,'14 高速路和大都市','淋巴液会收集感染处的代表性化学信号，并把信号直接传回免疫系统的情报中心','2040-2075',5,1711637582,1782480559);
INSERT INTO highlights VALUES('3300037073_19_1546-1589','3300037073',19,'14 高速路和大都市','心脏每天会将约7000升血液泵送到身体各处，而淋巴系统每天只回收不到3升的组织液入血。','1546-1589',5,1711637531,1782480559);
INSERT INTO highlights VALUES('3300037073_19_1379-1438','3300037073',19,'14 高速路和大都市','淋巴管的构造像单向阀：组织液可以流进，但不能流出。淋巴液也只朝一个方向流动，小淋巴管慢慢汇聚成大淋巴管，再汇合成淋巴干','1379-1438',5,1711637476,1782480559);
INSERT INTO highlights VALUES('3300037073_19_953-1022','3300037073',19,'14 高速路和大都市','淋巴系统会负责这项工作。它不停地回收身体和组织中多余的液体并运回血液当中，让它们重新循环起来。要是淋巴系统不做这些，人就会慢慢地肿成气球。','953-1022',5,1711636422,1782480559);
INSERT INTO highlights VALUES('3300037073_19_666-725','3300037073',19,'14 高速路和大都市','它没有像肝脏那样的巨型核心器官，有的只是千百个小小的淋巴结。不过和心血管系统一样，它有分布广泛的淋巴管网和专门的淋巴液','666-725',5,1711636368,1782480559);
INSERT INTO highlights VALUES('3300037073_18_3118-3166','3300037073',18,'13 细胞情报员：树突状细胞','树突状细胞这种战场快照和活的信息载体，必须抵达淋巴结。为此，它要进入免疫系统的高速路：淋巴系统。','3118-3166',5,1711636019,1782480559);
INSERT INTO highlights VALUES('3300037073_18_2523-2554','3300037073',18,'13 细胞情报员：树突状细胞','它还是会把敌人进一步分解成碎片，不过这是为了收集样本，识别敌人','2523-2554',5,1711635721,1782480559);
INSERT INTO highlights VALUES('3300037073_18_1823-1909','3300037073',18,'13 细胞情报员：树突状细胞','它们就像细心的品酒师，专门品尝细胞间液的味道，就像在高级品酒会上对待昂贵的红酒那样。它啜上一口，让液体布满整个“口腔”，充分品尝不同的味道、辨出各种成分后，再把液体吐出来。','1823-1909',5,1711635648,1782480559);
INSERT INTO highlights VALUES('3300037073_18_1758-1779','3300037073',18,'13 细胞情报员：树突状细胞','树突状细胞是一群行事小心又镇定自如的哨兵。','1758-1779',5,1711635615,1782480559);
INSERT INTO highlights VALUES('3300037073_18_1308-1371','3300037073',18,'13 细胞情报员：树突状细胞','感染一两天后的伤口，可能流出气味很怪的脓液。它是上百万英勇牺牲的中性粒细胞的尸体，混以平民细胞的残骸、死细菌和残余的抗菌物质。','1308-1371',5,1711635544,1782480559);
INSERT INTO highlights VALUES('3300037073_17_4736-4761','3300037073',17,'12 隐形杀手部队：补体系统','当周围再无敌人之时，补体又变回没有攻击性的隐形武器','4736-4761',5,1711635281,1782480559);
INSERT INTO highlights VALUES('3300037073_17_4291-4299','3300037073',17,'12 隐形杀手部队：补体系统','“膜攻击复合物”','4291-4299',5,1711634910,1782480559);
INSERT INTO highlights VALUES('3300037073_17_3859-3895','3300037073',17,'12 隐形杀手部队：补体系统','细胞和细菌的膜表面都带负电——玩过磁铁的我们都知道，同种电荷会互相排斥。','3859-3895',5,1711634861,1782480559);
INSERT INTO highlights VALUES('3300037073_17_4003-4008','3300037073',17,'12 隐形杀手部队：补体系统','补体带正电','4003-4008',5,1711634857,1782480559);
INSERT INTO highlights VALUES('3300037073_17_3437-3458','3300037073',17,'12 隐形杀手部队：补体系统','成千上万的C3a蛋白会离开伤口，四处呼救。','3437-3458',5,1711634723,1782480559);
INSERT INTO highlights VALUES('3300037073_17_3048-3067','3300037073',17,'12 隐形杀手部队：补体系统','几步下来，它变成了一个召集蛋白的平台。','3048-3067',5,1711634643,1782480559);
INSERT INTO highlights VALUES('3300037073_17_2886-2908','3300037073',17,'12 隐形杀手部队：补体系统','裂解成的两个蛋白一个叫C3b，名字可真有创意','2886-2908',5,1711634625,1782480559);
INSERT INTO highlights VALUES('3300037073_17_2944-2973','3300037073',17,'12 隐形杀手部队：补体系统','一旦发现目标，比如细菌，它就会紧紧黏附到细菌表面，决不松开','2944-2973',5,1711634622,1782480559);
INSERT INTO highlights VALUES('3300037073_17_1012-1072','3300037073',17,'12 隐形杀手部队：补体系统','本质上讲，补体系统是由30多种不同的蛋白质（不是细胞！）组成的军队，它们通力协作，巧妙配合，阻止入侵者在人体内优哉游哉。','1012-1072',5,1711634610,1782480559);
INSERT INTO highlights VALUES('3300037073_17_2455-2473','3300037073',17,'12 隐形杀手部队：补体系统','这种蛋白有一个全无用处的名字：C3。','2455-2473',5,1711633872,1782480559);
INSERT INTO highlights VALUES('3300037073_17_2380-2392','3300037073',17,'12 隐形杀手部队：补体系统','现在需要点燃第一根火柴。','2380-2392',5,1711633869,1782480559);
INSERT INTO highlights VALUES('3300037073_17_1688-1732','3300037073',17,'12 隐形杀手部队：补体系统','在未活化的形状下，补体没有功能。而活化后，补体可以改变其他补体蛋白的形状，从而激活它们。','1688-1732',5,1711633779,1782480559);
INSERT INTO highlights VALUES('3300037073_17_1504-1533','3300037073',17,'12 隐形杀手部队：补体系统','补体蛋白以某种被动的方式四处漂动，无所事事，直到被激活为止','1504-1533',5,1711633761,1782480559);
INSERT INTO highlights VALUES('3300037073_17_1265-1421','3300037073',17,'12 隐形杀手部队：补体系统',unistr('简而言之，补体系统有三大作用：\u000a● 打击敌人，让敌人不好过。\u000a● 激活免疫细胞，引导免疫细胞发现并消灭敌人。\u000a● 往敌人身上扎洞，直至它们死去。'),'1265-1421',5,1711633748,1782480559);
INSERT INTO highlights VALUES('3300037073_17_1096-1140','3300037073',17,'12 隐形杀手部队：补体系统','补体蛋白，数量约为1.5×1019','1096-1133',5,1711633719,1782480559);
INSERT INTO highlights VALUES('3300037073_16_3459-3480','3300037073',16,'11 闻出生命的基本构件','它们有免疫学中最糟糕的名字：“补体系统”。','3459-3480',5,1711633588,1782480559);
INSERT INTO highlights VALUES('3300037073_16_2293-2341','3300037073',16,'11 闻出生命的基本构件','细菌都有某种不可或缺的蛋白。而先天性免疫细胞上都配备有一组特殊受体，能够识别细菌的所有常见蛋白。','2293-2341',5,1711633184,1782480559);
INSERT INTO highlights VALUES('3300037073_16_2080-2133','3300037073',16,'11 闻出生命的基本构件','鞭毛蛋白并不是免疫卫士能够识别的唯一一种拼图块。凭借少数种类的受体，先天性免疫细胞可以识别相当多的蛋白质。','2080-2133',5,1711633094,1782480559);
INSERT INTO highlights VALUES('3300037073_16_1724-1758','3300037073',16,'11 闻出生命的基本构件','所以免疫细胞只要看到鞭毛，就知道长着它的东西百分百是异物，必须消灭掉','1724-1758',5,1711632928,1782480559);
INSERT INTO highlights VALUES('3300037073_16_1281-1355','3300037073',16,'11 闻出生命的基本构件','鞭毛就是个极好的例子。鞭毛是一种细胞器，有些种类的微生物、细菌用它们来移动。它们是长在细菌小屁股上的长长的蛋白质推进器，可以快速旋转，推动细菌前进。','1281-1355',5,1711632788,1782480559);
INSERT INTO highlights VALUES('3300037073_16_1084-1163','3300037073',16,'11 闻出生命的基本构件','对一些特定功能来说，使用的蛋白质不能换，否则功能就会丧失。不管细菌怎么突变，不管它有了怎样新奇聪颖的蛋白质组合，只要它还是细菌，就不得不使用一些特定的蛋白质。','1084-1163',5,1711632769,1782480559);
INSERT INTO highlights VALUES('3300037073_15_3585-3678','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','一旦细胞因子数量过多，免疫系统就会完全失控，陷入狂怒，做出过激反应——人们形象地称之为“细胞因子风暴”。它无非是指太多的免疫细胞释放了太多的细胞因子，哪怕实际上没有危险。其后果是很可怕的','3585-3678',5,1711623917,1782480559);
INSERT INTO highlights VALUES('3300037073_15_2850-2882','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','这些鼻子非常敏感，1%的细胞因子信号浓度差就能告诉细胞该往哪儿走','2850-2882',5,1711623815,1782480559);
INSERT INTO highlights VALUES('3300037073_15_2723-2767','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','，免疫细胞可不是只有一个“鼻子”，而是有百万千万个鼻子，浑身上下都是，全方位覆盖细胞膜。','2723-2767',5,1711623795,1782480559);
INSERT INTO highlights VALUES('3300037073_15_2625-2687','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','通过测量周围细胞因子的浓度，细胞可以准确定位信息来源，并朝该方向移动。哪里“气味”最浓，细胞就往哪里走，这样就可以到达战场。','2625-2687',5,1711623790,1782480559);
INSERT INTO highlights VALUES('3300037073_15_2289-2337','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？',unistr('细胞因子\u000a小分子蛋白质，用以传递信息'),'2289-2337',5,1711623764,1782480559);
INSERT INTO highlights VALUES('3300037073_15_1370-1386','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','细胞因子就是免疫细胞使用的语言。','1370-1386',5,1711621832,1782480559);
INSERT INTO highlights VALUES('3300037073_15_1194-1261','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','某种意义上，它们靠的是“闻”。对细胞来说，信息是实实在在的物理对象：“细胞因子”。简而言之，细胞因子是一类小分子蛋白质，用以传递信息。','1194-1261',5,1711621809,1782480559);
INSERT INTO highlights VALUES('3300037073_15_866-895','3300037073',15,'10 光秃、盲目又惊惧：细胞怎么知道要去哪儿？','要是你像细胞那么大，可见光的波长能从你的脚趾直接拉到肚脐。','866-895',5,1711621715,1782480559);
INSERT INTO highlights VALUES('3300037073_14_3622-3702','3300037073',14,'9 炎症：玩火的艺术','引发炎症的另一条途径更像是种主动策略：战斗中的巨噬细胞和中性粒细胞下令启动炎症反应。这样，只要战斗还在继续，它们就会释放化学物质冲刷战场，随时准备接收增援部队。','3622-3702',5,1711621623,1782480559);
INSERT INTO highlights VALUES('3300037073_14_3274-3315','3300037073',14,'9 炎症：玩火的艺术','肥大细胞”。它长得肥肥大大，细胞内充满了小炸弹似的颗粒，颗粒里都是超强效的化学物质','3274-3315',5,1711621556,1782480559);
INSERT INTO highlights VALUES('3300037073_14_2893-2944','3300037073',14,'9 炎症：玩火的艺术','细胞内容物就会散落得到处都是。像DNA和RNA等类的细胞内容物，会高度激活免疫系统，引发快速的炎症反应','2893-2944',5,1711621461,1782480559);
INSERT INTO highlights VALUES('3300037073_14_2675-2760','3300037073',14,'9 炎症：玩火的艺术','第一种是死亡细胞引发炎症。非常神奇，身体演化出了能区分细胞是自然死亡还是意外惨死的本领。免疫系统会把细胞非自然死亡和重大危险联系在一起，因此细胞死亡是引发炎症的一种信号。','2675-2760',5,1711621425,1782480559);
INSERT INTO highlights VALUES('3300037073_14_2503-2566','3300037073',14,'9 炎症：玩火的艺术','炎症会给身体造成不利影响，它给受累的组织带去压力，激活中性粒细胞这些会造成损害的免疫细胞，因此炎症也自有一些自我平息的内在机制','2503-2566',5,1711621394,1782480559);
INSERT INTO highlights VALUES('3300037073_14_1299-1346','3300037073',14,'9 炎症：玩火的艺术','简而言之，炎症就是血管壁细胞变形，于是血液的液体组分“血浆”大量渗出，涌到受损或感染部位的过程','1299-1346',5,1711621323,1782480559);
INSERT INTO highlights VALUES('3300037073_14_1913-2001','3300037073',14,'9 炎症：玩火的艺术','然后是疼痛。炎症释放的化学物质让神经末梢对疼痛更加敏感，在局部肿胀的过程中，具有疼痛感受器的神经细胞应压力而激活，把疼痛信号传给大脑。疼痛是有力的刺激信号，因为我们不想感到痛。','1913-2001',5,1711621289,1782480559);
INSERT INTO highlights VALUES('3300037073_14_1786-1816','3300037073',14,'9 炎症：玩火的艺术','大部分微生物都不喜欢热，所以伤口的升温会让病菌变得不那么活跃','1786-1816',5,1711621243,1782480559);
INSERT INTO highlights VALUES('3300037073_14_1153-1230','3300037073',14,'9 炎症：玩火的艺术','当今，每两个去世的人中，至少就有一个死于慢性炎症引发的疾病。尽管慢性炎症会给身体施加重负，“常规”炎症本身对免疫防御功能来说还是必不可少的。','1153-1230',5,1711621167,1782480559);
INSERT INTO highlights VALUES('3300037073_14_1046-1071','3300037073',14,'9 炎症：玩火的艺术','讽刺的是，炎症一旦变成慢性，就成了健康的头号敌人。','1046-1071',5,1711621142,1782480559);
INSERT INTO highlights VALUES('3300037073_14_711-1016','3300037073',14,'9 炎症：玩火的艺术','简而言之，炎症反应的目标是将感染局限在一定范围内，防止它扩散，同时也协助清除受损和死去的组织，为免疫细胞和免疫蛋白搭建起直达感染部位的特快通道。','711-783',5,1711621130,1782480559);
INSERT INTO highlights VALUES('3300037073_14_503-525','3300037073',14,'9 炎症：玩火的艺术','炎症是免疫系统对所有类别的损伤做出的普遍反应','503-525',5,1711621106,1782480559);
INSERT INTO highlights VALUES('3300037073_13_5389-5460','3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','因为，尽管含有染料的巨噬细胞某个时刻会死去，但新生的巨噬细胞会把前辈的尸体连同染料一起吞下，而新生代们同样不能分解染料，也只能任由其留在体内。','5389-5460',1,1711554074,1782480559);
INSERT INTO highlights VALUES('3300037073_13_5135-5176','3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','巨噬细胞分解细菌和细胞垃圾很厉害，但它们其实无法分解染料，所以只能把染料留在体内。','5135-5176',1,1711554023,1782480559);
INSERT INTO highlights VALUES('3300037073_13_4330-4513','3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','它一旦觉得有必要采取极端措施，就会开始疯狂的自杀。首先是细胞核溶解，释放出DNA。这些DNA充满细胞后，大量的蛋白质和酶——相当于故事中尖利的骨头碎片——会黏附其上。随后中性粒细胞会吐出所有这些DNA，在细胞周围形成巨大的网。这种网不但能困住并伤害敌人，还构建出了一道物理屏障，阻止细菌、病毒逃逸及进一步深入体内。在这之后，英勇的中性粒细胞会一命呜呼——不死才怪呢。','4330-4513',1,1711553938,1782480559);
INSERT INTO highlights VALUES('3300037073_13_4303-4314','3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','“中性粒细胞胞外陷阱”','4303-4314',1,1711553909,1782480559);
INSERT INTO highlights VALUES('3300037073_13_4088-4130','3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','可是守卫并没有朝你挥拳，而是撕开自己的胸膛，把肋骨劈成无数尖利的碎片，还掏出了肠子。','4088-4130',1,1711553887,1782480559);
INSERT INTO highlights VALUES('3300037073_13_3010-3089','3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','它是血液中数量最多同时无疑也是最厉害的免疫细胞。中性粒细胞的确很危险，因此都带有自毁装置。它们寿命很短，不发挥作用的情况下只能活几天，随后就会启动程序性死亡。','3010-3089',1,1711553778,1782480559);
INSERT INTO highlights VALUES('3300037073_12_4270-4311','3300037073',12,'7 伤口','但树突状细胞的目标不是吃掉敌人，而是收集死亡敌人的样本，呈递给免疫系统的情报中心。','4270-4311',1,1711553468,1782480559);
INSERT INTO highlights VALUES('3300037073_12_4142-4183','3300037073',12,'7 伤口','它就是“树突状细胞”，先天性免疫系统强大的信使和情报员，它是不会对灾难袖手旁观的。','4142-4183',1,1711553447,1782480559);
INSERT INTO highlights VALUES('3300037073_12_2920-2971','3300037073',12,'7 伤口','你感觉到的轻微肿胀，其实是免疫系统有意做出的反应。它名为“炎症”，是抵抗感染的细胞展开的重要防御过程。','2920-2971',1,1711553321,1782480559);
INSERT INTO highlights VALUES('3300037073_12_1322-1507','3300037073',12,'7 伤口','先天性免疫系统立即做出了反应。最先出现的是哨兵细胞——它们正在周围平静地巡逻，“大撞击”发生后听到呼救，看到碎屑瓦砾，火速赶到了出事地点。这些细胞名叫“巨噬细胞”，是体内最大的免疫细胞。巨噬细胞的体型很是惹眼。假如把普通细胞比作人类大小，巨噬细胞就相当于黑犀牛。而且就跟黑犀牛一样，你最好不要招惹它们。它们的工作是吞噬死去的细胞和活生生的敌人，组织防御，并帮助伤口愈合。','1322-1507',1,1711553145,1782480559);
INSERT INTO highlights VALUES('3300037073_11_4424-4486','3300037073',11,'6 荒漠之国：皮肤','科学家们现在还没完全弄清楚细菌和人体怎样达成的一致，免疫系统怎样决定哪些细菌可以住下，细菌又是怎样对免疫系统表明自己意图的。','4424-4486',1,1711552924,1782480559);
INSERT INTO highlights VALUES('3300037073_11_2357-2388','3300037073',11,'6 荒漠之国：皮肤','要是这还不够，那汗液中还有更多的天然抗生素，也能被动杀灭细菌。','2357-2388',5,1711518591,1782480559);
INSERT INTO highlights VALUES('3300037073_11_2324-2356','3300037073',11,'6 荒漠之国：皮肤','这样一来，皮肤表面就变成了一片盐碱地，而许多微生物不喜欢这种环境','2324-2356',5,1711518586,1782480559);
INSERT INTO highlights VALUES('3300037073_11_1965-1992','3300037073',11,'6 荒漠之国：皮肤','它在向上迁移时，也会被裹上一层脂质的天然被动“抗生素”','1965-1992',5,1711518569,1782480559);
INSERT INTO highlights VALUES('3300037073_11_1672-1756','3300037073',11,'6 荒漠之国：皮肤','你甚至可以说，皮肤细胞活着就是为了在合适的地方变成齐整的尸体。融合后的死亡皮肤细胞会被不断推向表层。足足有50层死细胞叠在一起，形成皮肤那“死去”的表层，覆盖整个身体。','1672-1756',5,1711518465,1782480559);
INSERT INTO highlights VALUES('3300037073_11_1593-1635','3300037073',11,'6 荒漠之国：皮肤','人体内的细胞自然死亡很常见，每秒钟就有至少100万细胞正经历着某种形式的程序性死亡。','1593-1635',5,1711518440,1782480559);
INSERT INTO highlights VALUES('3300037073_11_888-972','3300037073',11,'6 荒漠之国：皮肤','新的皮肤细胞一出生就要离开家门。皮肤干细胞不停增殖，新生代不断推动旧细胞朝表层移动。因此皮肤细胞是一直被下层的新生细胞推动着的。越靠近表面，就越要准备好承担防御的职责。','888-972',5,1711465272,1782480559);
INSERT INTO highlights VALUES('3300037073_10_2728-2765','3300037073',10,'第2部分 惨重损伤','事实上，大部分细菌对人不但无害，反而有益，人类的祖先早早就和它们达成了合作','2728-2765',5,1711421086,1782480559);
INSERT INTO highlights VALUES('3300037073_10_2089-2192','3300037073',10,'第2部分 惨重损伤','实际上细菌经历了悠久的演化，复杂程度刚刚好，在地球上超级成功！它们是生存大师，有养分的地方基本都能找到它们的踪影。要是实在没有营养物质，它们有时也可以通过吸收辐射或摄入其他一些通常不能消化的东西来自产养分。','2089-2192',5,1711345472,1782480559);
INSERT INTO highlights VALUES('3300037073_10_1948-1976','3300037073',10,'第2部分 惨重损伤','如果把细胞看做一个人大小，那细菌平均而言就相当于一只兔子','1948-1976',5,1711345452,1782480559);
INSERT INTO highlights VALUES('3300037073_10_1890-1918','3300037073',10,'第2部分 惨重损伤','细菌是地球上最古老的生物之一，已经热热闹闹地活了几十亿年','1890-1918',5,1711345420,1782480559);
INSERT INTO highlights VALUES('3300037073_9_2828-2881','3300037073',9,'4 免疫帝国','但其实它最重要的任务之一就是激励先天免疫细胞更努力、更高效地战斗，从而增强先天性免疫（这个我们后面再说）。','2828-2881',5,1711340279,1782480559);
INSERT INTO highlights VALUES('3300037073_9_2745-2777','3300037073',9,'4 免疫帝国','母亲可以通过母乳传给婴儿一点适应性免疫力，给他们保护，帮他们存活','2745-2777',5,1711340250,1782480559);
INSERT INTO highlights VALUES('3300037073_9_2669-2707','3300037073',9,'4 免疫帝国','人在出生时完全没有适应性免疫力，后来这种免疫力会不断增强，等到老年又会减弱。','2669-2707',5,1711340188,1782480559);
INSERT INTO highlights VALUES('3300037073_9_2486-2581','3300037073',9,'4 免疫帝国','不过现在我们只需要记住适应性免疫系统拥有可知宇宙中最大的图书馆，现有和将来可能出现的敌人在其中都有相关条目。还不仅如此，它还能记住只入侵过一次的敌人的一切。这也是为什么有些病一生只会得一次。','2486-2581',5,1711340164,1782480559);
INSERT INTO highlights VALUES('3300037073_9_2130-2203','3300037073',9,'4 免疫帝国','而适应性免疫系统王国，则由特化的超级细胞组成，会配合并支援一线部队。它拥有能生产重型蛋白质武器的工厂，和在病毒入侵时捕获、清除感染细胞的专门细胞。','2130-2203',5,1711340068,1782480559);
INSERT INTO highlights VALUES('3300037073_9_2033-2101','3300037073',9,'4 免疫帝国','所以在交战中，先天性免疫系统会收集情报数据，再做出往往关乎生死存亡的决策。如果判断情况严峻，它有权激活并召集二线部队，调动它们加入战斗。','2033-2101',5,1711340044,1782480559);
INSERT INTO highlights VALUES('3300037073_9_1767-1793','3300037073',9,'4 免疫帝国','先天性免疫干的都是累活，也参与了大部分真刀真枪的战斗','1767-1793',5,1711339973,1782480559);
INSERT INTO highlights VALUES('3300037073_9_1518-1595','3300037073',9,'4 免疫帝国','先天性系统的核心特征是智能，有能力区分自身和异物，一旦检测到异物就会快速反应。不过，先天性免疫没有针对特定敌人的定制武器，而是无差别地大范围攻击各种敌人。','1518-1595',5,1711339917,1782480559);
INSERT INTO highlights VALUES('3300037073_9_1057-1168','3300037073',9,'4 免疫帝国','最有效、最巧妙的两种免疫原理：先天性(innate)免疫系统和适应性(adaptive)免疫系统。','1057-1168',5,1711339815,1782480559);
INSERT INTO highlights VALUES('3300037073_9_635-946','3300037073',9,'4 免疫帝国','免疫系统是一个复合系统，里面包含了许多东西，有数百种小器官和一些稍大的器官，还有管道和组织的网络，特化为几十种类型的数十亿细胞，以及1018数量级的游离蛋白。￼','635-741',5,1711339769,1782480559);
INSERT INTO highlights VALUES('3300037073_8_6809-6861','3300037073',8,'3 细胞是什么样的？','自然界中这种现象很常见，叫“涌现”(emergence)，指的是实体拥有它的组成部分所没有的属性和能力。','6809-6861',5,1711339582,1782480559);
INSERT INTO highlights VALUES('3300037073_8_4672-4698','3300037073',8,'3 细胞是什么样的？','布朗运动”，指的是气体或液体中的分子所做的随机运动。','4672-4698',5,1711339133,1782480559);
INSERT INTO highlights VALUES('3300037073_8_4456-4481','3300037073',8,'3 细胞是什么样的？','于是理论上，在室温下，一个蛋白质平均每秒能移动5米','4456-4481',5,1711339098,1782480559);
INSERT INTO highlights VALUES('3300037073_8_4390-4436','3300037073',8,'3 细胞是什么样的？','蛋白质如此微小、几无重量，它们的世界和我们的有本质区别，因此其运动方式在人类看来也会非常奇特','4390-4436',5,1711339088,1782480559);
INSERT INTO highlights VALUES('3300037073_8_4196-4234','3300037073',8,'3 细胞是什么样的？','用个比喻来说就是，细胞这台机器人的灵魂，就是蛋白质及其背后的指导性生化反应。','4196-4234',5,1711338997,1782480559);
INSERT INTO highlights VALUES('3300037073_8_3982-3994','3300037073',8,'3 细胞是什么样的？','它们还是传递信息的信使，','3982-3994',5,1711338958,1782480559);
INSERT INTO highlights VALUES('3300037073_8_3869-3918','3300037073',8,'3 细胞是什么样的？','蛋白质的形状会决定它的功能。形状就是一切。某种意义上，你可以把蛋白质想象成特别复杂的三维立体拼图。','3869-3918',5,1711338940,1782480559);
INSERT INTO highlights VALUES('3300037073_8_3750-3780','3300037073',8,'3 细胞是什么样的？','氨基酸链生成后，会变形折叠，从二维的线条变成三维的立体结构。','3750-3780',5,1711338855,1782480559);
INSERT INTO highlights VALUES('3300037073_8_3440-3476','3300037073',8,'3 细胞是什么样的？','要是把你身体里的所有DNA都连成一长串，它就足够从地球到冥王星连一个来回','3440-3476',5,1711338840,1782480559);
INSERT INTO highlights VALUES('3300037073_8_3382-3411','3300037073',8,'3 细胞是什么样的？','单一个细胞中的DNA，展开连在一起就有2米长','3382-3411',5,1711338825,1782480559);
INSERT INTO highlights VALUES('3300037073_8_2883-2906','3300037073',8,'3 细胞是什么样的？','所谓的生命编码基本上就是构建蛋白质的指导手册。','2883-2906',5,1711289401,1782480559);
INSERT INTO highlights VALUES('3300037073_8_2809-2866','3300037073',8,'3 细胞是什么样的？','DNA中约有1%的序列会指导蛋白质的合成，这些序列就是“基因”。其余DNA调控合成蛋白质的时机、种类、方式和数量。','2809-2866',5,1711289379,1782480559);
INSERT INTO highlights VALUES('3300037073_8_1380-1404','3300037073',8,'3 细胞是什么样的？','以分子尺度看，水不再是液体，而变得像蜂蜜一样黏稠','1380-1404',5,1711289157,1782480559);
INSERT INTO highlights VALUES('3300037073_8_1247-1314','3300037073',8,'3 细胞是什么样的？','请想象这个房间堆得满满的。里面有数百万颗的沙粒和大米，几千只苹果和桃子，还有几十个大西瓜。细胞里面大概就像这样。这在现实中意味着什么？','1247-1314',5,1711288591,1782480559);
INSERT INTO highlights VALUES('3300037073_7_1558-1646','3300037073',7,'2 守卫每一寸身体','你可能会误以为黏膜属于身体内部。但其实，它们属于外部。仔细想想，其实从某种意义上说，人体不过是一根复杂的管道。没错，一根两端可闭合的管道，只不过更加湿漉漉、滑溜溜、乱糟糟一些。','1558-1646',5,1711287843,1782480559);
INSERT INTO highlights VALUES('3300037073_7_1269-1281','3300037073',7,'2 守卫每一寸身体','皮肤的总面积约有2平方米','1269-1281',5,1711287826,1782480559);
INSERT INTO highlights VALUES('3300037073_7_1485-1505','3300037073',7,'2 守卫每一寸身体','不过健康成年人的黏膜面积约有200平方米','1485-1505',5,1711287821,1782480559);
INSERT INTO highlights VALUES('3300037073_7_1405-1463','3300037073',7,'2 守卫每一寸身体','真正薄弱、易受感染的，其实是黏膜，它们分布在气管和肺、眼睑、口腔和鼻腔、胃肠道、生殖道和膀胱的内表面。','1405-1463',5,1711287798,1782480559);
INSERT INTO highlights VALUES('3300037073_7_1058-1123','3300037073',7,'2 守卫每一寸身体','假如你小得就像一个细胞，那么人体对你来说就有15到20座珠穆朗玛峰摞在一起那么大。这座血肉之躯将有至少100千米高，直插入大气外层','1058-1123',5,1711287769,1782480559);
INSERT INTO highlights VALUES('3300037073_6_5431-5471','3300037073',6,'第1部分 认识免疫系统','战场上只有鲁莽的免疫士兵想弄明白仗要怎么打，需不需要坦克和战斗机，要往哪儿集结。','5431-5471',5,1711287646,1782480559);
INSERT INTO highlights VALUES('3300037073_6_5266-5308','3300037073',6,'第1部分 认识免疫系统','区分自身和异物是免疫系统的核心，维持稳态是其目标，另外免疫系统还有许多种可能会出错。','5266-5308',5,1711287624,1782480559);
INSERT INTO highlights VALUES('3300037073_6_5021-5073','3300037073',6,'第1部分 认识免疫系统','因此，尽管拥有能对外界威胁做出快速有力反应的免疫系统对健康很是关键，但同时保证它不会失控和搞破坏也很重要','5021-5073',5,1711287588,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4809-4838','3300037073',6,'第1部分 认识免疫系统','另外，就算是运行正常，免疫系统也会在帮助你的同时带给你痛苦','4809-4838',5,1711287555,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4701-4780','3300037073',6,'第1部分 认识免疫系统','过敏性休克”就是一种严重的过敏反应，它凸显了免疫系统有多强大，一旦出错又多么可怕：疾病未必会马上置人于死地，而免疫系统带来的过敏性休克却能在几分钟内夺人性命。','4701-4780',5,1711287519,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4672-4700','3300037073',6,'第1部分 认识免疫系统','还有过敏反应，它是指免疫系统对无害的物质产生了过激反应。','4672-4700',5,1711287486,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4546-4643','3300037073',6,'第1部分 认识免疫系统','免疫系统也可能失衡或受损，从而糊涂地攻击自身。它会把“我”误判为“他”，实实在在地攻击起它本该保护的那些身体细胞，导致一系列自身免疫性疾病，而病人不得不长期服用可能伴有严重副作用的免疫抑制药物。','4546-4643',5,1711287468,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4400-4416','3300037073',6,'第1部分 认识免疫系统','预防癌症是免疫系统的头等大事之一','4400-4416',5,1711287431,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4092-4122','3300037073',6,'第1部分 认识免疫系统','因为总体而言，生而为人是幸福的，我们都希望自己可以活得久一点','4092-4122',5,1711287323,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4042-4091','3300037073',6,'第1部分 认识免疫系统','尽管这场守护健康的战争终会不可避免地输掉，变成徒劳，但我们仍在努力夺取多一些岁月，哪怕只是几个小时','4042-4091',5,1711287317,1782480559);
INSERT INTO highlights VALUES('3300037073_6_4027-4042','3300037073',6,'第1部分 认识免疫系统','对免疫系统来说，健康就是稳态。','4027-4042',5,1711287308,1782480559);
INSERT INTO highlights VALUES('3300037073_6_3848-3891','3300037073',6,'第1部分 认识免疫系统','健康其实是一个抽象的概念，因为它描述的是没有病痛、不受限制的状态，不是“有”而是“无”','3848-3891',5,1711287293,1782480559);
INSERT INTO highlights VALUES('3300037073_6_3637-3669','3300037073',6,'第1部分 认识免疫系统','免疫系统的首要目标是维持“稳态”，即维持体内全部细胞及物质的平衡','3637-3669',5,1711287221,1782480559);
INSERT INTO highlights VALUES('3300037073_6_3250-3325','3300037073',6,'第1部分 认识免疫系统','免疫系统中还有专门的“大学”，供细胞学习如何识别敌人及怎样作战。这所大学有着世界上最大的生物学图书馆，可以教你识别一生中可能碰到的所有敌人并记住它们。','3250-3325',5,1711287186,1782480559);
INSERT INTO highlights VALUES('3300037073_6_3184-3231','3300037073',6,'第1部分 认识免疫系统','1018数量级的蛋白质武器组成的防御系统','3184-3231',5,1711287164,1782480559);
INSERT INTO highlights VALUES('3300037073_6_3089-3173','3300037073',6,'第1部分 认识免疫系统','基于免疫器官和免疫“基础设施”，有几百亿免疫细胞在免疫路网和血流中巡逻，可以随时应召和敌人作战。此外，人体外部组织表面也有几十上百亿的免疫细胞形成的屏障，准备抵挡入侵。','3089-3173',5,1711287158,1782480559);
INSERT INTO highlights VALUES('3300037073_6_2795-2852','3300037073',6,'第1部分 认识免疫系统','不过，免疫系统并不只是存在于你的体内，它就是你本身。','2795-2852',5,1711275900,1782480559);
INSERT INTO highlights VALUES('3300037073_6_2388-2488','3300037073',6,'第1部分 认识免疫系统','而在最早的脊椎动物身上，我们就已经看到了重大的创新：出现了专门的免疫器官暨细胞的“训练场”，以及最为强大的免疫原理之一——能够识别特定的敌人，并快速制造大量的针对性武器实现精准打击，还要牢牢记住它们！','2388-2488',5,1711275855,1782480559);
INSERT INTO highlights VALUES('3300037073_6_2253-2292','3300037073',6,'第1部分 认识免疫系统','动物很可能没用多久就发展出了专业的防御细胞，相应的免疫就叫“细胞［介导］免疫”','2253-2292',5,1711275801,1782480559);
INSERT INTO highlights VALUES('3300037073_6_2056-2177','3300037073',6,'第1部分 认识免疫系统','体液免疫主要通过游离在细胞外体液中的微小蛋白来实现功能，杀伤、歼灭不该出现的外来微生物。这类防御非常有用，也非常成功，几乎所有现存的动物，包括我们人类，都有体液免疫。它没有被演化淘汰，而是变得举足轻重。原则上说，体液免疫在5亿年里都没怎么变。','2056-2177',5,1711275568,1782480559);
INSERT INTO highlights VALUES('3300037073_6_1871-1908','3300037073',6,'第1部分 认识免疫系统','选取相差悬殊的动物，比较它们的防御机制，我们就可以了解很多免疫系统的历史。','1871-1908',5,1711275509,1782480559);
INSERT INTO highlights VALUES('3300037073_6_1678-1719','3300037073',6,'第1部分 认识免疫系统','但通过科技的魔法，我们可以看到生命树的各个分叉，并观察现存动物，研究它们的免疫系统','1678-1719',5,1711275454,1782480559);
INSERT INTO highlights VALUES('3300037073_6_1635-1678','3300037073',6,'第1部分 认识免疫系统','可惜，经过数亿年的时间，细胞和组织都没有得到好好的保存，我们看不到免疫系统的化石遗迹。','1635-1678',5,1711275442,1782480559);
INSERT INTO highlights VALUES('3300037073_6_1050-1421','3300037073',6,'第1部分 认识免疫系统',unistr('我们现在并不特别清楚，到底是什么让单打独斗的细胞开始向着密切合作并有专门分工的庞大细胞群发展的。￼\u000a大约在5亿4100万年前，多细胞动物出现了爆发性增长，体型变得肉眼可见，多样性也以极快的速度大大增加。'),'1050-1421',5,1711274415,1782480559);
INSERT INTO highlights VALUES('3300037073_6_761-798','3300037073',6,'第1部分 认识免疫系统','风险更小的办法是潜入对手细胞内部并在此安家：分享宿主的食粮，享受它的呵护。','761-798',5,1711273592,1782480559);
INSERT INTO highlights VALUES('3300037073_6_598-670','3300037073',6,'第1部分 认识免疫系统','它们必须想办法把周围的化学物质转化成能为己所用的东西，同时获取生存必需的能量，而其中有些细胞就盯上了“捷径”。如果能偷别人的，干吗还要自己干呢？','598-670',5,1711273572,1782480559);
INSERT INTO highlights VALUES('3300037073_5_3588-3623','3300037073',5,'前言','不过，许多科学家并不擅长命名，也不擅长用通俗易懂的语言来描述他们的发现','3588-3623',5,1711273292,1782480559);
INSERT INTO highlights VALUES('3300037073_5_803-855','3300037073',5,'前言','免疫系统就像心、肺一样重要。实际上，它也是体内最大、分布最广的器官系统之一，尽管我们往往没有这样看待它。','803-855',5,1711224392,1782480559);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_31_39065-39113','CB_4S997B96qGVz6al6YD',31,'邓小平时代的关键人物','他的儿子习近平于2007年当选为最年轻的政治局常委，成为最有可能在2013年接任国家主席一职的人','39065-39113',NULL,1672127449,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_31_13305-13470','CB_4S997B96qGVz6al6YD',31,'邓小平时代的关键人物','陈云生性敏感，处事稳健而审慎，一遇到压力，尤其是受到毛的批评时，就会自称心脏不好，数周甚至数月闭门休养。1962年，当陈云提出实行包产到户的可能性而受到毛泽东批评时，他万分沮丧，以至两个星期不能说话，过了很久才恢复过来。毛泽东曾说，陈云太胆小，一片树叶落下来也怕砸到自己头上。陈云也是个不合群的人，他很少接待来客，常常独自一人吃饭','13305-13470',NULL,1672125515,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_69172-69213','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','美国是由保留着独立权力的各州所组成，而中国千百年来一直有一个控制着地方的中央政府。','69172-69213',NULL,1672119259,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_69072-69116','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','他们认为，立法机构制定法律但不负责执行法律的体制，不如集立法与执行于一身的体制更有效率。','69072-69116',NULL,1672119243,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_63510-63547','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','他把各种想法进行梳理和总结，用他的团队和群众所能接受的步调和方式展示给他们','63510-63547',NULL,1672118765,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_63486-63510','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','不如说，邓小平是为转型过程提供全面领导的总经理。','63486-63510',NULL,1672118758,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_63347-63429','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','改革开放并非由邓小平启动，它是邓小平上台之前在华国锋的领导下起步的。邓小平也不是手持伟大蓝图、主宰着变革的设计师；事实上，这个变革的时代并没有清晰、完整、现成的设计','63347-63429',NULL,1672118747,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_63134-63236','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','邓小平时代发生的转型是由多种因素共同塑造的：高度发达的中国传统，中国社会的规模和多样性，当时世界格局的性质，共享技术和管理方式的全球体系的开放性，中国共产党的性质，无数具有创造力和勤奋工作的人们的贡献等等','63134-63236',NULL,1672118707,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_50018-50093','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','按照邓小平的遗愿，他的眼角膜被捐出供眼科研究，内脏被捐出供医学研究，遗体被火化，骨灰盒上覆盖着中国共产党党旗。1997年3月2日，他的骨灰被撒入大海。','50018-50093',NULL,1672118657,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_47363-47506','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','天安门悲剧后的1989年至1991年，外国直接对华投资陷入停滞，平均每年只有40亿美元；但是从1992年到1999年，由于中国的对外开放政策和外国制裁的逐渐减弱，每年吸引的外资平均为350亿美元。快速增长引发了又一轮经济过热和通胀压力，但朱镕基在1995年以软着陆方式控制住了这些压力。','47363-47506',NULL,1672118416,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_46627-46671','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','在邓小平1992年南巡后的几年里，中国取得了世界上史无前例的增长率，其规模也是前无古人的','46627-46671',NULL,1672118349,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_45995-46051','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','与这些人相比，江泽民手下后来成为第四代领导人的都不是老革命，而是在邓小平那一代领导人创建的体制下成长起来的好学生','45995-46051',NULL,1672118295,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_45112-45138','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','邓小平在十四大选定的政治局常委中最年轻的成员是胡锦涛','45112-45138',NULL,1672118168,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_44708-44730','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','朱镕基副总理，兼担任了新组建的经贸办公室主任','44708-44730',NULL,1672118126,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_43838-43879','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','邓小平指定77岁的刘华清——他能听从江泽民的领导——和江泽民的亲信曾庆红取代了他们','43838-43879',NULL,1672118051,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_43668-43803','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','在中共十四大之前不久，邓小平迫使他的长期盟友、与他一起南行的杨尚昆和杨白冰兄弟退休。','43668-43803',NULL,1672118041,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_42086-42130','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','江泽民不但赞扬邓小平是中国改革开放的总设计师，而且把他的观点上升到“邓小平理论”的高度。','42086-42130',NULL,1672115857,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_39076-39210','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','江泽民进而把这些想法概括为一个他估计能得到邓小平赞成的说法：“社会主义市场经济”。','39076-39210',NULL,1672115465,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_26774-27023','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','计划不等于社会主义，市场也不等于资本主义。资本主义也有计划，社会主义也有市场。贫穷不是社会主义。要走共同富裕的社会主义道路。为了达到这个目标，先富起来的地方要多缴税，用来帮助落后地区。但各地的情况不可能很快拉平，不能搞“大锅饭”，这会打击人们的热情。邓小平鼓励干部进行试验，敢于冒险，不要怕犯错误，有错改了就好。','26774-27023',NULL,1672113230,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_14700-14797','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','可是1991年这把火并没有点着，决心已定的邓小平在1992年又点了一把更大的火。他以87岁高龄，乘专列南下，先去武汉，然后是深圳、珠海和上海，他在这些地方成功点燃了扩大市场开放和加快发展的大火。','14700-14797',NULL,1672112151,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_29_14620-14700','CB_4S997B96qGVz6al6YD',29,'第23章　邓小平时代的终曲——南巡：1992','当时邓小平对北京保守的经济政策也感到不快，可是他对这些政策又不能完全说了算。他无法在《人民日报》上表达自己的观点，便把它登在另一家报纸——上海的《解放日报》上。','14620-14700',NULL,1672112144,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_27_79325-79358','CB_4S997B96qGVz6al6YD',27,'第21章　天安门悲剧：1989年5月17日–6月4日','需要用什么来取代马列主义毛泽东思想呢？答案似乎不言自明：爱国主义。','79325-79358',NULL,1672111793,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_27_79165-79210','CB_4S997B96qGVz6al6YD',27,'第21章　天安门悲剧：1989年5月17日–6月4日','邓小平和他的党内元老们认识到，不能再指望用马列主义毛泽东思想的政治教育去打动中国的年轻人了','79165-79210',NULL,1672111771,1782480565);
