INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_54304-54330','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','政府无力在国营企业中扩大就业，因此允许家庭搞“个体户','54304-54330',NULL,1669254721,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_52115-52202','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','小平不认为在1978年就能预见到哪些制度最有利于中国的现代化。他授意赵紫阳成立研究机构，研究各地采用的截然不同的体制。如果试验取得成功，他会鼓励人们尝试在其他地方是否也能奏效','52115-52202',NULL,1669254539,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_29321-29481','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','华国锋还追求经济的过快增长。胡耀邦承认，这不是华国锋一个人的错误，也是邓小平和他本人的错误，其实，当时只有陈云认识到了那些计划太冒进。','29321-29481',NULL,1669098990,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_19743-19801','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','各部委和各省也都有一个不大的政策研究室，其主要任务之一便是随时了解和掌握高层领导的最新想法及其对本部门或本省的意义。','19743-19801',NULL,1669098051,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_18771-18818','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','万里成为事实上的副总理，并担任国家农业委员会主任，这为在全国农业生产中实行包产到户铺平了道路。','18771-18818',NULL,1669097814,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_18724-18770','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','胡耀邦成了党的总书记。华国锋名义上仍是总理，但赵紫阳成为实际上的总理，开始主持国务院日常工作','18724-18770',NULL,1669097803,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_16558-16586','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','他又悄悄将“收入翻两番”这个说法改为“国民生产总值翻两番','16558-16586',NULL,1669097626,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_16487-16516','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','小平逐渐相信，从1980年到2000年中国的收入能够翻两番','16487-16516',NULL,1669097608,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_15189-15239','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','然而，台湾在此后30年里取得的经济成功，完全取决于它跟大陆的经济关系，这在1980年几乎没人能想到。','15189-15239',NULL,1669097523,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_13692-13761','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','1980年1月16日，邓小平发表了重要讲话〈目前的形势和任务〉，提出他为1980年代确定的主要任务，这实际上是他关于未来十年的“国情咨文”','13692-13761',NULL,1669097360,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_19_6355-6470','CB_4S997B96qGVz6al6YD',19,'第13章 邓小平的治国术','从1980年到1987年胡耀邦下台的这段邓小平主政时期，用西方的话说，邓小平是董事会主席和首席执行官，胡耀邦和赵紫阳则在他手下分别担任党、政两大部门的执行总裁。党制定大政方针、主管自上而下各级部门人事和宣传，政府则负责各级行政管理','6355-6470',NULL,1669096843,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_76969-77010','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','邓小平在当时的15个月里5次出访国外。虽然他又活了18年，但是从此再也没有迈出国门','76969-77010',NULL,1669089835,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_75298-75353','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','邓小平访美后的一年里，有1,025名中国人持学生签证赴美，到1984年时则有14,000名中国学生进入美国大学','75298-75353',NULL,1669089671,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_57928-57978','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','《时代》不知道华国锋在中央工作会议上已元气大伤，将邓小平称为中国的首席执行官，华国锋则是董事会主席。','57928-57978',NULL,1668998424,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_57370-57405','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','邓小平是一个“非凡人物——急躁、好胜、自信、坦率、直接、强硬、头脑精明','57370-57405',NULL,1668998363,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_55462-55507','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','邓小平作出了深思熟虑的决定，因为他知道自己没有足够的力量使美国既同中国建交，又停止对台售武','55462-55507',NULL,1668946451,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_55087-55143','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','或许更重要的是，邓小平还知道，与美国实现关系正常化，会让中国更容易得到它在现代化建设中所需要的知识、资本和技术。','55087-55143',NULL,1668946380,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_54969-55086','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','但他知道，这个决定将使他最珍视的目标之一——在有生之年看到台湾回归大陆——的实现变得异常困难。那么他为什么还要同意呢？当时他刚刚在其势均力敌的同事中成为中国的头号领导人，他可能认为，实现中美关系正常化可以加强他在中国领导层中的个人地位','54969-55086',NULL,1668946370,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_54510-54589','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','伍德科克答道，他认为在关系正常化以后，随着时间的推移，美国人会接受台湾是中国的一部分，支持中国的统一——当时很多美国官员也和中国官员一样，认为这会在几年内发生','54510-54589',NULL,1668946307,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_46700-46778','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','中方坚持他们对《上海公报》的解释，即美国支持“一个中国”的政策。事实上，尼克逊在签署《上海公报》时只承认了海峡两岸都坚持只有一个中国，美国对这种观点不持异议','46700-46778',NULL,1668934070,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_31667-31704','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','充分运用了美国人对中国的好奇心，以及他本人的直率、迷人的机智和旺盛的精力。','31667-31704',NULL,1668879470,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_30510-30551','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','邓小平说，中国是有耐心的，不过美国也要清楚，中国不会让这个问题的解决无限期地拖下去','30510-30551',NULL,1668878943,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_19777-19834','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','从1979年到2007年，日本海外经济协力基金向中国提供的贷款多于它对任何其他国家的贷款，总计达到2.54万亿日元','19777-19834',NULL,1668798017,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_17_14119-14150','CB_4S997B96qGVz6al6YD',17,'第11章　向美国敞开大门：1978–1979','事实上，在邓复出之前，以君津为范例的宝山钢铁厂已经在筹划之中。','14119-14150',NULL,1668797396,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_44765-44788','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','如果他的行动引发一些新问题，他会逐个加以处理。','44765-44788',NULL,1668669245,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_44724-44764','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','小平是实用主义者，在遇到新问题时，他首先会尽量搞清楚症结所在，然后才决定如何应付','44724-44764',NULL,1668669236,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_42670-42724','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','小平觉得，井然有序的新加坡是一个令人向往的改革榜样，他准备派人去那里学习城市规划、公共管理和控制腐败的经验。','42670-42724',NULL,1668669012,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_31509-31553','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','中国在1960年代初开始向这些国家进行无线电广播，鼓动当地人民闹革命，更加剧了这种担心。','31509-31553',NULL,1668667221,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_29809-29887','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','他相信，要让苏联停止在东南亚的扩张，就得采取强而有力的军事行动。他打算“教训一下”越南，让它知道无视中国的警告以及向苏联提供军事基地，将付出多么沉重的代价。','29809-29887',NULL,1668666955,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_21452-21491','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','他们发动了规模浩大的运动，把大批华人成群结队送往拘留中心，致使很多华人逃离越南','21452-21491',NULL,1668665416,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_18783-18814','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','越南人原本不想完全依附于苏联，但它迫切需要为重建国家获得帮助。','18783-18814',NULL,1668665151,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_15298-15332','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','中国从1972年开始牺牲中越友谊跟美国改善关系，这也让越南人心中不快','15298-15332',NULL,1668664618,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_14950-15082','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','因为当他们在1954年日内瓦和会上为统一国家而努力时，中国没有为他们提供支持。','14950-15082',NULL,1668664589,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_13458-13488','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','同时，越南已经控制了老挝，并且正在策划入侵中国的盟友柬埔寨。','13458-13488',NULL,1668664406,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_12841-12891','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','邓小平的战略分析起点和毛泽东是一样的：分清主要敌人，广结盟友与之对抗；分化敌人的盟友，使其疏远敌人。','12841-12891',NULL,1668664248,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_10986-11024','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','但是，与毛和周相比，邓关注与中国有关的重大问题时更有系统性，也更加坦白直率。','10986-11024',NULL,1668664054,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_15_10946-10985','CB_4S997B96qGVz6al6YD',15,'第9章　苏联和越南的威胁：1978–1979','邓小平在会见外国人时，不但要完成既定的会谈内容，还会努力摸清来访者的性格和目的','10946-10985',NULL,1668664045,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_72851-72898','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','但是在如何划定自由的界限上，他们的分歧却愈演愈烈，最终导致邓小平在1987年决定将胡耀邦撤职。','72851-72898',NULL,1668663600,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_71624-71677','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','如果邓小平认为有什么事物是神圣的，那就是中国共产党。党受到批评时他会本能地发怒，强调公开批评党是不能容忍的','71624-71677',NULL,1668663459,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_71242-71288','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','但是他否认中国的问题是由社会主义造成的；在他看来，中共统治之前的封建历史和帝国主义才是成因。','71242-71288',NULL,1668663423,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_71114-71171','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','写作不能挑战以下四点：（1）社会主义道路；（2）无产阶级专政；（3）共产党的领导；（4）马克思列宁主义和毛泽东思想','71114-71171',NULL,1668663395,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_70528-70618','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','邓小平想要允许比毛时代更多的自由，但他也希望确立一些原则，明确划定哪一些政治言论可以接受，哪一些则不可接受。他对胡乔木、胡耀邦和其他讲话起草人说，要提出四项基本原则，说明自由的界限','70528-70618',NULL,1668663369,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_68308-68336','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','有些高层领导看过报告后批评说，会上的理论家们走得太远了。','68308-68336',NULL,1668663166,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_68375-68513','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','有些领导人甚至担心，赫鲁晓夫实行的非斯大林化政策削弱了党的权威，理论家们有可能步他的后尘。','68375-68513',NULL,1668663161,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_63321-63368','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','但是参加过理论工作务虚会公开讨论的干部都知道，胡耀邦个人认为允许更大的自由并不会威胁到社会秩序','63321-63368',NULL,1668660907,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_62420-62616','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','3月28日，北京市政府的干部根据正在发生变化的政治气候和邓小平本人的意见，发出规定宣佈：“禁止一切反对社会主义和无产阶级专政、反对党的领导和马克思列宁主义毛泽东思想的口号、大字报、书籍、杂志、图片等材料。”','62420-62616',NULL,1668660832,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_54319-54446','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','在邓小平看来，中国社会如此庞大，人口众多，百姓十分贫穷且相互对立严重，在行为方式上明显缺乏共识，所以必须有一定的自上而下的权威。自由的边界能够放得多宽，又不至于使中国社会陷入1949年以前或文革式的混乱？在整个邓小平时代，这一直是造成分歧的一个核心问题。','54319-54446',NULL,1668657563,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_53894-53931','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','文化大革命其实是一场“反文化的革命”，它攻击了旧文化，却并没有创造出新文化','53894-53931',NULL,1668657483,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_36388-36436','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','到1979年夏天，邓小平要收紧控制、创建更有效的统治架构，便开始逐步削弱华国锋并终于让他靠边站了','36388-36436',NULL,1668657189,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_35159-35199','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','而在三中全会成为头号领导人之后，他依旧是党的副主席、国务院副总理和中央军委副主席','35159-35199',NULL,1668657001,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_14_33550-33582','CB_4S997B96qGVz6al6YD',14,'第8章　为自由设限：1978–1979','虽然改革开放其实是由华国锋启动的，但它是在邓小平的领导下实现的。','33550-33582',NULL,1668656872,1782480565);
