INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_80265-80317','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','1978年中国所派出的最高级别的代表团，是当年春天组织的四个考察团，他们分别去了香港、东欧、日本和西欧。','80265-80317',NULL,1668596940,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_79464-79496','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','这一年里有13名副总理一级的干部出访约20次，共访问了50个国家','79464-79496',NULL,1668596721,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_63110-63265','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','马克思主义不是一成不变的思想体系，而是必须根据经验不断重新作出解释的。马克思主义的基本原理是理论与实践相结合。在某些情况下，对真理的认识有可能出错，但是如果经验表明它是错误的，就应当加以改正。这样一来新的经验和实践可以带来新的理论。如果马克思列宁主义和毛泽东思想的现有表述带有局限性或造成了灾难，也应当加以纠正','63110-63265',NULL,1668569201,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_63081-63109','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','这篇文章认为，评价真理的唯一方式是人民群众广泛的社会经验','63081-63109',NULL,1668569191,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_57212-57240','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','80年代的学生，用着70年代的教材，听60年代的老师上课','57212-57240',NULL,1668568757,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_55514-55553','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','从刘作出肯定回答的那一刻起，邓小平就下定了决心，无论如何要在1977年举行高考','55514-55553',NULL,1668514876,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_52076-52114','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','教育要狠狠地抓一下，一直抓它十年八年。我是要一直抓下去的。我的抓法就是抓头头','52076-52114',NULL,1668514568,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_46920-47034','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','再一次提出，学习毛主席的教导要有灵活性。他说，有人歪曲毛主席的思想，把一些话与当时的情况割裂开来，说它们同样适用于其他场合，但毛泽东对不同的情况是有不同的解决办法的，必须准确完整地理解毛泽东，把他的教导正确运用于每一种实际情况。','46920-47034',NULL,1668325498,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_46438-46508','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','但邓小平在全会上已正式恢复了他在1975年4月5日以前的全部职务：中央委员、政治局常委、党的副主席、中央军委副主席、副总理和解放军总参谋长。','46438-46508',NULL,1668325454,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_46384-46416','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','7月17日，十届三中全会通过了《关于恢复邓小平同志职务的决议》。','46384-46416',NULL,1668325441,1782480565);
