INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_41664-41802','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','他说，我们必须世世代代地用“准确的”、“完整的”毛泽东思想来指导我们全党、全军和全国人民。','41664-41802',NULL,1668324782,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_33998-34084','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','华国锋回国后，对中国能向南斯拉夫和罗马尼亚学习什么做了报告：这两个国家都接受外国货币，与外国公司开办合资企业，开展补偿贸易，引进外国技术——所有这一切丝毫没有损害两国的主权','33998-34084',NULL,1668239938,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_33176-33200','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','并于1977年8月12日至18日召开了党的十一大','33176-33200',NULL,1668239830,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_32725-32772','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','这篇社论宣佈，凡是毛主席作出的决策都要执行，凡是毛主席的指示都要照办，此即后来著名的“两个凡是','32725-32772',NULL,1668239795,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_28609-28647','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','是他——而不是邓小平——启动了中国的经济特区，并进行吸引外国直接投资的试验。','28609-28647',NULL,1668239304,1782480565);
