INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_12_27661-27696','CB_4S997B96qGVz6al6YD',12,'第6章　在华国锋时期复出：1977–1978','它得出结论说，华国锋是个“耳聪目明却平淡无奇的人，他的突出特点是谨慎。','27661-27696',NULL,1668239202,1782480565);
