INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_81289-81332','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','另一些大字报表示支持邓小平，还有人拉出一串小瓶子，因为汉语中的“小瓶”与“小平”谐音。','81289-81332',NULL,1668223991,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_77049-77089','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','也许对于毛泽东来说，最重要的是华国锋是文革的受益者，因此可以确信他不会否定文革。','77049-77089',NULL,1668223569,1782480565);
