INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_73229-73355','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','在那里，工人将骨灰送上一架飞机，从空中撒向他奉献了一生的中国大地。','73229-73355',NULL,1668222338,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_68998-69010','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','但是毛泽东没有出席追悼会','68998-69010',NULL,1668221922,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_68514-68553','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','试图借机抑制群众对周的怀念，对周一生的成就只给予了以党的标准而论尽可能低的评价','68514-68553',NULL,1668221884,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_50891-50935','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','他在1975年底对自己所支持的事拒不认错，使他在1977年复出时拥有了一个十分牢固的起点','50891-50935',NULL,1668221052,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_47167-47215','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','即使在漫长的会谈中也能始终对会谈内容保持高度专注，这正是邓小平面对压力时坚毅刚强的性格的一种体现','47167-47215',NULL,1668182830,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_44948-45034','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','他说，他在1975年初恢复工作时，一些工业部门的生产停滞不前，派性严重。为了解决派性问题，他首先抓了铁路，使问题很快得到解决。然后又以同样方式抓了钢铁工业，使生产有了增长。','44948-45034',NULL,1668182616,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_41225-41294','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','假如他能在毛泽东死后获得一定的统治权，他需要与阶级斗争划清界线，继续他的整顿政策，使那些在文革中受过迫害、视文革为一场灾难的人与他充分合作','41225-41294',NULL,1668181214,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_40963-41113','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','薄一波后来说，如果邓小平肯定文革，他就无法进行整顿，无法做到“实事求是”，也无法实行新的改革政策，解放人们的思想。','40963-41113',NULL,1668181177,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_10140-10262','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','但国家可以用“延期付款”的方式把外国的商品和资本引进中国。','10140-10262',NULL,1668045340,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_9183-9235','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','但在当时公开赞扬资本主义仍属禁忌，因为这将使中国多年来付出的牺牲的价值乃至中共是否应该继续执政受到质疑。','9183-9235',NULL,1668045176,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_10_5206-5291','CB_4S997B96qGVz6al6YD',10,'第4章　在毛泽东手下规划未来：1975','政研室比美国白宫的班子小得多，但除了不负责执行以外，它们的目的是相似的。它实际上就是一个核心内阁，是直接向邓小平负责的一批独立的顾问，可以帮他规划总体战略，起草政府公告。','5206-5291',NULL,1668014932,1782480565);
