INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_13054-13087','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','邓小平和新婚妻子张锡媛一起来到上海。他们两人是在苏联读书时的同学。','13054-13087',NULL,1667061079,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_12365-12428','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','即1927年1月12日，邓小平就和其他20名年轻的共产主义政治教导员一起，被共产国际派往当时驻扎在陕西黄河谷地的军阀冯玉祥那里','12365-12428',NULL,1667031183,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_11898-11966','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','他在1926年8月12日的课堂作业中写道：“集中的权力要自上而下地行使。服从上级命令是绝对必要的。允许多少民主，要视周围的环境变化而定。','11898-11966',NULL,1667031158,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_11437-11472','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','邓小平在苏联学习时，苏联还没有建成社会主义体制，仍在实行“新经济政策”','11437-11472',NULL,1667031098,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_10291-10323','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','大约300名学生被分成13个小组，邓小平被编入第7小组“理论组”','10291-10323',NULL,1667030943,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_8857-8913','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','“在法国，邓小平发现了西方、马克思主义、劳工世界、党的组织工作、中国的地位、社会和地区差别以及他的安身立命之本。','8857-8913',NULL,1667017349,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_8518-8695','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','1923年6月，中共宣佈加入孙中山领导的国民党，法国的中共党员也立刻宣佈他们会加入旅法的国民党。邓小平本人也加入了国民党，并在1925年成为国民党欧洲支部的领导人之一。','8518-8695',NULL,1667017324,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_7112-7128','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','想办法进了附近的夏狄戎学院念书。','7112-7128',NULL,1667017100,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_7019-7072','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','经过短暂的学徒期后，邓小平像其他工人一样成为计件工，于是他学会了抓紧干活，并工作很长时间，一周长达54小时','7019-7072',NULL,1667017093,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_7000-7009','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','工种是加工橡胶套鞋','7000-7009',NULL,1667017073,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_6777-6960','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','邓小平在施奈德军械厂时，被分派的工作是用大铁钳把烧红的大钢块从喷着火焰的鼓风炉里拖出来。邓小平当时还不到17岁，只有一米五的个头，他干了三周便离职而去，回到巴黎另寻工作。（他的堂叔在施奈德又干了一个多月。）几周后，邓小平在巴黎一家生产纸花的小工厂找到一份临时工，后来又在小镇夏莱特的哈金森橡胶厂（当时它雇用了大约1,000名工人，大多都是外国人）找到一份稳定的工作。','6777-6960',NULL,1667017063,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_6530-6688','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','1923年2月，邓小平参加了旅欧中国少年共产党临时代表大会，大会正式宣佈自己是“中国社会主义青年团”的一部分；周恩来当选为总书记。','6530-6688',NULL,1667017005,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_6418-6452','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','1922年在法国成立了一个组织，其成员称之为“旅欧中国少年共产党”。','6418-6452',NULL,1667016952,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_5459-5521','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','中国学生示威的一些领头人，如学生活动家蔡和森、后来担任了上海市长和外交部长的陈毅，因参加抗议而在1921年夏天被驱逐出法国。','5459-5521',NULL,1667016807,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_4760-4780','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','邓小平等19人被安排到诺曼第的巴耶中学。','4760-4780',NULL,1667016578,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_7_5186-5253','CB_4S997B96qGVz6al6YD',7,'第1章　革命者、建设者、改革者：1904–1969','邓小平和18位勤工俭学的同胞于3月13日离开巴耶，三周后他在南部城市克鲁梭的施奈德公司——法国最大的军械厂——找到一份勉强煳口的工作。','5186-5253',NULL,1667016567,1782480565);
