INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_7997-8053','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','他幼年接受儒家教育时就很优秀，学会了背诵大段的儒家经典。从事地下工作时他学会了不留下任何字迹，只把事情记在脑子里','7997-8053',NULL,1667012038,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_7433-7472','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','有人说，邓小平在经济方面没有多少经验，但经济活动一向就是党内多面手的重要职责。','7433-7472',NULL,1667011954,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_6930-6984','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','邓小平当了12年军队领导人，后来也时常自称军人。虽然他是政委而不是司令员，但他是党的书记，负责批准军事行动。','6930-6984',NULL,1667011890,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_6673-6733','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','毛把邓小平当作自己潜在的接班人之一，让邓小平参加政治局会议，并在1956年以后与其他五位国家最高官员一起参加政治局常委会','6673-6733',NULL,1667011795,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_6394-6436','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','在长征期间，邓小平参加了关键性的遵义会议，正是在这次会议上毛泽东作为领导人脱颖而出。','6394-6436',NULL,1667011749,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_6339-6393','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','当毛泽东开始在江西创建苏维埃根据地时，邓小平也去那里担任了瑞金县委书记，并学习到毛泽东是如何创建农村根据地的','6339-6393',NULL,1667011737,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_5920-5934','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','但他实际上变成了周恩来的徒弟','5920-5934',NULL,1667011653,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_5877-5920','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','他当时的工作是印刷向留法中国学生传播左派思想的宣传册，所以得了一个“油印博士”的绰号。','5877-5920',NULL,1667011643,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_5824-5876','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','在法国期间，邓小平放弃了工厂的工作，为周恩来——他比邓小平大六岁——领导下的那个小小的中共党支部干些杂活','5824-5876',NULL,1667011631,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_5624-5654','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','在苏联的一年使他得以观察第一个社会主义国家是如何应对现代化的','5624-5654',NULL,1667011581,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_4552-4574','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','早上起床后，他会在家里的花园快步绕行半小时。','4552-4574',NULL,1667011425,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_4238-4269','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','他经常打桥牌，就像他打牌时的表现一样，他只想把摸到手的牌打好。','4238-4269',NULL,1667011336,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_4173-4219','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','占美・卡特总统曾评论道，邓小平跟苏联领导人不一样，他有一种内在的自信，这使他能直奔实质问题。','4173-4219',NULL,1667011314,1782480565);
INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_2179-2238','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','政治体系控制到每家每户的做法搞过了头，造成了恐惧和主动精神的丧失；对经济体系的控制也搞过了头，导致的是失去活力的僵化。','2179-2238',NULL,1667011119,1782480565);
