INSERT INTO highlights VALUES('CB_4S997B96qGVz6al6YD_6_1302-1420','CB_4S997B96qGVz6al6YD',6,'导言　这个人和他的使命','“你如果觉得统治香港不容易，那就来统治中国试试。”','1302-1420',NULL,1667011034,1782480565);
