INSERT INTO highlights VALUES('3300039741_68_2187-2221','3300039741',68,'10.1　战略性资产配置','私募资产或私募股权投资是流动性最差的资产，通常很难或者根本无法出售。','2187-2221',5,1690966312,1782480563);
INSERT INTO highlights VALUES('3300039741_68_1310-1330','3300039741',68,'10.1　战略性资产配置','因此你无须进行交易来维持被动型市场配置。','1310-1330',5,1690966219,1782480563);
INSERT INTO highlights VALUES('3300039741_67_926-960','3300039741',67,'第三部分　资产配置和宏观投资策略','(2)基于当前市场观点对长期权重再配置，即战术性资产配置或市场择时。','926-960',5,1690962398,1782480563);
