INSERT INTO highlights VALUES('3300039741_61_6741-6804','3300039741',61,'8.5　尼克斯联合基金公司詹姆斯·查诺斯访谈录','过去25年中，几乎所有的重大金融舞弊案件都是内部告密者、记者或做空者揭露的，而不是外部审计师、外部法律顾问或者执法部门揭露的。','6741-6804',5,1690962258,1782480563);
INSERT INTO highlights VALUES('3300039741_61_5955-6021','3300039741',61,'8.5　尼克斯联合基金公司詹姆斯·查诺斯访谈录','部分原因是，大家对做空有很多误解。人们开始会想：你怎么可以售卖你并不拥有的东西呢？一旦有了这个想法，就会更难让人们在市场体系下理解它','5955-6021',5,1690962103,1782480563);
INSERT INTO highlights VALUES('3300039741_61_4526-4570','3300039741',61,'8.5　尼克斯联合基金公司詹姆斯·查诺斯访谈录','华尔街的存在是为了向人们出售股票。所以在任何时候你听到的大多数信息都是正面的，即买入建议','4526-4570',5,1690961938,1782480563);
INSERT INTO highlights VALUES('3300039741_61_1179-1210','3300039741',61,'8.5　尼克斯联合基金公司詹姆斯·查诺斯访谈录','我们不喜欢这样的商业模式，因为这会让级别低的分析师承担太多责任','1179-1210',5,1690804908,1782480563);
INSERT INTO highlights VALUES('3300039741_61_1066-1102','3300039741',61,'8.5　尼克斯联合基金公司詹姆斯·查诺斯访谈录','大多数对冲基金的研究方式是，基金经理处于顶端，而资历较浅的分析师处于底层','1066-1102',5,1690804895,1782480563);
INSERT INTO highlights VALUES('3300039741_60_2939-2976','3300039741',60,'8.4　案例分析：安然事件','我们判断，电力市场已经进入熊市阶段。这对安然公司来讲是“屋漏偏逢连夜雨”。','2939-2976',5,1690804821,1782480563);
INSERT INTO highlights VALUES('3300039741_60_2900-2938','3300039741',60,'8.4　案例分析：安然事件','不管风险对冲做得多完美，投资交易总是会在牛市中表现得更好，而在熊市中步履维艰','2900-2938',5,1690804810,1782480563);
INSERT INTO highlights VALUES('3300039741_60_911-975','3300039741',60,'8.4　案例分析：安然事件','“基于待售资产销售的预期利得”的会计核算方法允许公司预估当期交易在未来的盈利情况，并根据预估的盈利折算成现值，作为当期收益入账。','911-975',5,1690804546,1782480563);
INSERT INTO highlights VALUES('3300039741_58_2850-2880','3300039741',58,'8.2　卖空摩擦可能导致股价被高估','但是最终随着卖空需求被满足、股价回归基本面，融券费用也会回落','2850-2880',5,1690804179,1782480563);
INSERT INTO highlights VALUES('3300039741_58_2706-2749','3300039741',58,'8.2　卖空摩擦可能导致股价被高估','正是因为有融券收入的存在，在其他条件相同的情况下，股票持有人乐意付更高的价格买入股票。','2706-2749',5,1690804014,1782480563);
INSERT INTO highlights VALUES('3300039741_57_2777-2835','3300039741',57,'8.1　做空交易的运作流程及其困难','如果卖空者没有在股票被召回时如数归还股票，股票借出方就会执行强制买入，也就是前面所提到的用抵押资金从市场中购进股票。','2777-2835',5,1690803466,1782480563);
INSERT INTO highlights VALUES('3300039741_57_2696-2734','3300039741',57,'8.1　做空交易的运作流程及其困难','这时会出现股票借出方不愿意继续借出股票同时又很难找到其他股票借入渠道的风险，','2696-2734',5,1690803434,1782480563);
INSERT INTO highlights VALUES('3300039741_57_1900-1927','3300039741',57,'8.1　做空交易的运作流程及其困难','这只股票被另一投资者买入，并可能会接着出借，以此类推。','1900-1927',5,1690803260,1782480563);
INSERT INTO highlights VALUES('3300039741_57_1695-1743','3300039741',57,'8.1　做空交易的运作流程及其困难','融券费用通常接近于0，因为同一股票可以被重复出借多次，所以从理论上讲，可供出借的股票数量是无限的','1695-1743',5,1690803225,1782480563);
INSERT INTO highlights VALUES('3300039741_57_1791-1805','3300039741',57,'8.1　做空交易的运作流程及其困难','但在美国国库券市场常常会发生','1791-1805',5,1690803194,1782480563);
INSERT INTO highlights VALUES('3300039741_57_1441-1484','3300039741',57,'8.1　做空交易的运作流程及其困难','然而，美国市场上90%以上的股票融券费用都非常低，年化融券费用为0.10%~0.20%','1441-1484',5,1690803155,1782480563);
INSERT INTO highlights VALUES('3300039741_57_1410-1440','3300039741',57,'8.1　做空交易的运作流程及其困难','因此，卖空并不完全等同于做多的对立面，因为卖空还涉及融券费用','1410-1440',5,1690803147,1782480563);
INSERT INTO highlights VALUES('3300039741_57_1054-1057','3300039741',57,'8.1　做空交易的运作流程及其困难','保证金','1054-1057',5,1690803015,1782480563);
INSERT INTO highlights VALUES('3300039741_57_950-992','3300039741',57,'8.1　做空交易的运作流程及其困难','首先，当做空基金卖出IBM公司的股票时，它并没有拿到因卖出股票而获得的100美元现金','950-992',5,1690803001,1782480563);
INSERT INTO highlights VALUES('3300039741_56_634-743','3300039741',56,'第8章　专注股票做空策略','挖掘过分夸大盈利的公司、使用激进的会计方法的公司，或向美国证券交易委员会提交晦涩难懂的披露材料的公司。当他们发现这些公司有可能在掩盖什么信号时，就会更深入地挖掘事实真相，甚至会调查上市公司是否在明目张胆地进行欺诈活动。','634-743',5,1690367709,1782480563);
INSERT INTO highlights VALUES('3300039741_56_772-825','3300039741',56,'第8章　专注股票做空策略','除了做空有舞弊行为的公司股票外，专注股票做空策略的基金经理也会寻找那些诚实可信但商业计划存在先天缺陷的公司','772-825',5,1690367698,1782480563);
INSERT INTO highlights VALUES('3300039741_66_403-430','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','克利夫·阿斯尼斯是AQR公司的创始人之一和主管合伙人。','403-430',5,1690220426,1782480563);
INSERT INTO highlights VALUES('3300039741_6_18999-19017','3300039741',6,'导论','高盈利、经营稳定、成长性强和管理良好','18999-19017',0,1690214394,1782480563);
INSERT INTO highlights VALUES('3300039741_66_7906-7959','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','第三种原因可能是，当前我们正在做的有点像吃免费的午餐，利用了其他投资者的非理性或行为偏差导致的市场无效性。','7906-7959',0,1690208896,1782480563);
INSERT INTO highlights VALUES('3300039741_66_7485-7518','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','再次，我们也会检验投资理念是否符合经济学原理，而不仅仅看收益表现。','7485-7518',0,1690208833,1782480563);
INSERT INTO highlights VALUES('3300039741_66_7377-7415','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','其次，与主观型投资经理不同，我们一定会做检验，它必须经得起大量的样本外检验。','7377-7415',0,1690208777,1782480563);
INSERT INTO highlights VALUES('3300039741_66_7082-7141','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','坚守原则并不总是很容易，坚持一种投资策略是很难的。但人们放弃所选择的投资模型的时点好像总是在最差时机前后的一个半小时内','7082-7141',0,1690208722,1782480563);
INSERT INTO highlights VALUES('3300039741_66_5937-5973','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','虽然我们一直致力于完善我们的投资，但投资理念的核心20年来一直没有改变。','5937-5973',0,1690208474,1782480563);
INSERT INTO highlights VALUES('3300039741_66_5821-5887','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','我们会去寻找那些估值低且正在慢慢变好的股票，从学术角度看就是价值和动量投资，并且做空那些具有相反特征的、估值高且正在慢慢变糟的股票。','5821-5887',0,1690208444,1782480563);
INSERT INTO highlights VALUES('3300039741_66_2966-2990','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','其次，最大的调整就是你必须让人们相信你确实能行。','2966-2990',0,1690208125,1782480563);
INSERT INTO highlights VALUES('3300039741_66_1898-1934','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','即便如此，我也从未想过动量效应能有如此大的学术价值，我那时只是为了毕业。','1898-1934',0,1690207591,1782480563);
INSERT INTO highlights VALUES('3300039741_66_1223-1255','3300039741',66,'9.4　AQR公司克利夫·阿斯尼斯访谈录','在处理数据时，我发现的另一个现象是最近一个月的股价具有反转现象。','1223-1255',0,1690207512,1782480563);
