INSERT INTO highlights VALUES('3300039741_65_1691-1742','3300039741',65,'9.3　高频交易策略：足够高效又不完全有效的股票做市','因此，为了获得盈利，做市商就需要根据市场状况，不断做出调整。一旦有新的信息出现，他们必须立即调整报价。','1691-1742',0,1690206424,1782480563);
INSERT INTO highlights VALUES('3300039741_65_1519-1578','3300039741',65,'9.3　高频交易策略：足够高效又不完全有效的股票做市','实际上，卖盘压力大导致做市商成为净买入者的原因既可能是零散报价，也可能是均衡价格的确发生了变化，而做市商无法确定其原因','1519-1578',0,1690206395,1782480563);
INSERT INTO highlights VALUES('3300039741_65_1124-1164','3300039741',65,'9.3　高频交易策略：足够高效又不完全有效的股票做市','做市商将证券以库存形式持有，直到天然的买方出现，然后通过降低库存来满足买方的需求','1124-1164',0,1690206284,1782480563);
INSERT INTO highlights VALUES('3300039741_65_1059-1076','3300039741',65,'9.3　高频交易策略：足够高效又不完全有效的股票做市','做市商提供了一种服务，即流动性服务','1059-1076',0,1690206260,1782480563);
INSERT INTO highlights VALUES('3300039741_65_801-816','3300039741',65,'9.3　高频交易策略：足够高效又不完全有效的股票做市','大多数投资者并不会时刻关注市场','801-816',0,1690206211,1782480563);
INSERT INTO highlights VALUES('3300039741_65_409-589','3300039741',65,'9.3　高频交易策略：足够高效又不完全有效的股票做市','高频交易使用了很多不同的交易策略，有的提供流动性，有的则需要流动性。','409-589',0,1690206062,1782480563);
INSERT INTO highlights VALUES('3300039741_64_4327-4347','3300039741',64,'9.2　统计套利策略','但封闭式基金套利除外，它可能产生较大价差','4327-4347',0,1690206020,1782480563);
INSERT INTO highlights VALUES('3300039741_64_4053-4057','3300039741',64,'9.2　统计套利策略','残差反转','4053-4057',0,1690205881,1782480563);
INSERT INTO highlights VALUES('3300039741_64_3804-3877','3300039741',64,'9.2　统计套利策略','在这一策略中，统计套利交易者寻找高度相关的股票进行配对，识别股票价格出现分离的情形，并通过买入上涨滞后的股票、卖空上涨过快的股票来押注价差会收敛。','3804-3877',0,1690205777,1782480563);
INSERT INTO highlights VALUES('3300039741_64_2773-2800','3300039741',64,'9.2　统计套利策略','ADR与普通股价格非常接近，是因为这样的套利相对简单。','2773-2800',0,1690205637,1782480563);
INSERT INTO highlights VALUES('3300039741_64_2485-2528','3300039741',64,'9.2　统计套利策略','在孪生股票中，往往流动性差的那只股票价格更低，特别是当流动性溢价非常高的时候更是如此。','2485-2528',0,1690205568,1782480563);
INSERT INTO highlights VALUES('3300039741_63_13222-13274','3300039741',63,'9.1　基本面量化策略','因此，我们可以把股票收益率的统计分布看成两个不同分布的混合：基本面带来的冲击混合着流动性效应带来的冲击。','13222-13274',0,1690204815,1782480563);
INSERT INTO highlights VALUES('3300039741_63_13108-13170','3300039741',63,'9.1　基本面量化策略','实际上它表明这是一次流动性事件，而不是基于股票的基本面，也表明这种风险模型并没有考虑流动性风险，以及流动性旋涡内生的放大效应','13108-13170',0,1690204785,1782480563);
INSERT INTO highlights VALUES('3300039741_63_10766-10846','3300039741',63,'9.1　基本面量化策略','通常是买入按某一特征排名最靠前的10%的股票，并做空排名最靠后的10%的股票，依照此规则，每月对投资组合进行再平衡。这种策略的换手率很高，因此在实践中很少使用。','10766-10846',0,1690204459,1782480563);
INSERT INTO highlights VALUES('3300039741_63_10356-10384','3300039741',63,'9.1　基本面量化策略','剩下的风险就是与量化投资者想要押注的那些因子相关的风险。','10356-10384',0,1690204343,1782480563);
INSERT INTO highlights VALUES('3300039741_63_9140-9164','3300039741',63,'9.1　基本面量化策略','值得注意的是，低风险投资在美国的任一行业中都奏效','9140-9164',0,1690204094,1782480563);
INSERT INTO highlights VALUES('3300039741_63_4734-4769','3300039741',63,'9.1　基本面量化策略','一只价值特征和动量特征都非常好的股票，往往是正处于上升期的低估值的股票','4734-4769',0,1690203440,1782480563);
INSERT INTO highlights VALUES('3300039741_63_1277-1309','3300039741',63,'9.1　基本面量化策略','任何能够在理论上用来使价格标准化的变量，都可能让价值投资发挥作用','1277-1309',0,1690203037,1782480563);
INSERT INTO highlights VALUES('3300039741_63_725-783','3300039741',63,'9.1　基本面量化策略','多空股票对冲基金投资组合通常由多个因子构成，这些因子是一些投资于某种特定现象并以此现象来有规律地动态再平衡的投资组合','725-783',0,1690202847,1782480563);
INSERT INTO highlights VALUES('3300039741_63_7968-8003','3300039741',63,'9.1　基本面量化策略','而沃伦·巴菲特和杠杆收购投资者(LBO)一般会在更安全的股票上使用杠杆','7968-8003',5,1690199947,1782480563);
INSERT INTO highlights VALUES('3300039741_63_7769-7803','3300039741',63,'9.1　基本面量化策略','同时，这种选择也将减少对安全股票的需求，从而压低股价，提高预期收益率','7769-7803',5,1690199901,1782480563);
INSERT INTO highlights VALUES('3300039741_63_7500-7539','3300039741',63,'9.1　基本面量化策略','这种组合称为贝塔套利(betting-against-beta, BAB)因子','7500-7539',5,1690199789,1782480563);
INSERT INTO highlights VALUES('3300039741_63_7431-7500','3300039741',63,'9.1　基本面量化策略','通过对安全股票加杠杆、对高风险的股票去杠杆，让多头和空头双方资产组合的β值均为1。','7431-7500',5,1690199783,1782480563);
INSERT INTO highlights VALUES('3300039741_63_6891-6997','3300039741',63,'9.1　基本面量化策略','安全股票的收益率高于资本资产定价模型的预测结果，换句话说，安全股票有正的α，而风险高的股票有负的α。','6891-6997',5,1690199702,1782480563);
INSERT INTO highlights VALUES('3300039741_63_5372-5411','3300039741',63,'9.1　基本面量化策略','如果把价值投资和质量投资相结合，我们得到的新策略就是以合理价格买入高质量的股票','5372-5411',5,1690199550,1782480563);
INSERT INTO highlights VALUES('3300039741_63_5098-5166','3300039741',63,'9.1　基本面量化策略','平均而言，质量因子能够产生正的超额收益率。这不仅适用于美国股票，同样也适用于全球股票；不仅适用于市值低的股票，同样也适用于市值高的股票。','5098-5166',5,1690198512,1782480563);
INSERT INTO highlights VALUES('3300039741_63_4697-4734','3300039741',63,'9.1　基本面量化策略','由于两者负相关，组合策略的风险调整后，收益率会比两者中任意单一策略都更高。','4697-4734',5,1690198448,1782480563);
INSERT INTO highlights VALUES('3300039741_63_4663-4697','3300039741',63,'9.1　基本面量化策略','如果将动量投资策略和价值投资策略结合在一起，将会产生非常强大的组合。','4663-4697',5,1690198430,1782480563);
