INSERT INTO highlights VALUES('3300039741_36_2065-2105','3300039741',36,'5.5　交易策略或资产管理人的容积','因此，如果某只对冲基金想要扩大资产管理规模，它必须确保自身的专业水平也在持续提高','2065-2105',0,1689658843,1782480563);
