INSERT INTO highlights VALUES('3300039741_34_1052-1163','3300039741',34,'5.3　估算预期交易成本','如果要考虑很多股票（例如美国的股票市场），人们一般就不会独立估算每只股票的交易成本，而是假设交易成本将取决于波动性、日交易量(daily trading volume, DTV)、已发行股票数量及流通股数量之类的证券特征。','1052-1163',0,1689658079,1782480563);
INSERT INTO highlights VALUES('3300039741_34_964-980','3300039741',34,'5.3　估算预期交易成本','交易成本还取决于交易的规模大小。','964-980',0,1689658035,1782480563);
INSERT INTO highlights VALUES('3300039741_34_929-951','3300039741',34,'5.3　估算预期交易成本','交易量低的小盘股的交易成本往往要比大盘股更高','929-951',0,1689658029,1782480563);
