INSERT INTO highlights VALUES('3300039741_30_2105-2165','3300039741',30,'4.3　回撤管理','对于强手来说，他们拥有可以坚守仓位，甚至在低价格时还可以补仓的一切资源，雄厚的经济实力和坚毅的情感力量有助于他们渡过危机','2105-2165',0,1689655945,1782480563);
INSERT INTO highlights VALUES('3300039741_30_1919-1950','3300039741',30,'4.3　回撤管理','作为交易员，绝不要恐慌。但一旦恐慌，最好的方法就是第一个恐慌。','1919-1950',0,1689519456,1782480563);
INSERT INTO highlights VALUES('3300039741_30_1769-1821','3300039741',30,'4.3　回撤管理','当价格开始下跌时，基金经理往往坚持不卖出，但最终由于资金链断裂或者自身恐慌，不得不在接近底部的位置抛售。','1769-1821',0,1689519441,1782480563);
