INSERT INTO highlights VALUES('3300039741_29_2840-2888','3300039741',29,'4.2　风险管理','前瞻性风险管理有多种形式，包括分散化、风险限额、流动性管理以及通过期权和其他工具进行尾端对冲等。','2840-2888',0,1689519227,1782480563);
INSERT INTO highlights VALUES('3300039741_29_2058-2092','3300039741',29,'4.2　风险管理','通过设定不同的情景来模拟组合收益，然后考虑在这些情景中的最大损失金额','2058-2092',0,1689519150,1782480563);
INSERT INTO highlights VALUES('3300039741_29_2012-2031','3300039741',29,'4.2　风险管理','还有一种度量风险的方法是压力测试损失。','2012-2031',0,1689519142,1782480563);
INSERT INTO highlights VALUES('3300039741_29_1811-1857','3300039741',29,'4.2　风险管理','使用在险价值存在一个问题，就是如果实际亏损金额大于在险价值，在险价值就不再取决于实际亏损大小','1811-1857',0,1689519124,1782480563);
INSERT INTO highlights VALUES('3300039741_28_590-624','3300039741',28,'4.1　构建投资组合','第二个原则是仓位控制，即控制单只证券的市值敞口和（或）其风险贡献程度','590-624',0,1689517572,1782480563);
