INSERT INTO highlights VALUES('3300039741_25_4078-4121','3300039741',25,'3.3　如何回测检验投资策略','当然，避免样本内偏差最简单的方法就是找到一种足够简单且不需要依赖特定参数值的投资策略。','4078-4121',0,1689514778,1782480563);
