INSERT INTO highlights VALUES('3300039741_24_7201-7248','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','在这种情况下，并购套利型对冲基金就会买入一揽子并购标的股票，构建多元化投资组合，以提供流动性。','7201-7248',0,1689514161,1782480563);
INSERT INTO highlights VALUES('3300039741_24_7074-7121','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','需求压力产生的原因有许多。例如，许多事件驱动型对冲基金经理所利用的公司重大事件就与需求压力有关','7074-7121',0,1689514118,1782480563);
INSERT INTO highlights VALUES('3300039741_24_6378-6431','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','最后一种α的来源是对冲基金提供流动性以应对需求压力','6378-6431',0,1689513567,1782480563);
