INSERT INTO highlights VALUES('3300039741_24_4910-4949','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','买卖流动性差的证券是获取市场流动性风险溢价的一种方式，而做市业务是另一种方式。','4910-4949',0,1689513212,1782480563);
INSERT INTO highlights VALUES('3300039741_24_4363-4462','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','假如某只对冲基金因为流动性风险溢价的存在，可以低价买入证券，同时，交易频率不高，但方法先进，出现危机时，又可以避免被强制清盘，那么它将获得高收益。当然，这样做存在风险，这就是对冲基金得到补偿的原因。','4363-4462',0,1689513127,1782480563);
INSERT INTO highlights VALUES('3300039741_24_1860-1875','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','调整流动性后的资本资产定价模型','1860-1875',0,1689512836,1782480563);
INSERT INTO highlights VALUES('3300039741_24_1371-1419','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','投资者自然想对市场流动性风险收取补偿，因此流动性差的证券价格往往更便宜，可以获得的平均收益也更高','1371-1419',0,1689512723,1782480563);
INSERT INTO highlights VALUES('3300039741_24_862-902','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','然而，流动性风险不仅限制了套利，还直接影响了市场价格，因为它带来了流动性风险溢价','862-902',0,1689512599,1782480563);
INSERT INTO highlights VALUES('3300039741_24_800-833','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','流动性风险是套利的重要限制，它制约了交易者修正市场错误定价的能力。','800-833',0,1689512574,1782480563);
INSERT INTO highlights VALUES('3300039741_24_586-680','3300039741',24,'3.2　对流动性风险足够高效又不完全有效的补偿','我们想知道的是，对冲基金如何赚取作为风险补偿的α收益，尤其是对流动性风险等的风险补偿，而并不单单是赚取承受市场风险敞口的那部分收益。','586-680',0,1689512513,1782480563);
INSERT INTO highlights VALUES('3300039741_23_2339-2414','3300039741',23,'3.1　价格足够有效，但又无法完全有效地反映信息','对冲基金可能会尝试去“拥抱”泡沫而非对着干，正如互联网泡沫期间索罗斯所做的那样，尤其是当对冲基金认为其他资深的投资者不急于修正错误定价和戳破泡沫的时候','2339-2414',0,1689509137,1782480563);
INSERT INTO highlights VALUES('3300039741_23_1921-1952','3300039741',23,'3.1　价格足够有效，但又无法完全有效地反映信息','现实世界中所有套利交易都有风险，所以套利只能发生在有限的范围内','1921-1952',0,1689509045,1782480563);
INSERT INTO highlights VALUES('3300039741_21_754-794','3300039741',21,'2.9　历史回测与业绩记录','事实上，对冲基金也许要先确定一种策略是否有价值，为此它们将检视总收益是否确定为正','754-794',0,1689508676,1782480563);
INSERT INTO highlights VALUES('3300039741_19_1507-1556','3300039741',19,'2.7　调整流动性和滞后价格对业绩的影响','许多对冲基金投资于低流动性的证券，这些证券往往在很多个交易日都没有任何交易，因此月末的价格可能滞后','1507-1556',0,1689508324,1782480563);
INSERT INTO highlights VALUES('3300039741_16_3054-3082','3300039741',16,'2.4　时间维度和计算年化收益率','即使是这么好的策略，每分钟查看，损失的概率也接近50%。','3054-3082',0,1689508106,1782480563);
INSERT INTO highlights VALUES('3300039741_16_3094-3137','3300039741',16,'2.4　时间维度和计算年化收益率','只要你盯盘的周期是以分钟为频率的，很可能每隔一分钟就看到亏损。无怪乎它让人感到很痛苦。','3094-3137',0,1689508082,1782480563);
INSERT INTO highlights VALUES('3300039741_16_2073-2074','3300039741',16,'2.4　时间维度和计算年化收益率','[插图]','2073-2074',0,1689507745,1782480563);
INSERT INTO highlights VALUES('3300039741_15_991-1069','3300039741',15,'2.3　衡量投资业绩','而从统计角度来看，算术平均收益率往往是最优的估计方法，这一方法更贴近客户的投资经验，因为在特定情形下，他们往往为了保持对冲基金中的固定投资额而追加和赎回资金','991-1069',0,1689507585,1782480563);
INSERT INTO highlights VALUES('3300039741_14_5717-5765','3300039741',14,'2.2　风险回报比率','而索提诺比率(S)则使用下行风险作为分母','5717-5765',0,1689507412,1782480563);
INSERT INTO highlights VALUES('3300039741_14_5667-5692','3300039741',14,'2.2　风险回报比率','经济资本可以使用在险价值(VaR)或压力测试来估计','5667-5692',0,1689507406,1782480563);
INSERT INTO highlights VALUES('3300039741_14_5331-5383','3300039741',14,'2.2　风险回报比率','为了准确描述崩盘风险，有必要对回报风险比率的分母进行修正，比如使用风险调整后的资本收益率(RAROC)。','5331-5383',0,1689507391,1782480563);
INSERT INTO highlights VALUES('3300039741_14_4460-4496','3300039741',14,'2.2　风险回报比率','这一比率背后的理念是计算一种市场中性策略最大限度地使用杠杆所能获得的收益','4460-4496',0,1689507241,1782480563);
INSERT INTO highlights VALUES('3300039741_14_1519-1768','3300039741',14,'2.2　风险回报比率','但是，当对冲基金的收益率服从偏态分布￼和存在崩盘风险时，投资者的真实偏好可能要比我们用夏普比率描述的复杂得多','1519-1768',0,1689506423,1782480563);
INSERT INTO highlights VALUES('3300039741_14_530-655','3300039741',14,'2.2　风险回报比率','首先，虽然α可以说明一种投资策略与市场不相关的收益规模，但它并不能指明这种投资策略面临的风险有多高；其次，α取决于投资策略使用的杠杆大小。','530-655',0,1689506377,1782480563);
INSERT INTO highlights VALUES('3300039741_13_4619-4783','3300039741',13,'2.1　阿尔法和贝塔','式中，RHMLt是基于价值策略的收益率；RSMBt是基于规模策略的收益率','4619-4783',0,1689506310,1782480563);
INSERT INTO highlights VALUES('3300039741_13_4027-4127','3300039741',13,'2.1　阿尔法和贝塔','具体来说，超过2的t统计值意味着α在统计上显著大于0，这可以证明基金经理有高超的投资能力','4027-4127',0,1689506273,1782480563);
INSERT INTO highlights VALUES('3300039741_13_3435-3644','3300039741',13,'2.1　阿尔法和贝塔','经典的资本资产定价模型指出，任何证券或任何投资组合的预期收益率仅仅是由系统性风险（即β）决定的。换句话说，资本资产定价模型预测任何投资策略的α值都等于零。因此，对冲基金积极地寻找α，试图获得比系统性风险溢价更高的回报，这是在公然挑战资本资产定价模型。','3435-3644',0,1689506231,1782480563);
INSERT INTO highlights VALUES('3300039741_13_3044-3083','3300039741',13,'2.1　阿尔法和贝塔','α是整个回归公式中最显眼的一项，是所有主动型基金经理所追求的目标','3044-3083',0,1689506171,1782480563);
INSERT INTO highlights VALUES('3300039741_13_2186-2233','3300039741',13,'2.1　阿尔法和贝塔','从数学角度讲，市场中性意味着β值为零。','2186-2233',0,1689506089,1782480563);
INSERT INTO highlights VALUES('3300039741_13_1608-1697','3300039741',13,'2.1　阿尔法和贝塔','更广泛地说，投资的业绩表现同样取决于你承担的非系统风险，这里用εt来衡量','1608-1697',0,1689506034,1782480563);
INSERT INTO highlights VALUES('3300039741_11_892-898','3300039741',11,'1.4　对冲基金在经济中的角色','提供了流动性','892-898',0,1689505943,1782480563);
INSERT INTO highlights VALUES('3300039741_11_583-623','3300039741',11,'1.4　对冲基金在经济中的角色','首先，对冲基金收集公司信息，并通过交易让价格反映这些信息，从而使市场变得更加有效','583-623',0,1689505900,1782480563);
INSERT INTO highlights VALUES('3300039741_10_1589-1602','3300039741',10,'1.3　对冲基金的组织结构','基金经理自身往往也是投资者','1589-1602',0,1689505745,1782480563);
INSERT INTO highlights VALUES('3300039741_10_1416-1464','3300039741',10,'1.3　对冲基金的组织结构','主基金与基金管理公司签有投资管理协议，后者为主基金提供投资服务，涵盖策略开发、执行和具体交易活动','1416-1464',0,1689505710,1782480563);
INSERT INTO highlights VALUES('3300039741_9_1992-2017','3300039741',9,'1.2　业绩表现','事实上，对冲基金——特别是小型对冲基金的淘汰率很高','1992-2017',0,1689505449,1782480563);
INSERT INTO highlights VALUES('3300039741_9_1890-1911','3300039741',9,'1.2　业绩表现','此外，对冲基金的平均收益根本达不到市场中性','1890-1911',0,1689505421,1782480563);
INSERT INTO highlights VALUES('3300039741_9_767-814','3300039741',9,'1.2　业绩表现','其一，当对冲基金主动对外披露业绩的时候，其往往把历史业绩情况一同报告，因此数据库会出现回填现象','767-814',0,1689505307,1782480563);
INSERT INTO highlights VALUES('3300039741_9_540-579','3300039741',9,'1.2　业绩表现','原因在于对冲基金收益率的数据质量很差，往往样本期很短，而且存在一些显著的偏差。','540-579',0,1689505243,1782480563);
INSERT INTO highlights VALUES('3300039741_8_2478-2482','3300039741',8,'1.1　业绩目标和费用','双层失效','2478-2482',0,1689505220,1782480563);
INSERT INTO highlights VALUES('3300039741_8_1592-1611','3300039741',8,'1.1　业绩目标和费用','只有在业绩达到新高的时候才提取业绩提成','1592-1611',0,1689505042,1782480563);
INSERT INTO highlights VALUES('3300039741_8_1421-1440','3300039741',8,'1.1　业绩目标和费用','通常业绩提成并不取决于基金能否跑赢大盘','1421-1440',0,1689505004,1782480563);
INSERT INTO highlights VALUES('3300039741_8_858-901','3300039741',8,'1.1　业绩目标和费用','共同基金是根据其管理的规模收取固定比例的管理费用，而对冲基金通常还要另外收取业绩提成。','858-901',0,1689504951,1782480563);
INSERT INTO highlights VALUES('3300039741_8_474-521','3300039741',8,'1.1　业绩目标和费用','对冲基金不是在尝试打败市场，而是要争取在任何市场环境下都能盈利——这就是使用“对冲”一词的原因','474-521',0,1689504863,1782480563);
INSERT INTO highlights VALUES('3300039741_7_2142-2339','3300039741',7,'第一部分　主动型投资','在高效运行的无效市场中，投入对冲基金的资金总量不可能始终不断地增长。假定流动性需求有限，那么市场上存在的获利空间也是有限的，对于主动型投资的需求也必然是有限的。','2142-2339',0,1689504832,1782480563);
INSERT INTO highlights VALUES('3300039741_7_1478-1484','3300039741',7,'第一部分　主动型投资','禁止公开推介','1478-1484',0,1689504744,1782480563);
INSERT INTO highlights VALUES('3300039741_7_1315-1461','3300039741',7,'第一部分　主动型投资','在自由度方面，对冲基金可以使用杠杆、卖空、投资衍生品，还可以收取业绩提成；而在约束方面，对冲基金的投资者必须是“合格投资者”，即投资者需要有一定的财力基础和（或）金融专业知识才可以投资（这是为了保护资产比较少、相对不太专业的投资者，让其远离自己可能无法理解的复杂对冲基金策略和无法承受的风险）','1315-1461',0,1689504714,1782480563);
INSERT INTO highlights VALUES('3300039741_7_781-811','3300039741',7,'第一部分　主动型投资','简单地说，对冲基金是追求用各种复杂的交易策略来盈利的投资工具','781-811',0,1689504624,1782480563);
INSERT INTO highlights VALUES('3300039741_7_497-574','3300039741',7,'第一部分　主动型投资','这些投资者包括庞大且复杂的有内部交易业务的养老基金、捐赠基金、交易商、投资银行的自营交易部、大宗商品生产企业的交易部门、共同基金、自营交易公司和对冲基金。','497-574',0,1689504585,1782480563);
INSERT INTO highlights VALUES('3300039741_6_18974-18995','3300039741',6,'导论','质量投资是指购买质量优良的证券的投资风格，','18974-18995',0,1689504526,1782480563);
INSERT INTO highlights VALUES('3300039741_6_18732-18760','3300039741',6,'导论','低风险投资是指获得安全证券在风险调整后的高收益的投资风格','18732-18760',0,1689504490,1782480563);
INSERT INTO highlights VALUES('3300039741_6_18823-18858','3300039741',6,'导论','也称为反β策略','18823-18858',0,1689504480,1782480563);
INSERT INTO highlights VALUES('3300039741_6_17363-17429','3300039741',6,'导论','在他眼中，价值投资和动量投资策略是放之四海而皆准的，对于任何资产种类，都要购买处于上升趋势的廉价资产，同时做空处于下降趋势的昂贵资产','17363-17429',0,1689497655,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16624-16658','3300039741',6,'导论','在公司重大事件中，与并购相反的是企业分拆或裂股，即一家公司变成两家。','16624-16658',0,1689497544,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16727-16767','3300039741',6,'导论','这种在由同一家公司发行的不同证券的相对价值之间进行套利的策略，也称为资本结构套利','16727-16767',0,1689497513,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16488-16529','3300039741',6,'导论','这种价差反映了并购失败风险的存在，但也反映了很多投资者在消息公布后不久就出售了股份','16488-16529',0,1689497466,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16405-16453','3300039741',6,'导论','在企业并购活动中，收购方对并购目标发出的要约股价通常会高于当时的市价，激励持有人出售他们的股票。','16405-16453',0,1689497445,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16356-16384','3300039741',6,'导论','事件驱动型对冲基金努力挖掘企业重大事件中潜在的投资机会。','16356-16384',0,1689497408,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16202-16324','3300039741',6,'导论','可转换债券的市场价格往往低于其理论价值，这是因为要在短时间内快速变现可转换债券可能会比较困难，所以持有人要求为内含的流动性风险获得补偿。可转换债券套利包括购买便宜的可转换债券，并通过做空标的公司的股票来对冲风险，此外还可能会使用额外的对冲手段。','16202-16324',0,1689497325,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16145-16166','3300039741',6,'导论','普通公司债券和对公司股票的看涨期权的组合。','16145-16166',0,1689497296,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16106-16135','3300039741',6,'导论','可转换债券是指可以按预先约定的转股比例转化为股票的公司债券','16106-16135',0,1689497201,1782480563);
INSERT INTO highlights VALUES('3300039741_6_16087-16106','3300039741',6,'导论','另一种经典的套利交易是可转换债券套利。','16087-16106',0,1689496984,1782480563);
INSERT INTO highlights VALUES('3300039741_6_15753-15799','3300039741',6,'导论','由于固定收益证券通常都有确切的到期日，价格趋同最终必然发生，但其发生得越早，交易就越有利可图','15753-15799',0,1689496912,1782480563);
INSERT INTO highlights VALUES('3300039741_6_15676-15752','3300039741',6,'导论','固定收益套利建立在若干所谓趋同交易的基础之上。在趋同交易中，找出价格不同的相似证券，然后买进价格较低者，卖出价格较高者，并希望从两者价格之间的趋同中获利','15676-15752',0,1689496566,1782480563);
INSERT INTO highlights VALUES('3300039741_6_15613-15675','3300039741',6,'导论','套利策略(arbitrage strategies)大致可以分为固定收益套利策略、可转换债券套利策略和事件驱动型投资策略三类','15613-15675',0,1689496000,1782480563);
INSERT INTO highlights VALUES('3300039741_6_15433-15451','3300039741',6,'导论','风险管理是管理期货投资基金经理的根本','15433-15451',0,1689495948,1782480563);
INSERT INTO highlights VALUES('3300039741_6_15097-15162','3300039741',6,'导论','管理期货对冲基金专注于对价格数据的分析，或者采用统计方法（管理期货量化策略），或者使用经验规则（技术分析流派），而很少看基本面数据','15097-15162',0,1689495877,1782480563);
INSERT INTO highlights VALUES('3300039741_6_14913-14972','3300039741',6,'导论','管理期货投资基金经理往往将目光集中在寻找价格变化的趋势上，购买价格呈上升趋势的投资品种，卖空价格呈下降趋势的投资品种。','14913-14972',0,1689495839,1782480563);
INSERT INTO highlights VALUES('3300039741_6_15213-15232','3300039741',6,'导论','其原理是趋势始于人们对新闻的反应不足。','15213-15232',0,1689494871,1782480563);
INSERT INTO highlights VALUES('3300039741_6_14844-14913','3300039741',6,'导论','管理期货投资者（又称商品交易顾问，CTA）的很多投资标的与全球宏观投资策略的投资标的相同，包括债券期货、股票指数期货、货币远期和商品期货。','14844-14913',0,1689494689,1782480563);
INSERT INTO highlights VALUES('3300039741_6_14713-14746','3300039741',6,'导论','货币套息交易主要是指投资于较高利率的货币，同时做空较低利率的货币。','14713-14746',0,1689494605,1782480563);
INSERT INTO highlights VALUES('3300039741_6_12324-12500','3300039741',6,'导论','有些量化投资者专注于高频交易，他们会在买入后的几毫秒或几分钟内就立即卖出；有些专注于统计套利，即每天根据股票的统计特征来交易；还有些则专注于频率更低的交易，即所谓的基本面量化投资（或股票市场中性投资）。基本面量化投资会考虑很多与主观型投资相同的投资因素，比如试图买入便宜的股票、卖空昂贵的股票，但不同的是，基本面量化投资是借助计算机系统来系统化实现的。','12324-12500',0,1689494297,1782480563);
INSERT INTO highlights VALUES('3300039741_6_12965-13022','3300039741',6,'导论','量化投资还具有另外两个优势：可以高效地构建投资组合和进行历史回测，这意味着我们可以模拟某个策略过往的投资业绩表现。','12965-13022',0,1689494272,1782480563);
INSERT INTO highlights VALUES('3300039741_6_13690-13762','3300039741',6,'导论','全球宏观投资基金经理会押注世界各国经济领域的现象，比如股市整体趋势是上涨还是下跌，通货膨胀是否会使黄金价格暴涨，或者新兴市场货币将会升值还是贬值','13690-13762',0,1689494120,1782480563);
INSERT INTO highlights VALUES('3300039741_6_13641-13690','3300039741',6,'导论','我把宏观投资策略(macro strategies)划分为两类，即全球宏观投资策略和管理期货策略。','13641-13690',0,1689494114,1782480563);
INSERT INTO highlights VALUES('3300039741_6_13621-13640','3300039741',6,'导论','他们利用期货市场押注橙汁价格的变化方向','13621-13640',0,1689494107,1782480563);
INSERT INTO highlights VALUES('3300039741_6_12586-12649','3300039741',6,'导论','但这种投资是劳动密集型的，投入的精力多、耗时长，这意味着只能对有限数量的证券做深度研究，并且主观决策容易受投资者的心理偏差影响','12586-12649',0,1689493935,1782480563);
INSERT INTO highlights VALUES('3300039741_6_11961-11998','3300039741',6,'导论','量化基金经理会明确定义他们的交易规则，并建立技术系统来系统化地执行其策略。','11961-11998',0,1689493811,1782480563);
INSERT INTO highlights VALUES('3300039741_6_11708-11760','3300039741',6,'导论','由于股市上涨的概率比下跌的概率高（称为股票风险溢价），专注股票做空的基金经理往往在和市场的上升大势做斗争','11708-11760',0,1689493748,1782480563);
INSERT INTO highlights VALUES('3300039741_6_11004-11104','3300039741',6,'导论',unistr('更普遍的情况是，这种机会主义交易者试图在消息广为知晓之前建仓，当信息被披露并反映到价格中的时候就清仓。这种操作的座右铭是：\u000a买消息，卖事实。'),'11004-11104',0,1689493559,1782480563);
INSERT INTO highlights VALUES('3300039741_6_10920-10938','3300039741',6,'导论','另一种方法是尝试挖掘相对更短期的机会','10920-10938',0,1689493533,1782480563);
INSERT INTO highlights VALUES('3300039741_6_10616-10646','3300039741',6,'导论','虽然主观型基金经理往往投资于个股，但是他们也可以进行行业投资','10616-10646',0,1689493475,1782480563);
INSERT INTO highlights VALUES('3300039741_6_10474-10540','3300039741',6,'导论','主观型股票投资策略是相机开展多头或者空头操作，通常建立在对公司价值的基本面分析的基础上，包括比较公司的盈利与估值，分析公司的成长前景','10474-10540',0,1689493442,1782480563);
INSERT INTO highlights VALUES('3300039741_6_10676-10716','3300039741',6,'导论','一些基金经理（又称为价值投资者）重点关注购买价值被低估的公司，并长期持有这些股票','10676-10716',0,1689493386,1782480563);
INSERT INTO highlights VALUES('3300039741_6_9702-9738','3300039741',6,'导论','在广义层面上，我把对冲基金策略分为股票投资策略、宏观投资策略和套利策略。','9702-9738',0,1689493081,1782480563);
INSERT INTO highlights VALUES('3300039741_6_9585-9604','3300039741',6,'导论','不过，这种差异远比我们想象的要小得多。','9585-9604',0,1689493042,1782480563);
INSERT INTO highlights VALUES('3300039741_6_9450-9492','3300039741',6,'导论','由于对冲基金往往是受约束最少和最为老练的专业投资者，因此本书专注于分析对冲基金的策略','9450-9492',0,1689492999,1782480563);
INSERT INTO highlights VALUES('3300039741_6_8658-8693','3300039741',6,'导论','表0-4　新古典经济金融学原理和高效运行的无效市场中的经济金融理论对比','8658-8693',0,1689492787,1782480563);
INSERT INTO highlights VALUES('3300039741_6_7626-7689','3300039741',6,'导论','事实上，资产收益率并不像资本资产定价模型(CAPM)所说的那样只受市场风险的影响，在实践中还受到市场和融资需求的流动性风险影响','7626-7689',0,1689492257,1782480563);
INSERT INTO highlights VALUES('3300039741_6_7502-7509','3300039741',6,'导论','两基金分离定理','7502-7509',0,1689492220,1782480563);
INSERT INTO highlights VALUES('3300039741_6_5852-5964','3300039741',6,'导论','基金经理会因为提供流动性得到补偿。虽然他们的激烈竞争可能导致补偿接近于零，但竞争并不会将流动性的价格压低为零，因为这些交易始终包含着流动性风险。流动性风险是一个重要的概念，它意味着被迫在最坏时点以高额交易成本抛售证券的风险。','5852-5964',0,1689491603,1782480563);
INSERT INTO highlights VALUES('3300039741_6_4979-5014','3300039741',6,'导论','我这样明确定义市场，即事实上市场是一个处于相对高效运行状态的无效市场。','4979-5014',0,1687775032,1782480563);
INSERT INTO highlights VALUES('3300039741_6_4141-4198','3300039741',6,'导论','如果市场完全有效，主动型投资者就不会存在，因为价格不再具有任何投资指示意义，已经反映了你所期望收集的尽可能多的信息','4141-4198',0,1687774926,1782480563);
INSERT INTO highlights VALUES('3300039741_6_1588-1594','3300039741',6,'导论','乔治·索罗斯','1588-1594',0,1687754929,1782480563);
INSERT INTO highlights VALUES('3300039741_6_1492-1557','3300039741',6,'导论','量化行业先锋人物克利夫·阿斯尼斯介绍了如何借助计算机模型同时交易成千上万只证券，以及如何把他的学术成果——动量效应应用到现实世界中','1492-1557',0,1687754908,1782480563);
INSERT INTO highlights VALUES('3300039741_6_1427-1474','3300039741',6,'导论','著名的卖空投资人詹姆斯·查诺斯解释了他如何做空商业计划存在瑕疵和存在管理层欺诈问题的公司的股票','1427-1474',0,1687754896,1782480563);
INSERT INTO highlights VALUES('3300039741_6_1367-1426','3300039741',6,'导论','明星基金经理李·安斯利三世在为老虎基金传奇人物朱利安·罗伯逊(Julian Robertson)工作时磨炼出的选股方法','1367-1426',0,1687754886,1782480563);
INSERT INTO highlights VALUES('3300022098_46_715-942','3300022098',46,'关于作者',unistr('史蒂夫的人生使命：\u000a清醒自主、充满勇气地生活；\u000a享受，增益，分享平静、能量、热情与富足；\u000a与爱和悲悯之心共鸣；\u000a唤醒他人内在的伟大灵魂；\u000a全然拥抱当下时刻'),'715-942',5,1708738932,1782480561);
INSERT INTO highlights VALUES('3300022098_44_782-865','3300022098',44,'后记','保持开放，去探索生活的真相。勇敢接纳你发现的真相，还有随之而来的结果。摒弃虚假、否认和恐惧。让真相成为你的朋友，而不是敌人。这并不容易，却是正确的选择。','782-865',5,1708738795,1782480561);
INSERT INTO highlights VALUES('3300022098_43_7529-7571','3300022098',43,'第13章 心灵','我可以在不同场景下自由选择不同的滤镜，唯一的依据就是：它是否让我在当下时刻更有能量。','7529-7571',5,1708737499,1782480561);
INSERT INTO highlights VALUES('3300022098_43_6999-7042','3300022098',43,'第13章 心灵','实际上，更合理的问法应该是“你理解基督教的视角吗”，而不是试图用这种信仰来定义你这个人','6999-7042',5,1708737431,1782480561);
INSERT INTO highlights VALUES('3300022098_43_6574-6621','3300022098',43,'第13章 心灵','正如真实原则告诉我们的，信念体系只是滤镜，你通过滤镜来感知现实，但每个滤镜都只揭示了一部分现实','6574-6621',5,1708737384,1782480561);
INSERT INTO highlights VALUES('3300022098_43_6309-6342','3300022098',43,'第13章 心灵','你能做出的最有能量的人生选择之一，是把你持有的信念和你自己区分开来','6309-6342',3,1708737349,1782480561);
INSERT INTO highlights VALUES('3300022098_43_6387-6439','3300022098',43,'第13章 心灵','僵固不变的信念体系只会限制你的成长，就好像让你永远闭着一只眼睛看东西，结果让自己的视觉能力难以充分发挥。','6387-6439',0,1708737328,1782480561);
INSERT INTO highlights VALUES('3300022098_43_6191-6221','3300022098',43,'第13章 心灵','我能给你的最好建议，就是请遵从你的本心，看看它到底指向何方。','6191-6221',0,1708737303,1782480561);
INSERT INTO highlights VALUES('3300022098_43_5990-6028','3300022098',43,'第13章 心灵','我现在可以坦诚分享自己的过往，一个重要的原因是，我知道不坦诚是什么样的感觉。','5990-6028',0,1708737285,1782480561);
INSERT INTO highlights VALUES('3300022098_43_5895-5950','3300022098',43,'第13章 心灵','有时候我们可能会走入歧途，偏离真实、爱与能量这些基础原则，但长期来看，这种偏离也可以让我们学会更好地保持正轨。','5895-5950',0,1708737276,1782480561);
INSERT INTO highlights VALUES('3300022098_43_4824-4937','3300022098',43,'第13章 心灵','内观与冥想都是强有力的修行方法，可以帮我们向内联结，但最好的选择其实是同时向外进行丰富的探索。我们可以让自己的心灵从内外两个方向精进。有些时候，你能从沉静中找到答案；有些时候，你则需要从交流中获得启发。请对两种方法都保持接纳。','4824-4937',0,1708737185,1782480561);
INSERT INTO highlights VALUES('3300022098_43_4491-4559','3300022098',43,'第13章 心灵','学会从不同的视角看待现实，你能够突破很多单一信念体系的局限，逐渐把错误信念从自己的信念体系中移除，填补自己的认知空缺，最终活得更加真实。','4491-4559',0,1708737113,1782480561);
INSERT INTO highlights VALUES('3300022098_43_3819-3871','3300022098',43,'第13章 心灵','学会探索不同的信念体系，用不同的视角进行思考，这让我们拥有不同的滤镜，然后将它们放进自己的认知工具盒里。','3819-3871',0,1708737044,1782480561);
INSERT INTO highlights VALUES('3300022098_43_3523-3599','3300022098',43,'第13章 心灵','然而，其中任何一个都不是全部的真相。你实际上感知不到现实世界最原本的样子，因为原始信息的数量超出你的认知能力。你能接收的，是经过高度加工之后的那个结果。','3523-3599',0,1708737017,1782480561);
INSERT INTO highlights VALUES('3300022098_43_1681-1744','3300022098',43,'第13章 心灵','视觉立体化是我们人类最神奇的能力之一。我们的眼球捕捉到的其实是二维画面，而大脑和视神经则能快速地把这些二维信号转化成三维画面。','1681-1744',0,1708736735,1782480561);
INSERT INTO highlights VALUES('3300022098_43_1352-1459','3300022098',43,'第13章 心灵','一个有效的办法是，学会用不同的信念体系来审视现实世界，从而看到最全面的图景。你的信念体系就像滤镜一样，引导你看见现实的不同方面。穆斯林、佛教徒和不可知论者，他们看到的世界可能是不同的，然而其中一定也有某些重合的部分','1352-1459',0,1708736689,1782480561);
INSERT INTO highlights VALUES('3300022098_43_516-580','3300022098',43,'第13章 心灵','在这一章，“心灵”这个词指的是你对于现实世界信念的集合，包括你怎样理解现实世界的运行，以及怎样理解自己在这个世界中所扮演的角色。','516-580',5,1708701428,1782480561);
INSERT INTO highlights VALUES('3300022098_43_1096-1135','3300022098',43,'第13章 心灵','我的目的不是要说服你相信某种观点，而是帮你把清醒意识带入自己当下的信念体系中。','1096-1135',5,1708701419,1782480561);
INSERT INTO highlights VALUES('3300022098_42_15605-15635','3300022098',42,'第12章 关系','如果你犯下了错误，请学会原谅自己，也原谅他人。生活还要继续。','15605-15635',0,1708698216,1782480561);
INSERT INTO highlights VALUES('3300022098_42_8245-8342','3300022098',42,'第12章 关系','给他人带来能量的最好方式，就是让自己充满能量。只有当你自己能量满满的时候，才能真正支持到他人。相反，如果你自己很脆弱，那根本没法帮助他人。如果想让世界大躯体变强，每一个小细胞就要学会照顾好自己。','8245-8342',0,1708698215,1782480561);
INSERT INTO highlights VALUES('3300022098_42_14947-15023','3300022098',42,'第12章 关系','如果想吸引更多新联结进入你的生活，你能做出的最好选择，就是专注于向这个世界表达自我。通过真实地表达自我，你会吸引到更多的人，从而更容易建立起同频的联结。','14947-15023',0,1708698215,1782480561);
INSERT INTO highlights VALUES('3300022098_42_7349-7473','3300022098',42,'第12章 关系','对于交友，我最看重的一点就是：对方是不是主动成长的人。我经常会被主动成长的人吸引，彼此很容易就能建立联结。我并不在乎他们的客观条件，比如年龄大小、信仰、富有或者窘迫。我们对于个人成长的兴趣会变成友谊的共同支点，而彼此之间的差异又能让对方学到新东西。','7349-7473',0,1708698215,1782480561);
INSERT INTO highlights VALUES('3300022098_42_7953-8033','3300022098',42,'第12章 关系','一个经验是：如果你发现自己陷在了持续消耗能量的环境里，不要徒劳地斗争，起身离开就好。如果你还是想看看问题出在哪里，那也可以先抽离出来，从旁观的角度能看得更清楚。','7953-8033',0,1708698215,1782480561);
INSERT INTO highlights VALUES('3300022098_42_13220-13314','3300022098',42,'第12章 关系','为了避免一点小拒绝、小尴尬，你实际上付出了巨大的代价。从长远来看，你或许并不会因为一些不成功的关系而太过后悔；你真正后悔的，是没有勇气去尝试那些关系，你永远都会心心念念那可能是怎样的关系。','13220-13314',0,1708698215,1782480561);
INSERT INTO highlights VALUES('3300022098_42_14873-14917','3300022098',42,'第12章 关系','你与他人的任何一份关系都不可能完美地遵循真实、爱与能量原则，但依然可以给你带来显著的成长','14873-14917',0,1708698215,1782480561);
INSERT INTO highlights VALUES('3300022098_42_3070-3127','3300022098',42,'第12章 关系','最后，很重要的是，请接纳人与人之间关系的本质：所有关系都只是暂时的。无论你们之间有多坚韧的纽带，最终都一样会分离。','3070-3127',0,1708698214,1782480561);
INSERT INTO highlights VALUES('3300022098_42_5695-5825','3300022098',42,'第12章 关系','如果你正处于一段关系中，你能说出彼此最合得来的地方是什么吗？你们能遵循真实原则，分享知识并从彼此身上学到东西吗？你们能遵循爱原则，充分表达情感、享受彼此的陪伴吗？你们能遵循能量原则，鼓励、支持彼此追求自己的目标吗？如果三者都在一定程度上具备，哪一种是最主要的？','5695-5825',0,1708698214,1782480561);
INSERT INTO highlights VALUES('3300022098_42_5317-5463','3300022098',42,'第12章 关系','如果想建立联结，人与人之间就必须存在基本的兼容性。我们在进行交流的时候，彼此之间必然有一部分共同点，这样关系才能够建立起来。如果一段关系中没有足够的共同点，这段关系就缺少根基。但是，为了获得成长，一段关系中也需要差异的存在，否则很快就会遭遇瓶颈。共同点让我们能够建立联结，而差异帮助我们成长。','5317-5463',0,1708698214,1782480561);
INSERT INTO highlights VALUES('3300022098_42_5854-5922','3300022098',42,'第12章 关系','一个很有用的做法是，如果你们知道各自在这段关系中最主要的联结方式，那么每当感到彼此变得疏远时，就能运用自己擅长的方式让关系重新变得紧密。','5854-5922',0,1708698214,1782480561);
INSERT INTO highlights VALUES('3300022098_42_6867-6914','3300022098',42,'第12章 关系','如果你是一个特别忠诚的人，那就把这份忠诚给真正值得的人，而别给那些把你的付出视为理所当然的人。','6867-6914',0,1708698214,1782480561);
INSERT INTO highlights VALUES('3300022098_42_1351-1437','3300022098',42,'第12章 关系','面对这些问题的时候，请对自己保持坦诚。对于跟你最亲密的那些人，你能给他们什么支持？你能为伴侣提供什么？他人会因为你的存在而受益吗？或者，你只是在一味索取却并没有过什么给予？','1351-1437',0,1708698213,1782480561);
INSERT INTO highlights VALUES('3300022098_42_1731-1822','3300022098',42,'第12章 关系','请始终记得一点：所有关系都只存在于你的心里，所有关系都被你的认知界定。为了更准确地评估当前关系，你必须向内看。当想法产生的时候，全然接纳。如果你对某一段关系感到模糊不清，也不要惊讶。','1731-1822',0,1708698213,1782480561);
INSERT INTO highlights VALUES('3300022098_42_2753-2859','3300022098',42,'第12章 关系',unistr('不坦诚是有害的，不上心也一样。如果你不再主动关心一段关系中的真实情况，距离就会产生。真实不仅仅意味着不撒谎，实际上，探寻真相是关系中需要持续进行的一件事。\u000a'),'2753-2830',0,1708698213,1782480561);
INSERT INTO highlights VALUES('3300022098_41_11665-11702','3300022098',41,'第11章 健康','良好的健康状态，让你能更好地建立和享受与他人的爱，也就是下一章要讲的：关系','11665-11702',0,1708676846,1782480561);
INSERT INTO highlights VALUES('3300022098_41_9421-9459','3300022098',41,'第11章 健康','如果一个目标无法让你有哪怕任何一点点恐惧，那这个目标本身很可能就不值得追求。','9421-9459',0,1708676619,1782480561);
INSERT INTO highlights VALUES('3300022098_41_5803-5837','3300022098',41,'第11章 健康','背后的原理是，如果想保持心灵的澄澈和强大，身体的健康是一个重要基础。','5803-5837',0,1708676087,1782480561);
INSERT INTO highlights VALUES('3300022098_41_5158-5226','3300022098',41,'第11章 健康','如果想保持健康，你需要加强自律，从而克服社会上各种噪音的干扰。运用成熟的心智，做出清醒自主的选择，而不是听很多不健康的人告诉你该怎么做。','5158-5226',0,1708676004,1782480561);
INSERT INTO highlights VALUES('3300022098_40_16269-16331','3300022098',40,'第10章 金钱','最终我坦然接纳了这一点，因为我明白了：自己能做的最好，就是在每一个当下做出清醒自主的选择——选择遵循真实、爱与能量原则的生活','16269-16331',0,1708675097,1782480561);
INSERT INTO highlights VALUES('3300022098_40_14736-14768','3300022098',40,'第10章 金钱','商业的真正意义在于创造并传递价值，让所有人受益，而不是损人利己。','14736-14768',0,1708674858,1782480561);
INSERT INTO highlights VALUES('3300022098_40_13966-13992','3300022098',40,'第10章 金钱','如果你坚持遵从本心的道路，似乎整个世界都会开始帮你。','13966-13992',0,1708674750,1782480561);
INSERT INTO highlights VALUES('3300022098_40_11485-11612','3300022098',40,'第10章 金钱','如果一个组织在遵循不公平的管理方式，那结果就必然是非人性的。如果你是在为这样一个组织工作，那你就不只是自己屈服于被不公平对待，而且还是在助纣为虐。请别做这样的事。如果你在被不公平地对待，那是否要重新回到真实、爱与能量原则的轨道上，这需要你自己来做出决定。','11485-11612',0,1708674346,1782480561);
INSERT INTO highlights VALUES('3300022098_40_10494-10526','3300022098',40,'第10章 金钱','通常来说，为他人提供价值的最简单方式，就是分享你自己热爱的东西。','10494-10526',0,1708674190,1782480561);
INSERT INTO highlights VALUES('3300022098_40_9944-10026','3300022098',40,'第10章 金钱','解决办法是，寻找个人价值与社会价值的重合点。在这个重合点上工作，你可以做自己喜欢的事，同时还能创造他人需要的价值。别强迫自己在理想和金钱之间二选一，其实你可以兼顾。','9944-10026',0,1708674128,1782480561);
INSERT INTO highlights VALUES('3300022098_40_9710-9748','3300022098',40,'第10章 金钱','清醒自主地创造财富，最基础的方式是贡献社会价值，然而这种方式并不一定能成功。','9710-9748',0,1708674025,1782480561);
INSERT INTO highlights VALUES('3300022098_40_7858-7896','3300022098',40,'第10章 金钱','别让他们把你引入歧途。尽管去创造更多价值，别让一部分人的误解阻碍了你的道路。','7858-7896',0,1708673362,1782480561);
INSERT INTO highlights VALUES('3300022098_40_7771-7829','3300022098',40,'第10章 金钱','你不断提高自己的贡献能力，从而获得越来越高的收入，他们会用自己的价值观来衡量你，认为你肯定也是从别人那里索取了很多。','7771-7829',0,1708673360,1782480561);
INSERT INTO highlights VALUES('3300022098_40_7436-7546','3300022098',40,'第10章 金钱','你获取财富的唯一限制，是自己创造社会价值的能力。如果你想赚更多钱，那就学习技能，提高自己的能力，创造更多社会价值。专注于给予，回报往往会随着时间自动显现。整个社会系统会为贡献提供奖励，而你需要做的就是把价值提供到市场上。','7436-7546',0,1708673320,1782480561);
INSERT INTO highlights VALUES('3300022098_40_7149-7215','3300022098',40,'第10章 金钱','富足思维。这种思维认为，财富可以通过思想和行动创造出来。你的收入是你创造社会价值的反映，而如果想赚到更多钱，就需要创造实实在在的价值','7149-7215',0,1708673005,1782480561);
INSERT INTO highlights VALUES('3300022098_40_4616-4704','3300022098',40,'第10章 金钱','只要我们享受着他人的劳动成果，同时又没有支付回报，我们就是在索取。我们每个人其实都在索取着先辈的努力成果，但最终我们需要做出选择：是永远索取下去，还是为这个世界做出自己的贡献。','4616-4704',0,1708672995,1782480561);
INSERT INTO highlights VALUES('3300022098_40_6688-6714','3300022098',40,'第10章 金钱','你的收入取决于你从事工作的社会价值，而不是个人价值。','6688-6714',0,1708668268,1782480561);
INSERT INTO highlights VALUES('3300022098_40_3289-3347','3300022098',40,'第10章 金钱','还有一种赚钱方式，就是建立一个能产生收入的系统，比如开一个公司。这是我个人最喜欢的方式，因为比出售时间的效率高多了。','3289-3347',0,1708657047,1782480561);
INSERT INTO highlights VALUES('3300022098_40_2758-2817','3300022098',40,'第10章 金钱','因为钱背后是社会资源，所以赚钱实际上就是赚取更多社会资源。花钱的时候，你把钱转化成价值；赚钱的时候，你把价值转化成钱。','2758-2817',0,1708656969,1782480561);
INSERT INTO highlights VALUES('3300022098_39_12603-12648','3300022098',39,'第9章 职业','答案是：在这四个方面里，心灵那部分最适合作为改变的起点。心灵方面的改变会带动其他三个方面。','12603-12648',0,1708656295,1782480561);
INSERT INTO highlights VALUES('3300022098_39_11443-11641','3300022098',39,'第9章 职业',unistr('你需要关注以下四个方面的问题。\u000a(1)身体（需求）：我必须做什么？\u000a(2)头脑（能力）：我能做什么？\u000a(3)心灵（欲望）：我想要做什么？\u000a(4)精神（贡献）：我应该做什么？'),'11443-11641',0,1708656288,1782480561);
INSERT INTO highlights VALUES('3300022098_39_9507-9557','3300022098',39,'第9章 职业','还是从数学的角度来说，如果你知道一个游戏从概率上对你是有利的，那你玩这个游戏的最理想次数是：无数次。','9507-9557',0,1708655912,1782480561);
INSERT INTO highlights VALUES('3300022098_39_8615-8671','3300022098',39,'第9章 职业','如果你从来没做过任何一点能让自己有些恐惧、有所挑战的事情，那你就是对人生这场游戏太保守了，你会错过太多宝贵的机会','8615-8671',0,1708655770,1782480561);
INSERT INTO highlights VALUES('3300022098_39_8161-8215','3300022098',39,'第9章 职业',unistr('那些虚伪、冷漠或者懦弱的人也不可能成为好的领导者。\u000a'),'8161-8186',0,1708655678,1782480561);
INSERT INTO highlights VALUES('3300022098_39_7676-7736','3300022098',39,'第9章 职业','如果你为一家公司工作，而这家公司的价值观偏离了真实、爱与能量的原则，那你其实也就偏离了这些原则，你也对最终的结果负有责任','7676-7736',0,1708655616,1782480561);
INSERT INTO highlights VALUES('3300022098_39_5954-6038','3300022098',39,'第9章 职业','在做完这个练习之后，很多人把他们的人生使命分享给了我，而我通常会被那些使命的美好所感动。当你找到了自己人生中的那个信息，请遵循真实原则，找到一个适合自己的方式去表达它。','5954-6038',0,1708655432,1782480561);
INSERT INTO highlights VALUES('3300022098_39_5405-5637','3300022098',39,'第9章 职业',unistr('我现在的人生使命版本如下：\u000a清醒自主、充满勇气地生活；\u000a享受，增益，分享平静、能量、热情与富足；\u000a与爱和悲悯之心共鸣；\u000a唤醒他人内在的伟大灵魂；\u000a全然拥抱当下时刻。'),'5405-5637',0,1708655384,1782480561);
INSERT INTO highlights VALUES('3300022098_39_3838-3866','3300022098',39,'第9章 职业','提高收入的最好方式，就是找到能让你表达最真实自我的职业。','3838-3866',5,1708589612,1782480561);
INSERT INTO highlights VALUES('3300022098_39_3433-3487','3300022098',39,'第9章 职业','选择的职业载体对不对，最重要的一个标准是：它是否适合你想要表达的内在信息。请对这个信息保持坦诚，这一点很重要','3433-3487',5,1708589561,1782480561);
INSERT INTO highlights VALUES('3300022098_39_966-996','3300022098',39,'第9章 职业','两个人可能用着相似的载体，但这并不意味着他们在分享相同的信息','966-996',5,1708589273,1782480561);
INSERT INTO highlights VALUES('3300022098_39_610-630','3300022098',39,'第9章 职业','的职业实际上包括两个部分：载体，以及信息','610-630',5,1708589197,1782480561);
INSERT INTO highlights VALUES('3300022098_39_765-826','3300022098',39,'第9章 职业','但实际上，你通过职业传递出的信息本身，至少也和职业这个载体同等重要。载体代表着你表达自我的方式，而信息则是你表达出的内容。','765-826',5,1708589188,1782480561);
INSERT INTO highlights VALUES('3300022098_39_456-478','3300022098',39,'第9章 职业','请把职业看作你人生中创造性自我表达的首要途径','456-478',5,1708589133,1782480561);
INSERT INTO highlights VALUES('3300022098_39_377-427','3300022098',39,'第9章 职业',unistr('工作是爱的外显。\u000a——纪伯伦'),'377-427',5,1708589125,1782480561);
INSERT INTO highlights VALUES('3300022098_38_19565-19654','3300022098',38,'第8章 习惯','在习惯这件事上，你的成功跟任何外部成就无关。真正的成功，是你看着镜子里的自己，内心能够感到全然平静。当你的习惯遵循真实、爱与能量原则时，镜子里的那个人就会是你的朋友，而不是敌人。','19565-19654',5,1708589053,1782480561);
INSERT INTO highlights VALUES('3300022098_38_19056-19158','3300022098',38,'第8章 习惯','清醒自主地选择与真实自我相一致的习惯。对于每一个习惯，问问你自己：这是真实的我吗？这符合我最想成为的样子吗？如果生活中有哪个部分让你感到虚伪，感到偏离真实的自己，那这部分就需要改变。这并不容易，但是正确。','19056-19158',5,1708588957,1782480561);
INSERT INTO highlights VALUES('3300022098_38_18620-18652','3300022098',38,'第8章 习惯','去直面那些让自己感到有点恐惧的事情，把这作为一个提升勇气的习惯。','18620-18652',5,1708588876,1782480561);
INSERT INTO highlights VALUES('3300022098_38_15408-15441','3300022098',38,'第8章 习惯','20：找一张纸，在上面写出20个提高个人效能的方法。','15408-15441',5,1708588672,1782480561);
INSERT INTO highlights VALUES('3300022098_38_15200-15256','3300022098',38,'第8章 习惯','把自己的时间从他人的浪费中挽救回来。比如听无聊的演讲时，在脑子里思考自己的目标；开无聊的会时，写自己的购物清单。','15200-15256',5,1708588607,1782480561);
INSERT INTO highlights VALUES('3300022098_38_13161-13231','3300022098',38,'第8章 习惯','(22)区分优先级：把重要的事和紧急的事区分开。分出专门的时间去做那些真正重要但不紧急的事，比如锻炼，写书，找到合适的人生伴侣','13161-13231',5,1708588438,1782480561);
INSERT INTO highlights VALUES('3300022098_38_11624-11689','3300022098',38,'第8章 习惯','(8)早起：早点起床（比如5点），然后直接去做最重要的工作。通常在早上8点前，你就已经完成了比很多人一天都多的工作。','11624-11689',5,1708588343,1782480561);
INSERT INTO highlights VALUES('3300022098_38_10352-10446','3300022098',38,'第8章 习惯','培养至少一个习惯，能让你加深与这个世界的一体和联结。你可以在大自然中长距离徒步，可以享受与亲近的人相互依偎，用拥抱代替握手，对陌生人报以微笑……如果你坚持这些简单的习惯，就很少会感到孤独。','10352-10446',5,1708588186,1782480561);
INSERT INTO highlights VALUES('3300022098_38_10149-10210','3300022098',38,'第8章 习惯','看看自己是否可以做一份志愿工作，或者通过从事的职业做出贡献。比如，我通过自己的网站，向全世界的人们分享个人成长相关的思考。','10149-10210',5,1708588151,1782480561);
INSERT INTO highlights VALUES('3300022098_38_8488-8523','3300022098',38,'第8章 习惯','我的建议是，在你第一次进行30天尝试的时候，并行的事情最多不要超过3个','8488-8523',5,1708587979,1782480561);
INSERT INTO highlights VALUES('3300022098_38_5323-5367','3300022098',38,'第8章 习惯','在习惯改变的最终阶段，有两种强有力的方法可以帮你取得成功：“30天尝试”和“逐步前进”。','5323-5367',5,1708587582,1782480561);
INSERT INTO highlights VALUES('3300022098_38_4900-4927','3300022098',38,'第8章 习惯','在中段时，你可以开始运用一些具体策略，让自己占据优势。','4900-4927',5,1708587529,1782480561);
INSERT INTO highlights VALUES('3300022098_38_4652-4693','3300022098',38,'第8章 习惯','。在初始阶段，先专注于做好铺垫，目标是破坏旧习惯的支撑条件，从而让自己处于有利位置','4652-4693',5,1708587503,1782480561);
INSERT INTO highlights VALUES('3300022098_38_4156-4226','3300022098',38,'第8章 习惯','在习惯改变这件事上，能量原则恐怕是最重要的一条。如果想改变习惯，你就必须专注于自己想要的结果，并且真正付出努力。你越自律，改变习惯就越容易。','4156-4226',5,1708587443,1782480561);
INSERT INTO highlights VALUES('3300022098_38_4119-4126','3300022098',38,'第8章 习惯','习惯与能量原则','4119-4126',5,1708587437,1782480561);
INSERT INTO highlights VALUES('3300022098_38_3961-3990','3300022098',38,'第8章 习惯','请养成向外联结他人的习惯，打破总想独自做所有事的自我限制。','3961-3990',5,1708587395,1782480561);
INSERT INTO highlights VALUES('3300022098_38_3890-3925','3300022098',38,'第8章 习惯','你的社交圈会给你带来持续的影响，而这种影响往往是习惯改变的决定性因素。','3890-3925',5,1708587386,1782480561);
INSERT INTO highlights VALUES('3300022098_38_2890-2953','3300022098',38,'第8章 习惯','爱原则提醒你的就是：请发挥自己向外联结的能力。去争取外部支持，从而提高成功概率。不要让所谓的“自尊”变成阻碍，尽管去获得帮助。','2890-2953',5,1708560728,1782480561);
INSERT INTO highlights VALUES('3300022098_38_2642-2686','3300022098',38,'第8章 习惯','如果你不主动改变自己的习惯，那就只会不断强化现有的习惯，而你预测的对应未来就会变成现实。','2642-2686',5,1708560696,1782480561);
INSERT INTO highlights VALUES('3300022098_38_825-839','3300022098',38,'第8章 习惯','习惯是一种自动储存的解决方案','825-839',5,1708560203,1782480561);
INSERT INTO highlights VALUES('3300022098_36_15517-15548','3300022098',36,'第7章 清醒自主','一周是完成一轮练习的合理周期——每天一个行动，七天覆盖七条原则','15517-15548',5,1708559956,1782480561);
INSERT INTO highlights VALUES('3300022098_36_10995-11021','3300022098',36,'第7章 清醒自主','•当下我能做什么，让自己更好地体会到与世界的一体性？','10995-11021',5,1708399302,1782480561);
INSERT INTO highlights VALUES('3300022098_36_10608-10630','3300022098',36,'第7章 清醒自主','当下我能做什么，让自己变成一个更有能量的人？','10608-10630',5,1708399269,1782480561);
INSERT INTO highlights VALUES('3300022098_36_7001-7028','3300022098',36,'第7章 清醒自主','清醒自主人生的一个副产品，就是一种以自我为中心的平静感','7001-7028',5,1708395185,1782480561);
INSERT INTO highlights VALUES('3300022098_36_5870-5900','3300022098',36,'第7章 清醒自主','在这短暂的一生中，你能做出的最清醒自主的选择，就是保持成长。','5870-5900',5,1708394941,1782480561);
INSERT INTO highlights VALUES('3300022098_36_5615-5642','3300022098',36,'第7章 清醒自主','你越能够清醒自主地生活，就越有能力让这个世界变得更好。','5615-5642',5,1708394918,1782480561);
INSERT INTO highlights VALUES('3300022098_36_4654-4682','3300022098',36,'第7章 清醒自主','清醒自主的个人成长，最有趣的一点是：它是自我循环增强的。','4654-4682',5,1708394737,1782480561);
INSERT INTO highlights VALUES('3300022098_36_3464-3522','3300022098',36,'第7章 清醒自主','在清醒自主的个人成长道路上，我们需要自主地、创造性地表达自我。这远比金钱和地位更重要，金钱和地位并不能弥补成长的匮乏','3464-3522',5,1708394538,1782480561);
INSERT INTO highlights VALUES('3300022098_36_3426-3434','3300022098',36,'第7章 清醒自主','创造性的自我表达','3426-3434',5,1708394486,1782480561);
INSERT INTO highlights VALUES('3300022098_36_3260-3298','3300022098',36,'第7章 清醒自主','保持真实并不是要保持完美，而是尽最大可能，像一个完全真实的人那样去进行交流。','3260-3298',5,1708394458,1782480561);
INSERT INTO highlights VALUES('3300022098_36_2989-3033','3300022098',36,'第7章 清醒自主','随着越来越多新朋友进入我的生活、开始了解我，我发现他们和我相处的方式跟以前的朋友完全不同','2989-3033',5,1708394395,1782480561);
INSERT INTO highlights VALUES('3300022098_36_2283-2365','3300022098',36,'第7章 清醒自主','如果你尝试歪曲真实的想法，为的是让别人听到你以为他们想听的东西，你就是在偏离真实的自我；实际上，你也自以为是地替他人做了决定。否认自身的能量，本质上是对所有人的损害','2283-2365',5,1708394311,1782480561);
INSERT INTO highlights VALUES('3300022098_36_2098-2137','3300022098',36,'第7章 清醒自主','这样做的好处是，别人因此能够对你有准确的了解，由此和你建立足够坦诚而有爱的联结','2098-2137',5,1708394251,1782480561);
INSERT INTO highlights VALUES('3300022098_36_1900-1955','3300022098',36,'第7章 清醒自主',unistr('真实性\u000a真实性指的是，你能够保持内外一致地表达自我。'),'1900-1955',5,1708394212,1782480561);
INSERT INTO highlights VALUES('3300022098_36_1816-1849','3300022098',36,'第7章 清醒自主','清醒自主又具备五种品质：真实性、创造性的自我表达、成长、流动、美。','1816-1849',5,1708390312,1782480561);
INSERT INTO highlights VALUES('3300022098_36_1276-1319','3300022098',36,'第7章 清醒自主','清醒自主是我们生而为人最强有力的自我表达，正是清醒自主的意识，定义了我们作为人的存在。','1276-1319',5,1708388873,1782480561);
INSERT INTO highlights VALUES('3300022098_36_474-546','3300022098',36,'第7章 清醒自主','真实、爱与能量三条基础原则组合在一起，就得出个人成长的最高原则，也就是第七条原则：清醒自主。','474-546',5,1708388750,1782480561);
INSERT INTO highlights VALUES('3300022098_35_10986-11030','3300022098',35,'第6章 勇气','如果真的感到恐惧，那就尽管感到恐惧；但是，记得召唤内心的勇气，去追逐自己真正想要的东西。','10986-11030',5,1708388717,1782480561);
INSERT INTO highlights VALUES('3300022098_35_10524-10553','3300022098',35,'第6章 勇气','请记住：你害怕的东西，正是你迟早必须面对的东西，包括死亡。','10524-10553',5,1708388660,1782480561);
INSERT INTO highlights VALUES('3300022098_35_10268-10301','3300022098',35,'第6章 勇气','所有这些后来的行动，其实最开始只需要我说出那一句：“行，我参加。”','10268-10301',5,1708388642,1782480561);
INSERT INTO highlights VALUES('3300022098_35_7432-7539','3300022098',35,'第6章 勇气',unistr('本心之问\u000a在你做每天的计划时，把待办事项列出来，或者在脑子思考接下来要做什么，这个时候问问自己：遵循本心的方向是什么？'),'7432-7539',5,1708388329,1782480561);
INSERT INTO highlights VALUES('3300022098_35_5804-5870','3300022098',35,'第6章 勇气','别总是想着避免被拒绝，结果把自己锁在了充满虚假安全感的牢笼里。长远来看，相比在臆想的危险下落荒而逃，打造自己的勇气才是更明智的选择。','5804-5870',5,1708282834,1782480561);
INSERT INTO highlights VALUES('3300022098_35_2551-2606','3300022098',35,'第6章 勇气','如果你在当前这条路上找不到正确的方向，那就必须向这条路之外探索。你不能一边在错误的路上走，一边去寻找正确的路。','2551-2606',5,1708282384,1782480561);
INSERT INTO highlights VALUES('3300022098_35_2281-2311','3300022098',35,'第6章 勇气','勇气唤起你内在的真实能量；相反，寻求安全感只能让你变得脆弱。','2281-2311',5,1708282332,1782480561);
INSERT INTO highlights VALUES('3300022098_35_1582-1597','3300022098',35,'第6章 勇气','勇气就是你能够联结真实的自我。','1582-1597',5,1708282209,1782480561);
INSERT INTO highlights VALUES('3300022098_35_1386-1426','3300022098',35,'第6章 勇气','接下来，让我们一起探索勇气的四个组成部分：真实本心、发起行动、直截了当、荣耀感。','1386-1426',5,1708282193,1782480561);
INSERT INTO highlights VALUES('3300022098_35_1275-1350','3300022098',35,'第6章 勇气','恐惧不应该被逃避，恐惧是你找回真实自我的通路。我的经验是：你害怕的东西，正是你迟早必须面对的东西。','1275-1350',5,1708282184,1782480561);
INSERT INTO highlights VALUES('3300022098_34_11606-11724','3300022098',34,'第5章 主导','提高心智地图准确性的最好方法之一，就是直接进行试验。不要从别人那里捡二手经验，尽管直接尝试，以此丰富自己的认知。别盲目听信所谓专家的建议，亲自尝试，搞清楚对自己来说什么才是最有效的。每个人都是不一样的，对别人适用的东西不见得对你也适用。','11606-11724',5,1708274663,1782480561);
INSERT INTO highlights VALUES('3300022098_34_10654-10838','3300022098',34,'第5章 主导',unistr('你可以把自己手头的任务、项目或者其他活动分成三类：\u000a•第一类，无论你做不做，都没有太大意义。\u000a•第二类，无论你做不做，事情都能成功。\u000a•第三类，只有在恰当的时间里行动，才会产生重要的影响。'),'10654-10838',5,1708274245,1782480561);
INSERT INTO highlights VALUES('3300022098_34_9862-9917','3300022098',34,'第5章 主导','真正掌握主导权，你就要能够打破周围人给你的压力，而最好的方法之一就是：制造小反抗，下意识地违背他人对你的期待。','9862-9917',5,1708274143,1782480561);
INSERT INTO highlights VALUES('3300022098_34_8640-8691','3300022098',34,'第5章 主导','在人生中掌握主导权的人，能够专注于对他们来说真正重要的事情。他们不把时间和精力浪费在鸡毛蒜皮的小事上，','8640-8691',5,1708273955,1782480561);
INSERT INTO highlights VALUES('3300022098_34_7971-8041','3300022098',34,'第5章 主导','长期自信，则是能够预期长远的成功，即便短期出现失败也没关系。这种层面的自信，源于你很清楚一件事：在追求目标的道路上，失败只不过是一个必经阶段','7971-8041',5,1708273871,1782480561);
INSERT INTO highlights VALUES('3300022098_34_7748-7774','3300022098',34,'第5章 主导','准确的认知促成有效的结果，而自信就随着现实结果而产生','7748-7774',5,1708273732,1782480561);
INSERT INTO highlights VALUES('3300022098_34_7341-7378','3300022098',34,'第5章 主导','真正的自信，是内心深处明白一个真相：你是一个充满能量的存在。','7341-7371',5,1708273663,1782480561);
INSERT INTO highlights VALUES('3300022098_34_7267-7293','3300022098',34,'第5章 主导','用纪伯伦的话说：在该讲事实的时候谦虚，本质就是虚伪。','7267-7293',5,1708273638,1782480561);
INSERT INTO highlights VALUES('3300022098_34_4428-4449','3300022098',34,'第5章 主导','请主动去做出选择，哪怕有可能失败也没关系。','4428-4449',5,1708273245,1782480561);
INSERT INTO highlights VALUES('3300022098_34_4360-4399','3300022098',34,'第5章 主导','如果你失败了很多次，那只不过说明你还需要学习很多东西，才有足够的能力取得成功。','4360-4399',5,1708273160,1782480561);
INSERT INTO highlights VALUES('3300022098_34_3777-3794','3300022098',34,'第5章 主导','你失败了，但你也从此变得更聪明了。','3777-3794',5,1708273088,1782480561);
INSERT INTO highlights VALUES('3300022098_34_3731-3748','3300022098',34,'第5章 主导','要明白一件事：失败确实是良师益友。','3731-3748',5,1708273081,1782480561);
INSERT INTO highlights VALUES('3300022098_34_3235-3251','3300022098',34,'第5章 主导','经验是提高行动有效性的最好支撑。','3235-3251',5,1708272972,1782480561);
INSERT INTO highlights VALUES('3300022098_34_3144-3199','3300022098',34,'第5章 主导','当你行使自己的指挥权做出决策的时候，一定要重新回归真实原则。看看自己取得的结果，这些结果跟你原本预期的一样吗？','3144-3199',5,1708272959,1782480561);
INSERT INTO highlights VALUES('3300022098_34_2387-2447','3300022098',34,'第5章 主导','如果你沦为了某些权威的猎物，每当你行使自由意志就会受到惩罚，那么请看清真相：这样一种信仰不可能是对你有益的，赶紧放弃它吧','2387-2447',5,1708272804,1782480561);
INSERT INTO highlights VALUES('3300022098_34_1630-1650','3300022098',34,'第5章 主导','真正的指挥权并不意味着不受约束、滥用权力','1630-1650',5,1708272674,1782480561);
INSERT INTO highlights VALUES('3300022098_34_1520-1568','3300022098',34,'第5章 主导','但实际上，你永远都有选择。即便被痛苦折磨或者被死亡威胁，你依然是自己人生的指挥官。','1520-1568',5,1708272657,1782480561);
INSERT INTO highlights VALUES('3300022098_34_1423-1464','3300022098',34,'第5章 主导','如果你认为其他某个角色拥有对你的主导权，那只说明你主动选择了把自己的主导权送给别人','1423-1464',5,1708272632,1782480561);
INSERT INTO highlights VALUES('3300022098_34_1287-1300','3300022098',34,'第5章 主导','真正的领导者其实是你自己。','1287-1300',5,1708272603,1782480561);
INSERT INTO highlights VALUES('3300022098_34_1080-1120','3300022098',34,'第5章 主导','接下来，我们一起探索主导原则的五个组成部分：指挥权、有效性、坚持、自信、重要性。','1080-1120',5,1708272582,1782480561);
INSERT INTO highlights VALUES('3300022098_34_559-578','3300022098',34,'第5章 主导','主导原则，源于真实和能量两条基础原则。','559-578',5,1708268624,1782480561);
INSERT INTO highlights VALUES('3300022098_33_12175-12218','3300022098',33,'第4章 一体','一体原则是我们最难持续遵循的原则之一，主要原因是，现实世界在很多时候还是充满割裂现象的','12175-12218',5,1708257959,1782480561);
INSERT INTO highlights VALUES('3300022098_33_11978-11992','3300022098',33,'第4章 一体','他人跟你其实没有那么的不同。','11978-11992',5,1708257413,1782480561);
INSERT INTO highlights VALUES('3300022098_33_11014-11036','3300022098',33,'第4章 一体','。什么都不用说，去感受人与人之间的那种联结。','11014-11036',5,1708257266,1782480561);
INSERT INTO highlights VALUES('3300022098_33_10991-11014','3300022098',33,'第4章 一体','拥抱你的爱人，怀抱一个小孩子，或者轻抚一个婴儿','10991-11014',5,1708257263,1782480561);
INSERT INTO highlights VALUES('3300022098_33_10042-10107','3300022098',33,'第4章 一体','在这个世界里，没有武器，没有监狱，没有暴力，没有战争。人们会持有不同的观点，但他们会带着同情与公平的信念与他人合作，一同探寻真相。','10042-10107',5,1708256441,1782480561);
INSERT INTO highlights VALUES('3300022098_33_9314-9395','3300022098',33,'第4章 一体',unistr('在我清醒自主地做出选择时，能做到遵循一体原则而行动，但从这种角度思考问题对我来说很吃力，让我感到不自然。\u000a'),'9314-9366',5,1708252827,1782480561);
INSERT INTO highlights VALUES('3300022098_33_9237-9266','3300022098',33,'第4章 一体','如果更多个体选择联合而非冲突，世界整体就能够变得更加美好。','9237-9266',5,1708252806,1782480561);
INSERT INTO highlights VALUES('3300022098_33_9066-9157','3300022098',33,'第4章 一体','在发展一体视角的过程中，先从理性或者感性中的一个层面开始会比较好，这取决于你更擅长哪一层面。从你喜欢的一面开始，然后逐渐扩展到另一面。之后你就可以自由转换，逐渐让两个层面都有所提升。','9066-9157',5,1708252792,1782480561);
INSERT INTO highlights VALUES('3300022098_33_8279-8318','3300022098',33,'第4章 一体','做最好的自己，就是完全遵循一体的原则，去做出榜样，并教人们也同样做最好的自己。','8279-8318',5,1708251491,1782480561);
INSERT INTO highlights VALUES('3300022098_33_8248-8279','3300022098',33,'第4章 一体','你能对这个世界做出的最大贡献，就是做最好的自己。','8248-8272',5,1708251484,1782480561);
INSERT INTO highlights VALUES('3300022098_33_7440-7480','3300022098',33,'第4章 一体','意识到小细胞对大躯体的健康负有责任，所以作为个体，你其实对这个世界负有一份责任。','7440-7480',5,1708251431,1782480561);
INSERT INTO highlights VALUES('3300022098_33_7417-7438','3300022098',33,'第4章 一体','一体理念自然延伸的结果，就是联合意识的觉醒','7417-7438',5,1708251409,1782480561);
INSERT INTO highlights VALUES('3300022098_33_7061-7094','3300022098',33,'第4章 一体','如果你只是为了自己而活，那你的生命在人类整体背景下就真的微不足道了','7061-7094',5,1708251378,1782480561);
INSERT INTO highlights VALUES('3300022098_33_6556-6637','3300022098',33,'第4章 一体','然而，一旦我们拥有了一体的视角，这些纠结就没有了，因为我们能够从更高的层面看待回报。本质上，别人取得成就，你也能够从中获益。别人的成功就像自己的成功一样具有价值。','6556-6637',5,1708251134,1782480561);
INSERT INTO highlights VALUES('3300022098_33_6403-6527','3300022098',33,'第4章 一体',unistr('悔过这个选择。\u000a实际上，一体的理念还让我们在做出贡献时获得了更大的回报。如果没有一体视角，我们做事情的回报就仅仅停留在个体层面：这件事对我有什么好处？我自己能得到什么？我为什么要付出这些努力？'),'6403-6527',5,1708251120,1782480561);
INSERT INTO highlights VALUES('3300022098_33_5907-5950','3300022098',33,'第4章 一体','当我们对正义视而不见时，也就是选择了割裂思维而非一体原则，最终我们都会因此而受到惩罚。','5907-5950',5,1708251055,1782480561);
INSERT INTO highlights VALUES('3300022098_33_5427-5494','3300022098',33,'第4章 一体','一体原则给我们的，是一个做决策时更广阔的视角：不是局限在“对朋友和家人比对陌生人更慷慨”这种层面','5427-5494',5,1708247820,1782480561);
INSERT INTO highlights VALUES('3300022098_33_4967-5038','3300022098',33,'第4章 一体','这里“公平”的定义是：我们选择与人相处的方式，既能让彼此作为个体变得更好，同时也能让世界大躯体有所受益。','4967-5038',5,1708247546,1782480561);
INSERT INTO highlights VALUES('3300022098_33_4436-4462','3300022098',33,'第4章 一体','真正的坦诚，是遵从真实原则，同时又能被爱原则所调和。','4436-4462',5,1708247376,1782480561);
INSERT INTO highlights VALUES('3300022098_33_3942-3991','3300022098',33,'第4章 一体','他人的一些行为伤害了你，其实没那么要紧。你跟世上的每一个人都是联结的、一体的，每一个人都值得被爱。','3942-3991',5,1708247308,1782480561);
INSERT INTO highlights VALUES('3300022098_33_3829-3858','3300022098',33,'第4章 一体','本质上我其实没有给出去什么东西，我是在帮助另一部分的自己。','3829-3858',5,1708247294,1782480561);
INSERT INTO highlights VALUES('3300022098_32_543-570','3300022098',32,'第3章 能量','能量指的是这样一种力量：你能够清醒自主地创造周围世界。','543-570',5,1708239158,1782480561);
INSERT INTO highlights VALUES('3300022098_32_491-507','3300022098',32,'第3章 能量','个人成长的第三条基础原则：能量。','491-507',5,1708239152,1782480561);
INSERT INTO highlights VALUES('3300022098_33_4342-4387','3300022098',33,'第4章 一体','在你跟所有人沟通时，尽量直截了当，足够坦诚。不要让自己习惯于谎言和蒙骗。请保持真实的底线。','4342-4387',5,1708099302,1782480561);
INSERT INTO highlights VALUES('3300022098_33_3101-3118','3300022098',33,'第4章 一体','遵从一体的原则，你将选择主动行善。','3101-3118',5,1708098725,1782480561);
INSERT INTO highlights VALUES('3300022098_33_2398-2442','3300022098',33,'第4章 一体','因为一体视角让你建立起与他人共情的联结，所以它给你带来深刻的快乐，同时也带来深刻的悲伤。','2398-2442',5,1708098475,1782480561);
INSERT INTO highlights VALUES('3300022098_33_2114-2157','3300022098',33,'第4章 一体','为了深度理解一体原则，让我们来看看其六个组成部分：共情、悲悯、坦诚、公平、贡献、联合。','2114-2157',5,1708098302,1782480561);
INSERT INTO highlights VALUES('3300022098_33_2051-2085','3300022098',33,'第4章 一体','从此之后，你看待这世上的每一个人，都不再是与自己完全隔绝的孤立个体。','2051-2085',5,1708098288,1782480561);
INSERT INTO highlights VALUES('3300022098_33_1799-1844','3300022098',33,'第4章 一体','这就好像听一个熟悉的广播——电台是一直在播放的，只不过我需要把自己调整到正确的频率才能听到','1799-1844',5,1708098244,1782480561);
INSERT INTO highlights VALUES('3300022098_33_1484-1566','3300022098',33,'第4章 一体','一些小细胞完全没有意识到这个大躯体的存在，它们总是无意识地跟其他细胞争抢、对抗；但有一些小细胞已经意识到了，于是它们不断努力，去让大家共同所在的这个大躯体变得更好。','1484-1566',5,1708097904,1782480561);
INSERT INTO highlights VALUES('3300022098_33_1416-1448','3300022098',33,'第4章 一体','这个世界是一个巨大的躯体，而我们每一个个体都是其中的一个小细胞。','1416-1448',5,1708097893,1782480561);
INSERT INTO highlights VALUES('3300022098_33_783-859','3300022098',33,'第4章 一体','爱是通过清醒自主的选择去和内心真正渴望的事物建立联结，而一体是明白一个真相：与这个世界的联结，本就是你的自然状态。','783-859',5,1708097793,1782480561);
INSERT INTO highlights VALUES('3300022098_33_591-640','3300022098',33,'第4章 一体','真实与爱构成一体，真实与能量构成主导，爱与能量构成勇气，这些衍生原则将加深你对清醒自主人生的理解。','591-640',5,1708097728,1782480561);
INSERT INTO highlights VALUES('3300022098_33_640-687','3300022098',33,'第4章 一体','最终，真实、爱、能量这三条基础原则合而为一，则构成个人成长的第七条原则，也是最高原则：清醒自主','640-687',5,1708097721,1782480561);
INSERT INTO highlights VALUES('3300022098_33_377-412','3300022098',33,'第4章 一体','这世上所有的差异都只是程度的差异，而无关乎性质。因为世间万物本为一体。','377-412',5,1708097524,1782480561);
INSERT INTO highlights VALUES('3300022098_32_20318-20388','3300022098',32,'第3章 能量','拥有成功的职业生涯是不容易的，经营良好的亲密关系是不容易的，获得财富自由是不容易的。这些东西都不会平白无故掉在你的面前，你必须争取才能得到。','20318-20388',5,1708097486,1782480561);
INSERT INTO highlights VALUES('3300022098_32_20159-20194','3300022098',32,'第3章 能量','你来到这世上，不是为了做一个虚弱和被动的人。你是来发挥出自己的能量的。','20159-20194',5,1708096196,1782480561);
INSERT INTO highlights VALUES('3300022098_32_19728-19761','3300022098',32,'第3章 能量','竞争是一种很好的方法，帮助你打破固有习惯，推动你达到全新的能量水平','19728-19761',5,1708096168,1782480561);
INSERT INTO highlights VALUES('3300022098_32_19660-19682','3300022098',32,'第3章 能量','竞争的有趣之处在于，即使你输了，你也依然赢了','19660-19682',5,1708096147,1782480561);
INSERT INTO highlights VALUES('3300022098_32_19268-19305','3300022098',32,'第3章 能量','相比于仅仅为了个人提升，当能够赢得某些东西的时候，人们往往会变得更加卖力。','19268-19305',5,1708096108,1782480561);
INSERT INTO highlights VALUES('3300022098_32_18808-18844','3300022098',32,'第3章 能量','试试把常规性的工作放在一天中的最后，然后看看你的工作效率会有多大的提升。','18808-18844',5,1707804407,1782480561);
INSERT INTO highlights VALUES('3300022098_32_18527-18604','3300022098',32,'第3章 能量','你根本没动力快速完成手头的事，因为如果那样做了，你只会更快迎来更难的工作。于是你很自然地放慢速度，而这种习惯通常会导致一个结果：最难的工作被延迟到下一天。','18527-18604',5,1707804362,1782480561);
INSERT INTO highlights VALUES('3300022098_32_18218-18401','3300022098',32,'第3章 能量',unistr('难题前置￼\u000a如果你在一天中有什么难题要处理，那就在早上最先解决。在做每天的安排时，遵循“从难到易”的顺序，先解决困难问题。'),'18218-18401',5,1707804329,1782480561);
INSERT INTO highlights VALUES('3300022098_32_17360-17396','3300022098',32,'第3章 能量','掌控每天的第一个小时，去运动、阅读、沐浴、写作，或者做其他高产出的事情。','17360-17396',5,1707754755,1782480561);
INSERT INTO highlights VALUES('3300022098_32_17295-17328','3300022098',32,'第3章 能量','如果你给早起第一个小时设定自律的目标，那你就更容易拥有高效的一天；','17295-17328',5,1707754740,1782480561);
INSERT INTO highlights VALUES('3300022098_32_17109-17160','3300022098',32,'第3章 能量','训练过程本身让你变得更强；同时，最终还能产生有价值的结果（比如养成了某个新习惯）。这实际上是一种双赢。','17109-17160',5,1707754725,1782480561);
INSERT INTO highlights VALUES('3300022098_32_14550-14658','3300022098',32,'第3章 能量',unistr('做一个充满能量的人，去面对失败，总好过一辈子逃避现实、唯唯诺诺地生活。\u000a你在失败面前畏缩，只会让自己变得脆弱。只有不断犯下错误，并从中学到东西，你才会变得更强。'),'14550-14658',5,1707753489,1782480561);
INSERT INTO highlights VALUES('3300022098_32_13659-13707','3300022098',32,'第3章 能量','这种信念会成为自证预言。实际上你充满能量，只是选择了用自己的能量去压制自己，结果让自己变得很弱。','13659-13707',5,1707753321,1782480561);
INSERT INTO highlights VALUES('3300022098_32_13065-13128','3300022098',32,'第3章 能量','打造自律是你人生中最不容易的事情之一。正是因为太不容易了，以至于一些人为了避免自律愿意做任何事——无限制地拖延，甚至吸毒和自杀','13065-13128',5,1707753120,1782480561);
INSERT INTO highlights VALUES('3300022098_32_12313-12367','3300022098',32,'第3章 能量','自律必须跟理智相结合。把自己逼到崩溃并不会带来高产出；然而，把原本会被浪费的时间重新找回来，却必然会提高产出','12313-12367',5,1707752959,1782480561);
INSERT INTO highlights VALUES('3300022098_32_12110-12170','3300022098',32,'第3章 能量',unistr('如果说是动力让你开启了比赛，那么最终是自律让你能够通过终点线。\u000a'),'12110-12141',5,1707752904,1782480561);
INSERT INTO highlights VALUES('3300022098_32_11527-11618','3300022098',32,'第3章 能量','自律，就是无论你的状态如何，你都愿意坚持去做自己应该做的事。当你感觉没动力了，无聊了，犯懒了，这些时候就要靠自律来驱动你前进。在你自身的动力之外，“自律”就像一个附加的备用驱动装置。','11527-11618',5,1707752829,1782480561);
INSERT INTO highlights VALUES('3300022098_32_11134-11177','3300022098',32,'第3章 能量','请选择那些能让你真正感到兴奋的目标，这样的目标会让原本艰苦的努力都变得好像不怎么费力了','11134-11177',5,1707752728,1782480561);
INSERT INTO highlights VALUES('3300022098_32_10031-10095','3300022098',32,'第3章 能量','如果你的目标表面看起来很伟大，实际上却无法让你充满期待和动力，那这些目标就没什么意义。别停留在那些你根本不热爱的、没用的目标上。','10031-10095',5,1707752372,1782480561);
INSERT INTO highlights VALUES('3300022098_32_8226-8289','3300022098',32,'第3章 能量','你会发现，一些特定类型的目标总是能够激励你，而另一些就没有这样的效果。这些表面体现出来的规律，背后隐藏的其实就是你的人生目标；','8226-8289',5,1707752145,1782480561);
INSERT INTO highlights VALUES('3300022098_32_7805-7865','3300022098',32,'第3章 能量','重要的是，在当下，你就已经能够感到快乐，已经能够获得成就感。这让你可以在愉悦的状态中行动，往往还会因此而实现更高效的产出','7805-7865',5,1707751764,1782480561);
INSERT INTO highlights VALUES('3300022098_32_7056-7128','3300022098',32,'第3章 能量','请把你的专注点拉回当下，要意识到，所有这些东西都根本没发生。你只是在脑子里把这些编造了出来。被困在自己压根不想要的、假想出来的结果上，这多傻啊！','7056-7128',5,1707751625,1782480561);
INSERT INTO highlights VALUES('3300022098_32_6812-6843','3300022098',32,'第3章 能量','把目标设定作为提升当下专注度的方法，而不是当作控制未来的手段。','6812-6843',5,1707751585,1782480561);
INSERT INTO highlights VALUES('3300022098_32_6600-6686','3300022098',32,'第3章 能量','很多人在设定目标时，认为达成目标的道路上一定要有很多痛苦，有很多牺牲。但实际上，这种念头通常会导致失败。无论什么时候，当你思考一个新目标时，请留意它给你当前生活带来的影响。','6600-6686',5,1707751557,1782480561);
INSERT INTO highlights VALUES('3300022098_32_6357-6415','3300022098',32,'第3章 能量','设定目标的真正意义，在于提升你当下的状态。设定目标能够给你带来更大的清晰感，让你在当下能更加保持专注。','6357-6415',5,1707751443,1782480561);
INSERT INTO highlights VALUES('3300022098_32_5952-6083','3300022098',32,'第3章 能量',unistr('你无法控制时间的流逝，但你能够控制当下专注于什么。就是这样——没有过去，没有未来，只有当下。\u000a如果当下是唯一存在的东西，那我们谈论“长期目标”还有什么意义？事实上，我们还能“达成”任何目标吗？'),'5952-6083',5,1707751332,1782480561);
INSERT INTO highlights VALUES('3300022098_32_5662-5767','3300022098',32,'第3章 能量','时间并不是一种可以自由使用的资源。你没法“使用”时间，无论你做什么或者不做什么，时间都会自动往前走。你没法选择要不要使用时间，你唯一能选择的是，当下自己要把专注点放在哪里。','5662-5767',5,1707751275,1782480561);
INSERT INTO highlights VALUES('3300022098_32_5400-5479','3300022098',32,'第3章 能量','当你的专注点偏离当下时，就开始让自己的能量变得匮乏了，因为你开始屈从于幻象。也正因此，你应该把专注点放在当下，因为这是你真正拥有能量的唯一地方。','5400-5479',5,1707751229,1782480561);
INSERT INTO highlights VALUES('3300022098_32_4489-4567','3300022098',32,'第3章 能量','为了真正掌控自己的能量，你必须完全承担起对自己生活的责任。在难以判断的时候，在充满挑战的时候，甚至在需要冒险的时候……无论什么条件下，你都愿意主动做出选择。','4489-4567',5,1707751134,1782480561);
INSERT INTO highlights VALUES('3300022098_32_4613-4641','3300022098',32,'第3章 能量','唯一确定的是，无论结果是什么，你自己都是承担责任的那个人','4613-4641',5,1707751123,1782480561);
INSERT INTO highlights VALUES('3300022098_32_4364-4405','3300022098',32,'第3章 能量','自主选择指的是，你能够完全自由地决定自己想要什么，你不需要乞求任何人的允许或者批准','4364-4405',5,1707751068,1782480561);
INSERT INTO highlights VALUES('3300022098_32_4825-4865','3300022098',32,'第3章 能量','生活其实一直在不断地发问：你到底想要什么？','4825-4865',5,1707664481,1782480561);
INSERT INTO highlights VALUES('3300022098_32_2591-2634','3300022098',32,'第3章 能量','有那么一刻，我突然意识到：是我自己把自己推到了这一步，因为我自己丢掉了对生活的掌控权。','2591-2634',5,1707662801,1782480561);
INSERT INTO highlights VALUES('3300022098_32_2219-2291','3300022098',32,'第3章 能量','，人生的责任还是会落在你自己的肩上。这看起来似乎很不“公平”，因为你没法选择自己有一个怎样的童年。但这就是人生啊，总会有一些我们无法改变的事情。','2219-2291',5,1707662761,1782480561);
INSERT INTO highlights VALUES('3300022098_32_1630-1654','3300022098',32,'第3章 能量','你必须学会接受一件事：自己为自己的人生全权负责。','1630-1654',5,1707662688,1782480561);
INSERT INTO highlights VALUES('3300022098_32_1496-1528','3300022098',32,'第3章 能量','能量的六个组成部分：责任、欲望、自主选择、专注、努力行动、自律。','1496-1528',5,1707662676,1782480561);
INSERT INTO highlights VALUES('3300022098_32_1242-1270','3300022098',32,'第3章 能量','能量匮乏只是被内心深处的恐惧、否定、低自尊所误导的结果。','1242-1270',5,1707662635,1782480561);
INSERT INTO highlights VALUES('3300022098_32_779-810','3300022098',32,'第3章 能量','把能量用于好的事情还是不好的事情，取决于能量背后这个人的意识。','779-810',5,1707662548,1782480561);
INSERT INTO highlights VALUES('3300022098_31_15928-15950','3300022098',31,'第2章 爱','感觉自己是孤立存在的个体，这是一种错误幻觉。','15928-15950',5,1707583418,1782480561);
INSERT INTO highlights VALUES('3300022098_31_15973-16010','3300022098',31,'第2章 爱','总有一天你会明白，所有外部关系的真正意义，都是让你学会从内而外地爱你自己。','15973-16010',5,1707583418,1782480561);
INSERT INTO highlights VALUES('3300022098_31_14643-14711','3300022098',31,'第2章 爱',unistr('请注意，只有在赞赏发自内心时才能这么做。永远不要为了操纵别人而进行虚伪的赞赏。\u000a'),'14643-14682',5,1707580418,1782480561);
INSERT INTO highlights VALUES('3300022098_31_13214-13226','3300022098',31,'第2章 爱','不要害怕去做一个发起者。','13214-13226',5,1707580286,1782480561);
INSERT INTO highlights VALUES('3300022098_31_12921-12949','3300022098',31,'第2章 爱','你其实拥有一些永恒的、本质的东西，并不会随着时间而改变。','12921-12949',5,1707580112,1782480561);
INSERT INTO highlights VALUES('3300022098_31_12632-12664','3300022098',31,'第2章 爱','告诉五年前的自己，接下来会出现怎样的挑战。但最终，你都挺过来了。','12632-12664',5,1707580072,1782480561);
INSERT INTO highlights VALUES('3300022098_31_12465-12495','3300022098',31,'第2章 爱','然后，五年后的你离开，五年前的你走进来，还是坐在对面的椅子上','12465-12495',5,1707579956,1782480561);
INSERT INTO highlights VALUES('3300022098_31_12378-12410','3300022098',31,'第2章 爱','而对面坐着的是五年后的你。他知道接下来五年里你将经历的所有事情。','12378-12410',5,1707579929,1782480561);
INSERT INTO highlights VALUES('3300022098_31_12116-12165','3300022098',31,'第2章 爱','把爱看作生命中本就存在的东西，这会让爱变得更简单；相反，别把爱看作某种你需要从无到有去创造的东西。','12116-12165',5,1707579900,1782480561);
INSERT INTO highlights VALUES('3300022098_31_11949-12007','3300022098',31,'第2章 爱','爱不是某种意外之事。爱是一种选择，选择去感知我们在精神层面上与这个世界的深度联结。爱就是能够说出：我们都是一个整体。','11949-12007',5,1707579873,1782480561);
INSERT INTO highlights VALUES('3300022098_31_10521-10583','3300022098',31,'第2章 爱','就是先从跟你价值观最相投、最让你感到舒服、最有爱的人开始。先在这些人中间打磨自己的沟通技能，然后再拓展到没这么轻松的其他群体','10521-10583',5,1707579685,1782480561);
INSERT INTO highlights VALUES('3300022098_31_10368-10397','3300022098',31,'第2章 爱','你能够完全专注于彼此讨论的话题，以及此刻正与你交流的这个人','10368-10397',5,1707578867,1782480561);
INSERT INTO highlights VALUES('3300022098_31_10305-10331','3300022098',31,'第2章 爱','当你能够全然接纳自己时，以往那种过强的自我就会消散。','10305-10331',5,1707578858,1782480561);
INSERT INTO highlights VALUES('3300022098_31_9849-9892','3300022098',31,'第2章 爱','如果你在与人交往时感到尴尬、很难跟他人建立联结，原因也许非常简单：你只是缺少经验而已。','9849-9892',5,1707578765,1782480561);
INSERT INTO highlights VALUES('3300022098_31_9532-9556','3300022098',31,'第2章 爱','忍耐不是爱的表现；恰恰相反，忍耐是拒绝爱的表现。','9532-9556',5,1707568581,1782480561);
INSERT INTO highlights VALUES('3300022098_31_9306-9399','3300022098',31,'第2章 爱','允许自己学会放手，告别那些无法与你同频的组织、人、职业、行为……然后，新的机会才能进入你的生活。当你决定继续向前的时候，请带着爱向过往道别。然后，把珍贵的记忆保存起来，开始迎接新的生活。','9306-9399',5,1707568450,1782480561);
INSERT INTO highlights VALUES('3300022098_31_8104-8182','3300022098',31,'第2章 爱','对被拒绝的恐惧，往往让原本很小的社交问题看起来就像巨大的威胁。这种恐惧会让你感到空虚、孤独、被孤立，失去与他人建立联结的积极意愿，最终让你偏离爱的基本原则。','8104-8182',5,1707565216,1782480561);
INSERT INTO highlights VALUES('3300022098_31_6613-6687','3300022098',31,'第2章 爱','爱这世上的另一个人，也就是爱一部分的你自己；你自己的每一部分都是值得被爱的，所以在你世界中的每一个人都是值得被爱的。爱他人和爱自己，其实是同一件事。','6613-6687',5,1707560328,1782480561);
INSERT INTO highlights VALUES('3300022098_31_6511-6566','3300022098',31,'第2章 爱','你明白的第一个真相就是：对你来说，这世上并没有什么陌生人。','6511-6559',5,1707560311,1782480561);
INSERT INTO highlights VALUES('3300022098_31_6398-6482','3300022098',31,'第2章 爱','这世上并没有人规定，你必须把他人看作跟自己完全割裂的存在。相反，如果把世上所有人都看作自己生命的一部分，就像梦中的人物一样——从这种视角出发，你会产生一些更奇妙的洞见。','6398-6482',5,1707560283,1782480561);
INSERT INTO highlights VALUES('3300022098_31_5653-5782','3300022098',31,'第2章 爱',unistr('但同时，为了确保这个选择是真正清醒自主的，你需要真正了解自己。无论真实的你隐藏着什么问题，你都值得被爱。\u000a'),'5653-5724',5,1707559927,1782480561);
INSERT INTO highlights VALUES('3300022098_31_5367-5402','3300022098',31,'第2章 爱','当你学会在内心里感受到爱的联结时，就会发现，跟他人建立联结其实很简单。','5367-5402',5,1707559846,1782480561);
INSERT INTO highlights VALUES('3300022098_31_5330-5367','3300022098',31,'第2章 爱','如果你无法跟他人建立良好的联结，那很可能是因为你无法对内在的自我产生认同。','5330-5367',5,1707559819,1782480561);
INSERT INTO highlights VALUES('3300022098_31_2159-2202','3300022098',31,'第2章 爱','这些“规矩”根植于恐惧和孤立。如果你选择清醒自主的成长，那么这些东西根本没有立足之地。','2159-2202',5,1707558995,1782480561);
INSERT INTO highlights VALUES('3300022098_31_1959-2022','3300022098',31,'第2章 爱','：获得那些我们内心真正想要的东西，最好的方式就是径直走上前，与之建立联结。','1959-2015',5,1707556567,1782480561);
INSERT INTO highlights VALUES('3300022098_31_904-954','3300022098',31,'第2章 爱','但实际上，与外界产生联结，这本身就是生命中不可或缺的一个部分；我们甚至可以说，这就是我们为什么活着。','904-954',5,1707556397,1782480561);
INSERT INTO highlights VALUES('3300022098_31_694-709','3300022098',31,'第2章 爱','爱的本质，就是选择去建立联结。','694-709',5,1707556300,1782480561);
INSERT INTO highlights VALUES('3300022098_31_499-513','3300022098',31,'第2章 爱','个人成长的第二条基础原则：爱','499-513',5,1707556049,1782480561);
INSERT INTO highlights VALUES('3300022098_30_20780-20798','3300022098',30,'第1章 真实','镜子里的这个人，称得上是我的朋友吗？','20780-20798',5,1707555811,1782480561);
INSERT INTO highlights VALUES('3300022098_30_18423-18512','3300022098',30,'第1章 真实','你所在的位置并不重要，你的评分要基于这条路的方向。你可以什么都还没有，刚刚开始一个新的职业、一段新的关系、一次新的精神探索，但你依然可以打10分，只要你是走在一个正确的方向上的。','18423-18512',5,1707555354,1782480561);
INSERT INTO highlights VALUES('3300022098_30_18541-18647','3300022098',30,'第1章 真实','现在，请重新审视一下自己生活的各个领域，然后问问自己：我真正想要的到底是什么？我的梦想是什么？我对未来的期待是什么？什么是我内心深处真正渴望的东西，我犹豫、不敢承认，因为我觉得自己无法得到？我想体验什么样的人生？','18541-18647',5,1707555325,1782480561);
INSERT INTO highlights VALUES('3300022098_30_16379-16445','3300022098',30,'第1章 真实','你在真实原则上前进的每一步，都会让之后的成长变得更容易，进而不断达到更高程度的坦诚、自我认知和接纳。你并不需要一夜之间解决所有问题。','16379-16445',5,1707554651,1782480561);
INSERT INTO highlights VALUES('3300022098_30_14018-14065','3300022098',30,'第1章 真实','生活中重要的决定，应该在你头脑清醒、足够理智的时候去做，而不能放在过于乐观或者过于悲观的时候做','14018-14065',5,1707553483,1782480561);
INSERT INTO highlights VALUES('3300022098_30_13949-13989','3300022098',30,'第1章 真实','情绪可能会让你无法准确觉察现实，而高度的自我认知则让你避免在错误判断下做出行动。','13949-13989',5,1707553361,1782480561);
INSERT INTO highlights VALUES('3300022098_30_13563-13620','3300022098',30,'第1章 真实','真正清醒自主的个人成长，在很大程度上需要我们能定位自己持有的错误信念，并将其彻底清除。请对新信息保持最大程度的开放','13563-13620',5,1707551361,1782480561);
INSERT INTO highlights VALUES('3300022098_30_13079-13107','3300022098',30,'第1章 真实','自我信任让你获得自由，自我怀疑则让你变成他人信念的奴隶。','13079-13107',5,1707551158,1782480561);
INSERT INTO highlights VALUES('3300022098_30_12544-12574','3300022098',30,'第1章 真实','学会清醒自主地对这些信念进行审视，因为它们都是被社会引导过的','12544-12574',5,1707549667,1782480561);
INSERT INTO highlights VALUES('3300022098_30_12254-12286','3300022098',30,'第1章 真实','然而遗憾的是，这些领域可能会把其他的一些价值观置于真实原则之上。','12254-12286',5,1707549552,1782480561);
INSERT INTO highlights VALUES('3300022098_30_11857-11917','3300022098',30,'第1章 真实','每当面对媒体信息的时候，保持头脑清醒，明白这些媒体其实能扭曲你的认知，引导你相信一些并不真实的东西，然后以此来获取利益。','11857-11917',5,1707549471,1782480561);
INSERT INTO highlights VALUES('3300022098_30_11304-11340','3300022098',30,'第1章 真实','媒体最主要的收入来源是广告，而为了让投放广告的商家获利，就需要引导你消费','11304-11340',4,1707549331,1782480561);
INSERT INTO highlights VALUES('3300022098_30_10187-10278','3300022098',30,'第1章 真实','学会信任自己在这种更高认知状态下的判断。把自己的想法写下来，做出郑重承诺；之后，在你进入低迷状态，不再有那么高认知的时候，依然坚持遵守已经做出的承诺，即便你这个时候不再觉得那么情愿。','10187-10278',5,1707549112,1782480561);
INSERT INTO highlights VALUES('3300022098_30_10041-10084','3300022098',30,'第1章 真实','一个建立自我认知的好方法，就是让你所有的重要决策，都建立在自己最高质量的思维基础之上。','10041-10084',5,1707549088,1782480561);
INSERT INTO highlights VALUES('3300022098_30_9908-9976','3300022098',30,'第1章 真实','具体来说，就是远离各种成瘾习惯、消极情绪和基于恐惧的行为，取而代之的是自主选择的、基于原则的行动。','9908-9957',5,1707549058,1782480561);
INSERT INTO highlights VALUES('3300022098_30_9788-9807','3300022098',30,'第1章 真实','既有的自我认知总是倾向于使自身维持不变','9788-9807',5,1707549043,1782480561);
INSERT INTO highlights VALUES('3300022098_30_9620-9694','3300022098',30,'第1章 真实','当你在某种心境状态下做出选择并且采取相应行动时，这些行动就会反过来强化这种心境状态。结果就是，在未来遇到相同问题时，你更可能再次用相同的方式去应对。','9620-9694',5,1707548946,1782480561);
INSERT INTO highlights VALUES('3300022098_30_7625-7703','3300022098',30,'第1章 真实','准确度最高的预测，才是最好的预测。考虑到自我强化效应，预测最好能够提升自尊、积极情绪以及适度的创造性，而避免降低自尊、消极情绪或者不合理的退缩','7625-7703',5,1707548490,1782480561);
INSERT INTO highlights VALUES('3300022098_30_7454-7481','3300022098',30,'第1章 真实','这些错误的心智地图都有一个共同点：做出的预测过度悲观。','7454-7481',5,1707548447,1782480561);
INSERT INTO highlights VALUES('3300022098_30_6567-6645','3300022098',30,'第1章 真实','其中的关键就在于：清醒自主地管理风险，而不是否认风险的存在。学会在不确定性中获得成功，甚至享受不确定性。','6567-6645',5,1707548312,1782480561);
INSERT INTO highlights VALUES('3300022098_30_6210-6266','3300022098',30,'第1章 真实','否认生活中存在一定的不可预测性，给自己建立起虚假的安全感；或者，你可以接受生活中的变化，并与这种多变性和谐相处。','6210-6266',5,1707491596,1782480561);
INSERT INTO highlights VALUES('3300022098_30_5099-5171','3300022098',30,'第1章 真实','如果你足够有勇气，不妨问几个非常了解你的人，让他们给你一个坦诚的评估——在他们看来，20年后的你应该会是什么样子？他们的回答可能会让你感到吃惊。','5099-5171',5,1707489409,1782480561);
INSERT INTO highlights VALUES('3300022098_30_4875-4913','3300022098',30,'第1章 真实','第二种方法：运用预测能力，做出清醒自主的预测，并用这些预测来做出更好的决策。','4875-4913',5,1707489333,1782480561);
INSERT INTO highlights VALUES('3300022098_30_4415-4494','3300022098',30,'第1章 真实','一些人会说，涉猎如此广泛，是因为达·芬奇“智力过人”；而我认为也许正好相反，正是因为他涉猎如此广泛，最终才变得智力过人——涉猎广泛至少也是重要的影响因素之一。','4415-4494',5,1707461625,1782480561);
INSERT INTO highlights VALUES('3300022098_30_4183-4305','3300022098',30,'第1章 真实','读一本完全陌生领域的书，跟以往不打交道的人交流，去一个陌生的城市，总之，延展你原有的心智地图。如果想获得成长，你就要持续迎接新挑战、思考新点子，为你的大脑带来新的信息输入。如果你只是不断重复以前做过的事，就会变得停滞不前，心智能力也就随之衰减。','4183-4305',5,1707461557,1782480561);
INSERT INTO highlights VALUES('3300022098_30_3998-4024','3300022098',30,'第1章 真实','第一种方法：拥抱全新体验，以前从来没有过的全新体验。','3998-4024',5,1707461469,1782480561);
INSERT INTO highlights VALUES('3300022098_30_3917-3950','3300022098',30,'第1章 真实','你可以通过两种强有力的方法，运用心智地图的预测能力，推动个人成长。','3917-3950',5,1707461464,1782480561);
INSERT INTO highlights VALUES('3300022098_30_3722-3760','3300022098',30,'第1章 真实','为了能让你有所成长，这本书就肯定要打破你的某些预期，让你在某些时刻感到惊奇。','3722-3760',5,1707461428,1782480561);
INSERT INTO highlights VALUES('3300022098_30_3181-3223','3300022098',30,'第1章 真实','但如果现实结果跟你的预期不符，那说明你需要更新自己的心智地图，以匹配最新的现实情况。','3181-3223',5,1707461332,1782480561);
INSERT INTO highlights VALUES('3300022098_30_2906-3009','3300022098',30,'第1章 真实',unistr('先别担心该设定什么样的具体目标；先看清楚，自己觉察到了什么，以及自己对于这份觉察的真实反应又是什么。\u000a预测'),'2906-3009',5,1707458659,1782480561);
INSERT INTO highlights VALUES('3300022098_30_2075-2168','3300022098',30,'第1章 真实','觉察是个人成长中极其关键的一环，因为我们所有的行动，都是对自己觉察到的现实做出的反应。直面现实真相，改变的欲望才能被激发。只有当你站上体重秤发现自己已经超重的时候，你才会想：我要减肥了。','2075-2168',5,1707450539,1782480561);
INSERT INTO highlights VALUES('3300022098_28_7568-7701','3300022098',28,'引言',unistr('一体=真实+爱\u000a主导=真实+能量\u000a勇气=爱+能量\u000a清醒自主=真实+爱+能量'),'7568-7701',5,1707411362,1782480561);
INSERT INTO highlights VALUES('3300022098_28_7454-7504','3300022098',28,'引言','三条基础原则——真实、爱、能量，以及四条由基础原则组合而成的衍生原则——一体、主导、勇气、清醒自主。','7454-7504',5,1707411359,1782480561);
INSERT INTO highlights VALUES('3300022098_28_5462-5520','3300022098',28,'引言','为了评估这些原则，我定下了5条标准，而最终答案必须满足所有标准，具体包括通用性、完整性、不可再分性、一致性、实用性。','5462-5520',5,1707398908,1782480561);
INSERT INTO highlights VALUES('3300022098_28_5331-5372','3300022098',28,'引言','在个人成长领域，是否也适用同样的道理，是否也存在着关于清醒自主成长的某些通用原则？','5331-5372',5,1707397796,1782480561);
INSERT INTO highlights VALUES('3300022098_28_5066-5111','3300022098',28,'引言','它在逻辑上能够成立，以此通过我们左脑的检验；它也要在直觉层面成立，从而通过我们右脑的验证。','5066-5111',5,1707397694,1782480561);
INSERT INTO highlights VALUES('3300022098_28_4858-4884','3300022098',28,'引言','一些人鼓励你改变，另一些人又说你应该接纳自己的现状。','4858-4884',5,1707397665,1782480561);
INSERT INTO highlights VALUES('3300022098_28_4823-4857','3300022098',28,'引言','一些人说你可以通过自律和努力获得成功，一些人又让你顺其自然、听从上帝','4823-4857',5,1707397655,1782480561);
INSERT INTO highlights VALUES('3300022098_28_4104-4147','3300022098',28,'引言','对我们每一个具备清醒意识的人来说，到底什么才算是成长，以及我们怎样清醒自主地实现成长？','4104-4147',5,1707396600,1782480561);
INSERT INTO highlights VALUES('3300022098_28_3803-3845','3300022098',28,'引言','比如，我写一篇关于睡眠的文章，人们却能从中找到某些通用的东西，应用到自己的生意中去。','3803-3845',5,1707396571,1782480561);
INSERT INTO highlights VALUES('3300022098_28_2727-2771','3300022098',28,'引言','但是，我最重要的那些突破，通常都来源于自己的亲身尝试，而不是来源于疯狂阅读别人写的东西。','2727-2771',5,1707396362,1782480561);
INSERT INTO highlights VALUES('3300022098_28_1973-1993','3300022098',28,'引言','我甚至还在求学过程中多修了一个数学学位。','1973-1993',5,1707396250,1782480561);
INSERT INTO highlights VALUES('3300022098_28_1789-1829','3300022098',28,'引言','为了准备好应对高负荷的任务，我学习了很多时间管理技能，每次学到新东西就马上用起来','1789-1829',5,1707396220,1782480561);
INSERT INTO highlights VALUES('3300022098_28_1631-1675','3300022098',28,'引言','于是，我设定了一个非常有野心的目标：每个学期完成别人三倍的课程量，只用三个学期拿到学位。','1631-1675',5,1707396204,1782480561);
INSERT INTO highlights VALUES('3300022098_28_1221-1264','3300022098',28,'引言','逐渐建立起了能指引自己的一套全新道德标准，其中包括荣耀、诚实、慷慨、谦卑、公平，等等。','1221-1264',5,1707396142,1782480561);
INSERT INTO highlights VALUES('3300022098_28_1197-1220','3300022098',28,'引言','在接下来一年的平静生活里，我进行了向内的探索。','1197-1220',5,1707396115,1782480561);
INSERT INTO highlights VALUES('3300022098_28_373-450','3300022098',28,'引言','当处理一个问题的时候，我从来没考虑过“美”。我脑子里想的都是该怎样解决这个问题。但当我完成之后，如果发现解决方案不是优美的，那么我就知道，一定是哪里不对。','373-450',5,1707396007,1782480561);
INSERT INTO highlights VALUES('27256052_125_4593-4612','27256052',125,'小心提倡单一因素解释的人','但选择在意识形态领域是没有一席之地的。','4593-4612',5,1687669760,1782480563);
INSERT INTO highlights VALUES('27256052_125_3189-3258','27256052',125,'小心提倡单一因素解释的人','所有的性别差异都是社会建构的结果，这个主张既无法被证实，也无法被证伪，因为只要我们愿意付出相应的代价，文化本来就可以推动人类往任何方向发展','3189-3258',5,1687669717,1782480563);
INSERT INTO highlights VALUES('27256052_125_2209-2263','27256052',125,'小心提倡单一因素解释的人','后现代主义坚称性别差异是社会建构的产物，这个观点认为社会必须被改变，偏见必须被消除，直到所有的结果都完全平等','2209-2263',5,1687669554,1782480563);
INSERT INTO highlights VALUES('27256052_124_1638-1691','27256052',124,'文化源于人类的创造','在我看来，所谓的父权制度更像是男性和女性在数千年以来试图摆脱贫穷、疾病和艰辛所进行的一种不完美的集体尝试。','1638-1691',5,1687547738,1782480563);
INSERT INTO highlights VALUES('27256052_124_338-406','27256052',124,'文化源于人类的创造',unistr('文化源于人类的创造\u000a文化向来都是一种压迫性结构，这是一个根本而普遍存在的现实。'),'338-406',5,1687547565,1782480563);
INSERT INTO highlights VALUES('27256052_56_2605-2640','27256052',123,'诞生于偏见的“弱势群体”','男孩的宜人性更低，而宜人性是一个与同情、共情和避免冲突相关的性格特质。','2465-2500',0,1685859745,1782480563);
INSERT INTO highlights VALUES('27256052_54_4043-4116','27256052',121,'被阻止的不只是玩滑板','奥威尔认为原因是那些衣着考究、热衷思考批判、满心怜悯和同情的社会改革派并不喜欢穷人，他们只是仇恨富人，并且在用虔诚和自以为是来伪装自己的怨恨和嫉妒','3729-3802',5,1685622245,1782480563);
INSERT INTO highlights VALUES('27256052_52_3356-3415','27256052',156,'法则十 不要无视地毯下的龙：直面问题，言辞精确','直面存在的混乱，瞄准麻烦的海洋，明确目的地，然后绘制航线。承认你想要的东西，让周围的人知道你是谁。精准注视，径直前行。','1338-1562',5,1685621925,1782480563);
INSERT INTO highlights VALUES('27256052_52_2272-2371','27256052',157,'精确分析、创造结构、重建秩序','不要将幼小的恶龙藏在地毯下，它们会在黑暗中蓬勃生长，在你最意想不到的时候跳出来将你吞噬。你会因此坠入混沌和困惑的深渊，而不是进入光明美好的乐园。坦率真实的言辞能让你的现实变得简单、朴素、有序和宜居。','2208-2307',5,1685621806,1782480563);
INSERT INTO highlights VALUES('27256052_52_2158-2226','27256052',157,'精确分析、创造结构、重建秩序','未来有太多可能性，浑浊不堪、难以掌控，但谨慎的思想和语言可以帮助我们发现证明人生意义的独特、辉煌的命运。这就是眼睛和文字创造世界的方式。','2094-2162',5,1685585398,1782480563);
INSERT INTO highlights VALUES('27256052_52_1721-1764','27256052',157,'精确分析、创造结构、重建秩序','在想象中可怕到无法直面的东西，放在现实中虽然依旧可怕，但通常都会缩小为可以直面的东西。','1657-1700',5,1685585345,1782480563);
INSERT INTO highlights VALUES('27256052_52_1468-1488','27256052',157,'精确分析、创造结构、重建秩序','精确性无法改变悲剧本身，但可以赶走鬼神。','1404-1424',5,1685585293,1782480563);
INSERT INTO highlights VALUES('27256052_52_684-745','27256052',157,'精确分析、创造结构、重建秩序','我们应该在问题一出现就立刻关注它。“我不开心”是一个好的开始，“我有权不开心”则不是，因为后者解决问题的动机是值得质疑的。','620-681',5,1685455770,1782480563);
INSERT INTO highlights VALUES('27256052_51_7385-7431','27256052',118,'忽视问题是一切分崩离析的前兆','如果不这么做，那么替代一时痛苦的将会是由绝望和困惑造成的持续隐痛，以及坐看时光流逝的无力感。','7219-7265',5,1685452629,1782480563);
INSERT INTO highlights VALUES('27256052_51_7189-7251','27256052',118,'忽视问题是一切分崩离析的前兆','你最不愿意看到的事情会在你准备最不充分的时候不可避免地发生；你最怕遭遇的东西也会在你最弱、它最强的时候现身，而你终将被打败。','7023-7085',5,1685452607,1782480563);
INSERT INTO highlights VALUES('27256052_51_4052-4143','27256052',118,'忽视问题是一切分崩离析的前兆','当传统缺失时，人们就只剩下三个选择：被奴役、施行暴政或进行谈判。奴隶只会唯命是从，而且或许还乐意以这样的方式去逃避责任，摆脱生活的复杂性。但这只是临时的解决方案，奴隶的内心仍然会反抗','3886-3977',5,1685444160,1782480563);
INSERT INTO highlights VALUES('27256052_51_3960-3999','27256052',118,'忽视问题是一切分崩离析的前兆','在逃离了暴虐之后，随之而来的通常不是乐园，而是困惑、空虚又漫无目的的荒漠之旅。','3794-3833',5,1685444152,1782480563);
INSERT INTO highlights VALUES('27256052_51_985-1045','27256052',118,'忽视问题是一切分崩离析的前兆','我们要如何应对无法预期的灾难？事实是，我们需要放弃那缓慢而笨重的思想，转而依赖我们的身体，因为身体的反应比思想要快得多。','889-949',5,1685443887,1782480563);
INSERT INTO highlights VALUES('27256052_50_5640-5667','27256052',117,'复杂、多维又善变的世界','当世界更深层次的现实意外呈现时，各种疑惑都会竞相出现。','5405-5432',5,1685443775,1782480563);
INSERT INTO highlights VALUES('27256052_50_5174-5186','27256052',117,'复杂、多维又善变的世界','感知偏差和局限凸显无疑。','4939-4951',5,1685443707,1782480563);
INSERT INTO highlights VALUES('27256052_50_4864-4890','27256052',117,'复杂、多维又善变的世界','故障让被忽视的事实显现，模糊不清的后果就是混乱不堪。','4629-4655',5,1685443659,1782480563);
INSERT INTO highlights VALUES('27256052_50_4010-4045','27256052',117,'复杂、多维又善变的世界','现实的混乱仅仅通过观察是很难理解的，人的大脑可能无法胜任这个复杂的任务','3775-3810',5,1685443451,1782480563);
INSERT INTO highlights VALUES('27256052_50_2693-2761','27256052',117,'复杂、多维又善变的世界','我们可以通过螺丝刀感知到其他东西，当我们伸出握着螺丝刀的手时，也会自动将这个工具的长度算进臂长，并借助它来探索未知物体的每一个角落和缝隙','2509-2577',5,1684207470,1782480563);
INSERT INTO highlights VALUES('27256052_50_2146-2175','27256052',117,'复杂、多维又善变的世界','一个人必须拥有精确的目标，否则就会淹没在世界的复杂性当中。','2013-2042',5,1684199497,1782480563);
INSERT INTO highlights VALUES('27256052_50_2031-2071','27256052',117,'复杂、多维又善变的世界','人们感知的不是对象本身，而是它们的实用功能，这样的简化能让人充分理解感知的对象。','1898-1938',5,1684199478,1782480563);
INSERT INTO highlights VALUES('27256052_50_475-537','27256052',117,'复杂、多维又善变的世界','人类进化出来的感知系统并不只是将复杂的世界视作一个充满物体的存在，而是更进一步，将所有事物区分为对自己有用和会阻碍自己的两类','411-473',5,1684114902,1782480563);
INSERT INTO highlights VALUES('27256052_49_2193-2237','27256052',156,'法则十 不要无视地毯下的龙：直面问题，言辞精确','最终，所有这一切要想成为可能，都必须依赖一个更不显眼的元素，也就是由信任构成的社会契约。','2249-2293',5,1684114387,1782480563);
INSERT INTO highlights VALUES('27256052_48_1381-1399','27256052',155,'共同探索，互惠互利','你在聆听他人的时候其实也在聆听自己。','1317-1335',5,1684113874,1782480563);
INSERT INTO highlights VALUES('27256052_48_885-911','27256052',155,'共同探索，互惠互利','除非你的生活是完美无缺的，否则你已知的东西是不够的。','821-847',5,1684113808,1782480563);
INSERT INTO highlights VALUES('27256052_47_3718-3755','27256052',114,'确认你的对话动机','规矩只有一条：别做个无聊的人。另外，也别在装作讽刺别人的时候真的贬低他们。','3654-3691',5,1683594915,1782480563);
INSERT INTO highlights VALUES('27256052_47_1213-1242','27256052',114,'确认你的对话动机','越是极端的保守派或者自由派，越认为他们的立场是不证自明的。','1149-1178',5,1683509622,1782480563);
INSERT INTO highlights VALUES('27256052_46_6520-6584','27256052',113,'表达、思考、聆听自己','有时我们需要花很多时间才能真的理解别人表达的意思。通常这是因为别人也是第一次表述自己的观点，所以难免有钻牛角尖和自相矛盾的可能。','6350-6414',5,1683509428,1782480563);
INSERT INTO highlights VALUES('27256052_46_5333-5355','27256052',113,'表达、思考、聆听自己','聆听的首要要求是勇气，而我们并不总具备勇气。','5173-5195',5,1683465165,1782480563);
INSERT INTO highlights VALUES('27256052_46_2857-2932','27256052',113,'表达、思考、聆听自己','正在读这本书的你，很有可能享有许多特权。你能够阅读，你有时间阅读，这说明你栖身在橡树的顶端。这一切可能是无数前人努力的结果，而你应该对此多少心怀感激。','2729-2804',5,1682752662,1782480563);
INSERT INTO highlights VALUES('27256052_46_2266-2336','27256052',113,'表达、思考、聆听自己',unistr('思考是一件情感上痛苦、生理上辛苦的事情。\u000a要想在头'),'2170-2240',5,1682752547,1782480563);
INSERT INTO highlights VALUES('27256052_45_5577-5638','27256052',112,'别给建议，选择聆听','她就是尼采所说的“苍白的罪犯”（pale criminal）。这种人在上一刻还敢于违反神圣的法律，下一刻就会开始逃避责任。','5475-5536',5,1682752057,1782480563);
INSERT INTO highlights VALUES('27256052_45_994-1087','27256052',112,'别给建议，选择聆听','在临床工作中，对有的人我说得很多，对有的人我则聆听得更多。许多被我聆听的人在生活中没有任何倾诉对象，处于非常孤独的状态。这样的人比你想象的要多得多，你不会遇见他们，因为他们总是独自一人。','930-1023',5,1682751164,1782480563);
INSERT INTO highlights VALUES('27256052_43_5032-5107','27256052',153,'选择真相','这个元目标可以是“真实地活着”，这意味着你需要努力向清晰、明确的临时目标前进，随时清楚成败的标准是什么，如果别人能够了解你的标准并督促你，那就更好了。','4895-4970',5,1682721090,1782480563);
INSERT INTO highlights VALUES('27256052_43_3210-3278','27256052',153,'选择真相','我花了很长时间才看清自己的这种欺骗行为，有时我是在用言语保全面子，有时是在掩盖自己的无知，有时也是在利用他人的观点来逃避独立思考的责任。','3073-3141',5,1682720782,1782480563);
INSERT INTO highlights VALUES('27256052_43_2952-3024','27256052',153,'选择真相','一边前进一边观察，将你的经历尽可能清晰地向自己和他人表达，这样你就能更加有效地实现自己的目标。当然，这个过程中你不能撒谎，尤其是不能对自己撒谎。','2815-2887',5,1682647111,1782480563);
INSERT INTO highlights VALUES('27256052_43_2694-2717','27256052',153,'选择真相','设定自己的志向，即使你不确定应该有怎样的志向。','2557-2580',5,1682647051,1782480563);
INSERT INTO highlights VALUES('27256052_43_2162-2226','27256052',153,'选择真相','你绝不仅仅由那些你已知的部分构成，你也包括那些你只要愿意就可以获得的部分。你永远不应该为了当下的自己而牺牲未来你可能成为的样子。','2057-2121',5,1682646991,1782480563);
INSERT INTO highlights VALUES('27256052_43_1598-1629','27256052',153,'选择真相','奥西里斯代表了古老而又盲目的传统，而荷鲁斯则拥有洞悉一切的能力','1493-1524',5,1682646777,1782480563);
INSERT INTO highlights VALUES('27256052_42_7443-7566','27256052',109,'拒绝欺骗','理性是有生命的，它存在于每个人心中，却比任何人都年长。我们应该将它视作一个人格，而不是一种官能。它有自己的目标、诱惑物和弱点，能比其他天使飞得更高、看得更远。但是理性会爱上自己，也会爱上自己的创造，它会抬高自己创造的事物，并将它们奉为绝对的真理。','7270-7393',0,1682612275,1782480563);
INSERT INTO highlights VALUES('27256052_42_7310-7345','27256052',109,'拒绝欺骗','理性思维往往面对着一个最严重的诱惑，那就是将当下的已知视为绝对的真理。','7137-7172',0,1682609881,1782480563);
INSERT INTO highlights VALUES('27256052_42_6830-6912','27256052',109,'拒绝欺骗','心怀坦诚的人类有能力将存在的痛苦减少到可以忍受的程度。存在的悲剧源自人类经验中固有的局限和脆弱，甚至可以说这种悲剧是我们为存在付出的代价，因为存在必然伴随着局限性。','6657-6739',0,1682609816,1782480563);
INSERT INTO highlights VALUES('27256052_42_6013-6062','27256052',109,'拒绝欺骗','谎言会扭曲存在的结构。不真实会同时腐化灵魂和社会，而且一种形式的腐败往往还会滋养另一种形式的腐败。','5872-5921',0,1682609726,1782480563);
INSERT INTO highlights VALUES('27256052_42_4242-4285','27256052',109,'拒绝欺骗','每个游戏都有规则，有些最重要的规则是隐性的，当你决定玩游戏的时候其实就已经接受它们了。','4101-4144',0,1682609538,1782480563);
INSERT INTO highlights VALUES('27256052_42_3230-3348','27256052',109,'拒绝欺骗','这些基因为新的蛋白质编码，搭建大脑里的新结构。这意味着从生物学的角度来说，自我的大部分都还处于发展的状态，而停滞不会对其有任何好处。你需要通过新的言行和体验来激活自己，否则你就会停留在不完整的状态，而生活对于不完整的人来说是非常艰难的。','3121-3239',0,1682609372,1782480563);
INSERT INTO highlights VALUES('27256052_42_1402-1533','27256052',109,'拒绝欺骗',unistr('人类的理性有危险的骄傲倾向：我所知道的就是所有需要被知道的。\u000a骄傲使人爱上自己创造的思想，并且还会试图使之绝对化。'),'1325-1456',5,1682503681,1782480563);
INSERT INTO highlights VALUES('27256052_41_3458-3500','27256052',108,'逃避还是说出真相','逃避或者说出真相，不仅仅是两个不同的选择，更是两条人生道路，两种完全不同的存在方式。','3385-3427',5,1682503582,1782480563);
INSERT INTO highlights VALUES('27256052_41_2807-2826','27256052',108,'逃避还是说出真相','在你清楚什么才是真话的前提下，说真话。','2734-2753',5,1682503502,1782480563);
INSERT INTO highlights VALUES('27256052_41_2108-2144','27256052',108,'逃避还是说出真相','房东的女朋友身上有因自残而留下的伤痕，这是患有边缘型人格障碍的典型体现。','2035-2071',5,1682503404,1782480563);
INSERT INTO highlights VALUES('27256052_41_1389-1445','27256052',108,'逃避还是说出真相','虽然我的回应不太鼓舞人，也对他的想法持反对意见，但这名来访者依然信任我并愿意和我交流，因为我至少是专注和坦诚的。','1316-1372',5,1682503307,1782480563);
INSERT INTO highlights VALUES('27256052_41_632-678','27256052',108,'逃避还是说出真相','我发现自己内心有时会产生一些相当暴力的冲动，虽然从未付诸过行动，但这也让我深感对自己了解太少','559-605',5,1682472273,1782480563);
INSERT INTO highlights VALUES('27256052_40_2718-2767','27256052',152,'法则八 不买醉鬼卖的东西：说真话，或者至少别撒谎','比精心编造的善意谎言更冷漠。但是我有种预感，如果我撒谎，不论多么友善，都有可能带来意想不到的结果。','2771-2820',5,1682472241,1782480563);
INSERT INTO highlights VALUES('27256052_39_4993-5038','27256052',150,'法则七 苏格拉底的选择：追求意义，拒绝苟且','意义的出现表明了你在正确的时间和地点，恰当地平衡了秩序与混乱，让一切都实现了最好的可能性。','1276-1486',5,1682420545,1782480563);
INSERT INTO highlights VALUES('27256052_39_4872-4918','27256052',151,'超越当下，着眼未来','意义是自然显现的，你可以为它创造前提条件，然后在它出现的时候跟随它，但你无法刻意地制造意义。','4747-4793',5,1682420540,1782480563);
INSERT INTO highlights VALUES('27256052_39_3484-3525','27256052',151,'超越当下，着眼未来','你应该将缓解不必要的痛苦视为一种关于善的人生准则：我会尽我所能地减少不必要的痛苦。','3359-3400',5,1682420366,1782480563);
INSERT INTO highlights VALUES('27256052_39_3657-3697','27256052',151,'超越当下，着眼未来','将缓解不必要的痛苦当作自己的最高价值追求，等同于是在完善社会形态和优化个人心态。','3532-3572',5,1682420348,1782480563);
INSERT INTO highlights VALUES('27256052_39_2866-2904','27256052',151,'超越当下，着眼未来','痛苦是真实的，而为了让他人痛苦刻意进行的折磨则是错误的，这成了我信仰的基石。','2772-2810',5,1682420251,1782480563);
INSERT INTO highlights VALUES('27256052_39_2812-2832','27256052',151,'超越当下，着眼未来','有什么是我无法怀疑的？就是苦难的真实性。','2718-2738',5,1682420235,1782480563);
INSERT INTO highlights VALUES('27256052_39_2757-2783','27256052',151,'超越当下，着眼未来','我需要找到自己信仰的基石，而最终是怀疑帮我找到了它。','2663-2689',5,1682420230,1782480563);
INSERT INTO highlights VALUES('27256052_39_1845-1886','27256052',151,'超越当下，着眼未来','当想法在一个人身上表现出来时，它会让这个人成为自己的化身，并通过行动将它表现出来。','1751-1792',5,1682420098,1782480563);
INSERT INTO highlights VALUES('27256052_39_1278-1441','27256052',151,'超越当下，着眼未来',unistr('如同波普尔所说，人们能够让想法为了自己的利益而死。然后那个创造想法的自我就可以摆脱先前错误的限制继续前进。\u000a只有相信自我的某些部分不会因为这一系列死亡而改变，自我才能够开始思考。'),'1184-1347',5,1682420022,1782480563);
INSERT INTO highlights VALUES('27256052_38_3364-3433','27256052',105,'自由需要建立在约束之上','陀思妥耶夫斯基认为，教会这座庞大而又腐化的大厦仍然在设法为其创始人的思想腾出空间。这是一个明智而又深刻的灵魂在对不完美的智慧表达感激之情。','3247-3316',5,1682417048,1782480563);
INSERT INTO highlights VALUES('27256052_38_3142-3194','27256052',105,'自由需要建立在约束之上','尼采虽然充满智慧，但他允许自己的愤怒不受理性判断的控制。这恰恰是我认为陀思妥耶夫斯基真正超越尼采的地方。','3025-3077',5,1682416972,1782480563);
INSERT INTO highlights VALUES('27256052_38_1549-1582','27256052',105,'自由需要建立在约束之上','尼采认为基督教对真理标准的崇高追求导致了对自身根本假设的质疑和破坏','1461-1494',5,1682416735,1782480563);
INSERT INTO highlights VALUES('27256052_38_401-512','27256052',105,'自由需要建立在约束之上',unistr('自由需要建立在约束之上\u000a卡尔·荣格假设，欧洲文明之所以主动发展现代科学的认知技术去探究物质世界，是因为他们已经暗中认识到宗教对精神救赎的强调无法解决人类当下的痛苦。'),'338-449',5,1682416571,1782480563);
INSERT INTO highlights VALUES('27256052_37_6138-6171','27256052',104,'死亡，劳役与邪恶','邪恶会放大生活的灾难，大大增加我们用权宜之计来应对人生悲剧的动机。','5869-5902',5,1682415914,1782480563);
INSERT INTO highlights VALUES('27256052_37_5529-5626','27256052',104,'死亡，劳役与邪恶','在每个顶峰之上，还存在着另一个位置。那是当你选择自由翱翔在尘世之上时所获得的高瞻远瞩，是放下支配欲后对一切竞争的超越。那是纯粹和不受约束的觉察，在超然、警觉、全神贯注地等待着天时地利的行动机会。','5341-5438',5,1682415872,1782480563);
INSERT INTO highlights VALUES('27256052_37_4873-4921','27256052',104,'死亡，劳役与邪恶','为英雄雪中送炭的桥段是故事创作者们最廉价的写作手法，它嘲弄了独立、勇气、命运、自由意志和责任感。','4685-4733',5,1682384897,1782480563);
INSERT INTO highlights VALUES('27256052_37_2007-2060','27256052',104,'死亡，劳役与邪恶','所以生活的核心问题就不仅仅是通过牺牲来减轻痛苦，而是同时还要减轻由刻意、主动和报复性的邪恶带来的巨大痛苦。','1913-1966',0,1682322167,1782480563);
INSERT INTO highlights VALUES('27256052_37_970-990','27256052',104,'死亡，劳役与邪恶','一个不做任何牺牲的人，失败是情理之中的事','907-927',5,1682251202,1782480563);
INSERT INTO highlights VALUES('27256052_37_657-752','27256052',104,'死亡，劳役与邪恶','人类意识到了自己的脆弱、疾病和死亡的威胁，以及对生存的渴望，于是只有不停地工作。一旦看见了未来，就必须为之做准备，否则就会生活在逃避和恐惧之中。因此，人们只能为了更好的明天而牺牲今天的快乐。','594-689',5,1682251134,1782480563);
INSERT INTO highlights VALUES('27256052_36_3160-3192','27256052',103,'延迟满足的价值','延迟满足的前提是人类文明稳定到能够确保延迟行为在未来会得到奖励。','3018-3050',5,1682250569,1782480563);
INSERT INTO highlights VALUES('27256052_36_2691-2739','27256052',103,'延迟满足的价值','并非所有牺牲都能换来同样的回报，有时候更大的牺牲之后并不一定会有更好的未来，而且很难解释为什么。','2580-2628',5,1682250534,1782480563);
INSERT INTO highlights VALUES('27256052_36_1753-1815','27256052',103,'延迟满足的价值','人类的祖先演绎了一出虚构的戏剧，他们人格化了掌管命运的力量，把它当成一个人来对待，并与之交涉和交易。神奇的是，这么做是有效的','1642-1704',5,1682250417,1782480563);
INSERT INTO highlights VALUES('27256052_36_763-791','27256052',103,'延迟满足的价值','人类在意识到满足能被延迟的同时也发现了其与时间的因果关系','700-728',5,1682250295,1782480563);
INSERT INTO highlights VALUES('27256052_36_529-561','27256052',103,'延迟满足的价值','人终将一死，而工作可以延缓死亡，当下的牺牲从长远来看是有价值的。','466-498',5,1682249878,1782480563);
INSERT INTO highlights VALUES('27256052_36_638-690','27256052',103,'延迟满足的价值','海狸之所以会建造水坝，那是因为它们是海狸，它们不会一边建造一边想：“我宁可和女朋友去墨西哥的沙滩度假。”','575-627',5,1682247409,1782480563);
INSERT INTO highlights VALUES('27256052_34_907-954','27256052',149,'清理你的生活','停止卑鄙的行事方式，停止令你感到懦弱和羞耻的言语。只说让你感到强大的话，只做令你为之骄傲的事。','844-891',5,1682246256,1782480563);
INSERT INTO highlights VALUES('27256052_34_809-832','27256052',149,'清理你的生活','所以，只要你有一丁点停止的想法，那就立刻停止。','746-769',5,1682246243,1782480563);
INSERT INTO highlights VALUES('27256052_34_769-808','27256052',149,'清理你的生活','每个人都很复杂，以至于每个人都很难完全看清自己，但我们都拥有自己无法理解的智慧','706-745',5,1682246218,1782480563);
INSERT INTO highlights VALUES('27256052_34_619-651','27256052',149,'清理你的生活','如果答案是否定的，或许你可以试试看先停止做那些你明知是错误的事情','556-588',5,1682246092,1782480563);
INSERT INTO highlights VALUES('27256052_33_4834-4868','27256052',100,'痛苦时如何抉择','在一切崩溃时，主动为自己的失败负责，直面现实，这是极端负责任的表现。','4654-4688',5,1682246035,1782480563);
INSERT INTO highlights VALUES('27256052_33_3091-3111','27256052',100,'痛苦时如何抉择','报复心无论多么有理，都会阻碍内心的成长。','2942-2962',5,1682245828,1782480563);
INSERT INTO highlights VALUES('27256052_33_2971-3016','27256052',100,'痛苦时如何抉择','但事实恰恰相反，虐待会在代际间消失，因为人们会限制它的延续。这证明人心中的善是能压倒恶的。','2822-2867',5,1682245797,1782480563);
INSERT INTO highlights VALUES('27256052_33_2485-2709','27256052',100,'痛苦时如何抉择','这是尼采的观点。￼他认为面对过邪恶的人的确有可能继续推进邪恶，让它持续存在，但是经历邪恶也有可能让人学会善良。','2345-2560',5,1682245755,1782480563);
INSERT INTO highlights VALUES('27256052_33_1623-1659','27256052',100,'痛苦时如何抉择','但是也有人在经历了痛苦之后选择成为善良的人，这样的人在我看来就像超人一样','1483-1519',5,1682237879,1782480563);
INSERT INTO highlights VALUES('27256052_33_1587-1613','27256052',100,'痛苦时如何抉择','在经历了暴行之后，原谅岂不是懦弱和缺乏意志力的表现？','1447-1473',5,1682237872,1782480563);
INSERT INTO highlights VALUES('27256052_33_1363-1401','27256052',100,'痛苦时如何抉择','他的行为似乎在假设造物主应该为一切负责。这是人类报复心达到极致的最真实体现。','1223-1261',5,1682237842,1782480563);
INSERT INTO highlights VALUES('27256052_33_666-685','27256052',100,'痛苦时如何抉择','就像科伦拜枪击案的凶手明确表达的那样：','603-622',5,1682237805,1782480563);
INSERT INTO highlights VALUES('27256052_33_824-1029','27256052',100,'痛苦时如何抉择','你也许可以去惹别人，并且最终逃脱，但是对我不行。我不会忘记冤枉过我的人。','724-760',5,1682237801,1782480563);
INSERT INTO highlights VALUES('27256052_32_3177-3225','27256052',99,'存在的价值','托尔斯泰还不够悲观。生活在我们身上开的愚蠢玩笑不光会导致自杀，还可能带来以自杀为结局的大规模杀戮','2850-2898',5,1682237706,1782480563);
INSERT INTO highlights VALUES('27256052_32_2898-2933','27256052',99,'存在的价值','只有第四种逃脱方式富含力量，即在意识到生活的邪恶和无意义后主动地毁灭它','2644-2679',5,1682233068,1782480563);
INSERT INTO highlights VALUES('27256052_32_729-807','27256052',99,'存在的价值','《浮士德》便探讨了这个问题。该剧的主角是一个叫海因里希·浮士德的学者，他将自己的灵魂出卖给了恶魔墨菲斯托，作为回报，浮士德在有生之年可以得到任何他想要的东西','666-744',5,1682232868,1782480563);
INSERT INTO highlights VALUES('27256052_30_6591-6641','27256052',147,'管教五原则','在经历了足够多的难堪、违抗和被挑战之后，即使是最无私的父母也会变得满心怨恨，然后真正的惩罚就开始了。','6330-6380',5,1682232624,1782480563);
INSERT INTO highlights VALUES('27256052_30_5062-5115','27256052',147,'管教五原则','如果你从没有充分考虑过这些事情，也许你就是个不称职的家长。你主动把脏活留给了别人，而别人只会更加不留情面。','4905-4958',5,1682232552,1782480563);
INSERT INTO highlights VALUES('27256052_30_4820-4857','27256052',147,'管教五原则','如果你还在生气，要么是因为孩子没有完全悔改，要么便是你自己有记仇的坏毛病。','4663-4700',5,1682180493,1782480563);
INSERT INTO highlights VALUES('27256052_30_4599-4626','27256052',147,'管教五原则','有一个很实用的管教手段：隔离反省（time-out）。','4442-4469',0,1682144682,1782480563);
INSERT INTO highlights VALUES('27256052_30_1213-1493','27256052',147,'管教五原则','以下是一些建议。你可以告诉你的孩子：除非是自卫，否则不要咬人或者踢打别人；不要折磨和欺凌其他孩子，这样长大后你才不会成为罪犯；带着感恩之心文明地进餐，这样人们才会再次邀请你；学会分享，这样其他孩子才会喜欢和你玩耍；认真听大人讲话，这样他们才不会讨厌你，才会乐于与你分享有用的信息；安静地睡觉，这样父母才可以有一些私人空间，才不会讨厌你的存在；看管好你的个人物品，因为这是一项重要的能力，而且拥有这些物品是你的幸运；在玩耍的时候做个好的伙伴，这样别人才更乐于和你在一起；以令人愉悦的方式为人处世，让人们愿意待在你身边。一个懂得这些规则的孩子走到哪里都会受到欢迎。','1088-1368',0,1682144290,1782480563);
INSERT INTO highlights VALUES('27256052_30_401-406','27256052',147,'管教五原则','管教五原则','338-343',0,1682144200,1782480563);
INSERT INTO highlights VALUES('27256052_29_11313-11640','27256052',96,'建立规则与结构意识','如果一个社会对有益的亲社会行为没有给予足够的奖励，坚持以专横和不公平的方式分配资源，纵容偷窃和剥削，那么它将无法保持长久的和平。如果一个社会的等级制度大多建立在权力而非解决问题的能力之上，那么它也会在不久后崩溃。就连更为简单的黑猩猩等级制度也是如此，而这正证明了社会契约在根本的生物学层面上不是专横武断的。','11084-11237',0,1682144090,1782480563);
INSERT INTO highlights VALUES('27256052_29_11093-11142','27256052',96,'建立规则与结构意识','当一个人偏离轨道时，那些在乎他的人会以各种方式将他拉回正轨，所以和在乎自己的人在一起是很有必要的。','10864-10913',0,1682144044,1782480563);
INSERT INTO highlights VALUES('27256052_29_8208-8286','27256052',96,'建立规则与结构意识','不论是积极情绪还是消极情绪，最后都会以两种很有价值的形式表现出来：一种是满足感，它告诉人们过去的行为是好的；另一种是希望，它告诉人们令人愉悦的事物即将到来。','7993-8071',5,1682081962,1782480563);
INSERT INTO highlights VALUES('27256052_29_8117-8133','27256052',96,'建立规则与结构意识','痛苦和焦虑比快乐和希望更有力量。','7902-7918',5,1682081949,1782480563);
INSERT INTO highlights VALUES('27256052_29_8026-8062','27256052',96,'建立规则与结构意识','虽然消极情绪令人不适，但感到受伤、恐惧、羞耻和恶心却可以保护我们免受伤害','7811-7847',5,1682081938,1782480563);
INSERT INTO highlights VALUES('27256052_29_7828-7871','27256052',96,'建立规则与结构意识','观察者需要耐心地等待目标自发地做出所需要的行为，然后再予以强化，而等待会消耗大量的时间','7613-7656',5,1682081894,1782480563);
INSERT INTO highlights VALUES('27256052_29_7802-7828','27256052',96,'建立规则与结构意识','他指出，这种使用奖励的方法实施起来其实是非常困难的。','7587-7613',5,1682081882,1782480563);
INSERT INTO highlights VALUES('27256052_29_6787-6806','27256052',96,'建立规则与结构意识','事实上奖励对于良好行为的保持非常有效。','6580-6599',5,1682081785,1782480563);
INSERT INTO highlights VALUES('27256052_29_6671-6683','27256052',96,'建立规则与结构意识','管教和惩罚需要谨慎地进行','6464-6476',5,1682081686,1782480563);
INSERT INTO highlights VALUES('27256052_29_4705-4764','27256052',96,'建立规则与结构意识','我轻拍儿子的头，真诚地赞美他是个好孩子。当人们做到了你想让他们做的事情时，一定要及时给予奖励，这样才能让胜利不带怨恨。','4537-4596',5,1682081532,1782480563);
INSERT INTO highlights VALUES('27256052_29_3654-3712','27256052',96,'建立规则与结构意识','小孩子就像寻找墙面的盲人一样，需要不断地前进和尝试，然后才能发现边界在哪里，况且这些边界往往和人们声称的位置不一样。','3486-3544',5,1682081379,1782480563);
INSERT INTO highlights VALUES('27256052_29_2882-2930','27256052',96,'建立规则与结构意识','儿童之所以会打人，一方面是因为攻击性是天生的，尽管强度因人而异，另一方面是因为攻击性会增强欲望。','2751-2799',5,1682081358,1782480563);
INSERT INTO highlights VALUES('27256052_29_2516-2562','27256052',96,'建立规则与结构意识','暴力并不神秘，自制力才是神秘的。因为实施暴力很容易，而要想获得自制力，必须要经过一系列努力。','2416-2462',5,1682069796,1782480563);
INSERT INTO highlights VALUES('27256052_29_2316-2428','27256052',96,'建立规则与结构意识',unistr('接下来我做了一件让小坏蛋震惊但对他有好处的事情：我把他从云梯上举起来，扔到了10米开外的地方。\u000a不，我并没有。我只是把女儿带去了别的地方。但如果我真那么做或许对他更好。'),'2216-2328',5,1682069711,1782480563);
INSERT INTO highlights VALUES('27256052_29_786-828','27256052',96,'建立规则与结构意识','管教孩子是一种责任，管教不是对不良行为的愤怒或者报复，而是仁慈和长远判断的谨慎结合。','723-765',5,1682047952,1782480563);
INSERT INTO highlights VALUES('27256052_29_622-657','27256052',96,'建立规则与结构意识','所以父母必须采取必要的措施，并还要学会容忍孩子对他们的暂时性愤怒和怨恨','559-594',5,1682047942,1782480563);
INSERT INTO highlights VALUES('27256052_29_519-554','27256052',96,'建立规则与结构意识','父母太渴望和孩子建立友谊，甚至到了愿意牺牲自己尊严的地步。这是不对的。','456-491',5,1682047924,1782480563);
INSERT INTO highlights VALUES('27256052_28_6019-6046','27256052',95,'提升成本/收益比','缺乏深入关注给孩子带来的伤害甚至超过虐待所带来的伤害。','5800-5827',5,1682047733,1782480563);
INSERT INTO highlights VALUES('27256052_28_5836-5878','27256052',95,'提升成本/收益比','社会化这一重要过程能够避免伤害，培养善良。儿童必须被塑造和教育，否则就无法茁壮成长。','5617-5659',5,1682047716,1782480563);
INSERT INTO highlights VALUES('27256052_28_1614-1700','27256052',95,'提升成本/收益比','这些父母在年轻时也许曾不安而又难堪地活在20世纪60年代青少年风气的强大阴影下，这十年的放纵曾使他们普遍瞧不起成年人，无理由地反抗权威，无法区分不成熟的混乱和负责任的自由。','1551-1637',5,1682047420,1782480563);
INSERT INTO highlights VALUES('27256052_28_1439-1479','27256052',95,'提升成本/收益比','我们的祖先用智慧修筑高墙，将可怕的事物隔绝在外，推倒这些墙将使我们暴露在危险中。','1376-1416',5,1682047384,1782480563);
INSERT INTO highlights VALUES('27256052_28_725-822','27256052',95,'提升成本/收益比','不论你带着怎样的善意，脾气多么温和、包容，也是没办法和每年要争斗一个半月的人保持良好关系的。怨恨会累积，而且就算不会，所有被浪费掉的不快乐时光本来是可以用在更有建设性、更轻松和更好玩的活动上的。','662-759',5,1681814209,1782480563);
INSERT INTO highlights VALUES('27256052_27_3840-3873','27256052',146,'法则五 管教你家的小怪物：别让孩子做出令你讨厌他的事','自私的基因”这个著名的概念，认为基因会通过被偏爱的孩子一直延续下去','3874-3907',5,1681813907,1782480563);
INSERT INTO highlights VALUES('27256052_27_3298-3324','27256052',146,'法则五 管教你家的小怪物：别让孩子做出令你讨厌他的事','父母的确有理由偏好儿子到甚至愿意放弃女性胎儿的地步。','3343-3369',5,1681813860,1782480563);
INSERT INTO highlights VALUES('27256052_27_2186-2270','27256052',146,'法则五 管教你家的小怪物：别让孩子做出令你讨厌他的事','然而他的妈妈并没有安抚被惊吓的女儿，反倒是立刻把男孩抱起来，小声地告诉他不要做这样的事情，同时用一种显然是在表达认可的方式轻拍安抚他。她这是在塑造一个唯我独尊的小皇帝，','2249-2333',5,1681813687,1782480563);
INSERT INTO highlights VALUES('27256052_27_1932-1960','27256052',146,'法则五 管教你家的小怪物：别让孩子做出令你讨厌他的事','当父母不敢教孩子“不”的意义时，孩子就感知不到合理的边界','1995-2023',5,1681813666,1782480563);
INSERT INTO highlights VALUES('27256052_26_1544-1578','27256052',145,'集中注意力，改善现状','你会习惯性地问自己：“要让生活变得更好，哪些事情是我能做也愿意做的？','1481-1515',5,1681552532,1782480563);
INSERT INTO highlights VALUES('27256052_25_7501-7563','27256052',92,'走出认知困局','你选择相信存在的意义和目标是嘉言善行，这样的存在主义信仰可以帮助你战胜虚无主义，战胜怨恨和傲慢，遏制所有你对人生的仇恨和恶意','7321-7383',5,1681552320,1782480563);
INSERT INTO highlights VALUES('27256052_25_6759-6813','27256052',92,'走出认知困局',unistr('你什么都不明白。\u000a你甚至不知道自己其实是“失明”的。'),'6579-6633',5,1681385205,1782480563);
INSERT INTO highlights VALUES('27256052_25_6493-6546','27256052',92,'走出认知困局','要想知道自己真正相信什么，不能光局限于你认为自己相信什么，还要观察自己的所作所为，否则你就无法真正了解自己','6313-6366',5,1681385182,1782480563);
INSERT INTO highlights VALUES('27256052_25_5193-5242','27256052',92,'走出认知困局','你和世界互动时，它会合作或者反抗。但如果你的目标是与它共舞，尤其是当你德行兼备时，你甚至可以领舞。','5013-5062',5,1681384880,1782480563);
INSERT INTO highlights VALUES('27256052_25_4789-4878','27256052',92,'走出认知困局','你需要洗刷自己的精神，将它清理干净；你也需要更加谨慎，因为改善生活意味着承担更多责任；同时你也需要更努力、更用心地生活，而不是继续愚昧地活在痛苦中，自以为是、自欺欺人又满心怨恨。','4640-4729',5,1681384843,1782480563);
INSERT INTO highlights VALUES('27256052_24_2669-2738','27256052',91,'追求什么决定看见什么','也许你需要和“自己”说：“好，我知道我们过去相处得不太好。我向你道歉，我也在试着改善。接下来我可能还会犯错，但我会聆听你的反馈，努力学习。','2596-2665',5,1681237537,1782480563);
INSERT INTO highlights VALUES('27256052_24_2417-2501','27256052',91,'追求什么决定看见什么','或许你需要真诚地对他说：“不好意思，我打算减少一些痛苦，希望你可以帮帮我。不知道有没有什么事情是你愿意做的？对你的帮助我会很感激。”坦诚谦虚地询问，这么做其实并不容易。','2344-2428',1,1681236123,1782480563);
INSERT INTO highlights VALUES('27256052_24_2031-2059','27256052',91,'追求什么决定看见什么','当下永远都是有缺陷的，但是你前行的方向比你的起点更重要。','1958-1986',1,1681236074,1782480563);
INSERT INTO highlights VALUES('27256052_23_6214-6278','27256052',90,'与自我博弈','只有天晓得我们在走向和平的道路上需要经历怎样的战斗。你会如何避免冲突？会用怎样的谎言来掩盖你认为无法直视的真相？你又会假装什么？','6069-6133',0,1681043426,1782480563);
INSERT INTO highlights VALUES('27256052_23_5837-5868','27256052',90,'与自我博弈','当有话要讲的时候，沉默就是在撒谎，而暴政往往就建立在谎言之上。','5692-5723',0,1681039301,1782480563);
INSERT INTO highlights VALUES('27256052_23_5660-5686','27256052',90,'与自我博弈','傲慢、欺骗和怨恨是邪恶三合体，也是最具伤害性的存在。','5515-5541',0,1681039262,1782480563);
INSERT INTO highlights VALUES('27256052_23_5496-5534','27256052',90,'与自我博弈','你可能会发现自己只是因为害怕而故作高尚，也许满足心愿反而能避免让你误入歧途。','5351-5389',0,1681039235,1782480563);
INSERT INTO highlights VALUES('27256052_23_4554-4589','27256052',90,'与自我博弈','从象征意义上来说，人们应该离开“父亲”统治的家，独自面对个体存在的混乱','4409-4444',0,1681035991,1782480563);
INSERT INTO highlights VALUES('27256052_23_4040-4111','27256052',90,'与自我博弈','最后，你有可能发现你玩的所有游戏的细节对你来说都是如此独特和个人化，以至于和他人比较压根就不现实。也许你高估了自己没有的，也低估了自己已有的。','3895-3966',0,1681035917,1782480563);
INSERT INTO highlights VALUES('27256052_23_3669-3685','27256052',90,'与自我博弈','其次，你也不太可能只玩一个游戏。','3524-3540',0,1681035778,1782480563);
INSERT INTO highlights VALUES('27256052_23_3376-3393','27256052',90,'与自我博弈','首先，成败并不只存在于某一个游戏。','3231-3248',0,1681035741,1782480563);
INSERT INTO highlights VALUES('27256052_23_2640-2681','27256052',90,'与自我博弈','说服自己对什么都不在乎并不是在对存在进行深刻评判，而是在用理性思维玩一些低劣伎俩。','2526-2567',0,1681035608,1782480563);
INSERT INTO highlights VALUES('27256052_23_1920-2191','27256052',90,'与自我博弈','整整一代社会心理学家都将“积极错觉”视为保持精神健康的唯一可靠途径￼，他们的信条是让谎言做你的保护伞。','1818-2077',0,1681035519,1782480563);
INSERT INTO highlights VALUES('27256052_23_1379-1426','27256052',90,'与自我博弈','每个人内心都存在一个似乎能洞悉一切的批评家。他向来吵闹，不断谴责着我们的平庸，常常令人难以忍受','1277-1324',0,1681035434,1782480563);
INSERT INTO highlights VALUES('27256052_23_561-761','27256052',90,'与自我博弈','也许正是这个原因，伟人中出生在小地方的人占比总是高于平均水平。','498-529',0,1681035348,1782480563);
INSERT INTO highlights VALUES('27256052_21_587-614','27256052',143,'建立互惠关系','忠诚需要建立在公平和坦诚之上，友谊则应该是互惠的结果。','524-551',0,1681034962,1782480563);
INSERT INTO highlights VALUES('27256052_20_6902-6936','27256052',87,'拯救他人是高尚还是虚荣','不过需要指出的是，不能用这一点来为自私找借口，抛弃真心需要帮助的人。','6575-6609',0,1681034011,1782480563);
INSERT INTO highlights VALUES('27256052_20_6813-6856','27256052',87,'拯救他人是高尚还是虚荣','正确的做法是：结束这段关系，离开这里到别处去，重新振作起来，然后再以身作则，激励他人。','6486-6529',0,1681034001,1782480563);
INSERT INTO highlights VALUES('27256052_20_6521-6553','27256052',87,'拯救他人是高尚还是虚荣','罗杰斯认为人们不可能说服一个人改变，具备改善的意愿才是进步的前提','6194-6226',0,1681033980,1782480563);
INSERT INTO highlights VALUES('27256052_20_5914-5983','27256052',87,'拯救他人是高尚还是虚荣','成功和美德的秘诀难以捉摸，失败则只需要你养成几个坏习惯然后任其发酵，接下来你就会陷入恶性循环。失败会不请自来，而人的罪恶则会加快它的进程。','5595-5664',0,1681033950,1782480563);
INSERT INTO highlights VALUES('27256052_20_4785-4848','27256052',87,'拯救他人是高尚还是虚荣','在帮助一个人之前，你需要先弄明白他为什么身处困境。你不应该先假设他是不公正和剥削的无辜受害者，因为这往往是最不符合实际的解释。','4474-4537',0,1681013904,1782480563);
INSERT INTO highlights VALUES('27256052_20_3791-4082','27256052',87,'拯救他人是高尚还是虚荣','恶习会传染，自律和稳定却不会￼，因为堕落比奋进容易太多。','3521-3802',0,1680987872,1782480563);
INSERT INTO highlights VALUES('27256052_19_3431-3458','27256052',86,'摆脱“强迫性重复”','弗洛伊德把对过去糟糕经历的无意识重复称作“强迫性重复”','3357-3384',0,1680948632,1782480563);
INSERT INTO highlights VALUES('27256052_19_1302-1348','27256052',86,'摆脱“强迫性重复”','当生活向前推进的时候，你会陷入暂时的混乱，这虽然会给你带来压力，但同时也会让你产生新的希望。','1239-1285',0,1680948188,1782480563);
INSERT INTO highlights VALUES('27256052_19_1140-1185','27256052',86,'摆脱“强迫性重复”','在小镇上，每个人都认识你，你的过往就像绑在狗尾巴上的空罐子一样，你很难摆脱原有的生活轨迹。','1077-1122',0,1680948181,1782480563);
INSERT INTO highlights VALUES('27256052_16_5691-5926','27256052',141,'自助者天助','19世纪伟大的哲学家尼采说过一句很精彩的话：“一个人知道自己为什么而活，就可以忍受任何一种生活。”','5496-5545',0,1680921223,1782480563);
INSERT INTO highlights VALUES('27256052_16_5455-5595','27256052',141,'自助者天助','你需要先知道自己的方向，才能适时维护自己，不至于落得满腹怨言、怀恨在心；你需要明确自己的原则，这样别人就无法轻易占你便宜；你需要严格自律，信守对自己做出的承诺，并及时进行自我奖励，这样才能更好地信任和激励自己；你更需要以变成更好的人为目标。好事不会自动降临，我们需要努力强化自我。','5260-5400',0,1680887328,1782480563);
INSERT INTO highlights VALUES('27256052_16_3713-3732','27256052',141,'自助者天助','我们不完全是神明，但也并非什么都不是。','3549-3568',0,1680864894,1782480563);
INSERT INTO highlights VALUES('27256052_16_3622-3654','27256052',141,'自助者天助','你的存在和他人紧密相连，自我虐待有可能会给他人带来灾难性的影响。','3458-3490',0,1680864882,1782480563);
INSERT INTO highlights VALUES('27256052_16_3521-3550','27256052',141,'自助者天助','当你被折磨奴役时，站起来为自己说话和为别人说话没什么区别。','3357-3386',0,1680864867,1782480563);
INSERT INTO highlights VALUES('27256052_16_920-952','27256052',141,'自助者天助','这些救赎和自我修正的目的就是要在混乱中有意识地选择和创造善的存在','857-889',0,1680861168,1782480563);
INSERT INTO highlights VALUES('27256052_16_595-628','27256052',141,'自助者天助','如果说意识对于整个宇宙来说是有意义的，那么它的意义就在于自由选择。','532-565',0,1680861121,1782480563);
INSERT INTO highlights VALUES('27256052_16_482-520','27256052',141,'自助者天助','他们的善是被赐予的，而不是挣得的，这样也许更轻松，却比不上通过努力去获得善。','419-457',0,1680860917,1782480563);
INSERT INTO highlights VALUES('27256052_15_8954-8996','27256052',82,'认识你自己','原罪这一概念在现代学术界很不受欢迎，但考虑到人类作恶的能力，这一概念的存在完全合理。','8678-8720',0,1680860396,1782480563);
INSERT INTO highlights VALUES('27256052_15_7939-8001','27256052',82,'认识你自己','当你拒绝做对自己有益的事情时，就像是在为你所有的缺点惩罚自己。相比之下，一条无害、天真而且没有自我意识的狗显然比你更值得善待','7694-7756',0,1680860310,1782480563);
INSERT INTO highlights VALUES('27256052_15_7058-7088','27256052',82,'认识你自己','为了生育，女性高尚地进化出了更宽的臀部，甚至不惜影响跑步能力','6833-6863',0,1680837046,1782480563);
INSERT INTO highlights VALUES('27256052_15_4137-4884','27256052',82,'认识你自己','人类独有的敏锐视觉是几千万年来被迫进化的结果，其目的就在于发现和躲避蛇的威胁。￼此外，水果也从侧面反映了人类视觉的转变，因为人类进化出颜色识别能力正是为了迅速发现那些成熟可食用的果实。','4012-4470',0,1680797566,1782480563);
INSERT INTO highlights VALUES('27256052_15_3920-3996','27256052',82,'认识你自己','没有一个头脑清晰的女性能容忍糊涂的男性。这一点从古至今都没变过，女性一直都在拒绝或者羞辱不负责任的男性。不过考虑到女性承担着生育的重担，这也不足为怪了。','3795-3871',0,1680797496,1782480563);
INSERT INTO highlights VALUES('27256052_15_2824-2836','27256052',82,'认识你自己','保护远比不上培养和赋能。','2723-2735',0,1680797388,1782480563);
INSERT INTO highlights VALUES('27256052_14_11569-11643','27256052',81,'世界的本质：混乱和秩序','光有秩序是不够的，当你一直稳定、安全和一成不变的时候，就无法学习到重要的新事物。但是当需要学习的东西太多，超过了你的吸收能力时，你又会被混乱所淹没。','11207-11281',0,1680797201,1782480563);
INSERT INTO highlights VALUES('27256052_14_11718-11805','27256052',81,'世界的本质：混乱和秩序','你需要一边依赖已知和已掌握的事物，一边探索和学习新的东西。这样你既可以平衡对未知的恐惧，同时又能保持兴奋和投入的状态。如此一来，你便可以掌握新的，提升旧的，并且发现意义所在。','11356-11443',0,1680797193,1782480563);
INSERT INTO highlights VALUES('27256052_14_11096-11151','27256052',81,'世界的本质：混乱和秩序','当你恰到好处地处在秩序和混乱的交界线上时，生活就会变得跌宕起伏、扣人心弦且充满意义，你也会进入忘我的专注状态。','10734-10789',0,1680797105,1782480563);
INSERT INTO highlights VALUES('27256052_14_9141-9173','27256052',81,'世界的本质：混乱和秩序','犹太教的大卫星就是由向下指的女性三角形和向上指的男性三角形所组成','8855-8887',0,1680796838,1782480563);
INSERT INTO highlights VALUES('27256052_14_8294-8343','27256052',81,'世界的本质：混乱和秩序','从古至今，所有的女性平均每人都有过一个孩子，而所有的男性里有一半平均有过两个孩子，另一半则没有后代','8030-8079',0,1680796744,1782480563);
INSERT INTO highlights VALUES('27256052_14_7479-7496','27256052',81,'世界的本质：混乱和秩序','未知的混乱在象征意义上与女性对应。','7243-7260',0,1680796690,1782480563);
INSERT INTO highlights VALUES('27256052_14_7400-7449','27256052',81,'世界的本质：混乱和秩序','秩序受到冲击并失衡后会体现出强大的毁灭性，出现诸如强制迁徙、集中禁闭和意识湮灭的整齐正步等可怕情景','7164-7213',0,1680796689,1782480563);
INSERT INTO highlights VALUES('27256052_14_6528-6821','27256052',81,'世界的本质：混乱和秩序','由于人类的大脑太习惯于关注他人，所以从一开始我们就用自带人格分类的社会化大脑面对未知、混乱的非人类世界。','6313-6365',0,1680250383,1782480563);
INSERT INTO highlights VALUES('27256052_14_6442-6471','27256052',81,'世界的本质：混乱和秩序','这让我们演化出了好奇心，让我们对周遭的世界越发地关注和好奇','6227-6256',0,1680250360,1782480563);
INSERT INTO highlights VALUES('27256052_14_6345-6398','27256052',81,'世界的本质：混乱和秩序','现实就是我们在生存繁衍的过程中所要面对的一切，这当中包括他人的存在、他人对我们的态度，以及他人归属的社群。','6130-6183',0,1680250347,1782480563);
INSERT INTO highlights VALUES('27256052_14_4941-4966','27256052',81,'世界的本质：混乱和秩序','人们在感知物体的客观属性之前就已经赋予其人格属性了','4777-4802',0,1680250182,1782480563);
INSERT INTO highlights VALUES('27256052_14_4097-4134','27256052',81,'世界的本质：混乱和秩序','实体属于没有意识的客观世界，混乱和秩序则不一样，人们通常将它们理解为人格，','3970-4007',0,1680250156,1782480563);
INSERT INTO highlights VALUES('27256052_14_2837-2912','27256052',81,'世界的本质：混乱和秩序','这是他作为一个木偶此生最大的挑战，完成之后他才有可能变成真正的人类，才能将自己从谎言、掩饰、伤害、冲动和极权主义中解救出来，成为世界上一个真实的存在。','2765-2840',0,1680184428,1782480563);
INSERT INTO highlights VALUES('27256052_14_2137-2174','27256052',81,'世界的本质：混乱和秩序','秩序是人们戴上的社交面具，是文明的陌生人聚集时的客套，是谨慎维护的脆弱边界','2065-2102',0,1680184137,1782480563);
INSERT INTO highlights VALUES('27256052_14_1710-1750','27256052',81,'世界的本质：混乱和秩序','混乱的本质是无知和未知，它永远都在无限延伸，超越所有已知状态、思想和学科的边界。','1638-1678',0,1680139953,1782480563);
INSERT INTO highlights VALUES('27256052_14_1621-1681','27256052',81,'世界的本质：混乱和秩序','混乱和秩序的无尽纠缠让人们质疑存在的意义，绝望地举手投降，并迷失自我。而对意识的恰当理解又可以为人们指明走出困境的方向。','1549-1609',0,1680139946,1782480563);
INSERT INTO highlights VALUES('27256052_14_1535-1575','27256052',81,'世界的本质：混乱和秩序','这些成分一个是混乱，一个是秩序，还有一个则是调和混乱与秩序的过程，即所谓的意识。','1463-1503',0,1680139934,1782480563);
INSERT INTO highlights VALUES('27256052_14_1427-1460','27256052',81,'世界的本质：混乱和秩序','经验世界其实也存在一些原始组成，它们通过彼此互动书写了人生的戏剧。','1355-1388',0,1680139929,1782480563);
