INSERT INTO highlights VALUES('27256052_12_4304-4381','27256052',139,'走出失败者模式','因此，谨慎对待你的体态，别再低头徘徊。说你所想，追你所求，这是你和他人同样拥有的权利。挺胸迈步，直视前方，敢于冒险，这样你的神经通路才能充满急需的血清素。','4204-4281',0,1679972380,1782480563);
INSERT INTO highlights VALUES('27256052_12_3787-3845','27256052',139,'走出失败者模式','你会看见恶龙镇守的黄金，而不是被恶龙的存在吓退；你会在支配等级中找准自己的位置，占据领地，并且做好防守和扩张的准备。','3687-3745',0,1679972335,1782480563);
INSERT INTO highlights VALUES('27256052_12_3666-3704','27256052',139,'走出失败者模式','因为你不单只是一具肉体，你也有思想，物理层面的挺立也可以激发精神层面的挺拔。','3566-3604',0,1679972315,1782480563);
INSERT INTO highlights VALUES('27256052_12_3047-3095','27256052',139,'走出失败者模式','如果让你调整面部表情，做出悲伤的样子，你会感到更加悲伤；如果做出快乐的表情，你也会感到更加快乐。','2962-3010',0,1679972279,1782480563);
