INSERT INTO highlights VALUES('27256052_9_4910-5002','27256052',76,'生物界的领地之争','龙虾会像拳击手一样四处挥舞它那张开的钳子，镜像模仿对手，前后左右移动。同时它会使用眼睛下方的喷嘴向对手喷射液体，这种液体里的化学物质会告诉对手自己的体型大小、性别、健康程度和情绪状态。','4693-4785',0,1679742941,1782480563);
