INSERT INTO highlights VALUES('27256052_7_610-655','27256052',76,'生物界的领地之争','你和龙虾的共同点可能比你想象的要多， INSERT INTO highlights VALUES('27256052_6_6484-6536','27256052',73,'引言 如何抵御自我的不足与无知','为什么最终决定叫“人生十二法则”呢？最主要的原因是，它能很简洁地表明，人们需要指导规则，否则就会陷入混乱','6405-6457',0,1679739038,1782480563);
INSERT INTO highlights VALUES('27256052_6_5909-6050','27256052',73,'引言 如何抵御自我的不足与无知','这个世界如何才能够摆脱冲突与心理和社会解体之间可怕的两难境地？答案是：通过提升和发展个体，通过让每个人都主动地承担存在的重负。每个人都应该为自己、社会和世界承担尽可能多的责任，坚持真理，修补缺憾，这样人们才可以减少毒害世界的苦难。','5830-5964',0,1679738969,1782480563);
INSERT INTO highlights VALUES('27256052_6_5814-5880','27256052',73,'引言 如何抵御自我的不足与无知','人们是有可能超越对集体教条的盲目坚持，同时又避免陷入另一个极端的虚无主义陷阱的，人们也是可以在个体的意识和体验当中找到足够的意义的。','5735-5801',0,1679738808,1782480563);
INSERT INTO highlights VALUES('27256052_6_5272-5351','27256052',73,'引言 如何抵御自我的不足与无知','做了一个梦，梦见自己悬挂在半空中，紧紧抓着房顶的吊灯，离地面有好几层楼的高度，而头顶则是广阔的穹顶。地上的人显得遥远又渺小，我离四周的墙面和房顶的距离也很远。','5193-5272',0,1679738712,1782480563);
INSERT INTO highlights VALUES('27256052_6_5418-5440','27256052',73,'引言 如何抵御自我的不足与无知','我意识到自己所处的穹顶下方恰好就是信仰的中心','5339-5361',0,1679738708,1782480563);
INSERT INTO highlights VALUES('27256052_6_5050-5125','27256052',73,'引言 如何抵御自我的不足与无知','。西方人对传统、宗教和国家文化的逐步放弃，就是为了减少群体冲突的可能性，但与此同时，人们也越来越频繁地面对绝望和无意义感，所以这根本算不上是一种进步。','4971-5046',0,1679649994,1782480563);
INSERT INTO highlights VALUES('27256052_6_4945-4989','27256052',73,'引言 如何抵御自我的不足与无知','没有价值就没有意义，然而，不同的价值体系之间有可能会产生冲突，所以我们永远处在两难之中。','4866-4910',0,1679649934,1782480563);
INSERT INTO highlights VALUES('27256052_6_4822-4916','27256052',73,'引言 如何抵御自我的不足与无知','我们脆弱有限的生命里还包含痛苦和焦虑，因此我们必须用一些东西来对抗存在的固有痛苦。我们必须找到隐藏在深刻价值体系里的意义，否则存在的恐怖就会变得难以承受，然后绝望的虚无主义就会向我们招手。','4743-4837',0,1679649820,1782480563);
INSERT INTO highlights VALUES('27256052_6_4658-4732','27256052',73,'引言 如何抵御自我的不足与无知','共享的文化体系不仅能让人类的互动更加稳定，同时它也是一种价值等级体系，能赋予事物清晰的主次顺序。当缺失这样一个体系时，人们就会不知所措，甚至无法感知','4579-4653',0,1679649786,1782480563);
INSERT INTO highlights VALUES('27256052_6_4595-4629','27256052',73,'引言 如何抵御自我的不足与无知','因此，也不难理解人们会为了能使自己免于陷入混乱和恐惧情绪的事物而战。','4516-4550',0,1679649754,1782480563);
INSERT INTO highlights VALUES('27256052_6_4208-4260','27256052',73,'引言 如何抵御自我的不足与无知','在心理和行为上共享的信仰体系简化了人们眼中看到的彼此，甚至简化了整个世界，因为人们可以通过合作来征服世界','4129-4181',0,1679649676,1782480563);
INSERT INTO highlights VALUES('27256052_6_4069-4106','27256052',73,'引言 如何抵御自我的不足与无知','然后我意识到共同的信仰体系可以让人们理解彼此，而且这些体系不仅只关乎信仰。','3990-4027',0,1679649592,1782480563);
