INSERT INTO highlights VALUES('27256052_4_8685-8742','27256052',72,'推荐序 最重要的法则：为自己的人生负责','如果你用钥匙划坏最聪明的后现代相对主义教授的奔驰车，你就可以看到相对主义的面具和激进包容的伪装是如何被迅速脱下的。','8474-8531',0,1678974924,1782480563);
INSERT INTO highlights VALUES('27256052_4_8542-8557','27256052',72,'推荐序 最重要的法则：为自己的人生负责','人类的存在不可能不需要道德观。','8334-8349',0,1678974871,1782480563);
INSERT INTO highlights VALUES('27256052_4_8291-8358','27256052',72,'推荐序 最重要的法则：为自己的人生负责','对于古人来说，发现不同的人拥有不同的人生观并没有让他们陷入困境，反而加深了他们对于人性的理解，也引发了一些有关人生的最具启发性的对话。','8086-8153',0,1678974848,1782480563);
INSERT INTO highlights VALUES('27256052_4_7664-7744','27256052',72,'推荐序 最重要的法则：为自己的人生负责','人们随着对历史了解的不断深入，也越来越能看清不同时代拥有的不同道德准则。走遍世界之后，你也会发现，不同地区人们的道德准则其实是建立在自己所处社会的特定框架中的。','7468-7548',0,1678974744,1782480563);
INSERT INTO highlights VALUES('27256052_4_7583-7618','27256052',72,'推荐序 最重要的法则：为自己的人生负责','在一个相对主义的社会里，有时候唯一愿意提供建议的往往是那些最无知的人。','7390-7425',0,1678974729,1782480563);
INSERT INTO highlights VALUES('27256052_4_7371-7416','27256052',72,'推荐序 最重要的法则：为自己的人生负责','向他人宣传你的美德并不能体现你的美德，你只是在进行自我推销，而这有可能是人们最常见的恶习。','7181-7226',0,1678974685,1782480563);
INSERT INTO highlights VALUES('27256052_4_7117-7233','27256052',72,'推荐序 最重要的法则：为自己的人生负责',unistr('并站在经验和观察而非猜想的角度讨论了人类幸福的问题。培养区分善恶的能力是获取智慧的第一步，这是永不过时的道理。\u000a相比之'),'6930-7043',0,1678933790,1782480563);
INSERT INTO highlights VALUES('27256052_4_6681-6765','27256052',72,'推荐序 最重要的法则：为自己的人生负责','这种对包容的强调如此之强，以至于对很多人来说，拥有评价的态度就成了一个人最大的人格缺陷。既然我们无法区分对错和好坏，那么一个成年人给年轻人生活建议的行为就是很不恰当的。','6500-6584',0,1678933151,1782480563);
INSERT INTO highlights VALUES('27256052_4_6217-6262','27256052',72,'推荐序 最重要的法则：为自己的人生负责','。人们在希望摆脱规则的同时，也在寻找一种有序的结构。','6042-6087',0,1678932831,1782480563);
INSERT INTO highlights VALUES('27256052_4_5779-5794','27256052',72,'推荐序 最重要的法则：为自己的人生负责','而彼得森则更关注那些成功的英雄','5610-5625',0,1678932780,1782480563);
INSERT INTO highlights VALUES('27256052_4_5282-5350','27256052',72,'推荐序 最重要的法则：为自己的人生负责','抚养小孩、工作、衰老、患病和死亡都会让人感到痛苦，而当你需要独自面对一切，既没有亲密关系的支持，也没有心理层面的指引时，情况只会雪上加霜','5117-5185',0,1678932737,1782480563);
INSERT INTO highlights VALUES('27256052_4_4510-4552','27256052',72,'推荐序 最重要的法则：为自己的人生负责','针对这种狂妄自大，彼得森在本书中提出了一条重要的法则：批判世界之前先清理自己的房间。','4351-4393',0,1678932620,1782480563);
INSERT INTO highlights VALUES('27256052_4_3715-3782','27256052',72,'推荐序 最重要的法则：为自己的人生负责','不同的文化创造出了不同的故事，以帮助人们理解和应对从出生时就要面对的混乱，这种混乱包括所有未知的事物，以及所有外在或内在未探寻的领域。','3594-3661',0,1678932445,1782480563);
INSERT INTO highlights VALUES('27256052_4_3133-3212','27256052',72,'推荐序 最重要的法则：为自己的人生负责','彼得森虽然受训于行为主义流派，但对研究梦境、原型、童年创伤和防御机制的精神分析十分着迷。此外，彼得森也是多伦多大学心理学系唯一一位同时从事临床实践的教职人员。','3021-3100',0,1678932383,1782480563);
INSERT INTO highlights VALUES('27256052_4_2668-2705','27256052',72,'推荐序 最重要的法则：为自己的人生负责','彼得森喜欢通过他人看到事物的另一面，对他来说，思考显然就是一个对话的过程。','2565-2602',0,1678932348,1782480563);
INSERT INTO highlights VALUES('27256052_4_729-812','27256052',72,'推荐序 最重要的法则：为自己的人生负责','如果没有规则，我们很快就会成为自己情绪的奴隶，而这种情况是毫无自由可言的。当不受约束地用未经训练的本能做判断时，我们不仅会缺乏追求，还会崇拜那些不值得我们崇拜的品质。','653-736',0,1678932089,1782480563);
INSERT INTO highlights VALUES('27256052_4_598-621','27256052',72,'推荐序 最重要的法则：为自己的人生负责','人们并不喜欢规则，所以规则要有，但也不要有太多','525-548',0,1678932069,1782480563);
INSERT INTO highlights VALUES('27256052_3_2491-2579','27256052',136,'Jordan B. Peterson 乔丹·彼得森','在书中，彼得森列举的十二条法则，是他运用当代脑神经科学，融合荣格的集体潜意识、尼采的上帝之死、文学中的反乌托邦及边缘人格，与几千年前的神话、宗教及哲学思想相结合后梳理出来的结果','2669-2757',NULL,1675822775,1782480563);
INSERT INTO highlights VALUES('27256052_3_2382-2411','27256052',136,'Jordan B. Peterson 乔丹·彼得森','彼得森说，人类只要一适应幸福的状态，就又会开始觉得不幸福。','2560-2589',NULL,1675822752,1782480563);
