INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_23_2021-2063','CB_5ep7mx7jk2bn6jn6kg8w54br',23,'21 Roadster 特斯拉，2004—2006年','就是车企要尽可能自己生产关键部件，而不是采购独立供应商的数百个零部件后再组装成一辆车','2021-2063',5,1707658802,1782480559);
INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_22_8531-8589','CB_5ep7mx7jk2bn6jn6kg8w54br',22,'20 联合创始人 特斯拉，2003—2004年','艾伯哈德担任首席执行官，塔彭宁担任总裁，施特劳贝尔担任首席技术官，赖特担任首席运营官，马斯克是董事会主席和主要投资人','8531-8589',5,1707658130,1782480559);
