INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_22_6598-6640','CB_5ep7mx7jk2bn6jn6kg8w54br',22,'20 联合创始人 特斯拉，2003—2004年','由于新车会采用所谓的“感应电机”，他想到了以该设备的发明者尼古拉·特斯拉来命名公司。','6598-6640',5,1707654038,1782480559);
INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_22_6237-6275','CB_5ep7mx7jk2bn6jn6kg8w54br',22,'20 联合创始人 特斯拉，2003—2004年','双方达成的协议是，艾伯哈德将从AC推进公司获得电机和动力传动系统的授权许可。','6237-6275',5,1707653989,1782480559);
INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_21_8130-8356','CB_5ep7mx7jk2bn6jn6kg8w54br',21,'19 前往华盛顿 SpaceX，2002—2003年','SpaceX开创了另一种方式，由私营公司竞标执行特定的任务，比如将政府需要的有效载荷发射到轨道上。这些公司用自己的资金承担风险，只有当他们完成某些关键验收环节时才能得到报酬。这种基于发射结果的固定价格合同允许私营公司掌控火箭的设计和制造过程，其参数范围没有被规定死，而是更灵活、更宽泛。如果它打造的火箭具有成本效益，获得了成功，就可以赚很多钱，但如果失败了，就会损失很多钱。马斯克说：“这种机制是结果导向的激励方式，而不是鼓励你在建造过程中浪费资源。”','8130-8356',5,1707643131,1782480559);
INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_21_7562-7591','CB_5ep7mx7jk2bn6jn6kg8w54br',21,'19 前往华盛顿 SpaceX，2002—2003年','它加速了NASA和国防部对过去常用的成本加成合同进行替代。','7562-7591',5,1707642040,1782480559);
