INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_17_3013-3148','CB_5ep7mx7jk2bn6jn6kg8w54br',17,'15 火箭人 SpaceX，2002年','应该说这一次谈崩了，对马斯克来说，是塞翁失马，他因此想得更远：他不只是要发射一枚二手火箭，在火星上放一个示范性的温室，他还要构思一场更大胆的冒险——我们这个时代最无畏的冒险之一，即通过私营公司来建造火箭，用它来发射卫星，将人类送入太空轨道，最终把人类送到火星和其他地方。','3013-3148',5,1707628391,1782480559);
