INSERT INTO highlights VALUES('CB_5ep7mx7jk2bn6jn6kg8w54br_16_4543-4595','CB_5ep7mx7jk2bn6jn6kg8w54br',16,'14 火星 SpaceX，2001年','第一，他发现技术进步并不是必然的，戳穿这一点既令人感到惊讶，也让人心生恐惧——技术可能停滞，也可能倒退。','4543-4595',5,1707626536,1782480559);
