INSERT INTO highlights VALUES('42689053_23_34730-34784','42689053',48,'14 未来','其中一半权重衡量的是受过各种级别的教育的绝对人数，另一半衡量的是质量，如高校排名、考试成绩和平均受教育年限。','35259-35313',NULL,1674128751,1782480564);
INSERT INTO highlights VALUES('42689053_23_32762-32847','42689053',48,'14 未来','了解所有的可能性，考虑最坏的情况，然后想办法消除无法忍受的情况。首先要确定和消除无法忍受的最坏情况。这是因为，在生活或市场的博弈中，最重要的是不要被淘汰出局','33246-33338',NULL,1674128471,1782480564);
INSERT INTO highlights VALUES('42689053_23_33184-33233','42689053',48,'14 未来','因为已经考虑到了最坏的情况，（在清楚这一点后）这就让我拥有了安全感、自由度和能力去追求伟大的成果。','33675-33724',NULL,1674128369,1782480564);
INSERT INTO highlights VALUES('42689053_23_32405-32436','42689053',48,'14 未来','由此引出了本章的最后一点：如何基于人们很可能出错的假设而下注。','32875-32906',NULL,1674128285,1782480564);
INSERT INTO highlights VALUES('42689053_23_32307-32368','42689053',48,'14 未来','没有任何一起未来事件被精准详尽地预言过。对投资者而言，最重要的是对未来有相对正确的预测，而不是准确地理解历史，那是没用的。','32777-32838',NULL,1674128262,1782480564);
INSERT INTO highlights VALUES('42689053_23_31309-31336','42689053',48,'14 未来','因为人们在经济景气时对抗性较弱，在不景气时对抗性较强。','31779-31806',NULL,1674127944,1782480564);
INSERT INTO highlights VALUES('42689053_23_31157-31186','42689053',48,'14 未来','因此我不大担忧经济低迷的影响，而是更担忧滥发货币和货币贬值','31627-31656',NULL,1674127919,1782480564);
INSERT INTO highlights VALUES('42689053_23_30945-31014','42689053',48,'14 未来','我的猜测是下一次经济低迷将比往常来得更早。我估计在本书出版后4年左右会发生下一次经济低迷，误差是两三年（最晚不晚于从触底算起大约5年半）。','31415-31484',NULL,1674127880,1782480564);
INSERT INTO highlights VALUES('42689053_23_30801-30855','42689053',48,'14 未来','再往前的几个周期分别始于2001年、1990年、1982年、1980年、1974年、1970年和1960年等','31271-31325',NULL,1674127880,1782480564);
INSERT INTO highlights VALUES('42689053_23_30281-30353','42689053',48,'14 未来','未来10年里，最重要的动态是短期债务/货币/经济周期（也称商业周期）、内部政治周期以及中美之间不断升级的冲突和日益降低的相互依赖。','30751-30816',NULL,1674127671,1782480564);
INSERT INTO highlights VALUES('42689053_23_26963-27080','42689053',48,'14 未来','你可以看到，美国现在是最强大的国家，但正在衰落，中国紧随其后，正在迅速崛起。你可以看到美国在哪些方面极强，即储备货币地位、军事实力、经济产出、创新与技术、教育，也可以看到美国在哪些方面不强，即内部冲突、贫富差距、债务负担和预期增长率。','27395-27512',NULL,1674127411,1782480564);
INSERT INTO highlights VALUES('42689053_23_26120-26187','42689053',48,'14 未来','此外还存在没有展示的其他决定因素，因为这些因素要么太主观，要么太难加以量化（如领导力）。领导力的质量无法像经济产量一样得到客观的衡量。','26552-26619',NULL,1674127024,1782480564);
INSERT INTO highlights VALUES('42689053_23_22717-22811','42689053',48,'14 未来','我用相互保证毁灭来平衡艾利森的这些历史洞见，相互保证毁灭会降低战争风险。总体上，我的结论是未来10年里爆发大规模战争的概率是35%左右，这基本上是一个大略猜测。无论如何，这都是非常危险的。','23121-23215',NULL,1674126170,1782480564);
INSERT INTO highlights VALUES('42689053_23_21625-21666','42689053',48,'14 未来','中美之间看起来不可调和的主要分歧是台湾问题，所以我密切关注台海局势。','22009-22043',NULL,1674122801,1782480564);
INSERT INTO highlights VALUES('42689053_23_21213-21369','42689053',48,'14 未来','在可预见的未来，中国和美国将有足够实力对彼此造成不可接受的伤害，所以相互保证毁灭的前景应该可以防止军事战，尽管我几乎可以肯定两国会发生危险的小规模冲突。我认为情况会是这样，除非出现一种情况：某种意想不到的技术突破，如量子计算的巨大进步，给其中一个大国带来巨大的不对称优势，导致相互保证毁灭不复存在。','21597-21746',NULL,1674122767,1782480564);
INSERT INTO highlights VALUES('42689053_23_19616-19694','42689053',48,'14 未来','如以前的案例、特别是1930—1945年的案例所示，从这4种类型的战争发展到军事战，通常需要5~10年的时间。虽然中美军事战的风险似乎相对较低，但正在加大。','19984-20062',NULL,1674122462,1782480564);
INSERT INTO highlights VALUES('42689053_23_19528-19597','42689053',48,'14 未来','基于我们看到的情况，美国和中国显然处于4种类型的战争（贸易/经济战、技术战、资本战和地缘政治战）之中，这些战争虽然不是很激烈，但正在加剧。','19896-19965',NULL,1674122446,1782480564);
INSERT INTO highlights VALUES('42689053_23_17875-17993','42689053',48,'14 未来','历史告诉我们，扭转衰落是很难的，因为这需要逆转许多已经做过的事情。例如，如果一个人的支出大于收入，负债大于资产，那么只有通过努力工作或减少消费，才能扭转这样的情况。问题是我们美国人能否诚实面对挑战，为应对挑战而调适和改变。','18195-18306',NULL,1674117772,1782480564);
INSERT INTO highlights VALUES('42689053_23_17630-17645','42689053',48,'14 未来','当前的风险很高，但并非史无前例','17950-17965',NULL,1674117731,1782480564);
INSERT INTO highlights VALUES('42689053_23_16785-16903','42689053',48,'14 未来','美国国内的总体冲突水平现已达到自20世纪60年代末的民权运动和抗议越南战争以来的最高水平，但意义不如当时。“内部纷争”（这主要反映街头示威情况）指数处于中等偏高水平，而“政治冲突”指数处于20世纪20年代初以来的最高水平。','17068-17179',NULL,1674117679,1782480564);
INSERT INTO highlights VALUES('42689053_23_16473-16530','42689053',48,'14 未来','虽然美国看起来正处于不稳定的第五阶段，但美国也拥有持续时间最长、最广受推崇的内部秩序（其宪法体系）。','16756-16806',NULL,1674117055,1782480564);
INSERT INTO highlights VALUES('42689053_23_14545-14559','42689053',48,'14 未来','和平带来收益，战争造成损失。','14791-14805',NULL,1674116832,1782480564);
INSERT INTO highlights VALUES('42689053_23_5551-5635','42689053',48,'14 未来','● 尽管从过去推断未来通常是一种合理的做法，但出现令人惊奇的事也不意外，因为未来将和你预计的大为不同。','5591-5689',NULL,1674058398,1782480564);
INSERT INTO highlights VALUES('42689053_23_11412-11647','42689053',48,'14 未来','，以世界储备货币尤其是以美元计价的付款承诺规模太大、增加太快，无法用硬通货来支付。换言之，以这些货币计价的债务过剩，因此可能需要印钞来偿还债务，债务增长￼和利率可能会维持在低于通胀率和经济/收入增长率的水平。','11588-11822',NULL,1674053419,1782480564);
INSERT INTO highlights VALUES('42689053_23_8122-8231','42689053',48,'14 未来','。但首先我想分享一些关于5个决定因素的总体想法，这5个因素在过去影响最大，我相信也会对未来几年产生最大的影响。这5个因素是创新、债务/货币/资本市场周期、内部秩序和混乱周期、外部秩序和混乱周期、自然灾害。','8281-8383',NULL,1674053419,1782480564);
INSERT INTO highlights VALUES('42689053_23_11806-11837','42689053',48,'14 未来','长远来看，最大的风险是“货币价值”风险，而大多数人对此重视不足','11981-12012',NULL,1674053419,1782480564);
INSERT INTO highlights VALUES('42689053_23_11996-12054','42689053',48,'14 未来','主要风险不是这些大债务人会违约，而是债权人持有的资产将会贬值，即持有债务资产带来的回报率将低于通胀率。','12171-12222',NULL,1674053419,1782480564);
INSERT INTO highlights VALUES('42689053_23_1797-1826','42689053',48,'14 未来','最重要的东西总是以很容易看到和推断的方式发展','1744-1766',NULL,1674045110,1782480564);
INSERT INTO highlights VALUES('42689053_23_1537-1679','42689053',48,'14 未来','我的做法基于我对三点的想法：（a）进化，随时间推移而产生的变化通常带来改进，如生产率提高；（b）周期，即在经济中引起有节奏的起伏（如债务泡沫和泡沫的破裂）和其间的颠簸（非节奏的起伏，如自然灾害）；（c）指标，可以帮助我们看到当下在周期中所处的位置和接下来可能发生的情况。','1484-1619',NULL,1674045042,1782480564);
INSERT INTO highlights VALUES('42689053_21_24801-24845','42689053',46,'13 中美关系和战争','当我和世界领导人交谈时，我发现他们对这盘多维棋局中其他人的真实想法知之甚少，这让我震惊。','24727-24771',NULL,1674038504,1782480564);
INSERT INTO highlights VALUES('42689053_21_21325-21372','42689053',46,'13 中美关系和战争','中国的传统文化使中国人较易接受政府确定的方向，美国的文化则使美国人愿意就要做什么与政府展开对抗','21231-21278',NULL,1674037939,1782480564);
INSERT INTO highlights VALUES('42689053_21_19527-19567','42689053',46,'13 中美关系和战争','当国家出现严重的内部混乱时，这是敌对国家积极利用其弱点的合适时机。','19384-19417',NULL,1674032691,1782480564);
INSERT INTO highlights VALUES('42689053_21_18865-18894','42689053',46,'13 中美关系和战争','大多数知情人士的唯一共识是，这样一场战争将会超乎想象的可怕','18708-18737',NULL,1674025248,1782480564);
INSERT INTO highlights VALUES('42689053_21_18514-18552','42689053',46,'13 中美关系和战争','战争的种类比人们想象的更多，而且在每一种战争中，武器系统比任何人知道的都要多','18357-18395',NULL,1674025224,1782480564);
INSERT INTO highlights VALUES('42689053_21_18394-18436','42689053',46,'13 中美关系和战争','无法想象下一场大的战争会是什么样子，但有可能比任何人想象的更具破坏性。','18230-18265',NULL,1674025213,1782480564);
INSERT INTO highlights VALUES('42689053_21_18021-18054','42689053',46,'13 中美关系和战争','中国伤害美元及美国资本市场的能力较弱，中国最好的举措是增强人民币。','17843-17876',NULL,1674025183,1782480564);
INSERT INTO highlights VALUES('42689053_21_17364-17391','42689053',46,'13 中美关系和战争','不好的方面是，中国的国内债务相对较多，这些债务需要重组','17175-17202',NULL,1674025103,1782480564);
INSERT INTO highlights VALUES('42689053_21_13372-13401','42689053',46,'13 中美关系和战争','资本战的目标是切断敌人的资本，因为没有资金就等于没有实力。','13310-13339',NULL,1674022468,1782480564);
INSERT INTO highlights VALUES('42689053_21_12323-12375','42689053',46,'13 中美关系和战争','未来5~10年，除了其他领域逐步脱钩，我们还将看到哪些国家与中国结盟，哪些国家与美国结盟。','12261-12306',NULL,1674022358,1782480564);
INSERT INTO highlights VALUES('42689053_21_10642-10686','42689053',46,'13 中美关系和战争','希望对战争及其破坏性的恐惧将会阻止战争的发生，就像对相互保证毁灭的恐惧将会阻止战争一样。','10581-10625',NULL,1674022154,1782480564);
INSERT INTO highlights VALUES('42689053_21_10291-10447','42689053',46,'13 中美关系和战争','如果“台海危机”再次出现，那么我会非常担心。美国会为台湾而出击吗？这一点不能确定。如果美国不出击，那么这对中国来说将是巨大的地缘政治胜利，对美国来说将是巨大的耻辱。这将标志着美国在太平洋及其他地区的势力衰落，就像英国丢失苏伊士运河标志着大英帝国在中东及其他地方的终结一样。其影响将远远超出这些损失。','10230-10386',NULL,1674022098,1782480564);
INSERT INTO highlights VALUES('42689053_21_8650-8693','42689053',46,'13 中美关系和战争','两国科技正在脱钩，这是中美在更大范围内脱钩的一个方面，这将对5年后的世界产生巨大影响。','8590-8633',NULL,1674016516,1782480564);
INSERT INTO highlights VALUES('42689053_21_6132-6175','42689053',46,'13 中美关系和战争','在接下来的5~10年里，中国会以比美国快得多的速度，降低对可能被切断的外部供给的依赖。','6073-6116',NULL,1674015972,1782480564);
INSERT INTO highlights VALUES('42689053_20_26043-26170','42689053',45,'12 中国和人民币的大周期兴起','简言之，辩证唯物主义是这样一种系统：通过观察和影响“对立面”的“矛盾”来创造变化，由此带来“斗争”，“斗争”的解决意味着进步的发生。马克思想把辩证唯物主义应用到一切事物上。体现为资本主义与共产主义冲突的两个阶级之间的冲突和斗争，只是许多此类冲突中的一个。','25896-26023',NULL,1673919934,1782480564);
INSERT INTO highlights VALUES('42689053_20_23625-23693','42689053',45,'12 中国和人民币的大周期兴起','但就中国政策制定者对货币、信贷、货币政策、财政政策和对如何重组坏账的理解而言，我发现他们有着深刻而永恒的视角，犹如他们对自己历史的洞见。','23478-23546',NULL,1673919643,1782480564);
INSERT INTO highlights VALUES('42689053_20_21390-21430','42689053',45,'12 中国和人民币的大周期兴起','当你看到一种货币受到资本管制时，特别是当存在严重的国内债务问题时，远离这种货币。','21149-21189',NULL,1673919425,1782480564);
INSERT INTO highlights VALUES('42689053_20_21227-21275','42689053',45,'12 中国和人民币的大周期兴起','衡量一种货币是否具有真实价值的标准是，它是不是被积极使用，是不是在国际和国内以同样的汇率进行交易','20991-21039',NULL,1673919354,1782480564);
INSERT INTO highlights VALUES('42689053_20_19786-19811','42689053',45,'12 中国和人民币的大周期兴起','1933年，中国选择创造本国金属货币，并开始流通。','19590-19615',NULL,1673863380,1782480564);
INSERT INTO highlights VALUES('42689053_20_16507-16560','42689053',45,'12 中国和人民币的大周期兴起','传统的中国军事哲学认为，赢得战争的理想方式不是打仗，而是悄悄发展自己的力量，不战而屈人之兵。','16296-16342',NULL,1673835836,1782480564);
INSERT INTO highlights VALUES('42689053_20_13859-14087','42689053',45,'12 中国和人民币的大周期兴起','。最终目标是让中国经济总量达到美国的两倍左右，并让经济增长的好处得到广泛分享。','13694-13752',NULL,1673835599,1782480564);
INSERT INTO highlights VALUES('42689053_20_12378-12463','42689053',45,'12 中国和人民币的大周期兴起','美国人冲动，具备战术思维，他们为现在想要的东西而战。大多数中国人具备战略思维，他们为未来想要的东西未雨绸缪。我还发现中国领导人比美国领导人更有哲学意识（他们确实在读哲学）','12215-12300',NULL,1673835409,1782480564);
INSERT INTO highlights VALUES('42689053_20_10146-10160','42689053',45,'12 中国和人民币的大周期兴起','货币问题是帝国衰落的常见原因','10009-10023',NULL,1673835178,1782480564);
INSERT INTO highlights VALUES('42689053_20_9849-9891','42689053',45,'12 中国和人民币的大周期兴起','1. 在王朝发展过程中日益加剧的不平等和财政问题是衰落的关键驱动因素。','9717-9751',NULL,1673835174,1782480564);
INSERT INTO highlights VALUES('42689053_20_8844-8869','42689053',45,'12 中国和人民币的大周期兴起','就中国历史而言，关键的变量是土地所有权分配和土地税','8740-8765',NULL,1673790758,1782480564);
INSERT INTO highlights VALUES('42689053_20_7058-7105','42689053',45,'12 中国和人民币的大周期兴起','这段历史提供的教训至今依然得到当今中国领导人的重视，而且让我很入迷，特别是在历史模式的背景中。','7010-7057',NULL,1673783067,1782480564);
INSERT INTO highlights VALUES('42689053_20_2241-2330','42689053',45,'12 中国和人民币的大周期兴起','在本书开头探讨18个决定因素时，我列出了我认为对一个国家的健康最重要的因素。其中，我强调8种实力指标：教育、竞争力、创新/技术、贸易、经济产出、军事、金融中心地位和储备货币地位。','2187-2276',NULL,1673780698,1782480564);
INSERT INTO highlights VALUES('42689053_19_22570-22657','42689053',44,'11 美国和美元的大周期兴衰','我模型中的数据显示，美国在自身大周期中约处于70%的位置，误差范围为10个百分点。美国还没有越过界限进入第六阶段，即真的战斗打响的内战/革命阶段，但其国内冲突激烈程度日益加剧','22773-22860',NULL,1673780429,1782480564);
INSERT INTO highlights VALUES('42689053_19_18719-18937','42689053',44,'11 美国和美元的大周期兴衰','正如我在《债务危机》一书中详细阐述的那样，货币政策有三种类型：（1）由利率驱动的货币政策（我称之为第一种货币政策，因为这是最先采用的也是最受欢迎的货币政策）；（2）印钞和购买金融资产，其中最主要的是债券（我称之为第二种货币政策，现在被人们普遍称为“量宽”）；（3）协同实施财政政策和货币政策，中央政府进行大量的债务融资支出，央行购买这些债券（我称之为第三种货币政策，因为在前两种政策无法发挥作用的时候，这是第三种也是最后一种调控手段）。','18801-19019',NULL,1673779926,1782480564);
INSERT INTO highlights VALUES('42689053_19_17378-17421','42689053',44,'11 美国和美元的大周期兴衰','在这一时期，机器和其他国家（特别是中国）的工人替代了美国的中产阶级工人。','17422-17458',NULL,1673779771,1782480564);
INSERT INTO highlights VALUES('42689053_19_15470-15538','42689053',44,'11 美国和美元的大周期兴衰','我所忽略的是，如果债务以央行能够印发的货币形式存在，并且央行能够对债务进行重组，那么债务危机就能得到很好的应对，因此不会构成系统性威胁。','15496-15564',NULL,1673779371,1782480564);
INSERT INTO highlights VALUES('42689053_19_7816-7848','42689053',44,'11 美国和美元的大周期兴衰','虽然有许多可能的高风险情况，但在我看来，最让人担忧的是台海局势。','7812-7844',NULL,1673773352,1782480564);
INSERT INTO highlights VALUES('42689053_19_5331-5430','42689053',44,'11 美国和美元的大周期兴衰','在相对意义上，美国是大赢家，因为美国在战前和战争期间出售了很多东西，出借了很多钱，而且基本上所有战斗都发生在美国本土以外，所以美国没有受到实际损害，而且与大多数其他主要国家相比，美国的死亡人数较少。','5335-5434',NULL,1673773129,1782480564);
INSERT INTO highlights VALUES('42689053_19_2010-2065','42689053',44,'11 美国和美元的大周期兴衰','美国以一种独特的和平方式做到了这一切，它通过谈判、对协议近乎完全的尊重以及良好的治理设计，给国家开了一个好头。','1995-2050',NULL,1673671227,1782480564);
INSERT INTO highlights VALUES('42689053_19_856-937','42689053',44,'11 美国和美元的大周期兴衰','目前美国在教育、竞争力和贸易方面的相对优势有所下降，但在创新和科技、储备货币地位、金融市场和金融中心地位方面的优势依然强劲。','803-865',NULL,1673667422,1782480564);
INSERT INTO highlights VALUES('42689053_18_32502-32608','42689053',43,'10 大英帝国和英镑的大周期兴衰','具体来说，欧洲负债规模大，经济基本面不佳，内部矛盾比较大，活力和创新水平比较弱，军事力量不强。欧盟成员国之间和成员国内部的财富与收入不平等助长了民粹主义者的崛起，他们中的很多人反对欧盟，并成功地使英国退出了欧盟。','32855-32961',NULL,1673667340,1782480564);
INSERT INTO highlights VALUES('42689053_18_31827-31848','42689053',43,'10 大英帝国和英镑的大周期兴衰','开放各国边界（1985年，通过《申根协定》','32171-32192',NULL,1673667190,1782480564);
INSERT INTO highlights VALUES('42689053_18_30506-30787','42689053',43,'10 大英帝国和英镑的大周期兴衰',unistr('新世界秩序最重要的金融元素包括：\u000a• 布雷顿森林货币体系确立美元为世界储备货币。\u000a• 国际货币基金组织和世界银行，旨在支持新的全球金融体系。\u000a• 纽约成为新的全球金融中心。'),'30933-31181',NULL,1673666938,1782480564);
INSERT INTO highlights VALUES('42689053_18_30367-30387','42689053',43,'10 大英帝国和英镑的大周期兴衰','联合国成立以解决全球争端。','30804-30817',NULL,1673666900,1782480564);
INSERT INTO highlights VALUES('42689053_18_30102-30119','42689053',43,'10 大英帝国和英镑的大周期兴衰','战后秩序最重要的地缘政治因素包括：','30569-30586',NULL,1673666889,1782480564);
INSERT INTO highlights VALUES('42689053_18_30203-30232','42689053',43,'10 大英帝国和英镑的大周期兴衰','美国是主导性大国，因而成为事实上的世界警察。','30643-30665',NULL,1673666886,1782480564);
INSERT INTO highlights VALUES('42689053_18_23512-23560','42689053',43,'10 大英帝国和英镑的大周期兴衰','美国、英国和苏联战胜，尽管在经济上英国和苏联也失败了，美国在相对财富方面收获巨大。','23735-23776',NULL,1673666287,1782480564);
INSERT INTO highlights VALUES('42689053_18_18550-18684','42689053',43,'10 大英帝国和英镑的大周期兴衰','英国收入最高的10%的人占有惊人的93%的财富。','18662-18686',NULL,1673631017,1782480564);
INSERT INTO highlights VALUES('42689053_18_8054-8073','42689053',43,'10 大英帝国和英镑的大周期兴衰','在18世纪，法国的识字率几乎翻了一番。','8088-8107',NULL,1673630111,1782480564);
INSERT INTO highlights VALUES('42689053_18_7767-7839','42689053',43,'10 大英帝国和英镑的大周期兴衰','假如我活在18世纪早期，观察我设定的指标时，我会看到荷兰仍处于顶峰，波旁王朝统治的法国作为大国也在崛起，当时我会认为这两个国家都处于很好的状态。','7801-7873',NULL,1673630074,1782480564);
INSERT INTO highlights VALUES('42689053_18_3286-3338','42689053',43,'10 大英帝国和英镑的大周期兴衰','这种以人为中心的新哲学的核心思想是，社会应该建立在理性和科学的基础之上，政府的权力来自人民，而不是上帝。','3289-3341',NULL,1673629605,1782480564);
INSERT INTO highlights VALUES('42689053_18_460-616','42689053',43,'10 大英帝国和英镑的大周期兴衰',unistr('世\u000a界秩序的变化发生于两个或两个以上实力相当的国家（或国家联盟）斗争时，一方取胜，成为主导者，有能力制定新的规则，这就是新的世界秩序。在这之前，崛起国需要让本国实力达到与霸权国相当的水平，所以任何大国都是在远未成为大国之前，就开始本国的崛起之旅的。'),'433-556',NULL,1673629328,1782480564);
INSERT INTO highlights VALUES('42689053_17_11958-11983','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','原因是金钱和地缘政治因素比宗教意识形态因素更重要。','12077-12102',NULL,1673628309,1782480564);
INSERT INTO highlights VALUES('42689053_17_12145-12199','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','该和约发明了我们今天所说的国家，亦即，该和约承认了国家主权，承认国家能在其地理边界之内制定决策','12264-12311',NULL,1673598604,1782480564);
INSERT INTO highlights VALUES('42689053_17_11324-11357','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','一方是德国新教贵族，他们分别在不同时期与丹麦、荷兰、瑞典和法国结盟','11444-11477',NULL,1673598568,1782480564);
INSERT INTO highlights VALUES('42689053_17_10380-10412','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','这使荷兰盾成为一种真正的储备货币，这是世界历史上最早的储备货币。','10482-10514',NULL,1673598506,1782480564);
INSERT INTO highlights VALUES('42689053_17_9207-9293','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','16世纪中期，荷兰人在远航事业中引入了股权，这具有革命性。在1600年之前，这些股份只由少数商人持有，在很大程度上缺乏透明性，流动性差，所以这些股份对外部投资者的吸引力有限','9290-9376',NULL,1673598420,1782480564);
INSERT INTO highlights VALUES('42689053_17_9000-9145','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰',unistr('1602年，荷兰人创立了世界上第一家公开上市的公司（荷兰东印度公司）和第一家股票交易所，从而开了先河。\u000a像大多数发明一样，这些资本市场方面的发展也源于必要性和自利需求。'),'9083-9221',NULL,1673598368,1782480564);
INSERT INTO highlights VALUES('42689053_17_8643-8739','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','重申一遍，荷兰人两个最重要的发明是：（1）效能极其优异的帆船，使他们能在世界各地航行，这一点再加上他们从欧洲战事中获得的军事技能，使他们能收集巨大的财富；（2）为这些行动提供推动力的资本主义。','8726-8822',NULL,1673598342,1782480564);
INSERT INTO highlights VALUES('42689053_17_2364-2480','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','哈布斯堡王朝的衰落符合许多典型的情况。没有财富和权力的人向拥有它们的精英发动了革命，挑战现存秩序。如我在前一章中所述，新的宗教思想以宗教改革的形式出现，这是一场反对罗马天主教会的革命，罗马天主教会被视为腐朽的剥削势力。','2348-2457',NULL,1673596933,1782480564);
INSERT INTO highlights VALUES('42689053_17_678-832','42689053',42,'9 荷兰帝国与荷兰盾的大周期兴衰','荷兰在1650年左右达到顶峰，那个时代现在被称为荷兰的黄金时代。虽然荷兰人口不多，领土狭小，无法成为欧洲大陆上的主导性军事大国，但荷兰凭借经济实力、复杂的金融体系和强大的海军，完全弥补了这一劣势。强大的海军能够保护在世界各地拥有交易站和殖民地的荷兰帝国。这使荷兰盾成为历史上第一种全球储备货币。','625-779',NULL,1673596517,1782480564);
INSERT INTO highlights VALUES('42689053_16_13092-13158','42689053',41,'8 过去500年简述','战争结束时，新秩序在《威斯特伐利亚和约》中得以确立。该和约带来的最重要突破是确立各国的地理边界，并规定各国国民拥有决定本国事务的主权','12900-12966',NULL,1673596029,1782480564);
INSERT INTO highlights VALUES('42689053_16_9587-9721','42689053',41,'8 过去500年简述','探险时代开始于15世纪，当时欧洲人在世界各地旅行，寻找财富，历史上第一次在许多不同的民族之间建立起广泛的联系，并开始使世界变小。这个时代与文艺复兴时期大致重合，因为文艺复兴非凡的技术成就转变为造船和航海技术的进步，而远航船带回来的财富为文艺复兴的进一步发展提供了资金。','9348-9482',NULL,1673578080,1782480564);
INSERT INTO highlights VALUES('42689053_16_9221-9296','42689053',41,'8 过去500年简述','我们可以把前文说过的宋明理学视为中国的文艺复兴，因为就像欧洲的文艺复兴一样，它带来了更以逻辑和证据为基础的思维方式，以及更具创造性而非宗教性的世界观。','8982-9057',NULL,1673578010,1782480564);
INSERT INTO highlights VALUES('42689053_16_8106-8172','42689053',41,'8 过去500年简述','文艺复兴是历史上最重大的自我强化循环的案例之一，我在第5章中描述过这种循环：和平时期里，创造力和商业彼此促进，带来经济繁荣和巨大进步','7849-7915',NULL,1673577954,1782480564);
INSERT INTO highlights VALUES('42689053_16_8017-8106','42689053',41,'8 过去500年简述','文艺复兴始于意大利北部的各城邦，在那里，之前的商业革命已创造巨大财富，依靠理智主义和创造活动的帮助，这些财富带来了贸易、生产和银行业的进步。','7760-7830',NULL,1673577901,1782480564);
INSERT INTO highlights VALUES('42689053_16_6571-6708','42689053',41,'8 过去500年简述',unistr('商业革命（12—16世纪）\u000a商业革命是指从单纯以农业为基础的经济形态转变为包括多种商品贸易的经济形态。这场从12世纪开始直到1500年的演进，以意大利城邦为中心，由'),'6314-6451',NULL,1673577638,1782480564);
INSERT INTO highlights VALUES('42689053_16_6415-6513','42689053',41,'8 过去500年简述','你们会发现这些演变和周期具备两方面特征：（1）几次思维方式上的革命带来了延续几百年的巨大演变和进步；（2）许多周期，和平与繁荣时期和萧条、革命与战争时期交替，后者标志着旧秩序的结束和新秩序的开始。','6158-6256',NULL,1673577625,1782480564);
INSERT INTO highlights VALUES('42689053_16_6226-6286','42689053',41,'8 过去500年简述','最重要的变化是导致人们行为变化的思想变化，特别是在财富和权力的分配方式方面。这就是这段历史进程背后的因素。','5969-6022',NULL,1673577605,1782480564);
INSERT INTO highlights VALUES('42689053_16_6385-6513','42689053',41,'8 过去500年简述','在阅读这份对过去500年历史的概述时，请注意这些演变和周期。你们会发现这些演变和周期具备两方面特征：（1）几次思维方式上的革命带来了延续几百年的巨大演变和进步；（2）许多周期，和平与繁荣时期和萧条、革命与战争时期交替，后者标志着旧秩序的结束和新秩序的开始。','6128-6256',NULL,1673527739,1782480564);
INSERT INTO highlights VALUES('42689053_16_4778-4913','42689053',41,'8 过去500年简述','讽刺而同时又具有一般性意义的是，明朝巨大的财富和力量可能正是导致其最终衰落的原因之一。明朝皇帝自以为万物已备，别无他求，所以结束了探索世界的行动，关闭门户，安享生活，把管理政府的工作交给了大臣和宦官，这导致了功能失调性的内斗、腐败、虚弱和易于被攻击的脆弱。','4632-4760',NULL,1673527605,1782480564);
INSERT INTO highlights VALUES('42689053_16_4155-4198','42689053',41,'8 过去500年简述','这种实用的、以证据为基础的、科学的思维方式，是中国在中世纪远远领先于欧洲的关键原因之一','4049-4092',NULL,1673527496,1782480564);
INSERT INTO highlights VALUES('42689053_16_4107-4155','42689053',41,'8 过去500年简述','当时占主导地位的宋明理学，转移了儒家信仰体系的重心，使之变得更加理性化、哲学化、学术化和人文化。','4001-4049',NULL,1673527483,1782480564);
INSERT INTO highlights VALUES('42689053_14_16955-16991','42689053',39,'7 从大周期的角度思考投资','在我撰写本书时，如果你投资于美国和欧洲，那么你可能永远无法收回你的购买力','17103-17139',NULL,1673517971,1782480564);
INSERT INTO highlights VALUES('42689053_14_16033-16063','42689053',39,'7 从大周期的角度思考投资','由此可见，这些指标的以往水平比现在高得多，现在处于极低水平。','16144-16174',NULL,1673517482,1782480564);
INSERT INTO highlights VALUES('42689053_14_13945-14007','42689053',39,'7 从大周期的角度思考投资','，政府只有让利率和债权人的回报率处于低位且不佳，才能为负债过多的债务人提供救济；其次，政府设法通过继续增加债务来刺激经济增长','14000-14062',NULL,1673448673,1782480564);
INSERT INTO highlights VALUES('42689053_14_10653-10705','42689053',39,'7 从大周期的角度思考投资','1900—1914年，贫富悬殊和债务问题恶化，国际紧张局势加剧，导致我刚描述过的最差投资回报时期的到来。','10617-10669',NULL,1673448204,1782480564);
INSERT INTO highlights VALUES('42689053_14_10581-10624','42689053',39,'7 从大周期的角度思考投资','1900年之前，除了财富差距和怨恨情绪日益加剧、债务变得极其庞大外，形势似乎一派大好。','10545-10588',NULL,1673448166,1782480564);
INSERT INTO highlights VALUES('42689053_14_10309-10415','42689053',39,'7 从大周期的角度思考投资','当今的人们往往认为，在一战爆发前的几年，战争的到来一定很容易预见到，但事实并非如此。在一战前的大约50年里，世界主要大国几乎没有发生冲突，世界经历了最伟大的创新和前所未有的生产率增长，由此创造了巨大的财富和繁荣。','10274-10380',NULL,1673448121,1782480564);
INSERT INTO highlights VALUES('42689053_14_6101-6167','42689053',39,'7 从大周期的角度思考投资','大多数投资者面临的三大风险是，投资组合将无法提供支出所需的回报，投资组合将面临破产，以及很大一部分财富会被收走（例如，通过高税收）。','6080-6146',NULL,1673320296,1782480564);
INSERT INTO highlights VALUES('42689053_14_5965-6049','42689053',39,'7 从大周期的角度思考投资','在我看来，投资风险是无法赚取足够的钱来满足需求。它不是用标准差来衡量的波动率，而标准差几乎是用来衡量风险的唯一标准。','5944-6028',NULL,1673320276,1782480564);
INSERT INTO highlights VALUES('42689053_14_5408-5471','42689053',39,'7 从大周期的角度思考投资','信贷发放后，购买力是为了换取支付承诺而产生的。因此从短期来看，信贷刺激经济增长，但从长期来看，信贷抑制经济增长。','5387-5443',NULL,1673319885,1782480564);
INSERT INTO highlights VALUES('42689053_14_5105-5120','42689053',39,'7 从大周期的角度思考投资','如今，金融财富大大超过实物财富','5084-5099',NULL,1673319827,1782480564);
INSERT INTO highlights VALUES('42689053_14_5010-5105','42689053',39,'7 从大周期的角度思考投资','金融财富规模变得如此庞大，以至硬通货（黄金和白银）和其他有形财富（例如财产）变得相对不重要。当然，金融财富的承诺越多，无法兑现承诺的风险就越大。这就是为什么存在典型的债务/货币/经济大周期。','4989-5084',NULL,1673319814,1782480564);
INSERT INTO highlights VALUES('42689053_14_4179-4207','42689053',39,'7 从大周期的角度思考投资','今天我们所知的贷款炼金术最早出现于约1350年的意大利。','4159-4187',NULL,1673319667,1782480564);
INSERT INTO highlights VALUES('42689053_14_2339-2361','42689053',39,'7 从大周期的角度思考投资','经济增速和通胀率高于预期时，债券价格将会下跌','2300-2322',NULL,1673319451,1782480564);
INSERT INTO highlights VALUES('42689053_14_2004-2108','42689053',39,'7 从大周期的角度思考投资','为了影响市场回报和经济形势，中央政府与央行的职责有所不同。中央政府可以征税和支出，其决定政府资金的来源和去向，但不能创造货币和信贷。央行可以创造货币和信贷，但不能决定货币和信贷是否流入实体经济。','1965-2062',NULL,1673275394,1782480564);
INSERT INTO highlights VALUES('42689053_14_1251-1274','42689053',39,'7 从大周期的角度思考投资','所有的投资都是以当前的一次性支付换取未来的支付','1214-1237',NULL,1673257399,1782480564);
INSERT INTO highlights VALUES('42689053_14_1175-1211','42689053',39,'7 从大周期的角度思考投资','所有市场都是由以下4个决定因素驱动的：经济增长、通胀、风险溢价和折现率。','1131-1167',NULL,1673257364,1782480564);
INSERT INTO highlights VALUES('42689053_14_697-752','42689053',39,'7 从大周期的角度思考投资','通过研究过去500年以来的历史，我发现在财富和权力大起大落的大周期中，最重要的驱动因素是长期债务和资本市场周期','644-699',NULL,1673255953,1782480564);
INSERT INTO highlights VALUES('42689053_13_19049-19116','42689053',38,'6 外部秩序和混乱大周期','对投资者来说，出售所有债务和购买黄金是上策。因为国家通过借款和印钞为战争融资，导致债务和货币贬值。在这种情况下，人们也有理由不接受信贷','19267-19334',NULL,1673242754,1782480564);
INSERT INTO highlights VALUES('42689053_13_11399-11419','42689053',38,'6 外部秩序和混乱大周期','法西斯主义倡导专制、资本主义和集体主义。','11512-11532',NULL,1673240705,1782480564);
INSERT INTO highlights VALUES('42689053_13_7230-7263','42689053',38,'6 外部秩序和混乱大周期','运用实力的最好办法通常是隐藏实力，因为炫耀实力会使对手感觉受到威胁','7327-7360',NULL,1673235410,1782480564);
INSERT INTO highlights VALUES('42689053_13_7076-7113','42689053',38,'6 外部秩序和混乱大周期','最好是凭实力来谈判，达成协议，并执行协议，或者当一方的实力最大时进入战争。','7173-7210',NULL,1673235382,1782480564);
INSERT INTO highlights VALUES('42689053_13_6334-6425','42689053',38,'6 外部秩序和混乱大周期','这就引出了最后一个原则：● 获取权力，尊重权力，并明智地运用权力。','6411-6523',NULL,1673235286,1782480564);
INSERT INTO highlights VALUES('42689053_13_6253-6305','42689053',38,'6 外部秩序和混乱大周期','获胜的革命者则认为，这是英国人的愚蠢。为了独立和自由，改变战争规则是正当的。事实就是这样。','6330-6382',NULL,1673235247,1782480564);
INSERT INTO highlights VALUES('42689053_13_5979-6046','42689053',38,'6 外部秩序和混乱大周期','总的来说，双赢与双输关系之间的转变往往具有周期性。在繁荣时期，人们和国家更可能建立合作关系，在萧条时期则更可能发生争斗。','6056-6116',NULL,1673235204,1782480564);
INSERT INTO highlights VALUES('42689053_13_5604-5683','42689053',38,'6 外部秩序和混乱大周期','国家间很容易出现愚蠢的战争。原因包括：（a）囚徒困境，（b）针锋相对的升级过程，（c）衰落中的大国担心让步的代价，（d）在必须快速做出决策的情况下存在的误解。','5681-5760',NULL,1673235144,1782480564);
INSERT INTO highlights VALUES('42689053_13_5482-5511','42689053',38,'6 外部秩序和混乱大周期','获胜意味着在不失去最重要的东西的前提下，得到最重要的东西。','5552-5581',NULL,1673235124,1782480564);
INSERT INTO highlights VALUES('42689053_13_3948-3980','42689053',38,'6 外部秩序和混乱大周期','在财力上超过对手是一个国家能够拥有的最大优势之一。','3958-3983',NULL,1673190507,1782480564);
INSERT INTO highlights VALUES('42689053_13_3318-3419','42689053',38,'6 外部秩序和混乱大周期','，● 对于战争，最可确信的两点：（1）战争不会按计划进行，（2）战争远比想象的更糟糕。','3272-3380',NULL,1673190452,1782480564);
INSERT INTO highlights VALUES('42689053_13_1301-1348','42689053',38,'6 外部秩序和混乱大周期','国家之间的斗争主要有5种类别：贸易/经济战、技术战、地缘政治战、资本战和军事战。','1269-1309',NULL,1673190190,1782480564);
INSERT INTO highlights VALUES('42689053_13_1223-1246','42689053',38,'6 外部秩序和混乱大周期','国际秩序与其说是遵循国际法，不如说是丛林法则。','1191-1214',NULL,1673190156,1782480564);
INSERT INTO highlights VALUES('42689053_13_618-704','42689053',38,'6 外部秩序和混乱大周期','一个主要例外：● 国际关系更多地取决于原始实力的动态机制','565-665',NULL,1673190092,1782480564);
INSERT INTO highlights VALUES('42689053_12_34255-34311','42689053',37,'5 内部秩序和混乱大周期','这些历史研究告诉我，除了进化，没有什么是永恒的。进化过程中存在一些周期，它们像潮水一样起起落落，很难改变或对抗。','34470-34526',NULL,1673189993,1782480564);
INSERT INTO highlights VALUES('42689053_12_34091-34166','42689053',37,'5 内部秩序和混乱大周期','内战和革命是极其痛苦的，但往往带来结构性改革。如果其处理得当，就可以为更好的未来奠定基础。内战/革命之后将会出现怎样的状况，这取决于接下来的行动举措。','34306-34381',NULL,1673189976,1782480564);
INSERT INTO highlights VALUES('42689053_12_33273-33310','42689053',37,'5 内部秩序和混乱大周期','几乎所有内战都有一些外国势力参与，它们试图影响内战的结果，使其对自己有利。','33460-33497',NULL,1673189939,1782480564);
INSERT INTO highlights VALUES('42689053_12_32504-32565','42689053',37,'5 内部秩序和混乱大周期','在经济困难时期，贫富悬殊通常是冲突爆发的最主要因素，但总还有其他因素，这些因素汇合在一起，成为反对现有领导和体制的巨大力量','32677-32738',NULL,1672487921,1782480564);
INSERT INTO highlights VALUES('42689053_12_31586-31641','42689053',37,'5 内部秩序和混乱大周期','在大多数典型的内战与革命中，权力从右派向左派转移，但在一些情况下，财富和权力也从左派向右派转移。','31759-31807',NULL,1672474890,1782480564);
INSERT INTO highlights VALUES('42689053_12_30769-30840','42689053',37,'5 内部秩序和混乱大周期','几乎所有的体制都会经历这些变革。因为几乎所有的体制都以牺牲一些群体为代价，让另一些群体获益，最终前者变得无法忍受，他们通过斗争来改变未来的方向','30945-31016',NULL,1672474626,1782480564);
INSERT INTO highlights VALUES('42689053_12_22503-22529','42689053',37,'5 内部秩序和混乱大周期','把他人妖魔化和当作替罪羊，是一种典型的表现形式和问题','22595-22621',NULL,1672473729,1782480564);
INSERT INTO highlights VALUES('42689053_12_21627-21774','42689053',37,'5 内部秩序和混乱大周期','最近在美国，2016年特朗普当选总统，是向右翼民粹主义迈出的一步，而伯尼·桑德斯、伊丽莎白·沃伦和亚历山德里娅·奥卡西奥—科尔特斯获得了极高的支持率，这表明左翼民粹主义广受欢迎。在许多国家，民粹主义运动日益增多。可以说拜登的胜选表明，人们希望少一些极端主义，多一些温和主义，不过时间会见证一切。','21698-21845',NULL,1672473673,1782480564);
INSERT INTO highlights VALUES('42689053_12_21244-21287','42689053',37,'5 内部秩序和混乱大周期','混乱和不满会滋生这样的领导人：他们具有强烈的个性，反对精英主义，声称会为普通人而奋斗。','21315-21358',NULL,1672473586,1782480564);
INSERT INTO highlights VALUES('42689053_12_19664-19769','42689053',37,'5 内部秩序和混乱大周期','历史和逻辑都表明，有效地投资于各级教育（包括职业培训）、基础设施与能够提高生产率的发明和研究，都会很有成效。例如，尽管从投资到见效所用的时间相当长，但大规模的教育计划和基础设施建设计划几乎总能带来充足的回报（如','19702-19807',NULL,1672472591,1782480564);
INSERT INTO highlights VALUES('42689053_12_14179-14297','42689053',37,'5 内部秩序和混乱大周期','在这一阶段，典型的最佳领导者是“稳扎稳打、纪律严明的领导者”，他们理解和展示高标准的行为准则，实现经济效益，打造稳健财政，他们对大众的过度行为加以约束。在人们变得富裕后，他们带领国家继续把大量收入和时间再投资于生产性活动。','14078-14189',NULL,1672471705,1782480564);
INSERT INTO highlights VALUES('42689053_12_12952-13103','42689053',37,'5 内部秩序和混乱大周期','在这个阶段，值得关注的势态发展是，机会、收入、财富和价值观方面的差距扩大，同时大多数人面临不公平的困难处境；精英享有奢华和对他人不公的特权；生产率下滑；过度创造债务导致财政状况糟糕。这些自然发展趋势对国家构成巨大的风险，破坏自我维持的良好结果。伟大的国家能够实现自我维系，避免这些风险，继续留在第三阶段','12903-13054',NULL,1672471166,1782480564);
INSERT INTO highlights VALUES('42689053_12_13111-13175','42689053',37,'5 内部秩序和混乱大周期','如果不能避免这些风险，国家就会发展到第四阶段，即过度时期。在第四阶段，做成（或通过举债做成）一切的诱惑会将一个国家推至冲突边缘。','13062-13126',NULL,1672471161,1782480564);
INSERT INTO highlights VALUES('42689053_12_10424-10431','42689053',37,'5 内部秩序和混乱大周期','康拉德·阿登纳','10428-10435',NULL,1672470940,1782480564);
INSERT INTO highlights VALUES('42689053_12_7140-7264','42689053',37,'5 内部秩序和混乱大周期','基于我们观察到的历史情况，我们估计当60%~80%的危险信号出现时，爆发严重内部冲突的可能性约为1/6；当大量危险信号出现时（超过80%），爆发内战或革命的可能性约为1/3，虽然可能性依然不大，但已足以令人不安。美国目前处于60%~80%这一区间。','7116-7240',NULL,1672469780,1782480564);
INSERT INTO highlights VALUES('42689053_12_5924-5990','42689053',37,'5 内部秩序和混乱大周期','各国竞相夺取财富和全球政治权力，因此在一些国家崛起的同时，另一些国家走向衰落。全球整体的波动程度比任何单个国家都要小。','5893-5952',NULL,1672468722,1782480564);
INSERT INTO highlights VALUES('42689053_12_4303-4344','42689053',37,'5 内部秩序和混乱大周期','各国相比于其他国家所处的阶段会影响国家之间的关系，也是整个世界秩序的首要决定因素。','4207-4248',NULL,1672468537,1782480564);
INSERT INTO highlights VALUES('42689053_12_1710-1825','42689053',37,'5 内部秩序和混乱大周期','美国正处于我所称的第五阶段，即在财务状况不佳、冲突不断激化的同时，主要国家仍然拥有其他强大实力（如技术和军事），但这些实力正被相对削弱。一般来说，这个阶段出现在支出和债务严重过剩、财富和政治鸿沟扩大的时期之后，以及革命和内战之前。','1651-1766',NULL,1672467091,1782480564);
INSERT INTO highlights VALUES('42689053_11_11841-11875','42689053',36,'4 货币价值的演变','决策者和投资者必须能区分对体系有利的货币贬值和对体系不利的货币贬值。','11873-11907',NULL,1672466318,1782480564);
INSERT INTO highlights VALUES('42689053_11_5915-5967','42689053',36,'4 货币价值的演变','在1910年破裂，造成股市崩盘。有些人认为这是导致债务/货币/经济下行、促使中国封建帝国终结的一个因素。','5852-5904',NULL,1672455715,1782480564);
INSERT INTO highlights VALUES('42689053_11_5866-5878','42689053',36,'4 货币价值的演变','橡胶生产股引发的股市泡沫','5803-5815',NULL,1672455712,1782480564);
INSERT INTO highlights VALUES('42689053_11_5568-5617','42689053',36,'4 货币价值的演变','这一繁荣时期被称为第二次工业革命。在此期间，借款者用借来的资金获取了收入，因而能够以高利率偿还债务','5505-5554',NULL,1672455629,1782480564);
INSERT INTO highlights VALUES('42689053_10_21221-21326','42689053',35,'3 货币、信贷、债务和经济活动的大周期','对大多数人来说，债务越濒临崩溃（此时的未偿债权与硬通货和有形财富的比率最大），境况越危险，人们往往越感觉安全。这是因为他们一直持有债务，享受着债务带来的回报，而距离上一次债务危机的时间越长，人们对它的记忆就越淡','21208-21313',NULL,1672396900,1782480564);
INSERT INTO highlights VALUES('42689053_10_17083-17127','42689053',35,'3 货币、信贷、债务和经济活动的大周期','这一做法通常会显著推高金融资产价格，却不能有效地将资金、信贷和购买力送到最需要的人手中。','17130-17174',NULL,1672389939,1782480564);
INSERT INTO highlights VALUES('42689053_10_16078-16181','42689053',35,'3 货币、信贷、债务和经济活动的大周期','这是因为没有任何一个决策者能掌控整个长期债务周期。每个决策者只参与这个周期的一个或几个部分，他们根据当时的情况做出符合自身利益的、当时认为是最好的决策（包括违背承诺，尽管他们对整个周期的整体处理方式不佳）。','16105-16208',NULL,1672389175,1782480564);
INSERT INTO highlights VALUES('42689053_10_15929-16077','42689053',35,'3 货币、信贷、债务和经济活动的大周期','西方历史表明，● 我们不应该依靠政府来保护钱财。相反，我们应该预料到，大多数政府会滥用它们作为货币和信贷创造者与使用者的特权，如果你处在他们的位置，那么也可能出于同样的理由滥用特权','15935-16104',NULL,1672389170,1782480564);
INSERT INTO highlights VALUES('42689053_10_12402-12464','42689053',35,'3 货币、信贷、债务和经济活动的大周期','起初，硬通货债权票据的数量与银行里储存的硬通货一样多。之后，债权票据的持有者和银行共同发现了信贷和债务的奥妙。','12402-12457',NULL,1672386613,1782480564);
INSERT INTO highlights VALUES('42689053_10_12246-12270','42689053',35,'3 货币、信贷、债务和经济活动的大周期','挂钩货币体系，因为货币的价值与某种实物的价值挂钩','12243-12267',NULL,1672386588,1782480564);
INSERT INTO highlights VALUES('42689053_10_512-531','42689053',35,'3 货币、信贷、债务和经济活动的大周期','而货币和信贷对财富和权力增减的影响最大','459-478',NULL,1672207618,1782480564);
INSERT INTO highlights VALUES('42689053_10_10475-10496','42689053',35,'3 货币、信贷、债务和经济活动的大周期','这些长期债务周期取决于央行还剩下多少兴奋剂','10466-10487',NULL,1670055824,1782480564);
INSERT INTO highlights VALUES('42689053_10_10049-10298','42689053',35,'3 货币、信贷、债务和经济活动的大周期','我称之为短期债务周期，是为了区别于长期债务周期。长期债务周期通常持续50~100年（因此包括6~10个短期债务周期）。￼长期债务周期在人的一生中只出现一次，大多数人对其会毫无预料。','10041-10282',NULL,1670055793,1782480564);
INSERT INTO highlights VALUES('42689053_10_9725-9746','42689053',35,'3 货币、信贷、债务和经济活动的大周期','央行有一瓶兴奋剂，可以根据需要将其注入经济','9717-9738',NULL,1670055741,1782480564);
INSERT INTO highlights VALUES('42689053_10_9634-9670','42689053',35,'3 货币、信贷、债务和经济活动的大周期','央行只能在其控制货币和信贷增长的能力范围内调控经济，其调控能力是有限的。','9626-9662',NULL,1670055727,1782480564);
INSERT INTO highlights VALUES('42689053_10_8301-8334','42689053',35,'3 货币、信贷、债务和经济活动的大周期','因为货币和信贷的供应相对于需求增加了，这就是我们所说的“货币通胀”','8293-8326',NULL,1670047698,1782480564);
INSERT INTO highlights VALUES('42689053_10_8210-8288','42689053',35,'3 货币、信贷、债务和经济活动的大周期','如果货币和信贷不再流入增强经济需求的贷款，而是流入其他货币和通胀对冲资产，那么货币和信贷就无法刺激实体经济活动，反而会导致货币贬值，推高通胀对冲资产的价值。','8202-8280',NULL,1670047277,1782480564);
INSERT INTO highlights VALUES('42689053_10_7802-7836','42689053',35,'3 货币、信贷、债务和经济活动的大周期','实体经济的供求关系取决于商品和服务数量、购买这些商品和服务的买家数量','7794-7828',NULL,1670046600,1782480564);
INSERT INTO highlights VALUES('42689053_10_7567-7586','42689053',35,'3 货币、信贷、债务和经济活动的大周期','要想创造更多的财富，就必须提高生产率。','7559-7578',NULL,1670046519,1782480564);
INSERT INTO highlights VALUES('42689053_10_7537-7566','42689053',35,'3 货币、信贷、债务和经济活动的大周期','但是一个人无法单纯通过创造更多的货币和信贷来创造更多的财富','7529-7558',NULL,1670046509,1782480564);
INSERT INTO highlights VALUES('42689053_10_6684-6883','42689053',35,'3 货币、信贷、债务和经济活动的大周期','当借款还清时，资产和负债清零，借贷双方都得到收益。他们基本上分享了这种生产性贷款带来的利润。这对整个社会也有好处，由此带来的生产率增长使社会受益。','6678-6751',NULL,1670046348,1782480564);
INSERT INTO highlights VALUES('42689053_10_6489-6541','42689053',35,'3 货币、信贷、债务和经济活动的大周期','理解金钱和债务的区别很重要。金钱是清偿债务的手段，一个人付清欠账即告完事，而债务是对未来交付资金的承诺。','6483-6535',NULL,1670046275,1782480564);
INSERT INTO highlights VALUES('42689053_10_6023-6045','42689053',35,'3 货币、信贷、债务和经济活动的大周期','货币是一种交换媒介，也可以是财富贮藏的手段。','6017-6039',NULL,1670046195,1782480564);
INSERT INTO highlights VALUES('42689053_10_4805-4837','42689053',35,'3 货币、信贷、债务和经济活动的大周期','债务吞噬资产净值，但央行可以通过印钞来为债务融资。','4750-4789',NULL,1670043021,1782480564);
INSERT INTO highlights VALUES('42689053_10_3916-3950','42689053',35,'3 货币、信贷、债务和经济活动的大周期','其之所以看上去富有，是因为大举消费，持有很多资产，甚至还有很多现金。','3848-3882',NULL,1670042179,1782480564);
INSERT INTO highlights VALUES('42689053_10_3037-3153','42689053',35,'3 货币、信贷、债务和经济活动的大周期','如果货币和信贷用于消费，大多数商品、服务和投资资产的价格就会上涨。这也产生了必须偿还的债务，需要个人、公司、非营利组织和政府削减支出，最终使支出低于收入，这个过程是艰难和痛苦的。这就是为什么货币、信贷、债务和经济活动具有内在的周期性','2969-3085',NULL,1670037671,1782480564);
INSERT INTO highlights VALUES('42689053_10_2778-2788','42689053',35,'3 货币、信贷、债务和经济活动的大周期','你必须最先偿还债务。','2710-2720',NULL,1670037556,1782480564);
INSERT INTO highlights VALUES('42689053_10_2737-2772','42689053',35,'3 货币、信贷、债务和经济活动的大周期','债务吞噬资产净值。','2688-2697',NULL,1670037545,1782480564);
INSERT INTO highlights VALUES('42689053_9_31532-31567','42689053',34,'2 决定因素','他们也可能忽略了这样一个事实：他们的盈利形式不利于实现大多数人的目标。','31193-31228',NULL,1669773374,1782480564);
INSERT INTO highlights VALUES('42689053_9_31398-31447','42689053',34,'2 决定因素','他们还认为，私营部门比公共部门更有效率，资本主义最适合大多数人，白手起家的亿万富翁对社会的贡献最大','31063-31112',NULL,1669773347,1782480564);
INSERT INTO highlights VALUES('42689053_9_31339-31397','42689053',34,'2 决定因素','右倾/资本主义者的典型观点是，自给自足，从而获取效益，限制政府干预，允许个人保留自己的成果，允许个人选择社会道德标准','31004-31062',NULL,1669773341,1782480564);
INSERT INTO highlights VALUES('42689053_9_30629-30839','42689053',34,'2 决定因素','通过研究历史，我发现了这样一个永恒普适的真理：自孔子生活的公元前500年左右以来，● 那些最广泛地使用人才，并根据个人业绩而不是特权来赋予公民责任的社会最可能取得可持续性成功。这样做可以（1）找到最佳人选来很好地完成工作，（2）从多种视角看待问题，（3）让公民认为自己得到最公平的待遇，从而促进社会稳定。','30270-30494',NULL,1669773227,1782480564);
INSERT INTO highlights VALUES('42689053_9_28801-28942','42689053',34,'2 决定因素','自古至今，所有国家的人民都被归入不同“群体”（尽管程度不同），其原因要么是他们选择与自己相似的人在一起，要么是他们被其他人归入特定群体。','28568-28650',NULL,1669773016,1782480564);
INSERT INTO highlights VALUES('42689053_9_28407-28435','42689053',34,'2 决定因素','我预计，这些秩序将继续逐步和突发地演变，产生国内新秩序。','28160-28188',NULL,1669772969,1782480564);
INSERT INTO highlights VALUES('42689053_9_26514-26570','42689053',34,'2 决定因素','纵观所有国家的历史，财富拥有者也都拥有创造财富的手段，为了维持财富，他们与规则制定者和实行者合作。','26261-26310',NULL,1669726267,1782480564);
INSERT INTO highlights VALUES('42689053_9_26189-26243','42689053',34,'2 决定因素','“贫困者和富人相互争吵，无论哪一方占上风，都不会建立一个公正或受欢迎的政府，而是把政治霸权作为胜利的奖赏。”','25922-25976',NULL,1669715472,1782480564);
INSERT INTO highlights VALUES('42689053_9_25057-25360','42689053',34,'2 决定因素',unistr('创新发明 + 商业精神 + 兴旺发达的资本市场\u000a=\u000a生产率大幅提升\u000a=\u000a财富和权力增加'),'25060-25095',NULL,1669687397,1782480564);
INSERT INTO highlights VALUES('42689053_9_22644-22702','42689053',34,'2 决定因素','我把这个阶段的国家称为“健康高峰国家”。1950—1965年，美国处于这个阶段。中国正在进入这一阶段。','22615-22666',NULL,1669687098,1782480564);
INSERT INTO highlights VALUES('42689053_9_21967-22026','42689053',34,'2 决定因素','第三阶段：人民和他们的国家都富有，他们也认为自己富有。在这个阶段，人们的收入很高，所以劳动力变得更昂贵。','21939-21998',NULL,1669686963,1782480564);
INSERT INTO highlights VALUES('42689053_9_19855-19916','42689053',34,'2 决定因素','顺便说一下，将资金用于投资和基础设施（而不是消费）往往会带来更高的生产率，因此投资是一个可以很好地衡量经济繁荣的先行指标。','19803-19864',NULL,1669686660,1782480564);
INSERT INTO highlights VALUES('42689053_9_19732-19757','42689053',34,'2 决定因素','从长远来看，你拥有的财富和购买力取决于你创造的价值','19680-19705',NULL,1669686629,1782480564);
INSERT INTO highlights VALUES('42689053_9_15529-15576','42689053',34,'2 决定因素','需要明确的是，只要一方不给另一方带来生存风险（参见囚徒困境），竞争对手之间就可以存在双赢关系。','15429-15476',NULL,1666760125,1782480564);
INSERT INTO highlights VALUES('42689053_9_15322-15374','42689053',34,'2 决定因素','要想进一步降低发生冲突的风险，双方就需要交换利益，建立相互依赖的关系，使自身不能承受失去这种关系的后果。','15219-15271',NULL,1666760098,1782480564);
INSERT INTO highlights VALUES('42689053_9_13654-13730','42689053',34,'2 决定因素','在每一代人中，大约有几百人改变了一切。研究这些关键人物所发挥的作用，考察他们在不同情况下所采取的措施和带来的后果，可以帮助我们理解这台永动机的工作原理。','13548-13624',NULL,1666759205,1782480564);
INSERT INTO highlights VALUES('42689053_9_13573-13653','42689053',34,'2 决定因素','在阅读历史的过程中，你会反复看到，历史的进程如何被主要领域（如政府、科学、金融和商业、艺术等）的相对少数人的独特性改变（有时带来卓越的成就，有时带来可怕的恶果）','13467-13547',NULL,1666759198,1782480564);
INSERT INTO highlights VALUES('42689053_9_12068-12124','42689053',34,'2 决定因素','人类选择即时享受（而非长远福祉）的倾向自然夸大了周期的高峰和低谷，因为这样做是以牺牲未来为代价而提前享受美好时光','11950-12006',NULL,1666696703,1782480564);
INSERT INTO highlights VALUES('42689053_9_10321-10381','42689053',34,'2 决定因素','虽然许多国家都可以利用自己的自然资源，但人力资本是最可持续的资本，因为继承下来的资产最终会消失，而人力资本可以永远存在。','10178-10238',NULL,1666696478,1782480564);
INSERT INTO highlights VALUES('42689053_9_10040-10115','42689053',34,'2 决定因素','如果一个人能够使自己的收入超过支出，就拥有良好的人力资本，可以自给自足。我称之为“自给自足+”，这是所有个人、公司和国家都应该努力做到的','9876-9958',NULL,1666696452,1782480564);
INSERT INTO highlights VALUES('42689053_9_9728-9782','42689053',34,'2 决定因素','虽然一个国家继承的资产和负债非常重要，但历史表明，人们对待自己和他人的方式是最重要的决定因素。','9543-9590',NULL,1666696396,1782480564);
INSERT INTO highlights VALUES('42689053_9_7955-8110','42689053',34,'2 决定因素',unistr('1. 继承的决定因素：包括一个国家的地理、地质和自然现象，如气候和疾病。\u000a2. 人力资本的决定因素：人们对待自己和彼此的方式。这些因素受人类本性和不同文化的影响（影响方式各不相同）。'),'7759-7909',NULL,1666696202,1782480564);
INSERT INTO highlights VALUES('42689053_9_5040-5105','42689053',34,'2 决定因素','另外两个决定因素也值得注意，即（4）创新和技术发展步伐，这有助于人类解决问题和做出改进；及（5）天灾，最重要的是干旱、洪水和疾病。','4840-4905',NULL,1666695921,1782480564);
INSERT INTO highlights VALUES('42689053_9_4776-4893','42689053',34,'2 决定因素','我们不妨重点关注这三大周期：（1）有利和不利的金融周期（例如资本市场周期）；（2）内部秩序和混乱周期（取决于合作程度与财富和权力斗争，后者主要缘于财富和价值观差距）；（3）外部秩序和混乱周期（取决于现有大国在财富和权力斗争中的竞争力）','4576-4693',NULL,1666695884,1782480564);
INSERT INTO highlights VALUES('42689053_9_3507-3637','42689053',34,'2 决定因素','大多数人不这么看问题。大多数人相信未来是不可知的，也不存在命运。需要明确的是，虽然一个完美的模型能够近乎完美地预测注定的未来，这固然美好，但我并不指望我的模型能接近完美。我的目标只是拥有一个粗略但不断改进的模型，让我在竞争中获得优势，比没有模型的情况更有优势。','3288-3418',NULL,1666692678,1782480564);
INSERT INTO highlights VALUES('42689053_9_2970-2998','42689053',34,'2 决定因素','这些秩序的根本性质和运作方式取决于人类的本性、文化和环境','2751-2779',NULL,1666692541,1782480564);
INSERT INTO highlights VALUES('42689053_9_2672-2906','42689053',34,'2 决定因素','自古至今，所有人都有管理人们相处关系的体制或秩序。我把国家内部的体制称为“内部秩序”，把国家之间的体制称为“外部秩序”，把适用于全世界的体制称为“世界秩序”。这些秩序相互影响，而且总在改变。','2578-2673',NULL,1666692464,1782480564);
INSERT INTO highlights VALUES('42689053_8_27707-27813','42689053',33,'1 大周期简述','与此同时，伟大的人类思维与计算机智能携手合作，正在创造应对这些挑战的有效方法。如果我们能够和睦相处，就一定能够度过这段困难时期，进入一个全新的繁荣时期。我也同样相信，未来将会发生根本性的变化，会给许多人带来创伤。','27440-27546',NULL,1666666084,1782480564);
INSERT INTO highlights VALUES('42689053_8_21966-21991','42689053',33,'1 大周期简述','在通常情况下，国家的衰落是逐步发生的，然后骤然终止','21745-21770',NULL,1666531210,1782480564);
INSERT INTO highlights VALUES('42689053_8_21736-21825','42689053',33,'1 大周期简述','• 一旦国家开始找不到新的贷款人，那些持有国家货币的人就会设法出售和退出这种货币，而不是购买、存储、放贷和兑换它。这时，国家的实力开始衰落。','21525-21614',NULL,1666531182,1782480564);
INSERT INTO highlights VALUES('42689053_8_21213-21378','42689053',33,'1 大周期简述','虽然这在短期内提高了消费力，但从长期来看，它削弱了国家的财政健康和货币价值。换句话说，当进行大量借款和支出时，国家看起来非常强大，但其财政实力实际上已经削弱。为了维持超出自身能力的实力，国家不断借款，用来支撑国内的过度消费，为国际军事冲突提供资金，这是维持国家地位所必需的措施。','21011-21176',NULL,1666531113,1782480564);
INSERT INTO highlights VALUES('42689053_8_20835-20998','42689053',33,'1 大周期简述','拥有储备货币给予它们一种“过分的特权”','20664-20709',NULL,1666531078,1782480564);
INSERT INTO highlights VALUES('42689053_8_20356-20433','42689053',33,'1 大周期简述','• 此外，随着人们习惯富裕生活，他们会更趋于推断好时光会持续下去，于是通过借款来享受优越的生活，从而导致了金融泡沫。','20201-20278',NULL,1666530991,1782480564);
INSERT INTO highlights VALUES('42689053_8_20099-20203','42689053',33,'1 大周期简述','此外，随着领先大国的人民变得更富有，他们往往不会像以前那样努力工作，而更享受悠闲生活，追求生活中更精美但经济效益较低的东西，在极端的情况下，人们会变得颓废。','19947-20044',NULL,1666530923,1782480564);
INSERT INTO highlights VALUES('42689053_8_19958-20000','42689053',33,'1 大周期简述','其他国家自然会复制领先大国的方法和技术，这进一步降低了领先大国的竞争力','19809-19844',NULL,1666530903,1782480564);
INSERT INTO highlights VALUES('42689053_8_20001-20064','42689053',33,'1 大周期简述','例如，英国造船商雇用荷兰设计师，设计了更好的船舶，并由更廉价的英国工人制造，这使英国人更具竞争力，导致了英国的崛起和荷兰的衰落','19852-19915',NULL,1666530897,1782480564);
INSERT INTO highlights VALUES('42689053_8_19597-19601','42689053',43,'10 大英帝国和英镑的大周期兴衰','顶部阶段','15926-15930',NULL,1666525832,1782480564);
INSERT INTO highlights VALUES('42689053_8_19361-19406','42689053',33,'1 大周期简述','相较于其他国家，这个国家便可以以更低的利率得到更多的借款，因为别人希望以这种货币发放贷款。','19252-19297',NULL,1666525792,1782480564);
INSERT INTO highlights VALUES('42689053_8_18794-18978','42689053',33,'1 大周期简述',unistr('要想更好地提供激励机制和金融支撑，国家……\u000a• ……需要发展资本市场。最重要的是发展贷款、债券和股票市场。这使人们得以将储蓄转化为投资，为创新和发展提供资金，也让那些创造伟大成就的人得以分享他们的成功。'),'18694-18875',NULL,1666525711,1782480564);
INSERT INTO highlights VALUES('42689053_8_16843-16968','42689053',33,'1 大周期简述',unistr('下跌阶段：\u000a这是一个痛苦的阶段，充满各种争斗和结构性重组，从而导致严重冲突和巨大变革，推动内部和外部新秩序的建立，为下一个新秩序和繁荣建设时期埋下了种子。'),'16883-17008',NULL,1666525586,1782480564);
INSERT INTO highlights VALUES('42689053_8_16351-16557','42689053',33,'1 大周期简述',unistr('上升阶段：\u000a上升阶段是新秩序建立之后的繁荣建设时期。在这个阶段，国家的基本面较为强劲，因为（a）债务水平相对较低，（b）财富、价值观和政治差距相对较小，（c）人们通过有效合作来创造繁荣，（d）具备良好的教育和基础设施，（e）拥有强有力且有能力的领导者，（f）一个或多个世界主要大国主导着和平的世界秩序，进而发展到……'),'16397-16603',NULL,1666525572,1782480564);
INSERT INTO highlights VALUES('42689053_8_16617-16783','42689053',33,'1 大周期简述',unistr('顶部阶段：\u000a顶部阶段以各种形式的过度状况为特征：（a）高负债，（b）财富、价值观和政治差距巨大，（c）教育水平和基础设施不断下滑，（d）国家内部不同群体之间发生冲突，（e）过度扩张的国家受到新兴对手的挑战，引发国家之间的争斗，这导致……'),'16660-16826',NULL,1666525567,1782480564);
INSERT INTO highlights VALUES('42689053_8_14861-14929','42689053',33,'1 大周期简述','（1）教育，（2）竞争力，（3）创新和技术，（4）经济产出，（5）世界贸易份额，（6）军事实力，（7）金融中心实力，（8）储备货币地位。','14874-14942',NULL,1666467063,1782480564);
INSERT INTO highlights VALUES('42689053_8_11348-11467','42689053',33,'1 大周期简述','。请记住，经济毁灭时期和战争时代通常不会持续很长时间，一般是两三年。天灾（如干旱、洪水和大流行病）的持续时间和严重程度各不相同，不过随着人类适应力的增强，这种痛苦通常会减轻。同时遇到这三大危机（经济危机、革命/战争和天灾）的情况极为罕见。','11392-11511',NULL,1666466459,1782480564);
INSERT INTO highlights VALUES('42689053_8_9675-9769','42689053',33,'1 大周期简述','以往的经济和市场下行时期大约持续了三年（出入在几年之内），这取决于债务重组和/或债务货币化所需的时间。通过印钞填补债务缺口的速度越快，通缩性萧条就会越快结束，人们也就越快开始担心货币价值。','9720-9814',NULL,1666466196,1782480564);
INSERT INTO highlights VALUES('42689053_8_8676-8796','42689053',33,'1 大周期简述','因为相比人类适应力和创造力的逐步上行轨迹，这些动荡时期造成的影响微乎其微，几乎不能从前面的人均GDP和预期寿命图中分辨出来，只体现为一些小波动。不过在我们看来，这些波动的幅度似乎非常显著，因为我们是如此渺小，生命也是如此短暂。','8702-8815',NULL,1666466095,1782480564);
INSERT INTO highlights VALUES('42689053_8_7198-7302','42689053',33,'1 大周期简述','获取知识和提高生产率固然意义重大，但这个过程是渐进的，不会给财富和权力及其持有者带来巨大的突变。巨大的突变来自经济繁荣、经济萧条、革命和战争，这些时期主要由周期决定，而逻辑因果关系驱动这些周期。','7177-7274',NULL,1666465839,1782480564);
INSERT INTO highlights VALUES('42689053_8_7048-7088','42689053',33,'1 大周期简述','新的斗争随之而来，这些斗争围绕着谁能获得数据，以及如何利用这些数据获取财富和权力','7027-7067',NULL,1666465711,1782480564);
INSERT INTO highlights VALUES('42689053_8_5445-5571','42689053',33,'1 大周期简述','与围绕趋势线的波动相比，这些上行趋势非常明显，这一事实表明，相对于其他任何事物，人类的创造力极其强大。从整体格局来看，人均产出正在稳步提高，不过早期增速非常缓慢，但从19世纪开始加快了速度，那时的上行曲线明显走陡，反映了生产率的加速提升。','5407-5526',NULL,1666465563,1782480564);
INSERT INTO highlights VALUES('42689053_8_5171-5200','42689053',33,'1 大周期简述','甚至人类的进化方式也演进了，这表现为创造和革新方式的进步。','5137-5166',NULL,1666465522,1782480564);
INSERT INTO highlights VALUES('42689053_8_4069-4151','42689053',33,'1 大周期简述','进化是走向进步的上行轨迹，而进步源于适应和学习。周期围绕着上行轨迹而反复出现。在我看来，大多数事物是沿着一条具有周期性的上行轨迹发生的。这条轨迹就像一个上行的螺丝锥','4016-4098',NULL,1666465451,1782480564);
INSERT INTO highlights VALUES('42689053_8_4754-4795','42689053',33,'1 大周期简述','人类的生产率是驱动世界总财富、权力和生活水平逐步提高的最重要的力量。','4720-4754',NULL,1666465437,1782480564);
INSERT INTO highlights VALUES('42689053_8_3231-3340','42689053',33,'1 大周期简述','这些周期在历史的长河中基本上没有变化，原因与人类生命周期的基本要素在历史长河中保持不变是一样的：人类本性不会随着时间的推移而发生太大变化。例如，恐惧、贪婪、嫉妒和其他基本情感始终没有改变，它们是驱动周期发展的重要因素。','3178-3287',NULL,1666465020,1782480564);
INSERT INTO highlights VALUES('42689053_8_3171-3195','42689053',33,'1 大周期简述','朝着一个方向的走势中，潜藏着导致反向走势的要素。','3118-3142',NULL,1666367518,1782480564);
INSERT INTO highlights VALUES('42689053_8_2871-2920','42689053',33,'1 大周期简述','我在引言中提到的三个最重要的周期：长期债务和资本市场周期、内部秩序和混乱周期、外部秩序和混乱周期。','2818-2867',NULL,1666367447,1782480564);
INSERT INTO highlights VALUES('42689053_8_1514-1610','42689053',33,'1 大周期简述','我也发现古往今来，所有国家的财富拥有者都具备创造财富的手段。为了维持和增加财富，他们与政权掌控者合作，一起建立共生关系，制定和执行规则。我看到类似的情况发生在不同国家和不同时期。','1461-1550',NULL,1666367193,1782480564);
INSERT INTO highlights VALUES('42689053_8_1335-1420','42689053',33,'1 大周期简述','我发现自古至今，在大多数国家，对大多数人最主要的影响因素是，人们如何努力创造、获取、分配财富和权力，尽管也存在其他方面的争斗，最重要的是意识形态和宗教方面。','1282-1360',NULL,1666367155,1782480564);
INSERT INTO highlights VALUES('42689053_8_1041-1105','42689053',33,'1 大周期简述','我的目标是搞清世界的运行原理，总结出永恒普适的原则，从而妥善地应对当前形势。这么做不仅很有必要，也是我的兴趣所在。','988-1045',NULL,1666367086,1782480564);
INSERT INTO highlights VALUES('42689053_8_924-975','42689053',33,'1 大周期简述','我们将看到个案在何种程度上符合原型（本质上就是这些案例的平均情况），原型又在何种程度上反映个案的情况。','871-922',NULL,1666367075,1782480564);
INSERT INTO highlights VALUES('42689053_8_484-561','42689053',33,'1 大周期简述','世界正在迅速发生变化，这些重要的变化是在我们的一生中从未发生过但在历史上已经多次发生的。我的目标是揭示这些案例及其背后的驱动机制，并从这个视角来展望未来。','431-508',NULL,1666367009,1782480564);
INSERT INTO highlights VALUES('42689053_6_14330-14374','42689053',31,'引言','第二部分详细介绍个案，讲述主要储备货币过去500年的历史，其中一章重点探讨当前中美争端。','14331-14375',NULL,1666366987,1782480564);
INSERT INTO highlights VALUES('42689053_6_14038-14257','42689053',31,'引言','首先，我把我的研究发现提炼成国家的整体实力指数，用来反映不同国家兴衰的整体情况，它包括8个不同类型的实力指数￼。','14040-14258',NULL,1666366944,1782480564);
INSERT INTO highlights VALUES('42689053_6_13369-13430','42689053',31,'引言','请注意，尽管有了这些心得，但我仍然犯下许多错误（这就是为什么我把分散化投资看得高于一切），只是在此尽我所能地传述我的想法。','13368-13429',NULL,1666366854,1782480564);
INSERT INTO highlights VALUES('42689053_6_13240-13292','42689053',31,'引言','从我的经验来看，如果等到学至自己很满意的程度才肯采取行动或进行分享，我就永远无法运用和传述所学到的东西。','13239-13291',NULL,1666366809,1782480564);
INSERT INTO highlights VALUES('42689053_6_12211-12285','42689053',31,'引言','一般来说，大英帝国占领着其治下的国家，而美利坚帝国主要以奖励和威胁的方式控制更多的国家（并非绝对，因为在我撰写本书时，美国在70个国家设有军事基地）','12210-12284',NULL,1666340626,1782480564);
INSERT INTO highlights VALUES('42689053_6_11428-11451','42689053',31,'引言','要想把握全局，就不能着眼于细节。','11420-11450',NULL,1666324544,1782480564);
INSERT INTO highlights VALUES('42689053_6_11001-11080','42689053',31,'引言','如果过于关注当前事件，或者只看平均数据而不是个别案例，我们就会忽视这些周期。几乎所有人都在谈论当前事件，没有人谈论这些大周期，而大周期是当前事件的最大驱动力。','10979-11058',NULL,1666324463,1782480564);
INSERT INTO highlights VALUES('42689053_6_10695-10773','42689053',31,'引言','中国提供了考察王朝兴衰的许多案例，可以让我更好地了解其背后的模式和动因。通过这些案例，我们可以更清楚地了解其他因素（最重要的是技术和天灾）如何发挥重要作用。','10673-10751',NULL,1666324360,1782480564);
INSERT INTO highlights VALUES('42689053_6_10524-10566','42689053',31,'引言','当今最重要的美帝国和美元、之前最重要的大英帝国和英镑，以及再之前的荷兰帝国和荷兰盾。','10502-10544',NULL,1666324327,1782480564);
INSERT INTO highlights VALUES('42689053_6_9986-10101','42689053',31,'引言','因为央行充分降息以刺激经济的能力有限。除了这些传统工具失效之外，印钞和购买金融资产（现在被称作“量化宽松”）也扩大了贫富差距，因为购买金融资产会推高资产价格，这有利于持有更多金融资产的富人，而无利于贫困者。这会对未来产生何种影响？','9978-10093',NULL,1666322642,1782480564);
INSERT INTO highlights VALUES('42689053_6_8704-8785','42689053',31,'引言','事实上，在这些决策者的领导下，中国在制造业、贸易、科技、地缘政治和世界资本市场上成了美国的有力竞争对手。因此，我们必须毫无偏见地研究和理解中国是如何做到这一点的。','8719-8800',NULL,1666286501,1782480564);
INSERT INTO highlights VALUES('42689053_6_7855-7881','42689053',31,'引言','生产率和结构性改革：国家成败的原因和失败国家的对策”','7879-7905',NULL,1666286107,1782480564);
INSERT INTO highlights VALUES('42689053_6_6842-7065','42689053',31,'引言','通过从宏观角度考察历史，我认识到自古至今，只有几种性格类别的人类￼，沿着有限的几条道路前行，遇到有限的几类情况，发生有限的几起事件。随着时间的推移，这些事件反复出现。唯一不同的是当时人类的服饰及其使用的语言及技术。','6897-7119',NULL,1666285994,1782480564);
INSERT INTO highlights VALUES('42689053_6_6709-6834','42689053',31,'引言','我认为，人们之所以往往错过一生中的重要成长时刻，是因为每个人仅经历漫长历史的一小部分。我们就像蚂蚁一样，在短暂的一生中全神贯注于搬运面包屑，却无暇拓宽视野，发现事物发展的宏观规律和周期及其背后的重要关联、我们在周期中所处的位置，以及未来可能出现的情况','6764-6889',NULL,1666285939,1782480564);
INSERT INTO highlights VALUES('42689053_6_6297-6354','42689053',31,'引言','这种看待事物的方法改变了我的视野：从被各种事件（像袭来的暴风雪一样）围困，到超越各种事件，放眼于事物的长期发展规律','6353-6410',NULL,1666285907,1782480564);
INSERT INTO highlights VALUES('42689053_6_5618-5723','42689053',31,'引言','通过这个程序，我不断完善对因果关系的认识，直到我可以用“如果……那么……”这样的句式来制定决策规则（对现实情况的应对原则）：如果X发生了，那么我们就下注Y。接下来，我观察实际情况与我的原始模型及预期之间的差异。','5675-5780',NULL,1666285872,1782480564);
INSERT INTO highlights VALUES('42689053_6_5005-5030','42689053',31,'引言','股市非但没有随美元暴跌而下跌，反而上涨了大约4%。','5062-5087',NULL,1666283497,1782480564);
INSERT INTO highlights VALUES('42689053_6_4518-4591','42689053',31,'引言','一个人预测和应对未来的能力，取决于他对事物变化背后的因果关系的理解；一个人理解这些因果关系的能力，来自他对以往变化的发生机制的研究。','4568-4648',NULL,1666273587,1782480564);
INSERT INTO highlights VALUES('42689053_6_3749-3943','42689053',31,'引言','在我的一生中，美元一直是世界储备货币，货币政策一直是刺激经济的有效工具，人们普遍认为西方民主和资本主义是优越的政治和经济体制。任何研究历史的人都可以看到，● 没有任何一个政治体制、经济体系、货币或帝国可以永远存在。但当它们失灵时，几乎所有人都会感到惊讶，并受到毁灭性打击。','3764-3965',NULL,1666273515,1782480564);
INSERT INTO highlights VALUES('42689053_6_3603-3666','42689053',31,'引言','因此，在我撰写本书的时候，大多数人认为他们应该增加借款，尽管从历史来看，借款和债务融资拉动的经济繁荣会导致经济萧条和内外冲突。','3618-3681',NULL,1666273493,1782480564);
INSERT INTO highlights VALUES('42689053_6_3075-3293','42689053',31,'引言','● 就像许多事物一样，在人的一生中，重大的繁荣时期和重大的萧条时期只会出现一次，除非我们研究几代人的历史模式，否则很难预料到这些时期的到来。因为繁荣时期和萧条时期的更迭往往相隔很久，● 我们所面临的未来很可能与大多数人所预期的情况迥然不同。','3048-3308',NULL,1666273445,1782480564);
INSERT INTO highlights VALUES('42689053_6_2158-2259','42689053',31,'引言','这个大周期在以下两个时期之间产生更迭：（1）和平与繁荣时期，具有强大的创造力和生产力，生活水平明显提高；（2）萧条、革命与战争时期，财富和权力斗争此起彼伏，大量财富、生命和其他珍品被毁灭。','2110-2204',NULL,1666273347,1782480564);
INSERT INTO highlights VALUES('42689053_6_1047-1324','42689053',31,'引言','我开始研究各国及其储备货币和市场的兴衰。换言之，要想理解当前的势态发展，应对未来几年可能发生的情况，我需要研究类似历史案例背后的机制，例如研究1930—1945年期间荷兰、英国、中国的兴衰等。','1000-1096',NULL,1666273238,1782480564);
INSERT INTO highlights VALUES('42689053_6_1444-1476','42689053',31,'引言','与最严重的经济萧条和战争相比，这些罕见的异常天灾的影响力甚至更大','1396-1428',NULL,1666273234,1782480564);
INSERT INTO highlights VALUES('42689053_6_1000-1044','42689053',31,'引言','意识到，除非研究类似的历史时期，否则我无法真正理解当前的势态，也无法应对即将发生的情况。','953-997',NULL,1666273190,1782480564);
INSERT INTO highlights VALUES('42689053_6_733-783','42689053',31,'引言','我注意到一些重大势态发展，在我的有生之年里，这些事件从未发生过，但在历史上曾多次出现。','686-729',NULL,1666273153,1782480564);
INSERT INTO highlights VALUES('42689053_6_411-521','42689053',31,'引言',unistr('未\u000a来的时代将与我们有生之年所经历的时代完全不同，但与历史上的许多时代有着相似之处。\u000a我为何得出这样'),'390-474',NULL,1666273135,1782480564);
INSERT INTO highlights VALUES('42689053_6_919-951','42689053',31,'引言','最近一段与目前类似的时期是1930—1945年。这令我十分担忧。','872-904',NULL,1665681621,1782480564);
INSERT INTO highlights VALUES('907574_16_18442-18533','907574',16,'10 牧草：看待草地的13种方式','但是你想知道，我什么时候最怀念他吗？就是当我看到堆得厚厚的干草、满地的蚯蚓粪便，以及皮毛光滑的牛。这一切都是在他离开我们以后才取得的成就。啊，如果他看到这里现在的样子，会有多么骄傲！','18442-18533',0,1678015581,1782480564);
INSERT INTO highlights VALUES('907574_16_18023-18270','907574',16,'10 牧草：看待草地的13种方式','我每天仍会想念他。老爸绝对是个怪人，但是他是往好的方向怪。有多少保守的基督徒会看《大地母亲新闻》（Mother Earth News） ￼？他实践了自己的信仰。','18023-18270',0,1678015553,1782480564);
INSERT INTO highlights VALUES('907574_16_16177-16215','907574',16,'10 牧草：看待草地的13种方式','为什么要到委内瑞拉？“老爸觉得那里可以远离传统与规范，用自己期望的方式耕种。','16177-16215',0,1677807947,1782480564);
INSERT INTO highlights VALUES('907574_16_16245-16274','907574',16,'10 牧草：看待草地的13种方式','农场经营得有声有色，但是到了1959年，左派分子推翻政府，','16245-16274',0,1677807914,1782480564);
INSERT INTO highlights VALUES('907574_16_13565-13591','907574',16,'10 牧草：看待草地的13种方式','真正受惠于谷物的并不是美国人民，而是军事工业复合体，','13565-13591',0,1677765634,1782480564);
INSERT INTO highlights VALUES('907574_16_13038-13116','907574',16,'10 牧草：看待草地的13种方式','这些成本不会直接从消费者那儿收取，而是以看不到的方式，间接地从纳税人（以补助的形式）、公共卫生系统（以食物传染的疾病与肥胖的形式）、环境（以污染的形式）收取','13038-13116',0,1677765556,1782480564);
INSERT INTO highlights VALUES('907574_16_12463-12529','907574',16,'10 牧草：看待草地的13种方式','用草喂食的牛肉质量通常会因为季节和地区而有所不同，玉米喂食的牛就不会。长此以往，人们就渐渐忘记要如何让草地全年都长出好草来喂食牛了。','12463-12529',0,1677765453,1782480564);
INSERT INTO highlights VALUES('907574_16_12145-12174','907574',16,'10 牧草：看待草地的13种方式','适当管理的草地能比玉米田制造出更多营养（蛋白质和碳水化合物','12145-12174',0,1677765397,1782480564);
INSERT INTO highlights VALUES('907574_16_11883-11984','907574',16,'10 牧草：看待草地的13种方式','为何人类远离了免费的午餐，反而去吃以玉米为基础又会对生态造成伤害的午餐呢？美国人究竟为何要把这些反刍动物赶离草原？快餐店中那些从玉米和化石燃料制造出来的汉堡，为何会变得比由草原和阳光制造出来的食物便宜？','11883-11984',0,1677765372,1782480564);
INSERT INTO highlights VALUES('907574_16_11767-11806','907574',16,'10 牧草：看待草地的13种方式','这顿餐点是来自土壤，而非从土壤中挖掘出来；这顿餐点增加了而非损耗了地球的能量。','11767-11806',0,1677765360,1782480564);
INSERT INTO highlights VALUES('907574_16_11151-11198','907574',16,'10 牧草：看待草地的13种方式','正着手一项长期的计划，期望能将许多一年生谷类作物（包括玉米）转变成多年生作物，并将它们混合栽植','11151-11198',0,1677765271,1782480564);
INSERT INTO highlights VALUES('907574_16_10942-10998','907574',16,'10 牧草：看待草地的13种方式','我们很少注意到农业在全球变暖现象中所扮演的角色，然而人类活动所排放到大气中的温室气体，有三分之一是来自农耕活动。','10942-10998',0,1677765208,1782480564);
INSERT INTO highlights VALUES('907574_16_10794-10824','907574',16,'10 牧草：看待草地的13种方式','不过树木将碳储存于自身，草地则是将碳以腐殖质的形式储存于地底','10794-10824',0,1677765177,1782480564);
INSERT INTO highlights VALUES('907574_16_8694-8757','907574',16,'10 牧草：看待草地的13种方式','饲养场的食物链，触角横跨整个美洲大陆，延伸到艾奥瓦州的玉米田、墨西哥湾中氧气不足的海域，更探入波斯湾的油田，以其能源来供养玉米','8694-8757',0,1677420085,1782480564);
INSERT INTO highlights VALUES('907574_16_8941-8972','907574',16,'10 牧草：看待草地的13种方式','我们之所以难以了解草地的复杂程度，是因为这种复杂性不是人造的。','8941-8972',0,1677420085,1782480564);
INSERT INTO highlights VALUES('907574_16_9488-9542','907574',16,'10 牧草：看待草地的13种方式','对于牛和草而言，这一口并不是“零和交易”。当巴格咬下这丛草，它等于引发了一连串事件，让这块草地得到莫大好处。','9488-9542',0,1677420085,1782480564);
INSERT INTO highlights VALUES('907574_16_9542-9629','907574',16,'10 牧草：看待草地的13种方式','那丛被咬断的草会努力重新调整根部和叶片的比例以维持平衡，也就是让根的重量大致等于叶片的重量，而多出来的根就会被抛弃，由土壤中的生物如细菌、真菌和蚯蚓等，分解为肥沃的棕色腐殖质','9542-9629',0,1677420085,1782480564);
INSERT INTO highlights VALUES('907574_16_5366-5397','907574',16,'10 牧草：看待草地的13种方式','以“牛日”（cow day）为单位来界定一头牛一天的平均粮草量','5366-5397',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_7378-7435','907574',16,'10 牧草：看待草地的13种方式','我们利用可移动的电篱笆达到相同的目的。在我们的系统中，这些篱笆扮演了掠食者的角色，把动物集中在一处，并且每天移动。','7378-7435',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_4533-4593','907574',16,'10 牧草：看待草地的13种方式','如果让牛连续放牧两三次，那么“冰激凌”等级的草，如苜蓿、果园草、甜草、早熟禾和梯牧草等，便会越来越稀少，最后从草地中消失','4533-4593',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_5649-5685','907574',16,'10 牧草：看待草地的13种方式','提升到每公顷将近1000个牛日，而该州草地的平均产量只有170个牛日而已','5649-5685',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_5448-5502','907574',16,'10 牧草：看待草地的13种方式','牛日这种计算单位，可比光速这类的恒定值有弹性多了，因为一片草地可提供多少牛日，会因为上述各项变量而有所增减。','5448-5502',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_5531-5613','907574',16,'10 牧草：看待草地的13种方式','过度放牧会破坏草地，放牧不足也会导致牧草木质化与老化，而使生产力下降。但是如果配合得当，让适量的牛在牧草的成长加速期放牧，就能得到大量的牧草，同时也会改善土地质量。','5531-5613',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_7043-7081','907574',16,'10 牧草：看待草地的13种方式','原生草种都已演化出在这种放牧模式下繁衍的能力，甚至需要动物的中介才能完成繁衍','7043-7081',0,1677420084,1782480564);
INSERT INTO highlights VALUES('907574_16_1751-1799','907574',16,'10 牧草：看待草地的13种方式','人类虽然是杂食动物，但是缺乏瘤胃来消化纤维素，因此青草是自然界中虽有营养但人类不吃的少数东西之一','1751-1799',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_3575-3660','907574',16,'10 牧草：看待草地的13种方式','要有效利用太阳能，方法只有两个：一是你到菜园中拔根胡萝卜，然后吃掉；这是人类直接利用太阳能的方法。二是把一头动物送到户外，吸收植物中的免费太阳能，然后你再吃掉那头动物。”','3575-3660',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_3147-3186','907574',16,'10 牧草：看待草地的13种方式','所有农业的核心都在于撷取免费太阳能，然后将其转变为对人类具有高度营养价值的食物','3147-3186',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_1655-1722','907574',16,'10 牧草：看待草地的13种方式','我不吃梯牧草也不吃苜蓿，但如果我吃的话，我眼中的草地可能和它看到的一样，是个有秩序、美丽而可口的沙拉吧。只要专注，便能清楚辨识各种草。','1655-1722',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_2030-2051','907574',16,'10 牧草：看待草地的13种方式','草地农业在美国农业中还是一个相当新颖的名词','2030-2051',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_4041-4065','907574',16,'10 牧草：看待草地的13种方式','重要的是，你得知道所有草的生长速度都是呈S形曲线','4041-4065',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_4377-4409','907574',16,'10 牧草：看待草地的13种方式','你该做的，就是在这个时间点、这个生长的高峰期，在这片草地上放牧。','4377-4409',0,1677420083,1782480564);
INSERT INTO highlights VALUES('907574_16_723-764','907574',16,'10 牧草：看待草地的13种方式','有意思的是，我们喜欢草的这个现象似乎跟草本身没什么关系，而是因为我们更不喜欢森林。','723-764',0,1677420082,1782480564);
INSERT INTO highlights VALUES('907574_15_39530-39598','907574',15,'09 大型有机：超市中的田园诗','整体而言，根据皮门特尔的说法，有机耕作比传统耕作省下三分之一的化石燃料，但如果堆肥不是由当地或邻近地区生产的话，省下来的燃料就又被用掉了','39530-39598',0,1677386634,1782480564);
INSERT INTO highlights VALUES('907574_15_39344-39410','907574',15,'09 大型有机：超市中的田园诗','食品工业界所耗费的石油，占了全美的五分之一，直逼汽车的用量。目前在美国，每一卡路里的食物要搬上桌，需要耗费7~10卡路里的化石燃料。','39344-39410',0,1677386634,1782480564);
INSERT INTO highlights VALUES('907574_15_39055-39112','907574',15,'09 大型有机：超市中的田园诗','虽然我参观过的那些有机农场并没有直接得到政府的资助，但他们确实得到了纳税人的补助，尤其是加利福尼亚补助的水费和电费','39055-39112',0,1677386272,1782480564);
INSERT INTO highlights VALUES('907574_15_38492-38574','907574',15,'09 大型有机：超市中的田园诗','自行把标签上的“有机”字样视为健康的标记，也是一种错误，尤其当这个标签出现在高度加工或是远道而来的食物上，因为这些食物在抵达餐桌之前，营养成分和风味早就流失殆尽了。','38492-38574',0,1677385739,1782480564);
INSERT INTO highlights VALUES('907574_15_21322-21371','907574',15,'09 大型有机：超市中的田园诗','有机田翻土的频率远远高于传统农场，这样会破坏耕地土壤，并且和化学药剂一样，会降低土壤中的生物活性。','21322-21371',0,1677335479,1782480564);
INSERT INTO highlights VALUES('907574_15_31574-31644','907574',15,'09 大型有机：超市中的田园诗','我发现，提供给罗西的这片空间，和典型的美国前院草坪几乎没有什么两样：这是仪式般的空间，提供给整个小区的象征意义，远多于赋予自家住户的实质意义','31574-31644',0,1677331965,1782480564);
INSERT INTO highlights VALUES('907574_15_30407-30448','907574',15,'09 大型有机：超市中的田园诗','它长得太快，7周后就能被送进烤箱，所以它可怜的双脚无法承受身体的重量，走路经常跌倒','30407-30448',0,1677331965,1782480564);
INSERT INTO highlights VALUES('907574_15_34139-34206','907574',15,'09 大型有机：超市中的田园诗','这些蔬菜是有机栽培出来的。它们没有施加合成氮肥，所以不会快速生长，而生长较慢的细胞有较厚的细胞壁、吸取的水分较少，因此能够维持新鲜度。','34139-34206',0,1677331965,1782480564);
INSERT INTO highlights VALUES('907574_15_36624-36676','907574',15,'09 大型有机：超市中的田园诗','戴维斯分校的研究人员发现，以有机或其他永续方式栽培出来的水果和蔬菜中，维生素C和各种多酚的含量都比较高。','36624-36676',0,1677331965,1782480564);
INSERT INTO highlights VALUES('907574_15_25381-25459','907574',15,'09 大型有机：超市中的田园诗','每种蔬菜的栽种条件不同，长成所需的时间也不一样，所以是各自种在数公顷大的田地里。因此，谷地看起来像是由各种巨大色块组成的马赛克，有深绿、酒红、浅绿和蓝绿色。','25381-25459',0,1677331964,1782480564);
INSERT INTO highlights VALUES('907574_15_26324-26354','907574',15,'09 大型有机：超市中的田园诗','用合理的价格贩卖有机产品，只有在采收之后立即进入传统供应链。','26324-26354',0,1677331964,1782480564);
INSERT INTO highlights VALUES('907574_15_27555-27715','907574',15,'09 大型有机：超市中的田园诗','500克免洗沙拉可提供80卡路里热量，而根据康奈尔大学生态学家戴维·皮门特尔（David Pimentel）的计算，栽种、冷藏、清洗、包装、然后运输一盒这样的有机生菜到东岸，至少需要消耗4600卡路里的化石燃料能量，也就是每卡路里的食物需要消耗57卡路里的化石燃料能量。（如果以传统方式栽种，所需的能量还要再增加4%）。','27555-27715',0,1677331964,1782480564);
INSERT INTO highlights VALUES('907574_15_28113-28157','907574',15,'09 大型有机：超市中的田园诗','在“全食”超市中，这盒走了5天路程、奔波了5000千米的生菜，可以被称为“有机食品”吗？','28113-28157',0,1677331964,1782480564);
INSERT INTO highlights VALUES('907574_15_30348-30390','907574',15,'09 大型有机：超市中的田园诗','考尼什杂交鸡代表着产业化鸡育种的最高杰作，能以有史以来的最高效率，将玉米转变成鸡胸肉','30348-30390',0,1677331964,1782480564);
INSERT INTO highlights VALUES('907574_15_22138-22205','907574',15,'09 大型有机：超市中的田园诗','有许多研究指出，就单位面积的平均生产量计算，小农场的生产力比大农场更高，不过由于小农场不会大量栽种单一作物，因此小农场的交易成本会较高','22138-22205',0,1677331963,1782480564);
INSERT INTO highlights VALUES('907574_15_21913-22011','907574',15,'09 大型有机：超市中的田园诗','为何最接近有机理念的农场主都倾向于小规模耕作。有些农场主真的可以在一块田地种植几十种作物，从事长久而细腻的轮耕，因此在时间与空间上都具有多样性，而这种师法大自然运作的方式，才是农场永续经营的关键。','21913-22011',0,1677331963,1782480564);
INSERT INTO highlights VALUES('907574_15_24349-24371','907574',15,'09 大型有机：超市中的田园诗','米拉的父亲就发明了能够重复轻柔清洗生菜的机器','24349-24371',0,1677331963,1782480564);
INSERT INTO highlights VALUES('907574_15_21371-21417','907574',15,'09 大型有机：超市中的田园诗','频繁的翻土操作也会把许多氮元素释放到空气中，因此这些没有杂草的有机农地比传统农地需要更多氮肥','21371-21417',0,1677331130,1782480564);
INSERT INTO highlights VALUES('907574_15_18083-18372','907574',15,'09 大型有机：超市中的田园诗','结果有机产业获胜，最后出炉的法规完全忽略1990年颁布的法规，从维生素C到黄原胶之类的添加剂和合成物，都纳入了有机食品的合法名单中￼。','18083-18372',0,1677329685,1782480564);
INSERT INTO highlights VALUES('907574_15_16862-16913','907574',15,'09 大型有机：超市中的田园诗','在1997年颁布了一项宽松到令人惊异的标准：转基因、放射线辐射杀菌等乱七八糟的东西，一概纳入有机范围。','16862-16913',0,1677326378,1782480564);
INSERT INTO highlights VALUES('907574_15_16706-16766','907574',15,'09 大型有机：超市中的田园诗','然而，定义“有机”一事，居然拖了10年，因为该词在市场上已具有某种魔力，因此有机运动内外的各方势力竞相争夺该词的控制权。','16706-16766',0,1677326357,1782480564);
INSERT INTO highlights VALUES('907574_15_13394-13545','907574',15,'09 大型有机：超市中的田园诗','霍华有机农业的概念是前现代的，甚至是反科学的，他告诉我们无须为了控制自然，处心积虑地去了解腐殖质的运作及堆肥的效果。即使我们对于生机盎然的土壤一无所知，甚至将其视为荒野，也不妨碍我们呵护它。更何况，保持一无所知的状态，或是将其视为奥秘，都是一种健康的心态。这让我们免于过度简化事实，误以为科技是万灵丹。','13394-13545',0,1677316987,1782480564);
INSERT INTO highlights VALUES('907574_15_12486-12540','907574',15,'09 大型有机：超市中的田园诗','肥料虽能在短期内使收成剧增，但无法持久，因为化合物最后会摧毁土壤的肥力，今日的高收成不过是在掠夺未来的收成。','12486-12540',0,1677316859,1782480564);
INSERT INTO highlights VALUES('907574_15_11716-11861','907574',15,'09 大型有机：超市中的田园诗','一旦科学把某个现象简化成一些变量，不论这些变量有多么重要，人类都会把变量以外的事情忽略掉，然后假定所有要纳入考虑（或至少是重要的）的东西都在这些变量中。在面对肥沃土壤这样的神秘事物时，承认自己的无知是种健康的心态，因为一旦我们误以为自己已了解事情的全貌，就会过度傲慢，把自然当成机器来对待。','11716-11861',0,1677316764,1782480564);
INSERT INTO highlights VALUES('907574_15_11412-11463','907574',15,'09 大型有机：超市中的田园诗','根瘤菌，就生长在植物的根与根之间的土壤中，这些真菌会提供植物所需的可溶性养分，而植物则回报真菌一点蔗糖','11412-11463',0,1677316702,1782480564);
INSERT INTO highlights VALUES('907574_15_11496-11523','907574',15,'09 大型有机：超市中的田园诗','细菌会固定大气中的氮元素，将其转变为植物能够吸收的形式','11496-11523',0,1677316690,1782480564);
INSERT INTO highlights VALUES('907574_15_11337-11389','907574',15,'09 大型有机：超市中的田园诗','腐殖质并不是分解的终点，因为还有另一群生物会慢慢把腐殖质分解成植物生长所需的化学元素，包括氮、磷、钾等。','11337-11389',0,1677316644,1782480564);
INSERT INTO highlights VALUES('907574_15_11217-11288','907574',15,'09 大型有机：超市中的田园诗','小小一把土壤里，就栖息了成千上万个大大小小的生物，包括了细菌、噬菌体、真菌和蚯蚓，这些生物负责有机物的分解工作，而分解后剩下的东西，就是腐殖质','11217-11288',0,1677316618,1782480564);
INSERT INTO highlights VALUES('907574_15_11166-11190','907574',15,'09 大型有机：超市中的田园诗','腐殖质是土壤的成分，赋予土壤黑色外观与特殊气味。','11166-11190',0,1677316607,1782480564);
INSERT INTO highlights VALUES('907574_15_10535-10587','907574',15,'09 大型有机：超市中的田园诗','在霍华德的书中，引诱人类堕落的蛇，是19世纪德国的化学家利比希，他诱惑人类的果实则是一组英文缩写：NPK','10535-10587',0,1677316525,1782480564);
INSERT INTO highlights VALUES('907574_15_10179-10216','907574',15,'09 大型有机：超市中的田园诗','我们必须将“土壤、植物、动物以及人类的健康问题，当作一个重要的完整议题”。','10179-10216',0,1677316469,1782480564);
INSERT INTO highlights VALUES('907574_15_8248-8272','907574',15,'09 大型有机：超市中的田园诗','“反精致烹调”运动强调使用全谷物与未加工有机食材','8248-8272',0,1677316247,1782480564);
INSERT INTO highlights VALUES('907574_15_8075-8148','907574',15,'09 大型有机：超市中的田园诗','他们不仅要建立一套另类的生产模式（无化学药剂的农业），还要建立一套另类的销售系统（反资本主义的食物合作社），甚至是另类的食用模式（“反精致烹调”）','8075-8148',0,1677316214,1782480564);
INSERT INTO highlights VALUES('907574_15_3869-3919','907574',15,'09 大型有机：超市中的田园诗','当墙上的海报仍描绘着家庭农场的图像及相关的耕作理念，下方的商品却主要来自加利福尼亚有机种植的两大公司','3869-3919',0,1677292287,1782480564);
INSERT INTO highlights VALUES('907574_15_4065-4115','907574',15,'09 大型有机：超市中的田园诗','这两家公司主宰了美国有机生鲜食品市场，其中单是扎根大地农场生产的有机生菜就占全美市场销售量的80%。','4065-4115',0,1677292271,1782480564);
INSERT INTO highlights VALUES('907574_15_2875-2899','907574',15,'09 大型有机：超市中的田园诗','，以及特殊的文学风格（我称之为“超市中的田园诗”','2875-2899',0,1677292133,1782480564);
INSERT INTO highlights VALUES('907574_15_2609-2654','907574',15,'09 大型有机：超市中的田园诗','有机标签或许能让人脑海中浮现出一幅更单纯的农业印象，但这枚标签本身其实也是工业化的人造物。','2609-2654',0,1677292095,1782480564);
INSERT INTO highlights VALUES('907574_15_2554-2609','907574',15,'09 大型有机：超市中的田园诗','为了跨越这个距离，我们得仰赖认证者和标签撰写者，甚至还要自行运用许多想象力，来描绘这些食品生产农场的真实样貌。','2554-2609',0,1677292092,1782480564);
INSERT INTO highlights VALUES('907574_13_9785-9853','907574',13,'第二部分 田园牧草','虽然我们有能力从萨利纳斯山谷运来有机莴苣，或是从秘鲁进口有机鲜切花，但如果我们真正严肃地看待能源、时令产品和生物地缘主义，就不该这样做。','9785-9853',0,1677244897,1782480564);
INSERT INTO highlights VALUES('907574_13_7375-7422','907574',13,'第二部分 田园牧草','波利弗斯农场在技术上来说，并非有机农场，但是不论以何种标准来看，它都比其他有机农场更“永续”。','7375-7422',0,1677244732,1782480564);
INSERT INTO highlights VALUES('907574_13_5705-5756','907574',13,'第二部分 田园牧草','我一度认为我们修剪草地是在展现人类的主宰权，事实上人类剪除各种灌木与乔木，不过是草类占领全世界的伎俩。','5705-5756',0,1677244528,1782480564);
INSERT INTO highlights VALUES('907574_13_5335-5410','907574',13,'第二部分 田园牧草','当时的采猎者也跟萨拉丁一样，会刻意维护草地的丰美，这样才能吸引动物前来觅食并把它们养肥，再加以猎捕。猎人会定期在草原上放火，好烧掉树苗，并让土壤肥沃。','5335-5410',0,1677244446,1782480564);
INSERT INTO highlights VALUES('907574_13_4829-4928','907574',13,'第二部分 田园牧草','人类对于草地的喜好是一种生物趋性，这种倾向常被用来说明伟大生物学家爱德华．威尔森（E. O. Wilson）的“亲生命性”（biophilia），亦即人类在天性中，喜欢亲近一同演化出的动植物与环境。','4829-4928',0,1677231239,1782480564);
INSERT INTO highlights VALUES('907574_13_4441-4572','907574',13,'第二部分 田园牧草','旧约《圣经》说：“凡有血气的，尽都如草。￼”','4441-4572',0,1677212858,1782480564);
INSERT INTO highlights VALUES('907574_13_4110-4336','907574',13,'第二部分 田园牧草','地面上还有许多昆虫在漫步，地面下方的通道也进驻了许多动物，包括蚯蚓（从地面堆起的沙土可知它们的存在）、土拨鼠、鼹鼠和穴居昆虫；而它们活动的野地下，则住满看不见的细菌、噬菌体、如鳗鱼般的细长线虫、如虾般有节肢的轮虫，以及绵延数公里的菌丝（这是真菌在地底下的丝状结构）。我们认为草乃是食物链基础，但在草地之下的土壤，则容纳了众多生物的生息与死亡，交织出的复杂生态体系超乎人类想象。由于健康的土壤会消化死亡的生物体来滋养活的生物，所以萨拉丁称其为“大地之胃”','4110-4336',0,1677212445,1782480564);
INSERT INTO highlights VALUES('907574_13_3983-4099','907574',13,'第二部分 田园牧草','萨拉丁以蚂蚁般的细微视角，在一块30厘米见方的草地上，一一指出生活在里面的生物：鸭茅草、狐尾草、数种羊茅草、早熟禾和梯牧草。接着又找到几种豆科植物：红苜蓿、白苜蓿和羽扇豆。最后则是非禾草类的阔叶草本植物，如车前草、蒲公英、雪珠花等。','3983-4099',0,1677212433,1782480564);
INSERT INTO highlights VALUES('907574_13_3886-3901','907574',13,'第二部分 田园牧草','如果没有牧草，这一切都不会存在','3886-3901',0,1677204213,1782480564);
INSERT INTO highlights VALUES('907574_13_3752-3814','907574',13,'第二部分 田园牧草','萨拉丁的大胆假设是，人与大自然之间，未必一定是零合关系；未必人类获得越多，大自然就得失去越多，把表土、沃土和其上的生物都输光','3752-3814',0,1677203356,1782480564);
INSERT INTO highlights VALUES('907574_13_3597-3678','907574',13,'第二部分 田园牧草','在夏季结束之前，萨拉丁饲养的动物会将这些牧草转换成11000多千克的牛肉、22000多千克的猪肉、12000只肉鸡、800只火鸡、500只兔子和30000打鸡蛋。','3597-3678',0,1677203340,1782480564);
INSERT INTO highlights VALUES('907574_13_3327-3401','907574',13,'第二部分 田园牧草','在牛群离开这片草原之后，鸡群便开始为草地与牛群进行几项生态服务：它们啄取牛粪中美味的幼虫和蛆，而在这个过程中，牛粪会散落到各处，寄生虫的数量也会减少','3327-3401',0,1677203313,1782480564);
INSERT INTO highlights VALUES('907574_13_3459-3500','907574',13,'第二部分 田园牧草','此外，当母鸡欣喜地在这片牛啃过的短草地上轻啄，它们也会为这片草地贡献数千千克的氮肥','3459-3500',0,1677203305,1782480564);
INSERT INTO highlights VALUES('907574_13_911-976','907574',13,'第二部分 田园牧草','与我本周即将干的活相比，一个农民要为他的产品标上何种价格，都是合情合理的。鸡蛋一个1美元，非常公道；牛排一块50美元，简直太便宜。','911-976',0,1677157861,1782480564);
INSERT INTO highlights VALUES('907574_12_5019-5056','907574',12,'07 一顿餐点：快餐','汉堡和鸡块的魅力之一，是它们是没有骨头的抽象物质，让我们忘记自己吃的是动物','5019-5056',NULL,1677034637,1782480564);
INSERT INTO highlights VALUES('907574_12_4553-4577','907574',12,'07 一顿餐点：快餐','泰森公司于1983年应麦当劳的要求，发明了鸡块。','4553-4577',NULL,1677034590,1782480564);
INSERT INTO highlights VALUES('907574_12_3396-3437','907574',12,'07 一顿餐点：快餐','总而言之，鸡块比较像是个抽象的东西，而不是真实的食物，里面有关鸡的成分还有待加强。','3396-3437',NULL,1676998393,1782480564);
INSERT INTO highlights VALUES('907574_11_4578-4663','907574',11,'06 消费者：脂肪共和国','沃勒斯坦发现，如果能卖超大分量，那么人们就会吃下更多（比原来多很多）爆米花和汽水。因此就有了大桶装的爆米花和2000毫升的大杯汽水，还有之后麦当劳的巨无霸汉堡和大包薯条。','4578-4663',NULL,1676997787,1782480564);
INSERT INTO highlights VALUES('907574_11_3660-3692','907574',11,'06 消费者：脂肪共和国','不过每个人所消耗的30千克高果糖玉米糖浆，大多是掺在软饮料中的。','3660-3692',NULL,1676972816,1782480564);
INSERT INTO highlights VALUES('907574_11_3449-3535','907574',11,'06 消费者：脂肪共和国','这个结果显示，把玉米转变成高果糖玉米糖浆是一件多么聪明的事，它成功地引诱人们吃下超过自己极限的热量，大嚼过剩的玉米。脂肪共和国的玉米甜味剂，就相当于酒精共和国的玉米威士忌。','3449-3535',NULL,1676972711,1782480564);
INSERT INTO highlights VALUES('907574_11_3297-3314','907574',11,'06 消费者：脂肪共和国','每个人消耗的精制蔗糖还增加了2千克','3297-3314',NULL,1676972690,1782480564);
INSERT INTO highlights VALUES('907574_11_1926-1976','907574',11,'06 消费者：脂肪共和国','联合国在2000年的报告中指出，全世界有10亿人营养过剩，这个数字已经正式超过营养不良的人数：8亿。','1926-1976',NULL,1676955262,1782480564);
INSERT INTO highlights VALUES('907574_11_1861-1902','907574',11,'06 消费者：脂肪共和国','由于糖尿病以及其他与肥胖相关疾病的影响，这一代的小孩的寿命很可能会比他们的父母短，','1861-1902',NULL,1676955251,1782480564);
INSERT INTO highlights VALUES('907574_11_1687-1736','907574',11,'06 消费者：脂肪共和国','美国，肥胖已是官方认定的流行病，是美国目前最迫切的公共健康问题，医疗系统每年为此花费900亿美元。','1687-1736',NULL,1676955216,1782480564);
INSERT INTO highlights VALUES('907574_11_1628-1645','907574',11,'06 消费者：脂肪共和国','脂肪共和国如今已接替了酒精共和国。','1628-1645',NULL,1676955199,1782480564);
INSERT INTO highlights VALUES('907574_11_1222-1241','907574',11,'06 消费者：脂肪共和国','而原因很简单：美国农民生产的玉米太多，','1222-1241',NULL,1676955166,1782480564);
INSERT INTO highlights VALUES('907574_11_731-793','907574',11,'06 消费者：脂肪共和国','事实上，现在上班的咖啡时间，起源于将近中午时的喝威士忌时间“11时午前茶”（elevenses，这个字连发音都像是喝醉了酒）','731-793',NULL,1676955120,1782480564);
INSERT INTO highlights VALUES('907574_11_485-508','907574',11,'06 消费者：脂肪共和国','1820年，一般美国人每天要喝下约250毫升酒','485-508',NULL,1676955100,1782480564);
INSERT INTO highlights VALUES('907574_10_11569-11642','907574',10,'05 加工处理厂：制造合成食物','食品工业终于克服了胃纳有限的困境。你一餐要吃多少就可以吃多少，因为这些食物只会在消化道中经过而不留下痕迹。现在我们成为弹性十足的终极工业饮食者了。','11569-11642',NULL,1676933095,1782480564);
INSERT INTO highlights VALUES('907574_10_9328-9390','907574',10,'05 加工处理厂：制造合成食物','后来，就连营养强化面粉也变成了原材料，所以通用磨坊迈出更加远离自然（也远离了农场和植物）的一步，发明了蛋糕粉和甜味早餐谷物。','9328-9390',NULL,1676932535,1782480564);
INSERT INTO highlights VALUES('907574_10_9142-9178','907574',10,'05 加工处理厂：制造合成食物','由廉价原材料所生产的高附加值产品，自身也会变成另一种又多又便宜的原材料。','9142-9178',NULL,1676932474,1782480564);
INSERT INTO highlights VALUES('907574_10_8945-8962','907574',10,'05 加工处理厂：制造合成食物','食物能够赚钱，但是种食物不会赚钱。','8945-8962',NULL,1676932423,1782480564);
INSERT INTO highlights VALUES('907574_10_8816-8907','907574',10,'05 加工处理厂：制造合成食物','像鸡蛋这种未经处理的食物，花1美元会有0.4美元返给养鸡业者；相较之下，奈勒只能从1美元的玉米甜味剂中得到0.04美元，而剩下的钱大部分都进了ADM、可口可乐、通用磨坊等公司的口袋。','8816-8907',NULL,1676932410,1782480564);
INSERT INTO highlights VALUES('907574_10_8127-8184','907574',10,'05 加工处理厂：制造合成食物','食品工业界而言，其自然增长率约为每年一个百分点，这也是美国每年人口的增长率。问题是，华尔街无法忍受这样缓慢的增长。','8127-8184',NULL,1676913921,1782480564);
INSERT INTO highlights VALUES('907574_10_6465-6530','907574',10,'05 加工处理厂：制造合成食物','所以我们只能期望在前几个月就占领市场，建立品牌忠诚度，绝不能给对手留有机会做出相同产品。因此我们得非常小心，不能让手上的牌曝光。”','6465-6530',NULL,1676902552,1782480564);
INSERT INTO highlights VALUES('907574_10_5578-5599','907574',10,'05 加工处理厂：制造合成食物','成分标示（这是第三个时代才出现的文学样式）','5578-5599',NULL,1676902439,1782480564);
INSERT INTO highlights VALUES('907574_10_4888-4960','907574',10,'05 加工处理厂：制造合成食物','所以我们学会使用盐渍、风干、烟熏、腌渍等保存食物的方法，开启了第一个食品加工时代。而食品加工的第二个时代，则是以罐装、冷冻与真空包装来保存食物。','4888-4960',NULL,1676902354,1782480564);
INSERT INTO highlights VALUES('907574_10_2959-3006','907574',10,'05 加工处理厂：制造合成食物','湿磨”是非常耗能的食品生产程序，要制作出含1卡路里热量的加工食品，需消耗10卡路里的化石燃料。','2959-3006',NULL,1676753787,1782480564);
INSERT INTO highlights VALUES('907574_10_2635-2767','907574',10,'05 加工处理厂：制造合成食物','玉米油可用于烹饪或是制作色拉油，或是发生氢化反应后用来制造人造奶油等其他加工食品。氢化反应的过程是使氢原子与脂肪分子化合，这样脂肪在室温下可成为固态（氢化油本来是为了取代动物性脂肪而生产的健康产品，但现在医学研究认为，这些反式脂肪对人类动脉的影响比奶油还要糟糕）。','2635-2767',NULL,1676753737,1782480564);
INSERT INTO highlights VALUES('907574_10_2606-2634','907574',10,'05 加工处理厂：制造合成食物','这样胚芽就会浮上来。将胚芽干燥之后，我们就拿去榨玉米油。','2606-2634',NULL,1676753706,1782480564);
INSERT INTO highlights VALUES('907574_10_1270-1554','907574',10,'05 加工处理厂：制造合成食物','胚乳这个巨大的淀粉袋，是玉米对于产业化食物链的最大贡献，因为它富含长链的碳水化合物分子，而化学家已经知道如何分解这些碳水化合物，并且重组成几百种不同的有机化合物：酸类、糖类、淀粉类和醇类。倘若稍微研究一下加工食品包装上的成分标示，就会熟知这些化合物的名称：柠檬酸、乳酸、葡萄糖、果糖、麦芽糊精（maltodextrin）、乙醇（加入酒精性饮料和汽车油箱中）、山梨醇（sorbitol）、甘露醇（mannitol）、黄原胶（xanthan gum），变性淀粉和未变性的淀粉，还有糊精（dextrins）、环糊精（cyclodextrin）以及味精。以上只是一小部分而已。','1270-1554',NULL,1676753229,1782480564);
INSERT INTO highlights VALUES('907574_10_1033-1090','907574',10,'05 加工处理厂：制造合成食物','湿磨坊要做的，就是把每千克玉米转变成基本原料，让通用磨坊、麦当劳和可口可乐以这些基本原料来合成我们食用的加工食品。','1033-1090',NULL,1676753206,1782480564);
INSERT INTO highlights VALUES('907574_10_509-551','907574',10,'05 加工处理厂：制造合成食物','我们所吃到的玉米制品（不论是玉米棒、玉米片，或是加入松饼、玉米薄饼或洋芋片中的玉米粉','509-551',NULL,1676753123,1782480564);
INSERT INTO highlights VALUES('907574_10_574-582','907574',10,'05 加工处理厂：制造合成食物','甜玉米或白玉米。','574-582',NULL,1676753110,1782480564);
INSERT INTO highlights VALUES('907574_9_16325-16352','907574',9,'04 饲养场：制造肉类','所以我们现在（或说已经）不只是肉，也是2号玉米和石油。','16325-16352',NULL,1676753078,1782480564);
INSERT INTO highlights VALUES('907574_9_15815-15875','907574',9,'04 饲养场：制造肉类','假设534号小牛每天都吃11千克玉米，然后长到540千克时宰杀，那么它的一生将会消耗约130升石油，这几乎是一整桶石油。','15815-15875',NULL,1676752692,1782480564);
INSERT INTO highlights VALUES('907574_9_14591-14649','907574',9,'04 饲养场：制造肉类','我们用玉米喂牛，让牛的瘤胃变酸，然后破坏了我们食物链中防止细菌感染的重要屏障。我们原本想解决问题，最后却制造了问题。','14591-14649',NULL,1676752527,1782480564);
INSERT INTO highlights VALUES('907574_9_13884-13917','907574',9,'04 饲养场：制造肉类','人类总有一天会感染这些新菌株，而目前用来治疗这类感染的药物则会失效','13884-13917',NULL,1676752436,1782480564);
INSERT INTO highlights VALUES('907574_9_13772-13825','907574',9,'04 饲养场：制造肉类','小牛饲料中的玉米含量多到不正常，这虽能增加肉中的脂肪含量，却也破坏了小牛的健康，进而破坏了吃牛肉的人的健康','13772-13825',NULL,1676752382,1782480564);
INSERT INTO highlights VALUES('907574_9_12279-12358','907574',9,'04 饲养场：制造肉类','这些饲养场的废弃物，也含有重金属和荷尔蒙残留物，这些不易分解的化合物最后会进入水道流向下游，而科学家也发现，在下游河流中的鱼类和两栖类动物，性别特征已出现异常','12279-12358',NULL,1676752223,1782480564);
INSERT INTO highlights VALUES('907574_9_11352-11402','907574',9,'04 饲养场：制造肉类','因为长期下来，酸会腐蚀瘤胃胃壁，细菌便得以进入牛的血液，最后进入肝脏，在肝中形成脓疮，使肝功能受损。','11352-11402',NULL,1676751936,1782480564);
INSERT INTO highlights VALUES('907574_9_10733-10753','907574',9,'04 饲养场：制造肉类','吃玉米的反刍动物，最严重的毛病可能是胀气','10733-10753',NULL,1676751827,1782480564);
INSERT INTO highlights VALUES('907574_9_9126-9173','907574',9,'04 饲养场：制造肉类','把牛身上的剩余部位处理过后拿回去喂牛，似乎也很合理，直到科学家发现这么做会散播“牛海绵状脑病”','9126-9173',NULL,1676751395,1782480564);
INSERT INTO highlights VALUES('907574_9_8599-8817','907574',9,'04 饲养场：制造肉类','如果用玉米这样饱含热量的食物喂牛，主要优点是牛会快速增肥，肥瘦分布均匀，美国人喜欢这样的味道与口感。不过相较于其他牧草喂养出的动物，这种用玉米喂出来的肉类显然对身体不太健康，因为饱和脂肪酸含量较高、ω-3脂肪酸含量较低。越来越多的研究指出，吃牛肉所引起的健康问题，事实上是来自吃“玉米喂养的牛肉”（在现代，靠野生肉类为生的采猎者，罹患心脏病的概率要比美国人低）。反刍动物对玉米适应不良，而人类也一样，可能难以适应由玉米喂养出的反刍动物。','8599-8817',NULL,1676751316,1782480564);
INSERT INTO highlights VALUES('907574_9_8048-8103','907574',9,'04 饲养场：制造肉类','磨坊中规律的嘈杂声来自两个巨大的钢辊，这两个钢辊每天12小时以相反的方向把蒸过的玉米粒碾成温暖而带香气的玉米片','8048-8103',NULL,1676751213,1782480564);
INSERT INTO highlights VALUES('907574_9_7700-8019','907574',9,'04 饲养场：制造肉类','这些东西加上干燥的苜蓿和青贮饲料￼（以作为粗饲料￼），全部拌在一起，经由管道送到一辆辆自动倾卸卡车上。这些自动倾卸卡车会把这些饲料送出去，一天三次，以便让波克饲养场中总长13千米的饲料槽装满饲料。','7700-8019',NULL,1676751158,1782480564);
INSERT INTO highlights VALUES('907574_9_7623-7699','907574',9,'04 饲养场：制造肉类','磨坊旁边的棚子下面放着一桶桶液态维生素和合成雌激素，一旁的托盘上则堆着每包约22千克装的抗生素，比如瘤胃素（Rumensin）和乐菌素（Tylosin）','7623-7699',NULL,1676751150,1782480564);
INSERT INTO highlights VALUES('907574_9_5857-5905','907574',9,'04 饲养场：制造肉类','与小牛分离的母牛，会终日郁郁寡欢、低声吼叫，而且小牛会因为环境与食物改变所造成的压力而变得虚弱。','5857-5905',NULL,1676750917,1782480564);
INSERT INTO highlights VALUES('907574_9_4010-4049','907574',9,'04 饲养场：制造肉类','盖尔普立西逊和9534号母牛唯一的接触，是一份以15美元的价格邮购而来的精液。','4010-4049',NULL,1676720806,1782480564);
INSERT INTO highlights VALUES('907574_9_3662-3692','907574',9,'04 饲养场：制造肉类','美国出生的肉牛中，每5头中就有4头是由这4家公司宰杀与营销。','3662-3692',NULL,1676719851,1782480564);
INSERT INTO highlights VALUES('907574_9_2722-2775','907574',9,'04 饲养场：制造肉类','农场的肥料从哪来？（现在必须用化学肥料补救。）以及饲养场产生的污染问题如何解决？（目前几乎没有补救措施。）','2722-2775',NULL,1676718964,1782480564);
INSERT INTO highlights VALUES('907574_9_2689-2721','907574',9,'04 饲养场：制造肉类','动物饲养场最让人惊讶的事，就是把这样优雅的解决方案分成两个新问题','2689-2721',NULL,1676718963,1782480564);
INSERT INTO highlights VALUES('907574_9_2259-2324','907574',9,'04 饲养场：制造肉类','像牛这类的动物通常不吃玉米，但是现在玉米出现在它们的饮食中，就连培育出的养殖鲑鱼都可以吃玉米了。这些过剩的生物量总得找到一条出路。','2259-2324',NULL,1676718909,1782480564);
INSERT INTO highlights VALUES('907574_9_1747-1755','907574',9,'04 饲养场：制造肉类','集中型动物饲养场','1747-1755',NULL,1676718853,1782480564);
INSERT INTO highlights VALUES('907574_9_1446-1471','907574',9,'04 饲养场：制造肉类','我想知道产业化食物链是如何将1千克玉米转变成牛排的','1446-1471',NULL,1676718826,1782480564);
INSERT INTO highlights VALUES('907574_8_6074-6121','907574',8,'03 大谷仓：粮食玉米和原材料玉米','把牛纳入这条产业链特别费力，因为牛并不是天生就吃玉米。但是自然憎恶任何过剩，因此牛必须吃玉米。','6074-6121',NULL,1676513134,1782480564);
INSERT INTO highlights VALUES('907574_8_5977-6002','907574',8,'03 大谷仓：粮食玉米和原材料玉米','大部分玉米（五颗中有三颗）的终点，都是美国的饲养场','5977-6002',NULL,1676513114,1782480564);
INSERT INTO highlights VALUES('907574_8_4729-4844','907574',8,'03 大谷仓：粮食玉米和原材料玉米','从饲养场与食品工业化的兴起，到美国普遍存在的肥胖与食物中毒现象，再到连最早驯化玉米的国家都因大量买进北方廉价玉米而使国内玉米价格下跌、农民失业。人类企图消耗过剩的玉米，却由于玉米多变而矛盾的特性，使得自己同时陷入肥胖与饥饿的境地。','4729-4844',NULL,1676426284,1782480564);
INSERT INTO highlights VALUES('907574_8_4076-4107','907574',8,'03 大谷仓：粮食玉米和原材料玉米','也代表了美国每年190亿美元的税收，约有四分之一付给了玉米农。','4076-4107',NULL,1676426165,1782480564);
INSERT INTO highlights VALUES('907574_8_3112-3150','907574',8,'03 大谷仓：粮食玉米和原材料玉米','对于该物种“质量”的追求，就只朝着“产量”前进；也就是说，高产量就是高品质。','3112-3150',NULL,1676426000,1782480564);
INSERT INTO highlights VALUES('907574_8_2905-2964','907574',8,'03 大谷仓：粮食玉米和原材料玉米','由于这些标准很低（只是为虫咬、脏污、杂质和湿度设定一个可接受的标准），因此种植者和育种者可以转而把精力花费在提高产量上','2905-2964',NULL,1676425970,1782480564);
INSERT INTO highlights VALUES('907574_8_1545-1551','907574',8,'03 大谷仓：粮食玉米和原材料玉米','二号饲料玉米','1545-1551',NULL,1676425763,1782480564);
INSERT INTO highlights VALUES('907574_8_1688-1737','907574',8,'03 大谷仓：粮食玉米和原材料玉米','这种玉米的玉米粒硬得咬不动，泡入水中数小时后，你会发觉它尝起来并不像玉米，而是稍带玉米风味的淀粉。','1688-1737',NULL,1676425760,1782480564);
INSERT INTO highlights VALUES('907574_7_20645-20731','907574',7,'02 农场：一个农民养活129个人','在自然界中，如果一个物种不断扩张，等到所有食物消耗殆尽，整个族群就会崩溃。而在市场上，产品如果供给过剩，价格就会下降，直到过剩的物资消耗完毕，或是生产该产品不再有意义为止。','20645-20731',NULL,1676425618,1782480564);
INSERT INTO highlights VALUES('907574_7_20731-20766','907574',7,'02 农场：一个农民养活129个人','在玉米这个例子中，人类想尽办法让它挣脱这两种限制，就算是破产也要种玉米','20731-20766',NULL,1676425616,1782480564);
INSERT INTO highlights VALUES('907574_7_20355-20369','907574',7,'02 农场：一个农民养活129个人','人类已经成了自身工具的工具。','20355-20369',NULL,1676425474,1782480564);
INSERT INTO highlights VALUES('907574_7_19647-19701','907574',7,'02 农场：一个农民养活129个人','奈勒相信自己只要有计划地清理债务、好好保养他的老爷收割机和拖拉机，然后避开扩张的陷阱，就能够靠着农场维持生计','19647-19701',NULL,1676425405,1782480564);
INSERT INTO highlights VALUES('907574_7_19400-19421','907574',7,'02 农场：一个农民养活129个人','不过国库真正补贴的是那些购买廉价玉米的买家','19400-19421',NULL,1676383368,1782480564);
INSERT INTO highlights VALUES('907574_7_18799-19021','907574',7,'02 农场：一个农民养活129个人','在农业中，自由市场从来没有发挥作用，将来也不会发挥作用。家庭农场的经济运作模式和一般企业大不相同。当产品价格下跌，公司可以裁员、冻结生产线或减少产量，最后市场会找到新的供需平衡点。但是食物的需求量没有办法如此有弹性，人们不会因为食物比较便宜就吃得多，而解雇农民也无助于降低食物的供应量。你可以解雇我，但无法解雇我的土地，因为其他需要更大现金流或是自认为比我强的农民，会进驻这块土地然后开始耕种。所以就算我不耕种了，我的土地依然会持续生产玉米。”','18799-19021',NULL,1676383293,1782480564);
INSERT INTO highlights VALUES('907574_7_18624-18686','907574',7,'02 农场：一个农民养活129个人','奈勒说，农民情急之下大量增产，结果导致土壤退化，耕地周边的土地都拿来耕种，并且使用更多氮肥，总之想尽办法从土壤榨出更多玉米来','18624-18686',NULL,1676383216,1782480564);
INSERT INTO highlights VALUES('907574_7_18524-18585','907574',7,'02 农场：一个农民养活129个人','“在农产品价格下跌时，农民若想维持生活水平、支付账单、偿还债务，唯一的选择就是增加产量。”每个农民家庭每年都需要一定的现金','18524-18585',NULL,1676383199,1782480564);
INSERT INTO highlights VALUES('907574_7_18423-18448','907574',7,'02 农场：一个农民养活129个人','勒曲线与拉弗曲线有点儿相似，只不过奈勒曲线是真的。','18423-18448',NULL,1676383169,1782480564);
INSERT INTO highlights VALUES('907574_7_18031-18077','907574',7,'02 农场：一个农民养活129个人','所以基本上，艾奥瓦的农民每卖出1千克玉米，就要亏损4.2美分。但每年的玉米产量依旧持续增加。','18031-18077',NULL,1676383138,1782480564);
INSERT INTO highlights VALUES('907574_7_17891-17921','907574',7,'02 农场：一个农民养活129个人','随着玉米价格下跌，农场收入也持续减少，数百万农民身陷债务危机','17891-17921',NULL,1676383105,1782480564);
INSERT INTO highlights VALUES('907574_7_17149-17225','907574',7,'02 农场：一个农民养活129个人','他废除了“常平仓”，并且以1973年农业法案取代了农业新政，废除了先前以借贷、政府收购谷物以及土地休耕来维持农产品价格的做法，取而代之直接把钱付给农民。','17149-17225',NULL,1676382913,1782480564);
INSERT INTO highlights VALUES('907574_7_16313-16341','907574',7,'02 农场：一个农民养活129个人','布兹的确大幅改革了美国农业，使得食物链扎根于廉价的玉米上','16313-16341',NULL,1676382791,1782480564);
INSERT INTO highlights VALUES('907574_7_15579-15623','907574',7,'02 农场：一个农民养活129个人','“至少从南北战争以来，美国公民中最不守规矩、最独行独断，又最拥护共和政体的，就是那些小农','15579-15623',NULL,1676382710,1782480564);
INSERT INTO highlights VALUES('907574_7_14959-14986','907574',7,'02 农场：一个农民养活129个人','“常平仓”（Ever-Normal Granary）。','14959-14986',NULL,1676169362,1782480564);
INSERT INTO highlights VALUES('907574_7_14495-14559','907574',7,'02 农场：一个农民养活129个人','自从人类开始耕种，丰年造成的挑战和荒年一样严峻。如果食物过剩，作物的价格就会下跌，使农民破产，但在荒年来临时，又需要农民来耕种。','14495-14559',NULL,1676169282,1782480564);
INSERT INTO highlights VALUES('907574_7_14050-14102','907574',7,'02 农场：一个农民养活129个人','政府的农业计划本应控制产量以维持价格稳定（以及农民的生计），结果竟悄悄地把目标调整成增加产量以压低价格。','14050-14102',NULL,1676169154,1782480564);
INSERT INTO highlights VALUES('907574_7_13818-13862','907574',7,'02 农场：一个农民养活129个人','到现在，一千克玉米大约只能卖4美分，比种植成本还低——这对玉米农之外的其他人倒是个好消息','13818-13862',NULL,1676169061,1782480564);
INSERT INTO highlights VALUES('907574_7_13360-13401','907574',7,'02 农场：一个农民养活129个人','含氮的潮水刺激藻类疯狂生长，这些藻类隔绝了氧气而让鱼类窒息，制造出缺氧的“死亡区”','13360-13401',NULL,1676168955,1782480564);
INSERT INTO highlights VALUES('907574_7_12955-12996','907574',7,'02 农场：一个农民养活129个人','硝酸盐在水中会转变成亚硝酸盐，亚硝酸盐会和血红素结合，削弱血液将氧输送至大脑的能力','12955-12996',NULL,1676168895,1782480564);
INSERT INTO highlights VALUES('907574_7_12168-12257','907574',7,'02 农场：一个农民养活129个人','生产单位热量的食物，需消耗高于单位热量的化石燃料。但在化学肥料出现之前，奈勒农场投入一单位的能量，就能得到两单位能量的食物。就工业效率的观点而言，人类不能直接喝石油，真是可惜啊。','12168-12257',NULL,1676168679,1782480564);
INSERT INTO highlights VALUES('907574_7_11773-11797','907574',7,'02 农场：一个农民养活129个人','人类本来只靠着太阳的能量生存，现在开始啜饮石油了','11773-11797',NULL,1676168006,1782480564);
INSERT INTO highlights VALUES('907574_7_11171-11215','907574',7,'02 农场：一个农民养活129个人','高温高压都得耗费庞大电力，至于氢气则来自石油、煤或目前最普遍的天然气，而这些都是化石燃料','11171-11215',NULL,1676167820,1782480564);
INSERT INTO highlights VALUES('907574_7_11132-11170','907574',7,'02 农场：一个农民养活129个人','哈伯—博施法需要在高温高压的条件下，再经由催化剂的帮助，才能使氮气与氢气化合','11132-11170',NULL,1676167804,1782480564);
INSERT INTO highlights VALUES('907574_7_11117-11131','907574',7,'02 农场：一个农民养活129个人','能量来源就改由化石燃料提供了','11117-11131',NULL,1676167800,1782480564);
INSERT INTO highlights VALUES('907574_7_10684-10749','907574',7,'02 农场：一个农民养活129个人','虽然哈伯改信了基督教，但依然因其犹太人身份而在20世纪30年代被迫离开纳粹德国，并于1934年穷困潦倒地死于瑞士巴赛尔的旅馆房间。','10684-10749',NULL,1676167699,1782480564);
INSERT INTO highlights VALUES('907574_7_10348-10365','907574',7,'02 农场：一个农民养活129个人','哈伯又将自己的聪明才智用来研制毒气','10348-10365',NULL,1676167639,1782480564);
INSERT INTO highlights VALUES('907574_7_10233-10250','907574',7,'02 农场：一个农民养活129个人','第一次世界大战期间，哈伯为德军效力','10233-10250',NULL,1676167505,1782480564);
INSERT INTO highlights VALUES('907574_7_10052-10097','907574',7,'02 农场：一个农民养活129个人','不过这个数字也意味着，当哈伯赐予我们固氮的力量时，人类就像是在和大自然进行魔鬼般的交易了。','10052-10097',NULL,1676167488,1782480564);
INSERT INTO highlights VALUES('907574_7_9811-9876','907574',7,'02 农场：一个农民养活129个人','1972年美国总统尼克松访问中国之后，中国政府首要的订单就是建立13座巨大的肥料工厂。如果没有这些肥料工厂，中国可能已经陷入饥荒。','9811-9876',NULL,1676167362,1782480564);
INSERT INTO highlights VALUES('907574_7_9781-9811','907574',7,'02 农场：一个农民养活129个人','数十年后，中国科学家也产生同样的想法，中国因此实行改革开放。','9781-9811',NULL,1676167334,1782480564);
INSERT INTO highlights VALUES('907574_7_9674-9729','907574',7,'02 农场：一个农民养活129个人','在哈伯的发明出现之前，地球所能承载的生命总数（作物数量及其连带的人类数量）受限于细菌与闪电所能固定的氮的数量。','9674-9729',NULL,1676167317,1782480564);
INSERT INTO highlights VALUES('907574_7_9107-9191','907574',7,'02 农场：一个农民养活129个人','所有生物都需要氮，以便合成氨基酸、蛋白质和核酸；至于组成遗传指令并且让生命延续的遗传信息，也是以氮书写而成（所以科学家说氮提供了生命的“质”，而碳提供了生命的“量”）。','9107-9191',NULL,1676167145,1782480564);
INSERT INTO highlights VALUES('907574_7_8693-8706','907574',7,'02 农场：一个农民养活129个人','我们仍吃着‘二战’的厨余。','8693-8706',NULL,1676167036,1782480564);
INSERT INTO highlights VALUES('907574_7_8484-8509','907574',7,'02 农场：一个农民养活129个人','“二战”结束后，美国政府发现自己囤积了过量的硝酸铵','8484-8509',NULL,1676167015,1782480564);
INSERT INTO highlights VALUES('907574_7_8174-8248','907574',7,'02 农场：一个农民养活129个人','就如同许多美国人“自立自强”的成功故事，如果你看得越仔细，就越能发现背后有美国政府的影子：政府运用专利、垄断和优惠税率政策，在关键时刻推了主角一把。','8174-8248',NULL,1676166983,1782480564);
INSERT INTO highlights VALUES('907574_7_7247-7272','907574',7,'02 农场：一个农民养活129个人','在同一片土地上年复一年地种植玉米，果真带来了病虫害','7247-7272',NULL,1676166576,1782480564);
INSERT INTO highlights VALUES('907574_7_6988-7218','907574',7,'02 农场：一个农民养活129个人','20世纪五六十年代起，廉价玉米如潮水般涌现，这使得在农场用玉米养牛比在草地上放牧利润更高，而大型养鸡场也比在自家后院养鸡更好赚钱。艾奥瓦州的畜牧农民敌不过靠便宜玉米养鸡养牛的工厂（这些玉米还是那些农民种出来的呢），所以鸡和牛从农场上消失了，而放牧所需的草地与干草地也跟着不见了，取而代之的是收成量超越其他作物的物种：玉米。而当玉米价格滑落，农民就得种更多玉米才能保持收支平衡。到了20世纪80年代，艾奥瓦州原本具有多样生物景观的农家已经成为历史，玉米独霸称王。','6988-7218',NULL,1676166560,1782480564);
INSERT INTO highlights VALUES('907574_7_5608-5635','907574',7,'02 农场：一个农民养活129个人','F1杂交改良作物的田地里，实现了真正的社会主义乌托邦。','5608-5635',NULL,1676165045,1782480564);
INSERT INTO highlights VALUES('907574_7_5360-5397','907574',7,'02 农场：一个农民养活129个人','杂交改良的茎较粗，根系也更稳固，能种得更密、挺得更直，并且禁得起用机器采收','5360-5397',NULL,1676165017,1782480564);
INSERT INTO highlights VALUES('907574_7_5245-5308','907574',7,'02 农场：一个农民养活129个人','现代杂交改良玉米的高产量，主要是因为这些植株可以密集栽种。奈勒父亲的时代，一公顷地能种将近2万株，但现在可以种将近7.5万株。','5245-5308',NULL,1676164997,1782480564);
INSERT INTO highlights VALUES('907574_7_5039-5066','907574',7,'02 农场：一个农民养活129个人','到了20世纪50年代，每公顷地可以有四五千千克的收获量','5039-5066',NULL,1676164965,1782480564);
INSERT INTO highlights VALUES('907574_7_4917-4941','907574',7,'02 农场：一个农民养活129个人','到了20世纪30年代末期，杂交改良种子进入市场，','4917-4941',NULL,1676164930,1782480564);
INSERT INTO highlights VALUES('907574_7_4829-4855','907574',7,'02 农场：一个农民养活129个人','在1920年，美国每公顷地可以种出约1230千克玉米','4829-4855',NULL,1676164913,1782480564);
INSERT INTO highlights VALUES('907574_7_4523-4589','907574',7,'02 农场：一个农民养活129个人','基因改良作物跟过去的故事没什么两样：农民为了提高作物产量而采用最新发明，却发现农民大部分的生产所得，都进了发明这些技术的公司的口袋。','4523-4589',NULL,1676104961,1782480564);
INSERT INTO highlights VALUES('907574_7_4473-4499','907574',7,'02 农场：一个农民养活129个人','但是这些额外收成的玉米，最后只能补贴买更贵种子的钱。','4473-4499',NULL,1676104916,1782480564);
INSERT INTO highlights VALUES('907574_7_3258-3321','907574',7,'02 农场：一个农民养活129个人','就如同那个经典的数学题：“我们的呼吸的气体中，可能都包含了凯撒死前的最后一口气。”如果那些玉米没进到我口中，那也会进到你口中。','3258-3321',NULL,1676104558,1782480564);
INSERT INTO highlights VALUES('907574_7_2396-2440','907574',7,'02 农场：一个农民养活129个人','但是奈勒却处于破产边缘，而且邻居比他还惨（或许是因为他还在开那部1975年产的拖拉机）。','2396-2440',NULL,1676094342,1782480564);
INSERT INTO highlights VALUES('907574_7_2329-2367','907574',7,'02 农场：一个农民养活129个人','如果以每人的产能来计算，奈勒这样的人可说是人类自古至今生产效率最高的生产者。','2329-2367',NULL,1676094336,1782480564);
INSERT INTO highlights VALUES('907574_7_2039-2079','907574',7,'02 农场：一个农民养活129个人','而奈勒农场亦随着20世纪美国农业的发展，亦步亦趋地前进；那是个成就，也是场灾难。','2039-2079',NULL,1676086824,1782480564);
INSERT INTO highlights VALUES('907574_7_1726-1766','907574',7,'02 农场：一个农民养活129个人','大须芒草、狐尾草、针茅草与柳枝稷等；这些禾草每10年就会留下3~5厘米厚的土壤。','1726-1766',NULL,1676086762,1782480564);
INSERT INTO highlights VALUES('907574_7_1653-1693','907574',7,'02 农场：一个农民养活129个人','艾奥瓦州的这块地，有着全世界最肥沃的土壤，那里有一层厚约60厘米的松软冲积土壤。','1653-1693',NULL,1676086747,1782480564);
INSERT INTO highlights VALUES('907574_6_1630-1658','907574',6,'01 植物：玉米的领地','在这样小小一块面积上有那么多不同种类的植物、动物和真菌！','1630-1658',NULL,1676086384,1782480564);
INSERT INTO highlights VALUES('907574_5_13625-13702','907574',5,'第一部分 产业化的玉米','不过最重要的是，育种者发现F1种子杂交后产下的第二代（F2），和F1几乎没有相同之处；特别是到第三代时，产量更是一落千丈。所以后来生产的种子几乎没有用处。','13625-13702',NULL,1676086112,1782480564);
INSERT INTO highlights VALUES('907574_5_13327-13378','907574',5,'第一部分 产业化的玉米','如果一个产品售出之后，可以永远自行生产，那就很难掌控生产方式。这是生物规则和商业规则难以紧密配合之处。','13327-13378',NULL,1676086022,1782480564);
INSERT INTO highlights VALUES('907574_5_13241-13326','907574',5,'第一部分 产业化的玉米','那么我就能贩卖具有这种特征的玉米种子。然而这笔买卖却只能做一次，因为这种特殊种子会长成玉米，然后产出更多特殊种子，如此生生不息，永远都不用再花钱，所以这笔生意一下子就没了','13241-13326',NULL,1676085990,1782480564);
INSERT INTO highlights VALUES('907574_5_10693-10734','907574',5,'第一部分 产业化的玉米','比起长在顶端，玉米包长在茎节上更能够吸收养分，因而突然间就有能力产生数百个巨大种子','10693-10734',NULL,1676085809,1782480564);
INSERT INTO highlights VALUES('907574_5_12386-12435','907574',5,'第一部分 产业化的玉米','玉蜀黍这个物种是否能存活，取决于它能否满足人类持续改变的需求，而目前也证实了这是个卓越的演化策略。','12386-12435',NULL,1676085692,1782480564);
INSERT INTO highlights VALUES('907574_5_12149-12181','907574',5,'第一部分 产业化的玉米','对人类而言，要媒合同一株玉蜀黍中的花粉和雌花，是再简单不过的事情','12149-12181',NULL,1676085668,1782480564);
INSERT INTO highlights VALUES('907574_5_11638-11703','907574',5,'第一部分 产业化的玉米','其中一个细胞核负责在细长的花柱中打通一条用显微镜才看得到的细小管道，另一个细胞核则沿着这条通道滑下，穿过外壳，进入久候多时的花朵中','11638-11703',NULL,1676085584,1782480564);
INSERT INTO highlights VALUES('907574_5_11582-11609','907574',5,'第一部分 产业化的玉米','花粉中的细胞核会一分为二，成为一对带有相同基因的细胞核','11582-11609',NULL,1676085579,1782480564);
INSERT INTO highlights VALUES('907574_5_11448-11471','907574',5,'第一部分 产业化的玉米','一条细长有黏性的丝状物（植物学上称为“花柱”）','11448-11471',NULL,1676085378,1782480564);
INSERT INTO highlights VALUES('907574_5_11272-11294','907574',5,'第一部分 产业化的玉米','玉米的雄花长得像一般的花，而雌花长得像阴茎。','11272-11294',NULL,1676022104,1782480564);
INSERT INTO highlights VALUES('907574_5_11171-11202','907574',5,'第一部分 产业化的玉米','对于散布基因这件事，雄性的基本守则是“有备无患”与“多多益善”','11171-11202',NULL,1676022086,1782480564);
INSERT INTO highlights VALUES('907574_5_11105-11170','907574',5,'第一部分 产业化的玉米','在夏季，花药会于数日内释放出大量黄色粉末状花粉，平均每株植物可以释放出1400万到1800万个花粉，相当于一个玉米粒就有2万个花粉','11105-11170',NULL,1676022077,1782480564);
INSERT INTO highlights VALUES('907574_5_10456-10492','907574',5,'第一部分 产业化的玉米','目前植物学家的普遍看法是，数千年前，大刍草发生一连串意外突变，而成为玉米','10456-10492',NULL,1675993991,1782480564);
INSERT INTO highlights VALUES('907574_5_10316-10332','907574',5,'第一部分 产业化的玉米','事实上，野生玉米在今日已经不存在','10316-10332',NULL,1675993966,1782480564);
INSERT INTO highlights VALUES('907574_5_9708-9758','907574',5,'第一部分 产业化的玉米','玉米是用来购买这些非洲奴隶的交易物，也是这些奴隶在前往美国途中的食物。玉米是一种原始资本主义的植物。','9708-9758',NULL,1675993909,1782480564);
INSERT INTO highlights VALUES('907574_5_9634-9682','907574',5,'第一部分 产业化的玉米','玉米同时兼具食品与商品的特性，许多农民因此专门种植玉米，使这种赖以生存的庄稼一跃成为市场经济作物','9634-9682',NULL,1675993900,1782480564);
INSERT INTO highlights VALUES('907574_5_9089-9128','907574',5,'第一部分 产业化的玉米','玉米经压碎与发酵，能够酿成啤酒，或蒸馏成威士忌，这是当时拓荒者唯一的酒精来源。','9089-9128',NULL,1675993815,1782480564);
INSERT INTO highlights VALUES('907574_5_8418-8507','907574',5,'第一部分 产业化的玉米','corn这个英文单词最初是用来指称所有谷粒或粒状物，例如盐粒。因此盐腌牛肉的英文是corned beef。玉蜀黍很快就独占了corn这个词。现在，至少在美国，corn就是指玉米。','8418-8507',NULL,1675993709,1782480564);
INSERT INTO highlights VALUES('907574_5_7713-7772','907574',5,'第一部分 产业化的玉米','他提及一种高大的禾草，长着手臂般粗大的穗，上面的谷粒“天生就排列得非常整齐，大小如同菜园中的豆子，还未成熟时是白色的”','7713-7772',NULL,1675952461,1782480564);
INSERT INTO highlights VALUES('907574_5_6978-6994','907574',5,'第一部分 产业化的玉米','这就是美国人：会走路的加工玉米。','6978-6994',NULL,1675952353,1782480564);
INSERT INTO highlights VALUES('907574_5_6484-6505','907574',5,'第一部分 产业化的玉米','在西方，小麦被认为是最精致、最文明的作物。','6484-6505',NULL,1675952232,1782480564);
INSERT INTO highlights VALUES('907574_5_6250-6287','907574',5,'第一部分 产业化的玉米','如果人体里碳13对碳12的比值越高，就表示这个人饮食中玉米所占的比例越高，','6250-6287',NULL,1675926602,1782480564);
INSERT INTO highlights VALUES('907574_5_6148-6184','907574',5,'第一部分 产业化的玉米','不知何故，四碳植物在捕捉碳原子以合成四个碳的分子时，比较容易抓到碳13，','6148-6184',NULL,1675926588,1782480564);
INSERT INTO highlights VALUES('907574_5_5751-5819','907574',5,'第一部分 产业化的玉米','地球上万物的故事，从最基本的角度来看，就是物种间收集与储存能量的竞争。植物间彼此竞逐阳光，动物之间则争夺其他植物或动物身上所含有的能量。','5751-5819',NULL,1675926508,1782480564);
INSERT INTO highlights VALUES('907574_5_5638-5689','907574',5,'第一部分 产业化的玉米','玉米每次进行光合作用都会吸收额外的碳原子，因此不但能够限制水分逸出，又能把这些碳原子连接到有用的分子上','5638-5689',NULL,1675916814,1782480564);
INSERT INTO highlights VALUES('907574_5_5546-5595','907574',5,'第一部分 产业化的玉米','每当气孔张开让二氧化碳进入时，珍贵的水分子也会同时逸出。这就像是每当你张口吃饭，就会流失一些血液。','5546-5595',NULL,1675916792,1782480564);
INSERT INTO highlights VALUES('907574_5_5319-5377','907574',5,'第一部分 产业化的玉米','大部分植物进行光合作用时，会产生含有三个碳原子的分子，但是玉米（以及其他一小部分物种）产生的是含有四个碳原子的分子。','5319-5377',NULL,1675916741,1782480564);
INSERT INTO highlights VALUES('907574_5_5241-5272','907574',5,'第一部分 产业化的玉米','这个差异让玉米的光合作用更高效，也使收集到的碳原子具备某种特征','5241-5272',NULL,1675916730,1782480564);
INSERT INTO highlights VALUES('907574_5_4773-4793','907574',5,'第一部分 产业化的玉米','人类细胞组织中碳同位素的比例具有识别作用','4773-4793',NULL,1675905792,1782480564);
INSERT INTO highlights VALUES('907574_5_3953-3989','907574',5,'第一部分 产业化的玉米','从牙膏、化妆品到纸尿布、垃圾袋、清洁剂、煤块、火柴、电池等，都含有玉米。','3953-3989',NULL,1675905708,1782480564);
INSERT INTO highlights VALUES('907574_5_3907-3952','907574',5,'第一部分 产业化的玉米','美国的超市平均卖出45000种商品，其中四分之一以上含有玉米，甚至连非食用的商品也难以幸免','3907-3952',NULL,1675905698,1782480564);
INSERT INTO highlights VALUES('907574_5_2971-3001','907574',5,'第一部分 产业化的玉米','其中最主要的只有一种：玉蜀黍，大多数美国人都称之为“玉米”。','2971-3001',NULL,1675905597,1782480564);
INSERT INTO highlights VALUES('907574_5_2722-2916','907574',5,'第一部分 产业化的玉米','然而最终追溯到的起点，却往往是一样的：“玉米带”￼上的某块农地。','2722-2916',NULL,1675905524,1782480564);
INSERT INTO highlights VALUES('907574_5_1999-2056','907574',5,'第一部分 产业化的玉米','自然学家认为，生物多样性是土地健康的指标。现代超市致力于提供多样的产品与选择，似乎也反映出甚至促进了生态系的活力。','1999-2056',NULL,1675905423,1782480564);
INSERT INTO highlights VALUES('907574_5_737-773','907574',5,'第一部分 产业化的玉米','这也说明了为何这个果蔬成列的田园（有时也有鲜花），通常都位于顾客进门处。','737-773',NULL,1675905284,1782480564);
INSERT INTO highlights VALUES('907574_4_8019-8131','907574',4,'引言 全国性饮食失调','一如美国作家温德尔·贝里（Wendell Berry）的名言：“饮食就是农业活动。”然而饮食也是生态活动和政治活动，只不过许多事情都掩盖了这个简单事实。人类吃什么、怎么吃，强烈决定了人类利用这个世界的方式，以及改变世界的幅度','8019-8131',NULL,1675863555,1782480564);
INSERT INTO highlights VALUES('907574_4_7791-7826','907574',4,'引言 全国性饮食失调','工业化饮食最棘手与悲哀之处，在于其彻底掩埋了人类与各物种的关系与联系。','7791-7826',NULL,1675863526,1782480564);
INSERT INTO highlights VALUES('907574_4_7606-7667','907574',4,'引言 全国性饮食失调','其中许多物种都经过特意的演化，以取悦人类的感官。这样精巧的驯化让这些物种和人类一起成功繁衍，远超乎单独进化所能达到的地步。','7606-7667',NULL,1675863502,1782480564);
INSERT INTO highlights VALUES('907574_4_7187-7221','907574',4,'引言 全国性饮食失调','在农业发展初期，以及更久远的狩猎时期，人类就已对大自然造成巨大破坏。','7187-7221',NULL,1675863414,1782480564);
INSERT INTO highlights VALUES('907574_4_6976-7029','907574',4,'引言 全国性饮食失调','我们总想在食物链的生产端与食用端过度简化大自然的复杂性，结果是人类生产食物的系统酿成了许多健康与环境问题。','6976-7029',NULL,1675863369,1782480564);
INSERT INTO highlights VALUES('907574_4_6410-6426','907574',4,'引言 全国性饮食失调','与其说是实用性，不如说是哲学性。','6410-6426',NULL,1675863290,1782480564);
INSERT INTO highlights VALUES('907574_4_5749-5776','907574',4,'引言 全国性饮食失调','第二部所谈的是“田园食物链”，内容有别于产业化食物链。','5749-5776',NULL,1675863120,1782480564);
INSERT INTO highlights VALUES('907574_4_5551-5570','907574',4,'引言 全国性饮食失调','大规模种植单一作物是产业化食物链的特征','5551-5570',NULL,1675863110,1782480564);
INSERT INTO highlights VALUES('907574_4_5586-5589','907574',4,'引言 全国性饮食失调','玉蜀黍','5586-5589',NULL,1675863074,1782480564);
INSERT INTO highlights VALUES('907574_4_5236-5254','907574',4,'引言 全国性饮食失调','产业化农业的能量则大多来源于化石燃料','5236-5254',NULL,1675863029,1782480564);
INSERT INTO highlights VALUES('907574_4_5092-5124','907574',4,'引言 全国性饮食失调','生态学也告诉我们，地球上所有生物都可视作为太阳能而战的竞争物种。','5092-5124',NULL,1675863015,1782480564);
INSERT INTO highlights VALUES('907574_4_5149-5180','907574',4,'引言 全国性饮食失调','而所谓的食物链，就是让这些能量传递到缺乏这种吸收能力的物种身上','5149-5180',NULL,1675863012,1782480564);
INSERT INTO highlights VALUES('907574_4_4792-4824','907574',4,'引言 全国性饮食失调','经由我们所吃的食物，将人类与土地的生产力以及太阳的能量联结起来。','4792-4824',NULL,1675862965,1782480564);
INSERT INTO highlights VALUES('907574_4_4730-4772','907574',4,'引言 全国性饮食失调','本书将说明目前维系人类生存的三条主要食物链：产业化食物链、有机食物链以及采猎食物链。','4730-4772',NULL,1675862949,1782480564);
INSERT INTO highlights VALUES('907574_4_4229-4274','907574',4,'引言 全国性饮食失调','我们与生俱来的观察力与记忆力，以及对于大自然的好奇心与实验精神，也大多拜杂食这种特性所赐。','4229-4274',NULL,1675840784,1782480564);
INSERT INTO highlights VALUES('907574_4_4096-4161','907574',4,'引言 全国性饮食失调','我的基本假设是，人类和地球上其他生物一样，都是食物链中的一环，人类在食物链（或食物网）中的地位，或多或少决定了人类是什么样的生物。','4096-4161',NULL,1675840769,1782480564);
INSERT INTO highlights VALUES('907574_4_3987-4014','907574',4,'引言 全国性饮食失调','整个自然界就是‘吃’在主动语态与被动语态间的动词变化。','3987-4014',NULL,1675840743,1782480564);
INSERT INTO highlights VALUES('907574_4_3401-3427','907574',4,'引言 全国性饮食失调','而我发现，这一切还可追溯到艾奥瓦州等地的广大玉米田。','3401-3427',NULL,1675840632,1782480564);
INSERT INTO highlights VALUES('907574_4_3258-3357','907574',4,'引言 全国性饮食失调','由于缺乏坚实的饮食文化，我们非常容易受到食品科学家与商人的诱骗。对这些人而言，杂食者的两难反而是个机会。食品工业为了自身利益，先以各种方式加深消费者对于吃的焦虑，然后再塞给我们新产品来化解这种焦虑。','3258-3357',NULL,1675840602,1782480564);
INSERT INTO highlights VALUES('907574_4_2931-2964','907574',4,'引言 全国性饮食失调','。有了这些饮食传统，身为杂食者的人类便无须餐餐面对吃与不吃的两难。','2931-2964',NULL,1675840512,1782480564);
INSERT INTO highlights VALUES('907574_4_2514-2553','907574',4,'引言 全国性饮食失调','许多人类学家坚信，人类会演化出如此大而精密的脑，就是为了解决杂食者的两难问题。','2514-2553',NULL,1675840389,1782480564);
INSERT INTO highlights VALUES('907574_4_1937-2028','907574',4,'引言 全国性饮食失调','在某种程度上，“正餐要吃什么”这个问题，一直困扰着杂食动物。毕竟自然界的东西你几乎都可以吃，因此决定要吃什么，当然会引起焦虑，特别是有些食物很可能会致病甚至致命。这是“杂食者的两难”','1937-2028',NULL,1675840321,1782480564);
INSERT INTO highlights VALUES('907574_4_1111-1175','907574',4,'引言 全国性饮食失调','2002年夏天，《纽约时报杂志》针对这些研究，刊出封面故事“如果脂肪并不会让你发胖？”，更让饮食内容的方向发生了180度的转变。','1111-1175',NULL,1675839830,1782480564);
INSERT INTO highlights VALUES('907574_4_795-829','907574',4,'引言 全国性饮食失调','而现在，全民畏惧的对象改为碳水化合物，此症状如同痉挛发作，席卷全国。','795-829',NULL,1675839723,1782480564);
INSERT INTO highlights VALUES('907574_4_764-780','907574',4,'引言 全国性饮食失调','之后美国就进入“畏惧脂肪”的时代','764-780',NULL,1675839715,1782480564);
INSERT INTO highlights VALUES('907574_4_670-702','907574',4,'引言 全国性饮食失调','人类古老而珍贵的一种主食，竟突然从美国餐桌上消失——我指的是面包','670-702',NULL,1675839699,1782480564);
INSERT INTO highlights VALUES('907574_4_533-559','907574',4,'引言 全国性饮食失调','吃什么”这样的基本问题，居然也需仰赖许多专家来帮助。','533-559',NULL,1675839684,1782480564);
