INSERT INTO highlights VALUES('3300095033_26_1694-1720','3300095033',26,'结束语','但与此同时，你还必须学会在正确的时机使用合宜的工具。','1694-1720',5,1719538001,1782480557);
INSERT INTO highlights VALUES('3300095033_26_1442-1494','3300095033',26,'结束语','当我们期望别人做出超出他们能力范围的事时，就等于是在给自己找不快，这和对一只不会飞的企鹅发火没什么不同！','1442-1494',5,1719537949,1782480557);
INSERT INTO highlights VALUES('3300095033_26_1189-1237','3300095033',26,'结束语','跟大家分享一个诀窍，那就是将对方视为一个有价值的资源，能用来帮助你明确自己所持观点的优点和缺点。','1189-1237',5,1719537897,1782480557);
INSERT INTO highlights VALUES('3300095033_35_8216-8270','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','但有的时候即使给出反馈也不会产生什么效果。遇到这种不大常见的情况，接受对方是一只企鹅，对我们而言是一种解脱。','8216-8270',5,1719504091,1782480557);
INSERT INTO highlights VALUES('3300095033_35_7555-7665','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？',unistr('接受：“他就是这样一个人，在这种情况下是没法儿改变的。要想让事态有所改变，全都要靠我，我必须得成为那个先做点儿什么的人。”\u000a想要剔除冲突中的毒素，我们就要选择接受。'),'7555-7665',5,1719463898,1782480557);
INSERT INTO highlights VALUES('3300095033_35_6992-7020','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','悲伤的五个阶段的阐述，即否认、愤怒、讨价还价、抑郁和接受','6992-7020',5,1719463833,1782480557);
INSERT INTO highlights VALUES('3300095033_35_6859-6979','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','伊丽莎白·库伯勒-罗斯(Elisabeth K-bler-Ross)的经典著作《直到最后一课：生与死的学习》(On Death and Dying)改变了人们看待悲伤和处理悲伤的方式。','6859-6979',5,1719463828,1782480557);
INSERT INTO highlights VALUES('3300095033_35_5728-5757','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','我们也可以选择不被情绪牵着鼻子走，把注意力从本能反应上移开','5728-5757',5,1719463657,1782480557);
INSERT INTO highlights VALUES('3300095033_35_4153-4183','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','“疯狂就是一遍又一遍地做同样的事情，但期待得到不同的结果。”','4153-4183',5,1719463473,1782480557);
INSERT INTO highlights VALUES('3300095033_35_3381-3476','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？',unistr('无论如何，如果某人经常以同一种方式激怒你，那通常就表明你们已经陷入了一种不健康的沟通模式陷阱。\u000a听起来，你好像遇到了一个“企鹅问题”。'),'3381-3476',5,1719463332,1782480557);
INSERT INTO highlights VALUES('3300095033_35_877-906','3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','每当他在个人生活上取得重大成就时，詹姆斯都会表现得很消极。','877-906',5,1719461937,1782480557);
