INSERT INTO highlights VALUES('3300095033_34_9649-9669','3300095033',34,'第六章 学会倾听','给一种情绪打上“标签”有助于使之得到化解','9649-9669',5,1719411613,1782480557);
INSERT INTO highlights VALUES('3300095033_34_9722-9735','3300095033',34,'第六章 学会倾听','给对方的感受打上“标签”。','9722-9735',5,1719411611,1782480557);
INSERT INTO highlights VALUES('3300095033_34_9316-9345','3300095033',34,'第六章 学会倾听','想让对方感到被倾听，最有效的方法是在情感上与他们产生共鸣。','9316-9345',5,1719411539,1782480557);
INSERT INTO highlights VALUES('3300095033_34_8904-8957','3300095033',34,'第六章 学会倾听','如果你的目的是想让对方同意你的观点，你会发现，一旦对方确信自己的观点已经被你理解，便会很容易认同你的观点。','8904-8957',5,1719411485,1782480557);
INSERT INTO highlights VALUES('3300095033_34_8627-8659','3300095033',34,'第六章 学会倾听','只有在对方告诉我没有什么需要补充之后，我才会开始阐述自己的观点。','8627-8659',5,1719402902,1782480557);
INSERT INTO highlights VALUES('3300095033_34_8507-8589','3300095033',34,'第六章 学会倾听','这种方法看起来非常简单：向对方解释我的观点之前，我会先复述对方的观点，而且要比他们自己说得更加头头是道。然后，我会向对方确认我的理解是否正确，或者是否存在什么遗漏。','8507-8589',5,1719376478,1782480557);
INSERT INTO highlights VALUES('3300095033_34_6873-6912','3300095033',34,'第六章 学会倾听','想要让对方感觉被听到，最好的一个策略就是比他们更精辟地阐释他们本人所持的观点。','6873-6912',5,1719020008,1782480557);
INSERT INTO highlights VALUES('3300095033_34_6200-6212','3300095033',34,'第六章 学会倾听','道歉的关键在于承担责任。','6200-6212',5,1718760501,1782480557);
INSERT INTO highlights VALUES('3300095033_34_6090-6133','3300095033',34,'第六章 学会倾听','这些道歉中包含了“深感遗憾”和“深表抱歉”这样的短语，但没有表达出理解对方生气的原因，','6090-6133',5,1718760486,1782480557);
INSERT INTO highlights VALUES('3300095033_34_5536-5575','3300095033',34,'第六章 学会倾听','发自内心的好奇能够促进发自内心的倾听，而发自内心的倾听也能促进发自内心的理解。','5536-5575',5,1718760406,1782480557);
INSERT INTO highlights VALUES('3300095033_34_5068-5078','3300095033',34,'第六章 学会倾听','对方视为一个信息来源','5068-5078',5,1718586185,1782480557);
INSERT INTO highlights VALUES('3300095033_34_5007-5047','3300095033',34,'第六章 学会倾听','关键在于积极挖掘与你的现有观点不一致的信息，寻找所有有助于发现当前观点漏洞的信息','5007-5047',5,1718586172,1782480557);
INSERT INTO highlights VALUES('3300095033_34_4814-4876','3300095033',34,'第六章 学会倾听','虚荣心也有助于我们与确认偏误做斗争：如果你不想让自己看起来愚蠢无知或心胸狭窄，那就提醒自己，这两种特质都是确认偏误能够带来的','4814-4876',5,1718586108,1782480557);
INSERT INTO highlights VALUES('3300095033_34_4511-4557','3300095033',34,'第六章 学会倾听','我总结的技巧是，如果觉得不可能输掉某个案子，这就是一个预警信号，表明确认偏误正在影响我的判断','4511-4557',5,1718586057,1782480557);
INSERT INTO highlights VALUES('3300095033_34_4381-4400','3300095033',34,'第六章 学会倾听','我想出了一个提醒自己注意确认偏误的技巧','4381-4400',5,1718586027,1782480557);
INSERT INTO highlights VALUES('3300095033_34_1785-1803','3300095033',34,'第六章 学会倾听','原来，大多数人都无法复述对方的理由。','1785-1803',5,1718559091,1782480557);
INSERT INTO highlights VALUES('3300095033_34_1686-1723','3300095033',34,'第六章 学会倾听','唯一的规则是，你不能仅仅简单重复对方说的话，必须用自己的话重申对方的理由。','1686-1723',5,1718559085,1782480557);
INSERT INTO highlights VALUES('3300095033_34_1159-1231','3300095033',34,'第六章 学会倾听','沃伦·巴菲特(Warren Buffett)完美地总结了确认偏误，他表示：“以保护自己既有结论不受质疑的方式解读所有新信息，这是人类最擅长的事。','1159-1231',5,1718559027,1782480557);
INSERT INTO highlights VALUES('3300095033_34_994-1040','3300095033',34,'第六章 学会倾听','确认偏误。确认偏误是指人类倾向于支持那些证实自己现有理念的信息，而忽略与这些理念相矛盾的信息','994-1040',5,1718559003,1782480557);
INSERT INTO highlights VALUES('3300095033_33_10850-10879','3300095033',33,'第五章 评判陷阱','那些无法保护我们或导致我们偏离目标的评判来说，还是放手为好','10850-10879',5,1718542545,1782480557);
INSERT INTO highlights VALUES('3300095033_33_9398-9415','3300095033',33,'第五章 评判陷阱','对评判之心的有意觉知会赋予你力量。','9398-9415',5,1718542342,1782480557);
INSERT INTO highlights VALUES('3300095033_33_9248-9274','3300095033',33,'第五章 评判陷阱','认识到自己的评判之心已被激起时，请将注意力转向内心。','9248-9274',5,1718542298,1782480557);
INSERT INTO highlights VALUES('3300095033_33_9049-9078','3300095033',33,'第五章 评判陷阱','心怀怨恨、责备数落和以牙还牙，都会耗损我们追求目标的精力。','9049-9078',5,1718542269,1782480557);
INSERT INTO highlights VALUES('3300095033_33_8821-8836','3300095033',33,'第五章 评判陷阱','但在此之后，我们就应该放下评判','8821-8836',5,1718542211,1782480557);
INSERT INTO highlights VALUES('3300095033_33_8752-8802','3300095033',33,'第五章 评判陷阱','比如，如果有人泄露了我们私下分享的信息，我们可能会认为此人不值得信任，决定从此不再跟这个人分享秘密。','8752-8802',5,1718542136,1782480557);
INSERT INTO highlights VALUES('3300095033_33_8633-8667','3300095033',33,'第五章 评判陷阱','精力是一种有限的资源。越是爱评判别人，就越没有精力去实现自己的目标。','8633-8667',5,1718542112,1782480557);
INSERT INTO highlights VALUES('3300095033_33_8611-8632','3300095033',33,'第五章 评判陷阱','如果评判有用，那就坚持；如果无用，那就放弃','8611-8632',5,1718542098,1782480557);
INSERT INTO highlights VALUES('3300095033_33_8322-8384','3300095033',33,'第五章 评判陷阱','有的时候，在交流中表达评判或许很有益。关键点在于，带有评判的交流应是一种有意识的主动决定，而不是一种轻率而情绪化的消极反应。','8322-8384',5,1718542036,1782480557);
INSERT INTO highlights VALUES('3300095033_33_7777-7835','3300095033',33,'第五章 评判陷阱','所以在评价某人时，我们可以使用不带指责的语言进行交流，不把评判之心传达给对方。一种有效的方法就是专注于描述而不是评价','7777-7835',5,1718541923,1782480557);
INSERT INTO highlights VALUES('3300095033_33_7362-7412','3300095033',33,'第五章 评判陷阱','他并没有带任何的评判之心，而是真心想要知道事情的原委。就这样，他用同理心和同情心与老板进行了这次对话','7362-7412',5,1718537263,1782480557);
INSERT INTO highlights VALUES('3300095033_33_6493-6546','3300095033',33,'第五章 评判陷阱','然而，如果承认对方引发了我们想做出评判的冲动，我们就能有意识地选择是表露这种心迹，还是不加评判地与之交流。','6493-6546',5,1718537155,1782480557);
INSERT INTO highlights VALUES('3300095033_33_6113-6150','3300095033',33,'第五章 评判陷阱','有的时候你可能会发现，别人的评判更多的是他们自己的问题，而与你的行为无关。','6113-6150',5,1718465953,1782480557);
INSERT INTO highlights VALUES('3300095033_33_4921-4934','3300095033',33,'第五章 评判陷阱','把别人的评判当作学习的机会','4921-4934',5,1718465621,1782480557);
INSERT INTO highlights VALUES('3300095033_33_4487-4503','3300095033',33,'第五章 评判陷阱','有害评判会让我们远离自己的目标。','4487-4503',5,1718465571,1782480557);
INSERT INTO highlights VALUES('3300095033_33_1905-1930','3300095033',33,'第五章 评判陷阱','评判陷阱包含两方：做出评判的一方和受到评判的一方。','1905-1930',5,1718426750,1782480557);
INSERT INTO highlights VALUES('3300095033_33_1059-1109','3300095033',33,'第五章 评判陷阱','然而，当评判与恐惧、愤怒、自以为是或怨恨等毒素掺杂在一起时，它就会将我们拉进评判陷阱，引发负面冲突。','1059-1109',5,1718426583,1782480557);
INSERT INTO highlights VALUES('3300095033_33_558-606','3300095033',33,'第五章 评判陷阱','研究表明，我们在认识一个新朋友时半秒之内就会做出判断，这些判断更有可能是偏向消极的而不是积极的。','558-606',5,1718426400,1782480557);
INSERT INTO highlights VALUES('3300095033_32_16541-16613','3300095033',32,'第四章 逃避陷阱',unistr('克服逃避陷阱的工具\u000a◎ 把挑起冲突作为一项工作要求'),'16541-16613',5,1718426296,1782480557);
INSERT INTO highlights VALUES('3300095033_32_16227-16510','3300095033',32,'第四章 逃避陷阱',unistr('导致陷入逃避陷阱的有害恐惧有三大来源\u000a·心理安全感：害怕因表达自己对某件事的忧虑或指出错误而受到惩罚或羞辱。\u000a·印象管理：害怕坦露心声会给自己带来负面影响。\u000a·社会化：害怕提出建设性的批评会惹人不快，或被视为对人不尊重、不礼貌。'),'16227-16510',5,1718425356,1782480557);
INSERT INTO highlights VALUES('3300095033_32_15881-15920','3300095033',32,'第四章 逃避陷阱','虽然人们可能会记得你犯下了一个大错，但他们也肯定不会忘记你敢于站出来承担责任。','15881-15920',5,1718424669,1782480557);
INSERT INTO highlights VALUES('3300095033_32_15679-15707','3300095033',32,'第四章 逃避陷阱','既然错误不可避免，那么我们不妨张开双臂迎接错误引起的冲突','15679-15707',5,1718424580,1782480557);
INSERT INTO highlights VALUES('3300095033_32_12319-12371','3300095033',32,'第四章 逃避陷阱','三对三报告”：每个团队成员都承诺在未来一周完成三个目标，并以上周的三个目标作为标准，对本周表现进行评价。','12319-12371',5,1718424252,1782480557);
INSERT INTO highlights VALUES('3300095033_32_12133-12272','3300095033',32,'第四章 逃避陷阱','想要用一种更加正规的方式实施问责制，不妨将问责纳入日常信息流￼之中','12133-12272',5,1718424207,1782480557);
INSERT INTO highlights VALUES('3300095033_32_11901-11928','3300095033',32,'第四章 逃避陷阱','如果将错误视为学习和提高的机会，承认错误就会容易得多。','11901-11928',5,1718424158,1782480557);
INSERT INTO highlights VALUES('3300095033_32_11627-11652','3300095033',32,'第四章 逃避陷阱','除了坦率，对抗逃避陷阱的另一种方法就是重视问责制。','11627-11652',5,1718424136,1782480557);
INSERT INTO highlights VALUES('3300095033_32_11190-11224','3300095033',32,'第四章 逃避陷阱','想要赋予组织成员坦率沟通的精神，最好的方法就是实践，而且要经常实践。','11190-11224',5,1718423534,1782480557);
INSERT INTO highlights VALUES('3300095033_32_10735-10805','3300095033',32,'第四章 逃避陷阱',unistr('坦率与问责\u000a对抗逃避陷阱的第二个策略，是向组织成员宣传坦率与问责的文化'),'10735-10805',5,1718423409,1782480557);
INSERT INTO highlights VALUES('3300095033_32_10149-10203','3300095033',32,'第四章 逃避陷阱','在启动项目之前，召集团队探讨可能出现的挑战并提问：“假设我们在这个项目中遭遇了失败，可能是什么原因导致的？”','10149-10203',5,1718423370,1782480557);
INSERT INTO highlights VALUES('3300095033_32_10128-10149','3300095033',32,'第四章 逃避陷阱','除了简报会议，你还可以多加一场事前简报会。','10128-10149',5,1718423129,1782480557);
INSERT INTO highlights VALUES('3300095033_32_9382-9449','3300095033',32,'第四章 逃避陷阱','如果能专门划定一段时间，让人们对企业进行评判性的思考并指出问题所在，你就等于是在传递这样一条信息：表达自己的担忧是一种值得鼓励的行为。','9382-9449',5,1718239317,1782480557);
INSERT INTO highlights VALUES('3300095033_32_8857-8915','3300095033',32,'第四章 逃避陷阱','“强制简报”，即使在一般人的生活中，这也是一个用来对抗逃避陷阱的好方法。“强制简报”是一种必须产生对抗和冲突的形式。','8857-8915',5,1718208761,1782480557);
INSERT INTO highlights VALUES('3300095033_32_8682-8715','3300095033',32,'第四章 逃避陷阱','当人际关系问题得不到解决且进一步恶化时，它们便能衍生出糟糕的结果。','8682-8715',5,1718208737,1782480557);
INSERT INTO highlights VALUES('3300095033_32_8227-8354','3300095033',32,'第四章 逃避陷阱','如果大家对这种行为不管不问，马特就可能会在每次任务结束后都用无线电联系这位新人，确保他拿了梯子。这种做法会让对方愤愤不平，从而产生积怨，最终导致严重的问题。想象一下，你在海豹突击队执行任务，要把自己的生命交到队友的手中……这么一来，你会想让队友讨厌你吗？','8227-8354',5,1718208707,1782480557);
INSERT INTO highlights VALUES('3300095033_32_7381-7416','3300095033',32,'第四章 逃避陷阱','谁知，马特却讲起了他作为海豹突击队第六分队队长时第一次执行任务的故事。','7381-7416',5,1718208575,1782480557);
INSERT INTO highlights VALUES('3300095033_32_6979-7015','3300095033',32,'第四章 逃避陷阱','发现问题时，海豹突击队队员必须勇敢地说出来，而不能担心会伤害彼此的感情。','6979-7015',5,1718208562,1782480557);
INSERT INTO highlights VALUES('3300095033_32_6758-6796','3300095033',32,'第四章 逃避陷阱','第一个工具是让冲突成为一种需求，第二个工具是促进一种开诚布公和承担责任的文化','6758-6796',5,1718208413,1782480557);
INSERT INTO highlights VALUES('3300095033_32_6640-6646','3300095033',32,'第四章 逃避陷阱','避免逃避陷阱','6640-6646',5,1718208410,1782480557);
INSERT INTO highlights VALUES('3300095033_32_4912-4950','3300095033',32,'第四章 逃避陷阱','因此，选择避免冲突并不是出于恐惧，而是因为成本效益分析告诉你这样做得不偿失。','4912-4950',5,1718167171,1782480557);
INSERT INTO highlights VALUES('3300095033_32_4950-4969','3300095033',32,'第四章 逃避陷阱','你告诉自己：企鹅不会飞，你发什么火呢？','4950-4969',5,1718167133,1782480557);
INSERT INTO highlights VALUES('3300095033_32_4275-4294','3300095033',32,'第四章 逃避陷阱','落入逃避陷阱背后的驱动力是有害的恐惧。','4275-4294',5,1718156553,1782480557);
INSERT INTO highlights VALUES('3300095033_32_4241-4275','3300095033',32,'第四章 逃避陷阱','然而，不应逃避冲突的案例也有很多，二者主要的区别在于逃避背后的动机。','4241-4275',5,1718156547,1782480557);
INSERT INTO highlights VALUES('3300095033_32_4012-4054','3300095033',32,'第四章 逃避陷阱','然而，当这些经验导致我们对难以面对却意义重大的问题采取回避态度时，问题便得不到解决。','4012-4054',5,1718156507,1782480557);
INSERT INTO highlights VALUES('3300095033_32_3889-3923','3300095033',32,'第四章 逃避陷阱','除了心理安全感的匮乏和印象管理，社会化是导致有害恐惧出现的第三个毒素','3889-3923',5,1718156485,1782480557);
INSERT INTO highlights VALUES('3300095033_32_3339-3385','3300095033',32,'第四章 逃避陷阱','第二个可能导致有害恐惧出现的毒素，是想控制别人对我们的看法，也就是心理学家所说的“印象管理”','3339-3385',5,1718156177,1782480557);
INSERT INTO highlights VALUES('3300095033_32_3085-3130','3300095033',32,'第四章 逃避陷阱','心理安全感定义为：“相信不会因为表达想法、提出问题、说出担忧或指出错误而受到惩罚或羞辱。”','3085-3130',5,1718156012,1782480557);
INSERT INTO highlights VALUES('3300095033_32_3028-3052','3300095033',32,'第四章 逃避陷阱','导致有害恐惧出现的第一个毒素是心理安全感的匮乏。','3028-3052',5,1718156005,1782480557);
INSERT INTO highlights VALUES('3300095033_32_2337-2391','3300095033',32,'第四章 逃避陷阱','可是，如果能以一种不加指责的方式提出问题（这种情况非常适合使用“购物清单语气”），你们的关系最终会更加稳固。','2337-2391',5,1718155832,1782480557);
INSERT INTO highlights VALUES('3300095033_32_2116-2157','3300095033',32,'第四章 逃避陷阱','我们告诉自己，这种沉默基于尊重，但实际上这种沉默的基础却是对难以启齿的谈话的恐惧。','2116-2157',5,1718155797,1782480557);
INSERT INTO highlights VALUES('3300095033_32_1029-1052','3300095033',32,'第四章 逃避陷阱','从长远来看，规避小的冲突往往会造成更大的伤害。','1029-1052',5,1718153643,1782480557);
INSERT INTO highlights VALUES('3300095033_32_946-977','3300095033',32,'第四章 逃避陷阱','就是这种磨不开面子，让大多数人都选择缄口不语，也就是避免冲突。','946-977',5,1718153632,1782480557);
INSERT INTO highlights VALUES('3300095033_32_478-519','3300095033',32,'第四章 逃避陷阱','逃避陷阱在四种冲突陷阱中最为常见，当我们因为有害的恐惧规避冲突时，就会落入这种陷阱','478-519',5,1718153565,1782480557);
INSERT INTO highlights VALUES('3300095033_31_16709-16758','3300095033',31,'第三章 必胜陷阱','如果你发现是你的自尊在驱动冲突，那就按下暂停键。用理智决定是否要继续下去，不要让自尊左右你的行为。','16709-16758',5,1718025605,1782480557);
INSERT INTO highlights VALUES('3300095033_31_16788-16826','3300095033',31,'第三章 必胜陷阱','如果你看到是对方的自尊在推动冲突，那就满足对方的自尊。这样做不会浪费你一分钱','16788-16826',5,1718025604,1782480557);
INSERT INTO highlights VALUES('3300095033_31_16563-16593','3300095033',31,'第三章 必胜陷阱','迎合自己的自尊要付出代价，但迎合别人的自尊却不必付出任何代价','16563-16593',5,1718025554,1782480557);
INSERT INTO highlights VALUES('3300095033_31_15475-15523','3300095033',31,'第三章 必胜陷阱','如果意识到是对方的自尊作祟而导致冲突恶化，那就庆幸自己拥有一个不用花钱的工具：满足对方的自尊需要','15475-15523',5,1718025460,1782480557);
INSERT INTO highlights VALUES('3300095033_31_15259-15287','3300095033',31,'第三章 必胜陷阱','总的来说，避免落入必胜陷阱最好的方法就是提高你的觉知力。','15259-15287',5,1718025424,1782480557);
INSERT INTO highlights VALUES('3300095033_31_14891-15009','3300095033',31,'第三章 必胜陷阱','务必根据这段关系的长度和对你的价值来思考具体的应对方法。你只是在短时间内跟这个人打交道吗？还是说，你们俩的关系是持续终生的？这个人是你被迫与之共事的同事、邻居，还是伴侣的母亲？关系的性质不同，付出的成本及你愿意承受的成本上限也会有差异。','14891-15009',5,1718025349,1782480557);
INSERT INTO highlights VALUES('3300095033_31_14410-14467','3300095033',31,'第三章 必胜陷阱','一旦接受了米尔顿这类人的本性，我们的选择就变得清晰起来：满足他的需求，争取找出公平的解决方案，要不就干脆大胆开战。','14410-14467',5,1718025339,1782480557);
INSERT INTO highlights VALUES('3300095033_31_14223-14258','3300095033',31,'第三章 必胜陷阱','问题是，像米尔顿这样的人往往自带一种牵引力，会诱使其他人陷入必胜陷阱。','14223-14258',5,1718025336,1782480557);
INSERT INTO highlights VALUES('3300095033_31_14000-14067','3300095033',31,'第三章 必胜陷阱','如果你意识到自己已经落入沉没成本谬误的陷阱，只是因为不甘心而徒增亏损，你就能很容易地后退一步，评估这非赢不可的执念是否因沉没成本而起。','14000-14067',5,1718025208,1782480557);
INSERT INTO highlights VALUES('3300095033_31_13949-13971','3300095033',31,'第三章 必胜陷阱','想要为沉没成本排毒，唯一的方法就是选择接受。','13949-13971',5,1718025193,1782480557);
INSERT INTO highlights VALUES('3300095033_31_13713-13754','3300095033',31,'第三章 必胜陷阱','如果你和朋友起了口角，却在三十分钟后消气并觉得后悔，那么此时不失为一个停战的好时机','13713-13754',5,1718025149,1782480557);
INSERT INTO highlights VALUES('3300095033_31_13011-13049','3300095033',31,'第三章 必胜陷阱','换句话说，我满足了他的自尊，从而避免他的自尊上升到有害水平，引来无益的冲突。','13011-13049',5,1718024962,1782480557);
INSERT INTO highlights VALUES('3300095033_31_12579-12627','3300095033',31,'第三章 必胜陷阱','我们之间的电话会议往往没有得出解决方案就结束了，需要通过一系列后续邮件和更多乏味的电话会议跟进。','12579-12627',5,1718024864,1782480557);
INSERT INTO highlights VALUES('3300095033_31_11892-11992','3300095033',31,'第三章 必胜陷阱','你可以问问自己：我的行为是被自尊驱动的吗？对方的行为是被自尊驱动的吗？仅仅提出这些问题，便能让你的感觉更加灵敏。如果能在现实的冲突中熟练地提出这些问题，你就能把对方的自尊视为可以利用的资源并为己所用。','11892-11992',5,1718024468,1782480557);
INSERT INTO highlights VALUES('3300095033_31_11316-11362','3300095033',31,'第三章 必胜陷阱','在谈判中有这样一条技巧：迎合自己的自尊会让你付出昂贵的代价，但迎合别人的自尊却不必付出代价。','11316-11362',5,1718024255,1782480557);
INSERT INTO highlights VALUES('3300095033_31_10345-10361','3300095033',31,'第三章 必胜陷阱','有时，沉没成本和自尊会相互助长。','10345-10361',5,1718023986,1782480557);
INSERT INTO highlights VALUES('3300095033_31_10207-10246','3300095033',31,'第三章 必胜陷阱','在汽车销售店，销售员使用的最重要的一条策略，就是尽可能多地占用潜在客户的时间。','10207-10246',5,1718023977,1782480557);
INSERT INTO highlights VALUES('3300095033_31_10283-10316','3300095033',31,'第三章 必胜陷阱','越是花时间与某个销售员交流，你就越不愿意选择离开，到别人那里买车。','10283-10316',5,1718023973,1782480557);
INSERT INTO highlights VALUES('3300095033_31_9390-9422','3300095033',31,'第三章 必胜陷阱','研究表明，投入了时间、金钱、努力或其他资源的事物会让人更难放弃。','9390-9422',5,1718023823,1782480557);
INSERT INTO highlights VALUES('3300095033_31_9350-9390','3300095033',31,'第三章 必胜陷阱','心理学家将为了收回之前投入的成本而对某种行为执迷不悟的现象称为“沉没成本谬误”。','9350-9390',5,1718023807,1782480557);
INSERT INTO highlights VALUES('3300095033_31_9329-9350','3300095033',31,'第三章 必胜陷阱','“沉没成本”是指已经付出且不可收回的成本。','9329-9350',5,1718023794,1782480557);
INSERT INTO highlights VALUES('3300095033_31_8706-8741','3300095033',31,'第三章 必胜陷阱','对于那些但愿从未说出口的言论，我们倾向于坚守不放，原因就在于这种自尊。','8706-8741',5,1718023704,1782480557);
INSERT INTO highlights VALUES('3300095033_31_8336-8363','3300095033',31,'第三章 必胜陷阱','屈服如同是对自尊的一种打击，也是对我们身份的一种打击。','8336-8363',5,1718023584,1782480557);
INSERT INTO highlights VALUES('3300095033_31_8192-8220','3300095033',31,'第三章 必胜陷阱','不能因为某些东西存在于自然界，就认为它必然是健康有益的。','8192-8220',5,1718023536,1782480557);
INSERT INTO highlights VALUES('3300095033_31_7828-7857','3300095033',31,'第三章 必胜陷阱','过度的自尊往往会带来消极的影响，如任性或者自私自利的心态。','7828-7857',5,1718023418,1782480557);
INSERT INTO highlights VALUES('3300095033_31_7674-7697','3300095033',31,'第三章 必胜陷阱','导致陷入必胜陷阱的两种毒素分别是自尊和沉没成本','7674-7697',5,1718023405,1782480557);
INSERT INTO highlights VALUES('3300095033_31_5451-5481','3300095033',31,'第三章 必胜陷阱','想要判断某人是否陷入了必胜陷阱，了解此人的最终目标至关重要。','5451-5481',5,1718022217,1782480557);
INSERT INTO highlights VALUES('3300095033_31_4831-4889','3300095033',31,'第三章 必胜陷阱','竞争可以是健康的，也可以是有害的。竞争可以推动创新、生产力发展和人类进步的巨大动力，但其也会分散我们对目标的专注力。','4831-4889',5,1718022159,1782480557);
INSERT INTO highlights VALUES('3300095033_31_3696-3730','3300095033',31,'第三章 必胜陷阱','但如果你让引擎空转，等着那位司机下车时和他对峙，你就陷入了必胜陷阱。','3696-3730',5,1718022021,1782480557);
INSERT INTO highlights VALUES('3300095033_31_3281-3304','3300095033',31,'第三章 必胜陷阱','情绪会让冲突变成毫无意义甚至具有破坏性的争斗。','3281-3304',5,1718021916,1782480557);
INSERT INTO highlights VALUES('3300095033_30_18600-18622','3300095033',30,'第二章 霸凌陷阱','在给出负面的反馈时，抓住机会强调对方的价值。','18600-18622',5,1718021411,1782480557);
INSERT INTO highlights VALUES('3300095033_30_17755-17798','3300095033',30,'第二章 霸凌陷阱','身居要位的人更容易以自我为中心来看待问题，不那么体恤他人，且更容易用霸凌行为对待他人。','17755-17798',5,1718021350,1782480557);
INSERT INTO highlights VALUES('3300095033_30_17041-17085','3300095033',30,'第二章 霸凌陷阱','这些工具将会帮助你应对霸凌陷阱。在下面的内容中，我们将会探讨这些工具如何运用于其他的陷阱','17041-17085',5,1718019005,1782480557);
INSERT INTO highlights VALUES('3300095033_30_16847-16889','3300095033',30,'第二章 霸凌陷阱','在尝试了这些工具之后，如果对方仍然对你颐指气使，那就得出结论：这个人是不可能改变的。','16847-16889',5,1718018945,1782480557);
INSERT INTO highlights VALUES('3300095033_30_16679-16732','3300095033',30,'第二章 霸凌陷阱','如果你不是鲨鱼，就不要和鲨鱼一起游泳；如果你讨厌鲜血，那就别当外科医生；如果你恐高，就不要给摩天大楼擦窗户','16679-16732',5,1718018849,1782480557);
INSERT INTO highlights VALUES('3300095033_30_16151-16215','3300095033',30,'第二章 霸凌陷阱','单纯陈述事实和传达信息，不要激动，语气要冷静、清晰、准确。起初这并不容易，但我经常听到有人说，稍加练习就能很轻松地掌握这个技巧。','16151-16215',5,1718018631,1782480557);
INSERT INTO highlights VALUES('3300095033_30_15408-15449','3300095033',30,'第二章 霸凌陷阱','然而通常来说，我们可以冷静地让对方意识到我们的不安，从而让冲突得到一定程度的缓和。','15408-15449',5,1718014935,1782480557);
INSERT INTO highlights VALUES('3300095033_30_15483-15544','3300095033',30,'第二章 霸凌陷阱','我知道你想用你既定的方法拍这场戏，但我觉得不安全。一个工作人员告诉我，这辆车存在安全隐患。我们至少可以考虑一下另一种选择吧','15483-15544',5,1718014915,1782480557);
INSERT INTO highlights VALUES('3300095033_30_15323-15373','3300095033',30,'第二章 霸凌陷阱','在遭受霸凌的时候，我们自然会产生有害的愤怒。这种愤怒会引发战斗反应，导致冲突升级，抑或引发逃跑反应。','15323-15373',5,1718014884,1782480557);
INSERT INTO highlights VALUES('3300095033_30_14997-15002','3300095033',30,'第二章 霸凌陷阱','面对霸凌者','14997-15002',5,1718014527,1782480557);
INSERT INTO highlights VALUES('3300095033_30_14599-14620','3300095033',30,'第二章 霸凌陷阱','在开始对话之前，先凸显你们人性中的共同点。','14599-14620',5,1718014490,1782480557);
INSERT INTO highlights VALUES('3300095033_30_14398-14462','3300095033',30,'第二章 霸凌陷阱','在展开一场艰难的谈话之前，你可以向自己提出的一个最重要的问题是：“对方有怎样的愿望？”然后问问自己：“我何时也有过同样的愿望？”','14398-14462',5,1718014455,1782480557);
INSERT INTO highlights VALUES('3300095033_30_14065-14090','3300095033',30,'第二章 霸凌陷阱','一个有效抵抗人格解体的策略就是将对方视为完整的人。','14065-14090',5,1718014387,1782480557);
INSERT INTO highlights VALUES('3300095033_30_13781-13815','3300095033',30,'第二章 霸凌陷阱','如果你的目的是给予反馈，那就务必先在心中明确你想通过反馈达成的目标。','13781-13815',5,1718014341,1782480557);
INSERT INTO highlights VALUES('3300095033_30_13855-13881','3300095033',30,'第二章 霸凌陷阱','厘清思路有助于清除愤怒中的毒素，让你的信息更有条理。','13855-13881',5,1718014317,1782480557);
INSERT INTO highlights VALUES('3300095033_30_13568-13603','3300095033',30,'第二章 霸凌陷阱','一旦能用“购物清单语气”完整地传达信息，就说明你做好了给予反馈的准备。','13568-13603',5,1718014274,1782480557);
INSERT INTO highlights VALUES('3300095033_30_13218-13249','3300095033',30,'第二章 霸凌陷阱','如果情况可以稍缓一缓，那就最好睡一觉，让怒气散去再去解决问题。','13218-13249',5,1718013730,1782480557);
INSERT INTO highlights VALUES('3300095033_30_12668-12715','3300095033',30,'第二章 霸凌陷阱','然而在给予纠偏反馈的时候，宣泄愤怒并不是力量的表现，而是说明我们无法控制自己的情绪，意味着软弱','12668-12715',5,1718012670,1782480557);
INSERT INTO highlights VALUES('3300095033_30_12531-12537','3300095033',30,'第二章 霸凌陷阱','不要发泄怒气','12531-12537',5,1718012654,1782480557);
INSERT INTO highlights VALUES('3300095033_30_12381-12399','3300095033',30,'第二章 霸凌陷阱','养成经常表达感激的习惯，不要有所保留','12381-12399',5,1718012640,1782480557);
INSERT INTO highlights VALUES('3300095033_30_12255-12310','3300095033',30,'第二章 霸凌陷阱','如果想要对权力引发的行为加以控制，一点儿谦虚之心便能发挥巨大的作用，而这种谦虚也可以通过感恩和慷慨之心来培养。','12255-12310',5,1718012630,1782480557);
