INSERT INTO highlights VALUES('3300095033_30_11711-11772','3300095033',30,'第二章 霸凌陷阱','如果把失误当作成长的机会，事态就会有所扭转。如果我们能从提供支持的角度出发进行交流，便能中和有害的情绪，避免陷入霸凌陷阱。','11711-11772',5,1718012527,1782480557);
INSERT INTO highlights VALUES('3300095033_30_11470-11508','3300095033',30,'第二章 霸凌陷阱','我还有一个建议：在不得不给出严厉反馈的时候，请抓住机会凸显对方的价值所在——','11470-11508',5,1718012383,1782480557);
INSERT INTO highlights VALUES('3300095033_30_10634-10674','3300095033',30,'第二章 霸凌陷阱','第二种，用“购物清单语气”传达同样的信息，也就是在说话时做到沉着冷静、不动感情。','10634-10674',5,1718012264,1782480557);
INSERT INTO highlights VALUES('3300095033_30_10432-10467','3300095033',30,'第二章 霸凌陷阱','打起精神来，要不然，我就去找一个不会搞丢价值几百万美元订单的人来接替你','10432-10467',5,1718011947,1782480557);
INSERT INTO highlights VALUES('3300095033_30_9915-9965','3300095033',30,'第二章 霸凌陷阱','想要找到你的“购物清单语气”其实很简单。想象你的室友、配偶或父母正要去杂货店，问你需不需要带些什么。','9915-9965',5,1717991384,1782480557);
INSERT INTO highlights VALUES('3300095033_30_9626-9701','3300095033',30,'第二章 霸凌陷阱',unistr('你可以采用下面的建议来为情绪排毒。\u000a使用“购物清单语气”'),'9626-9701',5,1717991357,1782480557);
INSERT INTO highlights VALUES('3300095033_30_9087-9131','3300095033',30,'第二章 霸凌陷阱','但路易斯表示，当你和另一名司机之间隔着两块玻璃和一些距离的时候，嘴巴就突然没有把门的了。','9087-9131',5,1717912223,1782480557);
INSERT INTO highlights VALUES('3300095033_30_8471-8526','3300095033',30,'第二章 霸凌陷阱','这种人格解体的观点，让司机的愤怒飙升到了有害水平。司机如果能将对方看作一个完整的人，便能够对这种情绪进行控制。','8471-8526',5,1717845881,1782480557);
INSERT INTO highlights VALUES('3300095033_30_8357-8396','3300095033',30,'第二章 霸凌陷阱','这位司机没有把协管员看作一个完整的人，而是把他当成一个单维度的“贴罚单的人”。','8357-8396',5,1717845869,1782480557);
INSERT INTO highlights VALUES('3300095033_30_7916-7952','3300095033',30,'第二章 霸凌陷阱','激情、权威和愤怒混合在一起，形成了一种有毒的混合物，把他拉进了霸凌陷阱。','7916-7952',5,1717845808,1782480557);
INSERT INTO highlights VALUES('3300095033_30_7773-7814','3300095033',30,'第二章 霸凌陷阱','我们不觉得自己是恶霸，当然也不会故意欺负别人，但激情却能把理智之人也拖入霸凌陷阱。','7773-7814',5,1717845795,1782480557);
INSERT INTO highlights VALUES('3300095033_30_6937-6970','3300095033',30,'第二章 霸凌陷阱','如果普通人没有经过足够的训练就被置于权威地位，便很容易陷入霸凌陷阱','6937-6970',5,1717845268,1782480557);
INSERT INTO highlights VALUES('3300095033_30_6639-6652','3300095033',30,'第二章 霸凌陷阱','权力也可以源于财富或资历。','6639-6652',5,1717845247,1782480557);
INSERT INTO highlights VALUES('3300095033_30_5990-6041','3300095033',30,'第二章 霸凌陷阱','1971年著名的斯坦福监狱实验就是一个例子。这项研究最初计划进行两周，但最终只持续了六天就不得不终止。','5990-6041',5,1717845032,1782480557);
INSERT INTO highlights VALUES('3300095033_30_5900-5935','3300095033',30,'第二章 霸凌陷阱','由于不懂得领导之道，许多人都选择了“滥用权威”这一最没有含金量的招数。','5900-5935',5,1717845018,1782480557);
INSERT INTO highlights VALUES('3300095033_30_5504-5536','3300095033',30,'第二章 霸凌陷阱','即使是富有同情心的人，一旦拥有权威的地位，也有可能落入霸凌陷阱。','5504-5536',5,1717825561,1782480557);
INSERT INTO highlights VALUES('3300095033_30_5301-5331','3300095033',30,'第二章 霸凌陷阱','当我们的愤怒、恐惧和自尊达到有害程度时，霸凌陷阱便会被触发。','5301-5331',5,1717825521,1782480557);
INSERT INTO highlights VALUES('3300095033_30_4306-4332','3300095033',30,'第二章 霸凌陷阱','面对能够推动事情发展的健康冲突，我们也同样会避免参与','4306-4332',5,1717824936,1782480557);
INSERT INTO highlights VALUES('3300095033_30_3983-4004','3300095033',30,'第二章 霸凌陷阱','霸凌陷阱的主要驱动因素是以愤怒为首的毒素。','3983-4004',5,1717824872,1782480557);
INSERT INTO highlights VALUES('3300095033_30_3855-3907','3300095033',30,'第二章 霸凌陷阱','觉得自己曾在工作中受到过粗鲁对待的员工中，有大约一半的人表示会采取有意降低干劲或工作质量的方式进行报复。','3855-3907',5,1717824861,1782480557);
INSERT INTO highlights VALUES('3300095033_30_3651-3677','3300095033',30,'第二章 霸凌陷阱','对消除分歧和化解冲突而言，霸凌是一种非常无效的方法。','3651-3677',5,1717824823,1782480557);
INSERT INTO highlights VALUES('3300095033_30_3272-3296','3300095033',30,'第二章 霸凌陷阱','霸凌陷阱会出现在压力当头、情绪外露的重压环境下。','3272-3296',5,1717824221,1782480557);
INSERT INTO highlights VALUES('3300095033_30_3096-3124','3300095033',30,'第二章 霸凌陷阱','这种陷阱指的是累积起来的毒素引发他人“战或逃”反应的情况','3096-3124',5,1717824192,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2928-2948','3300095033',30,'第二章 霸凌陷阱','霸凌陷阱指的是在不经意间霸凌他人的情况，','2928-2948',5,1717823600,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2858-2893','3300095033',30,'第二章 霸凌陷阱','导致霸凌行为出现的因素有很多，但并非所有霸凌行为都必然会引发霸凌陷阱。','2858-2893',5,1717823587,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2783-2821','3300095033',30,'第二章 霸凌陷阱','一些人可能会满腔热情地追求某个目标，不惜将挡在成功之路上的任何人或事推到一边','2783-2821',5,1717823566,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2734-2738','3300095033',30,'第二章 霸凌陷阱','霸凌行为','2734-2738',5,1717823524,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2516-2606','3300095033',30,'第二章 霸凌陷阱','在肾上腺素飙升的时刻，每个人都有可能陷入霸凌陷阱。虽然昆汀和乌玛的冲突很棘手，但他们仍可以选择用不同的方式来应对：两人可以向那些认为这辆车不安全的工作人员咨询，或者昆汀也可以先在这','2516-2606',5,1717823510,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2453-2487','3300095033',30,'第二章 霸凌陷阱','但他的恐惧和愤怒还是飙升到了有害水平，将他本人和乌玛拽入了霸凌陷阱。','2453-2487',5,1717823230,1782480557);
INSERT INTO highlights VALUES('3300095033_30_2288-2336','3300095033',30,'第二章 霸凌陷阱','在这件事发生之前，两人堪称理想的工作拍档。然而在短短几分钟内，他们就逾越了一条界线，再也无法回头','2288-2336',5,1717823192,1782480557);
INSERT INTO highlights VALUES('3300095033_30_1801-1860','3300095033',30,'第二章 霸凌陷阱',unistr('无奈汽车却飘移出马路，撞到了一棵棕榈树上。\u000a乌玛遭受了脑震荡，'),'1801-1860',5,1717823153,1782480557);
INSERT INTO highlights VALUES('3300095033_29_19180-19256','3300095033',29,'第一章 冲突，是拥抱还是抗拒',unistr('四种常见的陷阱：\u000a·霸凌陷阱·必胜陷阱·逃避陷阱·评判陷阱'),'19180-19256',5,1717822985,1782480557);
INSERT INTO highlights VALUES('3300095033_29_18456-18474','3300095033',29,'第一章 冲突，是拥抱还是抗拒','所有冲突都遵循一套简单、可预测的模式','18456-18474',5,1717822893,1782480557);
INSERT INTO highlights VALUES('3300095033_29_17397-17401','3300095033',29,'第一章 冲突，是拥抱还是抗拒','穿梭外交','17397-17401',5,1717422950,1782480557);
INSERT INTO highlights VALUES('3300095033_29_17567-17606','3300095033',29,'第一章 冲突，是拥抱还是抗拒','调解人会让当事双方待在不同的房间里，然后来回“穿梭”，把一方说的话讲给另一方听','17567-17606',5,1717422947,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16830-16894','3300095033',29,'第一章 冲突，是拥抱还是抗拒','如果在对他人的评价中掺杂了恐惧或愤怒等毒素，混合而成的这款“鸡尾酒”就成了一种有害的评判，不仅消耗我们的精力，还会阻碍有效合作。','16830-16894',5,1717392083,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16790-16794','3300095033',29,'第一章 冲突，是拥抱还是抗拒','评判陷阱','16790-16794',5,1717392075,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16555-16579','3300095033',29,'第一章 冲突，是拥抱还是抗拒','出于恐惧而想要避免冲突时，我们便陷入了逃避陷阱。','16555-16579',5,1717392055,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16515-16519','3300095033',29,'第一章 冲突，是拥抱还是抗拒','逃避陷阱','16515-16519',5,1717392052,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16325-16358','3300095033',29,'第一章 冲突，是拥抱还是抗拒','这是一种好胜心失控的情形，非赢不可的执念会阻碍我们实现更重要的目标','16325-16358',5,1717392034,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16104-16126','3300095033',29,'第一章 冲突，是拥抱还是抗拒','这是指类似霸凌的行为无意中造成有害冲突的情况','16104-16126',5,1717392024,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16285-16289','3300095033',29,'第一章 冲突，是拥抱还是抗拒','必胜陷阱','16285-16289',5,1717392015,1782480557);
INSERT INTO highlights VALUES('3300095033_29_16064-16068','3300095033',29,'第一章 冲突，是拥抱还是抗拒','霸凌陷阱','16064-16068',5,1717391997,1782480557);
INSERT INTO highlights VALUES('3300095033_29_15884-15890','3300095033',29,'第一章 冲突，是拥抱还是抗拒','四大冲突陷阱','15884-15890',5,1717391987,1782480557);
INSERT INTO highlights VALUES('3300095033_29_15797-15825','3300095033',29,'第一章 冲突，是拥抱还是抗拒','然而，如果我们无法对这些毒素加以控制，情况就会迅速失控。','15797-15825',5,1717391981,1782480557);
INSERT INTO highlights VALUES('3300095033_29_15667-15703','3300095033',29,'第一章 冲突，是拥抱还是抗拒','在理想情况下，会有人反对你的理念、质疑你的想法，从而使你的理念得到改善。','15667-15703',5,1717391968,1782480557);
INSERT INTO highlights VALUES('3300095033_29_15315-15354','3300095033',29,'第一章 冲突，是拥抱还是抗拒','当确定真相的任务优先于一切时，出现误解、伤害感情和担心报复的可能性就会相应降低','15315-15354',5,1717335385,1782480557);
INSERT INTO highlights VALUES('3300095033_29_15237-15273','3300095033',29,'第一章 冲突，是拥抱还是抗拒','经过科学方法的训练，他们能够在挑战彼此的研究成果时抑制住自己的本能情绪。','15237-15273',5,1717305810,1782480557);
INSERT INTO highlights VALUES('3300095033_29_14984-15010','3300095033',29,'第一章 冲突，是拥抱还是抗拒','科学的一个伟大之处在于，整个实践的目的就是探索真相。','14984-15010',5,1717305777,1782480557);
INSERT INTO highlights VALUES('3300095033_29_14775-14818','3300095033',29,'第一章 冲突，是拥抱还是抗拒','可证伪假说是科学的基石，也就是说，在宣称某件事的正确性之前，必须尝试证明此事是错误的。','14775-14818',5,1717305734,1782480557);
INSERT INTO highlights VALUES('3300095033_29_13121-13133','3300095033',29,'第一章 冲突，是拥抱还是抗拒','营造充斥着有益冲突的环境','13121-13133',5,1717302743,1782480557);
INSERT INTO highlights VALUES('3300095033_29_13000-13030','3300095033',29,'第一章 冲突，是拥抱还是抗拒','我们可以先发制人地对他人的情绪进行调控，防止其达到有害程度。','13000-13030',5,1717302694,1782480557);
INSERT INTO highlights VALUES('3300095033_29_12927-12959','3300095033',29,'第一章 冲突，是拥抱还是抗拒','同样，沟通对象的恐惧、愤怒、评判和自尊也会对冲突产生巨大的影响。','12927-12959',5,1717302685,1782480557);
INSERT INTO highlights VALUES('3300095033_29_12164-12196','3300095033',29,'第一章 冲突，是拥抱还是抗拒','愤怒是一剂强有力的调味品。一小撮能够让人振作，放太多却会麻痹感官','12164-12196',5,1717302521,1782480557);
INSERT INTO highlights VALUES('3300095033_29_10793-10822','3300095033',29,'第一章 冲突，是拥抱还是抗拒','当这四种因素中的任何一种变得过量或不足时，它就会演化成毒素','10793-10822',5,1717301951,1782480557);
INSERT INTO highlights VALUES('3300095033_29_10667-10701','3300095033',29,'第一章 冲突，是拥抱还是抗拒','准确来说，评判和自尊不是情绪，但为了简单起见，请允许我在此稍做延伸）','10667-10701',5,1717301910,1782480557);
INSERT INTO highlights VALUES('3300095033_29_10584-10640','3300095033',29,'第一章 冲突，是拥抱还是抗拒','其他情绪也会对冲突造成影响（比如嫉妒、贪婪和欲望等），但我发现，专注于这四种最主要的毒素，可以带来改变人生的收益','10584-10640',5,1717301887,1782480557);
INSERT INTO highlights VALUES('3300095033_29_10560-10580','3300095033',29,'第一章 冲突，是拥抱还是抗拒','这四大毒素分别是：恐惧、愤怒、评判和自尊','10560-10580',5,1717301873,1782480557);
INSERT INTO highlights VALUES('3300095033_29_10489-10493','3300095033',29,'第一章 冲突，是拥抱还是抗拒','四大毒素','10489-10493',5,1717301864,1782480557);
INSERT INTO highlights VALUES('3300095033_29_10370-10421','3300095033',29,'第一章 冲突，是拥抱还是抗拒','由此带来的一个影响是，我们的行为和反应往往会在本不存在冲突的地方制造冲突，或者激化矛盾，让事态变得更糟','10370-10421',5,1717301853,1782480557);
INSERT INTO highlights VALUES('3300095033_29_9003-9082','3300095033',29,'第一章 冲突，是拥抱还是抗拒','但在当今世界，我们面临的威胁通常是学校的大考、工作中的重要演讲，或是家庭聚会上价值观截然不同的亲戚。在这些情况下，一触即发的杏仁核会让我们陷入巨大的麻烦之中。','9003-9082',5,1717236921,1782480557);
INSERT INTO highlights VALUES('3300095033_29_8471-8560','3300095033',29,'第一章 冲突，是拥抱还是抗拒','你是否也曾在冲突结束几小时后才想到完美的应对方法？之所以会这样，是因为你的前额叶皮质在暴怒状态之下停止了运转，而一旦它重新上线，你就能够对冲突加以分析并运用创造力想出解决方案了。','8471-8560',5,1717236864,1782480557);
INSERT INTO highlights VALUES('3300095033_29_8217-8271','3300095033',29,'第一章 冲突，是拥抱还是抗拒','前额叶皮质正是生成逻辑、理性、计划和目标的基础，是大脑中负责做出正确决定、找出答案、仔细权衡行为后果的部分。','8217-8271',5,1717236841,1782480557);
INSERT INTO highlights VALUES('3300095033_29_7851-7894','3300095033',29,'第一章 冲突，是拥抱还是抗拒','我们对冲突的本能反应源于大脑中的两个杏仁状腺体，它们叫作杏仁核，位于眼睛和视神经的后方','7851-7894',5,1717236799,1782480557);
INSERT INTO highlights VALUES('3300095033_29_7417-7489','3300095033',29,'第一章 冲突，是拥抱还是抗拒','冲突有两个主要驱动因素：其一是先天因素（我们的大脑天生就能以特定的方式对冲突做出反应），其二是后天因素（社会环境会让我们在处理冲突时适得其反）。','7417-7489',5,1717236720,1782480557);
INSERT INTO highlights VALUES('3300095033_29_7307-7347','3300095033',29,'第一章 冲突，是拥抱还是抗拒','将冲突视为消极的和应该避免的东西，这种观念不仅是错误的，而且可能造成巨大的损失。','7307-7347',5,1717236710,1782480557);
INSERT INTO highlights VALUES('3300095033_29_7108-7128','3300095033',29,'第一章 冲突，是拥抱还是抗拒','只要存在人类沟通的地方，就必定存在冲突。','7108-7128',5,1717236691,1782480557);
