INSERT INTO highlights VALUES('3300095033_29_6412-6477','3300095033',29,'第一章 冲突，是拥抱还是抗拒','但当冲突毫无预警地降临在她身上时，恐慌的情绪油然而生，让她不知如何应对（我敢肯定，如果她不是一个住在城郊的白人女性，情况会更糟）。','6412-6477',5,1717236613,1782480557);
INSERT INTO highlights VALUES('3300095033_29_5099-5130','3300095033',29,'第一章 冲突，是拥抱还是抗拒','她承认这一悲剧错在通用汽车，并且向全世界保证，情况正在逐渐改善','5099-5130',5,1717236510,1782480557);
INSERT INTO highlights VALUES('3300095033_29_4949-4976','3300095033',29,'第一章 冲突，是拥抱还是抗拒','虽然设计上的缺陷属于技术问题，但根本问题却出在文化上。','4949-4976',5,1717236485,1782480557);
