INSERT INTO highlights VALUES('3300095033_29_3586-3638','3300095033',29,'第一章 冲突，是拥抱还是抗拒','关心他人并不意味着要一脸微笑和善，只说对方想听的话，而是需要你给出不那么容易被接受的反馈，帮助对方成长。','3586-3638',5,1717236315,1782480557);
