INSERT INTO highlights VALUES('3300095033_29_3283-3324','3300095033',29,'第一章 冲突，是拥抱还是抗拒','出于善意而表现出尊重和礼貌的理念衍生出这样一种环境：人们只说他们觉得别人想听的话。','3283-3324',5,1717235830,1782480557);
