INSERT INTO highlights VALUES('3300095033_29_2372-2411','3300095033',29,'第一章 冲突，是拥抱还是抗拒','高管们会尽量在两句赞扬之间插入一句建设性的批评（这就是经典的“三明治谈话”法）','2372-2411',5,1717223210,1782480557);
INSERT INTO highlights VALUES('3300095033_29_2186-2234','3300095033',29,'第一章 冲突，是拥抱还是抗拒','史蒂夫总会提出一些深刻而尖锐的问题，再以“这简直是一团糟！”之类的话收场，却从不会动怒或情绪化。','2186-2234',5,1717223190,1782480557);
