INSERT INTO highlights VALUES('3300095033_4_3820-3918','3300095033',4,'序言','读完本书，你将会增强同理心；学会如何在陷入冲突陷阱之前辨识出危险；学会将冲突视为成功的有效驱动力；学会通过简单而高效的方式应对冲突，让冲突成为助推我们进步的燃料，在生活的方方面面实现更有效的沟通。','3820-3918',5,1717212087,1782480557);
INSERT INTO highlights VALUES('3300095033_4_3322-3356','3300095033',4,'序言','另一些人的职业生涯却一无所获，后者的原因可能就在于缺少对冲突的理解。','3322-3356',5,1717211999,1782480557);
INSERT INTO highlights VALUES('3300095033_4_2673-2714','3300095033',4,'序言','我们虽然几乎每天都要用到冲突管理方面的知识，却没有投入哪怕极少的时间学习相关内容。','2673-2714',5,1717211946,1782480557);
INSERT INTO highlights VALUES('3300095033_4_1938-1977','3300095033',4,'序言','但我注意到，如果能去除冲突中的毒素，反而可以用这些冲突来助推我们的业务向前发展','1938-1977',5,1717211844,1782480557);
INSERT INTO highlights VALUES('3300095033_4_1158-1205','3300095033',4,'序言','同样的痛苦状况也可能在我们的个人生活中上演，有害的冲突让我们与爱情、友谊等良好的人际关系无缘。','1158-1205',5,1717211688,1782480557);
