INSERT INTO highlights VALUES('3300046899_104_1805-2073','3300046899',207,'后记 不与糟糕的事情对抗',unistr('海灵格有首诗叫作《允许一切发生》，他说：\u000a情绪只是身体上的觉受，本无好坏。\u000a越是抗拒，越是强烈。\u000a若我觉得不应该出现这样的情绪，\u000a伤害的，只是自己。\u000a我唯一能做的，\u000a就是允许。'),'1841-2109',NULL,1675819951,1782480564);
