INSERT INTO highlights VALUES('3300046899_103_5746-5807','3300046899',206,'100 人性能有多复杂（二）','新鲜感很短暂，得靠距离和惊喜去维系，但长久的人生却更需要一个人有踏实、认真、务实、责任心等品质，这些都比“有趣”更有分量。','5869-5930',NULL,1675819685,1782480564);
INSERT INTO highlights VALUES('3300046899_103_3553-3577','3300046899',206,'100 人性能有多复杂（二）','打败婚姻的，并不是爱情的消失，而是注意力的转移。','3650-3674',NULL,1675819548,1782480564);
