INSERT INTO highlights VALUES('3300046899_103_2324-2355','3300046899',206,'100 人性能有多复杂（二）','婚姻制度很有意思，既维护了爱情的稳定，又让人总想突破这种稳定。','2395-2426',NULL,1675819458,1782480564);
INSERT INTO highlights VALUES('3300046899_103_1488-1551','3300046899',206,'100 人性能有多复杂（二）','大家总以为女人是爱上某个男人，其实未必，女人是爱上爱情本身，那个男人不过是爱情的工具人，不是他，还会有别人，而且，差别未必大。','1533-1596',NULL,1675819375,1782480564);
