INSERT INTO highlights VALUES('3300046899_101_1565-1623','3300046899',204,'98 婚姻里的尊严','婚姻里的尊严，并不是别人给的，而是来自自己的谋划——有时是收入，有时是协议，有时是共识，有时是遇见一个善良人的运气。','1584-1642',NULL,1675777394,1782480564);
INSERT INTO highlights VALUES('3300046899_100_874-930','3300046899',203,'97 人性的“不可能三角”','女人也有“不可能三角”：既漂亮，又经济独立，还不作，这三个点几乎无法同时出现在一个女人身上，世界上没有田螺姑娘。','893-949',NULL,1675777291,1782480564);
INSERT INTO highlights VALUES('3300046899_100_809-830','3300046899',203,'97 人性的“不可能三角”','男人不可能同时满足帅、有钱、专一这三个特点','828-849',NULL,1675777281,1782480564);
INSERT INTO highlights VALUES('3300046899_100_665-765','3300046899',203,'97 人性的“不可能三角”','人性的“不可能三角”：金钱、名气和权力几乎是每个人走进社会后的目标，但是这三者能获得一项已经是幸运；获得两项必须付出高处不胜寒的代价；如果三项都想要，那就太贪心，结局往往竹篮打水一场空，什么都得不到。','684-784',NULL,1675777267,1782480564);
INSERT INTO highlights VALUES('3300046899_100_447-481','3300046899',203,'97 人性的“不可能三角”','一个国家不可能同时实现资本流动自由、货币政策的独立性和汇率的稳定性。','466-500',NULL,1675777186,1782480564);
INSERT INTO highlights VALUES('3300046899_99_1226-1283','3300046899',202,'96 承认别人优秀，自己同样优秀','有底气和雅量，人的幸福感会强一些，毕竟，别人不会因为你的贬低而变得糟糕，你却会因为嫉妒而感到心塞，这有点得不偿失。','1245-1302',NULL,1675777170,1782480564);
INSERT INTO highlights VALUES('3300046899_98_2037-2234','3300046899',201,'95 向谁能借到30万救命？',unistr('久病床前，难有孝子。\u000a长年琐碎，消耗恩爱。\u000a终日阴霾，哪有阳光。\u000a这种现实和我们想象中的场景落差有点大。\u000a但这才是真实的人性：每个人都是自己的接盘侠，而不能指望别人托底。'),'2056-2253',NULL,1675777092,1782480564);
INSERT INTO highlights VALUES('3300046899_97_1285-1369','3300046899',200,'94 一位爸爸对三个女儿的期望','“我可以毫无保留地爱自己的女儿们，但不代表她们长大一定能遇到毫无保留爱她们的另一半。我可以把财产留给她们，但不代表她们就能富足地过一生，人争取财富和守住财富都要靠本事。','1304-1388',NULL,1675733654,1782480564);
INSERT INTO highlights VALUES('3300046899_96_3850-3879','3300046899',199,'93 该放弃，就放弃','大多数成年人，都将活得务实，略无趣，略保守，适度保持梦想。','3869-3898',NULL,1675733569,1782480564);
