INSERT INTO highlights VALUES('3300046899_94_1266-1351','3300046899',197,'第十章 自在','情绪化是我对世界毫无办法之后的发泄，解决不了问题，却烧光了自己的清醒，烧坏了别人对我的印象。搞不定可以绕道，绕不过去还可以放弃，放手有时是及时止损，甚至是另一个高效的开始','1279-1364',NULL,1675733136,1782480564);
