INSERT INTO highlights VALUES('3300046899_90_2496-2583','3300046899',193,'87 立场不同','现实生活中也是这样，每个人都有不同立场和不同角度，说的未必是谎言，但可能掩盖了很多不想让你知道的真相。多几个思考问题的角度，多几个看待别人的立场，能让我们的判断更接近于真实。','2515-2602',NULL,1675648134,1782480564);
