INSERT INTO highlights VALUES('3300046899_83_2286-2319','3300046899',186,'80 结婚需“划算”','所以，才要抓紧时间让自己开心啊，自己觉得满足，才是人生最大的划算。','2305-2338',NULL,1675617148,1782480564);
INSERT INTO highlights VALUES('3300046899_83_2169-2257','3300046899',186,'80 结婚需“划算”','人一辈子真能为自己活的时间其实很短暂，幼年要仰仗父母的照料，成年要应对社会的要求。当我们达到了一个小阶段，真的生长到通透，能够实现为自己而活的时候，却发现这个阶段短到转瞬即逝。','2188-2276',NULL,1675617134,1782480564);
INSERT INTO highlights VALUES('3300046899_83_2058-2097','3300046899',186,'80 结婚需“划算”','周国平老师说：“爱情是精神生活，遵循理想原则；婚姻是社会生活，遵循现实原则。”','2077-2116',NULL,1675617097,1782480564);
INSERT INTO highlights VALUES('3300046899_82_3121-3175','3300046899',185,'79 “活得久了，人生充满惊奇”','有足够的时间，才有足够腾挪跌宕的空间，才能等到迷雾逐渐散去，才能让痛苦逐渐变成平静，才能把困顿缓慢踏成坦途。','3140-3194',NULL,1675594073,1782480564);
INSERT INTO highlights VALUES('3300046899_82_3230-3247','3300046899',185,'79 “活得久了，人生充满惊奇”','你活得久了，就会发现人生充满惊奇。','3249-3266',NULL,1675594067,1782480564);
INSERT INTO highlights VALUES('3300046899_82_2311-2338','3300046899',185,'79 “活得久了，人生充满惊奇”','冯仑说，什么叫拧巴？你是个悲观主义者，却悲观得不彻底。','2330-2357',NULL,1675593973,1782480564);
INSERT INTO highlights VALUES('3300046899_80_3339-3371','3300046899',183,'77 自我，并不容易找到','但那又如何？没有什么比历尽波折找寻到真实的自己，更为快乐和强大。','3358-3390',NULL,1675518461,1782480564);
INSERT INTO highlights VALUES('3300046899_80_3400-3448','3300046899',183,'77 自我，并不容易找到','戴安娜短暂的36年生命中，她从未停止过寻找自我，这或许才是普通人长久喜欢她的原因，也是她的魅力。','3419-3467',NULL,1675518458,1782480564);
INSERT INTO highlights VALUES('3300046899_80_2777-2825','3300046899',183,'77 自我，并不容易找到','其实我们每个人都在终其一生寻找着自己的人生定位，谁都不是从一开始就能认清自我，确定这一生的追求。','2796-2844',NULL,1675518347,1782480564);
INSERT INTO highlights VALUES('3300046899_78_1349-1383','3300046899',181,'75 付出越多，越难被爱','人最底线的爱，是自爱；只要你依然爱着自己，世界上就不会缺少爱你的人。','1368-1402',NULL,1675518028,1782480564);
