INSERT INTO highlights VALUES('3300046899_78_397-479','3300046899',181,'75 付出越多，越难被爱',unistr('我曾经非常错误的行为模式，就是在各种关系中都会主动付出，希望用“主动示好”的方式，交换到对方的好评和友善。\u000a'),'416-469',NULL,1675517802,1782480564);
INSERT INTO highlights VALUES('3300046899_77_823-869','3300046899',180,'74 爱情是热烈的奔跑，婚姻是慢慢的生长','大多数文艺男女热爱幻想，踏实挣钱的能力极差，如果因为这些才华爱上对方，请做好安贫乐道的准备。','842-888',NULL,1675517772,1782480564);
INSERT INTO highlights VALUES('3300046899_77_445-519','3300046899',180,'74 爱情是热烈的奔跑，婚姻是慢慢的生长',unistr('恋爱男女的样子，基本是最好的样子。\u000a如果结婚是为了改变对方，期待对方以后更好，大概率是幻想。'),'464-538',NULL,1675497408,1782480564);
INSERT INTO highlights VALUES('3300046899_76_1499-1530','3300046899',179,'73 格局更大的择偶观','尤其恋爱和结婚，不仅是为自己选择伴侣，更是给未来的孩子选择父亲','1518-1549',NULL,1675497376,1782480564);
INSERT INTO highlights VALUES('3300046899_76_928-991','3300046899',179,'73 格局更大的择偶观','真正合适的配偶，应该具备这几个优点：诚实的品质，积极学习的态度，稳定的情绪，明确的人生目标，还有谈论别人时流露出的善意和谦虚。','947-1010',NULL,1675435029,1782480564);
INSERT INTO highlights VALUES('3300046899_76_724-812','3300046899',179,'73 格局更大的择偶观','有些男孩在寒风中等你下班，给你送花送礼物，夸你漂亮，或者给你发很感动的信息，都不用成为选择他的标准，因为这些都是低成本付出。容我刻薄一下，有些人不是因为“爱”，而是因为“闲”。','743-831',NULL,1675435010,1782480564);
INSERT INTO highlights VALUES('3300046899_75_1877-1937','3300046899',178,'72 婚姻打工人','这个时代给了很多人造富的机会，无论是和有钱的伴侣结婚富起来，还是白手起家富起来，都别糟蹋，像守护命运一样护住财富的来源。','1896-1956',NULL,1675434926,1782480564);
INSERT INTO highlights VALUES('3300046899_74_1155-1231','3300046899',177,'第八章 自愈','那段经历让我明白，如果想获得温暖，就去找一个天性温暖的人，不要试图捂热一块冰；如果想收获爱，就去找一个内心有爱的人，不要试图在一颗冷漠的心里，培育出爱。','1168-1244',NULL,1675434741,1782480564);
INSERT INTO highlights VALUES('3300046899_74_1049-1126','3300046899',177,'第八章 自愈','我不接招对方的冷暴力，他反而失落了；我降低对他的关注度，与朋友、同事多相处，结果发现这个世界上更多人从来不用冷暴力和别人沟通；再后来，我主动和这个人分开。','1062-1139',NULL,1675434731,1782480564);
INSERT INTO highlights VALUES('3300046899_73_2663-2709','3300046899',176,'70 做一件让你感到害怕的事','罗振宇说：“成长就是你主观世界遇到客观世界之间的那条沟，你掉进去了叫挫折，爬出来了叫成长。”','2682-2728',NULL,1675434684,1782480564);
