INSERT INTO highlights VALUES('3300046899_73_1932-1944','3300046899',176,'70 做一件让你感到害怕的事','第二，从5%的改变做起。','1951-1963',NULL,1675434489,1782480564);
INSERT INTO highlights VALUES('3300046899_73_2078-2129','3300046899',176,'70 做一件让你感到害怕的事','哪怕每天只有1%的进步，长期坚持就是了不起的成就。把难办的问题切分成小计划，长久以往，积累出巨大势能。','2097-2148',NULL,1675391284,1782480564);
INSERT INTO highlights VALUES('3300046899_73_1973-2041','3300046899',176,'70 做一件让你感到害怕的事','“5%的改变”是心理学者李松蔚老师的观点，他说：“你只想要100%的改变，所以你才被困住了。其实只需要改变5%，生活就会有全新的可能。”','1992-2060',NULL,1675391263,1782480564);
INSERT INTO highlights VALUES('3300046899_73_1580-1592','3300046899',176,'70 做一件让你感到害怕的事','穷则变，变则通，通则久。','1599-1611',NULL,1675391228,1782480564);
INSERT INTO highlights VALUES('3300046899_73_1593-1641','3300046899',176,'70 做一件让你感到害怕的事','意思是：发展到极点，叫“穷尽”，任何事情走到尽头，就要“变革”，改变之后才能通畅，通畅才能长久。','1612-1660',NULL,1675391220,1782480564);
INSERT INTO highlights VALUES('3300046899_71_1430-1505','3300046899',174,'68 有教养','我很喜欢英国哲学家约翰·洛克的表达：“在缺乏教养的人身上，勇敢就会成为粗暴，学识就会成为迂腐，机智就会成为逗趣，质朴就会成为粗鲁，温厚就会成为谄媚。”','1449-1524',NULL,1675334409,1782480564);
INSERT INTO highlights VALUES('3300046899_71_391-461','3300046899',174,'68 有教养','易中天老师说：“我太太定的家规是，服务员上菜，一定要说谢谢；快递员送货，一定要说辛苦了；司机把我们送回家，一定要行注目礼，车开走了才进门。”','410-480',NULL,1675334284,1782480564);
INSERT INTO highlights VALUES('3300046899_70_1360-1377','3300046899',173,'67 不被理解是常态','不被理解是常态，能被理解才是惊喜。','1379-1396',NULL,1675334271,1782480564);
INSERT INTO highlights VALUES('3300046899_70_1237-1277','3300046899',173,'67 不被理解是常态','假如在别人的目光里找快乐，可能始终悲哀；假如在别人的反应中找尊严，可能始终卑微。','1256-1296',NULL,1675334264,1782480564);
