INSERT INTO highlights VALUES('3300046899_68_844-883','3300046899',171,'65 总是吃苦，会忘记甜的滋味','延迟满足没错，但拖得太久，再好的东西都将随着时间的流逝，失去原本的惊喜和价值。','863-902',NULL,1675313397,1782480564);
INSERT INTO highlights VALUES('3300046899_67_1316-1403','3300046899',170,'64 八面玲珑不是夸奖','作家贾行家老师说过一段话特别绝：什么叫社会人？就是社交手段高明，在尊严上相当灵活，对个人利益的执行和变现能力很强，对道德评价看得很淡，他们相信别人的非议会随着自己的成功而消失','1335-1422',NULL,1675299560,1782480564);
INSERT INTO highlights VALUES('3300046899_67_967-973','3300046899',170,'64 八面玲珑不是夸奖','拙诚胜于巧诈','986-992',NULL,1675299417,1782480564);
INSERT INTO highlights VALUES('3300046899_67_821-846','3300046899',170,'64 八面玲珑不是夸奖','我决定这一辈子啊，就老老实实做事，还自己老实人本色','840-865',NULL,1675299397,1782480564);
