INSERT INTO highlights VALUES('3300046899_64_1329-1354','3300046899',167,'第七章 自然','最差的时候，暂时别打扰任何人，尝试先梳理清楚自己。','1342-1367',NULL,1675298859,1782480564);
INSERT INTO highlights VALUES('3300046899_63_1337-1373','3300046899',166,'60 再好，也有保留；再差，也能顾惜','所以，人与人之间再好也要有所保留，这是智慧；再差也得有所顾惜，这是善良。','1356-1392',NULL,1675298726,1782480564);
INSERT INTO highlights VALUES('3300046899_63_1265-1308','3300046899',166,'60 再好，也有保留；再差，也能顾惜','生活就像一列火车，他人是过客，自己才是故乡，极少有人能陪我们走一生，能走一程已是缘分。','1284-1327',NULL,1675298719,1782480564);
