INSERT INTO highlights VALUES('3300046899_61_463-533','3300046899',164,'58 为什么有些人，总在关系里处于弱势？','在交往中总是受委屈和被动，我观察到的最重要的原因是：缺少自己的原则和底线，别人怎样对待她都行，刁难、欺负或者无意间的伤害，她好像都可以接受。','482-552',NULL,1675259711,1782480564);
INSERT INTO highlights VALUES('3300046899_60_820-891','3300046899',163,'57 太懂事，容易被辜负','看到这句，我的眼泪哗啦下来了。有句话说：后来才知道，脾气好的在受气，善解人意的在体谅，会照顾人的没有人照顾，会哭闹的有糖吃，太懂事的没人心疼。','839-910',NULL,1675259646,1782480564);
INSERT INTO highlights VALUES('3300046899_59_1424-1462','3300046899',162,'56 不轻易原谅','金星老师说：“人不犯我，我不犯人；人若犯我，礼让三分；人再犯我，斩草除根。”','1443-1481',NULL,1675259599,1782480564);
INSERT INTO highlights VALUES('3300046899_59_1040-1088','3300046899',162,'56 不轻易原谅','我被气笑了：“瞧你这话说的，好像我读书就是为了受欺负一样。对不起，我读书多是为了变得不好欺负。”','1059-1107',NULL,1675259574,1782480564);
INSERT INTO highlights VALUES('3300046899_58_1778-1827','3300046899',161,'55 结交“贵人”的4个方法','“向上社交”的本质，是有耐心把自己变成最大的“贵人”，然后再用这个高价值的自我，去遇见更优秀的人。','1797-1846',NULL,1675259493,1782480564);
INSERT INTO highlights VALUES('3300046899_57_2201-2285','3300046899',160,'54 健康人际关系的6个特点','学会用离开的方式善待自己。离开某些人不是因为他们不好，而是因为跟他们在一起，我的状态不好。如果对方很容易激发我的脆弱、焦虑和不安，而我又无法改变，离开才是最好的选择。”','2220-2304',NULL,1675259358,1782480564);
INSERT INTO highlights VALUES('3300046899_57_2065-2073','3300046899',160,'54 健康人际关系的6个特点','6.感受到成长。','2084-2092',NULL,1675259343,1782480564);
