INSERT INTO highlights VALUES('3300046899_42_1812-1899','3300046899',145,'39 放下精英的傲慢','珍惜天分的可贵，做好努力的本分，感激幸运的力量，提醒自己保持谦和与清醒，世界上有太多东西劳而无功，太多事情竹篮打水，太多平凡人无法选择，生活中常见的不是“成功”，而是“意外”','1831-1918',NULL,1675234309,1782480564);
