INSERT INTO highlights VALUES('3300046899_41_1308-1381','3300046899',144,'38 实力强的人，更容易被宽容','有句话叫“你弱的时候坏人最多”，未必是坏人多，而是因为你弱，抗风险能力太差，别人有点动静对你都是惊涛骇浪，哪怕一个小机会被夺走，对你都是灭顶之灾。','1327-1400',NULL,1675234123,1782480564);
