INSERT INTO highlights VALUES('3300046899_39_1470-1526','3300046899',142,'36 找准优势，降维打击','放弃“专业对口”的执念，从低门槛的岗位开始，找到一个好平台，迅速在社会中定位自己，找准方向——这也是成事的方式。','1489-1545',NULL,1675233797,1782480564);
