INSERT INTO highlights VALUES('3300046899_16_1375-1417','3300046899',119,'13 被生活逼急了','但是，或许和这位保洁阿姨一样，只是被生活逼急了，而我们恰好遇到ta们被逼急的那一面。','1394-1436',NULL,1675205111,1782480564);
INSERT INTO highlights VALUES('3300046899_14_1886-1943','3300046899',117,'第二章 自省','人与人永远无法完全共情，语气温和但态度坚定，尽量别让硬邦邦的世界伤害自己，能给出“软钉子”，也是我们的“硬实力”。','1899-1956',NULL,1675202314,1782480564);
