INSERT INTO highlights VALUES('3300046899_14_1573-1633','3300046899',117,'第二章 自省','《非暴力沟通》中，介绍了怎样转变谈话方式来减少人与人之间因为语言而带来的痛苦，他总结了四个要素：观察、感受、需要和请求，','1586-1646',NULL,1675202201,1782480564);
