INSERT INTO highlights VALUES('3300046899_13_734-800','3300046899',116,'10 不断发现可能性','真实的写作过程很枯燥，如何衡量一个人是作家还是玩票，三个条件非常重要：一是长期从事写作，二是作品输出稳定，三是足够的社会认同和销量。','753-819',NULL,1675201234,1782480564);
INSERT INTO highlights VALUES('3300046899_12_1251-1282','3300046899',115,'9 思路决定出路','思考未来时，请记得：思路决定出路，态度决定高度，格局决定结局。','1270-1301',NULL,1675201167,1782480564);
INSERT INTO highlights VALUES('3300046899_11_1804-1873','3300046899',114,'8 逆袭必读','逆袭最大的难度不是超越自己，而是不让原来的圈层捆绑住你，不让原来的思维禁锢住你，不让原来的起点拉扯住你，努力飞到一片自己从未想象过的天空。','1823-1892',NULL,1675201033,1782480564);
INSERT INTO highlights VALUES('3300046899_11_911-991','3300046899',114,'8 逆袭必读','父母和朋友为我考虑了最安全的路线，初衷是为我好。但是，多少人全力以赴投入，都未必能做成事，凭什么我又追求稳定又想高收入，既不辞职也不全情投入，就能把事情做好呢？','930-1010',NULL,1675200878,1782480564);
INSERT INTO highlights VALUES('3300046899_10_1512-1533','3300046899',113,'7 世俗的成功给人自由','财富和地位，可以保护智者免受小人的伤害。”','1531-1552',NULL,1675200788,1782480564);
INSERT INTO highlights VALUES('3300046899_10_1170-1261','3300046899',113,'7 世俗的成功给人自由','我见过很多不符合主流道路的选择，起初被所有人反对，但如果获得了名利等世俗意义上的成功，别人的非议就会减少很多；还有一些不符合大众的审美，一旦被权威认定是独特的美丽，立刻变得光彩照人。','1189-1280',NULL,1675200729,1782480564);
INSERT INTO highlights VALUES('3300046899_9_3022-3076','3300046899',112,'6 条件交换','“条件交换”，假如总是吃亏，总是把合理利益让给别人，这不是福气，是没有原则，成年人该有的样子是宽容却不软弱。','3041-3095',NULL,1675200441,1782480564);
INSERT INTO highlights VALUES('3300046899_9_2396-2461','3300046899',112,'6 条件交换','你抢先把方向盘拆下来，当着对方的面扔掉。其实是让对手看到你破釜沉舟的决心，把难题丢给他，让他明白，只能他退，你就算想退也退不成了。','2415-2480',NULL,1675200354,1782480564);
INSERT INTO highlights VALUES('3300046899_9_1023-1058','3300046899',112,'6 条件交换','其实唐太宗赐的不是毒酒，传说是一壶醋，“吃醋”的典故据说就是由此而来。','1042-1077',NULL,1675200132,1782480564);
