INSERT INTO highlights VALUES('3300046899_5_728-788','3300046899',108,'2 与其“被喜欢”，不如“被需要”','“第三，很多人不喜欢你，是因为你得到了他们没有得到的东西，小到一个停车位、一件好看的衣服，大到一次升职、一个幸福的婚姻。','747-807',NULL,1675199658,1782480564);
INSERT INTO highlights VALUES('3300046899_5_635-699','3300046899',108,'2 与其“被喜欢”，不如“被需要”','第二，你不符合别人的价值观，这个你改不了，因为世界上每个人都有自己的价值观，你讨好不过来，所以，三观合拍就相处，不合就保持距离。','654-718',NULL,1675199647,1782480564);
INSERT INTO highlights VALUES('3300046899_5_575-605','3300046899',108,'2 与其“被喜欢”，不如“被需要”','第一，你确实有一些不讨人喜欢的习惯，这个你可以在自省后修正。','594-624',NULL,1675199641,1782480564);
INSERT INTO highlights VALUES('3300046899_5_518-545','3300046899',108,'2 与其“被喜欢”，不如“被需要”','不要花太多精力去讨别人喜欢。别人不喜欢你有三个原因——','537-564',NULL,1675199629,1782480564);
INSERT INTO highlights VALUES('3300046899_4_1594-1620','3300046899',107,'第一章 自主','有句话说：“主动与不主动之间，生命资源相差30倍。”','1624-1650',NULL,1675199556,1782480564);
INSERT INTO highlights VALUES('3300046899_3_2498-2576','3300046899',106,'前言 过好生活的基本功','我始终记得《宁静祷文》中所说：请赐给我雅量，平静接受不可改变的事；赐给我勇气，去改变应该改变的事；并赐给我智慧，去分辨什么是可以改变的、什么是不可改变的事。','2534-2612',NULL,1675199229,1782480564);
INSERT INTO highlights VALUES('3300046899_3_2332-2384','3300046899',106,'前言 过好生活的基本功','“自在”不是不争不抢不在乎，那是放弃。“自在”是掌握了基本方法之后，变得通情达理，还能把想做的事情办成。','2368-2420',NULL,1675199208,1782480564);
INSERT INTO highlights VALUES('3300046899_3_2259-2303','3300046899',106,'前言 过好生活的基本功','的确，与“成熟”相比，我更喜欢“自在”，这是一种不经意间“轻舟已过万重山”的开朗与豁达。','2295-2339',NULL,1675199200,1782480564);
INSERT INTO highlights VALUES('3300046899_3_1304-1334','3300046899',106,'前言 过好生活的基本功','自主、自省、自律、自修、自洽、自如、自然、自愈、自信和自在。','1340-1370',NULL,1675166012,1782480564);
INSERT INTO highlights VALUES('3300046899_3_889-949','3300046899',106,'前言 过好生活的基本功','就像生活里那些很厉害的人，大多数一直在踏踏实实做自己应该做的事，他们厉害在错误率低，而不是偶尔打出了几个惊天动地的好球。','925-985',NULL,1675165976,1782480564);
INSERT INTO highlights VALUES('35138325_51_2862-2883','35138325',51,'做个老实人','凡道理不可说得太高，太高则近于矫，近于伪。','2862-2883',5,1703304829,1782480562);
INSERT INTO highlights VALUES('35138325_51_2331-2384','35138325',51,'做个老实人','看上去非常普通的事情，其实是最难做到的。所以曾国藩另说：“养生与力学皆从有恒作出，故古人以有恒为作圣之基。','2331-2384',5,1703304764,1782480562);
INSERT INTO highlights VALUES('35138325_51_1085-1138','35138325',51,'做个老实人','平安是福，这句话听上去，是一个没有比它更老生常谈的老生常谈，但绝对是最重要的一句话：做个老实人，平安是福。','1085-1138',5,1703304733,1782480562);
INSERT INTO highlights VALUES('35138325_51_2107-2242','35138325',51,'做个老实人','第一原则，不给别人添不必要的麻烦，特别是不能陷害他人，不能耍权术。第二原则，自己的事情自己做。能做到这两条基本原则的人，无论贫、贱、美、丑，就是一个堂堂正正、合格的人。如果在此基础上，再能做到勤奋、谨慎，就是人才。如果再能做到大处着眼、小处着手，就是人杰。','2107-2242',5,1703304608,1782480562);
INSERT INTO highlights VALUES('35138325_50_3830-3860','35138325',50,'职场中最重要的品质','如果你持续地来实践这个“恕”，最大的副作用是，你身边的人最苦','3830-3860',5,1703303480,1782480562);
