INSERT INTO highlights VALUES('35138325_50_1973-2021','35138325',50,'职场中最重要的品质','雪花啤酒为什么能做到销量第一？有各种各样的原因，其中一个重要原因，就是对现饮渠道数据掌握的扎实性','1973-2021',5,1703302619,1782480562);
INSERT INTO highlights VALUES('35138325_50_1494-1598','35138325',50,'职场中最重要的品质','很多事情不见得有正确答案，但你要有一个正确的态度。“若将天地常揣摩，妙理终有一日开”，一定要事无巨细，综合分析，高到高高山顶，低到深深海底，大处着眼，小处着手，反复揣摩一个事情。然后你才能说，你有可能是对的。','1494-1598',5,1703302565,1782480562);
INSERT INTO highlights VALUES('35138325_50_1005-1014','35138325',50,'职场中最重要的品质','敬以持躬，恕以待人','1005-1014',5,1703302501,1782480562);
INSERT INTO highlights VALUES('35138325_50_659-721','35138325',50,'职场中最重要的品质','“古之欲明明德于天下者，先治其国；欲治其国者，先齐其家；欲齐其家者，先修其身；欲修其身者，先正其心；欲正其心者，先诚其意。”','659-721',5,1703302479,1782480562);
INSERT INTO highlights VALUES('35138325_50_613-630','35138325',50,'职场中最重要的品质','“修齐治平”之前是“诚意、正心”。','613-630',5,1703302465,1782480562);
INSERT INTO highlights VALUES('35138325_50_477-548','35138325',50,'职场中最重要的品质','职场中最重要的不是能力、人脉、所受的教育，而是态度。如果态度对了，就不会走错路，不会吃大亏，即使没什么成就，你还是一个很好的人。','477-548',5,1703302454,1782480562);
INSERT INTO highlights VALUES('35138325_49_3945-4010','35138325',49,'示弱的杀伤力','推功揽过，自己想立，先把别人立起来，自己想干事，先让别人也能干事，己欲达而达人，己欲立而立人，成大事的人，其实应该让他人也成大事。','3945-4010',5,1703302418,1782480562);
INSERT INTO highlights VALUES('35138325_49_2581-2638','35138325',49,'示弱的杀伤力','2.在示弱过程中，你自然而然地做了预期管理。如果到最后共同把事情做成了，大家反而会觉得，你做得不错，你其实有长进。','2581-2638',5,1703302219,1782480562);
INSERT INTO highlights VALUES('35138325_49_2483-2519','35138325',49,'示弱的杀伤力','1.让被示弱方知道你是他的同伴，而不是高高在上的所谓领导或者冰冷的对手。','2483-2519',5,1703302213,1782480562);
INSERT INTO highlights VALUES('35138325_49_2424-2454','35138325',49,'示弱的杀伤力','其实示弱管理，核心是强者示弱。强者示弱有两点非常明确的好处。','2424-2454',5,1703302199,1782480562);
INSERT INTO highlights VALUES('35138325_49_2004-2054','35138325',49,'示弱的杀伤力','对于自己负面的想法，我认、我忍，我接受自己的不完美、不能干。天地皆残，何况物乎，何况人乎，何况事乎？','2004-2054',5,1703301979,1782480562);
INSERT INTO highlights VALUES('35138325_49_1233-1316','35138325',49,'示弱的杀伤力','所以，时间可能是一个示弱的提示点，你时间、精力不够了，你要明确说，无论是从时间、体力、精力，还是你的能力、资源来看，你没本事来做这件事。这个时候就是你需要示弱的时候。','1233-1316',5,1703209734,1782480562);
INSERT INTO highlights VALUES('35138325_49_1051-1092','35138325',49,'示弱的杀伤力','选择何时示弱其实非常直接、简单，就是有件事，你特别想做，但是没时间和精力做的时候。','1051-1092',5,1703209693,1782480562);
INSERT INTO highlights VALUES('35138325_48_7023-7087','35138325',48,'什么是能量管理','能量管理是隐含在成事背后的发动机。把成事的事业作为一个马拉松，而不是一个百米短跑。你会发现漫长的一生，有了更多成事的可能和希望。','7023-7087',5,1703209619,1782480562);
INSERT INTO highlights VALUES('35138325_48_3023-3032','35138325',48,'什么是能量管理','3.维持能量平衡。','3023-3032',5,1702733379,1782480562);
INSERT INTO highlights VALUES('35138325_48_2445-2524','35138325',48,'什么是能量管理','打得太凶，看上去在短期内形成了某种成效，但不持续，你会发现，猛打、猛跑，效果差于你用不快不慢的速度持续行进。因为身体怕忽起忽落的节奏，心气其实也怕巨大的起伏。','2445-2524',5,1702733314,1782480562);
INSERT INTO highlights VALUES('35138325_48_1981-2003','35138325',48,'什么是能量管理','1.做一些胜算大的项目，不要总是去赌，去搏。','1981-2003',5,1702733115,1782480562);
