INSERT INTO highlights VALUES('35138325_48_1618-1697','35138325',48,'什么是能量管理','高管一旦离开了，相对的审计、监察、纪检部门就很容易做事了。因为高管一离开，一定是要把自己的工作托付给他的替手，替手一接手，如果有严重的问题，很容易就会暴露出来','1618-1697',5,1702733090,1782480562);
INSERT INTO highlights VALUES('35138325_48_1285-1381','35138325',48,'什么是能量管理','没有见过一直工作还能把工作做得非常好的人，纯粹的工作狂，完全没生活、没情调、不放松，还能把仗打好，几乎没有。对这种人，我往往会心存一点点戒心和恐惧，因为像一把刀一样，他很有可能造成巨大的风险。','1285-1381',5,1702732996,1782480562);
