INSERT INTO highlights VALUES('35138325_46_3786-3826','35138325',46,'找合拍的人一起做事','你可以跟周围最美的身边人说“We had good time together”','3786-3826',5,1702654717,1782480562);
INSERT INTO highlights VALUES('35138325_46_3526-3549','35138325',46,'找合拍的人一起做事','意义，如果有意义，就是那些过程中的点滴小时光。','3526-3549',5,1702654701,1782480562);
INSERT INTO highlights VALUES('35138325_46_2762-2841','35138325',46,'找合拍的人一起做事','危险之际，爱而从之者，或有一二；畏而从之者，则无其事也。”真的危险出现了，因为爱你能够跟你在一块儿的，或许能有一两个，因为怕你而跟你在一块儿的，根本就不存在。','2762-2841',5,1702638342,1782480562);
INSERT INTO highlights VALUES('35138325_46_2517-2608','35138325',46,'找合拍的人一起做事','所以，在职场中我想给的提示是，最大的幸福来自最美的身边人。不背叛，能互相包容、互相帮助，不为小利所动，不争一时得失，能够推功揽过，最美好的是能和这样的身边人一起工作，一起度过好时光。','2517-2608',5,1702638321,1782480562);
INSERT INTO highlights VALUES('35138325_46_1993-2041','35138325',46,'找合拍的人一起做事','如果非要挑，是和自己喜欢的人在一起，还是和喜欢自己的人在一起？他说他挑的是和喜欢自己的人在一起。','1993-2041',5,1702638216,1782480562);
INSERT INTO highlights VALUES('35138325_46_1917-1993','35138325',46,'找合拍的人一起做事','如果你不得不挑，是做自己擅长的事，还是自己喜欢的事？那你还是做自己擅长的事。因为慢慢地，别人的、社会的正向鼓励，你会认为自己擅长的事也是你自己喜欢的事。','1917-1993',5,1702638206,1782480562);
INSERT INTO highlights VALUES('35138325_46_1724-1842','35138325',46,'找合拍的人一起做事',unistr('他说人类幸福的根源，只有两件事：\u000a第一是人，就是和自己喜欢同时也喜欢自己的人，在一起工作；\u000a第二是事，做自己擅长又喜欢的事。'),'1724-1842',5,1702602771,1782480562);
INSERT INTO highlights VALUES('35138325_45_3482-3525','35138325',45,'交友的标准','争取有几个挑你毛病的朋友，也争取有几个一直不挑你毛病的朋友，或许是一个平衡的解决之道。','3482-3525',5,1702602648,1782480562);
INSERT INTO highlights VALUES('35138325_45_2442-2453','35138325',45,'交友的标准','6.不要经常教育晚辈。','2442-2453',5,1702602563,1782480562);
INSERT INTO highlights VALUES('35138325_45_2352-2413','35138325',45,'交友的标准','5.不要追忆从前，哪怕你是老将军，也不要总是追忆昔年壮勇，叹自己的欲望未酬。一旦开始经常追忆，离这个“中年油腻”就不远了。','2352-2413',5,1702602553,1782480562);
INSERT INTO highlights VALUES('35138325_45_1556-1575','35138325',45,'交友的标准','不成为一个油腻的小人，就是相当的圆满了','1556-1575',5,1702602463,1782480562);
INSERT INTO highlights VALUES('35138325_45_1355-1399','35138325',45,'交友的标准','中年正是可圣可狂之际，可以往上走，也可以往下走，也可以在中间晃悠。这就是中年人的难办之处','1355-1399',5,1702602437,1782480562);
INSERT INTO highlights VALUES('35138325_45_780-801','35138325',45,'交友的标准','不仅不能老自夸，而且不能经常互相夸、捧臭脚','780-801',5,1702602366,1782480562);
INSERT INTO highlights VALUES('35138325_44_3725-3743','35138325',44,'如何面对人际交往中的心机','难得糊涂，吃得下，睡得着，老实最安全','3725-3743',5,1702602307,1782480562);
INSERT INTO highlights VALUES('35138325_44_3376-3472','35138325',44,'如何面对人际交往中的心机','作为一个要成事的修炼者，尊重“人是不同的”的事实，不要妄图改变每个人的想法，不要妄图在每一件事上都能达成共识。更重要的是，不要让不同人的不同心眼和心思，特别是那些负面的心眼和心思，影响到自己。','3376-3472',5,1702571677,1782480562);
INSERT INTO highlights VALUES('35138325_44_3106-3189','35138325',44,'如何面对人际交往中的心机','面对心机，曾国藩说“惟忘机可以消众机，惟懵懂可以祓不祥”，只有忘掉心机，才可以消除大家的心机，只有懵懵懂懂，假装糊涂，或者不去想，才能除去不祥。“祓”，是除去的意思。','3106-3189',5,1702571605,1782480562);
INSERT INTO highlights VALUES('35138325_44_2367-2390','35138325',44,'如何面对人际交往中的心机','只要你是针对事交流，而不是针对人的心机去交流。','2367-2390',5,1702571529,1782480562);
INSERT INTO highlights VALUES('35138325_44_2107-2233','35138325',44,'如何面对人际交往中的心机','他人是地狱。我们经常会问自己，这个人怎么会这个样子？但是要知道存在即合理。我建议，要多思考、多了解这个人为什么这样子。不要总气愤地说，这个人怎么这个样子，而是真诚地问自己，这个人怎么会这个样子，他是怎么想的。站在对方的角度想一想这个问题，就会豁然开朗。','2107-2233',5,1702571507,1782480562);
INSERT INTO highlights VALUES('35138325_44_2025-2078','35138325',44,'如何面对人际交往中的心机','你要跟对方交流：为什么要做这件事，我们的目标是什么，以及这件事对于你、对于他的好处和坏处，这些一定要讲明。','2025-2078',5,1702571484,1782480562);
INSERT INTO highlights VALUES('35138325_44_1398-1491','35138325',44,'如何面对人际交往中的心机','一壶开水的热能转化成动能，转化率只有百分之二十左右，甚至百分之十。你扪心自问，一周工作五天，每天工作八小时，有几个小时是在创造价值？休假时间一长，你惊奇地发现，公司没有你照样转，对不对？','1398-1491',5,1700912601,1782480562);
INSERT INTO highlights VALUES('35138325_44_840-939','35138325',44,'如何面对人际交往中的心机','为什么我对这个故事印象如此深刻？因为我在管理工作中，无数次发出类似的感叹：如果团队能够齐心协力做事，你会发现，似乎很弱的团队也能做出极其伟大的事，就仿佛一壶开水的力量，把一整头大骆驼从地面提到四楼。','840-939',5,1700912540,1782480562);
INSERT INTO highlights VALUES('35138325_42_3772-3850','35138325',42,'怎样做一个讨人喜欢的人','夸人，嘴甜一点，也招人喜欢。在职场里，总舍不得夸人的人，是很难招人喜欢的。诀窍是，找准别人真的很赞的地方，往死里夸。不见得话很多，但是要往死里夸，多夸几次。','3772-3850',5,1700884395,1782480562);
INSERT INTO highlights VALUES('35138325_42_2135-2176','35138325',42,'怎样做一个讨人喜欢的人','有一类不招人喜欢的人，在职场什么事都觉得难，一碰壁就走。有想法，没办法，不能成事。','2135-2176',5,1700884199,1782480562);
INSERT INTO highlights VALUES('35138325_42_2059-2078','35138325',42,'怎样做一个讨人喜欢的人','你聪明，但是我笃定；你机巧，但是我赤诚','2059-2078',5,1700884184,1782480562);
INSERT INTO highlights VALUES('35138325_42_1739-1777','35138325',42,'怎样做一个讨人喜欢的人','一条我从曾国藩和我自己的经验中体会出来的路：两“心”——一是诚心，二是虚心。','1739-1777',5,1700884098,1782480562);
INSERT INTO highlights VALUES('35138325_40_3314-3434','35138325',40,'如何设计晋升机制','小公司，也要想三年的战略是什么；一年的商业计划是什么；业绩如何评价；管理报告哪怕只有两项，应该长成什么样；也要有某种内审机制，能确保人、财、物的准确和合法；还要有经理人考评体系，哪怕团队只有二十人，也要选出最合格的人。简化，但是逻辑不能变。','3314-3434',5,1700883669,1782480562);
INSERT INTO highlights VALUES('35138325_40_1620-1672','35138325',40,'如何设计晋升机制','包括以下6个系统：战略规划体系、商业计划体系、业绩评价体系、管理报告体系、内部审计体系、经理人考评体系。','1620-1672',5,1700701579,1782480562);
INSERT INTO highlights VALUES('35138325_40_1561-1588','35138325',40,'如何设计晋升机制','这个“6S”，就是6个“System”，6个系统构成。','1561-1588',5,1700701573,1782480562);
INSERT INTO highlights VALUES('35138325_40_1217-1266','35138325',40,'如何设计晋升机制','以战略管控为核心，战略管控相对是一个更好的平衡，它不像运营管控管得那么细，又不像财务管控管得那么宽','1217-1266',5,1700701556,1782480562);
INSERT INTO highlights VALUES('35138325_40_692-764','35138325',40,'如何设计晋升机制','公司最重要的管理思路，无非围绕两个维度：一是管理，二是控制。不同的公司有不同的管控模式，可以分为三类：一是财务管控，二是战略管控，三是运营管控。','692-764',5,1700701513,1782480562);
INSERT INTO highlights VALUES('35138325_39_4490-4541','35138325',39,'如何在团队中用民主集中制达成共识','说到底，无论是领袖/CEO、副手／核心团队、群众，在民主集中制中要秉着八个字：“尽心尽力，尽职尽责”。','4490-4541',5,1700660837,1782480562);
INSERT INTO highlights VALUES('35138325_39_3589-3731','35138325',39,'如何在团队中用民主集中制达成共识','你有反对的责任，出发点并不是为了显得你有多牛、多智慧、多伟大，而是为了团队的共同利益、领导的利益、自身的利益。完全不想自己的利益，完全不顾自己的团队、自己的部门，不对。但把自身的利益永远搁在整个大团队利益之上，总是搁在领导利益之上，你作为副手，作为核心团队人员，你很有可能走不了太远。','3589-3731',5,1700660600,1782480562);
INSERT INTO highlights VALUES('35138325_39_3006-3039','35138325',39,'如何在团队中用民主集中制达成共识','无论你民主得多么充分，如果没有集中，没有决策，就不是一个好的团队。','3006-3039',5,1700660479,1782480562);
INSERT INTO highlights VALUES('35138325_39_2672-2694','35138325',39,'如何在团队中用民主集中制达成共识','好的民主，从来不简单，很考验参与者和领导者。','2672-2694',5,1700660413,1782480562);
INSERT INTO highlights VALUES('35138325_39_1580-1625','35138325',39,'如何在团队中用民主集中制达成共识','绝对集中、绝对民主，都可能有问题，所以才要有民主集中制，达成某种程度的平衡才是最好的方式。','1580-1625',5,1700582095,1782480562);
INSERT INTO highlights VALUES('35138325_39_871-906','35138325',39,'如何在团队中用民主集中制达成共识','有可能他百分之九十战略方向对，决策对；但也有可能剩下的百分之十，他错了','871-906',5,1700581946,1782480562);
INSERT INTO highlights VALUES('35138325_39_2150-2218','35138325',39,'如何在团队中用民主集中制达成共识','倾听，是把自己放空，把自己的想法先放在一边，听听别人在说什么，别人怎么看这个问题。倾听，是要把身子往前倾过去，把心放空，去听别人的意见。','2150-2218',5,1699067539,1782480562);
INSERT INTO highlights VALUES('35138325_38_2889-2971','35138325',38,'变革管理：以不变应万变','作为一个CEO，作为一个核心团队，心中有一个要达到的目标，为了达到这个战略目标，每年、每月、每周应该干什么，在干的过程中，需要培养哪些组织能力，需要培养哪些价值观。','2889-2971',5,1699062385,1782480562);
INSERT INTO highlights VALUES('35138325_37_3178-3214','35138325',37,'要利用“庸众”的无知','如果你是CEO，话一定要多，要让你的团队基本能够背出来你到底是怎么想的。','3178-3214',5,1698884486,1782480562);
INSERT INTO highlights VALUES('35138325_37_763-818','35138325',37,'要利用“庸众”的无知','庸众无知，是个事实。这个事实，常常令人悲哀，也常常被各种领袖人物利用。你不洗他们的脑子，别人也会洗他们的脑子。','763-818',1,1698810071,1782480562);
INSERT INTO highlights VALUES('35138325_37_668-762','35138325',37,'要利用“庸众”的无知','表面上这句话的意思是，群众无知，只会盲从。实际的意思是，一个好的领导，如果他能掌握时机，在合适的时机振臂一呼，就能够起到以一当十、以十当百、以百当千的作用，这就是精英的素质，也是领导的艺术','668-762',1,1698810062,1782480562);
INSERT INTO highlights VALUES('35138325_36_2450-2474','35138325',36,'如何倾听不同的意见','“全赖见多识广，熟思审处，方寸中有一定之权衡。”','2450-2474',5,1698236351,1782480562);
INSERT INTO highlights VALUES('35138325_36_394-456','35138325',36,'如何倾听不同的意见','做人不能只听夸的，维系关系不能只靠夸赞。不论恋爱，还是婚姻，甚至工作，需要平衡感，需要相互听到对方的声音，尤其是反对的声音。','394-456',5,1698232740,1782480562);
INSERT INTO highlights VALUES('35138325_35_6410-6438','35138325',35,'百分之九十九的人不会开会','不一定每件事都能做成，但是要做到件件有落实，事事有回应。','6410-6438',5,1698232728,1782480562);
INSERT INTO highlights VALUES('35138325_35_5944-6030','35138325',35,'百分之九十九的人不会开会',unistr('会后要做到两点：一个是Follow through，一个是Feedback。\u000a'),'5944-5982',5,1698232411,1782480562);
INSERT INTO highlights VALUES('35138325_35_5305-5350','35138325',35,'百分之九十九的人不会开会','公司给你工资，给你时间，让你参加一个会议，不是让你去喝水的，不是让你在笔记本上练硬笔书法的','5305-5350',5,1698232367,1782480562);
INSERT INTO highlights VALUES('35138325_35_5276-5303','35138325',35,'百分之九十九的人不会开会','反对的责任(Obligation to dissent','5276-5303',5,1698232361,1782480562);
INSERT INTO highlights VALUES('35138325_35_4527-4552','35138325',35,'百分之九十九的人不会开会','达成共识有很多小技巧，最重要的技巧就是民主集中制。','4527-4552',5,1698210463,1782480562);
INSERT INTO highlights VALUES('35138325_35_4242-4295','35138325',35,'百分之九十九的人不会开会','如果大家都进入话痨和情绪化的状态，特别是有很激烈的情绪状态，我的建议是停止会议。没有什么是睡觉不能解决的。','4242-4295',5,1698207909,1782480562);
INSERT INTO highlights VALUES('35138325_35_3154-3200','35138325',35,'百分之九十九的人不会开会','最后一个P是Pay off，就是这个会希望最后达成什么共识，或者完成什么决策、安排什么事情。','3154-3200',5,1698178153,1782480562);
INSERT INTO highlights VALUES('35138325_34_4918-4933','35138325',34,'怎样看待公司的规章制度','成事本身是很有诱惑力的一件事。','4918-4933',5,1698164794,1782480562);
INSERT INTO highlights VALUES('35138325_34_3387-3457','35138325',34,'怎样看待公司的规章制度','运营制度、财务制度、人事制度建立了之后，重要的是行胜于言。执行，执行，执行，不断执行，坚决执行已经制定好、大家已经同意的规则。','3387-3457',5,1698164648,1782480562);
INSERT INTO highlights VALUES('35138325_34_3263-3287','35138325',34,'怎样看待公司的规章制度','另一个维度是管理制度，特别是财务制度和人事制度。','3263-3287',5,1698164638,1782480562);
INSERT INTO highlights VALUES('35138325_34_3165-3178','35138325',34,'怎样看待公司的规章制度','公司的一个维度是运营制度。','3165-3178',5,1698164616,1782480562);
INSERT INTO highlights VALUES('35138325_34_726-762','35138325',34,'怎样看待公司的规章制度','制定并不完美但能够充分执行的规则，要远远比制定完美规则而不去执行好得多。','726-762',5,1698162979,1782480562);
INSERT INTO highlights VALUES('35138325_33_2836-2878','35138325',33,'保持团队锐气的五条秘籍','其实，说这些人佛系，是对佛系的误解，佛是乐观的、往前走的，只是能拿得起、放得下而已。','2836-2878',5,1698162165,1782480562);
INSERT INTO highlights VALUES('35138325_33_2576-2603','35138325',33,'保持团队锐气的五条秘籍','那种相对悲观的应该去做艺术、做研究，不要做商业，干不好','2576-2603',5,1698162138,1782480562);
INSERT INTO highlights VALUES('35138325_33_2540-2565','35138325',33,'保持团队锐气的五条秘籍','2.选择本性乐观、好胜的人加入团队。','2540-2558',5,1698162118,1782480562);
INSERT INTO highlights VALUES('35138325_33_1826-1872','35138325',33,'保持团队锐气的五条秘籍','但是长期用兵，长期让团队保持心气儿，是极难的。锐气暗损，想争胜的心慢慢地消损，最为兵家所忌。','1826-1872',5,1698162043,1782480562);
INSERT INTO highlights VALUES('35138325_33_1262-1299','35138325',33,'保持团队锐气的五条秘籍','国藩讲，打仗用兵，尽管打打杀杀复杂，如果只需要一种机巧，就是锐气源源不断。','1262-1299',5,1698161965,1782480562);
INSERT INTO highlights VALUES('35138325_33_608-734','35138325',33,'保持团队锐气的五条秘籍','成一件事，最需要的是什么？最怕的是什么？最后总结为三个必要条件：一是这件事你能干，你有能力去干；二是这件事让你干，政策、法规、大形势、体制、机制让你干；三是这件事你想干，你有动力去干，你有热情、激情去干。如果非要在这三点里拎出更重要的，还是你想不想干。','608-734',5,1698147900,1782480562);
INSERT INTO highlights VALUES('35138325_24_5988-6039','35138325',24,'什么是终极领导力','心理学研究表明，自责、后悔、惭愧是负能量等级最高的情绪，“只要想起一生中后悔的事，梅花就落满了南山”。','5988-6039',5,1698080737,1782480562);
INSERT INTO highlights VALUES('35138325_32_467-483','35138325',32,'如何避免团队油腻的结构化','如何避免成为一个油腻的中年猥琐男','467-483',5,1698073938,1782480562);
INSERT INTO highlights VALUES('35138325_31_4022-4056','35138325',31,'高级领导的关键点','战车被能干的小人们绑架，时间就会变成我们的敌人，翻车的风险与日俱增。','4022-4056',5,1698049809,1782480562);
INSERT INTO highlights VALUES('35138325_31_2605-2627','35138325',31,'高级领导的关键点','知人是要有天赋、要犯很多错误才能做好的一件事','2605-2627',5,1698049627,1782480562);
INSERT INTO highlights VALUES('35138325_31_1597-1674','35138325',31,'高级领导的关键点','他接着说：“故群誉群毁之所在，下走常穆然深念，不敢附和。”不参与别人对其他人的评论，一旦听到大家都夸一个人或骂一个人，他就不说话，默默地走过去，不敢附和。','1597-1674',5,1698049505,1782480562);
INSERT INTO highlights VALUES('35138325_31_1359-1382','35138325',31,'高级领导的关键点','天下没有一成不变的君子，也没有一成不变的小人。','1359-1382',5,1698049470,1782480562);
INSERT INTO highlights VALUES('35138325_31_888-927','35138325',31,'高级领导的关键点','知人很难，而明白事理这件事可以通过阅历，通过不断地做事培养见识，通过努力得到。','888-927',5,1698049391,1782480562);
INSERT INTO highlights VALUES('35138325_31_703-729','35138325',31,'高级领导的关键点','居高位的人，就是所谓的高级领导，最重要的是知人晓事。','703-729',5,1698049365,1782480562);
INSERT INTO highlights VALUES('35138325_30_3273-3330','35138325',30,'CEO的工作是什么','“老实和尚不老实”，这是我常说的、古龙小说里的一句话。貌似忠厚老实的人，其实内心鸡贼得很。生活中这样的人不在少数。','3273-3330',5,1698049253,1782480562);
INSERT INTO highlights VALUES('35138325_29_4865-4912','35138325',29,'如何成为中层干部','不贪财、不怕死、不惜力，就是一个合格的好干部，假以时日、假以时机，就很有可能成为一个高级干部。','4865-4912',5,1698046604,1782480562);
INSERT INTO highlights VALUES('35138325_28_5138-5218','35138325',28,'麦肯锡的信任公式',unistr('这就是麦肯锡的信任公式：\u000a信任＝（可信度×可靠度×可亲度）÷自私度'),'5138-5218',5,1698032779,1782480562);
INSERT INTO highlights VALUES('35138325_28_4566-4648','35138325',28,'麦肯锡的信任公式','前面三个“度”——可信度（这个人是不是专家）、可靠度（这人是不是能交活）、可亲度（这个人跟我是不是很舒服），是除号上边的被除数，它们是一个相乘关系，它们仨越大越好。','4566-4648',5,1698032722,1782480562);
INSERT INTO highlights VALUES('35138325_28_3177-3198','35138325',28,'麦肯锡的信任公式','信任＝（可信度×可靠度×可亲度）÷自私度。','3177-3198',5,1698031171,1782480562);
INSERT INTO highlights VALUES('35138325_28_2290-2376','35138325',28,'麦肯锡的信任公式','麦肯锡的生意模式，是一小撮极其聪明、教育背景极好的人，服务于大公司的CEO们，让大公司更大、更强，同时让这一小撮人解决商业问题的功力在极短的时间内迅速提高，并过上体面生活。','2290-2376',5,1698031011,1782480562);
INSERT INTO highlights VALUES('35138325_28_1211-1226','35138325',28,'麦肯锡的信任公式','二是君子之交淡如水，不必多见面','1211-1226',5,1698030839,1782480562);
INSERT INTO highlights VALUES('35138325_28_831-895','35138325',28,'麦肯锡的信任公式','中国古人有成功十要素：一命，二运，三风水，四积阴德，五读书，六名，七相，八敬神，九交贵人，十养生。提示注意“九交贵人，十养生”，','831-895',5,1698030798,1782480562);
INSERT INTO highlights VALUES('35138325_27_4372-4390','35138325',27,'如何制定团队激励政策','还是一定要相信学习能力和常识的力量。','4372-4390',5,1698030607,1782480562);
INSERT INTO highlights VALUES('35138325_27_3198-3237','35138325',27,'如何制定团队激励政策','特别是湘军后期，升官发财是他们重要的推进手段，很像某种风险投资，高风险、高回报','3198-3237',5,1698030178,1782480562);
INSERT INTO highlights VALUES('35138325_27_1914-2001','35138325',27,'如何制定团队激励政策','亚洲企业，特别是中国企业，相对要“温良恭俭让”一点。比如，愿景会定得更高远、宏大，但是目标没有那么具体，组织没有那么扁平，业绩反馈老板知道，但是自己的团队内部不是相对透明的。','1914-2001',5,1698029952,1782480562);
INSERT INTO highlights VALUES('35138325_27_1730-1745','35138325',27,'如何制定团队激励政策','第五件事，结果管理，形成闭环。','1730-1745',5,1698029916,1782480562);
INSERT INTO highlights VALUES('35138325_27_1531-1543','35138325',27,'如何制定团队激励政策','第四件事，要有业绩反馈。','1531-1543',5,1698029900,1782480562);
INSERT INTO highlights VALUES('35138325_27_1291-1327','35138325',27,'如何制定团队激励政策','第二件事，有非常切实具体的可以衡量，以及经常会调整的近期、中期、长期目标','1291-1327',5,1698029824,1782480562);
INSERT INTO highlights VALUES('35138325_27_1400-1447','35138325',27,'如何制定团队激励政策','第三件事，组织架构一定要相对扁平，而且组织架构中的核心，要有明确的责权利（责任、权力、利益）。','1400-1447',5,1698029822,1782480562);
INSERT INTO highlights VALUES('35138325_27_1219-1262','35138325',27,'如何制定团队激励政策','如何能够长久地为人类和地球创造价值、财富、服务和产品，好的企业通常都会立住这样的愿景。','1219-1262',5,1698029822,1782480562);
INSERT INTO highlights VALUES('35138325_27_1048-1076','35138325',27,'如何制定团队激励政策','能在《财富》五百强中长盛不衰的企业，有五件事一定要做好。','1048-1076',5,1698029781,1782480562);
INSERT INTO highlights VALUES('35138325_27_1127-1162','35138325',27,'如何制定团队激励政策','第一件事，要志存高远，要有一个愿景，这个愿景是企业存在的价值和最终目的','1127-1162',5,1698029774,1782480562);
INSERT INTO highlights VALUES('35138325_26_4418-4480','35138325',26,'带团队的四条铁律','带团队的四条铁律：“勤”字为先；该放手的时候放手；维持好势能，不要让团队势穷力竭；最后不仅用钱激励团队，还要讲理想、讲精神。','4418-4480',5,1698029615,1782480562);
INSERT INTO highlights VALUES('35138325_26_3658-3715','35138325',26,'带团队的四条铁律','所以，势穷力竭是用兵大忌，你本来手上有一把好牌，但是势头没了，团队干不动了，本来已经有战略上的胜算，但是痛失好局。','3658-3715',5,1698029534,1782480562);
INSERT INTO highlights VALUES('35138325_26_3480-3486','35138325',26,'带团队的四条铁律','力，是指实战','3480-3486',5,1698029508,1782480562);
INSERT INTO highlights VALUES('35138325_26_3185-3203','35138325',26,'带团队的四条铁律','曾国藩说：“用兵之道，最忌势穷力竭。','3185-3203',5,1698029503,1782480562);
INSERT INTO highlights VALUES('35138325_26_3150-3155','35138325',26,'带团队的四条铁律','第三，势力','3150-3155',5,1698029501,1782480562);
INSERT INTO highlights VALUES('35138325_26_2858-2887','35138325',26,'带团队的四条铁律','三是如果干部因为这个坐牢，社员保证把他们的小孩养活到十八岁','2858-2887',5,1698029390,1782480562);
INSERT INTO highlights VALUES('35138325_26_2048-2115','35138325',26,'带团队的四条铁律','勿意，勿必，勿固，勿我，别总说我以为如何如何，别总认为必须如何如何，别总强调过去如何如何，别总维护自己，别总把自己放在最核心和最高处。','2048-2115',5,1698029226,1782480562);
INSERT INTO highlights VALUES('35138325_26_1726-1798','35138325',26,'带团队的四条铁律','执政者并不是管得很细，并不是要事事躬亲，他们最要做到的是带领老百姓向好的方向发展。“与人为善”的本义是带领老百姓向好的方向发展，不是说对人要善。','1726-1798',5,1698029134,1782480562);
INSERT INTO highlights VALUES('35138325_26_678-735','35138325',26,'带团队的四条铁律','“未有平日不早起，而临敌忽能早起者；未有平日不习劳，而临敌忽能习劳者；未有平日不忍饥耐寒，而临敌忽能忍饥耐寒者。”','678-735',5,1697957954,1782480562);
INSERT INTO highlights VALUES('35138325_24_5440-5497','35138325',24,'什么是终极领导力','“有时关切是问，有时关切是不问。”有时候不做比做什么都强。这就是“不着急”，对时间的态度，遵从万事万物的发展规律。','5440-5497',5,1697908394,1782480562);
INSERT INTO highlights VALUES('35138325_24_5094-5202','35138325',24,'什么是终极领导力',unistr('“不着急”，说的是对时间的态度。\u000a“不害怕”，说的是对结果的态度。\u000a“不要脸”，说的是对别人评论的态度。'),'5094-5202',5,1697908355,1782480562);
INSERT INTO highlights VALUES('35138325_24_4864-4981','35138325',24,'什么是终极领导力',unistr('第四，冯唐九字真言\u000a痛定思痛，我自己写下了九字真言：“不着急，不害怕，不要脸。”\u000a“不着急，不害怕，不要脸”意味着什么？'),'4864-4981',5,1697908328,1782480562);
INSERT INTO highlights VALUES('35138325_24_4411-4480','35138325',24,'什么是终极领导力','随着年岁越来越大，你会发现如果总这么做事，你在关键时刻可能已经没力气挺上去了，因为你太多的精力、太多的能量，在过程中已经被充分地消耗掉了。','4411-4480',5,1697908288,1782480562);
INSERT INTO highlights VALUES('35138325_24_3843-3904','35138325',24,'什么是终极领导力','天下的事，不如人意的经常十件事里有八件或九件，你总要坚忍耐烦，不避重活，不被其他人各种不好的说法所打扰，坚持住才可能有成就','3843-3904',5,1697908208,1782480562);
INSERT INTO highlights VALUES('35138325_24_3804-3842','35138325',24,'什么是终极领导力','夫天下之事，其不如人意者固十常八九，总在能坚忍耐烦，劳怨不避，乃能期于有成。','3804-3842',5,1697908197,1782480562);
INSERT INTO highlights VALUES('35138325_24_3692-3718','35138325',24,'什么是终极领导力','曾国藩的“大处着眼，小处着手；群居守口，独居守心”。','3692-3718',5,1697908171,1782480562);
INSERT INTO highlights VALUES('35138325_24_2902-2972','35138325',24,'什么是终极领导力','在公司生死存亡的危急时刻，领导者要知道，只有他自己才是可靠的，才是能靠得住的。这要求他亲自上阵，亲力亲为，自己指挥决胜于战场的瞬息变化之间。','2902-2972',5,1697908018,1782480562);
INSERT INTO highlights VALUES('35138325_24_2744-2761','35138325',24,'什么是终极领导力','曾国藩的意思是，团队其实也靠不住。','2744-2761',5,1697908002,1782480562);
INSERT INTO highlights VALUES('35138325_24_2441-2464','35138325',24,'什么是终极领导力','凡危急之时，只有在己者靠得住，其在人者皆不可靠','2441-2464',5,1697907969,1782480562);
INSERT INTO highlights VALUES('35138325_24_984-1105','35138325',24,'什么是终极领导力',unistr('所以能否成事，能否多成事，能否持续多成事，是我眼中领导力的金标准。\u000a那么，领导力的构成是什么？这些构成有没有先后顺序？如何练就？都是公说公有理，婆说婆有理。我谈谈我的看法，以及心路历程。'),'984-1105',5,1697901517,1782480562);
INSERT INTO highlights VALUES('35138325_23_5595-5616','35138325',23,'人人都该懂战略','我没见过，干不了小事，但是能干成大事的人。','5595-5616',5,1697901414,1782480562);
INSERT INTO highlights VALUES('35138325_23_3460-3545','35138325',23,'人人都该懂战略','有一个很好的工具，能帮助大家在大尺度时间、大尺度空间去思考，就是特别简单的“3C”。第一个C是Company，第二个C是Competitor，第三个C是Customer。','3460-3545',5,1697900917,1782480562);
INSERT INTO highlights VALUES('35138325_23_1620-1638','35138325',23,'人人都该懂战略','第三个核心词：合理性。','1620-1631',5,1697900732,1782480562);
INSERT INTO highlights VALUES('35138325_23_1395-1413','35138325',23,'人人都该懂战略','第二个核心词：系统性。','1395-1406',5,1697884488,1782480562);
INSERT INTO highlights VALUES('35138325_23_1271-1290','35138325',23,'人人都该懂战略','第一个核心词：行动方案。','1271-1283',5,1697884362,1782480562);
INSERT INTO highlights VALUES('35138325_20_1529-1608','35138325',20,'分清欲望和志向','真正的猛人，求的是千古文章，求的是宇宙太平，求的是洞察人性，求的是创造天地至美，“为天地立心，为生民立命，为往圣继绝学，为万世开太平”，这些是志向，不是欲望。','1529-1608',5,1697733951,1782480562);
INSERT INTO highlights VALUES('35138325_20_667-816','35138325',20,'分清欲望和志向',unistr('如何管理欲望，在我看来，分三点。\u000a第一，如何管理欲望\u000a1.尊重欲望，尊重自己的好胜心，这是你的能量之源。'),'667-816',5,1697733868,1782480562);
INSERT INTO highlights VALUES('35138325_20_1063-1086','35138325',20,'分清欲望和志向','2.警惕自己的好胜心，它很可能是把“双刃剑”。','1063-1086',5,1697733862,1782480562);
INSERT INTO highlights VALUES('35138325_20_891-913','35138325',20,'分清欲望和志向','那些病态“佛系”的人，就是一有了胜负心就砍掉','891-913',5,1697733842,1782480562);
INSERT INTO highlights VALUES('35138325_20_440-493','35138325',20,'分清欲望和志向','曾国藩说“降伏此心”，把自己的心按下去，非常难；但如果没有这颗心，“柔靡不能成一事”，人太软，就不能成事。','440-493',5,1697590347,1782480562);
INSERT INTO highlights VALUES('35138325_19_5894-5957','35138325',19,'怎么通过拯救睡眠实现人生逆袭','换一个角度，如果事情没有做得很完美，有反对的声音，有些噪声，不要太搭理它们。“关你屁事，关我屁事”，内心强大到浑蛋，非常重要。','5894-5957',5,1697590309,1782480562);
INSERT INTO highlights VALUES('35138325_19_4320-4376','35138325',19,'怎么通过拯救睡眠实现人生逆袭','因为往往呼吸不顺畅才造成打呼噜，呼吸不顺畅，进氧和排出二氧化碳的过程就没那么有效，长此以往睡眠质量就会受到影响。','4320-4376',5,1697590212,1782480562);
INSERT INTO highlights VALUES('35138325_19_2142-2172','35138325',19,'怎么通过拯救睡眠实现人生逆袭','如果你睡醒之后有精神干事，那这样的睡眠就是一个高质量的睡眠。','2142-2172',5,1697589797,1782480562);
INSERT INTO highlights VALUES('35138325_19_723-765','35138325',19,'怎么通过拯救睡眠实现人生逆袭','“冯三点”：第一，睡眠为什么重要；第二，什么是高质量的睡眠；第三，如何提高睡眠质量。','723-765',5,1697547939,1782480562);
INSERT INTO highlights VALUES('35138325_18_887-939','35138325',18,'以笨拙为本分，求仁得仁','第二个核心词是“勤”。“以勤补之”，说的是以勤劳去补笨拙，而非以投机取巧去补笨拙，以跟风随潮流去补笨拙。','887-939',5,1697501686,1782480562);
INSERT INTO highlights VALUES('35138325_18_765-766','35138325',18,'以笨拙为本分，求仁得仁','认','765-766',5,1697458361,1782480562);
INSERT INTO highlights VALUES('35138325_17_1762-1937','35138325',17,'摒弃“身心灵”，在现实中“修行”','如何在现实中修行？珍惜每一个不舒服和难受。在每一个不舒服、难受的时候，跳出自我，把自己的肉身和灵魂，当成人类中的一个，当成另一个他人。你想一想，观察一下，这个人到底怎么了？这个称为“我”的东西，他感受到了什么？他为什么不舒服、为什么难受？我们改变不了基因、原生家庭、环境、教育、遭遇，但我们可以从任何一刻开始觉察“我”这个人到底怎么了。','1762-1937',1,1697211133,1782480562);
INSERT INTO highlights VALUES('35138325_17_886-898','35138325',17,'摒弃“身心灵”，在现实中“修行”','CEO很大的责任是做政委','886-898',1,1697211058,1782480562);
INSERT INTO highlights VALUES('35138325_16_1387-1426','35138325',16,'选择，不仅只是断舍离','安于“规”，一生安稳；创新“轨”，一生颠簸。同样的一生，可能是截然不同的活法。','1387-1426',1,1697210730,1782480562);
INSERT INTO highlights VALUES('35138325_16_1040-1106','35138325',16,'选择，不仅只是断舍离','从表面来看，选择人才，要看一个人的志向，“卑者”和“高者”志向不同，结果也不同。但实际上再看一层，这句话的核心字在于“规”和“轨”。','1040-1106',1,1697210684,1782480562);
INSERT INTO highlights VALUES('35138325_16_550-560','35138325',16,'选择，不仅只是断舍离','人才高下，视其志趣。','550-560',1,1697210610,1782480562);
INSERT INTO highlights VALUES('35138325_15_4424-4515','35138325',15,'有时候“不努力”是种正确战略','3.获得某个细分领域最多的知识和最高的智慧。在你竖旗、立山头之前，你在这个细分领域多积累知识和智慧。不要太早就说自己已经具有了，多扪心自问，在你试图称王的领域，你的知识和智慧够不够？','4424-4515',1,1697210589,1782480562);
INSERT INTO highlights VALUES('35138325_15_4340-4395','35138325',15,'有时候“不努力”是种正确战略','2.能打仗、能力战、能快跑的时候，请力战、快跑、成事。你要具备能够力战、快跑的能力和精力。这是可以努力的地方。','4340-4395',1,1697210580,1782480562);
INSERT INTO highlights VALUES('35138325_15_4263-4311','35138325',15,'有时候“不努力”是种正确战略','1.你可以不屠龙，但不能不磨剑，你要时刻准备着你的时机到来。你可以把努力集中到去磨剑、长本事上。','4263-4311',1,1697210576,1782480562);
INSERT INTO highlights VALUES('35138325_15_4579-4634','35138325',15,'有时候“不努力”是种正确战略','练就一身本事，能成大事时成大事，不能成大事时继续躲在某处练成事的本事。得志行天下，不得志独善其身，淡定而从容。','4579-4634',1,1697210568,1782480562);
INSERT INTO highlights VALUES('35138325_13_5206-5267','35138325',13,'如何战胜自己，战胜逆境','“中庸”是一种平衡，如果在这种日子里，在这种无常里，能够平衡，能够立住，浪就会让你往前走，日子就会往前，你就会迎来好时光。','5206-5267',1,1697209926,1782480562);
INSERT INTO highlights VALUES('35138325_11_3497-3728','35138325',11,'掌控情绪',unistr('哪怕你天天微笑，天天看似淡定，但是做事就会有压力。那如何缓解压力，实际上是如何管理你的愤怒。\u000a如何克服愤怒呢？\u000a1.要把愤怒当成一个要克服的难题，心跟上了，身体也就快了。\u000a2.要经常告诫自己，要能行能藏。'),'3497-3728',1,1697088750,1782480562);
INSERT INTO highlights VALUES('35138325_10_2189-2208','35138325',10,'做自己熟悉的行业','1.先知道一百个关键词。','2189-2201',1,1697083364,1782480562);
INSERT INTO highlights VALUES('35138325_10_725-742','35138325',10,'做自己熟悉的行业','“客气先盛而后衰，主气先微而后壮”','725-742',1,1697083250,1782480562);
