INSERT INTO highlights VALUES('35138325_9_3141-3180','35138325',9,'做一个真猛人','“恒”是在对事上，坚持投入时间和精力，几年甚至几十年如一日，不求速效，不着急。','3141-3180',1,1697083143,1782480562);
INSERT INTO highlights VALUES('35138325_9_3077-3103','35138325',9,'做一个真猛人','“敬”是敬天悯人，尊重常识和积累，尊重事，不走捷径。','3077-3103',1,1697083137,1782480562);
INSERT INTO highlights VALUES('35138325_9_2117-2141','35138325',9,'做一个真猛人','3.真的猛人和假的猛人追求不一样。','2117-2134',1,1697083039,1782480562);
INSERT INTO highlights VALUES('35138325_9_1907-1940','35138325',9,'做一个真猛人','2.从事情来判断。真的猛人，他的凶猛和决绝是对事的。','1907-1933',1,1697083019,1782480562);
INSERT INTO highlights VALUES('35138325_8_2138-2246','35138325',8,'如何平衡工作和生活',unistr('第二，有所专\u000a有所专，有两方面。\u000a1.专心，该酒时酒，该花时花。'),'2138-2246',5,1696953655,1782480562);
INSERT INTO highlights VALUES('35138325_8_3109-3136','35138325',8,'如何平衡工作和生活','2.专业，培养一个爱好，把这个爱好做到专业，至少半专业','3109-3136',5,1696953650,1782480562);
INSERT INTO highlights VALUES('35138325_8_2756-2769','35138325',8,'如何平衡工作和生活','临事静对猛虎，事了闲看落花','2756-2769',5,1696953590,1782480562);
INSERT INTO highlights VALUES('35138325_8_642-670','35138325',8,'如何平衡工作和生活','我至少有两件事情，二十年来一直在做：一是工作，二是写作。','642-670',5,1696953375,1782480562);
INSERT INTO highlights VALUES('35138325_8_448-490','35138325',8,'如何平衡工作和生活','仓央嘉措有首名诗：“曾虑多情损梵行，入山又恐别倾城。世间安得双全法，不负如来不负卿。','448-490',5,1696953359,1782480562);
INSERT INTO highlights VALUES('35138325_7_3135-3181','35138325',7,'成大事无捷径','曾国藩说“困时切莫间断，熬过此关，便可少进”，之后“再进再困，再熬再奋，自有亨通精进之日”。','3135-3181',5,1696953240,1782480562);
INSERT INTO highlights VALUES('35138325_7_2830-2846','35138325',7,'成大事无捷径','困时切莫间断，熬过此关，便可少进','2830-2846',5,1696953206,1782480562);
INSERT INTO highlights VALUES('35138325_13_3999-4057','35138325',13,'如何战胜自己，战胜逆境','比如战胜拖延症。战胜拖延症的一个小技巧就是微型改进。假如不喜欢早起，那你不见得一定要明天六点起，而是可以微型改进。第','3999-4057',5,1691049788,1782480562);
INSERT INTO highlights VALUES('35138325_13_3269-3336','35138325',13,'如何战胜自己，战胜逆境','以前我总是信誓旦旦地说：“时间是一个人唯一真正拥有的财富。我的余生只给三类人花时间——真好玩的人，真好看的人，真的又好看又好玩的人。”','3269-3336',5,1690988363,1782480562);
INSERT INTO highlights VALUES('35138325_13_609-622','35138325',13,'如何战胜自己，战胜逆境','看脚下，不断行，莫存顺逆。','609-622',5,1690986328,1782480562);
INSERT INTO highlights VALUES('35138325_13_523-557','35138325',13,'如何战胜自己，战胜逆境','你有可能听过我的九字真言：不着急，不害怕，不要脸。这是对于顺境而言。','523-557',5,1690986298,1782480562);
INSERT INTO highlights VALUES('35138325_12_3790-3820','35138325',12,'如何对待妒忌和贪婪','我为什么好胜，是因为我实在不想把这么美好的世界留给那帮傻子。','3790-3820',5,1690986244,1782480562);
INSERT INTO highlights VALUES('35138325_12_3554-3614','35138325',12,'如何对待妒忌和贪婪','保证妒忌是不害人的、有度的，不是过分的。成事从来难，做个成事的人，一生成就无数更难，其中一个大大的关口，就是妒忌和贪婪。','3554-3614',5,1690986218,1782480562);
INSERT INTO highlights VALUES('35138325_12_3191-3246','35138325',12,'如何对待妒忌和贪婪','既然你都会妒忌，会贪婪，那对于别人的妒忌和贪婪之心，特别是针对你的，一笑置之，不加批判，因为换了你也可能这样。','3191-3246',5,1690986150,1782480562);
INSERT INTO highlights VALUES('35138325_12_1831-1888','35138325',12,'如何对待妒忌和贪婪','有句老话：“笑人无，恨人有。”如果一个人不停地得到，得到最好的名、最好的钱、最好的色，别人会羡慕嫉妒恨，那怎么办？','1831-1888',5,1690985976,1782480562);
INSERT INTO highlights VALUES('35138325_11_2780-2818','35138325',11,'掌控情绪','兄弟如果想活得长，也要把你的怒气当成毒蛇，拿出壮士断腕的勇气，斩除你的怒火。','2780-2818',5,1690985684,1782480562);
INSERT INTO highlights VALUES('35138325_11_389-433','35138325',11,'掌控情绪','如果你不做事，你会发现，最烦你的是你妈，她会说：“你干吗不干事呢？”“你整天躺在床上！”','389-433',5,1690985343,1782480562);
INSERT INTO highlights VALUES('35138325_10_2368-2397','35138325',10,'做自己熟悉的行业','明白了一百个关键词之后，你会发现，你跟专家的距离迅速缩短。','2368-2397',5,1690985130,1782480562);
INSERT INTO highlights VALUES('35138325_9_3791-3829','35138325',9,'做一个真猛人','对自己真狠，长期对自己真狠，才能成为一个真的猛人，才能在职场上获得真的自由。','3791-3829',5,1690984955,1782480562);
INSERT INTO highlights VALUES('35138325_9_2768-2805','35138325',9,'做一个真猛人','敬字、恒字二端，是彻始彻终工夫。鄙人生平欠此二字，至今老而无成，深自悔憾。','2768-2805',5,1690984819,1782480562);
INSERT INTO highlights VALUES('35138325_9_1520-1549','35138325',9,'做一个真猛人','1.看他的凶猛、他的强是对自己，还是对他人。','1520-1542',5,1690980261,1782480562);
INSERT INTO highlights VALUES('35138325_9_1318-1399','35138325',9,'做一个真猛人','“舍此而求以客气胜人，是刚愎而已矣。”如果你不是对自己狠，而是对别人严、对别人狠，自己无论好坏都是好，这种是刚愎。“二者相似，而其流相去霄壤，不可不察，不可不谨。','1318-1399',5,1690980109,1782480562);
INSERT INTO highlights VALUES('35138325_9_1198-1289','35138325',9,'做一个真猛人','强迫自己一直老老实实干活，多干活，不知疲倦地去干活，这是真的强。“不惯有恒，而强之贞恒，即毅也。”不习惯去做某件很难的事，但是强迫自己经常去干比较难或自己不喜欢干的事，这是真的毅力。','1198-1289',5,1690980089,1782480562);
INSERT INTO highlights VALUES('35138325_9_750-782','35138325',9,'做一个真猛人','就怕别人觉得你是一个挺软的人，实际上也真的软，有些事就做不成了。','750-782',5,1690979983,1782480562);
INSERT INTO highlights VALUES('35138325_8_5408-5544','35138325',8,'如何平衡工作和生活','曾国藩实际上说的是两种态度：做事要勇猛精进，处世要豁达恬淡。这也是他一直强调的“刚柔相济”，用平常心处世，用进取心做事。手上有刀，心里有佛；脚下有闹市，心中有山水。一个易行的方式是：上班你就埋头做事，下班埋头文艺，开会杀伐决断，然后去博物馆看美好的书画、器物，养眼、养心。','5408-5544',5,1690979387,1782480562);
INSERT INTO highlights VALUES('35138325_8_4587-4620','35138325',8,'如何平衡工作和生活','你可以把生活中的某种爱好，变成可真正获利的途径，然后理所当然地追逐','4587-4620',5,1690979285,1782480562);
INSERT INTO highlights VALUES('35138325_8_4467-4485','35138325',8,'如何平衡工作和生活','有所规划，多做计划，比眼前抓瞎要强。','4467-4485',5,1690979271,1782480562);
INSERT INTO highlights VALUES('35138325_8_3006-3061','35138325',8,'如何平衡工作和生活','为了自己不疯，应该逼着自己换换频道，去做跟工作不一样的事。去看看世界，谈谈恋爱，喝喝茶，焚焚香，看看书，等等。','3006-3061',5,1690978902,1782480562);
INSERT INTO highlights VALUES('35138325_8_2921-2977','35138325',8,'如何平衡工作和生活','这就是“loser”（失败者），该正经、该集中心力的时候集中不了心力，该放松的时候反而放松不了，这是成事的大忌。','2921-2977',5,1690978890,1782480562);
INSERT INTO highlights VALUES('35138325_8_1456-1472','35138325',8,'如何平衡工作和生活','没时间睡觉怎么办？用游泳代替睡眠','1456-1472',5,1690978694,1782480562);
INSERT INTO highlights VALUES('35138325_8_985-1037','35138325',8,'如何平衡工作和生活','我把我能够工作、生活两不误的最重要的秘诀教给大家，四个“有所”：一有所逼，二有所专，三有所规，四有所贪。','985-1037',5,1690978623,1782480562);
INSERT INTO highlights VALUES('35138325_8_974-983','35138325',8,'如何平衡工作和生活','手里有刀，心中有佛','974-983',5,1690978615,1782480562);
INSERT INTO highlights VALUES('35138325_7_3517-3577','35138325',7,'成大事无捷径','但在这个过程中，应该是痛苦比快乐多，特别是在早期，在你掌握一定的技能、技巧和能够游刃有余之前，想谈快乐学习，基本是扯淡。','3517-3577',5,1690978382,1782480562);
INSERT INTO highlights VALUES('35138325_7_1927-2039','35138325',7,'成大事无捷径',unistr('3.走捷径，容易受骗，被盛名所累。\u000a除非你是个别绝世天才，否则趁早成名了，很有可能不得不“端着”，为所谓的盛名所累。我们最怕的、最累的一件事，是德不配位。'),'1927-2039',5,1690978138,1782480562);
INSERT INTO highlights VALUES('35138325_7_613-638','35138325',7,'成大事无捷径','1.积累的时候，如果揠苗助长，容易伤身、容易伤心。','613-638',5,1690977983,1782480562);
INSERT INTO highlights VALUES('35138325_6_3953-3994','35138325',6,'用好你的天赋','3.你做出的东西有没有自己的风格，有没有相当多的人愿意自掏腰包去买。','3953-3987',5,1690977864,1782480562);
INSERT INTO highlights VALUES('35138325_6_3404-3436','35138325',6,'用好你的天赋','2.你偷偷摸摸坚持做这些事的时候，有快感和满足感。','3404-3429',5,1690977468,1782480562);
INSERT INTO highlights VALUES('35138325_6_3182-3199','35138325',6,'用好你的天赋','1.虽千万人吾往矣。','3182-3192',5,1690977451,1782480562);
INSERT INTO highlights VALUES('35138325_6_2531-2570','35138325',6,'用好你的天赋','第一点说了，没有天赋你也能过得挺好，但是过得挺好不意味着你应该否认天赋的存在。','2531-2570',5,1690977332,1782480562);
INSERT INTO highlights VALUES('35138325_6_1893-1958','35138325',6,'用好你的天赋','MBA只读两年，我学了六门财务课——金融会计、成本会计、税法、财务报表分析、企业金融、中级会计，占了我MBA课程的接近百分之四十。','1893-1958',5,1690977220,1782480562);
INSERT INTO highlights VALUES('35138325_6_826-870','35138325',6,'用好你的天赋','举一个曾国藩的例子，他说：“人生惟有常是第一美德。”人生的第一美德，是你能坚持做一件事。','826-870',5,1690976812,1782480562);
INSERT INTO highlights VALUES('35138325_6_772-797','35138325',6,'用好你的天赋','简单地说，就是坚持，没天赋也能活，甚至能活得挺好。','772-797',5,1690976801,1782480562);
INSERT INTO highlights VALUES('35138325_6_716-771','35138325',6,'用好你的天赋','我们经常会有一个巨大的困扰：这件事我必须做，但是我真的没有天赋把它做好，怎么办？两个字解决这个问题——“有常”','716-771',5,1690976797,1782480562);
INSERT INTO highlights VALUES('35138325_5_4363-4406','35138325',5,'如何管理自我','完全控制怒气容易变成“弱鸡”，但如果张牙舞爪去追求每一个欲望，你会发现自己离死不远了。','4363-4406',5,1690976678,1782480562);
INSERT INTO highlights VALUES('35138325_5_4053-4079','35138325',5,'如何管理自我','一是节制欲望，不要向外袒露；二是自立自强，强在内心。','4053-4079',5,1690976229,1782480562);
INSERT INTO highlights VALUES('35138325_5_3687-3698','35138325',5,'如何管理自我','至于倔强二字，却不可少','3687-3698',5,1690976185,1782480562);
INSERT INTO highlights VALUES('35138325_5_3350-3425','35138325',5,'如何管理自我','古今多少豪杰，都会遇上欲望这一关，不只是我跟你是这样，怎么办呢？“稍稍遏抑”，不是全杀掉，全杀掉可能你就没有动力干其他事了，要遏制，不能让它过分强烈。','3350-3425',5,1690976080,1782480562);
INSERT INTO highlights VALUES('35138325_5_3246-3255','35138325',5,'如何管理自我','强自禁制，降伏此心','3246-3255',5,1690975965,1782480562);
INSERT INTO highlights VALUES('35138325_5_1863-1902','35138325',5,'如何管理自我','不是求新，而是与传统衔接，才是所谓的正路，血战古人才是真的汉子，才是真的前卫。','1863-1902',5,1690975757,1782480562);
INSERT INTO highlights VALUES('35138325_5_635-673','35138325',5,'如何管理自我','整天赶时髦，你会发现你得到的欢喜，是没见识的欢喜，重要的那部分自我却损失掉了','635-673',5,1690974665,1782480562);
INSERT INTO highlights VALUES('35138325_5_502-517','35138325',5,'如何管理自我','我想说一个核心的理念，就是自在','502-517',5,1690974614,1782480562);
INSERT INTO highlights VALUES('316675_23_5859-5913','316675',55,'先说出你自己的错误',unistr('所以要改变一个人的意志，而不激起他的反感，第三项规则是： \u000a    在批评对方之前，不妨先谈谈你自己的错误。'),'2656-2733',NULL,1675144473,1782480564);
INSERT INTO highlights VALUES('316675_23_4043-4088','316675',54,'如何批评才不致引起反感',unistr('所以要改变人们的意志，而不引起对方的反感，第二项规则是： \u000a    间接地指出人们的过错。'),'1625-1693',NULL,1675144238,1782480564);
INSERT INTO highlights VALUES('316675_23_3929-3953','316675',54,'如何批评才不致引起反感','我们要劝阻一件事，一定牢记要永远躲开正面的批评。','1488-1512',NULL,1675144225,1782480564);
INSERT INTO highlights VALUES('316675_23_2953-3000','316675',53,'选好开始批评的方法',unistr('不使对方难堪、反感，而改变一个人的意志，第一项规则是： \u000a    用称赞和真诚的欣赏作开始。 '),'4029-4098',NULL,1674670354,1782480564);
INSERT INTO highlights VALUES('316675_23_248-285','316675',53,'选好开始批评的方法','当我们听到别人对我们的称赞后，如果再听到其他不愉快的话，就比较容易接受了。','692-729',NULL,1674640943,1782480564);
INSERT INTO highlights VALUES('316675_23_0-9','316675',53,'选好开始批评的方法','选好开始批评的方法','374-383',NULL,1674640813,1782480564);
INSERT INTO highlights VALUES('316675_16_40554-40613','316675',51,'当你无计可施时，就试试这个吧','菲司顿橡皮公司创办人菲司顿曾这样说过：“别以为用高额的薪金就可以聚集人才替我工作。只有竞争，才能发挥他们的工作效能。”','2444-2503',NULL,1674640798,1782480564);
INSERT INTO highlights VALUES('316675_16_39735-39769','316675',51,'当你无计可施时，就试试这个吧','争胜的欲望加上挑战的心理，对一个有血气的人来说，是一种最有效的激励。','1395-1429',NULL,1674640664,1782480564);
INSERT INTO highlights VALUES('316675_16_38985-39008','316675',50,'实行、推进，别停顿下来',unistr('第十一项规则是： \u000a    使你的意念戏剧化。'),'2354-2400',NULL,1674640528,1782480564);
INSERT INTO highlights VALUES('316675_16_37420-37432','316675',50,'实行、推进，别停顿下来','实行、推进，别停顿下来 ','374-385',NULL,1674625048,1782480564);
INSERT INTO highlights VALUES('316675_16_37352-37413','316675',49,'吸引所有人的魅力',unistr('所以，如果你要获得人们对你的赞同的话，在一般情形上，遵守第十项规则，是一件很好的事，那是： \u000a    激发人们更高尚的动机'),'4544-4628',NULL,1674625043,1782480564);
INSERT INTO highlights VALUES('316675_16_37296-37345','316675',49,'吸引所有人的魅力','如果你使他感觉到，你认为他是那么的诚实、公道、正直，大多数时候，他也会给你有像你所给他的同样反应。','4465-4514',NULL,1674625038,1782480564);
