INSERT INTO highlights VALUES('316675_16_28522-28578','316675',47,'一个创造奇迹的公式','为什么这人有那样的思想和行动，一定有他的理由。我们探求出那个隐藏着的理由来，对他的行动、人格就可以很清楚地了解。','518-574',NULL,1674323048,1782480564);
