INSERT INTO highlights VALUES('316675_16_24375-24481','316675',45,'处理一个抱怨者的安全手法','我们应该谦逊，因为你我都没有什么了不起，你我都要成为过去，百年之后我们都将为人所遗忘。生命是短促的，别把我们不值一提的成就作为谈话的资料，令人听了厌烦。我们要鼓励别人多说话。仔细想一想，你实在没有什么可以夸耀的。','4124-4230',NULL,1674321960,1782480564);
INSERT INTO highlights VALUES('316675_16_24246-24292','316675',45,'处理一个抱怨者的安全手法','别让我们表现出太多的成就，我们要虚怀若谷、处处谦虚，这样会永远使人喜欢你，谁都愿意跟你接近。','3945-3991',NULL,1674321939,1782480564);
INSERT INTO highlights VALUES('316675_16_24213-24236','316675',45,'处理一个抱怨者的安全手法','有些朋友看你遭遇到困难，比看你成功或许更为满意','3889-3912',NULL,1674321931,1782480564);
INSERT INTO highlights VALUES('316675_16_24159-24204','316675',45,'处理一个抱怨者的安全手法','德国人有句俗语，那是：“当我们所猜妒的人，发生一桩不幸的事时，会使我们有一种恶意的快感。”','3812-3857',NULL,1674321908,1782480564);
