INSERT INTO highlights VALUES('316675_16_21467-21508','316675',44,'苏格拉底的秘密',unistr('如果你要获得人们对你的同意，第五项规则是： \u000a    使对方很快地回答“是！是！”'),'4130-4194',NULL,1674321335,1782480564);
INSERT INTO highlights VALUES('316675_16_21389-21397','316675',44,'苏格拉底的秘密','“轻履者行远。”','4006-4014',NULL,1674321261,1782480564);
INSERT INTO highlights VALUES('316675_16_21176-21219','316675',44,'苏格拉底的秘密','他的处世技巧，现在被称为“苏格拉底辩证法”，就是以“是，是，”作为他唯一的反应观点。 ','3724-3766',NULL,1674321214,1782480564);
INSERT INTO highlights VALUES('316675_16_18868-18898','316675',44,'苏格拉底的秘密','当某人说出’不‘字后，为了自己人格的尊严，他就不得不坚持到底','636-666',NULL,1674318217,1782480564);
