INSERT INTO highlights VALUES('316675_16_18449-18503','316675',43,'使你走上理智的大路','伊索是希腊克洛赛斯宫中的奴隶，在基督降生前600多年，编著了一部不朽的作品，那就是流传到今天的《伊索寓言》。','7479-7533',NULL,1674318117,1782480564);
INSERT INTO highlights VALUES('316675_16_15020-15043','316675',43,'使你走上理智的大路','他用的是轻松的、友善的方法，而这方法使他成名。','3138-3161',NULL,1674287622,1782480564);
INSERT INTO highlights VALUES('316675_16_14294-14339','316675',43,'使你走上理智的大路','林肯大概在一百年前就说过类似的话，他说：“一滴蜂蜜，可以比一加仑的胆汁诱捕到更多的苍蝇。”','2263-2308',NULL,1674287500,1782480564);
INSERT INTO highlights VALUES('316675_16_14184-14288','316675',43,'使你走上理智的大路','如果有这样一个人，他心中已对你有成见、恶感，你就是找出所有的逻辑、理由来，也不能使他接受你的意见。如果用强迫的手段，更不能使他接受你的意见、向你屈服，但是我们如果用和善的友谊，温和的言语，我们可以引导他同意。','2130-2234',NULL,1674287481,1782480564);
INSERT INTO highlights VALUES('316675_16_12768-12778','316675',43,'使你走上理智的大路','使你走上理智的大路 ','374-383',NULL,1674287415,1782480564);
INSERT INTO highlights VALUES('316675_16_12745-12762','316675',39,'第三章 获取信服的12种方法','如果你错了，迅速、郑重地承认下来。','752-769',NULL,1674138932,1782480564);
INSERT INTO highlights VALUES('316675_16_11364-11421','316675',42,'如果不对就及时认错','任何一个愚蠢的人都会尽力辩护自己的过错……一个能承认自己错误的人，却可使他出类拔萃，并且给人一种尊贵、高尚的感觉。','3077-3134',NULL,1674138932,1782480564);
INSERT INTO highlights VALUES('316675_16_12768-12777','316675',43,'使你走上理智的大路','使你走上理智的大路','374-383',NULL,1674138932,1782480564);
INSERT INTO highlights VALUES('316675_16_10228-10294','316675',42,'如果不对就及时认错','这个警察具有一般的人性——他需要得到一种自重感。我自己承认错误时，他唯一能滋长自重感的方法，就是采取一种宽大的态度，显示出他的仁慈。','1649-1715',NULL,1674138931,1782480564);
INSERT INTO highlights VALUES('316675_16_10514-10581','316675',42,'如果不对就及时认错','你如果在别人责备你之前，很快地找个机会承认自己的错误，对方想要说的话，你已替他说了，他就没有话可说，那你有gg%的机会会获得他的谅解。','2027-2094',NULL,1674138931,1782480564);
INSERT INTO highlights VALUES('316675_16_9274-9308','316675',39,'第三章 获取信服的12种方法',unistr('尊重别人的意见，永远别指责对方是错的。 \u000a    如果不对就及时认错'),'702-756',NULL,1674138073,1782480564);
INSERT INTO highlights VALUES('316675_16_5823-5919','316675',41,'如何避免制造敌人','当我们有错误的时候，或许我们会对自己承认……如果对方能给我们承认的机会，我们会非常的感激；不用对方说，极自然地我们就承认了。如果有人硬把不合胃口的事实往我们的喉咙塞下去，我们是无法接受下来的。','3387-3483',NULL,1674137547,1782480564);
INSERT INTO highlights VALUES('316675_16_5050-5117','316675',41,'如何避免制造敌人','很少人有逻辑性，我们大多数的人都怀有成见，我们之间都被嫉妒、猜疑、恐惧和傲慢所损伤。很多人不愿意改变他的宗教、意志，甚至于包括他的发型','2448-2515',NULL,1673771571,1782480564);
INSERT INTO highlights VALUES('316675_16_4957-5042','316675',41,'如何避免制造敌人','可是，他是不是会对我友善，不，……我相信我有法律的根据，而且我也知道那次讲的比以前都好。但是我并没有说服那位法官，我犯了大错，我直接告诉一位极有学问而著名的人物——他错了','2332-2417',NULL,1673771564,1782480564);
INSERT INTO highlights VALUES('316675_16_3995-4020','316675',41,'如何避免制造敌人','我们要比人家聪明，可是你却不能告诉他。你比他聪明。','1140-1165',NULL,1673754675,1782480564);
INSERT INTO highlights VALUES('316675_16_3605-3760','316675',41,'如何避免制造敌人','你可以用神态、声调或是手势，告诉一个人他错了，这是你很容易就能做到的……而如果你告诉他错了，你以为他会感激你？不，永远不会！因为你对他的智力、判断、自信、自尊，都直接的给予了打击，他不但不会改变他的意志，而且还想向你反击。如果你运用柏拉图、康德的逻辑来跟他理论，他还是不会改变自己的意志，因为你已伤了他的自尊。','658-813',NULL,1673754567,1782480564);
INSERT INTO highlights VALUES('316675_16_3295-3361','316675',40,'争论中没有赢家','在尽可能的情形下，不妨对人谦让一点。与其跟一条狗同路走，不如让狗先走一步。如果给狗咬了一口，你即使把这条狗打死，也不能治好你的伤口。','4503-4569',NULL,1673754486,1782480564);
INSERT INTO highlights VALUES('316675_16_3223-3288','316675',40,'争论中没有赢家','林肯说：“一个成大事的人，不能处处计较别人，消耗自己的时间去和人家争论。无谓的争论，对自己性情上不但有所损害，且会失去自己的自制力','4437-4502',NULL,1673754473,1782480564);
INSERT INTO highlights VALUES('316675_16_2362-2384','316675',40,'争论中没有赢家','我们绝不可能用辩论使一个无知的人心服口服。”','3300-3322',NULL,1673754161,1782480564);
INSERT INTO highlights VALUES('316675_16_2081-2143','316675',40,'争论中没有赢家','就像聪明的老富兰克林常说的：“如果你辩论、反驳，或许你会得到胜利，可是那胜利是短暂、空虚的……你永远得不到对方对你的好感。”','2927-2989',NULL,1673754087,1782480564);
INSERT INTO highlights VALUES('316675_16_1275-1365','316675',40,'争论中没有赢家',unistr('巴恩互助人寿保险公司为他们的职员定下一条规则，那就是“不要争辩”。 \u000a    一个真正成功的推销员，他决不会跟顾客争辩，即使轻微的争辩，也加以避免……人类的思想不是那么容易改变的。'),'1949-2062',NULL,1673752793,1782480564);
INSERT INTO highlights VALUES('316675_16_1230-1269','316675',40,'争论中没有赢家','你必须知道，当人们逆着自己的意见，被人家说服时，他仍然会固执地坚持自己是对的。','1881-1920',NULL,1673752776,1782480564);
INSERT INTO highlights VALUES('316675_16_1042-1089','316675',40,'争论中没有赢家','一场辩论的终了，10次中有9次，那些辩论的人会更坚持他们的见解，相信他们是绝对正确，不会错的。','1647-1694',NULL,1673752737,1782480564);
INSERT INTO highlights VALUES('316675_16_988-1036','316675',40,'争论中没有赢家','天下只有一种方法，能得到辩论的最大胜利，那就是尽量避免辩论……避免辩论，就像避开毒蛇和地震一样。','1570-1618',NULL,1673752727,1782480564);
INSERT INTO highlights VALUES('316675_16_746-761','316675',40,'争论中没有赢家','永远避免正面的冲突，那才是对的','1259-1274',NULL,1673752700,1782480564);
INSERT INTO highlights VALUES('316675_16_0-7','316675',40,'争论中没有赢家','争论中没有赢家','374-381',NULL,1673752459,1782480564);
INSERT INTO highlights VALUES('316675_7_50026-50043','316675',38,'学会自我批评','记下自己做过的傻事，勇于批评自己。','2983-3000',NULL,1673752418,1782480564);
INSERT INTO highlights VALUES('316675_7_49335-49426','316675',38,'学会自我批评','我们每个人都不喜欢被人批评，而是希望听到别人的赞美，也不管这种批评和赞美是不是公正的。我们不是逻辑性的生物，而是一种感情动物，我们的逻辑就像一只独木小舟，在深不可测的情感海洋中漂荡。','2159-2250',NULL,1673752052,1782480564);
INSERT INTO highlights VALUES('316675_7_49240-49261','316675',38,'学会自我批评','我们敌人的意见，比我们自己的意见更接近实际','2064-2085',NULL,1673752032,1782480564);
INSERT INTO highlights VALUES('316675_7_48520-48579','316675',38,'学会自我批评','除了我自己，再也没有别人。除了我之外，没有任何人应该为我的失败承担责任。我是我自己最大的敌人，也是我不幸命运的根源。”','1273-1332',NULL,1673751554,1782480564);
INSERT INTO highlights VALUES('316675_7_48449-48489','316675',38,'学会自我批评','但是，随着年龄的不断渐长，我发现我所有的不幸与他人无任何关系，全都应该怪我自己。','1202-1242',NULL,1673751546,1782480564);
INSERT INTO highlights VALUES('316675_7_48078-48113','316675',38,'学会自我批评','只要是诚意的批评，是以知识为根据并带有建设性的批评，林肯都会欣然接受。','739-774',NULL,1673751397,1782480564);
INSERT INTO highlights VALUES('316675_7_47783-47790','316675',38,'学会自我批评','学会自我批评 ','374-380',NULL,1673751370,1782480564);
INSERT INTO highlights VALUES('316675_7_47561-47633','316675',37,'不要被批评伤害','我尽我所知的最好办法去做——也尽我所能去做，而我打算一直这样把事情做完。如果结果证明我是对的，那么即使花十倍的力气来说我是错的，也没有什么用。”','3001-3073',NULL,1673751331,1782480564);
INSERT INTO highlights VALUES('316675_7_46797-46852','316675',37,'不要被批评伤害','避免所有批评的唯一方法，就是“做你心里认为是对的事，因为无论如何你也是会受到批评的。做也该死，不做也该死？。”','2111-2166',NULL,1673751062,1782480564);
INSERT INTO highlights VALUES('316675_7_46489-46518','316675',37,'不要被批评伤害','只要你出类拔萃，你就一定会遭到批评，所以还是早点习惯为好。','1757-1786',NULL,1673751024,1782480564);
INSERT INTO highlights VALUES('316675_7_46159-46218','316675',37,'不要被批评伤害','虽然我难以阻止别人对我作任何不公正的批评，但我却可以做一件更加重要的事情：可以决定是否让自己受那些不公正批评的干扰。 ','1381-1439',NULL,1673750960,1782480564);
INSERT INTO highlights VALUES('316675_7_45994-46068','316675',37,'不要被批评伤害','一般人根本就不会想到你和我，或者注意别人对我们的批评，人们只会想到他们自己。他们对自己小问题的关注程度，要远远超过那些能置你或我于死地的大事上千倍。','1193-1267',NULL,1673705611,1782480564);
INSERT INTO highlights VALUES('316675_7_45295-45302','316675',37,'不要被批评伤害','不要被批评伤害','374-381',NULL,1673693909,1782480564);
INSERT INTO highlights VALUES('316675_7_45260-45289','316675',24,'第二章 平安快乐的14项法则','不公正的批评通常是种伪装过的恭维，从来没有人会踢一条死狗。','1249-1278',NULL,1673693893,1782480564);
INSERT INTO highlights VALUES('316675_7_44453-44479','316675',36,'没有人愿意踢一条死狗','话说得很凶。可是请记住，从来没有人会踢一条死了的狗。','1902-1928',NULL,1673693786,1782480564);
INSERT INTO highlights VALUES('316675_7_43092-43103','316675',36,'没有人愿意踢一条死狗','没有人愿意踢一条死狗 ','374-384',NULL,1673693569,1782480564);
INSERT INTO highlights VALUES('316675_7_43023-43086','316675',24,'第二章 平安快乐的14项法则','如果你想消除忧虑，获得平安与幸福的心境，那么，就学会对别人感兴趣，忘掉你自己：每天都做一件能使别人脸上带来快乐、微笑的好事吧。','1155-1218',NULL,1673693563,1782480564);
INSERT INTO highlights VALUES('316675_7_41860-41920','316675',35,'每天都要带给别人快乐','那些对别人毫无兴趣的人，在生活中遭到的困难最多，对别人所造成的伤害也最大。只有对别人感兴趣的人，才会拥有快乐，拥有健康。','1551-1611',NULL,1673693436,1782480564);
INSERT INTO highlights VALUES('316675_7_40802-40813','316675',35,'每天都要带给别人快乐','每天都要带给别人快乐 ','374-384',NULL,1673693295,1782480564);
INSERT INTO highlights VALUES('316675_7_40075-40118','316675',34,'将酸柠檬变成甜柠檬汁','“不要对任何人心存恶意，而应喜爱每一个人……”这是美国统治者曾说过的最美也最高贵的话。','4370-4413',NULL,1673693176,1782480564);
INSERT INTO highlights VALUES('316675_7_36816-36830','316675',34,'将酸柠檬变成甜柠檬汁','如果只有柠檬，就做一杯柠檬汁','571-585',NULL,1673692827,1782480564);
INSERT INTO highlights VALUES('316675_7_36693-36721','316675',34,'将酸柠檬变成甜柠檬汁','人类最奇妙的特性之一，就是“把负面改变为正面的力量。” ','454-481',NULL,1673692811,1782480564);
INSERT INTO highlights VALUES('316675_7_39795-39835','316675',34,'将酸柠檬变成甜柠檬汁','尼采对超人所做的定义是：“不仅能够在必要的情况下忍受一切，而且还要喜欢这一切。”','4021-4061',NULL,1673160890,1782480564);
INSERT INTO highlights VALUES('316675_7_38539-38591','316675',34,'将酸柠檬变成甜柠檬汁','是因为他们在刚开始的时候有一些缺陷，这些缺陷会阻碍他们的发展，从而促使他们加倍努力，而得到了更多的报偿。','2564-2616',NULL,1673160689,1782480564);
INSERT INTO highlights VALUES('316675_7_37494-37569','316675',34,'将酸柠檬变成甜柠檬汁','生命中最重要的，就是不要以你的收入为资本。任何一个傻子都会这样做，真正重要的，是要从你的损失中获利。这就需要聪明才智，而这一点也正是智者和傻子的区别。','1335-1410',NULL,1673160533,1782480564);
INSERT INTO highlights VALUES('316675_7_36637-36647','316675',34,'将酸柠檬变成甜柠檬汁','将酸柠檬变成甜柠檬汁','374-384',NULL,1673160434,1782480564);
INSERT INTO highlights VALUES('316675_7_36562-36631','316675',24,'第二章 平安快乐的14项法则','勤于思考并学会感恩，摆脱自怨自艾的困境，即使你遭遇过上千次的挫折，也要勇敢地数出1001个祝福。你的人生必将因此而步入海阔天空的全新境界！','998-1067',NULL,1673160427,1782480564);
INSERT INTO highlights VALUES('316675_7_35622-35662','316675',33,'时刻怀有感恩的心','生活中应该有两个目标：第一，要得到你所希望得到的。然后在得到它之后要充分享受它。','2749-2789',NULL,1673120227,1782480564);
INSERT INTO highlights VALUES('316675_7_35036-35062','316675',33,'时刻怀有感恩的心','我们很少想到我们已经拥有的，而总是想到我们所没有的。','2080-2106',NULL,1673120116,1782480564);
INSERT INTO highlights VALUES('316675_7_34803-34823','316675',33,'时刻怀有感恩的心','世界上最好的三位医生是节食、安静和快乐。','1847-1867',NULL,1673120073,1782480564);
INSERT INTO highlights VALUES('316675_7_33717-33844','316675',33,'时刻怀有感恩的心','在我们生活中大概有90%的事情都是对的，10%是错的。如果我们要得到快乐，我们所应该做的，就是把精力放在那90%正确的事情上，而不要理会那10%的错误。如果我们想难过，想担忧，想得病，那我们只需把精力集中在那10%的错事上即可，不必去理会那90%的好事。','629-756',NULL,1673119756,1782480564);
INSERT INTO highlights VALUES('316675_7_33509-33518','316675',33,'时刻怀有感恩的心','时刻怀有感恩的心 ','374-382',NULL,1673119695,1782480564);
INSERT INTO highlights VALUES('316675_7_33459-33503','316675',32,'施恩不图报',unistr('所以，寻求快乐的唯一途径是： \u000a    不要期望他人感恩，并在付出过程中享受施与的快乐！'),'4478-4545',NULL,1673119682,1782480564);
INSERT INTO highlights VALUES('316675_7_32186-32231','316675',32,'施恩不图报','忘记恩德是人类的天性，就像野草一样；而感恩却如玫瑰，必须给它施肥浇水，给它教养、爱和呵护。','3010-3055',NULL,1673063164,1782480564);
INSERT INTO highlights VALUES('316675_7_31956-32013','316675',32,'施恩不图报','她们希望有人去爱她们，但我们这个世界上唯一能够得到爱的办法，就是不再去乞求，而是立即开始付出，并且不希望得到回报。','2711-2768',NULL,1673063132,1782480564);
INSERT INTO highlights VALUES('316675_7_31396-31448','316675',32,'施恩不图报','当我们施恩时，如果我们偶然得到了别人的感激，那是一种意外之喜；如果我们得不到这种感激，也不必为此而难过。','2059-2111',NULL,1673063042,1782480564);
INSERT INTO highlights VALUES('316675_7_31108-31170','316675',32,'施恩不图报','其实，人终究是人，人的本性是不会改变的。在他的有生之日大概都不会有什么改变，既然对人施恩就不要希望得到回报，那是不可能的事情','1760-1822',NULL,1673063009,1782480564);
INSERT INTO highlights VALUES('316675_7_30480-30508','316675',32,'施恩不图报','感激别人的恩惠是良好教育的结果，这很难在一般人中找到。”','1017-1045',NULL,1673062890,1782480564);
INSERT INTO highlights VALUES('316675_7_29888-29931','316675',24,'第二章 平安快乐的14项法则',unistr('永远不要对敌人心存报复，那样对自己的伤害将会大过对任何人的。 \u000a    施恩不图报 \u000a'),'882-946',NULL,1673062819,1782480564);
INSERT INTO highlights VALUES('316675_7_29294-29338','316675',31,'勿存报复之心','“我没有时间和别人吵架，我没有时间去后悔，也没有任何人能强迫我将自己降低到恨他的地步。”','4941-4985',NULL,1673062719,1782480564);
INSERT INTO highlights VALUES('316675_7_28288-28391','316675',31,'勿存报复之心','当然，有一个很有效的方法，能使我们原谅和忘记那些误解和错对自己的人，那就是让我们去做一些绝对超出我们能力以外的事，这样我们所遭受的侮辱和敌意就变得无关紧要了。也只有这样，我们才不会浪费精力去计较理想之外的事','3757-3860',NULL,1673062248,1782480564);
INSERT INTO highlights VALUES('316675_7_28145-28177','316675',31,'勿存报复之心','有句老话说得好：“不会生气的人是笨蛋，而不生气的人才是聪明人。”','3568-3600',NULL,1673062208,1782480564);
INSERT INTO highlights VALUES('316675_7_28118-28137','316675',31,'勿存报复之心','从来不去为那些不喜欢的人而浪费他一分钟','3518-3537',NULL,1673062204,1782480564);
INSERT INTO highlights VALUES('316675_7_27593-27653','316675',31,'勿存报复之心','我们可能不能像圣人那样爱我们的仇人，但为了自己的健康和快乐，我们要原谅他们，忘记他们。如果我们能这样做，实在是明智之举。','2947-3007',NULL,1673062184,1782480564);
INSERT INTO highlights VALUES('316675_7_27945-27970','316675',31,'勿存报复之心','我知道仅有爱国还不够，我一定不能敌视或怨恨任何人。','3322-3347',NULL,1673062181,1782480564);
INSERT INTO highlights VALUES('316675_7_26665-26704','316675',31,'勿存报复之心','我们要试着去爱我们的仇人。即使我们不能爱我们的仇人，那我们至少也要爱我们自己。','1910-1949',NULL,1672997380,1782480564);
INSERT INTO highlights VALUES('316675_7_25785-25821','316675',31,'勿存报复之心','如果有个自私的人占了你的便宜，把他从你的朋友名单上删除，千万不要去报复。','904-940',NULL,1672997253,1782480564);
INSERT INTO highlights VALUES('316675_7_25739-25764','316675',31,'勿存报复之心','憎恨伤不了对方一根汗毛，却把自己的日子弄成了炼狱。','858-883',NULL,1672997244,1782480564);
INSERT INTO highlights VALUES('316675_7_25638-25704','316675',31,'勿存报复之心','如果我们对敌人心怀仇恨，那么就意味着我们要付出比对方更大的力量来击垮自己，使他得以有机会控制我们的睡眠、胃口、血压、健康，甚至心情。','763-829',NULL,1672997209,1782480564);
INSERT INTO highlights VALUES('316675_7_25319-25326','316675',31,'勿存报复之心','勿存报复之心 ','374-380',NULL,1672997162,1782480564);
INSERT INTO highlights VALUES('316675_7_25293-25313','316675',24,'第二章 平安快乐的14项法则','活在一个真实的今天，你才会获得平安快乐。','831-851',NULL,1672997158,1782480564);
INSERT INTO highlights VALUES('316675_7_23896-23929','316675',30,'活在真实的今天','我们总是无法及早学会这个道理：生命就在生活里，就在每一天和每一刻。','4682-4715',NULL,1672997018,1782480564);
INSERT INTO highlights VALUES('316675_7_23180-23232','316675',30,'活在真实的今天','我现在知道，不必害怕未来：我现在知道，每次只要活一天——而对一个聪明人来说，每一天都是一个崭新的生命。”','3853-3905',NULL,1672996944,1782480564);
INSERT INTO highlights VALUES('316675_7_22728-22785','316675',30,'活在真实的今天','可是如果我们不一件一件地做，让它们像沙粒通过沙漏的窄缝一样，慢慢平均地通过这一天，那我们就一定会损害到自己的健康了','3333-3390',NULL,1672996831,1782480564);
INSERT INTO highlights VALUES('316675_7_21444-21498','316675',30,'活在真实的今天','为明日做准备的最好方法，就是集中你所有的智慧和热诚，把今天的工作做得尽善尽美，这就是你能应对未来的唯一方法。','1675-1729',NULL,1672996679,1782480564);
INSERT INTO highlights VALUES('316675_7_21130-21187','316675',30,'活在真实的今天','按下按钮，用铁门把过去隔断——隔断已经过去的那些昨天；再按下另一个按钮，用铁门把未来也隔断，隔断那些尚未到来的明天','1338-1395',NULL,1672996611,1782480564);
INSERT INTO highlights VALUES('316675_7_21016-21103','316675',30,'活在真实的今天','你们每个人的组织都要比那条大海轮精美得多，所要走的航程也更远得多。你们也必须学习那位船长，知道怎样控制一切，你们要活在一个“完全独立的今天”，这才是在航程中确保安全的最好方法','1224-1311',NULL,1672996590,1782480564);
INSERT INTO highlights VALUES('316675_7_20328-20336','316675',30,'活在真实的今天','活在真实的今天 ','374-381',NULL,1672928658,1782480564);
INSERT INTO highlights VALUES('316675_7_17279-17340','316675',29,'克服忧虑的心理','柏拉图曾说过：“医生所犯的最大错误，就是他们只为病人治疗身体，却不为他们医治思想。可是精神和肉体是一体的，不能分别治疗。”','2604-2665',NULL,1672855743,1782480564);
INSERT INTO highlights VALUES('316675_7_15928-15971','316675',29,'克服忧虑的心理',unistr('轻松和享受 \u000a    最能使你轻松愉快的是： \u000a    健全的信仰、睡眠、音乐和欢笑；'),'909-998',NULL,1672843463,1782480564);
INSERT INTO highlights VALUES('316675_7_15510-15518','316675',29,'克服忧虑的心理','克服忧虑的心理 ','374-381',NULL,1672843410,1782480564);
INSERT INTO highlights VALUES('316675_7_13966-13992','316675',28,'学会放松，解除疲劳','“接受既定事实，是克服随之而来的任何不幸的第一步。”','3493-3519',NULL,1672843230,1782480564);
INSERT INTO highlights VALUES('316675_7_13678-13710','316675',28,'学会放松，解除疲劳','其实，当我们忧虑的时候，思想会到处乱转，从而丧失决策分析的能力。','3159-3191',NULL,1672843193,1782480564);
INSERT INTO highlights VALUES('316675_7_13451-13491','316675',28,'学会放松，解除疲劳','第三步：从这以后，我就平静下来，把我的时间和精力用于改善我所面对的问题和困难。 ','2885-2924',NULL,1672843125,1782480564);
INSERT INTO highlights VALUES('316675_7_13089-13241','316675',28,'学会放松，解除疲劳',unistr('它共有3个步骤： \u000a    第一步：我先放弃害怕，诚恳地分析整个情况，然后找出万一失败将会出现的最坏情况。没有人会把我关起来或者枪毙我，这一点可以肯定。只不过，我很可能会丢掉工作，我的老板也可能会拆掉整个机器，使两万美元泡汤。 \u000a    第二步：找出了很多可能发生的最坏的情况之后，我让自己敢于接受它。 '),'2460-2657',NULL,1672843100,1782480564);
INSERT INTO highlights VALUES('316675_7_12483-12537','316675',28,'学会放松，解除疲劳','“我发现，当我接受了现实后，一切都发生了变化。第一，我问自己：’可能发生的最坏情况是什么？‘答案是：死亡。”','1787-1870',NULL,1672843013,1782480564);
INSERT INTO highlights VALUES('316675_7_11441-11451','316675',28,'学会放松，解除疲劳','学会放松，解除疲劳 ','374-383',NULL,1672842885,1782480564);
INSERT INTO highlights VALUES('316675_7_11305-11384','316675',27,'从悲伤中走出来','让我们为自己的快乐而奋斗吧！一切只为今天。只为今天，我们要内心毫无惧怕。我们尤其不能害怕快乐，我们要去爱一切，去欣赏一切美，相信我们所爱的那些人也会爱我们。 ','2575-2653',NULL,1672842873,1782480564);
INSERT INTO highlights VALUES('316675_7_11197-11224','316675',27,'从悲伤中走出来','如果他不能振作他的思想，他永远只能陷于衰弱和愁苦之中。','2421-2448',NULL,1672842846,1782480564);
INSERT INTO highlights VALUES('316675_7_11087-11140','316675',27,'从悲伤中走出来','人们不能吸引他们所要的，却可以吸引他们所有的，能改变气质的神性就存在于我们自己的内心当中，也就是我们自己。','2311-2364',NULL,1672842836,1782480564);
INSERT INTO highlights VALUES('316675_7_10418-10467','316675',27,'从悲伤中走出来','如果说半个世纪的生活经历曾使我学到了什么的话，那就是“除了你自己，没有任何东西可以给你带来平静。”','1504-1553',NULL,1672842731,1782480564);
INSERT INTO highlights VALUES('316675_7_10218-10253','316675',27,'从悲伤中走出来','一个人可以关注一些很严峻的问题，但他同时可以将鲜花插在衣襟上昂首阔步。','1264-1299',NULL,1672842699,1782480564);
INSERT INTO highlights VALUES('316675_7_10162-10212','316675',27,'从悲伤中走出来','很不幸的是，生命不会像这样简单化，但我却鼓励大家要尽力采取积极正面的态度，而不要采取消极反面的态度。','1185-1235',NULL,1672842690,1782480564);
INSERT INTO highlights VALUES('316675_7_9692-9702','316675',27,'从悲伤中走出来','生活是由思想形成的。','623-633',NULL,1672842631,1782480564);
INSERT INTO highlights VALUES('316675_7_8938-9065','316675',26,'坚守自我，拒绝模仿',unistr('正如爱默生在他的散文《论自信》中所说的： \u000a    每个人在他的教育过程当中，一定会在某个时期发现，羡慕就是无知，模仿就是自杀。不论好坏，他都必须保持自己的本色。虽然广袤的宇宙之间全是美好的东西，但除非他耕耘那一块属于自己的土地，否则他绝不会有好收成。 '),'5233-5382',NULL,1672842543,1782480564);
INSERT INTO highlights VALUES('316675_7_8112-8157','316675',26,'坚守自我，拒绝模仿','我写了一本关于公开演讲的教材，完全以我自己的经验和观察，以一个演说家和演说教师的身份来写。','4275-4320',NULL,1672842424,1782480564);
INSERT INTO highlights VALUES('316675_7_8032-8075','316675',26,'坚守自我，拒绝模仿','“你一定要保持你自己的本色，不论你的错误有多少，你的能力多么的有限，你也不能变成别人。','4195-4238',NULL,1672842410,1782480564);
INSERT INTO highlights VALUES('316675_7_5827-5853','316675',26,'坚守自我，拒绝模仿','一个人最糟糕的是不能成为自己，不能在身心中保持自我。','1607-1633',NULL,1672805670,1782480564);
INSERT INTO highlights VALUES('316675_7_5401-5484','316675',26,'坚守自我，拒绝模仿',unistr('‘不论如何，保持本色，做独一无二的自己。’ \u000a    ”保持本色’这几个字在我眼前闪过，犹如当头棒喝。我发现，不幸的根源，在于我把自己套入了一个不属于自己的模式中。“'),'1122-1229',NULL,1672805623,1782480564);
INSERT INTO highlights VALUES('316675_7_4778-4801','316675',24,'第二章 平安快乐的14项法则',unistr('选择正确的思想。 \u000a    坚守自我，拒绝模仿'),'647-697',NULL,1672805560,1782480564);
INSERT INTO highlights VALUES('316675_7_4138-4194','316675',25,'选择正确的思想','所有这些改变只要从一个行动开始，就是做出开心的样子，做出可以付出一点爱心的样子——而不是徘徊在自己痛苦的深渊中。','5185-5241',NULL,1672805468,1782480564);
INSERT INTO highlights VALUES('316675_7_3500-3645','316675',25,'选择正确的思想','行动似乎在跟着感觉走，其实行动与感觉是并行的，大多都以意志控制行动，也就能间接控制感觉。也就是说，我们虽然不能一下决心就立即改变情绪，但是我们确实可以做到改变行动。当我们改变行动时就自动改变感觉。如果你不开心，那么，能使自己开心的唯一办法就是开心地坐直身体，并装作很开心的样子说话及行动。”','4484-4629',NULL,1672805391,1782480564);
INSERT INTO highlights VALUES('316675_7_3313-3369','316675',25,'选择正确的思想','失明的弥尔顿在三百年前就发现了同样的真理：“心灵，是它自己的殿堂：它可成为地狱中的天堂，也可成为天堂中的地狱。”','4251-4307',NULL,1672805351,1782480564);
INSERT INTO highlights VALUES('316675_7_3260-3305','316675',25,'选择正确的思想','如果我们拥有勇气与平静的思想，我们就能坐在自己棺木上还能欣赏风景，在饥寒交迫时还能纵情欢唱','4175-4220',NULL,1672805344,1782480564);
INSERT INTO highlights VALUES('316675_7_2322-2377','316675',25,'选择正确的思想','你的身心都很健康，打败你的不是你所遭遇的各种事情，而是你对这些事情的想法。一个人的想法将决定他是个什么样的人。','3102-3157',NULL,1672797892,1782480564);
INSERT INTO highlights VALUES('316675_7_1317-1393','316675',25,'选择正确的思想','每天早晨出门前，他一定会提醒自己抬头挺胸。他积极，有勇气，拒绝被挫折击倒。对他来说，挫折是人生的一部分！如果你要达到成功的巅峰，这将是一种有意义的磨炼。','1894-1970',NULL,1672797802,1782480564);
INSERT INTO highlights VALUES('316675_7_619-629','316675',25,'选择正确的思想','—“思想决定一生”。','1126-1136',NULL,1672797486,1782480564);
INSERT INTO highlights VALUES('316675_7_0-7','316675',24,'第二章 平安快乐的14项法则','选择正确的思想','647-654',NULL,1672797335,1782480564);
INSERT INTO highlights VALUES('316675_2_25759-25786','316675',23,'学会关心和帮助他人','我发现，对他们所做的事情感兴趣，会给他们带来极大的快乐','5845-5872',NULL,1672797145,1782480564);
INSERT INTO highlights VALUES('316675_2_25420-25490','316675',23,'学会关心和帮助他人','宗教学者左罗斯特拉说：“对别人好不是压力，而应该被看成是一种享受，因为它能使你健康快乐”富兰克林说得更简单：“取悦别人，事实上是取悦自己。”','5466-5536',NULL,1672797115,1782480564);
INSERT INTO highlights VALUES('316675_2_24803-24829','316675',23,'学会关心和帮助他人','他们的一生只想搭个便车，迫使他们只好去求助于心理医师','4734-4760',NULL,1672795972,1782480564);
INSERT INTO highlights VALUES('316675_2_24739-24798','316675',23,'学会关心和帮助他人','我的病患者中，有1/3以上在医学上找不出任何病因，他们只是不知道生活的意义在哪里而已。他们以自己为中心，只关注自己。”','4670-4729',NULL,1672795961,1782480564);
INSERT INTO highlights VALUES('316675_2_24587-24623','316675',23,'学会关心和帮助他人','这次灾难让我发觉了自己不曾知晓的力量，它让我从只关注自己转移到关注他人。','4493-4529',NULL,1672795926,1782480564);
INSERT INTO highlights VALUES('316675_2_23793-23852','316675',23,'学会关心和帮助他人','这次的经历让我懂得，要使自己快乐只有首先让别人快乐。我发觉，快乐是有感染力的，帮助别人、关爱别人，使我克服了忧虑和悲伤','3666-3725',NULL,1672795804,1782480564);
INSERT INTO highlights VALUES('316675_2_23716-23793','316675',23,'学会关心和帮助他人','通过跟他们交谈，发现自己是个幸运儿。我由衷地感谢上帝，儿时我的圣诞节过得是那么愉快，一直享受双亲的疼爱与呵护，这两个小孤儿带给我的远比我给他们的要多得多。','3589-3666',NULL,1672795794,1782480564);
INSERT INTO highlights VALUES('316675_2_22817-22849','316675',23,'学会关心和帮助他人','一个以自我为中心的人必定陷于对生活的抱怨之中，世界不能使他快乐。','2552-2584',NULL,1672766380,1782480564);
INSERT INTO highlights VALUES('316675_2_22466-22493','316675',23,'学会关心和帮助他人','由于我一直在帮助别人，所以，我现在的生活中很少有烦恼。','2117-2144',NULL,1672766344,1782480564);
