INSERT INTO highlights VALUES('316675_2_18830-18893','316675',22,'知悉对方的想法','你会永远站在别人立场去打算、设想，并由对方的观点去观察事物的趋向。如果你真获得了这本书上的那件事，那就是你一生事业转折的关键。','8542-8605',NULL,1672708987,1782480564);
INSERT INTO highlights VALUES('316675_2_14076-14154','316675',22,'知悉对方的想法','明天你要劝说某人去做某件事，在你尚未开口前，不妨自己先问：“我如何能使他要做这件事？”那问题可以阻止我们，在匆忙不小心之下去见人和毫无结果的谈论我们的欲望。','2193-2271',NULL,1672636992,1782480564);
INSERT INTO highlights VALUES('316675_2_13028-13066','316675',22,'知悉对方的想法','世界上唯一能影响对方的方法，就是谈论他所要的，而且还告诉他，如何才能得到它。','846-884',NULL,1672622650,1782480564);
INSERT INTO highlights VALUES('316675_2_12967-12996','316675',22,'知悉对方的想法','当然，你注意你的需要，你永远在注意，但别人对你却漠不关心。','762-791',NULL,1672622643,1782480564);
