INSERT INTO highlights VALUES('316675_2_12558-12633','316675',21,'发自内心地赞赏别人','停止思考我们自己的成就和需要，让我们去研究别人的优点，把对人的恭维、谄媚忘掉，给予人由衷、诚恳的赞赏。人们对你所讲的，将会重视和珍惜，终生藏之背诵……','8308-8383',NULL,1672592680,1782480564);
INSERT INTO highlights VALUES('316675_2_12112-12131','316675',21,'发自内心地赞赏别人','“别怕攻击你的敌人，提防谄媚你的朋友。','7720-7739',NULL,1672592547,1782480564);
INSERT INTO highlights VALUES('316675_2_11608-11675','316675',21,'发自内心地赞赏别人','拍马那一套，当然是骗不了明白人的，那是肤浅、自私、虚伪的，那应该失败，而且常常失败。可是，有些人对赞赏，出于内心的赞赏，简直太需要了。','7100-7167',NULL,1672591777,1782480564);
