INSERT INTO highlights VALUES('316675_2_10838-10868','316675',21,'发自内心地赞赏别人','“埋葬在这里的，是个知道如何跟比他自己聪明的人相处的一个人。','6123-6153',NULL,1672591590,1782480564);
