INSERT INTO highlights VALUES('316675_2_10411-10474','316675',21,'发自内心地赞赏别人','司华伯这样说：“我认为，我有激发他们热诚的能力，那是我所具有的最大的资源……我充分发掘每一个人才能的方法，是用赞赏和鼓励！” ','5564-5626',NULL,1672591498,1782480564);
INSERT INTO highlights VALUES('316675_2_10083-10117','316675',21,'发自内心地赞赏别人','据我所知道：有史以来，年薪百万元的只有两个人——克莱斯勒和司华伯。 ','5167-5200',NULL,1672591488,1782480564);
INSERT INTO highlights VALUES('316675_2_9038-9086','316675',21,'发自内心地赞赏别人','有些专家宣称……人可能真的会发疯，为的是要在疯狂的幻境中，寻找冷酷的现实世界上所得不到的自重感。','3875-3923',NULL,1672591281,1782480564);
INSERT INTO highlights VALUES('316675_2_8123-8177','316675',21,'发自内心地赞赏别人','如果你告诉我，你是如何得到你的自重感，我就可以告诉你，你是怎样的人。确定你的性格，对你来讲，是件最重要的事。','2707-2761',NULL,1672591087,1782480564);
INSERT INTO highlights VALUES('316675_2_7388-7412','316675',21,'发自内心地赞赏别人','寻求自重感的欲望，是人类和动物间，一项重要的差别','1742-1766',NULL,1672578936,1782480564);
INSERT INTO highlights VALUES('316675_2_7647-7690','316675',21,'发自内心地赞赏别人','假如我们的祖先，没有这种“自重感”炽烈的冲动，我们不会有文化，就跟其他动物差不多了。 ','2116-2158',NULL,1672578933,1782480564);
INSERT INTO highlights VALUES('316675_2_7351-7382','316675',21,'发自内心地赞赏别人','如果能诚挚地满足这种内心饥饿的人，就可以将人们掌握在手掌之中。','1682-1713',NULL,1672578889,1782480564);
INSERT INTO highlights VALUES('316675_2_7006-7135','316675',21,'发自内心地赞赏别人',unistr('差不多每个正常的成人都想要： \u000a    一、健康和生命的保护。 \u000a    二、食物。 \u000a    三、睡眠。 \u000a    四、金钱和金钱所能买到的。 \u000a    五、生命的后顾。 \u000a    六、性生活的满足。 \u000a    七、子女们的健康。 \u000a    八、自重感。 '),'1084-1396',NULL,1672578846,1782480564);
INSERT INTO highlights VALUES('316675_2_6965-6979','316675',21,'发自内心地赞赏别人','你要些什么？并不是很多的东西','1043-1057',NULL,1672578767,1782480564);
INSERT INTO highlights VALUES('316675_2_6730-6758','316675',21,'发自内心地赞赏别人','我能叫你去做任何事情的唯一方法，那就是把你所需要的给你。','693-721',NULL,1672578714,1782480564);
INSERT INTO highlights VALUES('316675_2_6772-6841','316675',21,'发自内心地赞赏别人','    维也纳一位20世纪最享盛誉的心理学家——弗洛伊德博士曾这样说：凡你我所做的事，都起源于两种动机，那是性的冲动和能成为伟人的欲望。 ','785-849',NULL,1672578696,1782480564);
INSERT INTO highlights VALUES('316675_2_6007-6049','316675',20,'不要批评、责怪或抱怨','当我们要应付一个人的时候，应该记住，我们不是应付理论的动物，而是在应付感情的动物。 ','7916-7957',NULL,1672578505,1782480564);
INSERT INTO highlights VALUES('316675_2_5854-5949','316675',20,'不要批评、责怪或抱怨','是的，我做错了，或许我应该得到这样的斥责。可是，人性使然，这使我深深的痛恨，对他怀着极度的愤恨。甚至10年后，我知道台维斯去世的消息时，我心里还深深恨他。而我却羞于承认，就是他给了我的伤痕。','7717-7812',NULL,1672578466,1782480564);
INSERT INTO highlights VALUES('316675_2_5439-5514','316675',20,'不要批评、责怪或抱怨','你所认识的人，你愿意他改变、调整，或是进步吗？是的，那是最好不过的。可是为什么不从你自己先开始呢？从自私的立场来说，从自己开始要比改进别人，获益得多。','7193-7268',NULL,1672578366,1782480564);
INSERT INTO highlights VALUES('316675_2_5363-5433','316675',20,'不要批评、责怪或抱怨','以后我们如果想要批评人家时，让我们从口袋拿出一张五元的钞票来，看看钞票上林肯的像，这样问自己：“如果林肯遭遇到这类的事，他将如何去处置呢？”','7094-7164',NULL,1672578355,1782480564);
INSERT INTO highlights VALUES('316675_2_3967-3983','316675',20,'不要批评、责怪或抱怨','“不要评议人，免得为人所评议”。','5306-5322',NULL,1672578122,1782480564);
INSERT INTO highlights VALUES('316675_2_3757-3839','316675',20,'不要批评、责怪或抱怨','这次对林肯来讲，是件最惊人、最恐怖的事，在林肯待人的艺术上却给了他一个极宝贵的教训。从那以后他永远不再写凌辱人的信，永远不再讥笑他人，几乎从不为任何事而批评任何人。','5073-5155',NULL,1672578089,1782480564);
INSERT INTO highlights VALUES('316675_2_2826-2865','316675',20,'不要批评、责怪或抱怨','人类自然的天性，是做错事只会责备别人，而绝不会责备自己，我们每个人都是如此的。','3942-3981',NULL,1672577949,1782480564);
INSERT INTO highlights VALUES('316675_2_2065-2152','316675',20,'不要批评、责怪或抱怨','不过我所要指出的一点，就是罗斯福所有的批评，并没有使塔夫脱自己觉得不对，那只能使塔夫脱尽力替自己辩护。眼中含着泪水，反复地说：“我不知道该怎么样做，才能和我所已做的有不同。”','3003-3090',NULL,1672577767,1782480564);
INSERT INTO highlights VALUES('316675_2_1424-1463','316675',20,'不要批评、责怪或抱怨','一百次中有九十九次，没有人会为了任何一桩事情来批评他自己，无论错误到何种程度。','2207-2246',NULL,1672577592,1782480564);
INSERT INTO highlights VALUES('316675_2_1230-1284','316675',20,'不要批评、责怪或抱怨','如果卡邦、“双枪”克劳雷、休士，和在监狱中的暴徒，完全不自责，归咎在自己身上……那你我所接触的人又如何呢？ ','1944-1997',NULL,1672577572,1782480564);
INSERT INTO highlights VALUES('316675_2_482-519','316675',20,'不要批评、责怪或抱怨','“在我衣服里面，是一颗疲惫的心——那是仁慈的，一颗不愿意伤害任何人的心。”','943-980',NULL,1672577426,1782480564);
INSERT INTO highlights VALUES('316675_2_0-10','316675',19,'第一章 为人处世的基本技巧','不要批评、责怪或抱怨','646-656',NULL,1672577108,1782480564);
INSERT INTO highlights VALUES('316675_1_0-83','316675',17,'序言','生活的经验和事实表明，那些在事业上获得重大成功的人除了知识以外，总是还具备一种别人所不及的本领，如善于讲话，善于转移和改变他人的思想，善于推销自己和出售自己的意见等。','634-717',NULL,1672551135,1782480564);
INSERT INTO highlights VALUES('316675_1_83-110','316675',17,'序言','同时还必须指出的是，他们都具有令人羡慕不已的积极心态。','717-744',NULL,1672551133,1782480564);
INSERT INTO highlights VALUES('23934823_34_4346-4574','23934823',76,'附录3 词汇表',unistr('金律（对称性）：\u000a以你想被对待的方式去对待他人。\u000a银律（用否定其对立面的方式体现金律）：\u000a如果你不希望别人这样对你，那你也不要这样对别人（己所不欲勿施于人）。要注意银律和金律的区别，银律可以阻止爱管闲事的人来操控你的生活。'),'4340-4568',NULL,1666092309,1782480565);
INSERT INTO highlights VALUES('23934823_32_2726-2830','23934823',74,'附录1 违背直觉的事情',unistr('绝大多数政策制定者不明白这样的道理，研究整体系统的运作机理比观察系统中的个体行为更重要。\u000a在合理的市场结构下，一群白痴也能创造出一个运转良好的市场。'),'2715-2819',NULL,1666091830,1782480565);
INSERT INTO highlights VALUES('23934823_30_1050-2314','23934823',72,'后记',unistr('不要没有力量的肌肉；\u000a不要没有信任的友谊；\u000a不要相信不承担责任的观点；\u000a不要缺乏美感的变化；\u000a不要没有价值观的阅历；\u000a不要未拼尽全力的人生；\u000a不要把资源和精力浪费在自己不渴望的事情上；\u000a不要吃没有营养的食物；\u000a不要没有相互奉献的爱情；\u000a不要拥有了权力却抛弃了公平；\u000a不要缺乏严谨调查的事实；\u000a不要没有逻辑的统计；\u000a不要没有证明的数学；\u000a不要没有实践经验的老师；\u000a不要冷若冰霜的礼貌；\u000a不要无法付诸实施的理论；\u000a不要没有真才实学的文凭；\u000a不要没有打击能力的军事行动；\u000a不要没有文明的进步；\u000a不要没有相互投入的友谊；\u000a不要遵奉美德却又不敢担当；\u000a不要忽略概率的遍历性；\u000a不要相信没有风险的财富机会；\u000a不要辞藻华丽却又言之无物；\u000a不要把问题搞得很复杂却又没有思想深度；\u000a不要忽略决策的非对称性；\u000a不要以为质疑会阻碍科学进步；\u000a不要缺乏宽容的宗教。\u000a最后也是最重要的是：\u000a没有“风险共担”就一事无成。'),'990-2254',NULL,1666091499,1782480565);
INSERT INTO highlights VALUES('23934823_29_12739-13163','23934823',71,'第19章 承担风险的逻辑',unistr('总结\u000a我用几句话总结一下本章的内容：\u000a人们可能会喜欢风险，但肯定厌恶爆仓、破产和毁灭。\u000a生活中的核心非对称性在于：\u000a如果一个策略有可能触发爆仓风险，那么无论多么大的收益都得不偿失。\u000a还有：\u000a摧毁系统的风险和系统内部的波动是两个物种。\u000a你承担的每一个风险累积起来最终会导致你的预期寿命缩短。\u000a最后：\u000a理性就是避免系统性毁灭。'),'12721-13145',NULL,1666091381,1782480565);
INSERT INTO highlights VALUES('23934823_29_10294-10330','23934823',71,'第19章 承担风险的逻辑','巴菲特只是建立了一个非常严格的筛选体系，只有通过筛选的项目他才进行投资。','10279-10315',NULL,1666079462,1782480565);
INSERT INTO highlights VALUES('23934823_29_8524-8544','23934823',71,'第19章 承担风险的逻辑','而是系统性风险一旦发生就会摧毁我们大家。','8470-8490',NULL,1666079114,1782480565);
INSERT INTO highlights VALUES('23934823_29_8281-8343','23934823',71,'第19章 承担风险的逻辑','正如我与几位同事提出的那样，预防系统因遍历性而产生的极端情况应该成为我们首要关注的事物——要防止自己成为系统遍历性的牺牲品。','8227-8289',NULL,1666079057,1782480565);
INSERT INTO highlights VALUES('23934823_29_8009-8056','23934823',71,'第19章 承担风险的逻辑','除非你极度自恋或者患有精神疾病，而即使那样，对于你而言最糟糕的事情也绝不仅限于失去自己的生命。','7955-8002',NULL,1666079006,1782480565);
INSERT INTO highlights VALUES('23934823_29_7006-7104','23934823',71,'第19章 承担风险的逻辑','盈利突破某一事先设定的阈值水平时，你就选择更加积极地下注；当你开始损失并跌破阈值时，你就减少下注金额，就好像有一个开关在控制你的下注金额一样。事实上，证券市场上几乎所有活下来的交易员都是这样做的。','6953-7051',NULL,1666078873,1782480565);
INSERT INTO highlights VALUES('23934823_29_7128-7226','23934823',71,'第19章 承担风险的逻辑','耸人听闻的干涉主义者理查德·塞勒就是其中之一，他对概率几乎一无所知，却将这个策略视为受“心理账户”影响的“追涨杀跌”行为，并敦促政府叫停我们在交易中使用该策略，这就使得我们的投资组合无法实现遍历性','7075-7173',NULL,1666078870,1782480565);
INSERT INTO highlights VALUES('23934823_29_6388-6478','23934823',71,'第19章 承担风险的逻辑','所有这些风险会加总起来，影响实验对象在测试中的态度，生活中充满了随机性的风险，而且都与“爆仓”风险有关，我们不能把这些因素和人的生活割裂开来，单独研究其针对某个事件的“损失厌恶”。','6335-6425',NULL,1666078644,1782480565);
INSERT INTO highlights VALUES('23934823_29_5561-5603','23934823',71,'第19章 承担风险的逻辑','在现实生活中，情况往往更糟，每个看起来微不足道的风险，累积起来就会降低你的预期寿命。','5508-5550',NULL,1666078497,1782480565);
INSERT INTO highlights VALUES('23934823_29_5497-5532','23934823',71,'第19章 承担风险的逻辑','就是不断地重复暴露在风险之中，无论多么小概率的危险，最终都会带来死亡。','5444-5479',NULL,1666078461,1782480565);
INSERT INTO highlights VALUES('23934823_29_3081-3248','23934823',71,'第19章 承担风险的逻辑','比如应用数学家克劳德·香农和艾德·索普，以及提出凯利标准的物理学家J.L.凯利都把这个问题搞清楚了，而且他们深入浅出地阐述了这个问题。保险数学之父、瑞典应用数学家哈拉尔德·克拉梅尔也搞清楚了这个问题。而在20多年前，我和马克·斯皮兹纳格这样的从业人员就已经按照这一准则建立了我们的交易策略（我在交易和决策过程中就已经把这个问题搞清楚了','3030-3197',NULL,1666065820,1782480565);
INSERT INTO highlights VALUES('23934823_29_2778-3033','23934823',71,'第19章 承担风险的逻辑','自从250多年前数学家雅各布·伯努利给出了不确定性条件下决策的方程以后，他的构想就成了一项标准，导致此后几乎这个领域里所有人都犯了混淆集合概率与时间概率的严重的错误','2727-2809',NULL,1666065504,1782480565);
INSERT INTO highlights VALUES('23934823_29_2194-2238','23934823',71,'第19章 承担风险的逻辑','个人也无法获得与市场相同的回报，除非他有源源不断的资金可以注入市场，而且不存在“爆仓点”','2143-2187',NULL,1666065373,1782480565);
INSERT INTO highlights VALUES('23934823_29_2067-2093','23934823',71,'第19章 承担风险的逻辑','我们把第一种情形称为集合概率，第二种情形称为时间概率','2016-2042',NULL,1666065355,1782480565);
