INSERT INTO highlights VALUES('23934823_28_8107-8147','23934823',70,'第18章 如何对理性保持理性','理性并不是那些可以用清晰的语言描述的因素，理性只有一个内涵：帮助生存，避免毁灭。','8018-8058',NULL,1666065213,1782480565);
INSERT INTO highlights VALUES('23934823_28_8011-8036','23934823',70,'第18章 如何对理性保持理性','最重要的是犹太人经历了这些艰难困苦之后幸存下来了。','7922-7947',NULL,1666065163,1782480565);
INSERT INTO highlights VALUES('23934823_28_7908-7956','23934823',70,'第18章 如何对理性保持理性','长期生存下来的部落会在内部产生凝聚力，并在部落成员之间建立信任感，这对商业的萌发是极有利的条件。','7819-7867',NULL,1666065147,1782480565);
INSERT INTO highlights VALUES('23934823_28_6593-6623','23934823',70,'第18章 如何对理性保持理性','你愿意为一个事物承担多大的风险，揭示了你对该事物的信任程度。','6506-6536',NULL,1666064956,1782480565);
INSERT INTO highlights VALUES('23934823_28_6151-6199','23934823',70,'第18章 如何对理性保持理性','我们称之为“信仰”的东西其实是人类思维的必需品。当然这是一个比喻，但至少信仰可以是一种治疗手段。','6065-6113',NULL,1666064903,1782480565);
INSERT INTO highlights VALUES('23934823_28_5793-5888','23934823',70,'第18章 如何对理性保持理性','90%以上从事决策研究的心理学家（包括卡斯·桑斯坦和理查德·塞勒在内的管理者和研究人员）对概率一无所知，并且试图阻止我们天然形成的偏执，但其实偏执也许是一种有效的风险防控手段和自我保护机制。','5707-5802',NULL,1666064864,1782480565);
INSERT INTO highlights VALUES('23934823_28_4917-5045','23934823',70,'第18章 如何对理性保持理性','因此我认为，宗教之所以存在是为了建立尾部风险管理体系，并将管控风险的知识传给下一代，宗教仪轨和教义很容易被人们理解、传授和执行，这样就能帮助部落增强抵抗风险的能力。尽管大自然存在尾部风险，但是人类仍然顽强地生存了下来，我们今天的生存不可能是随机产生的结果。','4790-4918',NULL,1666064781,1782480565);
INSERT INTO highlights VALUES('23934823_28_4697-4723','23934823',70,'第18章 如何对理性保持理性','换句话说，面临一个危险时，修正偏差比缩小方差容易得多','4581-4607',NULL,1666064666,1782480565);
INSERT INTO highlights VALUES('23934823_28_4168-4259','23934823',70,'第18章 如何对理性保持理性','这就是为什么我一直反对由政府决定哪些是正确的，哪些是错误的，哪些是我们应该做的……只有造物主知道什么是正确的，什么是错误的，前提是各物种都要置身于“风险共担”中参与大自然的进化选择。','4001-4092',NULL,1666064617,1782480565);
INSERT INTO highlights VALUES('23934823_28_4040-4083','23934823',70,'第18章 如何对理性保持理性','如果某些错误的代价较小，主动去犯这些错误反而是理性的做法，因为错误会给你带来新的发现。','3873-3916',NULL,1666064614,1782480565);
INSERT INTO highlights VALUES('23934823_28_3226-3265','23934823',70,'第18章 如何对理性保持理性','他认为，人的任何决策和行动都在主动显示自己的偏好，他创立了“显示偏好”的学说。','3059-3098',NULL,1666030286,1782480565);
INSERT INTO highlights VALUES('23934823_28_3122-3175','23934823',70,'第18章 如何对理性保持理性','肯·宾默尔说，“理性”这个概念本身的定义就很不清晰，在使用上就更模糊了，以至这个词的很多用法是没有意义的。','2955-3008',NULL,1666030270,1782480565);
INSERT INTO highlights VALUES('23934823_27_969-1030','23934823',68,'第17章 教皇是无神论者吗？','事实上，如果有人把这个顺序颠倒过来反而会被视为疯狂之举。这样做会违背天主教会的教义，因为这会被视为自愿死亡，这是被禁止的。','908-969',NULL,1666029653,1782480565);
INSERT INTO highlights VALUES('23934823_26_4055-4114','23934823',67,'第16章 信仰是一种“风险共担”','信仰的力量并非来自神“显灵”所展现出来的力量，而是取决于信众基于信仰的鼓舞而在其自身的“风险共担”中所表现出来的力量。','3957-4016',NULL,1666029523,1782480565);
INSERT INTO highlights VALUES('23934823_26_2170-2254','23934823',67,'第16章 信仰是一种“风险共担”','他们用铁链自我鞭打，直至伤痕累累。这种自我实施的鞭刑在基督教中也有，信徒们将其视为对基督受难的纪念，中世纪时曾经十分流行，现在只有在亚洲和拉丁美洲的一些地方才能见到了。','2073-2157',NULL,1666029229,1782480565);
INSERT INTO highlights VALUES('23934823_25_4838-4954','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','自由主义者有一个最基本的信仰，其核心就是个人服从于法律而不是服从于权威。其实自由主义者自己都没有意识到的是，他们信仰的其实是一个复杂系统。由于自由主义是一种运动，他们即使没有自己的政党，也仍然可以作为其他政党内部的自由主义派而存在。','4663-4779',NULL,1666028951,1782480565);
INSERT INTO highlights VALUES('23934823_25_3939-4060','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','就像爱德华·吉本所写的那样：（万神教时期的）罗马帝国流行各种宗教，在普通人看来，这些宗教都是真诚的；在哲学家看来，这些宗教都是错误的；在执政官看来，这些宗教都是有用的。因此宽容不仅仅造就了不同教徒之间的相互包容，而且造就了宗教之间的和睦相处。','3765-3886',NULL,1666002984,1782480565);
INSERT INTO highlights VALUES('23934823_25_3284-3351','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','从少数派主导规则中我们看到那些顽固的不容异己的少数派最终会逐渐占据主导地位，碾压曾经宽容他们的人，因此癌症必须在癌细胞转移前得到治疗。','3111-3178',NULL,1666002898,1782480565);
INSERT INTO highlights VALUES('23934823_25_2070-2097','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','而伊斯兰教和犹太教都没有在宗教与世俗之间做明显的隔离。','1897-1924',NULL,1666000679,1782480565);
INSERT INTO highlights VALUES('23934823_25_1894-2069','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','基督教是另一个领域，是“尚未来临的国度”，凡人只有在末世来临时才能进入这个国度。','1721-1761',NULL,1666000672,1782480565);
INSERT INTO highlights VALUES('23934823_25_1356-1417','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','对于早期犹太人来说，宗教是部落事务；对于早期穆斯林来说，宗教是共同价值；对于罗马人来说，宗教是社交活动、典礼仪式和节日狂欢','1183-1244',NULL,1666000568,1782480565);
INSERT INTO highlights VALUES('23934823_25_1064-1124','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','因此和大多数人的认知相反，哲学家并不推崇诡辩和言论技巧，哲学生来就是一种澄清行为，澄清自己的真实意图，澄清语言造成的困惑','891-951',NULL,1666000473,1782480565);
INSERT INTO highlights VALUES('23934823_25_727-810','23934823',66,'第15章 他们提到宗教的时候并不知道自己在说什么','数学家从对象和关系（精确来讲是定义和映射）的角度来考虑问题，法学家和法律思想家从构造的角度考虑问题，逻辑学家用抽象的运算符号考虑问题，而愚蠢的人……则用语言思考问题。','554-637',NULL,1666000394,1782480565);
INSERT INTO highlights VALUES('23934823_24_6108-6143','23934823',64,'第14章 和平，不靠条约，也不靠战争','美国国务院的文员也是如此，这些人不是冒险家和实干家，而是上述学者的学生','6007-6042',NULL,1666000232,1782480565);
INSERT INTO highlights VALUES('23934823_24_4520-4629','23934823',64,'第14章 和平，不靠条约，也不靠战争','大多数历史学家都倾向于前一种方式，而且他们会对数据过度解读和过度拟合。其实在自然科学领域情况也是这样的，前一种方式更容易引起媒体和公众的关注，后者往往吃力不讨好，所以历史学家和国际关系学者落入同样的陷阱也就不足为奇了。','4419-4528',NULL,1665999923,1782480565);
INSERT INTO highlights VALUES('23934823_24_4466-4520','23934823',64,'第14章 和平，不靠条约，也不靠战争','有两种挖掘历史数据的方式，一种是用历史数据来证明一个观点，另外一种是找出反例、特例和异常数据来推翻一个观点。','4365-4419',NULL,1665999770,1782480565);
INSERT INTO highlights VALUES('23934823_24_1918-1970','23934823',64,'第14章 和平，不靠条约，也不靠战争','为了拖垮俄罗斯，美国国务院想方设法地延长叙利亚战争，使之长期化，而实际上这样的做法只是在惩罚叙利亚人民。','1820-1872',NULL,1665982611,1782480565);
INSERT INTO highlights VALUES('23934823_24_951-1034','23934823',64,'第14章 和平，不靠条约，也不靠战争','巴以冲突问题已经持续了70年。就像一个狭小的厨房挤进来太多厨师一样，不仅解决不了问题，而且会让情况变得更糟糕，因为他们中的大多数人从来不必品尝自己做的食物（或者苦果）','853-936',NULL,1665982453,1782480565);
INSERT INTO highlights VALUES('23934823_23_6467-6543','23934823',63,'第13章 经营美德','从早期智人到今天的人类，漫长的进化史告诉我们一定要远离宏观概念，远离抽象事物，远离全球目标，远离那种所谓的社会改造计划，所有这些都只会给社会带来尾部风险','6371-6447',NULL,1665982304,1782480565);
INSERT INTO highlights VALUES('23934823_23_6255-6373','23934823',63,'第13章 经营美德',unistr('第一，不要试图表现美德；\u000a第二，更不要打着美德的旗号从事寻租活动；\u000a第三，你必须自己创业，把自己放到第一线，去开创一项事业。'),'6159-6277',NULL,1665982273,1782480565);
INSERT INTO highlights VALUES('23934823_23_6001-6076','23934823',63,'第13章 经营美德','有些记者把表达自己的观点变成了加入一边倒的媒体大合唱，他们觉得这样做既安全又能体现美德，这根本就不是美德，而是恶行，是个体懦弱和集体霸凌的奇怪混合体。','5906-5981',NULL,1665982256,1782480565);
INSERT INTO highlights VALUES('23934823_23_5441-5508','23934823',63,'第13章 经营美德','美德的最高形式是不受欢迎的。这并不意味着美德本身不受欢迎，而是说实践最高形式的美德往往需要承担风险，并勇敢地披露一个人真实的内心世界。','5346-5413',NULL,1665982171,1782480565);
INSERT INTO highlights VALUES('23934823_23_5173-5243','23934823',63,'第13章 经营美德','从美德的属性来看，我们可以放心地说，美德是牺牲个人狭隘的利益为集体赢得广泛的利益，美德并不仅仅是与人为善和关心他人，美德需要自我利益的牺牲。','5079-5149',NULL,1665982139,1782480565);
INSERT INTO highlights VALUES('23934823_23_3923-3945','23934823',63,'第13章 经营美德','展现自己并不拥有的美德，就是与美德背道而驰。','3831-3853',NULL,1665901087,1782480565);
INSERT INTO highlights VALUES('23934823_23_3760-3844','23934823',63,'第13章 经营美德','投资者查理·芒格曾经说过：“你愿意成为世界上最伟大的情人（却被每个人认为是世界上最糟糕的情人），还是愿意成为世界上最糟糕的情人（却被每个人认为是世界上最伟大的情人）？”','3668-3752',NULL,1665901061,1782480565);
INSERT INTO highlights VALUES('23934823_23_2602-2640','23934823',63,'第13章 经营美德','如果你连自己的行为都不能总结、推广和普及，那么你根本不应该接受普世主义思想。','2512-2550',NULL,1665900214,1782480565);
INSERT INTO highlights VALUES('23934823_23_2482-2513','23934823',63,'第13章 经营美德','如果你的生活与你的理智相冲突，被抛弃的应该是理智，而不是生活。','2392-2423',NULL,1665900153,1782480565);
INSERT INTO highlights VALUES('23934823_23_2372-2439','23934823',63,'第13章 经营美德','没有哪个道德体系会因为其他人没有去救人就允许你对落水者袖手旁观，也没有哪个道德体系会说：“只有当别人也去救那个落水者时，我才会去救人。','2282-2349',NULL,1665900139,1782480565);
INSERT INTO highlights VALUES('23934823_23_1392-1420','23934823',63,'第13章 经营美德','如果一个人不奉行自己宣扬的美德，那么这是极不道德的行为。','1303-1331',NULL,1665900017,1782480565);
INSERT INTO highlights VALUES('23934823_23_1275-1324','23934823',63,'第13章 经营美德','如果一个反对市场体系的人不住在与市场隔绝的佛蒙特州的小屋或阿富汗西北部的山洞里，那么他是不道德的。','1186-1235',NULL,1665900004,1782480565);
INSERT INTO highlights VALUES('23934823_23_632-684','23934823',63,'第13章 经营美德',unistr('斯\u000a巴达立法者吕库古对在斯巴达推行民主制度的建议，做了这样的回应：“先从你自己的家里做起。”'),'550-595',NULL,1665899764,1782480565);
INSERT INTO highlights VALUES('23934823_22_5180-5216','23934823',62,'第12章 事实是真的，新闻是假的','宽容如果成了一项原则，就必定是因为我们的道德体系中某些操守已经被放弃了。','5113-5149',NULL,1665899749,1782480565);
