INSERT INTO highlights VALUES('23934823_22_3347-3383','23934823',62,'第12章 事实是真的，新闻是假的','全行业参与“风险共担”会创造多样性，而不是单一性，从而带来全行业的繁荣。','3281-3317',NULL,1665899257,1782480565);
INSERT INTO highlights VALUES('23934823_21_3533-3562','23934823',61,'第11章 行胜于言','在政治领域，你应该多付点儿钱“让它看起来不像是一场意外”。','3441-3470',NULL,1665898778,1782480565);
INSERT INTO highlights VALUES('23934823_21_616-692','23934823',61,'第11章 行胜于言',unistr('最\u000a好让你的敌人在你的控制下参与到他的“风险共担”中去，你要让他知道是你制定了斗争规则，并且还要让他知道他之所以还活着，完全是因为你的仁慈。'),'534-603',NULL,1665898697,1782480565);
INSERT INTO highlights VALUES('23934823_22_1231-1313','23934823',62,'第12章 事实是真的，新闻是假的','我们只有一个地球，经不起试错，所以我认为与其针对地球大气层引进一个新的未经验证的保护机制，不如建立一个让那些污染环境（或者大量排放新合成物质）的人承担尾部风险的机制','1166-1248',NULL,1665895111,1782480565);
INSERT INTO highlights VALUES('23934823_21_5699-5786','23934823',61,'第11章 行胜于言','过去，坏事只会传播给知道如何正确看待事物的熟人。如今，无法完整而正确判断别人性格的陌生人摇身一变，成了网络上的道德警察。网络羞辱比过去的声誉抹黑更强大，而且有更多的尾部风险。','5605-5692',NULL,1665859309,1782480565);
INSERT INTO highlights VALUES('23934823_21_4357-4388','23934823',61,'第11章 行胜于言','蒙斯特伯爵对俄罗斯政体做过一个精辟的总结：“暗杀缓和了专制。”','4264-4295',NULL,1665859087,1782480565);
INSERT INTO highlights VALUES('23934823_20_3347-3381','23934823',60,'第10章 只有富人受害：其他人的偏好','人们需要平等，起码在聊天的时候应该保持平等，否则任何谈话都难以为继。','3246-3280',NULL,1665857741,1782480565);
INSERT INTO highlights VALUES('23934823_20_3194-3299','23934823',60,'第10章 只有富人受害：其他人的偏好','在任何情况下，你如果有了钱之后还想拥有朋友，就一定要隐瞒你的富有。这一点可能人人都知道，还有一点不太广为人知但同样重要的是，你还需要隐藏你的博学和知识。只有当人们不试图去攀比和超越对方的时候，他们才会成为朋友。','3093-3198',NULL,1665857729,1782480565);
INSERT INTO highlights VALUES('23934823_19_10442-10569','23934823',59,'第9章 外科医生看起来应该不像外科医生','一个人要靠一张体面的大学文凭才能在生活中出人头地，这无异于绑架一个年轻人的前途，然后对其父母进行敲诈勒索。我们有证据表明，社会进步并非是由高水平的教育机构推动的，恰恰相反，一个国家的教育水平是由居民财富水平决定的（从这个意义上讲，教育就是一种奢侈的消费）','10265-10392',NULL,1665840001,1782480565);
INSERT INTO highlights VALUES('23934823_19_6893-6950','23934823',59,'第9章 外科医生看起来应该不像外科医生','接球手的动作就好像他已经解出了描写棒球运动轨迹的微分方程。在其潜意识层面，一定有一个等同于数学计算的机制在起作用。','6720-6777',NULL,1665825543,1782480565);
INSERT INTO highlights VALUES('23934823_19_2678-2785','23934823',59,'第9章 外科医生看起来应该不像外科医生','一章的主题是林迪兼容效应，拉丁谚语说过，“别以为好看的苹果会更好吃”，这句话有另外一个更广为人知的版本，“会发光的并不都是金子”——消费者花了半个世纪才明白这一点。即便如此，他们也还是会继续被产品美观的外形所吸引。','2509-2616',NULL,1665824381,1782480565);
INSERT INTO highlights VALUES('23934823_19_1312-1433','23934823',59,'第9章 外科医生看起来应该不像外科医生','如果一个人看起来不像是干这一行的，却又在这一行干了很长时间，这说明他需要比别人克服更多的困难，这种困难来自病人以貌取人的天然倾向带给他的不信任感，他一定是用卓越的医术成功地扭转了别人对自己不利的第一印象，否则他早就被淘汰了，根本干不了这么久。','1144-1265',NULL,1665824199,1782480565);
INSERT INTO highlights VALUES('23934823_18_12994-13078','23934823',57,'第8章 一个叫林迪的专家','希尼斯：“可您现在已经在享受生活了，为什么还要去冒险呢？”蒙田在这个故事的结尾引用了卢克莱修的哲学长诗《物性论》中的一句话：“人类无休止地折腾自己以期过上安宁的日子。”','12891-12975',NULL,1665768830,1782480565);
