INSERT INTO highlights VALUES('23934823_14_2606-2660','23934823',52,'第4章 别人为你承担风险','一个人在道德困境中无法做出符合道德标准的决定，当你做出决定时，你家人的利益和社会公众的利益不能处于矛盾状态。','2513-2567',NULL,1665585828,1782480565);
INSERT INTO highlights VALUES('23934823_14_2379-2445','23934823',52,'第4章 别人为你承担风险','大公司喜欢招募成了家的员工，这已经不是秘密了。像这种承担家庭责任的员工很容易控制，如果他们还被一大笔房贷压得喘不过气来，那就更好了。','2286-2352',NULL,1665585789,1782480565);
