INSERT INTO highlights VALUES('23934823_13_13959-14211','23934823',51,'第3章 如何合法地控制他人','普京让我明白驯化的（还有绝育的）动物没有机会对抗野生捕食者，绝对没机会！这事儿和军事实力无关：重要的是推动决策的生物本能。','13787-13848',NULL,1665557221,1782480565);
INSERT INTO highlights VALUES('23934823_13_13850-13930','23934823',51,'第3章 如何合法地控制他人','和老板谈生意要比和雇员谈判容易得多，后者根本不知道自己明年是否还在这个岗位上。同理，人们更容易相信大权在握的专制者，而不是由选举产生的、四处受到掣肘的行政官员。','13678-13758',NULL,1665557218,1782480565);
INSERT INTO highlights VALUES('23934823_13_13189-13237','23934823',51,'第3章 如何合法地控制他人','在上述体制中，那些高高在上的公众人物其实是被体制控制的奴隶，他们要面对的往往是专制制度下的君主。','13017-13065',NULL,1665457860,1782480565);
INSERT INTO highlights VALUES('23934823_13_10654-10717','23934823',51,'第3章 如何合法地控制他人','交易员和销售员只有在不能给公司带来利润的时候才变得温顺，愿意接受规章制度的管理，但是当发生这种情况的时候，公司已经不需要他们了','10484-10547',NULL,1665367580,1782480565);
