INSERT INTO highlights VALUES('23934823_13_10417-10460','23934823',51,'第3章 如何合法地控制他人','因为公司试图通过规范化的管理隔离销售员和客户，使得公司的业务不再依赖于销售员的个人魅力','10247-10290',NULL,1665367543,1782480565);
INSERT INTO highlights VALUES('23934823_13_9754-9788','23934823',51,'第3章 如何合法地控制他人','你天然会捍卫属于你的东西，但只有你能够捍卫的东西，它们才真正属于你。','9585-9619',NULL,1665335966,1782480565);
