INSERT INTO highlights VALUES('23934823_13_9391-9431','23934823',51,'第3章 如何合法地控制他人','。享有自由是以承担风险为代价的，这是“风险共担”的真谛——自由从来都不是免费的。','9222-9262',NULL,1665335835,1782480565);
INSERT INTO highlights VALUES('23934823_13_8550-8649','23934823',51,'第3章 如何合法地控制他人','就足以让他对这种生活上瘾。他比当地人挣的工资要高很多，他的地位类似于生活在殖民地时期等级社会中的那种优越的顶层。他只和其他公司的外派人员建立社交关系，他在当地待的时间越长，他就越希望可以永远待下去。','8382-8481',NULL,1665335756,1782480565);
INSERT INTO highlights VALUES('23934823_13_7425-7479','23934823',51,'第3章 如何合法地控制他人','科斯其实离“风险共担”的概念仅有一步之遥，他未能从风险管理的角度来考虑雇用公司正式员工也是一种风险管理策略。','7259-7313',NULL,1665335599,1782480565);
INSERT INTO highlights VALUES('23934823_13_7259-7285','23934823',51,'第3章 如何合法地控制他人','但是在公司内部，市场传递信息和配置资源的力量被削弱了','7093-7119',NULL,1665335560,1782480565);
INSERT INTO highlights VALUES('23934823_13_7039-7208','23934823',51,'第3章 如何合法地控制他人','科斯认为，如果一个公司把全部业务外包给承包商，并且通过合同维持上下游供应链关系，每笔交易的磋商、议定和执行的法律成本和商务成本就会很高，这最终会侵蚀公司的利润。解决这个问题的方法是雇用员工，由岗位职责明确的员工来处理每一笔交易，这样你就用每月固定的薪酬代替了每笔交易的法律和商务成本（只要你的交易达到一定规模，你这样做就能实现更高的利润）','6873-7042',NULL,1665335535,1782480565);
INSERT INTO highlights VALUES('23934823_13_6897-6927','23934823',51,'第3章 如何合法地控制他人','科斯定理，严谨地证明了市场在资源分配和污染物处理方面的有效性','6731-6761',NULL,1665335492,1782480565);
INSERT INTO highlights VALUES('23934823_13_4741-4795','23934823',51,'第3章 如何合法地控制他人','在公司待的时间越长，他在工作中投入的感情就会越多，在离开公司的时候，就会有一种自发的荣誉感推动他“光荣隐去”','4576-4630',NULL,1665313701,1782480565);
INSERT INTO highlights VALUES('23934823_13_1775-1912','23934823',51,'第3章 如何合法地控制他人','其实每个机构都希望其成员失去一部分自由，只有这样才能把人“组织”起来。那么你用什么办法才能把人“组织”起来呢？第一，以培训的名义对他们进行心理操纵。第二，把他们拧在一起，让他们在某种程度上参与“风险共担”，和公司共担风险；让他们明白如果不服从组织权威，就会失去某些重要的东西','1612-1749',NULL,1665313338,1782480565);
INSERT INTO highlights VALUES('23934823_12_19617-19669','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','革命，毫无疑问是由偏执的少数派推动的，整个社会的进步，无论是在经济还是道德层面上，都源于一小部分人的推动','19456-19508',NULL,1665313086,1782480565);
INSERT INTO highlights VALUES('23934823_12_19259-19380','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位',unistr('一头狮子就够了\u000a亚历山大大帝曾经说过，一头狮子带领的一群羊要比一只羊带领的一群狮子战斗力强得多。亚历山大（或者那个真正总结了这句谚语的人）理解那些狂热、偏执、积极和勇敢的少数派的价值。'),'19098-19219',NULL,1665313037,1782480565);
INSERT INTO highlights VALUES('23934823_12_19064-19146','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','科学探索其实是一个由少数派主导的过程。科学并不是科学家思想的总和，而是如市场一样，充满了固执的偏见，一旦某领域的真相被揭示以后，我们才突然发现我们以前掌握的都是错的','18904-18986',NULL,1665312991,1782480565);
INSERT INTO highlights VALUES('23934823_12_18719-18737','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','市场像一个巨大的电影院，但出口很窄。','18559-18577',NULL,1665312889,1782480565);
INSERT INTO highlights VALUES('23934823_12_18445-18527','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','全球股市的总市值大约是30万亿美元，但是在2008年，仅仅500亿美元的交易，还不到总市值的2‰，就导致全球股票市值下跌了10%，由此给投资人造成了3万亿美元的损失','18285-18367',NULL,1665312855,1782480565);
INSERT INTO highlights VALUES('23934823_12_18285-18338','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','市场不是全体参与者的总和，市场价格变动仅仅是由其中最积极的买方和卖方驱动的。是的，就是由他们这些人决定的。','18125-18178',NULL,1665312814,1782480565);
INSERT INTO highlights VALUES('23934823_12_17819-17839','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','怀疑主义依据其本身的定义并不排斥被怀疑，','17660-17680',NULL,1665312655,1782480565);
INSERT INTO highlights VALUES('23934823_12_15860-15933','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','而且这些道德规则都有共同的特点，即执行起来非黑即白、二元对立（要么是“0”，要么是“1”），没有灰色地带（用数学语言来说就是离散的，而不是连续的）','15702-15775',NULL,1665311494,1782480565);
INSERT INTO highlights VALUES('23934823_12_15626-15673','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','纵观人类社会发展史，你会发现某些道德规则是普遍存在的，当然在不同历史时期或不同地区之间略有差异','15468-15515',NULL,1665311464,1782480565);
INSERT INTO highlights VALUES('23934823_12_15777-15811','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','随着时代的发展和进步，我们发现这些道德规则也在不断地向普世化方向演进','15619-15653',NULL,1665311462,1782480565);
INSERT INTO highlights VALUES('23934823_12_14977-15116','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','所以，道德标准一旦被建立起来，只需要满足几个条件就足以在全社会维护整个道德体系：（1）极小部分人对道德禁止的事情极为厌恶，对道德提倡的事情极为热衷；（2）这一小部分约占总人口的3%~4%；（3）这部分人永不妥协，极为固执；（4）这部分人平均分布在社会的各个阶层和国家的各个地区。','14820-14959',NULL,1665292611,1782480565);
INSERT INTO highlights VALUES('23934823_12_14455-14567','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','我们由此可以推断当今社会的道德并非是由大多数人的共识演变而来的，而是由社会中那些最顽固的少数派把他们所推崇的道德强加给了社会，又因为少数派的极端不容忍，最终成了全社会普遍接受的美德。同样，公民权利也是通过这样的途径争取来的。','14298-14410',NULL,1665292424,1782480565);
INSERT INTO highlights VALUES('23934823_12_13489-13523','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','这种做法的结果就是每次出现的新教派往往都是比现有教派更不宽容的派系。','13334-13368',NULL,1665292181,1782480565);
INSERT INTO highlights VALUES('23934823_12_13206-13295','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','通过关注和研究地中海地区的宗教，或者干脆研究这一地区人们的礼仪、行为和信仰的历史变迁，我们发现这一演变过程实际上由一些最不宽容的少数派主导着，直至演变成我们今天看到的各种宗教。由','13051-13140',NULL,1665292143,1782480565);
INSERT INTO highlights VALUES('23934823_12_12411-12537','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','其实，早期罗马帝国针对基督徒采取的宗教迫害主要起因是基督徒不能容忍罗马万神教的其他神，而不是因为万神教不容忍基督教。但是我们今天读到的历史绝大多数讲的都是基督徒无辜受迫害的故事，相反的记载却很少见。毕竟我们读的历史书是基督教徒，而不是罗马万神教徒写的。','12256-12382',NULL,1665250396,1782480565);
INSERT INTO highlights VALUES('23934823_12_10907-11161','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','第一，依据穆斯林法律，如果一个非穆斯林男人娶了一个穆斯林女人为妻，那么他必须改信伊斯兰教，而且只要新生儿的父母中有一方是穆斯林，那么小孩就要成为穆斯林；￼第二，成为穆斯林是一件不可逆的事情，因为在伊斯兰教法中叛教是最重的罪行，会被判处死刑','10752-11006',NULL,1665250149,1782480565);
INSERT INTO highlights VALUES('23934823_12_10232-10304','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位',unistr('基因遵循多数派主导的规律，语言则遵循少数派主导的规则。\u000a语言行走四方，基因落地生根。'),'10078-10150',NULL,1665208423,1782480565);
INSERT INTO highlights VALUES('23934823_12_6194-6230','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','因为，沉溺于抽象思维不仅会让人头脑变得迟钝，而且会让人举止失态、相貌丑陋','6002-6038',NULL,1665115049,1782480565);
INSERT INTO highlights VALUES('23934823_12_5633-5698','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','再举一个例子。不要以为自动挡汽车的普及是因为多数人喜欢开自动挡汽车，真正的原因是会开手动挡的人也一定会开自动挡的汽车，反之则不然。','5442-5507',NULL,1664992131,1782480565);
INSERT INTO highlights VALUES('23934823_12_4995-5095','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','他们应该意识到，接受转基因食品的人会接受非转基因食品，反之则不然。因此，只要有不超过5%的不接受转基因食品的人均匀地分布在全国，他们就会迫使其所在的群体逐步演变成只吃非转基因食品的群体。怎么会这样呢？','4804-4904',NULL,1664991739,1782480565);
INSERT INTO highlights VALUES('23934823_12_2669-2709','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','遵纪守法的老实人永远都不会触犯刑法，但罪犯在一生的大部分时间中都在做合法的事情。','2477-2517',NULL,1664991110,1782480565);
INSERT INTO highlights VALUES('23934823_12_1292-1378','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','其实在很多事情中，都有少数派主导规则存在：那一小部分人绝不轻易妥协，而且又品德高尚，他们凭着勇气参与到“风险共担”中，他们的抗争和坚持使得社会（作为一个整体系统）运转良好。','1101-1187',NULL,1664990932,1782480565);
INSERT INTO highlights VALUES('23934823_12_993-1083','23934823',49,'第2章 最不宽容者获胜：顽固少数派的主导地位','在任何一个群体中，只要有3%~4%永不妥协的少数派，他们就会全身心地投入“风险共担”，捍卫自己的切身利益（有时候甚至拿灵魂来捍卫），最终，整个群体的人都会服从于少数派的偏好和选择。','802-892',NULL,1664990847,1782480565);
INSERT INTO highlights VALUES('23934823_11_17224-17307','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','然而，监管者没有参与其中，他们才是医疗体系运转不畅的罪魁祸首。整个地球现在到处都是监管者，在任何一个行业、任何一项事业、任何一个历史时期中，监管者从来都是灾难的根源。','17037-17120',NULL,1664990769,1782480565);
INSERT INTO highlights VALUES('23934823_11_14899-15020','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','本书的一个观点是，市场操纵以及利益冲突相较于给别人糟糕的投资建议而自己又免责而言，前者对社会的危害更小。其主要原因在于一旦记者被排除在“风险共担”之外，为了保险起见，他们就会照搬其他记者的观点，这就会形成单一思维和集体臆想，由此加剧市场动荡。','14713-14834',NULL,1664880245,1782480565);
INSERT INTO highlights VALUES('23934823_11_12112-12195','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','“风险共担”对群体的定义是：某空间内存在一种机制，即别人会以你对待他们的方式对待你；该空间内还普遍存在一个规范，即个体奉行银律之“己所不欲勿施于人”的戒条来对待他人。','11929-12012',NULL,1664879853,1782480565);
INSERT INTO highlights VALUES('23934823_11_11580-11660','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','在集体主义原则下，人们不会全力以赴地努力工作，因为他们很难实现个人利益。但是，如果你认为在私有产权制度之下，个人和集体就能运转良好，那么也绝对是一个严重的错误。','11397-11477',NULL,1664879739,1782480565);
INSERT INTO highlights VALUES('23934823_11_11125-11149','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','道德自其诞生之日起，就基于“本地化”的社会关系。','10943-10967',NULL,1664867579,1782480565);
INSERT INTO highlights VALUES('23934823_11_10026-10078','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','干涉主义者最愚蠢之处就是他们总是谴责别人秉持“教派”观念，而不能意识到这其实是人们固有的“部落”归属感。','9844-9896',NULL,1664867483,1782480565);
INSERT INTO highlights VALUES('23934823_11_9129-9171','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','即使在以贪婪自私著称的投资银行高盛，由于合伙人体系的存在，其内部竟然像共产主义社会。','8947-8989',NULL,1664867348,1782480565);
INSERT INTO highlights VALUES('23934823_11_8109-8133','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','那些同情关心陌生人的人，对自己的亲友却冷酷无情。','7928-7952',NULL,1664867199,1782480565);
INSERT INTO highlights VALUES('23934823_11_5986-6101','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','“加拉尔”￼（gharar）原则','5806-5921',NULL,1664861173,1782480565);
INSERT INTO highlights VALUES('23934823_11_5535-5597','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','我们并不一定要通过更强的监管来要求卖方披露更多信息，侵权法以及买家对卖家欺诈行为的追溯，迫使卖家自觉地提升了产品信息的透明度','5355-5417',NULL,1664861112,1782480565);
INSERT INTO highlights VALUES('23934823_11_3308-3457','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','罗马人早就洞悉了这一点，他们说：如果一个人拼命赞美某商品，那么他一定急于卖掉它。','3130-3170',NULL,1664860647,1782480565);
INSERT INTO highlights VALUES('23934823_11_1076-1159','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','墨丘利很快察觉到这些渔民其实只是想摆脱自己并不需要的食物，于是他起身命令这些渔民把海龟肉全部吃掉。由此，墨丘利制定了一条规则，那就是“想让别人吃什么，你自己先得吃”。','899-982',NULL,1664860250,1782480565);
INSERT INTO highlights VALUES('23934823_11_970-1009','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','在罗马神话中，墨丘利不辞辛劳地担任信使，因此他的名字就用天上运转最快的水星命名','793-832',NULL,1664860200,1782480565);
INSERT INTO highlights VALUES('23934823_11_749-873','23934823',47,'第1章 为什么每个人都必须吃掉自己捕到的海龟：不确定条件下的公平性问题','你如果抓到海龟，最好就自己吃掉它。','572-589',NULL,1664860174,1782480565);
INSERT INTO highlights VALUES('23934823_10_3873-3926','23934823',45,'不确定性的共同基因','把一本书读两遍的收获要远大于读两本不同的书，这就是“非线性凸性效应”（前提当然是这本书的内容是有深度的）。','3725-3778',NULL,1664859330,1782480565);
INSERT INTO highlights VALUES('23934823_10_3321-3380','23934823',45,'不确定性的共同基因','我终于意识到了我最厌恶的事情并不是普通人听不懂我的话（无非是对牛弹琴），而是被迫听专家对着我胡说（一群牛对着我弹琴）。','3174-3233',NULL,1664859283,1782480565);
INSERT INTO highlights VALUES('23934823_9_25977-26020','23934823',44,'对称性','从这个意义上来说，分散化和碎片化除了可以稳定系统以外，还可以增强人们与劳动之间的关系。','25869-25912',NULL,1664858786,1782480565);
INSERT INTO highlights VALUES('23934823_9_25187-25450','23934823',44,'对称性','如果把目光局限于经济利益，我们就无法理解为什么人们会有动机去追求其他方面的利益。这是因为人的诉求有许多方面，不仅只有经济利益。','25079-25142',NULL,1664858706,1782480565);
INSERT INTO highlights VALUES('23934823_9_24070-24116','23934823',44,'对称性','你在书本中学到的勇气并不会使你变得勇敢，就像吃牛肉不会让你变得像牛那样蠢一样，两者是一个道理','23962-24008',NULL,1664858412,1782480565);
INSERT INTO highlights VALUES('23934823_9_19771-19814','23934823',44,'对称性','还有另外一种尊严：和其他人一起参与到“风险共担”中去，并甘愿为共同的事业牺牲自己的利益','19664-19707',NULL,1664854703,1782480565);
INSERT INTO highlights VALUES('23934823_9_18968-19024','23934823',44,'对称性','我对成功的定义就是过上一种挺直脊梁充满荣誉感的有尊严的生活，绝对不能让别人替我们去承担由我们的错误所造成的损失。','18861-18917',NULL,1664854609,1782480565);
INSERT INTO highlights VALUES('23934823_9_18904-18931','23934823',44,'对称性','如果你不能为自己的言论承担后果，那么你等于什么都没说。','18797-18824',NULL,1664854601,1782480565);
INSERT INTO highlights VALUES('23934823_9_18465-18566','23934823',44,'对称性','尽管监管体系可以为社会带来一小部分净收益，但是我还是希望选择法律体系而不是监管体系。只有这样，我才能尽可能地保持我的自由，但是我会履行作为公民的责任，接受命运的安排，如果我伤害了别人，我就应该接受惩罚。','18359-18460',NULL,1664817451,1782480565);
INSERT INTO highlights VALUES('23934823_9_17818-17863','23934823',44,'对称性','那就是把“风险共担”置于《合同法》的保护下进行，未能如约履行责任的一方将会受到法律的惩罚。','17712-17757',NULL,1664817299,1782480565);
INSERT INTO highlights VALUES('23934823_9_17676-17749','23934823',44,'对称性','总有寄生虫会从监管措施中获利。商人会利用政府，通过保护性监管和设置行业门槛使自己的生意获利。这种机制被称为“监管套利”，这种做法违背了监管的初衷。','17570-17643',NULL,1664817290,1782480565);
INSERT INTO highlights VALUES('23934823_9_17134-17232','23934823',44,'对称性','它完全是一个“任由书呆子制造更多书呆子”的体系。如果我们把数学变成和孩子们自身兴趣和利益切身相关的事情，他们中的很多人就会爱上数学，长大以后会自觉地运用数学方法，并及时发现数学在哪些领域被滥用了。','17028-17126',NULL,1664816444,1782480565);
INSERT INTO highlights VALUES('23934823_9_14435-14521','23934823',44,'对称性','招供）。但是，演讲者大多数并没有意识到自己注意力不集中，这是因为他们在讲台上被灯光照射的缘故，或者说真正的原因是做大型演讲的演讲者不干灯光工作，而灯光工程师又不做大型演讲。','14329-14415',NULL,1664633955,1782480565);
INSERT INTO highlights VALUES('23934823_9_13049-13121','23934823',44,'对称性','唯智主义者认为，行为与结果可以相互分离，理论与实践可以完全割裂，他们甚至还认为建立一套严格的等级制度就可以用程序化的方法解决一个复杂系统的问题。','12943-13015',NULL,1664633692,1782480565);
INSERT INTO highlights VALUES('23934823_9_12394-12460','23934823',44,'对称性','“风险共担”总体来说是必需的，但是我们也不要教条地将其应用到日常生活的所有事情上去，如果后果不严重，我们就完全可以忽略“风险共担”。','12289-12355',NULL,1664616240,1782480565);
INSERT INTO highlights VALUES('23934823_9_11834-12123','23934823',44,'对称性',unistr('所谓理性就是首先保证自己所在的集体生存更长时间。\u000a很多不严谨的心理学或社会科学书籍中声称的“理性”，其实根本就不是那回事。'),'11729-11818',NULL,1664616171,1782480565);
INSERT INTO highlights VALUES('23934823_9_9911-10008','23934823',44,'对称性','一方面，人的想法其实和他实际的行动之间并无多大关联，因此你要避免掉到含混不清的心理学陷阱里面。人们总会为自己的行为辩解，其实那不过是他们自己编织的自圆其说的故事罢了，它和科学方法并没有什么关系。','9806-9903',NULL,1664615945,1782480565);
INSERT INTO highlights VALUES('23934823_9_7889-7931','23934823',44,'对称性','关于银律（我再次提醒读者一下，银律是“己所不欲勿施于人”），还存在下面一种表达方法：','7784-7826',NULL,1664615299,1782480565);
INSERT INTO highlights VALUES('23934823_9_7962-8001','23934823',44,'对称性','不要听从那些以咨询谋生的人给你的建议，除非他们会为自己提供的错误咨询接受惩罚。','7857-7896',NULL,1664615293,1782480565);
INSERT INTO highlights VALUES('23934823_9_6269-6328','23934823',44,'对称性','但糟糕的是，凡是笼统的、抽象的和普世的东西总是能够吸引那些自以为是的精神病人，他们与前文中提到的干涉主义者是一伙儿的。','6164-6223',NULL,1664615123,1782480565);
INSERT INTO highlights VALUES('23934823_9_6010-6036','23934823',44,'对称性','普世性的行为在书本上是伟大的，但在实际中是灾难性的。','5905-5931',NULL,1664615064,1782480565);
INSERT INTO highlights VALUES('23934823_9_5612-5883','23934823',44,'对称性','伊曼纽尔·康德的“道德律”￼。我将其简化为：“如果其他人在相同条件下也会做出相同行为，那么你就去做吧！”康德还说：“对待自己一如对待他人，这不应该成为你做人的手段，而应该是你作为人的目的。”','5507-5778',NULL,1664613497,1782480565);
INSERT INTO highlights VALUES('23934823_9_5376-5473','23934823',44,'对称性','民主制度面对的最大威胁是，以某些言论可能伤害他人为由，试图去限制这些言论。这种趋势一旦形成，就会使民主滑向深渊。这些限制并非都来自国家，也有可能来自用媒体引导舆论的“思想警察”所建立的强权文化。','5271-5368',NULL,1664613462,1782480565);
INSERT INTO highlights VALUES('23934823_9_4136-4233','23934823',44,'对称性','首先，它告诫你管好自己的事情，不要替他人决定什么对他有利（即金律没有排除这样一种逻辑可能：你单方面把你误以为对他有利的事情强加给了对方）。事实上，相对于判断什么是有利的，我们更清楚什么是不利的。','4031-4128',NULL,1664609121,1782480565);
INSERT INTO highlights VALUES('23934823_8_9300-9331','23934823',43,'安泰俄斯之死','“风险共担”用淘汰傲慢自大者的办法，约束了人类的傲慢自大倾向。','9153-9184',NULL,1664513872,1782480565);
INSERT INTO highlights VALUES('23934823_8_8592-8686','23934823',43,'安泰俄斯之死','一般来说，人们越崇尚所谓的神圣不可侵犯的国家（或者同样神圣的大公司），他们就越讨厌“风险共担”；人们越相信自己的预测能力，就越讨厌“风险共担”；越是喜欢西装革履的人，就越讨厌“风险共担”。','8445-8539',NULL,1664513849,1782480565);
INSERT INTO highlights VALUES('23934823_8_8397-8412','23934823',43,'安泰俄斯之死','没有“风险共担”，就没有进化。','8250-8265',NULL,1664513764,1782480565);
INSERT INTO highlights VALUES('23934823_8_8040-8071','23934823',43,'安泰俄斯之死','或者说得再准确一点，现实并不在乎对错和输赢，生存才是最重要的。','7893-7924',NULL,1664513707,1782480565);
INSERT INTO highlights VALUES('23934823_8_7987-8011','23934823',43,'安泰俄斯之死','你永远无法说服一个人他错了，只有现实才能教育他。','7840-7864',NULL,1664513703,1782480565);
INSERT INTO highlights VALUES('23934823_8_7864-7919','23934823',43,'安泰俄斯之死','那个允许银行家向普通人转嫁风险的体系，就是那个阻止监管者亲历“风险共担”并学会真知的体系，这两者是同一个体系。','7717-7772',NULL,1664513700,1782480565);
INSERT INTO highlights VALUES('23934823_8_5898-5944','23934823',43,'安泰俄斯之死','在一个由官僚，而不是贵族主导的体系中，一个人的行为和他本来需要为此承担的后果被轻易地分开了。','5752-5798',NULL,1664480944,1782480565);
INSERT INTO highlights VALUES('23934823_8_4528-4565','23934823',43,'安泰俄斯之死','我们一直都很疯狂，但过去我们没有足够的力量去摧毁这个世界，而现在我们有了。','4384-4421',NULL,1664480245,1782480565);
INSERT INTO highlights VALUES('23934823_8_3487-3524','23934823',43,'安泰俄斯之死','即人们如果对后果不是很有把握，就不应该触碰、干涉或者阻止一个复杂系统的运行','3343-3380',NULL,1664480069,1782480565);
INSERT INTO highlights VALUES('23934823_8_2713-2795','23934823',43,'安泰俄斯之死','他们有三个缺陷：（1）他们只考虑静止的状态，而不考虑动态的机制；（2）他们的思考是低维度而非高维度的；（3）他们只想到了采取什么行动，而没有想到行动本身会有反作用。','2570-2652',NULL,1664479965,1782480565);
INSERT INTO highlights VALUES('23934823_8_1149-1221','23934823',43,'安泰俄斯之死','希腊谚语说：“Pathemata mathemata”（直译为：在痛苦中学习），意即学习知识必然是痛苦的，因为你只有在痛苦的实践中才能学到东西。','1007-1079',NULL,1664479724,1782480565);
INSERT INTO highlights VALUES('23934823_7_3782-3836','23934823',42,'第一卷 绪论','对于市场参与者来说，“风险共担”意味着你必须坚信“实践出真知”，而且“实践是获得真理和获悉真相的唯一途径”。','4441-4495',NULL,1664455182,1782480565);
INSERT INTO highlights VALUES('23934823_7_3682-3753','23934823',42,'第一卷 绪论','对于我个人而言，到市场上去亲历“风险共担”，意味着我将体验到：人类的正义理想、个人的荣誉感、自我牺牲精神，以及其他事关人类生存的最宝贵的品质。','4341-4412',NULL,1664455140,1782480565);
INSERT INTO highlights VALUES('23934823_7_1699-1775','23934823',42,'第一卷 绪论','如果你想获得回报，你就必须承担风险，而不是让别人替你承担损失。如果你把风险强加给别人，你就必须给他们一定的补偿，你对待他们必须像你希望被他们对待的那样。','2358-2434',NULL,1664454866,1782480565);
INSERT INTO highlights VALUES('23934823_6_1251-1311','23934823',41,'译序','这让我想起达特茅斯学院工程学大楼入口处的格言：为最困难的任务准备最负责任的肩膀（并没有提到最聪明的头脑和最复杂的模型）。','1219-1279',NULL,1664453085,1782480565);
INSERT INTO highlights VALUES('23934823_6_993-1077','23934823',41,'译序','人类学研究表明，人类的决策过程主要是由激素推动的。知识、经验和理智在这个过程中所起的作用并不大，我们往往是在做出决定之后，再用智慧去寻找证据以便证明自己的决定是正确的。','961-1045',NULL,1664453021,1782480565);
INSERT INTO highlights VALUES('23934823_6_613-655','23934823',41,'译序','他只是认为市场对重大系统性风险的估计严重不足，导致深度价外的看跌期权价格被严重低估，','583-625',NULL,1664452942,1782480565);
INSERT INTO highlights VALUES('23934823_5_3288-3326','23934823',40,'推荐序2 中国视角下的“非对称风险”','不要听从以提建议为谋生手段的人的建议，除非对他们提出的建议有对应的惩罚措施。','3232-3270',NULL,1664452862,1782480565);
INSERT INTO highlights VALUES('23934823_5_2274-2324','23934823',40,'推荐序2 中国视角下的“非对称风险”','在当今的生活中，对称性和互惠性的背离问题并不少见，一个没有风险共担的系统会慢慢积累不平衡，最终垮掉。','2226-2276',NULL,1664451903,1782480565);
INSERT INTO highlights VALUES('23934823_5_1918-1990','23934823',40,'推荐序2 中国视角下的“非对称风险”','所以，一个人的价值、真正受到尊重的程度，取决于他愿意为他人承受多少损失。那些不愿意承担风险，还将他人置于风险之中的人，应该被置于人类金字塔的底部','1874-1946',NULL,1664451868,1782480565);
INSERT INTO highlights VALUES('32764984_31_60380-60480','32764984',44,'3 自我辩护','一位领导人怎样才能避免落入自我辩护的陷阱？历史上的案例告诉我们，走出这个过程的方法是，这位领导人需从他（她）的核心圈子之外引进专业的顾问，因为这些顾问们不会陷入减少领袖早期决策所造成的失调的需要之中。','60402-60502',5,1708759050,1782480560);
INSERT INTO highlights VALUES('32764984_31_55381-55411','32764984',44,'3 自我辩护','为了避免被人认为是伪君子并保持自尊，他们开始践行他们所说的。','55403-55433',5,1708758421,1782480560);
INSERT INTO highlights VALUES('32764984_31_53368-53463','32764984',44,'3 自我辩护','失调理论认为，如果科学家想激励人们立即对全球变暖采取行动，就必须让他们相信，对全球变暖采取行动在他们的掌控之中。仅仅激起人们的恐惧便可能导致他们：要么否认它的存在，要么极力忽视那些科学证据。','53390-53485',5,1708758158,1782480560);
INSERT INTO highlights VALUES('32764984_31_53174-53259','32764984',44,'3 自我辩护','如果这些步骤看来是徒劳的，那么付出努力的前景只会进一步增加我们的失调感。在这种情况下，我们很可能通过否认潜在灾难的可能性或大大低估其严重程度，来为我们不采取安全措施辩护。','53196-53281',5,1708758129,1782480560);
INSERT INTO highlights VALUES('32764984_31_53125-53173','32764984',44,'3 自我辩护','因此，我们所采用策略的性质，可能取决于我们是否相信预防措施会真正提高我们对不可避免事件的控制意识','53147-53195',5,1708758116,1782480560);
INSERT INTO highlights VALUES('32764984_31_52783-52854','32764984',44,'3 自我辩护','对危险和不可避免的事件做出自我辩护的反应，在短期内是令人欣慰的。但是，当这种反应阻止我们采取措施以确保我们的安全时，从长远来看则可能是致命的。','52805-52876',5,1708758057,1782480560);
INSERT INTO highlights VALUES('32764984_31_51917-51970','32764984',44,'3 自我辩护','当一个人得知自己不可避免地要和另一个人呆在一起，会增强那个人积极的一面，或者至少会淡化他（她）消极的一面。','51939-51992',5,1708757978,1782480560);
INSERT INTO highlights VALUES('32764984_31_49581-49654','32764984',44,'3 自我辩护','非人化根植于面对他人不幸时对自己感觉更好的愿望，由此便可以排解人们的厌恶、悲伤、震惊、恐惧等负面感受。受害者的困境促使人们消除对他们的非人化对待。','49603-49676',5,1707667322,1782480560);
INSERT INTO highlights VALUES('32764984_31_49267-49361','32764984',44,'3 自我辩护','他们称之为制度的正当性：许多出生在社会最高阶层、拥有最大财富和权力的人，通过相信他们的优越能力和天生才能来证明这个职位的正当性，而所有那些贫穷和疲于奔命的人都没有能力或者没有动力获得成功。','49289-49383',5,1707667214,1782480560);
INSERT INTO highlights VALUES('32764984_31_47268-47363','32764984',44,'3 自我辩护','具有讽刺意义的是：正是因为我觉得自己是个好人，所以如果我做了什么让别人痛苦的事情，我必须让自己相信这个人是只老鼠。因为像我这样的好人不会到处伤害无辜，所以如果我伤害了你一定是因为你罪有应得。','47290-47385',5,1707666910,1782480560);
INSERT INTO highlights VALUES('32764984_31_45771-45824','32764984',44,'3 自我辩护','理想的情况是，如果我们想测量因失调而导致的态度变化，我们应该知道在引起失调的事件发生之前人们的态度是什么。','45793-45846',5,1707666721,1782480560);
INSERT INTO highlights VALUES('32764984_31_44554-44581','32764984',44,'3 自我辩护','我一再强调，我们需要说服自己：我们是正派、有理智的人。','44576-44603',5,1707666512,1782480560);
INSERT INTO highlights VALUES('32764984_31_42714-42797','32764984',44,'3 自我辩护','如果一个人为了达到某种目标而经历了一段艰难或痛苦的经历，那么这个目标就会变得更有吸引力——这个过程叫做竭力去辩护。','42736-42819',5,1707665313,1782480560);
INSERT INTO highlights VALUES('32764984_31_40633-40715','32764984',44,'3 自我辩护','如果经过努力我们得到了一些东西，那么与那些较为容易得到的东西相比，我们很可能会对之更加喜欢。假如这些东西不那么吸引人，我们可能需要别出心裁地来为我们的努力加以辩护。','40655-40737',5,1707665014,1782480560);
INSERT INTO highlights VALUES('32764984_31_40465-40499','32764984',44,'3 自我辩护','人们会感受到最大的失调。他们感受到的失调越大，态度就越容易发生改变。','40487-40521',5,1707664975,1782480560);
INSERT INTO highlights VALUES('32764984_31_40135-40159','32764984',44,'3 自我辩护','真正有自尊心的年轻人会更有安全感，不会去欺负他人','40157-40181',5,1707664919,1782480560);
INSERT INTO highlights VALUES('32764984_31_38840-38898','32764984',44,'3 自我辩护','如果以人为的或者肤浅的方式来提高自尊心，或者如果一个人的自尊心缺乏现实的基础，那么提升自尊心便不太可能产生积极的效果','38862-38920',5,1707664819,1782480560);
INSERT INTO highlights VALUES('32764984_31_39073-39113','32764984',44,'3 自我辩护','此外，尤为重要的是要将健康的自尊与自恋区分开来，自恋会导致不切实际的浮夸和优越感','39095-39135',5,1707664787,1782480560);
INSERT INTO highlights VALUES('32764984_31_38422-38472','32764984',44,'3 自我辩护','如果高自尊能起到缓冲不诚实行为和促进理想行为的作用，那么尽一切可能帮助个体学会尊重自己似乎是合理的。','38444-38494',5,1707664727,1782480560);
INSERT INTO highlights VALUES('32764984_31_37919-37944','32764984',44,'3 自我辩护','感觉自己低人一等的结果是，这个人会做出低劣的行为。','37941-37966',5,1707664629,1782480560);
INSERT INTO highlights VALUES('32764984_31_37272-37331','32764984',44,'3 自我辩护','我对认知失调理论加以修正的一个最大优点在于，它考虑到了精神病患者和低自尊者的自我概念，由此而提高了该理论预测的准确性。','37294-37353',5,1707217961,1782480560);
INSERT INTO highlights VALUES('32764984_31_36326-36384','32764984',44,'3 自我辩护','当人们的行为方式与他们对自己的高见相反时，他们会经历最大的失调，他们会比那些平均自尊水平的人更加努力地去减少这种失调','36348-36406',5,1707217894,1782480560);
INSERT INTO highlights VALUES('32764984_31_33723-33795','32764984',44,'3 自我辩护','从某种意义上来说，1美元足够诱使被试说谎，但却并不足以防止他们感到愚蠢。为了减少他们愚蠢的感觉，他们不得不减少为了一点点报酬而说谎所造成的失调。','33745-33817',5,1707143818,1782480560);
INSERT INTO highlights VALUES('32764984_31_33514-33567','32764984',44,'3 自我辩护','弗里德曼的严重威胁在抑制后续行为方面并不起作用——而某种轻微的威胁在长达九周后仍然对后续行为有着抑制作用。','33536-33589',5,1707036321,1782480560);
INSERT INTO highlights VALUES('32764984_31_32007-32076','32764984',44,'3 自我辩护','威胁越不严重，外部理由就越少；外部理由越少，对内部理由的需要也就越大。允许人们有机会形成自己的内部理由，可以帮助他们形成一套永久的价值观。','32029-32098',5,1707032346,1782480560);
INSERT INTO highlights VALUES('32764984_31_31048-31150','32764984',44,'3 自我辩护','采用严厉惩罚的威胁作为让某人不做他（她）喜欢做的事情的手段，对此我们需要时刻保持警惕。如果人们能以某种方式享受做有益于自身健康和福利以及他人健康和福利的事情，那么这种做法将更为有效，所需要的约束也会少得多','31070-31172',5,1707032198,1782480560);
INSERT INTO highlights VALUES('32764984_31_30227-30269','32764984',44,'3 自我辩护','与常识不同，认知失调理论会预测，如果受到了一位自己不喜欢的人的邀请，你会更喜欢吃蚱蜢','30249-30291',5,1707032086,1782480560);
INSERT INTO highlights VALUES('32764984_31_26755-26809','32764984',44,'3 自我辩护','内在理由(internal justification)，即通过态度改变来证明自己行为的正当性','26777-26831',5,1707031786,1782480560);
INSERT INTO highlights VALUES('32764984_31_26589-26668','32764984',44,'3 自我辩护','实际上，这类理由是根据具体情境来确定的，我们称之为外在理由(external justification)','26611-26690',5,1707031781,1782480560);
INSERT INTO highlights VALUES('32764984_31_27594-27643','32764984',44,'3 自我辩护','如果你想要一个人改变态度，那么就让他去做出或说出一些与他观点相反的事情，并为此支付给他较低的报酬。','27616-27665',5,1707031550,1782480560);
INSERT INTO highlights VALUES('32764984_31_27521-27553','32764984',44,'3 自我辩护','而那些没有外在理由说谎的人，则朝着相信他们所说的是真实的方向前进','27543-27575',5,1707031528,1782480560);
INSERT INTO highlights VALUES('32764984_31_24627-24663','32764984',44,'3 自我辩护','诱设(entrapment)过程中的态度和行为是如何变化的','24649-24685',5,1707021491,1782480560);
INSERT INTO highlights VALUES('32764984_31_24460-24547','32764984',44,'3 自我辩护','当你到达金字塔底部的时候，你将与那些面临同样的困境但作出不同决定并从相反的方向滑下金字塔的人相距甚远。你会确信自己的决策是绝对正确的，而那些从另一边溜下来的人都是白痴或骗子。','24482-24569',5,1707021482,1782480560);
INSERT INTO highlights VALUES('32764984_31_24370-24460','32764984',44,'3 自我辩护','无论怎样，当你朝着某个方向迈出一步的时候，你总会感受到失调——现在你会被激励为减少失调而去为自己所做的事情辩护。反过来，这样的辩护会让你更难改变主意，即便是在你应该做出改变的时候。','24392-24482',5,1707021444,1782480560);
INSERT INTO highlights VALUES('32764984_31_23922-23969','32764984',44,'3 自我辩护','总体而言，那些作弊的孩子对欺骗变得更加宽容，那些抵制作弊诱惑的孩子对欺骗采取了更加严厉的态度。','23944-23991',5,1707021376,1782480560);
INSERT INTO highlights VALUES('32764984_31_21139-21210','32764984',44,'3 自我辩护','一旦某个决定是不可挽回的，人们便会竭力让自己为所作出的选择感到高兴。由此可见，一旦人们感到已经无能为力，他们便会更加确信自己作出了明智的决定。','21161-21232',5,1706870540,1782480560);
INSERT INTO highlights VALUES('32764984_31_19800-19857','32764984',44,'3 自我辩护','人们对所作选择的隐私或公众能见度的感知会与文化因素相互作用，以确定是否引起了失调、是否需要对选择的合理性作出判断。','19822-19879',5,1706859523,1782480560);
INSERT INTO highlights VALUES('32764984_31_18719-19045','32764984',44,'3 自我辩护','在一些个体主义不明显的社会里，减少失调的行为可能存在更为普遍的形式。￼在这样的文化里，自己的行为让别人感到羞辱或失望，会比为自己的不当行为辩护，更有可能让人们感到失调。','18741-19067',5,1706859481,1782480560);
INSERT INTO highlights VALUES('32764984_31_18499-18527','32764984',44,'3 自我辩护','当一个人面对不一致的信息时，大脑的推理区域实际上被关闭了','18521-18549',5,1706859392,1782480560);
INSERT INTO highlights VALUES('32764984_31_17488-17564','32764984',44,'3 自我辩护','我的朋友问。孩子思考了一会儿说道：“妈妈，那个小女孩不喜欢贴纸。”3岁的孩子已经能够降低失调！她在保留了自己所有贴纸的同时，成功地将自己视为一个好女孩。','17510-17586',5,1706859343,1782480560);
INSERT INTO highlights VALUES('32764984_31_16265-16433','32764984',44,'3 自我辩护','她也许会后悔今天和明天所做的选择，但是很快（以及她的余生）她便会相信自己已经作出了最好的决定。','16287-16334',5,1706859228,1782480560);
INSERT INTO highlights VALUES('32764984_31_15774-15792','32764984',44,'3 自我辩护','减少失调的过程在很大程度上是无意识的','15796-15814',5,1706859127,1782480560);
INSERT INTO highlights VALUES('32764984_31_15536-15603','32764984',44,'3 自我辩护','无论我们谈论的是电器还是恋人，一旦作出了某种坚定的承诺，人们便会倾向于关注自己所做选择的积极方面，而忽略自己所拒绝的其他选择的吸引力。','15558-15625',5,1706805085,1782480560);
INSERT INTO highlights VALUES('32764984_31_15476-15507','32764984',44,'3 自我辩护','简言之，没有威胁，就不会出现失调；没有失调，便不会去贬低他人。','15498-15529',5,1706805054,1782480560);
INSERT INTO highlights VALUES('32764984_31_14210-14292','32764984',44,'3 自我辩护','我们又一次看到了决策所引起的认知失调：对所喜欢的对象的任何负面认知，与选择了它的认知之间会产生失调；对没有选择的对象的正面认知，与没有选择它的认知之间也会产生失调。','14232-14314',5,1706804926,1782480560);
INSERT INTO highlights VALUES('32764984_31_13476-13539','32764984',44,'3 自我辩护','这要归功于社交媒体，人们不必花费过多努力就能获得与他们刚买的车相符的信息，认同他们现在所持有的想法，回避任何与之不相符的信息。','13498-13561',5,1706718237,1782480560);
INSERT INTO highlights VALUES('32764984_31_11974-12005','32764984',44,'3 自我辩护','但我的观点是，当我们需要减少失调时，我们都会做出不理性的行为。','11996-12027',5,1706718056,1782480560);
INSERT INTO highlights VALUES('32764984_31_11255-11666','32764984',44,'3 自我辩护','在类似政治或宗教之类的问题上，不管我们的论点多么有力和公正，那些笃信某种观点的人也几乎不可能按照我们的方式去对事物进行观察。','11277-11339',5,1706717981,1782480560);
INSERT INTO highlights VALUES('32764984_31_10136-10397','32764984',44,'3 自我辩护','失调理论预测人们会记住那些赞同自己观点的似是而非的论点以及赞同对方观点的不可信的论点。','10158-10201',5,1706717853,1782480560);
INSERT INTO highlights VALUES('32764984_31_8546-8618','32764984',44,'3 自我辩护','与邪教成员一样，每当我们感到对宗教、政党、有魅力的领袖或意识形态强烈忠诚的时候，以及当这些忠诚受到事实挑战的时候，我们会提出各种歪曲事实的证据。','8568-8640',5,1706717579,1782480560);
INSERT INTO highlights VALUES('32764984_31_7844-8082','32764984',44,'3 自我辩护','摩根有可能是在撒谎。但我感到他所说的要比撒谎复杂得多。我的猜测是，随着时间的推移，像摩根这样的人开始相信自己的谎言，并试图对自己进行欺骗。','7866-7935',5,1706717500,1782480560);
INSERT INTO highlights VALUES('32764984_31_7356-7396','32764984',44,'3 自我辩护','因此，为了把自己看作是聪明、善良和正确的人，你采取了愚蠢、错误和有害健康的行动。','7378-7418',5,1706717413,1782480560);
INSERT INTO highlights VALUES('32764984_31_6754-6795','32764984',44,'3 自我辩护','相反，他们以不同的方式减少了认知失调：让自己相信吸烟并不像他们最初想象的那么糟糕。','6776-6817',5,1706717340,1782480560);
INSERT INTO highlights VALUES('32764984_31_6961-7003','32764984',44,'3 自我辩护','那些决心戒烟、减肥或锻炼的人最初感觉很糟，但在很短的时间里，便成功地淡化了这种决心。','6983-7025',5,1706717299,1782480560);
INSERT INTO highlights VALUES('32764984_31_4297-4330','32764984',44,'3 自我辩护','人类是这样一种生物，他们一生都在试图说服自己他们的存在不是荒谬的。','4319-4352',5,1706707788,1782480560);
INSERT INTO highlights VALUES('32764984_31_4093-4169','32764984',44,'3 自我辩护','费斯汀格将认知失调描述为一种紧张状态，当一个人简单地持有两种心理上不一致的认知（观念、态度、信仰、观点）时便会发生。两种认知如果相互对立，则是不一致的。','4115-4191',5,1706707750,1782480560);
INSERT INTO highlights VALUES('32764984_31_3893-3906','32764984',44,'3 自我辩护','认知失调理论','3915-3928',5,1706707734,1782480560);
INSERT INTO highlights VALUES('32764984_31_3694-3736','32764984',44,'3 自我辩护','的确，如果说有的话，也是一些令人欣慰的谣言，比如有人预言，水的供应将会在短期内恢复。','3716-3758',5,1706707674,1782480560);
INSERT INTO highlights VALUES('32764984_31_3232-3288','32764984',44,'3 自我辩护','一种解释是，人们非常害怕，但是由于他们缺乏足够的理由来解释这种恐惧，便制造了自己的恐惧，这使他们不至于显得愚蠢。','3254-3310',5,1706707638,1782480560);
INSERT INTO highlights VALUES('32764984_31_2278-2393','32764984',44,'3 自我辩护','我们的许多行为都会受到一些未知因素的支配。之后，当我们被要求解释自己的行为时，我们试图构建出一个有意义的故事，同时满足我们的愿望，让自己和他人看起来都不错。这便是自我辩护的本质。','2300-2415',5,1706707526,1782480560);
INSERT INTO highlights VALUES('32764984_31_2097-2164','32764984',44,'3 自我辩护','人们持有为自己的行为、看法和感觉辩护的动机。当他们做某件事情的时候，如果可能的话，他们会让自己（和其他人）确信这是一件合乎逻辑的事情。','2119-2186',5,1706707505,1782480560);
INSERT INTO highlights VALUES('32764984_30_65896-65974','32764984',43,'2 社会认知','对我个人而言，社会性动物最吸引人的方面就是需要把自己看作是善良的、聪明的、明智的人，以及观察这种需要如何经常导致人们的所做所思既不善良，也不聪明，更不明智。','65918-65996',5,1706672620,1782480560);
INSERT INTO highlights VALUES('32764984_30_65341-65370','32764984',43,'2 社会认知','我们的认知吝啬能够以最小努力和最大效率帮助我们度过每一天。','65363-65392',5,1706672558,1782480560);
INSERT INTO highlights VALUES('32764984_30_65289-65305','32764984',43,'2 社会认知','你自己和这个世界的某种扭曲的画面','65311-65327',5,1706672541,1782480560);
INSERT INTO highlights VALUES('32764984_30_65059-65096','32764984',43,'2 社会认知','回忆本书的最好方法之一就是把它与你的个人经历联系起来，思考它如何适用于你。','65081-65118',5,1706672003,1782480560);
INSERT INTO highlights VALUES('32764984_30_63676-64033','32764984',43,'2 社会认知','我们对自己的过去不一定是在撒谎，只是我们错误地记住了一些与我们的图式相符的东西。','63698-63738',5,1706460096,1782480560);
INSERT INTO highlights VALUES('32764984_30_62128-62176','32764984',43,'2 社会认知','我们的记忆正在经历不断的修正，它们受到其他人告诉我们的有关过去事件的信息、照片和道听途说的影响。','62150-62198',5,1706458468,1782480560);
INSERT INTO highlights VALUES('32764984_30_61966-62099','32764984',43,'2 社会认知','相反，记忆是一个重构的过程。对我们记忆最为强烈的影响不是过去实际发生的事件，而是我们现在对那些事件的思考。我们通过过滤和修改我们的观念重新创造了自己的记忆——可能是什么，应该是什么，或者我们希望事情以何种方式发生。','61988-62121',5,1706458455,1782480560);
INSERT INTO highlights VALUES('32764984_30_61755-61800','32764984',43,'2 社会认知','假如在制定计划时你能够意识到，人们倾向于把未来解释得比现在更美好，你便可能摆脱很多的悲伤。','61777-61822',5,1706458426,1782480560);
INSERT INTO highlights VALUES('32764984_30_59932-60237','32764984',43,'2 社会认知','然而，我们对与自身有关事情的预测经常会大错特错。￼无论是积极的还是消极的，我们都会高估未来发生事件可能带来的情感影响，以及我们所做反应持续的时间。','59954-60259',5,1706458021,1782480560);
INSERT INTO highlights VALUES('32764984_30_57162-57208','32764984',43,'2 社会认知','互联网让人预料不到的一个危险便是，从阴谋论到伪科学的医学建议，只要不停地重复，便会大行其道。','57184-57230',5,1706457781,1782480560);
INSERT INTO highlights VALUES('32764984_30_56989-57085','32764984',43,'2 社会认知','我们对一个声明或想法越熟悉，它越可能对我们发生作用。仅仅是一遍又一遍地听到某种说法、哪怕是最卑鄙的谎言，只要让人们更加熟悉它，便会增加他们的信念——如果某种说法为人们所熟悉，它就一定是真实的。','57011-57107',5,1706457762,1782480560);
INSERT INTO highlights VALUES('32764984_30_56711-56959','32764984',43,'2 社会认知','与说同一件事但不那么恰当的说法相比，押韵的说法或“脱口而出”的说法被认为更加真实。','56733-56774',5,1706457751,1782480560);
INSERT INTO highlights VALUES('32764984_30_55919-55951','32764984',43,'2 社会认知','这就是为什么那些喜欢看犯罪剧和电视新闻的人往往会大大高估犯罪率。','55941-55973',5,1706457700,1782480560);
INSERT INTO highlights VALUES('32764984_30_55738-55754','32764984',43,'2 社会认知','启动效应可以增加我们易得的图像。','55760-55776',5,1706457661,1782480560);
INSERT INTO highlights VALUES('32764984_30_55526-55566','32764984',43,'2 社会认知','但目前的统计数据显示，与死于恐怖袭击相比，人们更有可能被一个蹒跚学步的孩子枪杀。','55548-55588',5,1706457597,1782480560);
INSERT INTO highlights VALUES('32764984_30_55329-55391','32764984',43,'2 社会认知','易得性便捷判断是这样一种倾向，即预测一个事件的可能性，或判断它的风险有多大，根据的是那些容易记起的具体的例子。','55351-55413',5,1706457464,1782480560);
INSERT INTO highlights VALUES('32764984_30_54553-54627','32764984',43,'2 社会认知','代表性便捷式判断 当我们专注于表面相似性进行推论时，我们就是在使用代表性便捷判断。','54575-54649',5,1706457445,1782480560);
INSERT INTO highlights VALUES('32764984_30_54467-54504','32764984',43,'2 社会认知','三种最常见的便捷式判断：代表性便捷式判断、易得性便捷式判断和情感便捷式判断','54489-54526',5,1706457402,1782480560);
INSERT INTO highlights VALUES('32764984_30_53801-53861','32764984',43,'2 社会认知','首因效应并不是不可避免的，特别是当我们被激励去仔细注意的时候。然而，认知的吝啬倾向却意味着第一印象的形成是快速而持久的。','53823-53883',5,1706432740,1782480560);
INSERT INTO highlights VALUES('32764984_30_53612-53670','32764984',43,'2 社会认知','但是，那些被激励会提高自身的猜谜能力的指导者，却将猜谜能力更聪明的评价给予了那些开始时成绩不佳但最终表现良好的指导者','53634-53692',5,1706432716,1782480560);
INSERT INTO highlights VALUES('32764984_30_52112-52170','32764984',43,'2 社会认知','这被称为首因效应，指的是前期获取的信息比后期信息有更大的影响力。','52134-52192',5,1706432577,1782480560);
INSERT INTO highlights VALUES('32764984_30_48990-49026','32764984',43,'2 社会认知','我们可以把别人看作是灵感和知识的源泉，而不是因此而觉得自己存在某种缺憾。','49012-49048',5,1706431646,1782480560);
INSERT INTO highlights VALUES('32764984_30_48952-48985','32764984',43,'2 社会认知','成长心态指的是，人们所持有的对人类成长能力的信念和对自我提升的承诺','48974-49007',5,1706431634,1782480560);
INSERT INTO highlights VALUES('32764984_30_48870-48945','32764984',43,'2 社会认知','我们还可以通过培养卡罗尔·德韦克(Carol Dweck)所谓的成长心态来避免与他人进行痛苦的比较','48892-48967',5,1706431609,1782480560);
INSERT INTO highlights VALUES('32764984_30_48620-48665','32764984',43,'2 社会认知','最幸福的人不是通过关注他人的行为来评价自己，而是通过调整和参考自己的内在成功标准来评价自己','48642-48687',5,1706431595,1782480560);
INSERT INTO highlights VALUES('32764984_30_48561-48588','32764984',43,'2 社会认知','社会比较是不可避免的，它们会不自觉地、轻而易举地出现。','48583-48610',5,1706431585,1782480560);
INSERT INTO highlights VALUES('32764984_30_48020-48035','32764984',43,'2 社会认知','而今不少人患上了“脸书忧郁症”','48042-48057',5,1706431514,1782480560);
INSERT INTO highlights VALUES('32764984_30_47196-47306','32764984',43,'2 社会认知','我们对自己的重要判断也会受到对比效应的影响。关于我们自己的最有力的信息来源之一是社会比较，这是一种通过将我们自己与他人比较来评估我们的能力、成就、态度和其他特征的过程。','47218-47328',5,1706431474,1782480560);
INSERT INTO highlights VALUES('32764984_30_46664-46733','32764984',43,'2 社会认知','使用这种诱饵的原理正是对比效应：在人们看来，好坏的变化不过是与类似的东西对比所形成的。','46686-46755',5,1706375701,1782480560);
INSERT INTO highlights VALUES('32764984_30_45684-45733','32764984',43,'2 社会认知','社会认知的一个基本原则是，一切判断都是相对的。我们对某个人或某件事的认识和思考取决于它的社会背景。','45706-45755',5,1706336759,1782480560);
INSERT INTO highlights VALUES('32764984_30_43912-43947','32764984',43,'2 社会认知','有乐观解释风格的人把不幸的事件归为外在的、情境性的以及他们能控制的原因','43934-43969',5,1706333275,1782480560);
INSERT INTO highlights VALUES('32764984_30_43626-43843','32764984',43,'2 社会认知','随着时间的推移，人们养成了解释自己成功和失败的习惯模式，这种被称为解释风格的模式影响了人们的控制感和幸福感。','43648-43728',5,1706333252,1782480560);
INSERT INTO highlights VALUES('32764984_30_43260-43323','32764984',43,'2 社会认知','成功与失败归因，以及自证预言 在我们所有的归因中，那些关于成功和失败的归因是最重要的，因为它会影响我们的控制感。','43282-43345',5,1706333208,1782480560);
INSERT INTO highlights VALUES('32764984_30_43127-43156','32764984',43,'2 社会认知','它提醒我们：我们自己可能陷入了导致我们行为不端的情境之中。','43149-43178',5,1706333179,1782480560);
INSERT INTO highlights VALUES('32764984_30_42847-42934','32764984',43,'2 社会认知','我并不是说罪犯不应该为他们的行为负责，我也不是说懒惰、无情或邪恶等性格因素不存在。是的，的确如此！但是，将重点放在个人因素而不是情境因素将导致采取不同的政策来减少贫穷和犯罪。','42869-42956',5,1706333145,1782480560);
INSERT INTO highlights VALUES('32764984_30_41182-41409','32764984',43,'2 社会认知','基本归因错误 基本归因错误指的是人类在描述和解释人们为什么做自己所做的事情时，倾向于高估个性因素或者与情境环境有关的性格因素的重要性。','41204-41278',5,1706323063,1782480560);
INSERT INTO highlights VALUES('32764984_30_40955-41000','32764984',43,'2 社会认知','这种归因分析是非常有用的，它能够帮助我们作出比确定一个人为什么要亲吻另一个人更重要的决定。','40977-41022',5,1706323000,1782480560);
INSERT INTO highlights VALUES('32764984_30_40499-40647','32764984',43,'2 社会认知','根据归因理论，人们在回答问题前会做出两种因果解释：一种解释与人的典型人格有关，这是一种性格归因；另一种则与当事人所处的情况有关，即情境归因。','40521-40669',5,1706322927,1782480560);
INSERT INTO highlights VALUES('32764984_30_39173-39213','32764984',43,'2 社会认知','对于那些感到被边缘化和被疏远的人来说，对归属和被重视的需要可能比生命本身更珍贵。','39195-39235',5,1706322659,1782480560);
INSERT INTO highlights VALUES('32764984_30_37927-38338','32764984',43,'2 社会认知','当我们觉得我们属于自己的时候，当我们能够对结果加以预测的时候，当我们可以自由地作出选择并控制自己的时候，当我们开始做那些让我们觉得有价值工作的时候，当我们信任我们所爱的人和同事的时候，我们便能做到最好。','37949-38050',5,1706322585,1782480560);
INSERT INTO highlights VALUES('32764984_30_37294-37310','32764984',43,'2 社会认知','难道孤独会比不信任更令人寂寞？”','37316-37332',5,1706322508,1782480560);
INSERT INTO highlights VALUES('32764984_30_37062-37109','32764984',43,'2 社会认知','尽管由于信任而使自己处于弱势的风险，但我们通常确实期望其他人、特别是与我们类似的人不会伤害我们','37084-37131',5,1706322465,1782480560);
INSERT INTO highlights VALUES('32764984_30_36942-36951','32764984',43,'2 社会认知','信任','36964-36966',5,1706322442,1782480560);
INSERT INTO highlights VALUES('32764984_30_36182-36194','32764984',43,'2 社会认知','被重视需要','36204-36209',5,1706322347,1782480560);
INSERT INTO highlights VALUES('32764984_30_36043-36079','32764984',43,'2 社会认知','当他们不能进行控制的时候，他们的行为却在显示仿佛他们仍然具有控制的能力。','36065-36101',5,1706322329,1782480560);
INSERT INTO highlights VALUES('32764984_30_35930-35957','32764984',43,'2 社会认知','他们可以被一个更大的、更具支配地位的猴子或者老板所控制','35952-35979',5,1706322311,1782480560);
INSERT INTO highlights VALUES('32764984_30_35589-35617','32764984',43,'2 社会认知','缺乏控制的感觉会令我们不愉快，从长远来看，也是不健康的。','35611-35639',5,1706322290,1782480560);
INSERT INTO highlights VALUES('32764984_30_35482-35491','32764984',43,'2 社会认知','控制','35504-35506',5,1706322182,1782480560);
INSERT INTO highlights VALUES('32764984_30_34707-34723','32764984',43,'2 社会认知','理解他人和准确预测','34729-34738',5,1706322129,1782480560);
INSERT INTO highlights VALUES('32764984_30_35492-35524','32764984',43,'2 社会认知','确定性甚至是不幸的确定性，满足了第三种强烈的社会动机：控制的需要','35514-35546',5,1706322075,1782480560);
INSERT INTO highlights VALUES('32764984_30_34866-34916','32764984',43,'2 社会认知','不确定性使我们陷入困境，无法为即将到来的事情做好准备。的确，我们确信有坏事发生，比怀疑有坏事发生要好','34888-34938',5,1706321974,1782480560);
INSERT INTO highlights VALUES('32764984_30_34410-34658','32764984',43,'2 社会认知','音乐之所以重要，是因为它在情感上把我们自己与他人联系在一起。','34432-34462',5,1706269813,1782480560);
INSERT INTO highlights VALUES('32764984_30_34227-34286','32764984',43,'2 社会认知','相反，音乐之所以无处不在，是因为它有能力以一种其他任何事物都无法达成的方式，把一个人的情绪或意图的信息同时传递给许多人','34249-34308',5,1706269771,1782480560);
INSERT INTO highlights VALUES('32764984_30_31611-31677','32764984',43,'2 社会认知','在支配社会生活的所有动机中，最重要的是归属：我们渴望与他人建立稳定、有意义的联系','31633-31699',5,1706267390,1782480560);
INSERT INTO highlights VALUES('32764984_30_31240-31282','32764984',43,'2 社会认知','所有人都在不同程度地追求社会动机，这是由他们的文化、他们的个性以及具体的情境所决定的','31262-31304',5,1706267373,1782480560);
INSERT INTO highlights VALUES('32764984_30_29206-29260','32764984',43,'2 社会认知','与会者坚持认为，他们的态度的形成有着内在的逻辑，仅以政策为基础——尽管很明显，他们的取舍是由团体归属驱动的。','29228-29282',5,1706261699,1782480560);
INSERT INTO highlights VALUES('32764984_30_27708-27745','32764984',43,'2 社会认知','我们不仅认为我们部落中的人更加多样化，而且我们认为我们部落更优秀、更值得。','27730-27767',5,1706260691,1782480560);
INSERT INTO highlights VALUES('32764984_30_26514-26595','32764984',43,'2 社会认知','有句古老的贝都因谚语说：“我与我的兄弟为敌，我和我的兄弟与表兄弟为敌，我们都与陌生人为敌。”这句谚语完美地抓住了我们的部落心态如何将世界划分成“我们”和“他们”。','26536-26617',5,1706260524,1782480560);
INSERT INTO highlights VALUES('32764984_30_25620-25678','32764984',43,'2 社会认知','与人类联系有关的心理系统，和生理疼痛信号有关的系统相关联。这就解释了为什么辱骂、躲避和骂人的严重程度不亚于身体伤害。','25642-25700',5,1706199029,1782480560);
INSERT INTO highlights VALUES('32764984_30_24873-24928','32764984',43,'2 社会认知','感情上的痛苦，有助于确保人们在社会关系破裂或处于危险之时能够安全挺过；没有经历过分离或排斥的人，不会走得太远。','24895-24950',5,1706198935,1782480560);
INSERT INTO highlights VALUES('32764984_30_24255-24349','32764984',43,'2 社会认知','社会痛苦为什么如此强烈 “我的心都碎了”、“我的感情受伤了”，尽管心碎和骨折之间有明显的区别，但人类这种表达形式说明，社会痛苦（排斥、羞辱或侮辱带来的刺痛）如同肉体上的痛苦。','24277-24371',5,1706198889,1782480560);
INSERT INTO highlights VALUES('32764984_30_24115-24148','32764984',43,'2 社会认知','印象形成组比那些在试图记住事实以应对回忆测试的人，记住了更多的事实','24137-24170',5,1706198851,1782480560);
