INSERT INTO highlights VALUES('32764984_30_21331-21367','32764984',43,'2 社会认知','。另外的99%是意识之外的，但他认为，这个百分比控制了我们大部分的行为。','21353-21389',5,1706198422,1782480560);
INSERT INTO highlights VALUES('32764984_30_21295-21331','32764984',43,'2 社会认知','有意识的推理——“我们完全了解的词汇和图像流”——只占我们思维的1%左右','21317-21353',5,1706198406,1782480560);
INSERT INTO highlights VALUES('32764984_30_20775-20798','32764984',43,'2 社会认知','与自动处理不同的是，受控处理不能同时做两件事。','20797-20820',5,1706198385,1782480560);
INSERT INTO highlights VALUES('32764984_30_20811-20846','32764984',43,'2 社会认知','尽管我们会自我中心式地相信自己的能力，但却不可能有效地同时执行多项任务','20833-20868',5,1706198360,1782480560);
INSERT INTO highlights VALUES('32764984_30_20478-20588','32764984',43,'2 社会认知','大多数决策都是分两步进行的。我们的自动系统首先产生了对现实的快速而又有污染的评估——基于直觉和感受，一种不假思索的偏好。然后，假如我们具有某种动机，而且能够获得有效的信息，我们会使用更多的控制或深思熟虑来改变最初的印象。','20500-20610',5,1706198300,1782480560);
INSERT INTO highlights VALUES('32764984_30_19791-19830','32764984',43,'2 社会认知','自动处理指的是引导我们大部分行为的无意识（内隐的）和不自主的操作','19813-19852',5,1706198187,1782480560);
INSERT INTO highlights VALUES('32764984_30_19726-19791','32764984',43,'2 社会认知','人脑的两种思维系统 人类的思维系统是按照两种处理方式来划分的：自动的和受控的。','19748-19794',5,1706198177,1782480560);
INSERT INTO highlights VALUES('32764984_30_19399-19677','32764984',43,'2 社会认知','这些习惯通过产生满足感来抵消消极偏见的影响。','19421-19443',5,1706198109,1782480560);
INSERT INTO highlights VALUES('32764984_30_18053-18112','32764984',43,'2 社会认知','人们更倾向于避免损失，而不是试图获得收益，这种现象被称为损失厌恶。','18075-18134',5,1706164215,1782480560);
INSERT INTO highlights VALUES('32764984_30_17383-17478','32764984',43,'2 社会认知','他们总结道，从进化的角度来说，这是一种适应性，因为坏事情比好事情影响力强，因为动物对危险、痛苦、失败的警觉程度更高，或者有过其他负面经历者更有可能在威胁中存活下来，从而更有可能遗传他们的基因','17405-17500',5,1706164189,1782480560);
INSERT INTO highlights VALUES('32764984_30_16680-16937','32764984',43,'2 社会认知',unistr('消极反馈比积极反馈对情绪的影响更大。坏消息比好消息更容易、更经常地被分享。￼\u000a'),'16702-16739',5,1706164152,1782480560);
INSERT INTO highlights VALUES('32764984_30_16555-16613','32764984',43,'2 社会认知','我们倾向于关注潜在的威胁而不是祝福，这种倾向通常被称为消极偏见。','16577-16635',5,1706164140,1782480560);
INSERT INTO highlights VALUES('32764984_30_15955-16019','32764984',43,'2 社会认知','巴纳姆效应指的是，当人们被赋予可以适用于几乎所有人的模糊、万能的自我描述时，他们通常会说“难以置信！那就是我！”。','15977-16041',5,1706163581,1782480560);
INSERT INTO highlights VALUES('32764984_30_14848-14893','32764984',43,'2 社会认知','许多青少年害怕上学，是因为一旦他们突然发现自己有某种缺陷，他们会认定“每个人都会注意到”。','14870-14915',5,1706162164,1782480560);
INSERT INTO highlights VALUES('32764984_30_13218-13266','32764984',43,'2 社会认知','也就是说，一个不特别内向或外向的人在回答第一组问题时会显得外向，而在回答第二组问题时会显得内向。','13240-13288',5,1706162106,1782480560);
INSERT INTO highlights VALUES('32764984_30_12293-12346','32764984',43,'2 社会认知','历史经常会不幸地显示，如果人们确信自己是绝对正确的，而其他人是错误的，那么他们便很容易做出仇恨和残忍的行为','12315-12368',5,1706154558,1782480560);
INSERT INTO highlights VALUES('32764984_30_12205-12292','32764984',43,'2 社会认知','我们相信自己对现实的主观解释就是现实。我们所看到的是事物的本来面目，而那些人是存在偏见的。这种信念使我们更容易认为，任何不认同我们观点的人都是被误导的、无知的、自私的或邪恶的','12227-12314',5,1706154554,1782480560);
INSERT INTO highlights VALUES('32764984_30_11599-11626','32764984',43,'2 社会认知','我们的许多信仰都是内隐的，隐藏在能够意识到的意识之下。','11621-11648',5,1706154425,1782480560);
INSERT INTO highlights VALUES('32764984_30_11466-11505','32764984',43,'2 社会认知','人类大脑被设计得可以有效地进行工作，但是在这个过程中仍然会出现一些怪癖和偏见。','11488-11527',5,1706154405,1782480560);
INSERT INTO highlights VALUES('32764984_30_11505-11586','32764984',43,'2 社会认知','其中一种典型的偏见便是所谓偏见盲点，即认为我们自己比大多数人更客观、更少偏差。我们偏见性地认为自己不存在偏见！','11527-11608',5,1706154400,1782480560);
INSERT INTO highlights VALUES('32764984_30_11056-11152','32764984',43,'2 社会认知','我们天生就存在偏见和攻击性，对外界和那些我们认为是威胁的人保持警惕和敌对。我们的大脑发展了快速心理反应过程，以提醒我们注意危险，迅速决定谁是朋友或敌人，并准备好与我们所感知的敌人战斗或者逃离。','11078-11174',5,1706154339,1782480560);
INSERT INTO highlights VALUES('32764984_30_10733-10917','32764984',43,'2 社会认知','但在当今复杂的多元文化世界中，同样的虚构、错误和对理性的背离，对我们以及狩猎—采集者都是有益的。游戏规则已经改变，但我们的进化倾向却没有改变。','10755-10826',5,1706154270,1782480560);
INSERT INTO highlights VALUES('32764984_30_10665-10733','32764984',43,'2 社会认知','我们的许多不合逻辑、不适应的倾向和动机——以及慷慨、富有同情心和感人的倾向和动机——都植根于我们生活在一小群狩猎—采集者时代的生存价值。','10687-10755',5,1706154209,1782480560);
INSERT INTO highlights VALUES('32764984_30_9829-9893','32764984',43,'2 社会认知','了解150人限制的一个有用的含义是，当人类组织不再变得更大时，其功能会更好——他们可以像社区那样运作，而不会像行政机构那样运作。','9851-9915',5,1706154115,1782480560);
INSERT INTO highlights VALUES('32764984_30_9116-9191','32764984',43,'2 社会认知','邓巴发现，我们的大脑容量似乎可以容纳大约150人，我们可以与他们建立起稳定、有意义的关系；当人类群体的数量不超过150人时，他们的功能会达到最佳状态。','9138-9213',5,1706147125,1782480560);
INSERT INTO highlights VALUES('32764984_30_8901-8956','32764984',43,'2 社会认知','动物群体的大小与动物大脑新皮层的大小有着密切的关系。新皮质是哺乳动物大脑中最后进化的部分，包含了许多高级功能。','8923-8978',5,1706147094,1782480560);
INSERT INTO highlights VALUES('32764984_30_7716-7814','32764984',43,'2 社会认知','从隐喻的角度来说，我们的思想更像是草图，而不是白纸。经验并不是从零开始的；它对已经存在的东西加以细化，进行修正，并利用个人、文化和社会的影响来给它着色。与生俱来和后天培养相互作用，使我们成为自己。','7738-7836',5,1706119639,1782480560);
INSERT INTO highlights VALUES('32764984_30_6408-6434','32764984',43,'2 社会认知','但我们的大脑并不像计算机那样真正存储记忆或处理信息。','6430-6456',5,1706119462,1782480560);
INSERT INTO highlights VALUES('32764984_30_3281-3440','32764984',43,'2 社会认知','“我们看到的并非事物的本来面目；而是我们所看到的事物的本来面目。”','3303-3336',5,1706119133,1782480560);
INSERT INTO highlights VALUES('32764984_30_1937-2009','32764984',43,'2 社会认知','我们现代人的行为，在多大程度上和几个世纪前的夜壶使用者是一致的？每一代人都可以回过头来审视他们祖先的愚蠢行为，找到很多理由来加以解释并自鸣得意。','1959-2031',5,1706110814,1782480560);
INSERT INTO highlights VALUES('32764984_29_10841-10874','32764984',42,'1 什么是社会心理学','社会影响会决定人们的想法、感受和行为，这种影响往往是巨大而隐秘的。','10863-10896',5,1706027077,1782480560);
INSERT INTO highlights VALUES('32764984_29_10238-10273','32764984',42,'1 什么是社会心理学','至关重要的是要明白这些情景中的什么要素会导致令人不悦的、破坏性的行为。','10260-10295',5,1706027002,1782480560);
INSERT INTO highlights VALUES('32764984_29_9822-9888','32764984',42,'1 什么是社会心理学','人格倾向论会令我们自以为是，按照这种假设，我们在外部压力下是无懈可击的——而事实上外部压力往往会导致我们做出愚蠢、疯狂或残忍的举动。','9844-9910',5,1706026946,1782480560);
INSERT INTO highlights VALUES('32764984_29_9445-9496','32764984',42,'1 什么是社会心理学','人们倾向于通过赋予过错者某种性格特质来解释其令人厌恶的行为，比如“精神病”、“虐待狂”或“邪恶之人”。','9467-9518',5,1706026887,1782480560);
INSERT INTO highlights VALUES('32764984_29_8083-8155','32764984',42,'1 什么是社会心理学','我们可以比业余社会心理学家获得更为精确而丰富的材料，并在此基础上得出结论。而后者则只能依靠对随机发生事件的观察，并且不能排除许多同时发生的事情。','8105-8177',5,1706026745,1782480560);
INSERT INTO highlights VALUES('32764984_29_7137-7427','32764984',42,'1 什么是社会心理学','的确，社会心理学研究发现，与被要求预测将发生什么的大学生相比，那些被告知在研究中发生了什么的大学生会认为所发生的一切更为显而易见。￼一旦出现事后聪明偏见，一切都会变得显而易见。','7159-7449',5,1705987625,1782480560);
INSERT INTO highlights VALUES('32764984_29_6022-6089','32764984',42,'1 什么是社会心理学','洞察人们的社会动机，可以用来做好事，可以用来做坏事，可以用来赢得电视真人秀比赛，可以用来做任何与社会影响相关的事情——这几乎是所有事情','6044-6111',5,1705987486,1782480560);
INSERT INTO highlights VALUES('32764984_29_5661-5718','32764984',42,'1 什么是社会心理学','他人在场或榜样的作用，无论是来自现实生活，还是来自类似《辛德勒的名单》的影片，都能激发出积极的情感和慷慨好施的举动','5683-5740',5,1705987449,1782480560);
INSERT INTO highlights VALUES('32764984_29_5603-5644','32764984',42,'1 什么是社会心理学','被拒绝是人类最痛苦的经历之一，会导致各种各样的自我挫败和破坏行为，从暴饮暴食到暴力','5625-5666',5,1705987434,1782480560);
INSERT INTO highlights VALUES('32764984_29_5073-5159','32764984',42,'1 什么是社会心理学','齐默尔曼注意到一个穿着连帽衫的高大黑人少年，他以为这可能是一个持有武器的危险罪犯，而事实并非如此：特雷文不过是一个从便利店独行回家的普通高中生，手里拿着一杯冰茶和一袋快餐。','5095-5181',5,1705987387,1782480560);
INSERT INTO highlights VALUES('32764984_29_3042-3106','32764984',42,'1 什么是社会心理学','在哥伦拜恩中学大屠杀发生后的近二十年里，数百名美国青春期男孩在校园里实施了同样可怕的大规模枪击。曾经不可思议的事情已经司空见惯。','3064-3128',5,1705942758,1782480560);
INSERT INTO highlights VALUES('32764984_29_1421-1463','32764984',42,'1 什么是社会心理学','这个研究领域提供了对人类社会生活的科学理解，更为重要的是，提供了改进人类社会的方法。','1443-1485',5,1705932143,1782480560);
INSERT INTO highlights VALUES('32764984_28_465-513','32764984',28,'社会性动物','那些不能过公共生活，或者可以自给自足不需要过公共生活，因而不参与社会的，要么是兽类，要么是上帝。','465-513',5,1705931916,1782480560);
INSERT INTO highlights VALUES('32764984_26_3834-3869','32764984',41,'本书的故事','这些事件是很久以前发生的，但其中隐含的社会心理教训却没有被很好地吸取。','3856-3891',5,1705931779,1782480560);
