INSERT INTO highlights VALUES('32764984_26_3155-3197','32764984',41,'本书的故事','而今，在2017年的夏天，在给诸位讲述这个故事的时候，我已经变成了一位头发花白的老者','3177-3219',5,1705931240,1782480560);
INSERT INTO highlights VALUES('32764984_26_3117-3154','32764984',41,'本书的故事','1970年当我第一次开始撰写本书时，才38岁左右，还是一个踌躇满志的年轻人','3139-3176',5,1705931226,1782480560);
INSERT INTO highlights VALUES('32764984_26_2380-2485','32764984',41,'本书的故事','科学的自明之理在于，真正认识世界的唯一途径是重构： 也就是说，为了真实地理解是一种事物导致了另一种事物，仅仅靠简单的观察是远远不够的，更为重要的是，我们有责任创设一种事物以便确定它的出现的确导致了另一事物的出现','2402-2507',5,1705931081,1782480560);
INSERT INTO highlights VALUES('32764984_26_2148-2217','32764984',41,'本书的故事','本书的目的曾经是（而且至今仍然是），为了阐明社会心理学研究有可能帮助我们理解（甚至有可能开始帮助我们解决）困扰当代社会的一些最重要的问题。','2170-2239',5,1705930795,1782480560);
INSERT INTO highlights VALUES('32764984_26_1825-1898','32764984',41,'本书的故事','然而，从深层次看，对我而言声称社会心理学是一门年轻的学科，则又会陷入因极力逃避而带来的自责之中——这无疑是在恳求我的学生们不要对我们抱太大的期望。','1847-1920',5,1705930766,1782480560);
INSERT INTO highlights VALUES('32764984_26_1726-1795','32764984',41,'本书的故事','然而真正意义上的实验社会心理学则诞生于20世纪30年代后期，主要是因为有了库尔特·勒温(Kurt Lewin)以及他的那些杰出学生们的推动','1748-1817',5,1705930741,1782480560);
INSERT INTO highlights VALUES('22947638_30_1509-1543','22947638',30,'钱德洪跋','于是，我又收集了一些未刊刻的记录，采用其中不违背先生主张的，编成一卷','1509-1543',NULL,1672283288,1782480564);
INSERT INTO highlights VALUES('22947638_29_9519-9591','22947638',29,'黄以方录','良知虽然人人具有，但良知遇到的情况是千变万化的，所以，致良知的功夫，也是千变万化的），这个良知怎么能捉摸得到？把良知理解透彻了，也就成为圣人了。','9519-9591',NULL,1672283017,1782480564);
INSERT INTO highlights VALUES('22947638_29_9451-9510','22947638',29,'黄以方录','事物总是在变化之中，各种性质比如上下、刚柔等总在互相转换，没有固定不变的，当然也就没有固定不变的准则，人要学习随机应变','9451-9510',NULL,1672283002,1782480564);
INSERT INTO highlights VALUES('22947638_29_9043-9116','22947638',29,'黄以方录','心中千万不可‘有我’,‘有我’就是傲。古代圣贤有很多优秀的地方，也只是‘无我’罢了。‘无我’自然会谦谨。谦谨是一切善的基础，傲慢是一切恶的源泉。”','9043-9116',NULL,1672282937,1782480564);
INSERT INTO highlights VALUES('22947638_29_8894-8910','22947638',29,'黄以方录','人生的大毛病，就是一个‘傲’字。','8894-8910',NULL,1672282916,1782480564);
INSERT INTO highlights VALUES('22947638_29_7155-7217','22947638',29,'黄以方录','任何念头都不要滞留在心体上，这就好像一点点灰尘都不能吹进眼睛里。一点点能有多少呢？然而，再少的灰尘，都能使人满眼天昏地暗了。','7155-7217',NULL,1672282730,1782480564);
INSERT INTO highlights VALUES('22947638_29_5084-5096','22947638',29,'黄以方录','念头的精微就是事理的精微','5084-5096',NULL,1672282395,1782480564);
INSERT INTO highlights VALUES('22947638_29_3879-3909','22947638',29,'黄以方录','把心和理分开为二，造成的结果是，自己已陷入霸道虚伪还没觉察到','3879-3909',NULL,1672281439,1782480564);
INSERT INTO highlights VALUES('22947638_29_3668-3677','22947638',29,'黄以方录','这心在物上就是理。','3668-3677',NULL,1672281403,1782480564);
