INSERT INTO highlights VALUES('22947638_27_17412-17432','22947638',27,'钱德洪录','人心原本是晶莹无滞的，原本是一个未发之中','17412-17432',NULL,1672237434,1782480564);
INSERT INTO highlights VALUES('22947638_27_16925-16958','22947638',53,'钱德洪录','无善无恶是心之体，有善有恶是意之动，知善知恶是良知，为善去恶是格物','17416-17449',NULL,1672237246,1782480564);
INSERT INTO highlights VALUES('22947638_27_15523-15587','22947638',27,'钱德洪录','如今，我确信良知的真是真非，随手拈来，再也不用隐藏着。现在我终于有了一个‘狂者’的胸襟。即便全天下人都讲我言行不符也毫无关系。”','15523-15587',NULL,1672237067,1782480564);
INSERT INTO highlights VALUES('22947638_27_15079-15117','22947638',27,'钱德洪录','我们学习的人，如果能充分信任良知，不被气所扰乱，便能经常做一个羲皇时代的人。','15079-15117',NULL,1672236957,1782480564);
INSERT INTO highlights VALUES('22947638_27_14044-14070','22947638',27,'钱德洪录','未敲钟时，原本就是惊天动地的，敲了之后也只是寂静无声','14044-14070',NULL,1672222667,1782480564);
INSERT INTO highlights VALUES('22947638_27_13643-13670','22947638',27,'钱德洪录','张仪、苏秦已掌握到了良知的妙用，但用在了不好的地方。”','13643-13670',NULL,1672222622,1782480564);
INSERT INTO highlights VALUES('22947638_27_13421-13480','22947638',27,'钱德洪录','“《大学》中的‘所恶于上’（讨厌上级对我无礼的态度），就是良知；‘毋以使下’（我不用同样的态度对待下属），就是致知。”','13421-13480',NULL,1672222596,1782480564);
INSERT INTO highlights VALUES('22947638_27_8210-8230','22947638',27,'钱德洪录','巧也只在用力处，有力而无巧，只是空有其力','8210-8230',NULL,1672198608,1782480564);
INSERT INTO highlights VALUES('22947638_27_8201-8209','22947638',27,'钱德洪录','巧和力并非两回事','8201-8209',NULL,1672198602,1782480564);
INSERT INTO highlights VALUES('22947638_27_6904-6981','22947638',27,'钱德洪录','圣人只明白事物发展的规律，善于应付各种变化。良知不分前后，只要明白规律，就能一了百了。如果存了一个想要预先知道（前知）的心，就是私心，就是趋利避害的意思。','6904-6981',NULL,1672197957,1782480564);
INSERT INTO highlights VALUES('22947638_27_7083-7186','22947638',27,'钱德洪录','本体原本就是无知无不知的。就像太阳，从未有意要去照耀宇宙万物，但又无物不照耀。无照无不照，原本就是太阳的本体。良知本来无知，如今却要它有知，良知本来是无不知的，如今却怀疑它有不知。这些只因不够相信良知罢了。','7083-7186',NULL,1671810370,1782480564);
INSERT INTO highlights VALUES('22947638_27_5155-5276','22947638',27,'钱德洪录','“至于对自己和亲人，更不会分个厚此薄彼。因为仁民爱物都从这里产生，如果这里能够忍心，就会无所不忍了。《大学》上说的厚薄，是良知上自然而然的秩序，不可逾越，这就称为义；遵循这个秩序，就称为礼；明白这个秩序就称为智；始终坚持这个秩序，就称为信。”','5155-5276',NULL,1671778727,1782480564);
INSERT INTO highlights VALUES('22947638_27_4376-4391','22947638',27,'钱德洪录','人的良知，也就是草木瓦石的良知','4376-4391',NULL,1671778201,1782480564);
INSERT INTO highlights VALUES('22947638_27_3844-4028','22947638',27,'钱德洪录','心的本体原本不动。只因为言行有不符合义的，心才会动。孟子无论心动与否，只管去‘集义’。如果所行都是义，这个心自然就没有可动之处。告子只是要这个心不动，也就是死扣这个心不放，如此，反把这个心生生不息的根给阻挠了，这不但没有什么益处，反而又伤害了心。孟子所讲的‘集义’功夫，自然可以把这个心修养得充实丰满，没有丝毫亏欠，当然能纵横自在，生机勃勃。这就是所谓的‘浩然之气’。','3844-4028',NULL,1671778136,1782480564);
INSERT INTO highlights VALUES('22947638_27_2984-3070','22947638',27,'钱德洪录','良知在夜气下生发的，才是良知的本体，因为它没有夹杂丝毫物欲。学习者要想在事物烦忧的时侯仍像夜气一样，就是‘通乎昼夜之道而知’（通晓了昼夜运行的规律，也就明白了自然之道）。”','2984-3070',NULL,1671774604,1782480564);
INSERT INTO highlights VALUES('22947638_26_2418-2546','22947638',26,'黄省曾录','毁谤是从身外来的，即使是圣人也无法避免。人贵在自我修行。如果自己真的是一个圣贤，纵然世人都毁谤他，也不能对他有什么损害。就如同浮云遮日，怎么能损害太阳的光辉呢？如果自己是个外貌恭敬庄重而内心空虚无德的人，纵然没有人说他坏话，他隐藏的恶终有一天还是会暴露无遗','2418-2546',NULL,1671773603,1782480564);
INSERT INTO highlights VALUES('22947638_26_1680-1807','22947638',26,'黄省曾录',unistr('有位朋友问：“读书记不住，怎么办呢？”\u000a先生说：“只要理解了，为什么非要记住？理解也是次要的，重要的是明白自己的本体。如果只求记住，往往不能很好地理解；如果只求理解，往往不能使自心的本体明朗清楚。”'),'1680-1807',NULL,1671773499,1782480564);
INSERT INTO highlights VALUES('22947638_26_1289-1368','22947638',26,'黄省曾录','先生说：“‘率性之谓道’，就是道心。一旦添加了一些人的欲望，就是人心。道心原本无声无味，因此称为‘微’。按照人心去做，就有许多不安稳的地方，因此称为‘惟危’。','1289-1368',NULL,1671773379,1782480564);
INSERT INTO highlights VALUES('22947638_25_3815-3857','22947638',25,'黄修易录','从今以后，你不要去议论别人的是非，要责备别人的时候，就把它当作自己的一大私欲加以克治','3815-3857',NULL,1671772349,1782480564);
INSERT INTO highlights VALUES('22947638_25_3584-3659','22947638',25,'黄修易录','学习一定要反省自己。如果只去指责别人，就只能看到别人的错误，就不会看到自己的缺点。如果能反省自己，才能看到自己有许多不足之处，哪还有时间去指责别人呢？','3584-3659',NULL,1671772327,1782480564);
INSERT INTO highlights VALUES('22947638_25_3447-3493','22947638',25,'黄修易录','谁没有根呢？良知就是天生的灵根，生生不息。只因为被私欲拖累，把这灵根残害蒙蔽了，不能生发出来','3447-3493',NULL,1671772261,1782480564);
INSERT INTO highlights VALUES('22947638_25_3163-3240','22947638',25,'黄修易录','先生又说：“人若实实在在地用功，不论别人如何诽谤和侮辱，依然会处处受益，处处都是品德进步的资本。若不用功，别人的诽谤和侮辱就会有如魔鬼，最终会被它拖垮。”','3163-3240',NULL,1671772204,1782480564);
INSERT INTO highlights VALUES('22947638_25_3028-3133','22947638',25,'黄修易录','各位只要经常怀着一个‘遁世无闷，不见是而无闷’的心，根据良知耐心用功，不在乎别人的嘲笑、诽谤、称誉、侮辱，任凭功夫有进有退，我持守着致良知，从不停息，时间久了，就会感到有力量，也自然不会被外面的任何事情所动摇。','3028-3133',NULL,1671772192,1782480564);
INSERT INTO highlights VALUES('22947638_25_2218-2312','22947638',25,'黄修易录','把这类事情归罪于父母的，天下并不少见。说到底，还是自己没有志向。志向坚定了，在良知的主宰下，千事万事也只是一件事。读书作文，怎么会成为人的负担呢？人还是被自己的那个计较得失的心给困扰了啊！','2218-2312',NULL,1671700366,1782480564);
INSERT INTO highlights VALUES('22947638_24_4805-4971','22947638',24,'黄直录','先生说：“佛家担心父子关系是一种牵累，于是就逃避了父子关系；担心君臣关系是一种牵累，于是就逃避了君臣关系；担心夫妻关系是一种牵累，于是就逃避了夫妻关系。这些，都是执着于君臣、父子、夫妻的‘相’，他才要逃避。我们儒家，有父子关系，就给予仁爱；有君臣关系，就给予忠义；有夫妻关系，就给予礼节。什么时候执着于父子、君臣、夫妻的‘相’呢？”','4805-4971',NULL,1671684239,1782480564);
INSERT INTO highlights VALUES('22947638_24_4698-4731','22947638',24,'黄直录','佛家不执着于相，其实是执着于相，我们儒家执着于相，其实是不执着于相','4698-4731',NULL,1671684189,1782480564);
INSERT INTO highlights VALUES('22947638_24_4504-4534','22947638',24,'黄直录','现在，我们对于愤怒等情绪，只要顺其自然，不要刻意去抑制或放任','4504-4534',NULL,1671684150,1782480564);
INSERT INTO highlights VALUES('22947638_24_3802-3852','22947638',24,'黄直录','有人过于直率。先生说：“如今讲良知学说，如果在外在行为上不检点，不自我约束，又是把心与事分成两件事了','3802-3852',NULL,1671683986,1782480564);
INSERT INTO highlights VALUES('22947638_24_3744-3772','22947638',24,'黄直录','人的精力有限，一味在容貌上用功，往往就不能照顾到内心了。','3744-3772',NULL,1671683971,1782480564);
INSERT INTO highlights VALUES('22947638_24_2954-2989','22947638',24,'黄直录','您的《修道说》中讲‘率性之谓道’为圣人之事，‘修道之谓教’为贤人之事。','2954-2989',NULL,1671683787,1782480564);
INSERT INTO highlights VALUES('22947638_24_2805-2879','22947638',24,'黄直录','对善能切切实实地喜爱，就不会有不善的念头了。对恶能切切实实地憎恨，就不会有邪恶的念头了。如此，又怎能不是圣人？所以，圣人的学问也只是一个“诚”字罢了','2805-2879',NULL,1671683698,1782480564);
INSERT INTO highlights VALUES('22947638_24_2419-2430','22947638',24,'黄直录','本体上稍有闪失就是恶了','2419-2430',NULL,1671683638,1782480564);
INSERT INTO highlights VALUES('22947638_24_2411-2418','22947638',24,'黄直录','至善是心的本体','2411-2418',NULL,1671683617,1782480564);
INSERT INTO highlights VALUES('22947638_24_2202-2264','22947638',24,'黄直录','礼乐、名物方面，圣人不必全部知道，然而他知道一个天理，这样自然会掌握许多规矩法则，不知道的能够去问，这也正是天理规则所在之处','2202-2264',NULL,1671683605,1782480564);
INSERT INTO highlights VALUES('22947638_24_1521-1635','22947638',24,'黄直录','和人探讨学问，也必须依据他能力的大小。这就好像树刚刚萌芽，只用少量的水去浇灌；树芽稍长了一点，再多浇一点水；从双手合握粗细到双臂合抱粗细，浇水的多少，都要根据树的大小来决定，刚萌生的嫩芽，如果用一桶水去浇灌它，就会把它浸坏了。”','1521-1635',NULL,1671683521,1782480564);
INSERT INTO highlights VALUES('22947638_24_1176-1218','22947638',24,'黄直录','“圣贤不是没有功业和气节，只是他们能遵循天理，这就是道。圣贤不是因为事功气节而闻名天','1176-1218',NULL,1671607762,1782480564);
INSERT INTO highlights VALUES('22947638_23_5467-5513','22947638',23,'陆九川录','人如果明白良知的诀窍，不管有多少歪思邪念，只要被良知发觉，自然会消融。有如灵丹一粒，点铁成金','5467-5513',NULL,1671600822,1782480564);
INSERT INTO highlights VALUES('22947638_23_4478-4605','22947638',23,'陆九川录','你的那点良知，正是你自己的行为准则。你的意念所到之处，正确的就知道是正确的，错误的就知道是错误的，不可能有丝毫的隐瞒。只要你不去欺骗良知，真真切切地依循着良知去做，如此就能存善，如此就能除恶。此处是何等的稳当快乐！这些就是格物的真正秘诀，致知的实在功夫。','4478-4605',NULL,1671600024,1782480564);
INSERT INTO highlights VALUES('22947638_23_3470-3542','22947638',23,'陆九川录','人必须在事上磨炼，在事上用功才会有帮助。如果只是追求表面的安静，遇事还会慌乱，始终不会有进步。那静时的功夫，表面看是收敛，实际上却是放纵沉沦。”','3470-3542',NULL,1671599831,1782480564);
INSERT INTO highlights VALUES('22947638_23_3034-3067','22947638',23,'陆九川录','听见了看见了，没有什么关系，只要你的心不去跟随所见所闻，就可以了。','3034-3067',NULL,1671599743,1782480564);
INSERT INTO highlights VALUES('22947638_23_2841-2856','22947638',23,'陆九川录','不是从本体发出的念就是私心杂念','2841-2856',NULL,1671599695,1782480564);
INSERT INTO highlights VALUES('22947638_23_2614-2647','22947638',23,'陆九川录','静并非不动，动也并非不静。戒慎恐惧就是念头，为什么要区分动和静呢？','2614-2647',NULL,1671596824,1782480564);
INSERT INTO highlights VALUES('22947638_23_2418-2437','22947638',23,'陆九川录','人的念头怎么能打消？只能让它变得纯正。','2418-2437',NULL,1671596816,1782480564);
INSERT INTO highlights VALUES('22947638_23_2180-2192','22947638',23,'陆九川录','《中庸》上说‘不诚无物’','2180-2192',NULL,1671596756,1782480564);
INSERT INTO highlights VALUES('22947638_23_1683-1755','22947638',23,'陆九川录','就它充盈空间而言，称为身；从它主宰的作用而言，称为心；从心的发动上而言，称为意；从心的灵明上而言，称为知；从意的涉及之处而言，称为物，都是一回事','1683-1755',NULL,1671596642,1782480564);
INSERT INTO highlights VALUES('22947638_23_1511-1531','22947638',23,'陆九川录','只要理解身、心、意、知、物是一件事就行了','1511-1531',NULL,1671596587,1782480564);
INSERT INTO highlights VALUES('22947638_23_1192-1218','22947638',23,'陆九川录','后来经过体验，我认为意的真诚与否，必须先有知觉才可以','1192-1218',NULL,1671596541,1782480564);
INSERT INTO highlights VALUES('22947638_23_947-988','22947638',23,'陆九川录','但也觉得先生主张意的所在处是物的看法，好像也有问题，主要是这个“物”的意义不甚明了','947-988',NULL,1671596461,1782480564);
INSERT INTO highlights VALUES('22947638_19_5272-5314','22947638',19,'答聂文蔚（二）','我们的功夫，必须一心一意地在“夭寿不贰，修身以俟”上做，如此就是尽心、知天功夫的开端','5272-5314',NULL,1671072124,1782480564);
INSERT INTO highlights VALUES('22947638_19_1962-2074','22947638',19,'答聂文蔚（二）','实实在在地致良知，自然不会有“忘”的毛病；无丝毫的意（做事不凭空猜测）、必（做事不绝对）、固（做事不固执）、我（做事不以自我为中心），也自然不会有“助”的毛病。因此，说到格物、致知、诚意、正心时，也就不用再说“勿忘勿助”了。','1962-2074',NULL,1671071535,1782480564);
INSERT INTO highlights VALUES('22947638_19_1436-1455','22947638',19,'答聂文蔚（二）','偶尔想求速效，这就是助，就必须“勿助”','1436-1455',NULL,1670986474,1782480564);
INSERT INTO highlights VALUES('22947638_19_1363-1387','22947638',19,'答聂文蔚（二）','“必有事焉”，就是每时每刻去“集义”（积累道义）','1363-1387',NULL,1670986457,1782480564);
INSERT INTO highlights VALUES('22947638_18_1972-2011','22947638',18,'答聂文蔚','更何况对于广大的天下，众多的百姓，纷繁的事物，又怎么能把它们看作是与我一体呢？','1972-2011',NULL,1670930277,1782480564);
INSERT INTO highlights VALUES('22947638_18_1398-1505','22947638',18,'答聂文蔚','古人看到善就像自己做了好事；看到恶就像自己做了坏事；把百姓的饥饿困苦看成是自己的饥饿困苦；只要有一个人没有安顿好，就觉得是自己把他推进了阴沟。这样做，并不是想以此来获得天下人的信任，而是一心实现良知以求自己心安罢了','1398-1505',NULL,1670930210,1782480564);
INSERT INTO highlights VALUES('22947638_18_1022-1044','22947638',18,'答聂文蔚','与其让天下人都相信，还不如被一个人真正相信。','1022-1044',NULL,1670930135,1782480564);
INSERT INTO highlights VALUES('22947638_17_4172-4269','22947638',17,'答罗整庵少宰书','对天下公有的东西，只得秉公而论。所以，正确的言论，即便与自己的见解不同，也对自己有益；错误的言论，即便与自己的见解相同，也对自己有损害。对自己有益的，自己一定会喜欢；对自己有害的，自己一定会厌恶','4172-4269',NULL,1670930023,1782480564);
INSERT INTO highlights VALUES('22947638_17_4010-4026','22947638',17,'答罗整庵少宰书','知我者谓我心忧，不知我者谓我何求','4010-4026',NULL,1670929999,1782480564);
INSERT INTO highlights VALUES('22947638_17_3296-3333','22947638',17,'答罗整庵少宰书','墨子主张“兼爱”，是实行“仁”过了头；杨朱主张“为我”，是实行“义”过了头','3296-3333',NULL,1670929895,1782480564);
INSERT INTO highlights VALUES('22947638_17_2451-2580','22947638',17,'答罗整庵少宰书','正心诚意、致知格物，都是为了修身。格物的意思，其实就是只要你每天下功夫，就可以每天见到自己的成长。因此，格物，就是探究修正心中的物欲、探究修正意念中的物欲、探究修正认知中的物欲。正心，就是修正物欲的心；诚意，就是使物欲的意念诚实；致知，就是把物欲转化为良知。','2451-2580',NULL,1670853301,1782480564);
INSERT INTO highlights VALUES('22947638_16_4028-4123','22947638',16,'答欧阳崇一','君子修学是为了自己，不会担心被别人欺骗，只是永远不欺骗自己的良知罢了；从不担心别人对自己不诚信，只是永远相信自己的良知罢了；也从不预先察觉别人的欺诈和不诚信，只是永远努力体察自己的良知罢了。','4028-4123',NULL,1670852740,1782480564);
INSERT INTO highlights VALUES('22947638_16_3480-3502','22947638',16,'答欧阳崇一','不事先怀疑别人的欺诈和不诚信，但又能先知先觉','3480-3502',NULL,1670811382,1782480564);
INSERT INTO highlights VALUES('22947638_16_3037-3066','22947638',16,'答欧阳崇一','凡是做学问的功夫，只要始终如一就会真诚，三心二意就会虚伪。','3037-3066',NULL,1670811208,1782480564);
INSERT INTO highlights VALUES('22947638_15_8451-8515','22947638',15,'答陆原静书（二）','“无所住而生其心”，佛陀说过这样一句话，说得很正确。明镜照物，美的呈现为美，丑的呈现为丑，一照就是它的真实面目，也就是“生其心”','8451-8515',NULL,1670751385,1782480564);
INSERT INTO highlights VALUES('22947638_15_8516-8545','22947638',15,'答陆原静书（二）','美的为美，丑的为丑，照过之后一切都不留下，这就是“无所住”','8516-8545',NULL,1670751372,1782480564);
