INSERT INTO highlights VALUES('22947638_15_6675-6719','22947638',15,'答陆原静书（二）','仁义礼智是人性的本质，聪明睿智是人性的禀赋，喜怒哀乐是人性的情感，私欲虚伪是人性的障蔽。','6675-6719',NULL,1670727370,1782480564);
