INSERT INTO highlights VALUES('22947638_13_4471-4515','22947638',13,'启问道通书','古人说：“攻吾短者是吾师（攻击我短处的人都是我老师）。”既然是老师，又怎么能讨厌他们呢？','4471-4515',NULL,1670680486,1782480564);
INSERT INTO highlights VALUES('22947638_13_4091-4141','22947638',13,'启问道通书','朱熹与陆象山两位先生之所以招致后世的众多议论，是因为他们的功夫还不精炼、纯熟，难免有意气用事的弊病。','4091-4141',NULL,1670680416,1782480564);
INSERT INTO highlights VALUES('22947638_13_3365-3473','22947638',13,'启问道通书','处理事情有时尽善有时未尽善，以及有困顿失序的问题，都是由于太在意毁誉得失，而不能切实地实现良知。如果能切实地实现良知，就会发现平日所谓处理得好的不一定就是好，所谓处理得不好，大概就是因为在意毁誉得失，自己毁掉了良知。','3365-3473',NULL,1670680285,1782480564);
INSERT INTO highlights VALUES('22947638_13_3329-3350','22947638',13,'启问道通书','事情一来，只要充分发挥我们的良知来应对便好','3329-3350',NULL,1670680254,1782480564);
INSERT INTO highlights VALUES('22947638_13_2633-2700','22947638',13,'启问道通书','圣人的气象怎么才能认识到？自己的良知原本和圣人没有区别，如果能清楚地体认自己的良知，那么，圣人的气象就不在圣人那里，而在我自己身上了。','2633-2700',NULL,1670680120,1782480564);
INSERT INTO highlights VALUES('22947638_12_16893-16967','22947638',12,'答顾东桥书（原题“答人论学说”）','但实际上，记诵的广博，恰好滋长了他们的傲慢；知识的增多，恰好让他们去为非作歹；见闻的广泛，恰好使他们恣意狡辩；辞章的华丽，恰好掩饰了他们的虚伪做作。','16893-16967',NULL,1670679593,1782480564);
INSERT INTO highlights VALUES('22947638_12_16666-16700','22947638',12,'答顾东桥书（原题“答人论学说”）','今天，功利的流毒，已深深渗透到人的灵魂里，积习成性，已有几千年之久。','16666-16700',NULL,1670679549,1782480564);
INSERT INTO highlights VALUES('22947638_12_15629-15698','22947638',12,'答顾东桥书（原题“答人论学说”）','之所以圣人的学问至简至易，易知易从，容易学会，容易成才，正是因为它把恢复人心本体所共同的义理当根本问题，而非只注重有关知识技能方面的事情。','15629-15698',NULL,1670679396,1782480564);
INSERT INTO highlights VALUES('22947638_12_14542-14566','22947638',12,'答顾东桥书（原题“答人论学说”）','父子有亲，君臣有义，夫妇有别，长幼有序，朋友有信','14542-14566',NULL,1670678946,1782480564);
INSERT INTO highlights VALUES('22947638_12_14300-14374','22947638',12,'答顾东桥书（原题“答人论学说”）','天下平常人的心，起初与圣人并没有什么不同。他们只是被自我的私心迷惑，受到物欲的蒙蔽而阻隔，天下为公的大心变成了为自己的小心，通达的心变成了有阻碍的心','14300-14374',NULL,1670678895,1782480564);
INSERT INTO highlights VALUES('22947638_12_13068-13131','22947638',12,'答顾东桥书（原题“答人论学说”）','制作礼乐，必须有中和的德行；只有以声为音律，以身为尺度的人，才有能力制礼作乐，其他像礼仪乐器的细节和技巧，则是乐工和祝史的工作','13068-13131',NULL,1670678468,1782480564);
INSERT INTO highlights VALUES('22947638_12_11607-11669','22947638',12,'答顾东桥书（原题“答人论学说”）','学问之道无他，求其放心而已矣。”不像后来的人，把广记博诵古人的言词当成热爱古人的学问，却又念念不忘追求功名利禄等外在的东西。','11607-11669',NULL,1670678237,1782480564);
INSERT INTO highlights VALUES('22947638_12_10602-10675','22947638',12,'答顾东桥书（原题“答人论学说”）','后世的人不肯尽力致良知，不在处理事物时细察义理，反而去空谈一些反常的事，并把它们作为处理事情的原则，以求得处事时没有过失，这样就偏离了正确的方向。','10602-10675',NULL,1670678049,1782480564);
INSERT INTO highlights VALUES('22947638_12_9507-9560','22947638',12,'答顾东桥书（原题“答人论学说”）','道在迩而求诸远，事在易而求诸难”（答案就在你身边却非要到远方去寻求，事情本来很容易却非要用困难的方法去做）','9507-9560',NULL,1670666787,1782480564);
INSERT INTO highlights VALUES('22947638_12_9431-9499','22947638',12,'答顾东桥书（原题“答人论学说”）','道的大原则，一般人都很容易理解”，这句话是对的。问题在哪里呢？在于后来的学习者疏忽了那容易理解的道而不去遵循，却把难以明白的东西作为学问','9431-9499',NULL,1670666778,1782480564);
INSERT INTO highlights VALUES('22947638_12_8646-8693','22947638',12,'答顾东桥书（原题“答人论学说”）','一定要切实实行了温凊父母、奉养父母的意念，并且在做的时候感到愉快而没有违心的感觉，这才叫诚意。','8646-8693',NULL,1670663936,1782480564);
INSERT INTO highlights VALUES('22947638_12_7233-7310','22947638',12,'答顾东桥书（原题“答人论学说”）','糊涂的人，如果能随时随物省察人心中的天理，发现本有的良知，那么，再愚笨也会变得聪明，再柔弱也会变得刚强，最终，就能够确立起最根本的本体，走在最终极的道路上','7233-7310',NULL,1670418308,1782480564);
INSERT INTO highlights VALUES('22947638_12_5951-6062','22947638',12,'答顾东桥书（原题“答人论学说”）','因此，以能够成就事情而言，称为学；以能够解除困惑而言，称为问；以能够通晓事物的道理而言，称为思；以能够精细考察而言，称为辨；以能够踏踏实实地践行而言，称为行。分析它们的功用，有五个方面；综合它们所干的事，其实只是同一件事。','5951-6062',NULL,1670417986,1782480564);
INSERT INTO highlights VALUES('22947638_12_3698-3727','22947638',12,'答顾东桥书（原题“答人论学说”）','存养内心，是因为还不能充分穷尽内心，所以必须加以存养的功夫','3698-3727',NULL,1670387363,1782480564);
INSERT INTO highlights VALUES('22947638_12_2802-2848','22947638',12,'答顾东桥书（原题“答人论学说”）','心只有一个，就恻怛之心而言，即称为仁；就心的合理而言，即称为义；就心的有条理而言，即称为理。','2802-2848',NULL,1670381528,1782480564);
INSERT INTO highlights VALUES('22947638_12_2210-2236','22947638',12,'答顾东桥书（原题“答人论学说”）','知的切实实行之处，就是行；行的明晰精察之处，就是知。','2210-2236',NULL,1670381296,1782480564);
INSERT INTO highlights VALUES('22947638_12_2056-2077','22947638',12,'答顾东桥书（原题“答人论学说”）','“真正的知是能够实行，不实行就不足以称为知','2056-2077',NULL,1670381263,1782480564);
