INSERT INTO highlights VALUES('22947638_9_14872-14954','22947638',9,'薛侃录','你若真为了那个身体的自己，就必须依靠这个真正的自己，必须常常保持这个真正自己的本体。做到‘戒慎不睹，恐惧不闻’（在人看不到听不到的地方仍然保持警惕谨慎，唯恐有过错）','14872-14954',NULL,1670339174,1782480564);
