INSERT INTO highlights VALUES('22947638_9_12352-12424','22947638',9,'薛侃录','如果不懂得心的本体并不是固定在某一个事物上，始终刻意去做善事、不做恶事，就又多了一分执着的意思，就不是‘廓然大公’（坦坦荡荡地没有一点私心）了。','12352-12424',NULL,1670338711,1782480564);
