INSERT INTO highlights VALUES('22947638_9_4746-4789','22947638',9,'薛侃录','不刻意喜欢或厌恶，并不是说完全没有了好恶，如果完全没有了好恶，就是一个没有知觉的人了。','4746-4789',NULL,1670289254,1782480564);
INSERT INTO highlights VALUES('22947638_9_4436-4535','22947638',9,'薛侃录','佛家着眼于无善无恶，就一切都不管，不能够治理天下。圣人的无善无恶，只是不要从私欲出发而刻意生发善恶，不为情绪所动，却遵循先王之道，达到了极致，就自然能依循天理，就能‘裁成天地之道，辅相天地之宜’了。','4436-4535',NULL,1670289184,1782480564);
INSERT INTO highlights VALUES('22947638_9_4292-4346','22947638',9,'薛侃录','无善无恶是因为天理本来寂静，有善有恶是因为情绪顺时变幻。不为情绪的变化所动，就是无善无恶，可以称为至善了。”','4292-4346',NULL,1670252668,1782480564);
INSERT INTO highlights VALUES('22947638_9_2683-2708','22947638',9,'薛侃录','我们普通人向圣人学习，不过是去掉私欲而存养天理罢了','2683-2708',NULL,1670238640,1782480564);
INSERT INTO highlights VALUES('22947638_9_1884-1927','22947638',9,'薛侃录','如果只在那里寻求表面景象，讲功用效果，反而助长了向外寻求的弊端，不是真切的求学功夫了。','1884-1927',NULL,1670238484,1782480564);
INSERT INTO highlights VALUES('22947638_9_1011-1046','22947638',9,'薛侃录','学问的深究，也是修养本性。不去深究学问，还是因为修养本性的心志不够真切','1011-1046',NULL,1670238364,1782480564);
INSERT INTO highlights VALUES('22947638_9_824-862','22947638',9,'薛侃录','了解了心的运作，所用功夫才有着落。如果只是死守志向，大概在功夫上又会发生问题','824-862',NULL,1670238283,1782480564);
INSERT INTO highlights VALUES('22947638_8_21398-21451','22947638',8,'陆澄录','人心就是天理。没有私心，就是合乎天理。不合乎天理，就是存有私心。如果把人心和天理分开来分析，好像不太恰当。','21398-21451',NULL,1670223257,1782480564);
INSERT INTO highlights VALUES('22947638_8_21166-21206','22947638',8,'陆澄录','墨子的兼爱没有什么区别，把自己的父子、兄弟与陌生人同等看待，这自然就没有了发端处','21166-21206',NULL,1670222075,1782480564);
