INSERT INTO highlights VALUES('22947638_8_20487-20626','22947638',8,'陆澄录','如果知道至善就是我们的本性，天性都在我们心中，我们的心就是至善存留的地方。那么，我们就不会像从前那样急着向外求取，心志也就安定了。心志安定了，就不会受到干扰，人就安静了。安静而不妄动就是安宁。安宁了，就能专心致志在至善处。千思万想，非要去寻求这个至善，这样就能透过思虑而到达至善','20487-20626',NULL,1670165071,1782480564);
INSERT INTO highlights VALUES('22947638_8_19978-20027','22947638',8,'陆澄录','修身是在情绪已经发生的时候，正心是在情绪还没有发生的时候。心正，就是所谓的中；身修，就是所谓的和。','19978-20027',NULL,1670164958,1782480564);
INSERT INTO highlights VALUES('22947638_8_19560-19582','22947638',8,'陆澄录','格，就是正。纠正那些不正的，使它们归于正道。','19560-19582',NULL,1670162621,1782480564);
INSERT INTO highlights VALUES('22947638_8_18557-18585','22947638',8,'陆澄录','如果一个人说话颠三倒四，那么，他的本心一定缺乏足够的存养','18557-18585',NULL,1670162493,1782480564);
INSERT INTO highlights VALUES('22947638_8_18450-18491','22947638',8,'陆澄录','只要时常存养本心，就是学习。过去和将来的事，想了有什么用呢？想多了就会失去本心。”','18450-18491',NULL,1670162482,1782480564);
