INSERT INTO highlights VALUES('22947638_8_17758-17834','22947638',8,'陆澄录','必须把平时的好色、贪利、慕名之私欲统统清理干净，不得有丝毫遗留，使这颗心彻底纯洁空明，完全是天理，才可以叫作‘喜怒哀乐未发之中’，这才是天下最大的根本。','17758-17834',NULL,1670162190,1782480564);
INSERT INTO highlights VALUES('22947638_8_17274-17527','22947638',8,'陆澄录',unistr('陆澄说：“什么是天理？”\u000a先生说：“摒除一己的私欲，就可以看到天理了。”\u000a陆澄问：“天理为什么称为中？”\u000a先生说：“不偏不倚。”\u000a陆澄问：“不偏不倚，是什么样的状态？”\u000a先生说：“就好像明镜，通体透明彻亮，没有丝毫尘埃沾染。”'),'17274-17527',NULL,1670142953,1782480564);
