INSERT INTO highlights VALUES('22947638_8_15434-15516','22947638',8,'陆澄录','◎“善念萌生时，要意识到并加以扩充。恶念萌生时，要意识到并加以遏制。意识到、扩充、遏制，都是意志、志向，是天赋的智慧。圣人只有这些意志，学习的人应当存养这些意志。”','15434-15516',NULL,1670123551,1782480564);
INSERT INTO highlights VALUES('22947638_8_14935-14982','22947638',8,'陆澄录','“挖一个面积很大但没有源泉的池塘，还不如挖一口面积很小但水源不断的小水井，这样才能生机无限。”','14935-14982',NULL,1670123416,1782480564);
INSERT INTO highlights VALUES('22947638_8_14614-14722','22947638',8,'陆澄录','成就一个人，也只是要他心体纯粹，完全合乎天理。运用事物的时候，都是从天理上生发出来的，然后才可以称‘才’。达到纯天理的境界，才能‘不器’（才能不局限于某一个方面）。就是让羲和稷交换角色，夔种谷，稷作乐，也是可以的。”','14614-14722',NULL,1670123274,1782480564);
INSERT INTO highlights VALUES('22947638_8_14166-14189','22947638',8,'陆澄录','心即道，道即天。明白了心就是明白了道、明白了天','14166-14189',NULL,1670123050,1782480564);
INSERT INTO highlights VALUES('22947638_8_14115-14147','22947638',8,'陆澄录','如果明白要向心里探寻，认识了自己的本心，那么，无时无处不是这个道','14115-14147',NULL,1670122895,1782480564);
INSERT INTO highlights VALUES('22947638_8_13756-13842','22947638',8,'陆澄录','现在的人，对已知的天理不肯存养，对已知的私欲不肯摒弃，却在发愁不能知道所有的事情，只讲空话，有什么好处呢？等到自己内心私欲摒除尽，再发愁不能完全知道所有的事，也为时不晚。”','13756-13842',NULL,1670121168,1782480564);
INSERT INTO highlights VALUES('22947638_8_12909-13021','22947638',8,'陆澄录','心犹如镜子。圣人的心像明亮的镜子，平常人的心像昏暗的镜子。近世的格物之说，好比用镜照物，只在照上用功，却不明白如果镜子昏暗的话，怎么能照得清楚？先生的格物，就像打磨镜子使它明亮，是在打磨上下功夫，镜子明亮之后，就不会耽误照物','12909-13021',NULL,1670121053,1782480564);
INSERT INTO highlights VALUES('22947638_8_12686-12732','22947638',8,'陆澄录','学习的人应当致力于正业，不然把音乐律数算得再熟也没有多大用处。心中必须有礼乐的根本方才可以。','12686-12732',NULL,1670121029,1782480564);
INSERT INTO highlights VALUES('22947638_8_12816-12838','22947638',8,'陆澄录','所以，学习的人必须先从礼乐的根本上苦下功夫。','12816-12838',NULL,1670121026,1782480564);
INSERT INTO highlights VALUES('22947638_8_12264-12303','22947638',8,'陆澄录','喜怒哀乐的本体原为中和。自己一旦有别的想法，稍有过分或不及，便是私欲的表现。”','12264-12303',NULL,1670120910,1782480564);
INSERT INTO highlights VALUES('22947638_8_12111-12198','22947638',8,'陆澄录',unistr('陆澄向先生请教道家所谓的元气、元神、元精指的是什么。\u000a先生说：“三者是一个意思。流行就是气，凝聚就是精，妙用就是神。”'),'12111-12198',NULL,1670120892,1782480564);
INSERT INTO highlights VALUES('22947638_8_11592-11633','22947638',8,'陆澄录','“精神、道德、言行，常常以收敛为主，向外扩散是不得已而为之。天地、人物无不如此。”','11592-11633',NULL,1670120844,1782480564);
INSERT INTO highlights VALUES('22947638_8_9200-9244','22947638',8,'陆澄录','现今的人不能做到情感生发的时候都能符合合适的度，是因为不能全然做到没有生发时候的中正。”','9200-9244',NULL,1666273065,1782480564);
INSERT INTO highlights VALUES('22947638_8_8985-9069','22947638',8,'陆澄录','然而，《孝经》中说：‘不能过分悲哀而失去本性。’并非圣人要求世人抑制情感，而是天理本身自有它的分寸界限，不可超越太过。人只要明了了心体，情感自然就不会增减一分一毫了。”','8985-9069',NULL,1666273029,1782480564);
INSERT INTO highlights VALUES('22947638_8_8008-8032','22947638',8,'陆澄录','子思概括《大学》一书的大意，写了《中庸》的第一章','8008-8032',NULL,1666235378,1782480564);
INSERT INTO highlights VALUES('22947638_8_7678-7733','22947638',8,'陆澄录','“邪鬼怎能迷惑正直的人？这一怕其实是心里有邪念，心有邪念，就会被迷惑。并不是鬼迷惑了人，是人被自己的心迷惑了。','7678-7733',NULL,1666235341,1782480564);
INSERT INTO highlights VALUES('22947638_8_7148-7301','22947638',8,'陆澄录','这时应该教他做省察克治的功夫。省察克治，就没间断的时候了，好比驱除盗贼，要有一个彻底驱除的决心。无事时，将好色、贪财、慕名等私欲统统搜寻出来，一定要将病根拔去，让它永远不再复发，才算痛快。又好比猫逮鼠，眼睛盯着，耳朵听着。稍有杂念萌动，就坚决除掉，不给它喘息的机会。既不让它躲藏，也不让它逃脱，这才是真功夫','7148-7301',NULL,1666235185,1782480564);
INSERT INTO highlights VALUES('22947638_8_7084-7119','22947638',8,'陆澄录','因此，应该教他静坐，借以安定思绪。等到一定时间，心意就会渐渐安定下来。','7084-7119',NULL,1666229483,1782480564);
INSERT INTO highlights VALUES('22947638_8_7038-7083','22947638',8,'陆澄录','教别人求学，不可偏执一端。开始学习的时候，往往心猿意马、心神不定，所想的大多是私欲方面的事','7038-7083',NULL,1666229464,1782480564);
INSERT INTO highlights VALUES('22947638_8_5831-5865','22947638',8,'陆澄录','心就是本性，本性就是道理，说一个‘与’字，未免将心和理一分而为二了。','5831-5865',NULL,1666229183,1782480564);
INSERT INTO highlights VALUES('22947638_8_5514-5556','22947638',8,'陆澄录','应该在心体上下苦功夫，大凡不明白、行不通的，必须返回自身，在自己心上体会，这样就能通','5514-5556',NULL,1666229137,1782480564);
INSERT INTO highlights VALUES('22947638_8_5221-5336','22947638',8,'陆澄录','立志用功，就好像种树。开始生根发芽，没有树干；有了树干，没有枝节；有了枝节，然后有树叶；有了树叶，然后有花果。刚种植时，只顾栽培浇灌，不要想着枝啊，叶啊，花啊，果啊。空想有什么用？只要不忘记栽培浇灌的功夫，哪用担心没有枝叶和花果？','5221-5336',NULL,1666229068,1782480564);
INSERT INTO highlights VALUES('22947638_8_4688-4771','22947638',8,'陆澄录','君子只求在现在位置上做自己应该做的事，不愿去做本分以外的事。处在夷狄的位置，就做夷狄的事。身处患难，就做患难时所应该做的事。君子无论在什么地方，都能心安理得、怡然自在','4688-4771',NULL,1666154195,1782480564);
INSERT INTO highlights VALUES('22947638_8_4302-4443','22947638',8,'陆澄录','静时念念不忘去摒弃私欲、存养天理，动时也念念不忘摒弃私欲、存养天理，不管是否安静。如果仅仅依靠安静下来，不仅渐渐会有喜静厌动的毛病，而且其中诸多毛病并没有解决，会潜伏积累下来，最终不能根除，遇到什么事还会再次发生。如果以遵循天理为重，怎么会不安静？以安静为重，但不一定能遵循天理。”','4302-4443',NULL,1666147700,1782480564);
INSERT INTO highlights VALUES('22947638_8_3781-3823','22947638',8,'陆澄录','“认知是践行的开始，践行是认知的结果。圣学只有一个功夫，知、行不能分开当作两件事。”','3781-3823',NULL,1666147548,1782480564);
INSERT INTO highlights VALUES('22947638_8_3657-3701','22947638',8,'陆澄录','‘格物’‘致知’是‘诚意’的功夫，‘道问学’是‘尊德性’的功夫，‘明善’是‘诚身’的功夫','3657-3701',NULL,1666147487,1782480564);
INSERT INTO highlights VALUES('22947638_8_3638-3656','22947638',8,'陆澄录','其他的比如，‘博文’是‘约礼’的功夫','3638-3656',NULL,1666147477,1782480564);
INSERT INTO highlights VALUES('22947638_8_3602-3638','22947638',8,'陆澄录','博学、审问、慎思、明辨、笃行，都是为了获得‘惟一’而进行的‘惟精’功夫。','3602-3638',NULL,1666147461,1782480564);
INSERT INTO highlights VALUES('22947638_8_3462-3487','22947638',8,'陆澄录','‘惟一’是‘惟精’的目的，‘惟精’是‘惟一’的功夫','3462-3487',NULL,1666147438,1782480564);
INSERT INTO highlights VALUES('22947638_8_3303-3341','22947638',8,'陆澄录','学者只需从人情事理上用功，自然可以通达仁义，不必另外去寻找通达仁义的途径。”','3303-3341',NULL,1666147374,1782480564);
INSERT INTO highlights VALUES('22947638_8_2843-2932','22947638',8,'陆澄录','先生说：“这是由于你只知道在安静中修养，却没有在克己上下功夫。这样的话，碰到一点什么事情，就会摇摆不定。人应该在事情上磨炼自己，才能立足沉稳，才能达到‘静亦定，动亦定’的境界。”','2843-2932',NULL,1666147081,1782480564);
INSERT INTO highlights VALUES('22947638_8_2206-2315','22947638',8,'陆澄录','圣人遇到什么样的时机，才会做什么样的事情。只怕镜子不够明亮，不怕物来了不能照。研究事物的变化，如同照镜子。但是，学习的人必须有一个‘明’的功夫。对于学习的人来说，只担心自己的心还没有明白透彻，不害怕事物变化的无穷无尽。','2206-2315',NULL,1666145871,1782480564);
INSERT INTO highlights VALUES('22947638_8_1956-2050','22947638',8,'陆澄录',unistr('◎陆澄问：“圣人能应变无穷，莫非事先做过准备？”\u000a先生说：“哪能顾及那么多？圣人的心犹如明镜，只是一个‘明’字，随时感应，遇物而照。'),'1956-2050',NULL,1666145830,1782480564);
INSERT INTO highlights VALUES('22947638_8_1213-1249','22947638',8,'陆澄录','和朋友相处，彼此谦让，就会彼此受益；彼此攀比、争强好胜，只能彼此受损。”','1213-1249',NULL,1666145633,1782480564);
INSERT INTO highlights VALUES('22947638_8_799-816','22947638',8,'陆澄录','主一，就是一心一意专注在天理上。”','799-816',NULL,1666145570,1782480564);
INSERT INTO highlights VALUES('3300026077_316_1550-1640','3300026077',316,'跋 摇摇晃晃的人间','而诗歌是什么呢，我不知道，也说不出来，不过是情绪在跳跃，或沉潜。不过是当心灵发出呼唤的时候，它以赤子的姿势到来。不过是一个人摇摇晃晃地在摇摇晃晃的人间走动的时候，它充当了一根拐杖。','1550-1640',1,1723519643,1782398562);
INSERT INTO highlights VALUES('3300026077_316_1479-1521','3300026077',316,'跋 摇摇晃晃的人间','活到这个年纪，说的话已经太多太多。但是诗歌一直跟在身边，我想它的时候，它不会拒绝我。','1479-1521',1,1723519608,1782398562);
INSERT INTO highlights VALUES('3300026077_316_983-1149','3300026077',316,'跋 摇摇晃晃的人间','其实我一直不是一个安静的人，我不甘心这样的命运，我也做不到逆来顺受，但是我所有的抗争都落空，我会泼妇骂街，当然我本身就是一个农妇，我没有理由完全脱离她的劣根性。但是我根本不会想到诗歌会是一种武器，即使是，我也不会用，因为太爱，因为舍不得。即使我被这个社会污染得没有一处干净的地方，而回到诗歌，我又干净起来。诗歌一直在清洁我，悲悯我。','983-1149',1,1723519561,1782398562);
INSERT INTO highlights VALUES('3300026077_315_748-842','3300026077',315,'再致','来不及爱，就这样告别。心疼你在伤痕累累的人身上最锋利的刀也划不出新的印痕','748-842',1,1723519458,1782398562);
INSERT INTO highlights VALUES('3300026077_315_370-391','3300026077',315,'再致','来不及爱，就得告别，像我遇见的那么多人一样','370-391',1,1723519433,1782398562);
INSERT INTO highlights VALUES('3300026077_314_729-916','3300026077',314,'离我最近的是雨声','刚写下你的名字风吹了进来：纸张颤抖我也颤抖着雨打窗棂这从天而降的事物离破碎不足一秒钟','729-916',1,1723519347,1782398562);
INSERT INTO highlights VALUES('3300026077_313_1064-1151','3300026077',313,'我想这样和你一起生活','如果我还颤抖，哭泣请你相信，我不过是把这样的幸福在梦里复述','1064-1151',1,1723519290,1782398562);
INSERT INTO highlights VALUES('3300026077_313_748-841','3300026077',313,'我想这样和你一起生活','风吹动晾晒着的我们的衣裳它们廉价，柔软风吹动阳台上的花草，它们也有醉意','748-841',1,1723519279,1782398562);
