INSERT INTO highlights VALUES('3300026077_289_370-485','3300026077',289,'春雪','雪下了，万物泛白。我不该想到更大的黑隐匿着在一棵植物还没有发青的内部，没有多余的赞美词雪，一片接一片下坠，以轻击重','370-485',1,1723516976,1782398562);
INSERT INTO highlights VALUES('3300026077_288_759-867','3300026077',288,'你只需活着','活着，如一截影子，从天空落进水里一辈子在一起的人无法相爱，独自成活是谁无法让我们对这样的人生说：不！','759-867',1,1723516382,1782398562);
INSERT INTO highlights VALUES('3300026077_288_610-677','3300026077',288,'你只需活着','而儿子仿佛一个慢慢走近的客人，慢慢染上了我的体味要说幸福，这恰恰是，刚刚好。','610-677',1,1723516304,1782398562);
