INSERT INTO highlights VALUES('3300026077_276_378-400','3300026077',276,'每一个时辰都是孤独的','我只要一平米的孤独：一盏灯，一本书，一个疾病','378-400',1,1723514449,1782398562);
INSERT INTO highlights VALUES('3300026077_275_1020-1115','3300026077',275,'今夜，我特别想你','只是一想到你，世界在明亮的光晕里倒退一些我们以为永恒的，包括时间都不堪一击','1020-1115',1,1723514250,1782398562);
INSERT INTO highlights VALUES('3300026077_275_608-828','3300026077',275,'今夜，我特别想你','即便病入膏肓，我依然高挂明月它让我白，让我有理由空荡让我在这个地图上找不到的村庄里奢侈地悲伤只是一想到你，我就小了，轻了如一棵狗尾草怀抱永恒的陌生摇晃','608-828',1,1723514194,1782398562);
INSERT INTO highlights VALUES('3300026077_274_845-936','3300026077',274,'赞美诗','一朵云如一辆邮车好消息从一个地方搬运到另一个地方仿佛低下头看了看我','845-936',1,1723514020,1782398562);
INSERT INTO highlights VALUES('3300026077_273_790-804','3300026077',273,'背景','不忍惊动远方传来的零星的消息','790-804',1,1723513956,1782398562);
INSERT INTO highlights VALUES('3300026077_273_660-761','3300026077',273,'背景','我坐在田头，秋风都往怀里吹麻雀儿一阵阵的，落下又旋起它们落在横过麦田的电话线上，那么轻','660-761',1,1723513942,1782398562);
INSERT INTO highlights VALUES('3300026077_273_576-631','3300026077',273,'背景','新种的小麦晃出一层毛茸茸的绿野草枯黄出让人心醉的时辰','576-631',1,1723513935,1782398562);
INSERT INTO highlights VALUES('3300026077_272_566-628','3300026077',272,'冬天里的我的村庄','他的院子里落满了树叶子，在风里打了几转落下来，再打了几转，再落下来','566-628',1,1723513862,1782398562);
