INSERT INTO highlights VALUES('3300026077_245_626-689','3300026077',245,'那么多水，汇集','她以为遇见一个人，就能让生命寿终正寝如同水回流到水。过程不会留下湿痕','626-689',1,1723509862,1782398562);
INSERT INTO highlights VALUES('3300026077_245_421-499','3300026077',245,'那么多水，汇集','她相信在海的下面还有一个天，飘着白云，阳光，咒语，棺材如同爱，从头顶和脚底扣拢，在胸口拱出巨大的山','421-499',1,1723509811,1782398562);
