INSERT INTO highlights VALUES('3300026077_228_995-1047','3300026077',228,'我还是想','幸好是你。不然这人间哪配得上一个女人的心怀不轨','995-1047',1,1723451417,1782398562);
INSERT INTO highlights VALUES('3300026077_224_375-457','3300026077',224,'我们很久不见了','我去见你白杨树芽紧握拳头那个春天必然会受沉重一击','375-457',1,1723451119,1782398562);
