INSERT INTO highlights VALUES('3300026077_220_689-864','3300026077',220,'我想要的爱情','天空把所有鸟的叫声都当成了礼物才惊心动魄地蓝我被天空裹住，越来越紧而我依旧腾出心靠左边的位置爱你真是一件不可思议的事情','689-864',1,1723450728,1782398562);
INSERT INTO highlights VALUES('3300026077_220_515-614','3300026077',220,'我想要的爱情','你看，我不打算以容貌取悦你了也没有需要被你怜悯的部分：我爱我身体里块块锈斑胜过爱你','515-614',1,1723450700,1782398562);
INSERT INTO highlights VALUES('3300026077_219_619-845','3300026077',219,'麦子黄了','深夜，看见父亲背着月亮吸烟——那个生长过万顷麦子的脊背越来越窄了父亲啊，你的幸福是一层褐色的麦子皮痛苦是纯白的麦子心我很满意在这里降落如一只麻雀儿衔着天空的蓝穿过','619-845',1,1723450432,1782398562);
INSERT INTO highlights VALUES('3300026077_219_542-590','3300026077',219,'麦子黄了','如何在如此的浩荡里，找到一粒白住进去？','542-590',1,1723450420,1782398562);
INSERT INTO highlights VALUES('3300026077_219_455-513','3300026077',219,'麦子黄了','在月光里静默的麦子，它们之间轻微的摩擦就是人间万物在相爱了','455-513',1,1723450284,1782398562);
INSERT INTO highlights VALUES('3300026077_217_769-988','3300026077',217,'五月·小麦','作为一个农人，我羞于用笔墨说出对一颗麦子的情怀我只能把它放在嘴里咀嚼从秋到夏的过程慢慢咽下去，填满我在尘世的忧戚以此心安理得地构建对一颗麦子的反包围','769-988',1,1723450215,1782398562);
INSERT INTO highlights VALUES('3300026077_215_887-976','3300026077',215,'在黄昏','她们和每一片树叶，每一棵小麦，每一条狗每一个活着和死去的打招呼','887-976',1,1723449897,1782398562);
INSERT INTO highlights VALUES('3300026077_215_728-779','3300026077',215,'在黄昏','没有人知道我体贴每一棵草也没有人知道我的宝藏','728-779',1,1723449880,1782398562);
INSERT INTO highlights VALUES('3300026077_215_590-699','3300026077',215,'在黄昏','我看见每一个我在晚风里摇晃在遥远的村庄里沉默地抒情，没有人知道我没有人知道我腹腔的花朵，鸟鸣，一条蛇皮','590-699',1,1723449863,1782398562);
INSERT INTO highlights VALUES('3300026077_213_779-919','3300026077',213,'每个春天，我都会唱歌','那么多人经过春天，那么多花在打开他猜不出我在说什么但是，每个春天我都会唱歌歌声在风里摇曳的样子，忧伤又甜蜜','779-919',1,1723433503,1782398562);
INSERT INTO highlights VALUES('3300026077_213_641-662','3300026077',213,'每个春天，我都会唱歌','一朵花开的时间太短，一个春天驻足的日子太少','641-662',1,1723433481,1782398562);
INSERT INTO highlights VALUES('3300026077_212_374-526','3300026077',212,'渴望一场大雪','渴望一场没有预谋，比死亡更厚的大雪它要突如其来，要如倾如注，把所有的仇恨都往下砸我需要它如此用力。我的渺小不是一场雪漫不经心的理由','374-526',1,1723433429,1782398562);
INSERT INTO highlights VALUES('3300026077_211_370-476','3300026077',211,'夜晚','蛙鸣。虫吟。泥土呼吸。一个手电筒的光由远及近一个人在夜里走动，偶尔遇见另外一个不打招呼，各自走远','370-476',1,1723433279,1782398562);
INSERT INTO highlights VALUES('3300026077_210_860-879','3300026077',210,'浮尘','她把远方拉进身体，依然有无法穿过的恐惧','860-879',1,1723426466,1782398562);
INSERT INTO highlights VALUES('3300026077_210_496-543','3300026077',210,'浮尘','一次次，她试图从身体里掏出光亮掏出蜜','496-543',1,1723426445,1782398562);
INSERT INTO highlights VALUES('3300026077_206_742-959','3300026077',206,'日记：我仅仅存在于此','而此刻，夜来香的味道穿过窗棂门口的虫鸣高高低低。我曾经与多少人遇见过在没有伴侣的人世里我是如此丰盈，比一片麦子沉重但是我只是低着头接受月光的照耀','742-959',1,1723425754,1782398562);
INSERT INTO highlights VALUES('3300026077_205_647-790','3300026077',205,'在田野上打柴火','人间情事一丢，就有了清澈的骨骼是否有一颗高贵的灵魂不是我在意的田间小麦长势良好喜鹊一会儿落在树上，一会儿落在地上','647-790',1,1723425685,1782398562);
INSERT INTO highlights VALUES('3300026077_204_714-733','3300026077',204,'唯独我，不是','——我怀疑我的爱，每一次都让人粉身碎骨','714-733',1,1723425602,1782398562);
INSERT INTO highlights VALUES('3300026077_204_455-685','3300026077',204,'唯独我，不是','抱膝于午夜，听窗外的凋零之声：不仅仅是蔷薇的还有夜的本身，还有整个银河系一个宇宙——我不知道向谁呼救生命的豁口：很久不至的潮汐一落千丈许多夜晚，我是这样过来的：把花朵撕碎','455-685',1,1723425593,1782398562);
INSERT INTO highlights VALUES('3300026077_204_807-897','3300026077',204,'唯独我，不是','无论如何，我依旧无法和他对称我相信他和别人的都是爱情唯独我，不是','807-897',1,1723425567,1782398562);
