INSERT INTO highlights VALUES('3300026077_171_830-1063','3300026077',171,'与一面镜子遇见了','没有这面镜子，世界该是公允的了就是说，没有那个人，世界就是公允的遇见他，我就喜欢在这镜子前徘徊，如一个傻子，一个犯病者结果我不停地撞上去知道自己是死在哪里，却不肯写一个验尸报告','830-1063',1,1723369674,1782398562);
