INSERT INTO highlights VALUES('3300026077_161_2782-2878','3300026077',161,'代序 余秀华：让我疼痛的诗歌','“她的诗，放在中国女诗人的诗歌中，就像把杀人犯放在一群大家闺秀里一样醒目——别人都穿戴整齐、涂着脂粉、喷着香水，白纸黑字，闻不出一点汗味，唯独她烟熏火燎、泥沙俱下，字与字之间，还有明显的血污。','2782-2878',1,1720224657,1782398562);
INSERT INTO highlights VALUES('3300026077_161_2246-2292','3300026077',161,'代序 余秀华：让我疼痛的诗歌','当我某个时候写到这些内容的时候，那一定是它们触动了，温暖了我，或者让我真正伤心了，担心了。”','2246-2292',1,1720224434,1782398562);
