INSERT INTO highlights VALUES('651358_30_10980-10996','651358',60,'第二十八章 中国哲学在现代世界','人必须先说很多话，然后保持静默。','8669-8685',NULL,1659879734,1782480567);
INSERT INTO highlights VALUES('651358_30_10337-10365','651358',60,'第二十八章 中国哲学在现代世界','一个完全的形上学系统，应当始于正的方法，而终于负的方法。','8026-8054',NULL,1659879314,1782480567);
INSERT INTO highlights VALUES('651358_30_9741-9764','651358',60,'第二十八章 中国哲学在现代世界','在西方，康德可以说曾经应用过形上学的负的方法。','7430-7453',NULL,1659879256,1782480567);
INSERT INTO highlights VALUES('651358_30_9891-9936','651358',60,'第二十八章 中国哲学在现代世界','形上学的任务不在于，对于不可知者说些什么；而仅仅在于，对于不可知是不可知这个事实，说些什么','7580-7625',NULL,1659879230,1782480567);
INSERT INTO highlights VALUES('651358_30_9282-9389','651358',60,'第二十八章 中国哲学在现代世界','在《新知言》一书中，我认为形上学有两种方法：正的方法和负的方法。正的方法的实质，是说形上学的对象是什么；负的方法的实质，则是不说它。这样做，负的方法也就启示了它的性质和某些方面，这些方面是正的描写和分析无法说出的。','6971-7078',NULL,1659879165,1782480567);
INSERT INTO highlights VALUES('651358_30_9437-9521','651358',60,'第二十八章 中国哲学在现代世界','西方哲学以他所谓“假设的概念”为出发点，中国哲学以他所谓“直觉的概念”为出发点。其结果，正的方法很自然地在西方哲学中占统治地位，负的方法很自然地在中国哲学中占统治地位。','7126-7210',NULL,1659879106,1782480567);
INSERT INTO highlights VALUES('651358_30_8566-8679','651358',60,'第二十八章 中国哲学在现代世界','他做的都只是平常人所做的事，但是由于有高度的觉解，他所做的事对于他就有不同的意义。换句话说，他是在觉悟状态做他所做的事，别人是在无明状态做他们所做的事。禅宗有人说，“觉”字乃万妙之源。由觉产生的意义，构成了他的最高的人生境界。','6616-6729',NULL,1659879039,1782480567);
INSERT INTO highlights VALUES('651358_30_7162-7218','651358',60,'第二十八章 中国哲学在现代世界','我们可以把各种不同的人生境界划分为四个概括的等级。从最低的说起，它们是：自然境界、功利境界、道德境界、天地境界。','5212-5268',NULL,1659878860,1782480567);
INSERT INTO highlights VALUES('651358_30_6214-6258','651358',60,'第二十八章 中国哲学在现代世界','人必须思及不可思者，可是刚一要这么做，它就立即溜掉了。这正是哲学最迷人而又最恼人的地方。','4625-4669',NULL,1659878800,1782480567);
INSERT INTO highlights VALUES('651358_30_6182-6214','651358',60,'第二十八章 中国哲学在现代世界','人需要思，才能知道不可思者；正如有时候人需要声音，才能知道静默。','4593-4625',NULL,1659878783,1782480567);
INSERT INTO highlights VALUES('651358_30_5518-5552','651358',60,'第二十八章 中国哲学在现代世界','哲学，特别是形上学，它的用处不是增加实际的知识，而是提高精神的境界。','3929-3963',NULL,1659878612,1782480567);
INSERT INTO highlights VALUES('651358_30_5440-5500','651358',60,'第二十八章 中国哲学在现代世界','如果有人要我下哲学的定义，我就会用悖论的方式回答：哲学，特别是形上学，是一门这样的知识，在其发展中，最终成为“不知之知”','3851-3911',NULL,1659878604,1782480567);
INSERT INTO highlights VALUES('651358_30_4832-4931','651358',60,'第二十八章 中国哲学在现代世界','好的形上学是明明白白的，不需要说相信它，就像不需要说相信数学一样。形上学与数学、逻辑的区别，在于后二者不需要以“有某种事物”为出发点。“有某种事物”是对实际的一个肯定，也是形上学需要做的唯一的肯定。','3604-3703',NULL,1659878574,1782480567);
INSERT INTO highlights VALUES('651358_30_2827-2969','651358',60,'第二十八章 中国哲学在现代世界','北大哲学系的传统和重点是历史研究，其哲学倾向是观念论，用西方哲学的名词说是康德派、黑格尔派，用中国哲学的名词说是陆王。相反，清华哲学系的传统和重点是用逻辑分析方法研究哲学问题，其哲学倾向是实在论，用西方哲学的名词说是柏拉图派（因为新实在论哲学是柏拉图式的），用中国哲学的名词说是程朱。','1600-1742',NULL,1659877828,1782480567);
INSERT INTO highlights VALUES('651358_29_9848-10024','651358',59,'第二十七章 西方哲学的传入','西方哲学对中国哲学的永久性贡献，是逻辑分析方法。在第二十一章我曾说，佛家和道家都用负的方法。逻辑分析方法正和这种负的方法相反，所以可以叫做正的方法。负的方法，试图消除区别，告诉我们它的对象不是什么；正的方法，则试图做出区别，告诉我们它的对象是什么。','7889-8065',NULL,1659877422,1782480567);
INSERT INTO highlights VALUES('651358_29_7701-7871','651358',59,'第二十七章 西方哲学的传入','余疲于哲学有日矣。哲学上之说，大都可爱者不可信，可信者不可爱。余知真理，而余又爱其谬误伟大之形而上学、高严之伦理学与纯粹之美学，此吾人所酷嗜也。然求其可信者，则宁在知识论上之实证论、伦理学上之快乐论与美学上之经验论。知其可信而不能爱，觉其可爱而不能信，此近二三年中最大之烦闷，而近日之嗜好所以渐由哲学而移于文学，而欲于其中求直接之慰藉者也。','6104-6274',NULL,1659877051,1782480567);
INSERT INTO highlights VALUES('651358_28_10401-10463','651358',58,'第二十六章 新儒家：心学','若顺着这种论证推下去，我们可以说，新儒家比道家、佛家更为一贯地坚持道家、佛家的基本观念。他们比道家还要道家，比佛家还要佛家。','7390-7452',NULL,1659876131,1782480567);
INSERT INTO highlights VALUES('651358_28_10307-10372','651358',58,'第二十六章 新儒家：心学','都是为了君臣父子夫妇著了相，便需逃避。如吾儒有个父子，还他以仁；有个君臣，还他以义；有个夫妇，还他以别。何曾著父子君臣夫妇的相？”','7296-7361',NULL,1659876126,1782480567);
INSERT INTO highlights VALUES('651358_28_7856-7932','651358',58,'第二十六章 新儒家：心学','什么是良知？它不过是我们心的内在光明，宇宙本有的统一，也就是《大学》所说的“明德”。所以致良知也就是明明德。这样，全部的《大学》就归结为一句话：致良知。','5561-5637',NULL,1659875759,1782480567);
INSERT INTO highlights VALUES('651358_28_7299-7335','651358',58,'第二十六章 新儒家：心学','致良知不能用佛家沉思默虑的方法。致良知，必须通过处理普通事务的日常经验。','5004-5040',NULL,1659875615,1782480567);
INSERT INTO highlights VALUES('651358_28_6554-6672','651358',58,'第二十六章 新儒家：心学','这句话的意思是，人人有做圣人的潜能。他可能成为实际的圣人，只要他遵从他的良知的指示而行。换句话说，他需要做的，是将他的良知付诸实践，或者用王守仁的术语说，就是“致良知”。因此，“致良知”就成了王学的中心观念，王守仁在晚年就只讲这三个字。','4617-4735',NULL,1659875554,1782480567);
INSERT INTO highlights VALUES('651358_28_5722-5805','651358',58,'第二十六章 新儒家：心学','我们对事物的最初反应，使我们自然而自发地知道是为是，非为非。这种知，是我们本性的表现，王守仁称之为“良知”。我们需要做的一切，不过是遵从这种知的指示，毫不犹豫地前进。','3786-3869',NULL,1659875422,1782480567);
INSERT INTO highlights VALUES('651358_28_5591-5610','651358',58,'第二十六章 新儒家：心学','三纲领”就归结为“一纲领”：“明明德。','3655-3674',NULL,1659875400,1782480567);
INSERT INTO highlights VALUES('651358_28_4719-4915','651358',58,'第二十六章 新儒家：心学','关于“亲民”，他写道：“明明德者，立其天地万物一体之体也；亲民者，达其天地万物一体之用也。故明明德必在于亲民，而亲民乃所以明其明德也。亲吾之父以及人之父，以及天下人之父，而后吾之仁实与吾之父、人之父、与天下人之父而为一体矣，实与之为一体而后孝之明德始明矣。……君臣也，夫妇也，朋友也，以至于山川神鬼鸟兽草木也，莫不实有以亲之，以达吾一体之仁。然后吾之明德始无不明，而真能以天地万物为一体矣。”','3141-3337',NULL,1659875359,1782480567);
INSERT INTO highlights VALUES('651358_28_3635-3780','651358',58,'第二十六章 新儒家：心学','根据朱熹的系统，那就只能说，因有孝之理，故有孝亲之心；因有忠之理，故有忠君之心。可是不能反过来说。但是王守仁所说的，恰恰是反过来说。根据朱熹的系统，一切理都是永恒地在那里，无论有没有心，理照样在那里。根据王守仁的系统，则如果没有心，也就没有理。如此，则心是宇宙的立法者，也是一切理的立法者。','2415-2560',NULL,1659874761,1782480567);
INSERT INTO highlights VALUES('651358_28_3306-3411','651358',58,'第二十六章 新儒家：心学','由这几段话，我们可以知道，王守仁的宇宙概念是什么意思。在他的这个概念中，宇宙是一个精神的整体，其中只有一个世界，就是我们自己经验到的这个具体的实际世界。这样，当然就没有，朱熹如此着重强调的、抽象的理世界的地位。','2086-2191',NULL,1659874672,1782480567);
INSERT INTO highlights VALUES('651358_28_3454-3474','651358',58,'第二十六章 新儒家：心学','心即理也。天下又有心外之事，心外之理乎？','2234-2254',NULL,1659874662,1782480567);
INSERT INTO highlights VALUES('651358_28_2035-2126','651358',58,'第二十六章 新儒家：心学','在朱熹看来，实在有两个世界，一个是抽象的，一个是具体的。在陆九渊看来，实在只有一个世界，它就是心（个人的心）或“心”（宇宙的心）。','1173-1264',NULL,1659873101,1782480567);
INSERT INTO highlights VALUES('651358_28_1633-1646','651358',58,'第二十六章 新儒家：心学','宇宙便是吾心，吾心即是宇宙','771-784',NULL,1659872983,1782480567);
INSERT INTO highlights VALUES('651358_28_1571-1613','651358',58,'第二十六章 新儒家：心学','四方上下曰宇，往古来今曰宙。’忽大省曰：‘宇宙内事，乃己分内事；己分内事，乃宇宙内事','709-751',NULL,1659872964,1782480567);
INSERT INTO highlights VALUES('651358_27_3088-3154','651358',57,'第二十五章 新儒家：理学','如舟只可行之于水，车只可行之于陆。”又有一段说：“问：枯槁有理否？曰：才有物，便有理。天不曾生个笔，人把兔毫来做笔，才有笔，便有理。','1863-1929',NULL,1659869467,1782480567);
INSERT INTO highlights VALUES('651358_26_10890-10935','651358',56,'第二十四章 新儒家：两个学派的开端','无论如何，我们还是在这里找到了中国的浪漫主义（风流）与中国的古典主义（名教）的最好的结合。','8697-8742',NULL,1659864236,1782480567);
INSERT INTO highlights VALUES('651358_26_10765-10820','651358',56,'第二十四章 新儒家：两个学派的开端','这样的人是不可征服的，在这个意义上，他们真是“豪雄”。可是他们并不是普通意义上的“豪雄”，他们是“风流人豪”。','8572-8627',NULL,1659864186,1782480567);
INSERT INTO highlights VALUES('651358_26_9404-9457','651358',56,'第二十四章 新儒家：两个学派的开端','风流的基本品质，是有个超越万物区别的心，在生活中只遵从这个心，而不遵从别的。照朱熹的解释，曾点恰恰是这种人','7085-7138',NULL,1659864044,1782480567);
INSERT INTO highlights VALUES('651358_26_6765-6811','651358',56,'第二十四章 新儒家：两个学派的开端','程颢说的“廓然而大公，物来而顺应”，勿“自私”，勿“用智”，与周敦颐说的“静虚动直”是一回事','4809-4855',NULL,1659863667,1782480567);
INSERT INTO highlights VALUES('651358_26_6661-6700','651358',56,'第二十四章 新儒家：两个学派的开端','圣人之喜，以物之当喜；圣人之怒，以物之当怒。是圣人之喜怒，不系于心，而系于物也','4705-4744',NULL,1659863638,1782480567);
INSERT INTO highlights VALUES('651358_26_6509-6552','651358',56,'第二十四章 新儒家：两个学派的开端','新儒家处理情感的方法，遵循着与王弼相同的路线。最重要的一点是不要将情感与自我联系起来。','4553-4596',NULL,1659863560,1782480567);
INSERT INTO highlights VALUES('651358_26_5709-5741','651358',56,'第二十四章 新儒家：两个学派的开端','在修养的方法论上，以“敬”代“静”，标志着新儒家进一步离开了禅宗','4116-4148',NULL,1659863513,1782480567);
INSERT INTO highlights VALUES('651358_26_5150-5295','651358',56,'第二十四章 新儒家：两个学派的开端','程颐也区别“形而上”与“形而下”。这两个名词，源出《易传》：“形而上者谓之道，形而下者谓之器。”（《系辞传上》）在程朱的系统中，这个区别相当于西方哲学中“抽象”与“具体”的区别。“理”是“形而上”的“道”，也可以说是“抽象”的；“器”，程朱指个体事物，是“形而下”的，也可以说是“具体”的。','3557-3702',NULL,1659863425,1782480567);
INSERT INTO highlights VALUES('651358_26_4474-4489','651358',56,'第二十四章 新儒家：两个学派的开端','在有数学之前已有一个“数学”。','3244-3259',NULL,1659863369,1782480567);
INSERT INTO highlights VALUES('651358_26_4185-4265','651358',56,'第二十四章 新儒家：两个学派的开端','程朱认为，我们所见的宇宙，不仅是气的产物，也是理的产物。事物有不同的种类，是因为气聚时遵循不同的理。花是花，因为气聚时遵循花之理；叶是叶，因为气聚时遵循叶之理。','2955-3035',NULL,1659863284,1782480567);
INSERT INTO highlights VALUES('651358_26_3907-3967','651358',56,'第二十四章 新儒家：两个学派的开端','道家的“道”是统一的最初的“一”，由它生出宇宙的万物。相反，《易传》的道则是“多”，它们是支配宇宙万物每个单独范畴的原则','2677-2737',NULL,1659863253,1782480567);
INSERT INTO highlights VALUES('651358_26_2320-2513','651358',56,'第二十四章 新儒家：两个学派的开端','“必有事焉”，“勿助长”，这是孟子养浩然之气的方法，也是新儒家极其赞赏的方法。在程颢看来，人必须首先觉解他与万物本来是合一的道理。然后，他需要做的一切，不过是把这个道理放在心中，做起事来诚实地聚精会神地遵循着这个道理。这样的功夫积累多了，他就会真正感觉到他与万物合一。所谓“以诚敬存之”，就是“必有事焉”。可是达到这个合一，又必须毫无人为的努力。在这个意义上，他一定“未尝致纤毫之力”。','1453-1646',NULL,1659862333,1782480567);
INSERT INTO highlights VALUES('651358_26_1245-1266','651358',56,'第二十四章 新儒家：两个学派的开端','自然界的规律是不是人心（或宇宙的心）创制的','741-762',NULL,1659862226,1782480567);
INSERT INTO highlights VALUES('651358_25_16694-16784','651358',55,'第二十三章 新儒家：宇宙发生论者','新儒家建立了一个观点，从这个观点看来，原先儒家评定为道德的行为，都获得更高的价值，即超道德的价值。它们本身全都有禅宗称为“妙道”的性质。在这个意义上，新儒家确实是禅宗进一步的发展。','14284-14374',NULL,1659862165,1782480567);
INSERT INTO highlights VALUES('651358_25_16457-16633','651358',55,'第二十三章 新儒家：宇宙发生论者','圣人就是充分觉解这个过程的人。因此，他既不求在此过程以外，如佛家那样追求破除因果，结束生命；又不求长生不老，如道教那样追求修炼身体，尽可能地长留人世。圣人由于觉解宇宙之性，因而知道“生无所得”，“死无所丧”（《正蒙·诚明篇》，见《张子全书》卷三）。所以他只求过正常的生活。他活着，就做作为社会一员和作为宇宙一员的义务需要他做的事；一旦死去，他就安息了。','14047-14223',NULL,1659862109,1782480567);
INSERT INTO highlights VALUES('651358_25_15755-15874','651358',55,'第二十三章 新儒家：宇宙发生论者','《正蒙》中又写道：“气聚，则离明得施而有形；不聚，则离明不得施而无形。方其聚也。安得不谓之客；方其散也，安得遽谓之无！”于是张载尽力排除佛老的无。他说：“知太虚即气，即无无。”太虚实际上不是绝对真空；它只是气处于散的状态，再也看不见而已。','13345-13464',NULL,1659861983,1782480567);
INSERT INTO highlights VALUES('651358_25_15620-15726','651358',55,'第二十三章 新儒家：宇宙发生论者','太和是气的全体之名，又被形容为“游气”。浮、升、动之性都是阳性，沈、降、静之性都是阴性。气受到阳性的影响，就浮、升；受到阴性的影响，就沈、降。这就使得气永远在聚散。气聚，就形成具体的万物；气散，就造成万物的消亡。','13210-13316',NULL,1659861955,1782480567);
INSERT INTO highlights VALUES('651358_25_14347-14471','651358',55,'第二十三章 新儒家：宇宙发生论者','关于凡物都包含自己的否定的理论，听起来好像黑格尔的理论，不过照黑格尔的说法，一个事物被否定了，一个新事物在更高水平上开始了。但是照老子和《易传》的说法，一个事物被否定了，新事物只是重复旧事物。这是具有农业民族特征的哲学，我在第二章已经指出了这一点。','12291-12415',NULL,1659861827,1782480567);
INSERT INTO highlights VALUES('651358_25_11873-11958','651358',55,'第二十三章 新儒家：宇宙发生论者','邵雍进一步写道：“太阳为日，太阴为月，少阳为星，少阴为辰，日月星辰交而天之体尽之矣。……太柔为水，太刚为火，少柔为土，少刚为石，水火土石交而地之体尽之矣。”（《说卦传》）','10135-10220',NULL,1659860824,1782480567);
INSERT INTO highlights VALUES('651358_25_6088-6129','651358',55,'第二十三章 新儒家：宇宙发生论者','这就是周敦颐提出的怎样成为圣人的方法，也就是像禅僧的方法一样：自然而生，自然而行。','4485-4526',NULL,1659860609,1782480567);
INSERT INTO highlights VALUES('651358_25_5388-5443','651358',55,'第二十三章 新儒家：宇宙发生论者','《通书》中说：“无欲则静虚动直。静虚则明，明则通。动直则公，公则溥。明通公溥，庶矣乎！”（《周濂溪集》卷五）。','3785-3840',NULL,1659860520,1782480567);
INSERT INTO highlights VALUES('651358_25_5175-5226','651358',55,'第二十三章 新儒家：宇宙发生论者','怎样成为圣人，是新儒家的主要问题之一，周敦颐的回答是“主静”，他又进一步说“主静”就是“无欲”的状态。','3572-3623',NULL,1659860387,1782480567);
INSERT INTO highlights VALUES('651358_25_4945-5026','651358',55,'第二十三章 新儒家：宇宙发生论者','佛家的佛与儒家的圣人，区别在于，佛必须在社会和人世间之外提高精神修养，圣人则必须在社会关系之内提高精神修养。中国佛学的最重要的发展，是企图降低佛教固有的出世性质。','3342-3423',NULL,1659852284,1782480567);
INSERT INTO highlights VALUES('651358_25_4320-4424','651358',55,'第二十三章 新儒家：宇宙发生论者','《易传》的《系辞传上》说：“易有太极，是生两仪。”《太极图说》就是这个观念的发展。它虽然很短，却是朱熹（1130—1200）的宇宙发生论的基本提纲。朱熹如果不是新儒家最大的哲学家，也是新儒家最大的哲学家之一。','3079-3183',NULL,1659852264,1782480567);
INSERT INTO highlights VALUES('651358_25_3938-3995','651358',55,'第二十三章 新儒家：宇宙发生论者','《太极图说》云：“无极而太极。太极动而生阳，动极而静，静而生阴。静极复动。一动一静，互为其根；分阴分阳，两仪立焉。','2697-2754',NULL,1659852053,1782480567);
INSERT INTO highlights VALUES('651358_25_2805-2978','651358',55,'第二十三章 新儒家：宇宙发生论者','新儒家的主要来源可以追溯到三条思想路线。第一，当然是儒家本身。第二是佛家，包括以禅宗为中介的道家，因为在佛家各宗之中，禅宗在新儒家形成时期是最有影响的。在新儒家看来，禅与佛是同义语；前一章已经讲过，在某种意义上，可以说新儒家是禅宗的合乎逻辑的发展。第三是道教，道教有一个重要成分是阴阳家的宇宙发生论。新儒家的宇宙发生论主要是与这条思想路线联系着。','1928-2101',NULL,1659851440,1782480567);
INSERT INTO highlights VALUES('651358_24_8843-8888','651358',54,'第二十二章 禅宗：静默的哲学','对任何事皆无滞着，禅宗的人常说：“终日吃饭，未曾咬着一粒米”；“终日著衣，未曾挂著一缕丝”','6550-6595',NULL,1659851020,1782480567);
INSERT INTO highlights VALUES('651358_24_7237-7354','651358',54,'第二十二章 禅宗：静默的哲学','禅师们用“如桶底子脱”的比喻，形容顿悟。桶底子脱了，则桶中所有之物，都顿时脱出。同样，一个人顿悟了，就觉得以前所有的各种问题，也顿时解决。其解决并不是具体解决，而是在悟中了解此等问题，本来都不是问题。所以悟后所得之道，为“不疑之道”。','5305-5422',NULL,1659850769,1782480567);
INSERT INTO highlights VALUES('651358_24_5951-6046','651358',54,'第二十二章 禅宗：静默的哲学','所以不修之修本身就是一种修，正如不知之知本身也是一种知。这样的知，不同于原来的无明；不修之修，也不同于原来的自然。因为原来的无明和自然，都是自然的产物；而不知之知，不修之修，都是精神的创造。','4380-4475',NULL,1659850637,1782480567);
INSERT INTO highlights VALUES('651358_24_5429-5499','651358',54,'第二十二章 禅宗：静默的哲学','所以修行的道路，就是要充分相信自己，其他一切放下，不必于日用平常行事外，别有用功，别有修行。这就是不用功的用功，也就是禅师们所说的不修之修。','3858-3928',NULL,1659850550,1782480567);
INSERT INTO highlights VALUES('651358_24_5268-5300','651358',54,'第二十二章 禅宗：静默的哲学','有些人刻意成佛，却往往不能顺着这个自然过程，原因在于他们缺乏自信','3697-3729',NULL,1659850511,1782480567);
INSERT INTO highlights VALUES('651358_24_5114-5160','651358',54,'第二十二章 禅宗：静默的哲学','一个人的行为不引起任何结果，那么在他以前积累的业消除净尽以后，他就能超脱生死轮回，达到涅槃。','3543-3589',NULL,1659850461,1782480567);
INSERT INTO highlights VALUES('651358_24_4610-4685','651358',54,'第二十二章 禅宗：静默的哲学','因此照禅宗所说，为了成佛，最好的修行方法，是不做任何修行，就是不修之修。有修之修，是有心的作为，就是有为。有为当然也能产生某种良好效果，但是不能长久。','3039-3114',NULL,1659850333,1782480567);
INSERT INTO highlights VALUES('651358_23_11726-11788','651358',53,'第二十一章 中国佛学的建立','但是孟子所说的“心”、“性”，都是心理的，不是形上学的。沿着道生的理论所提示的路线，给予心、性以形上学的解释，就达到了新儒家','9411-9473',NULL,1659849748,1782480567);
INSERT INTO highlights VALUES('651358_23_9782-9838','651358',53,'第二十一章 中国佛学的建立','道生还有一个理论，主张“一切众生，莫不是佛，亦皆涅槃”（《法华经疏》），即每个有感觉的生物都有佛性，或宇宙的心。','7468-7524',NULL,1658109999,1782480567);
INSERT INTO highlights VALUES('651358_23_8492-8590','651358',53,'第二十一章 中国佛学的建立','无为的意思并不是真正无所作为，而是无心而为。只要遵循无为、无心的原则，对于物也就无所贪恋迷执，即使从事各种活动，也是如此。既然“业”而受报，是由于贪恋和迷执，现在没有贪恋和迷执，当然“业”不受报了','6179-6277',NULL,1658109796,1782480567);
INSERT INTO highlights VALUES('651358_23_7516-7685','651358',53,'第二十一章 中国佛学的建立','僧肇把“般若”描写成圣智，可是他又说圣智实际上是无知。因为要知某一事物，就要选出这个事物的某一性质，以此性质作为知的对象。但是圣智是要知“无”，它“超乎形象”，没有性质，所以“无”根本不能成为知的对象。要知“无”，只有与“无”同一。这种与“无”同一的状态，就叫做涅槃。涅槃和般若，是一件事情的两个方面。正如涅槃不是可知之物，般若是不知之知','5566-5735',NULL,1658074784,1782480567);
INSERT INTO highlights VALUES('651358_23_7425-7441','651358',53,'第二十一章 中国佛学的建立','说万物非有非无，非动非静，是真谛','5475-5491',NULL,1658074758,1782480567);
INSERT INTO highlights VALUES('651358_23_7153-7216','651358',53,'第二十一章 中国佛学的建立','意思就是说，万物每刻都在变化。在任何特定的时刻存在的任何事物，实际上是这个时刻的新事物，与过去存在的这个事物，不是同一个事物。','5203-5266',NULL,1658074726,1782480567);
INSERT INTO highlights VALUES('651358_23_5887-5922','651358',53,'第二十一章 中国佛学的建立','一切都否定了，包括否定这个“否定一切”，就可以达到庄子哲学中相同的境界','4298-4333',NULL,1658073668,1782480567);
INSERT INTO highlights VALUES('651358_23_4320-4375','651358',53,'第二十一章 中国佛学的建立','佛教大乘的其他宗派，如中国人称为空宗，又称为中道宗的，却不是这样描述涅槃的。它们的描述方法，我称之为负的方法。','3090-3145',NULL,1658073457,1782480567);
INSERT INTO highlights VALUES('651358_23_3740-3862','651358',53,'第二十一章 中国佛学的建立','照佛学的说法，这一切痛苦，都起于个人对事物本性的根本无知。宇宙的一切事物都是心的表现，所以是虚幻的，暂时的，可是无知的个人还是渴求它们，迷恋它们。这种根本无知，就是“无明”。无明生贪嗔痴恋；由于对于生的贪恋，个人就陷入永恒的生死轮回，万劫不复。','2510-2632',NULL,1658073375,1782480567);
INSERT INTO highlights VALUES('651358_23_3891-3928','651358',53,'第二十一章 中国佛学的建立','要逃脱生死轮回，唯一的希望在于将“无明”换成觉悟，觉悟就是梵语的“菩提”。','2661-2698',NULL,1658073374,1782480567);
INSERT INTO highlights VALUES('651358_23_3406-3542','651358',53,'第二十一章 中国佛学的建立','佛学的说法，宇宙的一切现象，或者更确切地说，一个有情物的宇宙的一切现象，都是他的心的表现。不论何时，他动，他说，以至于他想，这都是他的心做了点什么，这点什么一定产生它的结果，无论在多么遥远的将来。这个结果就是业的报应。业是因，报是果。一个人的存在，就是一连串的因果造成的。','2176-2312',NULL,1658073279,1782480567);
INSERT INTO highlights VALUES('651358_23_3138-3249','651358',53,'第二十一章 中国佛学的建立',unistr('小乘、大乘的经文都翻译过来了，但是只有大乘在中国的佛学中获得永久的地位。\u000a总的说来，大乘佛学对中国人影响最大者是它的宇宙的心的概念，以及可以称为它的形上学的负的方法。'),'1908-2019',NULL,1658073220,1782480567);
INSERT INTO highlights VALUES('651358_23_2574-2664','651358',53,'第二十一章 中国佛学的建立','佛教的中道宗与道家哲学有某些相似之处。中道宗与道家哲学相互作用，产生了禅宗。禅宗虽是佛教，同时又是中国的。禅宗虽是佛教的一个宗派，可是它对于中国哲学、文学、艺术的影响，却是深远的。','1703-1793',NULL,1658073190,1782480567);
INSERT INTO highlights VALUES('651358_22_7323-7339','651358',52,'第二十章 新道家：主情派','可以归结为一句话：圣人有情而无累','5386-5402',NULL,1658072672,1782480567);
INSERT INTO highlights VALUES('651358_22_6149-6280','651358',52,'第二十章 新道家：主情派','支遁（314—366）对鹤的同情，诸阮对猪的一视同仁，说明他们具有物我无别、物我同等的感觉。要有风流的品格，这种感觉也是本质的东西。要成为艺术家，这种感觉也是本质的东西。真正的艺术家一定能够把他自己的感情投射到他所描绘的对象上，然后通过他的工具媒介把它表现出来。','4572-4703',NULL,1658072563,1782480567);
INSERT INTO highlights VALUES('651358_22_4640-4754','651358',52,'第二十章 新道家：主情派','“杨朱”感兴趣的似乎大都是追求肉体的快乐。当然，按照新道家所说，追求这样的快乐，也并不是必然要遭到鄙视。然而，如果以此为唯一目的，毫不理解“超乎形象”的东西，那么，用新道家的话说，这就不够“风流”（就“风流”的最好的意义而言）。','3055-3169',NULL,1658072391,1782480567);
INSERT INTO highlights VALUES('651358_22_3466-3506','651358',52,'第二十章 新道家：主情派','前者以向郭为代表，强调遵从理性而生；后者以下面讲到的人们为代表，强调任从冲动而生','2239-2279',NULL,1658072247,1782480567);
INSERT INTO highlights VALUES('651358_22_3313-3394','651358',52,'第二十章 新道家：主情派','治内，相当于向郭所说的任我；所说的治外，相当于向郭所说的从人。人活着，应当任我，不应当从人。就是说，人活着应当任从他自己的理性或冲动，不应当遵从当时的风俗和道德。','2087-2168',NULL,1658046789,1782480567);
INSERT INTO highlights VALUES('651358_22_2185-2221','651358',52,'第二十章 新道家：主情派','汉人风度是庄严、雄伟，晋人风度是放达、文雅。文雅也是“风流”的特征之一。','1319-1355',NULL,1658046645,1782480567);
INSERT INTO highlights VALUES('651358_22_2013-2052','651358',52,'第二十章 新道家：主情派','中国历史上儒家与道家的传统，在某种程度上，相当于西方的古典主义与浪漫主义的传统','1147-1186',NULL,1658046626,1782480567);
INSERT INTO highlights VALUES('651358_22_1535-1625','651358',52,'第二十章 新道家：主情派','清谈的艺术在于，将最精粹的思想，通常就是道家思想，用最精粹的语言，最简洁的语句，表达出来，所以它是很有讲究的，只能在智力水平相当高的朋友之间进行，被人认为是一种最精妙的智力活动。《','673-763',NULL,1658046562,1782480567);
INSERT INTO highlights VALUES('651358_21_13060-13160','651358',51,'第十九章 新道家：主理派','所以向郭注除了对原来的道家做了重要的修正，还把庄子只是暗示了一下的东西讲得更加明确，但是谁若只爱暗示不爱明确，当然会同意禅宗某和尚所说的：“曾见郭象注庄子，识者云：却是庄子注郭象。”（本书第一章已引）','8979-9079',NULL,1658046461,1782480567);
INSERT INTO highlights VALUES('651358_21_12909-13031','651358',51,'第十九章 新道家：主理派','在向郭的体系里，“道”是真正的“无”。在这个体系中，“天”或“天地”（这里译为universe）才是最重要的观念。天是万物的总名，所以是一切存在的全体。从天的观点看万物，使自己与天同一，也就是超越万物及其差别，用新道家的话说，就是“超乎形象”。','8828-8950',NULL,1658046442,1782480567);
INSERT INTO highlights VALUES('651358_21_11712-11741','651358',51,'第十九章 新道家：主理派','一个人若能超越事物的差别，他就能享受绝对的自由和绝对的幸福','7623-7652',NULL,1658046298,1782480567);
INSERT INTO highlights VALUES('651358_21_10352-10397','651358',51,'第十九章 新道家：主理派','所以模仿是无用的，没有结果的，有害的。唯一合理的生活方式是“任我”，这也就是实践“无为”。','6979-7024',NULL,1658046179,1782480567);
INSERT INTO highlights VALUES('651358_21_9242-9465','651358',51,'第十九章 新道家：主理派','老庄都反对社会上通常公认的那种圣人。在先秦道家文献中，“圣人”一词有两个意义。一个意义是完全的人（按道家的标准），一个意义是有一切种类知识的人。老庄攻击知识，因之也攻击这后一种圣人。但是由上述可知，向郭没有反对那些是圣人的人。他所反对的是那些企图模仿圣人的人。柏拉图生来就是柏拉图，庄子生来就是庄子。他们的天资就像龙章风姿一样的自然。他们就像任何一物一样的纯素。他们写《理想国》、《逍遥游》，也若无事然，因为他们写这些东西，不过是顺乎自己的自然。','5869-6092',NULL,1658046103,1782480567);
INSERT INTO highlights VALUES('651358_21_8206-8312','651358',51,'第十九章 新道家：主理派','因此向郭对于先秦道家天、人的观念，有为、无为的观念，都做了新的解释。社会形势变化了，新的制度和道德就自生了。任它们自己发展，就是顺着天和自然，就是无为，反对它们，固执过时的旧制度和旧道德，就是人和人为，就是有为。','5191-5297',NULL,1658045950,1782480567);
INSERT INTO highlights VALUES('651358_21_4548-4590','651358',51,'第十九章 新道家：主理派','向郭注对于老子、庄子原来的道家学说做了若干极重要的修正。第一个修正是，道是真正的无。','2607-2649',NULL,1658045459,1782480567);
INSERT INTO highlights VALUES('651358_21_2978-3046','651358',51,'第十九章 新道家：主理派','新道家，尽管是道家，却认为孔子甚至比老子、庄子更伟大。他们认为，孔子没有说忘，因为他已经忘了忘；孔子也没有说无欲，因为他已经无欲于无欲。','1753-1821',NULL,1658044987,1782480567);
INSERT INTO highlights VALUES('651358_20_8341-8395','651358',50,'第十八章 儒家的独尊和道家的复兴','禅宗是中国佛教的一支，它真正是佛学和道家哲学最精妙之处的结合。它对后来中国的哲学、诗词、绘画都有巨大的影响。','6019-6073',NULL,1658044362,1782480567);
INSERT INTO highlights VALUES('651358_20_8264-8295','651358',50,'第十八章 儒家的独尊和道家的复兴','他们谈到了“非非”的时候，就一笑无言，正是在无言中彼此了解了。','5942-5973',NULL,1658044310,1782480567);
INSERT INTO highlights VALUES('651358_20_4819-4882','651358',50,'第十八章 儒家的独尊和道家的复兴','今文学派可能是先秦儒家理想派的继续，古文学派可能是先秦儒家现实派的继续。换句话说，今文学派出于孟子学派，古文学派出于荀子学派。','3224-3287',NULL,1657978794,1782480567);
INSERT INTO highlights VALUES('651358_20_2757-2970','651358',50,'第十八章 儒家的独尊和道家的复兴','汉朝的措施，不是像秦朝的措施那样不加区别地禁绝一切学派的思想，造成思想领域的真空，而是从“百家”之中选出一家，即儒家，给予独尊的地位，作为国家的教义。还有一点不同，汉朝的措施没有颁布对于私自教授其他各家思想的刑罚。它仅只规定，凡是希望做官的人都必须学习《六经》和儒学。以儒学为国家教育的基础，也就打下了中国的著名的考试制度的基础，这种制度是用于扩充政府新官员的。这样一来，汉朝的措施实际上是秦朝的措施与以前的私学相调和的产物。','1887-2100',NULL,1657977660,1782480567);
INSERT INTO highlights VALUES('651358_19_9843-9904','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','照董仲舒说，直接继承周朝的既不是秦朝，也不是汉朝。他断言，实际上是孔子受天命继周而正黑统。孔子不是实际的王，却是合法的王。','6761-6822',NULL,1657953024,1782480567);
INSERT INTO highlights VALUES('651358_19_9141-9197','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','董仲舒的王者受命于天的学说，既为行使皇权提供根据，又对行使皇权有所限制。皇帝必须注视天的喜怒表现，依照它来行事。','6425-6481',NULL,1657952991,1782480567);
INSERT INTO highlights VALUES('651358_19_8858-8913','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','改制并没有改变基本原则，董仲舒称之为“道”。他说：“道之大原出于天，天不变，道亦不变。”（《汉书·董仲舒传》）','6142-6197',NULL,1657952967,1782480567);
INSERT INTO highlights VALUES('651358_19_8284-8357','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','董仲舒修改了这个学说，认为朝代的更迭不是根据五德运行，而是根据他所说的“三统”顺序。三统是黑统、白统、赤统。每统各有其统治系统，每个朝代各正一统。','5576-5649',NULL,1657952915,1782480567);
INSERT INTO highlights VALUES('651358_19_7037-7069','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','可是不是一切人都能自己做到这一点。所以政府的职能就是帮助发展人性','4695-4727',NULL,1657952841,1782480567);
INSERT INTO highlights VALUES('651358_19_7143-7181','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','王者以庆、赏、罚、刑为“四政”，相当于四季。董仲舒说：“庆赏刑罚与春夏秋冬，','4801-4839',NULL,1657952830,1782480567);
INSERT INTO highlights VALUES('651358_19_6389-6398','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','仁、义、礼、智、信','4413-4422',NULL,1657952797,1782480567);
INSERT INTO highlights VALUES('651358_19_5155-5240','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','董仲舒因此强调人为和教化的作用，只有教化才使人与天、地同等。在这方面，他接近荀子。但是他又和荀子不同，不同之处在于，他不认为人的质已经是恶的。善是性的继续，不是性的逆转。','3545-3630',NULL,1657949767,1782480567);
INSERT INTO highlights VALUES('651358_19_5024-5032','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','善如米，性如禾。','3414-3422',NULL,1657949735,1782480567);
INSERT INTO highlights VALUES('651358_19_4774-4826','651358',49,'第十七章 将汉帝国理论化的哲学家：董仲舒','由于天有其阴阳，人是天的副本，所以人心也包含两个成分：性、情。董仲舒用“性”字，有时取广义，有时取狭义。','3164-3216',NULL,1657949705,1782480567);
INSERT INTO highlights VALUES('651358_18_8103-8202','651358',48,'第十六章 世界政治和世界哲学','由此看来，《天下》篇的含意似乎是说，儒家知道具体的“数度”，而不知所含的原理；道家知道原理，而不知数度。换句话说，儒家知道“道”之末，而不知其本；道家知其本，而不知其末。只有两家的结合才是全部真理。','5776-5875',NULL,1657894443,1782480567);
INSERT INTO highlights VALUES('651358_18_7373-7429','651358',48,'第十六章 世界政治和世界哲学','全部真理就是“内圣外王之道”，对于它的研究称为“道术”；部分真理是全部真理的某一方面，对于它的研究称为“方术”。','5046-5102',NULL,1657894286,1782480567);
INSERT INTO highlights VALUES('651358_18_7245-7327','651358',48,'第十六章 世界政治和世界哲学','《庄子》最后一篇《天下》篇的作者，提出了道家的折中观点。这一篇实际上是先秦哲学的总结。我们不能肯定这位作者是谁，这并不妨碍他真正是先秦哲学的最好的历史学家和批评家。','4918-5000',NULL,1657894019,1782480567);
INSERT INTO highlights VALUES('651358_18_6736-6795','651358',48,'第十六章 世界政治和世界哲学','照荀子的看法，哲学家的“见”和“蔽”是联在一起的。他有所见，可是常常同时为其见所蔽。因而他的哲学的优点同时是它的缺点。','4769-4828',NULL,1657893088,1782480567);
INSERT INTO highlights VALUES('651358_17_10512-10625','651358',47,'第十五章 儒家的形上学','这就是儒家的方法，这种方法把人的精神提高到同天的境界。它与道家的方法不同，道家的方法是通过否定知识，把人的精神提高到超脱人世间的“彼”“此”分别。儒家的方法不是这样，它是通过推广仁爱，把人的精神提高到超脱寻常的人我和物我分别。','7856-7969',NULL,1657890554,1782480567);
INSERT INTO highlights VALUES('651358_17_10137-10313','651358',47,'第十五章 儒家的形上学','成己的同时，一定要看到还要成人。不管成人，也就不能成己。这是因为，只有通过人伦，即在社会领域内，才能尽其性。这就回到孔子、孟子的传统了，就是为了成己，必须行忠、恕，即行仁，这就包含着助人。成己，就是尽其性，即尽其受之于天者；助人，就是赞天地之化育。完全明白了这些意义，就可以与天地参。完全明白了意义，就是《中庸》所说的明；如此与天地参，就是它所说的诚。','7481-7657',NULL,1657890490,1782480567);
INSERT INTO highlights VALUES('651358_17_9764-9832','651358',47,'第十五章 儒家的形上学','一个人若是明白了日常生活中普通而平常的活动的一切意义，诸如饮食人伦的意义，他就已经是圣人。一个人若是把他所明白的完全做到了，他也是圣人。','7108-7176',NULL,1657890431,1782480567);
INSERT INTO highlights VALUES('651358_17_8948-9076','651358',47,'第十五章 儒家的形上学','还有一层，虽然所有人由于实际需要不得不在某种程度上遵循“道”，但是并不是所有人都能完全地遵循之。所以固然没有人能够完全不顾人伦而在社会中生活，可是同时也只有极少数的人能够完全符合这些人伦提出的条件。教的作用，就是使人把事实上已经不同程度地在做的事，做完全。','6649-6777',NULL,1657890331,1782480567);
INSERT INTO highlights VALUES('651358_17_7337-7493','651358',47,'第十五章 儒家的形上学','以上是就情感说，所说的也适用于欲望。在个人行为和社会关系中，都有些适中之点，作为满足欲望和表现情感的恰当的限度。一个人，一切欲望和情感都满足和表达到恰当的限度，他的内部就达到和谐，在精神上很健康。一个社会也同样，其中各式各样的人的一切欲望和情感，都满足和表现到恰当的限度，这个社会的内部就达到和谐，安定而有秩序。','5396-5552',NULL,1657890146,1782480567);
INSERT INTO highlights VALUES('651358_17_6882-6920','651358',47,'第十五章 儒家的形上学','增之一分则太长，减之一分则太短，著粉则太白，施朱则太赤。”（《登徒子好色赋》','4941-4979',NULL,1657890071,1782480567);
INSERT INTO highlights VALUES('651358_17_6137-6196','651358',47,'第十五章 儒家的形上学','危者，安其位者也。亡者，保其存者也。乱者，有其治者也。是故君子安而不忘危，存而不忘亡，治而不忘乱，是以身安而国家可保也','4554-4613',NULL,1657890023,1782480567);
INSERT INTO highlights VALUES('651358_17_6078-6126','651358',47,'第十五章 儒家的形上学','要取得胜利，就一定要注意不要过分地胜利；要避免丧失某物，就一定要在此物中补充一些与它相反的东西。','4495-4543',NULL,1657890003,1782480567);
INSERT INTO highlights VALUES('651358_17_5942-6035','651358',47,'第十五章 儒家的形上学','六十四卦的顺序安排至少有三点含义：（一）宇宙中的一切，包括自然界、人类社会，形成一个自然序列的连续链条；（二）在演变过程中，每个事物都包含自己的否定；（三）在演化过程中，“物不可穷也”。','4359-4452',NULL,1657889985,1782480567);
INSERT INTO highlights VALUES('651358_17_2975-2986','651358',47,'第十五章 儒家的形上学','先，迷失道；后，顺得常','2106-2117',NULL,1657889654,1782480567);
INSERT INTO highlights VALUES('651358_16_10087-10156','651358',46,'第十四章 韩非和法家','儒家的观念是理想主义的，法家的观念是现实主义的。正由于这个缘故，所以在中国历史上，儒家总是指责法家卑鄙、粗野，法家总是指责儒家迂腐、空谈。','7443-7512',NULL,1657881460,1782480567);
INSERT INTO highlights VALUES('651358_16_5208-5238','651358',46,'第十四章 韩非和法家','“民道弊而所重易也；世事变而行道异也。”（《商君书·开塞》）','3632-3662',NULL,1657637949,1782480567);
INSERT INTO highlights VALUES('651358_16_4757-4815','651358',46,'第十四章 韩非和法家','法家是先秦最后的主要的一家，对于这种历史观，却是鲜明的例外。他们充分认识到时代变化的要求，又极其现实地看待这些要求。','3181-3239',NULL,1657637811,1782480567);
INSERT INTO highlights VALUES('651358_16_4625-4728','651358',46,'第十四章 韩非和法家','像这样朝后看，这些哲学家就创立了历史退化论。他们虽然分属各家，但是都同意这一点，就是人类黄金时代在过去，不在将来。自从黄金时代过去后，历史的运动一直是逐步退化的运动。因此，拯救人类，不在于创新，而在于复古。','3049-3152',NULL,1657637795,1782480567);
INSERT INTO highlights VALUES('651358_16_2646-2759','651358',46,'第十四章 韩非和法家','由此可见，把法家思想与法律和审判联系起来，是错误的。用现代的术语说，法家所讲的是组织和领导的理论和方法。谁若想组织人民，充当领袖，谁就会发现法家的理论与实践仍然很有教益，很有用处，但是有一条，就是他一定要愿意走极权主义的路线。','1786-1899',NULL,1657600967,1782480567);
INSERT INTO highlights VALUES('651358_16_2198-2310','651358',46,'第十四章 韩非和法家','。当时各国诸侯面临的都是这样的情况，自孔子以来诸子百家共同努力解决的就是这些问题。可是他们提出的解决方案，多是不够现实的，不能实行的。各国诸侯需要的不是对百姓行仁政的理想纲领，而是如何应付他们的政府所面临的新情况的现实方法。','1338-1450',NULL,1657600904,1782480567);
INSERT INTO highlights VALUES('651358_16_919-1030','651358',46,'第十四章 韩非和法家','西周封建社会根据两条原则办事：一条是“礼”；一条是“刑”。礼是不成文法典，以褒贬来控制“君子”即贵族的行为。刑则不然，它只适用于“庶人”；或“小人”，即平民。这就是《礼记》中说的：“礼不下庶人，刑不上大夫。”（《曲礼上》）','415-526',NULL,1657599211,1782480567);
INSERT INTO highlights VALUES('651358_15_7236-7527','651358',45,'第十三章 儒家的现实主义派：荀子','荀子还作了《乐论》，其中说：“人不能不乐，乐则不能无形，形而不为道，则不能无乱。先王恶其乱也，故制《雅》、《颂》之声以道之，使其声足以乐而不流，使其文足以辨而不￼，使其曲直、繁省、廉肉、节奏，足以感动人之善心，使夫邪污之气无由得接焉，是先王立乐之方也。”所以在荀子看来，音乐是道德教育的工具。这一直是儒家奉行的音乐观。','5284-5583',NULL,1657203180,1782480567);
INSERT INTO highlights VALUES('651358_15_6209-6348','651358',45,'第十三章 儒家的现实主义派：荀子','宗教、诗，二者都是人的幻想的表现。二者都是把想象和现实融合起来。所不同者，宗教是把它当做真的来说，而诗是把它当做假的来说。诗所说的不是真事，它自己也知道不是真事。所以它是自己欺骗自己，可是是自觉的自欺。它很不科学，可是并不反对科学。我们从诗中得到情感的满足而并不妨碍理智的进步。','4257-4396',NULL,1657203091,1782480567);
INSERT INTO highlights VALUES('651358_15_4592-4641','651358',45,'第十三章 儒家的现实主义派：荀子','这是荀子所做的一个方面的论证，以解释道德上善的起源。这种论证完全是功利主义的，与墨子的论证很相似。','3002-3051',NULL,1657202909,1782480567);
INSERT INTO highlights VALUES('651358_15_4481-4563','651358',45,'第十三章 儒家的现实主义派：荀子','人们必须一起生活，为了在一起生活而无争，各人在满足自己的欲望方面必须接受一定的限制。礼的功能就是确定这种限制。有礼，才有道德。遵礼而行就是道德，违礼而行就是不道德。','2891-2973',NULL,1657202889,1782480567);
INSERT INTO highlights VALUES('651358_15_2117-2151','651358',45,'第十三章 儒家的现实主义派：荀子','列星随旋，日月递照，四时代御，阴阳大化，风雨博施，万物各得其和以生。','1251-1285',NULL,1657202000,1782480567);
INSERT INTO highlights VALUES('651358_14_4234-4307','651358',44,'第十二章 阴阳家和先秦的宇宙发生论','作者还告诉我们，人类世界和自然世界是互相关联的，君主方面的恶行就导致自然界异常现象的出现。这个学说，被后来的阴阳家大为发展了，叫做“天人感应论”。','2998-3071',NULL,1656828388,1782480567);
INSERT INTO highlights VALUES('651358_14_2361-2375','651358',44,'第十二章 阴阳家和先秦的宇宙发生论','所谓积极的，我是指实事求是的','1494-1508',NULL,1656828165,1782480567);
INSERT INTO highlights VALUES('651358_14_2145-2250','651358',44,'第十二章 阴阳家和先秦的宇宙发生论','术数的本身是以迷信为基础的，但是也往往是科学的起源。术数与科学有一个共同的愿望，就是以积极的态度解释自然，通过征服自然使之为人类服务。术数在放弃了对于超自然力的信仰并且试图只用自然力解释宇宙的时候，就变成科学。','1278-1383',NULL,1656828047,1782480567);
INSERT INTO highlights VALUES('651358_13_10597-10656','651358',43,'第十一章 后期墨家','我们看到后期墨家如此富于逻辑头脑，实在令人赞叹。他们试图创造一个认识论和逻辑学的纯系统，这是中国古代其他各家所不及的。','8325-8384',NULL,1656827880,1782480567);
INSERT INTO highlights VALUES('651358_13_6607-6714','651358',43,'第十一章 后期墨家','事实上，每个人都有一些他所爱的人。例如，每个人都爱他自己的孩子。所以光凭人总会爱一些人，这个事实，不能说他爱一切人。但是在否定方面，他若害了某些人，哪怕是他自己的孩子，凭这一点就可以说他不爱人，墨家的推理就是这样。','5054-5161',NULL,1656826642,1782480567);
INSERT INTO highlights VALUES('651358_13_5920-5973','651358',43,'第十一章 后期墨家','《经上》篇说：“利，所得而喜也。”“害，所得而恶也。”这样，后期墨家就为墨家的功利哲学做出享乐主义的解释。','4367-4420',NULL,1656822068,1782480567);
INSERT INTO highlights VALUES('651358_13_2554-2683','651358',43,'第十一章 后期墨家','《墨经》还对于知识进行了分类。按知识的来源，把知识分为三类：一类是来自认识者亲身经验；一类是来自权威的传授（即得自传闻或文献）；一类是来自推论的知识（即得自演绎，以已知推未知）。又按认识的各种对象，把知识分为四类：名的知识；实的知识；相合的知识；行为的知识。','1711-1840',NULL,1656819759,1782480567);
INSERT INTO highlights VALUES('651358_12_5860-6008','651358',42,'第十章 道家第三阶段：庄子','无知的人不仅在各方面受到外部原因的扰乱，从未享受灵魂的真正和平，而且过着对上帝、对万物似乎一概无知的生活，活着也是受苦，一旦不再受苦了，也就不再存在了。另一方面，有知的人，在他有知的范围内，简直可以不动心，而且由于理解他自己、上帝、万物都有一定的永恒的必然性，他也就永远存在，永远享受灵魂的和平。','3918-4066',NULL,1656767196,1782480567);
INSERT INTO highlights VALUES('651358_12_5436-5451','651358',42,'第十章 道家第三阶段：庄子','用道家的话说，就是“以理化情”','3494-3509',NULL,1656767156,1782480567);
INSERT INTO highlights VALUES('651358_12_5355-5415','651358',42,'第十章 道家第三阶段：庄子','正如斯宾诺莎所说：“心灵理解到万物的必然性，理解的范围有多大，它就在多大的范围内有更大的力量控制后果，而不为它们受苦。”','3413-3473',NULL,1656767148,1782480567);
INSERT INTO highlights VALUES('651358_11_7318-7383','651358',41,'第九章 道家第二阶段：老子','家学说“无为”，也可以从这个总学说演绎出来。“无为”的意义，实际上并不是完全无所作为，它只是要为得少一些，不要违反自然地任意地为。','5378-5443',NULL,1656764561,1782480567);
INSERT INTO highlights VALUES('651358_11_6578-6732','651358',41,'第九章 道家第二阶段：老子','老子警告我们：“不知常，妄作，凶。”（第十六章）我们应该知道自然规律，根据它们来指导个人行动。老子把这叫做“袭明”。人“袭明”的通则是，想要得些东西，就要从其反面开始；想要保持什么东西，就要在其中容纳一些与它相反的东西。谁若想变强，就必须从感到他弱开始；谁若想保持资本主义，就必须在其中容纳一些社会主义成分。','4638-4792',NULL,1656764400,1782480567);
INSERT INTO highlights VALUES('651358_10_10811-10857','651358',40,'第八章 名家','道家是名家的反对者，又是名家真正的继承者。惠施是庄子的真正好朋友，这个事实就是这一点的例证。','8891-8937',NULL,1656762101,1782480567);
INSERT INTO highlights VALUES('651358_10_6460-6482','651358',40,'第八章 名家','天下无方，故所在为中；循环无端，故所在为始也','5246-5268',NULL,1656728339,1782480567);
INSERT INTO highlights VALUES('651358_9_2584-2657','651358',39,'第七章 儒家的理想主义派：孟子','恻隐之心，仁之端也；羞恶之心，义之端也；辞让之心，礼之端也；是非之心，智之端也。人之有是四端也，犹其有四体也。……凡有四端于我者，知皆扩而充之矣。','1717-1790',NULL,1656699048,1782480567);
INSERT INTO highlights VALUES('651358_8_6475-6612','651358',38,'第六章 道家第一阶段：杨朱','《庄子》有许多地方加以发挥，产生了“齐生死、一物我”的理论。它的意思也就是，从一个更高的观点看生死、看物我。从这个更高的观点看事物，就能够超越现实的世界。这也是“避”的一种形式；然而不是从社会到山林，而很像是从这个世界到另一个世界。这是先秦道家发展的第三阶段，也是最后阶段。','4172-4309',NULL,1656698430,1782480567);
INSERT INTO highlights VALUES('651358_8_6221-6328','651358',38,'第六章 道家第一阶段：杨朱','《老子》的大部分思想表示出另一种企图，就是揭示宇宙事物变化的规律。事物变，但是事物变化的规律不变。一个人如果懂得了这些规律，并且遵循这些规律以调整自己的行动，他就能够使事物转向对他有利。这是先秦道家发展的第二阶段。','3918-4025',NULL,1656698098,1782480567);
INSERT INTO highlights VALUES('651358_8_2883-2905','651358',38,'第六章 道家第一阶段：杨朱','杨朱的两个基本观念：“为我”、“轻物重生”。','1657-1679',NULL,1656469467,1782480567);
INSERT INTO highlights VALUES('651358_7_10066-10094','651358',37,'第五章 墨子：孔子的第一个反对者','墨子发展了侠的职业道德，那是非常强调团体内的服从和纪律的','7388-7416',NULL,1656464234,1782480567);
INSERT INTO highlights VALUES('651358_7_8200-8236','651358',37,'第五章 墨子：孔子的第一个反对者','行礼只是祭祀祖先的人出于孝敬祖先的感情，所以礼的意义是诗的，不是宗教的。','5884-5920',NULL,1656464049,1782480567);
INSERT INTO highlights VALUES('651358_6_9833-9873','651358',36,'第四章 孔子：第一位教师','他的行动用不着有意的指导，他的行动用不着有意的努力。这代表着圣人发展的最高阶段。','6814-6854',NULL,1656347415,1782480567);
INSERT INTO highlights VALUES('651358_6_8030-8132','651358',36,'第四章 孔子：第一位教师','所以我们能够做的，莫过于一心一意地尽力去做我们知道是我们应该做的事，而不计成败。这样做，就是“知命”。要做儒家所说的君子，知命是一个重要的必要条件。所以孔子说：“不知命，无以为君子也。”（《论语·尧曰》）','5369-5471',NULL,1656347160,1782480567);
INSERT INTO highlights VALUES('651358_6_7723-7824','651358',36,'第四章 孔子：第一位教师','孔子本人的一生正是这种学说的好例。他生活在社会、政治大动乱的年代，他竭尽全力改革世界。他周游各地，还像苏格拉底那样，逢人必谈。虽然他的一切努力都是枉费，可是他从不气馁。他明知道他不会成功，仍然继续努力。','5062-5163',NULL,1656347098,1782480567);
INSERT INTO highlights VALUES('651358_3_11659-11687','651358',33,'第一章 中国哲学的精神','禅宗和尚说：“曾见郭象注庄子，识者云：却是庄子注郭象。”','10089-10117',NULL,1656219814,1782480567);
INSERT INTO highlights VALUES('651358_3_9016-9080','651358',33,'第一章 中国哲学的精神','对于他，哲学从来就不只是为人类认识摆设的观念模式，而是内在于他的行动的箴言体系；在极端的情况下，他的哲学简直可以说是他的传记。”','7804-7868',NULL,1656219393,1782480567);
INSERT INTO highlights VALUES('651358_3_5064-5137','651358',33,'第一章 中国哲学的精神','在未来的世界，人类将要以哲学代宗教。这是与中国传统相合的。人不一定应当是宗教的，但是他一定应当是哲学的。他一旦是哲学的，他也就有了正是宗教的洪福。','4202-4275',NULL,1656218703,1782480567);
INSERT INTO highlights VALUES('651358_3_2679-2837','651358',33,'第一章 中国哲学的精神',unistr('宗教也和人生有关系。每种大宗教的核心都有一种哲学。事实上，每种大宗教就是一种哲学加上一定的上层建筑，包括迷信、教条、仪式和组织。这就是我所说的宗教。\u000a这样来规定“宗教”一词的含义，实际上与普通的用法并无不同，'),'1819-1977',NULL,1656218302,1782480567);
INSERT INTO highlights VALUES('651358_3_2305-2377','651358',33,'第一章 中国哲学的精神','哲学家所说的宇宙是一切存在之全，相当于古代中国哲学家惠施所说的“大一”，其定义是“至大无外”','1445-1517',NULL,1656218232,1782480567);
INSERT INTO highlights VALUES('651358_3_1798-1822','651358',33,'第一章 中国哲学的精神','我所说的哲学，就是对于人生的有系统的反思的思想。','938-962',NULL,1656217568,1782480567);
