INSERT INTO highlights VALUES('3300091899_22_4901-4934','3300091899',104,'3.5 变量','缓存变量一般应用于目录程序中，便于对构建过程的一些配置进行持久化。','4969-5002',0,1728102327,1782480555);
INSERT INTO highlights VALUES('3300091899_22_4402-4420','3300091899',104,'3.5 变量','然而其值仍然是原始值，而非修改后的值','4453-4471',0,1728101784,1782480555);
INSERT INTO highlights VALUES('3300091899_22_3647-3692','3300091899',104,'3.5 变量','值参数也可以被省略，此时，该变量会从当前作用域中移除，相当于对该变量调用了unset命令。','3698-3743',0,1728101708,1782480555);
INSERT INTO highlights VALUES('3300091899_22_3312-3343','3300091899',104,'3.5 变量','set命令可以用于定义或赋值一个普通变量、缓存变量或环境变量。','3346-3377',0,1728101593,1782480555);
INSERT INTO highlights VALUES('3300091899_22_2468-2515','3300091899',104,'3.5 变量','CMAKE_CURRENT_LIST_DIR表示当前运行中的CMake程序所在目录的绝对路径。','2502-2549',0,1728097730,1782480555);
INSERT INTO highlights VALUES('3300091899_22_1299-1325','3300091899',104,'3.5 变量','子目录的程序可以访问但无法修改父目录作用域中的变量。','1316-1342',0,1728037113,1782480555);
INSERT INTO highlights VALUES('3300091899_22_1256-1296','3300091899',104,'3.5 变量','子目录的程序被执行前，会先将父目录作用域中的所有变量复制一份到子目录的作用域中。','1273-1313',0,1728037103,1782480555);
