INSERT INTO highlights VALUES('3300091899_22_875-927','3300091899',104,'3.5 变量','缓存变量主要用于构建过程，cmake -P执行脚本程序时不会对缓存变量进行修改。缓存变量具有全局作用域。','875-927',0,1728037031,1782480555);
