INSERT INTO highlights VALUES('3300091899_22_596-610','3300091899',104,'3.5 变量','CMake却有三种变量分类。','596-610',0,1728036989,1782480555);
INSERT INTO highlights VALUES('3300091899_22_439-506','3300091899',104,'3.5 变量','CMake变量有些与众不同：其数据类型总是文本型的，只不过在使用时，文本型的变量可能被一些命令解释成数值、列表等，以实现更加丰富的功能','422-489',0,1728036844,1782480555);
INSERT INTO highlights VALUES('3300091899_21_4202-4250','3300091899',103,'3.4 命令参数','由于历史原因，CMake的转义行为在不同版本中会有所不同，需要指定该CMake程序要求的最低版本','4185-4233',0,1728013358,1782480555);
INSERT INTO highlights VALUES('3300091899_21_3400-3554','3300091899',103,'3.4 命令参数',unistr('“\\;”的转义又分为以下情况。\u000a– 如果它被用于变量引用或非引号参数中，则转义为分号“;”。但在非引号参数，转义后分号不用于分隔列表元素，即其前后相邻文本包括分号本身会作为一个整体'),'3383-3537',0,1728013324,1782480555);
INSERT INTO highlights VALUES('3300091899_21_2580-2633','3300091899',103,'3.4 命令参数','set(var_a 您好)￼ INSERT INTO highlights VALUES('3300091899_21_2481-2495','3300091899',103,'3.4 命令参数','变量引用还支持嵌套的递归引用','2464-2478',0,1728013037,1782480555);
INSERT INTO highlights VALUES('3300091899_21_2448-2478','3300091899',103,'3.4 命令参数','变量名未定义，CMake并不会报错，而是将其替换为空字符串。','2431-2461',0,1728012998,1782480555);
