INSERT INTO highlights VALUES('3300091899_21_1618-1657','3300091899',103,'3.4 命令参数','简单做个不够准确的定义：CMake列表是一种特殊的字符串，由分号分隔各个元素。','1601-1640',0,1728012923,1782480555);
INSERT INTO highlights VALUES('3300091899_21_1548-1567','3300091899',103,'3.4 命令参数','被传递前，会被当作CMake列表来处理','1531-1550',0,1728012884,1782480555);
INSERT INTO highlights VALUES('3300091899_21_1503-1538','3300091899',103,'3.4 命令参数','非引号参数不总是作为一个整体传递给命令，它有可能被拆分成若干参数传递。','1486-1521',0,1728012812,1782480555);
INSERT INTO highlights VALUES('3300091899_21_773-801','3300091899',103,'3.4 命令参数','也就是说，引号参数中不仅能够包含空格，还可以包含换行符。','756-784',0,1728012739,1782480555);
INSERT INTO highlights VALUES('3300091899_21_726-733','3300091899',103,'3.4 命令参数','必须使用双引号','709-716',0,1728012713,1782480555);
INSERT INTO highlights VALUES('3300091899_21_408-601','3300091899',103,'3.4 命令参数',unistr('命令参数在命令调用的括号中书写。命令参数一共有以下三种类型：\u000a● 引号参数(quoted argument)；\u000a● 非引号参数(unquoted argument)；\u000a● 括号参数(bracket argument)。'),'391-584',0,1728012697,1782480555);
INSERT INTO highlights VALUES('3300091899_20_818-838','3300091899',102,'3.3 命令调用','应当使用空格或换行符等空白符将它们分隔开','801-821',0,1728012642,1782480555);
INSERT INTO highlights VALUES('3300091899_20_597-626','3300091899',102,'3.3 命令调用','但语法有些不同。先书写命令名称，其后跟括号括起来的命令参数','580-609',0,1728012621,1782480555);
INSERT INTO highlights VALUES('3300091899_20_457-516','3300091899',102,'3.3 命令调用','CMake程序中的if条件分支、for循环等程序结构统一采用命令调用形式。这也是CMake程序语法有点“怪”的原因之一','440-499',0,1728012603,1782480555);
INSERT INTO highlights VALUES('3300091899_18_1412-1454','3300091899',100,'3.1 CMake程序','CMake的目录程序和脚本程序均可以通过include等命令引用CMake模块程序。','1395-1437',0,1728012491,1782480555);
INSERT INTO highlights VALUES('3300091899_18_1493-1513','3300091899',100,'3.1 CMake程序','CMake模块是一种主要的代码复用单元。','1476-1496',0,1728012469,1782480555);
INSERT INTO highlights VALUES('3300091899_18_1254-1283','3300091899',100,'3.1 CMake程序','因此一些与构建相关的CMake命令是不允许出现在脚本中的。','1237-1266',0,1728012441,1782480555);
INSERT INTO highlights VALUES('3300091899_18_602-632','3300091899',100,'3.1 CMake程序','扩展名为.cmake的程序又分为脚本程序和模块程序两种类型。','585-615',0,1728012364,1782480555);
INSERT INTO highlights VALUES('3300091899_18_411-530','3300091899',100,'3.1 CMake程序',unistr('CMake程序根据文件名，可分为以下两种类型：\u000a● 名为CMakeLists.txt的文件；\u000a● 扩展名为.cmake的程序。'),'394-513',0,1728010521,1782480555);
INSERT INTO highlights VALUES('3300091899_17_651-667','3300091899',99,'第3章 基础语法','但它其实是一个图灵完备的脚本语言','634-650',0,1728010464,1782480555);
INSERT INTO highlights VALUES('3300091899_14_3295-3309','3300091899',96,'2.1 为什么使用CMake','它所专注的便是构建这个领域，','3278-3292',0,1728008523,1782480555);
INSERT INTO highlights VALUES('3300091899_14_3219-3284','3300091899',96,'2.1 为什么使用CMake','CMake脚本语言是领域特定语言(Domain Specific Language，DSL)，即专注于某个应用程序领域的计算机语言','3202-3267',0,1728008519,1782480555);
INSERT INTO highlights VALUES('3300091899_13_1115-1144','3300091899',95,'第2章 CMake简介','它更像是一个“元构建工具”，或者说是“构建工具的构建工具”','1098-1127',0,1728008280,1782480555);
INSERT INTO highlights VALUES('3300091899_13_936-987','3300091899',95,'第2章 CMake简介','CMake本身并不实际调用编译器和链接器等，而是根据配置生成Makefile或者其他构建工具的配置文件','919-970',0,1728008231,1782480555);
INSERT INTO highlights VALUES('3300091899_13_687-759','3300091899',95,'第2章 CMake简介','而广义的CMake指的是一系列工具的组合，包括用于构建的狭义的CMake、用于测试的CTest、用于打包的CPack等，它们都属于CMake家族','670-742',0,1728008205,1782480555);
INSERT INTO highlights VALUES('3300091899_13_428-458','3300091899',95,'第2章 CMake简介','CMake是一个跨平台开源工具家族，用于构建、测试和打包软件','411-441',0,1728008169,1782480555);
INSERT INTO highlights VALUES('3300091899_13_459-517','3300091899',95,'第2章 CMake简介','CMake通过简单的平台无关且编译器无关的配置文件来控制软件的编译流程，并能够生成原生的Makefile和工作空间，','442-500',0,1728008164,1782480555);
INSERT INTO highlights VALUES('3300091899_12_15839-15905','3300091899',94,'1.6 旅行笔记','有了构建模型之后，我们就不必再专注于不同平台的编译器的差异，而是将重心放在如何组织项目中的不同组件的依赖关系、构建要求和使用要求等。','15986-16052',0,1728008133,1782480555);
INSERT INTO highlights VALUES('3300091899_12_12854-12902','3300091899',94,'1.6 旅行笔记','当然，在编写Makefile时，需要为main目标的构建规则增加设定头文件搜索目录的编译器选项。','12986-13034',0,1728007933,1782480555);
INSERT INTO highlights VALUES('3300091899_12_12610-12637','3300091899',94,'1.6 旅行笔记','这里将库B中的函数f的返回值类型从void改为了类A。','12742-12769',0,1728007860,1782480555);
INSERT INTO highlights VALUES('3300091899_12_11849-11887','3300091899',94,'1.6 旅行笔记','为了避免这个问题，我们应当根据依赖关系，先链接有依赖的库，再链接被依赖的库。','11964-12002',0,1728007808,1782480555);
INSERT INTO highlights VALUES('3300091899_12_9289-9310','3300091899',94,'1.6 旅行笔记','需要注意的是，在构建静态库时没有链接这一步','9371-9392',0,1728007648,1782480555);
INSERT INTO highlights VALUES('3300091899_12_7955-7968','3300091899',94,'1.6 旅行笔记','接口处暴露库A中定义的符号','8020-8033',0,1728007559,1782480555);
INSERT INTO highlights VALUES('3300091899_12_7888-7944','3300091899',94,'1.6 旅行笔记','既然main间接地引用了库A的头文件，也就意味着main应该根据库A的使用要求来链接它。这种情形称作“递归传递”','7953-8009',0,1728007539,1782480555);
INSERT INTO highlights VALUES('3300091899_12_7581-7625','3300091899',94,'1.6 旅行笔记','如果可执行文件main本身使用了库A，那么库A的使用要求肯定应该传递给main的构建要求','7646-7690',0,1728007491,1782480555);
INSERT INTO highlights VALUES('3300091899_12_3865-3910','3300091899',94,'1.6 旅行笔记','而与其使用者相关的属性，则决定了构建目标的使用要求(usage requirements)','3899-3944',0,1727965090,1782480555);
INSERT INTO highlights VALUES('3300091899_12_3815-3864','3300091899',94,'1.6 旅行笔记','与构建目标自身源程序相关的属性，确定了构建目标的构建要求(build specification)','3849-3898',0,1727965085,1782480555);
INSERT INTO highlights VALUES('3300091899_12_2892-2970','3300091899',94,'1.6 旅行笔记',unistr('● 接口库；\u000a● 导入目标；\u000a● 别名目标。'),'2909-2987',0,1727964934,1782480555);
INSERT INTO highlights VALUES('3300091899_12_2728-2804','3300091899',94,'1.6 旅行笔记','将头文件库这种伪构建目标推广一下：自身不需要编译，但对使用者有一定要求的构建目标。这个推广后的伪构建目标称作接口库(interface library)','2745-2821',0,1727964924,1782480555);
INSERT INTO highlights VALUES('3300091899_12_2615-2643','3300091899',94,'1.6 旅行笔记','只需引用这个构建目标，并不需要知道头文件库具体的存储位置','2632-2660',0,1727964886,1782480555);
