INSERT INTO highlights VALUES('3300091899_12_1969-1979','3300091899',94,'1.6 旅行笔记','它就是目标文件的集合','1969-1979',0,1727964713,1782480555);
INSERT INTO highlights VALUES('3300091899_12_1934-1955','3300091899',94,'1.6 旅行笔记','目标文件库(object library)','1934-1955',0,1727964710,1782480555);
INSERT INTO highlights VALUES('3300091899_12_1768-1905','3300091899',94,'1.6 旅行笔记',unistr('二进制构建目标基本上包括以下类型：\u000a● 可执行文件；\u000a● 一般库（包含静态库和动态库）；\u000a● 目标文件库。'),'1768-1905',0,1727964696,1782480555);
