INSERT INTO highlights VALUES('3300091899_12_1422-1441','3300091899',94,'1.6 旅行笔记','构建目标是建立在源程序之上的更高层抽象','1405-1424',0,1727964557,1782480555);
INSERT INTO highlights VALUES('3300091899_12_1400-1421','3300091899',94,'1.6 旅行笔记','构建目标（target，简称目标）这个概念','1383-1404',0,1727964550,1782480555);
INSERT INTO highlights VALUES('3300091899_12_1369-1396','3300091899',94,'1.6 旅行笔记','目标文件虽然名叫“目标”，但终究不是我们最终想要的目标','1352-1379',0,1727964542,1782480555);
INSERT INTO highlights VALUES('3300091899_12_993-1190','3300091899',94,'1.6 旅行笔记',unistr('同时，还要根据一些特殊的构建要求，确定编译时传递的参数，例如：\u000a● 头文件搜索目录；\u000a● 链接库文件搜索目录；\u000a● 宏定义；\u000a● 其他编译链接参数等（如编译优化选项等）。'),'976-1173',0,1727964529,1782480555);
INSERT INTO highlights VALUES('3300091899_12_904-964','3300091899',94,'1.6 旅行笔记','如果不把头文件当作源程序，则可以说，源程序就是会被编译器编译成目标文件的文件。源程序可以看作构建过程中最基本的组成单元。','887-947',0,1727964495,1782480555);
INSERT INTO highlights VALUES('3300091899_12_785-802','3300091899',94,'1.6 旅行笔记','总结出共通之处，形成通用的构建模型','768-785',0,1727964466,1782480555);
INSERT INTO highlights VALUES('3300091899_12_660-722','3300091899',94,'1.6 旅行笔记','尽量避免直接调用平台相关的API，转而采用条件编译等技巧。然而，“到处编译”听起来就是一件麻烦的事情，这也是本书的焦点所在。','643-705',0,1727889296,1782480555);
INSERT INTO highlights VALUES('3300091899_11_8113-8156','3300091899',93,'1.5 引用第三方库','LINKFLAGS变量定义了向链接器传递的公共参数LIBPATH，即链接库的搜索目录。','8250-8293',0,1727884664,1782480555);
INSERT INTO highlights VALUES('3300091899_11_7976-8037','3300091899',93,'1.5 引用第三方库','/MD参数代表程序将会动态链接C++运行时库，与之相对地，MSVC还有一个/MT参数，表示程序将会静态链接C++运行时库。','8113-8174',0,1727882251,1782480555);
INSERT INTO highlights VALUES('3300091899_11_7920-7943','3300091899',93,'1.5 引用第三方库','CXXFLAGS变量用于向编译器传递公共参数。','8057-8080',0,1727882189,1782480555);
INSERT INTO highlights VALUES('3300091899_11_6592-6627','3300091899',93,'1.5 引用第三方库','注意：由于该表达式仅用于演示，刻意写得较为简短，并不能准确提取URL。','6712-6747',0,1727846574,1782480555);
INSERT INTO highlights VALUES('3300091899_11_4485-4517','3300091899',93,'1.5 引用第三方库','其中，主版本号14和次版本号的第一个数字2唯一决定其ABI稳定性','4554-4586',0,1727846438,1782480555);
INSERT INTO highlights VALUES('3300091899_11_4186-4273','3300091899',93,'1.5 引用第三方库','由于C++标准不保证编译后的应用程序二进制接口(Application Binary Interface，ABI)稳定性，不同版本的编译器编译出的程序无法保证相互引用而不出错','4255-4342',0,1727846395,1782480555);
INSERT INTO highlights VALUES('3300091899_11_3781-3841','3300091899',93,'1.5 引用第三方库','Boost通过文件名前缀来辨别二者：lib开头的.lib文件是静态库，而那些与动态库文件名完全匹配的则是动态库的导入库。','3816-3876',0,1727846371,1782480555);
INSERT INTO highlights VALUES('3300091899_11_2816-2867','3300091899',93,'1.5 引用第三方库','这里为编译器提供了参数/I "C:\boost"，表示将C:\boost添加到编译器的头文件搜索目录中','2816-2867',0,1727846130,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1777-1828','3300091899',93,'1.5 引用第三方库','最典型的例子可能就是C++的标准模板库(Standard Template Library，STL)了','1760-1811',0,1727845984,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1657-1687','3300091899',93,'1.5 引用第三方库','另外，分发头文件库也意味着开源是必需的了，毕竟需要用户来编译','1640-1670',0,1727845960,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1578-1596','3300091899',93,'1.5 引用第三方库','但其缺点也很明显，那就是影响编译时间','1561-1579',0,1727845939,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1472-1487','3300091899',93,'1.5 引用第三方库','头文件库在性能方面也更具有优势','1455-1470',0,1727845917,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1356-1402','3300091899',93,'1.5 引用第三方库','源程序引用头文件，相当于复制了头文件的内容，这样头文件库实际上也就成为了引用它的程序的一部分','1339-1385',0,1727845889,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1271-1318','3300091899',93,'1.5 引用第三方库','头文件库(header-only library)指只包含头文件（.h、.hpp等）的程序库。','1254-1301',0,1727845870,1782480555);
INSERT INTO highlights VALUES('3300091899_11_1076-1148','3300091899',93,'1.5 引用第三方库','Boost库中有一些源程序，需要被编译成动态库或静态库来使用。但我们暂时不会用到这些编译后的库文件，因此Boost库的安装构建会在后续章节介绍。','1059-1131',5,1727837463,1782480555);
INSERT INTO highlights VALUES('3300091899_10_13014-13110','3300091899',92,'1.4 构建动态库','其中的Pss指分摊内存(Proportional Set Size，PSS)，代表了这部分内存空间被共享进程平均分摊后的大小。或者说，用总占用内存空间除以共享这部分内存的进程的数量得出的结果。','13026-13122',5,1727836642,1782480555);
INSERT INTO highlights VALUES('3300091899_10_13742-13832','3300091899',92,'1.4 构建动态库','果然，剩下的唯一主程序进程中，动态库所在内存空间的第一部分，也就是代码段的Pss上涨到了2KB，而最后一部分对应的数据段的Pss则没有变化。也就是说，代码段确实在物理内存中共享。','13754-13844',5,1727836634,1782480555);
INSERT INTO highlights VALUES('3300091899_10_10163-10395','3300091899',92,'1.4 构建动态库','动态链接器会按照下面列举的顺序依次搜索：1.动态节中的RPATH项指定的路径；2.环境变量LD_LIBRARY_PATH指定的路径；3.系统配置文件/etc/ld.so.conf指定的路径；4.动态节中的RUNPATH项指定的路径。','10175-10407',5,1727836212,1782480555);
INSERT INTO highlights VALUES('3300091899_10_9583-9681','3300091899',92,'1.4 构建动态库','程序既然有能力告诉动态链接器它需要链接哪些动态库，就也应该有本事提醒动态链接器去哪里搜索动态库。这些信息存储在程序的动态节(dynamic section)中，我们可以通过readelf命令查看：','9595-9693',5,1727836156,1782480555);
INSERT INTO highlights VALUES('3300091899_10_9175-9197','3300091899',92,'1.4 构建动态库','但它默认只会在系统配置的一些目录下搜索动态库','9187-9209',5,1727836116,1782480555);
INSERT INTO highlights VALUES('3300091899_10_9262-9318','3300091899',92,'1.4 构建动态库','动态链接器还可以根据环境变量LD_LIBRARY_PATH的值来搜索动态库，因此可以通过设置环境变量来提示链接器','9274-9330',5,1727836111,1782480555);
INSERT INTO highlights VALUES('3300091899_10_8150-8231','3300091899',92,'1.4 构建动态库','实际上，Linux确实也支持类似Windows操作系统中通过静态重定位实现动态链接的方式，不过如果此时ASLR特性也是启用的，动态库就确实不能在物理内存中共享了。','8145-8226',5,1727835848,1782480555);
INSERT INTO highlights VALUES('3300091899_10_7495-7500','3300091899',92,'1.4 构建动态库','动态重定位','7490-7495',5,1727835721,1782480555);
INSERT INTO highlights VALUES('3300091899_10_7291-7378','3300091899',92,'1.4 构建动态库','这是因为它往往是有额外代价的。当启用了地址无关代码之后，目标代码访问全局变量、调用全局函数时，都会使用全局偏移表(Global Offset Table，GOT)做一次中转。','7286-7373',0,1727835693,1782480555);
INSERT INTO highlights VALUES('3300091899_10_7133-7233','3300091899',92,'1.4 构建动态库','地址无关代码(Position-Independent Code，PIC)就是指这种不访问内存绝对地址的代码。如果想让GCC编译器和Clang编译器生成地址无关代码，必须指定一个编译器参数-fPIC。','7128-7228',0,1727835662,1782480555);
INSERT INTO highlights VALUES('3300091899_10_6830-6926','3300091899',92,'1.4 构建动态库','Linux操作系统同样具有ASLR特性：通常情况下，每一个进程被创建时，都会将其可执行文件及其链接的动态库装载到不同的随机虚拟地址。这相比Windows操作系统更为激进，也提供了更好的安全性。','6825-6921',5,1727835642,1782480555);
INSERT INTO highlights VALUES('3300091899_10_5341-5401','3300091899',92,'1.4 构建动态库','由于导入库文件和静态库文件的扩展名都是“.lib”​，第一条主程序链接动态库的构建规则看起来和链接静态库时的规则完全一致。','5338-5398',5,1727835186,1782480555);
INSERT INTO highlights VALUES('3300091899_10_4826-4865','3300091899',92,'1.4 构建动态库','编译链接时，只导入库提供的链接信息就够了；只有程序运行时，才需要动态库的存在。','4823-4862',0,1727835119,1782480555);
INSERT INTO highlights VALUES('3300091899_10_4760-4822','3300091899',92,'1.4 构建动态库','我们可以简单地把“.lib”导入库看作一种接口定义，在链接时提供必要信息；而“.dll”动态库则包含运行时程序逻辑的目标代码','4757-4819',5,1727835072,1782480555);
INSERT INTO highlights VALUES('3300091899_10_4564-4596','3300091899',92,'1.4 构建动态库','其实这并非一个静态库。​“.lib”文件还可以是动态库的导入库文件','4562-4594',5,1727835033,1782480555);
INSERT INTO highlights VALUES('3300091899_10_4510-4522','3300091899',92,'1.4 构建动态库','还有一个liba.lib','4508-4520',5,1727835026,1782480555);
INSERT INTO highlights VALUES('3300091899_10_3714-3792','3300091899',92,'1.4 构建动态库','开发者可以决定动态库暴露给用户使用的函数或变量有哪些，并隐藏其他符号，避免外部用户使用。这也是动态库的一个特点，相比静态库而言，动态库能够提供更好的封装性。','3712-3790',5,1727834774,1782480555);
INSERT INTO highlights VALUES('3300091899_10_2121-2167','3300091899',92,'1.4 构建动态库','Windows操作系统中的ASLR特性的“随机化”​，对于动态链接库而言，只发生在计算机重启后','2103-2149',5,1727834553,1782480555);
INSERT INTO highlights VALUES('3300091899_10_1727-1732','3300091899',92,'1.4 构建动态库','偏好基地址','1741-1746',5,1727834456,1782480555);
INSERT INTO highlights VALUES('3300091899_10_1594-1656','3300091899',92,'1.4 构建动态库','这就意味着其编译后的机器代码中，凡是访问内存某一绝对位置的代码，在装载时都需要被改写。这就是重定位(relocation)。','1576-1638',5,1727834439,1782480555);
INSERT INTO highlights VALUES('3300091899_10_1449-1458','3300091899',92,'1.4 构建动态库','地址空间布局随机化','1431-1440',5,1727834408,1782480555);
INSERT INTO highlights VALUES('3300091899_10_1383-1428','3300091899',92,'1.4 构建动态库','当启动进程时，Windows操作系统会装载进程所需的动态链接库，并调用动态链','1365-1403',5,1727834400,1782480555);
INSERT INTO highlights VALUES('3300091899_10_1338-1353','3300091899',92,'1.4 构建动态库','Windows中动态链接的原理','1320-1335',5,1727834347,1782480555);
INSERT INTO highlights VALUES('3300091899_10_1075-1133','3300091899',92,'1.4 构建动态库','任何程序都能够在运行时将同一个动态库的目标代码动态链接到自己的程序中执行，而且这份动态库的代码在内存中可以只装载一份','1057-1115',5,1727834333,1782480555);
INSERT INTO highlights VALUES('3300091899_10_928-1001','3300091899',92,'1.4 构建动态库','与静态库不同，动态库的目标代码是在程序装载时或运行时被动态链接的，而非在编译过程中静态链接的。这样，动态库与使用动态库的程序就在编译期做到了解耦。','910-983',0,1727834292,1782480555);
INSERT INTO highlights VALUES('3300091899_10_554-558','3300091899',92,'1.4 构建动态库','浪费空间','537-541',5,1727834233,1782480555);
INSERT INTO highlights VALUES('3300091899_10_477-482','3300091899',92,'1.4 构建动态库',' 难以维护','461-465',5,1727834231,1782480555);
INSERT INTO highlights VALUES('3300091899_10_438-447','3300091899',92,'1.4 构建动态库','静态库有它的缺点。','421-430',0,1727834224,1782480555);
INSERT INTO highlights VALUES('3300091899_9_3353-3366','3300091899',91,'1.3 构建静态库','-lab指链接名为ab的库','3370-3383',5,1727834173,1782480555);
INSERT INTO highlights VALUES('3300091899_9_3135-3163','3300091899',91,'1.3 构建静态库','它通过ar归档命令，将目标文件a.o和b.o打包为静态库','3152-3180',5,1727834121,1782480555);
INSERT INTO highlights VALUES('3300091899_9_2257-2275','3300091899',91,'1.3 构建静态库','MSVC的lib.exe来生成静态库','2257-2275',5,1727834056,1782480555);
INSERT INTO highlights VALUES('3300091899_9_1065-1103','3300091899',91,'1.3 构建静态库','开发者只需引用提供的头文件，然后链接静态库，就可以使用该库开发好的实用功能了','1048-1086',0,1727801546,1782480555);
INSERT INTO highlights VALUES('3300091899_9_485-515','3300091899',91,'1.3 构建静态库','静态库可以被视作一系列目标文件的集合，甚至可以被解包软件打开','468-498',0,1727801486,1782480555);
INSERT INTO highlights VALUES('3300091899_9_409-464','3300091899',91,'1.3 构建静态库','静态库(static library)，也称为静态链接库(statically-linked library)','392-447',0,1727801472,1782480555);
INSERT INTO highlights VALUES('3300091899_9_469-484','3300091899',91,'1.3 构建静态库','最简单直接的一种复用代码的形式','452-467',0,1727801465,1782480555);
INSERT INTO highlights VALUES('3300091899_8_9655-9691','3300091899',90,'1.2 构建多源程序','这里最明显的问题就是MSVC编译器的参数写法和GCC/Clang并不兼容','9752-9788',1,1727796666,1782480555);
INSERT INTO highlights VALUES('3300091899_8_9365-9408','3300091899',90,'1.2 构建多源程序','归根结底，它只是根据规则推导出执行命令的顺序罢了，并非是一个专门针对构建某类程序的工具','9463-9506',1,1727796604,1782480555);
INSERT INTO highlights VALUES('3300091899_8_9281-9301','3300091899',90,'1.2 构建多源程序','尤其是面临跨平台需求时，其不足就很明显了','9379-9399',1,1727796584,1782480555);
INSERT INTO highlights VALUES('3300091899_8_9251-9281','3300091899',90,'1.2 构建多源程序','make简约而不简单。它实在太灵活了，有时候会让人无所适从。','9349-9379',1,1727796570,1782480555);
INSERT INTO highlights VALUES('3300091899_8_8826-8887','3300091899',90,'1.2 构建多源程序','Windows中的copy命令会保留被复制文件的修改时间，因而NMake不会认为这个main.cpp比main.exe更新','8907-8968',1,1727796552,1782480555);
INSERT INTO highlights VALUES('3300091899_8_7750-7775','3300091899',90,'1.2 构建多源程序','它只是简单地对比了一下构建目标与依赖目标的修改日期','7814-7839',1,1727796481,1782480555);
INSERT INTO highlights VALUES('3300091899_8_7610-7647','3300091899',90,'1.2 构建多源程序','如果想使用Clang编译器而非GCC，也可以在调用make的时候加上参数：','7674-7711',1,1727796361,1782480555);
INSERT INTO highlights VALUES('3300091899_8_7238-7306','3300091899',90,'1.2 构建多源程序','修改主程序main.cpp（通过复制并覆盖文件的方式），再次调用make命令构建项目，可以看到make只按需编译了变更的main.cpp','7302-7370',1,1727796349,1782480555);
INSERT INTO highlights VALUES('3300091899_8_6732-6761','3300091899',90,'1.2 构建多源程序','每个规则下面缩进的部分，就是构建这一目标所需要执行的命令。','6796-6825',1,1727796176,1782480555);
INSERT INTO highlights VALUES('3300091899_8_6315-6347','3300091899',90,'1.2 构建多源程序','简言之，Makefile规则文件是由一系列面向目标的规则构成的。','6379-6411',1,1727796105,1782480555);
INSERT INTO highlights VALUES('3300091899_8_6184-6191','3300091899',90,'1.2 构建多源程序','MSBuild','6231-6238',1,1727796088,1782480555);
INSERT INTO highlights VALUES('3300091899_8_6069-6125','3300091899',90,'1.2 构建多源程序','GNU make（简称make）是Linux中一个常见的构建工具。Windows上也有类似的工具，称为NMake','6116-6172',1,1727796073,1782480555);
INSERT INTO highlights VALUES('3300091899_8_4256-4297','3300091899',90,'1.2 构建多源程序','MSVC编译器的/c参数，可以使编译器仅将源程序编译为目标文件，而不进行链接过程。','4288-4329',1,1727795889,1782480555);
INSERT INTO highlights VALUES('3300091899_8_3825-3853','3300091899',90,'1.2 构建多源程序','因此，按需编译的关键，就是分别编译各个源程序到目标文件。','3841-3869',1,1727795844,1782480555);
INSERT INTO highlights VALUES('3300091899_8_3395-3517','3300091899',90,'1.2 构建多源程序','链接器的作用，就是把这些目标文件链接在一起，解析其中未定义的符号引用','3412-3446',1,1727795775,1782480555);
INSERT INTO highlights VALUES('3300091899_8_2364-2395','3300091899',90,'1.2 构建多源程序','MSVC编译器的/EHsc参数用于启用C++异常处理的展开语义','2364-2395',1,1727795457,1782480555);
INSERT INTO highlights VALUES('3300091899_8_820-843','3300091899',90,'1.2 构建多源程序','extern const char *msg;','809-832',1,1727795314,1782480555);
INSERT INTO highlights VALUES('3300091899_7_1697-1702','3300091899',89,'1.1 单源文件程序：您好，世界','a.out','1713-1718',1,1727795232,1782480555);
INSERT INTO highlights VALUES('3300091899_7_738-828','3300091899',89,'1.1 单源文件程序：您好，世界','Microsoft Visual C++（简称MSVC）广义上讲是一个集成开发环境，包含了Windows C和C++编程各个环节所需的功能组件；狭义上讲，则指微软的C和C++编译器','738-828',1,1727795047,1782480555);
INSERT INTO highlights VALUES('3300091899_5_522-532','3300091899',86,'本书读者','跨平台C和C++程序','505-515',1,1727794887,1782480555);
