INSERT INTO highlights VALUES('3300105051_111_2343-2403','3300105051',111,'没钱汉子难','1921年，日本海军预算占日本财政总支出的32%，再加上陆军的支出，日本一半以上财政都砸到了军备上面，穷兵黩武到了极点。','2343-2403',5,1725448298,1782480556);
INSERT INTO highlights VALUES('3300105051_111_1422-1470','3300105051',111,'没钱汉子难','14条和平纲领，其中第二条明确要求以后各国无论在和平还是战时都不能私自封锁除自己领海以外的海域。','1422-1470',5,1725414539,1782480556);
