INSERT INTO highlights VALUES('3300105051_83_997-1063','3300105051',83,'德国的锦囊','于是德国海军就这么瞻前顾后地蹉跎了快两年，如今国内已经被封锁到饿死人了，他们的主力军舰都还全须全尾地蹲在港口里，整得跟个吉祥物似的。','997-1063',5,1725295655,1782480556);
INSERT INTO highlights VALUES('3300105051_82_1169-1193','3300105051',82,'第十一章 决战日德兰','它思绪万千、夜不能寐、情不自禁地流下了哈喇子……','1169-1193',5,1725294629,1782480556);
INSERT INTO highlights VALUES('3300105051_81_2646-2710','3300105051',81,'海洋的权柄','这样的结果就是德国家门口的海域被英国海军彻底封锁，而这也正体现了海权分配的规律：一片海域的制海权只属于这片海域里最强的那支海军。','2646-2710',5,1725294511,1782480556);
INSERT INTO highlights VALUES('3300105051_80_3832-3873','3300105051',80,'命运的齿轮','如果德国同时与俄法交战，那就应该首先闪击法国，几个星期内搞定法国后再转过头进攻俄国','3832-3873',5,1725240406,1782480556);
INSERT INTO highlights VALUES('3300105051_80_1261-1292','3300105051',80,'命运的齿轮','于是在1914年7月23日，奥匈帝国向塞尔维亚发出了最后通牒。','1261-1292',5,1725240129,1782480556);
INSERT INTO highlights VALUES('3300105051_68_1445-1559','3300105051',68,'统一与崛起',unistr('而那些本来不愿意统一的南方各邦国，也在民族危难之际放下嫌隙，与北德意志联邦联合，共同抗法。\u000a于是，俾斯麦就如愿以偿地与法国这个统一路上最后的障碍开始决战，史称“普法战争”。'),'1445-1559',5,1725208278,1782480556);
INSERT INTO highlights VALUES('3300105051_67_4418-4454','3300105051',67,'铁与血','普鲁士在吞掉这些邦国后，建立了北德意志联邦，德国实现了大部分领土的统一。','4418-4454',5,1725207994,1782480556);
INSERT INTO highlights VALUES('3300105051_66_2332-2389','3300105051',66,'统一之路','同年7月，全德意志范围内的起义被镇压，德国1848年革命失败，德意志又回到分裂割据的局面，和平统一的梦想就此破灭。','2332-2389',5,1725207426,1782480556);
INSERT INTO highlights VALUES('3300105051_64_1741-1825','3300105051',64,'一盘散沙',unistr('神圣罗马帝国覆灭仅2个月后，拿破仑的铁蹄就踏进了普鲁士的勃兰登堡大门，还顺走了勃兰登堡大门上面的和平女神雕像。\u000a'),'1741-1796',5,1725206905,1782480556);
INSERT INTO highlights VALUES('3300105051_61_2263-2328','3300105051',61,'赢家','日本民众的选择导致当时那个相对理智的政府失去了话语权，于是，就逐渐有一批新的政客开始把控日本政坛，他们大都毕业于日本陆军大学校……','2263-2328',5,1725198133,1782480556);
