INSERT INTO highlights VALUES('3300105051_57_4046-4099','3300105051',57,'内讧型军队','紧接着攻城臼炮的炮弹就砸向了旅顺港内的俄第一太平洋舰队，困在港内的军舰毫无还手之力，这支远东劲旅就此覆灭。','4046-4099',5,1725120412,1782480556);
INSERT INTO highlights VALUES('3300105051_108_3645-3682','3300105051',108,'破产式维新','秋山真之对海战的理解超越了所有的日本同僚，甚至走到了世界海战理论的最前沿。','3645-3682',5,1723908263,1782480556);
INSERT INTO highlights VALUES('3300105051_108_3471-3513','3300105051',108,'破产式维新','秋山真之就读于安纳波利斯海军军官学校，其导师正是海权论的泰斗阿尔弗雷德·赛耶·马汉。','3471-3513',5,1723908249,1782480556);
INSERT INTO highlights VALUES('3300105051_108_2534-2562','3300105051',108,'破产式维新','一个人的命运啊，当然要靠自我奋斗，但也要考虑到历史进程。','2534-2562',5,1723908164,1782480556);
INSERT INTO highlights VALUES('3300105051_108_2029-2074','3300105051',108,'破产式维新','日本人都穷成这样了，却仍对维新的前景抱有巨大的期望，这种盲目乐观主义精神在世界上并不多见。','2029-2074',5,1723908127,1782480556);
INSERT INTO highlights VALUES('3300105051_49_2155-2190','3300105051',49,'日不落的棋局','英国于1902年1月30日与日本签订了《英日同盟协定》，正式成为盟友。','2155-2190',5,1723907842,1782480556);
INSERT INTO highlights VALUES('3300105051_49_1778-1801','3300105051',49,'日不落的棋局','不过这人哪，一旦放弃了脸面，那路就会越走越宽。','1778-1801',5,1723907810,1782480556);
INSERT INTO highlights VALUES('3300105051_49_1066-1246','3300105051',49,'日不落的棋局',unistr('俄国却以保护自己通向旅顺的铁路不受义和团破坏为由，额外集结十几万军队攻打根本就没有多少义和团的东三省。\u000a面对俄国的武力，东北清军无奈地妥协，俄军则劫掠了几乎所有的东北城镇，而且义和团运动失败以后，俄军也没走。十几万俄军就此常驻东北，使得俄国成了东北的实际控制者。大清的“以夷制夷”最终造成了“引熊入室”。'),'1066-1246',5,1723907748,1782480556);
INSERT INTO highlights VALUES('3300105051_49_837-864','3300105051',49,'日不落的棋局','日不落帝国猛然发现，这个世界它已经开始有些拿捏不住了。','837-864',5,1723907680,1782480556);
INSERT INTO highlights VALUES('3300105051_49_621-747','3300105051',49,'日不落的棋局',unistr('而俄国在19世纪的崛起势头非常强劲，对这样的国家，英国自然是“严重关切”。事实上两国在近几十年间冲突不断，已然成为一对死敌。\u000a所以，英国当然乐于看到日本在远东地区坐大，因为这样可以遏制俄国的发展。'),'621-747',5,1723907661,1782480556);
INSERT INTO highlights VALUES('3300105051_49_549-592','3300105051',49,'日不落的棋局','作为全球霸主，大英帝国不希望看到任何一个国家抬头，谁有崛起的苗头，英国都要去打压一番。','549-592',5,1723907640,1782480556);
INSERT INTO highlights VALUES('3300105051_107_755-797','3300105051',107,'皇图霸业','俄国从1891年就开始倾举国之力修建圣彼得堡至远东地区的超级铁路，其总长达一万公里。','755-797',5,1723907492,1782480556);
INSERT INTO highlights VALUES('3300105051_46_1811-1862','3300105051',46,'龙兴之地','“三国干涉还辽”事件让大清看到了解决问题的思路，何不来个“以夷制夷”，把旁边的俄国拉入东北来协防日本？','1811-1862',5,1723818569,1782480556);
INSERT INTO highlights VALUES('3300105051_44_1690-1789','3300105051',44,'霸权之路','在罗斯福治下，美国的国际影响力空前提升，海军实力也上升至世界第二。再加上其任上对国内腐败和垄断势力的整治，这位总统的个人名望达到顶峰，并最终被刻上了总统山，他至今仍是美国史上最受民间好评的总统之一。','1690-1789',5,1723817975,1782480556);
INSERT INTO highlights VALUES('3300105051_44_1309-1356','3300105051',44,'霸权之路','在美国控制完古巴后，罗斯福再接再厉，又策动巴拿马独立，进而获得巴拿马运河的开挖权和管理使用权。','1309-1356',5,1723817938,1782480556);
INSERT INTO highlights VALUES('3300105051_44_817-866','3300105051',44,'霸权之路','“以加勒比海和中美洲地峡水域为基础控制其他海洋，以菲律宾为基础争夺东亚利益”，堪称“美版隆中对”。','817-866',5,1723808616,1782480556);
INSERT INTO highlights VALUES('3300105051_44_688-734','3300105051',44,'霸权之路','马汉从战场归来后又陆续发表了《海权论》三部曲，这批著作后来成为美国建立海洋霸权的指导性纲领。','688-734',5,1723808592,1782480556);
INSERT INTO highlights VALUES('3300105051_43_5440-5472','3300105051',43,'古巴决战','而西班牙则失去了几乎所有的殖民地，以后江湖上再也没人叫它大哥了。','5440-5472',5,1723808556,1782480556);
INSERT INTO highlights VALUES('3300105051_43_5200-5293','3300105051',43,'古巴决战','古巴将面积为117平方公里（其中78平方公里陆地面积，39平方公里海湾面积）的关塔那摩地区无限期租给美国作为海军基地，美国每年支付古巴2000美元的租金（1974年涨价为4085美元）。','5200-5293',5,1723808531,1782480556);
INSERT INTO highlights VALUES('3300105051_43_4409-4490','3300105051',43,'古巴决战','1898年12月10日，两国在巴黎签署《巴黎和约》，西班牙放弃古巴并撤军，允许古巴独立，同时还将波多黎各和关岛割让给美国，并以2000万美元的价格将菲律宾卖给美国','4409-4490',5,1723730119,1782480556);
INSERT INTO highlights VALUES('3300105051_43_4090-4134','3300105051',43,'古巴决战','此役西班牙海军474人阵亡，1750人被俘，而美军仅1人阵亡，10人受伤，舰船基本无损。','4090-4134',5,1723730085,1782480556);
INSERT INTO highlights VALUES('3300105051_43_2256-2285','3300105051',43,'古巴决战','罗斯福在开战后就辞去了海军部副部长的职务，报名参加了志愿军','2256-2285',5,1723684595,1782480556);
INSERT INTO highlights VALUES('3300105051_43_2165-2202','3300105051',43,'古巴决战','在登陆的美国陆军中，我们可以看到一个有些发福的身影，他就是西奥多·罗斯福。','2165-2202',5,1723684509,1782480556);
INSERT INTO highlights VALUES('3300105051_43_1832-1879','3300105051',43,'古巴决战','海军存在的意义在于争夺海域的制海权，只有控制了制海权，本国的支援和补给才能源源不断地送往战场。','1832-1879',5,1723684487,1782480556);
INSERT INTO highlights VALUES('3300105051_43_1023-1087','3300105051',43,'古巴决战','其中原本布置在西海岸的“俄勒冈”号战列舰更是不惜以平均12节的巡航速度连续航行66天，疯狂跋涉15000海里绕过南美洲赶到古巴。','1023-1087',5,1723684339,1782480556);
INSERT INTO highlights VALUES('3300105051_43_408-459','3300105051',43,'古巴决战','多年以后，看着圣地亚哥来来往往的船只，西班牙人会回想起无敌舰队从里斯本起航的那个清晨，那是帝国的斜阳。','408-459',5,1723684185,1782480556);
INSERT INTO highlights VALUES('3300105051_42_1604-1630','3300105051',42,'破局','他们在来的路上还顺手牵羊地抢走了西班牙的殖民地关岛。','1604-1630',5,1723684100,1782480556);
INSERT INTO highlights VALUES('3300105051_42_971-1034','3300105051',42,'破局','最后，美国人拍着胸脯向菲军表示：等战争尘埃落定后，就让你们独立，我们的敌人是西班牙，跟你们合作就是交个朋友，没有什么别的企图。','971-1034',5,1723684044,1782480556);
INSERT INTO highlights VALUES('3300105051_41_3222-3263','3300105051',41,'风云际会马尼拉','接下来杜威的一系列操作向世人证明了一件事——美国毫无疑问是大英搅局者的最佳传承人。','3222-3263',5,1723683966,1782480556);
INSERT INTO highlights VALUES('3300105051_41_2582-2620','3300105051',41,'风云际会马尼拉','他们都在伺机抢夺美军的胜利果实。一时间美西英德菲五路人马齐聚一堂，风云际会。','2582-2620',5,1723683858,1782480556);
INSERT INTO highlights VALUES('3300105051_41_2440-2456','3300105051',41,'风云际会马尼拉','那时候的菲律宾人也曾是血性男儿，','2440-2456',5,1723683831,1782480556);
INSERT INTO highlights VALUES('3300105051_40_1842-1879','3300105051',40,'古巴惊雷','没过多久，美国亚洲舰队就完成了弹药储备，随后杜威大手一挥，全军向香港开拔。','1842-1879',5,1723612646,1782480556);
INSERT INTO highlights VALUES('3300105051_40_1175-1223','3300105051',40,'古巴惊雷','在这几年里，美国媒体孜孜不倦地宣传古巴义军的英勇和西班牙殖民者的残忍，甚至不惜杜撰出来很多故事。','1175-1223',5,1723612494,1782480556);
INSERT INTO highlights VALUES('3300105051_40_1112-1118','3300105051',40,'古巴惊雷','疯狂“造舆论','1112-1118',5,1723612480,1782480556);
INSERT INTO highlights VALUES('3300105051_40_929-1000','3300105051',40,'古巴惊雷','丛林世界里可没有法官给你主持公道，在这里倚老卖老是没有前途的。而且退一万步来说，就算这个世界上真的有公道，那首先考虑的也应该是古巴人民的公道。','929-1000',5,1723612463,1782480556);
INSERT INTO highlights VALUES('3300105051_39_1602-1676','3300105051',39,'造舰到底有什么用','而美国也如梦方醒，终于明白为什么自己这么有钱还会被人看不起，也终于想清楚海军的开销其实不是成本，而是赌桌上的筹码；有筹码在，才有机会赢得更多的利益。','1602-1676',5,1723612130,1782480556);
INSERT INTO highlights VALUES('3300105051_39_1379-1416','3300105051',39,'造舰到底有什么用','这些列强闷头搞了几百年的海军，直到遇见马汉才弄明白自己为什么要造这么多军舰','1379-1416',5,1723612046,1782480556);
INSERT INTO highlights VALUES('3300105051_39_1544-1573','3300105051',39,'造舰到底有什么用','原来各国造舰基本上够用就行，现在造舰要比对手更大更强才行。','1544-1573',5,1723600213,1782480556);
INSERT INTO highlights VALUES('3300105051_39_695-788','3300105051',39,'造舰到底有什么用','马汉认为现实世界没有什么岁月静好，就算有也只是暂时的。在他眼里，这个世界的基调永远是优胜劣汰、适者生存。对一个国家来说，放弃海军、长期龟缩是不行的；自己不强起来，迟早会被列强海军打进来。','695-788',5,1723600029,1782480556);
INSERT INTO highlights VALUES('3300105051_39_488-560','3300105051',39,'造舰到底有什么用','阿尔弗雷德·赛耶·马汉，1840年出生。他和前面提到的杜威一样，都是海军军官，不过和杜威不同的是，他对当英雄没兴趣，更喜欢蹲在学校里搞理论研究。','488-560',5,1723599999,1782480556);
INSERT INTO highlights VALUES('3300105051_38_1068-1135','3300105051',38,'“老炮”的威胁','19世纪末，通过南北战争完成实质统一的美国在经济和工业发展上一飞冲天，1894年，美国的工业生产总值超过英国，成为全球最大的工业国家。','1068-1135',5,1723599874,1782480556);
INSERT INTO highlights VALUES('3300105051_38_811-848','3300105051',38,'“老炮”的威胁','到19世纪末的时候，西班牙的殖民地只剩古巴和菲律宾，以及非洲的一小块地方。','811-848',5,1723599850,1782480556);
INSERT INTO highlights VALUES('3300105051_37_1927-1954','3300105051',37,'躺平美利坚','长期以来，各国海军的主要作用是辅助陆军和守护贸易航线。','1927-1954',5,1723599785,1782480556);
INSERT INTO highlights VALUES('3300105051_37_1055-1122','3300105051',37,'躺平美利坚','美国本来是蒸汽铁甲舰的开创者，国会却规定今后美国海军只能以风帆作为主要动力，非必要不烧煤。国会老爷们觉得烧煤太贵，免费的风动力不香吗？','1055-1122',5,1723599713,1782480556);
INSERT INTO highlights VALUES('3300105051_35_2750-2823','3300105051',35,'真实的逻辑','到了1949年，中国终于成功跨入现代国家的门槛，国家间的代差逐渐缩小最终不复存在，对外战争的逻辑也彻底改变。从此以后，中国的对外战争就再也没输过。','2750-2823',5,1723599586,1782480556);
INSERT INTO highlights VALUES('3300105051_35_2610-2680','3300105051',35,'真实的逻辑','在这个时间段里，中国的国家体系总是落后外敌一个时代，中国所有的对外战争都是有代差的战争，要么是古代军队打近代军队，要么是近代军队打现代军队。','2610-2680',5,1723599572,1782480556);
INSERT INTO highlights VALUES('3300105051_35_2173-2269','3300105051',35,'真实的逻辑','尽管这是一个国不知有民、民不知有国的蒙昧国家，战场上还是涌现出了大批视死如归的爱国将领和官兵，这体现的其实是文明的底蕴。在文明最黑暗的时刻，中国正是靠着几千年积攒出来的底蕴维持着最后一丝希望。','2173-2269',5,1723599427,1782480556);
INSERT INTO highlights VALUES('3300105051_35_1635-1654','3300105051',35,'真实的逻辑','《想象的共同体：民族主义的起源与散布》','1635-1654',5,1723599368,1782480556);
INSERT INTO highlights VALUES('3300105051_35_1133-1169','3300105051',35,'真实的逻辑','签订《马关条约》的清朝统治者虽然怂包，但投降确实也是当时他们唯一的选择。','1133-1169',5,1723599110,1782480556);
INSERT INTO highlights VALUES('3300105051_106_2050-2117','3300105051',106,'日本的不归路','日本不仅没有岁月静好，反而加上了更大的杠杆。这之后日本在海军上砸的钱超过了北洋水师和之前日本舰队之和的十倍，迅速成为世界海军列强之一。','2050-2117',5,1723598955,1782480556);
INSERT INTO highlights VALUES('3300105051_106_1417-1447','3300105051',106,'日本的不归路','就算它赢了战争，如果它拿不到巨额的赔款，它的经济一样会崩溃。','1417-1447',5,1723598918,1782480556);
INSERT INTO highlights VALUES('3300105051_33_2417-2486','3300105051',33,'“一次性舰队”','1895年2月3日，威海卫陷落，随后重伤瘫痪的“定远”“靖远”为不资敌而自爆，北洋水师提督和总兵履行其“苟丧舰，必自裁”的誓言，自杀殉国。','2417-2486',5,1723598757,1782480556);
INSERT INTO highlights VALUES('3300105051_33_1764-1874','3300105051',33,'“一次性舰队”',unistr('为何修不好呢？因为战舰维修需要大量的进口零件，清廷事先并未做好准备，也没钱买。而且不要说进口零件了，连专业的维修工人都凑不齐，政府竟然调用铁路和煤矿的工匠来凑合。\u000a'),'1764-1845',5,1723598569,1782480556);
INSERT INTO highlights VALUES('3300105051_33_635-684','3300105051',33,'“一次性舰队”','和我们经常听到的说法不同的是，北洋官兵的素质其实要好于日军，北洋水师的射击命中率比日本联合舰队更高','635-684',5,1723598498,1782480556);
INSERT INTO highlights VALUES('3300105051_33_559-606','3300105051',33,'“一次性舰队”','而日本舰队总共发射了3982发大口径炮弹，其他的小口径速射炮发射炮弹更是高达16939发之多。','559-606',5,1723598477,1782480556);
INSERT INTO highlights VALUES('3300105051_32_4355-4395','3300105051',32,'黄海决战','其中落单的“经远”被日舰咬住，在顽强坚持了一个多小时后，最终“船身碎裂”而沉。“','4355-4395',5,1723598370,1782480556);
INSERT INTO highlights VALUES('3300105051_32_4215-4240','3300105051',32,'黄海决战','“致远”舰邓世昌以下252人除7人获救外全部殉国。','4215-4240',5,1723598333,1782480556);
INSERT INTO highlights VALUES('3300105051_32_1567-1600','3300105051',32,'黄海决战','日军这个单纵队以侧面对敌的阵型后来也成为各国战列舰炮战的标准队形。','1567-1600',5,1723598007,1782480556);
INSERT INTO highlights VALUES('3300105051_105_2360-2415','3300105051',105,'明治杠杆天团','正所谓贷款一时爽，一直贷款一直爽。杠杆在手的明治政府仿佛打出了一张“无中生有”的牌，一夜之间从穷鬼变成了土豪。','2360-2415',5,1723567792,1782480556);
INSERT INTO highlights VALUES('3300105051_105_1877-1902','3300105051',105,'明治杠杆天团','日本通过明治维新设立了一个清朝没有的东西——银行。','1877-1902',5,1723567727,1782480556);
INSERT INTO highlights VALUES('3300105051_105_1504-1566','3300105051',105,'明治杠杆天团','到了甲午战争前，日本虽然经济总量不如清朝，但是国家的年财政收入达到了7000万两白银，已经接近清朝8000多万两白银的水平。','1504-1566',5,1723567697,1782480556);
INSERT INTO highlights VALUES('3300105051_105_1084-1118','3300105051',105,'明治杠杆天团','首先，日本民众承受的税负比清朝民众重得多，同时社会还能保持稳定运行。','1084-1118',5,1723567646,1782480556);
INSERT INTO highlights VALUES('3300105051_27_2868-2913','3300105051',27,'新的时代','德国海军司令甚至带着老婆孩子亲自到场盛情款待：“欢迎莅临德国，尊敬的大清国特使先生们……”','2867-2912',5,1723567313,1782480556);
INSERT INTO highlights VALUES('3300105051_27_1640-1665','3300105051',27,'新的时代','也就是说，直到2013年，奴隶制才在美国彻底终结。','1639-1664',5,1723514738,1782480556);
INSERT INTO highlights VALUES('3300105051_27_1042-1096','3300105051',27,'新的时代','在产业保护的政策下，这个新兴国家逐步摆脱了对旧大陆的经济依赖，肃清了殖民主义的遗毒，开始走上自力更生的道路。','1042-1096',5,1723514648,1782480556);
INSERT INTO highlights VALUES('3300105051_27_887-918','3300105051',27,'新的时代','建立在战争基础上的统一，其妥协的空间更小，共识的凝结更为牢固。','887-918',5,1723514632,1782480556);
INSERT INTO highlights VALUES('3300105051_27_771-809','3300105051',27,'新的时代','美国通过这场战争在国家统治上确立了强势总统模式，全国实现了真正意义上的统一。','771-809',5,1723514298,1782480556);
INSERT INTO highlights VALUES('3300105051_27_504-520','3300105051',27,'新的时代','这场战争到处充斥着工业化的影响，','504-520',5,1723514269,1782480556);
INSERT INTO highlights VALUES('3300105051_104_2996-3047','3300105051',104,'大国买办的结局','美国的南方势力就这样被抛弃了。这也是大国买办最常见的下场，上赶着做别人的棋子，终究会成为所有人的弃子。','2996-3047',5,1723514131,1782480556);
INSERT INTO highlights VALUES('3300105051_104_2373-2405','3300105051',104,'大国买办的结局','南北战争爆发的1861年和1862年正好是英国粮食歉收的两年……','2373-2405',5,1723514104,1782480556);
INSERT INTO highlights VALUES('3300105051_104_1682-1739','3300105051',104,'大国买办的结局','林肯为了表达对俄国的感谢，就跟它谈下了一笔大生意，花720万美元“巨款”买下了俄国一片鸟不拉屎的荒地——阿拉斯加。','1682-1739',5,1723513727,1782480556);
INSERT INTO highlights VALUES('3300105051_104_1578-1613','3300105051',104,'大国买办的结局','19世纪的美国在世界上没什么朋友，俄国是它在那个黑暗年代里唯一的依靠。','1578-1613',5,1723513716,1782480556);
INSERT INTO highlights VALUES('3300105051_104_1134-1202','3300105051',104,'大国买办的结局','美国曾在1823年提出“门罗主义”，即“美洲事务是美洲人的事务”，翻译过来就是：“拉美这些国家只能我美国来揍，你们欧洲人谁也不准动手。”','1134-1202',5,1723513613,1782480556);
INSERT INTO highlights VALUES('3300105051_104_663-694','3300105051',104,'大国买办的结局','到1862年，英国失业人口已经攀升到全国人口总数的31.8%。','663-694',5,1723513556,1782480556);
INSERT INTO highlights VALUES('3300105051_25_3745-3784','3300105051',25,'乌龟游戏','说到底，海战是最拼工业实力的一个战场，仅靠“歪招”是改变不了海权控制的格局的。','3745-3784',5,1723513478,1782480556);
INSERT INTO highlights VALUES('3300105051_25_624-666','3300105051',25,'乌龟游戏','为了以防万一，北方军还是组织人力物力模仿南方军捣鼓了一艘类似的蒸汽铁甲舰“班长”号。','624-666',5,1723511557,1782480556);
INSERT INTO highlights VALUES('3300105051_24_999-1027','3300105051',24,'改变世界的怪物','在海上作战首先拼的是工业实力，你得先拿得出足够的军舰再说','999-1027',5,1723469599,1782480556);
INSERT INTO highlights VALUES('3300105051_23_4180-4205','3300105051',23,'北美内斗大陆','一个有进取心的大国注定不会让买办阶层永远舒服下去。','4180-4205',5,1723469487,1782480556);
INSERT INTO highlights VALUES('3300105051_23_2812-2907','3300105051',23,'北美内斗大陆','美国的产业保护本质上是一条牺牲农业来发展工业的路子。从理论上讲，等工业发展起来了可以再反哺农业，可是南方的种植园主们显然没有这个觉悟和耐心去等待这一天，他们果断地对北方搞的产业保护政策说不。','2812-2907',1,1723453927,1782480556);
INSERT INTO highlights VALUES('3300105051_23_2409-2448','3300105051',23,'北美内斗大陆','南方这些蓄奴州在经济结构上只是旧大陆（欧洲）的延伸，它们的经济严重依赖旧大陆，','2409-2448',5,1723427282,1782480556);
INSERT INTO highlights VALUES('3300105051_23_941-973','3300105051',23,'北美内斗大陆','当时美国的问题是，北方的工业虽然发展得很快，但整体水平仍然很低。','941-973',5,1723427119,1782480556);
INSERT INTO highlights VALUES('3300105051_23_782-827','3300105051',23,'北美内斗大陆','于是，南方的奴隶交易规模迅速扩大，到19世纪，美国奴隶数量从独立时的60万暴增到400万。','782-827',5,1723427102,1782480556);
INSERT INTO highlights VALUES('3300105051_22_2039-2092','3300105051',22,'大英“内卷”帝国','在美国，塞缪尔硬是凭着自己的记忆复制出英国先进的阿克莱特水力纺纱机，并在此基础上建立起美国第一家棉纺织厂。','2039-2092',5,1723427036,1782480556);
INSERT INTO highlights VALUES('3300105051_22_1973-2010','3300105051',22,'大英“内卷”帝国','1789年的塞缪尔正是在这样的背景下伪装成一个农夫，空着手跑到北美大陆的。','1973-2010',5,1723427026,1782480556);
