INSERT INTO highlights VALUES('3300105051_103_1528-1578','3300105051',103,'新王登基','贸然和英国这个“欧洲工厂”进行切割，导致欧洲诸国的经济运行成本大幅增加，联合封锁的局面注定不可持续。','1528-1578',5,1723356903,1782480556);
INSERT INTO highlights VALUES('3300105051_19_5330-5371','3300105051',19,'特拉法尔加海战','他命令每艘法国军舰都挂上纳尔逊的肖像以示纪念，也是希望法国人能多学习一点纳尔逊精神','5330-5371',5,1723356754,1782480556);
