INSERT INTO highlights VALUES('3300105051_17_1042-1061','3300105051',17,'山雨欲来','丛林世界的和平只建立在大炮的射程之内，','1042-1061',5,1723355765,1782480556);
INSERT INTO highlights VALUES('3300105051_16_409-456','3300105051',16,'全村的希望','1768年，热那亚把地中海的科西嘉岛卖给法国，于是，一年后在科西嘉岛出生的拿破仑就成了法国人。','409-456',5,1723355333,1782480556);
INSERT INTO highlights VALUES('3300105051_102_4488-4518','3300105051',102,'暴雷欧洲','就在英国以为可以高枕无忧的时候，法国刮出了一张史诗级的彩票。','4488-4518',5,1723355318,1782480556);
INSERT INTO highlights VALUES('3300105051_102_3762-3803','3300105051',102,'暴雷欧洲','1756年的七年战争可以这样理解：法国为了续命，做出最后一搏，结果偷鸡不成蚀把米。','3762-3803',5,1723355254,1782480556);
INSERT INTO highlights VALUES('3300105051_102_3832-3912','3300105051',102,'暴雷欧洲',unistr('战争的失败进一步加剧了法国的国库空虚和负债水平；同时，失去大量殖民地也导致法国经济的造血功能急剧下降。\u000a'),'3832-3883',5,1723355234,1782480556);
INSERT INTO highlights VALUES('3300105051_102_3680-3718','3300105051',102,'暴雷欧洲','顺便说一句，这位以一己之力带崩欧陆最强国家的金融鬼才约翰·劳，他是个英国人。','3680-3718',5,1723355197,1782480556);
INSERT INTO highlights VALUES('3300105051_102_1977-1999','3300105051',102,'暴雷欧洲','英国思来想去，就打算向它的北美殖民地收点税。','1977-1999',5,1723355037,1782480556);
INSERT INTO highlights VALUES('3300105051_102_1847-1909','3300105051',102,'暴雷欧洲','而英国则通过这场战争吞并了法国在北美、西印度群岛、非洲以及印度的大片殖民地，从此成为欧洲各国中占有海外殖民地数量最多的国家。','1847-1909',5,1723355027,1782480556);
INSERT INTO highlights VALUES('3300105051_102_1695-1743','3300105051',102,'暴雷欧洲','英国海军开始大肆扫荡各国的海外殖民地，连续攻占了孟加拉国、加拿大、西属佛罗里达、印度法属据点等地','1695-1743',5,1723354993,1782480556);
INSERT INTO highlights VALUES('3300105051_102_1208-1253','3300105051',102,'暴雷欧洲','为了维护欧洲谁也吃不掉谁的大好局面，英国赶紧一棍子搅到这场乱局中，果断和普鲁士结成了盟友。','1208-1253',5,1723353783,1782480556);
INSERT INTO highlights VALUES('3300105051_14_2711-2787','3300105051',14,'抢劫，还是贸易',unistr('法案最重要的一条就是，运往英国和英国殖民地的货物必须用英国的商船。\u000a这就是个强买强卖的霸王条款。'),'2711-2787',5,1723353365,1782480556);
INSERT INTO highlights VALUES('3300105051_14_1953-1972','3300105051',14,'抢劫，还是贸易','第一家股份有限公司——荷兰东印度公司。','1953-1972',5,1723353292,1782480556);
INSERT INTO highlights VALUES('3300105051_14_1849-1892','3300105051',14,'抢劫，还是贸易','更重要的是，荷兰还超前地建立了完备的金融体系，可以说荷兰定义了我们现在看到的现代金融。','1849-1892',5,1723353286,1782480556);
INSERT INTO highlights VALUES('3300105051_14_1073-1115','3300105051',14,'抢劫，还是贸易','西班牙衰败后，英国就开始“洗白”上岸，停止了官方的海盗行为，把主要精力用在贸易上面。','1073-1115',5,1723353154,1782480556);
INSERT INTO highlights VALUES('3300105051_14_741-808','3300105051',14,'抢劫，还是贸易','本来世界霸主借点钱也不是什么难事，但是西班牙有一个很不好的作风，就是经常仗着船坚炮利借钱不还。于是，欠的债越来越多，借贷成本也越来越高','741-808',5,1723353127,1782480556);
INSERT INTO highlights VALUES('3300105051_14_492-553','3300105051',14,'抢劫，还是贸易','这里面的逻辑也很简单，抢来的钱太容易，人们很容易放弃生产，只会购买他国产品，再加上掠夺的钱又源源不断，自然会引发通货膨胀。','492-553',5,1723352985,1782480556);
INSERT INTO highlights VALUES('3300105051_14_448-462','3300105051',14,'抢劫，还是贸易','靠抢劫建立起来的霸权不可持续','448-462',5,1723352978,1782480556);
INSERT INTO highlights VALUES('3300105051_101_2952-3024','3300105051',101,'霸主沉浮','1620年，三十多个走投无路的英国清教徒（属于加尔文派）来到普利茅斯港，他们坐上一艘小型英式盖伦船，和其他一些失意者前往美洲大陆去寻找新的生活。','2952-3024',5,1723081689,1782480556);
INSERT INTO highlights VALUES('3300105051_101_2685-2721','3300105051',101,'霸主沉浮','这对国王来说确实是打破了神权的垄断，而对普通人来说，“中间商”仍然存在。','2685-2721',5,1723081665,1782480556);
INSERT INTO highlights VALUES('3300105051_101_1304-1345','3300105051',101,'霸主沉浮','我们中国有句古话：“主不可以怒而兴师，将不可以愠而攻战。合于利而动，不合于利而止。','1304-1345',5,1723081162,1782480556);
INSERT INTO highlights VALUES('3300105051_101_934-985','3300105051',101,'霸主沉浮','西班牙也和今天很多的石油大佬一样，陷入了资源的诅咒。这里通货膨胀严重，消费主义盛行，社会风气奢侈糜烂。','934-985',5,1723081117,1782480556);
INSERT INTO highlights VALUES('3300105051_10_3132-3164','3300105051',10,'孤注一掷','而受尽官僚主义折磨的里卡尔德则在回到西班牙后抑郁成疾，三天后病逝','3132-3164',5,1723081024,1782480556);
INSERT INTO highlights VALUES('3300105051_9_696-751','3300105051',9,'海峡鏖战','英国舰队虽然士兵比西班牙少，但是船比西班牙快，而且火炮威力也更大。这得益于英国在十几年前就完成的一次舰队革新。','696-751',5,1723080434,1782480556);
INSERT INTO highlights VALUES('3300105051_8_2177-2215','3300105051',8,'渺茫的希望','皇家舰队的副指挥正是当年那个完成“环球零元购”的海贼王弗朗西斯·德雷克爵士。','2177-2215',5,1723080286,1782480556);
INSERT INTO highlights VALUES('3300105051_8_2414-2477','3300105051',8,'渺茫的希望','总指挥是对海战一窍不通的贵族西多尼亚，这位大佬不仅对海战一窍不通，甚至还晕船。他走上这个工作岗位完全是被菲利普二世赶鸭子上架的','2414-2477',5,1723080261,1782480556);
INSERT INTO highlights VALUES('3300105051_8_1002-1032','3300105051',8,'渺茫的希望','实际上里面的大多数舰船并非王室所有，而是属于一个个海盗个体户','1002-1032',5,1723079245,1782480556);
INSERT INTO highlights VALUES('3300105051_7_1851-1939','3300105051',7,'伦敦爱情故事',unistr('摆在伊丽莎白面前的道理却很简单：只要我不嫁，整个英国就都是我的。\u000a婚姻只会分掉女性一半的家产，王权则让女性彻底走向独立。'),'1851-1939',5,1722919990,1782480556);
INSERT INTO highlights VALUES('3300105051_7_1712-1741','3300105051',7,'伦敦爱情故事','当时一个国王选择信奉新教，就是摆明了试图摆脱罗马教廷的控制','1712-1741',5,1722919964,1782480556);
INSERT INTO highlights VALUES('3300105051_7_801-848','3300105051',7,'伦敦爱情故事','为了复辟天主教，玛丽一世对新教势力进行血腥的镇压，她也因此获得一个响亮的称号——“血腥玛丽”。','801-848',5,1722782128,1782480556);
INSERT INTO highlights VALUES('3300105051_100_4937-5038','3300105051',100,'自作孽的岛国','德雷克的这次环球航行可不是冲着冒险和破纪录去的，他在航行过程中毫不客气地掠夺了南美洲的西班牙殖民地，还袭击了西班牙在欧洲的港口，完成了“环球零元购”的德雷克最终满载而归，给投资者带来了4700%的利润。','4937-5038',5,1722781726,1782480556);
INSERT INTO highlights VALUES('3300105051_100_4148-4193','3300105051',100,'自作孽的岛国','。视财如命的女王迅速采取措施，马上没收了当时正好停靠在英国港口的一支西班牙船队的所有财宝。','4148-4193',5,1722781175,1782480556);
INSERT INTO highlights VALUES('3300105051_100_2805-2877','3300105051',100,'自作孽的岛国','葡萄牙和西班牙开启了波澜壮阔的大航海时代，葡西两国从非洲获取奴隶，从美洲获取金银，从印度洋获取各种珍贵商品，在海洋上赚得盆满钵满，国力迅速增长。','2805-2877',5,1722781145,1782480556);
INSERT INTO highlights VALUES('3300105051_100_3939-3972','3300105051',100,'自作孽的岛国','获得王室入股的英国海盗走私生意越做越大，西班牙人则越来越忍无可忍。','3939-3972',5,1722781099,1782480556);
INSERT INTO highlights VALUES('3300105051_100_718-785','3300105051',100,'自作孽的岛国','西班牙不仅独占伊比利亚半岛，还称霸地理大发现带来的新世界，其国土从秘鲁延伸至菲律宾，是人类历史上第一个日不落帝国，无可争议的全球霸主。','718-785',5,1722765231,1782480556);
INSERT INTO highlights VALUES('3300105051_99_1643-1672','3300105051',99,'序言','可以说，从15世纪到今天，世界的秩序本质上就是海洋的秩序。','1643-1672',5,1722765086,1782480556);
INSERT INTO highlights VALUES('3300020372_35_4078-4280','3300020372',35,'睡个好觉是为了身体还是大脑','从进化的视角看，记忆的唯一好处就是帮助我们应对未来。','4078-4104',5,1709978421,1782480560);
INSERT INTO highlights VALUES('3300020372_35_3970-4018','3300020372',35,'睡个好觉是为了身体还是大脑','当清晨降临，无比神奇的是，所有信息在我的大脑中变得清清楚楚。那么，在我睡着的时候到底发生了什么？','3970-4018',5,1709978405,1782480560);
INSERT INTO highlights VALUES('3300020372_35_3803-3890','3300020372',35,'睡个好觉是为了身体还是大脑','其中一个明显的益处是认知方面的，睡眠帮助我们记住重要的事情，再帮助我们对这些事情进行梳理整合、融会贯通。这听上去很神奇，但是睡觉的时候，我们的大脑确实在对信息进行保存和分析。','3803-3890',5,1709978386,1782480560);
INSERT INTO highlights VALUES('3300020372_35_3721-3752','3300020372',35,'睡个好觉是为了身体还是大脑','其实我们不需要动太多脑筋就可以想象出来，睡眠与大脑的关系最大。','3721-3752',5,1709978369,1782480560);
INSERT INTO highlights VALUES('3300020372_35_3224-3264','3300020372',35,'睡个好觉是为了身体还是大脑','数百万年前人类尚未熟练掌控火种之时，在这些嗜血野兽的嘶吼声中努力入睡一定无比恐惧','3224-3264',5,1709978311,1782480560);
INSERT INTO highlights VALUES('3300020372_35_2972-3018','3300020372',35,'睡个好觉是为了身体还是大脑','但是，其实我们并不需要依靠睡眠来节约能量、修复组织、恢复状态，我们坐着的时候也能做这些事情。','2972-3018',5,1709978281,1782480560);
INSERT INTO highlights VALUES('3300020372_35_1874-1900','3300020372',35,'睡个好觉是为了身体还是大脑','如果一切正常的话，随着曙光来临，我们的梦会变得更密集','1874-1900',5,1709978146,1782480560);
INSERT INTO highlights VALUES('3300020372_35_1694-1773','3300020372',35,'睡个好觉是为了身体还是大脑','“快速眼动”（rapid eye movement）阶段。在快速眼动睡眠期，我们通常处于梦境之中，脑电波呈现频率升高、电压降低的状态，我们的眼球此时快速转动。','1694-1773',5,1709978092,1782480560);
INSERT INTO highlights VALUES('3300020372_35_1499-1608','3300020372',35,'睡个好觉是为了身体还是大脑','对脑电波的测量显示了睡眠的两种基本形态（见图4-1）。开始时，我们会经历几个渐进的“非快速眼动”（non-rapid eye movement）阶段。每经历一个阶段，我们都会逐渐进入无意识状态，新陈代谢变缓，体温下降。','1499-1608',5,1709978045,1782480560);
INSERT INTO highlights VALUES('3300020372_35_1608-1665','3300020372',35,'睡个好觉是为了身体还是大脑','在非快速眼动阶段，我们的脑电波信号大多数时间呈现频率降低、电压升高的状态，我们的眼球在眼皮后面保持静止或者缓慢转动','1608-1665',5,1709978039,1782480560);
INSERT INTO highlights VALUES('3300020372_35_1319-1365','3300020372',35,'睡个好觉是为了身体还是大脑','任何拥有大脑的生物都能进入某种形式的睡眠状态，这种状态无论从行为上还是从心理上都能被识别出来','1319-1365',5,1709977969,1782480560);
INSERT INTO highlights VALUES('3300020372_34_4249-4279','3300020372',34,'第4章 为什么压力会影响休息 以讹传讹的谬误4：每晚需要睡够8小时','总之，我想知道，一个“正常人”的“正常”睡眠应该是怎么样的？','4249-4279',5,1709977883,1782480560);
INSERT INTO highlights VALUES('3300020372_34_3852-3899','3300020372',34,'第4章 为什么压力会影响休息 以讹传讹的谬误4：每晚需要睡够8小时','人类的本能实际上是逃避锻炼和睡眠，我们得到的忠告与我们的本能之间存在对立，该如何解释这种对立呢','3852-3899',5,1709880805,1782480560);
INSERT INTO highlights VALUES('3300020372_34_1735-1766','3300020372',34,'第4章 为什么压力会影响休息 以讹传讹的谬误4：每晚需要睡够8小时','皮质醇，是如何在一天当中起伏变化从而对人体的警觉程度进行调节的','1735-1766',5,1709880648,1782480560);
INSERT INTO highlights VALUES('3300020372_34_1652-1709','3300020372',34,'第4章 为什么压力会影响休息 以讹传讹的谬误4：每晚需要睡够8小时','你上课的时候会睡着吗？会。你在图书馆学习的时候会睡着吗？会。学校放假的时候你在家的睡眠状况会比在校时好一些吗？会。','1652-1709',5,1709880628,1782480560);
INSERT INTO highlights VALUES('3300020372_33_11728-11775','3300020372',33,'我该如何坐，我该坐多久','我需要再次重复以下观点，我们读到的关于坐姿的那些可怕数据，主要是从非工作时间坐着的时长得出的。','11728-11775',5,1709725958,1782480560);
INSERT INTO highlights VALUES('3300020372_33_10011-11430','3300020372',33,'我该如何坐，我该坐多久','据我所知，对于避免背部疼痛最好的建议是增强腰部肌肉，因为肌肉可以抵抗疲劳；反过来，有着强壮的腰部肌肉、可以抵抗疲劳的人，就更有可能拥有更好的姿态。￼换句话说，人们一直把因果关系弄反了。','10011-11430',5,1709725916,1782480560);
INSERT INTO highlights VALUES('3300020372_33_3152-3186','3300020372',33,'我该如何坐，我该坐多久','你先回忆一下，大约每隔多久就会有人提醒你要坐直了，不要驼背也不要瘫着','3152-3186',5,1709724942,1782480560);
INSERT INTO highlights VALUES('3300020372_33_2095-2133','3300020372',33,'我该如何坐，我该坐多久','这些略带欺骗性的市场策略让人们错误地认为，只要不是坐着，身体就处于活动状态。','2095-2133',5,1709723839,1782480560);
INSERT INTO highlights VALUES('3300020372_33_1900-1960','3300020372',33,'我该如何坐，我该坐多久','而且，我们的祖先与今天的狩猎采集者和农耕者一样，即使坐着也不会闲着，他们会同时做一些杂务、照看孩子，还会时不时地站起来。','1900-1960',5,1709723718,1782480560);
INSERT INTO highlights VALUES('3300020372_33_538-574','3300020372',33,'我该如何坐，我该坐多久','问题并不是出在坐姿本身，而是出在长时间不动的坐姿外加几乎没有任何锻炼上。','538-574',5,1709723604,1782480560);
INSERT INTO highlights VALUES('3300020372_33_463-503','3300020372',33,'我该如何坐，我该坐多久','香烟是一种易成瘾、昂贵、有特殊气味、有毒的健康头号杀手，但也只是新近才出现的事物','463-503',5,1709723557,1782480560);
INSERT INTO highlights VALUES('3300020372_32_7823-7842','3300020372',32,'有活力地坐着','坐不住的习惯能够将全因死亡率降低30%','7823-7842',5,1709723517,1782480560);
INSERT INTO highlights VALUES('3300020372_32_7046-7320','3300020372',32,'有活力地坐着','“坐不住”的被试比那些安静坐着的被试每天多消耗100～800大卡能量。','7046-7081',5,1709723501,1782480560);
INSERT INTO highlights VALUES('3300020372_32_6808-6868','3300020372',32,'有活力地坐着','“有活力的坐”还有一种形式，那就是“动来动去”（fidget），用研究人员使用的专业术语来说，就是“无意识的身体活动”。','6808-6868',5,1709723469,1782480560);
INSERT INTO highlights VALUES('3300020372_32_5264-6132','3300020372',32,'有活力地坐着','这些活动算不上真正的锻炼，但实验表明，当被试被要求打破久坐状态，哪怕只是很短的时间，比如每半小时起身100秒，他们血液中的血糖、血脂和所谓的坏胆固醇的浓度也会降低。','5264-5346',5,1709660727,1782480560);
INSERT INTO highlights VALUES('3300020372_32_2962-3017','3300020372',32,'有活力地坐着','“有活力地坐着”，即起起坐坐，比连续的久坐对人的损害要稍微小一些。那么我是否需要每10分钟站起来做几个开合跳？','2962-3017',5,1709660667,1782480560);
INSERT INTO highlights VALUES('3300020372_32_1996-2048','3300020372',32,'有活力地坐着','投入时间进行中等强度运动和剧烈运动的锻炼者，虽然可以降低与久坐相关的死亡风险，但是并不能完全消除这种风险','1996-2048',5,1709660666,1782480560);
INSERT INTO highlights VALUES('3300020372_32_1494-1533','3300020372',32,'有活力地坐着','如果你认为在健身房锻炼一小时可以抵消一天陷在椅子中的久坐风险，那么你要失望了。','1494-1533',5,1709660666,1782480560);
INSERT INTO highlights VALUES('3300020372_32_1177-1249','3300020372',32,'有活力地坐着','你我也许坐的时间一样长，但是坐的方式不一样，久坐前后做的事情也不同，所以我们需要考虑不同类型的坐——持续坐着与间断坐着，对慢性轻度炎症的潜在影响','1177-1249',5,1709660666,1782480560);
INSERT INTO highlights VALUES('3300020372_32_2376-2859','3300020372',32,'有活力地坐着','即使我们有运动习惯且健康状况良好，坐着的时间越久，你患与炎症相关的慢性病的风险越高，包括一些癌症。','2376-2425',5,1709660666,1782480560);
INSERT INTO highlights VALUES('3300020372_31_5480-5576','3300020372',31,'久坐如何引发慢性轻度炎症','久坐引发慢性轻度炎症的第三种方式令人担忧，那就是心理压力。我希望你在读到现在这段文字的时候正愉悦地待在沙滩上或者其他让你心旷神怡的地方，而不是正在为膨胀的脂肪细胞和炎症等乱七八糟的事情而焦虑。','5480-5576',5,1709398796,1782480560);
INSERT INTO highlights VALUES('3300020372_31_5655-5703','3300020372',31,'久坐如何引发慢性轻度炎症','皮质醇的水平。这个经常被误解的激素实际上并不会对人造成压力，它是在人处于压力状态下被激发出来的。','5655-5703',5,1709398732,1782480560);
INSERT INTO highlights VALUES('3300020372_31_4186-4227','3300020372',31,'久坐如何引发慢性轻度炎症','久坐会降低身体从血液中吸收脂肪和糖的能力，这是它引发全身慢性轻度炎症的第二种方式。','4186-4227',5,1709358594,1782480560);
INSERT INTO highlights VALUES('3300020372_31_3407-3457','3300020372',31,'久坐如何引发慢性轻度炎症','身体长时间不活动外加热量摄入过多，共同造成了过多内脏脂肪的堆积，继而点燃了慢性轻度炎症的“星星之火”','3407-3457',5,1709358471,1782480560);
INSERT INTO highlights VALUES('3300020372_31_2399-2490','3300020372',31,'久坐如何引发慢性轻度炎症','过多的脂肪，尤其是内脏内部和周围的脂肪会引发慢性轻度炎症。这是久坐引发慢性轻度炎症的第一种方式，这一过程的机理提醒我们，久坐会带来危险，而原因很可能仅仅就是这一行为造成了体重的增加。','2399-2490',5,1709358383,1782480560);
INSERT INTO highlights VALUES('3300020372_31_2241-2280','3300020372',31,'久坐如何引发慢性轻度炎症','当内脏脂肪细胞膨胀时，它们会向血液里释放大量可以造成炎症的蛋白质。即细胞因子。','2241-2280',5,1709358129,1782480560);
INSERT INTO highlights VALUES('3300020372_31_1883-1921','3300020372',31,'久坐如何引发慢性轻度炎症','如果脂肪细胞过大，它们就会膨胀、功能失调，从而招致白细胞前来，并最终引发炎症','1883-1921',5,1709295023,1782480560);
INSERT INTO highlights VALUES('3300020372_31_1573-1613','3300020372',31,'久坐如何引发慢性轻度炎症','内脏脂肪细胞是新陈代谢过程积极的参与者，它们一旦被激发，便会迅速向血液中释放脂肪','1573-1613',5,1709294932,1782480560);
INSERT INTO highlights VALUES('3300020372_31_1531-1535','3300020372',31,'久坐如何引发慢性轻度炎症','内脏脂肪','1531-1535',5,1709294922,1782480560);
INSERT INTO highlights VALUES('3300020372_31_882-915','3300020372',31,'久坐如何引发慢性轻度炎症','这些脂肪绝大部分（90%～95%）位于皮下，因此也被称作皮下脂肪。','882-915',5,1709294905,1782480560);
INSERT INTO highlights VALUES('3300020372_31_1432-1477','3300020372',31,'久坐如何引发慢性轻度炎症','皮下脂肪细胞还有其他功能，尤其重要的是，它们所构成的腺体可以产生调节食欲和生殖功能的激素。','1432-1477',5,1709294836,1782480560);
INSERT INTO highlights VALUES('3300020372_31_804-821','3300020372',31,'久坐如何引发慢性轻度炎症','大多数脂肪不仅无害，而且有益健康。','804-821',5,1709256586,1782480560);
INSERT INTO highlights VALUES('3300020372_30_3504-3598','3300020372',30,'当我坐着的时候，身体正在着火','慢性轻度炎症的一大诱因在很大程度上是可以避免、可以预防、可以解决的，这些诱因是吸烟、肥胖、某些促炎症食物的过度摄入，其中最主要的一种食物是红肉；另一大诱因你可能万万没想到，那就是缺乏活动。','3504-3598',5,1709256550,1782480560);
INSERT INTO highlights VALUES('3300020372_30_1654-1919','3300020372',30,'当我坐着的时候，身体正在着火','慢性轻度炎症在更多疾病中留下的痕迹，包括结肠癌、红斑狼疮、多发性硬化症，以及各种以“炎”命名的疾病，比如关节炎。','1654-1710',5,1709256506,1782480560);
INSERT INTO highlights VALUES('3300020372_30_1371-1417','3300020372',30,'当我坐着的时候，身体正在着火','慢性轻度炎症就像是得了一场永远无法痊愈的感冒，但它们又极为轻微，你甚至根本感觉不到它们的存在','1371-1417',5,1709256477,1782480560);
INSERT INTO highlights VALUES('3300020372_30_1271-1295','3300020372',30,'当我坐着的时候，身体正在着火','在全身范围内激发出持久、不易被感知的慢性轻度炎症','1271-1295',5,1709256438,1782480560);
INSERT INTO highlights VALUES('3300020372_30_647-817','3300020372',30,'当我坐着的时候，身体正在着火','无论破坏者是病毒、细菌还是过度日晒，免疫系统都会迅速调集大批细胞投入战斗。这些细胞会密集地释放大量化合物，造成血管扩张、渗透性提高，从而让白细胞顺利穿过血管进入受损组织，消灭入侵者。额外增加的血流量为身体提供了重要的免疫细胞和免疫液体，但是血管的膨胀会挤压神经并引发4种基本的发炎症状：皮肤发红、发热、肿胀和疼痛，从字面上看就是“着火”了。','647-817',5,1709256253,1782480560);
INSERT INTO highlights VALUES('3300020372_30_585-628','3300020372',30,'当我坐着的时候，身体正在着火','从机理上说，发炎是指免疫系统在发现有害病原体、有毒物质和受损组织之后第一时间做出的反应','585-628',5,1709255982,1782480560);
INSERT INTO highlights VALUES('3300020372_29_8925-8962','3300020372',29,'我们每天要坐多久？','即使是那些久坐不动的美国“沙发土豆”，他们的活动量也远远超过了野生黑猩猩。','8925-8962',5,1709255912,1782480560);
INSERT INTO highlights VALUES('3300020372_29_8046-8274','3300020372',29,'我们每天要坐多久？','而一个普通哈扎成年人每天花在轻量活动上的时间接近4小时，中等强度活动2小时，剧烈活动20分钟。','8046-8093',5,1709255802,1782480560);
INSERT INTO highlights VALUES('3300020372_29_7677-7724','3300020372',29,'我们每天要坐多久？','普通成年人每天的轻量活动时间大约为5.5小时，中等强度活动只有20分钟，剧烈活动时间不足1分钟','7677-7724',5,1709255790,1782480560);
INSERT INTO highlights VALUES('3300020372_29_5899-5936','3300020372',29,'我们每天要坐多久？','按照一般规律，采用坐姿进行活动时的心率，介于静息心率和最高心率的40%之间','5899-5936',5,1709255744,1782480560);
INSERT INTO highlights VALUES('3300020372_29_2030-2045','3300020372',29,'我们每天要坐多久？','我坐着的时间比自己想象中少很多','2030-2045',5,1709208129,1782480560);
INSERT INTO highlights VALUES('3300020372_28_9368-9604','3300020372',28,'我们是怎么坐的以及为什么要坐','一位医生在1879年发出了这样的警告：“在文明所催生的所有折磨人类的机器中……没有几样在执行这项刑罚时比椅子更坚决、更广泛、更残暴。”','9368-9435',5,1709207536,1782480560);
INSERT INTO highlights VALUES('3300020372_28_8179-8455','3300020372',28,'我们是怎么坐的以及为什么要坐','比于经常使用那种最常见的靠背椅的城市青少年，极少使用靠背椅的肯尼亚农村孩子的背部力量要强壮21%～41%。','8179-8232',5,1709207460,1782480560);
INSERT INTO highlights VALUES('3300020372_28_4221-4267','3300020372',28,'我们是怎么坐的以及为什么要坐','采用坐姿每小时节省的那一点点能量历经漫长的时间所累积起来的优势效应，还是使坐着变成了一种本能','4221-4267',5,1709173166,1782480560);
INSERT INTO highlights VALUES('3300020372_28_2953-3000','3300020372',28,'我们是怎么坐的以及为什么要坐','人类的站立效率也比类人猿高，因为我们可以挺直自己的臀部和膝盖，而且我们的脊下部有一个向后的曲度','2953-3000',5,1709173058,1782480560);
INSERT INTO highlights VALUES('3300020372_28_2071-2207','3300020372',28,'我们是怎么坐的以及为什么要坐','双足人类的站立效率￼显然比双足鸟类和牛、麋鹿等四足动物要高。没错，确实有人测量过麋鹿站立时的能量消耗','2071-2207',5,1709173041,1782480560);
INSERT INTO highlights VALUES('3300020372_28_764-1739','3300020372',28,'我们是怎么坐的以及为什么要坐','站立比安静地坐在普通的椅子上要多消耗8%～10%的能量。','764-792',5,1709173008,1782480560);
INSERT INTO highlights VALUES('3300020372_28_715-745','3300020372',28,'我们是怎么坐的以及为什么要坐','从好的方面说，坐着不像站着那么累，而且更容易使身体保持稳定。','715-745',5,1709173003,1782480560);
INSERT INTO highlights VALUES('3300020372_27_5126-5150','3300020372',27,'第3章 坐着等同于吸烟吗 以讹传讹的谬误3：从本质上讲，久坐是不健康的','我们使用进化和人类学这两个“镜头”去获取一些视角','5126-5150',5,1709172966,1782480560);
INSERT INTO highlights VALUES('3300020372_26_2331-2387','3300020372',26,'避免非必要的身体活动是人类的正常选择','时至今日，人类的生存条件发生了奇怪的反转，出于健康目的而自愿进行的身体活动，也就是锻炼，已经变成了特权阶级的特权','2331-2387',5,1709054983,1782480560);
INSERT INTO highlights VALUES('3300020372_26_1475-1567','3300020372',26,'避免非必要的身体活动是人类的正常选择','今天很多人的工作只涉及一点点体力劳动，甚至完全不涉及，这就需要我们通过锻炼增加一些身体活动。无论是走楼梯、慢跑还是去健身房，我们都需要战胜“避免不必要的身体活动”这一古老而强大的本能。','1475-1567',5,1709054902,1782480560);
INSERT INTO highlights VALUES('3300020372_25_6371-6416','3300020372',25,'生而懒惰','人类之所以能够实施这种能量策略，关键在于通过进化我们获得的能量和消耗的能量都远远多于黑猩猩','6371-6416',5,1709008681,1782480560);
INSERT INTO highlights VALUES('3300020372_25_5181-5198','3300020372',25,'生而懒惰','到底发生了什么使得人类变得更加好动','5181-5198',5,1708997837,1782480560);
INSERT INTO highlights VALUES('3300020372_25_3510-3533','3300020372',25,'生而懒惰','大多数野生哺乳动物的PAL值为2.0～4.0，','3510-3533',5,1708912948,1782480560);
INSERT INTO highlights VALUES('3300020372_25_6817-6867','3300020372',25,'生而懒惰','我们是从一个格外低能耗的节约型祖先进化而来的，而我们又进化成为以格外高能耗的方式提高繁衍成功率的物种','6817-6867',5,1708912846,1782480560);
INSERT INTO highlights VALUES('3300020372_25_6023-6200','3300020372',25,'生而懒惰','而且，将食物制熟后，她可以获取比生吃更多的能量。','6023-6047',5,1708912745,1782480560);
INSERT INTO highlights VALUES('3300020372_25_5251-5309','3300020372',25,'生而懒惰','是气候的变化促使我们的祖先进化出一种非同寻常却极度成功的生活方式——狩猎和采集，当然，这种生活方式需要投入更多的劳动','5251-5309',5,1708912257,1782480560);
INSERT INTO highlights VALUES('3300020372_25_4283-4335','3300020372',25,'生而懒惰','类人猿和工业化国家中习惯久坐群体的运动量，比大多数哺乳动物要低很多，而狩猎采集者的运动量仅比哺乳动物低。','4283-4335',5,1708909191,1782480560);
INSERT INTO highlights VALUES('3300020372_25_1208-1258','3300020372',25,'生而懒惰','由于人类权衡能量的方式与动物不同，所以人类似乎比绝大多数动物更抵触锻炼，至于具体原因，非常值得推敲。','1208-1258',5,1708872535,1782480560);
INSERT INTO highlights VALUES('3300020372_24_3095-3173','3300020372',24,'尽可能保持静态，是人类进化的结果','简而言之，尽可能地保持静态，是人类进化的结果。或者说得更准确一点，在自然选择的作用下，我们的身体会在包括身体活动在内的非繁衍活动中投入适当而不是过量的能量。','3095-3173',5,1708872234,1782480560);
INSERT INTO highlights VALUES('3300020372_24_2990-3065','3300020372',24,'尽可能保持静态，是人类进化的结果','当能量有限时，以下行为会变得更有意义，即减少不必要的身体活动，将这些能量分配到繁衍或者可以将繁衍率最大化的功能上，即使这种权衡会损害健康，甚至缩短寿命','2990-3065',5,1708872224,1782480560);
INSERT INTO highlights VALUES('3300020372_24_2602-2661','3300020372',24,'尽可能保持静态，是人类进化的结果','自然选择根本就不会在乎我们是否快乐、善良或者富有，它只偏爱那些有利于繁衍后代的可遗传性状，而权衡也是一种可遗传的性状。','2602-2661',5,1708872186,1782480560);
INSERT INTO highlights VALUES('3300020372_24_2314-2380','3300020372',24,'尽可能保持静态，是人类进化的结果','你只能将一份特定的能量用于这5个方面：身体生长、生命维持（静息代谢）、能量存储（例如，以脂肪形式存储）、身体活动、繁衍（见图2-1）','2314-2380',5,1708866860,1782480560);
INSERT INTO highlights VALUES('3300020372_24_2188-2232','3300020372',24,'尽可能保持静态，是人类进化的结果','在这些权衡中，最为重要的一项是，将宝贵的能量分配给静态时的身体，还是分配给动态时的身体。','2188-2232',5,1708866842,1782480560);
INSERT INTO highlights VALUES('3300020372_24_1470-1512','3300020372',24,'尽可能保持静态，是人类进化的结果','因为通常情况下，变异只有为数不多的选项，所有自然选择只能通过权衡成本与收益进行抉择。','1470-1512',5,1708866604,1782480560);
INSERT INTO highlights VALUES('3300020372_23_4984-5054','3300020372',23,'休息并不等于身体的静态','休息并不是一种身体静态。虽然我们看上去什么都没有做，但实际上很多维持生命活力和高能耗的生理活动一直都在进行中，我们的身体时刻为此消耗着能量。','4984-5054',5,1708865309,1782480560);
INSERT INTO highlights VALUES('3300020372_23_3660-3674','3300020372',23,'休息并不等于身体的静态','把那些耗能器官的尺寸都缩小了','3660-3674',5,1708865221,1782480560);
INSERT INTO highlights VALUES('3300020372_23_3273-3362','3300020372',23,'休息并不等于身体的静态','饥饿状态下被试的静息代谢率会大幅下降，我们从这一事实中得到了一条关键信息——人的静息代谢是可变的。更重要的是，静息代谢是身体为维持生命所“愿意”提供的能量，而不是必须提供的能量。','3273-3362',5,1708865178,1782480560);
INSERT INTO highlights VALUES('3300020372_23_3080-3176','3300020372',23,'休息并不等于身体的静态','他们的身体生成了一套不易察觉却非常重要的适应——他们的身体即使在休息的时候也会节约能量。在24周的饥饿实验之后，志愿者们的静息代谢率和基础代谢率骤降40%，大大超出体重的下降，这非常出乎预料。','3080-3176',5,1708865135,1782480560);
INSERT INTO highlights VALUES('3300020372_23_2574-2602','3300020372',23,'休息并不等于身体的静态','脂肪是巨大的能量存储器，当身体需要能量时，就会燃烧脂肪。','2574-2602',5,1708857457,1782480560);
INSERT INTO highlights VALUES('3300020372_23_2516-2554','3300020372',23,'休息并不等于身体的静态','即使是瘦型男性，他的平均体脂率也约为15%（瘦型女性的平均体脂率为25%）。','2516-2554',5,1708826549,1782480560);
INSERT INTO highlights VALUES('3300020372_23_855-951','3300020372',23,'休息并不等于身体的静态','战争结束之后，数百万处于饥饿中的人们会更容易被法西斯主义所操控。正是出于人道主义和地缘政治战略双重考虑，美国政府决定资助基斯成立一个科学家小组，招募志愿者，对饥饿和身体康复的效应进行充分研究。','855-951',5,1708826292,1782480560);
INSERT INTO highlights VALUES('3300020372_22_6188-6236','3300020372',22,'“无所事事”的代价','总而言之，即使你是一个超级好动之人，你消耗在其他事情上的能量可能也没有消耗在维持生命上的能量多。','6188-6236',5,1708826163,1782480560);
INSERT INTO highlights VALUES('3300020372_22_6108-6159','3300020372',22,'“无所事事”的代价','地球上的人类每天要消耗超过20万亿大卡的能量，这些能量中的绝大部分消耗在了休息状态下的身体基本需求上。','6108-6159',5,1708826122,1782480560);
INSERT INTO highlights VALUES('3300020372_22_6010-6057','3300020372',22,'“无所事事”的代价','我们得到了一个明确的数据，为了保持身体功能正常，成年人每千克非脂肪体重每天消耗的能量为30大卡','6010-6057',5,1708826100,1782480560);
INSERT INTO highlights VALUES('3300020372_22_4974-5006','3300020372',22,'“无所事事”的代价','如果你的体重是82千克，那么你的每日能量消耗大约是2 700大卡','4977-5009',5,1708826009,1782480560);
INSERT INTO highlights VALUES('3300020372_22_3529-3542','3300020372',22,'“无所事事”的代价','我们的做法是测量你的尿液。','3529-3542',5,1708825873,1782480560);
INSERT INTO highlights VALUES('3300020372_22_2542-2616','3300020372',22,'“无所事事”的代价','每日能量消耗（daily energy expenditure），也就是在24小时内你消耗在身体活动、阅读、打喷嚏、谈话和消化等一切行为上的总能量。','2542-2616',5,1708825829,1782480560);
INSERT INTO highlights VALUES('3300020372_22_2346-2390','3300020372',22,'“无所事事”的代价','基础代谢率（basal metabolic rate），应该比你的静息代谢率低大约10%','2346-2390',5,1708825789,1782480560);
INSERT INTO highlights VALUES('3300020372_22_1964-2139','3300020372',22,'“无所事事”的代价','如果你是一个体重处于均值的美国成年男性，也就是82千克，那么你安安静静地坐在椅子上时的能量消耗为每小时70大卡。这就是你的静息代谢率（resting metabolic rate），当你处于完全静止的状态时，静息代谢包含了你体内发生的所有化学反应。以静息代谢率为基础，可以计算出如果你24小时都保持不活动的静止状态，你的身体将消耗大约1 700大卡。','1964-2139',5,1708825709,1782480560);
INSERT INTO highlights VALUES('3300020372_21_2628-2650','3300020372',21,'第2章 静态的意义，懒惰也很重要 以讹传讹的谬误2：懒惰是不正常的行为','绝大多数情况下成年大猩猩比较温和，不大愿意动','2628-2650',5,1708825395,1782480560);
INSERT INTO highlights VALUES('3300020372_19_5541-5844','3300020372',19,'“古怪”的锻炼行为','美国政府推荐我每周最少进行150分钟中等强度或者75分钟高强度的锻炼，外加最少两次力量练习。￼','5541-5587',5,1708824863,1782480560);
INSERT INTO highlights VALUES('3300020372_19_5097-5171','3300020372',19,'“古怪”的锻炼行为','过去100年，为了满足人们的健康和健身需求，人类发明了数量惊人的运动方法和运动设备。锻炼顺理成章地被强力包装成为一种美德，被商品化、商业化、工业化。','5097-5171',5,1708824779,1782480560);
INSERT INTO highlights VALUES('3300020372_19_2936-2988','3300020372',19,'“古怪”的锻炼行为','身体文化在19世纪迅速传遍欧洲、美国和世界的各个角落，尤其是在中学和大学。锻炼和教育被紧密地联系在一起。','2936-2988',5,1708824665,1782480560);
INSERT INTO highlights VALUES('3300020372_19_2260-2291','3300020372',19,'“古怪”的锻炼行为','在印度，瑜伽几千年前就得以发明和普及，用于训练人们的身体和头脑','2260-2291',5,1708824278,1782480560);
INSERT INTO highlights VALUES('3300020372_19_2041-2091','3300020372',19,'“古怪”的锻炼行为','柏拉图、苏格拉底和芝诺等哲学家会像布道一样告诉你，若想实现完美人生，你不仅要锻炼头脑，还需锻炼体魄。','2041-2091',5,1708824262,1782480560);
INSERT INTO highlights VALUES('3300020372_19_1622-1752','3300020372',19,'“古怪”的锻炼行为','我认为用以下两点来概括人类的锻炼行为也许更合情理：第一，玩耍是青少年的本能，体育是人类的普遍行为，而缺乏游戏元素的锻炼行为则极为罕见，是最近几千年才出现的行为；第二，随着技术进步和社会发展，工业化时代，人类的身体活动大幅减少，专家不断发出警告：现代人缺乏锻炼。','1622-1752',5,1708824168,1782480560);
INSERT INTO highlights VALUES('3300020372_19_1423-1485','3300020372',19,'“古怪”的锻炼行为','人类是为数不多的成年之后仍会玩耍的物种，而且是唯一一个会以体育的形式玩耍的物种，并且人类这种独特的行为在每一种文化中都有体现','1423-1485',5,1708823481,1782480560);
INSERT INTO highlights VALUES('3300020372_19_1382-1423','3300020372',19,'“古怪”的锻炼行为','据我们所知，所有哺乳动物在小时候都会玩耍，这样可以帮助它们习得社会经验和身体技能。','1382-1423',5,1708823471,1782480560);
INSERT INTO highlights VALUES('3300020372_17_5793-5857','3300020372',17,'“正常人”都是沙发土豆吗','虽然整日忙忙碌碌已经使他们的活动时间达到了美国人和欧洲人平均值的12倍，但无论如何，也没人会认为哈扎人的工作强度达到了繁重的地步','5793-5857',5,1708785857,1782480560);
INSERT INTO highlights VALUES('3300020372_17_4172-4210','3300020372',17,'“正常人”都是沙发土豆吗','在大约1 200名哈扎人中，只有约400人仍然将狩猎和采集作为主要生活方式。','4172-4210',5,1708785857,1782480560);
INSERT INTO highlights VALUES('3300020372_18_719-1017','3300020372',18,'不同年代的身体活动','“身体活动水平”（Physical Activity Level，PAL）。￼PAL的计算方法是：用一个人正常工作和生活24小时消耗的能量除以完全不离开床的情况下所消耗的能量','719-1017',5,1708785857,1782480560);
INSERT INTO highlights VALUES('3300020372_17_7364-7425','3300020372',17,'“正常人”都是沙发土豆吗','结果表明，具有代表性的人类工作时间为每天7小时，其中绝大部分时间用于完成轻体力劳动，而用于完成重体力劳动的时间最多为1小时','7364-7425',5,1708785857,1782480560);
INSERT INTO highlights VALUES('3300020372_17_2130-2187','3300020372',17,'“正常人”都是沙发土豆吗','这些部落的生活方式终将不可避免地消失，因此，在那一天到来之前，人类学家和其他领域的科学家正全力以赴对他们进行研究。','2130-2187',5,1708785857,1782480560);
INSERT INTO highlights VALUES('3300020372_17_4552-4628','3300020372',17,'“正常人”都是沙发土豆吗','我再强调一下我所见到的情景：哈扎人没有蜷在沙发上，没有看电视，没有吃大量的薯片，没有喝苏打水，但是他们正在做一件健康专家提醒我们绝对要避免的事情：坐着。','4552-4628',5,1708785857,1782480560);
INSERT INTO highlights VALUES('3300020372_16_4922-4973','3300020372',16,'并不成立的“运动原始人”假说','推翻这种假说并没有回答最基本的问题：对于一个“正常人”来说，以何种强度进行哪项身体活动，才是最正常的？','4922-4973',5,1708782029,1782480560);
INSERT INTO highlights VALUES('3300020372_16_3937-4087','3300020372',16,'并不成立的“运动原始人”假说','换句话说，他们日常劳作对应的运动量，已经超过了那些为备战背靠背马拉松￼而进行训练的选手的运动量','3937-4087',5,1708781955,1782480560);
INSERT INTO highlights VALUES('3300020372_15_2232-2344','3300020372',15,'两个不同却又相似的赛事','子夜时，阿努弗队套了希尔维诺队一圈，在参赛者最终跑了大约112千米后比赛终于结束了。与在科纳举行的比赛不同，此时没有掌声、没有主持人、没有音乐来庆祝比赛结束。人们只是围坐在一堆巨大的篝火旁，开始享用装在葫芦里的自酿玉米啤酒。','2232-2344',5,1708781191,1782480560);
INSERT INTO highlights VALUES('3300020372_14_3318-3379','3300020372',14,'为什么有人在不需要跑步的时候跑步','然后他非常明确地表达了他的想法——在没必要跑步的时候跑步是荒谬的。他满脸疑惑地问我：“为什么有人在不需要跑步的时候跑步？”','3318-3379',5,1708780555,1782480560);
INSERT INTO highlights VALUES('3300020372_12_2104-2481','3300020372',12,'为什么我们进行的是博物学研究','唯有在进化知识之光的照耀下，锻炼的生物学研究才有意义；唯有在人类学知识之光的照耀下，锻炼的行为学研究才有意义。','2104-2159',5,1708762860,1782480560);
INSERT INTO highlights VALUES('3300020372_11_1430-1642','3300020372',11,'与锻炼有关的悖论','依据个人经历和学术研究，我逐渐得出了一些结论，比如锻炼，这个现代且健康的行为包含着一些自相矛盾的内容，但是像美国这样的工业化社会并没有认识到锻炼的复杂程度，从而导致了人们对于锻炼的理解和态度充满了以讹传讹的谬误（myth）￼。','1430-1642',5,1708762359,1782480560);
INSERT INTO highlights VALUES('3300020372_11_1079-1097','3300020372',11,'与锻炼有关的悖论','我开始对人类奔跑的进化过程产生了兴趣','1079-1097',5,1708762305,1782480560);
INSERT INTO highlights VALUES('3300020372_10_1522-1575','3300020372',10,'序言 我们从未进化出锻炼的本能','这台跑步机正好概括了我想写的这本书的主题：我们从未进化出锻炼的本能。','1522-1575',5,1708761967,1782480560);
INSERT INTO highlights VALUES('3300020372_10_868-905','3300020372',10,'序言 我们从未进化出锻炼的本能','，目的是研究当世界处于高速现代化的进程中，彭雅当地人的身体发生了怎样的变化','868-905',5,1708761867,1782480560);
INSERT INTO highlights VALUES('3300020372_7_1613-1670','3300020372',7,'为什么要区分体育与锻炼','奥林匹克主义所要开创的人生道路，是以奋斗中所体验到的乐趣、优秀榜样的教育价值和对一般伦理的基本原则的尊敬为基础的。','1613-1670',5,1708761276,1782480560);
INSERT INTO highlights VALUES('3300020372_7_1287-1367','3300020372',7,'为什么要区分体育与锻炼','承认锻炼的反进化反本能的本质，承认锻炼之艰难，但也承认其健康的功用，把锻炼当作一种承诺，愿意以科学的锻炼方法来“惩罚”自己、塑造自己，才更像是一个理性的现代人。','1287-1367',5,1708761175,1782480560);
INSERT INTO highlights VALUES('3300020372_7_1052-1073','3300020372',7,'为什么要区分体育与锻炼','而体育是人类的伟大发明，是一种高级的游戏。','1052-1073',5,1708761146,1782480560);
INSERT INTO highlights VALUES('3300020372_7_979-1052','3300020372',7,'为什么要区分体育与锻炼','锻炼是人类最近几千年来，尤其是越来越多的工具出现之后，由于体力劳动的减少，而不得不进行的额外的身体活动，其唯一目的是保持身体的健康状态和正常机能。','979-1052',5,1708761142,1782480560);
INSERT INTO highlights VALUES('3300020372_6_624-671','3300020372',6,'这本书为什么叫《锻炼》','sports　体育：在对手之间进行的、以获胜为目的、按照完善的规则和标准进行的对抗性身体活动。','624-671',5,1708760900,1782480560);
INSERT INTO highlights VALUES('3300020372_5_701-759','3300020372',5,'译者序 我可以热爱体育但是讨厌锻炼吗','至于“热爱体育”，你应该完全义无反顾地热爱体育，因为体育最终给予你的，远比健康的身体和强健的体魄更为美好、更为宝贵。','701-759',5,1708760827,1782480560);
INSERT INTO highlights VALUES('3300020372_5_597-672','3300020372',5,'译者序 我可以热爱体育但是讨厌锻炼吗','人类从未进化出锻炼的本能。他还认为，休息、犯懒、节约能量、储存脂肪在人类数百万年的进化史中是常态。而锻炼，是最近几千年才出现的“不可理喻的古怪行为”。','597-672',5,1708749792,1782480560);
INSERT INTO highlights VALUES('3300020372_5_525-537','3300020372',5,'译者序 我可以热爱体育但是讨厌锻炼吗','当然应该本能地讨厌锻炼。','525-537',5,1708749780,1782480560);
INSERT INTO highlights VALUES('3300020372_4_1621-1655','3300020372',4,'测一测 你真的锻炼对了吗？','【exercised】烦恼、焦虑、担心、厌烦（形容词）','1621-1655',5,1706340606,1782480560);
INSERT INTO highlights VALUES('3300020372_4_623-625','3300020372',4,'测一测 你真的锻炼对了吗？','繁衍','623-625',5,1706340523,1782480560);
INSERT INTO highlights VALUES('3300020372_4_518-519','3300020372',4,'测一测 你真的锻炼对了吗？','否','518-519',5,1706340507,1782480560);
INSERT INTO highlights VALUES('3300020372_3_1447-1510','3300020372',3,'作者简介','最为突出的就是所谓的“失配性疾病”，即人类现有的旧石器时代的身体尚且不能适应或不能充分适应某些现代行为和环境条件所导致的疾病。','1447-1510',5,1706340362,1782480560);
INSERT INTO highlights VALUES('921791_23_3658-3678','921791',46,'第十四章 掌控随机现象','命运女神唯一不能控制的东西，是你的行为。','3650-3670',NULL,1664254297,1782480565);
INSERT INTO highlights VALUES('921791_23_3514-3542','921791',46,'第十四章 掌控随机现象','不要将你的命运怪罪于任何人，即使他们确实是祸首也是一样。','3506-3534',NULL,1664254276,1782480565);
INSERT INTO highlights VALUES('921791_23_3224-3271','921791',46,'第十四章 掌控随机现象','下次碰到厄运时，不妨开始强调个人举止的优雅。你应该表现出不管在什么状况下，都“知道如何生存”。','3216-3263',NULL,1664254256,1782480565);
INSERT INTO highlights VALUES('921791_23_1206-1248','921791',46,'第十四章 掌控随机现象','不管我们的选择有多复杂、我们多擅长支配运气，随机性总是最后的裁判，我们仅剩的只有尊严','1199-1241',NULL,1664254043,1782480565);
INSERT INTO highlights VALUES('921791_22_3998-4057','921791',45,'第十三章 概率与怀疑论','索罗斯这类真正的投机者和别人不一样的地方，在于他们的行为缺乏路径依赖。他们完全不受过去的行为束缚，每一天都是一张白纸。','3985-4044',NULL,1664253618,1782480565);
INSERT INTO highlights VALUES('921791_22_3319-3445','921791',45,'第十三章 概率与怀疑论','是我见过最优秀的交易员之一，他有一种优异的特质：他的信念完全不受路径依赖（path dependence）的观念束缚。他可能一时冲动买进几个小时前才强烈断定会下跌的某种货币，但他一点也不觉得不好意思。什么事情改变了他的心意？他认为没有必要回答这个问题。','3306-3432',NULL,1664253572,1782480565);
INSERT INTO highlights VALUES('921791_22_664-680','921791',45,'第十三章 概率与怀疑论','数学是用以思考而不是计算的工具。','657-673',NULL,1664253256,1782480565);
INSERT INTO highlights VALUES('921791_21_4543-4654','921791',44,'第十二章 赌徒的迷信和笼中的鸽子','由于我感性的一面似乎不能认同理性，所以我必须郑重其事，避免做出不合理性的操作决策。也就是说，不让自己去接触绩效报告，除非绩效到达预定的门槛。这就像想吃巧克力时，把脑子和口腹之欲分离开来。我的做法是绝不在交易台底下摆巧克力。','4531-4642',NULL,1664253150,1782480565);
INSERT INTO highlights VALUES('921791_21_3301-3407','921791',44,'第十二章 赌徒的迷信和笼中的鸽子','它们根据内在根深蒂固的统计机制，发展出极其复杂、有如祈雨舞般的行为。有只鸽子会对着笼中特定的一角有规律地摇头，另一只鸽子会以逆时钟方向转头。几乎每一只鸽子都发展出一种与喂食联结起来的特别仪式，慢慢固定到它们心里。','3290-3396',NULL,1664248831,1782480565);
INSERT INTO highlights VALUES('921791_21_2391-2440','921791',44,'第十二章 赌徒的迷信和笼中的鸽子','此外，我觉得赌博的最好定义是，不管赔率对他有利还是不利，行为者面对随机结果都能获得刺激的一种活动。','2383-2432',NULL,1664248693,1782480565);
INSERT INTO highlights VALUES('921791_21_2233-2290','921791',44,'第十二章 赌徒的迷信和笼中的鸽子','在理性上，这种统计关联性是骗人的，因为样本很小。但是这种天生的统计本能，并没有因为我在假说检验上的专长而有所抑制。','2225-2282',NULL,1664248675,1782480565);
INSERT INTO highlights VALUES('921791_20_2179-2246','921791',54,'第三篇 活在随机世界中',unistr('戒掉媒体\u000a我最引以为豪的成就，是戒掉了接触电视和新闻媒体的习惯。'),'2696-2757',NULL,1664248410,1782480565);
INSERT INTO highlights VALUES('921791_20_2375-2388','921791',54,'第三篇 活在随机世界中','我的花招是把音量完全关闭。','2886-2899',NULL,1664248408,1782480565);
INSERT INTO highlights VALUES('921791_20_1266-1311','921791',54,'第三篇 活在随机世界中','我和本书取笑的每一个人根本没有两样，甚至可能比他们还糟，因为信念和行为之间可能正好是负相关','1781-1826',NULL,1664248213,1782480565);
INSERT INTO highlights VALUES('921791_20_1089-1172','921791',54,'第三篇 活在随机世界中','在面对随机性的事业生涯中，我顿悟的一件事是：了解自己不够聪明、不够坚强，不必奢望去对抗自己的情绪反应。此外，我也相信需要靠各种情感来构思一些观念，从而得到实践的力量。','1604-1687',NULL,1664248163,1782480565);
INSERT INTO highlights VALUES('921791_20_424-544','921791',54,'第三篇 活在随机世界中',unistr('第三篇 INSERT INTO highlights VALUES('921791_19_16073-16100','921791',53,'第十一章 我们是概率盲','一个人发表的意见中，估计值或预测值的重要性不如信赖水平','16098-16125',NULL,1664216075,1782480565);
INSERT INTO highlights VALUES('921791_19_15020-15045','921791',53,'第十一章 我们是概率盲','涨跌2%的显著性不是涨跌1%的2倍，而应该是4倍。','14971-14996',NULL,1664215988,1782480565);
INSERT INTO highlights VALUES('921791_19_12762-12787','921791',53,'第十一章 我们是概率盲','新闻记者把无条件预期寿命和条件预期寿命混为一谈了。','12717-12742',NULL,1664213069,1782480565);
INSERT INTO highlights VALUES('921791_19_10740-10887','921791',53,'第十一章 我们是概率盲','我把期权交易员分为两类：溢价卖方和溢价买方。溢价卖方（也称做期权卖方）卖出期权，大致可以安安稳稳地赚钱，如第一章和第五章所说的约翰。溢价买方的行动则恰好相反。这一行的人常说，期权卖方吃时像小鸡，拉时像大象。唉，我在事业生涯上碰的大部分期权交易员都是溢价卖方，而他们炸毁时，赔掉的通常是别人的钱。','10704-10851',NULL,1664203529,1782480565);
INSERT INTO highlights VALUES('921791_19_9535-9601','921791',53,'第十一章 我们是概率盲','身为期权交易员，我注意到人们往往低估期权的价值，因为他们经常无法以正确的心态，去评估提供不确定性报偿的工具，即使他们很懂数学也一样。','9499-9565',NULL,1664203252,1782480565);
INSERT INTO highlights VALUES('921791_19_8282-8484','921791',53,'第十一章 我们是概率盲','但是更深一层的原因是，人类不是被设计来理解事物的，我们只是被设计来求生和繁衍后代，但为了求生存，我们必须夸大某些事情的概率，例如可能影响我们存活的事件发生的概率。举例来说，大脑对生命危险特别在意的人（也就是偏执狂），比较能够生存下来，因此他们的基因遗传下去。但是这种偏执狂也不能过头，否则必须付出太高代价，反而成为缺点。某些偏见已经深深嵌进我们的大脑里，阻碍我们处理较复杂、可能需要更精确评估概率的环境。','8253-8455',NULL,1664202465,1782480565);
INSERT INTO highlights VALUES('921791_19_4534-4586','921791',53,'第十一章 我们是概率盲','我们的许多问题出在我们脱离原始栖息地的速度，远快于基因进化的速度。甚至更糟的是：我们的基因根本没有改变。','4523-4575',NULL,1664174843,1782480565);
INSERT INTO highlights VALUES('921791_19_4497-4534','921791',53,'第十一章 我们是概率盲','我们没有去计算偶然性，只是因为我们不敢去算？当然应该是因为我们不需要去算。','4486-4523',NULL,1664174834,1782480565);
INSERT INTO highlights VALUES('921791_19_3351-3458','921791',53,'第十一章 我们是概率盲','我并没有告诉太多同事，他们的决策带有从穴居人时代残留下来的习性，但在市场急上直下时，我也难免感到一股肾上腺素分泌，就像看到一头美洲豹潜进我的交易台。一些同事发生亏损时摔坏电话筒，他们的心理构造或许更接近人类的老祖先','3340-3447',NULL,1664174664,1782480565);
INSERT INTO highlights VALUES('921791_19_1429-1493','921791',53,'第十一章 我们是概率盲','任何特定的时刻，我们只能想象一种状态，假使让我们凭想象去决定的话，我们可能用不合理性的方式去赌，因为其中一种状态会盘踞整幅画面。','1421-1485',NULL,1664107151,1782480565);
INSERT INTO highlights VALUES('921791_18_4807-4812','921791',41,'第十章 生活中的非线性现象','非线性轻推','4787-4792',NULL,1664106920,1782480565);
INSERT INTO highlights VALUES('921791_18_4163-4377','921791',41,'第十章 生活中的非线性现象','瓦尔拉斯（Leon Walras）、德布鲁（Gerard Debreu）、萨缪尔森（Paul Samuelson）等人急着引进数学模型建构技巧，却没有考虑到也许他们使用的数学，对于他们想要处理的这类问题来说有太多限制；或者他们应该注意，数学语言的精确性可能导致人们在尚未找到解答时，就误以为他们已经得到答案。他们所用的数学确实没办法在真实的世界中运作，原因可能是我们需要更丰富的操作程序—而且他们拒绝接受没有数学可能更好的事实。','4147-4361',NULL,1664106816,1782480565);
INSERT INTO highlights VALUES('921791_18_4097-4163','921791',41,'第十章 生活中的非线性现象','经济学发展成一门科学的过程中，什么地方出了差错？答案是一群聪明人觉得一定得用数学来告诉自己，他们的想法很严谨、他们研究的是一门科学。','4081-4147',NULL,1664106804,1782480565);
INSERT INTO highlights VALUES('921791_18_3837-3878','921791',41,'第十章 生活中的非线性现象','仿真这种过程，可以看到结果变异很大，有惊人的成功，也有极多的失败，我们称之为偏态。','3821-3862',NULL,1664106755,1782480565);
INSERT INTO highlights VALUES('921791_18_3553-3648','921791',41,'第十章 生活中的非线性现象','处理这个问题的数学取向应运而生。在传统模式（如财务领域非常有名的布朗随机漫步）中，成功的概率并没有随着每踏出一步而变化，只有累积的财富才会。阿瑟则提出波利亚过程（Polya process）','3537-3633',NULL,1664106719,1782480565);
INSERT INTO highlights VALUES('921791_18_3015-3020','921791',41,'第十章 生活中的非线性现象','网络外部性','3000-3005',NULL,1664106617,1782480565);
INSERT INTO highlights VALUES('921791_18_2985-2989','921791',41,'第十章 生活中的非线性现象','循环效应','2970-2974',NULL,1664106613,1782480565);
INSERT INTO highlights VALUES('921791_18_2931-2980','921791',41,'第十章 生活中的非线性现象','这一切都是他该得的吗？显然不是。大部分人选用他的软件，只是因为别人也都在使用他的软件，我就是这样。','2916-2965',NULL,1664106610,1782480565);
