INSERT INTO highlights VALUES('921791_17_2629-2720','921791',40,'第九章 买卖证券比煎蛋容易','第五章谈过有些人的特质恰好暂时符合当时的随机结构，因而能够存活。这里我们谈的是更为简单的状况，其中的随机结构为已知。第一个例子是一句流行格言：即使是停住不动的时钟，一天也有两次正确。','2617-2708',NULL,1664004229,1782480565);
INSERT INTO highlights VALUES('921791_17_2111-2193','921791',40,'第九章 买卖证券比煎蛋容易','为什么财务学的内容那么丰富？因为很少研究领域像它那样，拥有很多的信息，譬如大量的价格数列，但是无法像物理学那般进行实验。于是对过去数据的依赖，成了它显而易见的瑕疵。','2104-2186',NULL,1664004143,1782480565);
