INSERT INTO highlights VALUES('921791_15_2361-2456','921791',52,'第二篇 打字机前的猴子','这些偏差可以简述如下：第一，存活者偏差（又称打字机前的猴子），起于我们只看见赢家，对运气持有的看法遭到扭曲。第二，不同凡响的成功最常见的原因是运气。第三，我们在生物构造上缺乏了解概率的能力。','2871-2966',NULL,1663957312,1782480565);
INSERT INTO highlights VALUES('921791_15_2288-2332','921791',52,'第二篇 打字机前的猴子','第二篇的内容比较平实，我将用很快的速度，综合整理目前众多相关著作中各种关于随机性的偏差。','2798-2842',NULL,1663957310,1782480565);
INSERT INTO highlights VALUES('921791_15_2172-2245','921791',52,'第二篇 打字机前的猴子','第一篇阐述人们不了解稀有事件，而且似乎不接受它们发生的概率，也不接受发生这些事情的悲惨后果。第一篇也谈我个人所持、其他著作似乎不曾探讨的一些观念。','2682-2755',NULL,1663957275,1782480565);
INSERT INTO highlights VALUES('921791_15_1172-1200','921791',52,'第二篇 打字机前的猴子','但是一如以往，只懂少许概率知识比完全不懂概率的结局更惨。','1689-1717',NULL,1663957114,1782480565);
INSERT INTO highlights VALUES('921791_15_641-691','921791',52,'第二篇 打字机前的猴子','如果把无限多的猴子放在打字机前面，让它们去乱敲，那么其中一只肯定会打出一字不差的《伊利亚特》叙事诗。','1158-1208',NULL,1663957034,1782480565);
INSERT INTO highlights VALUES('921791_15_515-539','921791',52,'第二篇 打字机前的猴子','由于我们只看到成功者，而由此形成对机遇的歪曲看法','1032-1056',NULL,1663957027,1782480565);
INSERT INTO highlights VALUES('921791_14_7396-7468','921791',37,'第七章 归纳法的问题','波普尔相信任何乌托邦的理想都属封闭式的，因为它会阻塞本身的反驳能力。认为社会已有个很好的模式，不可能开放接受否证，这样的观念本身会形成极权主义。','7342-7414',NULL,1663854330,1782480565);
INSERT INTO highlights VALUES('921791_14_7183-7238','921791',37,'第七章 归纳法的问题','波普尔的否证论和开放社会的观念关系密切。一个开放的社会中，没有一种真理永存不朽，这样的社会允许相反的观念出现。','7129-7184',NULL,1663854263,1782480565);
INSERT INTO highlights VALUES('921791_14_5987-6020','921791',37,'第七章 归纳法的问题','如果没有什么事情能够改变一位交易员的看法，那么他就称不上是交易员。','5937-5970',NULL,1663854086,1782480565);
INSERT INTO highlights VALUES('921791_14_4368-4505','921791',37,'第七章 归纳法的问题','虽然索罗斯在他写的文章中没有明白表示，但他懂得怎么处理随机性，方法是保持批判性的开放心胸，而且不以改变看法为耻，但这样的副作用是使他把人当做餐巾看待。他到处宣称自己容易犯错，却仍拥有那么强大的力量，因为他知道自身的缺点，其他人却自视甚高。他了解波普尔，也过着波普尔式的生活。','4351-4488',NULL,1663820073,1782480565);
INSERT INTO highlights VALUES('921791_14_3139-3244','921791',37,'第七章 归纳法的问题','他靠卖价外期权（out-of-the-money option）为生；我则靠买进它们为生。卖出价外期权是赌某个事件不会发生；但我买进价外期权，则只赌它可能发生。他试着赚取稳定的收入，我则喜欢偶尔一次来个大丰收。','3123-3228',NULL,1663812474,1782480565);
INSERT INTO highlights VALUES('921791_14_1832-1849','921791',37,'第七章 归纳法的问题','任何“可检测的”陈述都应该加以检测','1816-1833',NULL,1663812242,1782480565);
INSERT INTO highlights VALUES('921791_14_1283-1331','921791',37,'第七章 归纳法的问题','他是十分严重的怀疑论者，从来就不相信两件事之间真的有因果关系，但本书略微冲淡了他在这方面的色彩。','1271-1319',NULL,1663812157,1782480565);
INSERT INTO highlights VALUES('921791_14_1175-1200','921791',37,'第七章 归纳法的问题','问题是，如果方法不适当，经验观察会引导你误入歧途。','1163-1188',NULL,1663812143,1782480565);
INSERT INTO highlights VALUES('921791_13_12404-12447','921791',51,'第六章 偏态与不对称','财务工程”（financial engineering）的应用就带有浓厚的伪科学成分。','12460-12503',NULL,1663812011,1782480565);
INSERT INTO highlights VALUES('921791_13_11520-11561','921791',51,'第六章 偏态与不对称','比我懂很多的计量经济学家不问这种问题，因为那无异于自曝其短，徒然让人知道自己的愚蠢','11576-11617',NULL,1663811869,1782480565);
INSERT INTO highlights VALUES('921791_13_10679-10734','921791',51,'第六章 偏态与不对称','如果在满是黑球的罐内取到红球的概率很小，那么我们对罐内没有红球的信心，会增加得非常慢，比期望中的平方根值还慢。','10739-10794',NULL,1663735339,1782480565);
INSERT INTO highlights VALUES('921791_13_10422-10470','921791',51,'第六章 偏态与不对称','总归一句话，那是一个简单的概念：你得到的信息越多，你对结果就会越有把握。但问题来了：有多大把握？','10482-10530',NULL,1663735303,1782480565);
INSERT INTO highlights VALUES('921791_13_8282-8330','921791',51,'第六章 偏态与不对称','起来彬彬有礼像个善良公民的老邻居，得等到哪天你在报纸上看到他的照片，才会知道原来他是个疯狂杀手。','8345-8393',NULL,1663677762,1782480565);
INSERT INTO highlights VALUES('921791_13_7536-7633','921791',51,'第六章 偏态与不对称','根据过去的信息来预测未来时，我们可能太过马虎，也可能太过严格。我无法接受单靠过去的一个时间序列，作为未来表现的指针。除了数据，我还需要更多的东西。我的主要理由在于稀有事件，但还有更多的其他理由。','7604-7701',NULL,1663672634,1782480565);
INSERT INTO highlights VALUES('921791_13_7269-7417','921791',51,'第六章 偏态与不对称','我们没办法确定我们的世界真的那么清楚明白。我们会发现，从分析过去的特征而得出的判断，偶尔可能有用，但也可能缺乏意义，有时甚至会误导你往相反的方向走。有些时候，市场数据成了陷阱，让你看到和它的本质相反的形貌，促使你投资错误的证券，或者害你管理风险不当。举例来说，有史以来最为稳定的货币，却最容易崩跌','7337-7485',NULL,1663671617,1782480565);
INSERT INTO highlights VALUES('921791_13_5473-5541','921791',51,'第六章 偏态与不对称','我比塔利波更积极、更先进：我利用这种方法规划经营出一套能真正获利的工作生涯和事业。换句话说，我的目标是下不对称的赌注，好靠稀有事件赚钱。','5502-5570',NULL,1663671225,1782480565);
INSERT INTO highlights VALUES('921791_13_4614-4752','921791',51,'第六章 偏态与不对称','这辈子我在市场中做的事，称之为“倾力赌一边”最为恰当。也就是说，我试图从稀有事件中获利，这种事件不常重复发生，也因此一旦发生时报偿很高。我试着不要常赚钱，而且尽可能不常赚钱。原因很简单，因为我相信稀有事件在市场上并没有得到合理的价值，而且事件越稀有，它的价格被人低估得越严重。','4643-4781',NULL,1663569534,1782480565);
INSERT INTO highlights VALUES('921791_13_3395-3482','921791',51,'第六章 偏态与不对称','假使读者接受我的意见，也就是下个星期市场有70%的概率上涨，30%的概率下跌。但是再假设如果上涨，只会涨1%，下跌则可能跌10%。这么一来，读者要怎么做？是看好呢，还是看坏？','3432-3519',NULL,1663555968,1782480565);
INSERT INTO highlights VALUES('921791_13_502-556','921791',51,'第六章 偏态与不对称','我的意见是市场上涨的可能性比较高（我看好后市），但最好是卖空（我看坏结果），因为万一市场下跌，它可能跌很多。','495-549',NULL,1663523675,1782480565);
INSERT INTO highlights VALUES('921791_12_13120-13169','921791',35,'第五章 最不适者可能生存吗？','这里面有个不良的属性，就是这些动物不曾遭遇稀有事件的时间越久，则它们对该稀有事件的承受力越显脆弱。','13088-13137',NULL,1663523596,1782480565);
INSERT INTO highlights VALUES('921791_12_10469-10496','921791',35,'第五章 最不适者可能生存吗？','交易员和投资人的不同点，在于下赌注的时间长短和赌注金额','10437-10464',NULL,1663523205,1782480565);
INSERT INTO highlights VALUES('921791_12_5941-5968','921791',35,'第五章 最不适者可能生存吗？','在任何一个时间点，赚钱最多的交易员往往是最差的交易员。','5918-5945',NULL,1663522484,1782480565);
INSERT INTO highlights VALUES('921791_12_5603-5629','921791',35,'第五章 最不适者可能生存吗？','“什么经济学，鬼扯淡经济学。其实一切都是市场动力。”','5579-5605',NULL,1663522443,1782480565);
INSERT INTO highlights VALUES('921791_11_4870-4994','921791',34,'第四章 随机性和科学知识分子','面对日常生活中的细节，我们不需要那么理性、那么讲究科学。只有在可能伤害我们、危及我们生存的状况中，才需要那么做。现代生活似乎诱导我们做出完全相反的事情：面对宗教和个人行为等事物时，我们变得极其务实和理智，面对市场和受随机性影响的事物时，却失去理性。','4856-4980',NULL,1663519681,1782480565);
INSERT INTO highlights VALUES('921791_11_2020-2073','921791',34,'第四章 随机性和科学知识分子','有时你可以用蒙特·卡罗发生器复制某样东西，让人以为那是文学作品；但是你却不可能用随机的方式写出一篇科学作品','2008-2061',NULL,1663519427,1782480565);
INSERT INTO highlights VALUES('921791_11_1327-1399','921791',34,'第四章 随机性和科学知识分子','要区分科学知识分子和人文学者有一个方法：科学知识分子通常能够辨别其他人的著作，但人文学者则无法区分科学家和能言善道的非科学家两者的作品有什么不同','1319-1391',NULL,1663519366,1782480565);
INSERT INTO highlights VALUES('921791_10_16154-16277','921791',50,'第三章 从数学的角度思考历史','最后，这可以解释为什么太密切注意随机性的人反倒会被烧伤，他们由于体验到一连串的痛苦，情绪上筋疲力尽。不管人们怎么说，他们体验到的痛苦，没有办法被感受到的愉悦抵消，那会造成情绪上的赤字。经济学家估计，有些行为负面影响的强度是正面影响强度的2.5倍。','16151-16274',NULL,1663493958,1782480565);
INSERT INTO highlights VALUES('921791_10_11246-11331','921791',50,'第三章 从数学的角度思考历史','换句话说，我现在把别人看这些东西的现象当成是一种保险，因为有了那么多不懂随机性的笨蛋，才可以保障我继续待在期权交易这个有趣的行业中。','11208-11293',NULL,1663492804,1782480565);
INSERT INTO highlights VALUES('921791_10_10909-10941','921791',50,'第三章 从数学的角度思考历史','信息的问题不在于它令我们分心且通常一无用处，而是在于它含有毒性。','10871-10903',NULL,1663492742,1782480565);
INSERT INTO highlights VALUES('921791_10_10493-10584','921791',50,'第三章 从数学的角度思考历史','我的看法恰好相反，错过飞机、汽车等“新新事物”的机会成本，和我们为了找到这些珠宝必须接受垃圾所产生的毒性相比，实在微不足道，不过这些事物真能使我们的生活有所改善吗？我经常怀疑这一点。','10454-10545',NULL,1663492562,1782480565);
INSERT INTO highlights VALUES('921791_10_10034-10075','921791',50,'第三章 从数学的角度思考历史','数学的角度来说，进步意指某些新信息优于旧信息，但并不是说一般的新信息都会取代旧信息','9995-10036',NULL,1663492407,1782480565);
INSERT INTO highlights VALUES('921791_10_9754-9799','921791',50,'第三章 从数学的角度思考历史','要求新闻记者以历史学家的方式去思考很困难，但可叹的是，现在的历史学家竟然越来越像新闻记者。','9715-9760',NULL,1663471682,1782480565);
INSERT INTO highlights VALUES('921791_10_9210-9248','921791',50,'第三章 从数学的角度思考历史','而一条非常、非常长的样本路径的性质，类似于许多较短路径平均值的蒙特·卡罗性质','9176-9214',NULL,1663466734,1782480565);
INSERT INTO highlights VALUES('921791_10_9170-9209','921791',50,'第三章 从数学的角度思考历史','大致而言，它的意思是说，在某些情况下，众多非常长的样本路径最后看起来会彼此相似','9136-9175',NULL,1663466710,1782480565);
INSERT INTO highlights VALUES('921791_10_9154-9157','921791',35,'第五章 最不适者可能生存吗？','遍历性','13153-13156',NULL,1663466702,1782480565);
INSERT INTO highlights VALUES('921791_10_7695-7729','921791',50,'第三章 从数学的角度思考历史','我们有足够的证据，显示身为直立人的我们，天赋的本能不利于经验的传承。','7664-7698',NULL,1663466492,1782480565);
INSERT INTO highlights VALUES('921791_10_4858-4942','921791',50,'第三章 从数学的角度思考历史','读者猜想得到，探索概率的下一步，是进入哲学的层次，尤其是研究知识哲学分支的知识论、方法学，或者科学哲学。它们因波普尔和索罗斯（George Soros）等人而普及开来。','4843-4927',NULL,1663434864,1782480565);
INSERT INTO highlights VALUES('921791_10_4147-4205','921791',50,'第三章 从数学的角度思考历史','我们被人称做“数字专家”（quants），就像物理学家一样，我们感兴趣的是如何运用数学工具，但对工具本身并不感兴趣。','4132-4190',NULL,1663434049,1782480565);
INSERT INTO highlights VALUES('921791_10_2031-2069','921791',50,'第三章 从数学的角度思考历史','我们不关心比如说一年后投资人的财富有多少，但关心这段时间内他所有财富的起落。','2020-2058',NULL,1663433783,1782480565);
INSERT INTO highlights VALUES('921791_10_1475-1501','921791',50,'第三章 从数学的角度思考历史','数学主要是用来作为冥思的工具，不是当做计算工具使用。','1467-1493',NULL,1663433720,1782480565);
