INSERT INTO highlights VALUES('33915626_3_1576-1606','33915626',3,'CHAPTER 1 一生的亲密关系始于有意义的对话','真正的爱情,不是花前月下的山盟海誓,而是平凡日子里的细水长流','1576-1606',1,1723542119,1782398552);
INSERT INTO highlights VALUES('30179184_13_4125-4154','30179184',13,'第6章 机制：受限直接执行','内核通过在启动时设置陷阱表（trap table）来实现。','4125-4154',1,1708085848,1782480561);
INSERT INTO highlights VALUES('30179184_13_4091-4112','30179184',13,'第6章 机制：受限直接执行','因此内核必须谨慎地控制在陷阱上执行的代码。','4091-4112',5,1708081941,1782480561);
INSERT INTO highlights VALUES('30179184_13_3794-3901','30179184',13,'第6章 机制：受限直接执行','因此，C库中进行系统调用的部分是用汇编手工编码的，因为它们需要仔细遵循约定，以便正确处理参数和返回值，以及执行硬件特定的陷阱指令。现在你知道为什么你自己不必写汇编代码来陷入操作系统了，因为有人已经为你写了这些汇编。','3794-3901',5,1708081848,1782480561);
INSERT INTO highlights VALUES('30179184_13_3573-3607','30179184',13,'第6章 机制：受限直接执行','原因很简单：它是一个过程调用，但隐藏在过程调用内部的是著名的陷阱指令','3573-3607',5,1708081661,1782480561);
INSERT INTO highlights VALUES('30179184_13_3203-3259','30179184',13,'第6章 机制：受限直接执行','执行陷阱时，硬件需要小心，因为它必须确保存储足够的调用者寄存器，以便在操作系统发出从陷阱返回指令时能够正确返回。','3203-3259',5,1708017164,1782480561);
INSERT INTO highlights VALUES('30179184_13_1540-1596','30179184',13,'第6章 机制：受限直接执行','第二个问题：当我们运行一个进程时，操作系统如何让它停下来并切换到另一个进程，从而实现虚拟化CPU所需的时分共享？','1540-1596',5,1708016776,1782480561);
INSERT INTO highlights VALUES('30179184_13_1483-1540','30179184',13,'第6章 机制：受限直接执行','第一个问题很简单：如果我们只运行一个程序，操作系统怎么能确保程序不做任何我们不希望它做的事，同时仍然高效地运行它？','1483-1540',5,1708016749,1782480561);
INSERT INTO highlights VALUES('30179184_13_945-1014','30179184',13,'第6章 机制：受限直接执行','为了使程序尽可能快地运行，操作系统开发人员想出了一种技术——我们称之为受限的直接执行（limited direct execution）。','945-1014',5,1708016689,1782480561);
INSERT INTO highlights VALUES('30179184_13_920-931','30179184',13,'第6章 机制：受限直接执行','基本技巧：受限直接执行','920-931',5,1708016682,1782480561);
INSERT INTO highlights VALUES('30179184_13_651-685','30179184',13,'第6章 机制：受限直接执行','因此，在保持控制权的同时获得高性能，这是构建操作系统的主要挑战之一。','651-685',5,1708016516,1782480561);
INSERT INTO highlights VALUES('30179184_12_10484-10596','30179184',12,'第5章 插叙：进程API','比如通过ps命令来查看当前在运行的进程，阅读man手册来了解ps命令所接受的参数。工具top也很有用，它展示当前系统中进程消耗CPU或其他资源的情况。有趣的是，你常常会发现top命令自己就是最占用资源的，它或许有一点自大狂。','10484-10596',5,1707977561,1782480561);
INSERT INTO highlights VALUES('30179184_12_10358-10389','30179184',12,'第5章 插叙：进程API','比如可以通过kill()系统调用向进程发送信号（signal）','10358-10389',5,1707977506,1782480561);
INSERT INTO highlights VALUES('30179184_12_10187-10210','30179184',12,'第5章 插叙：进程API','RTFM中的F只是为这个短语增加了一点色彩……','10187-10210',5,1707977489,1782480561);
INSERT INTO highlights VALUES('30179184_12_9794-9832','30179184',12,'第5章 插叙：进程API','现在，知道fork()和exec()组合在创建和操作进程时非常强大就足够了。','9794-9832',5,1707977415,1782480561);
INSERT INTO highlights VALUES('30179184_12_7438-7484','30179184',12,'第5章 插叙：进程API','子进程执行结束后，shell从wait()返回并再次输出一个提示符，等待用户输入下一条命令。','7438-7484',5,1707976643,1782480561);
INSERT INTO highlights VALUES('30179184_12_6641-6660','30179184',12,'第5章 插叙：进程API','对exec()的成功调用永远不会返回。','6641-6660',5,1707976352,1782480561);
INSERT INTO highlights VALUES('30179184_12_6472-6563','30179184',12,'第5章 插叙：进程API','exec()会从可执行程序中加载代码和静态数据，并用它覆写自己的代码段（以及静态数据），堆、栈及其他内存空间也会被重新初始化。然后操作系统就执行该程序，将参数通过argv传递给该进程','6472-6563',5,1707976328,1782480561);
INSERT INTO highlights VALUES('30179184_12_4882-4906','30179184',12,'第5章 插叙：进程API','常常想运行不同的程序，exec()正好做这样的事','4882-4906',5,1707972227,1782480561);
INSERT INTO highlights VALUES('30179184_12_3195-3259','30179184',12,'第5章 插叙：进程API','事实表明，有时候父进程需要等待子进程执行完毕，这很有用。这项任务由wait()系统调用（或者更完整的兄弟接口waitpid()）','3195-3259',5,1707843086,1782480561);
INSERT INTO highlights VALUES('30179184_12_2958-3033','30179184',12,'第5章 插叙：进程API','事实表明，这种不确定性（non-determinism）会导致一些很有趣的问题，特别是在多线程程序（multi-threaded program）中。','2958-3033',5,1707842458,1782480561);
INSERT INTO highlights VALUES('30179184_12_2927-2958','30179184',12,'第5章 插叙：进程API','由于CPU调度程序非常复杂，所以我们不能假设哪个进程会先运行。','2927-2958',5,1707842448,1782480561);
INSERT INTO highlights VALUES('30179184_12_2426-2515','30179184',12,'第5章 插叙：进程API','虽然它拥有自己的地址空间（即拥有自己的私有内存）、寄存器、程序计数器等，但是它从fork()返回的值是不同的。父进程获得的返回值是新创建子进程的PID，而子进程获得的返回值是0。','2426-2515',5,1707842288,1782480561);
INSERT INTO highlights VALUES('30179184_12_2307-2384','30179184',12,'第5章 插叙：进程API','子进程不会从main()函数开始执行（因此hello world信息只输出了一次），而是直接从fork()系统调用返回，就好像是它自己调用了fork()。','2307-2384',5,1707842215,1782480561);
INSERT INTO highlights VALUES('30179184_12_2223-2269','30179184',12,'第5章 插叙：进程API','对操作系统来说，这时看起来有两个完全一样的p1程序在运行，并都从fork()系统调用中返回。','2223-2269',5,1707842177,1782480561);
INSERT INTO highlights VALUES('30179184_12_913-1048','30179184',12,'第5章 插叙：进程API','系统调用fork()用于创建新进程[C63]。但要小心，这可能是你使用过的最奇怪的接口[1]。具体来说，你可以运行一个程序，代码如图5.1所示。仔细看这段代码，建议亲自键入并运行！','913-1048',5,1707841995,1782480561);
INSERT INTO highlights VALUES('30179184_11_7503-7508','30179184',11,'第4章 抽象：进程','上下文切换','7503-7508',5,1707750718,1782480561);
INSERT INTO highlights VALUES('30179184_11_6850-6959','30179184',11,'第4章 抽象：进程','首先，系统必须决定在Process0发出I/O时运行Process1。这样做可以通过保持CPU繁忙来提高资源利用率。其次，当I/O完成时，系统决定不切换回Process0。目前还不清楚这是不是一个很好的决定。你怎么看？','6850-6959',5,1707749754,1782480561);
INSERT INTO highlights VALUES('30179184_11_6710-6742','30179184',11,'第4章 抽象：进程','OS发现Process0不使用CPU并开始运行Process1。','6710-6742',5,1707749733,1782480561);
INSERT INTO highlights VALUES('30179184_11_4809-4902','30179184',11,'第4章 抽象：进程','通过将代码和静态数据加载到内存中，通过创建和初始化栈以及执行与I/O设置相关的其他工作，OS现在（终于）为程序执行搭好了舞台。然后它有最后一项任务：启动程序，在入口处运行，即main()','4809-4902',5,1707749410,1782480561);
INSERT INTO highlights VALUES('30179184_11_4455-4492','30179184',11,'第4章 抽象：进程','堆用于显式请求的动态分配数据。程序通过调用malloc()来请求这样的空间','4455-4492',5,1707749305,1782480561);
INSERT INTO highlights VALUES('30179184_11_4424-4448','30179184',11,'第4章 抽象：进程','操作系统也可能为程序的堆（heap）分配一些内存','4424-4448',5,1707749293,1782480561);
INSERT INTO highlights VALUES('30179184_11_2450-2470','30179184',11,'第4章 抽象：进程','策略为“哪个（which）”问题提供答案','2450-2470',5,1707748991,1782480561);
INSERT INTO highlights VALUES('30179184_11_2409-2432','30179184',11,'第4章 抽象：进程','机制看成为系统的“如何（how）”问题提供答案','2409-2432',5,1707748988,1782480561);
INSERT INTO highlights VALUES('30179184_11_2058-2109','30179184',11,'第4章 抽象：进程','进程的机器状态的另一部分是寄存器。许多指令明确地读取或更新寄存器，因此显然，它们对于执行该进程很重要。','2058-2109',5,1707748853,1782480561);
INSERT INTO highlights VALUES('30179184_11_1950-1973','30179184',11,'第4章 抽象：进程','进程的机器状态有一个明显组成部分，就是它的内存','1950-1973',5,1707748820,1782480561);
INSERT INTO highlights VALUES('30179184_11_1877-1914','30179184',11,'第4章 抽象：进程','机器状态（machine state）：程序在运行时可以读取或更新的内容。','1877-1914',5,1707748811,1782480561);
INSERT INTO highlights VALUES('30179184_11_1023-1045','30179184',11,'第4章 抽象：进程','机制是一些低级方法或协议，实现了所需的功能。','1023-1045',5,1707730247,1782480561);
INSERT INTO highlights VALUES('30179184_11_961-1022','30179184',11,'第4章 抽象：进程','要实现CPU的虚拟化，要实现得好，操作系统就需要一些低级机制以及一些高级智能。我们将低级机制称为机制（mechanism）','961-1022',5,1707728082,1782480561);
INSERT INTO highlights VALUES('30179184_11_869-911','30179184',11,'第4章 抽象：进程','这就是时分共享（time sharing）CPU技术，允许用户如愿运行多个并发进程。','869-911',5,1707728050,1782480561);
INSERT INTO highlights VALUES('30179184_11_407-481','30179184',11,'第4章 抽象：进程','进程就是运行中的程序。程序本身是没有生命周期的，它只是存在磁盘上面的一些指令（也可能是一些静态数据）。是操作系统让这些字节运行起来，让程序发挥作用。','407-481',5,1707727907,1782480561);
INSERT INTO highlights VALUES('30179184_10_1607-1633','30179184',10,'第1部分 虚拟化','不用担心，毕竟我也不喜欢吃桃子。那我们开始学习吧……','1607-1633',5,1707727821,1782480561);
INSERT INTO highlights VALUES('30179184_10_1314-1348','30179184',10,'第1部分 虚拟化','虚拟化要做的就是将这个CPU虚拟成多个虚拟CPU并分给每一个进程使用','1314-1348',5,1707725075,1782480561);
INSERT INTO highlights VALUES('30179184_10_1035-1086','30179184',10,'第1部分 虚拟化','教授：是的！你说得没错。但吃的人多才有这样的问题。多数时间他们都在打盹或者做其他事情','1035-1086',5,1707725038,1782480561);
INSERT INTO highlights VALUES('30179184_9_22200-22214','30179184',9,'第2章 操作系统介绍','大写版本是我们自己的包装函数','22200-22214',5,1707724899,1782480561);
INSERT INTO highlights VALUES('30179184_9_22001-22025','30179184',9,'第2章 操作系统介绍','要让这个例子能工作，需要确保禁用地址空间随机化。','22001-22025',5,1707724811,1782480561);
INSERT INTO highlights VALUES('30179184_9_21852-21877','30179184',9,'第2章 操作系统介绍','命令之间的分号允许我们在tcsh中同时运行多个程序','21852-21877',5,1707724766,1782480561);
INSERT INTO highlights VALUES('30179184_9_21280-21337','30179184',9,'第2章 操作系统介绍','当然，现代处理器在背后做了许多奇怪而可怕的事情，让程序运行得更快。例如，一次执行多条指令，甚至乱序执行并完成它们！','21280-21337',5,1707723710,1782480561);
INSERT INTO highlights VALUES('30179184_9_17830-17859','30179184',9,'第2章 操作系统介绍','由于篇幅的限制，我们在本书中将不会涉及操作系统的一些部分。','17830-17859',5,1707723494,1782480561);
INSERT INTO highlights VALUES('30179184_9_17445-17474','30179184',9,'第2章 操作系统介绍','事实上，如果不存在这样一个系统，很难想象这些新公司的成功。','17445-17474',5,1707723407,1782480561);
INSERT INTO highlights VALUES('30179184_9_17215-17358','30179184',9,'第2章 操作系统介绍','幸运的是，对于UNIX来说，一位名叫Linus Torvalds的年轻芬兰黑客决定编写他自己的UNIX版本，该版本严重依赖最初系统背后的原则和思想，但没有借用原来的代码集，从而避免了合法性问题。他征集了世界各地许多其他人的帮助，不久，Linux就诞生了（同时也开启了现代开源软件运动）。','17215-17358',5,1707723385,1782480561);
INSERT INTO highlights VALUES('30179184_9_17177-17190','30179184',9,'第2章 操作系统介绍','补充：然后出现了Linux','17177-17190',5,1707723375,1782480561);
INSERT INTO highlights VALUES('30179184_9_16833-16903','30179184',9,'第2章 操作系统介绍',unistr('该发行版拥有先进的虚拟内存、文件系统和网络子系统。Joy后来与朋友共同创立了Sun Microsystems。\u000a'),'16833-16903',5,1707723326,1782480561);
INSERT INTO highlights VALUES('30179184_9_16200-16211','30179184',9,'第2章 操作系统介绍','补充：UNIX的重要性','16200-16211',5,1707723132,1782480561);
INSERT INTO highlights VALUES('30179184_9_15963-16024','30179184',9,'第2章 操作系统介绍','Windows在计算历史中同样采用了许多伟大的思想，特别是从Windows NT开始，这是微软操作系统技术的一次巨大飞跃。','15963-16024',5,1707723102,1782480561);
INSERT INTO highlights VALUES('30179184_9_15919-15963','30179184',9,'第2章 操作系统介绍','例如，macOS X的核心是 UNIX，包括人们期望从这样一个成熟系统中获得的所有功能。','15919-15963',5,1707723072,1782480561);
INSERT INTO highlights VALUES('30179184_9_15650-15677','30179184',9,'第2章 操作系统介绍','因为早期的系统忘记了（或从未知道）小型机时代的经验教训','15650-15677',5,1707722931,1782480561);
INSERT INTO highlights VALUES('30179184_9_15516-15567','30179184',9,'第2章 操作系统介绍','在苹果公司早期的机器（如Apple II）和IBM PC的引领下，这种新机器很快就成为计算的主导力量，','15516-15567',5,1707722914,1782480561);
INSERT INTO highlights VALUES('30179184_9_14765-14860','30179184',9,'第2章 操作系统介绍','操作系统不是一次只运行一项作业，而是将大量作业加载到内存中并在它们之间快速切换，从而提高CPU利用率。这种切换非常重要，因为I/O设备很慢。在处理I/O时让程序占着CPU，浪费了CPU时间。','14765-14860',5,1707722625,1782480561);
INSERT INTO highlights VALUES('30179184_9_14653-14706','30179184',9,'第2章 操作系统介绍','成本下降的主要影响之一是开发者活动的增加。更聪明的人接触到计算机，从而让计算机系统做出更有趣和漂亮的事情。','14653-14706',5,1707722576,1782480561);
INSERT INTO highlights VALUES('30179184_9_14508-14514','30179184',9,'第2章 操作系统介绍','多道程序时代','14508-14514',5,1707722404,1782480561);
INSERT INTO highlights VALUES('30179184_9_14359-14451','30179184',9,'第2章 操作系统介绍','功能。当操作系统完成请求的服务时，它通过特殊的陷阱返回（return-from-trap）指令将控制权交还给用户，该指令返回到用户模式，同时将控制权交还给应用程序，回到应用离开的地方。','14359-14451',5,1707722316,1782480561);
INSERT INTO highlights VALUES('30179184_9_14235-14254','30179184',9,'第2章 操作系统介绍','硬件将控制转移到预先指定的陷阱处理程序','14235-14254',5,1707722273,1782480561);
INSERT INTO highlights VALUES('30179184_9_14028-14102','30179184',9,'第2章 操作系统介绍','系统调用和过程调用之间的关键区别在于，系统调用将控制转移（跳转）到OS中，同时提高硬件特权级别（hardware privilege level）。','14028-14102',5,1707722134,1782480561);
INSERT INTO highlights VALUES('30179184_9_13971-14015','30179184',9,'第2章 操作系统介绍','这里的想法是添加一些特殊的硬件指令和硬件状态，让向操作系统过渡变为更正式的、受控的过程。','13971-14015',5,1707722033,1782480561);
INSERT INTO highlights VALUES('30179184_9_13671-13733','30179184',9,'第2章 操作系统介绍','其中一个重要方面是意识到代表操作系统运行的代码是特殊的。它控制了设备，因此对待它的方式应该与对待正常应用程序代码的方式不同。','13671-13733',5,1707721942,1782480561);
INSERT INTO highlights VALUES('30179184_9_13432-13479','30179184',9,'第2章 操作系统介绍','这种计算模式被称为批（batch）处理，先把一些工作准备好，然后由操作员以“分批”的方式运行。','13432-13479',5,1707721912,1782480561);
INSERT INTO highlights VALUES('30179184_9_13335-13359','30179184',9,'第2章 操作系统介绍','这个操作员完成了你认为现代操作系统会做的许多事情','13335-13359',5,1707721842,1782480561);
INSERT INTO highlights VALUES('30179184_9_13174-13232','30179184',9,'第2章 操作系统介绍',unistr('早期操作系统：只是一些库\u000a一开始，操作系统并没有做太多事情。基本上，它只是一组常用函数库。'),'13174-13232',5,1707721820,1782480561);
INSERT INTO highlights VALUES('30179184_9_12520-12550','30179184',9,'第2章 操作系统介绍','操作系统往往力求提供高度的可靠性（reliability）。','12520-12550',5,1707721705,1782480561);
INSERT INTO highlights VALUES('30179184_9_12397-12463','30179184',9,'第2章 操作系统介绍','保护是操作系统基本原理之一的核心，这就是隔离（isolation）。让进程彼此隔离是保护的关键，因此决定了OS必须执行的大部分任务。','12397-12463',5,1707721494,1782480561);
INSERT INTO highlights VALUES('30179184_9_12015-12049','30179184',9,'第2章 操作系统介绍','设计和实现操作系统的一个目标，是提供高性能（performance）','12015-12049',5,1707721450,1782480561);
INSERT INTO highlights VALUES('30179184_9_12270-12311','30179184',9,'第2章 操作系统介绍','另一个目标是在应用程序之间以及在OS和应用程序之间提供保护（protection）','12270-12311',5,1707721441,1782480561);
INSERT INTO highlights VALUES('30179184_9_12154-12191','30179184',9,'第2章 操作系统介绍','这些开销会以多种形式出现：额外时间（更多指令）和额外空间（内存或磁盘上）。','12154-12191',5,1707721428,1782480561);
INSERT INTO highlights VALUES('30179184_9_10649-10723','30179184',9,'第2章 操作系统介绍','这些系统调用（system call）被转到称为文件系统（file system）的操作系统部分，然后该系统处理这些请求，并向用户返回某种错误代码。','10649-10723',5,1707719191,1782480561);
INSERT INTO highlights VALUES('30179184_9_9692-9713','30179184',9,'第2章 操作系统介绍','编译器使用该输入文件创建一个新的可执行文件','9692-9713',5,1707719105,1782480561);
INSERT INTO highlights VALUES('30179184_9_9395-9465','30179184',9,'第2章 操作系统介绍','不像操作系统为CPU和内存提供的抽象，操作系统不会为每个应用程序创建专用的虚拟磁盘。相反，它假设用户经常需要共享（share）文件中的信息。','9395-9465',5,1707719027,1782480561);
INSERT INTO highlights VALUES('30179184_9_9307-9340','30179184',9,'第2章 操作系统介绍','操作系统中管理磁盘的软件通常称为文件系统（file system）','9307-9340',5,1707718975,1782480561);
INSERT INTO highlights VALUES('30179184_9_9211-9294','30179184',9,'第2章 操作系统介绍','在现代系统中，硬盘驱动器（hard drive）是存储长期保存的信息的通用存储库，尽管固态硬盘（Solid-State Drive，SSD）正在这个领域取得领先地位。','9211-9294',5,1707718921,1782480561);
INSERT INTO highlights VALUES('30179184_9_8787-8881','30179184',9,'第2章 操作系统介绍','一条将计数器的值从内存加载到寄存器，一条将其递增，另一条将其保存回内存。因为这 3 条指令并不是以原子方式（atomically）执行（所有的指令一次性执行）的，所以奇怪的事情可能会发生。','8787-8881',5,1707718512,1782480561);
INSERT INTO highlights VALUES('30179184_9_7674-7717','30179184',9,'第2章 操作系统介绍','可以将线程看作与其他函数在同一内存空间中运行的函数，并且每次都有多个线程处于活动状态。','7674-7717',5,1707718241,1782480561);
INSERT INTO highlights VALUES('30179184_9_7588-7659','30179184',9,'第2章 操作系统介绍','主程序利用Pthread_create()创建了两个线程（thread）','7588-7659',5,1707718219,1782480561);
INSERT INTO highlights VALUES('30179184_9_6170-6218','30179184',9,'第2章 操作系统介绍','对于正在运行的程序，它完全拥有自己的物理内存。但实际情况是，物理内存是由操作系统管理的共享资源。','6170-6218',5,1707717039,1782480561);
INSERT INTO highlights VALUES('30179184_9_4334-4366','30179184',9,'第2章 操作系统介绍','不要忘记，程序的每个指令都在内存中，因此每次读取指令都会访问内存','4334-4366',5,1707715523,1782480561);
INSERT INTO highlights VALUES('30179184_9_3863-3910','30179184',9,'第2章 操作系统介绍','如果两个程序想要在特定时间运行，应该运行哪个？这个问题由操作系统的策略（policy）来回答。','3863-3910',5,1707715399,1782480561);
INSERT INTO highlights VALUES('30179184_9_3573-3613','30179184',9,'第2章 操作系统介绍','操作系统负责提供这种假象（illusion），即系统拥有非常多的虚拟CPU的假象','3573-3613',5,1707715300,1782480561);
INSERT INTO highlights VALUES('30179184_9_1991-2049','30179184',9,'第2章 操作系统介绍','每个CPU、内存和磁盘都是系统的资源（resource），因此操作系统扮演的主要角色就是管理（manage）这些资源','1991-2049',5,1707715052,1782480561);
INSERT INTO highlights VALUES('30179184_9_1572-1665','30179184',9,'第2章 操作系统介绍','也就是说，操作系统将物理（physical）资源（如处理器、内存或磁盘）转换为更通用、更强大且更易于使用的虚拟形式。因此，我们有时将操作系统称为虚拟机（virtual machine）。','1572-1665',5,1707714890,1782480561);
INSERT INTO highlights VALUES('30179184_9_898-947','30179184',9,'第2章 操作系统介绍','我们将了解到在一个程序运行的同时，还有很多其他疯狂的事情也在同步进行——主要是为了让系统易于使用。','898-947',5,1707714611,1782480561);
INSERT INTO highlights VALUES('30179184_8_1698-1784','30179184',8,'第1章 关于本书的对话','这样似乎很连贯。我是孔子的粉丝，更是荀子的粉丝，实际上荀子才是说这句话的人[1]。','1698-1784',5,1707714325,1782480561);
INSERT INTO highlights VALUES('30179184_8_1540-1617','30179184',8,'第1章 关于本书的对话',unistr('就像孔子说的那样……\u000a学生：我知道！“不闻不若闻之，闻之不若见之，见之不若知之，知之不若行之。”'),'1540-1617',5,1707714305,1782480561);
INSERT INTO highlights VALUES('30179184_8_1409-1448','30179184',8,'第1章 关于本书的对话','首先听课，听老师讲解并做好笔记，然后每个周末阅读笔记，以便更好地理解这些概念。','1409-1448',5,1707714292,1782480561);
INSERT INTO highlights VALUES('30179184_8_898-923','30179184',8,'第1章 关于本书的对话','这很合适，因为操作系统的难度差不多是物理学的一半。','898-923',5,1707714107,1782480561);
INSERT INTO highlights VALUES('30179184_6_9056-9147','30179184',6,'前言','教育过程的真正意义在于：前进，学习许多新的和引人入胜的主题，通过学习不断成熟，最重要的是，找到能为你点火的东西。','9056-9147',5,1707711347,1782480561);
INSERT INTO highlights VALUES('30179184_6_8740-8815','30179184',6,'前言','叶芝的主要观点显而易见：教育的真正要点是让你对某些事情感兴趣，可以独立学习更多关于这个主题的东西，而不仅仅是你需要消化什么才能在某些课程上取得好成绩。','8740-8815',5,1707711291,1782480561);
INSERT INTO highlights VALUES('30179184_6_1511-1544','30179184',6,'前言','抽象是计算机科学各个方面的基础，因此它在操作系统中也是必不可少的。','1511-1544',5,1707710646,1782480561);
INSERT INTO highlights VALUES('30179184_6_1077-1131','30179184',6,'前言','在许多地方，我们将通过显示一段时间内的行为来解释系统的工作原理。这些时间线（timeline）是理解的本质。','1077-1131',5,1707710576,1782480561);
INSERT INTO highlights VALUES('30179184_6_705-734','30179184',6,'前言','希望你在这个过程中体会到一些乐趣。学习新事物很有趣，对吧？','705-734',5,1707710425,1782480561);
INSERT INTO highlights VALUES('30179184_5_364-432','30179184',5,'内容提要','全书围绕虚拟化、并发和持久性这3个主要概念展开，介绍了所有现代系统的主要组件（包括调度、虚拟内存管理、磁盘和I/O子系统、文件系统 ）。','364-432',5,1707710238,1782480561);
INSERT INTO highlights VALUES('837618_50_2818-3019','837618',68,'08 传染：为什么意志力会传染？','想象一下你在意志力挑战中取得成功后会多么自豪。这样，你就能充分利用“被认可”这个人类的基本需求。想一想你所在“群体”中的某个人，可以是一个家庭成员、一个朋友、一个同事、一个老师。想象他们的观点与你相符，或者他们会为了你的成功感到高兴。当你作出一个让自己感到自豪的选择时，你可以更新Facebook的个人状态，或是在Twitter上发布信息。如果你不喜欢高科技产品，你也可以和人们面对面地分享自己的故事。','17150-17351',NULL,1657381867,1782480567);
INSERT INTO highlights VALUES('837618_40_2384-2945','837618',66,'06 “那又如何”：情绪低落为何会使人屈服于诱惑？',unistr('乐观给我们动力，但少许的悲观能帮我们走向成功。研究发现，如果能预测自己什么时候、会如何受到诱惑和违背承诺，你就更有可能拥有坚定的决心。\u000a想一想你自己的意志力挑战，请扪心自问：我什么时候最可能受到诱惑并放弃抗争？什么东西最可能分散我的注意力？当我允许自己拖延的时候，我会怎样劝说自己？当你头脑中出现这样的情景时，想象自己真的处在这样的情景中，你会有什么感觉？会想到什么？让你自己看一看典型的意志力失效是怎么发生的。\u000a然后，把想象中的意志力失效变成现实中的意志力成功。想一\u000a想你要采取哪些具体行动来坚定自己的决心。你需要回忆一下自己的动力吗？需要远离诱惑吗？需要找朋友帮忙吗？需要用你学过的其他意志力策略吗？当你头脑中有了一个具体策略后，想象一下你正在这样做，再想象一下这会有什么感觉。想象自己成功了，让这种想象给你自信，相信自己为了完成目标会不惜一切。\u000a用这种方法预见失败其实是一种自我同情的方式，而不是自我怀疑的方式。当你真的受到诱惑的时候，你就能有所准备，能将自己的计划付诸实践。'),'16313-16874',NULL,1657381825,1782480567);
INSERT INTO highlights VALUES('837618_28_3409-3551','837618',64,'04 容忍罪恶：为何善行之后会有恶行？',unistr('· 明天和今天毫无区别。当你想改变行为的时候，试着减少行为的变化性，而不是减少某种行为。\u000a· 取消许可，牢记理由。下一回，当你发现自己在用曾经的善行为放纵辩护的时候，停下来想一想你做“好”事的原因，而不是你应不应该得到奖励。'),'20512-20692',NULL,1657381805,1782480567);
INSERT INTO highlights VALUES('837618_22_3273-3515','837618',63,'03 累到无力抵抗：为什么自控力和肌肉一样有极限？',unistr('· 意志力饮食。确保你的身体摄入了足够的食物，能为你提供足够多的能量。\u000a· 意志力锻炼。本周，选择一件事来做（“我想要”的力量）或不做（“我不想”的力量），或者记录一件你不曾关注的事情，以此锻炼你的“自控力肌肉”。\u000a· 发现你的“我想要”的力量。发现自己最重要的“我想要”的力量，也就是你脆弱的时候给你动力的东西。每当你面对诱惑、想要放弃的时候，都想一想这个东西。'),'19732-19998',NULL,1657381780,1782480567);
INSERT INTO highlights VALUES('837618_16_2842-3092','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑',unistr('呼吸出你的自控力。把你的呼吸降到每分钟4-6次，将身体调整到适合自控的生理状态。\u000a· 5分钟给意志力加油。出门活动，哪怕只是在周围转转，也能减少压力、改善心情、提供动力。\u000a· 睡眠。打盹或补觉可以消除睡眠不足的影响。\u000a· 放松能让你恢复意志力储备。躺下，深呼吸，让“放松的生理反应”帮你从自控和压力造成的疲惫中恢复过来。'),'19341-19549',NULL,1657381757,1782480567);
INSERT INTO highlights VALUES('837618_10_1959-2109','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','专心呼吸是一种简单有效的冥想技巧，它不但能训练大脑，还能增强意志力。它能减轻你的压力，指导大脑处理内在的干扰（比如冲动、担忧、欲望）和外在的诱惑（比如声音、画面、气味）。新研究表明，定期的思维训练能帮人戒烟、减肥、戒毒、保持清醒。无论你“要做”和“不要”的是什么，这种5分钟冥想都有助于你增强意志力。','12045-12195',NULL,1657381741,1782480567);
INSERT INTO highlights VALUES('837618_56_1518-1524','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','意志力实验：','8542-8548',NULL,1657381648,1782480567);
INSERT INTO highlights VALUES('837618_50_2776-2787','837618',68,'08 传染：为什么意志力会传染？','意志力实验：自豪的力量','17107-17118',NULL,1657381607,1782480567);
INSERT INTO highlights VALUES('837618_45_2670-2676','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','意志力实验：','8542-8548',NULL,1657381584,1782480567);
INSERT INTO highlights VALUES('837618_40_2334-2353','837618',66,'06 “那又如何”：情绪低落为何会使人屈服于诱惑？','意志力实验：乐观的悲观主义者更可能成功','16262-16281',NULL,1657381560,1782480567);
INSERT INTO highlights VALUES('837618_35_2997-3066','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','为了你的“我要做”挑战释放多巴胺。如果你总是拖延着不做某些事，试着把它和那些能让你的多巴胺神经元燃烧的事联系在一起，促使你自己去做那些事。','21862-21931',NULL,1657381527,1782480567);
INSERT INTO highlights VALUES('837618_35_2958-2964','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','意志力实验：','8542-8548',NULL,1657381525,1782480567);
INSERT INTO highlights VALUES('837618_35_2648-2692','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','我们的大脑错把奖励的承诺当做快乐的保证，所以，我们会从不可能带来满足的事物中寻找满足感。','21451-21495',NULL,1657381508,1782480567);
INSERT INTO highlights VALUES('837618_28_3372-3378','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','意志力实验：','8542-8548',NULL,1657381175,1782480567);
INSERT INTO highlights VALUES('837618_22_3236-3242','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','意志力实验：','8542-8548',NULL,1657381142,1782480567);
INSERT INTO highlights VALUES('837618_16_2803-2809','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','意志力实验：','8542-8548',NULL,1657381076,1782480567);
INSERT INTO highlights VALUES('837618_10_1913-1928','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','意志力实验：5分钟训练大脑冥想','11998-12013',NULL,1657381038,1782480567);
INSERT INTO highlights VALUES('837618_57_1475-1511','837618',70,'10 结语','如果说真的有自控力秘诀，那么从科学的角度来说确实有一个，那就是集中注意力','1253-1289',NULL,1656035951,1782480567);
INSERT INTO highlights VALUES('837618_57_1396-1446','837618',70,'10 结语','自控力最强的人不是从与自我的较量中获得自控，而是学会了如何接受相互冲突的自我，并将这些自我融为一体。','1174-1224',NULL,1656035939,1782480567);
INSERT INTO highlights VALUES('837618_56_1557-1818','837618',69,'09 别读这章：“我不要”力量的局限性',unistr('忠于你的感受，但别相信你所有的想法。当你产生不快的想法时，将注意力转移到身体上，然后专注于呼吸，想象这些想法像浮云一样逐渐淡去。\u000a· 直面自身欲望，但不要付诸行动。当欲望来袭时，注意到它，但不要马上试着转移注意力或与之争论。提醒自己“白熊”现象和“反弹”效应，记住你真正重要的目标。\u000a· 驾驭冲动。当冲动一直存在时，与这些生理上的感觉共处，像驾驭海浪一样驾驭它，不要试图摆脱它，但也不要将冲动付诸行动。'),'20571-20804',NULL,1656000227,1782480567);
INSERT INTO highlights VALUES('837618_55_1852-1911','837618',69,'09 别读这章：“我不要”力量的局限性','学会接受和掌控不愉快的心情，不再一感觉不适就用不健康的习惯（例如吸烟）来获得愉悦，这正是“驾驭冲动”技巧最棒的副作用。','17554-17613',NULL,1656000004,1782480567);
INSERT INTO highlights VALUES('837618_52_2387-2412','837618',69,'09 别读这章：“我不要”力量的局限性','为了阻止你“堕落”, “监控”直接把你引向了堕落。','3522-3546',NULL,1655915367,1782480567);
INSERT INTO highlights VALUES('837618_50_5652-5680','837618',68,'08 传染：为什么意志力会传染？','自控受到社会认同的影响，这使得意志力和诱惑都具有传染性。','20107-20135',NULL,1655888048,1782480567);
INSERT INTO highlights VALUES('837618_50_541-648','837618',68,'08 传染：为什么意志力会传染？','在考虑如何作出选择时，我们经常想象自己是别人评估的对象。研究发现，这为人们自控提供了强大的精神支持。预想自己实现目标（比如戒烟或献血）后会非常自豪的人，更有可能坚持到底并获得成功，预想自己的行为会受到谴责也很有效。','14812-14919',NULL,1655793604,1782480567);
INSERT INTO highlights VALUES('837618_48_6990-7108','837618',68,'08 传染：为什么意志力会传染？','花一点时间去想一想，谁是和你关系密切的人。你和谁在一起的时间最长？你最尊重谁？你觉得谁和自己最像？谁的意见对你来说最重要？你最信任谁，最关心谁？你能不能想到哪些行为（无论是有益的还是有害的）是你从他们身上学来的，或是他们从你身上学到的？','9587-9705',NULL,1655733612,1782480567);
INSERT INTO highlights VALUES('837618_48_3498-3576','837618',68,'08 传染：为什么意志力会传染？','但是，这种自动读心术也有一种自控的副作用：它会激活我们心中的共同目标。心理学家称之为“目标传染病”。研究发现，我们很容易感染别人的目标，从而改变自己的行为。','5993-6071',NULL,1655728046,1782480567);
INSERT INTO highlights VALUES('837618_48_2017-2038','837618',68,'08 传染：为什么意志力会传染？','大脑让我们误入迷途的第二种形式是传染情绪。','4450-4471',NULL,1655727878,1782480567);
INSERT INTO highlights VALUES('837618_48_1466-1478','837618',68,'08 传染：为什么意志力会传染？','第一种形式是无意识的模仿','3899-3911',NULL,1655727871,1782480567);
INSERT INTO highlights VALUES('837618_45_2709-3010','837618',67,'07 出售未来：及时享乐的经济学',unistr('等待10分钟。在诱惑面前强制安排10分钟的等待时间。在这10分钟里，一定要时刻想着长远的奖励，抵制住诱惑。\u000a· 降低你的折扣率。当你受到诱惑，要做和长期利益相悖的事情时，请想一想，这个选择意味着，你为了即时的满足感放弃了更好的长期奖励。\u000a· 预先对未来的自己作出承诺。作好拒绝诱惑的准备，让改变偏好变得更难，用奖励或威胁来激励未来的自己。\u000a· 预见未来的自己。创造一个未来的记忆，给未来的自己发条信息，想象一下未来的自己。'),'23586-23845',NULL,1655727392,1782480567);
INSERT INTO highlights VALUES('837618_44_1588-1647','837618',67,'07 出售未来：及时享乐的经济学','但实际上，我们更可能解救现在的自己，不让他受到太大的压力。我们会给未来的自己增加负担，就好像那时的自己是个陌生人一样。','14402-14461',NULL,1655725327,1782480567);
INSERT INTO highlights VALUES('837618_43_4417-4485','837618',67,'07 出售未来：及时享乐的经济学','这种方法之所以有效，是因为有人对参与者负责任，支持他们实现目标。有没有这么一个人，你能和他分享你的目标，能在你感觉受诱惑时寻求他的帮助？','13076-13144',NULL,1655654060,1782480567);
INSERT INTO highlights VALUES('837618_39_4134-4241','837618',66,'06 “那又如何”：情绪低落为何会使人屈服于诱惑？','众多研究显示，自我批评会降低积极性和自控力，而且也是最容易导致抑郁的因素。它不仅耗尽了“我要做”的力量，还耗尽了“我想要”的力量。相反，自我同情则会提升积极性和自控力，比如，在压力和挫折面前支持自己、对自己好一些。','11553-11660',NULL,1655642257,1782480567);
INSERT INTO highlights VALUES('837618_38_3632-3723','837618',66,'06 “那又如何”：情绪低落为何会使人屈服于诱惑？','请花上24个小时，远离那些会让你产生恐惧的电视新闻、访谈节目、杂志或网页。如果你觉得自己不关注那些正在发生的大事小事，世界末日也不会降临的话，就请别在这些媒体上毫无意义地消磨时光了。','7596-7687',NULL,1655641666,1782480567);
INSERT INTO highlights VALUES('837618_38_2100-2119','837618',66,'06 “那又如何”：情绪低落为何会使人屈服于诱惑？','这种焦虑会让吸烟者用默认的方法缓解压力','6023-6042',NULL,1655641503,1782480567);
INSERT INTO highlights VALUES('837618_37_1031-1054','837618',66,'06 “那又如何”：情绪低落为何会使人屈服于诱惑？','当你面对压力时，你面前的所有诱惑都会更有诱惑力','1957-1980',NULL,1655640838,1782480567);
INSERT INTO highlights VALUES('837618_35_2171-2219','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','如果我们想拥有自控力，就需要区分让我们的生活有意义的真实奖励，和让我们分散精力、上瘾的虚假奖励。','20933-20981',NULL,1655640465,1782480567);
INSERT INTO highlights VALUES('837618_34_1174-1205','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','我们没有意识到，我们渴望的东西既是快乐的源泉，也是压力的源泉。','15856-15887',NULL,1655639311,1782480567);
INSERT INTO highlights VALUES('837618_32_3290-3329','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','一点小小的奖励承诺就能成为缓解焦虑的良药，就能帮助人们走近自己本想逃离的东西。','11481-11520',NULL,1655544724,1782480567);
INSERT INTO highlights VALUES('837618_31_542-550','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','警醒、清醒、着迷','4521-4529',NULL,1655544231,1782480567);
INSERT INTO highlights VALUES('837618_31_1270-1337','837618',65,'05 大脑的弥天大谎：为什么我们误把渴望当幸福？','多巴胺控制的是行动，而不是快乐。奖励的承诺保证了被试者成功地行动，从而获得奖励。当奖励系统活跃的时候，他们感受到的是期待，而不是快乐。','5249-5316',NULL,1655531467,1782480567);
INSERT INTO highlights VALUES('837618_28_2250-2375','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','想要走出“道德许可”的陷阱，我们就要知道，那个想变好的自己才是真正的自己，想按核心价值观生活的自己。如此一来，我们就不会认为那个冲动、懒散、容易受诱惑的自己是“真正”的自己了。我们就不会再表现得像个必须被强迫完成目标、然后为作出的努力索要奖励的人了。','19282-19407',NULL,1655528523,1782480567);
INSERT INTO highlights VALUES('837618_27_3199-3227','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','省钱不再是买到便宜的东西，而是在支出限额内买到便宜的东西','17201-17229',NULL,1655528258,1782480567);
INSERT INTO highlights VALUES('837618_26_4357-4492','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','把你今天作的每个决定都看成是对今后每天的承诺。因此，不要问自己“我现在想不想吃这块糖？”，而要问自己“我想不想在一年里每天下午都吃一块糖？”或者，你明知道应该做一件事情却拖延不做时，不要问自己“我是想今天做还是明天做？”，而要问自己“我是不是想承担永远拖延下去的恶果？”','13095-13230',NULL,1655483168,1782480567);
INSERT INTO highlights VALUES('837618_26_3411-3438','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','请不要作出理想状态下的假设，请根据你的实际情况作出预测','12129-12156',NULL,1655482933,1782480567);
INSERT INTO highlights VALUES('837618_26_2542-2677','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','当你要作与意志力挑战有关的决定时，注意一下，你脑海中是否闪过了“未来再好好表现”的承诺。你是不是告诉自己，明天会弥补今天的过错？这对你当下的自控有什么影响？一直保持关注，从今天一直关注到明天。你是不是真的做到了你所说的？或者，“今天放纵，明天改变”的循环是不是又开始了？','11239-11374',NULL,1655482862,1782480567);
INSERT INTO highlights VALUES('837618_25_2613-2659','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','下一回，当你发现自己在用曾经的善行给现在的放纵作辩护时，停下来想一想，你当时为什么能拒绝诱惑','8928-8974',NULL,1655447307,1782480567);
INSERT INTO highlights VALUES('837618_25_2476-2499','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','记住我们为什么会拒绝诱惑，这是个很有效的办法。','8791-8814',NULL,1655447288,1782480567);
INSERT INTO highlights VALUES('837618_24_2385-2475','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','他们这样为自己辩解：“我已经这么好了，应该得到一点奖励。”这种对补偿的渴望常常使我们堕落。因为我们很容易认为，纵容自己就是对美德最好的奖励。我们忘记了自己真正的目标，向诱惑屈服了。','3705-3795',NULL,1655369854,1782480567);
INSERT INTO highlights VALUES('837618_24_2229-2266','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','简单说来，只要我们的思想中存在正反两方，好的行为就总是允许我们做一点坏事。','3549-3586',NULL,1655369833,1782480567);
INSERT INTO highlights VALUES('837618_23_1752-1871','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','我们要思考一下，这整个过程如何削弱了我们的动力，乐观精神如何允许我们放纵自己，为什么觉得自己品德高尚反而是通往罪恶的快速通道。每一次我们都会发现，放弃抵抗是一种选择，而且并非不可避免。了解我们是如何给自己许可的，能让我们学会如何不离正轨。','1530-1649',NULL,1655366204,1782480567);
INSERT INTO highlights VALUES('837618_23_1507-1550','837618',64,'04 容忍罪恶：为何善行之后会有恶行？','不是每一次自控力失效都是因为真的失去了控制。有时，我们是有意识地选择了在诱惑面前屈服。','1285-1328',NULL,1655366160,1782480567);
INSERT INTO highlights VALUES('837618_22_2957-2998','837618',63,'03 累到无力抵抗：为什么自控力和肌肉一样有极限？','核心思想：自控力就像肌肉一样有极限。自控力用得太多会疲惫，但坚持训练能增强自控力。','19392-19433',NULL,1655365929,1782480567);
INSERT INTO highlights VALUES('837618_21_1857-1880','837618',63,'03 累到无力抵抗：为什么自控力和肌肉一样有极限？','疲惫不是一种身体反应，而是一种感觉，一种情绪。','13326-13349',NULL,1654736314,1782480567);
INSERT INTO highlights VALUES('837618_19_1953-2019','837618',63,'03 累到无力抵抗：为什么自控力和肌肉一样有极限？','自控时大脑每分钟需要的能量不会超过跑酷运动所需能量的一半。自控可能比大脑处理其他问题时所用的能量多，但远远低于身体运动时所需的能量。','5678-5744',NULL,1654699250,1782480567);
INSERT INTO highlights VALUES('837618_16_2533-2567','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','意志力是种生理本能，它和压力一样，通过不断进化来保护我们不受自身伤害','18956-18990',NULL,1654698582,1782480567);
INSERT INTO highlights VALUES('837618_16_875-897','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','从长远的角度看，没有什么比压力更消耗意志力了','17237-17259',NULL,1654697477,1782480567);
INSERT INTO highlights VALUES('837618_15_831-864','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','长时间的自控就像慢性压力一样，会削弱免疫系统的功能，增大患病的概率','15309-15342',NULL,1654697270,1782480567);
INSERT INTO highlights VALUES('837618_15_481-534','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','但自控力也是有代价的。集中注意力、权衡目标、缓解压力、克制欲望等所有这些脑力工作都需要能量，真正的身体能量','14959-15012',NULL,1654689401,1782480567);
INSERT INTO highlights VALUES('837618_14_5976-6082','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','如果你明知道自己能获得更多的睡眠，却没法早点入睡，那就不要想睡觉这件事，想一想你到底对什么说了“我想要”。这个意志力法则同样适用于你想逃避或拖延的事——当你不知道自己想做什么的时候，你或许需要知道自己不想做什么。','14701-14807',NULL,1654689373,1782480567);
INSERT INTO highlights VALUES('837618_14_5712-5782','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','如果我们将“获得更多睡眠”定义为“我不要”的意志力挑战，那么事情就说得通了。真正的问题并不是强迫自己去睡觉，而是远离那些让自己没法睡觉的事。','14439-14509',NULL,1654689345,1782480567);
INSERT INTO highlights VALUES('837618_14_4772-4795','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','因此，如果你想获得更强的意志力，那就早点休息吧','13458-13481',NULL,1654689276,1782480567);
INSERT INTO highlights VALUES('837618_14_4709-4754','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','一项研究中，每天5分钟的冥想训练帮助患者恢复了睡眠，让他们每天的有效睡眠时间增加了1个小时','13395-13440',NULL,1654689268,1782480567);
INSERT INTO highlights VALUES('837618_14_4494-4522','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','警报系统不再受到审查，因此它对所有普通的压力都会反应过度','13180-13208',NULL,1654689244,1782480567);
INSERT INTO highlights VALUES('837618_14_3665-3706','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','如果你觉得锻炼太累了，或是没有时间锻炼，那么不妨将锻炼当做恢复体能和意志力的方法。','12330-12371',NULL,1654689092,1782480567);
INSERT INTO highlights VALUES('837618_14_2223-2248','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','任何能让你离开椅子的活动，都能提高你的意志力储备。','10894-10919',NULL,1654688970,1782480567);
INSERT INTO highlights VALUES('837618_14_1062-1079','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','意志力的奇迹实际上来自身体的训练。','9734-9751',NULL,1654688937,1782480567);
INSERT INTO highlights VALUES('837618_14_1668-1700','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','改善心情、缓解压力的最有效的锻炼是每次5分钟，而不是每次几小时。','10340-10372',NULL,1654682418,1782480567);
INSERT INTO highlights VALUES('837618_14_1456-1469','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','白质能迅速有效地连通脑细胞','10128-10141',NULL,1654682393,1782480567);
INSERT INTO highlights VALUES('837618_14_1410-1452','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','神经生物学家在检查这些刚开始锻炼的人的时候，发现他们大脑里产生了更多的细胞灰质和白质','10082-10124',NULL,1654682388,1782480567);
INSERT INTO highlights VALUES('837618_14_1252-1297','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','事实证明，科学家找到的自控力良药竟然是锻炼！对起步者来说，锻炼对意志力的效果是立竿见影的。','9924-9969',NULL,1654682355,1782480567);
INSERT INTO highlights VALUES('837618_13_3484-3834','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','这本书不会教给你什么捷径，但能告诉你一种快速提高意志力的方法：将呼吸频率降低到每分钟4-6次，也就是每次呼吸用10-15秒时间，比平常呼吸要慢一些。只要你有足够的耐心，加上必要的练习，这一点不难办到。放慢呼吸能激活前额皮质、提高心率变异度，有助于你的身心从压力状态调整到自控力状态。这样训练几分钟之后，你就会感到平静、有控制感，能够克制欲望、迎接挑战。','7860-8036',NULL,1654682154,1782480567);
INSERT INTO highlights VALUES('837618_13_2722-2739','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','心率变异度能很好地反映意志力的程度','7078-7095',NULL,1654681856,1782480567);
INSERT INTO highlights VALUES('837618_13_2023-2028','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','心率变异度','6379-6384',NULL,1654681740,1782480567);
INSERT INTO highlights VALUES('837618_13_1836-1932','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','虽然“三思而后行”和应激反应都是人类天性中的一部分，但你可能发现它们看起来不像本能。反而，吃奶酪蛋糕才更像人的本能。想了解为何意志力本能不是总能生效，我们需要深入了解压力和自控力的生理学基础。','6171-6267',NULL,1654681720,1782480567);
INSERT INTO highlights VALUES('837618_13_721-744','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','的起因是你意识到了内在的冲突，而不是外在的威胁','5035-5058',NULL,1654679613,1782480567);
INSERT INTO highlights VALUES('837618_13_697-702','837618',63,'03 累到无力抵抗：为什么自控力和肌肉一样有极限？','三思而后行','10242-10247',NULL,1654679607,1782480567);
INSERT INTO highlights VALUES('837618_12_2011-2048','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','应激反应是一种管理能量的本能，这种本能决定了你将如何利用有限的体力和脑力。','2948-2985',NULL,1654663225,1782480567);
INSERT INTO highlights VALUES('837618_12_1685-1715','837618',62,'02 意志力的本能：人生来就能抵制奶酪蛋糕的诱惑','警报系统会在大脑里产生复杂的化学反应，阻止前额皮质发挥作用。','2622-2652',NULL,1654663187,1782480567);
INSERT INTO highlights VALUES('837618_10_4370-4490','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？',unistr('· 记录你的意志力选择。至少选一天，注意观察你做的关于意志力的决定。\u000a· 5分钟大脑训练冥想。在脑海中默念“呼”和“吸”，把注意力集中在呼吸上。当你开始走神的时候，重新集中注意力。'),'14540-14698',NULL,1654662825,1782480567);
INSERT INTO highlights VALUES('837618_10_3550-3586','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','自控力是一个过程，在这个过程中，人们不断偏离目标，又不断把注意力收回来。','13657-13693',NULL,1654662675,1782480567);
INSERT INTO highlights VALUES('837618_10_2390-3000','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？',unistr('2．注意你的呼吸。\u000a闭上眼睛。要是怕睡着，你可以盯着某处看，比如盯着一面白墙，但不要看家庭购物频道。注意你的呼吸。吸气时在脑海中默念“吸”，呼气时在脑海中默念“呼”。当你发现自己有点走神的时候，重新将注意力集中到呼吸上。这种反复的注意力训练，能让前额皮质开启高速模式，让大脑中处理压力和冲动的区域更加稳定。\u000a3．感受呼吸，弄清自己是怎么走神的。\u000a几分钟后，你就可以不再默念“呼”、“吸”了。试着专注于呼吸本身。你会注意到空气从鼻子和嘴巴进入和呼出的感觉，感觉到吸气时胸腹部的扩张和呼气时胸腹部的收缩。不再默念“呼”、“吸”后，你可能更容易走神。像之前一样，当你发现自己在想别的事情时，重新将注意力集中到呼吸上。如果你觉得很难重新集中注意力，就在心里多默念几遍“呼”和“吸”。这部分的训练能锻炼你的自我意识和自控能力。\u000a刚开始的时候，你每天锻炼5分钟就行。习惯成自然之后，请试着每天做10-15分钟。如果你觉得有负担，那就减少到5分钟。每天做比较短的训练，也比把比较长的训练拖到明天好。这样，你每天都会有一段固定的时间冥想，比如早晨洗澡之前。如果你做不到，可以对时间进行适当的调整。'),'12476-13086',NULL,1654579175,1782480567);
INSERT INTO highlights VALUES('837618_10_2180-2189','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','原地不动，安静坐好','12266-12275',NULL,1654579128,1782480567);
INSERT INTO highlights VALUES('837618_10_1524-1678','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','研究发现，经过仅仅3个小时的冥想练习，他们的注意力和自控力就有大幅提高。11个小时后，研究人员已经能观察到大脑的变化。刚学会冥想的人大脑里负责控制注意力、排除干扰、控制冲动的区域之间增加了许多类神经元。另一项研究发现，持续8周的日常冥想训练可以提升人们日常生活中的自我意识，相应大脑区域里的灰质也会随之增多。','11590-11744',NULL,1654579074,1782480567);
INSERT INTO highlights VALUES('837618_10_646-733','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','人脑像一个求知欲很强的学生，对经验有着超乎大家想象的反应。如果你每天都让大脑学数学，它就会越来越擅长数学。如果你让它忧虑，它就会越来越忧虑。如果你让它专注，它就会越来越专注。','10712-10799',NULL,1654578945,1782480567);
INSERT INTO highlights VALUES('837618_9_4146-4241','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','请至少选一天，把你作的决定都记下来。在这一天结束的时候，回想你作的决定，分析哪些有利于你实现目标，哪些会消磨你的意志。坚持记录你的决定，还有助于减少在注意力分散时作决定，同时增强你的意志力。','9487-9582',NULL,1654578821,1782480567);
INSERT INTO highlights VALUES('837618_8_3017-3057','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','前额皮质并非始终可靠，醉酒、缺觉、分心等都会影响到它，使我们无法控制自己的冲动。','5427-5467',NULL,1654577765,1782480567);
INSERT INTO highlights VALUES('837618_7_1439-1499','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','顽强的意志力是一个人最突出的优点。自控力比智商更有助于拿高分，比个人魅力更有助于领导别人，比同理心更有助于维持婚姻幸福。','2553-2613',NULL,1654363373,1782480567);
INSERT INTO highlights VALUES('837618_7_1226-1242','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','为什么直到今天，意志力仍然很重要','2339-2355',NULL,1654363346,1782480567);
INSERT INTO highlights VALUES('837618_7_1170-1196','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','意志力是一种抑制冲动的能力，它使我们成为了真正的人。','2263-2289',NULL,1654363314,1782480567);
INSERT INTO highlights VALUES('837618_7_1097-1125','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','为了适应环境、与人合作、维持关系，人脑很早就学会了自控。','2190-2218',NULL,1654363303,1782480567);
INSERT INTO highlights VALUES('837618_6_1329-1364','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','想要做到自控，你就得在关键时刻明确自己的目标。这就是“我想要”的力量。','1108-1143',NULL,1654363151,1782480567);
INSERT INTO highlights VALUES('837618_6_1138-1224','837618',61,'01 我要做，我不要，我想要：什么是意志力？为什么意志力至关重要？','“我要做”和“我不要”是自控的两种表现，但它们不是意志力的全部。要想在需要“说不”时“说不”，在需要“说好”时“说好”，你还得有第三种力量：那就是牢记自己真正想要的是什么。','917-1003',NULL,1654363126,1782480567);
INSERT INTO highlights VALUES('837618_5_3056-3302','837618',60,'导言 欢迎阅读意志力入门',unistr('* “我要做”意志力挑战：有没有什么事是你想多做一些的，或是停止拖延的，因为你知道这样做能提高你的生活质量？\u000a* “我不要”意志力挑战：你生活中最“顽固”的习惯是什么？有什么是你想放弃，或者想少做一点的，因为它妨害了你的健康、幸福甚至成功？\u000a* “我想要”意志力挑战：你最想集中精力完成哪一项重要的长远目标？哪种当下的“渴望”最有可能分散你的注意力、诱惑你远离自己的目标？'),'6053-6316',NULL,1654362218,1782480567);
INSERT INTO highlights VALUES('837618_5_1905-1995','837618',60,'导言 欢迎阅读意志力入门','你的意志力挑战可能是你逃避的事（我们称为“我要做”的意志力挑战）或者你想改掉的习惯（“我不要”的意志力挑战），也可以是你愿意花更多精力去关注的重要生活目标（“我想要”的意志力挑战）','4872-4962',NULL,1654362002,1782480567);
INSERT INTO highlights VALUES('837618_5_901-964','837618',60,'导言 欢迎阅读意志力入门','在做每一个作业时，试着带上观察者的眼光，没有偏见、保持好奇心，就像一名通过显微镜作观察的科学家一样，期待发现有趣且有用的东西。','3847-3910',NULL,1654361881,1782480567);
INSERT INTO highlights VALUES('837618_3_1907-1964','837618',60,'导言 欢迎阅读意志力入门','对意志力科学的理解有助于他们培养自控力，让他们更有精力去追逐最重要的东西。科学的洞见对于戒酒者和戒网瘾者同样有效。','1790-1847',NULL,1654361665,1782480567);
INSERT INTO highlights VALUES('837618_3_653-679','837618',60,'导言 欢迎阅读意志力入门','所谓意志力，就是控制自己的注意力、情绪和欲望的能力。','536-562',NULL,1654338575,1782480567);
INSERT INTO highlights VALUES('22791651_237_3892-3927','22791651',237,'第十二品 尊重正教分','“万缘放却只低眉”，所以菩萨慈目低眉，眼睛一闭，一打坐，万缘都放下了。','3892-3927',0,1780417937,1782480547);
INSERT INTO highlights VALUES('22791651_237_3144-3234','22791651',237,'第十二品 尊重正教分','做人做事就是一个恭敬的敬，就是儒家所讲的敬。一个人能够敬己，然后才可以敬人；敬别人，恭敬别人，也就是可以敬自己。一念的诚敬，当下就可以证到佛的境界，所以这一段的道理，是叫我们正信。','3144-3234',0,1780417722,1782480547);
INSERT INTO highlights VALUES('22791651_236_5354-5412','22791651',236,'第十一品 无为福胜分','世界上最值钱的东西也最不值钱，最值钱的东西没有价钱，智慧是绝对无价；但是智慧也一毛钱都不值，这就是佛常说的众生颠倒。','5354-5412',0,1780232264,1782480547);
INSERT INTO highlights VALUES('22791651_235_5112-5137','22791651',235,'第十品 庄严净土分','。所以说我们一切应无所住而生其心，此心本如羚羊挂角','5112-5137',0,1778750002,1782480547);
INSERT INTO highlights VALUES('22791651_235_4850-4892','22791651',235,'第十品 庄严净土分','“若留净土即留尘”，你心中还有一个净土，认为是佛境界，这个清净就是尘，留尘就是障碍。','4850-4892',0,1778749957,1782480547);
INSERT INTO highlights VALUES('22791651_235_4086-4145','22791651',235,'第十品 庄严净土分','不生不死的法身，也是一句抽象的话，佛法只有实证，你证到了以后才知道，是法不可说，不可说，凡是说的都不对，这个就是法身。','4086-4145',0,1778749837,1782480547);
INSERT INTO highlights VALUES('22791651_235_2978-3006','22791651',235,'第十品 庄严净土分','不应住色生心。不应住声香味触法生心。应无所住。而生其心。','2978-3006',0,1778749345,1782480547);
INSERT INTO highlights VALUES('22791651_234_15231-15266','22791651',234,'第九品 一相无相分','学大乘的啊，想要跳出这个世界的牢笼，要跟牢犯、阎王、看守都变成朋友才行','15231-15266',0,1778746851,1782480547);
INSERT INTO highlights VALUES('22791651_234_6874-6920','22791651',234,'第九品 一相无相分','这个意思是一个悟道的人，能不能逢人便说他已经悟道了？如果真有人如此，大家不把他送疯人院才怪。','6874-6920',0,1778740993,1782480547);
INSERT INTO highlights VALUES('22791651_234_5936-5975','22791651',234,'第九品 一相无相分','一个人要把心中的贪瞋痴慢疑洗刷干净，平等，慈悲，爱一切世人，设法除掉见思两惑。','5936-5975',0,1778740738,1782480547);
INSERT INTO highlights VALUES('22791651_234_3909-3958','22791651',234,'第九品 一相无相分','余情是剩余下来的情感，断不了的，还是要七还人间才能了。如果七还人间时，不晓得再进修，还是会后退的。','3909-3958',0,1778740416,1782480547);
INSERT INTO highlights VALUES('22791651_234_3609-3679','22791651',234,'第九品 一相无相分','所以贪、瞋、痴、慢、疑这五样，是思惑，思想上根本障道，不能解脱。学佛是求解脱，能解脱一样已经是了不起了，五样都能解脱了，才能够证到四果罗汉。','3609-3679',0,1778740319,1782480547);
INSERT INTO highlights VALUES('22791651_234_1404-1448','22791651',234,'第九品 一相无相分','“见惑”有五个，是思想上，学问上，观念上的问题；就是身见、边见、见取见、邪见、戒禁取见。','1404-1448',0,1778739852,1782480547);
INSERT INTO highlights VALUES('22791651_234_1487-1503','22791651',234,'第九品 一相无相分','思想学问愈高的人，这个五见愈厉害','1487-1503',0,1778739850,1782480547);
INSERT INTO highlights VALUES('22791651_233_4012-4082','22791651',233,'第八品 依法出生分','佛法的目的是什么呢？我们被人世间一切的烦恼感情捆缚着，要解脱三界的情欲、烦恼、妄想，脱开了一切的黏缚，回到自己本来的面目，这就是佛法的究竟。','4012-4082',0,1778739678,1782480547);
INSERT INTO highlights VALUES('22791651_233_1523-1593','22791651',233,'第八品 依法出生分','但是，假使有一个人，对《金刚经》或者四句偈有些了解了，再劝导人家，解脱了人家的烦恼，这个人的福报，比布施三千大千世界七宝的福报，还要来得大。','1523-1593',0,1778736598,1782480547);
INSERT INTO highlights VALUES('22791651_232_3016-3072','22791651',232,'第七品 无得无说分','治生产业就是大家谋生！或做生意等，各种生活的方式，皆与实相不相违背，同那个基本的形而上道，并没有违背，并没有两样','3016-3072',0,1778701212,1782480547);
INSERT INTO highlights VALUES('22791651_232_2587-2621','22791651',232,'第七品 无得无说分','真正到达了佛境界是包容万象，也否定了万象，也建立了万象，这是佛境界。','2587-2621',0,1778692339,1782480547);
INSERT INTO highlights VALUES('22791651_231_8714-8727','22791651',231,'第六品 正信希有分','埋的是慈悲，不埋的是解脱。','8714-8727',0,1778691059,1782480547);
INSERT INTO highlights VALUES('22791651_231_8312-8365','22791651',231,'第六品 正信希有分','所以这个人很难做，认真不认真之间，很难拿准火候；所以不应取法，不应取非法，就是这个道理，就是讲做人的行为。','8312-8365',0,1778690983,1782480547);
INSERT INTO highlights VALUES('22791651_231_7639-7730','22791651',231,'第六品 正信希有分','这四段的反复说明，反正你讲空也不对，不是佛法，执着有也不是佛法，非空非有也不对，即空即有也不是佛法。这很难办了，所以真正佛法是能断金刚般若波罗蜜，要想悟道，是在这个地方，是要真智慧。','7639-7730',0,1778690652,1782480547);
INSERT INTO highlights VALUES('22791651_231_6590-6601','22791651',231,'第六品 正信希有分','“离一切相，即一切法”','6590-6601',0,1778690200,1782480547);
INSERT INTO highlights VALUES('22791651_231_5772-5798','22791651',231,'第六品 正信希有分','一念放下，当然无我相，也无人相，无众生相，无寿者相。','5772-5798',0,1778690019,1782480547);
INSERT INTO highlights VALUES('22791651_231_2335-2373','22791651',231,'第六品 正信希有分','也就是禅宗祖师们后来说的“佛来斩佛，魔来斩魔”的道理，这也是修行的无上秘诀。','2335-2373',0,1778687327,1782480547);
INSERT INTO highlights VALUES('22791651_231_2166-2204','22791651',231,'第六品 正信希有分','他拿起锅铲一边就打过去，一边嘴里说：文殊是文殊，文喜是文喜，你跑来这里干什么','2166-2204',0,1778687291,1782480547);
INSERT INTO highlights VALUES('22791651_231_2024-2069','22791651',231,'第六品 正信希有分','文喜禅师因为自己悟了道，愿意发心为大家做苦差事，行人所不能行，忍人所不能忍，这就是菩萨道。','2024-2069',0,1778687253,1782480547);
INSERT INTO highlights VALUES('22791651_230_6938-7034','22791651',230,'第五品 如理实见分','更有趣的是，有些人昨天夜里做的好梦，今天他还坐在那里想，还舍不得离开梦境，所以人生就很妙，觉时恋梦，醒了以后还贪恋那个梦。做梦的时候呢，又想自己快一点醒才好，你说究竟哪一样好？自己都搞不清楚。','6938-7034',0,1778686640,1782480547);
INSERT INTO highlights VALUES('22791651_230_3456-3478','22791651',230,'第五品 如理实见分','一念不生全体现，也是指的法身，法身是无相的。','3456-3478',0,1776959475,1782480547);
INSERT INTO highlights VALUES('22791651_230_3007-3036','22791651',230,'第五品 如理实见分','成佛有三身，清净是法身，圆满是报身，千百亿形象不同是化身。','3007-3036',0,1776946233,1782480547);
INSERT INTO highlights VALUES('22791651_230_2083-2111','22791651',230,'第五品 如理实见分','佛告须菩提。凡所有相。皆是虚妄。若见诸相非相。即见如来。','2083-2111',0,1776782956,1782480547);
INSERT INTO highlights VALUES('22791651_260_10791-10817','22791651',260,'第四品 妙行无住分','佛说：他啊，当时就是以这个大便供养我，所以跟我结了缘','10791-10817',0,1776704158,1782480547);
INSERT INTO highlights VALUES('22791651_260_10023-10073','22791651',260,'第四品 妙行无住分','因为你是有心，是住相。小孩子拿着沙子，他看那个沙子就像黄金一样，一念的诚意供养，所以叫做不住相布施。','10023-10073',0,1776628907,1782480547);
INSERT INTO highlights VALUES('22791651_260_8657-8685','22791651',260,'第四品 妙行无住分','《金刚经》告诉你，真正的福德要怎样修呢？就是不住相布施。','8657-8685',0,1776628630,1782480547);
INSERT INTO highlights VALUES('22791651_260_4614-4623','22791651',260,'第四品 妙行无住分','风来竹面，雁过长空','4614-4623',0,1776387957,1782480547);
INSERT INTO highlights VALUES('22791651_260_2615-2661','22791651',260,'第四品 妙行无住分','“极迥色”，远大得很，延伸到银河系统那一边的，包括了整个宇宙中间的这一些东西，称之为极迥色。','2615-2661',0,1776387523,1782480547);
INSERT INTO highlights VALUES('22791651_260_2369-2393','22791651',260,'第四品 妙行无住分','无表色”是属于精神方面的，是抽象的，没有办法表示','2369-2393',0,1776387489,1782480547);
INSERT INTO highlights VALUES('22791651_260_1792-1886','22791651',260,'第四品 妙行无住分','“应无所住，行于布施”，什么叫修行？念念皆空，随时丢，物来则应，过去不留；就算做了一件好事，做完了就没有了，心中不存。连好事都不存在心中，坏事当然不会去做了，处处行于布施，随时随地无所住。','1792-1886',0,1776387376,1782480547);
INSERT INTO highlights VALUES('22791651_260_1693-1763','22791651',260,'第四品 妙行无住分','此心应该随时随地无所住，如果你此心随时在空的境界上，那已经错了，因为你住在空上；如说此心住在光明上，或住在气脉上，都错了，因为那不是无所住。','1693-1763',0,1776387362,1782480547);
INSERT INTO highlights VALUES('22791651_228_5859-5915','22791651',228,'第三品 大乘正宗分','佛经上说，一个学佛的人，你首先观察他有没有发起厌离心，也就是说厌烦世间的洪福，对洪福有厌离心，才是走向学佛之路。','5859-5915',0,1775823091,1782480547);
INSERT INTO highlights VALUES('22791651_228_10117-10181','22791651',228,'第三品 大乘正宗分','本经的原文，佛说这四相，用现在的话来讲，这四相是人类众生共通的、牢不可破的、顽固的主观观念。要把这个观念破除掉，学佛就差不多了。','10117-10181',0,1775823091,1782480547);
INSERT INTO highlights VALUES('22791651_228_8528-8552','22791651',228,'第三品 大乘正宗分','佛不过把他成就的方法告诉我们，你要自己修持才行。','8528-8552',0,1775823091,1782480547);
INSERT INTO highlights VALUES('22791651_228_5803-5847','22791651',228,'第三品 大乘正宗分','一个人先要养成会享受寂寞，那你就差不多了，可以了解人生了，才体会到人生更高远的一层境界。','5803-5847',0,1775823090,1782480547);
INSERT INTO highlights VALUES('22791651_228_1195-1279','22791651',228,'第三品 大乘正宗分','佛要教化一切众生，慈爱一切众生，对好的要慈悲，对坏的更要慈悲。好人要度，要教化，坏人更要教化。天堂的人要度，地狱里的更可怜，更要度。这是佛法的精神，所以说要度一切众生。','1195-1279',0,1775753374,1782480547);
INSERT INTO highlights VALUES('22791651_228_791-814','22791651',228,'第三品 大乘正宗分','因为那个时机过去了，禅宗所谓机，这个禅机过去了','791-814',0,1775753284,1782480547);
INSERT INTO highlights VALUES('22791651_227_16338-16393','22791651',227,'第二品 善现启请分','烦恼的自性本来是空的，所有的喜怒哀乐，忧悲苦恼，当我们在这个位置上坐下来的时候，一切都没有了，永远拉不回来了。','16338-16393',0,1775664734,1782480547);
INSERT INTO highlights VALUES('22791651_227_16209-16255','22791651',227,'第二品 善现启请分','老年人常回忆，想当年我如何如何……那真是自寻烦恼，因为一切事不能回头的，像春梦一样了无痕的。','16209-16255',0,1775664708,1782480547);
INSERT INTO highlights VALUES('22791651_227_15862-15880','22791651',227,'第二品 善现启请分','住即不住，不住即住。无所住，即是住。','15862-15880',0,1775664616,1782480547);
INSERT INTO highlights VALUES('22791651_227_15835-15855','22791651',227,'第二品 善现启请分','所以大乘佛法，如何才能安住？无所住即是住','15835-15855',0,1775664609,1782480547);
INSERT INTO highlights VALUES('22791651_227_15033-15086','22791651',227,'第二品 善现启请分','你问问题的时候，你的心已经没有烦恼了，就在这个时候，就是禅宗所谓当下即是，当念即是，不要另外去想一个方法。','15033-15086',0,1775664498,1782480547);
INSERT INTO highlights VALUES('22791651_227_13452-13537','22791651',227,'第二品 善现启请分','所谓真正的定，佛经有一句话：如香象渡河，截流而过。一个有大智慧、大气魄的人，自己的思想、妄念，立刻可以切断，就像香象渡河一般，连弯都懒得转，便在湍急河水之中，截流而过了。','13452-13537',0,1775664102,1782480547);
INSERT INTO highlights VALUES('22791651_227_9419-9438','22791651',227,'第二品 善现启请分','所以一切要自求多福，佛法就是这个道理。','9419-9438',0,1774945278,1782480547);
INSERT INTO highlights VALUES('22791651_227_8924-8990','22791651',227,'第二品 善现启请分','佛法既认为一切众生个个是佛，平等平等，但是，为什么众生不能成佛呢？因为他找不到自心，迷失了。如果自己觉悟了，不再迷失，个个自性成佛。','8924-8990',0,1774945183,1782480547);
INSERT INTO highlights VALUES('22791651_227_5197-5224','22791651',227,'第二品 善现启请分','菩萨是如来的前因，成了佛如来是菩萨的果位，成就的果位。','5197-5224',0,1774944209,1782480547);
INSERT INTO highlights VALUES('22791651_227_4803-4868','22791651',227,'第二品 善现启请分','就是说他是入世的，外形虽是入世的，心却是出世的，所以菩萨境界谓之大乘。罗汉境界住空，不敢入世，一切不敢碰，眼不见心不烦，只管自己。','4803-4868',0,1774944050,1782480547);
INSERT INTO highlights VALUES('22791651_227_4510-4542','22791651',227,'第二品 善现启请分','禅宗则称之谓担板汉，挑一个板子走路，只看到这一面，看不见另一面。','4510-4542',0,1774943986,1782480547);
INSERT INTO highlights VALUES('22791651_227_4452-4485','22791651',227,'第二品 善现启请分','专心于自己的修行，也就是放弃一切而成就自己的道，叫做小乘罗汉的境界','4452-4485',0,1774943978,1782480547);
INSERT INTO highlights VALUES('22791651_227_4314-4358','22791651',227,'第二品 善现启请分','世界上最多情的人是佛，是菩萨，也就是觉悟有情。“菩萨”是佛弟子中，走大乘路线的一个总称。','4314-4358',0,1774943845,1782480547);
INSERT INTO highlights VALUES('22791651_227_3932-3971','22791651',227,'第二品 善现启请分','所谓的觉悟，觉悟什么呢？就是佛的境界，也就是所谓自利利他，自觉觉他的这个觉悟。','3932-3971',0,1774943701,1782480547);
INSERT INTO highlights VALUES('22791651_227_3838-3850','22791651',227,'第二品 善现启请分','采用梵文的音，简译成菩萨','3838-3850',0,1774943668,1782480547);
INSERT INTO highlights VALUES('22791651_227_3799-3815','22791651',227,'第二品 善现启请分','菩提的意思就是觉悟，萨埵是有情。','3799-3815',0,1774943630,1782480547);
INSERT INTO highlights VALUES('22791651_227_656-699','22791651',227,'第二品 善现启请分','善现就是“须菩提”，是中文的意译，意思是他的人生境界，是道德的至善，表现出来的是长寿。','656-699',0,1774943050,1782480547);
INSERT INTO highlights VALUES('22791651_227_870-896','22791651',227,'第二品 善现启请分','一般都知道须菩提谈空第一，这一本经就是空和有的研究。','870-896',0,1774943047,1782480547);
INSERT INTO highlights VALUES('22791651_226_7959-7995','22791651',226,'第一品 法会因由分','我们现在看到出家人站在门口拿个引磬叮叮，那个就是释迦牟尼佛留下来的风范。','7959-7995',0,1774942635,1782480547);
INSERT INTO highlights VALUES('22791651_226_4634-4693','22791651',226,'第一品 法会因由分','所谓这个世界，不是只讲这个人世间；佛学里所谓世间，有三世间与四世间两种概念。所谓三世间是：器世间、国土世间、有情世间。','4634-4693',0,1774767039,1782480547);
INSERT INTO highlights VALUES('22791651_226_2738-2779','22791651',226,'第一品 法会因由分','有些人看到风景很高兴，痛苦人看到同样的风景，却悲哀得要想死，都是个人自己唯心所造。','2738-2779',0,1774765073,1782480547);
INSERT INTO highlights VALUES('22791651_226_2617-2631','22791651',226,'第一品 法会因由分','“风月无古今，情怀自浅深。”','2617-2631',0,1774765051,1782480547);
INSERT INTO highlights VALUES('22791651_226_1979-2006','22791651',226,'第一品 法会因由分','所以有些人要学梵文来研究佛学，那就是一个非常滑稽的事。','1979-2006',0,1774764813,1782480547);
INSERT INTO highlights VALUES('22791651_226_1603-1646','22791651',226,'第一品 法会因由分','怎么样叫做如？如者，如如不动之如也，然后怎么样叫如如不动？如如不动者，佛法之境界也……','1603-1646',0,1774764760,1782480547);
INSERT INTO highlights VALUES('22791651_225_9226-9256','22791651',225,'出版说明','原始的佛经是一篇连下来的文章，没有段落，分章分段是后世所作。','9226-9256',0,1774764482,1782480547);
INSERT INTO highlights VALUES('22791651_225_9002-9038','22791651',225,'出版说明','世界上有没有一个东西是坚固不破的？这个大坚固力，到底有没有？你们要去找。','9002-9038',0,1774764443,1782480547);
INSERT INTO highlights VALUES('22791651_226_978-1050','22791651',226,'第一品 法会因由分','平常就是道，最平凡的时候是最高的，真正的真理是在最平凡之间。真正仙佛的境界，是在最平常的事物上。所以真正的人道完成，也就是出世、圣人之道的完成。','978-1050',0,1774605568,1782480547);
INSERT INTO highlights VALUES('22791651_225_9833-9927','22791651',225,'出版说明','那时我只有一个愿力，每天晚上睡觉以前，一定要给我父母念《金刚经》、《心经》。这是我的秘密，我心中自己的愿力，外面不知道，可是我的经验上知道，感应力量非常大，非常大，我只能向诸位报告到这里。','9833-9927',0,1774605397,1782480547);
INSERT INTO highlights VALUES('22791651_225_6143-6209','22791651',225,'出版说明','譬如说看佛经，他能够用特殊的一种方法，把难懂的立刻就懂进去，最难表达的东西，他用一种方式表达出来，别人一听就懂了，这就属于方便般若。','6143-6209',0,1774604208,1782480547);
INSERT INTO highlights VALUES('22791651_226_820-836','22791651',226,'第一品 法会因由分','世间莫若修行好，天下无如吃饭难。','820-836',5,1691516686,1782480547);
INSERT INTO highlights VALUES('22791651_225_8190-8290','22791651',225,'出版说明',unistr('开经偈。\u000a无上甚深微妙法　百千万劫难遭遇\u000a我今见闻得受持　愿解如来真实义'),'8190-8290',5,1691489494,1782480547);
INSERT INTO highlights VALUES('22791651_225_6967-7041','22791651',225,'出版说明','为什么在般若上面加了“金刚”两个字呢？金刚，在金属之中最坚固，就像金刚钻一样，能破一切法。也可以说，能建一切法，而且无坚不摧，所以叫金刚般若波罗蜜。','6967-7041',5,1691489320,1782480547);
INSERT INTO highlights VALUES('22791651_225_6605-6632','22791651',225,'出版说明','佛学讲的六度，就是布施、持戒、忍辱、精进、禅定、般若。','6605-6632',5,1691489204,1782480547);
INSERT INTO highlights VALUES('22791651_225_4480-4575','22791651',225,'出版说明','我们大家都读过书，都认得字，可是很少有人变成真正的文学家，因为优美的句子出不来，没有文字的般若。有的人出语成章，话一讲出来就是文章，每一句话都很优美，很漂亮，因为他有文学的境界，有文字般若。','4480-4575',5,1691327643,1782480547);
INSERT INTO highlights VALUES('22791651_225_4228-4282','22791651',225,'出版说明','自己本有的智慧仓库打开了，不是老师传授给你的，是你自己固有的智慧爆发了，天上天下，无所不知。这就是境界般若。','4228-4282',5,1691327601,1782480547);
INSERT INTO highlights VALUES('22791651_225_4194-4228','22791651',225,'出版说明','真悟道的人，智慧开发是无穷尽的，佛学的名词叫做无师智，也叫做自然智。','4194-4228',5,1691327588,1782480547);
INSERT INTO highlights VALUES('22791651_225_3867-3945','22791651',225,'出版说明','所以，境界包含一切境界，修道人有一分的成就，境界就有一分的不同，有两分的成就，就有两分的不同。换句话说，人修持到了某一种境界，人生的境界就开朗到某一种程度。','3867-3945',5,1691327521,1782480547);
INSERT INTO highlights VALUES('22791651_225_2892-2906','22791651',225,'出版说明','实相般若是属于般若中最根本的','2892-2906',5,1691327242,1782480547);
INSERT INTO highlights VALUES('22791651_225_2729-2771','22791651',225,'出版说明','禅宗干脆不用道，也不用佛，就是这个，这个就是那个，那个就是这个，反正都是代名词而已。','2729-2771',5,1691327192,1782480547);
INSERT INTO highlights VALUES('22791651_225_2682-2720','22791651',225,'出版说明','但是一般人一听到佛，脑子里马上想到大殿上那个塑得发亮发光的佛像，不免又着相了','2682-2720',5,1691327182,1782480547);
INSERT INTO highlights VALUES('22791651_225_2395-2521','22791651',225,'出版说明',unistr('真正的道体是不可思议的，是不可以用我们普通的知识、意识去思想、讨论、研究的。大家要注意！它并没有说不能思议啊！\u000a“不可”是遮法，遮住，挡住，不准看，不可以用普通的知识、意识去推测、去思想道是什么。'),'2395-2521',5,1691327132,1782480547);
INSERT INTO highlights VALUES('22791651_225_1975-2028','22791651',225,'出版说明','所谓根本的智慧，也是一个名称，拿现在观念来讲，就是超越一般聪明与普通的智慧，而了解到形而上生命的本源、本性','1975-2028',5,1691326992,1782480547);
INSERT INTO highlights VALUES('22791651_222_1210-1248','22791651',222,'编者的话','佛所谓度众生，其实是传授智慧，而众生自性自度，只要平实地去做人，个个都是佛。','1210-1248',5,1691326535,1782480547);
INSERT INTO highlights VALUES('22791651_222_1035-1098','22791651',222,'编者的话','般若的含义：般若智慧不是普通的智慧，而是能够了解道、悟道、修证、了脱生死、超凡入圣的智慧，需要身心两方面投入求证，才可能得到。','1035-1098',5,1691326434,1782480547);
INSERT INTO highlights VALUES('22791651_222_915-942','22791651',222,'编者的话','它最伟大之处，是超越了一切宗教性，但也包含了一切宗教性','915-942',5,1691326366,1782480547);
INSERT INTO highlights VALUES('837932_140_45542-45698','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','在生活中，为了养家糊口，你不妨偶尔替那些丧失理智的自大狂服务。但你应该像格兰特·麦克费登那样为人处世。那是个很好的道理。','45542-45698',0,1747100126,1782480552);
INSERT INTO highlights VALUES('837932_140_45235-45275','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','这个例子表明从事律师业的问题之一。在很大程度上，你不得不跟一些非常低劣的人打交道','45235-45275',0,1747100090,1782480552);
INSERT INTO highlights VALUES('837932_140_35827-35846','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','我从现在到离世都不会去赌场赌100美元','35827-35846',0,1746752340,1782480552);
INSERT INTO highlights VALUES('837932_140_32966-33005','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','然而，迪士尼有些业务比一个大金矿更好。我的孙儿孙女们——我是说，那些录像带……','32966-33005',0,1746752104,1782480552);
INSERT INTO highlights VALUES('837932_140_31128-31146','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','我们购买的是有强制性赎回权的优先股。','31128-31146',0,1746751822,1782480552);
INSERT INTO highlights VALUES('837932_140_30214-30262','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','我发现有件事情让我很吃惊，那就是经营一家低科技企业的难度和经营一家高科技企业的难度竟然是差不多的','30214-30262',0,1746751742,1782480552);
INSERT INTO highlights VALUES('837932_140_26303-26345','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','但它们股票的价格升得太高了，所以突然之间，到底应该购买哪只股票这个问题变得很难回答。','26303-26345',0,1746706163,1782480552);
INSERT INTO highlights VALUES('837932_140_24158-24178','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','如果你想要改变行为，那么就必须改变动机。','24158-24178',0,1746668804,1782480552);
INSERT INTO highlights VALUES('837932_140_23648-23683','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','所以与其创立一种有漏洞的制度，还不如就不要赔偿了——就让生活艰辛一些。','23648-23683',0,1746668730,1782480552);
INSERT INTO highlights VALUES('837932_140_19726-19808','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','要做到这一点，办法只有一个：你们必须全面掌握各种主要模型，把它们当作一张检查清单。再强调一下，你们必须注意那些能够产生lollapalooza后果的多因素组合效应。','19726-19808',0,1746375239,1782480552);
INSERT INTO highlights VALUES('837932_140_19671-19697','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','所以你们非常有必要注意lollapalooza效应。','19671-19697',0,1746375232,1782480552);
INSERT INTO highlights VALUES('837932_140_13865-13881','837932',140,'第三讲 论基本的、普世的智慧（修正稿）','实际上，只要看看心理否认就够了。','13865-13881',0,1746092393,1782480552);
INSERT INTO highlights VALUES('837932_139_57255-57301','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','告知查理他的学生对这次题为“论基本的、普世的智慧，及其与投资管理和商业的关系”的演讲的反应。','57255-57301',0,1746016662,1782480552);
INSERT INTO highlights VALUES('837932_139_18210-18271','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系',unistr('苏联工人的经典感叹：\u000a“他们假装给薪水，我们假装在工作。”'),'18210-18271',0,1745738977,1782480552);
INSERT INTO highlights VALUES('837932_139_11395-11439','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','我发现把自由的市场经济——或者部分自由的市场经济——当作某种生态系统是很有用的思维方式。','11395-11439',0,1745727898,1782480552);
INSERT INTO highlights VALUES('837932_139_9607-9650','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','心理学的基础部分——我称之为误判心理学——是极其重要的知识。它包括了大约20个小原则。','9607-9650',0,1745727641,1782480552);
INSERT INTO highlights VALUES('837932_139_9290-9354','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','一个使用工具的人应该了解它的局限，同样道理，一个使用认知工具的人也应该了解它的局限。顺便说一声，这种知识可以用来操控和激励别人。','9290-9354',0,1745727616,1782480552);
INSERT INTO highlights VALUES('837932_139_7522-7587','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','工程学里面的后备系统是一种非常有用的思想，断裂点理论也是一种非常强大的思维模型。物理学里面的临界质量概念是一种非常强大的思维模型。','7522-7587',0,1745726000,1782480552);
INSERT INTO highlights VALUES('837932_139_7009-7083','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','答案很明显，那些来自硬科学和工程学的思维模型是地球上最可靠的思维模型。而工程学的质量控制理论——至少对你我这样的非专业工程师来说也是很重要的核心部分','7009-7083',0,1745724966,1782480552);
INSERT INTO highlights VALUES('837932_139_6672-6854','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','如果你告诉人们事情的时候，总是告诉他们原因，他们就能更深刻地理解你说的话，就会更加重视你说的话，也会更倾向于听从你说的话。就算他们不理解你的理由，他们也会更倾向于听你的话。','6672-6854',0,1745724941,1782480552);
INSERT INTO highlights VALUES('837932_139_4944-4958','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','显然，你们也应该掌握会计学。','4944-4958',0,1745722912,1782480552);
INSERT INTO highlights VALUES('837932_139_1201-1298','837932',139,'第二讲 论基本的、普世的智慧，及其与投资管理和商业的关系','基本的、普世的智慧是什么？嗯，第一条规则是，如果你们只是记得一些孤立的事物，试图把它们硬凑起来，那么你们无法真正地理解任何东西。如果这些事物不在一个理论框架中相互联系，你们就无法把它们派上用场。','1201-1298',0,1745660760,1782480552);
INSERT INTO highlights VALUES('837932_138_14145-14209','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲',unistr('如果仇敌和密友都无法伤害你；\u000a如果你在乎每个人，但不会缺了谁就不行，'),'14145-14209',0,1745650680,1782480552);
INSERT INTO highlights VALUES('837932_138_10401-10430','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','在座各位，愿你们在漫长的人生中日日以避免失败为目标而成长。','10401-10430',0,1745649765,1782480552);
INSERT INTO highlights VALUES('837932_138_9528-9555','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','如果你们希望将来碌碌无为，那么千万不能以达尔文为榜样。','9528-9555',0,1745648788,1782480552);
INSERT INTO highlights VALUES('837932_138_9240-9295','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','雅可比(Carl Jacobi)用的也是卡森这种办法，众所周知，他经常重复一句话：“反过来想，总是反过来想。”','9240-9295',0,1745648718,1782480552);
INSERT INTO highlights VALUES('837932_138_7220-7282','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','我为你们的痛苦生活开出的第三味药是，当你们在人生的战场上遭遇第一、第二或者第三次严重的失败时，就请意志消沉，从此一蹶不振吧。','7220-7282',0,1745648290,1782480552);
INSERT INTO highlights VALUES('837932_138_5765-5788','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','“人生就像悬挂式滑翔，起步没有成功就完蛋啦。”','5765-5788',0,1745648125,1782480552);
INSERT INTO highlights VALUES('837932_138_5447-5514','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','我为痛苦生活开出的第二味药是，尽可能从你们自身的经验获得知识，尽量别从其他人成功或失败的经验中广泛地吸取教训，不管他们是古人还是今人。','5447-5514',0,1745648079,1782480552);
INSERT INTO highlights VALUES('837932_138_4783-4843','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲',unistr('芒格另开的四味药。\u000a第一，要反复无常，不要虔诚地做你正在做的事。'),'4783-4843',0,1745647887,1782480552);
INSERT INTO highlights VALUES('837932_138_4423-4525','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲','约翰逊说得好，他说生活本已艰辛得难以下咽，何必再将它塞进怨恨的苦涩果皮里呢。','4423-4525',0,1745647706,1782480552);
INSERT INTO highlights VALUES('837932_138_2277-2416','837932',138,'第一讲 在哈佛学校毕业典礼上的演讲',unistr('卡森给的确保痛苦生活的处方包括：\u000a1.为了改变心情或者感觉而使用化学物质；\u000a2.妒忌；\u000a3.怨恨。'),'2277-2416',0,1745647534,1782480552);
INSERT INTO highlights VALUES('837932_135_539-560','837932',135,'塞内加尔谈芒格','查理首先敏锐地指出好市多的会员制非常有价值','539-560',0,1745632489,1782480552);
INSERT INTO highlights VALUES('837932_132_687-744','837932',132,'幽默','如果你把葡萄干和大便搅在一起，你得到的仍然是大便。','687-744',0,1745627485,1782480552);
INSERT INTO highlights VALUES('837932_131_523-562','837932',131,'怎样变得幸福、富裕，以及其他建议','生活和生意上的大多数成功来自你知道应该避免哪些事情：过早死亡、糟糕的婚姻等等。','523-562',0,1745626845,1782480552);
INSERT INTO highlights VALUES('837932_130_873-903','837932',130,'对高等教育的批评','（高等教育）错误程度让人吃惊。学科之间毫无关联，这是致命的。','873-903',0,1745626795,1782480552);
INSERT INTO highlights VALUES('837932_129_435-474','837932',129,'思维模型','你必须知道重要学科的重要理论，并经常使用它们——要全部都用上，而不是只用几种。','435-474',0,1745626353,1782480552);
INSERT INTO highlights VALUES('837932_95_1229-1293','837932',95,'关于本书','特别指出的是，查理会反复地使用一些用语和例子。他是有意的：他知道对于要达到他所倡导的那种有深度的“熟练”来说，重复是教导的核心。','1229-1293',5,1715661239,1782480552);
INSERT INTO highlights VALUES('837932_94_2092-2108','837932',94,'导读','独立是赚钱的目的，而不是倒过来。','2092-2108',5,1715660940,1782480552);
INSERT INTO highlights VALUES('837932_94_1940-1977','837932',94,'导读','查理认为生活的决定比投资的决定重要。他那来自各种学科的思维模型反复地出现，','1940-1977',5,1715519081,1782480552);
INSERT INTO highlights VALUES('837932_94_1458-1469','837932',94,'导读','反过来想，总是反过来想','1458-1469',5,1715519039,1782480552);
INSERT INTO highlights VALUES('837932_94_482-518','837932',94,'导读','查理的世界观很独特，他用“跨学科的”方法让自己养成了清晰而简单的思维模式','482-518',5,1715518598,1782480552);
INSERT INTO highlights VALUES('837932_92_2209-2240','837932',92,'序言 巴菲特论芒格','最后，这位伙伴还会在漫漫长路上结伴同游时能不断地给你带来快乐。','2209-2240',5,1715518217,1782480552);
INSERT INTO highlights VALUES('837932_92_2176-2188','837932',92,'序言 巴菲特论芒格','他还应该是个慷慨大方的人','2176-2188',5,1715518212,1782480552);
INSERT INTO highlights VALUES('837932_92_2448-2462','837932',92,'序言 巴菲特论芒格','“……最后，她们会感激不尽。','2448-2462',5,1715518145,1782480552);
INSERT INTO highlights VALUES('837932_92_2072-2089','837932',92,'序言 巴菲特论芒格','首先，要找比你更聪明、更有智慧的人','2072-2089',5,1715518071,1782480552);
INSERT INTO highlights VALUES('837932_92_1267-1287','837932',92,'序言 巴菲特论芒格','这两个基金的目的是要向人们传授复利的魔力','1267-1287',5,1715517763,1782480552);
INSERT INTO highlights VALUES('837932_92_647-711','837932',92,'序言 巴菲特论芒格','从1733年到1758年，本杰明·富兰克林借由《穷理查年鉴》传播了许多有用且永恒的建议。他赞扬的美德包括节俭、负责、勤奋和简朴。','647-711',5,1715517684,1782480552);
INSERT INTO highlights VALUES('837932_92_815-839','837932',92,'序言 巴菲特论芒格','查理原初只是本杰明的信徒，但很快开辟了新的境界。','815-839',5,1715517674,1782480552);
INSERT INTO highlights VALUES('837932_90_13388-13430','837932',90,'中文版序言 书中自有黄金屋','查理是一个完全凭借智慧取得成功的人，这对于中国的读书人来讲无疑是一个令人振奋的例子。','13388-13430',5,1715517165,1782480552);
INSERT INTO highlights VALUES('837932_90_13119-13151','837932',90,'中文版序言 书中自有黄金屋','阅读广泛，知识渊博，真正关注的是自身道德的修养与社会的终极关怀。','13119-13151',5,1715517128,1782480552);
INSERT INTO highlights VALUES('837932_90_12633-12673','837932',90,'中文版序言 书中自有黄金屋','从工业革命开始，市场经济和科学技术逐渐成为政府之外影响人类生活最重要的两股力量。','12633-12673',5,1715517017,1782480552);
INSERT INTO highlights VALUES('837932_90_12247-12296','837932',90,'中文版序言 书中自有黄金屋','中国文明的灵魂其实就是士大夫文明，士大夫的价值观所体现的就是一个如何提高自我修养，自我超越的过程。','12247-12296',5,1715516913,1782480552);
INSERT INTO highlights VALUES('837932_90_11952-11992','837932',90,'中文版序言 书中自有黄金屋','客观地讲，作为“五四”之后成长的中国人，我们对于中国的传统基本上是持否定的态度的','11952-11992',5,1715516629,1782480552);
INSERT INTO highlights VALUES('837932_90_11873-11913','837932',90,'中文版序言 书中自有黄金屋','与查理交往的这些年，我常常会忘记他是一个美国人。他更接近于我理解的中国传统士大夫','11873-11913',5,1715516615,1782480552);
INSERT INTO highlights VALUES('837932_90_11718-11731','837932',90,'中文版序言 书中自有黄金屋','我的剑留给能够挥舞它的人。','11718-11731',5,1715516601,1782480552);
INSERT INTO highlights VALUES('837932_90_11627-11681','837932',90,'中文版序言 书中自有黄金屋','比如，有人问查理如何才能找到一个优秀的配偶。查理说最好的方式就是让自己配得上她/他，因为优秀配偶都不是傻瓜。','11627-11681',5,1715516553,1782480552);
INSERT INTO highlights VALUES('837932_90_11527-11560','837932',90,'中文版序言 书中自有黄金屋','我知道查理本人很喜欢这本书，认为它收集了他一生的思想精华和人生体验','11527-11560',5,1715516528,1782480552);
INSERT INTO highlights VALUES('837932_90_10993-11023','837932',90,'中文版序言 书中自有黄金屋','查理一生研究人类失败的原因，所以对人性的弱点有着深刻的理解。','10993-11023',5,1715516465,1782480552);
INSERT INTO highlights VALUES('837932_90_10845-10867','837932',90,'中文版序言 书中自有黄金屋','查理一旦确定了做一件事情，他可以去做一辈子。','10845-10867',5,1715515097,1782480552);
INSERT INTO highlights VALUES('837932_90_10182-10228','837932',90,'中文版序言 书中自有黄金屋','我一辈子想要的就是融入生活(engage life)，而不希望自己被孤立(isolate)。','10182-10228',5,1715505893,1782480552);
INSERT INTO highlights VALUES('837932_90_9460-9502','837932',90,'中文版序言 书中自有黄金屋','以后我逐渐了解，查理与人约会一定早到。到了以后也不浪费时间，会拿出准备好的报纸翻阅。','9460-9502',5,1715492551,1782480552);
INSERT INTO highlights VALUES('837932_90_9145-9176','837932',90,'中文版序言 书中自有黄金屋','一个人的成功并不是偶然的，时机固然重要，但人的内在品质更重要。','9145-9176',5,1715492506,1782480552);
INSERT INTO highlights VALUES('837932_90_8806-8902','837932',90,'中文版序言 书中自有黄金屋','查理天生精力充沛。我认识查理是在1996年，那时他72岁。到2011年查理87岁，已经过了十几年了。在这十几年里，查理的精力完全没有变化。他永远是精力旺盛，很早起身。早餐会议永远是七点半开始。','8806-8902',5,1715492052,1782480552);
INSERT INTO highlights VALUES('837932_90_8711-8732','837932',90,'中文版序言 书中自有黄金屋','比如他捐助的所有建筑物都是他自己亲自设计的','8711-8732',5,1715492037,1782480552);
INSERT INTO highlights VALUES('837932_90_8663-8673','837932',90,'中文版序言 书中自有黄金屋','他还是个出色的建筑师','8663-8673',5,1715492023,1782480552);
INSERT INTO highlights VALUES('837932_90_8632-8662','837932',90,'中文版序言 书中自有黄金屋','他有一艘世界上最大的私人双体游艇，而这艘游艇就是他自己设计的','8632-8662',5,1715492014,1782480552);
INSERT INTO highlights VALUES('837932_90_8604-8632','837932',90,'中文版序言 书中自有黄金屋','查理的兴趣不仅限于思考，凡事也喜欢亲力亲为，并注重细节。','8604-8632',5,1715491999,1782480552);
INSERT INTO highlights VALUES('837932_90_8400-8433','837932',90,'中文版序言 书中自有黄金屋','相对于任何来自象牙塔内的思想体系，芒格主义完全为解决实际问题而生。','8400-8433',5,1715491963,1782480552);
INSERT INTO highlights VALUES('837932_90_8147-8201','837932',90,'中文版序言 书中自有黄金屋','甚至指出金融衍生产品是金融式的大规模杀伤武器，如果不能得到及时有效的制止，将会给现代文明社会带来灾难性的影响','8147-8201',5,1715491920,1782480552);
INSERT INTO highlights VALUES('837932_90_7998-8078','837932',90,'中文版序言 书中自有黄金屋','查理一辈子研究人类灾难性的错误，对于由于人类心理倾向引起的灾难性错误尤其情有独钟。最具贡献的是他预测金融衍生产品的泛滥和会计审计制度的漏洞即将给人类带来的灾难。','7998-8078',5,1715491902,1782480552);
INSERT INTO highlights VALUES('837932_90_7873-7928','837932',90,'中文版序言 书中自有黄金屋','至少在两个重大问题上，查理帮我指出了我思维上的盲点，如果不是他的帮助，我现在还在从猿到人的进化过程中慢慢爬行。','7873-7928',5,1715491867,1782480552);
INSERT INTO highlights VALUES('837932_90_7759-7797','837932',90,'中文版序言 书中自有黄金屋','巴菲特说：“本杰明·格雷厄姆曾经教我只买便宜的股票，查理让我改变了这种想法。','7759-7797',5,1715491826,1782480552);
INSERT INTO highlights VALUES('837932_90_7534-7590','837932',90,'中文版序言 书中自有黄金屋','巴菲特就把查理的这个特点称作“两分钟效应”——他说查理比世界上任何人更能在最短时间之内把一个复杂商业的本质说清楚','7534-7590',5,1715491792,1782480552);
INSERT INTO highlights VALUES('837932_90_7482-7533','837932',90,'中文版序言 书中自有黄金屋','正是这样的“理性”，让查理具有敏锐独到的眼光和洞察力，即使对于完全陌生的领域，他也能一眼看到事物的本质','7482-7533',5,1715491755,1782480552);
INSERT INTO highlights VALUES('837932_90_7277-7342','837932',90,'中文版序言 书中自有黄金屋','查理说，如果我要拥有一种观点，如果我不能够比全世界最聪明、最有能力、最有资格反驳这个观点的人更能够证否自己，我就不配拥有这个观点。','7277-7342',5,1715491717,1782480552);
INSERT INTO highlights VALUES('837932_90_7238-7263','837932',90,'中文版序言 书中自有黄金屋','一种不能够界定其边界的能力当然不能称为真正的能力。','7238-7263',5,1715491693,1782480552);
INSERT INTO highlights VALUES('837932_90_7070-7155','837932',90,'中文版序言 书中自有黄金屋','在这本书里，查理也讲到了通过后天的训练是可以培养客观的精神的。而这种思维方式的养成将使你看到别人看不到的东西，预测到别人预测不到的未来，从而过上更幸福、自由和成功的生活。','7070-7155',5,1715491044,1782480552);
INSERT INTO highlights VALUES('837932_90_7056-7070','837932',90,'中文版序言 书中自有黄金屋','但是查理却可以做到凡事客观。','7056-7070',5,1715491027,1782480552);
INSERT INTO highlights VALUES('837932_90_6869-6890','837932',90,'中文版序言 书中自有黄金屋','查理这种思维方式的基础是基于对知识的诚实。','6869-6890',5,1715490905,1782480552);
INSERT INTO highlights VALUES('837932_90_6428-6469','837932',90,'中文版序言 书中自有黄金屋','任何一个问题在他看来都可以使用正确的方法通过自学完全掌握，并可以在前人的基础上创新','6428-6469',5,1715490861,1782480552);
INSERT INTO highlights VALUES('837932_90_6400-6427','837932',90,'中文版序言 书中自有黄金屋','一生都有强烈的求知欲和好奇心，几乎对所有的问题都感兴趣','6400-6427',5,1715490852,1782480552);
INSERT INTO highlights VALUES('837932_90_6109-6135','837932',90,'中文版序言 书中自有黄金屋','我只想知道将来我会死在什么地方，这样我就不去那儿了。','6109-6135',5,1715490806,1782480552);
INSERT INTO highlights VALUES('837932_90_5980-6038','837932',90,'中文版序言 书中自有黄金屋','如果要明白人生如何得到幸福，查理首先是研究人生如何才能变得痛苦；要研究企业如何做强做大，查理首先研究企业是如何衰败的','5980-6038',5,1715490790,1782480552);
INSERT INTO highlights VALUES('837932_90_5962-5980','837932',90,'中文版序言 书中自有黄金屋','比如说，查理思考问题总是从逆向开始。','5962-5980',5,1715490779,1782480552);
INSERT INTO highlights VALUES('837932_90_5162-5237','837932',90,'中文版序言 书中自有黄金屋','我所遇到的问题几乎就是华尔街的全部问题。整个华尔街的思维方式都有问题，虽然伯克希尔已经取得了这么大的成功，但在华尔街上却找不到任何一家真正模仿它的公司','5162-5237',5,1714336156,1782480552);
INSERT INTO highlights VALUES('837932_90_3859-3885','837932',90,'中文版序言 书中自有黄金屋','买进下跌的股票时是卖家难受，作为买家你应该高兴才对。','3859-3885',5,1714335975,1782480552);
INSERT INTO highlights VALUES('837932_90_3742-3813','837932',90,'中文版序言 书中自有黄金屋','在价值投资者看来，投资股市最大的风险其实并不是价格的上下起伏，而是你的投资未来会不会出现永久性的亏损。单纯的股价下跌不仅不是风险，其实还是机会','3742-3813',5,1714335953,1782480552);
INSERT INTO highlights VALUES('837932_90_3690-3723','837932',90,'中文版序言 书中自有黄金屋','比如他们相信市场完全有效理论，因而相信股价的波动就等同真实的风险，','3690-3723',5,1714335940,1782480552);
INSERT INTO highlights VALUES('694341_75_918-984','694341',75,'5.8 远期和期货价格相等吗','当S与利率有正的相关性时，期货价格往往会高于远期价格；当S与利率有负相关性时，通过类似的讨论我们可以说明远期价格往往会高于期货价格。','918-984',0,1691475744,1782480563);
INSERT INTO highlights VALUES('694341_145_1080-1117','694341',145,'10.11 认股权证、雇员股票期权和可转换债券','认股权证、雇员股票期权和可转换债券的一个共同特性是期权发行数量在事先已确定','1080-1117',0,1689921953,1782480563);
INSERT INTO highlights VALUES('694341_265_1749-1786','694341',265,'19.8 Vega','但不幸的是，一个Gamma中性的交易组合一般不会是Vega中性，反之亦然。','1749-1786',0,1686652297,1782480563);
INSERT INTO highlights VALUES('694341_263_4175-4196','694341',263,'19.6 Gamma','对于平值期权，Gamma随期限的缩短而增大','4175-4196',0,1686651937,1782480563);
INSERT INTO highlights VALUES('694341_263_1718-1735','694341',263,'19.6 Gamma','当Gamma为正时，Θ往往是负值。','1718-1735',0,1686651807,1782480563);
INSERT INTO highlights VALUES('694341_117_2657-2703','694341',117,'8.3 问题出在哪里','代理成本（agency cost）来描述在某个商业行为中两个不同参与者的利益不完全一致的情形','2657-2703',0,1684221870,1782480563);
INSERT INTO highlights VALUES('694341_116_4339-4391','694341',116,'8.2 美国住房市场','但市场上有许多违约者是出于投机的目的，他们买房屋是为了出租，并选择行使看跌期权，这些房屋的租客成了受害人','4339-4391',0,1684221542,1782480563);
INSERT INTO highlights VALUES('694341_116_4083-4130','694341',116,'8.2 美国住房市场','因此贷款人事实上持有一个免费的美式看跌期权：他可以在任何时候以贷款余额价值将房屋售于贷款借出方','4083-4130',0,1684220147,1782480563);
INSERT INTO highlights VALUES('694341_116_1544-1567','694341',116,'8.2 美国住房市场','贷款经纪人与贷款商不得不设法进一步降低贷款标准','1544-1567',0,1684219927,1782480563);
INSERT INTO highlights VALUES('694341_116_1326-1447','694341',116,'8.2 美国住房市场','对贷款经纪人和贷款商而言，房屋价格上涨以及大量的借贷需求无疑是个好消息，更多的借贷意味着更多的盈利，并且房屋价格的上涨意味着贷款会有很好的抵押品，即使贷款人（即借入贷款者）违约时，由于丧失回赎权（foreclousure）也不会给银行造成损失','1326-1447',0,1684219876,1782480563);
INSERT INTO highlights VALUES('694341_116_980-1014','694341',116,'8.2 美国住房市场','2000~2006年，美国按揭市场的一个显著特点是次级按揭贷款的激增','980-1014',0,1684219831,1782480563);
INSERT INTO highlights VALUES('694341_115_3628-3670','694341',115,'8.1 证券化','这样产生的结构叫作资产支持证券的债务抵押证券（即ABS CDO或中层ABS CDO）','3628-3670',0,1684219586,1782480563);
INSERT INTO highlights VALUES('694341_115_2958-2991','694341',115,'8.1 证券化','一般来讲，资产支持证券会有多于3个以上的份额，份额的信用评级也多种','2958-2991',0,1684219335,1782480563);
INSERT INTO highlights VALUES('694341_115_565-587','694341',115,'8.1 证券化','其现金流（利息和本金）被打包成债券卖给投资人','565-587',0,1683782045,1782480563);
INSERT INTO highlights VALUES('694341_44_2536-2639','694341',44,'3.4 交叉对冲','对冲效率（hedge effectiveness）可以被定义为对冲所消除的方差量占总方差的比例，这正是将ΔS对ΔF进行线性回归的R2系数，等于ρ2。','2536-2639',0,1677157770,1782480563);
INSERT INTO highlights VALUES('694341_44_886-917','694341',44,'3.4 交叉对冲','对冲者采用的对冲比率应当使被对冲后头寸价格变化的方差达到极小。','886-917',0,1677157675,1782480563);
INSERT INTO highlights VALUES('694341_43_5756-5793','694341',43,'3.3 基差风险','因此在某些情形下，对冲者常常会倾向于采用短期合约，并且不断将合约向前展期。','5756-5793',0,1677128556,1782480563);
INSERT INTO highlights VALUES('694341_43_5733-5756','694341',43,'3.3 基差风险','在实际中，短期限期货合约往往具有最强的流动性。','5733-5756',0,1677128546,1782480563);
INSERT INTO highlights VALUES('694341_43_3694-3779','694341',43,'3.3 基差风险','有时给对冲者带来风险的资产与用于对冲的合约标的资产是不一样的，这种情形下的对冲叫交叉对冲（cross hedging）','3694-3779',0,1677120151,1782480563);
INSERT INTO highlights VALUES('694341_43_2969-3031','694341',43,'3.3 基差风险','对冲风险与b2的不确定性有关，此风险即为基差风险。','2969-3031',0,1677120068,1782480563);
INSERT INTO highlights VALUES('694341_43_1019-1031','694341',43,'3.3 基差风险','基差=期货价格-即期价格','1019-1031',0,1677119998,1782480563);
INSERT INTO highlights VALUES('694341_43_555-578','694341',43,'3.3 基差风险','在实际中对冲时常常并没这么容易，部分原因如下：','555-578',0,1677119966,1782480563);
INSERT INTO highlights VALUES('694341_43_607-747','694341',43,'3.3 基差风险',unistr('（1）需要对冲价格风险的资产与期货合约的标的资产可能并不完全一样；\u000a（2）对冲者可能无法确定买入或卖出资产的准确时间；\u000a（3）对冲者可能需要在期货到期月之前将期货平仓。'),'607-747',0,1677119962,1782480563);
INSERT INTO highlights VALUES('694341_42_1646-1672','694341',42,'3.2 拥护与反对对冲的观点','当黄金价格上涨时，经济压力会造成珠宝批发价格普遍上涨','1646-1672',NULL,1677036103,1782480563);
INSERT INTO highlights VALUES('694341_41_2810-2848','694341',41,'3.1 基本原理','如果公司采用后一方法，它必须每磅支付340美分，并且还要付出利息和贮存费用。','2810-2848',NULL,1677035860,1782480563);
INSERT INTO highlights VALUES('694341_41_2066-2103','694341',41,'3.1 基本原理','当公司已知在将来需要买入一定资产并想在今天将价格锁定时，可以采用多头对冲。','2066-2103',NULL,1677035820,1782480563);
INSERT INTO highlights VALUES('694341_41_960-991','694341',41,'3.1 基本原理','在当前不拥有资产但在将来会拥有资产的情况下，也可以选择空头对冲','960-991',NULL,1677035667,1782480563);
INSERT INTO highlights VALUES('694341_41_874-917','694341',41,'3.1 基本原理','当对冲者已经拥有了某种资产并期望在将来某时刻卖出资产时，这时选择期货空头对冲是合理的。','874-917',NULL,1677035630,1782480563);
INSERT INTO highlights VALUES('694341_41_830-841','694341',41,'3.1 基本原理','空头对冲','830-841',NULL,1677035628,1782480563);
INSERT INTO highlights VALUES('694341_40_972-989','694341',40,'第3章 利用期货的对冲策略','密切监视对冲策略，并经常调整头寸。','972-989',NULL,1677035537,1782480563);
INSERT INTO highlights VALUES('694341_40_926-939','694341',40,'第3章 利用期货的对冲策略','动态对冲策略','926-939',NULL,1677035530,1782480563);
INSERT INTO highlights VALUES('694341_40_795-861','694341',40,'第3章 利用期货的对冲策略','保完即忘策略（hedge-and-forget strategy），也就是说，一旦设定对冲策略后，无须再对其进行调整。','795-861',NULL,1677035519,1782480563);
INSERT INTO highlights VALUES('694341_40_567-618','694341',40,'第3章 利用期货的对冲策略','完美对冲（perfect hedge）是指完全消除风险的策略，在实际中完美对冲极其罕见。','567-618',NULL,1677035495,1782480563);
INSERT INTO highlights VALUES('694341_35_1117-1340','694341',35,'2.11 远期与期货合约的比较','假设投资者A进入了90天期限、面值100万英镑的远期合约多头，而投资者B进入了90天期限，面值也为100万英镑的期货合约多头。（因为1份期货合约是关于62500英镑，投资者B应持有16份合约。）假定在90天后，即期汇率为1.7000，投资者A在90天后收入200000美元；投资者B也有收益，但其收益分散在90天上。在某些天投资者B可能会有损失，而在其他天会有收益。但是总体来讲，将损失和收益相抵后，投资者B在90天内的总收益为200000美元。','1117-1340',NULL,1675998405,1782480563);
INSERT INTO highlights VALUES('694341_34_1189-1273','694341',34,'2.10 会计和税收','如果公司买入期货合约的目的是为了对冲在2015年2月需要买入的5000蒲式耳玉米，因此合约可以按对冲会计准则处理，从而将全部1500美元的收入当成是在2015年发生的。','1189-1273',NULL,1675997945,1782480563);
INSERT INTO highlights VALUES('694341_33_462-551','694341',33,'2.9 制度','当前美国的期货市场是由联邦政府级机构，即商品期货交易委员会（Commodity Futures Trading Commission，CFTC，www.cftc.org）来监管。','462-551',NULL,1675997588,1782480563);
INSERT INTO highlights VALUES('694341_32_775-992','694341',32,'2.8 交易员类型和交易指令类型','短期投机者（scalper）通过观察价格的短期走势而试图从中盈利，这些交易员持有头寸时间可能只有几分钟。短线交易员（day trader）持有头寸的时间不超过1个交易日，他们不愿承担每天晚上由于不利消息所带来的风险。头寸交易员（position trader）持有期限较长，他们希望从市场上大的变动中取得可观的盈利。','775-992',NULL,1675997286,1782480563);
INSERT INTO highlights VALUES('694341_30_2245-2298','694341',30,'2.6 市场报价','如果合约价格是期限的递减函数，我们称这种市场为反向市场','2245-2298',NULL,1674137419,1782480563);
INSERT INTO highlights VALUES('694341_30_2178-2229','694341',30,'2.6 市场报价','交割价格是期限的递增函数，我们称这种市场为正常市场','2178-2229',NULL,1674137419,1782480563);
INSERT INTO highlights VALUES('694341_11_1771-1786','694341',11,'1.2 场外市场','场外市场规模远远大于交易所市场','1771-1786',NULL,1674137418,1782480563);
INSERT INTO highlights VALUES('694341_26_3588-3634','694341',26,'2.2 期货合约的规格','头寸限额是一个投机者可持有的最大合约数量，头寸限额的目的是为了防止投机者对市场有不良的影响。','3588-3634',NULL,1674136179,1782480563);
INSERT INTO highlights VALUES('694341_19_1924-1982','694341',19,'1.10 危险','衍生产品一定要被用于指定的目的，在交易中必须建立风险额度，银行必须经常监控交易员的交易以保证风险额度制度的贯彻执行。','1924-1982',NULL,1674135562,1782480563);
INSERT INTO highlights VALUES('694341_17_3271-3329','694341',17,'1.8 投机者','投机者使用期货时，潜在的损失与收益都很大。但采用期权产品时，不管市场有多么糟糕，投机者的损失不会超过所支付的期权费用','3271-3329',NULL,1674135389,1782480563);
INSERT INTO highlights VALUES('694341_17_1323-1368','694341',17,'1.8 投机者','期货市场可以使投机者取得杠杆效应，即投资者只需要支出少量资金就可以建立一个很大的投机头寸。','1323-1368',NULL,1674135339,1782480563);
INSERT INTO highlights VALUES('694341_17_1236-1261','694341',17,'1.8 投机者','与之相比，第2种做法只需要将少量资金存入保证金账户','1236-1261',NULL,1674135328,1782480563);
INSERT INTO highlights VALUES('694341_14_521-733','694341',14,'1.5 期权合约','看涨期权（call option）的持有者有权在将来某一特定时间以某一特定价格买入某种资产，看跌期权（put option）的持有者有权在将来某一特定时间以某一特定价格卖出某种资产。合约中所说的特定价格叫执行价格（exercise price）或敲定价格','521-726',NULL,1674134649,1782480563);
INSERT INTO highlights VALUES('694341_12_2253-2515','694341',12,'1.3 远期合约',unistr('一般来讲，在合约到期时，对于远期合约多头方来讲，每1单位合约的收益为\u000aST-K\u000a这里K为合约的交割价格（delivery price），ST为资产在合约到期时的市场价格，合约中的多头方必须以K的价格买入价值为ST的资产。同样，对于远期合约的空头方来讲，合约所带来的收益为\u000aK-ST'),'2253-2515',NULL,1674134309,1782480563);
INSERT INTO highlights VALUES('694341_12_611-667','694341',12,'1.3 远期合约','即期合约是指立刻就要买入或卖出资产的合约，远期合约常常是金融机构之间或金融机构与其客户之间在场外市场进行的交易。','611-667',NULL,1674133947,1782480563);
INSERT INTO highlights VALUES('694341_11_1708-1746','694341',11,'1.2 场外市场','尽管与交易所市场相比，场外市场交易数量相对较小，但是交易的平均规模却大得多。','1708-1746',NULL,1674133805,1782480563);
INSERT INTO highlights VALUES('694341_11_901-1087','694341',11,'1.2 场外市场','金融机构常常是市场上流行产品的做市商（market maker）。这意味着他们在随时准备提供买入价（bid price）（即以这一价格买入产品）的同时，也提供卖出价（offer price）（即以这一价格卖出产品）。','901-1087',NULL,1674133708,1782480563);
INSERT INTO highlights VALUES('694341_11_589-699','694341',11,'1.2 场外市场','一旦同意了场外交易，双方可以将交易递交到中央交易对手（central counterparty，CCP）或进行双边清算，中央交易对手的作用如同交易所的清算中心：它介于交易对手之间，从而使交易的一方不用顾虑对手的违约风险。','589-699',NULL,1674133604,1782480563);
INSERT INTO highlights VALUES('694341_10_2043-2108','694341',10,'1.1 交易所市场','电子交易促成了高频率交易（high-frequency trading）与算法交易（algorithmic trading）的发展','2043-2108',NULL,1674133428,1782480563);
INSERT INTO highlights VALUES('694341_10_1626-1629','694341',10,'1.1 交易所市场','保证金','1626-1629',NULL,1674133388,1782480563);
INSERT INTO highlights VALUES('694341_10_1562-1588','694341',10,'1.1 交易所市场','这样安排交易的优点是交易员们不需要顾虑对手的信用问题','1562-1588',NULL,1674133377,1782480563);
INSERT INTO highlights VALUES('694341_10_1223-1247','694341',10,'1.1 交易所市场','期权的标的资产包括外汇、期货合约以及股票和股指。','1223-1247',NULL,1674133334,1782480563);
INSERT INTO highlights VALUES('694341_24_518-581','694341',24,'第2章 期货市场的运作机制','期货合约交易是在有组织的交易所中进行的，而且交易所将合约标准化；而远期合约是在场外市场进行交易，交易双方可以按需要来设计合约。','518-581',NULL,1674133085,1782480563);
INSERT INTO highlights VALUES('694341_278_1528-1555','694341',278,'20.1 为什么波动率微笑对看涨期权与看跌期权是一样的','在无套利的前提下，看跌-看涨平价关系式对市场价格也成立','1528-1555',NULL,1662372557,1782480563);
INSERT INTO highlights VALUES('694341_263_4093-4105','694341',263,'19.6 Gamma','多头的Gamma总是为正','4093-4105',NULL,1661129213,1782480563);
INSERT INTO highlights VALUES('694341_263_3290-3368','694341',263,'19.6 Gamma','Delta中性保证了在对冲再平衡之间交易组合价值不受股票价格微小变化的影响，而Gamma中性则保证了在对冲再平衡之间交易组合价值不受股票价格较大变化的影响。','3290-3368',NULL,1661129048,1782480563);
INSERT INTO highlights VALUES('694341_263_470-540','694341',263,'19.6 Gamma','一个期权交易组合的Gamma（Γ）是指交易组合Delta的变化与标的资产价格变化的比率。','470-540',NULL,1661128583,1782480563);
INSERT INTO highlights VALUES('694341_262_3196-3241','694341',262,'19.5 Theta','正如我们在今后会看到的那样，在一个Delta中性的交易组合中，Theta是Gamma的近似','3196-3241',NULL,1661128572,1782480563);
INSERT INTO highlights VALUES('694341_262_3084-3164','694341',262,'19.5 Theta','这是因为未来股票的价格有很大的不定性，但时间走向却没有不定性。通过对冲来消除交易组合关于标的资产价格变化的风险很有意义，但对冲交易组合对于时间的变化就毫无意义。','3084-3164',NULL,1661128559,1782480563);
INSERT INTO highlights VALUES('694341_262_2171-2340','694341',262,'19.5 Theta','期权的Theta一般是负的，￼这是因为在其他条件不变的情况下，随着期限的减小，期权价值会降低','2171-2340',NULL,1661128475,1782480563);
INSERT INTO highlights VALUES('694341_262_470-593','694341',262,'19.5 Theta','期权组合的Theta（Θ）定义为在其他条件不变时，投资组合价值变化与时间变化的比率。Theta有时称为组合的时间损耗（time decay）。','470-593',NULL,1661128395,1782480563);
INSERT INTO highlights VALUES('694341_261_8729-8759','694341',261,'19.4 Delta对冲','但对一个很大的期权组合进行对冲时，Delta中性就会切实可行','8729-8759',NULL,1661128373,1782480563);
INSERT INTO highlights VALUES('694341_261_611-653','694341',261,'19.4 Delta对冲','Delta（Δ），该变量定义为期权价格变动与其标的资产价格变动的比率。','611-653',NULL,1661127761,1782480563);
INSERT INTO highlights VALUES('694341_260_2180-2216','694341',260,'19.3 止损交易策略','尽管止损交易策略从表面上看起来很诱人，但这一策略并不是个有效的对冲手段。','2180-2216',NULL,1661127686,1782480563);
INSERT INTO highlights VALUES('694341_260_491-524','694341',260,'19.3 止损交易策略','止损交易策略（stop-loss strategy）','491-524',NULL,1661127580,1782480563);
INSERT INTO highlights VALUES('694341_260_595-632','694341',260,'19.3 止损交易策略','在股票价格刚刚高于K时马上买入股票，而在股票价格刚刚低于K时马上卖出股票。','595-632',NULL,1661127578,1782480563);
INSERT INTO highlights VALUES('694341_259_1180-1202','694341',259,'19.2 裸露头寸和带保头寸','裸露头寸和带保头寸都不是很好的对冲交易策略。','1180-1202',NULL,1661127521,1782480563);
INSERT INTO highlights VALUES('694341_259_867-896','694341',259,'19.2 裸露头寸和带保头寸','带保头寸（covered position）','867-896',NULL,1661127506,1782480563);
INSERT INTO highlights VALUES('694341_259_478-545','694341',259,'19.2 裸露头寸和带保头寸','金融机构可采用的一种策略是对期权头寸不采取任何对冲措施，这种做法被称为持有裸露头寸','478-538',NULL,1661127398,1782480563);
INSERT INTO highlights VALUES('694341_257_735-796','694341',257,'第19章 希腊值','每一个希腊值都是用来度量期权头寸的某种特定风险，而交易员的目标就是管理这些希腊值，以便将风险保持在一个可以接受的范围之内。','735-796',NULL,1661127247,1782480563);
INSERT INTO highlights VALUES('694341_54_2364-2391','694341',54,'4.2 利率的度量','在大多数实际情况下，我们可以认为连续复利与每天复利等价','2404-2431',NULL,1565103926,1782480563);
INSERT INTO highlights VALUES('694341_53_918-930','694341',53,'4.1 利率的种类','因此国债利率为无风险利率','918-930',NULL,1565103346,1782480563);
INSERT INTO highlights VALUES('694341_51_2477-2512','694341',51,'附录3A 资本资产定价模型','其中β是组合的beta，该系数可以根据组合中每个股票β的加权平均来计算','2477-2512',NULL,1565017186,1782480563);
INSERT INTO highlights VALUES('694341_51_1878-1890','694341',51,'附录3A 资本资产定价模型','资产回报只取决于一个因子','1878-1890',NULL,1565017091,1782480563);
INSERT INTO highlights VALUES('694341_51_522-542','694341',51,'附录3A 资本资产定价模型','资产的回报期望值与回报风险联系起来的模型','522-542',NULL,1565016305,1782480563);
INSERT INTO highlights VALUES('694341_44_2705-2713','694341',44,'3.4 交叉对冲','相等而且互不重叠','2764-2772',NULL,1564883781,1782480563);
INSERT INTO highlights VALUES('694341_43_5596-5599','694341',43,'3.3 基差风险','流动性','5729-5732',NULL,1564883190,1782480563);
INSERT INTO highlights VALUES('694341_43_5247-5263','694341',43,'3.3 基差风险','选择一个在稍后月份交割的期货合约','5380-5396',NULL,1564883117,1782480563);
INSERT INTO highlights VALUES('694341_43_5127-5134','694341',43,'3.3 基差风险','最紧密的相关性','5260-5267',NULL,1564883036,1782480563);
INSERT INTO highlights VALUES('45369847_66_1265-1316','45369847',66,'状态导向：别等准备好了才行动','“做错”的后悔可能持续几周、几个月，但“没做”的后悔，可能持续许多年，乃至于成为记忆里一个永久的遗憾。','1265-1316',0,1754124801,1782480550);
INSERT INTO highlights VALUES('45369847_66_913-933','45369847',66,'状态导向：别等准备好了才行动','很多时候，错过就是错过，不会再有机会了。','913-933',0,1754012182,1782480550);
INSERT INTO highlights VALUES('45369847_65_7054-7101','45369847',65,'反馈缺失：如何战胜短期诱惑','如果一项任务是重复、单调的：没关系，它能够提高我的熟练度，让我在这项技能的使用上更加得心应手。','7054-7101',0,1754012133,1782480550);
INSERT INTO highlights VALUES('45369847_65_5169-5247','45369847',65,'反馈缺失：如何战胜短期诱惑','快乐是有层级之分的，创造的快乐要比消费的快乐更高一层。因为创造需要你主动思考，你的快乐来源于“动脑”这个过程；而消费不需要动脑，你的快乐来源于消费对象本身。','5169-5247',0,1754011961,1782480550);
INSERT INTO highlights VALUES('45369847_49_5297-5498','45369847',49,'稳定：拖累成长脚步的元凶',unistr('预设立场：我们的行为和认知往往会为我们预设下一个个立场，让我们带着立场去获取信息；\u000a2.证实偏见：在预设立场的基础上，我们会更容易接受跟立场一致的信息，忽略不一致的信息，从而强化我们的立场；\u000a3.合理化：一旦我们接触到不一致的信息，我们也会倾向于把它往一致的方向解释，尽可能强化我们的立场。'),'5297-5498',1,1753623608,1782480550);
INSERT INTO highlights VALUES('45369847_49_4513-4548','45369847',49,'稳定：拖累成长脚步的元凶','进一步，在认知失调效应的影响下，一个重要的开关就被打开了，即动机性推理','4513-4548',1,1753623495,1782480550);
INSERT INTO highlights VALUES('45369847_49_4253-4297','45369847',49,'稳定：拖累成长脚步的元凶','通过最省力的方式，去干涉这种认知和行为，使它们尽量保持一致。这种做法，就叫作“合理化”。','4253-4297',1,1753622312,1782480550);
INSERT INTO highlights VALUES('45369847_49_4158-4187','45369847',49,'稳定：拖累成长脚步的元凶','这就是经典的“认知失调”理论：我们总是追求认知和行为一致。','4158-4187',1,1753622282,1782480550);
INSERT INTO highlights VALUES('45369847_49_3641-3721','45369847',49,'稳定：拖累成长脚步的元凶','但我们必须自己行动起来，让自己的大脑更快地适应当下的环境，适应这个充满变化和可能性的世界，从发展和完善中获得安全感。这可能是在这个时代，我们最需要去完成的课题。','3641-3721',1,1753622189,1782480550);
INSERT INTO highlights VALUES('45369847_49_1371-1410','45369847',49,'稳定：拖累成长脚步的元凶','适应性：大脑希望我们的生活模式是稳定不变的，一旦发生变化，它就想尽量恢复原状。','1371-1410',1,1753621837,1782480550);
INSERT INTO highlights VALUES('45369847_49_1318-1354','45369847',49,'稳定：拖累成长脚步的元凶','一致性：大脑希望接收的信息跟内在的心智模型是一致的，尽量减少矛盾和冲突。','1318-1354',1,1753621820,1782480550);
INSERT INTO highlights VALUES('45369847_49_1264-1301','45369847',49,'稳定：拖累成长脚步的元凶','确定性：大脑希望未来是可以根据过往的经验进行预测的，尽量减少模糊和不确定。','1264-1301',1,1753621801,1782480550);
INSERT INTO highlights VALUES('45369847_48_4604-4643','45369847',48,'节能：为了不思考，人类什么都做得出来','在不考虑其他因素的情况下，如果一张面孔多次出现，我们对它的感受就会越趋于喜欢。','4604-4643',1,1753621126,1782480550);
INSERT INTO highlights VALUES('45369847_48_3733-3739','45369847',48,'节能：为了不思考，人类什么都做得出来','赫伯特·西蒙','3733-3739',1,1753620839,1782480550);
INSERT INTO highlights VALUES('45369847_64_8317-8345','45369847',64,'威胁敏感：你是精神内耗者吗','而对碎片时间最好的利用方式，不是阅读，不是学习，是思考。','8317-8345',0,1753444314,1782480550);
INSERT INTO highlights VALUES('45369847_64_1835-1927','45369847',64,'威胁敏感：你是精神内耗者吗','当我们专注在某个任务上面时，这时激发的大脑模式，叫作中央执行网络（Central Executive Network，以下简称CEN）。它会高度激活与当前任务相关的区域，抑制其他区域。','1835-1927',0,1753405889,1782480550);
INSERT INTO highlights VALUES('45369847_63_783-829','45369847',63,'三分钟热度？蚕食行动力的四个原因','这些现象，你可以叫它拖延，也可以叫它懒惰，它们的本质其实是一样的，都是“缺乏行动力”的表现。','783-829',0,1753405568,1782480550);
INSERT INTO highlights VALUES('45369847_61_3763-3831','45369847',61,'避免“计数器陷阱”','这一步，可以参考行为科学家福格(BJ Fogg)“福格行为模型”中的一个小技巧：把新习惯放到旧习惯后面，让旧习惯成为新习惯的“触发器”。','3763-3831',0,1753405314,1782480550);
INSERT INTO highlights VALUES('45369847_60_5154-5238','45369847',60,'系统优化法：把自律变成自驱','更好的方式是什么呢？首先，你要设计一个框架，明确自己想要的理想结果。比如：为什么想要去读书？想了解的领域和主题是什么？想通过这段时间的读书，弄懂什么问题、达到什么效果？','5154-5238',0,1753320057,1782480550);
INSERT INTO highlights VALUES('45369847_60_4696-4712','45369847',60,'系统优化法：把自律变成自驱','让它朝着“想要的结果”前进一步。','4696-4712',0,1753320041,1782480550);
INSERT INTO highlights VALUES('45369847_60_4277-4344','45369847',60,'系统优化法：把自律变成自驱','总而言之，先设定框架，再建立一个最简单的系统，最后不断去优化它，直到实现想要的愿景。这个方法可以在最大化动力的同时，最小化我们的阻力。','4277-4344',0,1753320015,1782480550);
INSERT INTO highlights VALUES('45369847_60_2045-2099','45369847',60,'系统优化法：把自律变成自驱','在这个时代，当我们想动起来去改变自己，探寻一种新的、更健康的生活方式时，其实是在与我们身处的整个环境作斗争。','2045-2099',0,1753319849,1782480550);
INSERT INTO highlights VALUES('45369847_60_1826-1912','45369847',60,'系统优化法：把自律变成自驱','你明知道时间宝贵，却还是瘫着刷手机、看视频，是因为缺乏意志力吗？不是。是因为你每一次告诉自己“好累啊，歇会吧”的时候，大脑都忠实地接收到了这条信息，并又一次强化了这种习惯。','1826-1912',0,1753319827,1782480550);
INSERT INTO highlights VALUES('45369847_60_1768-1826','45369847',60,'系统优化法：把自律变成自驱','无法坚持运动、锻炼的习惯，是因为缺乏意志力吗？不是。是因为你一直以来都习惯待着不动，大脑一时间适应不了“运动”模式。','1768-1826',0,1753319823,1782480550);
INSERT INTO highlights VALUES('45369847_60_1064-1118','45369847',60,'系统优化法：把自律变成自驱','我读一本书的时候，绝不会持有“我要把这本书读完”的任务心态，而是想着“我有一个问题，这本书能解答我的疑惑”。','1064-1118',0,1753319752,1782480550);
INSERT INTO highlights VALUES('45369847_59_4861-4950','45369847',59,'意志力真的存在吗？','试试让自己接受“意志力无限”的设定，将思维转变成：终于干完今天的活了，又有一段自由支配的时间，可以去做真正想做的、重要而不紧急的事情了。这会让你的生活变得更充实，更有“获得感”。','4861-4950',0,1753319657,1782480550);
INSERT INTO highlights VALUES('45369847_59_1727-1756','45369847',59,'意志力真的存在吗？','只要你相信意志力是无限的，那么对你而言，意志力就是无限的。','1727-1756',0,1753317603,1782480550);
INSERT INTO highlights VALUES('45369847_56_4075-4154','45369847',56,'七个日常练习，提高情绪免疫力','身体状态决定了你心理状态的上限。一个具备更佳身体状态的人，在面对压力和挑战时，总是能够比一个状态不佳的人拥有更强的主动性、进取心、自信心，以及毫不懈怠的毅力。','4075-4154',0,1753305141,1782480550);
INSERT INTO highlights VALUES('45369847_56_2036-2081','45369847',56,'七个日常练习，提高情绪免疫力','进行线下的社交是最好的，因为它可以充分调动你的前额叶皮质，让它始终保持活跃，使它变得更发达','2036-2081',0,1753304180,1782480550);
INSERT INTO highlights VALUES('45369847_56_1738-1817','45369847',56,'七个日常练习，提高情绪免疫力','如果你目前还没有一个能够依赖的“后花园”，不妨花一点时间去探索世界，接触一些平时被忽略的事情，从中找到可以去尝试的方向。这会是你对抗压力和负面情绪的有力支撑。','1738-1817',0,1753304151,1782480550);
INSERT INTO highlights VALUES('45369847_56_1073-1177','45369847',56,'七个日常练习，提高情绪免疫力',unistr('后花园\u000a想办法为自己找到一个心灵的“后花园”。也就是培养一个兴趣爱好，把它作为一种休息和放松的方式。这个爱好最好是你感兴趣，愿意投入时间去动手创作的。'),'1073-1177',0,1753304068,1782480550);
INSERT INTO highlights VALUES('45369847_56_709-784','45369847',56,'七个日常练习，提高情绪免疫力','在这个时间段之外，当你产生任何焦虑和担忧时，都先不要去想它们，而是把它们快速记下来，并告诉自己：“现在不是该焦虑的时候，我先记下来，等到点再去考虑。”','709-784',0,1753304043,1782480550);
INSERT INTO highlights VALUES('45369847_55_6474-6505','45369847',55,'掌控情绪的四种武器','一个简单易行的做法是定期记录下一段时间里面，我“做对了什么”。','6474-6505',0,1753303973,1782480550);
INSERT INTO highlights VALUES('45369847_55_6044-6143','45369847',55,'掌控情绪的四种武器','我们之所以容易受到情绪的侵袭，除了对未知的威胁和挑战过度夸大，造成不必要的担忧和恐惧之外，另一方面原因在于对自己的能力不够自信。生活中的威胁容易唤起自己失败和挫折的回忆，从而难以鼓起勇气去克服困难。','6044-6143',0,1753303846,1782480550);
INSERT INTO highlights VALUES('45369847_55_2555-2625','45369847',55,'掌控情绪的四种武器','情绪的产生并不是必然的。我们依据已有的信念，对外界事件进行解读，从而产生对应的情绪反应。如果我们的信念发生改变，那么产生的情绪也会随之改变。','2555-2625',0,1753287515,1782480550);
INSERT INTO highlights VALUES('45369847_54_5196-5298','45369847',54,'愤怒、恐惧、焦虑，它们来自哪里','小结一下。愤怒、恐惧、焦虑三种情绪的生理基础都与“杏仁核-前额叶”通路密切相关。杏仁核和前额叶是互相抑制、此消彼长的关系，锻炼我们的前额叶，可以有效抑制杏仁核的活跃，从而减少负面情绪的困扰。','5196-5298',0,1753234938,1782480550);
INSERT INTO highlights VALUES('45369847_54_4712-4784','45369847',54,'愤怒、恐惧、焦虑，它们来自哪里','有些人特别容易受负面情绪的侵扰，其中一个非常重要的原因就是他们的杏仁核太强大、太活跃，而前额叶又比较弱，锻炼得比较少，从而无法彻底“镇住”杏仁核','4712-4784',0,1753234868,1782480550);
INSERT INTO highlights VALUES('45369847_54_3683-3764','45369847',54,'愤怒、恐惧、焦虑，它们来自哪里','灾难性想象”。它产生的原因是，为了更好地趋利避害，大脑被塑造得对危险远远比对收益更敏感。哪怕是好坏参半的结果，大脑也会自动对坏结果赋予更高的权重，更加谨慎地对待。','3683-3764',0,1753234799,1782480550);
INSERT INTO highlights VALUES('45369847_54_2902-2981','45369847',54,'愤怒、恐惧、焦虑，它们来自哪里','可以说，焦虑与恐惧是同源的，它本质上是一种低度的、持续的、弥散的恐惧。恐惧是由某个具体对象所诱发的应激反应，而焦虑是由这个对象的可能性和不确定性所诱发的反应。','2902-2981',0,1753234509,1782480550);
INSERT INTO highlights VALUES('45369847_54_2613-2709','45369847',54,'愤怒、恐惧、焦虑，它们来自哪里','焦虑的本质是对不确定性的担忧。当我们面对一个可能但尚未到来的危险时，它的不确定性就会占据我们大脑的思考空间。这种不确定性所导致的负荷感，以及不稳定所带来的未完成感，萦绕在脑海中，就形成了焦虑。','2613-2709',0,1753234496,1782480550);
INSERT INTO highlights VALUES('45369847_54_2529-2562','45369847',54,'愤怒、恐惧、焦虑，它们来自哪里','用情绪维度理论来划分，愤怒是负面且可控的，恐惧则是负面且不可控的。','2529-2562',0,1753234392,1782480550);
INSERT INTO highlights VALUES('45369847_53_2833-2880','45369847',53,'情绪的本质：大脑预装的报警器','。而在负面情绪里面，最常见、对我们影响最大的是什么呢？是愤怒，恐惧，以及广受心理学家关注的焦虑','2833-2880',0,1753233035,1782480550);
INSERT INTO highlights VALUES('45369847_53_1997-2075','45369847',53,'情绪的本质：大脑预装的报警器','研究情绪的先驱保罗·艾克曼(Paul Ekman)认为：人有6种基本情绪，分别是恐惧、愤怒、喜悦、悲伤、厌恶和惊讶。后来他又作了修正，加上了轻蔑，变成7种。','1997-2075',0,1753232876,1782480550);
INSERT INTO highlights VALUES('45369847_53_1516-1545','45369847',53,'情绪的本质：大脑预装的报警器','情绪这个警报器，在现代更加稳定、安全的环境里显得过于敏感。','1516-1545',0,1753232824,1782480550);
INSERT INTO highlights VALUES('45369847_53_520-604','45369847',53,'情绪的本质：大脑预装的报警器','情绪的本质是什么？从进化的角度讲，情绪相当于大脑的一个报警器。它不间断地扫描着周围的环境，一旦监测到环境中存在异常信息，就会立即给身体发送信号，让身体切换到对应的状态。','520-604',0,1753232689,1782480550);
INSERT INTO highlights VALUES('45369847_51_5850-5879','45369847',51,'反馈：让你停不下来的甜蜜陷阱','不妨试一试，有意识地远离短期反馈，避免自己的阈值被无限拉高','5850-5879',0,1753232548,1782480550);
INSERT INTO highlights VALUES('45369847_51_3981-4062','45369847',51,'反馈：让你停不下来的甜蜜陷阱','上瘾”就是一个典型的高动机低快感的现象。当我们沉迷于某一事物时，我们可能并不感到快乐，但就是控制不住自己，原因就在于这些奖励刺激的是我们的奖赏回路，而不是享乐热点','3981-4062',0,1753232366,1782480550);
INSERT INTO highlights VALUES('45369847_51_3126-3141','45369847',51,'反馈：让你停不下来的甜蜜陷阱','多巴胺调控的是动机，而非快乐。','3126-3141',0,1753232164,1782480550);
INSERT INTO highlights VALUES('45369847_50_6725-6792','45369847',50,'预测：喂给大脑什么，它就会变成什么','因此在生活管理中，我设置了一个“15%可能性”的项目，也就是抽出大约15%的时间去尝试和探索自己没有做过的事情，为生活引进一些新鲜感。','6725-6792',1,1753200485,1782480550);
INSERT INTO highlights VALUES('45369847_50_6516-6583','45369847',50,'预测：喂给大脑什么，它就会变成什么','大脑的稳定原理希望生活尽可能一成不变，但大脑的预测原理告诉我们，完全一成不变是不可取的，我们还是需要一定的新鲜刺激才能更好地生存下去。','6516-6583',1,1753200461,1782480550);
INSERT INTO highlights VALUES('45369847_50_6009-6073','45369847',50,'预测：喂给大脑什么，它就会变成什么','我们之所以排斥无聊，正是因为大脑根据整个进化史以及我们的生活经验，形成了一种心智模型：一成不变的生活是不好的，不利于我们的生存。','6009-6073',1,1753200423,1782480550);
INSERT INTO highlights VALUES('45369847_50_6214-6279','45369847',50,'预测：喂给大脑什么，它就会变成什么','大脑在心智模型里面，会建立起一条非常重要的规则：我们不能局限在一成不变的环境里，必须时不时有一些新的刺激，有一些陌生的探索和反馈。','6214-6279',0,1753159254,1782480550);
INSERT INTO highlights VALUES('45369847_50_5384-5456','45369847',50,'预测：喂给大脑什么，它就会变成什么','我常常说：“当你产生情绪时，先退一步，缓一缓，再行动，这是最有效的控制情绪的方法。”因为情绪本质上也是大脑按照预测加工模式所向我们发出的一个信号','5384-5456',0,1753159176,1782480550);
INSERT INTO highlights VALUES('45369847_50_758-830','45369847',50,'预测：喂给大脑什么，它就会变成什么','在这种情况下，大脑每一天的工作是通过外界输入的电信号，微调神经元之间的连接，优化由神经元构成的神经网络，使得这个神经网络能够更好地反映外部世界。','758-830',0,1753122792,1782480550);
INSERT INTO highlights VALUES('45369847_49_7513-7552','45369847',49,'稳定：拖累成长脚步的元凶','大脑认知的改变不是突变，而是渐变。就像种下一颗种子，悉心照料，等待它慢慢成长。','7513-7552',0,1753122545,1782480550);
INSERT INTO highlights VALUES('45369847_49_7276-7331','45369847',49,'稳定：拖累成长脚步的元凶','为什么我们总是难以真正有效地改变自己？因为一切偏离基线的状态和行为，对大脑来说都是异常的，都是需要纠正和修复的','7276-7331',0,1753122529,1782480550);
INSERT INTO highlights VALUES('45369847_49_4947-4989','45369847',49,'稳定：拖累成长脚步的元凶','你持有什么立场，就总是更容易接受与你的立场相一致的信息，下意识忽略那些不一致的信息。','4947-4989',0,1752231467,1782480550);
INSERT INTO highlights VALUES('45369847_49_4757-4823','45369847',49,'稳定：拖累成长脚步的元凶','如果我们对一个人有成见，那么当他做了一些不符合我们心意的事情时，我们就会更容易注意到，同时在心里对自己说“看吧，他果然是这样的人”。','4757-4823',0,1752231435,1782480550);
INSERT INTO highlights VALUES('45369847_49_3845-3909','45369847',49,'稳定：拖累成长脚步的元凶','尽量不要对一个事物“立场先行”，不要带着立场去理解它、评判它。因为当我们对一个事物抱持着预设的立场，就很容易落入一致性的陷阱里。','3845-3909',0,1752231286,1782480550);
INSERT INTO highlights VALUES('45369847_49_2604-2696','45369847',49,'稳定：拖累成长脚步的元凶','因此，我们总会下意识地排斥不确定性，企图在不确定性中寻求确定性、建立可控性，让我们感受到：我们对外部世界是有解释的能力的，甚至是有预测和干预的能力的——通过这种方式，让我们获得安全感。','2604-2696',0,1752231182,1782480550);
INSERT INTO highlights VALUES('45369847_49_2286-2382','45369847',49,'稳定：拖累成长脚步的元凶','后来“二战”结束，美军离开了坦纳岛。但岛上的原住民并没有就此罢休，他们发展出了一个宗教，把仓库和跑道当成祭坛，把飞机当成图腾，甚至发展了一套复杂的仪式，祈求他们的神明再次眷顾，为他们送来物资。','2286-2382',0,1752231131,1782480550);
INSERT INTO highlights VALUES('45369847_48_6544-6584','45369847',48,'节能：为了不思考，人类什么都做得出来','人们可以通过强烈的动机，来克服天性中对捷径的倾向，使用更加深思熟虑的方式思考问题','6544-6584',1,1751906448,1782480550);
INSERT INTO highlights VALUES('45369847_48_6495-6515','45369847',48,'节能：为了不思考，人类什么都做得出来','提出了一个2.0版本，叫作“动机策略者”','6495-6515',1,1751906438,1782480550);
INSERT INTO highlights VALUES('45369847_48_5743-5748','45369847',48,'节能：为了不思考，人类什么都做得出来','.代表性：','5743-5748',1,1751906357,1782480550);
INSERT INTO highlights VALUES('45369847_48_5677-5681','45369847',48,'节能：为了不思考，人类什么都做得出来','.可得性','5677-5681',1,1751906353,1782480550);
INSERT INTO highlights VALUES('45369847_48_5562-5602','45369847',48,'节能：为了不思考，人类什么都做得出来','具体来说，卡尼曼把运用系统一做出判断的方式称为“启发式”（可以理解为直觉思考）。','5562-5602',1,1751906343,1782480550);
INSERT INTO highlights VALUES('45369847_48_5197-5265','45369847',48,'节能：为了不思考，人类什么都做得出来','同样，许多人阅读的时候喜欢所谓的“金句”，而这些“金句”之所以会得到青睐，很可能是因为它们足够简单且朗朗上口，从而具备极高的认知流畅性。','5197-5265',1,1751906297,1782480550);
INSERT INTO highlights VALUES('45369847_48_4717-4723','45369847',48,'节能：为了不思考，人类什么都做得出来','单纯曝光效应','4717-4723',0,1751862371,1782480550);
INSERT INTO highlights VALUES('45369847_48_4501-4573','45369847',48,'节能：为了不思考，人类什么都做得出来','认知流畅性是认知心理学中重要的一个理论。它指的是，如果一条信息加工处理起来更流畅、更省力，那么大脑就会更加喜欢它，也会更加倾向于接受它、相信它。','4501-4573',0,1751862352,1782480550);
INSERT INTO highlights VALUES('45369847_48_4049-4122','45369847',48,'节能：为了不思考，人类什么都做得出来','认知吝啬鬼。她们认为，大脑有一个内在的、固定的倾向，那就是对绝大多数事物，都希望采取走捷径的方式快速理解和处理它。因为这样是最省力、最节能的做法。','4049-4122',0,1751862153,1782480550);
INSERT INTO highlights VALUES('45369847_48_3794-3848','45369847',48,'节能：为了不思考，人类什么都做得出来','在这种情况下，我们处理问题的原则并不是做出最好的选择，而是做出性价比最高的选择。这就是他知名的有限理性假说。','3794-3848',0,1751862141,1782480550);
INSERT INTO highlights VALUES('45369847_48_3283-3344','45369847',48,'节能：为了不思考，人类什么都做得出来','所以，为什么习惯那么难以改变？就是因为习惯的本质是一整套自动化加工的结果，是大脑最舒服、最省力的状态，也是大脑最自然的状态','3283-3344',0,1751832794,1782480550);
INSERT INTO highlights VALUES('45369847_48_1912-1987','45369847',48,'节能：为了不思考，人类什么都做得出来','每一分每一秒，大脑都在兢兢业业地接收着外界的信息，用这些信息在大脑内部构建起一个模型，并努力修补这个模型，使得它更加接近真实世界，更好地模拟真实世界。','1912-1987',0,1751832651,1782480550);
INSERT INTO highlights VALUES('45369847_48_2088-2095','45369847',48,'节能：为了不思考，人类什么都做得出来','“贝叶斯大脑”','2088-2095',0,1751832647,1782480550);
INSERT INTO highlights VALUES('45369847_48_1072-1117','45369847',48,'节能：为了不思考，人类什么都做得出来','大脑之所以会不断进化、变得更加复杂，本质上就是为了更好地“趋利避害”，来维持更长久的生存。','1072-1117',0,1751832579,1782480550);
INSERT INTO highlights VALUES('45369847_48_465-478','45369847',48,'节能：为了不思考，人类什么都做得出来','大脑最基本的原理，是节能。','465-478',0,1751832509,1782480550);
INSERT INTO highlights VALUES('3300060305_8_10853-10898','3300060305',8,'第一章 由衷的给予','它指引我们通过将注意力聚焦在观察、感受、需要和请求这四个要素，来重新构建表达和聆听的方式。','10853-10898',1,1713795671,1782480559);
INSERT INTO highlights VALUES('3300060305_8_7951-7977','3300060305',8,'第一章 由衷的给予','有些人在亲密关系中用非暴力沟通创造了深度的连结与关爱','7951-7977',1,1713795603,1782480559);
INSERT INTO highlights VALUES('3300060305_8_6659-6716','3300060305',8,'第一章 由衷的给予','非暴力沟通的一部分是对这四个要素的清晰表达，表达的形式也不拘泥于语言。而另一部分则是从对方的表达中了解这四个要素。','6659-6716',1,1713795477,1782480559);
INSERT INTO highlights VALUES('3300060305_8_6192-6208','3300060305',8,'第一章 由衷的给予','首先，我们观察实际上发生了什么。','6192-6208',1,1713795357,1782480559);
INSERT INTO highlights VALUES('3300060305_8_6076-6163','3300060305',8,'第一章 由衷的给予',unistr('非暴力沟通过程\u000a要达到让双方都能发自内心地相互给予，我们需将注意力聚焦在四个方面——它们是非暴力沟通模式的四个要素。'),'6076-6163',1,1713795348,1782480559);
INSERT INTO highlights VALUES('3300060305_15_3009-3086','3300060305',15,'第八章 同理心的力量','我们越是能够与他人的感受和需要相连，就越不害怕袒露自己。很多时候，我们之所以不愿意展现内心的脆弱，往往是因为我们想要显得“强悍”，害怕失去权威感和掌控感。','3009-3086',1,1702478594,1782480559);
INSERT INTO highlights VALUES('3300060305_15_2447-2486','3300060305',15,'第八章 同理心的力量','在“上司”面前，我们时常急着为自己辩护或向对方道歉，以致无法安静下来同理他们。','2447-2486',1,1702478561,1782480559);
INSERT INTO highlights VALUES('3300060305_15_1055-1098','3300060305',15,'第八章 同理心的力量','如果有人真的听到了你的心声，不对你评头论足，不试图为你负责，也不想改变你，这多么美好啊','1055-1098',1,1702478260,1782480559);
INSERT INTO highlights VALUES('3300060305_14_18211-18216','3300060305',14,'第七章 以同理心倾听','不完全一致','18211-18216',1,1702478207,1782480559);
INSERT INTO highlights VALUES('3300060305_14_17094-17157','3300060305',14,'第七章 以同理心倾听',unistr('5.A：你怎么可以这样和我说话？\u000aB：我那样说话，你是不是很伤心？'),'17094-17157',1,1702478158,1782480559);
INSERT INTO highlights VALUES('3300060305_14_18079-18165','3300060305',14,'第七章 以同理心倾听','如果你选择这个对话，我们的意见不一致。我认为B在为A的感受承担责任，而非同理A的内心世界。如果用同理的方式来回应A,B可以说：“你是不是有些伤心，你希望我能同意你的请求？”','18079-18165',1,1702478147,1782480559);
INSERT INTO highlights VALUES('3300060305_14_17383-17385','3300060305',14,'第七章 以同理心倾听','8.','17383-17385',1,1702478079,1782480559);
INSERT INTO highlights VALUES('3300060305_14_17188-17190','3300060305',14,'第七章 以同理心倾听','6.','17188-17190',1,1702478059,1782480559);
INSERT INTO highlights VALUES('3300060305_14_16868-16870','3300060305',14,'第七章 以同理心倾听','3.','16868-16870',1,1702477966,1782480559);
INSERT INTO highlights VALUES('3300060305_14_13182-13249','3300060305',14,'第七章 以同理心倾听','当意识到自己处于辩解防卫的状态或痛苦得无法同理他人时，我们可以选择(1)停顿，深呼吸，同理自己；(2)“非暴力呐喊”；(3)离开现场。','13182-13249',1,1702474915,1782480559);
INSERT INTO highlights VALUES('3300060305_14_11728-11755','3300060305',14,'第七章 以同理心倾听','你越是忠实地聆听自己内心的声音，就越能听到外面的世界。','11728-11755',1,1702474907,1782480559);
INSERT INTO highlights VALUES('3300060305_14_8594-8700','3300060305',14,'第七章 以同理心倾听','作家、神话学家约瑟夫·坎贝尔说过：“腾出‘他人如何看待我’这个想法的空间给天赐之福。”一旦我们将那些原本听起来像批评或指责的话看作来自他人的礼物——为身处痛苦中的人们提供服务的机会，我们就会感受到这份极致的幸福。','8594-8700',1,1701876729,1782480559);
INSERT INTO highlights VALUES('3300060305_14_8419-8476','3300060305',14,'第七章 以同理心倾听','我们以为自己受到了指责，实际上，人们之所以会说那些话，其实是在诉说他们有一些需要没有得到满足，希望得到我们的帮助。','8419-8476',1,1701876598,1782480559);
INSERT INTO highlights VALUES('3300060305_14_8349-8396','3300060305',14,'第七章 以同理心倾听','正如先前提到的，当我们专注于话语背后的感受和需要时，就再也听不到任何批评、攻击、辱骂和评判了。','8349-8396',1,1701876580,1782480559);
INSERT INTO highlights VALUES('3300060305_14_8116-8209','3300060305',14,'第七章 以同理心倾听','如果我们的语气像是在下判断，仿佛认定对方心里在想什么，这通常会让他人感到不舒服。因而，带着觉知聆听他人的感受和需要时，我们的语气是探询式的，是为了确认我们的理解是否到位，而不是在下结论。','8116-8209',1,1701876542,1782480559);
INSERT INTO highlights VALUES('3300060305_14_8068-8116','3300060305',14,'第七章 以同理心倾听','在复述时，要特别注意语气。一个人在听别人反馈自己的话时，哪怕听到一点点批评或嘲讽，都会格外敏感。','8068-8116',1,1701876531,1782480559);
INSERT INTO highlights VALUES('3300060305_14_6623-6669','3300060305',14,'第七章 以同理心倾听','如果我们实在要这么问，根据我的经验，最好先披露自己的感受和需要，让对方明白我们为什么这样问。','6623-6669',1,1701876276,1782480559);
INSERT INTO highlights VALUES('3300060305_14_5942-5985','3300060305',14,'第七章 以同理心倾听','此外，这样做还有一个好处是，给了对方一些时间来思考自己所说的话，从而有机会深入了解自己','5942-5985',1,1701876043,1782480559);
INSERT INTO highlights VALUES('3300060305_14_3645-3674','3300060305',14,'第七章 以同理心倾听','同理的核心是“临在”——全然地与他人以及他们当下的体验同在','3645-3674',1,1701705551,1782480559);
INSERT INTO highlights VALUES('3300060305_14_1020-1063','3300060305',14,'第七章 以同理心倾听','本章我们将这四个要素运用于沟通过程的另一部分——同理倾听他人的观察、感受、需要和请求。','1020-1063',5,1701493255,1782480559);
INSERT INTO highlights VALUES('3300060305_13_2332-2357','3300060305',13,'第六章 提出请求，丰盈生命','我只知道自己不想要什么，却没有理清自己到底想要什么','2332-2357',5,1701407234,1782480559);
INSERT INTO highlights VALUES('3300060305_12_12864-12905','3300060305',12,'第五章 为自己的感受负责','我们全然地为自己的感受负责，同时我们也意识到，牺牲他人的福祉也无法满足自己的需要。','12864-12905',5,1701356345,1782480559);
INSERT INTO highlights VALUES('3300060305_12_12485-12507','3300060305',12,'第五章 为自己的感受负责','体会他人在消极的话语下隐藏着什么感受与需要。','12485-12507',5,1701356286,1782480559);
INSERT INTO highlights VALUES('3300060305_12_11434-11502','3300060305',12,'第五章 为自己的感受负责','我尝试让她明白，相比委曲求全，真诚待人是一份更加珍贵的礼物。同时我也向她展示了当他人生气时，她可以如何同理对方，而无须为他们的感受负责。','11434-11502',5,1701356004,1782480559);
INSERT INTO highlights VALUES('3300060305_12_11081-11124','3300060305',12,'第五章 为自己的感受负责','我意识到她正在行使新发现的权利——表达自己的需要，即使她采取的方式与他人的需要相冲突。','11081-11124',5,1701355947,1782480559);
INSERT INTO highlights VALUES('3300060305_12_9363-9389','3300060305',12,'第五章 为自己的感受负责','一个人如果无法说出自己的需要，会造成何等痛苦的后果。','9363-9389',5,1701355714,1782480559);
INSERT INTO highlights VALUES('3300060305_12_8759-8812','3300060305',12,'第五章 为自己的感受负责','“36年来，我一直生你父亲的气，我认为他不在乎我的需要。此刻我才意识到，我从没有清楚地告诉他我想要什么。”','8759-8812',5,1701355625,1782480559);
INSERT INTO highlights VALUES('3300060305_12_3832-3873','3300060305',12,'第五章 为自己的感受负责','孩子为了父母的感受而改变行为来迎合父母，那么改变也只是为了避免愧疚，而非出自真心。','3832-3873',5,1701354609,1782480559);
INSERT INTO highlights VALUES('3300060305_12_3397-3444','3300060305',12,'第五章 为自己的感受负责','为了让我们对自身所负的责任有更多的意识，我们可以替换成“我感到……因为我……”这样的句式来表达','3397-3444',5,1701354559,1782480559);
INSERT INTO highlights VALUES('3300060305_12_2256-2418','3300060305',12,'第五章 为自己的感受负责',unistr('在以下表达失望的例子中，请注意其中的差异：\u000a例1：\u000a甲：“昨晚你没来，让我很失望。”\u000a乙：“昨晚你没来，我很失望，因为我想要和你聊一些烦心事。”'),'2256-2418',5,1701354415,1782480559);
INSERT INTO highlights VALUES('3300060305_12_2473-2493','3300060305',12,'第五章 为自己的感受负责','而乙将他的失望归因于自己未被满足的需要。','2473-2493',5,1701354414,1782480559);
INSERT INTO highlights VALUES('3300060305_12_2099-2120','3300060305',12,'第五章 为自己的感受负责','第四种选择是关注对方想要表达的感受和需要。','2099-2120',5,1701354330,1782480559);
INSERT INTO highlights VALUES('3300060305_12_1559-1587','3300060305',12,'第五章 为自己的感受负责','感受源自我们如何看待他人的言行以及我们当时的需要和期待。','1559-1587',5,1701354288,1782480559);
INSERT INTO highlights VALUES('3300060305_12_1528-1559','3300060305',12,'第五章 为自己的感受负责','他人的言行举止或许会激发我们的感受，但绝非产生这些感受的原因。','1528-1559',5,1701354283,1782480559);
INSERT INTO highlights VALUES('3300060305_11_5307-5346','3300060305',11,'第四章 体会与表达感受','在非暴力沟通中，我们需要区分：我们是在表达自己的感受，还是在表达对自己的想法。','5307-5346',5,1701234754,1782480559);
INSERT INTO highlights VALUES('3300060305_11_5560-5679','3300060305',11,'第四章 体会与表达感受',unistr('“想到我的吉他弹奏水平，我感到失望。”\u000a“想到我的吉他弹奏水平，我感到着急。”\u000a“想到我的吉他弹奏水平，我感到沮丧。”'),'5560-5679',5,1701234749,1782480559);
INSERT INTO highlights VALUES('3300060305_11_2903-2974','3300060305',11,'第四章 体会与表达感受','和他们说话就像对着一堆机器，所以我们不喜欢找他们咨询问题。”于是，我鼓励技术部门的成员在与同事们沟通时更多地表达他们的感受，之后情况就改善了。','2903-2974',5,1701219602,1782480559);
INSERT INTO highlights VALUES('3300060305_11_1023-1070','3300060305',11,'第四章 体会与表达感受','成熟的人能捕捉到感受的细微差别，不论是强烈热忱的，还是微妙细腻的，就好像聆听交响乐的不同乐章。','1023-1070',5,1701188473,1782480559);
INSERT INTO highlights VALUES('3300060305_10_7830-7893','3300060305',10,'第三章 不带评论的观察','非暴力沟通的第一个要素是区分观察与评论。当我们在观察中夹杂着自己的评论时，他人往往会认为我们在批评他们，并因而产生抗拒的心理。','7830-7893',5,1701173268,1782480559);
INSERT INTO highlights VALUES('3300060305_10_4715-4746','3300060305',10,'第三章 不带评论的观察','对大部分人来说，观察他人而不做任何评判、批判或分析是很困难的。','4715-4746',5,1701167655,1782480559);
INSERT INTO highlights VALUES('3300060305_10_4636-4654','3300060305',10,'第三章 不带评论的观察','不带评论的观察是人类智力的最高形式。','4636-4654',5,1701167637,1782480559);
INSERT INTO highlights VALUES('3300060305_10_2235-2260','3300060305',10,'第三章 不带评论的观察','非暴力沟通并不要求我们保持完全客观，不做任何评论。','2235-2260',5,1701167506,1782480559);
INSERT INTO highlights VALUES('3300060305_9_7813-7850','3300060305',9,'第二章 疏离生命的语言','用惩罚的方式强迫他人是多么愚蠢，而我真希望自己不曾用那样的方式来对待他们。','7813-7850',5,1701167201,1782480559);
INSERT INTO highlights VALUES('3300060305_9_5266-5297','3300060305',9,'第二章 疏离生命的语言','当我们将行动的原因归咎于外部因素时，我们便在试图推卸自己的责任','5266-5297',5,1701164663,1782480559);
INSERT INTO highlights VALUES('3300060305_9_4946-4975','3300060305',9,'第二章 疏离生命的语言','借由这样的说法，我们也回避了为自己的感受和想法所负的责任。','4946-4975',5,1701164642,1782480559);
INSERT INTO highlights VALUES('3300060305_9_3966-3999','3300060305',9,'第二章 疏离生命的语言','他建议读者，如果真的想让自己的生活变得悲惨，就去学着与他人做比较。','3966-3999',5,1701164531,1782480559);
INSERT INTO highlights VALUES('3300060305_9_2721-2773','3300060305',9,'第二章 疏离生命的语言','在这里，重要的是不要把“价值判断”与“道德评判”混为一谈。每个人都会对生命中自己所珍视的品质做出价值判断','2721-2773',5,1701160061,1782480559);
INSERT INTO highlights VALUES('3300060305_9_2483-2543','3300060305',9,'第二章 疏离生命的语言','在我看来，当我们在分析和评判时，其实都是在表达自身的价值观和需要，但这样的表达方式却是悲剧性的，引发的是对方的防卫与抗拒','2483-2543',5,1701160014,1782480559);
INSERT INTO highlights VALUES('3300060305_8_6851-6944','3300060305',8,'第一章 由衷的给予','如此你来我往，最终双方都能自然而然地展现善意：我此刻的观察、感受和需要是什么；为了让我的生命更美好，我的请求是什么；你此刻的观察、感受和需要是什么；为了让你的生命更美好，你的请求是什么？','6851-6944',5,1701146185,1782480559);
INSERT INTO highlights VALUES('3300060305_8_5380-5419','3300060305',8,'第一章 由衷的给予','每当我们想要丰盈他人的生命，由衷给予他人时，我们是出于心中油然而生的喜悦之情。','5380-5419',5,1701108002,1782480559);
INSERT INTO highlights VALUES('3300060305_8_5190-5203','3300060305',8,'第一章 由衷的给予','你施于我，我给予我的接受；','5190-5203',5,1701107978,1782480559);
INSERT INTO highlights VALUES('3300060305_8_4692-4738','3300060305',8,'第一章 由衷的给予','为此，我开发了非暴力沟通。它作为一种训练注意力的方式，让我们可以把注意力放在真正要去的地方。','4692-4738',5,1701107941,1782480559);
INSERT INTO highlights VALUES('3300060305_8_4275-4346','3300060305',8,'第一章 由衷的给予','尽管我称非暴力沟通是一种“沟通过程”或是“善意沟通”，它却不止于此。在一个更深的层面，它是持续的提醒，让我们更好地专注于自己的生命意义和方向。','4275-4346',5,1701107865,1782480559);
INSERT INTO highlights VALUES('3300060305_8_4194-4246','3300060305',8,'第一章 由衷的给予','通过强调深度聆听自己和他人，非暴力沟通能够培育我们对他人的尊重、觉察与同理心，并愿意发自内心地相互给予。','4194-4246',5,1701107854,1782480559);
INSERT INTO highlights VALUES('3300060305_8_3120-3162','3300060305',8,'第一章 由衷的给予','这里借用甘地曾使用的“非暴力”一词，来指代当暴力从心中消融，天性中的善自然呈现的状态','3120-3162',5,1701089958,1782480559);
INSERT INTO highlights VALUES('3300060305_6_2329-2347','3300060305',6,'序言','温柔的人有福了，因为他们必承受土地。','2329-2347',5,1701089555,1782480559);
INSERT INTO highlights VALUES('3300060305_6_2241-2262','3300060305',6,'序言','解决所有暴力的唯一道路便是放下自己的执见。','2241-2262',5,1701089538,1782480559);
INSERT INTO highlights VALUES('3300060305_6_1892-1940','3300060305',6,'序言','他认为所有的说辞都会有意无意地造成冲突，所以他将焦点放在连结上——搭建人与人之间一座心灵的桥梁。','1892-1940',5,1701089492,1782480559);
INSERT INTO highlights VALUES('3300060305_6_1965-1985','3300060305',6,'序言','重要的不是你做了什么，而是你注意力的品质','1965-1985',5,1701089463,1782480559);
INSERT INTO highlights VALUES('3300060305_6_1677-1784','3300060305',6,'序言',unistr('“Ahimsa”的首要宗旨是：不伤害。让我对刚刚过世不久、享年80岁的马歇尔博士钦佩不已的是，他把握住了“非暴力”的两方面：行动和意识。\u000a“非暴力沟通”的过程'),'1677-1784',5,1701089429,1782480559);
INSERT INTO highlights VALUES('3300060305_6_1339-1361','3300060305',6,'序言','马歇尔认为，我们并不等同于我们的观念（故事）','1339-1361',5,1701089375,1782480559);
INSERT INTO highlights VALUES('3300060305_6_1181-1263','3300060305',6,'序言','千百年来全世界都在同一时期出现尚武或恐武的价值思想。荣格学派的心理学家认为，战神的原型存在于每个人的潜意识中，因而冲突和侵略乃无可避免的现象，这是人类与生俱来的恶。','1181-1263',5,1701089348,1782480559);
INSERT INTO highlights VALUES('3300060305_6_541-556','3300060305',6,'序言','你说出口的话将会改变你的人生。','541-556',5,1700970800,1782480559);
INSERT INTO highlights VALUES('3300060305_5_2002-2021','3300060305',5,'译序','便是“非暴力”的精神与力量：心无敌人。','2002-2021',5,1700970738,1782480559);
INSERT INTO highlights VALUES('3300060305_5_1527-1618','3300060305',5,'译序','《非暴力沟通》难道不是关于人际沟通、好好说话吗？我希望透过这一版的《非暴力沟通》能够为大家更清晰地呈现马歇尔在书名中所要展现的：一种生命的语言。“我想要与那美妙的生命之流保持连结。”','1527-1618',5,1700970514,1782480559);
INSERT INTO highlights VALUES('3300060305_5_466-488','3300060305',5,'译序','体会其大道至简背后所蕴藏着的对人性深刻的理解','466-488',5,1700966136,1782480559);
INSERT INTO highlights VALUES('3300060305_4_984-1106','3300060305',4,'中文版序','于我，从马歇尔那收获的重大学习是自我同理。通过自我同理，我对自己有了更多的理解和认识。例如理解自己为什么会去做那些让自己后悔的事情。这意味着，如果在行动之前就能懂得这些，我便不用如此行动。我学会了如何理解我的错误，我也学会了宽恕自己意味着什么。','984-1106',5,1700965979,1782480559);
INSERT INTO highlights VALUES('3300060305_4_706-772','3300060305',4,'中文版序','马歇尔向我们展示了如何在日常生活中一步一步地做到这些，不论是在家庭中还是工作中，如此我们将拥有改变情境的力量，而不是让它变得更糟糕。','706-772',5,1700965948,1782480559);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_271_5436-5441','CB_AzO97m9AzGVz6al6YD',271,'《北京法源寺》离诺贝尔文学奖还有多远□ 记者（下文简称记）：最近，由于您的小说‘北京法源寺’获得推荐，参选今年的诺贝尔文学奖，您成为媒体和公众瞩目的焦点人物，因为这个奖一直是国人心中的情结。','心肠太软！','5436-5441',NULL,1665156561,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_271_5309-5407','CB_AzO97m9AzGVz6al6YD',271,'《北京法源寺》离诺贝尔文学奖还有多远□ 记者（下文简称记）：最近，由于您的小说‘北京法源寺’获得推荐，参选今年的诺贝尔文学奖，您成为媒体和公众瞩目的焦点人物，因为这个奖一直是国人心中的情结。',unistr('：自信，是一种技巧的表达，说对我捧得不够，是一种戏谑的说法。其实我本人是很谦虚的。\u000a自恋是因为我的确比别人伟大。其实每个人都是自恋的。\u000a其实我很知道我的缺点是什么。'),'5309-5407',NULL,1665156557,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_271_4666-4723','CB_AzO97m9AzGVz6al6YD',271,'《北京法源寺》离诺贝尔文学奖还有多远□ 记者（下文简称记）：最近，由于您的小说‘北京法源寺’获得推荐，参选今年的诺贝尔文学奖，您成为媒体和公众瞩目的焦点人物，因为这个奖一直是国人心中的情结。','李：我是很精明的，很早我就知道不能穷酸潦倒，口袋不空才能挺直腰杆，才能不求人、不看人脸色、不怕被封锁。我早有准备。','4666-4723',NULL,1665156477,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_271_3135-3223','CB_AzO97m9AzGVz6al6YD',271,'《北京法源寺》离诺贝尔文学奖还有多远□ 记者（下文简称记）：最近，由于您的小说‘北京法源寺’获得推荐，参选今年的诺贝尔文学奖，您成为媒体和公众瞩目的焦点人物，因为这个奖一直是国人心中的情结。','李：康有为实际上是写我自己。他一直走在最前面，但走得太快了，大家跟不上，就认为他落伍了。其实他的见解无人能及。康有为的想法和我自己的想法很像，实际上受古代文化影响的人都会像他。','3135-3223',NULL,1665156323,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_271_3025-3083','CB_AzO97m9AzGVz6al6YD',271,'《北京法源寺》离诺贝尔文学奖还有多远□ 记者（下文简称记）：最近，由于您的小说‘北京法源寺’获得推荐，参选今年的诺贝尔文学奖，您成为媒体和公众瞩目的焦点人物，因为这个奖一直是国人心中的情结。','李：我会选梁启超。谭嗣同是以身殉道的烈士，最后被杀头，是失败者。而梁启超是战士，危难时逃走保身，以后再回来推翻清朝。','3025-3083',NULL,1665156299,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_271_2332-2374','CB_AzO97m9AzGVz6al6YD',271,'《北京法源寺》离诺贝尔文学奖还有多远□ 记者（下文简称记）：最近，由于您的小说‘北京法源寺’获得推荐，参选今年的诺贝尔文学奖，您成为媒体和公众瞩目的焦点人物，因为这个奖一直是国人心中的情结。','西方语文学界总有一天要了解中国，中国占有全世界1/4的人口，西方无法漠视东方的存在。','2332-2374',NULL,1665156218,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_21_3333-3366','CB_AzO97m9AzGVz6al6YD',21,'《北京法源寺》作为书名，是十六年前我第一次做政治犯时在国民党黑狱中决定的。自一九七一年起，我被国民党政府关过两次，第一次十足关了五年八个月；第二次十足关了六个月，一共十足关了六年两个月，再加上被在家软禁十四个月，一共是七年四个月。七年四个月中，六年两个月是在牢里度过的。我历经七间牢房，其中有保安处不见天日的密封房、有军法处臭气四溢的十一房、有仁教所完全隔离的太平房、有台北看守所龙蛇杂处的三二房……其中住得最久，是军法处的八号房，我一人住了二年半之久。八号房不到两坪大，扣掉四分之一的马桶、水槽和四分之一','正因为如此，我相信除非小说加强仅能由小说来表达的思想，它将殊少前途','3333-3366',NULL,1665155715,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_21_2787-2854','CB_AzO97m9AzGVz6al6YD',21,'《北京法源寺》作为书名，是十六年前我第一次做政治犯时在国民党黑狱中决定的。自一九七一年起，我被国民党政府关过两次，第一次十足关了五年八个月；第二次十足关了六个月，一共十足关了六年两个月，再加上被在家软禁十四个月，一共是七年四个月。七年四个月中，六年两个月是在牢里度过的。我历经七间牢房，其中有保安处不见天日的密封房、有军法处臭气四溢的十一房、有仁教所完全隔离的太平房、有台北看守所龙蛇杂处的三二房……其中住得最久，是军法处的八号房，我一人住了二年半之久。八号房不到两坪大，扣掉四分之一的马桶、水槽和四分之一','例如小和尚普净，他是三个人的合并化身，就参加两次革命而言，他是董必武；就精通佛法而言，他是熊十力；就为共产党献身做烈士而言，他是李大钊','2787-2854',NULL,1665155639,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_21_1728-1879','CB_AzO97m9AzGVz6al6YD',21,'《北京法源寺》作为书名，是十六年前我第一次做政治犯时在国民党黑狱中决定的。自一九七一年起，我被国民党政府关过两次，第一次十足关了五年八个月；第二次十足关了六个月，一共十足关了六年两个月，再加上被在家软禁十四个月，一共是七年四个月。七年四个月中，六年两个月是在牢里度过的。我历经七间牢房，其中有保安处不见天日的密封房、有军法处臭气四溢的十一房、有仁教所完全隔离的太平房、有台北看守所龙蛇杂处的三二房……其中住得最久，是军法处的八号房，我一人住了二年半之久。八号房不到两坪大，扣掉四分之一的马桶、水槽和四分之一','《北京法源寺》以具象的、至今屹立的古庙为纵线，以抽象的、烟消云散的历朝各代的史事人物为横剖，举凡重要的主题：生死、鬼神、僧俗、出入、仕隐、朝野、家国、君臣、忠好、夷夏、中外、强弱、群己、人我、公私、情理、常变、去留、因果、经济（经世济民）等等，都在论述之列。这种强烈表达思想的小说，内容丰富自是罕见的。','1728-1879',NULL,1665155467,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_21_718-728','CB_AzO97m9AzGVz6al6YD',21,'《北京法源寺》作为书名，是十六年前我第一次做政治犯时在国民党黑狱中决定的。自一九七一年起，我被国民党政府关过两次，第一次十足关了五年八个月；第二次十足关了六个月，一共十足关了六年两个月，再加上被在家软禁十四个月，一共是七年四个月。七年四个月中，六年两个月是在牢里度过的。我历经七间牢房，其中有保安处不见天日的密封房、有军法处臭气四溢的十一房、有仁教所完全隔离的太平房、有台北看守所龙蛇杂处的三二房……其中住得最久，是军法处的八号房，我一人住了二年半之久。八号房不到两坪大，扣掉四分之一的马桶、水槽和四分之一','我一人住了二年半之久','718-728',NULL,1665155325,1782480565);
