INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_11_6030-6116','CB_AzO97m9AzGVz6al6YD',11,'第七章　回向',unistr('王安石的一首《梦》诗，老兄还记得吗？\u000a知世如梦无所求，\u000a无所求心普空寂。\u000a还似梦中随梦境，\u000a成就河沙梦功德。'),'6030-6116',NULL,1664950155,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_11_3702-3745','CB_AzO97m9AzGVz6al6YD',11,'第七章　回向','佛法里的‘执’有‘我执’和‘法执’：我执是一般入所认为主观的我；法执是所认为客观的宇宙','3702-3745',NULL,1664949488,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_11_3094-3245','CB_AzO97m9AzGVz6al6YD',11,'第七章　回向','《华严经》有‘回向品’，主张已成‘菩萨道’的人，还得‘回向’人间，由出世回到入世，为众生舍身。这种‘回向’后的舍身，才是真正的佛教。但是，佛教传到中国，中国人只知出世而不知入世，只走了一半，就以为走完了全程。他们的人生与解脱目标是‘涅槃’，以为消极、虚无、生存意志绝灭等，是这种路线的目标，他们全错了。','3094-3245',NULL,1664949307,1782480565);
