INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_9_1218-1361','CB_AzO97m9AzGVz6al6YD',9,'第五章　康进士','这种大著作，可分三部：第一部是打破传统学说的《新学伪经考》，告诉知识分子，要敢于摆脱传统的枷锁；第二部点破孔子真义的《孔子改制考》，告诉知识分子，即使是孔子，也是主张改革现状的，不要怕改革现状；第三部是提出未来远景的《大同书》，告诉知识分子，应先走改革路线以至小康，最后再到大同的境界。','1218-1361',NULL,1664939765,1782480565);
