INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_8_2105-2172','CB_AzO97m9AzGVz6al6YD',8,'第四章　西太后','一八四二年的南京条约起，给了洋鬼子领事裁判权、内河航行权、最惠国待遇、关税的控制、租界的范围、通商的港口、大量的军费赔偿和香港的领土。','2105-2172',NULL,1664902748,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_7_12050-12127','CB_AzO97m9AzGVz6al6YD',7,'第三章　“休怀粉身念”','所以，大事不全是强者做的，弱者也可以做不小的事，如果结局是粉身碎骨，弱者也许不敢做。但如果‘休怀粉身念’，不必多想它，最后弱者做出的功德，也不一定小呢。”','12050-12127',NULL,1664898741,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_7_11736-11883','CB_AzO97m9AzGVz6al6YD',7,'第三章　“休怀粉身念”','丁香很柔弱，结子又多，叶子和花都漂亮，但是是素色中的美丽，不是艳丽的。把丁香种在房子后面，为了是给有思想的人欣赏。丁香自己呢？它早晚像兰麝一样发出芳香，但却不必想到自己会磨成粉的。整首诗的意思是，一个柔弱美丽的生物，它该知道自己的特质，完成自我，虽然自我的最后完成恐怕是粉身碎骨，也不必多想了！','11736-11883',NULL,1664892100,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_7_11067-11178','CB_AzO97m9AzGVz6al6YD',7,'第三章　“休怀粉身念”',unistr('丁香体柔弱，\u000a乱结枝犹垫。\u000a细叶带浮毛，\u000a疏花披素艳。\u000a深栽小斋后，\u000a庶使幽人占。\u000a晚随兰麝中，\u000a休怀粉身念。'),'11067-11178',NULL,1664891991,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_7_10423-10450','CB_AzO97m9AzGVz6al6YD',7,'第三章　“休怀粉身念”','若亡而实在。看起来好像过去了，其实没有、其实还在那儿。','10423-10450',NULL,1664891902,1782480565);
