INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_7_6852-6967','CB_AzO97m9AzGVz6al6YD',7,'第三章　“休怀粉身念”','一般人不了解，全弄错了。鱼和肉叫腥，臭菜——葱、蒜、韭菜等等——叫荤，大家以为荤是鱼和肉，所以吃斋只是不吃鱼和肉，而大吃臭菜，这是精神上先没了解吃素的真义；至于有的庙里大做素鸡素鸭，那简直是精神上完全在吃荤，一点也没吃素的本意了。','6852-6967',NULL,1664891300,1782480565);
