INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_9549-9586','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','康有为。《书经》里‘康济小民’的康；《礼记》里‘养其身以为有为也’的有为。','9549-9586',NULL,1663654523,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_6554-6603','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','袁督师是我们老广第一个影响中国政治举足轻重的人物，明朝不杀他，满洲人就进不了关，中国整个历史都改写','6554-6603',NULL,1663608535,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_5157-5361','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','真正的唯心是破除我执，释迦牟尼与何罗逻仙人辩道时说：‘若能除我及我执，一切尽舍，是名真解脱。’我执就是主观的心，善如果没行出来，只凭主观的心认为已经是善就善了，这是唯心的魔道，不是唯心的正道。唯心的正道是破除这种凭想凭说就算行了善的魔道。真正的唯心在告诉人什么是唯心的限度、什么是光凭唯心做不到的。比如说吃饭，必须吃，想吃和说吃并不算吃，一定要有吃的行为；善也是这类性质，善要有行为，没有行为的善才真是伪善。','5157-5361',NULL,1663608347,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_4983-5074','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','孟子认为发善情就是善，所谓‘乃若其情，则可以谓善矣’；王阳明认为在内心就是善，所谓‘至善只是此心纯乎天理之极便是’，这些抽象的检定善的标准，我是不承认的。善必须要行，藏在心里是不行的','4983-5074',NULL,1663608323,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_4844-4912','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','任何人做出来的善我都肯定，而不以人废善。至于想去行善、说去行善，那只是一念之善，并没有行，那是不算的。善和行善是两回事，善不行，不算是善','4844-4912',NULL,1663608303,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_3100-3116','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','只能说他动机复杂、纯度不够而已。','3100-3116',NULL,1663608079,1782480565);
INSERT INTO highlights VALUES('CB_AzO97m9AzGVz6al6YD_6_3030-3100','CB_AzO97m9AzGVz6al6YD',6,'第二章　寂寞余花','我认为唐太宗做了，不管是后悔后做了、还是忏悔后做了、还是为了女人寡妇做了、还是为了收揽民心做了，不管是什么理由，他做了。你就很难说他是伪善。','3030-3100',NULL,1663608073,1782480565);
