INSERT INTO highlights VALUES('3300056625_117_437-889','3300056625',117,'沉默','是早晨大雾的沉默是中午树荫的沉默是傍晚烟斗的沉默是镰刀，是锄头是一种铁慢慢生锈的沉默故乡的沉默此前是父亲此后是，因为父亲','437-889',1,1719133085,1782398567);
INSERT INTO highlights VALUES('3300056625_112_864-1018','3300056625',112,'春天','的确是这样，我时常万念俱灰。也时常死灰复燃生活给了我多少积雪我就能遇到多少个春天','864-1018',1,1719132878,1782398567);
INSERT INTO highlights VALUES('3300056625_110_437-717','3300056625',110,'寂静','关上窗这一刻的寂静让人心动像流水里躲进一块石头内部的鱼推开窗城市的喧嚣水流一样涌进来到处都在咕嘟咕嘟冒泡','437-717',1,1719132741,1782398567);
INSERT INTO highlights VALUES('3300056625_109_440-1171','3300056625',109,'竹子或扁担','竹子的骨气是因为，心是空的一个了无牵挂的人很容易活出一身正气而扁担则不同作为竹子的一部分需要承担生活的压力一路吱吱扭扭全是琐碎的唠叨和叮嘱不是我矫情总想起过世多年的母亲曾经的孤儿一身正气的铁姑娘后来因为挑着我们被生活劈成三片四片的样子','440-1171',1,1719132672,1782398567);
