INSERT INTO highlights VALUES('3300056625_93_936-1039','3300056625',93,'石台上的老人','让他擦去我满身锈迹让我像一把闪光的铁锹插在新鲜的春泥里','936-1039',1,1719130900,1782398567);
INSERT INTO highlights VALUES('3300056625_88_973-1166','3300056625',88,'一片野芦苇','春天是岁月的加速度一片野芦苇却让我慢下来慢到须发皆白像一个雪人等待季节的确认和融化','973-1166',1,1719130502,1782398567);
INSERT INTO highlights VALUES('3300056625_86_852-1295','3300056625',86,'拾柴记','那年冬天，我接受着一棵树的馈赠和树林一起保守着一棵树的死讯直到开春林管员砍走了那棵树我在那棵树的树墩上哭了一场傍晚，我蹲在墙角看着母亲把最后几根树枝塞进灶膛看着它用火苗忽明忽暗地映照着母亲仿佛晃动的树荫','852-1295',1,1719130272,1782398567);
INSERT INTO highlights VALUES('3300056625_83_1039-1107','3300056625',83,'床前明月光','原来所有的想念都是有重量的从前压弯着一个人，现在压弯另一个人','1039-1107',1,1719130067,1782398567);
INSERT INTO highlights VALUES('3300056625_76_2052-2363','3300056625',76,'麦子熟了','其实，我的余生里始终有一片麦地一直金黄，如漫无边际的黄沙父亲曾用一生的时间在沙里淘金最后只淘了一捧黄土当我把白晃晃的馒头供奉给父亲才发现覆盖父亲的坟只是一个巨大的窝头','2052-2363',1,1719129560,1782398567);
INSERT INTO highlights VALUES('3300056625_76_1171-1382','3300056625',76,'麦子熟了','几十年，父母在麦口里拔芽拔掉自己的黑发换成白发拔掉自己的青年换老年我曾那么惬意地躺在麦子的舌头上以为温柔才是柔软的故乡','1171-1382',1,1719129529,1782398567);
INSERT INTO highlights VALUES('3300056625_75_441-820','3300056625',75,'火车穿过村庄','一列火车从远处赶来又向远方奔去像一位慌张的母亲打着手电，叫喊了一声许多年以后我在阳台小声应答日子仍像一列绿皮火车在深夜过去了一节，还有一节','441-820',1,1719129394,1782398567);
INSERT INTO highlights VALUES('3300056625_71_1023-1127','3300056625',71,'最后一头耕牛','每当黎明现出霞光我都会看见两行潮湿的蹄印和一次含泪的回眸','1023-1127',1,1719128849,1782398567);
INSERT INTO highlights VALUES('3300056625_71_441-674','3300056625',71,'最后一头耕牛','最后一头水牛被从池塘牵出时正值壮年一对弯角轻易就把太阳从地平线里挑出顺便把天空划出伤口','441-674',1,1719128711,1782398567);
