INSERT INTO highlights VALUES('3300056625_60_757-949','3300056625',60,'钢性','看来，我远不如一颗钉子在过去几十年的时光里我也四处碰壁然而至今我仍是一个漂泊的人','757-949',1,1719127928,1782398567);
INSERT INTO highlights VALUES('3300056625_59_442-633','3300056625',59,'想念是一种幸福','想念是把叠好的衣服一件一件放满衣橱怀念是把衣服挂满房间而衣橱是空的','442-633',1,1719127620,1782398567);
INSERT INTO highlights VALUES('3300056625_56_891-948','3300056625',56,'素日','一个人的爱被拒绝却依然保持着明亮不容易','891-948',1,1719127074,1782398567);
INSERT INTO highlights VALUES('3300056625_55_439-585','3300056625',55,'站着打盹','在我身边等餐的兄弟斜靠着墙正在从世界上退出还是正在拥有全部的世界','439-585',1,1719126908,1782398567);
INSERT INTO highlights VALUES('3300056625_54_542-657','3300056625',54,'再明亮的月光也是夜晚','我看见月亮从天上跑下来伏在父亲的右肩，跟随父亲回家月亮安静得很，像个熟睡的孩子','542-657',1,1719126865,1782398567);
INSERT INTO highlights VALUES('3300056625_52_544-603','3300056625',52,'和留守老人攀谈一会儿','一个木匠，儿女们都像完工的家具被租给了南方','544-603',1,1719126697,1782398567);
