INSERT INTO highlights VALUES('3300056625_42_710-996','3300056625',42,'旱情','我可以叫她大婶子四嫂子、二大娘也可以叫她三麦家的她们都有白得发苦的头发像晴空中的白云都有一嗓子嘹亮的哭腔像胡同里的风','710-996',1,1719109268,1782398567);
INSERT INTO highlights VALUES('3300056625_39_868-1116','3300056625',39,'春天','这个七单全超的年轻人现在坐在地下道的出口处抽烟像一根木头想把自己点燃但他潮湿的眼睛让他富含水分所以只能发出滋滋的声音','868-1116',1,1719109151,1782398567);
INSERT INTO highlights VALUES('3300056625_38_852-994','3300056625',38,'时间的水分','还有的人一出生就能将另一个人一生的奋斗拧成一条奔腾的河流','852-994',1,1719108964,1782398567);
INSERT INTO highlights VALUES('3300056625_35_437-1134','3300056625',35,'春光','我可不可以这样理解太阳不制造光而是所有的光创造了太阳所有追逐着光的事物都是艰苦的都要经过黑夜漫长的煎熬枝条默默返青草地默默吐绿这些默默的事物在黑暗里摸索默默构成了一个盛大的春天我可不可以这样认为是花朵成就了春天而不是春天催开了花朵','437-1134',1,1719108828,1782398567);
INSERT INTO highlights VALUES('3300056625_32_437-793','3300056625',32,'靠山','那时我虽小父亲要想举起我就要向上天做出投降的动作放下我又要给大地鞠躬致歉为了我父亲一直在天地之间卑躬屈膝','437-793',1,1719108636,1782398567);
INSERT INTO highlights VALUES('3300056625_31_1019-1214','3300056625',31,'无用之用','每次经过我都无法抵御内心对这些密集断头后的恐惧无法抵御对失去头颅仍要保持站立不倒的恐惧','1019-1214',1,1719108546,1782398567);
INSERT INTO highlights VALUES('3300056625_30_396-900','3300056625',30,'我是虚无的','我是虚无的我总感觉自己是虚无的一些事物常常把我冲散像一团浓烟每次重新聚拢都会少去一部分我还遇到很多和我一样的人我们形成一场场大雾在阳光之前等待又在阳光之中消失','396-900',1,1719108489,1782398567);
INSERT INTO highlights VALUES('3300056625_29_528-946','3300056625',29,'夜行','电瓶车灯照耀的光像一种救赎仿佛世界的开端天地那么大无尽的夜色包裹我如同泥土包裹一颗种子带给我强烈的责任感愿人间所有的黑暗都在与我对峙每一线光明都和我有关','528-946',1,1719108454,1782398567);
INSERT INTO highlights VALUES('3300056625_28_437-534','3300056625',28,'倒影','看这些柔软的水是如何将这沉重的山轻松倒吊的','437-534',1,1719108364,1782398567);
INSERT INTO highlights VALUES('3300056625_27_809-951','3300056625',27,'无题','这多像一些真理被少数人践行总有一些不被认可的路要自己去走','809-951',1,1719108329,1782398567);
INSERT INTO highlights VALUES('3300056625_26_437-873','3300056625',26,'道别','每次和母亲道别我都不再回头就像刮过树梢的风不肯回头就像拐过小桥的流水不肯回头我不能把一场离别分成多次丢给母亲不能让一棵落光叶子的树还在风中摇摆不能让一个老人在冰冷的桥头多次滑倒','437-873',1,1719108303,1782398567);
INSERT INTO highlights VALUES('3300056625_23_437-874','3300056625',23,'时光','我们总以为拥有大把的时光实际上是时光拥有大把的我们比如此刻那么多骑手聚在一起等单就像时光的手指上落满了一群叽叽喳喳的燕子等时光之手把我们握紧几十年来，朝阳一直没变有的人正值青春而我已接近迟暮','437-874',1,1719108083,1782398567);
INSERT INTO highlights VALUES('3300056625_21_663-950','3300056625',21,'灰烬万岁','生而为树没有萎靡于漫长的腐败没有用木耳或蘑菇掩盖内心的不甘和惊慌而是用轰轰烈烈地燃烧向热爱过的大地表明态度','663-950',1,1719107961,1782398567);
INSERT INTO highlights VALUES('3300056625_19_667-724','3300056625',19,'空心菜','是谁早早摘取了我的心却要我活出人间滋味','667-724',1,1719107856,1782398567);
INSERT INTO highlights VALUES('3300056625_18_886-942','3300056625',18,'春天','而我身体里的春天拒绝了一枚青果的成熟','886-942',1,1719107681,1782398567);
INSERT INTO highlights VALUES('3300056625_17_396-1050','3300056625',17,'往事','往事为何我会反复提到钉子我感觉的疼，深入骨髓动一动都有金属的质感如果回头我还要承受分离的痛那些旧时光的钉子把我钉在了今生有些注定会成为过往来世遥远。我力所能及的是把自己从现世的墙壁取下来或者挂上去。而这一切都和钉子有关','396-1050',1,1719107536,1782398567);
INSERT INTO highlights VALUES('3300056625_16_852-1278','3300056625',16,'谋杀者','我在山坡上来回行走曲里曲折的小路像一条白绫一头捆着村庄，一头被我牵着我向村庄走去小路变宽，白绫松弛我向山上攀爬白绫绷紧，小路细长村庄呼吸困难眩晕，被白绫吊着','852-1278',1,1719107468,1782398567);
INSERT INTO highlights VALUES('3300056625_16_438-586','3300056625',16,'谋杀者','我的村庄老了不再像当初那样打闹，欢笑而变得安静，落寞在阳光下昏昏欲睡','438-586',1,1719107438,1782398567);
INSERT INTO highlights VALUES('3300056625_15_782-945','3300056625',15,'天空','一只鸟飞了，也就飞了天空并不因此更加空旷一些日子飞了，也就飞了有的消失于遗忘，有的消失于无尽的怀想','782-945',1,1719107324,1782398567);
INSERT INTO highlights VALUES('3300056625_14_719-1009','3300056625',14,'我爱','我爱这周而复始的生活也爱生活里的小悲伤小欢喜，小意外如果我们老了就让我们像一对坏掉的钟表突然停在了某个时刻让这个时刻成为永恒','719-1009',1,1719106863,1782398567);
INSERT INTO highlights VALUES('3300056625_12_891-1030','3300056625',12,'写诗','所有的钉子不是死于尖锐而是在漫长的等待中被想念锈蚀','891-1030',1,1719106656,1782398567);
INSERT INTO highlights VALUES('3300056625_9_633-689','3300056625',9,'打桩',unistr('打桩机还在哐哐，哐哐，哐哐\u000a像夜的肺病'),'633-689',5,1719538417,1782480557);
INSERT INTO highlights VALUES('3300056625_8_777-1021','3300056625',8,'打工潮','我一直无法描述这样的场景在辽阔的大地上工厂、车间、出租房以及流水线上到处都是散落的标点符号等着被文字重新认领','777-1021',1,1707873901,1782398567);
INSERT INTO highlights VALUES('3300056625_6_437-668','3300056625',6,'失事','想让一张纸站立起来就把纸折出棱角太平整的纸只会俯首帖耳听命于笔而站立起来的纸则不同','437-668',1,1707873639,1782398567);
INSERT INTO highlights VALUES('3300056625_4_1317-1377','3300056625',4,'午夜推行人',unistr('月亮是天空的一处漏洞\u000a所以夜从来都黑得不够彻底'),'1317-1377',5,1719148632,1782480557);
INSERT INTO highlights VALUES('3300056625_3_1665-1738','3300056625',3,'用笔记录生活','我相信世界终究是美好的，也会呈现生活的另一面。就像一棵树的枝叶、枝条上的霜雪、叶片上的虫洞，都是一棵树所要承受的生命之重，但它从不重于生命的本身。','1665-1738',5,1719148452,1782480557);
INSERT INTO highlights VALUES('3300056625_3_434-650','3300056625',3,'用笔记录生活','又到春天了如果想念是一种植物是像迎春一样开黄色的花还是像柳枝抽嫩绿的芽？如果春风里也有刀子倒春寒是不是那个转身离开的背影？','434-650',1,1707873004,1782398567);
INSERT INTO highlights VALUES('3300056625_9_778-872','3300056625',9,'打桩',unistr('一个民工\u000a站在它的阴影部分\u000a站成一根钉子'),'778-872',5,1719552270,1782480557);
INSERT INTO highlights VALUES('3300056625_8_827-1021','3300056625',8,'打工潮',unistr('在辽阔的大地上\u000a工厂、车间、出租房\u000a以及流水线上\u000a到处都是散落的标点符号\u000a等着被文字重新认领'),'827-1021',5,1719149021,1782480557);
INSERT INTO highlights VALUES('3300056625_5_575-671','3300056625',5,'母亲白了',unistr('一改往常的褐色\u000a白了，像一场大雪\u000a覆盖了原野'),'575-671',5,1719148711,1782480557);
INSERT INTO highlights VALUES('3300056625_3_1785-1821','3300056625',3,'用笔记录生活','三十年前，父亲一把火烧掉了我所有的手稿，那堆火苗却温暖了我此后所有的冬天','1785-1821',5,1719148494,1782480557);
INSERT INTO highlights VALUES('25926815_6_6418-6529','25926815',6,'我的住地；我的生活探索','据说，成汤王的浴盆上刻着如下文字：“苟日新，日日新，又日新。”﻿[12]我懂得个中深意。','6418-6529',NULL,1671595992,1782480565);
INSERT INTO highlights VALUES('25926815_6_4184-4215','25926815',6,'我的住地；我的生活探索','我住在一个小湖边上，离康科德村以南约莫一英里半，地势比它稍高些','4184-4215',NULL,1671595593,1782480565);
INSERT INTO highlights VALUES('25926815_6_3424-3441','25926815',6,'我的住地；我的生活探索','让我回想到前年观光过的一间山上小屋','3424-3441',NULL,1671595483,1782480565);
INSERT INTO highlights VALUES('25926815_6_3535-3663','25926815',6,'我的住地；我的生活探索','晨风永不停歇地吹拂，创世记的诗篇从来没有间断过；惜乎听者寥寥无几。奥林匹斯山﻿[5]到处都有，但能悟出个中奥妙之人却屈指可数。','3535-3663',NULL,1671595342,1782480565);
INSERT INTO highlights VALUES('25926815_6_3164-3216','25926815',6,'我的住地；我的生活探索','我住进树林子的第一天（也就是说，开始日日夜夜地在树林子里过日子），碰巧正是独立日，亦即1845年7月4日','3164-3216',NULL,1671595273,1782480565);
INSERT INTO highlights VALUES('25926815_6_2695-2741','25926815',6,'我的住地；我的生活探索','你们要尽可能长时间地生活得自由自在，无牵无挂。你们把自己捆在农场上，无异于将自己投进大牢里。','2695-2741',NULL,1671595205,1782480565);
INSERT INTO highlights VALUES('25926815_6_1825-1976','25926815',6,'我的住地；我的生活探索','我经常看到一个诗人，欣赏了农场里令人叫绝的风景就离去了，而脾气急躁的农场主还以为他拿走的只是几个野苹果罢了。殊不知诗人已写了诗吟咏他的农场，而农场主多少年来都还蒙在鼓里呢；这么一道令人艳羡的无形栅篱，已经把农场圈了起来，把它的牛奶挤了出来，取其精华——奶油，然后通通拿走，留给农场主的是撇去了奶油的奶水','1825-1976',NULL,1671595028,1782480565);
INSERT INTO highlights VALUES('25926815_6_1662-1767','25926815',6,'我的住地；我的生活探索',unistr('我是眺望全景的皇帝，\u000a我的权利毋庸争议。﻿[2]'),'1662-1767',NULL,1671594953,1782480565);
INSERT INTO highlights VALUES('25926815_6_1055-1085','25926815',6,'我的住地；我的生活探索','因为一个人总有许许多多事情，反正越是放得下来，也就越是富有。','1055-1085',NULL,1671594744,1782480565);
INSERT INTO highlights VALUES('25926815_5_58222-58309','25926815',5,'省俭有方',unistr('你应像枣树一样慷慨大度。\u000a即使你是贫无所有，\u000a也应像柏树一样无拘无束。'),'58222-58309',NULL,1671594354,1782480565);
INSERT INTO highlights VALUES('25926815_5_57668-57717','25926815',5,'省俭有方','先让我们自己简朴和美如同大自然一样，驱散悬在我们额头上的乌云，给我们体内的毛孔注入一丁点儿生命活力','57668-57717',NULL,1671594330,1782480565);
INSERT INTO highlights VALUES('25926815_5_57932-58045','25926815',5,'省俭有方','有人问一位哲学家说： 主造了那么多高大、成荫、有名的树，为什么单把不结果实的柏树称为“自由树”呢？他回答说： 每一种树都有一定的季节，到了那季节，才会茂长，过了那季节，便会凋落。唯有柏树，不为时间所限，四季常青，所以叫做自由。','57932-58045',NULL,1671594311,1782480565);
INSERT INTO highlights VALUES('25926815_5_56610-56673','25926815',5,'省俭有方','我们应该广泛施予人们的是我们的勇气，不是我们的绝望；是我们的健康和安适，不是我们的病恙，而且还要小心莫让疾病通过感染四处蔓延。','56610-56673',NULL,1671594043,1782480565);
INSERT INTO highlights VALUES('25926815_5_56466-56569','25926815',5,'省俭有方','我要的是一个人好比能开花结果，让芳香从他那里向我飘过来，成熟果子就在我们的交往中芳香四溢。想必他的善良不是局部的、短暂的行为，而是持久的、绰绰有余，对他丝毫无损，但也是无意识的行为。这是一种掩盖万恶的善行。','56466-56569',NULL,1671593970,1782480565);
INSERT INTO highlights VALUES('25926815_5_56384-56424','25926815',5,'省俭有方','我器重一个人并不是以他的正直与善行为主要依据，因为两者不外乎是他的枝枝叶叶罢了。','56384-56424',NULL,1671593951,1782480565);
INSERT INTO highlights VALUES('25926815_5_56068-56095','25926815',5,'省俭有方','人类里头善良的大伯大婶们，要比真正的圣灵父母更受尊敬。','56068-56095',NULL,1671593889,1782480565);
INSERT INTO highlights VALUES('25926815_5_55987-56003','25926815',5,'省俭有方','而正是我们的自私才对它估计过高了','55987-56003',NULL,1671593850,1782480565);
INSERT INTO highlights VALUES('25926815_5_55758-55795','25926815',5,'省俭有方','正是假虔诚的蓄奴主拿出奴隶创造的利润的十分之一，给别的奴隶购买星期日的自由','55758-55795',NULL,1671593807,1782480565);
INSERT INTO highlights VALUES('25926815_5_54793-54809','25926815',5,'省俭有方','从广义上说，慈善并不是泛爱同胞。','54793-54809',NULL,1671593580,1782480565);
INSERT INTO highlights VALUES('25926815_5_53549-53641','25926815',5,'省俭有方','不过，我不会阻拦任何一个人去发挥他的天才。这种事我自己是不做的，但是有人全心全意，毕其一生地去做了，我就会对他说，哪怕世人管它叫做坏事，他们很可能会有这样看法，可你们也一定要坚持下去。','53549-53641',NULL,1671593338,1782480565);
INSERT INTO highlights VALUES('25926815_5_53373-53400','25926815',5,'省俭有方','从事慈善事业，如同从事别的事情一样，非得具备天资不可。','53373-53400',NULL,1671593307,1782480565);
INSERT INTO highlights VALUES('25926815_5_52778-52866','25926815',5,'省俭有方','如果说一个人有信心，那他不论到哪儿都会跟同样有信心的人合作；如果说他没有信心，那他会像世界上其他的人一样，继续过自己的日子，不管他跟什么人做伴儿。合作无非就是让我们生活在一起。','52778-52866',NULL,1671468133,1782480565);
INSERT INTO highlights VALUES('25926815_5_52460-52496','25926815',5,'省俭有方','也许我们在预定期间到达不了我们的港口，可是我们断断乎不会偏离正确的航线。','52460-52496',NULL,1671468065,1782480565);
INSERT INTO highlights VALUES('25926815_5_28659-28702','25926815',5,'省俭有方','我们至今还不得不把我们的精神面包削得更薄，甚至削得比我们祖先削过的全麦面包更要薄得多。','28659-28702',NULL,1671273306,1782480565);
INSERT INTO highlights VALUES('25926815_5_26901-26917','25926815',5,'省俭有方','人们已经成为他们的工具的工具了。','26901-26917',NULL,1671273103,1782480565);
INSERT INTO highlights VALUES('25926815_5_26676-26775','25926815',5,'省俭有方','我宁愿坐在一只南瓜上，为我一人所独占，也不乐意跟众人一起挤坐在一个有天鹅绒坐垫的椅子上。我宁愿坐在一辆牛车上走天下，来去自由，也不愿意搭乘什么花里胡哨的观光游览列车飞向天空，一路上呼吸着污浊的空气。','26676-26775',NULL,1671273047,1782480565);
INSERT INTO highlights VALUES('25926815_5_23645-23685','25926815',5,'省俭有方','尽管我们被各种奢侈品所包围，但是如果跟野蛮人的成千种舒适相比，我们都是一贫如洗的','23645-23685',NULL,1671245133,1782480565);
INSERT INTO highlights VALUES('25926815_5_23375-23447','25926815',5,'省俭有方','破产和拒付债务都是一块块跳板，我们的文明有好大一部分从这些跳板上一个劲儿腾跃，又不断在翻跟斗往上蹿，而野蛮人却依然站在饥荒这块没有弹性的木板上。','23375-23447',NULL,1671245053,1782480565);
INSERT INTO highlights VALUES('25926815_5_21946-22005','25926815',5,'省俭有方','文明不会使房价太贵就可以造出质量较好的住房；所谓物价，就是用于交换物品的我称之为生命的量，要么立即支付，要么以后支付。','21946-22005',NULL,1671207772,1782480565);
INSERT INTO highlights VALUES('25926815_5_20685-20738','25926815',5,'省俭有方','为了给一个更大、更豪华的箱子付房租，许多人一直被困扰得快死了，而在这么一个小箱子里头，他们万万不会冻死的。','20685-20738',NULL,1671207553,1782480565);
INSERT INTO highlights VALUES('25926815_5_19830-19962','25926815',5,'省俭有方','从某种程度上说，每个孩子都是在开始重演这个创世纪的历程，喜欢待在户外，哪怕是雨天和冷天。孩子玩造房子，骑木马游戏，都是出于本能罢。有谁会不记得小时候窥探一座叠岩，或者走近一个岩洞时引起的极大兴趣呢？这是一种与生俱有的渴望，我们最原始祖先把它的一部分遗留在我们体内。','19830-19962',NULL,1671159592,1782480565);
INSERT INTO highlights VALUES('25926815_5_18913-18956','25926815',5,'省俭有方','原来他们的主要目的，并不是让人们穿得既好而又体面，而是，毫无疑问，为了公司要多多地赚钱','18913-18956',NULL,1671121383,1782480565);
INSERT INTO highlights VALUES('25926815_5_18376-18447','25926815',5,'省俭有方','反正衣服一离开了特定身份的人，就会显得可怜兮兮，或者稀奇古怪。唯有以严肃的眼光凝视穿衣人的真诚生活，方能抑制住嘲笑并对人们所穿的衣服肃然起敬。','18376-18447',NULL,1671121319,1782480565);
INSERT INTO highlights VALUES('25926815_5_17804-17830','25926815',5,'省俭有方','巴黎的猴王戴上了一顶旅行帽，全美国的猴子便群起仿效。','17804-17830',NULL,1671121120,1782480565);
INSERT INTO highlights VALUES('25926815_5_17214-17258','25926815',5,'省俭有方','有一个人穷虽穷，但一穿上用自己的辛苦钱置备的行头，难道说还会没有聪明人去向他表示敬意吗？','17214-17258',NULL,1671121042,1782480565);
INSERT INTO highlights VALUES('25926815_5_16483-16519','25926815',5,'省俭有方','人之所求，不是做事情时要穿什么，而是要做什么，或者换句话说，要成为什么。','16483-16519',NULL,1671120888,1782480565);
INSERT INTO highlights VALUES('25926815_5_15988-16011','25926815',5,'省俭有方','反正一个女人的衣服，少说也是一辈子都做不完的。','15988-16011',NULL,1671120720,1782480565);
INSERT INTO highlights VALUES('25926815_5_15909-15939','25926815',5,'省俭有方','不过，那些如此这般尊敬的人，尽管人数极多，但都是不信上帝的人','15909-15939',NULL,1671120703,1782480565);
INSERT INTO highlights VALUES('25926815_5_15372-15403','25926815',5,'省俭有方','因为他考虑的，不是真正令人可敬的东西，而是受到人们尊敬的东西。','15372-15403',NULL,1671120615,1782480565);
INSERT INTO highlights VALUES('25926815_5_13061-13102','25926815',5,'省俭有方','我琢磨的，不是如何让人感到值得来买篮子，我琢磨的是如何避免篮子编好后非得卖掉不可。','13061-13102',NULL,1671115698,1782480565);
INSERT INTO highlights VALUES('25926815_5_12132-12171','25926815',5,'省俭有方','我煞费苦心地写作，换来的只是痛苦。不过，就这件事来说，痛苦乃是它自身的回报罢。','12132-12171',NULL,1671115555,1782480565);
INSERT INTO highlights VALUES('25926815_5_11613-11666','25926815',5,'省俭有方','说真的，太阳冉冉升起，我可从来没有具体地出过力，但是切莫怀疑，只要赶在日出之时到达现场，其意义就非同小可。','11613-11666',NULL,1671115409,1782480565);
INSERT INTO highlights VALUES('25926815_5_9856-9949','25926815',5,'省俭有方','大学问家和大思想家的成功，不是帝王式的，也不是壮汉式的，通常都是侍臣式的成功。他们一味随流徇俗，应对生活变化，他们的所作所为，实际上跟父辈们如出一辙，压根儿成不了什么顶天立地的人类始祖。','9856-9949',NULL,1671112479,1782480565);
INSERT INTO highlights VALUES('25926815_5_9528-9584','25926815',5,'省俭有方','古代哲学家，不论在中国、印度、波斯还是希腊，都是同一种类型的人，从外表看，他们比谁都穷，从内心看，他们却比谁都富','9528-9584',NULL,1671112428,1782480565);
INSERT INTO highlights VALUES('25926815_5_7971-8044','25926815',5,'省俭有方','人的生活必需品可以极其精确地分为几大类： 食物、住所、衣服和燃料；因为只有获得以上这些东西，我们方才可以自由地考虑真正的人生问题，并有望取得成功。','7971-8044',NULL,1671112127,1782480565);
INSERT INTO highlights VALUES('25926815_5_7249-7310','25926815',5,'省俭有方','但既然从一个中心可以画出好多好多半径来，生活方式一样也有好多好多。一切变革都是奇迹，值得思考；而奇迹是分分秒秒都在发生的。','7249-7310',NULL,1671111997,1782480565);
INSERT INTO highlights VALUES('25926815_5_6793-6842','25926815',5,'省俭有方','凡是我的邻居说是好的，大部分在我心目中却认为是坏的，如果说我有什么要反思，也许恰恰是我的正派作风。','6793-6842',NULL,1671097265,1782480565);
INSERT INTO highlights VALUES('25926815_5_6348-6395','25926815',5,'省俭有方','，人的各种能量从来还没有被估量过；我们也不应该根据任何先例来判断人的能量，尝试过的事委实太少了','6348-6395',NULL,1671091736,1782480565);
INSERT INTO highlights VALUES('25926815_5_5818-5890','25926815',5,'省俭有方','有些东西在某些人的圈子里，那些最无助、病得最重的人，确实是生命的必需品，但换了一个圈子，却仅仅成了奢侈品，要是再换一个圈子，则完全成了未知之物。','5818-5890',NULL,1671091698,1782480565);
INSERT INTO highlights VALUES('25926815_5_5249-5290','25926815',5,'省俭有方','老人说你不能做的事，你不妨试一试，却发现你是能做的。老人有老办法，新人有新招数。古','5249-5290',NULL,1671091561,1782480565);
INSERT INTO highlights VALUES('25926815_5_5133-5185','25926815',5,'省俭有方','捐弃我们的偏见，从来不算为时太晚。任何一种思考方式或者行为方式，不管它有多么古老，如无确证都是不可信的。','5133-5185',NULL,1671091534,1782480565);
