INSERT INTO highlights VALUES('25926815_5_3646-3714','25926815',5,'省俭有方','我们天性中最优秀的品质，好似水果外皮的粉霜，只有精心加以呵护才保得住。可是，我们不管对待自己也好，还是对待别人也好，都缺失如此温情柔意。','3646-3714',NULL,1671091260,1782480565);
