INSERT INTO highlights VALUES('25926815_4_6335-6375','25926815',4,'《瓦尔登湖》： 人与自然和美共存的赞歌','爱默生偏重于哲理的思辨，而梭罗则力求将自己相信的哲理付诸实践，就是说要身体力行。','6335-6375',NULL,1671090596,1782480565);
INSERT INTO highlights VALUES('25926815_4_6176-6224','25926815',4,'《瓦尔登湖》： 人与自然和美共存的赞歌','超验主义思想的基本出发点，就是反对权威，崇尚直觉；其核心是主张人能超越感觉和理性而直接认识真理。','6176-6224',NULL,1671090330,1782480565);
INSERT INTO highlights VALUES('25926815_4_6147-6175','25926815',4,'《瓦尔登湖》： 人与自然和美共存的赞歌','爱默生的《论自然》等著述中的超验主义思想却给他较深的影响','6147-6175',NULL,1671090302,1782480565);
INSERT INTO highlights VALUES('25926815_4_4864-4910','25926815',4,'《瓦尔登湖》： 人与自然和美共存的赞歌','但是，弦外之音，反过来说，政府要是逼迫人民去做违背自己意愿的事，人民就应该拥有消极抵抗的权利','4864-4910',NULL,1671090130,1782480565);
INSERT INTO highlights VALUES('25926815_4_4481-4525','25926815',4,'《瓦尔登湖》： 人与自然和美共存的赞歌','我无意写一首闷闷不乐的颂歌，可我要像破晓晨鸡在栖木上引吭啼唱，只要能唤醒我的左邻右舍就好','4481-4525',NULL,1671090035,1782480565);
