INSERT INTO highlights VALUES('25926815_4_1830-1866','25926815',4,'《瓦尔登湖》： 人与自然和美共存的赞歌','此书一开头，作者就声明是为了“乡友们细致入微地探听我的生活方式”而写的。','1830-1866',NULL,1671089540,1782480565);
INSERT INTO highlights VALUES('25926815_5_21270-21389','25926815',5,'省俭有方','虽然空中的鸟儿有窝﻿[38]，狐狸有洞，野蛮人有棚屋，然而，在现代文明社会里，居有其所的家庭却不到一半。','21270-21389',NULL,1653627305,1782480565);
INSERT INTO highlights VALUES('25926815_5_13302-13395','25926815',5,'省俭有方','我到瓦尔登湖去的目的，不是因为那儿生活费用便宜或者昂贵，而是去经营一些私人业务，在那儿麻烦可以减到最少；要不然，由于缺乏业务常识，又没有做生意的才干而一事无成，难免做出惨不忍睹的傻事来。','13302-13395',NULL,1653580632,1782480565);
INSERT INTO highlights VALUES('25926815_5_9641-9827','25926815',5,'省俭有方','一个人唯有站在我们称之为甘于清贫的有利地位上，方能成为人类生活的公正、睿智的观察家。不论在农业、商业、文学或艺术中，奢侈生活结出的果实也都是奢侈。时下哲学教授比比皆是，但哲学家却一个也没有。然而，教授是令人艳羡的，因为教授的生活曾经令人艳羡。做一个哲学家，不仅要有奥博的思想，乃至于建立一个学派，而且还要热爱智慧，按照智慧的要求，过一种简朴、独立、豁达大度与富有信心的生活','9641-9827',NULL,1653580180,1782480565);
INSERT INTO highlights VALUES('25926815_5_9299-9435','25926815',5,'省俭有方','奢侈的富人不只是得到令人舒适的暖和，而是热得太过反常；正如我前文所说的，他们肉体是在烘烤来着，不消说，是很切合时尚的方式﻿[19]在烘烤。','9299-9435',NULL,1653580112,1782480565);
INSERT INTO highlights VALUES('25926815_5_8810-8835','25926815',5,'省俭有方','就人体来说，最大的必需品就是保暖，保持生命的热量。','8810-8835',NULL,1653580046,1782480565);
INSERT INTO highlights VALUES('3300007102_83_1434-1493','3300007102',83,'为什么胃癌到晚期才有感觉？','胃癌的演变过程一般是这样的：慢性非萎缩性胃炎（慢性浅表性胃炎）→慢性萎缩性胃炎/肠上皮化生→不典型增生/原位癌→胃癌。','1434-1493',NULL,1654529493,1782480567);
INSERT INTO highlights VALUES('3300007102_83_2031-2094','3300007102',83,'为什么胃癌到晚期才有感觉？','第一，并不是所有慢性萎缩性胃炎都会癌变，癌变的概率较小。第二，慢性萎缩性胃炎变成胃癌的速度比较快，5年之内就有发生癌变的可能。','2031-2094',NULL,1654529442,1782480567);
INSERT INTO highlights VALUES('3300007102_83_867-938','3300007102',83,'为什么胃癌到晚期才有感觉？','在患有急性胃炎的时候，千万不要胡乱吃止痛药，因为布洛芬、芬必得、阿司匹林等止痛药会损害胃黏膜，有可能加重胃炎或者胃溃疡的症状，甚至造成胃穿孔。','867-938',NULL,1654529337,1782480567);
INSERT INTO highlights VALUES('3300007102_79_961-1169','3300007102',79,'得癌症后，有人活了1年，有人却活了30年','目前国际上通用的病理分期系统为TNM分期系统，做完手术之后，病理科医生会出具病理报告，病理报告上面详细记录了肿瘤的分期情况。T代表肿瘤的大小或浸润的深度，可以分为T1、T2、T3、T4，N代表有没有淋巴结转移，淋巴结转移的数目和部位，M代表有没有远处器官的转移，转移的部位和数目，将这三个因素综合起来就能得到一个TNM分期，由此可以把肿瘤分为一期、二期、三期、四期，一期和二期属于肿瘤早期，三期和四期属于肿瘤中晚期。','961-1169',NULL,1654442782,1782480567);
INSERT INTO highlights VALUES('3300007102_78_940-999','3300007102',78,'癌症已经有淋巴结转移，还有必要做手术吗？','癌细胞可以通过至少四种途径转移，分别是淋巴结转移、血行转移、种植播散和直接侵犯，其中，淋巴结转移是癌症转移的常见方式。','940-999',NULL,1654442624,1782480567);
INSERT INTO highlights VALUES('3300007102_72_1395-1534','3300007102',72,'便血时，如何判断是得了痔疮还是直肠癌？','痔疮则以保守治疗为主，没有症状的痔疮不需要治疗；有症状的痔疮以保守治疗为主，例如多吃蔬菜水果，多喝水，保持规律的排便习惯，防止便秘。另外，还可选择坐浴，局部使用栓剂或外用药物等。只有保守治疗效果欠佳，出现内痔脱出无法还纳，血栓性外痔，以及痔疮大出血等严重的情况时才需要手术治疗。','1395-1534',NULL,1654440007,1782480567);
INSERT INTO highlights VALUES('3300007102_72_588-679','3300007102',72,'便血时，如何判断是得了痔疮还是直肠癌？','痔疮本身是一种良性病，是直肠肛门周围的静脉曲张，形成扩张迂曲的静脉团，一般来说不会恶变。如果发生在直肠内，那就是内痔；如果发生在直肠外，那就是外痔；如果内痔和外痔都有，那就是混合痔。','588-679',NULL,1654439922,1782480567);
INSERT INTO highlights VALUES('3300007102_69_560-572','3300007102',69,'手术之后，医生怎么天天关心我有没有放屁？','在医学上，放屁叫作排气。','560-572',NULL,1654410349,1782480567);
INSERT INTO highlights VALUES('3300007102_68_1108-1187','3300007102',68,'手术切口那么大，为什么不会大出血？','做局部麻醉手术的时候，需要在切口周围注射麻药，医生可能会在麻药中加入肾上腺素，这样可以收缩血管，也可以减缓麻药的吸收，增加麻药的作用时间，同时也可以减少出血。','1108-1187',NULL,1654410297,1782480567);
INSERT INTO highlights VALUES('3300007102_65_1267-1320','3300007102',65,'结节、息肉、囊肿、增生，哪种是癌症的先兆？','囊肿是良性的，囊肿中其实是液体，其外表有一个完整的包膜，常见的囊肿有肝囊肿、肾囊肿、乳腺囊肿、甲状腺囊肿。','1267-1320',NULL,1654409514,1782480567);
INSERT INTO highlights VALUES('3300007102_65_1176-1201','3300007102',65,'结节、息肉、囊肿、增生，哪种是癌症的先兆？','如果发现了胃息肉、肠息肉，应该尽早切掉，防止其恶变','1176-1201',NULL,1654409065,1782480567);
INSERT INTO highlights VALUES('3300007102_65_1036-1054','3300007102',65,'结节、息肉、囊肿、增生，哪种是癌症的先兆？','息肉指的是人体组织表面长出的赘生物，','1036-1054',NULL,1654409049,1782480567);
INSERT INTO highlights VALUES('3300007102_65_773-802','3300007102',65,'结节、息肉、囊肿、增生，哪种是癌症的先兆？','恶性结节的表现为质地坚硬，活动度差，边界不清，不伴有触痛。','773-802',NULL,1654408991,1782480567);
INSERT INTO highlights VALUES('3300007102_65_631-654','3300007102',65,'结节、息肉、囊肿、增生，哪种是癌症的先兆？','结节是新生肿物的统称，结节包括良性的和恶性的。','631-654',NULL,1654408967,1782480567);
INSERT INTO highlights VALUES('3300007102_62_2245-2277','3300007102',62,'如何看懂肝功能化验单？','体内的胆红素升高，会导致我们身体皮肤和黏膜黄染，我们称之为黄疸。','2245-2277',NULL,1654408576,1782480567);
INSERT INTO highlights VALUES('3300007102_62_1384-1409','3300007102',62,'如何看懂肝功能化验单？','白蛋白与球蛋白的比例（A/G）就会下降，甚至倒置。','1384-1409',NULL,1654408425,1782480567);
INSERT INTO highlights VALUES('3300007102_61_595-701','3300007102',61,'身体出现“红痣”是肝病的标志吗？','原来他们所说的“红痣”叫作樱桃状血管瘤，是局部血管增生引起的，并不是肝病的标志。樱桃状血管瘤是最常见的血管瘤，发病与年龄有关系，随着年龄的增长，血管瘤的数目开始增多，因此也被称为老年性血管瘤，民间俗称为“红痣”。','595-701',NULL,1654407221,1782480567);
INSERT INTO highlights VALUES('3300007102_60_1632-1741','3300007102',60,'提高免疫力才是抗癌之根本','目前比较成熟的免疫治疗主要有两种，分别是PD-1抑制剂疗法和CAR-T疗法。这两种方法都是通过重建机体对癌细胞的免疫力，利用免疫细胞来杀死癌细胞的，在对抗恶性黑色素瘤、白血病、淋巴瘤、肝癌、肺癌等过程中取得了巨大的成果','1632-1741',NULL,1654403761,1782480567);
INSERT INTO highlights VALUES('3300007102_60_1377-1381','3300007102',60,'提高免疫力才是抗癌之根本','扶正固本','1377-1381',NULL,1654403733,1782480567);
INSERT INTO highlights VALUES('3300007102_60_657-787','3300007102',60,'提高免疫力才是抗癌之根本','健康的生活方式包括健康的饮食与合理的作息。在饮食方面，不抽烟，不喝酒，不吃油炸食品，少吃腌制、加工肉类，少吃隔夜菜，坚决不吃霉变的食物。多吃新鲜的蔬菜和水果，高蛋白质低脂清淡饮食，多吃优质蛋白，如鸡蛋、鱼肉、鸡肉等。少食多餐，不暴饮暴食，饮食规律，按时吃三餐。','657-787',NULL,1654403443,1782480567);
INSERT INTO highlights VALUES('3300007102_59_1760-1811','3300007102',59,'运动会让癌细胞扩散得更快吗？','每周进行150分钟的中度有氧运动，例如快走、骑自行车、游泳。每周额外进行2～3次的力量训练，例如举重。','1760-1811',NULL,1654403399,1782480567);
INSERT INTO highlights VALUES('3300007102_59_500-553','3300007102',59,'运动会让癌细胞扩散得更快吗？','运动不会让癌细胞扩散得更快，而且运动可以降低疲劳感，提高身体素质，降低癌症的复发率，延长癌症患者的生存期。','500-553',NULL,1654403297,1782480567);
INSERT INTO highlights VALUES('3300007102_57_810-897','3300007102',57,'癌症术后30年复发，癌症还能治愈吗？','有些癌细胞会潜伏在身体的内部，例如骨髓、淋巴结等部位。这些癌细胞暂时不活动，处于静止状态，就像动物冬眠一样一直隐藏在身体里，但它们就像定时炸弹一样，随时都有复发、转移的风险。','810-897',NULL,1654403225,1782480567);
INSERT INTO highlights VALUES('3300007102_54_1783-1846','3300007102',54,'乳房疼痛是乳腺癌吗？其实不疼更可怕','总之，乳腺疼痛并不可怕，如果突然有一天，你发现自己乳房有一个硬硬的肿块，既不痛也不痒，这时候就要注意了，请立即去医院进行检查。','1783-1846',NULL,1654365569,1782480567);
INSERT INTO highlights VALUES('3300007102_54_961-1071','3300007102',54,'乳房疼痛是乳腺癌吗？其实不疼更可怕','乳房疼痛最常见的原因是乳腺增生。乳腺增生是一种良性病，很多女性都有乳腺增生，它与激素分泌紊乱、不良的生活习惯、辛辣刺激性饮食、工作压力大、心情不好都有关系。因为乳腺增生与雌激素有关，所以多见于年轻女性，而且与月经有关系。','961-1071',NULL,1654365509,1782480567);
INSERT INTO highlights VALUES('3300007102_53_4082-4144','3300007102',53,'胸大的人更容易得乳腺癌吗？','地中海饮食可降低乳腺癌发病率，地中海饮食的特点为高膳食纤维，多吃新鲜蔬菜水果，多吃鱼和海鲜，做菜时使用植物油，特别是橄榄油。','4082-4144',NULL,1654365411,1782480567);
INSERT INTO highlights VALUES('3300007102_52_2220-2237','3300007102',52,'不抽烟不喝酒，为什么会得胃癌？','不规律的饮食习惯会导致胃酸分泌紊乱','2220-2237',NULL,1654057668,1782480567);
INSERT INTO highlights VALUES('3300007102_51_832-851','3300007102',51,'突然戒烟，更容易得肺癌？','会让男性出现勃起功能障碍、性功能障碍，','832-851',NULL,1654057246,1782480567);
INSERT INTO highlights VALUES('3300007102_50_2036-2083','3300007102',50,'为什么胰腺癌被称为“癌中之王”？','总之，目前，胰腺癌还缺乏有效的治疗方法，需要早发现，早治疗，这样才有可能取得比较好的治疗效果。','2036-2083',NULL,1654057170,1782480567);
INSERT INTO highlights VALUES('3300007102_50_1349-1377','3300007102',50,'为什么胰腺癌被称为“癌中之王”？','肿瘤的治疗手段包括手术、放化疗、免疫治疗、生物靶向治疗等','1349-1377',NULL,1654057084,1782480567);
INSERT INTO highlights VALUES('3300007102_42_1388-1421','3300007102',42,'放屁多是大肠癌的信号吗？','引起肠梗阻的原因有很多，例如肿瘤、肠粘连、肠道血运障碍、肠麻痹等。','1388-1421',NULL,1654055660,1782480567);
INSERT INTO highlights VALUES('3300007102_42_1233-1277','3300007102',42,'放屁多是大肠癌的信号吗？','如果平时放屁比较多，突然连续几天不放屁了，肚子胀起来了，那就要非常小心，有可能是肠梗阻。','1233-1277',NULL,1654055634,1782480567);
INSERT INTO highlights VALUES('3300007102_42_931-963','3300007102',42,'放屁多是大肠癌的信号吗？','一个正常的成年人，每天放屁5～10次，总体积可以达到500毫升。','931-963',NULL,1654055609,1782480567);
INSERT INTO highlights VALUES('3300007102_41_1728-1812','3300007102',41,'大肠癌是最“笨”的癌症','红肉指的是未加工之前呈红色的哺乳动物的肉，例如猪肉、牛肉、羊肉等。红肉是二类致癌物，长期大量摄入会增加大肠癌发病率。每日摄入100克的红肉，大肠癌发病风险会增加17%。','1728-1812',NULL,1654046519,1782480567);
INSERT INTO highlights VALUES('3300007102_41_856-930','3300007102',41,'大肠癌是最“笨”的癌症','在40岁左右时做一次肠镜检查。如果没有发现肠息肉，那么至少5年内就可以不用再做肠镜了；如果发现了肠息肉，做一个肠镜下息肉切除手术，就可以其防止癌变。','856-930',NULL,1653974092,1782480567);
INSERT INTO highlights VALUES('3300007102_39_1352-1387','3300007102',39,'癌症都是静悄悄的，警惕这四个标志','炎症引起的淋巴结肿大会伴有热痛，而癌症引起的淋巴结肿大常常为无痛性的。','1352-1387',NULL,1653973981,1782480567);
INSERT INTO highlights VALUES('3300007102_37_1778-1864','3300007102',37,'好几天没有排便，大便去哪里了？','产生便意的时候，一定要尽早去大便。如果把大便憋住，大便就变得更加干燥，水分太少，不够润滑，可能会导致排便困难。长此以往，就会形成恶性循环，导致排便越来越困难，最后患上便秘。','1778-1864',NULL,1653973832,1782480567);
INSERT INTO highlights VALUES('3300007102_34_1381-1469','3300007102',34,'震惊！不吃早餐等于吃大便？','那么人饥饿时，从哪里获得能量呢？首先肝脏里的肝糖原会分解代谢，变成葡萄糖，给身体供应能量。如果肝糖原被消耗完了，非糖类的脂肪酸和氨基酸就会通过糖异生反应，变成葡萄糖，提供能量。','1381-1469',NULL,1653973550,1782480567);
INSERT INTO highlights VALUES('3300007102_31_1336-1426','3300007102',31,'牙结石为什么那么臭？','现在最常被推荐的刷牙方法是巴氏刷牙法','1336-1426',NULL,1653669744,1782480567);
INSERT INTO highlights VALUES('3300007102_30_1388-1424','3300007102',30,'内裤和袜子能一起洗吗？','建议大家天天洗内裤，不要几天才换一次内裤，否则内裤上可能会沾上很多粪便。','1388-1424',NULL,1653669678,1782480567);
INSERT INTO highlights VALUES('3300007102_30_520-568','3300007102',30,'内裤和袜子能一起洗吗？','但其实，在大部分情况下，内裤比袜子脏。人在擦屁股时可能擦得不那么干净，内裤上多少会沾有一点粪便。','520-568',NULL,1653669600,1782480567);
INSERT INTO highlights VALUES('3300007102_26_573-599','3300007102',26,'这样午睡，越睡越困','如果午睡的时间太长的话，会增加心脑血管疾病发病的风险','573-599',NULL,1653669391,1782480567);
INSERT INTO highlights VALUES('3300007102_24_1319-1373','3300007102',24,'失温时应该如何自救？','酒的热量并不高，而且喝酒之后，全身的外周血管会扩张，反而会把热量带走。通过喝酒的方式来暖身子，这是不科学的。','1319-1373',NULL,1653669198,1782480567);
INSERT INTO highlights VALUES('3300007102_24_1087-1096','3300007102',24,'失温时应该如何自救？','立即给核心区域复温','1087-1096',NULL,1653669124,1782480567);
INSERT INTO highlights VALUES('3300007102_24_1007-1029','3300007102',24,'失温时应该如何自救？','把身上潮湿的衣服脱下来，换上干净、保暖的衣服','1007-1029',NULL,1653669119,1782480567);
INSERT INTO highlights VALUES('3300007102_20_501-536','3300007102',20,'冬虫夏草不是保健品，长期服用可能中毒','冬虫夏草中砷含量超标，是正常限值的4倍以上，人长期摄入，会导致砷中毒。','501-536',NULL,1652761840,1782480567);
INSERT INTO highlights VALUES('3300007102_16_1857-1927','3300007102',16,'人每天都要补充益生菌吗？','喝酸奶补充益生菌只是一个美好愿望，想要补充益生菌还是建议购买专门的益生菌制剂，选择菌株可靠、活菌数量足、有专门抵抗胃液消化处理的益生菌产品。','1857-1927',NULL,1652761362,1782480567);
INSERT INTO highlights VALUES('3300007102_15_2656-2778','3300007102',15,'爱吃糖容易得糖尿病吗？',unistr('升糖指数高的食物有馒头、粥、白米饭、爆米花、西瓜、汽水、可乐、蜂蜜、白糖、橙汁等。\u000a升糖指数低的食物有燕麦、全麦面包、荞麦面、藜麦、茄子、苦瓜、黄瓜、豆类、牛奶、鸡蛋、菠菜、生菜、芹菜等。'),'2656-2778',NULL,1652761197,1782480567);
INSERT INTO highlights VALUES('3300007102_14_1364-1408','3300007102',14,'晚餐后吃水果会诱发酒精肝？','酒精肝是长期大量饮酒导致的肝脏损害的结果，与吃水果没有任何关系，大家不要相信这样的谣言。','1364-1408',NULL,1652723701,1782480567);
INSERT INTO highlights VALUES('3300007102_13_973-1025','3300007102',13,'不吃早餐容易得胆囊结石？','所以，如果长期不规律饮食，不管是不吃三餐中的哪一餐都有可能诱发胆结石。为了预防胆囊结石，要规律地吃三餐。','973-1025',NULL,1652722011,1782480567);
INSERT INTO highlights VALUES('3300007102_12_1803-1834','3300007102',12,'到底吃什么才能补肾？','富含精氨酸的食物有鳝鱼、泥鳅、海参、墨鱼、章鱼、蚕蛹、鸡肉等。','1803-1834',NULL,1652619817,1782480567);
INSERT INTO highlights VALUES('3300007102_12_1378-1451','3300007102',12,'到底吃什么才能补肾？','谷类、南瓜、绿叶蔬菜、蛋黄、坚果类食物、肉及乳制品中的维生素E含量较为丰富，可以多吃，另外还可以适量使用维生素E制品，不过一定要在医生指导下使用。','1378-1451',NULL,1652619794,1782480567);
