INSERT INTO highlights VALUES('3300007102_5_1497-1575','3300007102',5,'“酸奶”既没营养还容易让人长胖？','酸奶与牛奶相比，谁的营养价值更高呢？答案是酸奶。因为酸奶在发酵的过程中还会产生一些维生素，而牛奶含有的营养成分在酸奶中基本都有，两者的营养价值差别不会很大。','1497-1575',NULL,1652586833,1782480567);
INSERT INTO highlights VALUES('3300007102_5_1426-1468','3300007102',5,'“酸奶”既没营养还容易让人长胖？','所以如果想吃最健康的酸奶，还是应该选择原味发酵乳，但不可否认，原味发酵乳的口感较差。','1426-1468',NULL,1652586805,1782480567);
