INSERT INTO highlights VALUES('25615385_68_1623-1675','25615385',176,'过多的自我意识，反而会束缚自己','没有目标也无妨。认真过好“此时此刻”，这本身就是跳舞。不要把人生弄得太深刻。请不要把认真和深刻混为一谈。','37325-37403',NULL,1595489067,1782480568);
INSERT INTO highlights VALUES('25615385_26_1408-1451','25615385',170,'为什么讨厌自己？','哲人：健全的自卑感不是来自与别人的比较，而是来自与“理想的自己”的比较。','22092-22135',NULL,1595488721,1782480568);
INSERT INTO highlights VALUES('25615385_70_3184-3256','25615385',177,'后记','如果不懂得如何构筑良好的人际关系，有时候就会因为想要满足他人期待或者不想伤害他人而导致虽有自己主张但无法传达，最终不得不放弃自己真正想做的事情。','3222-3294',NULL,1595425450,1782480568);
INSERT INTO highlights VALUES('25615385_69_4804-4868','25615385',176,'过多的自我意识，反而会束缚自己','再送给你一句阿德勒的话：“必须有人开始。即使别人不合作，那也与你无关。我的意见就是这样。应该由你开始，不用去考虑别人是否合作。”','43170-43234',NULL,1595425164,1782480568);
INSERT INTO highlights VALUES('25615385_69_2858-2929','25615385',176,'过多的自我意识，反而会束缚自己','那颗星是什么呢？哲人：他者贡献。','41146-41217',NULL,1595425059,1782480568);
INSERT INTO highlights VALUES('25615385_69_2589-2593','25615385',176,'过多的自我意识，反而会束缚自己','引导之星','40870-40874',NULL,1595425033,1782480568);
INSERT INTO highlights VALUES('25615385_68_2401-2510','25615385',176,'过多的自我意识，反而会束缚自己','人生中最大的谎言就是不活在“此时此刻”。纠结过去、关注未来，把微弱而模糊的光打向人生整体，自认为看到了些什么。你之前就一直忽略“此时此刻”，只关注根本不存在的过去和未来。对自己的人生和无可替代的刹那撒了一个大大的谎言。','38148-38264',NULL,1595424840,1782480568);
INSERT INTO highlights VALUES('25615385_68_1874-1905','25615385',176,'过多的自我意识，反而会束缚自己','并且还要记住一点。站在现实性角度的时候，人生总是处于完结状态。','37602-37659',NULL,1595424800,1782480568);
INSERT INTO highlights VALUES('25615385_68_1272-1295','25615385',176,'过多的自我意识，反而会束缚自己','等时机到了就去做”，是一种拖延人生的生活方式。','36974-36997',NULL,1595424752,1782480568);
INSERT INTO highlights VALUES('25615385_68_800-826','25615385',176,'过多的自我意识，反而会束缚自己','今天这一天就为此存在，而不是为遥远的将来的考试而存在','36450-36476',NULL,1595424712,1782480568);
INSERT INTO highlights VALUES('25615385_67_1550-1663','25615385',176,'过多的自我意识，反而会束缚自己','人生是连续的刹那，根本不存在过去和未来。你是想要通过关注过去或未来为自己寻找免罪符。过去发生了什么与你的“此时此刻”没有任何关系，未来会如何也不是“此时此刻”要考虑的问题。假如认真地活在“此时此刻”，那就根本不会说出那样的话。','35104-35243',NULL,1595424479,1782480568);
INSERT INTO highlights VALUES('25615385_66_2548-2579','25615385',176,'过多的自我意识，反而会束缚自己','把过程本身也看作结果的运动”，跳舞是如此，旅行等本身也是如此。','33125-33156',NULL,1595424142,1782480568);
INSERT INTO highlights VALUES('25615385_66_1234-1283','25615385',176,'过多的自我意识，反而会束缚自己','人生就像是在每一个瞬间不停旋转起舞的连续的刹那。并且，暮然四顾时常常会惊觉：“已经来到这里了吗？”','31726-31782',NULL,1595424060,1782480568);
INSERT INTO highlights VALUES('25615385_65_1517-1550','25615385',176,'过多的自我意识，反而会束缚自己','哲人：请不要把人生理解为一条线，而要理解成点的连续。','30193-30226',NULL,1595423733,1782480568);
INSERT INTO highlights VALUES('25615385_63_2042-2104','25615385',176,'过多的自我意识，反而会束缚自己','无论是希望特别优秀还是希望特别差劲，其目的都一样——引起他人的关注、脱离“普通”状态、成为“特别的存在”。这就是他们的目的。','25973-26061',NULL,1595423453,1782480568);
INSERT INTO highlights VALUES('25615385_62_4531-4634','25615385',176,'过多的自我意识，反而会束缚自己','人只有在能够感觉到“我对别人有用”的时候才能体会到自己的价值。但是，这种贡献也可以通过看不见的形式实现。只要有“对别人有用”的主观感觉，即“贡献感”就可以。并且，哲人还得出了这样的结论：幸福就是“贡献感”。','24258-24361',NULL,1595423097,1782480568);
INSERT INTO highlights VALUES('25615385_62_3891-3907','25615385',176,'过多的自我意识，反而会束缚自己','通过认可欲求获得的贡献感没有自由','23590-23606',NULL,1595423008,1782480568);
INSERT INTO highlights VALUES('25615385_62_3457-3476','25615385',176,'过多的自我意识，反而会束缚自己','而获得贡献感的常见手段就是寻求他人认可','23156-23175',NULL,1595422962,1782480568);
INSERT INTO highlights VALUES('25615385_62_2486-2492','25615385',176,'过多的自我意识，反而会束缚自己','幸福即贡献感','22178-22184',NULL,1595422870,1782480568);
INSERT INTO highlights VALUES('25615385_61_2284-2381','25615385',176,'过多的自我意识，反而会束缚自己','人际关系不顺利既不是因为口吃也不是因为脸红恐惧症，真正的问题在于无法做到自我接纳、他者信赖和他者贡献，却将焦点聚集到微不足道的一个方面并企图以此来评价整个世界。这就是缺乏人生和谐的错误生活方式。','18135-18258',NULL,1595422527,1782480568);
INSERT INTO highlights VALUES('25615385_61_1234-1322','25615385',176,'过多的自我意识，反而会束缚自己','“假如有10个人，其中势必会有1个人无论遇到什么事都会批判你。他讨厌你，你也不喜欢他。而且，10个人中也会有2个人能够成为与你互相接纳一切的好朋友。剩下的7个人则两者都不是。”','17085-17173',NULL,1595422431,1782480568);
INSERT INTO highlights VALUES('25615385_60_1631-1761','25615385',176,'过多的自我意识，反而会束缚自己','正因为接受了真实的自我——也就是“自我接纳”——才能够不惧背叛地做到“他者信赖”；而且，正因为对他人给予无条件的信赖并能够视他人为自己的伙伴，才能够做到“他者贡献”；同时，正因为对他人有所贡献，才能够体会到“我对他人有用”进而接受真实的自己，做到“自我接纳”。','14521-14651',NULL,1595421405,1782480568);
INSERT INTO highlights VALUES('25615385_59_2598-2612','25615385',176,'过多的自我意识，反而会束缚自己','最容易理解的他者贡献就是工作','12594-12608',NULL,1595410047,1782480568);
INSERT INTO highlights VALUES('25615385_59_1124-1180','25615385',176,'过多的自我意识，反而会束缚自己','青年：也就是说，要想获得归属感就必须把他人看作伙伴，而要做到视他人为伙伴就需要自我接纳和他者信赖。','11094-11150',NULL,1595409655,1782480568);
INSERT INTO highlights VALUES('25615385_57_3211-3268','25615385',176,'过多的自我意识，反而会束缚自己','上帝，请赐予我平静，去接受我无法改变的；给予我勇气，去改变我能改变的；赐我智慧，分辨这两者的区别。”来自一部小说。','5433-5497',NULL,1595408940,1782480568);
INSERT INTO highlights VALUES('25615385_57_2691-2697','25615385',176,'过多的自我意识，反而会束缚自己','肯定性的达观','4861-4867',NULL,1595408884,1782480568);
INSERT INTO highlights VALUES('25615385_56_2138-2182','25615385',176,'过多的自我意识，反而会束缚自己','自我意识总是牵绊着自己、严重束缚着自己的言行。我的自我意识根本不允许自己无拘无束地行动。','2008-2052',NULL,1595408719,1782480568);
INSERT INTO highlights VALUES('25615385_54_2730-2788','25615385',174,'个体心理学和整体论','并不是说将任何人都变成朋友或者像对待朋友一样去对待每一个人，不是这样的，重要的是意识上的平等以及坚持自己应有的主张。','30310-30394',NULL,1595408394,1782480568);
INSERT INTO highlights VALUES('25615385_53_3589-3643','25615385',174,'个体心理学和整体论','必须得有人开始。即使其他人不合作，那也跟你没关系。我的意见就是这样：应该由你来开始。不必去考虑他人是否合作。','27898-27952',NULL,1595408249,1782480568);
INSERT INTO highlights VALUES('25615385_52_1760-1805','25615385',174,'个体心理学和整体论','人怎样才能够获得“勇气”？阿德勒的见解是：人只有在能够感觉自己有价值的时候才可以获得勇气。','23342-23413',NULL,1595407938,1782480568);
INSERT INTO highlights VALUES('25615385_51_2814-2878','25615385',174,'个体心理学和整体论','假如你会因为得到表扬而感到喜悦，那就等于是从属于纵向关系和承认“自己没能力”。因为表扬是“有能力的人对没能力的人所作出的评价”。','21570-21634',NULL,1595407828,1782480568);
INSERT INTO highlights VALUES('25615385_51_2462-2484','25615385',174,'个体心理学和整体论','因为人会因为被表扬而形成“自己没能力”的信念','21211-21233',NULL,1595404910,1782480568);
INSERT INTO highlights VALUES('25615385_51_1912-1928','25615385',174,'个体心理学和整体论','基于横向关系的援助称为“鼓励”。','20635-20658',NULL,1595404870,1782480568);
INSERT INTO highlights VALUES('25615385_51_1196-1210','25615385',174,'个体心理学和整体论','需要做一些不是干涉的“援助”','19900-19914',NULL,1595404777,1782480568);
INSERT INTO highlights VALUES('25615385_50_2771-2826','25615385',174,'个体心理学和整体论','表扬”背后的上下级关系和纵向关系。人表扬他人的目的就在于“操纵比自己能力低的对方”，其中既没有感谢也没有尊敬。','17497-17552',NULL,1595395198,1782480568);
INSERT INTO highlights VALUES('25615385_50_949-953','25615385',174,'个体心理学和整体论','横向关系','15616-15620',NULL,1595395073,1782480568);
INSERT INTO highlights VALUES('25615385_49_3659-3721','25615385',174,'个体心理学和整体论','这里有需要记住的行动原则。当我们在人际关系中遇到困难或者看不到出口的时候，首先应该考虑的是“倾听更大共同体的声音”这一原则。','14268-14356',NULL,1595394213,1782480568);
INSERT INTO highlights VALUES('25615385_48_3095-3186','25615385',174,'个体心理学和整体论','无论是你还是我，我们都不是世界的中心，必须用自己的脚主动迈出一步去面对人际关系课题；不是考虑“这个人会给我什么”，而是要必须思考一下“我能给这个人什么”。这就是对共同体的参与和融入。','10553-10670',NULL,1595393848,1782480568);
INSERT INTO highlights VALUES('25615385_48_3003-3063','25615385',174,'个体心理学和整体论','如果你认为自己就是世界的中心，那就丝毫不会主动融入共同体中，因为一切他人都是“为我服务的人”，根本没必要由自己采取行动。','10461-10521',NULL,1595393834,1782480568);
INSERT INTO highlights VALUES('25615385_48_2545-2561','25615385',174,'个体心理学和整体论','你是共同体的一部分，而不是中心。','9970-9993',NULL,1595393788,1782480568);
INSERT INTO highlights VALUES('25615385_47_1558-1627','25615385',174,'个体心理学和整体论','在只关心“我”这个意义上来讲，是以自我为中心。你正因为不想被他人认为自己不好，所以才在意他人的视线。这不是对他人的关心，而是对自己的执著。','7176-7245',NULL,1595299628,1782480568);
INSERT INTO highlights VALUES('25615385_46_3029-3077','25615385',174,'个体心理学和整体论','把对自己的执著（self interest）变成对他人的关心（social interest）。','5933-5981',NULL,1595157184,1782480568);
INSERT INTO highlights VALUES('25615385_46_1565-1578','25615385',174,'个体心理学和整体论','还包括国家或人类等一切存在','4443-4456',NULL,1595157110,1782480568);
INSERT INTO highlights VALUES('25615385_46_1188-1224','25615385',174,'个体心理学和整体论','像这样把他人看作伙伴并能够从中感到“自己有位置”的状态，就叫共同体感觉。','4040-4102',NULL,1595157076,1782480568);
INSERT INTO highlights VALUES('25615385_45_2809-2887','25615385',174,'个体心理学和整体论','“要想缔结良好的人际关系，需要保持一定距离；太过亲密就无法正面对话。但是，距离也不可以太远。”课题分离不是为了疏远他人，而是为了解开错综复杂的人际关系之线。','2731-2809',NULL,1595143603,1782480568);
INSERT INTO highlights VALUES('25615385_42_3460-3497','25615385',172,'自由就是不再寻求认可？','不畏惧被人讨厌而是勇往直前，不随波逐流而是激流勇进，这才是对人而言的自由。','25485-25522',NULL,1595055562,1782480568);
INSERT INTO highlights VALUES('25615385_42_2128-2137','25615385',172,'自由就是不再寻求认可？','自由就是被别人讨厌','22474-22483',NULL,1595055470,1782480568);
INSERT INTO highlights VALUES('25615385_42_1419-1444','25615385',172,'自由就是不再寻求认可？','真正的自由是一种把滚落下来的自己从下面向上推的态度','23392-23417',NULL,1594954534,1782480568);
INSERT INTO highlights VALUES('25615385_37_1901-1966','25615385',172,'自由就是不再寻求认可？','基本上，一切人际关系矛盾都起因于对别人的课题妄加干涉或者自己的课题被别人妄加干涉。只要能够进行课题分离，人际关系就会发生巨大改变。','9340-9412',NULL,1594917579,1782480568);
INSERT INTO highlights VALUES('25615385_36_4172-4176','25615385',172,'自由就是不再寻求认可？','课题分离','7631-7635',NULL,1594917461,1782480568);
INSERT INTO highlights VALUES('25615385_36_2208-2253','25615385',172,'自由就是不再寻求认可？','在犹太教教义中有这么一句话：“倘若自己都不为自己活出自己的人生，那还有谁会为自己而活呢？”','5570-5615',NULL,1594873373,1782480568);
INSERT INTO highlights VALUES('25615385_35_3594-3610','25615385',172,'自由就是不再寻求认可？','阿德勒心理学否定寻求他人的认可。','3509-3532',NULL,1594873257,1782480568);
INSERT INTO highlights VALUES('25615385_33_790-828','25615385',170,'为什么讨厌自己？','青年：也就是“不在于被给予了什么，而在于如何去使用被给予的东西','44141-44179',NULL,1594794724,1782480568);
INSERT INTO highlights VALUES('25615385_33_734-740','25615385',170,'为什么讨厌自己？','使用的心理学','44078-44084',NULL,1594794716,1782480568);
INSERT INTO highlights VALUES('25615385_32_1958-1962','25615385',170,'为什么讨厌自己？','人生谎言','41065-41069',NULL,1594794636,1782480568);
INSERT INTO highlights VALUES('25615385_30_1379-1450','25615385',170,'为什么讨厌自己？','首先，行为方面的目标有“自立”和“与社会和谐共处”这两点。而且，支撑这种行为的心理方面的目标是“我有能力”以及“人人都是我的伙伴”这两种意识。','35069-35140',NULL,1594655845,1782480568);
INSERT INTO highlights VALUES('25615385_29_2832-2880','25615385',170,'为什么讨厌自己？','眼镜模糊了，只能看到眼前的胜负就会走错道路，我们只有摘掉竞争或胜负之争的眼镜才能够改变完善自己。','34084-34132',NULL,1594655724,1782480568);
INSERT INTO highlights VALUES('25615385_22_1435-1447','25615385',170,'为什么讨厌自己？','人的烦恼皆源于人际关系。','7042-7054',NULL,1594400569,1782480568);
INSERT INTO highlights VALUES('25615385_18_961-972','25615385',168,'不为人知的心理学“第三巨头”','人生中思考或行为的倾向','20304-20315',NULL,1593952670,1782480568);
INSERT INTO highlights VALUES('25615385_18_821-836','25615385',168,'不为人知的心理学“第三巨头”','生活方式”一词来说明性格或秉性','20164-20179',NULL,1593952661,1782480568);
INSERT INTO highlights VALUES('25615385_13_1451-1462','25615385',168,'不为人知的心理学“第三巨头”','为了大发雷霆而制造怒气','10075-10086',NULL,1593850735,1782480568);
INSERT INTO highlights VALUES('25615385_12_1536-1635','25615385',168,'不为人知的心理学“第三巨头”','任何经历本身并不是成功或者失败的原因。我们并非因为自身经历中的刺激——所谓的心理创伤——而痛苦，事实上我们会从经历中发现符合自己目的的因素。决定我们自身的不是过去的经历，而是我们自己赋予经历的意义。','7005-7130',NULL,1593850497,1782480568);
INSERT INTO highlights VALUES('25615385_12_1347-1375','25615385',168,'不为人知的心理学“第三巨头”','阿德勒心理学明确否定心理创伤，这一点具有划时代的创新意义','6809-6844',NULL,1593850469,1782480568);
INSERT INTO highlights VALUES('25615385_11_2866-2894','25615385',168,'不为人知的心理学“第三巨头”','阿德勒心理学考虑的不是过去的“原因”，而是现在的“目的”','5038-5085',NULL,1593850351,1782480568);
INSERT INTO highlights VALUES('25615385_5_1635-1669','25615385',163,'推荐序二 自我的枷锁和解放','重要的不是过去，而是你怎么看待过去，而我们对过去的看法，是可以改变的','1578-1612',NULL,1593793581,1782480568);
INSERT INTO highlights VALUES('40055543_55_6612-6691','40055543',55,'第二节 政府的发展与转型','中国目前缺乏属于地方的主体税种。以往依托税收之外的“土地财政”和“土地金融”模式已经无法再持续下去，因此要想扩大民生支出，可能需要改革税制，将税入向地方倾斜。','6612-6691',NULL,1653221388,1782480567);
INSERT INTO highlights VALUES('40055543_55_5227-5309','40055543',55,'第二节 政府的发展与转型','此时若仍将资源继续向政府和国企集中，效率就会大打折扣。投资、融资、生产都需要更加分散化的决策。市场化改革要想更进一步，“生产型政府”就需要逐步向“服务型政府”转型。','5227-5309',NULL,1653220960,1782480567);
INSERT INTO highlights VALUES('40055543_55_1516-1630','40055543',55,'第二节 政府的发展与转型','对发展中国家而言，市场和政府的关系，不是简单的一进一退的问题，而是政府能否为市场运行打造出一个基本框架和空间的问题。这需要投入很多资源，一步一步建设。如果政府不去做这些事，市场经济和所谓“企业家精神”，不会像变戏法一样自动出现。','1516-1630',NULL,1653220621,1782480567);
INSERT INTO highlights VALUES('40055543_53_1210-1309','40055543',53,'第八章 总结：政府与经济发展','一套严格的概念框架无疑有助于厘清问题，但也经常让人错把问题当成答案。社会科学总渴望发现一套‘放之四海而皆准’的方法和规律，但这种心态需要成熟起来。不要低估经济现实的复杂性，也不要高估科学工具的质量。','1210-1309',NULL,1653219911,1782480567);
INSERT INTO highlights VALUES('40055543_51_424-545','40055543',51,'结语','本书介绍了我国地方政府推动经济发展的模式，从微观机制开始，到宏观现象结束。总结一下，这一模式有三大特点。第一个特点是城市化过程中“重土地、轻人”。第二个特点是招商引资竞争中“重规模、重扩张”。第三个特点是经济结构上“重投资、重生产、轻消费”。','424-545',NULL,1653160388,1782480567);
INSERT INTO highlights VALUES('40055543_50_1144-1183','40055543',50,'第三节 再平衡与国内大循环','所以解决就业和提高收入必须依靠服务业的大发展，而这只能发生在人口密集的城市中。','1144-1183',NULL,1653160199,1782480567);
INSERT INTO highlights VALUES('40055543_48_9701-9787','40055543',48,'第一节 低消费与产能过剩','虽然从会计核算角度讲，投资确实可以提升当下的GDP数字，但若投资形成的资产不能提高生产率、带来更高的收入，不能成为未来更高的消费，这种投资就没有形成实质性的财富，就是浪费。','9701-9787',NULL,1653159441,1782480567);
INSERT INTO highlights VALUES('40055543_48_2479-2598','40055543',48,'第一节 低消费与产能过剩','目前主流的解释是计划生育、政府民生支出不足、房价上涨三者的共同作用。','2479-2513',NULL,1653158593,1782480567);
INSERT INTO highlights VALUES('40055543_44_5776-5815','40055543',44,'第四节 化解债务风险','总的来看，我国债务风险的本质不是金融投机的风险，而是财政和资源分配机制的风险。','5776-5815',NULL,1653143337,1782480567);
INSERT INTO highlights VALUES('40055543_44_3411-3734','40055543',44,'第四节 化解债务风险',unistr('我国目前的货币政策比较谨慎，国务院和央行都数次明确表态不搞“大水漫灌”，“不搞竞争性的零利率或量化宽松政策”。(41)主要原因可能有二：第一，政府不愿看到宽松的货币政策再次推高房价，“房住不炒”是个底线原则；第二，货币政策治标不治本，无法从根本上解决债务负担背后的经济增速放缓问题，因为这是结构性的问题，是地方政府推动经济发展的模式问题。\u000a遏制新增债务'),'3411-3734',NULL,1653142380,1782480567);
INSERT INTO highlights VALUES('40055543_44_2242-2326','40055543',44,'第四节 化解债务风险','第三类增加货币供给的做法是把债务货币化。政府加大财政支出去刺激经济，由财政部发债融资，央行直接印钱买过来，无需其他金融机构参与也无需支付利息，这便是所谓“赤字货币化”。','2242-2326',NULL,1653142084,1782480567);
INSERT INTO highlights VALUES('40055543_44_1897-1993','40055543',44,'第四节 化解债务风险','“量化宽松”的主要问题是难以把增发的货币转到穷人手中，因此难以刺激消费支出，还会拉大贫富差距。央行“发钱”的方式是购买各种金融资产，所以会推高资产价格，受益的是资产所有者，也就是相对富裕的人。','1897-1993',NULL,1653139518,1782480567);
INSERT INTO highlights VALUES('40055543_43_8178-8188','40055543',43,'第三节 中国的债务与风险','金融业规模显然过大了','8178-8188',NULL,1653139089,1782480567);
INSERT INTO highlights VALUES('40055543_43_7449-7541','40055543',43,'第三节 中国的债务与风险','保增加等，都会从需求端刺激信贷规模的扩张。所以商业银行的信贷扩张，固然离不开宽松的货币环境，但也同样离不开信贷需求的扩张，离不开地方政府的土地金融和房地产繁荣，此所谓“银根连着地根”。','7449-7541',NULL,1653139009,1782480567);
INSERT INTO highlights VALUES('40055543_43_3347-3424','40055543',43,'第三节 中国的债务与风险','是资本市场发展不充分，企业融资以债务尤其是银行贷款为主，股权融资占比很低。2018年末，企业债务总额约140万亿元，但在境内的股票融资余额不过区区7万亿元','3347-3424',NULL,1653134407,1782480567);
INSERT INTO highlights VALUES('40055543_43_3285-3299','40055543',43,'第三节 中国的债务与风险','但企业债务负担远高于发达国家','3285-3299',NULL,1653134399,1782480567);
INSERT INTO highlights VALUES('40055543_42_8432-8529','40055543',42,'第二节 债台为何高筑：欧美的教训','在缺乏增长点的情况下，央行给银行体系提供流动性，但商业银行资金贷不出去，容易流向资产市场。放松货币条件总体上有利于资产持有者，超宽松的货币政策可能加剧财富分化，固化结构扭曲，使危机调整的过程更长','8432-8529',NULL,1653120801,1782480567);
INSERT INTO highlights VALUES('40055543_42_6611-6754','40055543',42,'第二节 债台为何高筑：欧美的教训','穷人借债主要是买房，因此富人的余钱也就通过银行等金融中介流向了房地产。金融危机前，美国银行业将近七成的贷款是按揭或其他房地产相关贷款。所以大部分银行并没有把社会闲散资金导向实体企业，变成生产性投资，而是充当了富人借钱给穷人买房的中介。这种金融服务的扩张，降低了资金配置效率，加大了风险。','6611-6754',NULL,1653119978,1782480567);
INSERT INTO highlights VALUES('40055543_42_5240-5464','40055543',42,'第二节 债台为何高筑：欧美的教训','为保持美元的国际储备货币地位，美国的对外贸易可能需要常年保持逆差，以向世界提供更多美元。但持续的逆差会累积债务，最终威胁美元的储备货币地位，这个逻辑也被称为“特里芬悖论”。(17)所以如今的全球经济失衡，是贸易失衡和美元地位带来的资本流动失衡所共同造就的。','5240-5464',NULL,1653119836,1782480567);
INSERT INTO highlights VALUES('40055543_41_1707-1755','40055543',41,'第一节 债务与经济衰退','可见债务危机往往也会殃及那些债务水平健康的部门，形成连锁反应，造成地区性甚至全国范围的经济衰退。','1707-1755',NULL,1653118733,1782480567);
INSERT INTO highlights VALUES('40055543_24_5958-6253','40055543',24,'第三节 招商引资中的地方官员','从经济发展的角度看，我国的腐败现象有两个显著特点。第一，腐败与经济高速增长长期并存。这与“腐败危害经济”这一过度简单化的主流观念冲突，以腐败为由唱空中国经济的预测屡屡落空。第二，随着改革的深入，政府和市场间关系在不断变化，腐败形式也在不断变化。20世纪80年代的腐败案件大多与价格双轨制下的“官倒”和各种“投机倒把”有关；90年代的案件则多与国企改革和国有资产流失有关；21世纪以来，与土地开发相关的案件成了主流。(34)','5958-6253',NULL,1652528311,1782480567);
INSERT INTO highlights VALUES('40055543_23_5164-5265','40055543',23,'第二节 地方政府债务','地方债也是一样的道理，不能用整体数字掩盖局部风险。纵向上看，层级越低的政府负担越重，风险越高。县级债务负担远高于省级，因为县级的经济发展水平更低，财政收入更少。横向上看，中西部的债务负担和风险远高于东部','5164-5265',NULL,1652527327,1782480567);
INSERT INTO highlights VALUES('40055543_23_4113-4147','40055543',23,'第二节 地方政府债务','这个低风险高收益的“怪胎”对债券市场发展影响很大，积累的风险其实不小','4113-4147',NULL,1652527214,1782480567);
INSERT INTO highlights VALUES('40055543_23_1868-2041','40055543',23,'第二节 地方政府债务','要想在城市建设开发中引入银行资金，需要解决三个技术问题。第一，需要一个能借款的公司，因为政府不能直接从银行贷款；第二，城建开发项目繁复，包括自来水、道路、公园、防洪，等等，有的赚钱，有的赔钱，但缺了哪个都不行，所以不能以单个项目分头借款，最好捆绑在一起，以赚钱的项目带动不赚钱的项目；第三，仅靠财政预算收入不够还债，要能把跟土地有关的收益用起来。','1868-2041',NULL,1652526920,1782480567);
INSERT INTO highlights VALUES('40055543_22_3687-3722','40055543',22,'第一节 城投公司与土地金融','但大多数融资平台的主业不是旅游开发，而是工业园区开发和城市基础设施建设','3687-3722',NULL,1652525961,1782480567);
INSERT INTO highlights VALUES('40055543_22_3160-3180','40055543',22,'第一节 城投公司与土地金融','《担保法》规定政府不能为融资平台提供担保','3160-3180',NULL,1652525845,1782480567);
INSERT INTO highlights VALUES('40055543_22_771-815','40055543',22,'第一节 城投公司与土地金融','我国政府不但拥有城市土地，也掌控着金融系统，自然会以各种方式参与实业投资，不可能置身事外','771-815',NULL,1652523110,1782480567);
INSERT INTO highlights VALUES('40055543_19_1016-1140','40055543',19,'结语','所以土地真正的力量还不在“土地财政”，而在以土地为抵押而撬动的银行信贷与其他各路资金。“土地财政”一旦嫁接了资本市场，加上了杠杆，就成了“土地金融”，能像滚雪球般越滚越大，推动经济飞速扩张，也造就了地方政府越滚越多的债务，引发了一系列宏观经济问题。','1016-1140',NULL,1652520702,1782480567);
INSERT INTO highlights VALUES('40055543_18_6625-7048','40055543',18,'第三节 纵向不平衡与横向不平衡','经济情况越好、财力越雄厚的地区，反而可能拿到更多的专项转移支付项目，原因有三。第一，上级分配项目时一般不会“撒胡椒面儿”，而是倾向于集中财力投资大项目，并且交给有能力和条件的地区来做，所谓“突出重点，择优支持”。第二，2015年之前，许多项目都要求地方政府提供配套资金，只有有能力配套的地方才有能力承接大项目，拿到更多转移支付。(37)第三，项目审批过程中人情关系在所难免。很多专项资金是由财政部先拨款给各部委后再层层下拨，所以就有了“跑部钱进”的现象，而经济发达地区往往与中央部委的关系也更好。','6625-6966',NULL,1652520602,1782480567);
INSERT INTO highlights VALUES('40055543_18_6445-6462','40055543',18,'第三节 纵向不平衡与横向不平衡','专项转移支付约占转移支付总额的四成','6445-6462',NULL,1652520531,1782480567);
INSERT INTO highlights VALUES('40055543_18_3819-3895','40055543',18,'第三节 纵向不平衡与横向不平衡','“乡财县管”和“省直管县”改革，实质上把我国五级的行政管理体制（中央—省—市—区县—乡镇）在财政管理体制上“拉平”了，变成了三级体制（中央—省—市县）。','3819-3895',NULL,1652518016,1782480567);
INSERT INTO highlights VALUES('40055543_18_1459-1474','40055543',18,'第三节 纵向不平衡与横向不平衡','农民真苦，农村真穷，农业真危险','1459-1474',NULL,1652517763,1782480567);
INSERT INTO highlights VALUES('40055543_18_800-885','40055543',18,'第三节 纵向不平衡与横向不平衡','分税制改革之后，中央和省分成，省也要和市县分成。可因为上级权威高于下级，所以越往基层分到的钱往往越少，但分到的任务却越来越多，出现了“财权层层上收，事权层层下压”的局面。','800-885',NULL,1652517702,1782480567);
INSERT INTO highlights VALUES('40055543_17_6653-6860','40055543',17,'第二节 土地财政','经济学家张五常曾做过一个比喻：地方政府就像一家商场，招商引资就是引入商铺。商铺只要交一个低廉的入场费用（类似工业用地转让费），但营业收入要和商场分成（类似增值税，不管商铺是否盈利，只要有流水就要分成）。商场要追求总体收入最大化，所以既要考虑入门费和租金的平衡，也要考虑不同商铺间的平衡。一些商铺大名鼎鼎，能为商场带来更大客流，那商场不仅可以免除它们的入门费，还可以降低分成，甚至可以倒贴（类似地方给企业的各种补贴）','6653-6860',NULL,1652517118,1782480567);
INSERT INTO highlights VALUES('40055543_17_6506-6523','40055543',17,'第二节 土地财政','此外，地方之间招商引资竞争非常激烈','6506-6523',NULL,1652517095,1782480567);
INSERT INTO highlights VALUES('40055543_17_6338-6387','40055543',17,'第二节 土地财政','地方政府压低工业用地价格，因为工业对经济转型升级的带动作用强，能带来增值税和其他税收，还能创造就业','6338-6387',NULL,1652517069,1782480567);
INSERT INTO highlights VALUES('40055543_17_5721-5781','40055543',17,'第二节 土地财政','所以商住用地虽然面积上只占出让土地的一半，但贡献了几乎所有的土地使用权转让收入。因此“土地财政”的实质是“房地产财政”。','5721-5781',NULL,1652516928,1782480567);
INSERT INTO highlights VALUES('40055543_17_3459-3590','40055543',17,'第二节 土地财政','规定了农地要想转为建设用地，必须经过征地后变成国有土地，这也就确立了城市政府对土地建设的垄断权力。','3459-3508',NULL,1652516553,1782480567);
INSERT INTO highlights VALUES('40055543_17_951-1000','40055543',17,'第二节 土地财政','改革前，企业的大多数税收按隶属关系上缴，改革后则变成了在所在地上缴，这自然会刺激地方政府招商引资。','951-1000',NULL,1652515468,1782480567);
INSERT INTO highlights VALUES('40055543_17_1146-1200','40055543',17,'第二节 土地财政','因为绝大多数税收征收自企业，且多在生产环节征收，所以地方政府重视企业而相对轻视民生，重视生产而相对轻视消费。','1146-1200',NULL,1652515435,1782480567);
INSERT INTO highlights VALUES('40055543_17_580-625','40055543',17,'第二节 土地财政','另一方面，地方可以增加预算外收入，其中最重要的就是围绕土地出让和开发所产生的“土地财政”。','580-625',NULL,1652515286,1782480567);
INSERT INTO highlights VALUES('40055543_16_8145-8277','40055543',16,'第一节 分税制改革','改革大大增强了中央政府的宏观调控能力，为之后应付一系列重大冲击（1997年亚洲金融危机、2008年全球金融危机和汶川地震等）奠定了基础，也保障了一系列重大改革（如国企改革和国防现代化建设）和国家重点建设项目的顺利实施。分税制也从根本上改变了地方政府发展经济的模式。','8145-8277',NULL,1652512135,1782480567);
INSERT INTO highlights VALUES('40055543_16_6586-6600','40055543',16,'第一节 分税制改革','立刻引发了第四季度的收税狂潮','6586-6600',NULL,1652511867,1782480567);
INSERT INTO highlights VALUES('40055543_16_6218-6275','40055543',16,'第一节 分税制改革','成功的政策背后是成功的协商和妥协，而不是机械的命令与执行，所以理解利益冲突，理解协调和解决机制，是理解政策的基础。','6218-6275',NULL,1652511811,1782480567);
INSERT INTO highlights VALUES('40055543_16_6148-6171','40055543',16,'第一节 分税制改革','缺少社会阅历的学生容易把博弈结果错当成博弈过程','6148-6171',NULL,1652511801,1782480567);
INSERT INTO highlights VALUES('40055543_15_1533-1553','40055543',15,'第二章 财税与政府行为','实际情况是地方政府的支出和收入高度不匹配','1533-1553',NULL,1652455930,1782480567);
INSERT INTO highlights VALUES('40055543_14_461-472','40055543',14,'扩展阅读','治理中国：从革命到改革','461-472',NULL,1652455715,1782480567);
INSERT INTO highlights VALUES('40055543_12_545-581','40055543',12,'第五节 招商引资','招商引资不仅是招商局的部门职能，也是以经济建设为中心的地方政府的核心任务','545-581',NULL,1652455274,1782480567);
INSERT INTO highlights VALUES('40055543_11_3089-3173','40055543',11,'第四节 激励相容','我们的国家这样大，人口这样多，情况这样复杂，有中央和地方两个积极性，比只有一个积极性好得多。我们不能像苏联那样，把什么都集中到中央，把地方卡得死死的，一点机动权也没有。','3089-3173',NULL,1652423603,1782480567);
INSERT INTO highlights VALUES('40055543_11_1640-1692','40055543',11,'第四节 激励相容','最起码，能评价和奖惩工作业绩的上级，能决定工作内容的上级，受下级工作影响最大的上级，应该尽量是同一上级。','1640-1692',NULL,1652423118,1782480567);
INSERT INTO highlights VALUES('40055543_10_5379-5407','40055543',10,'第三节 复杂信息','所谓权力，实质就是在说不清楚的情况下由谁来拍板决策的问题','5379-5407',NULL,1652422904,1782480567);
INSERT INTO highlights VALUES('40055543_10_1243-1259','40055543',10,'第三节 复杂信息','下级国企实际上主要由下级政府管辖','1243-1259',NULL,1652422508,1782480567);
INSERT INTO highlights VALUES('40055543_10_1180-1186','40055543',10,'第三节 复杂信息','国企改革为例','1180-1186',NULL,1652422476,1782480567);
INSERT INTO highlights VALUES('40055543_10_880-1046','40055543',10,'第三节 复杂信息','所以上级虽然名义上有最终决定权，拥有“形式权威”，但由于信息复杂、不易处理，下级实际上自主性很大，拥有“实际权威”。维护两类权威的平衡是政府有效运作的关键。若下级有明显信息优势，且承担主要后果，那就该自主决策。若下级虽有信息优势，但决策后果对上级很重要，上级就可能多干预。但上级干预可能会降低下级的工作积极性，结果不一定对上级更有利','880-1046',NULL,1652422465,1782480567);
INSERT INTO highlights VALUES('40055543_9_7340-7399','40055543',9,'第二节 外部性与规模经济','但在现实工作中，干预与否、干预到什么程度、能否达到干预效果，都受制于公共事务的外部性大小、规模经济、跨地区协调的难度等','7340-7399',NULL,1652421298,1782480567);
INSERT INTO highlights VALUES('40055543_9_7183-7194','40055543',9,'第二节 外部性与规模经济','跨区域的共同上级来协调','7183-7194',NULL,1652421264,1782480567);
INSERT INTO highlights VALUES('40055543_9_4989-5024','40055543',9,'第二节 外部性与规模经济','人为打破自然边界，不以天险为界来划分行政区，防止地方势力依天险制造分裂','4989-5024',NULL,1652421020,1782480567);
INSERT INTO highlights VALUES('40055543_9_4852-4874','40055543',9,'第二节 外部性与规模经济','人口密度变化频繁，但行政区域的调整要缓慢得多','4852-4874',NULL,1652420466,1782480567);
INSERT INTO highlights VALUES('40055543_8_4237-4295','40055543',8,'第一节 政府治理的特点','在任何体制下，权力运作都受到两种约束：做事的能力及做事的意愿。前者取决于掌握的资源，后者取决于各方的积极性和主动性。','4237-4295',NULL,1652385417,1782480567);
INSERT INTO highlights VALUES('40055543_8_4194-4236','40055543',8,'第一节 政府治理的特点','像所有政治制度一样，实际的权力运作与纸面的规章制度并不完全一致，但也绝不是任性随意的','4194-4236',NULL,1652385399,1782480567);
INSERT INTO highlights VALUES('40055543_8_3533-3569','40055543',8,'第一节 政府治理的特点','若是经常性的跨部门事务，则设置上级“分管领导”甚至“领导小组”来协调推进','3533-3569',NULL,1652385256,1782480567);
INSERT INTO highlights VALUES('40055543_8_3343-3380','40055543',8,'第一节 政府治理的特点','制度设计的一大任务就是要避免把过多决策推给上级，减轻上级负担，提高决策效率','3343-3380',NULL,1652385222,1782480567);
INSERT INTO highlights VALUES('40055543_8_3012-3123','40055543',8,'第一节 政府治理的特点','大多数地方部门都要同时接受“条条”和“块块”的双重领导。拿县教育局来说，既要接受市教育局的指导，又要服从县委、县政府的领导。通常情况下，“条条”关系是业务关系，“块块”关系才是领导关系，因为地方党委和政府可以决定人事任免。','3012-3123',NULL,1652385078,1782480567);
INSERT INTO highlights VALUES('40055543_8_2869-2880','40055543',8,'第一节 政府治理的特点','党委、政府、人大、政协','2869-2880',NULL,1652385002,1782480567);
INSERT INTO highlights VALUES('40055543_8_1361-1395','40055543',8,'第一节 政府治理的特点','在土地和经济事务上，县级市的权力比县大，而县的权力又比一般市辖区大。','1361-1395',NULL,1652384795,1782480567);
INSERT INTO highlights VALUES('3300064086_10_4710-4793','3300064086',10,'第五章 无论你走到哪里，你都在那里：你无法逃避自己','期望通常是痛苦和欲望结合而生，痛苦是指现在有某种疾病存在的感觉，而欲望来自“感觉某种美好的东西潜伏在地平线上等待取代疾病”。总之，如果我们能“到达那里”，情况会更好。','4710-4793',0,1773811343,1782480548);
INSERT INTO highlights VALUES('3300064086_10_4101-4152','3300064086',10,'第五章 无论你走到哪里，你都在那里：你无法逃避自己','拖延往往是人们发现自己的工作没有成就感的迹象。在这种情况下，如果可能的话，考虑找一些更令人兴奋的工作。','4101-4152',0,1773811202,1782480548);
INSERT INTO highlights VALUES('3300064086_10_3656-3680','3300064086',10,'第五章 无论你走到哪里，你都在那里：你无法逃避自己','目标的改变表明思想在海上漂流，就像被风吹着一样”','3656-3680',0,1773811105,1782480548);
INSERT INTO highlights VALUES('3300064086_10_3307-3331','3300064086',10,'第五章 无论你走到哪里，你都在那里：你无法逃避自己','“学习不是为了了解得更多，而是为了了解得更好”。','3307-3331',0,1773811049,1782480548);
INSERT INTO highlights VALUES('3300064086_10_2462-2490','3300064086',10,'第五章 无论你走到哪里，你都在那里：你无法逃避自己','当你有了一个真正的目的地，你就真切知道你活着是为了什么。','2462-2490',0,1773810792,1782480548);
INSERT INTO highlights VALUES('3300064086_10_690-728','3300064086',10,'第五章 无论你走到哪里，你都在那里：你无法逃避自己','“你必须改变头脑，而不是改变地点”，因为“不管你去哪里，你的错误会跟随你”。','690-728',0,1773029924,1782480548);
INSERT INTO highlights VALUES('3300064086_9_12201-12295','3300064086',9,'第四章 愤怒的问题',unistr('一个医生预期每天都能见到一大批患者。正如塞涅卡所写：\u000a智者面对别人犯错误时，在精神上是平静和平衡的。他不是犯错者的敌人，而是帮助犯错者康复'),'12201-12295',0,1772963763,1782480548);
INSERT INTO highlights VALUES('3300064086_9_11257-11317','3300064086',9,'第四章 愤怒的问题','记住，如果有人开始让你生气，你可以稍等片刻：死亡最终会让我们人人平等。因此，与其生气，不如把注意力集中在更重要的事情上。','11257-11317',0,1772963525,1782480548);
INSERT INTO highlights VALUES('3300064086_9_10135-10180','3300064086',9,'第四章 愤怒的问题','“没有人会伤害你，如果你不认为那是伤害的话；只有当你认为自己受到了伤害时，你才会受到伤害”','10135-10180',0,1772963235,1782480548);
INSERT INTO highlights VALUES('3300064086_9_8883-8949','3300064086',9,'第四章 愤怒的问题','1.退后一步。在一开始就阻止愤怒的最好办法是，注意到“我被冤枉了”的第一感觉或印象，然后暂停一下，给它们平息的时间，而不要认同它们。','8883-8949',0,1772963030,1782480548);
INSERT INTO highlights VALUES('3300064086_9_8761-8818','3300064086',9,'第四章 愤怒的问题','每一种消极情绪起初都是脆弱的。但随着情绪的发展，它会自我激发并增强力量。它在开始时更容易被排斥，后来要驱除就难了”','8761-8818',0,1772963005,1782480548);
INSERT INTO highlights VALUES('3300064086_9_7828-7880','3300064086',9,'第四章 愤怒的问题','“在刺激和反应之间有一个空间。在这个空间里是我们选择反应的力量。我们的成长和自由存在于我们的反应当中。”','7828-7880',0,1772962793,1782480548);
INSERT INTO highlights VALUES('3300064086_9_7673-7732','3300064086',9,'第四章 愤怒的问题','事实上，艾比克泰德说“对‘印象’进行审视是哲学家唯一重要的任务，除非经过仔细的审视，否则任何‘印象’都不应该被接受”。','7673-7732',0,1772962768,1782480548);
INSERT INTO highlights VALUES('3300064086_9_7464-7558','3300064086',9,'第四章 愤怒的问题','愤怒源于一种你受到了委屈的信念，你不应该只看表面就轻易接受。你应该推迟判断，即使它看起来很清楚很明显，因为有些虚假的事情看起来似乎是真的。我们必须始终留出一些时间：一些用来揭示真相的时间。','7464-7558',0,1772962687,1782480548);
INSERT INTO highlights VALUES('3300064086_9_6126-6223','3300064086',9,'第四章 愤怒的问题','愤怒本身总是基于两种心理判断。第一个判断是“我受到了伤害”或“有人对我不公”。第二个判断是“如果我受到了伤害，我应该通过报复或惩罚来寻求补偿”。如果这两个判断结合起来，结果很可能表现为极端愤怒。','6126-6223',0,1772863891,1782480548);
INSERT INTO highlights VALUES('3300064086_9_5880-5892','3300064086',9,'第四章 愤怒的问题','没有她，我永远都不会幸福','5880-5892',0,1772863854,1782480548);
INSERT INTO highlights VALUES('3300064086_9_4060-4116','3300064086',9,'第四章 愤怒的问题','对斯多葛学派来说，最主要的人类情感是对他人的关怀和爱。父母自然会爱他们的孩子，而人类的爱将人们和社区联系在一起。','4060-4116',0,1772863616,1782480548);
INSERT INTO highlights VALUES('3300064086_9_3262-3294','3300064086',9,'第四章 愤怒的问题','他们相信，极端的愤怒是可以避免的，而且可以一开始就不允许它产生。','3262-3294',0,1772863547,1782480548);
INSERT INTO highlights VALUES('3300064086_9_2613-2641','3300064086',9,'第四章 愤怒的问题','愤怒来自一种“我受到了伤害”或“我被冤枉了”的头脑判断，','2613-2641',0,1772863457,1782480548);
INSERT INTO highlights VALUES('3300064086_9_1388-1409','3300064086',9,'第四章 愤怒的问题','塞涅卡说极端的“愤怒是一种短暂的精神错乱”','1388-1409',0,1772770135,1782480548);
INSERT INTO highlights VALUES('3300064086_9_1886-1914','3300064086',9,'第四章 愤怒的问题','一个狂怒的人外表如此可怕，他的内心看起来会是什么样子呢？','1886-1914',0,1772513133,1782480548);
INSERT INTO highlights VALUES('3300064086_9_712-764','3300064086',9,'第四章 愤怒的问题','对斯多葛学派来说，愤怒（他们的意思是暴怒）是极端负面情绪中最糟糕和最具毒性的情绪，他们称为“激烈情绪”。','712-764',0,1772513051,1782480548);
INSERT INTO highlights VALUES('3300064086_8_9450-9549','3300064086',8,'第三章 如何克服担忧和焦虑','灵魂开始像太阳一样发光；只要我们能保持这种“我在”和自足的感觉，太阳会继续照耀。这并不意味着不会有外部干扰，但这些干扰会像飘浮在宁静而灿烂的太阳下的云朵。这些乌云飘过，不会改变或干扰太阳或它的光芒。','9450-9549',0,1771770194,1782480548);
INSERT INTO highlights VALUES('3300064086_8_8510-8549','3300064086',8,'第三章 如何克服担忧和焦虑','有些事情造成的情绪冲击不避免。这些反应是自然的、本能的，而不是基于人们的看法。','8510-8549',0,1771761000,1782480548);
INSERT INTO highlights VALUES('3300064086_8_8164-8237','3300064086',8,'第三章 如何克服担忧和焦虑','塞涅卡指出，人们对死亡有一种非理性的恐惧，尽管死亡是生命的一部分。因为死亡是自然的，是每个人都应该能预计到的，把它看作一件可怕的事情是一个认知错误','8164-8237',0,1771760805,1782480548);
INSERT INTO highlights VALUES('3300064086_8_5692-5752','3300064086',8,'第三章 如何克服担忧和焦虑','我们过快赞同自己的意见。我们不去检测那些导致我们产生恐惧的想法，也不会小心地质疑它们……所以，让我们仔细地审视各种事情吧','5692-5752',0,1771759268,1782480548);
INSERT INTO highlights VALUES('3300064086_8_5495-5535','3300064086',8,'第三章 如何克服担忧和焦虑','“不要让未来困扰你。”因为当未来到来的时候，你将以你面对当下时一样的理性来面对。','5495-5535',0,1771758875,1782480548);
INSERT INTO highlights VALUES('3300064086_8_5314-5371','3300064086',8,'第三章 如何克服担忧和焦虑','在塞涅卡等斯多葛派哲学家看来，对未来的事情感到关切是合理的，但是事先就对可能根本不会发生的事情感到担忧是一个错误。','5314-5371',0,1771756018,1782480548);
INSERT INTO highlights VALUES('3300064086_8_5250-5285','3300064086',8,'第三章 如何克服担忧和焦虑','把我们的思绪从未来召唤回来，完全生活在当下，因为未来在此刻根本不存在。','5250-5285',0,1771756002,1782480548);
INSERT INTO highlights VALUES('3300064086_8_4471-4549','3300064086',8,'第三章 如何克服担忧和焦虑','当想象与原始情感混合在一起时，就可以创建一个反馈回路，想象放大情感，情感又放大想象。（现代心理学家有时会把这种“对焦虑感到焦虑”的体验称为元担忧或元焦虑。）','4471-4549',0,1771755752,1782480548);
INSERT INTO highlights VALUES('3300064086_8_4359-4373','3300064086',8,'第三章 如何克服担忧和焦虑','想象力也可能以消极的形式出现','4359-4373',0,1771755706,1782480548);
INSERT INTO highlights VALUES('3300064086_8_4176-4263','3300064086',8,'第三章 如何克服担忧和焦虑','其中一种做法，因马可·奥勒留而闻名，今天被称为“俯瞰”：它让你想象自己在我们星球上空遥远的地方俯视地球，看看我们有多渺小，并意识到我们的个人麻烦与浩瀚的宇宙相比有多微不足道。','4176-4263',0,1771755672,1782480548);
INSERT INTO highlights VALUES('3300064086_8_3285-3294','3300064086',8,'第三章 如何克服担忧和焦虑','惧是奴役的一种形式','3285-3294',0,1771755291,1782480548);
INSERT INTO highlights VALUES('3300064086_8_2812-2832','3300064086',8,'第三章 如何克服担忧和焦虑','但实际上我们是在对自己内心的事物做出反应','2812-2832',0,1771755149,1782480548);
INSERT INTO highlights VALUES('3300064086_8_1873-1919','3300064086',8,'第三章 如何克服担忧和焦虑','塞涅卡解释说，每个人都需要努力克服的两大恐惧是对死亡的恐惧和对贫困的恐惧（或对财富的渴望）。','1873-1919',0,1771754862,1782480548);
INSERT INTO highlights VALUES('3300064086_7_8504-8592','3300064086',7,'第二章 珍视你的时间：不要推迟生命','但对于那些忘记过去、忽视现在、害怕未来的人来说，生命非常短暂，令人焦虑。当他们到达生命的尽头时，这些可怜的人意识到他们忙忙碌碌很长时间但一无所获，只是他们意识到这一点为时已晚。','8504-8592',0,1771691552,1782480548);
INSERT INTO highlights VALUES('3300064086_7_6772-6803','3300064086',7,'第二章 珍视你的时间：不要推迟生命','一个正在接受训练以成为斯多葛派的人就像一个努力获得自由的奴隶。','6772-6803',0,1771691329,1782480548);
INSERT INTO highlights VALUES('3300064086_7_6435-6528','3300064086',7,'第二章 珍视你的时间：不要推迟生命','对于古希腊和罗马的人来说，自由并不意味着完全拥有“做任何自己喜欢做的事”的自由（即许可）；它意味着自我掌控的自由或“免于控制”。这意味着你拥有自我，属于你自己，而不是任何外人外物的奴隶。','6435-6528',0,1771691291,1782480548);
INSERT INTO highlights VALUES('3300064086_7_6159-6252','3300064086',7,'第二章 珍视你的时间：不要推迟生命','举个例子，如果有人总是生气，日复一日地攻击他周围的人，那个人就是在心理上受到了负面情绪的奴役。但获得自由也是可能的。斯多葛学派谈到“心理奴役”，我们今天说到“上瘾”，这是一个相关的概念。','6159-6252',0,1771690650,1782480548);
INSERT INTO highlights VALUES('3300064086_7_5703-5729','3300064086',7,'第二章 珍视你的时间：不要推迟生命','即人除了在身体上被奴役之外，也有可能在心理上被奴役。','5703-5729',0,1771690528,1782480548);
INSERT INTO highlights VALUES('3300064086_7_4688-4721','3300064086',7,'第二章 珍视你的时间：不要推迟生命','我们必要的任务完成后，我们应该休息，把我们的头脑用在更好的事情上。','4688-4721',0,1771667867,1782480548);
INSERT INTO highlights VALUES('3300064086_7_3475-3504','3300064086',7,'第二章 珍视你的时间：不要推迟生命','许多人在剧院、房子和市场之间跑来跑去，我们必须尽量不要瞎忙','3475-3504',0,1771646345,1782480548);
INSERT INTO highlights VALUES('3300064086_7_2207-2261','3300064086',7,'第二章 珍视你的时间：不要推迟生命','人们经常喜欢几乎没有真正价值的身外之物，而往往不重视真正属于他们自己的最宝贵的东西：构成我们生命的有限时间。','2207-2261',0,1771646162,1782480548);
INSERT INTO highlights VALUES('3300064086_7_1509-1571','3300064086',7,'第二章 珍视你的时间：不要推迟生命','我们错误地认为死亡存在于未来：其实大部分的死亡已经从我们身边经过，但没有被我们注意到。我们度过的任何一年都已掌握在死神手中。','1509-1571',0,1771646015,1782480548);
INSERT INTO highlights VALUES('3300064086_6_11870-11902','3300064086',6,'第一章 失落的友谊艺术','下一种最好的友谊存在于致力帮助彼此取得内在进步以变得更好的人之间','11870-11902',0,1771645869,1782480548);
INSERT INTO highlights VALUES('3300064086_6_11451-11488','3300064086',6,'第一章 失落的友谊艺术','假如连偶尔体验一下圣人般的感觉都不可能，那渴望成为一名圣人到底有什么意义？','11451-11488',0,1771645797,1782480548);
INSERT INTO highlights VALUES('3300064086_6_11040-11063','3300064086',6,'第一章 失落的友谊艺术','附录还为“斯多葛哲学练习”列出了一个简短的清单','11040-11063',0,1771645741,1782480548);
INSERT INTO highlights VALUES('3300064086_6_10186-10218','3300064086',6,'第一章 失落的友谊艺术','不只是你要完成的一个练习，而且是你为了更好地做事而进行练习的工具','10186-10218',0,1771520172,1782480548);
INSERT INTO highlights VALUES('3300064086_6_9988-10043','3300064086',6,'第一章 失落的友谊艺术','别要求我应该是最好的，只要求我比最坏的好。如果我每天能减少自己恶行的数量，并纠正我的错误，这对我来说就足够了。','9988-10043',0,1771516307,1782480548);
INSERT INTO highlights VALUES('3300064086_6_6308-6374','3300064086',6,'第一章 失落的友谊艺术','对塞涅卡等罗马斯多葛主义者来说，做所有事情的核心都是在朝着获得智慧和培养更好的品质方向前进，最终目标是成为斯多葛派的圣人或睿智的人。','6308-6374',0,1771515892,1782480548);
INSERT INTO highlights VALUES('3300064086_6_5987-6024','3300064086',6,'第一章 失落的友谊艺术','只有当你意识到自己的错误，或你可能缺乏的品质时，你才有可能取得真正的进步。','5987-6024',0,1771515853,1782480548);
INSERT INTO highlights VALUES('3300064086_5_11360-11381','3300064086',5,'引言 真正值得一过的人生','他是我们的同时代人，我们关切着同样的问题。','11360-11381',0,1771405338,1782480548);
INSERT INTO highlights VALUES('3300064086_5_10921-10962','3300064086',5,'引言 真正值得一过的人生','他是西方世界上第一个深入探索消费主义心理学的人。他还为理解情绪和愤怒做出了重大贡献','10921-10962',0,1771405301,1782480548);
INSERT INTO highlights VALUES('3300064086_5_10426-10491','3300064086',5,'引言 真正值得一过的人生','我们是复杂的生物，既渴望成为一个好人，让世界变得更美好，同时又受到贪婪、野心、担忧、恐惧、悲伤、愤怒、金钱焦虑、性欲和上瘾的困扰。','10426-10491',0,1771405170,1782480548);
INSERT INTO highlights VALUES('3300064086_5_10347-10379','3300064086',5,'引言 真正值得一过的人生','这些事情在今天听起来很稀松平常，原因很简单，就是人性并没有改变。','10347-10379',0,1771405159,1782480548);
INSERT INTO highlights VALUES('3300064086_5_9011-9314','3300064086',5,'引言 真正值得一过的人生','虽然塞涅卡最后谈论哲学的话没有流传下来，但我们可以想象他在重复苏格拉底关于死亡的话：“虽然你可以杀我，但你不能伤害我。”￼用我们的话说就是：“虽然你可能杀死我的身体，但你不能摧毁我内在的品质。”','9011-9314',0,1771405024,1782480548);
INSERT INTO highlights VALUES('3300064086_5_3521-3530','3300064086',5,'引言 真正值得一过的人生','人类是自然的一部分','3521-3530',0,1771404167,1782480548);
INSERT INTO highlights VALUES('3300064086_5_3011-3025','3300064086',5,'引言 真正值得一过的人生','罗马斯多葛主义的8个核心理念','3011-3025',0,1771404131,1782480548);
INSERT INTO highlights VALUES('3300064086_5_3390-3405','3300064086',5,'引言 真正值得一过的人生','“与自然和谐共处”以发现幸福。','3390-3405',0,1771404116,1782480548);
INSERT INTO highlights VALUES('3300064086_5_3758-3780','3300064086',5,'引言 真正值得一过的人生','美德，即内在品质的卓越，是唯一真正的好东西。','3758-3780',0,1771404076,1782480548);
INSERT INTO highlights VALUES('3300064086_5_1220-1256','3300064086',5,'引言 真正值得一过的人生','心灵宁愿自娱自乐，也不愿治愈自己，使得可以治愈心灵的哲学变成了一种消遣。','1220-1256',0,1771348320,1782480548);
INSERT INTO highlights VALUES('277781_37_6284-6307','277781',60,'第十一章 只求了解与认识而已','他说：“这是一个恋足的网站，我是一个恋足者。”','6284-6307',0,1730219036,1782480555);
INSERT INTO highlights VALUES('277781_37_4599-4631','277781',60,'第十一章 只求了解与认识而已','其实对动物不好的人不一定对人不好，对动物好的人也不一定对人好。”','4599-4631',0,1730218809,1782480555);
INSERT INTO highlights VALUES('277781_37_2130-2200','277781',60,'第十一章 只求了解与认识而已','他对杀死一只猫没有兴趣，也不享受虐待的过程。他说这么做只是为钱，拍下来提供给网站，一次两千，比他一个月的工资要高，还不包括卖碟和高跟鞋的钱。','2130-2200',0,1729915332,1782480555);
INSERT INTO highlights VALUES('277781_36_17664-17710','277781',59,'第十章 真相常流失于涕泪交加中','准确是这一工种最重要的手艺，而自我感动、感动先行是准确最大的敌人，真相常流失于涕泪交加中。”','17664-17710',0,1729914393,1782480555);
INSERT INTO highlights VALUES('277781_36_17243-17315','277781',59,'第十章 真相常流失于涕泪交加中','他送我那本《金刚经》里，有一句注解“念起即觉，觉已不随”，人是不能清空自己的情绪判断的，但要有个戒备，念头起来要能觉察，觉察之后你就不会跟随它。','17243-17315',0,1729705773,1782480555);
INSERT INTO highlights VALUES('277781_36_16988-17042','277781',59,'第十章 真相常流失于涕泪交加中','Doing the right thing is the best defence.”——准确是最好的防御。','16988-17042',0,1729705732,1782480555);
INSERT INTO highlights VALUES('277781_36_16493-16591','277781',59,'第十章 真相常流失于涕泪交加中','你要成为一个写作者，就要跟各种各样的人保持接触，这样才可以去研究和了解他们的一切特点，而且不要向他们寻求同情与共鸣，这样才可以和任何人打交道……你必须投入广大的世界里，不管你是喜欢还是不喜欢它。”','16493-16591',0,1729313898,1782480555);
INSERT INTO highlights VALUES('277781_36_15706-15792','277781',59,'第十章 真相常流失于涕泪交加中','说完这三个细节，我说：“您认为媒体有偏见，是的，可能媒体会有偏见，世界任何一个国家都这样，但纠正偏见的最好方式就是让意见市场流通起来，让意见与意见较量，用理性去唤起理性。”','15706-15792',0,1729313788,1782480555);
INSERT INTO highlights VALUES('277781_36_14478-14518','277781',59,'第十章 真相常流失于涕泪交加中','思想的本质是不安，一个人一旦左右摇摆，新的思想萌芽就出现了，自会剥离掉泥土露出来','14478-14518',0,1729311563,1782480555);
INSERT INTO highlights VALUES('277781_36_13045-13144','277781',58,'第九章 许多事情，是有人相信，才会存在','保持对不同论述的警惕，才能保持自己的独立性。探寻就是要不断相信、不断怀疑、不断幻灭、不断摧毁、不断重建，为的只是避免成为偏见的附庸。或者说，煽动各种偏见的互殴，从而取得平衡，这是我所理解的‘探寻’。','16970-17069',0,1729311401,1782480555);
INSERT INTO highlights VALUES('277781_36_11825-11895','277781',59,'第十章 真相常流失于涕泪交加中','很多人都会奇怪，为什么那么多这样的人居然会接受电视采访，“60分钟”的记者华莱士说过一句话：“因为所有你认为的坏蛋在心里都不认为自己错了。”','11825-11895',0,1729311254,1782480555);
INSERT INTO highlights VALUES('277781_36_10919-10964','277781',59,'第十章 真相常流失于涕泪交加中','一个世界如果只按强弱黑白两分，它很有可能只是一个立方体，你把它推倒，另一面朝上，原状存在。','10919-10964',0,1729184671,1782480555);
INSERT INTO highlights VALUES('277781_36_7774-7902','277781',59,'第十章 真相常流失于涕泪交加中',unistr('“因为她的报道中观点太多，”她说，“她总是站在她认为的弱者一方简单地批评。”\u000a我说安娜说她的原则就是“批评是记者唯一的语言”。\u000a她摇头：“这样的报道很难客观。”'),'7774-7902',0,1729098599,1782480555);
INSERT INTO highlights VALUES('277781_36_5805-5877','277781',59,'第十章 真相常流失于涕泪交加中','调查性报道很容易惹官司，只要数字或者细节存在争议，被起诉的可能性很大，一旦被起诉，出于保护，证人多数不会出庭，媒体的一审败诉率在百分之六十以上。','5805-5877',0,1729098314,1782480555);
INSERT INTO highlights VALUES('277781_36_3348-3404','277781',59,'第十章 真相常流失于涕泪交加中','电视节目习惯把一个人塑造为好人，另一个是坏人，实际上这个世界上没有好人和坏人，只有做了好事的人，和做了坏事的人。','3348-3404',0,1728109888,1782480555);
