INSERT INTO highlights VALUES('29971966_19_1237-1337','29971966',19,'让机器起作用','用户可以在Altair上的18个插槽插满256字节的内存板，并将盖茨和艾伦的BASIC输入系统，理论上这样就能运行这种高级编程语言了。但是这个过程极其乏味，需要拨动开关3万次以上，而且一次也不能出错。','1237-1337',0,1738638841,1782480553);
