INSERT INTO highlights VALUES('29971966_14_3925-4019','29971966',14,'两位年轻的黑客','程序员对自己苦心孤诣获得的知识都会有所保留，但盖茨却懂得如何利用自己的年少来赢得TRW公司中年长专家的欢心，让他们倾囊相授。正如盖茨自己所说，他们认为自己“不具威胁性”，毕竟他只是个孩子。','3925-4019',0,1738250743,1782480553);
