INSERT INTO highlights VALUES('29971966_13_4547-4582','29971966',13,'从小型计算机到微型计算机','经过了几番冷场，奥尔森开口表示，他想不出谁会想在自己家中弄一台计算机。','4547-4582',0,1738250232,1782480553);
INSERT INTO highlights VALUES('29971966_13_3252-3305','29971966',13,'从小型计算机到微型计算机','DEC公司视计算机为一种工业产品。阿尔后来回忆说：“在他们看来，计算机就如同一块生铁。他们只对卖铁感兴趣！','3252-3305',0,1738250073,1782480553);
INSERT INTO highlights VALUES('29971966_13_2176-2211','29971966',13,'从小型计算机到微型计算机','于是他出版了第一份个人计算机刊物，传播个人学习和使用计算机知识的方式。','2176-2211',0,1738249980,1782480553);
INSERT INTO highlights VALUES('29971966_13_1934-2033','29971966',13,'从小型计算机到微型计算机','高级工程师承认这名普通工程师的设计可行且造价便宜，但惠普不是生产这种机器的公司。这名没有学位的工程师叫史蒂夫·沃兹尼亚克，他后来离开了惠普，在一家起步于车库、名为苹果的创业公司制造出了自己的计算机。','1934-2033',0,1738249925,1782480553);
INSERT INTO highlights VALUES('29971966_13_1637-1697','29971966',13,'从小型计算机到微型计算机','在一些公司，心切的工程师提出过制造微型计算机的详尽方案，甚至拿出了能工作的样机，但这些方案都遭到了否决，样机也被束之高阁','1637-1697',0,1738249869,1782480553);
