INSERT INTO highlights VALUES('29971966_10_7866-7954','29971966',10,'巴贝奇的梦想','冯·诺伊曼觉得，除算术运算之外，EDVAC应该还能进行逻辑运算，并能以代码符号进行运算，而且那些以代码符号进行运算和解释的指令本身也应该是编入机器的代码符号，并用以继续操作运算','7866-7954',0,1738240884,1782480553);
INSERT INTO highlights VALUES('29971966_10_5563-5591','29971966',10,'巴贝奇的梦想','相较于继电器开关，真空管的高效使得计算机的面世成为现实。','5563-5591',0,1738240455,1782480553);
INSERT INTO highlights VALUES('29971966_10_4242-4291','29971966',10,'巴贝奇的梦想','但IBM的机器还不是计算机，也不是像布拉克逻辑机那样的机器。它们不过是被过分美化的大型计算器而已。','4242-4291',0,1738240309,1782480553);
