INSERT INTO highlights VALUES('29971966_8_1967-2074','29971966',8,'引言 想要拥有一部自己的计算机','个人计算机的起源也颇具革命性，因为它并不是由那些搞研发的专业团队在成本昂贵、设备精良的实验室研制出来的。它始于企业和学术机构之外，由黑客、计算机发烧友和误打误撞的创业者利用业余时间在车库、地下室和卧室等地方创造出来','1967-2074',0,1737807385,1782480553);
