INSERT INTO highlights VALUES('3300072235_18_1371-1403','3300072235',18,'第三节 化疗期间可以吃中药调理吗','因此，中医的理论体系更适用于我们这几千年来最常患的疾病，如伤风、','1371-1403',0,1758958618,1782480550);
INSERT INTO highlights VALUES('3300072235_17_15145-15188','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','但是很多营养物质在应季的食物当中含量更为丰富，例如，冬季的番茄维生素C的含量远低于夏季','15145-15188',0,1758958315,1782480550);
INSERT INTO highlights VALUES('3300072235_17_14841-14853','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','红色蔬菜主要包含番茄红素','14841-14853',0,1758958285,1782480550);
