INSERT INTO highlights VALUES('3300072235_17_14797-14809','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','深绿色蔬菜主要包含叶绿素','14797-14809',0,1758958278,1782480550);
INSERT INTO highlights VALUES('3300072235_17_14602-14626','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','但是朋友们也要记住，吃菜也不要超过食物总量的一半','14602-14626',0,1758958261,1782480550);
INSERT INTO highlights VALUES('3300072235_17_14531-14558','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','建议每人每日应摄入300—500克蔬菜，也就是1斤蔬菜','14531-14558',0,1758958246,1782480550);
INSERT INTO highlights VALUES('3300072235_17_14407-14450','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','加强蔬菜的摄入可以降低这些癌症的复发风险：肺癌、乳腺癌和卵巢癌等，但是具体原因尚不明确','14407-14450',0,1758958232,1782480550);
INSERT INTO highlights VALUES('3300072235_17_14012-14047','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','膳食纤维也是碳水化合物的一种，只不过这种碳水化合物是从植物当中获得的。','14012-14047',0,1758958192,1782480550);
INSERT INTO highlights VALUES('3300072235_17_13766-13810','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','但是综合来看，目前没有任何证据可以证实，补充硒元素可以降低癌症的发病率、死亡率和复发率。','13766-13810',0,1758958174,1782480550);
INSERT INTO highlights VALUES('3300072235_17_9754-9800','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','在营养吸收当中，我们希望蛋白质不承担或者少承担能量供给者的角色，而是把原料的作用发挥到最大。','9754-9800',0,1758957898,1782480550);
INSERT INTO highlights VALUES('3300072235_17_11737-11769','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','病人家属能做的，就是把出入量计算好，如何平衡的问题可以交给医生。','11737-11769',0,1758459711,1782480550);
INSERT INTO highlights VALUES('3300072235_17_11363-11420','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','因为人体排尿的同时会带走一些离子，所以病人喝的水中也可以适当加入一些橘子汁、橙汁、脉动等饮料，适当补充一些电解质。','11363-11420',0,1758459642,1782480550);
INSERT INTO highlights VALUES('3300072235_17_9832-9864','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','碳水化合物和脂肪来供能，这两者的比例一般在碳水化合物∶脂肪1∶1','9832-9864',0,1758459509,1782480550);
INSERT INTO highlights VALUES('3300072235_17_9218-9242','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','这也提示我们大家在炒菜的时候尽量多使用橄榄油等。','9218-9242',0,1758459400,1782480550);
INSERT INTO highlights VALUES('3300072235_17_9024-9076','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','人体正常代谢反式脂肪酸的速度一般是51天，代谢速度非常缓慢，因此反式脂肪酸导致肥胖的能力是普通脂肪的7倍','9024-9076',0,1758459379,1782480550);
INSERT INTO highlights VALUES('3300072235_17_8338-8396','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','对于癌症病人来说，最关键的营养物质莫过于这类ω-3（欧米伽3）系列脂肪酸了，包括α-亚麻酸(ω-3)、DHA和EPA','8338-8396',0,1758459280,1782480550);
INSERT INTO highlights VALUES('3300072235_17_7988-8087','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','那些会让你变胖，会阻塞在你血管当中的脂肪，主要是饱和脂肪酸和反式脂肪酸，是要减少摄入的，而另外那些负责搬运走沉积在身体各个地方的脂肪的清洁工，是需要加强摄入的，例如，单不饱和脂肪酸和多不饱和脂肪酸。','7988-8087',0,1758459230,1782480550);
INSERT INTO highlights VALUES('3300072235_17_7737-7828','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','脂肪除了提供能量以外，还有很多作用。人体能够把摄入的脂类物质打破成脂肪酸，并且储存在体内的脂肪细胞当中，在肚子里面形成像快递里面防撞泡沫一样的被子，盖在腹腔内脏器的表面，起到缓冲作用','7737-7828',0,1758459173,1782480550);
INSERT INTO highlights VALUES('3300072235_17_7480-7541','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','如果说人体是一辆车，那么蛋白质就是酒精（4大卡/克），碳水化合物也是酒精（4大卡/克），脂类就是超浓缩汽油（9大卡/克）。','7480-7541',0,1758459130,1782480550);
INSERT INTO highlights VALUES('3300072235_17_5332-5382','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','但是现实是残酷的，没有一项研究可以证实，停止摄入糖就可以治疗癌症，甚至连癌症病人的生存期也没有改变。','5332-5382',0,1758459041,1782480550);
INSERT INTO highlights VALUES('3300072235_17_1627-1705','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','美国癌症研究所推荐的优质蛋白质来源包括：鱼、家禽（鸡、鸭、鹅、鹌鹑）、红瘦肉（猪肉、牛肉、羊肉等）、鸡蛋、低脂奶制品、坚果或者干豆类、豌豆、扁豆以及豆制品。','1627-1705',0,1758458788,1782480550);
INSERT INTO highlights VALUES('3300072235_16_3431-3432','3300072235',16,'第三章 化疗病人的饮食指导','了','3431-3432',0,1758458431,1782480550);
INSERT INTO highlights VALUES('3300072235_16_3241-3277','3300072235',16,'第三章 化疗病人的饮食指导','最早开始的时间，就是病人能够正常饮食、正常生活的时候，如手术后4周左右。','3241-3277',0,1758458381,1782480550);
INSERT INTO highlights VALUES('3300072235_16_2041-2111','3300072235',16,'第三章 化疗病人的饮食指导','辅助化疗的意思是，手术已经达到根治癌症的目标，但是可能还有残余的癌细胞，或者血液里癌细胞的余孽尚存，用化疗可以让这些细胞彻底失去再生的机会。','2041-2111',0,1758458296,1782480550);
INSERT INTO highlights VALUES('3300072235_15_5471-5511','3300072235',15,'第八节 开完刀掉了10斤肉，营养跟不上怎么办','整蛋白型：口感好，需要完全消化才能吸收。如能全力、安素、瑞代、瑞能、瑞高、瑞素。','5471-5511',0,1758457481,1782480550);
INSERT INTO highlights VALUES('3300072235_14_3059-3151','3300072235',14,'第七节 手术损失的“元气”吃什么补得快','无论何种手术，我们都鼓励病人在手术之后保持一定的锻炼。这样做会提高病人对氧和能量的需求，才能积极地调动起人体的消化系统和造血系统，帮助病人更好地创造红细胞，并且提高人体消化吸收的能力。','3059-3151',0,1758456484,1782480550);
INSERT INTO highlights VALUES('3300072235_14_1639-1718','3300072235',14,'第七节 手术损失的“元气”吃什么补得快','简单来说，对于在12克/分升以下的病人，我们建议手术后适当地补血。例如，增加动物肝脏、动物血液等食物的摄入，这补的其实不是血，而是人在造血过程中需要的原材料。','1639-1718',0,1758456335,1782480550);
INSERT INTO highlights VALUES('3300072235_13_7015-7059','3300072235',13,'第六节 街坊说手术后好些忌口，该不该信','那些不喝骨头汤的病人，我很少看到低钙的，但是长期喝骨头汤的病人，骨质疏松的我可没少见过。','7015-7059',0,1758456166,1782480550);
INSERT INTO highlights VALUES('3300072235_13_5269-5300','3300072235',13,'第六节 街坊说手术后好些忌口，该不该信','所以输液经常会导致电解质失衡，只能依赖医生的经验和定期的监测。','5269-5300',0,1758456040,1782480550);
INSERT INTO highlights VALUES('3300072235_13_3777-3861','3300072235',13,'第六节 街坊说手术后好些忌口，该不该信','适当地吃辣椒对于胃黏膜还能起到保护作用。辣椒的营养价值非常丰富，含有大量的维生素和微量元素，同时它也是一种对抗氧自由基损伤非常好的食品，长期服用甚至能够减少癌症的发生。','3777-3861',0,1758455910,1782480550);
INSERT INTO highlights VALUES('3300072235_13_1934-1971','3300072235',13,'第六节 街坊说手术后好些忌口，该不该信','我们老祖宗的这些所谓的“发物”，都是营养丰富的食品，并没有发现任何致癌成分','1934-1971',0,1758455731,1782480550);
INSERT INTO highlights VALUES('3300072235_12_7888-7940','3300072235',12,'第五节 别光知道喝粥了——史上最简洁的手术后饮食过渡一览图','我建议把不可溶性纤维食物当作每天进食必需的一个部分，但一定是次要部分，主食一定要占每顿饭至少一半才合理。','7888-7940',0,1758455511,1782480550);
INSERT INTO highlights VALUES('3300072235_12_3018-3057','3300072235',12,'第五节 别光知道喝粥了——史上最简洁的手术后饮食过渡一览图','清流食最好的产品是肠内营养制剂，如瑞能、安素、百普力等产品（后文会展开讨论）。','3018-3057',0,1758455113,1782480550);
INSERT INTO highlights VALUES('3300072235_11_11354-11371','3300072235',11,'第四节 划重点：刚刚手术完，病人应该怎么吃','骨头汤到底能不能补钙？答案是不能！','11354-11371',0,1758454721,1782480550);
INSERT INTO highlights VALUES('3300072235_17_6371-6449','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','淀粉像涓涓细流滋润人的身体，糖则像在体内打出了一发能量核弹，为了降低核弹的影响，胰腺疯狂地加工胰岛素到筋疲力尽，肝脏拼命地把葡萄糖合成肝糖原储存在肝脏当中。','6371-6449',0,1758222438,1782480550);
INSERT INTO highlights VALUES('3300072235_17_5982-5999','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','吃淀粉是对的，吃糖是绝对不鼓励的。','5982-5999',0,1758222395,1782480550);
INSERT INTO highlights VALUES('3300072235_17_3734-3782','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','每一餐你尽可能把所有的菜都吃全，在难受的时候再坚持一下，你会发现你的康复就会出现意想不到的效果。','3734-3782',0,1758222190,1782480550);
INSERT INTO highlights VALUES('3300072235_17_3716-3734','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','其实你再多吃一点点，该有的就都有了。','3716-3734',0,1758222182,1782480550);
INSERT INTO highlights VALUES('3300072235_17_2719-2766','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','公斤体重的病人，每天需要蛋白质的含量大约在60—120克，才有可能让病人抵挡住化疗的暴风骤雨。','2719-2766',0,1758222103,1782480550);
INSERT INTO highlights VALUES('3300072235_17_2639-2678','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','推荐18—50岁的成年人，男性每天摄入蛋白质65克，女性每天摄入蛋白质55克。','2639-2678',0,1758222092,1782480550);
INSERT INTO highlights VALUES('3300072235_17_2310-2367','3300072235',17,'第二节 从零开始学：化疗病人怎么补营养','大量的蛋白质摄入，首先会加重肝脏和肾脏的负担，如果蛋白质摄入量过高，远远超出了人体的需要量，就会先从肾脏当中滤出去','2310-2367',0,1758222056,1782480550);
INSERT INTO highlights VALUES('3300072235_8_3526-3578','3300072235',8,'第二章 手术前后，医生没告诉你的那些事','这个时候，ω-3多不饱和脂肪酸可以让我们的炎症反应更温和一些。它既能发挥作用，又不会产生过多的不良影响。','3526-3578',1,1753011674,1782480550);
INSERT INTO highlights VALUES('3300072235_8_3205-3262','3300072235',8,'第二章 手术前后，医生没告诉你的那些事','ω-3多不饱和脂肪酸、精氨酸和谷氨酰胺，改造成“免疫增强型”肠内营养液的话，对于减少术后的感染和并发症有很大的帮助','3205-3262',1,1753011622,1782480550);
INSERT INTO highlights VALUES('3300072235_8_1268-1325','3300072235',8,'第二章 手术前后，医生没告诉你的那些事','抵抗炎症反应的免疫球蛋白，让人体体态健美的肌肉里面的蛋白质，甚至是传宗接代需要的“弹药”都会出现“库存”紧张的状况','1268-1325',1,1753011418,1782480550);
INSERT INTO highlights VALUES('3300072235_8_1028-1085','3300072235',8,'第二章 手术前后，医生没告诉你的那些事','抓紧在病人还没有了解到这个领域谁是最牛的专家之前，赶紧把手术给做了。手术多，自己的成长就会多，各方面的回报也会多。','1028-1085',1,1753011330,1782480550);
INSERT INTO highlights VALUES('3300072235_8_631-653','3300072235',8,'第二章 手术前后，医生没告诉你的那些事','导致恶液质，也就是体重急剧下降、低蛋白情况等','631-653',1,1753011288,1782480550);
INSERT INTO highlights VALUES('3300072235_7_5830-5873','3300072235',7,'第二节 大数据告诉你，癌症离我们到底有多远','但是男性和女性癌症死亡率从2008年以来出现显著下降（分别年降低1.4%和1.1%）。','5830-5873',1,1752995853,1782480550);
INSERT INTO highlights VALUES('3300072235_7_5423-5463','3300072235',7,'第二节 大数据告诉你，癌症离我们到底有多远','中国目前的人口结构正在加速进入老龄化倒金字塔状态，癌症的发生将可能成为一种常态。','5423-5463',1,1752995772,1782480550);
INSERT INTO highlights VALUES('3300072235_7_2595-2678','3300072235',7,'第二节 大数据告诉你，癌症离我们到底有多远','恶性肿瘤当中，从胚胎的上皮（葡萄皮）起源发生变异的，医学上称为“癌”，从间质（葡萄瓤）起源的，医学上称为“肉瘤”，其他部位起源的，单独进行命名，例如，淋巴瘤、白血病等','2595-2678',1,1752995567,1782480550);
INSERT INTO highlights VALUES('3300072235_7_1518-1585','3300072235',7,'第二节 大数据告诉你，癌症离我们到底有多远','首先开始掠夺周围的正常空间，作为自己孩子的食物，这就叫作肿瘤的“侵袭”，之后开始向人体的各个部位输送自己的孩子，这就叫作肿瘤的“转移”','1518-1585',1,1752995410,1782480550);
INSERT INTO highlights VALUES('3300072235_7_1000-1051','3300072235',7,'第二节 大数据告诉你，癌症离我们到底有多远','为什么细胞不能一直存活？因为细胞的基因组本身就存在缺陷，它会随着分裂次数的增加而逐渐失去优秀的编码能力','1000-1051',1,1752995344,1782480550);
INSERT INTO highlights VALUES('43685146_13_3676-3716','43685146',13,'第4章　休息，有规律地“无所事事”','今天的消耗不要超过今天所能恢复的限度，本星期的消耗不要超过本星期所能恢复的限度。','3676-3716',0,1728264078,1782480555);
INSERT INTO highlights VALUES('43685146_13_3203-3244','43685146',13,'第4章　休息，有规律地“无所事事”','他们都在上午训练，训练分成3段，每段不超过90分钟，每段训练之间都会有休息的时间。','3203-3244',0,1728145580,1782480555);
INSERT INTO highlights VALUES('43685146_13_3111-3162','43685146',13,'第4章　休息，有规律地“无所事事”','研究表明，让精力的消耗和恢复保持一种规律的节奏，才能带来身体和精神的巅峰表现，这种结论不只适用于运动员','3111-3162',0,1728145569,1782480555);
INSERT INTO highlights VALUES('43685146_13_1151-1185','43685146',13,'第4章　休息，有规律地“无所事事”','他告诉办公室里的每个人他需要减少工作时间，结果，他获得了大家的支持。','1151-1185',0,1728145335,1782480555);
INSERT INTO highlights VALUES('43685146_12_11602-11866','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”',unistr('1．当我们对伤害自己的人放下惩罚的念头时，被释放的并不是对方，而是我们自己。\u000a2．当你专注于你所缺乏的，你会失去你所拥有的；当你专注于你所拥有的，你会得到你所缺乏的。\u000a3．掌握“习惯处方”——在抱怨之后，说一些值得感恩的事情，让感恩变成一种习惯。\u000a4．积极情绪会为我们展现新的视角和可能性，提高应对下一次挑战时的胜算。'),'11602-11866',0,1728145232,1782480555);
INSERT INTO highlights VALUES('43685146_12_11037-11063','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','当有人向你展示他们是什么样的人时，第一次就相信他们。','11037-11063',0,1728145155,1782480555);
INSERT INTO highlights VALUES('43685146_12_10332-10362','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','对于怨恨，我们应该不忙于雇用，或者根本不雇用，而忙于解雇它。','10332-10362',0,1728145089,1782480555);
INSERT INTO highlights VALUES('43685146_12_9327-9446','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','怨恨假装屈从于我们，但实际上接管了我们。它让我们陷入无休止的责怪、自以为是和自我厌恶的循环。7','9327-9446',0,1728144818,1782480555);
INSERT INTO highlights VALUES('43685146_12_8991-9038','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','怨恨耗费了我们的资源，但并没有给我们的投资带来令人满意的回报。所以，我们必须把怨恨“解雇”掉。','8991-9038',0,1728144796,1782480555);
INSERT INTO highlights VALUES('43685146_12_8797-8829','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','人们并不是真正地购买产品或服务。相反，人们是“雇用”它们来做事的','8797-8829',0,1728144770,1782480555);
INSERT INTO highlights VALUES('43685146_12_8673-8706','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','试着提出一个不寻常的问题：我“雇用”怨恨这种情绪都做了些什么事情？','8673-8706',0,1728144757,1782480555);
INSERT INTO highlights VALUES('43685146_12_6275-6290','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','抱怨之后，说一些值得感恩的事情','6275-6290',0,1728144586,1782480555);
INSERT INTO highlights VALUES('43685146_12_6041-6082','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','创建一个新的习惯，我们只需要找到一件我们已经做过的事情，然后将一个新的行为加入其中','6041-6082',0,1728144557,1782480555);
INSERT INTO highlights VALUES('43685146_12_5100-5196','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','简言之，如果维持一个系统运转所需投入的能源越来越少，那么这个系统就变成了一个自我维持系统。一旦这种自我维持启动了，维持这个系统的难度就降低了，然后系统的运行就会变得容易起来，一切既高效又轻松。','5100-5196',0,1727886944,1782480555);
INSERT INTO highlights VALUES('43685146_12_4337-4379','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','当你专注于你所缺乏的，你会失去你所拥有的。当你专注于你所拥有的，你会得到你所缺乏的。','4337-4379',0,1727886892,1782480555);
INSERT INTO highlights VALUES('43685146_12_3545-3569','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','当我们专注于我们所拥有的东西时，我们会拥有得更多','3545-3569',0,1726985352,1782480555);
INSERT INTO highlights VALUES('43685146_12_3486-3512','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','感恩有一种强大的力量，它使消极情绪失去赖以生存的氧气','3486-3512',0,1726985344,1782480555);
INSERT INTO highlights VALUES('43685146_12_2885-2903','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','抱怨是典型的“容易但不重要”的事情。','2885-2903',0,1726985295,1782480555);
INSERT INTO highlights VALUES('43685146_12_2441-2512','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','当成为“不幸”的牺牲品时，我们总会为失去的东西而烦恼、哀愁和抱怨。实际上，抱怨是最容易的事情之一，它太容易了，以至于许多人抱怨起来就停不下来。','2441-2512',0,1726985260,1782480555);
INSERT INTO highlights VALUES('43685146_12_1735-1800','43685146',12,'第3章　释怀，雇用“感恩”，解雇“报怨”','这些微小的错误在你脑中留下的痕迹会被放大，使它看起来就像巨大的失败。为了夺回脑中的空间，我们需要把头脑中的“冲锋队盔甲”们打发走。','1735-1800',0,1726985214,1782480555);
INSERT INTO highlights VALUES('43685146_11_10683-10714','43685146',11,'第2章　享受，“满足”不需要被延时','用自己的独特性定义自己的仪式，将乏味的任务变成创造快乐的体验。','10683-10714',0,1726977222,1782480555);
INSERT INTO highlights VALUES('43685146_11_9883-9953','43685146',11,'第2章　享受，“满足”不需要被延时','不管这些行为表面上看起来多傻，只要始终如一地坚持，就可以让我们获得平静，缓解我们的焦虑，并且用一种只属于我们自己的方式让我们恢复到轻松状态。','9883-9953',0,1726977166,1782480555);
INSERT INTO highlights VALUES('43685146_11_8880-8911','43685146',11,'第2章　享受，“满足”不需要被延时','仪式给习惯注入意义，以此使重要的习惯更容易保持。','8880-8911',5,1726899795,1782480555);
INSERT INTO highlights VALUES('43685146_11_8766-8800','43685146',11,'第2章　享受，“满足”不需要被延时','但仪式有一个与习惯不同的关键点：你会在仪式过程中就体验到心理满足感。','8766-8800',5,1726899783,1782480555);
INSERT INTO highlights VALUES('43685146_11_6127-6178','43685146',11,'第2章　享受，“满足”不需要被延时','他们不喜欢被别人发号施令，这令他们感到沮丧。家务必须要做，但没有人喜欢做家务，所以我们决定换一种方式。','6127-6178',5,1726767594,1782480555);
INSERT INTO highlights VALUES('43685146_11_5730-5746','43685146',11,'第2章　享受，“满足”不需要被延时','跑步的同时收听他最喜欢的每日播客','5730-5746',5,1726767550,1782480555);
INSERT INTO highlights VALUES('43685146_11_5573-5620','43685146',11,'第2章　享受，“满足”不需要被延时','但很长时间以来，你是不是都只凭借意志力迫使自己去做那些重要但困难的事情，而不是让它们变得有趣？','5573-5620',5,1726767535,1782480555);
INSERT INTO highlights VALUES('43685146_11_5465-5485','43685146',11,'第2章　享受，“满足”不需要被延时','那些令人愉悦的事情你是无论如何都会去做的','5465-5485',5,1726767510,1782480555);
INSERT INTO highlights VALUES('43685146_11_4624-4628','43685146',11,'第2章　享受，“满足”不需要被延时','手工技艺','4624-4628',5,1726767353,1782480555);
INSERT INTO highlights VALUES('43685146_11_3605-3620','43685146',11,'第2章　享受，“满足”不需要被延时','不再延迟满足，现在就是快乐时刻','3605-3620',1,1726678191,1782480555);
INSERT INTO highlights VALUES('43685146_11_2373-2408','43685146',11,'第2章　享受，“满足”不需要被延时','并不是每一件重要的事都能令人感到愉快，但我们可以想办法让自己乐在其中。','2373-2408',1,1726678123,1782480555);
INSERT INTO highlights VALUES('43685146_11_1501-1505','43685146',11,'第2章　享受，“满足”不需要被延时','红鼻子日','1501-1505',1,1726678058,1782480555);
INSERT INTO highlights VALUES('43685146_11_1292-1365','43685146',11,'第2章　享受，“满足”不需要被延时','图森突然有了一个主意——一个将影响数百万人生活的主意：如果能进行一场“活泼、感人、有参与感和有趣的”慈善捐款，也许就能将捐款这个过程变得容易一些。','1292-1365',1,1726677733,1782480555);
INSERT INTO highlights VALUES('43685146_11_1365-1405','43685146',11,'第2章　享受，“满足”不需要被延时','她的主意是，把人们都喜欢做的事情，比如在电视上看喜剧，与穷苦之人的困境结合起来。','1365-1405',1,1726677731,1782480555);
INSERT INTO highlights VALUES('43685146_10_10722-10999','43685146',10,'第1章　倒置，自觉追求“更容易”',unistr('1．面对一项难以完成的任务时，自问：“有没有更容易的办法？”\u000a2．如果将事情简单化，就不太可能出错。\u000a3．摆脱那些让问题看起来很难的假设，简单易行的方案会层出不穷。\u000a4．放弃对复杂的执念，即使微小的努力也能推进重要的事情。\u000a5．一旦找到简洁的方法，就可能破解无法达成的目标。'),'10722-10999',1,1726677516,1782480555);
INSERT INTO highlights VALUES('43685146_10_9673-9710','43685146',10,'第1章　倒置，自觉追求“更容易”','“我并不指望跳过7英尺的栏杆，我四处寻找1英尺的栏杆，让我可以一步迈过。”','9673-9710',5,1725647135,1782480555);
INSERT INTO highlights VALUES('43685146_10_9293-9322','43685146',10,'第1章　倒置，自觉追求“更容易”','制造了一种错觉，令人认为把巨石推上山坡是通往成功的唯一方式','9293-9322',5,1725647105,1782480555);
INSERT INTO highlights VALUES('43685146_10_8413-8450','43685146',10,'第1章　倒置，自觉追求“更容易”','摆脱那些让问题看起来很难的假设，你会惊讶地发现，简单易行的方案会层出不穷。','8413-8450',5,1725646741,1782480555);
INSERT INTO highlights VALUES('43685146_6_8864-8952','43685146',6,'引言　让关键的事情变得容易做','这本书由三个简单的部分组成：第一部分帮助你恢复“轻松状态”，第二部分教会你采取“轻松行动”；第三部分揭秘5种杠杆力量，让你轻松实现理想成果。每一部分都建立在前一部分的基础之上。','8864-8952',5,1725636538,1782480555);
INSERT INTO highlights VALUES('43685146_6_8304-8352','43685146',6,'引言　让关键的事情变得容易做','一定要摆脱这种心态，即认为做困难的事情本身具有内在价值，不仅迷信困难，还怀疑所有做起来容易的事。','8304-8352',5,1725636484,1782480555);
INSERT INTO highlights VALUES('43685146_6_2039-2061','43685146',6,'引言　让关键的事情变得容易做','他可以找一个更简单的方法去获得他想要的成功。','2039-2061',5,1725596903,1782480555);
INSERT INTO highlights VALUES('43685146_6_1778-1871','43685146',6,'引言　让关键的事情变得容易做',unistr('麦金尼斯以前常常这样说。但他突然意识到，更加努力工作的边际收益实际上是个负值，这绝不是获得人生最优回报的好办法。\u000a'),'1778-1871',5,1725596887,1782480555);
INSERT INTO highlights VALUES('43685146_6_1483-1504','43685146',6,'引言　让关键的事情变得容易做','博克瑟马（Boxer the Horse）','1483-1504',5,1725596847,1782480555);
INSERT INTO highlights VALUES('43685146_5_1004-1024','43685146',5,'推荐序2　高手为什么更轻松','“轻松”并不是指完全轻松，而是指举重若轻','1004-1024',5,1725596592,1782480555);
INSERT INTO highlights VALUES('43685146_5_1586-1619','43685146',5,'推荐序2　高手为什么更轻松','人生是一场长跑，只有放轻松，做到轻而不浮，松而不懈，才能跑完全程。','1586-1619',5,1725596577,1782480555);
INSERT INTO highlights VALUES('43685146_4_3070-3113','43685146',4,'推荐序1　放轻松带来的双重复利','一切要从学会放轻松做起，因为这样才可能一直健康活着，才可能享受既赚钱又赚命的双重复利。','3070-3113',5,1725500113,1782480555);
INSERT INTO highlights VALUES('43685146_4_2878-2908','43685146',4,'推荐序1　放轻松带来的双重复利','，接下来就应该顺其自然，因为说到底绝大多数的我们都是普通人。','2878-2908',5,1725500091,1782480555);
INSERT INTO highlights VALUES('43685146_4_2846-2878','43685146',4,'推荐序1　放轻松带来的双重复利','人的一生应该先尽力而为，努力探索能力边界，让自己配得上想要的生活','2846-2878',5,1725500088,1782480555);
INSERT INTO highlights VALUES('43685146_4_2619-2683','43685146',4,'推荐序1　放轻松带来的双重复利','作者主张发挥5种杠杆的力量，把产生线性成果的行为转变为产生复利成果的行为，由此，只要付出一次努力，就能一次又一次地轻松获得收益。','2619-2683',5,1725500064,1782480555);
INSERT INTO highlights VALUES('43685146_4_1666-1710','43685146',4,'推荐序1　放轻松带来的双重复利','林迪效应”（Lindy Effect），也就是一本书存世越久，它在未来留存的可能性就越高','1666-1710',5,1725499972,1782480555);
INSERT INTO highlights VALUES('43685146_4_1456-1483','43685146',4,'推荐序1　放轻松带来的双重复利','人的一生面临着大大小小的选择，是这些选择造就了人的命运','1456-1483',5,1725499931,1782480555);
INSERT INTO highlights VALUES('43685146_3_2600-2645','43685146',3,'作者简介','旨在帮助个人和公司将80%的时间集中于重要的少数事务上，并且以聪明的做事方法轻松获得成功。','2600-2645',5,1725497334,1782480555);
INSERT INTO highlights VALUES('43685146_3_2228-2262','43685146',3,'作者简介','当他的生活已经被剥离到只剩重要事项时，要做的事仍然太多。他该怎么办？','2228-2262',5,1725497300,1782480555);
INSERT INTO highlights VALUES('43685146_3_1893-1960','43685146',3,'作者简介','星期，学生们都自觉关掉笔记本电脑和智能手机，让自己的头脑开足马力地思考，练习经过深思熟虑后将最精要的少数从众多好东西中识别和区分出来。','1893-1960',5,1725497265,1782480555);
INSERT INTO highlights VALUES('43685146_3_1283-1321','43685146',3,'作者简介','麦吉沃恩本来是为了赢得客户的尊重而出席会议，但客户感觉到的却是他不悦的心情。','1283-1321',5,1725497225,1782480555);
INSERT INTO highlights VALUES('834467_20_19813-19885','834467',42,'回到南门','我看到了远处突然升起一片火光，越来越大的雨点与那片火纠缠起来，燃烧的火不仅没有熄灭，反而逐渐增大。就如不可阻挡的呼喊，在雨中脱颖而出，熊熊燃烧。','19725-19797',1,1700666539,1782398597);
INSERT INTO highlights VALUES('834467_20_12091-12117','834467',42,'回到南门','然后她走到窗前打开窗户，像刚下了蛋的母鸡一样叫唤了。','12063-12089',1,1700665748,1782398597);
INSERT INTO highlights VALUES('834467_20_8774-8830','834467',42,'回到南门','那个贫困家中唯一的装饰品，破碎时的声响让我经历了长时间的战栗。王立强会像拧断一根黄瓜一样，咔嚓一声拧断我的脖子。','8746-8802',1,1700665373,1782398597);
INSERT INTO highlights VALUES('834467_20_1620-1728','834467',42,'回到南门','可我回到家中以后，王立强令我失望地没有流露一丝的吃惊，仿佛他早就知道我能提回家中似的接过了水瓶。看着他蹲下去的背影，我用最后的希望提醒他：“我只休息了一次。”','1594-1702',1,1700664108,1782398597);
INSERT INTO highlights VALUES('834467_20_1432-1506','834467',42,'回到南门','希望在想象里为我描绘了这样的情形，当我将两瓶开水提回家时，王立强是那样的欣喜若狂，他高声喊叫李秀英，那个床上的女人也走过来了，他们两人由衷地赞叹我。','1406-1480',1,1700664065,1782398597);
INSERT INTO highlights VALUES('834467_19_5245-5324','834467',41,'诬陷','我努力使自己勇敢，心里还是一阵阵发虚。下课后我极力鼓动受罚的同学和我一样反抗老师。他们在表达自己不满时和我一样激动，可一旦说到拒绝写检查，他们全部吞吞吐吐了。','5222-5301',1,1700492179,1782398597);
INSERT INTO highlights VALUES('834467_18_9924-9979','834467',40,'抛弃','这个女人以她垂暮的气息腐化着国庆蓬勃的生命力，从而让我现在眺望尚是年幼的国庆时，看到了他脸上闪烁着灰暗的衰落。','9871-9926',1,1700399032,1782398597);
INSERT INTO highlights VALUES('834467_18_7935-8089','834467',40,'抛弃','这种时候国庆在谈到他母亲时，不再因为往事过于遥远而显得淡漠。他经常说从前这个词了，从前他母亲活着的时候，他有多么多么好。他从来没有告诉我们从前幸福的具体事例，只是用不停的感叹，让我们对他模糊不清的从前羡慕不已。他开始想象他的母亲，在无依无靠的时候，这个只有九岁的孩子，想象没有面对未来，而是过早地通往了过去。','7911-8065',1,1700398642,1782398597);
INSERT INTO highlights VALUES('834467_18_3271-3418','834467',40,'抛弃','前面走着一个单薄的大孩子，他的笛声固然美妙，可他能打败国庆的父亲吗？我们三个人傻乎乎地跟着他，他发怒的样子让我们充满信心。他走到了一棵挂满雨水的树下，突然沉思起来，可是等到我们也走入树下后，他立刻抬腿猛踢一下树木，同时自己逃离了出去。树上的雨水纷纷落下，淋得我们满身都是。他却哈哈大笑地回家了。','3247-3394',1,1700385520,1782398597);
INSERT INTO highlights VALUES('834467_18_511-553','834467',40,'抛弃','过早的自由使他像扛着沉重的行李一样，扛着自己的命运，在纷繁的街道上趔趔趄趄不知去向。','487-529',1,1700384427,1782398597);
INSERT INTO highlights VALUES('834467_17_13282-13337','834467',39,'威胁','我是这时候转身离去的，像一只清晨的公鸡那样昂首阔步。我当时心里充满了罪恶的欢乐，国庆绝望的神色是我欢乐的基础。','13293-13348',1,1700354254,1782398597);
INSERT INTO highlights VALUES('834467_17_12357-12471','834467',39,'威胁','此后的时间里，我必须为自己不负责任的威胁承担后果。国庆和刘小青正如他们宣告的那样，不再理睬我。而我在实现自己的威胁时，却显得力不从心。他们是两个人，我只是一个人，问题的关键就在这里，他们可以坚定地不理我，我则是心慌意乱地不理他们','12368-12482',1,1700354211,1782398597);
INSERT INTO highlights VALUES('834467_17_11377-11463','834467',39,'威胁','我清晰地记起了当初刘小青说这话时的神态，他是将快要掉进嘴巴的鼻涕使劲一吸，吸回到鼻孔后突发奇想说这番话的。他吸鼻涕的声音十分响亮，我都能感觉到鼻涕飞入他鼻孔时滑溜溜的过程。','11388-11474',1,1700353953,1782398597);
INSERT INTO highlights VALUES('834467_17_9861-9905','834467',39,'威胁','她只是沉浸在我当时年龄还无法理解的自我与孤独之中，她站在生与死的界线上，同时被两者抛弃。','9872-9916',1,1700353763,1782398597);
INSERT INTO highlights VALUES('834467_17_9336-9414','834467',39,'威胁','里面黑白的相片让我看到了一群严肃的男女老人，竟然没有一个在微笑。老太太轻声告诉我：“他们全死了。”','9347-9425',1,1700353703,1782398597);
INSERT INTO highlights VALUES('834467_17_5621-5651','834467',39,'威胁','我突然发现了逃跑的意义，它使惩罚变得遥远，同时又延伸了快乐。','5597-5627',1,1699974267,1782398597);
INSERT INTO highlights VALUES('834467_17_2541-2623','834467',39,'威胁','接着是很细的声音，像一根线穿过针眼一样穿过了我的耳朵，她告诉我，她要是穿上潮湿的内衣就会——“立刻死掉。”','2517-2599',1,1699973913,1782398597);
INSERT INTO highlights VALUES('834467_17_2254-2313','834467',39,'威胁','我一直没有弄明白李秀英究竟得了什么病，她对阳光的热爱给了我无法磨灭的印象。这位我后来的母亲整个身体就像是一场绵绵阴雨。','2230-2289',1,1699973774,1782398597);
INSERT INTO highlights VALUES('834467_15_9647-9762','834467',36,'消失','我当时的心情十分古怪，说不准是悲哀，还是不安。我能明确意识到的，那就是一种情景将在我眼中永远消失。在傍晚的时刻，孙有元步履蹒跚地在那条小路上摇摇晃晃地出现，向我和池塘走来。我总是很远就看到了他抱在怀里的油布雨伞，和肩上的蓝布包袱。','9623-9738',1,1699972530,1782398597);
INSERT INTO highlights VALUES('834467_15_7688-7694','834467',36,'消失','“死啦，死啦','7664-7670',1,1699972309,1782398597);
INSERT INTO highlights VALUES('834467_15_7615-7659','834467',36,'消失','我父亲像是被凳子发射出去似的，蹿进了祖父的房间，过了一会十分紧张地走出来，手舞足蹈地说：','7591-7635',1,1699972304,1782398597);
INSERT INTO highlights VALUES('834467_15_7413-7482','834467',36,'消失','“你们爷爷快死啦。”他的理由是，“人和黄鼠狼一样，你要捉它时它就放个臭屁把你熏晕了，自己可以逃走。你们爷爷要逃走啦，所以那里面臭死人啦。”','7389-7458',1,1699972246,1782398597);
INSERT INTO highlights VALUES('834467_15_6185-6256','834467',36,'消失','即将收割的稻子在阳光里摇晃时，吹来的东南风里飘拂着植物的气息。我不知道祖父是否闻到了，但我祖父古怪的思维断定了自己迟迟未死和那些沉重的稻穗有关','6161-6232',1,1699972081,1782398597);
INSERT INTO highlights VALUES('834467_15_3550-3625','834467',36,'消失','在期待里躺了一夜的孙有元，翌日清晨看到孙广才走进来时，敏捷地撑起身体问他的儿子：“棺材呢？”','3526-3601',1,1699971750,1782398597);
INSERT INTO highlights VALUES('834467_14_6727-6767','834467',35,'风烛残年','孙有元当时坐在那个斑驳的墙角，用一贯的慈祥看着我，他亲切的目光在那时让我不寒而栗','6699-6739',1,1699709873,1782398597);
INSERT INTO highlights VALUES('834467_14_5112-5159','834467',35,'风烛残年','满脸通红的孙广才像个孩子那样不知疲惫地乱喊乱叫，他的喊叫如同狂风似的吹得我们弟兄三人身体抖动。','5086-5133',1,1699709718,1782398597);
INSERT INTO highlights VALUES('834467_14_4097-4126','834467',35,'风烛残年','接着我听到了哥哥幼稚的声音穿上了严肃的外套后，向我祖父走去','4071-4100',1,1699709479,1782398597);
INSERT INTO highlights VALUES('834467_14_3143-3169','834467',35,'风烛残年','他像冬天的狂风那样在我们狭窄的家中，时时会突然咆哮。','3117-3143',1,1699709345,1782398597);
INSERT INTO highlights VALUES('834467_13_5580-5635','834467',34,'遥远','然后是三个人走出家门，我祖母身穿黑衣的婆婆，将他们带到一条大路上。她指示我的祖母往西走，而她自己则走向了东面。','5556-5611',1,1699694434,1782398597);
INSERT INTO highlights VALUES('834467_10_17358-17387','834467',30,'战栗','总之当我们凶狠地对待这个世界时，这个世界突然变得温文尔雅了','17333-17362',1,1699688983,1782398597);
INSERT INTO highlights VALUES('834467_10_11879-11928','834467',30,'战栗','在我眺望昔日的时光时，在池塘旁所看到的苏宇快乐幸福的童年生活，其实如当时从水面上吹过的风一样不可靠','11852-11901',1,1699688098,1782398597);
INSERT INTO highlights VALUES('834467_8_4738-4928','834467',27,'出生','“剪刀离得远，拿起来不方便。孩子生下来还得给他洗洗。本来早就给你送饭来了，没出家门就疼了。我知道要生了，想去拿剪刀，疼得走不过去……”父亲很不耐烦地打断她的唠叨：“是男的？还是女的？”母亲回答：“是男的。”','4716-4906',1,1699674681,1782398597);
INSERT INTO highlights VALUES('834467_7_6660-6709','834467',26,'死去','翌日清晨，全家都换上了补丁遍体的衣服，仿佛鱼的鳞片一样，我们像是四条可笑的鱼，迎着旭日游出了家门。','6638-6687',1,1699664495,1782398597);
INSERT INTO highlights VALUES('834467_7_2164-2181','834467',26,'死去','他的喊叫像破碎的玻璃片一样纷纷扬扬','2142-2159',1,1699663926,1782398597);
INSERT INTO highlights VALUES('834467_7_835-976','834467',26,'死去','他走出的已经不是房屋。我的弟弟不小心走出了时间。他一旦脱离时间便固定下来，我们则在时间的推移下继续前行。孙光明将会看着时间带走了他周围的人和周围的景色。我看到了这样的真实场景：生者将死者埋葬以后，死者便永远躺在那里，而生者继续走动。这真实的场景是时间给予依然浪迹在现实里的人的暗示。','813-954',1,1699663751,1782398597);
INSERT INTO highlights VALUES('834467_6_6072-6115','834467',25,'婚礼','这位春风得意的年轻人立刻脸色惨白，我记得杂声四起的晒场在那一刻展现了声响纷纷掉落的图景','6050-6093',1,1699662760,1782398597);
INSERT INTO highlights VALUES('834467_5_9719-9786','834467',24,'南门','她经常嗑着我们家的瓜子出现在操场上，她吐瓜子壳时的放肆劲，仿佛她已经儿女成群。有一次她吐出瓜子壳以后，我看到她嘴角长时间挂着一条唾沫。','9697-9764',1,1699661337,1782398597);
INSERT INTO highlights VALUES('834467_18_14237-14296','834467',42,'回到南门',unistr('我摸上了另一条路，急步走了一阵，发现那老人还跟着我，我转回身向他喊叫： \u000a    “你别跟着，我家很穷的，养不起你。”'),'19595-19677',NULL,1664430302,1782480565);
INSERT INTO highlights VALUES('834467_18_11686-11716','834467',42,'回到南门','突然而起的喊声是那样的锋利，犹如一块玻璃碎片在空中呼啸而去。','15965-15995',NULL,1664430058,1782480565);
INSERT INTO highlights VALUES('834467_18_2648-2713','834467',42,'回到南门','事实上我过去和现在，都不是那种愿为信念去死的人，我是那样崇拜生命在我体内流淌的声音。除了生命本身，我再也找不出活下去的另外理由了。','4066-4131',NULL,1664428934,1782480565);
INSERT INTO highlights VALUES('834467_17_1915-1942','834467',41,'诬陷','我倾听时，仰起的脸上饱尝了他的唾沫，犹如在细雨中听课。','2964-2991',NULL,1664417954,1782480565);
INSERT INTO highlights VALUES('834467_17_1594-1654','834467',41,'诬陷',unistr('“你那么喜欢他，就收他做儿子算了。” \u000a    我们的老师毫不示弱，他笑眯眯地说： \u000a    “我倒是想收国庆做孙子。”'),'2528-2634',NULL,1664417930,1782480565);
INSERT INTO highlights VALUES('834467_16_15560-15640','834467',40,'抛弃','他拿住菜刀后就扔到了一旁，那时国庆根本没有注意这个动作，长时间的委屈和害怕终于找到了依靠，国庆扑过去抱住他的身体哭起来。警察却一把提起国庆脖后的衣领，走了出去。','21155-21235',NULL,1664388524,1782480565);
INSERT INTO highlights VALUES('834467_16_8189-8276','834467',40,'抛弃','我再次睁大眼睛，那时天完全黑了。害怕和虔诚终于让我看到了菩萨，我不知道是真正看到，还是在想象中看到。总之我看到了一尊有房屋那么大，像阳光那么金灿灿的菩萨，不过它一闪就消失了。','11393-11480',NULL,1664387796,1782480565);
INSERT INTO highlights VALUES('834467_16_7219-7274','834467',40,'抛弃','这个女人以她垂暮的气息腐化着国庆蓬勃的生命力，从而让我现在眺望尚是年幼的国庆时，看到了他脸上闪烁着灰暗的衰落。','9871-9926',NULL,1664387681,1782480565);
INSERT INTO highlights VALUES('834467_16_266-369','834467',40,'抛弃',unistr('我的同学用和那个清晨一样清新的嗓音问父亲，会不会搬到一个到处都有长翅膀的白马那里去。一贯严肃的父亲没有被儿子的幻想所感动，相反他对儿子的荒唐想法显得很不耐烦，他让儿子走开，对他说： \u000a    “别挡着道。”'),'762-888',NULL,1664345392,1782480565);
INSERT INTO highlights VALUES('834467_15_8665-8749','834467',39,'威胁','对国庆母亲的询问，所引发出来对天空的敬畏，是我心里最初感到的束缚。直到现在，我仍会突然感到自己正被一双眼睛追踪着，我无处可逃，我的隐私并不安全可靠，它随时面临着被揭露。','11174-11258',NULL,1664297715,1782480565);
INSERT INTO highlights VALUES('834467_15_8553-8618','834467',39,'威胁','那时的天空蓝得令人感到幽深无底，天空在看着我们。三个孩子被一种巨大的虚无笼罩着，我内心升起一股虔诚的战栗，辽阔的天空使我无法隐藏。','11016-11081',NULL,1664297695,1782480565);
INSERT INTO highlights VALUES('834467_15_7593-7637','834467',39,'威胁','她只是沉浸在我当时年龄还无法理解的自我与孤独之中，她站在生与死的界线上，同时被两者抛弃。','9872-9916',NULL,1664297564,1782480565);
INSERT INTO highlights VALUES('834467_13_4684-4705','834467',36,'消失','“儿子啊，我的魂一回来，你就又要受穷啦。”','6537-6558',NULL,1664296556,1782480565);
INSERT INTO highlights VALUES('834467_13_2921-2991','834467',36,'消失','能使他灵魂得到安宁的木头敲打声消失后，孙有元苍白无力的嗓音里，飘荡着饥渴的沙沙声。他生前最后的奢望，由于我弟弟的马虎，一下子变得虚无缥缈了。','4383-4453',NULL,1664296371,1782480565);
INSERT INTO highlights VALUES('834467_10_7515-7598','834467',32,'年幼的朋友','“你们身上的衣服，你们的钱都是国家发的，你们只要管好国家的事就行了，我身上的东西是自己长出来的，不是国家发的，我陪谁睡觉是我的事，我的东西自己会管的，不用你们操心。”','10922-11005',NULL,1664295744,1782480565);
INSERT INTO highlights VALUES('834467_10_4234-4287','834467',32,'年幼的朋友','孩子在孤立无援的时候，寻求他想象中哥哥的支持。我知道想象和希望对于他的重要和必需，事实上对于我也同样如此。','6888-6941',NULL,1664279272,1782480565);
INSERT INTO highlights VALUES('834467_10_4187-4233','834467',32,'年幼的朋友','后来我才知道鲁鲁其实没有哥哥，但我对这个事实一直保持沉默，这样孩子就不会感到我注意了他的编造','6841-6887',NULL,1664279263,1782480565);
