INSERT INTO highlights VALUES('3300081421_14_5890-5972','3300081421',14,'第7章 表达式','自增运算符将其操作数的值加1，而自减运算符则减1。运算符返回的值取决于运算符是前置还是后置。前置运算符将返回修改后的操作数的值，而后置运算符则返回修改前操作数的值。','5890-5972',1,1753461001,1782480550);
