INSERT INTO highlights VALUES('3300081421_12_12381-12435','3300081421',12,'第5章 运行时多态','通常，需要在接口中添加虚析构函数。在某些罕见的情况下，如果没有把析构函数标记为虚函数，就有可能泄漏资源。考虑','12381-12435',0,1753305542,1782480550);
