INSERT INTO highlights VALUES('3300081421_12_803-884','3300081421',12,'第5章 运行时多态','多态代码是指只写一次，但是可以用不同的类型反复使用的代码。最终，这种灵活性产生了松耦合且高度可重用的代码。它消除了烦琐的复制和粘贴过程，使代码更易于维护、更可读。','803-884',1,1753197264,1782480550);
