INSERT INTO highlights VALUES('25672236_10_3413-3473','25672236',10,'第五章 战争','。3月23日，穿着黄马褂的李鸿章奉旨检阅海军，北洋舰队已被视作亚洲最令人生畏的海军力量，一份西方军事杂志将它列为全球第八','3413-3473',5,1689736125,1782480563);
