INSERT INTO highlights VALUES('25672236_9_14355-14404','25672236',9,'第四章 狂生','康有为保持着他的狂傲，没有依照惯例去拜访座师，这令主考官徐桐颇为不悦，多少为日后的灾难埋下了伏笔。','14355-14404',5,1689734431,1782480563);
