INSERT INTO highlights VALUES('25672236_9_7048-7092','25672236',9,'第四章 狂生','旧宅墙壁内发现《尚书》《礼记》《孝经》等经书，是用战国时的篆文写成的，因此被称为古文经。','7048-7092',5,1689533045,1782480563);
