INSERT INTO highlights VALUES('25672236_9_478-515','25672236',9,'第四章 狂生','惠爱街，总督府、城隍庙、巡抚衙门、学宫沿街而立，撑起“广府第一街”的名号。','478-515',5,1689531753,1782480563);
INSERT INTO highlights VALUES('25672236_8_11743-11864','25672236',8,'第三章 春闱','他在显微镜镜头中发现一只蚂蚁好似大象这么大，一片菊花瓣像是一片芭蕉叶，一滴水里竟有如此之多的微生物，有鳞有角，如蛟龙一样蠕动。这些都给予他观察世界的全新方法，大与小、重与轻、长久与短暂，一切都变成相对的，与佛教典籍颇有相同之处，万物真实又虚幻','11743-11864',5,1689502580,1782480563);
INSERT INTO highlights VALUES('25672236_8_11346-11618','25672236',8,'第三章 春闱','知万国之故、地球之理”。￼他还对一个新世界有直接感受，在香港看到“宫室之瑰丽、道路之整洁、巡捕之严密，乃知西人治国有法度，不得以古旧之夷狄视之”。','11346-11519',5,1689502538,1782480563);
INSERT INTO highlights VALUES('25672236_8_11141-11197','25672236',8,'第三章 春闱','立志三十岁前读完群书、成为圣贤，还曾到山中冥想世界，感到天地万物与自己成为一体，转而忧虑苍生困苦，放声大笑大哭。','11141-11197',5,1689502512,1782480563);
INSERT INTO highlights VALUES('25672236_8_9568-9610','25672236',8,'第三章 春闱','康有为谈论了《诗》《礼》等诸经，攻击盛行多年的考据之风，还用自己的视角重新诠释了孔子','9568-9610',5,1689502364,1782480563);
INSERT INTO highlights VALUES('25672236_8_9132-9219','25672236',8,'第三章 春闱','在回乡路过上海时，他在四马路的书局买到徐继畬的《瀛寰志略》，意外地发现世界上原来还有五大洲之说，中国不过是这五大洲中的一国。他还看到上海制造局译出的西书若干种，可惜无力购买。','9132-9219',5,1689502283,1782480563);
INSERT INTO highlights VALUES('25672236_8_6982-7042','25672236',8,'第三章 春闱','外来者很容易被贡院中的景象震惊。大多数人相信这是帝国最为公正的人才选拔机制，它不是基于血缘、神权，而是建立在个人才能之上','6982-7042',5,1689480873,1782480563);
INSERT INTO highlights VALUES('25672236_8_7299-7331','25672236',8,'第三章 春闱','中国的举子当然不会知晓这些看法，毕竟他们看不到人生还有其他选择。','7299-7331',5,1689480249,1782480563);
INSERT INTO highlights VALUES('25672236_8_7171-7203','25672236',8,'第三章 春闱','鞑靼人的一个小朝廷能利用文官竞争考试的制度来网络全中国的才智之士','7171-7203',5,1689480233,1782480563);
