INSERT INTO highlights VALUES('25672236_7_6380-6545','25672236',7,'第二章 学海堂','“中国人足智多谋，将他们对物理学有限的知识发挥得淋漓尽致，实是让人叹为观止。令人迷惑不解的是，他们既能将知识应用于日常生活，为何又长期故步自封，驻足不前？”','6380-6458',5,1689360446,1782480563);
INSERT INTO highlights VALUES('25672236_6_11028-11050','25672236',6,'第一章 茶坑村','他记忆力惊人，对语言极度敏感，尤其善于作对子','11028-11050',5,1689185385,1782480563);
INSERT INTO highlights VALUES('25672236_6_5748-5845','25672236',6,'第一章 茶坑村','可以想象，他应该是个过分拘谨的读书人，将科举的失败转化成更深的道德要求，而这道德要求又经常是脆弱的，容易被现实诱惑吞没——这也是整个帝国的特征，在一套高洁、夸张的言辞背后，是一个道德坍塌的社会。','5748-5845',5,1689051806,1782480563);
INSERT INTO highlights VALUES('25672236_6_5120-5187','25672236',6,'第一章 茶坑村','梁启超的出生给这个家庭带来了满足与希望，他是这个小家庭的第一个男孩，也是长孙，是家族未来的继承人，注定肩负起与宗族其他支脉竞争的任务。','5120-5187',5,1688975996,1782480563);
INSERT INTO highlights VALUES('25672236_6_4290-4320','25672236',6,'第一章 茶坑村','数百年来，整个帝国秩序正是依赖一个个这样的本地士绅艰难维持。','4290-4320',5,1688975422,1782480563);
INSERT INTO highlights VALUES('25672236_6_2314-2363','25672236',6,'第一章 茶坑村','它离广州110公里，西江纵贯新会全境，潭江横穿其西部，它们在入海口处汇成银洲湖，南海就此展现在眼前','2314-2363',5,1688974536,1782480563);
INSERT INTO highlights VALUES('25672236_6_2191-2225','25672236',6,'第一章 茶坑村','这个进程在16世纪中叶陡然增强了，因为广州、长崎、马尼拉贸易圈的形成','2191-2225',5,1688974506,1782480563);
INSERT INTO highlights VALUES('25672236_6_1900-1943','25672236',6,'第一章 茶坑村','蒙古军队的入侵导致北部山区被抛荒，加速了土地被侵蚀，将更多的泥沙通过北江送入珠三角区域','1900-1943',5,1688974487,1782480563);
INSERT INTO highlights VALUES('25672236_5_7444-7493','25672236',5,'引言 逃亡','他们决定给伊藤博文与林权助写“泣血百拜”的书信，目之所及，似乎唯有这两位外来者才可能提供某种帮助。','7444-7493',5,1688973779,1782480563);
INSERT INTO highlights VALUES('25672236_5_4831-4921','25672236',5,'引言 逃亡','离开公使馆前，梁启超做出人生另一个重大决定，他剪掉脑后的辫子，并换上了西装。或许维新者私下谈论了很多次断发易服之必要，但真的发生时，内心恐怕也不无挣扎，它毕竟意味着公开成为反叛者。','4831-4921',5,1688972296,1782480563);
INSERT INTO highlights VALUES('25672236_5_2295-2341','25672236',5,'引言 逃亡','梁启超乞求，日本出面救助光绪帝与康有为，他自己准备迎接死亡，“我如被逮捕，三天之内会被杀”。','2295-2341',5,1688968393,1782480563);
INSERT INTO highlights VALUES('25672236_5_1211-1250','25672236',5,'引言 逃亡','由于“江米”与“交民”读音相近，巷子逐渐被称作“交民巷”，又变成了“东交民巷”','1211-1250',5,1688956800,1782480563);
INSERT INTO highlights VALUES('25672236_4_4468-4488','25672236',4,'自序 一个青年变革者','接见华人领袖，还品尝了一种叫王老吉的饮料','4468-4488',5,1688921854,1782480563);
INSERT INTO highlights VALUES('25672236_4_4312-4387','25672236',4,'自序 一个青年变革者','或是在北京的法源寺外闲坐，想象他与谭嗣同、夏曾佑热烈的青春……很可惜，在一轮轮的拆毁与重建中，历史现场早已面目全非，你只能依赖想象力，尽管它常不可靠。','4312-4387',5,1688921807,1782480563);
INSERT INTO highlights VALUES('25672236_4_4252-4258','25672236',4,'自序 一个青年变革者','广州万木草堂','4252-4258',5,1688921381,1782480563);
INSERT INTO highlights VALUES('25672236_4_4041-4068','25672236',4,'自序 一个青年变革者','即使人人都受制于自身环境，自由意志仍催促一些人脱颖而出','4041-4068',5,1688921340,1782480563);
INSERT INTO highlights VALUES('25672236_4_2408-2509','25672236',4,'自序 一个青年变革者','他理应进入塞缪尔·约翰逊(Samuel Johnson)、伏尔泰、福泽谕吉与爱默生(Ralph Emerson)的行列，他们身处一个新旧思想与知识交替的时代，成为百科全书式的存在，唤醒了某种沉睡的精神。','2408-2509',5,1688920946,1782480563);
INSERT INTO highlights VALUES('25672236_4_1716-1757','25672236',4,'自序 一个青年变革者','他是一位行动者，二十五岁就卷入百日维新的旋涡中，流亡至日本后又参与策划自立军起义。','1716-1757',5,1688920850,1782480563);
INSERT INTO highlights VALUES('25672236_4_673-679','25672236',4,'自序 一个青年变革者','城市之光书店','673-679',5,1688920701,1782480563);
INSERT INTO highlights VALUES('25672236_4_995-1039','25672236',4,'自序 一个青年变革者','这家书店不仅是“垮掉一代”作家的发源地，代表着自由不羁的文学趣味，还身处两个世界的交汇地','995-1039',5,1688920695,1782480563);
INSERT INTO highlights VALUES('25672236_4_560-605','25672236',4,'自序 一个青年变革者','他动员散落在世界各处的华人商人与劳工捐献资金，组织起来，营救受困的皇帝，建立一个富强的中国','560-605',5,1688920623,1782480563);
INSERT INTO highlights VALUES('3300116432_14_3666-3735','3300116432',14,'第十一章 大脑皮层如何激活杏仁核？','你有没有回想过过去发生的可怕的事情？光是回忆起这件事是不是就会让你感到一阵焦虑？在想象未来可能发生的压力情况时，你有没有发现心会怦怦直跳？','3666-3735',0,1769852944,1782480548);
INSERT INTO highlights VALUES('3300116432_14_1737-1772','3300116432',14,'第十一章 大脑皮层如何激活杏仁核？','这种情况下，梅琳达的杏仁核是通过皮质通路激活的。我想，你会认可这个观点','1737-1772',0,1769337661,1782480548);
INSERT INTO highlights VALUES('3300116432_14_955-1044','3300116432',14,'第十一章 大脑皮层如何激活杏仁核？','“杏仁核在看皮层电视”的说法来解释两个大脑区域之间的关系。当杏仁核观察到皮层中产生痛苦情境的想法或图像时，这些想法和图像会促使杏仁核激活防御反应，让我们感到焦虑、害怕甚至是恐慌。','955-1044',0,1769337430,1782480548);
INSERT INTO highlights VALUES('3300116432_13_10165-10204','3300116432',13,'第十章 用暴露法教杏仁核','为了进行学习，你需要在诱发刺激存在的情况下体会焦虑的减轻，等待你的不适感缓解。','10165-10204',0,1768669029,1782480548);
INSERT INTO highlights VALUES('3300116432_13_9989-10063','3300116432',13,'第十章 用暴露法教杏仁核','暴露绝对是困难与不好受的，他们坚持下来这点做得很好。我提醒他们，恐惧是存在的，要敢于面对恐惧。记住，没有一种情绪是永久的。只要你忍受，它终将会过去。','9989-10063',0,1768668963,1782480548);
INSERT INTO highlights VALUES('3300116432_13_9506-9529','3300116432',13,'第十章 用暴露法教杏仁核','但暴露将不会有效地改变其杏仁核对诱发刺激的反应','9506-9529',0,1768668873,1782480548);
INSERT INTO highlights VALUES('3300116432_13_9436-9487','3300116432',13,'第十章 用暴露法教杏仁核','虽然这可以阻碍杏仁核产生防御反应（这通常是人们服用镇静药物的原因），但它也会阻止杏仁核产生任何新的反应','9436-9487',0,1768668821,1782480548);
INSERT INTO highlights VALUES('3300116432_13_7747-7783','3300116432',13,'第十章 用暴露法教杏仁核','你应集中注意力在发生的事情或当下正在经历的事上，而不是预想可能发生的事。','7747-7783',0,1768668659,1782480548);
INSERT INTO highlights VALUES('3300116432_13_9072-9136','3300116432',13,'第十章 用暴露法教杏仁核','反应预防是必要的。如果你已学会运用某些反应、仪式或是检查行为来应付自己的恐惧、焦虑或不安，你需要在暴露过程中杜绝这些行为','9072-9136',0,1768668659,1782480548);
INSERT INTO highlights VALUES('3300116432_13_8845-8872','3300116432',13,'第十章 用暴露法教杏仁核','杏仁核学到的是去商场要带药物，而不是减少去商场的恐惧。','8845-8872',0,1768668659,1782480548);
INSERT INTO highlights VALUES('3300116432_13_6052-6087','3300116432',13,'第十章 用暴露法教杏仁核','暴露的目的是让你的主观痛苦感觉评分至少降到你在该疗程中所得最高分的一半','6052-6087',0,1768668658,1782480548);
INSERT INTO highlights VALUES('3300116432_13_6848-6888','3300116432',13,'第十章 用暴露法教杏仁核','应保持杏仁核处于某种程度的激活状态，因为杏仁核若不被激活，新的网络神经就无法发育','6848-6888',0,1768668658,1782480548);
INSERT INTO highlights VALUES('3300116432_13_7463-7499','3300116432',13,'第十章 用暴露法教杏仁核','有些现实情境下的暴露是不道德的。（例如，要求害怕配错药的药剂师去这样做。','7463-7499',0,1768668658,1782480548);
INSERT INTO highlights VALUES('3300116432_13_1317-1373','3300116432',13,'第十章 用暴露法教杏仁核','然而，在暴露疗程中，触发因素不能仅仅只出现一次，而是要让它多次“暴露”，直到这个人能够在这样的情景下保持不焦虑。','1317-1373',0,1767935883,1782480548);
INSERT INTO highlights VALUES('3300116432_12_5798-5844','3300116432',12,'第九章 杏仁核如何制造触发点？','如果你让自己暴露在触发点中，同时确保它没有与负面体验配对，那么杏仁核可能会学会不害怕触发点。','5798-5844',0,1767372903,1782480548);
INSERT INTO highlights VALUES('3300116432_12_3070-3116','3300116432',12,'第九章 杏仁核如何制造触发点？','这就表明，尽管她的大脑皮层并未记住这名医生，但她的杏仁核却记下了这位医生给她带来的情感记忆。','3070-3116',0,1767372230,1782480548);
INSERT INTO highlights VALUES('3300116432_11_5703-5745','3300116432',11,'第八章 运动和饮食如何影响杏仁核？','在锻炼前两到三个小时要吃豆类、全麦面包和意大利面等食物，而水果应该在上述食物之前吃。','5703-5745',0,1766496320,1782480548);
INSERT INTO highlights VALUES('3300116432_11_3434-3507','3300116432',11,'第八章 运动和饮食如何影响杏仁核？','然而，如果你的饮食中经常含有咖啡因，那么突然减少咖啡因摄入很可能会导致戒断症状，包括头痛、疲劳、精力不足、肌肉疼痛、注意力不集中、易怒，甚至焦虑。','3434-3507',0,1766496108,1782480548);
INSERT INTO highlights VALUES('3300116432_11_2581-2600','3300116432',11,'第八章 运动和饮食如何影响杏仁核？','许多人没有意识到糖也会对焦虑产生影响。','2581-2600',0,1766495973,1782480548);
INSERT INTO highlights VALUES('3300116432_10_9412-9418','3300116432',10,'第七章 睡眠如何影响你的杏仁核？','艾司佐匹克隆','9412-9418',0,1766495420,1782480548);
INSERT INTO highlights VALUES('3300116432_10_8741-8796','3300116432',10,'第七章 睡眠如何影响你的杏仁核？','在寻找应用程序时，请记住，听音乐通常不如听别人说话有帮助，因为音乐不会像纯粹的话语那样能够打断和取代你的想法。','8741-8796',0,1766474841,1782480548);
INSERT INTO highlights VALUES('3300116432_10_2678-2735','3300116432',10,'第七章 睡眠如何影响你的杏仁核？','不要以为午睡对杏仁核有帮助。它不太可能提供任何快速眼动睡眠，相反，它经常会影响你在晚上入睡的能力，缩短你的睡眠时间','2678-2735',0,1766470805,1782480548);
INSERT INTO highlights VALUES('3300116432_10_870-969','3300116432',10,'第七章 睡眠如何影响你的杏仁核？','杏仁核本身往往会导致睡眠困难。当杏仁核被激活时，它会唤醒大脑，使我们变得警觉和清醒，这显然会减少睡眠的可能性。这就解释了为什么经常感到焦虑的人，或者杏仁核过度活跃的人，一旦醒来就很难入睡或重新入睡。','870-969',0,1766470211,1782480548);
INSERT INTO highlights VALUES('3300116432_9_5755-5789','3300116432',9,'第六章 如何让杏仁核平静下来？','记住任何时候都不要屏住呼吸。在任何给定的时刻，你要么吸气，要么呼气。','5755-5789',0,1766465625,1782480548);
INSERT INTO highlights VALUES('3300116432_8_5701-5751','3300116432',8,'第五章 杏仁核的语言','虽然像深呼吸和锻炼等策略可以帮助你在杏仁核的层面上与它沟通，但也许将新信息传递给杏仁核才是最重要的。','5701-5751',0,1766457191,1782480548);
INSERT INTO highlights VALUES('3300116432_8_5552-5575','3300116432',8,'第五章 杏仁核的语言','比运动更简单的是，你可以用呼吸向杏仁核发送信息','5552-5575',0,1766457170,1782480548);
INSERT INTO highlights VALUES('3300116432_8_5306-5349','3300116432',8,'第五章 杏仁核的语言','例如，当感觉到我的杏仁核激活防御反应时，我经常选择用一种它能理解的方式来回应——锻炼。','5306-5349',0,1766457136,1782480548);
INSERT INTO highlights VALUES('3300116432_8_3890-3955','3300116432',8,'第五章 杏仁核的语言','葡萄糖从肝脏中释放出来，为肌肉活动提供所需燃料，这意味着你的血糖水平会迅速上升。你可能会感到肾上腺素激增，也可能觉得需要上个厕所。','3890-3955',0,1766456791,1782480548);
INSERT INTO highlights VALUES('3300116432_8_1156-1204','3300116432',8,'第五章 杏仁核的语言','尽管我们知道防御反应通常为“战斗或逃跑”，但研究人员发现，杏仁核还会产生第三种反应——木僵反应。','1156-1204',0,1766415172,1782480548);
INSERT INTO highlights VALUES('3300116432_7_4510-4550','3300116432',7,'第四章 大脑焦虑的两种途径','但是皮质失明的人会表现出对运动的意识，他们声称自己能对看不见的东西做出惊吓反应。','4510-4550',0,1764650992,1782480548);
INSERT INTO highlights VALUES('3300116432_7_3164-3186','3300116432',7,'第四章 大脑焦虑的两种途径','在皮层通道中，首先信息会从感觉器官传到丘脑。','3164-3186',0,1764650794,1782480548);
INSERT INTO highlights VALUES('3300116432_7_2698-2765','3300116432',7,'第四章 大脑焦虑的两种途径','有些人把杏仁核的反应误认为是反射，但二者的原理并不相同。刺激引起神经冲动，神经冲动传递到脊髓，脊髓向肌肉发送直接信号，这才叫“反射”。','2698-2765',0,1764650690,1782480548);
INSERT INTO highlights VALUES('3300116432_7_2225-2271','3300116432',7,'第四章 大脑焦虑的两种途径','你并不知道杏仁核看到了什么，它能处理的细节比大脑皮层要少得多，但它能更快地检测到潜在的危险。','2225-2271',0,1764650648,1782480548);
INSERT INTO highlights VALUES('3300116432_7_1897-1979','3300116432',7,'第四章 大脑焦虑的两种途径','杏仁核获取信息的速度比大脑皮层快，这意味着你的杏仁核可以在你有意识地感知这些事物之前处理你所看到的、听到的、感觉到的和尝到的东西，因为你依靠大脑皮层来获取感官信息。','1897-1979',0,1764650615,1782480548);
INSERT INTO highlights VALUES('3300116432_7_1801-1830','3300116432',7,'第四章 大脑焦虑的两种途径','这就是气味能唤起强烈的情绪的原因——它们直接到达杏仁核。）','1801-1830',0,1764650598,1782480548);
INSERT INTO highlights VALUES('3300116432_7_1554-1609','3300116432',7,'第四章 大脑焦虑的两种途径','丘脑就像中央车站，所有的感官通道都可以同时进入。丘脑的工作是将接收到的信息发送到大脑中处理这些信息的正确位置。','1554-1609',0,1764650536,1782480548);
INSERT INTO highlights VALUES('3300116432_7_784-834','3300116432',7,'第四章 大脑焦虑的两种途径','本章将介绍大脑中两种不同的焦虑途径——杏仁核途径和大脑皮层途径，并了解杏仁核在每种途径中所起的作用。','784-834',0,1764650461,1782480548);
INSERT INTO highlights VALUES('3300116432_7_653-689','3300116432',7,'第四章 大脑焦虑的两种途径','这是杏仁核起作用的一个很好的例子。杏仁核旨在快速发现危险并帮助你做出反应','653-689',0,1764650445,1782480548);
INSERT INTO highlights VALUES('3300116432_6_12206-12229','3300116432',6,'第三章 设定目标：回归生活的第一招','夺回生活控制权的一个好方法就是：专注于具体目标','12206-12229',0,1763051520,1782480548);
INSERT INTO highlights VALUES('3300116432_6_477-488','3300116432',6,'第三章 设定目标：回归生活的第一招','你必须确定你的人生目标','477-488',0,1754210160,1782480548);
INSERT INTO highlights VALUES('3300116432_5_3632-3644','3300116432',5,'第二章 认识杏仁核','重要的是要确保你有动力，','3632-3644',0,1754210131,1782480548);
INSERT INTO highlights VALUES('3300116432_5_3475-3505','3300116432',5,'第二章 认识杏仁核','它们对杏仁核有惊人的镇静效果。这些习惯包括睡眠、锻炼和饮食。','3475-3505',0,1754210108,1782480548);
INSERT INTO highlights VALUES('3300116432_5_3207-3248','3300116432',5,'第二章 认识杏仁核','其次，你可以努力教杏仁核在特定情况下做出不同的反应，向其提供关于这些情况的新信息。','3207-3248',0,1754210061,1782480548);
INSERT INTO highlights VALUES('3300116432_5_3123-3152','3300116432',5,'第二章 认识杏仁核','首先，你可以聚焦日常事务，专注于改变杏仁核的总体反应水平。','3123-3152',0,1754210043,1782480548);
INSERT INTO highlights VALUES('3300116432_5_1549-1604','3300116432',5,'第二章 认识杏仁核','无论是感到恐惧、焦虑、害怕，还是类似的情绪，身体都处于杏仁核带来的那种防御状态，这种状态被称为迎战或逃跑反应。','1549-1604',0,1754209672,1782480548);
INSERT INTO highlights VALUES('38395237_11_3293-3408','38395237',11,'古老的故事','这种思想至少在其最初的萌芽阶段，试图努力纯粹通过理智的力量去洞悉那个无偏见的自然。抽象的、仿佛具有神性的原则取代了旧有的诸神。这种思想推动了以后被称为“科学”的东西的出现。当然从公元前6世纪到“科学”还有漫长的路……','3293-3408',5,1717187928,1782480557);
INSERT INTO highlights VALUES('38395237_11_2627-2652','38395237',11,'古老的故事','逻各斯意味着“言说”“口头传达”“语词”或“句子”','2627-2652',5,1717187790,1782480557);
INSERT INTO highlights VALUES('38395237_11_2542-2618','38395237',11,'古老的故事','在这个通过神话被确立起来的充斥着橄榄树、葡萄园、山羊岩画和繁荣的商业城市的世界中，生成了第二条思想线索——所谓的“逻各斯”（logos）。','2542-2618',5,1717187783,1782480557);
INSERT INTO highlights VALUES('38395237_11_2129-2216','38395237',11,'古老的故事','如果说《伊利亚特》与《奥德赛》是理解闲散状态下与战争期间的贵族阶层的伦理学不可或缺的来源，那么在《工作与时日》中，赫西俄德则提供了一种渺小而艰辛劳作的人们的伦理学之类的东西。','2129-2216',5,1717187700,1782480557);
INSERT INTO highlights VALUES('38395237_10_4941-4956','38395237',10,'第一位哲学家？','泰勒斯相信，万物皆充塞着诸神。','4941-4956',5,1717187333,1782480557);
INSERT INTO highlights VALUES('38395237_10_4739-4773','38395237',10,'第一位哲学家？','根据我们今天所知，生物是有生命的——而空气、土地以及水本身则不是生物','4739-4773',5,1717177178,1782480557);
INSERT INTO highlights VALUES('38395237_10_4786-4807','38395237',10,'第一位哲学家？','哪些特质可能使泰勒斯相信水是一切质料的质料','4786-4807',5,1717177157,1782480557);
INSERT INTO highlights VALUES('38395237_10_3991-4013','38395237',10,'第一位哲学家？','据说他是将所有自然现象归因于唯一起源的第一人','3991-4013',5,1717177052,1782480557);
INSERT INTO highlights VALUES('38395237_10_3460-3485','38395237',10,'第一位哲学家？','对世界的哲学观察历来都是一个人所共知的局外人之事。','3460-3485',5,1716561075,1782480557);
INSERT INTO highlights VALUES('38395237_10_3121-3169','38395237',10,'第一位哲学家？','如何理解色雷斯女仆的嘲笑？显而易见这是对脱离生活的理论家的嘲笑，他从未成功地掌控自己的日常生活。','3121-3169',5,1716561014,1782480557);
INSERT INTO highlights VALUES('38395237_10_808-819','38395237',10,'第一位哲学家？','其中最著名的就是米利都','808-819',5,1716560691,1782480557);
INSERT INTO highlights VALUES('38395237_10_736-782','38395237',10,'第一位哲学家？','几乎没有证据表明，今天希腊国土上，【41】公元前7和前6世纪的居民认为自己是一个文化共同体。','736-782',5,1716560675,1782480557);
INSERT INTO highlights VALUES('38395237_9_2673-2729','38395237',9,'西方大地的日食','如果泰勒斯预言了日食，这就意味着，日食是自然事件。与所有的自然现象一样，它可以被智慧的自然研究者认识并且计算出来','2673-2729',5,1716560610,1782480557);
INSERT INTO highlights VALUES('38395237_9_1932-1948','38395237',9,'西方大地的日食','他所写的文本没有任何一篇留传下来','1932-1948',5,1716560396,1782480557);
INSERT INTO highlights VALUES('38395237_9_1595-1643','38395237',9,'西方大地的日食','据说，泰勒斯出生于公元前624年。他也许出身米利都的贵族家庭，又或许是一个迁居至米利都的腓尼基人','1595-1643',5,1716560256,1782480557);
INSERT INTO highlights VALUES('38395237_9_796-869','38395237',9,'西方大地的日食','唯独一个人未受这一切影响：智者，米利都的泰勒斯（Thales von Milet）。因为，他已经预先精确计算出这次日食，并公布出来，这是一个传奇。','796-869',5,1716560161,1782480557);
INSERT INTO highlights VALUES('38395237_9_748-795','38395237',9,'西方大地的日食','互相敌对的米底人和吕底亚人的军队面对着诸神的介入，在战役中放下了武器，结束了这场历时五年的战争','748-795',5,1716560131,1782480557);
INSERT INTO highlights VALUES('38395237_6_6399-6437','38395237',6,'雅典学园【21】','本书第一卷的重点将大致放在那些引人入胜的政治—经济问题以及自然哲学的问题上。','6399-6437',5,1716559858,1782480557);
INSERT INTO highlights VALUES('38395237_6_6515-6562','38395237',6,'雅典学园【21】','亚里士多德的《形而上学》只有部分被涉及，出于叙述编排的原因，我将在第二卷补充论述他的《政治学》','6515-6562',5,1716559727,1782480557);
INSERT INTO highlights VALUES('38395237_6_6480-6498','38395237',6,'雅典学园【21】','因此我谈柏拉图时集中在认识论和伦理学','6480-6498',5,1716559725,1782480557);
INSERT INTO highlights VALUES('38395237_6_6297-6326','38395237',6,'雅典学园【21】','留传下来的内容丰富或完整的著作，比贫乏与不完整的罕见得多。','6297-6326',5,1716559636,1782480557);
INSERT INTO highlights VALUES('38395237_6_5751-5792','38395237',6,'雅典学园【21】','可以估计，古代的非基督教文献中只有千分之一留传下来，也就是只有大约3000个章节。','5751-5792',5,1716555016,1782480557);
INSERT INTO highlights VALUES('38395237_6_5231-5269','38395237',6,'雅典学园【21】','“理念论”真的是柏拉图思想的中心组成部分，还是仅仅对于柏拉图主义来说是这样？','5231-5269',5,1716554868,1782480557);
INSERT INTO highlights VALUES('38395237_6_5008-5026','38395237',6,'雅典学园【21】','他们之中没有人把自己当作先驱或者前辈','5008-5026',5,1716554835,1782480557);
INSERT INTO highlights VALUES('38395237_6_4871-4907','38395237',6,'雅典学园【21】','另一方面，我们必须问自己，这个观点在多大程度上阻碍了我们对古代哲学的理解','4871-4907',5,1716554808,1782480557);
INSERT INTO highlights VALUES('38395237_6_4785-4836','38395237',6,'雅典学园【21】','我们今天的文化通常看起来就是对古希腊文化的延续，可能甚至是逻辑上的推进，其间历经了基督教中世纪的更新。','4785-4836',5,1716554771,1782480557);
INSERT INTO highlights VALUES('38395237_6_3701-3728','38395237',6,'雅典学园【21】','这个场景绝对带有讽刺意味，因为柏拉图并不喜欢普罗泰戈拉','3701-3728',5,1716554596,1782480557);
INSERT INTO highlights VALUES('38395237_6_2571-2630','38395237',6,'雅典学园【21】','通常被认为是赫拉克利特（Heraklit）的那位，却有着拉斐尔的重要竞争者米开朗琪罗（Michelangelo）的容貌','2571-2630',5,1716053081,1782480557);
INSERT INTO highlights VALUES('38395237_6_2042-2120','38395237',6,'雅典学园【21】','将柏拉图视作基督教的先驱，【23】完美地将其与亚里士多德和普罗提诺（Plotin）归为一类，并与摩西（Moses）和耶稣（Jesus）一道排入同一个族谱中。','2042-2120',5,1716042477,1782480557);
INSERT INTO highlights VALUES('38395237_5_6860-6914','38395237',5,'导言【11】*','维特根斯坦说：“哲学不是理论，而是行动。”这种行动让我们对生活和共同生活中经常出现疑问的假设和断言更为敏感。','6860-6914',5,1716042064,1782480557);
INSERT INTO highlights VALUES('38395237_5_4630-4661','38395237',5,'导言【11】*','“哲学”更多地呈现为一种以文化的方式保存超越时代之价值的行为。','4630-4661',5,1716041426,1782480557);
INSERT INTO highlights VALUES('38395237_5_3827-3894','38395237',5,'导言【11】*','就如艺术形成了很多风格和主义，那些世界观哲学也与此相似。人们不再建造一座大楼，而是凸显一种思想风格，而世界观就成了标志。','3827-3894',5,1716026032,1782480557);
INSERT INTO highlights VALUES('38395237_5_3509-3536','38395237',5,'导言【11】*','哲学家不再是认识这个世界，而是向它投去极富主观性的目光','3509-3536',5,1716024638,1782480557);
INSERT INTO highlights VALUES('38395237_5_3342-3445','38395237',5,'导言【11】*','与之相反的观点是，哲学思想是思想的艺术。它在对黑格尔的批判中脱颖而出。叔本华，还有尼采（Friedrich Nietzsche）怀着冲天之怒摧毁了对唯一一种理性的信仰以及所有建基于其上的哲学。','3342-3445',5,1716024619,1782480557);
INSERT INTO highlights VALUES('38395237_5_3206-3241','38395237',5,'导言【11】*','诚然，这样的一门科学不再解释，而只是描述。','3206-3241',5,1716024586,1782480557);
INSERT INTO highlights VALUES('38395237_5_3028-3108','38395237',5,'导言【11】*','如果谁要努力实现某种程度上的理性，也只能在字面上实践。他不仅得遵从一种逻辑，还要遵循一种语法。并且他要使用一种语言，这种语言并非永恒不变，而是受文化的限制和浸染','3028-3108',5,1716024545,1782480557);
INSERT INTO highlights VALUES('38395237_5_2962-2998','38395237',5,'导言【11】*','最晚是在20世纪初，我们就不得不承认，唯一一种理性并不存在','2962-2998',5,1716024521,1782480557);
INSERT INTO highlights VALUES('38395237_5_2838-2879','38395237',5,'导言【11】*','因此，哲学家的全部工作就在于，以理性的方式洞悉世界，以此促使永恒的真理大白于天下。','2838-2879',5,1716024503,1782480557);
INSERT INTO highlights VALUES('38395237_5_2669-2684','38395237',5,'导言【11】*','存在唯一一种哲学','2669-2684',5,1716024481,1782480557);
INSERT INTO highlights VALUES('38395237_5_2722-2791','38395237',5,'导言【11】*','黑格尔在这种程度上书写哲学史——那基本是最早的哲学史作之一，即仿佛这栋思想建筑客观地存在于世界上。整个建筑的黏合剂是被称为理性的建筑材料。','2722-2791',5,1716024476,1782480557);
INSERT INTO highlights VALUES('38395237_5_2338-2390','38395237',5,'导言【11】*','在它们的创立者柏拉图（Plato）和亚里士多德（Aristoteles）看来，哲学是关于正确生活的追问。','2338-2390',5,1716024397,1782480557);
INSERT INTO highlights VALUES('38395237_5_2200-2249','38395237',5,'导言【11】*','因为在这两种彼此争论的见解背后隐藏着差异极大的观点，即在哲学中究竟隐含或应当隐含多少科学或自由风格','2200-2249',5,1716024348,1782480557);
INSERT INTO highlights VALUES('38395237_5_1903-1954','38395237',5,'导言【11】*','哲学思想的前进并不必然意味着真理的揭示与明了。今天在我们看来，真理这个概念在很多方面就已是值得怀疑的。','1903-1954',5,1716024308,1782480557);
INSERT INTO highlights VALUES('38395237_5_1681-1756','38395237',5,'导言【11】*','叔本华（Arthur Schopenhauer），已然愤怒地批评这样一种被彻底诠释的哲学史了。阅读一段被完全评定了的历史，就像“吃别人咀嚼过的食物”。','1681-1756',5,1716024250,1782480557);
INSERT INTO highlights VALUES('38395237_5_1250-1297','38395237',5,'导言【11】*','蒙田（Michel de Montaigne）曾说过：“令我们感到幸福的是享受，而不是占有。”','1250-1297',5,1716024144,1782480557);
INSERT INTO highlights VALUES('914697_24_6177-6376','914697',24,'积善之方','因此，凡是要行善积德，绝不可以只依赖自己的眼睛所见、耳朵所听作为判断的依据，而应从内心最隐秘、细微的地方，默默地省察自己的起心动念，并加以洗涤、净化。纯然的救世之心，那就是“端”；如果有一丝一毫的媚俗之心，那就是“曲”。纯然是爱人的心，那就是“端”；如果有一丝一毫的嫉愤之心，那就是“曲”。纯然是尊敬他人的心，那就是“端”；如果有一丝一毫的玩世之心，那就是“曲”。像这些细微的区别，都应当仔细分辨。','6177-6376',1,1696779085,1782480563);
INSERT INTO highlights VALUES('914697_24_12894-12944','914697',24,'积善之方','人之所以为人，是因为有恻隐之心。求仁的人要追求的就是这个恻隐之心，积德的人积累的，也是这个恻隐之心。','12894-12944',1,1696778726,1782480563);
INSERT INTO highlights VALUES('914697_24_12617-12703','914697',24,'积善之方','什么叫敬重尊长？家庭的父兄、国家的君长，以及一切年事高、德行高、见识高的人，我们都应该恭敬对待。在家里侍奉父母，要和颜悦色、柔声下气，养成习惯，以成本性。这叫和气感通上天。','12617-12703',1,1696778683,1782480563);
INSERT INTO highlights VALUES('914697_24_12497-12556','914697',24,'积善之方',unistr('所以，凡是见到供奉圣贤的庙宇，以及经书典籍，都应当敬重而加以修缮保护。至于弘扬正法，报答佛祖的恩德，尤其应当勉励。\u000a INSERT INTO highlights VALUES('914697_24_12253-12313','914697',24,'积善之方','如果我们大家把看得最为重要的东西看得不重要，随时可以舍出去，那么，对内我们就可以破除吝啬之心，对外我们就可以救人于危急。','12253-12313',1,1696778568,1782480563);
INSERT INTO highlights VALUES('914697_24_11924-11954','914697',24,'积善之方','小到一乡之内，大到一县之内，凡是有利于大众的，都应该去兴建。','11924-11954',1,1696778458,1782480563);
INSERT INTO highlights VALUES('914697_24_11748-11796','914697',24,'积善之方','遇到了困难中的人，应当像自己也在痛苦中一样，赶快设法帮助他。或者陪他说说话，帮他舒缓心中的压抑。','11748-11796',1,1696778430,1782480563);
INSERT INTO highlights VALUES('914697_24_11353-11436','914697',24,'积善之方','方便的时候一定要尽力提醒对方，让他从迷惑、迷雾里看清真相，好像有人在长夜里沉睡做梦，我们让他醒悟过来；又好像有人陷于烦恼的纠缠，我们给他一剂清凉剂让他跳出烦恼的泥潭。','11353-11436',1,1696778382,1782480563);
INSERT INTO highlights VALUES('914697_24_10998-11035','914697',24,'积善之方','凡是见到人做善事，或这个人的志向有可取的地方，就应该引导和扶持，极力成就他','10998-11035',1,1696778332,1782480563);
INSERT INTO highlights VALUES('914697_24_10694-10711','914697',24,'积善之方','君子所存养的心，只是敬人爱人的心。','10694-10711',1,1696778238,1782480563);
INSERT INTO highlights VALUES('914697_24_10455-10510','914697',24,'积善之方','看到别人有一点点的长处值得学习，有一点点的善行值得记录，都应该放下成见，向他们学习，并要为他们赞叹且广为宣传。','10455-10510',1,1696778200,1782480563);
INSERT INTO highlights VALUES('914697_24_10409-10455','914697',24,'积善之方','见到别人的过失，应当有所包涵，为他掩盖，可以让他有改过的机会，也能够让他有所顾忌而不敢放纵。','10409-10455',1,1696778172,1782480563);
INSERT INTO highlights VALUES('914697_24_9956-10064','914697',24,'积善之方','顺其自然地帮助别人，有各种各样的方法，大概而言，有十种：第一，与人为善；第二，爱敬存心；第三，成人之美；第四，劝人为善；第五，救人危急；第六，兴建大利；第七，舍财作福；第八，护持正法；第九，敬重尊长；第十，爱惜物命。','9956-10064',1,1696778020,1782480563);
INSERT INTO highlights VALUES('914697_25_3148-3230','914697',25,'谦德之效','孟子对齐王说：“大王如果真正喜欢音乐，那么，齐国也就治理得差不多了。”我认为读书人之于科举，也是一样。如果你发自内心地喜欢，有坚定不移的志向，那就一定能够获得功名。','3148-3230',1,1696775984,1782480563);
INSERT INTO highlights VALUES('914697_25_2129-2168','914697',25,'谦德之效','“造命的是天，而立命的是自己。只要尽力去做善事，广积阴德，什么福泽求不到呢？”','2129-2168',1,1696775833,1782480563);
INSERT INTO highlights VALUES('914697_24_10265-10298','914697',24,'积善之方','但他不用言语教导，而是以身作则来转变大家的思想行为，真是用心良苦。','10265-10298',1,1696775131,1782480563);
INSERT INTO highlights VALUES('914697_24_9264-9321','914697',24,'积善之方','阎王回答：“只要一起念，如果是不正当的念头，就已经犯下了罪过。不一定要真正付诸行动才是过错。一念之差，也是过错。”','9264-9321',1,1696774970,1782480563);
INSERT INTO highlights VALUES('914697_24_5844-5874','914697',24,'积善之方','为善而不求任何回报，就是真善，为了某种目的而行善，就是伪善。','5844-5874',1,1696774240,1782480563);
INSERT INTO highlights VALUES('914697_24_4987-5047','914697',24,'积善之方','都应当仔细辨别。做善事而不去推究做善事的道理，自己以为自己在做好事，很可能反而是在造孽，枉费了一番苦心，却没有任何益处。','4987-5047',1,1696774092,1782480563);
INSERT INTO highlights VALUES('914697_23_3306-3384','914697',23,'改过之法','发愿改正自己的过失，在明处，须有朋友不断督促提醒；在暗处，须有鬼神监督察看。要一心忏悔，昼夜不停，经过一周、两周，乃至一个月、两个月、三个月，一定会有效果。','3306-3384',1,1696771500,1782480563);
INSERT INTO highlights VALUES('914697_23_3083-3124','914697',23,'改过之法','一般而言，最好的方法是从心灵上彻底根治，一旦心念上清净了，你的每一个当下也就清净了','3083-3124',1,1696771457,1782480563);
INSERT INTO highlights VALUES('914697_23_2906-2937','914697',23,'改过之法','一心培植良善的心念，一心去做善良的事情，每时每刻显现的都是正念','2906-2937',1,1696771427,1782480563);
INSERT INTO highlights VALUES('914697_23_2384-2464','914697',23,'改过之法','再比如，以前好发脾气，就要好好想想：别人固然做得不好，但别人做得不好，恰恰应该同情。如果违背情理相互争斗，对自己又有什么好处呢？实在没有什么是值得我们发脾气的。','2384-2464',1,1696771382,1782480563);
INSERT INTO highlights VALUES('914697_23_1645-1674','914697',23,'改过之法','因此必须发奋振作，不要犹犹豫豫，不要消极等待，要立即行动。','1645-1674',1,1696771246,1782480563);
INSERT INTO highlights VALUES('914697_23_1589-1599','914697',23,'改过之法','第三，是要有勇猛心。','1589-1599',1,1696771231,1782480563);
INSERT INTO highlights VALUES('914697_23_1365-1449','914697',23,'改过之法','人世无常，生命非常脆弱，就像佛陀说的，命在一呼一吸之间，一口气接不上，想改过也来不及了。所以，改过要趁早，觉悟要趁早；而一旦觉悟，就一定一刻都不能懈怠，一念都不能放纵。','1365-1449',1,1696771175,1782480563);
INSERT INTO highlights VALUES('914697_23_943-1037','914697',23,'改过之法','第二，要有敬畏心。天地在上，我们很难欺骗鬼神。即使在没有人看到的地方做坏事，头顶的神明，也看得清清楚楚，一一记录；重则让你遭遇各种祸害，轻则让你折损现世的福报，我们怎么可以不存敬畏之心呢？','943-1037',1,1696771123,1782480563);
INSERT INTO highlights VALUES('914697_23_746-763','914697',23,'改过之法','改正过失的方法，第一，要有羞耻心。','746-763',1,1696771120,1782480563);
INSERT INTO highlights VALUES('914697_23_609-624','914697',23,'改过之法','其实至诚到合乎自然，福气就来了','609-624',1,1696771060,1782480563);
INSERT INTO highlights VALUES('914697_22_7796-7809','914697',22,'译文','只因“因循”两字，耽搁一生','7796-7809',1,1696757711,1782480563);
INSERT INTO highlights VALUES('914697_22_7375-7521','914697',22,'译文','当你飞黄腾达的时候，要保持谦卑，要常作落寞之想；即使一帆风顺的时候，也要多多想到艰难险阻；即使丰衣足食的时候，也要想到忍饥挨饿；即使人家对自己很好，也要想想自己有什么值得人家善待的；即使家道兴隆的时候，也要居安思危；即使已经很有学问了，还是要看到更有学问的人，要意识到自己的学问其实远远不够。','7375-7521',1,1696757671,1782480563);
INSERT INTO highlights VALUES('914697_22_5492-5534','914697',22,'译文','现在改为“了凡”，意思是证悟了关于创造自己命运的深刻道理，不想像凡夫那样被命运束缚。','5492-5534',1,1696757384,1782480563);
INSERT INTO highlights VALUES('914697_22_5131-5262','914697',22,'译文','“我们对于命运的态度，应当是勤勉修身而又能安心等待。也就是说，是竭尽所能之后的放下。又可以说，是用出世的心做入世的事业。所谓‘修’，就是自身有过错，都应当彻底改正，永不再犯。所谓‘俟’，就是哪怕有一点点非分的企图、念头，有一点点的迁就、迎合，都应当彻底斩断它们。','5131-5262',1,1696757303,1782480563);
INSERT INTO highlights VALUES('914697_22_4357-4375','914697',22,'译文','乐于做好事的人家，一定会得到许多幸福','4357-4375',1,1696757204,1782480563);
INSERT INTO highlights VALUES('914697_22_3877-3969','914697',22,'译文',unistr('从前的那个你，等于昨天已经死了，从今以后，就从今天开始，诞生一个新的你。这个新的你，一定可以超越固有命数，是再生的义理之身。\u000a“'),'3877-3969',1,1696757112,1782480563);
INSERT INTO highlights VALUES('914697_22_3316-3409','914697',22,'译文','此外，大地上越是污秽之处，越是能够生长作物，水太清了就没有鱼能够生存。我几乎是一个有洁癖的人，所以，这是没有儿子的第一个原因。和气才能化育万物，我却经常发怒，这是我没有儿子的第二个原因。','3316-3409',1,1696756993,1782480563);
INSERT INTO highlights VALUES('914697_21_807-826','914697',21,'四','最好是，只做好事，莫问前程，心安就好。','807-826',1,1696756436,1782480563);
INSERT INTO highlights VALUES('914697_20_1027-1136','914697',20,'三','从佛学或老子、庄子的角度看，《了凡四训》显然不够究竟，也包含着有所求和无所求的深刻悖论。另外，就像中国所有的家训一样，把对安全感的追求，完全寄望于个人的心态、行为，却没有终极与制度层面的思考，不能不说是中国传统的缺憾。','1027-1136',1,1696756138,1782480563);
INSERT INTO highlights VALUES('914697_20_412-482','914697',20,'三','首先是改过，就是矫正自己的行为，有所不为。其次是行善，就是不断地做好事。他分辨何为善何为恶，又细细列了十种善事。最后，讲了保持谦虚的重要性。','412-482',1,1696755968,1782480563);
INSERT INTO highlights VALUES('914697_19_1520-1572','914697',19,'二','那就修炼成与财富名望相匹配的心态、思想、品德和能力。没有什么东西能够真正保佑我们，除了我们自己的所想所为','1520-1572',1,1696755926,1782480563);
INSERT INTO highlights VALUES('914697_19_1141-1213','914697',19,'二','这本《了凡四训》，是他写给自己儿子的。在这本书里，袁了凡通过自身经历，讲述了命运可以透过修行改变，透过什么修行改变呢？透过持续不断地做好事来改变','1141-1213',1,1696755878,1782480563);
INSERT INTO highlights VALUES('914697_19_679-715','914697',19,'二','每个人的命运，其实都是自己造作而成；每个人的福报，也是自己努力追求而得。','679-715',1,1696755644,1782480563);
INSERT INTO highlights VALUES('914697_18_1553-1612','914697',18,'译序','《了凡四训》的价值，正在于把儒家、道家、佛教的思想，与命理风水相融汇，超越了迷信的层面，变成一种操作性很强的生活哲学。','1553-1612',1,1696755596,1782480563);
INSERT INTO highlights VALUES('914697_18_645-695','914697',18,'译序','千百年来，中国人最关心的人生问题，是这样两个切身的功利问题：一个是如何保平安，一个是如何获得功名利禄','645-695',0,1696755486,1782480563);
INSERT INTO highlights VALUES('3300177660_17_4248-4291','3300177660',17,'13 用来做这个就不能做那个','我的解决方案是，尽早教会孩子编程。','4248-4291',0,1782050992,1782480547);
INSERT INTO highlights VALUES('3300177660_17_2532-2556','3300177660',17,'13 用来做这个就不能做那个','想尽一切办法用其他有意义的活动占据孩子的注意力。','2532-2556',0,1782050963,1782480547);
INSERT INTO highlights VALUES('3300177660_22_1369-1426','3300177660',22,'总结','我们甚至可以把那些多巴胺劫匪最常用的工具拿过来为己所用。例如，利用恐惧让自己清醒，或者主动给自己洗脑（通过复述）。','1369-1426',0,1781584674,1782480547);
INSERT INTO highlights VALUES('3300177660_21_4811-4848','3300177660',21,'17 值不值的终极判断标准','除了你自己，没有人能使上劲——因为实际上一切都只发生在你自己的大脑皮层上啊','4811-4848',0,1781584219,1782480547);
INSERT INTO highlights VALUES('3300177660_21_3490-3543','3300177660',21,'17 值不值的终极判断标准','如果你觉得自己实在找不到，请认真阅读《财富的真相》，它会给你一个虽笼统但也非常确定的方向，两个字——生产。','3490-3543',0,1781583916,1782480547);
INSERT INTO highlights VALUES('3300177660_21_3195-3242','3300177660',21,'17 值不值的终极判断标准','把持续建设自己的大脑当作此生唯一重要的任务','3195-3242',0,1781583886,1782480547);
INSERT INTO highlights VALUES('3300177660_21_2776-2868','3300177660',21,'17 值不值的终极判断标准','财富的唯一合理、有效来源就是生产。”所以，注意力的最佳去处是生产，以及为了不断提高生产力的自学——注意是主动的自学，而非被动的学习。','2776-2868',0,1781570133,1782480547);
INSERT INTO highlights VALUES('3300177660_21_2453-2528','3300177660',21,'17 值不值的终极判断标准','做事要有判断标准，与人交往也要有判断标准，标准应该严格，却也如此简单，最后落实就是两个字——值吗？','2453-2528',0,1781570100,1782480547);
INSERT INTO highlights VALUES('3300177660_21_2318-2395','3300177660',21,'17 值不值的终极判断标准','选择交往的人时，这个标准也同样适用且有效。与人交往更需要时间、体力、脑力，甚至金钱，要在轻松的时候一起共度时光，要在艰难的时候相互扶持。问题是：此人值吗？','2318-2395',0,1781570088,1782480547);
INSERT INTO highlights VALUES('3300177660_21_510-603','3300177660',21,'17 值不值的终极判断标准',unistr('时间是最重要的生产资料，甚至是我们的终极生产资料。\u000a我们一生中赚到的所有钱或财富，从本质上来看，全都是从自己的时间里挖出来的。'),'510-603',0,1781545591,1782480547);
INSERT INTO highlights VALUES('3300177660_19_3984-4057','3300177660',19,'15 顺序决定质量','刚开始也许要打一阵子工，但只要有机会，就要想尽办法，彻头彻尾地为自己做事——在个体独立工作的机会极大丰富的今天，不认真考虑这一选项，实在过于可惜。','3984-4057',0,1781545252,1782480547);
INSERT INTO highlights VALUES('3300177660_19_3905-3955','3300177660',19,'15 顺序决定质量','因为打工的时候把工作当自己的事做，相当于在生活中剔除了一个最耗能的多任务——在两个任务之间反复切换。','3905-3955',0,1781545247,1782480547);
INSERT INTO highlights VALUES('3300177660_19_3759-3778','3300177660',19,'15 顺序决定质量','人这辈子一定要为自己做事','3759-3778',0,1781545231,1782480547);
INSERT INTO highlights VALUES('3300177660_19_3632-3692','3300177660',19,'15 顺序决定质量','以学习效果作为衡量工作质量的标准，这样做的好处是，你在不知不觉间调整了工作和学习的重要性顺序——无论如何，都是学习第一。','3632-3692',0,1781545224,1782480547);
INSERT INTO highlights VALUES('3300177660_19_3555-3597','3300177660',19,'15 顺序决定质量','首先，我的建议是以学习的方式工作','3555-3597',0,1781545212,1782480547);
INSERT INTO highlights VALUES('3300177660_18_4093-4134','3300177660',18,'14 冥想不一定最有效最普适','除了冥想，还有很多可以锻炼、维护和提升脑力的方法，核心都一样：尽量长时间地专心致志','4093-4134',0,1781544981,1782480547);
INSERT INTO highlights VALUES('3300177660_18_3261-3343','3300177660',18,'14 冥想不一定最有效最普适','更重要的意义在于它们也同样锻炼脑力。和“一个人能不能跑很久跑很远”展现体力（至少是耐力）一样，“一个人能不能极长时间注意力高度集中”展现的是脑力（同样至少是耐力）。','3261-3343',0,1781544900,1782480547);
INSERT INTO highlights VALUES('3300177660_18_740-822','3300177660',18,'14 冥想不一定最有效最普适','在《学习的真相》课程里，我推荐家长们想尽一切办法带着孩子养成朗读的习惯，甚至将其变成爱好。原理上，朗读是非常接近冥想的活动，因为两者一样，做的人只能注意力高度集中。','740-822',0,1781544767,1782480547);
INSERT INTO highlights VALUES('3300177660_17_4054-4146','3300177660',17,'13 用来做这个就不能做那个','还有一点，运动习惯如果小时候没有养成，成年后是很难重新建立的。小时候爱运动，一辈子爱运动；长大后因为身体不好了想健身，大概率坚持不下去；少数能坚持的，也很大概率因为各种原因受伤而放弃。','4054-4146',0,1781541568,1782480547);
INSERT INTO highlights VALUES('3300177660_17_551-625','3300177660',17,'13 用来做这个就不能做那个','与坏习惯斗争，很多的时候并不见得是优势策略，正像前文所提及的，克制或者控制其实是相当耗费整体脑力的——反过来可能更有效，纵容好习惯会有效地抑制坏习惯','551-625',0,1781541370,1782480547);
INSERT INTO highlights VALUES('3300177660_16_3863-3938','3300177660',16,'12 都不是超人却有可能过人','剩下的少数里，竟然绝大多数是心甘情愿内耗的人，效率根本就提不上来，也不用跟他们比。差不多了吧？你已经属于剩下的极少数了，还比什么？专心做自己的事就好。','3863-3938',0,1781499688,1782480547);
INSERT INTO highlights VALUES('3300177660_16_3817-3862','3300177660',16,'12 都不是超人却有可能过人','因为人群之中绝大多数人是没有自制力的，他们连自己的多巴胺能系统被劫持都不知道，不用跟他们比','3817-3862',0,1781499671,1782480547);
INSERT INTO highlights VALUES('3300177660_16_3197-3289','3300177660',16,'12 都不是超人却有可能过人','很多人终生的压力、纠结甚至抑郁，来自为别人打工而不是为自己做事，这两个东西如果不能重合，那可真的是时时刻刻在天壤之别的任务之间切换来切换去。同它相比，看一眼手机，真值得那么大动干戈吗？','3197-3289',0,1781499541,1782480547);
INSERT INTO highlights VALUES('3300177660_16_1771-1902','3300177660',16,'12 都不是超人却有可能过人','首先要接受一个无论谁都改变不了的事实： INSERT INTO highlights VALUES('3300177660_15_4058-4119','3300177660',15,'11 为自己洗脑也不是不可以','很多人读了那么多书、听了那么多道理之后，还是像原来一样苟活，只是因为他们读书、听话之后，漏掉了这个原本不可或缺的环节：复述','4058-4119',0,1781229314,1782480547);
INSERT INTO highlights VALUES('3300177660_15_2450-2550','3300177660',15,'11 为自己洗脑也不是不可以','短时间内足量重复地向自己复述重要的道理，甚至多角度反复尝试，是真正改变自己的最有效方式，因为你已经用了天下最“狠”的手段：给自己洗脑。','2450-2550',0,1781224313,1782480547);
INSERT INTO highlights VALUES('3300177660_15_2061-2134','3300177660',15,'11 为自己洗脑也不是不可以','整体上看，教师群体就是自我要求相对更高的人群。这种高尚，说实话也不是他们故意的。主要原因在于，他们的日常工作就是讲述道理——准确地讲，是复述道理。','2061-2134',0,1781224134,1782480547);
INSERT INTO highlights VALUES('3300177660_15_1019-1066','3300177660',15,'11 为自己洗脑也不是不可以','久而久之，大脑会选择只相信自己想出来的东西——随着年龄渐长，人会普遍越来越固执，也是这个原因。','1019-1066',0,1781223828,1782480547);
INSERT INTO highlights VALUES('3300177660_15_572-617','3300177660',15,'11 为自己洗脑也不是不可以','到最后，洗脑也好，恐惧也罢，都不过是可供我们选择的工具而已，和医生手里的手术刀没什么区别。','572-617',0,1781223796,1782480547);
INSERT INTO highlights VALUES('3300177660_12_3608-3655','3300177660',12,'8 不可抗拒的诱惑来自哪里',unistr('· 价值观脆弱。\u000a· 价值观缺失。'),'3608-3655',0,1780587196,1782480547);
INSERT INTO highlights VALUES('3300177660_12_3455-3530','3300177660',12,'8 不可抗拒的诱惑来自哪里','因为前额叶皮层并未存有相应的认知，于是即便多巴胺能系统激活了控制回路，那化学反应一路抵达前额叶皮层后却空手而归，什么指令都没有，于是欲望回路被迫开工。','3455-3530',0,1780587188,1782480547);
INSERT INTO highlights VALUES('3300177660_12_3423-3455','3300177660',12,'8 不可抗拒的诱惑来自哪里','他们只是没过脑子，既没用上控制回路，也没用上前额叶皮层，为什么？','3423-3455',0,1780587182,1782480547);
INSERT INTO highlights VALUES('3300177660_12_2704-2808','3300177660',12,'8 不可抗拒的诱惑来自哪里','所以从更深层次来看，问题不在于诱惑太大，而在于缺乏判断，在于比较不够严肃，在于比较得出的结果不够严重……换个说法就是： INSERT INTO highlights VALUES('3300177660_11_3995-4067','3300177660',11,'7 最具价值的稀缺资源是什么','如今我们对未来的形容是“未来呼啸而来”，不仅发展得快，而且速度惊人。一切都指向同一个方向：注意力越来越稀缺，注意力越来越宝贵，注意力越来越重要。','3995-4067',0,1780586698,1782480547);
INSERT INTO highlights VALUES('3300177660_11_2334-2419','3300177660',11,'7 最具价值的稀缺资源是什么','对学习、对进步来说，注意时长低于20分钟等于毫无意义——做任何有意义的思考，有意义的练习，有意义的实践，有意义的复盘和改进，都需要20分钟或更长（甚至长得多）的注意时长。','2334-2419',0,1780586468,1782480547);
INSERT INTO highlights VALUES('3300177660_11_1901-1922','3300177660',11,'7 最具价值的稀缺资源是什么','人与人之间最大的差异是注意力上的贫富差距。','1901-1922',0,1780586436,1782480547);
INSERT INTO highlights VALUES('3300177660_10_4132-4172','3300177660',10,'6 不知不觉失去的都是什么','把自己的注意力像倒垃圾一样扔掉，连走路都要低头看手机的人，和行尸走肉有什么区别？','4132-4172',0,1780586312,1782480547);
INSERT INTO highlights VALUES('3300177660_10_2187-2268','3300177660',10,'6 不知不觉失去的都是什么','当我们讨论一个人注意力是否足够强大的时候，准确地讲，我们讨论的是基于感兴趣和注意之后的有意图，甚至是专注的能力，以及专注的时间长度——我们都知道这个时间越长越好。','2187-2268',0,1780582702,1782480547);
INSERT INTO highlights VALUES('3300177660_10_943-1001','3300177660',10,'6 不知不觉失去的都是什么','结果一不小心看了好几个视频；这时你想起来微信应该有回复消息了，于是切换过去看，发现对方的消息已经是好几分钟之前的了。','943-1001',0,1780549305,1782480547);
INSERT INTO highlights VALUES('3300177660_9_1545-1590','3300177660',9,'5 家里有婴幼儿的应该扔掉电视','但在他们的大脑中，有意义的学习并未发生。注意力全被占据了，大脑却不仅没有发展，反倒因此受损','1545-1590',0,1780549123,1782480547);
INSERT INTO highlights VALUES('3300177660_8_3017-3056','3300177660',8,'4 多巴胺能系统被劫持的恶果','做了并不爽，不做就得难受死。所谓的“爽”，逐渐沦为“摆脱难受的瞬间解脱”而已。','3017-3056',0,1780548728,1782480547);
INSERT INTO highlights VALUES('3300177660_5_3179-3221','3300177660',5,'1 多巴胺不是什么快乐物质','后来，研究人员才发现，快感是由另外三种化学物质——内啡肽、催产素、血清素共同导致的。','3179-3221',0,1780464117,1782480547);
INSERT INTO highlights VALUES('3300070786_10_2396-2473','3300070786',10,'为什么认识新朋友这么难','选择泛滥反而让选择变得更加困难。我们不但把目标放在追求完美伴侣上（这未必是一件坏事），还会成为一个拒绝接受瑕疵的最大化者（这会让我们面临失望，甚至绝望）。','2396-2473',1,1699060939,1782398598);
INSERT INTO highlights VALUES('3300070786_10_2209-2245','3300070786',10,'为什么认识新朋友这么难','而实际上，在轻松自由的社交场合中认识的对象，能更好地加深彼此之间的了解。','2209-2245',1,1699060890,1782398598);
INSERT INTO highlights VALUES('3300070786_9_1888-2028','3300070786',9,'长久的爱情青睐谁','一段关系刚刚开始时，尤其是你想要向对方发出约会邀请乃至前几次约会时，你都可以将自己调整得像一个满足者。这样做会让你有更多的选择，避免一时冲动做出判断，错过一个合适的潜在伴侣。在关系升温的过程中，每个人都应该让自己像个最大化者，只有在一切感觉都良好的情况下，才让关系进一步发展下去。','1888-2028',1,1699060219,1782398598);
INSERT INTO highlights VALUES('3300070786_9_1791-1809','3300070786',9,'长久的爱情青睐谁','“好吧，为了平静的生活，一切随缘”。','1791-1809',1,1699060151,1782398598);
INSERT INTO highlights VALUES('3300070786_8_1887-1905','3300070786',8,'最大化者vs满足者','选择的泛滥正在让更多人变成最大化者。','1887-1905',5,1694963008,1782480563);
INSERT INTO highlights VALUES('3300070786_8_1549-1578','3300070786',8,'最大化者vs满足者','因为他认为选择所涉及的时间、金钱、精力、情绪都需要考虑在内','1549-1578',1,1699059768,1782398598);
INSERT INTO highlights VALUES('3300070786_8_1034-1052','3300070786',8,'最大化者vs满足者','因为满足者追求的是优秀，而不是完美。','1034-1052',1,1699059648,1782398598);
INSERT INTO highlights VALUES('3300070786_7_1846-1949','3300070786',7,'多即是少','我们总是执着地相信世界上存在完美的恋人，可以永远陪在自己身边，做心有灵犀的灵魂伴侣。事实上，谈恋爱和买牛仔裤有很多相似之处，很少有人在一开始就能遇到最合适的人。我们都是在细水长流的日子里相濡以沫，永不分离。','1846-1949',1,1699059507,1782398598);
INSERT INTO highlights VALUES('3300070786_7_985-1031','3300070786',7,'多即是少','更多的选择实际上会降低我们的愉悦感，因为我们担心在被淘汰和放弃的选项中，可能会有自己更喜欢的','985-1031',1,1699059300,1782398598);
INSERT INTO highlights VALUES('3300070786_6_1819-1859','3300070786',6,'第一章 为什么单身的人那么多','太多的选择和没有选择一样糟糕；选择泛滥可能是人们不快乐、不满足，甚至抑郁的根源。','1819-1859',1,1699059091,1782398598);
INSERT INTO highlights VALUES('3300070786_73_6172-6214','3300070786',73,'练习','一场改变人生的浪漫冒险就在眼前，所以，放心大胆地去旅行，不要走马观花，而要好好享受。','6172-6214',5,1696759321,1782480563);
INSERT INTO highlights VALUES('3300070786_73_1761-1829','3300070786',73,'练习','如果你经常幻想你们的恋情能开花结果，请不要再让自己沉浸在这样的幻想中。虽然白日梦会给你带来片刻欢愉，但清醒后的你也会感到愈发痛苦和空虚。','1761-1829',5,1696758970,1782480563);
INSERT INTO highlights VALUES('3300070786_72_1670-1708','3300070786',72,'幸福的归宿','相信自己，让一切慢慢来，做好准备去改变，矢志不渝的真挚爱情就在不远处等着你。','1670-1708',5,1696598930,1782480563);
INSERT INTO highlights VALUES('3300070786_63_870-904','3300070786',63,'建立关系的第一步','其实人类很擅长辨别虚伪的人，所以那些心门紧闭的人难以获得别人的信任。','870-904',5,1696183418,1782480563);
INSERT INTO highlights VALUES('3300070786_32_1313-1325','3300070786',32,'找回自信','5　设定小而现实的目标。','1313-1325',5,1696158716,1782480563);
INSERT INTO highlights VALUES('3300070786_32_1145-1154','3300070786',32,'找回自信','4　明确目标方向。','1145-1154',5,1696158704,1782480563);
INSERT INTO highlights VALUES('3300070786_32_1047-1063','3300070786',32,'找回自信','把它们换成积极的语言，如“我选择','1047-1063',5,1696158700,1782480563);
INSERT INTO highlights VALUES('3300070786_32_952-998','3300070786',32,'找回自信',unistr('3　重构自己的思维。\u000a'),'952-998',5,1696158688,1782480563);
INSERT INTO highlights VALUES('3300070786_32_731-745','3300070786',32,'找回自信','2　不要拿自己和别人做比较。','731-745',5,1696158672,1782480563);
INSERT INTO highlights VALUES('3300070786_32_528-538','3300070786',32,'找回自信','1　不要再贬低自己。','528-538',5,1696158654,1782480563);
INSERT INTO highlights VALUES('3300070786_30_3579-3626','3300070786',30,'是什么阻碍了我们','提升攻略：报复会引起对方回击，进一步激起我们的愤怒，还会让我们和前任纠缠得更久。','3579-3626',5,1696158259,1782480563);
INSERT INTO highlights VALUES('3300070786_30_2921-2964','3300070786',30,'是什么阻碍了我们','沉迷于一段已经逝去的关系会消耗太多的精力，占据太多的空间，让你的生活无法接纳其他事情。','2921-2964',5,1696158207,1782480563);
INSERT INTO highlights VALUES('3300070786_30_2268-2287','3300070786',30,'是什么阻碍了我们','解决争论的好办法是一次只解决一个问题。','2268-2287',5,1696158140,1782480563);
INSERT INTO highlights VALUES('3300070786_30_1967-1986','3300070786',30,'是什么阻碍了我们','何时送女儿回家，成了他们争论不休的问题','1967-1986',5,1696158120,1782480563);
INSERT INTO highlights VALUES('3300070786_26_742-895','3300070786',26,'练习',unistr('1.发生什么事情都无所谓，关键是我如何应对。\u000a2.我不能控制逆境，但我可以控制自己对逆境的反应。\u000a3.我应该努力寻找积极的资源，借助它们克服困难，而不是只关注消极的事情，认定自己做不到。'),'742-895',5,1696128760,1782480563);
INSERT INTO highlights VALUES('3300070786_26_697-710','3300070786',26,'练习','接下来，记住这三条黄金法则','697-710',5,1696128755,1782480563);
INSERT INTO highlights VALUES('3300070786_25_5903-5935','3300070786',25,'今天的单身生活','我们越是不敢面对单身的痛苦和空虚，就越难找到一段充满爱意的关系。','5903-5935',5,1696128705,1782480563);
INSERT INTO highlights VALUES('3300070786_22_2243-2269','3300070786',22,'保持乐观心态','最好的状态是介于温和的悲观主义和适度的乐观主义之间。','2243-2269',5,1695752123,1782480563);
INSERT INTO highlights VALUES('3300070786_21_944-984','3300070786',21,'第三章 漫长的单身','那些与伴侣长相厮守的人往往有三种基本心态：保持乐观，正确处理投射，坦然面对承诺。','944-984',5,1695751905,1782480563);
INSERT INTO highlights VALUES('3300070786_21_907-944','3300070786',21,'第三章 漫长的单身','也许我们不能改变出身和成长环境，但是我们可以调整思维方式，保持乐观的心态。','907-944',5,1695751893,1782480563);
INSERT INTO highlights VALUES('3300070786_17_7662-7706','3300070786',17,'离异家庭后遗症','长期影响：离异家庭的孩子非常渴望爱情，但他们在潜意识里却希望对方背叛自己。','7662-7706',5,1695751714,1782480563);
INSERT INTO highlights VALUES('3300070786_17_6820-6888','3300070786',17,'离异家庭后遗症','年轻人的自我认知是建立在不断试错的基础上的，这样才能确立自己独有的价值、标准以及维系亲密关系的方式，而不是单纯地接受父母曾经的所做所想。','6820-6888',5,1695751605,1782480563);
INSERT INTO highlights VALUES('3300070786_14_602-625','3300070786',14,'过去与未来','我们的恋爱对象在某种程度上就是我们父母的翻版。','602-625',5,1695469552,1782480563);
INSERT INTO highlights VALUES('3300070786_14_373-409','3300070786',14,'过去与未来','如果说亲密关系是一道难题，那么破解这道难题的金钥匙就藏在我们的过往经历中','373-409',5,1695469538,1782480563);
INSERT INTO highlights VALUES('3300070786_13_1952-2021','3300070786',13,'第二章 爱情从认识自己开始','你看待自己以及对待自己的方式恰恰是别人看待你、对待你的方式。换句话说，如果你在内心深处认为自己不值得被爱，那你就会吸引那些根本不爱你的人。','1952-2021',5,1695469310,1782480563);
INSERT INTO highlights VALUES('3300070786_13_551-604','3300070786',13,'第二章 爱情从认识自己开始','吸引力效应，即你是什么样的人，就会吸引什么样的人。换言之，我们在状态不好时很容易吸引那些同样陷入危机的人。','551-604',5,1695469057,1782480563);
INSERT INTO highlights VALUES('3300070786_10_2101-2171','3300070786',10,'为什么认识新朋友这么难','“脆弱的、浅尝辄止的单链关系正在逐渐取代过去密集、多元且成熟的人际关系网络。我们身边的许多社会联系是一次性的、带有特定目的，并以自我为中心。','2101-2171',5,1695468257,1782480563);
INSERT INTO highlights VALUES('3300070786_10_1654-1668','3300070786',10,'为什么认识新朋友这么难','社群社交式团体的特点是排外。','1654-1668',5,1695468177,1782480563);
INSERT INTO highlights VALUES('3300070786_10_1465-1577','3300070786',10,'为什么认识新朋友这么难','社会之所以会发生这样巨大的变化，一方面是因为我们与周围人相处的时间减少了，另一方面则是因为人际关系的互动方式发生了变化，即社群社交多于社区社交。人们往往更愿意和同类型的人相互来往，大家关系亲密且彼此信任，形成社群社交式团体。','1465-1577',5,1695468174,1782480563);
INSERT INTO highlights VALUES('3300070786_8_665-760','3300070786',8,'最大化者vs满足者','追求完美固然是好事，但最大化者总是心存疑虑，即便已经将很满意的东西带回家，他们仍会忍不住纠结：“也许我应该再多逛几家店，这样才能货比三家”或“如果我去大一点的商场，会不会找到更满意的牛仔裤”','665-760',5,1694945162,1782480563);
INSERT INTO highlights VALUES('3300070786_7_1316-1337','3300070786',7,'多即是少','‘为什么快打烊的时候，女孩们都变漂亮了？’','1316-1337',5,1694945057,1782480563);
INSERT INTO highlights VALUES('44000669_37_2070-2174','44000669',94,'我们为什么相爱相杀','爱情的一个基本要义是，放不下。为什么要结婚？就是因为你爱这个人，如果你不跟他在一起的话，你就不知道他的未来，他以后会遇到什么，所以你心里特别放不下，这个时候你唯一的最好的选择就是跟他结婚，共同度过以后的岁月。','6235-6339',NULL,1662209117,1782480566);
INSERT INTO highlights VALUES('44000669_35_1188-1232','44000669',94,'我们为什么相爱相杀','但生活不是天上掉下来的，而是去创造的，为了创造美好的生活，你的一切资源都要有非常好的配置','3175-3219',NULL,1662205739,1782480566);
INSERT INTO highlights VALUES('44000669_35_1050-1158','44000669',94,'我们为什么相爱相杀','其实爱上一个人就是爱上一种生活。一个人最可悲的就是一辈子没有生活过，一辈子都在追逐生活的条件，要挣钱、要大房子，虽然最终得到了，一辈子的时间也过去了。真正的恋爱是两个人共同打开生活，在对方身上看到自己非常喜欢的生活。','3038-3146',NULL,1662205721,1782480566);
INSERT INTO highlights VALUES('44000669_35_916-934','44000669',94,'我们为什么相爱相杀','能“相杀”的人肯定是看到了对方的价值','407-425',NULL,1662205707,1782480566);
INSERT INTO highlights VALUES('44000669_33_558-671','44000669',94,'我们为什么相爱相杀',unistr('其实爱上一个人就是爱上一种生活。\u000a喜欢一个人，跟他在一起，你要看他到底在干什么，他在建设一种什么样的生活。爱情是两个人一起去建设一种生活，两个人都是生活的建设者。'),'528-639',NULL,1662205249,1782480566);
INSERT INTO highlights VALUES('44000669_31_813-850','44000669',93,'谈女性写作','很多人的叛逆是假叛逆，是本能的反应，并没有吸收到新东西，仍然有很强的依赖性','5848-5885',NULL,1662204704,1782480566);
INSERT INTO highlights VALUES('44000669_30_1560-1584','44000669',93,'谈女性写作','写作其实是一个人的生活方式，不只是个简单的动作。','4319-4343',NULL,1662141457,1782480566);
INSERT INTO highlights VALUES('44000669_25_2592-2625','44000669',92,'谈女性文化','真正的生命是流动的，像水一样，它有无限丰富的精神，是一种体验过程。','7678-7711',NULL,1662096614,1782480566);
INSERT INTO highlights VALUES('44000669_25_2245-2376','44000669',92,'谈女性文化','一个人有过逆流而上的人生，才算真正体验过生活。在农业社会中很多人都希望风调雨顺，平平顺顺，这样的生活是最庸常的，就像一条鱼在同一个水层游动，还没有更多机会思考生命的深刻议题时，一生就这样过去了。人需要过一种逆流而上的生活，这种生活尽管艰苦，但可以打开生命的维度。','7332-7463',NULL,1662096567,1782480566);
INSERT INTO highlights VALUES('44000669_23_2852-2936','44000669',92,'谈女性文化','波伏瓦特别感叹，我们不是生来是女人，而是成长为女人、社会的第二性，是被整个社会塑造扭曲，成为一名女性。所以女性，尤其从心理方面来说，不是天然的，而是被塑造的、被规定的。','3094-3178',NULL,1661734441,1782480566);
INSERT INTO highlights VALUES('44000669_21_3814-3907','44000669',91,'躺平与幸福','以上这些，就是我们现在的年轻人躺平之后要思考探索的，未来我们到底该以怎样的方式度过一生？不是消极地躺平再躺平，而是生命中暗含一种积极的探索精神，大家躺了半天躺不住了，跳起来去干自己的事。','7703-7796',NULL,1661703151,1782480566);
INSERT INTO highlights VALUES('44000669_21_3048-3161','44000669',91,'躺平与幸福','我一无所知，年轻人要保持这样的自省。不要封闭，不要自以为是。归零时代就是一个伟大的开锁时代、伟大的学习时代。所以我们今天的年轻人要探索新的价值，要去打开一个新的世界，不能固守成见、故步自封，一定要像孩子一样天真，面向时代学习。','6914-7027',NULL,1661703064,1782480566);
INSERT INTO highlights VALUES('44000669_21_795-959','44000669',91,'躺平与幸福','如何联结自己的父母？我们能做的是赶紧访问一下自己的爷爷奶奶、爸爸妈妈。有的人一辈子都不知道自己的爷爷奶奶经历了什么，爸爸妈妈小时候经历了什么，对自己的来路不清楚。知晓过去而展望未来，这是一代又一代人的价值传递。50年后的中国历史若要书写出来，一定会对爷爷奶奶、爸爸妈妈这辈人的评价至高，因为他们完成了中国的工业化。这是多么难啊！','4615-4779',NULL,1661702764,1782480566);
INSERT INTO highlights VALUES('44000669_17_536-578','44000669',90,'谈人格','好人的一个标准是我们自己的内心感觉是否幸福，另外一个标准是有没有对别人造成大的伤害。','7607-7649',NULL,1661680129,1782480566);
INSERT INTO highlights VALUES('44000669_16_1775-1907','44000669',90,'谈人格','但实际上不是这样，永泽是很有追求的，他要自由的青春，他要寻找自己生活的价值，但初美把他当作唯一，当作永生，初美的爱对永泽来说是巨大的压力，他觉得可能要用自由来交换这份感情，他不能确定他跟初美间的这份爱是不是根深蒂固的，所以他只好通过一种残忍的方式去维护自己的自由。','7089-7221',NULL,1661680004,1782480566);
INSERT INTO highlights VALUES('44000669_16_589-640','44000669',90,'谈人格','第二种是黑格尔特别强调我们要做的思维的人——一个有思考的人，能够深切地理解自己，知道自己在做什么的人。','5879-5930',NULL,1661678949,1782480566);
INSERT INTO highlights VALUES('44000669_14_1515-1590','44000669',90,'谈人格','这两个杀人的人想让大家阻止自己，但是在现代社会里，人都处在一种摇摆中，个体聚集在一起就有看戏的心理。我们不能说人都变坏了，而是社会本身就有残酷的一面。','1734-1809',NULL,1661509633,1782480566);
INSERT INTO highlights VALUES('44000669_12_1680-1750','44000669',89,'谈工作','一个人在尝试的过程中一定要有百分之百的真诚、百分之百的韧性，而不能浅尝辄止。因为在没有深入一定程度的时候，我们无法得知自己和一件事情的联系。','11994-12064',NULL,1661509331,1782480566);
INSERT INTO highlights VALUES('44000669_12_1317-1358','44000669',89,'谈工作','很多人一辈子都没有移动到自己最恰当的位置上，因为缺乏面向这个广阔世界的接触和尝试。','11633-11674',NULL,1661509294,1782480566);
INSERT INTO highlights VALUES('44000669_12_735-801','44000669',89,'谈工作','将来会有大量的新产业诞生，传统行业的人力得到解放。那么，人解放后做什么呢？社会可能会产生微娱乐，而各种新行业、新创意都需要人的参与。','11027-11093',NULL,1661509230,1782480566);
INSERT INTO highlights VALUES('44000669_11_2359-2430','44000669',89,'谈工作','陶渊明归隐的核心是“种豆南山下，草盛豆苗稀”，而非“采菊东篱下，悠然见南山”，那只是知识分子特有的一种情怀。人生最重要的是回归土地，回归耕耘。','10369-10440',NULL,1661509156,1782480566);
INSERT INTO highlights VALUES('44000669_11_1300-1357','44000669',89,'谈工作','这是一个拼图时代，没有谁比谁高，自己认真生活，把体会到的事实分享给大家，同时也不要求所有人、事、物都符合自己的期待','9288-9345',NULL,1661509049,1782480566);
INSERT INTO highlights VALUES('44000669_11_1358-1414','44000669',89,'谈工作','这时候每个人才开始真正活得有尊严、有价值。一个人的价值是在差异性里体现自己的创造性，这是年轻人需要去理解的部分。','9346-9402',NULL,1661509047,1782480566);
INSERT INTO highlights VALUES('44000669_10_4192-4275','44000669',89,'谈工作','一个群体聚集起来，不管是文化生产还是经济生产，它是不同活法的人聚在一起，但如果把人限制在某一种活法中，那整个民族的细胞不会活跃起来，整个空间压抑久了就会出现各种问题。','6980-7063',NULL,1661509014,1782480566);
INSERT INTO highlights VALUES('44000669_10_3005-3026','44000669',89,'谈工作','生产力的根本说到底还是人的创造力、想象力。','5720-5741',NULL,1661423680,1782480566);
INSERT INTO highlights VALUES('44000669_10_1622-1726','44000669',89,'谈工作','19世纪工业运动之后，人们好不容易才争取到8小时工作制。年轻人在8小时之外，他的生命应该去欣赏艺术、谈恋爱，如果这些时间被侵占了，等于让他丧失了生命旅程真正的完整性，这是很残酷的事情，于道义上也是很不应该的。','4291-4395',NULL,1661423515,1782480566);
INSERT INTO highlights VALUES('44000669_10_1518-1592','44000669',89,'谈工作','场景置换也是时代置换，所以要相信年轻人，如果不摸鱼就坏事了，说明他固化了。他有这个状态，说明他还在思考，在摸鱼中探索，还算是清醒的人、有真生命的人。','4188-4262',NULL,1661423503,1782480566);
INSERT INTO highlights VALUES('44000669_9_2564-2659','44000669',89,'谈工作','做任何工作，你历经千难万苦，最后让你不放弃的，实际上还是人，当然这工作首先是你自己喜欢的。和对的人一起做对的事，这可以作为一个衡量标准。但现在很多年轻人选工作，首选工资高，其实方向都走错了。','2876-2971',NULL,1661423397,1782480566);
INSERT INTO highlights VALUES('44000669_9_1870-1911','44000669',89,'谈工作','佛教里面四圣谛中的一个就是苦谛，苦谛形容人必须经历的各种苦。每一代人有每一代人的苦','2159-2200',NULL,1661423300,1782480566);
INSERT INTO highlights VALUES('44000669_7_2971-3043','44000669',88,'谈自我','如何衡量自我价值？其实很简单：每天都反思一下自己，看看在知识上有没有增加？文化视野的宽度有没有扩大？情感的含量有没有更加丰富？行动性有没有增强？','412-484',NULL,1661423130,1782480566);
INSERT INTO highlights VALUES('44000669_6_1058-1175','44000669',88,'谈自我','青年要认识自我，不能坐在房子里，坐井观天，往往需要在不完美的探索中认识自己，有痛苦，有欢乐，于痛苦中发现自己活着，于欢乐中发现自己还很平庸，在这个过程中，才逐渐知道自己热爱什么样的生活，跟什么样的世界联系在一起。这就是所谓青春的激情。','3988-4105',NULL,1661422875,1782480566);
INSERT INTO highlights VALUES('44000669_5_2535-2689','44000669',88,'谈自我','今天的年轻人，往往自我分裂。他们的生存方式、劳动方式是农业民族定居式的，要风调雨顺，具有因果逻辑的直接性，延续的是农业民族种瓜得瓜、种豆得豆的传统思维；但现在势态下的我们又有很多游牧民族的特点，需要我们“逐水草而居”，像找工作，大有这个特点；全球化阶段，我们又有海洋民族的特点，必须去探索、开拓，去乘风破浪。','2742-2896',NULL,1661422775,1782480566);
INSERT INTO highlights VALUES('44000669_5_2149-2182','44000669',88,'谈自我','人类发展到今天，青年一定要明白一点，我们是站在巨人的肩膀上发展的。','2331-2364',NULL,1661422729,1782480566);
INSERT INTO highlights VALUES('44000669_5_1551-1602','44000669',88,'谈自我','一个人照亮自己、发现自己，一定要知道自己在社会和历史舞台上处于什么位置，而不是做一个漫无目的的自然人。','1736-1787',NULL,1661422668,1782480566);
INSERT INTO highlights VALUES('44000669_5_930-954','44000669',88,'谈自我','所以在认识自己这个问题上，首先要认识本然的自我。','1090-1114',NULL,1661422575,1782480566);
INSERT INTO highlights VALUES('44000669_3_4360-4429','44000669',87,'序言 高黎贡，所有这一切的真正起点','也就在那个时刻，我明白了幸福与快乐不是一回事儿：快乐是轻松欣喜，实现心之所欲；而幸福，那是一路艰辛的奋斗，是生命的展开，是一步一步地活过。','4123-4192',NULL,1661422531,1782480566);
INSERT INTO highlights VALUES('44000669_3_4429-4502','44000669',87,'序言 高黎贡，所有这一切的真正起点','唯有劳动者，才能打开幸福的内核，播撒未来的种子。这信念朴素而简单，但在现代生活无时无刻不经受着冲击，滚滚历史八面来风，如何在纷纭中走自己的人生路？','4192-4265',NULL,1661422531,1782480566);
INSERT INTO highlights VALUES('44000669_3_4327-4360','44000669',87,'序言 高黎贡，所有这一切的真正起点','那一刻我深切地体会到，自己种出来的果实最香甜，其他一切都显得虚浮。','4090-4123',NULL,1661422530,1782480566);
INSERT INTO highlights VALUES('44000669_3_3070-3136','44000669',87,'序言 高黎贡，所有这一切的真正起点','原来那些“绿叶”是一树密密麻麻的碧色毛虫。看来是它们受不了满地的药水气息，到树上避难了。这是我人生中看到的最惊悚的画面，至今历历在目','2893-2959',NULL,1661422529,1782480566);
INSERT INTO highlights VALUES('44000669_3_3184-3233','44000669',87,'序言 高黎贡，所有这一切的真正起点','这记忆伴随着回城后的精神成长，让我深深地知道，我们为什么需要改革开放，为什么不能让这样的苦难重现。','3007-3056',NULL,1661422529,1782480566);
INSERT INTO highlights VALUES('534286_24_14721-14738','534286',59,'关于轻断食的一切答疑','每八到十天断食一天，而不是一周两天','14361-14378',NULL,1657897314,1782480567);
INSERT INTO highlights VALUES('534286_34_395-417','534286',69,'食物热量表(Calorie Counter)','食物热量表（Calorie Counter）','339-360',NULL,1657552387,1782480567);
INSERT INTO highlights VALUES('534286_25_935-965','534286',60,'轻断食的未来展望','采用间歇式限制热量摄取的人，减肥效果不输给天天控制热量的人。','893-923',NULL,1657552100,1782480567);
INSERT INTO highlights VALUES('534286_24_14938-15047','534286',59,'关于轻断食的一切答疑','恰恰相反，想断食就立刻行动吧。轻断食可能会延长你的寿命，调节你的食欲，协助你减轻体重。这些好处很快就会得到，通常在你断食的第一周就能看出效果。这全部都能让你的老年更健康苗条，更长寿，更少看医生，精力更充沛，更不易生病。','14569-14678',NULL,1657552025,1782480567);
INSERT INTO highlights VALUES('534286_24_14539-14651','534286',59,'关于轻断食的一切答疑',unistr('Q：我已经够苗条了，但也想要得到轻断食的健康效益，有什么办法吗？\u000aA：如果你已经拥有合理的满意体重，仍然可以好好断食，但在非断食日多摄取一些高热量的食物。'),'14179-14291',NULL,1657552017,1782480567);
INSERT INTO highlights VALUES('534286_24_11732-11746','534286',59,'关于轻断食的一切答疑','已经极为苗条的人也不要断食。','11453-11467',NULL,1657516356,1782480567);
INSERT INTO highlights VALUES('534286_24_2022-2044','534286',59,'关于轻断食的一切答疑','，蔬菜和豆类都很棒，是你应该选择的断食日餐点','1933-1955',NULL,1657456578,1782480567);
INSERT INTO highlights VALUES('534286_24_829-876','534286',59,'关于轻断食的一切答疑','依据生活及身体的转变调整你的断食计划。但不要动不动取消断食日，否则可能故态复萌。宽容，但坚定。','776-823',NULL,1657452431,1782480567);
INSERT INTO highlights VALUES('534286_23_2078-2115','534286',58,'顺利执行轻断食的12个秘诀','抗拒食欲至少10分钟，办得到的话就15分钟，看看饥饿会不会消退（通常会）。','1977-2014',NULL,1657452182,1782480567);
INSERT INTO highlights VALUES('534286_23_1942-1975','534286',58,'顺利执行轻断食的12个秘诀','重要的是，非断食日吃东西的时候就别计算热量了。你还有更好的事可做。','1850-1883',NULL,1657451183,1782480567);
INSERT INTO highlights VALUES('534286_23_3752-3832','534286',58,'顺利执行轻断食的12个秘诀','。嘴巴干是脱水的最后一个征兆，而不是第一个，因此在身体抱怨之前喝水吧，也要知道，喝水是安抚空肚皮的速效方法，至少能暂时满足肚皮。喝水也能避免你把口渴误认为饥饿。','3614-3694',NULL,1657451103,1782480567);
INSERT INTO highlights VALUES('534286_23_457-474','534286',58,'顺利执行轻断食的12个秘诀','1.在开始前测量体重，计算BMI。','401-418',NULL,1657440528,1782480567);
INSERT INTO highlights VALUES('534286_20_618-666','534286',55,'轻断食的效果','十周应该可以减少约四公斤半的脂肪，胜过典型的低热量饮食。关键是，你可以长期不反弹。','560-608',NULL,1657440503,1782480567);
INSERT INTO highlights VALUES('534286_20_499-524','534286',55,'轻断食的效果','大致上，每个断食日可以减少约半公斤。','450-468',NULL,1657440461,1782480567);
INSERT INTO highlights VALUES('534286_19_1000-1027','534286',54,'坚持轻断食：找出适合你自己的模式','关键在于，经过耐心及意志力，认识到你可以撑到明天的早餐','932-959',NULL,1657440399,1782480567);
INSERT INTO highlights VALUES('534286_19_831-910','534286',54,'坚持轻断食：找出适合你自己的模式','没有特制的低脂食品，没有额外的禁令，没有复杂的规则，没有其他重点，更没有故弄玄虚或稀奇古怪的做法。不用随时随地都说“不行，我在减肥，我不能吃。”','763-835',NULL,1657440389,1782480567);
INSERT INTO highlights VALUES('534286_19_1775-1832','534286',54,'坚持轻断食：找出适合你自己的模式','轻断食的人仍然可以从食物得到满足，他们的生活仍然精彩，没有小题大做，没有拼命节食，没有自我鞭笞。减肥不费吹灰之力。','1704-1761',NULL,1657437819,1782480567);
INSERT INTO highlights VALUES('534286_18_914-987','534286',53,'将轻断食融入日常生活','。在展开断食前，先在日记写下你的体重、BMI、目标体重，等着看到自己的进展。','858-915',NULL,1657436169,1782480567);
INSERT INTO highlights VALUES('534286_18_825-856','534286',53,'将轻断食融入日常生活','忙碌的一天能让断食日飞逝，慵懒的日子则往往会让时间以龟速前进。','769-800',NULL,1657436140,1782480567);
INSERT INTO highlights VALUES('534286_17_3534-3588','534286',52,'吃什么，吃多少，如何开始','最符合这项原则的食物是蛋白质含量高但升糖指数（glycemic index, GI）低的食物。','3435-3481',NULL,1657435559,1782480567);
INSERT INTO highlights VALUES('534286_17_1171-1225','534286',52,'吃什么，吃多少，如何开始','记住饮食要多多变换花样：不同的质地、色香味、咔吱咔吱的口感。只要讨好了嘴巴，你便不至于对断食的辛苦皱眉头了。','1131-1185',NULL,1657433159,1782480567);
INSERT INTO highlights VALUES('534286_14_1985-2127','534286',49,'开始轻断食：我的个人经历','体脂肪是用脂肪占总体重的百分比例计算的。体重计是以一种叫作阻抗（impedance）的系统为你测量体脂。它会发出微小的电流通过你的身体，然后测量电阻。肌肉及其他组织的导电性比脂肪高，如此便能估计体脂的比例。女性的体脂通常比男性高。男性的体脂肪如果超过25%，就算过重。女性则是30%。','1905-2047',NULL,1657432885,1782480567);
INSERT INTO highlights VALUES('534286_13_7422-7512','534286',48,'轻断食的回报有哪些','医生们总是建议血糖高的病人要摄取健康的饮食，但效果通常微乎其微。间歇式断食说不定可以让全世界人民的健康出现翻天覆地的大逆转。','7348-7429',NULL,1657432662,1782480567);
INSERT INTO highlights VALUES('534286_13_5995-6161','534286',48,'轻断食的回报有哪些','胰岛素能控制血糖，它从血液中汲取血糖，转化为稳定的糖原，储放在肝脏或肌肉中，视需求而释出使用。但很少有人知道胰岛素也能控制脂肪。它抑制脂肪分解作用（lipolysis），此作用可用来分解囤积的体脂肪。同时，它会强迫脂肪细胞接收并存放血液中的脂肪。也就是说，胰岛素过高也会让人变胖。高浓度的胰岛素会增加脂肪的囤积，浓度低则会消耗脂肪。','5930-6096',NULL,1657432521,1782480567);
INSERT INTO highlights VALUES('534286_13_5284-5341','534286',48,'轻断食的回报有哪些','间歇式断食不光是有益大脑，也能改善身体的其他状态，诸如心脏、血液、患癌风险，健康效果都可以测量出来。','5213-5263',NULL,1657432474,1782480567);
INSERT INTO highlights VALUES('534286_13_4718-4755','534286',48,'轻断食的回报有哪些','一周断食两天只要持续几周，BDNF浓度便会开始上升，抑制焦虑感，改善情绪。','4656-4693',NULL,1657432415,1782480567);
INSERT INTO highlights VALUES('534286_13_3642-3662','534286',48,'轻断食的回报有哪些','在食物匮乏的时候，人就必须变得聪明机灵。','3574-3594',NULL,1657432367,1782480567);
INSERT INTO highlights VALUES('534286_13_2380-2431','534286',48,'轻断食的回报有哪些','海马是大脑记忆不可或缺的区域。在核磁共振影像中，经常走路的人跟整天坐着不动的人相比，大脑平均年轻两岁。','2312-2363',NULL,1657432340,1782480567);
INSERT INTO highlights VALUES('534286_13_1396-1432','534286',48,'轻断食的回报有哪些','断食可以改善情绪，保护大脑，避免记忆力下降及认知能力变差。','1332-1361',NULL,1657432309,1782480567);
INSERT INTO highlights VALUES('534286_13_473-560','534286',48,'轻断食的回报有哪些','简单来说，轻断食的做法是：你在一星期中选2天摄取500大卡或600大卡，其他5天的饮食不要严重过量，便能稳定减轻体重。','436-514',NULL,1657432277,1782480567);
INSERT INTO highlights VALUES('534286_12_5421-5462','534286',47,'轻断食的前身','与天天节食相比，间歇式断食看起来是另一种安全又可行的减肥方法，体重也能维持轻盈。”','5360-5401',NULL,1657432267,1782480567);
INSERT INTO highlights VALUES('534286_12_3824-3889','534286',47,'轻断食的前身','克丽丝塔认为主要原因是执行的难易度。可以偶尔摄取高脂饮食的志愿者，比只准吃低脂食物的人更能遵守规定，纯粹是因为他们觉得伙食好多了。','3776-3841',NULL,1657432016,1782480567);
INSERT INTO highlights VALUES('534286_12_3055-3126','534286',47,'轻断食的前身','在断食日，男性一天可摄取约600大卡，女性是500大卡。在她的断食规划中，所有的热量一次摄取完毕，通常是午餐。在进食日，则是爱吃什么就吃什么。','3016-3087',NULL,1657423929,1782480567);
INSERT INTO highlights VALUES('534286_11_2487-2551','534286',46,'轻断食的研究初衷','“少量毒素有益健康”的说法鲜活地描述了毒物兴奋效应（hormesis）的理论：适当的压力或毒素可以使一个人或任何生物变得更强壮。','2451-2515',NULL,1657380300,1782480567);
INSERT INTO highlights VALUES('534286_11_1166-1254','534286',46,'轻断食的研究初衷','我们每天多摄取约180大卡，大部分来自含牛奶的饮料、果汁、碳酸饮料，我们的正餐也吃得更多，平均每天多出120大卡。也就是说，我们没有因为吃点心而减少正餐的分量，食欲反而更旺盛。','1124-1212',NULL,1657380228,1782480567);
INSERT INTO highlights VALUES('534286_11_419-517','534286',46,'轻断食的研究初衷','对大部分的野生动物来说，三餐不济是生活的常态。远古的人类祖先很少一天进食四五次。他们猎捕动物，狼吞虎咽，优哉游哉，然后长时间没有食物。我们的身体及基因，就是在食物匮乏但偶尔可以大吃的环境中进化的。','377-475',NULL,1657380112,1782480567);
INSERT INTO highlights VALUES('534286_8_1831-1885','534286',43,'咪咪·史宾赛的动机：女性的观点','这二十年来我接触过的减肥方法中，只有轻断食让我在瘦下来之后不反弹。至于抗衰老的健康益处，更是得来全不费工夫。','1752-1806',NULL,1657253497,1782480567);
INSERT INTO highlights VALUES('534286_8_1242-1288','534286',43,'咪咪·史宾赛的动机：女性的观点','执行轻断食六个月以来，我的精力更充沛，皮肤弹性更好，肤质更剔透，对生活更热情。','1175-1214',NULL,1657253460,1782480567);
INSERT INTO highlights VALUES('534286_7_1930-2061','534286',42,'麦克尔·莫斯利的动机：男性的观点','因此，我很开心地发现了间歇式断食，也就是降低热量摄取，但只偶尔为之。假如科学研究没有错，间歇式断食便具备限制热量的好处，却没有那么痛苦。','1875-1988',NULL,1657189300,1782480567);
INSERT INTO highlights VALUES('534286_7_866-919','534286',42,'麦克尔·莫斯利的动机：男性的观点','隐藏性肥胖，亦即外表瘦瘦的，体脂肪却很高。内脏脂肪是最危险的脂肪，它会包覆内脏，增加心脏病及糖尿病的风险。','815-868',NULL,1657166035,1782480567);
INSERT INTO highlights VALUES('35666063_11_582-655','35666063',11,'第6讲 化剑式：保险策略','当投资者已持有标的股票，但又担心短期市场向下的风险，可买入认沽期权为现货多头保险。若卖空股票但担心短期市场上涨时，可买入认购期权对冲现货空头风险。','582-655',NULL,1654577766,1782480567);
INSERT INTO highlights VALUES('35666063_10_9608-9609','35666063',10,'第5讲 短剑式：卖方策略','C','9608-9609',NULL,1653716724,1782480567);
INSERT INTO highlights VALUES('35666063_10_9204-9205','35666063',10,'第5讲 短剑式：卖方策略','A','9204-9205',NULL,1653716693,1782480567);
INSERT INTO highlights VALUES('35666063_10_8971-8972','35666063',10,'第5讲 短剑式：卖方策略','B','8971-8972',NULL,1653716679,1782480567);
INSERT INTO highlights VALUES('35666063_10_7021-7061','35666063',10,'第5讲 短剑式：卖方策略','期权卖方的风险点主要有四个：保证金风险、巨额亏损风险、流动性风险与行权交割风险。','7021-7061',NULL,1653716547,1782480567);
INSERT INTO highlights VALUES('35666063_10_4193-4221','35666063',10,'第5讲 短剑式：卖方策略','个是买卖价差较窄，另一个是盘口的报价数量较大，深度较深。','4193-4221',NULL,1653716243,1782480567);
INSERT INTO highlights VALUES('35666063_10_4028-4067','35666063',10,'第5讲 短剑式：卖方策略','因为有时做卖方，不一定真的是看趋势，而是找到一份保费特别高的保险，然后卖掉它。','4028-4067',NULL,1653716101,1782480567);
INSERT INTO highlights VALUES('35666063_10_3490-3553','35666063',10,'第5讲 短剑式：卖方策略','期权市场中，有一个很重要的指标叫做“隐含波动率”，大家可以把该指标想象成“期权的市盈率”，用来刻画该期权的价格是否被明显高估。','3490-3553',NULL,1653716033,1782480567);
INSERT INTO highlights VALUES('35666063_10_2814-2869','35666063',10,'第5讲 短剑式：卖方策略','卖出认购期权属于三级投资者的交易权限，适用于后市不涨的市场环境，收益有限，最多为全部的权利金，理论上亏损无限。','2814-2869',NULL,1653715979,1782480567);
INSERT INTO highlights VALUES('35666063_10_1424-1508','35666063',10,'第5讲 短剑式：卖方策略','与期货的买卖双方都要缴纳保证金不同，期权的买方就像投保人，付了保险费，只有权利，没有义务，所以不需要缴纳保证金；期权的卖方，就像保险公司，承担了义务，才需要缴纳保证金。','1424-1508',NULL,1653715880,1782480567);
INSERT INTO highlights VALUES('35666063_10_1194-1221','35666063',10,'第5讲 短剑式：卖方策略','通过卖出认沽期权我们可以实现间接降低买入标的股票的成本','1194-1221',NULL,1653715817,1782480567);
INSERT INTO highlights VALUES('35666063_10_1038-1078','35666063',10,'第5讲 短剑式：卖方策略','不看涨不等于看跌。因为不看涨可能是小跌、大跌，也可能是横盘震荡，这些都叫做不看涨','1038-1078',NULL,1653715695,1782480567);
INSERT INTO highlights VALUES('35666063_10_959-982','35666063',10,'第5讲 短剑式：卖方策略','所以对于期权的卖方来说，预期肯定和买方是相反的','959-982',NULL,1653715669,1782480567);
INSERT INTO highlights VALUES('35666063_10_639-708','35666063',10,'第5讲 短剑式：卖方策略','短仓（义务仓，short option）指卖出期权、收入权利金，并负有义务的一方。期权卖方需要缴纳保证金，需要防范保证金、强行平仓等风险。','639-708',NULL,1653715650,1782480567);
INSERT INTO highlights VALUES('35666063_9_7723-7725','35666063',9,'第4讲 长剑式：买方策略','B.','7723-7725',NULL,1653677561,1782480567);
INSERT INTO highlights VALUES('35666063_9_7452-7454','35666063',9,'第4讲 长剑式：买方策略','C.','7452-7454',NULL,1653677519,1782480567);
INSERT INTO highlights VALUES('35666063_9_7057-7059','35666063',9,'第4讲 长剑式：买方策略','A.','7057-7059',NULL,1653677496,1782480567);
INSERT INTO highlights VALUES('35666063_9_706-730','35666063',9,'第4讲 长剑式：买方策略','平值期权的价格波动较大，应密切关注，做好风险控制','706-730',NULL,1653574703,1782480567);
INSERT INTO highlights VALUES('35666063_7_11387-11388','35666063',7,'第3讲 独剑式：单腿策略','C','11387-11388',NULL,1653315133,1782480567);
INSERT INTO highlights VALUES('35666063_7_11127-11128','35666063',7,'第3讲 独剑式：单腿策略','D','11127-11128',NULL,1653315080,1782480567);
INSERT INTO highlights VALUES('35666063_7_10678-10679','35666063',7,'第3讲 独剑式：单腿策略','A','10678-10679',NULL,1653315008,1782480567);
INSERT INTO highlights VALUES('35666063_7_9709-9743','35666063',7,'第3讲 独剑式：单腿策略','卖方的盈亏等于开仓时刻权利金的成交金额减去平仓时刻权利金的成交金额。','9709-9743',NULL,1653314937,1782480567);
INSERT INTO highlights VALUES('35666063_7_5452-5499','35666063',7,'第3讲 独剑式：单腿策略','在期权市场上，同一份期权的买卖双方属于零和博弈，买方到期所赚的钱就是卖方所亏损的钱，反之亦然。','5452-5499',NULL,1653309360,1782480567);
INSERT INTO highlights VALUES('35666063_7_2652-2674','35666063',7,'第3讲 独剑式：单腿策略','看大涨买认购，看大跌买认沽。”','2652-2674',NULL,1653308306,1782480567);
INSERT INTO highlights VALUES('35666063_7_423-625','35666063',7,'第3讲 独剑式：单腿策略',unistr('买认购，盼股涨，下跌可能全亏光。\u000a卖认购，怕股涨，风险无限细思量。\u000a买认沽，盼股跌，上涨或许皆湮灭。\u000a卖认沽，怕股跌，损失巨大空悲切。'),'423-625',NULL,1653307926,1782480567);
INSERT INTO highlights VALUES('35666063_6_8744-8746','35666063',6,'第2讲 论剑式：合约要素','C.','8744-8746',NULL,1653307892,1782480567);
INSERT INTO highlights VALUES('35666063_6_9216-9218','35666063',6,'第2讲 论剑式：合约要素','A.','9216-9218',NULL,1653307892,1782480567);
INSERT INTO highlights VALUES('35666063_6_8982-8984','35666063',6,'第2讲 论剑式：合约要素','B.','8982-8984',NULL,1653307892,1782480567);
INSERT INTO highlights VALUES('35666063_5_10729-10731','35666063',5,'第1讲 拔剑式：基本概念','C.','10729-10731',NULL,1653306526,1782480567);
INSERT INTO highlights VALUES('35666063_5_10504-10506','35666063',5,'第1讲 拔剑式：基本概念','D.','10504-10506',NULL,1653306514,1782480567);
INSERT INTO highlights VALUES('35666063_5_10119-10120','35666063',5,'第1讲 拔剑式：基本概念','B','10119-10120',NULL,1653306500,1782480567);
INSERT INTO highlights VALUES('35666063_5_7941-8004','35666063',5,'第1讲 拔剑式：基本概念','现在有了期权，就可以构造诸如卖出跨式组合这样的策略获得小幅盘整市场下的收益，或者买入跨式组合实现可能大涨或大跌条件的盈利机会。','7941-8004',NULL,1653294132,1782480567);
INSERT INTO highlights VALUES('35666063_5_6098-6133','35666063',5,'第1讲 拔剑式：基本概念','期权价格与股价波动率相关，可以用来管理波动性风险，这是期货没有的功能。','6098-6133',NULL,1653293668,1782480567);
INSERT INTO highlights VALUES('35666063_5_5963-5985','35666063',5,'第1讲 拔剑式：基本概念','认购期权可以为融券卖出的股票（卖空）进行保险','5963-5985',NULL,1653293648,1782480567);
INSERT INTO highlights VALUES('35666063_5_5730-5782','35666063',5,'第1讲 拔剑式：基本概念','在我国股票交易不能“T+0”的情况下，投资者还可以通过买入认沽期权，降低当日买入股票无法当日卖出的损失。','5730-5782',NULL,1653293598,1782480567);
INSERT INTO highlights VALUES('35666063_5_5613-5689','35666063',5,'第1讲 拔剑式：基本概念','例如，投资者持有标的股票时，担心股价下跌造成损失，就可以买入认沽期权进行保险，以锁定未来最低卖出价。当股价下跌后，投资者仍然可以按照约定的价格卖出股票。','5613-5689',NULL,1653293532,1782480567);
INSERT INTO highlights VALUES('35666063_5_2052-2098','35666063',5,'第1讲 拔剑式：基本概念','认购期权其实就是拥有未来买入某个东西的权利。','2052-2098',NULL,1653293225,1782480567);
INSERT INTO highlights VALUES('35666063_5_1384-1429','35666063',5,'第1讲 拔剑式：基本概念','股票期权就好比是投资股票的保险，期权的买方就相当于投保人，期权的卖方呢，就相当于保险公司。','1384-1429',NULL,1653293140,1782480567);
INSERT INTO highlights VALUES('35666063_4_704-712','35666063',4,'第1小时','实值、平值和虚值','704-712',NULL,1653239791,1782480567);
INSERT INTO highlights VALUES('37462156_10_9371-9398','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','各地的人群在互动，这种互动的重要性与自然环境不相上下。','9281-9308',NULL,1661614115,1782480566);
INSERT INTO highlights VALUES('37462156_10_4791-4838','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','福山就把丹麦当作一个标本来分析解剖，从中发现了构成良好政治秩序的三个要素：国家、法治和问责制。','4735-4782',NULL,1661604757,1782480566);
INSERT INTO highlights VALUES('37462156_10_1553-1608','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','而福山就是当代极为罕见的普遍主义者之一，他最根本的观点，如果用一句话来概括，那就是人类政治的发展是殊途同归的。','1527-1582',NULL,1661604132,1782480566);
INSERT INTO highlights VALUES('37462156_10_1190-1262','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','而“人同此心，心同此理”就代表了普遍主义的立场，相信人类的共同之处要比相互间的差异更为根本，因此人类最终会走向融合，追求大同小异的理想政治秩序。','1167-1239',NULL,1661603806,1782480566);
INSERT INTO highlights VALUES('37462156_10_1095-1160','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','“非我族类，其心必异”代表了一种特殊主义的立场，认为生活在不同环境中的群体，必定有各自特殊的文化，也一定会建立自己特殊的政治秩序。','1073-1138',NULL,1661603790,1782480566);
INSERT INTO highlights VALUES('37462156_10_1008-1049','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','“非我族类，其心必异”，还有一句来自南宋哲学家陆九渊，他说“人同此心，心同此理”。','987-1028',NULL,1661603766,1782480566);
INSERT INTO highlights VALUES('37462156_10_838-900','37462156',42,'人类政治的发展会殊途同归吗？——解读福山《政治秩序的起源》','人类的政治将何去何从？各种不同的政体究竟是永久保持彼此之间的差异，还是会最终走向融合？这可能是世界政治中最大最难的问题之一。','818-880',NULL,1661603743,1782480566);
INSERT INTO highlights VALUES('37462156_9_5495-5579','37462156',41,'民粹主义的本质——米勒《什么是民粹主义？》中译本导读','各种民粹主义在道德宣称的垄断性上具有形式相似性，但其内容的合法性来源却相当不同，有些诉诸超验的宗教信仰，有些标举传统，有些则依据“国家”或“革命”等世俗观念的话语建构。','5912-5996',NULL,1661396404,1782480566);
INSERT INTO highlights VALUES('37462156_9_1881-1997','37462156',41,'民粹主义的本质——米勒《什么是民粹主义？》中译本导读','米勒认为，民粹主义的“界定性特征”（defining feature）不是反对精英，而是对“人民”代表性的垄断：民粹主义者们宣称，他们，且只有他们才代表“真正的人民”及其意志和利益。这种对政治代表性的道德垄断才是民粹主义的独特之处。','2082-2198',NULL,1661395943,1782480566);
INSERT INTO highlights VALUES('37462156_8_10500-10595','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','政治家必须具备卓越的判断力，对复杂的局面和形势，既要有深入其中、抵达内在理解的能力，又要有抽身而出、拉开距离、冷眼旁观的能力。政治家需要清醒的审时度势，保持良好的分寸感，这是相当难得的品质。','10436-10531',NULL,1661338245,1782480566);
INSERT INTO highlights VALUES('37462156_8_10130-10157','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','政治家在人格上应当具备三种品质：热情、责任感和判断力。','10068-10095',NULL,1661338207,1782480566);
INSERT INTO highlights VALUES('37462156_8_9955-9982','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','官僚多半是“靠政治而生存”，而政治家是“为政治而生存”','9894-9921',NULL,1661338197,1782480566);
INSERT INTO highlights VALUES('37462156_8_8374-8524','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','第一是实用性的价值，学术能够帮助人们“计算”，能够通过证据和分析来辨析状况，使人更好地理解自身的处境，从而有效地权衡利弊和控制行为。第二，学术具有思想方法的价值，能促进思维训练，扩展思考的工具。这两种价值浅显易懂，韦伯只是点到为止。最后，他阐述了学术的第三种，也是最重要的益处，在于使人头脑“清明”。','8321-8471',NULL,1661337998,1782480566);
INSERT INTO highlights VALUES('37462156_8_8345-8373','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','指出，学术虽然不具有人们以往相信的意义，但仍然有三种价值','8292-8320',NULL,1661337995,1782480566);
INSERT INTO highlights VALUES('37462156_8_7226-7320','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','首先是否定性的论述，就是论证学术并没有人们通常以为的那些价值和意义。在揭示了种种错觉和误会之后，韦伯转向了肯定性的论述，试图最终阐明学术还可能有什么意义，为何还能作为“志业”值得我们奉献。','7176-7270',NULL,1661337720,1782480566);
INSERT INTO highlights VALUES('37462156_8_6192-6263','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','韦伯实际上不动声色地转移了话题，从“如何做学术”转向了“为何要做学术”的发问，最后切入根本性的大问题：在现代世界中，学术本身究竟还有什么意义？','6146-6217',NULL,1661337522,1782480566);
INSERT INTO highlights VALUES('37462156_8_5439-5488','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','黑夜是等不过去的，在黑夜里，我们仍然应当做自己能做的事情，这是激发和鼓励一种踏实而审慎的积极态度。','5399-5448',NULL,1661304716,1782480566);
INSERT INTO highlights VALUES('37462156_8_5001-5107','37462156',40,'祛魅时代的学术与政治——韦伯志业演讲导读','因此，韦伯同时要与“狂热”和“绝望”两面作战，他试图在各种蛊惑人心的喧哗之中发出冷峻的告诫，引导人们走向清醒，认清现代世界的特征和自身的处境，从而在良好的现实感中寻求有限的希望，在审慎的判断中付诸积极进取的努力。','4963-5069',NULL,1661302005,1782480566);
INSERT INTO highlights VALUES('37462156_7_4163-4201','37462156',39,'世俗时代的死亡问题','我们的时代还远不是一个可以落实在自满的无神论的时代。动荡将持续不断地浮现”。','4135-4173',NULL,1661301443,1782480566);
INSERT INTO highlights VALUES('37462156_7_3621-3796','37462156',39,'世俗时代的死亡问题','“你回想自己的全部生活历史，那些幸福的时刻、那些阳光下的旅行，都是被沐浴在对另一些岁月、另一些旅行的感受之中，这些曾经的体验也因此在当下此刻变得鲜活起来。这就是美好的重归，是真正的（尼采所说的）‘永恒轮回’（Ewige Wiederkehr）：不只是似曾相识之事再现，而是那些时刻中永恒事物的重归。这就是普鲁斯特所要捕捉的，而不只是回忆永远逝去的爱。','3594-3769',NULL,1661249949,1782480566);
INSERT INTO highlights VALUES('37462156_7_3338-3441','37462156',39,'世俗时代的死亡问题','因为爱在本质上渴望永恒或永存（eternity）。深刻的爱，伴随着生命的兴衰枯荣，将过去与现在凝结在一起，将时间“汇聚起来”，生成一种丰厚的意义。而死亡是一个终极性的破裂，驱散了爱所凝聚的时间，驱散了永存。','3313-3416',NULL,1661249862,1782480566);
INSERT INTO highlights VALUES('37462156_7_1774-1814','37462156',39,'世俗时代的死亡问题','宗教的社会功能也发生了重要变化，突出体现在宗教基本上退出了政治领域（政教分离）。','1754-1794',NULL,1661230261,1782480566);
INSERT INTO highlights VALUES('37462156_7_912-930','37462156',39,'世俗时代的死亡问题','宗教社会到现代世俗社会的演变，出版之','895-913',NULL,1661228196,1782480566);
INSERT INTO highlights VALUES('37462156_6_8628-8701','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','只有通过将自我的构成理解为关系性的，理解为对超越自我之共同背景的依赖，我们才能恰当地理解和实践个人自主性的理想，才有可能克服对本真性的误解和滥用。','9652-9725',NULL,1661215777,1782480566);
INSERT INTO highlights VALUES('37462156_6_7934-8158','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','那个单独的“自我”实际上并没有独自赋予或创造价值，那些看似高度自主的价值决定，在背后往往是有渊源和来路的，是由许多经历和故事造就的，是在关系中形成的。价值判断需要依据价值尺度，而价值尺度不可能由“自我”来发明创造，我们只能“选用”和“改造”价值尺度，这正是关系性的自主性观念所揭示的结构性规范限制。我们各自（选用）的价值尺度可能并不一致，我们对具体事物的价值判断可能发生严重分歧，但这不意味着我们的价值是完全主观的、不受约束的或是由自我任意决定的。','8849-9073',NULL,1661215563,1782480566);
INSERT INTO highlights VALUES('37462156_6_4793-4948','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','在世界祛魅之后，人们不再能够将自己与超越自我的更大视野相伴相随，于是产生了某种失落：“不再有更高的目标感，不再感觉到有某种值得以死相趋的东西。”[6]现代人获得了前所未有的自由，却也陷入了空前的意义迷失。这成为现代文化深刻的困境。','5323-5536',NULL,1661215053,1782480566);
INSERT INTO highlights VALUES('37462156_6_4277-4315','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','其次，现代政治制度的出现是针对这样一个背景——预先存在作为权利承担者的个人。','4748-4786',NULL,1661214907,1782480566);
INSERT INTO highlights VALUES('37462156_6_4125-4171','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','首先是一种信念，认为所有关于社会的思考都应当始于个人，而社会应当为个人之间的互惠利益而存在。','4596-4642',NULL,1661214897,1782480566);
INSERT INTO highlights VALUES('37462156_6_4401-4424','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','第三，政治社会的组织原则是为了维护个人的权利。','4872-4895',NULL,1661214882,1782480566);
INSERT INTO highlights VALUES('37462156_6_4469-4526','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','第四，平等地向所有个体确保他们的权利、自由和互惠利益。','4940-4967',NULL,1661214876,1782480566);
INSERT INTO highlights VALUES('37462156_6_3437-3448','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','一是“个人主义的转向”','3910-3921',NULL,1661214535,1782480566);
INSERT INTO highlights VALUES('37462156_6_3363-3376','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','一是“人类中心主义的转向”','3836-3849',NULL,1661214522,1782480566);
INSERT INTO highlights VALUES('37462156_6_2959-3055','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','由此可见，在这样一种文化视域中，所谓“自我”，首先处在整体的关系结构之中，个人“嵌入”在一个比自己更大的宇宙秩序整体中，并根据在其中占据的恰当位置，来获得自我认同、行为规范、价值感和生活意义。','3196-3292',NULL,1661214257,1782480566);
INSERT INTO highlights VALUES('37462156_6_2000-2026','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','现代人的错误，便是认为这种对个体的理解是理所当然的。','1975-2001',NULL,1661165352,1782480566);
INSERT INTO highlights VALUES('37462156_6_1631-1690','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','在西方哲学中，“本真性”有更为特定的含义：人忠实于自己的内心，而不盲从于外在的压力与影响，这是应对外部世界的一种方式。','1607-1666',NULL,1661165310,1782480566);
INSERT INTO highlights VALUES('37462156_6_996-1140','37462156',38,'没有幻觉的个人自主性——（查尔斯·泰勒《本真性的伦理》中译本导读）','泰勒力图阐明，基于个人自主性的现代文化源自一种历史性的深刻转变，人们由此获得了一种崭新的“自我理解”，这带来了空前膨胀的个人权利和自由。这是现代性的重要成就，但同时也造成了严峻的困境，突出体现在现代社会价值标准的混乱、道德规范的失序以及人生意义的迷失。这是所谓“现代性之隐忧”的要害所在。','977-1121',NULL,1661165205,1782480566);
INSERT INTO highlights VALUES('37462156_5_2363-2485','37462156',37,'我的非经典阅读','《思想家——当代哲学的创造者们》（三联书店1987年翻译出版）。这是英国BBC广播公司为知识大众制作的哲学家访谈节目的文本，由布莱恩·麦基（Bryan Magee）采访包括伯林、马尔库塞、艾耶尔、奎因、乔姆斯基和普特南等14位著名思想家和学者。','2333-2455',NULL,1661165035,1782480566);
INSERT INTO highlights VALUES('37462156_5_2069-2091','37462156',37,'我的非经典阅读','《理想的冲突——西方社会中变化着的价值观念》','2039-2061',NULL,1661165009,1782480566);
INSERT INTO highlights VALUES('37462156_3_2850-2877','37462156',35,'自序 在新的地平线上','并告诫公众：不要看重他的善良意图，而只应当判断他的论点','2798-2825',NULL,1661164679,1782480566);
INSERT INTO highlights VALUES('29373667_12_975-1005','29373667',12,'第2章 组合与结构','技术是机械艺术的集合，它是一种文化用来运转经济和社会的资源。','975-1005',5,1722753321,1782480556);
INSERT INTO highlights VALUES('29373667_11_2295-2319','29373667',11,'本书的主题','技术，曾经的生产手段，正在成为一种“化学物质”。','2295-2319',5,1722753211,1782480556);
INSERT INTO highlights VALUES('29373667_11_2168-2210','29373667',11,'本书的主题','现代技术不仅是稍具独立的生产方式的集合，而且已经进化成创造经济结构与功能的开放语言。','2168-2210',5,1722753191,1782480556);
INSERT INTO highlights VALUES('29373667_11_899-935','29373667',11,'本书的主题','第三条基本原理是，所有的技术都会利用或开发某种（通常是几种）效应或现象。','899-935',5,1722753015,1782480556);
INSERT INTO highlights VALUES('29373667_11_806-825','29373667',11,'本书的主题','其次，技术的每个组件自身也是缩微的技术','806-825',5,1722752968,1782480556);
INSERT INTO highlights VALUES('29373667_11_744-770','29373667',11,'本书的主题','第一条我已经谈到过：技术（所有的技术）都是某种组合。','744-770',5,1722752937,1782480556);
INSERT INTO highlights VALUES('29373667_11_644-663','29373667',11,'本书的主题','本书尤其想创建的是关于技术的进化理论。','644-663',5,1722752907,1782480556);
INSERT INTO highlights VALUES('29373667_11_725-744','29373667',11,'本书的主题','我将基于三条基本原理逐步建构这一理论。','725-744',5,1722752904,1782480556);
INSERT INTO highlights VALUES('29373667_10_4826-4857','29373667',10,'组合进化','我们必须要关注人类，特别是人类思维在这一组合过程中的巨大作用。','4826-4857',5,1722752849,1782480556);
INSERT INTO highlights VALUES('29373667_10_4347-4393','29373667',10,'组合进化','我认为，这些超出组合之外的其它事物，就是持续地捕捉新的自然现象，并为了特定目的而利用这些现象','4347-4393',5,1722686884,1782480556);
INSERT INTO highlights VALUES('29373667_10_3784-3819','29373667',10,'组合进化','该进化机制可以简述如下：之前的技术形式会被作为现在原创技术的组成部分。','3784-3819',5,1722686425,1782480556);
INSERT INTO highlights VALUES('29373667_10_1724-1757','29373667',10,'组合进化','熊彼特问的是：经济能否在没有外界因素的情况下，完全从内部变革它自身','1724-1757',5,1722686145,1782480556);
INSERT INTO highlights VALUES('29373667_9_3618-3659','29373667',9,'技术的进化','你可以对20世纪30年代的半导体线圈进行任何你喜欢的改变，但是你永远不可能得到雷达','3618-3659',5,1722604738,1782480556);
INSERT INTO highlights VALUES('29373667_9_3217-3424','29373667',9,'技术的进化','即一种突变的、根本的新颖性，成了技术进化论者最主要的障碍。￼根本性的新技术的出现，即相当于生物的新物种的出现，还不能被解释和说明。','3217-3424',5,1722604652,1782480556);
INSERT INTO highlights VALUES('29373667_9_780-1084','29373667',9,'技术的进化','另一个含义是指，某类事物的所有对象联结在一起的过程，而其联结纽带也在于它们诞降（descent）自相同的先前对象的集合￼。这是进化的完整含义，也正是我所谓的进化（evolution）。','780-1084',5,1722604365,1782480556);
INSERT INTO highlights VALUES('29373667_8_2945-2994','29373667',8,'缺失了本质的技术','为什么绝少有工程师尝试去奠定他们领域的理论基础，他的回答是：“工程师只喜欢那些他们能解决的问题。”','2945-2994',5,1722604198,1782480556);
INSERT INTO highlights VALUES('29373667_8_1827-1989','29373667',8,'缺失了本质的技术',unistr('技术思想前沿\u000a关于技术的理论之所以缺失，是因为：\u000a•　技术一直处于科学的阴影之中。\u000a•　那些认真思考技术的人大多数都是社会科学家和哲学家。'),'1827-1989',5,1722604123,1782480556);
INSERT INTO highlights VALUES('29373667_7_2698-2750','29373667',7,'第1章 问题','然而，作为人类，我们实际上不应该和技术如此紧密地结合，而是应该和其他什么东西融合得更为紧密，那就是自然。','2698-2750',5,1722601523,1782480556);
INSERT INTO highlights VALUES('29373667_7_2221-2278','29373667',7,'第1章 问题','技术的循环：技术总是进行这样的循环，为解决老问题去采用新技术，新技术又引起新问题，新问题的解决又要诉诸更新的技术。','2221-2278',5,1722601437,1782480556);
INSERT INTO highlights VALUES('29373667_6_5418-5490','29373667',6,'前言 技术的追问','他们每次都从最熟悉的地方开始探险之旅，迅速到达一个新的地方，偶然会回到以前曾被别人占领过的地方。我的这次探险也不例外。我们会遇到一些从前的旅人。','5418-5490',5,1722600019,1782480556);
INSERT INTO highlights VALUES('29373667_6_2668-2729','29373667',6,'前言 技术的追问','经济是从满足我们需要的生产性的方法、法规和组织性安排当中产生出来的，因此经济是从捕捉现象及之后的技术组合过程中发展起来的。','2668-2729',5,1722562368,1782480556);
INSERT INTO highlights VALUES('29373667_6_2551-2586','29373667',6,'前言 技术的追问','每个技术都是建立在某个现象，以及从该现象挖掘出来的某种或几种效应之上的','2551-2586',5,1722562309,1782480556);
INSERT INTO highlights VALUES('29373667_6_1949-1963','29373667',6,'前言 技术的追问','那就意味着技术自己创造了自己','1949-1963',5,1722562125,1782480556);
INSERT INTO highlights VALUES('29373667_6_1578-1876','29373667',6,'前言 技术的追问','我意识到，新技术并不是无中生有地被“发明”出来的，我看到的技术的例子都是从先前已有的技术中被创造（被建构、被聚集、被集成）而来的。换句话说，技术是由其他的技术构成的，技术产生于其他技术的组合（combinations）￼。','1578-1876',5,1722562084,1782480556);
INSERT INTO highlights VALUES('29373667_6_1530-1577','29373667',6,'前言 技术的追问','实际上吸引我的并不是那些直接与收益递增相关的技术，而是在技术呈现之初，那些看起来模模糊糊的状态','1530-1577',5,1722562078,1782480556);
INSERT INTO highlights VALUES('29373667_6_1174-1248','29373667',6,'前言 技术的追问','技术，是新的技术产品和生产工艺（例如，早期的汽车）通过被应用和被采用而获得改善，之后再获得进一步的应用和采用，在被采用的过程中形成正反馈或收益递增。','1174-1248',5,1722561984,1782480556);
INSERT INTO highlights VALUES('29373667_6_965-1010','29373667',6,'前言 技术的追问','在某种意义上，经济不过是通过明智地组织技术来满足我们的需求，故而它也会随技术的进化而进化。','965-1010',5,1722561840,1782480556);
INSERT INTO highlights VALUES('29373667_6_946-961','29373667',6,'前言 技术的追问','经济很大程度上是从技术中产生的','946-961',5,1722561829,1782480556);
INSERT INTO highlights VALUES('29373667_5_2254-2292','29373667',5,'推荐序二 打开“技术黑箱”的一个新尝试','这样一来，所有技术产生于已有技术，也就是说，已有技术的组合使新技术成为可能。','2254-2292',5,1722434507,1782480556);
INSERT INTO highlights VALUES('29373667_5_1981-2051','29373667',5,'推荐序二 打开“技术黑箱”的一个新尝试','“自然现象是技术赖以产生的必不可少的资源。所有的技术，无论是多么简单或者多么复杂的技术，实际上都是应用了一种或几种现象之后乔装打扮出来的。”','1981-2051',5,1722434473,1782480556);
INSERT INTO highlights VALUES('29373667_5_1939-1981','29373667',5,'推荐序二 打开“技术黑箱”的一个新尝试','布莱恩的“现象”是自然现象或“自然效应”，所有技术都建立在对这种自然现象的利用之上。','1939-1981',5,1722434451,1782480556);
INSERT INTO highlights VALUES('29373667_5_1554-1592','29373667',5,'推荐序二 打开“技术黑箱”的一个新尝试','技术的最基本结构包含一个用来执行基本功能的主集成和一套支持这一集成的次集成。','1554-1592',5,1722434383,1782480556);
INSERT INTO highlights VALUES('29373667_5_1537-1553','29373667',5,'推荐序二 打开“技术黑箱”的一个新尝试','结构首先是指技术是由零部件构成的','1537-1553',5,1722434373,1782480556);
INSERT INTO highlights VALUES('29373667_5_1527-1536','29373667',5,'推荐序二 打开“技术黑箱”的一个新尝试','技术有其自身的结构','1527-1536',5,1722434367,1782480556);
INSERT INTO highlights VALUES('29373667_4_2649-2684','29373667',4,'推荐序一 路径依赖性：人口、经济、技术','技术，阿瑟指出，不是科学的副产品，而是或许恰好相反，科学是技术的副产品','2649-2684',5,1722433263,1782480556);
INSERT INTO highlights VALUES('29373667_4_2367-2414','29373667',4,'推荐序一 路径依赖性：人口、经济、技术','人的行为依赖于他们过去的全部行为。注意，是“依赖”而不是“由此被决定”，也不是“完全不依赖”。','2367-2414',5,1722433195,1782480556);
INSERT INTO highlights VALUES('29373667_4_1785-1822','29373667',4,'推荐序一 路径依赖性：人口、经济、技术','任何主流，包括经济学主流，都不可避免地压迫和排斥人类的独立精神和自由思想。','1785-1822',5,1722433062,1782480556);
INSERT INTO highlights VALUES('29373667_4_770-790','29373667',4,'推荐序一 路径依赖性：人口、经济、技术','只知道一件大事的刺猬和知道许多小事的狐狸','770-790',5,1722432861,1782480556);
INSERT INTO highlights VALUES('3300151958_13_5818-5842','3300151958',13,'第一章 无善无恶心之体——阳明心学的世界观','朱熹觉得，“理”在“气”先，有“理”才有“气”。','5818-5842',0,1764641742,1782480549);
INSERT INTO highlights VALUES('3300151958_13_3878-3919','3300151958',13,'第一章 无善无恶心之体——阳明心学的世界观','“和”是中华文明的精髓，王阳明之前的儒家世界观认为，世界浓缩成一个字，那就是“和”','3878-3919',0,1764641284,1782480549);
INSERT INTO highlights VALUES('3300151958_7_15658-15724','3300151958',7,'第二章 王阳明如何做到知行合一之南赣剿匪','人面对事情时如果有侥幸心理，必定失败。即使真有人能躲过，但大多数人一定躲不过，而谢志山毫无悬念地属于大多数人里的一员。','15658-15724',0,1760059003,1782480549);
INSERT INTO highlights VALUES('3300151958_7_5423-5505','3300151958',7,'第二章 王阳明如何做到知行合一之南赣剿匪','不要迷信自己的经验。世间一切瞬息万变，拿从前的经验对待新出现的事物是胶柱鼓瑟，尤其是当你面对新对手时，经验就是道教的丹药，会神不知鬼不觉地置你于死地。','5423-5505',0,1759314437,1782480549);
INSERT INTO highlights VALUES('3300151958_7_3826-3858','3300151958',7,'第二章 王阳明如何做到知行合一之南赣剿匪','所以，十家牌法的功利性就在于，它把每个人都变成了神经兮兮的间谍。','3826-3858',0,1759314250,1782480549);
INSERT INTO highlights VALUES('3300151958_6_64747-64836','3300151958',6,'第一章 为什么悟道的是王阳明','用儒家语境来说，禅宗注重的是修养（尊德性），而几乎没有学问（道问学）。','64747-64836',1,1755100040,1782480549);
INSERT INTO highlights VALUES('3300151958_6_64275-64312','3300151958',6,'第一章 为什么悟道的是王阳明','真理已在我心中，我去实践，只是去验证这个真理，其实最终目的就是磨炼我们的心','64275-64312',1,1755099907,1782480549);
INSERT INTO highlights VALUES('3300151958_6_64112-64134','3300151958',6,'第一章 为什么悟道的是王阳明','‘在心上用功’后，必须去实践。','64112-64134',1,1755099892,1782480549);
INSERT INTO highlights VALUES('3300151958_6_64042-64066','3300151958',6,'第一章 为什么悟道的是王阳明','禅宗说了‘人人都有佛性’后就枯坐，什么都不管了。','64042-64066',1,1755099885,1782480549);
INSERT INTO highlights VALUES('3300151958_6_63860-63902','3300151958',6,'第一章 为什么悟道的是王阳明','王阳明回答：“你的心能知是非善恶，一个恶念发动时就克掉它，一个善念流行时就保持它。”','63860-63902',1,1755099867,1782480549);
INSERT INTO highlights VALUES('3300151958_6_61614-61677','3300151958',6,'第一章 为什么悟道的是王阳明','陆九渊的心学有点“粗糙”，“粗糙”的原因就是陆九渊不太注重实践（事上练）','61614-61677',0,1755015528,1782480549);
INSERT INTO highlights VALUES('3300151958_6_56185-56191','3300151958',6,'第一章 为什么悟道的是王阳明','申明亭是黑榜','56185-56191',0,1754530182,1782480549);
INSERT INTO highlights VALUES('3300151958_6_56130-56137','3300151958',6,'第一章 为什么悟道的是王阳明','旌善亭是光荣榜','56130-56137',0,1754530174,1782480549);
INSERT INTO highlights VALUES('3300151958_6_53767-53857','3300151958',6,'第一章 为什么悟道的是王阳明','王阳明仍然坚信这样一点：普通平民在什么时代都是弱势群体，弱势群体每天烧香求佛保佑不被政府欺压都来不及，哪里还有心情找政府的麻烦。如果他们真反常地时常找政府麻烦，那肯定是政府有问题。','53767-53857',0,1754496860,1782480549);
INSERT INTO highlights VALUES('3300151958_6_52900-52910','3300151958',6,'第一章 为什么悟道的是王阳明','江西吉安府庐陵县县令','52900-52910',0,1754496701,1782480549);
INSERT INTO highlights VALUES('3300151958_6_51593-51647','3300151958',6,'第一章 为什么悟道的是王阳明','而我提倡静坐，是因为现在的人心浮气躁，静坐能让他们把心沉静下来，我并没有让人一味静坐去获取真理，那不是正路。','51593-51647',0,1754492009,1782480549);
INSERT INTO highlights VALUES('3300151958_6_50496-50536','3300151958',6,'第一章 为什么悟道的是王阳明','由此看来，王阳明在龙场的身份不仅是个驿站站长，还是个教育家，偶尔还客串下政治家。','50496-50536',0,1754445719,1782480549);
INSERT INTO highlights VALUES('3300151958_6_49065-49268','3300151958',6,'第一章 为什么悟道的是王阳明','王阳明给出了四点。第一，立志。就是要打定主意，下定做圣贤的决心；第二，勤学。做圣贤必须勤奋，努力学习知识和提升品德；第三，改过。有错就要改，绝不姑息；第四，责善。也就是在朋友之间要以责备的方式劝善。','49065-49268',0,1754445411,1782480549);
INSERT INTO highlights VALUES('3300151958_6_48607-48643','3300151958',6,'第一章 为什么悟道的是王阳明','宇宙中最真的孝，就是不让父母担心。知道了这个，你就知道怎么去孝顺父母了。','48607-48643',0,1754412071,1782480549);
INSERT INTO highlights VALUES('3300151958_6_36763-36781','3300151958',6,'第一章 为什么悟道的是王阳明','“百年臣小悲何极，夜夜江涛泣子胥”。','36763-36781',0,1754226022,1782480549);
INSERT INTO highlights VALUES('3300151958_6_25092-25118','3300151958',6,'第一章 为什么悟道的是王阳明','道二教本身没有问题，有问题的是弘扬佛道二教的那些人。','25092-25118',0,1754223925,1782480549);
INSERT INTO highlights VALUES('3300151958_6_22947-22990','3300151958',6,'第一章 为什么悟道的是王阳明','原来俗世才是最亲切的','22947-22983',0,1754221207,1782480549);
INSERT INTO highlights VALUES('3300151958_6_21638-21656','3300151958',6,'第一章 为什么悟道的是王阳明','却指明了让王阳明重回儒学中的心学领域','21638-21656',0,1754221035,1782480549);
INSERT INTO highlights VALUES('3300151958_6_19996-19999','3300151958',6,'第一章 为什么悟道的是王阳明','九华山','19996-19999',0,1754221005,1782480549);
INSERT INTO highlights VALUES('3300151958_6_17891-17932','3300151958',6,'第一章 为什么悟道的是王阳明','因为王阳明在去世后，从“伯”跳到了“侯”，终明一代，文臣有如此殊荣，唯王阳明一人。','17891-17932',0,1754220330,1782480549);
INSERT INTO highlights VALUES('3300151958_6_12414-12447','3300151958',6,'第一章 为什么悟道的是王阳明','格个竹子都这么费劲，天下万物那么多，我们格到死，连圣贤的影都看不到','12414-12447',0,1754219573,1782480549);
INSERT INTO highlights VALUES('3300151958_6_16084-16136','3300151958',6,'第一章 为什么悟道的是王阳明','始终不能坚持唯一志向，而是在各个领域间跳来跳去，也没有循序渐进地去研究一个领域，所以什么成果都没有获得。','16084-16136',0,1754219526,1782480549);
INSERT INTO highlights VALUES('3300151958_5_7290-7349','3300151958',5,'序章 心学诞生的前夜','理学家是道貌岸然的伪君子，说一套做一套，理学宗师们规定的那些道德要求，都是让别人用的，理学信奉者只是讲师，不是实践者。','7290-7349',0,1754131723,1782480549);
INSERT INTO highlights VALUES('3300151958_5_7141-7166','3300151958',5,'序章 心学诞生的前夜','程颐还算是合格的，他的一生极端严肃，几乎没有笑过。','7141-7166',0,1754131686,1782480549);
INSERT INTO highlights VALUES('3300151958_5_4763-4851','3300151958',5,'序章 心学诞生的前夜','孟子说人性本善，荀子说人性本恶，告子则说，人性可善可恶。理学家则说，孟子说得对，荀子说得也有道理，而告子给我们提了个醒。所以，我们应该时刻注意自己的心，一定要“存天理灭人欲”。','4763-4851',0,1754130827,1782480549);
INSERT INTO highlights VALUES('3300151958_5_4128-4308','3300151958',5,'序章 心学诞生的前夜','为天地立心（为社会重建精神价值），为生民立命（为民众确立生命意义），为往圣继绝学（为前圣继承已绝之学统），为万世开太平（为万世开拓太平之基业）。','4128-4308',0,1754130740,1782480549);
INSERT INTO highlights VALUES('3300151958_5_3960-3989','3300151958',5,'序章 心学诞生的前夜','南宋时，朱熹继承了程颐的思想，而陆九渊则继承了程颢的思想。','3960-3989',0,1754127707,1782480549);
INSERT INTO highlights VALUES('3300151958_5_3781-3838','3300151958',5,'序章 心学诞生的前夜','我当时在饭局上，怀里有美女，心中就有美女，我现在回家了，怀里没有美女，心中也没有了，而你直到现在，心中还有美女？”','3781-3838',0,1754127681,1782480549);
INSERT INTO highlights VALUES('3300151958_5_3377-3437','3300151958',5,'序章 心学诞生的前夜','一个人如果饿了非不吃饭，困了非不睡觉，这也是“人欲”，虽然它不是不合理的欲望，却是不合理的行为，因为违反了人的生理规律。','3377-3437',0,1754127638,1782480549);
INSERT INTO highlights VALUES('3300151958_5_3321-3376','3300151958',5,'序章 心学诞生的前夜','饿了吃饭是“天理”，但非要吃鱼翅鲍鱼，这就是“人欲”；困了睡觉是“天理”，但非要有帅哥美女陪睡，这就是“人欲”','3321-3376',0,1754127602,1782480549);
INSERT INTO highlights VALUES('3300151958_5_2895-2916','3300151958',5,'序章 心学诞生的前夜','《太极图说》。书中提到了“无极”这一概念，','2895-2916',0,1754126924,1782480549);
INSERT INTO highlights VALUES('3300151958_5_2019-2036','3300151958',5,'序章 心学诞生的前夜','吾性自足，不假外求。','2019-2036',0,1754126779,1782480549);
INSERT INTO highlights VALUES('3300151958_5_1806-1823','3300151958',5,'序章 心学诞生的前夜','恻隐之心充足到极点，就是‘仁’了。','1806-1823',0,1754126752,1782480549);
INSERT INTO highlights VALUES('25449864_25_699-748','25449864',25,'第19章 访问模式','对应用到的技术的总结写成文章分享出来，这一习惯从大二开始，一路坚持下来Tony已经写了不少原创文章','699-748',0,1768024047,1782480548);
INSERT INTO highlights VALUES('25449864_24_4309-4371','25449864',24,'第18章 享元模式','在程序中我们可以在用到的时候再去创建它，这在包含一些初始化非常耗时的对象时，可有效地提升程序的性能，因为把耗时的操作分解了。','4309-4371',0,1768011139,1782480548);
INSERT INTO highlights VALUES('25449864_24_3727-3810','25449864',24,'第18章 享元模式','UnshareFlyweightImpl是不可共享的对象，不能够使用共享技术的对象（一般不会出现在享元工厂中），只是实现了抽象类Flyweight的接口（或空实现）。','3727-3810',0,1768010969,1782480548);
INSERT INTO highlights VALUES('25449864_24_3362-3429','25449864',24,'第18章 享元模式','享元对象的外部状态必须由客户端保存，并在享元对象被创建之后，在需要使用的时候再传入享元对象内部，如故事剧情中颜料的使用者就是外部状态。','3362-3429',0,1768010676,1782480548);
INSERT INTO highlights VALUES('25449864_20_5405-5450','25449864',20,'第14章 策略模式',unistr('缺点：\u000a所有策略类都需要对外暴露。'),'5405-5450',0,1767887153,1782480548);
INSERT INTO highlights VALUES('25449864_20_4875-4911','25449864',20,'第14章 策略模式','（1）上下文环境（Context）','4875-4911',0,1767886915,1782480548);
INSERT INTO highlights VALUES('25449864_20_2996-3051','25449864',20,'第14章 策略模式','定义一系列算法，将每个算法都封装起来，并且使它们之间可以相互替换。策略模式使算法可以独立于使用它的用户而变化。','2996-3051',0,1767886738,1782480548);
INSERT INTO highlights VALUES('25449864_18_7287-7531','25449864',18,'第12章 构建模式',unistr('（1）产品（Product）：即你要构建的对象。\u000a（2）构建者（Builder）：构建模式的核心类，负责产品的构建过程。\u000a（3）指挥者（BuilderManager）：构建的管理类，负责管理每一种产品的创建数量和创建顺序'),'7287-7531',0,1767453510,1782480548);
INSERT INTO highlights VALUES('25449864_18_4339-4403','25449864',18,'第12章 构建模式','：先把内存卡、硬盘、CPU组装在主板上，再把主板、电池、风扇组装在机箱里，最后连接鼠标、键盘、显示器，就构成了一台完整的台式电脑','4339-4403',0,1767438599,1782480548);
INSERT INTO highlights VALUES('25449864_18_3848-3877','25449864',18,'第12章 构建模式','联系：组合模式和构建模式其实也经常被一起使用','3848-3877',0,1767438560,1782480548);
INSERT INTO highlights VALUES('25449864_18_2707-2749','25449864',18,'第12章 构建模式','将一复杂对象的构建过程和它的表现分离，使得同样的构建过程可以获取（创建）不同的表现。','2707-2749',0,1767438465,1782480548);
INSERT INTO highlights VALUES('25449864_23_2871-2916','25449864',23,'第17章 备忘模式','在不破坏内部结构的前提下捕获一个对象的内部状态，这样便可在以后将该对象恢复到原先保存的状态','2871-2916',0,1767200247,1782480548);
INSERT INTO highlights VALUES('25449864_23_811-835','25449864',23,'第17章 备忘模式','每天9点到公司，花10分钟想一下今天有哪些工作项','811-835',0,1767108376,1782480548);
INSERT INTO highlights VALUES('25449864_22_4831-4854','25449864',22,'第16 章命令模式','Command是核心类，表示一项任务或一个动作','4831-4854',0,1766929228,1782480548);
INSERT INTO highlights VALUES('25449864_22_3737-3743','25449864',22,'第16 章命令模式','高内聚的模式','3737-3743',0,1766929174,1782480548);
INSERT INTO highlights VALUES('25449864_21_5735-5754','25449864',21,'第15章 工厂模式','工厂方法使一个类的实例化延迟到其子类。','5735-5754',0,1765969366,1782480548);
INSERT INTO highlights VALUES('25449864_21_2341-2454','25449864',21,'第15章 工厂模式','专门定义一个类来负责创建其他类的实例，根据参数的不同创建不同类的实例，被创建的实例通常具有共同的父类，这个模式叫简单工厂模式（Simple Factory Pattern）。','2341-2454',0,1765935387,1782480548);
INSERT INTO highlights VALUES('25449864_10_3331-3376','25449864',10,'第4章 装饰模式','动态地给一个对象增加一些额外的职责，就拓展对象功能来说，装饰模式比生成子类的方式更为灵活。','3331-3376',0,1752508662,1782480548);
INSERT INTO highlights VALUES('25449864_9_10396-10428','25449864',9,'第3章 中介模式','想通过一个中间类来封装多个类中的行为，同时又不想生成太多的子类。','10396-10428',0,1752230618,1782480548);
INSERT INTO highlights VALUES('25449864_9_4977-5046','25449864',9,'第3章 中介模式','中介模式的作用就是将这种网状结构（如图3-3所示）分离成星型结构（如图3-4所示）。这样调整之后，使得对象间的结构更加简洁，交互更加顺畅。','4977-5046',0,1752072830,1782480548);
INSERT INTO highlights VALUES('25449864_8_7952-8040','25449864',8,'第2章 状态模式','一个操作中含有庞大的多分支的条件语句，这些分支依赖于该对象的状态，且每一个分支的业务逻辑都非常复杂时，我们可以使用状态模式来拆分不同的分支逻辑，使程序有更好的可读性和可维护性。','7952-8040',0,1752072379,1782480548);
INSERT INTO highlights VALUES('25449864_8_5906-5931','25449864',8,'第2章 状态模式','Context是上下文环境类，负责具体状态的切换。','5906-5931',0,1751978962,1782480548);
INSERT INTO highlights VALUES('25449864_8_4680-4716','25449864',8,'第2章 状态模式','表示状态的类应该只会有一个实例，因为不可能出现“固态1”“固态2”的情形','4680-4716',0,1751978688,1782480548);
INSERT INTO highlights VALUES('25449864_7_2885-2943','25449864',7,'第1章 监听模式','被观察者对象在状态或内容（数据）发生变化时，会通知所有观察者对象，使它们能够做出相应的变化（如自动更新自己的信息）。','2885-2943',0,1747316759,1782480548);
INSERT INTO highlights VALUES('25449864_6_12051-12116','25449864',6,'基础篇','关联（Association）是一种拥有关系，它使一个类知道另一个类的属性和方法。关联可以是双向的，也可以是单向的。','12051-12116',0,1747310072,1782480548);
INSERT INTO highlights VALUES('25449864_6_11608-11654','25449864',6,'基础篇','聚合（Aggregation）是整体与部分的关系，部分可以离开整体而单独存在。','11608-11654',0,1747310021,1782480548);
INSERT INTO highlights VALUES('25449864_6_9641-9669','25449864',6,'基础篇','其中类图是应用最广泛的一种图，经常被用于软件架构设计中。','9641-9669',0,1747309700,1782480548);
INSERT INTO highlights VALUES('25449864_6_9541-9594','25449864',6,'基础篇','UML 的这一整套图被分为两组，一组叫结构性图，包含类图、组件图、部署图、对象图、包图、组合结构图、轮廓图','9541-9594',0,1747309671,1782480548);
INSERT INTO highlights VALUES('25449864_5_4287-4310','25449864',5,'前言','但每一篇内的不同章之间是没有阅读的先后顺序的（','4287-4310',0,1747292659,1782480548);
INSERT INTO highlights VALUES('25449864_5_2481-2520','25449864',5,'前言','第一次将设计模式提升到理论高度，并将之规范化，该书提出了23种经典的设计模式。','2481-2520',0,1747282510,1782480548);
INSERT INTO highlights VALUES('25449864_5_2296-2375','25449864',5,'前言','GoF全称是Gang of Four（四人帮），即Erich Gamma、Richard Helm、Ralph Johnson和John Vlissides。','2296-2375',0,1747282494,1782480548);
INSERT INTO highlights VALUES('25449864_1_38-130','25449864',1,'封面',unistr('从基础的监听模式到复杂的MVC模式，涵盖了23种经典设计模式以及它们的衍生模式，如适配器模式、策略模式等。 \u000a通过Python语言实现这些模式，帮助读者更好地理解和应用这些设计思想。 '),'38-130',0,1747276142,1782480548);
INSERT INTO highlights VALUES('25449864_7_2483-2742','25449864',7,'第1章 监听模式',unistr('什么是监听模式\u000aDefine a one-to-many dependency between objects so that when one object changes state,all its dependents are notified and updated automatically.\u000a在对象间定义一种一对多的依赖关系，当这个对象状态发生改变时，所有依赖它的对象都会被通知并自动更新。'),'2483-2742',0,1739043940,1782480548);
INSERT INTO highlights VALUES('25449864_6_12580-12643','25449864',6,'基础篇','依赖（Dependency）是一种使用的关系，即一个类的实现需要另一个类的协助，所以尽量不要使用双向的互相依赖。','12580-12643',0,1739043594,1782480548);
INSERT INTO highlights VALUES('25449864_6_10626-10676','25449864',6,'基础篇','实现（Realization）是一种类与接口的关系，表示类是接口所有特征和行为的实现。','10626-10676',0,1739043474,1782480548);
INSERT INTO highlights VALUES('25449864_6_10146-10211','25449864',6,'基础篇','泛化（Generalization）是一种继承关系，表示一般与特殊的关系，它指定了子类如何特化父类的所有特征和行为。','10146-10211',0,1739043421,1782480548);
INSERT INTO highlights VALUES('25449864_6_10012-10060','25449864',6,'基础篇','这些关系的强弱顺序为：泛化=实现 > 组合 > 聚合 > 关联 > 依赖','10012-10060',0,1739043353,1782480548);
INSERT INTO highlights VALUES('3300011992_9_5624-5728','3300011992',9,'/你一直渴望交流，却习惯被动沉默/','由于早年的经历，被动沉默者养成了极度敏感的性格，但这已经成为既定事实，因此不要去跟自己的敏感、紧张较劲，也不要去跟别人比较。允许自己敏感、紧张，允许自己恐惧，接纳自己的不足，真正做到理解自己，而不是强求自己。','5624-5728',5,1693059384,1782480563);
INSERT INTO highlights VALUES('3300011992_9_5561-5595','3300011992',9,'/你一直渴望交流，却习惯被动沉默/','最后，被动沉默者要走出被动沉默的心理困境，绝对不能和敏感、紧张较劲。','5561-5595',5,1693059364,1782480563);
INSERT INTO highlights VALUES('3300011992_8_5284-5311','3300011992',8,'/当爱情来临时，你在害怕什么/','一个人如果意识不到自己是在伪装，就无法面对真实的自我。','5284-5311',5,1693057935,1782480563);
INSERT INTO highlights VALUES('3300011992_8_3402-3474','3300011992',8,'/当爱情来临时，你在害怕什么/','因为一个内在缺乏安全感的人，他的外在往往会有多种表现形式，比如花心、习惯性劈腿行为等，除非你是强大的“拯救者型”人格，否则退出真的是最好的选择。','3402-3474',5,1693042601,1782480563);
INSERT INTO highlights VALUES('3300011992_8_1258-1341','3300011992',8,'/当爱情来临时，你在害怕什么/','有些人从外表看特别强势，其实心里却渴望遇到一个能透过自己表面的伪装看到自己真实内心的人。只是他们的伪装如此自然，因此很多时候他们吸引过来的都是一些迷恋他们的强势的异性','1258-1341',5,1693040621,1782480563);
INSERT INTO highlights VALUES('3300011992_8_1748-1810','3300011992',8,'/当爱情来临时，你在害怕什么/',unistr('以上这几类人有一个共同的特点：无法近距离地袒露真实的自我。\u000a2'),'1748-1810',5,1693040360,1782480563);
INSERT INTO highlights VALUES('3300011992_8_855-896','3300011992',8,'/当爱情来临时，你在害怕什么/','答案是：他们的体内有两个自我，一个是真实的、虚弱的自我，另一个是虚假的、强硬的自我','855-896',5,1693040266,1782480563);
INSERT INTO highlights VALUES('3300011992_7_5612-5629','3300011992',7,'/你的退让，是对方得寸进尺的温床/','生闷气，另一方面是对自己产生愤怒。','5612-5629',5,1693040148,1782480563);
INSERT INTO highlights VALUES('3300011992_7_5450-5489','3300011992',7,'/你的退让，是对方得寸进尺的温床/','遗憾的是，在人际关系中，我们根本无法控制别人的行为，但我们必须对自己的感受负责','5450-5489',5,1693040131,1782480563);
INSERT INTO highlights VALUES('3300011992_7_5015-5042','3300011992',7,'/你的退让，是对方得寸进尺的温床/','拥有健康的攻击性，还需要做到拒绝生闷气、拒绝压抑情绪。','5015-5042',5,1693040116,1782480563);
INSERT INTO highlights VALUES('3300011992_7_4673-4697','3300011992',7,'/你的退让，是对方得寸进尺的温床/','只有允许不健康的关系终结，才能建立起健康的关系。','4673-4697',5,1693040050,1782480563);
INSERT INTO highlights VALUES('3300011992_7_4304-4359','3300011992',7,'/你的退让，是对方得寸进尺的温床/','弗洛伊德说：性和攻击性是人类行为的两大基本动力。拥有健康的攻击性是我们活着的根本，也是我们的活力和健康的源泉。','4304-4359',5,1693040008,1782480563);
INSERT INTO highlights VALUES('3300011992_6_5941-5971','3300011992',6,'/害怕失败的人，从一开始就输了/','面对自己喜欢的东西，我们要大胆追求，不要缩手缩脚，害怕失败。','5941-5971',5,1693039661,1782480563);
INSERT INTO highlights VALUES('3300011992_6_5684-5791','3300011992',6,'/害怕失败的人，从一开始就输了/',unistr('是的，你会怎么想，你就会怎么做，把精力投入你所想的方面，最后就会收获所想的现实。\u000a我们唯有先觉察出自己的限制性信念，时刻观察自己、校正自己，才能真正获得成长。'),'5684-5791',5,1693039640,1782480563);
INSERT INTO highlights VALUES('3300011992_6_5372-5410','3300011992',6,'/害怕失败的人，从一开始就输了/','人生是一个自我预言的过程，大量实践表明：你选择相信什么，你就有可能得到什么。','5372-5410',5,1693039607,1782480563);
INSERT INTO highlights VALUES('3300011992_6_4685-4700','3300011992',6,'/害怕失败的人，从一开始就输了/','（4）我很难得到自己想要的东西','4685-4700',5,1693039541,1782480563);
INSERT INTO highlights VALUES('3300011992_6_4596-4654','3300011992',6,'/害怕失败的人，从一开始就输了/','人生是一场修行，越害怕失败的人，越容易活在挫败中，只有放下对失败的恐惧，破除潜意识里的限制性信念，才有机会获得成功。','4596-4654',5,1693039536,1782480563);
INSERT INTO highlights VALUES('3300011992_6_4205-4213','3300011992',6,'/害怕失败的人，从一开始就输了/','（3）我不能失败','4205-4213',5,1693039524,1782480563);
INSERT INTO highlights VALUES('3300011992_6_3366-3381','3300011992',6,'/害怕失败的人，从一开始就输了/','（2）我不配得到自己喜欢的东西','3366-3381',5,1693039516,1782480563);
INSERT INTO highlights VALUES('3300011992_6_2933-2951','3300011992',6,'/害怕失败的人，从一开始就输了/','（1）我注定不可能得到自己喜欢的东西','2933-2951',5,1693039512,1782480563);
INSERT INTO highlights VALUES('3300011992_6_4393-4413','3300011992',6,'/害怕失败的人，从一开始就输了/','阻碍他成功的潜意识信念就是：我不能失败。','4393-4413',5,1693039495,1782480563);
INSERT INTO highlights VALUES('3300011992_6_2254-2320','3300011992',6,'/害怕失败的人，从一开始就输了/','简而言之，持有不同信念的人做事的逻辑不一样，人生的底色就不一样，从而构筑的人生脚本的主题、色调也不一样，因此人生的动力就会完全不同。','2254-2320',5,1693039307,1782480563);
INSERT INTO highlights VALUES('3300011992_6_2159-2186','3300011992',6,'/害怕失败的人，从一开始就输了/','而对于“追求成功”的人来说，做事的主要动机就是追求成功','2159-2186',5,1693039298,1782480563);
INSERT INTO highlights VALUES('3300011992_6_2076-2130','3300011992',6,'/害怕失败的人，从一开始就输了/','对于“避免失败”的人来说，做事的主要动机就是避免失败。因此这些人会极力逃避生活中的风险，努力让自己活得安全。','2076-2130',5,1693039293,1782480563);
INSERT INTO highlights VALUES('3300011992_6_2023-2047','3300011992',6,'/害怕失败的人，从一开始就输了/','人类可以被划分为“避免失败”和“追求成功”两类。','2023-2047',5,1693039284,1782480563);
INSERT INTO highlights VALUES('3300011992_6_1979-2002','3300011992',6,'/害怕失败的人，从一开始就输了/','美国心理学家阿特金森就提出了著名的成就动机理论','1979-2002',5,1693039277,1782480563);
INSERT INTO highlights VALUES('3300011992_6_1678-1742','3300011992',6,'/害怕失败的人，从一开始就输了/','然而，还有些人在面对自己喜欢的人或事物时，会被激发出紧张、焦虑等负面情绪，他们甚至会让自己进入应激状态，陷入持久的焦虑和担心中，','1678-1742',5,1693039257,1782480563);
INSERT INTO highlights VALUES('3300011992_5_6028-6073','3300011992',5,'/你不解决问题，你就会成为问题/','厘清自己，你就厘清了一切。所有的逃避都是对自我的逃避，所有的不清楚都是对自我认识的不清楚。','6028-6073',5,1693039169,1782480563);
INSERT INTO highlights VALUES('3300011992_5_4885-4935','3300011992',5,'/你不解决问题，你就会成为问题/','人们不会尊重一个毫无主见、胆小懦弱的人。这样的人在群体中往往得不到重视，反而会被认为是缺乏能力的人。','4885-4935',5,1693039073,1782480563);
INSERT INTO highlights VALUES('3300011992_5_4711-4754','3300011992',5,'/你不解决问题，你就会成为问题/','所以，逃避冲突最终并不会解决冲突，反而会引来更严重的内心冲突，最终导致与别人发生冲突。','4711-4754',5,1693039045,1782480563);
INSERT INTO highlights VALUES('3300011992_5_4586-4626','3300011992',5,'/你不解决问题，你就会成为问题/','但这些不同的想法或意见并不会因为受到压制就消失，它们会一直存在，甚至比原来更强烈','4586-4626',5,1693039037,1782480563);
INSERT INTO highlights VALUES('3300011992_5_2193-2232','3300011992',5,'/你不解决问题，你就会成为问题/','害怕与别人发生冲突的人，本质上是害怕面对自己，以及害怕别人对自己有不好的评价。','2193-2232',5,1693038833,1782480563);
INSERT INTO highlights VALUES('3300011992_5_1405-1439','3300011992',5,'/你不解决问题，你就会成为问题/','你害怕发生人际冲突的根源在于，你认为人际冲突会给自己带来灾难性的影响','1405-1439',5,1693038783,1782480563);
INSERT INTO highlights VALUES('3300011992_5_753-840','3300011992',5,'/你不解决问题，你就会成为问题/','久而久之，你的境遇会比当初更加糟糕。你开始觉得难以忍受，直到有一天你提出了抗议，但这种抗议是以同他人发生剧烈的冲突表现出来的。最终你还是会以惨败收场，所有人都觉得你不可理喻。','753-840',5,1693035773,1782480563);
INSERT INTO highlights VALUES('3300011992_3_1502-1597','3300011992',3,'自序','我们通常讲的“了解自己”，很大程度上就是要了解自己的防御机制，了解自己当初回避了怎样的痛苦、麻烦、挑战，然后再去尝试面对自己曾经一味回避的东西，消除旧有模式，让自己回到可以自由选择的状态里。','1502-1597',5,1692957538,1782480563);
INSERT INTO highlights VALUES('3300011992_3_521-561','3300011992',3,'自序','细想来，这些变化无不与我逐渐能够正视自己、越来越少地使用逃避的心理防御机制有关。','521-561',5,1692957433,1782480563);
INSERT INTO highlights VALUES('3300020163_42_2783-2836','3300020163',42,'过年三记','我妈边走边骂阿黄：“刚才我们叫你，为什么不理？就只顾自己瞎跑。哼，现在再听话再摇尾巴也没有用了！不理你！”','2783-2836',5,1714544008,1782480559);
INSERT INTO highlights VALUES('3300020163_42_2553-2574','3300020163',42,'过年三记','月亮静静地浮在天空的另一边，边缘薄而锋利。','2553-2574',5,1714543968,1782480559);
INSERT INTO highlights VALUES('3300020163_42_2459-2524','3300020163',42,'过年三记','每当抬头看到这太阳，都好像是有生以来第一次看到一样——心里微微一动，惊奇感转瞬即逝，但记起现实后的那种猛然而至的空洞感却难以愈合。','2459-2524',5,1714543960,1782480559);
INSERT INTO highlights VALUES('3300020163_42_1278-1363','3300020163',42,'过年三记','我想它是崇拜阿黄的，看上去它极想跟着阿黄闯世界去，却又不敢远离我和我妈。于是便不停地在我们和远远的阿黄之间来回奔波。结果，它一个人走的路估计比我们四个加起来走的路还要多。','1278-1363',5,1714534291,1782480559);
INSERT INTO highlights VALUES('3300020163_42_510-568','3300020163',42,'过年三记','我们一大早起来，穿得厚厚的，暖暖和和的。把家里的三条狗也带上，一起穿过村子进入荒原，一直向南面走，直到走累了为止。”','510-568',5,1714534177,1782480559);
INSERT INTO highlights VALUES('3300020163_41_3374-3458','3300020163',41,'通往滴水泉的路','那些所有的，沿着群山边缘，沿着戈壁滩起伏不定的地势，沿着春夏寒暑，沿着古老的激情，沿着古老的悲伤，沿着漫漫时光，沿着深沉的畏惧与威严……而崎岖蜿蜒至此的道路，都被抛弃了','3374-3458',5,1714534065,1782480559);
INSERT INTO highlights VALUES('3300020163_41_3332-3345','3300020163',41,'通往滴水泉的路','通往滴水泉的路，被抛弃了。','3332-3345',5,1714534050,1782480559);
INSERT INTO highlights VALUES('3300020163_41_3262-3274','3300020163',41,'通往滴水泉的路','但是，他们一直等到现在。','3262-3274',5,1714534037,1782480559);
INSERT INTO highlights VALUES('3300020163_41_3181-3233','3300020163',41,'通往滴水泉的路','他们坐下来等待冬天，等待第一辆车在门口鸣笛刹车，等待门帘突然被猛地掀开，等待人间的喧哗再一次点燃滴水泉。','3181-3233',5,1714534028,1782480559);
INSERT INTO highlights VALUES('3300020163_41_1283-1311','3300020163',41,'通往滴水泉的路','乌斯曼的烈马走出了一条忽明忽暗的道路，笔直地戳向滴水泉。','1283-1311',5,1714533639,1782480559);
INSERT INTO highlights VALUES('3300020163_41_700-761','3300020163',41,'通往滴水泉的路','那时，只在牧民之间，寂静而神秘地流传着一种说法：在戈壁滩最最干涸的腹心地带，在那里的某个角落，深深地掩藏着一眼奇迹般的泉水','700-761',5,1714533494,1782480559);
INSERT INTO highlights VALUES('3300020163_41_629-651','3300020163',41,'通往滴水泉的路','它们因为深藏着水的气息而生有晶莹深邃的眼睛。','629-651',5,1714528402,1782480559);
INSERT INTO highlights VALUES('3300020163_41_608-611','3300020163',41,'通往滴水泉的路','鹅喉羚','608-611',5,1714528387,1782480559);
INSERT INTO highlights VALUES('3300020163_41_510-551','3300020163',41,'通往滴水泉的路','那些路断断续续地，虚弱地行进在群山褶皱之中，遥遥连接着阿尔泰的绿洲和南方的草原雪山','510-551',5,1714528344,1782480559);
INSERT INTO highlights VALUES('3300020163_40_4907-4943','3300020163',40,'摩托车穿过春天的荒野','再四下一看，脚下像这样的漂亮石子比比皆是，一枚挨一枚紧紧嵌在坚硬的大地上','4907-4943',5,1714499744,1782480559);
INSERT INTO highlights VALUES('3300020163_40_3825-3905','3300020163',40,'摩托车穿过春天的荒野','可是在背包里翻半天，只翻出一只用来装针线的小号“娃哈哈”酸奶瓶子。于是这两个男人把那台摩托车翻倒，我小心翼翼地持着这个过于小巧纤细的瓶子对准油箱流出的那股清流。','3825-3905',5,1714499622,1782480559);
INSERT INTO highlights VALUES('3300020163_40_3195-3261','3300020163',40,'摩托车穿过春天的荒野','那风大得呀——后来，我不小心在这样的风里失手掉落五块钱，跟在钱后面一路狂追了几百米都没能追上。幸亏钱最后被一丛芨芨草挂住了才停下来。','3195-3261',5,1714499521,1782480559);
INSERT INTO highlights VALUES('3300020163_40_2972-3015','3300020163',40,'摩托车穿过春天的荒野','再定睛一看，原来是门牙变成黑色的了……全是给风吹的，沾了厚厚一层土，口水一浸就成了黑色','2972-3015',5,1714499497,1782480559);
INSERT INTO highlights VALUES('3300020163_40_2615-2640','3300020163',40,'摩托车穿过春天的荒野','透过它看到的世界肮脏又朦胧，视力所及之处一塌糊涂，','2615-2640',5,1714499441,1782480559);
INSERT INTO highlights VALUES('3300020163_40_2469-2550','3300020163',40,'摩托车穿过春天的荒野','于是我只好又把头盔顶在头上挡风。但是不一会儿，呼吸不畅，憋气得很，只好再取下来。但是一取下来，立刻就对比出了戴上的好处。于是又抖抖索索地重戴上。立刻又呼吸不畅……','2469-2550',5,1714499413,1782480559);
INSERT INTO highlights VALUES('3300020163_39_2877-2937','3300020163',39,'打电话','后来才知道，来我家打电话的哈萨克人全都是正在恋爱中的姑娘小伙儿。因为这一带就我们一家汉人，当着我们的面谈情说爱也方便点。','2877-2937',5,1714409159,1782480559);
INSERT INTO highlights VALUES('3300020163_39_1574-1609','3300020163',39,'打电话','……娃儿啊，生火的时候，要先在灶里搁小柴，底脚架空呷，搁点刨花儿引火。','1574-1609',5,1714409044,1782480559);
INSERT INTO highlights VALUES('3300020163_37_3254-3317','3300020163',37,'属于我的马','这样，我就得为了马永远留下来，永远地……也就是说，除非我真正地爱上阿勒泰，决心永远生活在阿勒泰，否则我就永远不可能拥有一匹马。','3254-3317',5,1714408555,1782480559);
INSERT INTO highlights VALUES('3300020163_37_2743-2776','3300020163',37,'属于我的马','我一直目送那人和他的马消失在街道拐弯处，才意识到他们刚才闯红灯了。','2743-2776',5,1714408453,1782480559);
INSERT INTO highlights VALUES('3300020163_37_2639-2665','3300020163',37,'属于我的马','四面都是车辆，那马儿居然视若无物，大约是见过世面的。','2639-2665',5,1714408435,1782480559);
INSERT INTO highlights VALUES('3300020163_37_2410-2521','3300020163',37,'属于我的马',unistr('至于马，已经可要可不要了。\u000a但是，哪怕到了现在，拥有一匹马——这仍然是多么巨大的愿望啊！至于被一匹马高高载着，风驰电掣地奔向远方——那情景让人一想到便忍不住心血沸腾。'),'2410-2521',5,1714408125,1782480559);
INSERT INTO highlights VALUES('3300020163_37_2230-2277','3300020163',37,'属于我的马','漫长的劳动使阿克哈拉的土地渐渐睁开了眼睛。它看到了我们，认清我们的模样，从此才真正接受了我们。','2230-2277',5,1714408113,1782480559);
INSERT INTO highlights VALUES('3300020163_36_4210-4248','3300020163',36,'我所能带给你们的事物','外婆拄杖站在旁边，笑眯眯地看着。她那暂时的欢乐，因这“暂时”而显得那样悲伤。','4210-4248',5,1714407903,1782480559);
INSERT INTO highlights VALUES('3300020163_36_4098-4132','3300020163',36,'我所能带给你们的事物','以后再也别买这些东西回来了，死了可怜得很……你回来了就好了，我很想你','4098-4132',5,1714407881,1782480559);
INSERT INTO highlights VALUES('3300020163_36_3796-3820','3300020163',36,'我所能带给你们的事物','那时我远在回家的路上，却已经感觉到家才有的温暖。','3796-3820',5,1714407748,1782480559);
INSERT INTO highlights VALUES('3300020163_36_1654-1741','3300020163',36,'我所能带给你们的事物','原来她挂了电话后，立刻买来驼毛，连夜洗了，烧旺炉子烘干。再用柳条儿抽打着弹松、扯匀，细细裹上纱布。熬了一个通宵才赶制出来。然后又倒了三趟班车，坐了十多个钟头的车赶往乌鲁木齐。','1654-1741',5,1714400818,1782480559);
INSERT INTO highlights VALUES('3300020163_36_625-702','3300020163',36,'我所能带给你们的事物','给它什么就吃什么，毫不含糊。到了后来居然连肉也吃。兔子还吃肉？真是没听说过兔子还能吃肉……后来，果然证实了兔子是不能吃肉的，它们才吃了一次肉，就给吃死了。','625-702',5,1714400693,1782480559);
INSERT INTO highlights VALUES('3300020163_36_549-578','3300020163',36,'我所能带给你们的事物','比一般的家兔还大，贼肥贼肥的，肥得跳都跳不动，只好爬着走。','549-578',5,1714400670,1782480559);
INSERT INTO highlights VALUES('3300020163_33_526-552','3300020163',33,'三版序','这个新的版本最大的调整就是去掉了之前版本的第三部分。','526-552',5,1714400469,1782480559);
INSERT INTO highlights VALUES('3300020163_32_1016-1047','3300020163',32,'自序','但经验是，信笔为之的文字往往比郑重地写出的更真诚，并且更可靠。','1016-1047',5,1714400422,1782480559);
INSERT INTO highlights VALUES('3300020163_32_657-688','3300020163',32,'自序','阴天里，世界的白是纯然深厚的白；晴天，则成了泛着荧荧蓝光的白。','657-688',1,1714239424,1782480559);
INSERT INTO highlights VALUES('932498_38_17214-17246','932498',38,'第一章 先生，太可怕了，存在主义！','虽然他自己的时代无法理解他，但他总认为，他的成功之日一定会到来。','17214-17246',5,1702905829,1782480562);
INSERT INTO highlights VALUES('932498_38_16853-16958','932498',38,'第一章 先生，太可怕了，存在主义！','现在，我们只能靠自己了。正确的生存方式，不是我们去信仰什么，而是要全情地投入到我们自己的生命之中，把握好每一个时刻，它是什么样，我们就怎么活，不要希望任何东西有所不同，也不要藏匿对他人或对自身命运的愤怒与仇恨。','16853-16958',5,1702905778,1782480562);
INSERT INTO highlights VALUES('932498_38_16729-16791','932498',38,'第一章 先生，太可怕了，存在主义！','研究我们自己的道德谱系学，不能帮助我们摆脱或超越自身，但它能让我们更清晰地看到我们的幻觉，并过上一种更有活力、更坚定的生活。','16729-16791',5,1702905770,1782480562);
INSERT INTO highlights VALUES('932498_38_16678-16713','932498',38,'第一章 先生，太可怕了，存在主义！','相信，每一个伟大的哲学家，实际上都是在书写“一种不自觉和无意识的回忆录','16678-16713',5,1702905749,1782480562);
INSERT INTO highlights VALUES('932498_38_16044-16088','932498',38,'第一章 先生，太可怕了，存在主义！','克尔凯郭尔写道：“忧虑是自由的眩晕。”在他和萨特看来，我们整个人生都处在悬崖峭壁的边缘。','16044-16088',5,1702905652,1782480562);
INSERT INTO highlights VALUES('932498_38_14492-14574','932498',38,'第一章 先生，太可怕了，存在主义！','1813年生于哥本哈根的索伦·克尔凯郭尔，用“存在的”(existential)一词来表示与人类存在问题有关的思想，为其赋予了新的含义，也为后来的存在主义定下了基调','14492-14574',5,1702899466,1782480562);
INSERT INTO highlights VALUES('932498_38_14000-14067','932498',38,'第一章 先生，太可怕了，存在主义！','通过以哲学的方式反思生命的无常，他们相信自己会变得更加坚韧，更能超然于环境，并能更充分地做好准备，去面对悲痛、害怕、发怒、失望和焦虑。','14000-14067',5,1702899367,1782480562);
INSERT INTO highlights VALUES('932498_38_13826-13846','932498',38,'第一章 先生，太可怕了，存在主义！','你经历了什么，那这个什么就是个哲学话题。','13826-13846',5,1702899342,1782480562);
INSERT INTO highlights VALUES('932498_38_13132-13186','932498',38,'第一章 先生，太可怕了，存在主义！','随着他俩地位的提高，所有一切都想诱使他们进入权威机构，但萨特和波伏娃却一直很决绝，坚持要做体制外的知识分子。','13132-13186',5,1702899233,1782480562);
INSERT INTO highlights VALUES('932498_38_11346-11419','932498',38,'第一章 先生，太可怕了，存在主义！','在这个反叛者的世界里，和早期时代巴黎那些放荡不羁的文化人以及达达主义者一样，一切危险和煽动性的事物都是好的，而所有美好的或中产阶级的事物都是坏的。','11346-11419',5,1702899023,1782480562);
INSERT INTO highlights VALUES('932498_38_11142-11149','932498',38,'第一章 先生，太可怕了，存在主义！','“溺水者”造型','11142-11149',5,1702898929,1782480562);
INSERT INTO highlights VALUES('932498_38_9727-9818','932498',38,'第一章 先生，太可怕了，存在主义！','马克思主义者也讨厌它。现在，萨特常常被认为是一名共产主义的支持者，但在很长时间里，他其实一直不被他们所接受。说到底，如果人们坚持认为自己是自由的个体，那么怎么可能会有组织得当的革命？','9727-9818',5,1702833926,1782480562);
INSERT INTO highlights VALUES('932498_38_8699-8717','932498',38,'第一章 先生，太可怕了，存在主义！','但寻求新的开始，还有更深层次的理由。','8699-8717',5,1702784824,1782480562);
INSERT INTO highlights VALUES('932498_38_8494-8569','932498',38,'第一章 先生，太可怕了，存在主义！','没有任何划定的道路来引导人去救赎自己；他必须不断创造自己的道路。但是，创造道路，他便拥有了自由与责任，失去了推脱的借口，而所有希望都存在于他本身之中。','8494-8569',5,1702782621,1782480562);
INSERT INTO highlights VALUES('932498_38_8377-8410','932498',38,'第一章 先生，太可怕了，存在主义！','萨特的存在主义暗示的是，只要你一直努力，那就有可能获得真实与自由。','8377-8410',5,1702782599,1782480562);
INSERT INTO highlights VALUES('932498_38_8249-8326','932498',38,'第一章 先生，太可怕了，存在主义！','如果你为了逃避责任，便自欺欺人地认为自己是环境或者什么糟糕建议的受害者，那你便没有达到人类生命的要求，而是选择了一种虚假的存在，脱离了你自己的“真实性”。','8249-8326',5,1702782586,1782480562);
INSERT INTO highlights VALUES('932498_38_8162-8213','932498',38,'第一章 先生，太可怕了，存在主义！','他反而通过指出你做什么真的至关重要而强化了这种焦虑','8162-8213',5,1702782568,1782480562);
INSERT INTO highlights VALUES('932498_38_8021-8086','932498',38,'第一章 先生，太可怕了，存在主义！','你也仍然可以自由地在心中和行动上决定如何去看待它。从你现在所处的地方开始，你进行选择。而在选择中，你便选择了你将会成为什么样的人。','8021-8086',5,1702782537,1782480562);
INSERT INTO highlights VALUES('932498_38_7862-7929','932498',38,'第一章 先生，太可怕了，存在主义！','他要告诉我们的是，也许你认为自己受着道德规范的指引，或者以特定的方式行事，乃是源于你的心理状态或过往经历，或是因为你周围发生的那些事。','7862-7929',5,1702782508,1782480562);
INSERT INTO highlights VALUES('932498_38_7640-7719','932498',38,'第一章 先生，太可怕了，存在主义！','没有哪个古老的权威能够解除你身负的自由重担。你尽可以小心翼翼地去权衡各种道德与实际的考虑，但说到底，你都得冒险一试，去做点儿什么，而这个什么是什么，由你决定。','7640-7719',5,1702782476,1782480562);
INSERT INTO highlights VALUES('932498_38_7589-7620','932498',38,'第一章 先生，太可怕了，存在主义！','你是自由的人，那就去选择吧——也就是说，去创造(invent)','7589-7620',5,1702782458,1782480562);
INSERT INTO highlights VALUES('932498_38_6854-6911','932498',38,'第一章 先生，太可怕了，存在主义！','但这里的情况更为复杂，因为事实是，他既不确定自己的英国之行是否真的能帮到任何人，也不确定离开母亲是否会严重伤害她。','6854-6911',5,1702782395,1782480562);
INSERT INTO highlights VALUES('932498_38_6752-6756','932498',38,'第一章 先生，太可怕了，存在主义！','胖子难题','6752-6756',5,1702782377,1782480562);
INSERT INTO highlights VALUES('932498_38_5946-5971','932498',38,'第一章 先生，太可怕了，存在主义！','后来又以此写了一本书，即《存在主义是一种人道主义》','5946-5971',5,1702782273,1782480562);
INSERT INTO highlights VALUES('932498_38_5178-5335','932498',38,'第一章 先生，太可怕了，存在主义！','你可能认为你可以用一些标签定义我，但你错了，因为我始终会是一件正在加工的作品。我不断地通过行动创造自身，这一点根深蒂固地存在于我的人类境遇之中，以至于在萨特看来，它本身就是人类境遇，从有第一缕意识那一刻开始，直到死亡将其抹去为止。我是我自己的自由：不多，也不少。','5178-5335',5,1702782180,1782480562);
INSERT INTO highlights VALUES('932498_38_5116-5177','932498',38,'第一章 先生，太可怕了，存在主义！','大概来讲，它的意思就是，发现自己被抛入世界中后，我会持续创造我自己的定义（或本性，或本质），但其他客体或生命形式却不会这样','5116-5177',0,1702749009,1782480562);
INSERT INTO highlights VALUES('932498_38_5038-5044','932498',55,'第一章 先生，太可怕了，存在主义！','存在先于本质','1944-1950',0,1702748984,1782480562);
INSERT INTO highlights VALUES('932498_38_4769-4987','932498',38,'第一章 先生，太可怕了，存在主义！','自由，在萨特看来，位于人类所有经验的中心，正是这一点，才把人类与其他事物区分开来。其他事物只能在某处待着，听凭摆布。萨特相信，就连人之外的动物，大多数时候也只是在听从塑造了它们那个物种的本能和习性行事。但作为一个人，我根本没有预先被决定的本性。我的本性，要通过我选择去做什么来创造。当然，我可能会被我的生物性影响，或者被我所处的文化和个人背景等方面影响，但这些并不能合成一张用来制造我的完整蓝图。我总是先我自己一步，边前行，边构筑自身。','4769-4987',0,1702748959,1782480562);
INSERT INTO highlights VALUES('932498_38_4708-4740','932498',38,'第一章 先生，太可怕了，存在主义！','他写作中最重要的内容，是一个十分宏大的主题：获得自由意味着什么。','4708-4740',0,1702748935,1782480562);
INSERT INTO highlights VALUES('932498_38_4537-4578','932498',38,'第一章 先生，太可怕了，存在主义！','他在眩晕、窥视、羞耻、虐待、革命、音乐和做爱中——大量地做爱——创造出了一门哲学。','4537-4578',0,1702748905,1782480562);
INSERT INTO highlights VALUES('932498_38_4224-4297','932498',38,'第一章 先生，太可怕了，存在主义！','他以一种现象学创立者未曾想见的但却更让人兴奋和个人化的方式，把现象学应用到人们的生活之中，创建了一种兼具国际影响和巴黎风味的新哲学：现代存在主义。','4224-4297',0,1702748863,1782480562);
INSERT INTO highlights VALUES('932498_38_3065-3112','932498',38,'第一章 先生，太可怕了，存在主义！','如果说萨特听到了阿隆有关现象学的消息后面色发白，那么究其原因，可能一半来自恼怒，一半源于兴奋。','3065-3112',0,1702748696,1782480562);
INSERT INTO highlights VALUES('932498_38_2095-2177','932498',38,'第一章 先生，太可怕了，存在主义！','另一个现象学家马丁·海德格尔，补充了一个不同的观点。他认为，纵观历史，所有哲学家都把时间浪费在了次要问题上，而忘记去问那个最重要的问题——存在(being)的问题。','2095-2177',0,1702748443,1782480562);
INSERT INTO highlights VALUES('932498_38_1931-2038','932498',38,'第一章 先生，太可怕了，存在主义！','现象学家中最重要的思想家埃德蒙德·胡塞尔，提出了一个振奋的口号：“回到事物本身(to the things themselves)！”意思是别在事物不断累加的诠释上浪费时间了，尤其是别浪费时间去琢磨事物是否真实了。','1931-2038',0,1702748401,1782480562);
INSERT INTO highlights VALUES('932498_38_1620-1670','932498',38,'第一章 先生，太可怕了，存在主义！','传统的哲学家常常从抽象的公理或者理论出发，但是德国的现象学家，却直接研究起了他们时刻正在经历的生活。','1620-1670',0,1702748356,1782480562);
INSERT INTO highlights VALUES('932498_38_1245-1301','932498',38,'第一章 先生，太可怕了，存在主义！','但如果你逼着自己注视他的左眼，就会发现一个温暖、智慧的眼神正在回望着你：这个男人对你告诉他的每一件事，都感兴趣。','1245-1301',0,1702748277,1782480562);
INSERT INTO highlights VALUES('32042419_28_667-748','32042419',28,'规划你的人生弧线','预先设想出了未来的情景，你就能思考如何让自己和他们在接下来的10年过得最好。你设想得越具体（例如，你需要多少钱和时间去达成什么目标），下一个10年的情况就会越好。','667-748',NULL,1673703187,1782480564);
INSERT INTO highlights VALUES('32042419_21_1016-1101','32042419',21,'瑞的其他原则','遵循以下五步流程来获得成功：（1）明确你的目标；（2）识别你的问题，并且不容忍你的问题；（3）诊断你的问题，以找出根本原因；（4）设计解决问题的方案；（5）践行你的方案。','1016-1101',NULL,1673702831,1782480564);
INSERT INTO highlights VALUES('32042419_16_29762-29808','32042419',16,'STEP 5 DO IT','我对你的唯一期望是，按照自己的好原则生活，这些原则能帮助你决定要做什么，并给你去践行的勇气。','29762-29808',NULL,1673702502,1782480564);
INSERT INTO highlights VALUES('32042419_16_29137-29206','32042419',16,'STEP 5 DO IT','不用管这些原则从何而来，只要明确它们是否对你有用，然后根据自己的需要改进。无论如何，选好你自己的原则，把它们记录下来，让它们和你一起进化。','29137-29206',NULL,1673702496,1782480564);
INSERT INTO highlights VALUES('32042419_16_25952-25995','32042419',16,'STEP 5 DO IT','我不再想穿过丛林去获取奖励了。相反，我想待在丛林里，和我关心的人一起奋斗，去获得成功。','25952-25995',NULL,1673702436,1782480564);
INSERT INTO highlights VALUES('32042419_16_25456-25514','32042419',16,'STEP 5 DO IT','我们所追求的东西只是鱼饵……与我们关心的人一起为共同的目标而奋斗，从而获得个人进化和有意义的关系，这才是真正的回报。','25456-25514',NULL,1673702418,1782480564);
INSERT INTO highlights VALUES('32042419_16_20671-20704','32042419',16,'STEP 5 DO IT','要穿过人生丛林，最好的办法就是和有见解但与我视角不同的人结伴同行。','20671-20704',NULL,1673702315,1782480564);
INSERT INTO highlights VALUES('32042419_16_19073-19153','32042419',16,'STEP 5 DO IT','我想从他们的视角去看事物，也想让他们从我的视角去看……这样我们就可以一起找出什么是真相，以及如何应对真相。妥善处理深思熟虑后的分歧是一门艺术，我想掌握这门艺术。','19073-19153',NULL,1673702288,1782480564);
INSERT INTO highlights VALUES('32042419_16_17540-17586','32042419',16,'STEP 5 DO IT','总有别人能够看到而你看不到的东西，如果你能获得这些人的帮助，就能在很大程度上拓宽自己的视野。','17540-17586',NULL,1673702271,1782480564);
INSERT INTO highlights VALUES('32042419_16_18356-18395','32042419',16,'STEP 5 DO IT','为了实现我的目标，我需要不再为自己是对的而沾沾自喜，要为了解到真相而感到喜悦。','18356-18395',NULL,1673702260,1782480564);
INSERT INTO highlights VALUES('32042419_16_17256-17285','32042419',16,'STEP 5 DO IT','思维盲点障碍之所以存在，是因为不同的人看待事物的方式不同。','17256-17285',NULL,1673702181,1782480564);
INSERT INTO highlights VALUES('32042419_16_16469-16517','32042419',16,'STEP 5 DO IT','我们尤其不喜欢正视自己的错误和弱点。当别人指出我们的错误和弱点时，我们本能地视之为对我们的攻击。','16469-16517',NULL,1673702150,1782480564);
INSERT INTO highlights VALUES('32042419_16_15432-15448','32042419',16,'STEP 5 DO IT','我们的自我意识障碍和思维盲点障碍','15432-15448',NULL,1673702021,1782480564);
INSERT INTO highlights VALUES('32042419_16_12992-13036','32042419',16,'STEP 5 DO IT','我注意到，人们容易受近期事件的影响，而忽视很久没发生的事，尤其是他们没有亲身经历过的事。','12992-13036',NULL,1673701609,1782480564);
INSERT INTO highlights VALUES('32042419_16_11969-12019','32042419',16,'STEP 5 DO IT','有些事情很少发生，我们可能一辈子都没遇上，当这种事情发生时，我们往往感到震惊（比如百年一遇的风暴）。','11969-12019',NULL,1673701488,1782480564);
INSERT INTO highlights VALUES('32042419_16_12393-12475','32042419',16,'STEP 5 DO IT','相对于将事物看成纷涌而至的诸多独立个体，我将每件事物都看作“同类事物的又一例”。我可以看到它们背后的因果关系，总结出应对的原则，并用文字和计算机代码来表达这些原则。','12393-12475',NULL,1673701483,1782480564);
INSERT INTO highlights VALUES('32042419_16_7071-7236','32042419',16,'STEP 5 DO IT',unistr('但是，一切都会过去……\u000a一直都存在一条最好的前进之路，你可能只是还没有发现。\u000a你只需要让自己冷静下来，好好反思，就能找到这条路……\u000a然后拥抱你的现实，好好应对它。'),'7071-7236',NULL,1673700272,1782480564);
INSERT INTO highlights VALUES('32042419_16_2790-2842','32042419',16,'STEP 5 DO IT','我们每个人都会遭遇挫折。它们有可能毁了我们……也有可能极大程度地帮助我们进步，这取决于我们如何应对挫折。','2790-2842',NULL,1673700080,1782480564);
INSERT INTO highlights VALUES('32042419_16_2463-2479','32042419',16,'STEP 5 DO IT','当然，你爬得越高，跌得也就越重。','2463-2479',NULL,1673700070,1782480564);
INSERT INTO highlights VALUES('32042419_16_1881-1916','32042419',16,'STEP 5 DO IT','当你在这个过程中不断前进时，你将取得更大的成功，也会迎来更严峻的挑战。','1881-1916',NULL,1673700065,1782480564);
INSERT INTO highlights VALUES('32042419_16_1383-1403','32042419',16,'STEP 5 DO IT','所谓进化，就是要么适应、要么消亡的过程。','1383-1403',NULL,1673699898,1782480564);
INSERT INTO highlights VALUES('32042419_13_430-451','32042419',13,'第四步 方案','第四步是制订方案，以解决阻碍你前进的问题。','430-451',NULL,1673699840,1782480564);
INSERT INTO highlights VALUES('32042419_11_430-449','32042419',11,'第三步 诊断','第三步是准确诊断问题，找到问题的根源。','430-449',NULL,1673699665,1782480564);
INSERT INTO highlights VALUES('32042419_9_479-500','32042419',9,'第二步 问题','为了进化，你需要找出问题，并且不容忍问题。','479-500',NULL,1673699637,1782480564);
INSERT INTO highlights VALUES('32042419_6_9975-9984','32042419',6,'文前','痛苦 +反思=进步','9975-9984',NULL,1673699569,1782480564);
INSERT INTO highlights VALUES('32042419_6_9427-9471','32042419',6,'文前','后来，我意识到这些痛苦是一种信号，提醒我需要反思自己的现状，以及反思如何最好地应对现实。','9427-9471',NULL,1673699561,1782480564);
INSERT INTO highlights VALUES('32042419_6_9203-9242','32042419',6,'文前','一开始，我的问题、错误和弱点让我很痛苦，主要是因为我陷入了不想面对它们的情绪。','9203-9242',NULL,1673699558,1782480564);
INSERT INTO highlights VALUES('32042419_6_6848-6862','32042419',6,'文前','梦想+现实+决心=成功的生活','6848-6862',NULL,1673699499,1782480564);
INSERT INTO highlights VALUES('32042419_6_6073-6157','32042419',6,'文前','知道真相是什么，也就是知道现实是如何运行的。为了成功，我们必须遵循自然法则，这些自然法则并不是由人类创造的，但如果我们能理解这些自然法则，就能利用它们来实现自己的目标。','6073-6157',NULL,1673699460,1782480564);
INSERT INTO highlights VALUES('32042419_6_6438-6484','32042419',6,'文前','这让我成为一个超级现实的人：拥抱现实并妥善应对现实，而不是否定现实，还抱怨现实不如自己的意。','6438-6484',NULL,1673699447,1782480564);
INSERT INTO highlights VALUES('32042419_6_5740-5762','32042419',6,'文前','要想做出好的决定，知道真相是什么，至关重要。','5740-5762',NULL,1673699412,1782480564);
INSERT INTO highlights VALUES('32042419_6_1992-2007','32042419',6,'文前','决定的质量将决定你的生活质量。','1992-2007',NULL,1673699340,1782480564);
INSERT INTO highlights VALUES('32042419_6_1319-1336','32042419',6,'文前','我们无法停止前行，也无法回避现实。','1319-1336',NULL,1673699325,1782480564);
INSERT INTO highlights VALUES('32042419_6_877-911','32042419',6,'文前','时间就像一条河流，推着我们前行，途中会与现实相遇，需要我们做出决策。','877-911',NULL,1673699319,1782480564);
INSERT INTO highlights VALUES('32042419_6_730-744','32042419',6,'文前','独立思考，并保证头脑极度开放','730-744',NULL,1673699307,1782480564);
INSERT INTO highlights VALUES('3300056202_13_1043-1071','3300056202',13,'1.7 训练开始之前的热身','成年人是如何学会新技能的呢？是靠改变神经细胞之间的连接。','1043-1071',5,1722388832,1782480556);
INSERT INTO highlights VALUES('3300056202_13_641-686','3300056202',13,'1.7 训练开始之前的热身','在做完本书包含的练习之外，还请读者自行寻找适合的阅读材料来练习，练习时间需至少持续一个月。','641-686',5,1722388667,1782480556);
INSERT INTO highlights VALUES('3300056202_12_634-912','3300056202',12,'1.6 四步读书法：预、通、内、外',unistr('• 第一步，预读：通过看目录、前言等了解全书概要和书的结构信息。\u000a• 第二步，通读：使用多种快速阅读技巧通读全文，找出对自己有用的重点，做好勾画批注。\u000a• 第三步，反刍内化：重读在上一步通读环节所做的勾画批注，再思考，做拓展联想，为把新知识迁移到自己的使用场景做准备。\u000a• 第四步，外化使用：选出书中最有价值的知识点，将其输出或应用到自己的生活、工作的实际场景中，或者在实际场景中做演练。'),'634-912',5,1722388637,1782480556);
INSERT INTO highlights VALUES('3300056202_12_1030-1102','3300056202',12,'1.6 四步读书法：预、通、内、外','要求保持一定的阅读节奏，不能总停下来做深度思考，但真正有价值的东西必须经过自己的反复思考才能消化吸收，所以我把“通读”与“反刍内化”两个环节分开','1030-1102',5,1722388604,1782480556);
INSERT INTO highlights VALUES('3300056202_11_2807-2843','3300056202',11,'1.5 阅读的5步转化漏斗','最后还会讨论养成阅读习惯的方法。通过这一章的学习，基本解决“忙”的问题。','2807-2843',5,1722388187,1782480556);
INSERT INTO highlights VALUES('3300056202_11_2132-2197','3300056202',11,'1.5 阅读的5步转化漏斗','其中第3章会着重介绍快速阅读的方法、技巧和工具，这是全书技术性最强的部分，读者在阅读本书之后，需要经常练习才能掌握这一章介绍的技巧','2132-2197',5,1722387897,1782480556);
INSERT INTO highlights VALUES('3300056202_11_1071-1098','3300056202',11,'1.5 阅读的5步转化漏斗','长期阅读成效=∑（某次阅读成效×该次信息存储提取效率）','1071-1098',5,1722387728,1782480556);
INSERT INTO highlights VALUES('3300056202_11_854-946','3300056202',11,'1.5 阅读的5步转化漏斗',unistr('阅读成效=\u000a精力投入×内容适合程度×信息输入速度×内化吸收率×外化行动转化率'),'854-946',5,1722387698,1782480556);
INSERT INTO highlights VALUES('3300056202_10_3074-3169','3300056202',10,'1.4 阅读目的——最关键因素','首先，在这个日新月异的时代，确实我们必须不断地学习新东西，研究新问题。但追热点、风口的前提是我们已经有了牢固的根基，特别是对于处于职业生涯早期的读者来说，如果基础不牢就去追逐流行，是危险的。','3074-3169',5,1722387635,1782480556);
INSERT INTO highlights VALUES('3300056202_10_3305-3331','3300056202',10,'1.4 阅读目的——最关键因素','其次，不用以对商业领袖、投资人的知识要求来衡量自己。','3305-3331',5,1722387631,1782480556);
INSERT INTO highlights VALUES('3300056202_10_3394-3459','3300056202',10,'1.4 阅读目的——最关键因素',unistr('此时如果我们用80%的知识与别人100%的知识来竞争，那么只会输得很惨。\u000a'),'3394-3459',5,1722387624,1782480556);
INSERT INTO highlights VALUES('3300056202_10_2721-2788','3300056202',10,'1.4 阅读目的——最关键因素','真正会读书的人，先要了解，我应该要读哪些书，我为什么要读这本书，我期待从读这本书中学习到什么。明确了这些问题，读书的时候才会更有效率。','2721-2788',5,1722387570,1782480556);
INSERT INTO highlights VALUES('3300056202_10_2497-2535','3300056202',10,'1.4 阅读目的——最关键因素','要成为高手，第一要务就是明确自己的学习目的，然后聚焦在自己的目的上，展开阅读','2497-2535',5,1722387545,1782480556);
INSERT INTO highlights VALUES('3300056202_10_810-899','3300056202',10,'1.4 阅读目的——最关键因素','很多知识，听起来高大上，但实际上解决不了现实问题，或者和自己的切身生活相距甚远。这种知识只能被当作谈资，泛读、闲读它们即可，万万不可把它们作为阅读的主体，把主要精力耗费在它们上。','810-899',5,1722302350,1782480556);
INSERT INTO highlights VALUES('3300056202_10_634-669','3300056202',10,'1.4 阅读目的——最关键因素','最重要的事情是：明确的阅读目的。','634-669',5,1722302330,1782480556);
INSERT INTO highlights VALUES('3300056202_9_1083-1183','3300056202',9,'1.3 核心原则：以我为主，学以致用','学习的时候应该轻记忆，重理解，重点在举一反三，把知识迁移到自己的实际场景中。','1083-1183',5,1722302316,1782480556);
INSERT INTO highlights VALUES('3300056202_9_593-674','3300056202',9,'1.3 核心原则：以我为主，学以致用','在职场人的学习中，“以我为主，学以致用”是核心原则。职场人的学习，应该围绕自己的实际需求，着重联系自己既有的经验，以学习之后的运用为目标，这样才能更有成效地学习。','593-674',5,1722302316,1782480556);
INSERT INTO highlights VALUES('3300056202_8_1388-1402','3300056202',8,'1.2 成年人学习的特点','3.倾向于实用的学习准备状态','1388-1402',5,1722302315,1782480556);
INSERT INTO highlights VALUES('3300056202_8_1079-1085','3300056202',8,'1.2 成年人学习的特点','2.关联经验','1079-1085',5,1722302315,1782480556);
INSERT INTO highlights VALUES('3300056202_8_1438-1492','3300056202',8,'1.2 成年人学习的特点','学习准备状态，是指促进学习者从一个学习阶段进入下一个学习阶段的发展任务，如果做好了准备就可以进入下一个阶段。','1438-1492',5,1722302315,1782480556);
INSERT INTO highlights VALUES('3300056202_8_1905-1931','3300056202',8,'1.2 成年人学习的特点','“不愤不启，不悱不发。举一隅不以三隅反，则不复也。”','1905-1931',5,1722302315,1782480556);
INSERT INTO highlights VALUES('3300056202_8_689-695','3300056202',8,'1.2 成年人学习的特点','1.自我导向','689-695',5,1722301959,1782480556);
INSERT INTO highlights VALUES('3300056202_8_625-637','3300056202',8,'1.2 成年人学习的特点','成年人学习的五大基本特征','625-637',5,1722301954,1782480556);
INSERT INTO highlights VALUES('3300056202_7_1986-2015','3300056202',7,'1.1 职场人阅读的四大困惑：忙、慢、忘、无用','对于职场人来说，知识还不是力量，能实际使用的知识才是力量。','1986-2015',5,1722301925,1782480556);
INSERT INTO highlights VALUES('3300056202_7_1803-1891','3300056202',7,'1.1 职场人阅读的四大困惑：忙、慢、忘、无用',unistr('从这个角度来说，我们读了多少书并不重要，重要的是阅读之后，有多少知识能够为我们所用，真正被运用到我们的工作、生活当中。\u000a'),'1803-1891',5,1722301909,1782480556);
INSERT INTO highlights VALUES('3300056202_7_1658-1679','3300056202',7,'1.1 职场人阅读的四大困惑：忙、慢、忘、无用','职场人的阅读成效=可提高行动能力的信息增量','1658-1679',5,1722301867,1782480556);
INSERT INTO highlights VALUES('3300056202_7_1066-1134','3300056202',7,'1.1 职场人阅读的四大困惑：忙、慢、忘、无用','我们要讨论“职场人如何提高阅读效率”，先要定义清楚什么是阅读的成效，然后才能讨论如何在有限的时间内提高成效。职场人阅读，是为了获取知识。','1066-1134',5,1722217795,1782480556);
INSERT INTO highlights VALUES('3300056202_6_1984-2067','3300056202',6,'第1章 适合职场人的四步高效阅读法','问题是：不会选择学习的内容。他的学习没有明确的方向，纯粹是兴趣使然，充其量只能算一种修身养性的业余爱好而已。这样的学习，效率极低，其实和打游戏、追连续剧没有本质区别。','1984-2067',5,1722217628,1782480556);
INSERT INTO highlights VALUES('3300056202_6_1135-1166','3300056202',6,'第1章 适合职场人的四步高效阅读法','“艾森豪威尔矩阵”来划分，学习属于典型的“重要但不紧急”的事情','1135-1166',5,1722217573,1782480556);
INSERT INTO highlights VALUES('3300056202_5_5016-5069','3300056202',5,'自序','多年以来，一直在自己的阅读中实践、探索各种阅读方法，并且无论工作多忙，一直保持每天阅读20万字以上的习惯。','5016-5069',5,1722217371,1782480556);
INSERT INTO highlights VALUES('3300056202_5_4914-4947','3300056202',5,'自序','本书的写作全部是在从每天早晨6点起床到8点半上班这个时间段进行的。','4914-4947',5,1722217339,1782480556);
INSERT INTO highlights VALUES('3300056202_5_4476-4514','3300056202',5,'自序','对内容本身的兴趣，其实会极大地影响阅读时的注意力，从而影响阅读速度和理解力。','4476-4514',5,1722217291,1782480556);
INSERT INTO highlights VALUES('3300056202_5_3069-3100','3300056202',5,'自序','因为一本书通常的篇幅是15万~20万字，3小时左右即可通读完。','3069-3100',5,1722215912,1782480556);
INSERT INTO highlights VALUES('3300056202_5_2860-2908','3300056202',5,'自序','作为职场业余读书者，与其为了加快阅读速度而损失对内容的理解，不如在选书和消化吸收上多下一些功夫。','2860-2908',5,1722215890,1782480556);
INSERT INTO highlights VALUES('3300056202_5_1709-1776','3300056202',5,'自序','首先，职场人阅读的首要目的通常是解决自己工作生活中的问题，如果阅读的内容无法改善我们的工作、生活，往往就会读不进去，读了也会很快忘掉。','1709-1776',5,1722215762,1782480556);
INSERT INTO highlights VALUES('3300116836_51_2576-2613','3300116836',51,'第三章 通过思维模型的网格获得普世智慧','我认为你也应该用10%到20%的时间努力了解所有其他学科中全部的伟大思想。','2576-2613',0,1731122949,1782480554);
INSERT INTO highlights VALUES('3300116836_51_2211-2246','3300116836',51,'第三章 通过思维模型的网格获得普世智慧','通识能力的专才，是对一个专业领域了解较深，对其他一些专业领域浅显了解。','2211-2246',0,1731113848,1782480554);
INSERT INTO highlights VALUES('3300116836_51_2071-2085','3300116836',51,'第三章 通过思维模型的网格获得普世智慧','，另一类是有多种观点的狐狸。','2071-2085',0,1731113809,1782480554);
INSERT INTO highlights VALUES('3300116836_51_2055-2071','3300116836',51,'第三章 通过思维模型的网格获得普世智慧','一类是对世界有着统一大视角的刺猬','2055-2071',0,1731113807,1782480554);
INSERT INTO highlights VALUES('3300116836_51_607-645','3300116836',51,'第三章 通过思维模型的网格获得普世智慧','因为你不了解关键学科的宏大理念，你开始做出决定却没有考虑到世界是如何运转的。','607-645',0,1731113590,1782480554);
INSERT INTO highlights VALUES('3300116836_50_14619-14674','3300116836',50,'第一部分 获得普世智慧','要将第一性原理思维应用于价值投资领域，需要考虑几个基本真理。如果你想成为一个好的投资者，请理解并实践以下几点：','14619-14674',0,1731112553,1782480554);
INSERT INTO highlights VALUES('3300116836_50_14454-14473','3300116836',50,'第一部分 获得普世智慧','两个物体之间的吸引力取决于它们的距离。','14454-14473',0,1731112520,1782480554);
INSERT INTO highlights VALUES('3300116836_50_13924-13941','3300116836',50,'第一部分 获得普世智慧','必须使用一个孩子能理解的简单语言时','13924-13941',0,1729184748,1782480554);
INSERT INTO highlights VALUES('3300116836_50_13709-13815','3300116836',50,'第一部分 获得普世智慧',unistr('费曼技巧有四个简单的步骤：\u000a1. 挑选并研究一个主题。\u000a2. 拿出一张白纸，在纸的顶端写上你想学的某个主题。'),'13709-13815',0,1729184740,1782480554);
INSERT INTO highlights VALUES('3300116836_50_12678-12754','3300116836',50,'第一部分 获得普世智慧','在实践中，你不必为了获得第一性原理思维的好处而将每个问题都简化到原子级别，你只需要比大多数人更深入一两个层次。不同的解决方案将在不同的抽象层面得以呈现。','12678-12754',0,1729067191,1782480554);
INSERT INTO highlights VALUES('3300116836_50_11967-11995','3300116836',50,'第一部分 获得普世智慧','第一性原理指的是不能归纳为任何其他原则的起源或主要概念。','11967-11995',0,1729067091,1782480554);
INSERT INTO highlights VALUES('3300116836_50_11796-11821','3300116836',50,'第一部分 获得普世智慧','八个字就可以将好与伟大区分开来：完美执行基本原则。','11796-11821',0,1729067066,1782480554);
INSERT INTO highlights VALUES('3300116836_50_11387-11449','3300116836',50,'第一部分 获得普世智慧','至于方法，可能有一百万个，但原则很少，只有几个。把握原则的人可以成功地选择自己的方法。尝试方法而忽视原则的人肯定会遇到麻烦。','11387-11449',0,1729066804,1782480554);
INSERT INTO highlights VALUES('3300116836_50_9485-9524','3300116836',50,'第一部分 获得普世智慧','通过主题阅读，你能够将这些书中的信息与你自己的生活经验和自身知识编织成一张网络','9485-9524',0,1729066430,1782480554);
INSERT INTO highlights VALUES('3300116836_50_9609-9683','3300116836',50,'第一部分 获得普世智慧','这么做很有意思——从不同学科看似毫不相干的想法中找出联系。这项活动的重要性我怎么强调都不为过，因为在我的投资生涯中，它经常会给我带来许多幸运和机遇。','9609-9683',0,1729066418,1782480554);
INSERT INTO highlights VALUES('3300116836_50_8451-8489','3300116836',50,'第一部分 获得普世智慧','之所以把阅读分级，是因为我们必须先达到一个水平，才能提升到下一个更高的水平。','8451-8489',0,1729066271,1782480554);
INSERT INTO highlights VALUES('3300116836_50_8381-8419','3300116836',50,'第一部分 获得普世智慧','艾德勒和范多伦提出了阅读的四个层次：基础阅读、检视阅读、分析阅读和主题阅读。','8381-8419',0,1729066211,1782480554);
INSERT INTO highlights VALUES('3300116836_50_7769-7858','3300116836',50,'第一部分 获得普世智慧','如果一本书经受住了时间考验，经过五十年、一百年或五百年仍然广为流传，是因为其中蕴含着永恒的智慧，那它就有望在今后的五十年、一百年或五百年里仍然传世——原因就是，它的智慧是永恒的。','7769-7858',0,1729066129,1782480554);
INSERT INTO highlights VALUES('3300116836_50_7706-7765','3300116836',50,'第一部分 获得普世智慧','迪效应是指科技或创意等不会自然消亡的东西的预期寿命与当前年龄成正比，所以每增加一段生存期，就意味着剩余的预期寿命更长。','7706-7765',0,1729066118,1782480554);
INSERT INTO highlights VALUES('3300116836_50_7214-7279','3300116836',50,'第一部分 获得普世智慧',unistr('哪怕是最小的一家书店，仍然蕴藏着比电视史上所呈现的思想更具价值的创意。”\u000a'),'7214-7250',0,1729066035,1782480554);
INSERT INTO highlights VALUES('3300116836_50_7049-7100','3300116836',50,'第一部分 获得普世智慧','”他的主要论点是，媒体所报道的是噪声而不是信息，但大多数人没有意识到媒体就是以引起我们的注意而牟利的。','7049-7100',0,1729066016,1782480554);
INSERT INTO highlights VALUES('3300116836_50_6877-6918','3300116836',50,'第一部分 获得普世智慧','阅读旧新闻，你很快就会发现，你的最终目标的预期寿命比绝大多数新闻头条的生命都要长。','6877-6918',0,1729065982,1782480554);
INSERT INTO highlights VALUES('3300116836_50_6445-6507','3300116836',50,'第一部分 获得普世智慧',unistr('真正稀缺的商品在不久的未来将会受到人类的关注。\u000a——萨提亚·纳德拉'),'6445-6507',0,1729065916,1782480554);
INSERT INTO highlights VALUES('3300116836_50_5758-5831','3300116836',50,'第一部分 获得普世智慧','然而，仅仅阅读不足以增长你的知识。学习一些有见地的东西还需要你付出努力。你必须读一些超越你当前水平的东西，你需要找到比你更了解某一特定主题的作家。','5758-5831',0,1729065850,1782480554);
INSERT INTO highlights VALUES('3300116836_50_5234-5252','3300116836',50,'第一部分 获得普世智慧','帮你找寻人生意义、了解自我、改善生活','5234-5252',0,1729065794,1782480554);
INSERT INTO highlights VALUES('3300116836_50_4862-4921','3300116836',50,'第一部分 获得普世智慧','因此，矛盾的是，当你读的书越多，你会发现未读的书也越来越多，而不是更少。这是因为你的好奇心会随着阅读每一本好书而增长。','4862-4921',0,1729065770,1782480554);
INSERT INTO highlights VALUES('3300116836_50_3017-3070','3300116836',50,'第一部分 获得普世智慧','这给了我们一种定义成功投资者的方法，即时间对他们的约束已超过金钱。最终的地位象征是时间。时间就是新的金钱。','3017-3070',0,1729065575,1782480554);
INSERT INTO highlights VALUES('3300116836_50_2573-2621','3300116836',50,'第一部分 获得普世智慧','因此，三人行，必有我师。弄清楚你要去哪里，看看谁去过那里。知识来自经验，但不一定非得是你的经验。','2573-2621',0,1729065532,1782480554);
INSERT INTO highlights VALUES('3300116836_49_5414-5439','3300116836',49,'第一章 引言：你能做的最好的投资就是投资自己','正是出于这个原因，巴菲特尽量避免长时间的日常通勤。','5414-5439',0,1729046582,1782480554);
INSERT INTO highlights VALUES('3300116836_49_5272-5341','3300116836',49,'第一章 引言：你能做的最好的投资就是投资自己','这相当于花不到1美分就能买到1美元。这就是为什么好书是最被低估的资产类别：随着时间的推移，正确的想法就算不能价值亿万美元，也能价值千万美元','5272-5341',0,1729046565,1782480554);
INSERT INTO highlights VALUES('3300116836_49_2762-2874','3300116836',49,'第一章 引言：你能做的最好的投资就是投资自己',unistr('1.所存储信息的准确性和相关性。\u000a2.按需查找或检索信息的能力。\u000a3.在需要时使用这些信息的能力，即应用这些信息的能力。'),'2762-2874',0,1729046336,1782480554);
INSERT INTO highlights VALUES('3300116836_49_2504-2523','3300116836',49,'第一章 引言：你能做的最好的投资就是投资自己','每天读500页的书对你来说可能不现实。','2504-2523',0,1729046323,1782480554);
INSERT INTO highlights VALUES('3300116836_49_1530-1555','3300116836',49,'第一章 引言：你能做的最好的投资就是投资自己','所有人都可以努力多学些知识，但大多数人不会投入努力','1530-1555',0,1729046220,1782480554);
INSERT INTO highlights VALUES('3300116836_49_1198-1252','3300116836',49,'第一章 引言：你能做的最好的投资就是投资自己','巴菲特把自己许多成功的决定归功于他令人难以置信的阅读习惯。他估计，自己每天花在阅读和思考上的时间多达80%。','1198-1252',0,1729046194,1782480554);
INSERT INTO highlights VALUES('34632152_11_1481-1518','34632152',11,'在法的门前','“这儿除了你，谁都不许进去，因为这道门只是为你开的。我现在要去关上它了。”','1481-1518',5,1716785447,1782480558);
INSERT INTO highlights VALUES('34632152_10_3129-3178','34632152',10,'乡村医生','他们已经失去了旧信仰；牧师坐在家中，撕着一件又一件弥撒服；医生凭他动手术的纤弱之手，却应当无所不能','3129-3178',5,1716715740,1782480558);
INSERT INTO highlights VALUES('34632152_10_2961-2998','34632152',10,'乡村医生','可怜的孩子，你没救了。我找到了你的大伤口；你就要毁在这侧身体的这朵奇葩上。','2961-2998',5,1716715691,1782480558);
INSERT INTO highlights VALUES('34632152_10_2817-2873','34632152',10,'乡村医生','玫瑰红色，但各处深浅不一，中间颜色深，越往边上颜色越浅，呈小颗粒状，还有东一块西一块的瘀血，像露天矿一样裸露着。','2817-2873',5,1716715658,1782480558);
INSERT INTO highlights VALUES('34632152_10_1340-1381','34632152',10,'乡村医生','否则我就不去了，不管这有多紧急。我从未想过走这一趟得以这个姑娘为代价，得把她给你。','1340-1381',5,1716715111,1782480558);
INSERT INTO highlights VALUES('34632152_10_1059-1103','34632152',10,'乡村医生','但我随即意识到，我根本不认识他；也不知道他来自何方，现在谁也不肯帮忙，他却主动雪中送炭。','1059-1103',5,1716715069,1782480558);
INSERT INTO highlights VALUES('34632152_10_984-1034','34632152',10,'乡村医生','她刚一走近，马夫就抱住了她，把脸贴到她的脸上。她尖叫一声，逃回我身边；她的脸颊上印着两排红红的齿印。','984-1034',5,1716715043,1782480558);
INSERT INTO highlights VALUES('34632152_10_483-514','34632152',10,'乡村医生','我身穿皮衣，提着手术包，已经站在院子里准备出发；却没有马，马。','483-514',5,1716714881,1782480558);
INSERT INTO highlights VALUES('34632152_9_17043-17104','34632152',9,'在流放地','所有其他人从机器中获得的解脱，军官没有得到；他双唇紧闭，眼睛睁着，恍若生者，目光安详，充满信念，一根大铁钉穿透了他的额头。','17043-17104',5,1716714266,1782480558);
INSERT INTO highlights VALUES('34632152_9_8323-8356','34632152',9,'在流放地','上百个犯人临死前吸过咬过的衔嘴现在让他含在嘴里，他怎么会不恶心呢？','8323-8356',5,1716708139,1782480558);
INSERT INTO highlights VALUES('34632152_9_7273-7321','34632152',9,'在流放地','军官不停地从旁边瞧着旅行者，似乎想从他的脸上看出他对处决的印象，至少他已为旅行者做了粗浅的讲解。','7273-7321',5,1716706669,1782480558);
INSERT INTO highlights VALUES('34632152_9_6850-6882','34632152',9,'在流放地','这时便不会再发生什么了，犯人开始辨认文字。他撅着嘴，仿佛在聆听。','6850-6882',5,1716706522,1782480558);
INSERT INTO highlights VALUES('34632152_9_6436-6482','34632152',9,'在流放地','耙开始写字；等它在犯人的背上写完第一遍后，棉花层就会转动，把身体缓缓卷到一旁，为耙腾出地方。','6436-6482',5,1716705143,1782480558);
INSERT INTO highlights VALUES('34632152_9_6173-6208','34632152',9,'在流放地','身体的其他地方用来刻装饰性图案。您现在可以赞赏耙和整个机器的运作了吗？','6173-6208',5,1716705078,1782480558);
INSERT INTO highlights VALUES('34632152_9_4852-4900','34632152',9,'在流放地','不过，我可以明天，等机器——它一用起来就弄得很脏，这是它唯一的缺点——打扫干净后，补做详尽的解释','4852-4900',5,1716704785,1782480558);
INSERT INTO highlights VALUES('34632152_9_4304-4350','34632152',9,'在流放地','这个人非但不站起来请求原谅，反而抱住主人的腿，摇着主人，喊道：‘扔掉鞭子，不然我就吃了你！’','4304-4350',5,1716704653,1782480558);
INSERT INTO highlights VALUES('34632152_9_3292-3365','34632152',9,'在流放地','“我们的判决听起来并不严厉。用耙把被判决者所触犯的戒条写在他身上。比如在这个被判决者的身上，”——军官指了指被判决者——“将要写：尊敬你的上级！”','3292-3365',5,1716704003,1782480558);
INSERT INTO highlights VALUES('34632152_9_2754-2785','34632152',9,'在流放地','人一被捆牢，床就动起来。它上下左右同时颤动，细微而迅速地抽搐着','2754-2785',5,1716703884,1782480558);
INSERT INTO highlights VALUES('34632152_9_2503-2524','34632152',9,'在流放地','在这两口箱子之间，耙顺着一根钢绳上下移动。','2503-2524',5,1716703823,1782480558);
INSERT INTO highlights VALUES('34632152_9_1636-1648','34632152',9,'在流放地','中间上下移动的部分叫耙。','1636-1648',5,1716703574,1782480558);
INSERT INTO highlights VALUES('34632152_9_1016-1043','34632152',9,'在流放地','在此之前还需要人来操作，从现在起，机器就完全自行运转了','1016-1043',5,1716703318,1782480558);
INSERT INTO highlights VALUES('34632152_9_956-988','34632152',9,'在流放地','“军服意味着故乡；我们不愿失去故乡。——您还是看看这台机器吧，”','956-988',5,1716703298,1782480558);
INSERT INTO highlights VALUES('34632152_9_627-674','34632152',9,'在流放地','被判决者看上去像狗一样顺从，似乎尽可以放他在山坡上乱跑，只要处决开始时吹声口哨，他便应声而来。','627-674',5,1716703239,1782480558);
INSERT INTO highlights VALUES('34632152_6_452-493','34632152',6,'变形记','一天清晨，格雷戈尔·萨姆沙从一串不安的梦中醒来时，发现自己在床上变成一只硕大的虫子','452-493',5,1716571940,1782480558);
INSERT INTO highlights VALUES('34632152_5_8148-8223','34632152',5,'判决','他仍紧握栏杆，透过栏杆间的空隙，看准了一辆公共汽车，汽车的噪音将很容易掩盖他的落水声，他轻声说道：“亲爱的双亲，我一直都是爱你们的。”松开手落了下去。','8148-8223',5,1716571870,1782480558);
INSERT INTO highlights VALUES('34632152_5_7892-7942','34632152',5,'判决','直到现在，你只知道你自己！你原本是个无辜的孩子，其实却更是个魔鬼！——所以你听着：我现在就判你溺死！','7892-7942',5,1716571791,1782480558);
INSERT INTO highlights VALUES('34632152_5_6638-6698','34632152',5,'判决','“滑稽演员！”格奥尔格憋不住，一下子喊出了口，马上意识到惹祸了，赶紧咬住舌头，却已太迟，他两眼发直，直咬到舌头疼痛难忍。','6638-6698',5,1716571556,1782480558);
INSERT INTO highlights VALUES('34632152_5_5823-5872','34632152',5,'判决','知道，你想把我盖上，我的小孬种，可我还没被盖上呢。要对付你，我的最后一点力气就够了，而且绰绰有余！','5823-5872',5,1716565987,1782480558);
INSERT INTO highlights VALUES('34632152_5_3820-3856','34632152',5,'判决','即便就他孤独的生活方式而言，这几乎不可能，反正他至少不该从我这儿知道这事','3820-3856',5,1716564941,1782480558);
INSERT INTO highlights VALUES('34632152_5_3293-3313','34632152',5,'判决','“我的父亲仍然是个巨人。”格奥尔格想着。','3293-3313',5,1716564880,1782480558);
INSERT INTO highlights VALUES('34632152_5_2951-2971','34632152',5,'判决','来到父亲的房间，他已经好几个月没来这儿了','2951-2971',5,1716564806,1782480558);
INSERT INTO highlights VALUES('34632152_5_2367-2388','34632152',5,'判决','有这样的朋友，格奥尔格，那你原本就不该订婚','2367-2388',5,1716564692,1782480558);
INSERT INTO highlights VALUES('34632152_5_2090-2165','34632152',5,'判决','格奥尔格却宁可给他写这种事，也不愿坦白，他自己一个月前与一位富家之女弗丽达·勃兰顿菲尔德小姐订婚了。他经常向未婚妻说起这位朋友以及与他通信的特别情形。','2090-2165',5,1716564648,1782480558);
INSERT INTO highlights VALUES('34632152_5_2012-2076','34632152',5,'判决','都向朋友报告了一个无关紧要的男人与一个同样无关紧要的女人订婚的事，结果完全与格奥尔格的初衷相悖，这位朋友开始对这件怪事产生了兴趣','2012-2076',5,1716179917,1782480558);
INSERT INTO highlights VALUES('834465_35_6422-6442','834465',68,'第二十九章','这就叫屌毛出得比眉毛晚，长得倒比眉毛长。','6439-6459',5,1702069291,1782480562);
INSERT INTO highlights VALUES('834465_35_4505-4550','834465',68,'第二十九章','许三观说：“我想吃一盘炒猪肝，我想喝二两黄酒，我想卖了血以后就去吃炒猪肝，就去喝黄酒……”','4522-4567',5,1702069096,1782480562);
INSERT INTO highlights VALUES('834465_34_24456-24482','834465',67,'第二十八章','来喜说：“我不能喝水，我把血卖给你，我就不能喝水。”','24712-24738',5,1702068260,1782480562);
INSERT INTO highlights VALUES('834465_32_16200-16340','834465',65,'第二十六章','然后，许三观来到医院外面，在一堆乱砖上坐下来，深秋的风吹得他身体一阵阵发冷，他将双手插在袖管里，脖子缩到衣领里面。他一直坐在那里，心里想着根龙，还有阿方，想到他们两个人第一次带着他去卖血，他们教他卖血前要喝水，卖血后要吃一盘炒猪肝，喝二两黄酒……想到最后，许三观坐在那里哭了起来。','16218-16358',5,1702061139,1782480562);
INSERT INTO highlights VALUES('834465_32_4702-4762','834465',65,'第二十六章','一乐回过头来，对许三观点点头，接着低下头进了船舱。许三观仍然站在检票口，直到船开走了，他才转身走出了候船室，往家里走去。','4719-4779',5,1702060324,1782480562);
INSERT INTO highlights VALUES('834465_31_13483-13550','834465',64,'第二十五章','“我和林芬芳只有一次，你们妈和何小勇也只有一次。我今天说这些，就是要让你们知道，其实我和你们妈一样，都犯过生活错误。你们不要恨她……”','13710-13777',5,1702059865,1782480562);
INSERT INTO highlights VALUES('834465_31_7944-7991','834465',64,'第二十五章','许三观说：“你已经在水里了，这世上只有我一个人还想着救你，我要是也被拉到水里，就没人救你了。”','7961-8008',5,1702059583,1782480562);
INSERT INTO highlights VALUES('834465_27_3385-3418','834465',60,'第二十一章','他开始哭泣了，先是没有声音地流泪，接着他扑在桌子上呜呜地大哭起来。','3402-3435',5,1702057315,1782480562);
INSERT INTO highlights VALUES('834465_25_3826-3866','834465',58,'第十九章','于是许三观一家人从白天睡到晚上，又从晚上睡到白天，一睡睡到了这一年的十二月七日。','3843-3883',5,1702056468,1782480562);
INSERT INTO highlights VALUES('834465_25_2076-2099','834465',58,'第十九章','以前有二十来家饭店，现在只有胜利饭店还在营业。','2093-2116',5,1702056199,1782480562);
INSERT INTO highlights VALUES('834465_20_4907-4942','834465',53,'第十四章','林芬芳话音未落，许三观霍地站了起来，他的双手扑向了林芬芳丰硕的胸脯……','4924-4959',5,1701973734,1782480562);
INSERT INTO highlights VALUES('834465_19_771-811','834465',52,'第十三章','“我卖血啦！我许三观卖了血，替何小勇还了债，我许三观卖了血，又去做了一次乌龟。”','788-828',5,1701973198,1782480562);
INSERT INTO highlights VALUES('834465_18_1295-1373','834465',51,'第十二章','“话不能这么说，”许三观卸着车上的凳子说，“事情都是被逼出来的，人只有被逼上绝路了，才会有办法，没上绝路以前，不是没想到办法，就是想到了也不知道该不该去做。','1522-1600',5,1701973097,1782480562);
INSERT INTO highlights VALUES('834465_17_2474-2577','834465',50,'第十一章','“我不能收你的东西，”李血头拍了一下桌子说，“你要是半年前送来，我还会收下，现在我不会收你的东西了。上次阿方和根龙给我送了两斤鸡蛋来，我一个都没要。我现在是共产党员了，你知道吗？我现在是不拿群众一针一线。”','2491-2594',5,1701945596,1782480562);
INSERT INTO highlights VALUES('834465_17_966-992','834465',50,'第十一章','于是他想到卖血了，想到十年前与阿方和根龙去卖血的情景','983-1009',5,1701945365,1782480562);
INSERT INTO highlights VALUES('834465_17_788-886','834465',50,'第十一章','你们长大了要替我去报复何小勇。你们认识何小勇的两个女儿吗？认识，你们知道何小勇的女儿叫什么名字吗？不知道，不知道没关系，只要能认出来就行。你们记住，等你们长大以后，你们去把何小勇的两个女儿强奸了。','805-903',5,1701945337,1782480562);
INSERT INTO highlights VALUES('834465_15_6621-6679','834465',48,'第九章',unistr('他说：\u000a“他妈的，这一乐不是我儿子了，我就不能随便揍他了。”'),'6638-6696',5,1701927146,1782480562);
INSERT INTO highlights VALUES('834465_14_1762-1828','834465',47,'第八章','我不把一乐送还给他了，以后一乐还由我来抚养，但是这一次，这一次的钱他非出不可，要不我就没脸见人啦……他妈的，便宜了那个何小勇了……”','1779-1845',5,1701911130,1782480562);
INSERT INTO highlights VALUES('834465_14_1557-1599','834465',47,'第八章','一乐又不是我的儿子，我白养了他九年，他花了我多少钱？我不找何小勇算这笔账已经够客气了','1574-1616',5,1701911069,1782480562);
INSERT INTO highlights VALUES('834465_13_10355-10513','834465',46,'第七章',unistr('一乐抬起头来看准了那个人脑袋在什么地方，然后举起石头使劲砸在了那人的头上，那个人“哇”地叫了一声，一乐又连着在他的头上砸了三下，把那个人砸倒在地上，鲜血流了一地。一乐看他不会爬起来了，才扔掉石头，拍了拍手上的灰尘，对吓呆了的二乐和三乐招招手，说：\u000a“回家了。”'),'10343-10501',5,1701879942,1782480562);
INSERT INTO highlights VALUES('834465_13_3081-3123','834465',46,'第七章','一个三十岁的女人和一个八岁的男孩，说起话来就像是两个三十岁的女人或者是两个八岁的男孩','3098-3140',5,1701753630,1782480562);
INSERT INTO highlights VALUES('834465_13_1280-1315','834465',46,'第七章','许玉兰把手套放到箱子的最底层，积到了四副手套时，就可以给三乐织一件线衣','1297-1332',5,1701737589,1782480562);
INSERT INTO highlights VALUES('834465_11_414-436','834465',44,'第五章','可是在一乐的脸上，他们看不到来自许三观的影响','431-453',5,1701688156,1782480562);
INSERT INTO highlights VALUES('834465_9_6557-6649','834465',42,'第三章','“对了，”许玉兰想起了什么，她说，“你听着，到了我过节的时候，我就什么都不做了，就是淘米洗菜的事我都不能做，我要休息了，那几天家里的活全得由你来做了，你听到了没有？你为什么不点头呢？”','6574-6666',5,1701687290,1782480562);
INSERT INTO highlights VALUES('834465_7_6624-6694','834465',40,'第一章','“那女人与李血头的交情，是一个被窝里的交情，她要是去卖血，谁都得站一边先等着，谁要是把她给得罪了，身上的血哪怕是神仙血，李血头也不会要了。”','7061-7131',5,1701595242,1782480562);
INSERT INTO highlights VALUES('834465_7_6135-6198','834465',40,'第一章','阿方接着说：“这就像是我们村里的村长，村长管我们人，李血头就是管我们身上血的村长，让谁卖血，不让谁卖血，全是他一个人说了算数。','6572-6635',5,1701595209,1782480562);
INSERT INTO highlights VALUES('834465_7_5289-5376','834465',40,'第一章','我们早晨什么都没吃，就喝了几碗水，现在又喝了几碗，到了城里还得再喝几碗，一直要喝到肚子又胀又疼，牙根一阵阵发酸……这水喝多了，人身上的血也会跟着多起来，水会浸到血里去的……”','5726-5813',5,1701595090,1782480562);
INSERT INTO highlights VALUES('834465_7_4182-4231','834465',40,'第一章','“我们卖血从来不带粮食，”十九岁的根龙说，“我们卖完血以后要上馆子去吃一盘炒猪肝，喝二两黄酒……”','4619-4668',5,1701584521,1782480562);
INSERT INTO highlights VALUES('834465_6_1029-1067','834465',70,'意大利文版自序','汉语自身的灵活性帮助了我，让我将南方的节奏和南方的气氛注入到了北方的语言之中','1048-1086',5,1701583948,1782480562);
INSERT INTO highlights VALUES('834465_6_485-534','834465',70,'意大利文版自序','佛罗伦萨的语言是由于一首伟大的长诗而荣升为国家的语言，这样的事实在我们中国人看来，如同传说一样美妙','504-553',5,1701582921,1782480562);
INSERT INTO highlights VALUES('834465_6_598-637','834465',70,'意大利文版自序','比起古老的拉丁语，《神曲》的语言似乎更有生机，我相信还有着难以言传的亲切之感。','617-656',5,1701582915,1782480562);
INSERT INTO highlights VALUES('834465_4_1237-1253','834465',69,'附录','屌毛出得比眉毛晚，长得倒比眉毛长','1280-1296',5,1701538609,1782480562);
INSERT INTO highlights VALUES('834465_4_1088-1143','834465',69,'附录','当他的生活极其糟糕时，因为别人的生活同样糟糕，他也会心满意足。他不在乎生活的好坏，但是不能容忍别人和他不一样。','1131-1186',5,1701538579,1782480562);
