INSERT INTO highlights VALUES('40870001_29_3086-3130','40870001',29,'第3章 auto占位符（C++11～C++17）','注意，在C++14中，auto可以为lambda表达式声明形参','3086-3130',0,1731259038,1782480554);
INSERT INTO highlights VALUES('40870001_29_2418-2486','40870001',29,'第3章 auto占位符（C++11～C++17）','虽然C++11标准已经支持在声明成员变量时初始化（见第8章），但是auto却无法在这种情况下声明非静态成员变量','2418-2486',0,1731242028,1782480554);
INSERT INTO highlights VALUES('40870001_29_2162-2214','40870001',29,'第3章 auto占位符（C++11～C++17）','当使用条件表达式初始化auto声明的变量时，编译器总是使用表达能力更强的类型：','2162-2214',0,1731241991,1782480554);
INSERT INTO highlights VALUES('40870001_29_2027-2136','40870001',29,'第3章 auto占位符（C++11～C++17）','细心的读者可能会注意到，如果将赋值代码替换为int m = 10.0;，则编译器会进行缩窄转换，最终结果可能会在给出一条警告信息后编译成功，而在使用auto声明变量的情况下编译器是直接报错的。','2027-2136',0,1731241964,1782480554);
INSERT INTO highlights VALUES('40870001_29_1405-1485','40870001',29,'第3章 auto占位符（C++11～C++17）','用一个auto关键字声明多个变量的时候，编译器遵从由左往右的推导规则，以最左边的表达式推断auto的具体类型','1405-1485',0,1731241912,1782480554);
INSERT INTO highlights VALUES('40870001_27_1465-1549','40870001',27,'2.2 嵌套命名空间的简化语法','请注意，inline可以出现在除第一个namespace之外的任意namespace之前。','1465-1549',0,1731241685,1782480554);
INSERT INTO highlights VALUES('40870001_27_449-482','40870001',27,'2.2 嵌套命名空间的简化语法','幸运的是，C++17标准允许使用一种更简洁的形式描述嵌套命名空间，','449-482',0,1731241589,1782480554);
INSERT INTO highlights VALUES('40870001_26_2933-3000','40870001',26,'第2章 内联和嵌套命名空间（C++11～C++20）','示例代码中只能有一个内联命名空间，否则编译时会造成二义性问题，编译器不知道使用哪个内联命名空间的foo函数。','2933-3000',0,1731241554,1782480554);
INSERT INTO highlights VALUES('40870001_26_1806-1851','40870001',26,'第2章 内联和嵌套命名空间（C++11～C++20）','实际上，该特性可以帮助库作者无缝升级库代码，让客户不用修改任何代码也能够自由选择新老库代码','1806-1851',0,1731241410,1782480554);
INSERT INTO highlights VALUES('40870001_26_1063-1149','40870001',26,'第2章 内联和嵌套命名空间（C++11～C++20）','C++11标准增强了命名空间的特性，提出了内联命名空间的概念。内联命名空间能够把空间内函数和类型导出到父命名空间中，这样即使不指定子命名空间也可以使用其空间内的函数和类型了','1063-1149',0,1731241362,1782480554);
INSERT INTO highlights VALUES('40870001_22_456-501','40870001',22,'1.2.4 新字符串连接','如果其中一个字符串字面量没有前缀，则将其视为与另一个字符串字面量具有相同前缀的字符串字面量','456-501',0,1731240716,1782480554);
INSERT INTO highlights VALUES('40870001_21_1057-1098','40870001',21,'1.2.3 wchar_t存在的问题','但是起初在定义wchar_t时并没有规定其占用内存的大小','1057-1098',0,1731240715,1782480554);
INSERT INTO highlights VALUES('40870001_20_1337-1407','40870001',20,'1.2.2 使用新字符类型char16_t和char32_t','char utf8c = u8''好''是无法通过编译的，因为存储“好”需要3字节，显然utf8c只能存储1字节，所以会编译失败。','1337-1407',0,1731220464,1782480554);
INSERT INTO highlights VALUES('40870001_20_1215-1265','40870001',20,'1.2.2 使用新字符类型char16_t和char32_t','因为在C++11标准中u8只能作为字符串字面量的前缀，而无法作为字符的前缀','1215-1265',0,1731220436,1782480554);
INSERT INTO highlights VALUES('40870001_17_3499-3527','40870001',17,'第1章 新基础类型（C++11～C++20）','在C++中应该尽量少使用宏，用模板取而代之是明智的选择。','3499-3527',0,1731185282,1782480554);
INSERT INTO highlights VALUES('40870001_17_863-970','40870001',17,'第1章 新基础类型（C++11～C++20）','我们知道long通常表示一个32位整型，而long long则是用来表示一个64位的整型。不得不说，这种命名方式简单粗暴。不仅写法冗余，而且表达的含义也并不清晰。','863-970',0,1728275881,1782480554);
INSERT INTO highlights VALUES('40870001_8_374-484','40870001',8,'本书特色','本书并不是直接告诉读者C++11～C++20的新特性该怎么使用，而是希望读者通过本书能够了解新特性诞生的前因后果，用实际例子探讨过去C++中的缺陷以及新特性如何修复和完善优化，并且尽可能地描述新特性在编译器中的实现原理。','374-484',0,1728271406,1782480554);
INSERT INTO highlights VALUES('40870001_6_702-729','40870001',6,'前言','他认为新特性的增强足以使C++11感觉像是一种新语言。','702-729',0,1728271339,1782480554);
