INSERT INTO highlights VALUES('3300054736_7_850-911','3300054736',7,'第二章 二次创业 遭遇“黑单事件”','但是这家公司的产品出来之后，广告人可以用计算机完成广告创意的过程，告别了原始的广告制作方法，创意喷涌，这让该产品风靡一时。','850-911',5,1721094868,1782480556);
INSERT INTO highlights VALUES('3300054736_6_21140-21222','3300054736',6,'第一章 研发反病毒卡——创业初体验','如《一万小时天才理论》里阐述的，在任何一个领域要想出众，都是要通过至少一万小时的练习，并且这些练习并不是在你的舒适区里进行的，而是你在容易犯错的地方进行的精深练习。','21140-21222',5,1721094430,1782480556);
INSERT INTO highlights VALUES('3300054736_6_19405-19475','3300054736',6,'第一章 研发反病毒卡——创业初体验','这并没有熄灭我的创业梦想。这些事情唯一改变的是我对失败的态度。我不再把失败看作一个挫折或者不祥之兆，我把失败看作一条进入前方风景的必经之路。','19405-19475',5,1721094119,1782480556);
INSERT INTO highlights VALUES('3300054736_6_18826-18919','3300054736',6,'第一章 研发反病毒卡——创业初体验','但是，我当时已经慢慢领悟到，光有技术是没有用的，尤其是学校里学习的技术，拿到社会上并不怎么管用。而真实社会的光怪陆离，怎么去做营销和管理，则是创业中比技术重要或者说和技术同等重要的工作。','18826-18919',5,1721093996,1782480556);
INSERT INTO highlights VALUES('3300054736_6_17626-17640','3300054736',6,'第一章 研发反病毒卡——创业初体验','做产品，必须有一定的专注度。','17626-17640',5,1721008564,1782480556);
INSERT INTO highlights VALUES('3300054736_6_17081-17109','3300054736',6,'第一章 研发反病毒卡——创业初体验','《广谱防病毒技术》，这本书谈到一个基于病毒的行为做的研究','17081-17109',5,1721008456,1782480556);
INSERT INTO highlights VALUES('3300054736_6_16983-17003','3300054736',6,'第一章 研发反病毒卡——创业初体验','我犯了一个技术员很容易犯的错误——固执。','16983-17003',5,1721008443,1782480556);
INSERT INTO highlights VALUES('3300054736_6_16939-16962','3300054736',6,'第一章 研发反病毒卡——创业初体验','我们的反病毒卡无法升级，这就是做硬件产品的弊端','16939-16962',5,1721008437,1782480556);
INSERT INTO highlights VALUES('3300054736_6_16449-16513','3300054736',6,'第一章 研发反病毒卡——创业初体验','我们不应该忽视错误或试图忘记它们，因为它们为我们指出了道路所在，同时为我们指出了一个事实：那些不敢冒险的人就无法发展他们的才能。','16449-16513',5,1721008314,1782480556);
INSERT INTO highlights VALUES('3300054736_6_6007-6045','3300054736',6,'第一章 研发反病毒卡——创业初体验','“有一天我路过足球场，里面飞过来一个足球，我觉得这个球不错，就抱回宿舍了！”','6007-6045',5,1720885468,1782480556);
INSERT INTO highlights VALUES('3300054736_6_4193-4235','3300054736',6,'第一章 研发反病毒卡——创业初体验','于是，我们想出了一个没有办法的办法，在学校找一些活干，一边干活一边借学校的计算机用。','4193-4235',5,1720885255,1782480556);
INSERT INTO highlights VALUES('3300054736_6_3367-3393','3300054736',6,'第一章 研发反病毒卡——创业初体验','给计算机插上反病毒卡之后，通过调用软件实现整个功能。','3367-3393',5,1720885173,1782480556);
