INSERT INTO highlights VALUES('3300054736_6_2317-2365','3300054736',6,'第一章 研发反病毒卡——创业初体验','其实IBM做PC胜过了苹果，从商业上讲，苹果败给了IBM，但从价值观来说，苹果被当成硅谷的英雄。','2317-2365',5,1720884852,1782480556);
INSERT INTO highlights VALUES('3300054736_6_2204-2238','3300054736',6,'第一章 研发反病毒卡——创业初体验','“产品为王”这个想法对我影响很大，因此这么多年，我一直都是在做产品。','2204-2238',5,1720884830,1782480556);
INSERT INTO highlights VALUES('3300054736_6_715-743','3300054736',6,'第一章 研发反病毒卡——创业初体验','，坐在火车上，我阅读了一本对我影响至深的书——《硅谷热》','715-743',5,1720883919,1782480556);
INSERT INTO highlights VALUES('3300054736_6_1324-1350','3300054736',6,'第一章 研发反病毒卡——创业初体验','一旦某个人有了这种能驾驭未来的威力感，他就会勇往直前','1324-1350',5,1715489570,1782480556);
INSERT INTO highlights VALUES('3300054736_6_874-1014','3300054736',6,'第一章 研发反病毒卡——创业初体验','《硅谷热》总共分三部分：第一部分是“硅谷的崛起”，以苹果公司的传奇故事为主线，讲述了硅谷的发展历史；第二部分是“高技术文明”，从风险投资、创业故事、人物传奇等各个方面描绘了硅谷的生态状况；第三部分是“硅谷的明天”，讲述了硅谷模式在全球的扩散、硅谷面临的全球竞争和对世界的深远影响。','874-1014',5,1715489520,1782480556);
INSERT INTO highlights VALUES('3300054736_4_5500-5556','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','日复一日的工作让人变得疲惫，不过我们可以借助好奇心和内驱力来恢复对生活的能量，让日常的工作变得更有趣和富有意义。','5500-5556',5,1715488685,1782480556);
INSERT INTO highlights VALUES('3300054736_4_5152-5195','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','人一旦有了些成绩，金钱和江湖地位的吸引力就会慢慢减弱，只有内驱力才能推动一个人持续学习','5152-5195',5,1715488634,1782480556);
INSERT INTO highlights VALUES('3300054736_4_5001-5025','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','当年我在方正工作时，可以连续两天不睡觉调一个程序','5001-5025',5,1715488275,1782480556);
INSERT INTO highlights VALUES('3300054736_4_4618-4658','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','实际上驱动很多人在某一领域取得些成绩的，都是兴趣，他们往往是养成终身学习习惯的人','4618-4658',5,1715488221,1782480556);
INSERT INTO highlights VALUES('3300054736_4_4287-4297','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','超越好奇心的是学习力','4287-4297',5,1715488173,1782480556);
INSERT INTO highlights VALUES('3300054736_4_3932-3941','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','不装，不端，有点二','3932-3941',5,1715488154,1782480556);
INSERT INTO highlights VALUES('3300054736_4_3835-3894','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','“保持谦虚，求知若饥，虚心若愚(Stay Humble,Stay Hungry,Stay Foolish)”，市面上有','3835-3894',5,1715488145,1782480556);
INSERT INTO highlights VALUES('3300054736_4_2109-2170','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','再比如，创业既要保持专注，又要大胆尝试，专注可以让工作事半功倍，不过我认为足够任性和做事极端的人才能坚持下去，最终改变世界','2109-2170',5,1715486794,1782480556);
INSERT INTO highlights VALUES('3300054736_4_2018-2062','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','比如“第一性思维”，凡事从问题的本质出发寻找解决方案，在用户的需求中才能找到真正的创新。','2018-2062',5,1715486793,1782480556);
INSERT INTO highlights VALUES('3300054736_4_1777-1825','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','我刚工作时就很生猛，虽然犯了不少错，比如天天给老板写不接地气的战略报告，但是“努力工作”永远没错','1777-1825',5,1715485466,1782480556);
INSERT INTO highlights VALUES('3300054736_4_1826-1875','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','如果你能在聪明和勤奋中占一项，就能超过大量的同龄人；而如果你想站在金字塔尖儿上，聪明和勤奋缺一不可','1826-1875',5,1715485466,1782480556);
INSERT INTO highlights VALUES('3300054736_4_1041-1090','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','在安全领域做的时间越长就越有敬畏心，安全一定是数字化的基础，我们也要找准自己的定位，不能喧宾夺主。','1041-1090',5,1715449556,1782480556);
INSERT INTO highlights VALUES('3300054736_4_897-973','3300054736',4,'前言 你要怼我，请先懂我——给初入职场和早期创业的年轻人的经验分享','互联网进入下半场，产业互联网勃兴，这个时代的主角一定是传统企业。互联网公司要调整心态，甘当配角，帮助传统企业完成数字化改造，帮助实体产业实现数字化转型。','897-973',5,1715449532,1782480556);
INSERT INTO highlights VALUES('35148817_19_2187-2243','35148817',19,'泌乳现象的产生','原来，妻子为了满足丈夫对大胸的渴望，一直不停地往自己胸部涂抹含有雌激素的丰乳霜，然后这些药膏又被蹭到了丈夫身上。','2187-2243',1,1726505070,1782480556);
INSERT INTO highlights VALUES('35148817_19_1471-1500','35148817',19,'泌乳现象的产生','例如，怀孕并不是获得乳房发育和乳汁分泌所需激素的唯一途径。','1471-1500',1,1726504889,1782480556);
INSERT INTO highlights VALUES('35148817_19_1202-1226','35148817',19,'泌乳现象的产生','在生殖腺、前列腺和脑垂体所分泌的激素的共同作用下','1202-1226',1,1726504861,1782480556);
INSERT INTO highlights VALUES('35148817_19_987-1003','35148817',19,'泌乳现象的产生','胎盘类哺乳动物的雌雄两性都有乳腺','987-1003',1,1726504777,1782480556);
INSERT INTO highlights VALUES('35148817_19_1074-1101','35148817',19,'泌乳现象的产生','雄性老鼠的乳腺组织没有导管和乳头，从外表上根本看不出来','1074-1101',1,1726504758,1782480556);
INSERT INTO highlights VALUES('35148817_18_2361-2403','35148817',18,'两性的遗传差异','23号染色体上的少量基因与其他染色体上的基因相互配合，最终决定了男女之间的所有差异。','2361-2403',1,1726504649,1782480556);
INSERT INTO highlights VALUES('35148817_14_841-864','35148817',14,'交配后“抛妻弃子”的例外情况','雄性棘鱼会筑起巢穴，以保护鱼卵免受猎食者的袭击','841-864',5,1724063510,1782480556);
INSERT INTO highlights VALUES('35148817_14_661-777','35148817',14,'交配后“抛妻弃子”的例外情况','雌性排出尚未受精的卵子，而后在附近徘徊的雄性会将精子射在卵子上，并立刻将受精卵拢到一起，以防其他雄性趁机浑水摸鱼。该雄性会继续照顾这些受精卵，并对这份亲子关系信心十足。这就是令一些鱼类和蛙类的雄性在授精之后成为单亲父亲的进化论逻辑。','661-777',5,1724063491,1782480556);
INSERT INTO highlights VALUES('35148817_13_2170-2195','35148817',13,'错失的机会','对于雄性来说，照料孩子无异于在进化竞赛中孤注一掷。','2170-2195',5,1724043054,1782480556);
INSERT INTO highlights VALUES('35148817_13_1958-2126','35148817',13,'错失的机会','实际上，雄性只知道自己的精子进入了雌性体内，一些时日后，雌性生了一个宝宝，但它并不知道雌性有没有在自己没注意时和其他雄性发生性关系，也不知道与卵子结合的究竟是自己的精子还是其他雄性的精子。在这种无法避免的不确定性面前，进化的结果就是，绝大多数雄性哺乳动物在交配完成后，便会立刻离开，转而寻找更多可以受孕的雌性，并让那些雌性独自养育后代。','1958-2126',5,1724043042,1782480556);
INSERT INTO highlights VALUES('35148817_13_1557-1595','35148817',13,'错失的机会','那些摆在雄性眼前的大好机会促成了动物世界中主要由雌性负责养育孩子的普遍现象。','1557-1595',5,1724042973,1782480556);
INSERT INTO highlights VALUES('35148817_13_1106-1145','35148817',13,'错失的机会','如果该雌性是哺乳动物，那么它还要在生产后负责哺乳，这意味着它需要投入更长的时间','1106-1145',5,1724042870,1782480556);
INSERT INTO highlights VALUES('35148817_13_642-660','35148817',13,'错失的机会','第二个因素，即因育儿而放弃的其他机会','642-660',5,1724042798,1782480556);
INSERT INTO highlights VALUES('35148817_13_593-634','35148817',13,'错失的机会','有三个相关因素会影响父母是否会做出照顾后代的“抉择”，第一个因素就是对后代的投入。','593-634',5,1724042790,1782480556);
INSERT INTO highlights VALUES('35148817_12_1858-1904','35148817',12,'谁对后代的投入更多','由此可见，体内受精要求母亲对胚胎做出更多投入，而这一阶段的投入远远超过产卵以及受精时的投入。','1858-1904',5,1724042671,1782480556);
INSERT INTO highlights VALUES('35148817_12_1750-1823','35148817',12,'谁对后代的投入更多','胎生要求动物有特定的内部结构，其中最为复杂就是哺乳动物的胎盘，因为胎盘要负责将母体内的营养物质输送到发育中的胚胎体内，再将胚胎的排泄物传送回母体。','1750-1823',5,1724042648,1782480556);
INSERT INTO highlights VALUES('35148817_8_1973-2044','35148817',8,'人类独特的性征','我想在此提出一个相反的观点：相较于火的使用以及语言、艺术和文字的发展，以娱乐为目的的性行为和更年期的作用与直立行走和脑容量较大的作用同样重要。','1973-2044',5,1724031271,1782480556);
INSERT INTO highlights VALUES('35148817_8_1783-1859','35148817',8,'人类独特的性征','除了直立行走和脑容量较大这两个特点之外，人类还有其他特点，比如相对于其他动物而言，没有那么多毛发；非常依赖工具；会控制并利用火；发展了语言、艺术和文字。','1783-1859',5,1724031211,1782480556);
INSERT INTO highlights VALUES('35148817_8_1521-1559','35148817',8,'人类独特的性征','很明显，人类脑容量的增大和直立行走对人类文明的诞生与发展起到了决定性的作用。','1521-1559',5,1724031157,1782480556);
INSERT INTO highlights VALUES('35148817_8_887-1046','35148817',8,'人类独特的性征','在亲缘关系上，与人类最近的是非洲黑猩猩和倭黑猩猩。人类与它们在DNA上的差异只有1.6%。我们与大猩猩（差异为2.3%）和猩猩（差异为3.6%）在亲缘关系上也比较近。人类祖先与黑猩猩、倭黑猩猩祖先的“分离”仅仅发生在700万年前，与大猩猩祖先的“分离”发生在900万年前，与猩猩祖先的“分离”发生在1 400百万年前。','887-1046',5,1724031073,1782480556);
INSERT INTO highlights VALUES('35148817_7_3567-3633','35148817',7,'哺乳动物的性行为和人类的性行为','倭黑猩猩则在某些方面与人类非常相似：雌性对雄性的接纳会贯穿长达几周的发情期、性行为主要以娱乐为目的、种群中的许多成员都会参与一些合作','3567-3633',5,1724030974,1782480556);
INSERT INTO highlights VALUES('35148817_7_2928-2985','35148817',7,'哺乳动物的性行为和人类的性行为','绝大多数哺乳动物的幼崽都由母亲负责养育，而父亲什么都不管。对于某些鸟类、蛙类和鱼类来说，父亲则是后代的唯一看护者。','2928-2985',5,1724030821,1782480556);
INSERT INTO highlights VALUES('35148817_7_2531-2643','35148817',7,'哺乳动物的性行为和人类的性行为','人类性行为的所有特征构成了我们假定的正常现象，这些特征包括：保持长期的性伴侣关系、共同养育子女、与其他结成性伴侣关系的人保持社会交往、保持性行为的私密性、排卵期具有隐秘性、女性对性接受度的延长、以娱乐为目的、女性有更年期等。','2531-2643',5,1724030777,1782480556);
INSERT INTO highlights VALUES('35148817_7_2447-2496','35148817',7,'哺乳动物的性行为和人类的性行为','大多数孩子都会从父亲那里获得照料。这种照料表现为日常的照顾、教育、保护，以及提供食物、住所和金钱。','2447-2496',5,1724030711,1782480556);
INSERT INTO highlights VALUES('35148817_7_2234-2293','35148817',7,'哺乳动物的性行为和人类的性行为','普遍现象依然是：在任意给定的时间段内，人类社会中的大多数成年人都保持着长期的配偶关系，即被大多数法律认可的一夫一妻制。','2234-2293',5,1724030680,1782480556);
INSERT INTO highlights VALUES('35148817_7_1774-1830','35148817',7,'哺乳动物的性行为和人类的性行为','过去半个世纪发展起来的DNA亲子鉴定技术证明，在美国、英国和意大利，大多数宝宝的父亲的确是妈妈的丈夫或固定男友。','1774-1830',5,1723984415,1782480556);
INSERT INTO highlights VALUES('35148817_7_1292-1321','35148817',7,'哺乳动物的性行为和人类的性行为','由此可见，人类性行为主要以追求性快感为目的，而非孕育后代。','1292-1321',5,1723984243,1782480556);
INSERT INTO highlights VALUES('35148817_6_2602-2637','35148817',6,'01 最怪异的性行为','比如，对于包括倭黑猩猩和海豚在内的少数物种来说，性和生育是可以分开的。','2602-2637',5,1723984062,1782480556);
INSERT INTO highlights VALUES('35148817_6_2225-2266','35148817',6,'01 最怪异的性行为','成年的雄性黑猩猩和处于发情期的雌性黑猩猩会离群生活几天，人类观察者将其称为伴侣时期','2225-2266',5,1723983939,1782480556);
INSERT INTO highlights VALUES('35148817_6_1994-2072','35148817',6,'01 最怪异的性行为','不过，共性之中也存在例外。有少数成年雄性哺乳动物也会照顾后代，例如，有多个配偶的雄性斑马、妻妾成群的大猩猩、出双入对的长臂猿，以及“一妻二夫”的雄性绢毛猴。','1994-2072',5,1723983898,1782480556);
INSERT INTO highlights VALUES('35148817_6_1704-1741','35148817',6,'01 最怪异的性行为','对于绝大多数哺乳动物来说，进行交配的雄性和雌性并不会组建家庭共同抚养后代。','1704-1741',5,1723983842,1782480556);
