INSERT INTO highlights VALUES('635800_6_15851-15877','635800',36,'第二章 知善恶树','于是，认知革命正是历史从生物学中脱离而独立存在的起点','16245-16271',NULL,1531498600,1782480569);
INSERT INTO highlights VALUES('635800_6_11524-11573','635800',36,'第二章 知善恶树','然而，所谓“想象的现实”指的是某件事人人都相信，而且只要这项共同的信念仍然存在，力量就足以影响世界','11772-11821',NULL,1531319147,1782480569);
