INSERT INTO highlights VALUES('635800_6_4002-4054','635800',36,'第二章 知善恶树','人类语言真正最独特的功能，并不在于能够传达关于人或狮子的信息，而是能够传达关于一些根本不存在的事物的信息','4077-4129',NULL,1531188003,1782480569);
