INSERT INTO highlights VALUES('635800_6_1836-1899','635800',36,'第二章 知善恶树','得到普遍认可的理论认为，某次偶然的基因突变，改变了智人的大脑内部连接方式，让他们以前所未有的方式来思考，用完全新式的语言来沟通','1884-1947',NULL,1531187785,1782480569);
