INSERT INTO highlights VALUES('635800_5_7572-7625','635800',35,'第一章 人类：一种也没什么特别的动物','一直要到40万年前，有几种人种才开始固定追捕大型猎物，而要到10万年前智人崛起，人类才一跃而居于食物链顶端','7722-7775',NULL,1531024586,1782480569);
INSERT INTO highlights VALUES('635800_5_7024-7069','635800',35,'第一章 人类：一种也没什么特别的动物','然而，其实人类早就具有这些优势，但在整整200万年期间，人类一直就只是一种弱小、边缘的生物','7166-7211',NULL,1531024407,1782480569);
