INSERT INTO highlights VALUES('635800_5_584-629','635800',35,'第一章 人类：一种也没什么特别的动物','在这之后过了大约30万年，物质和能量开始形成复杂的结构，称为“原子”，再进一步构成“分子”','536-581',NULL,1531022848,1782480569);
INSERT INTO highlights VALUES('24235906_7_5160-5259','24235906',7,'第3章 满怀激情地起床','开始前，先在清单上列出你想养成的习惯和想重新安排到早上的晚间惯例。好的晨间习惯能让你在起床时保持精力充沛、头脑清醒和心态积极。我建议培养一些平和而安静的习惯，像是冥想、祷告，或者阅读一本正能量的书。','5160-5259',NULL,1668485422,1782480565);
INSERT INTO highlights VALUES('24235906_7_4913-5004','24235906',7,'第3章 满怀激情地起床','在向晨型人转变期间，你可以在新增的那些“15分钟”里制定健康高效的新活动。如果你早起之后还是一如既往无所事事的话，那么除了睡眠，一切都毫无变化。而我们的目标是提高效率并获得实际成果。','4913-5004',NULL,1668485391,1782480565);
INSERT INTO highlights VALUES('24235906_6_7337-7376','24235906',6,'第2章 追求卓越','多年来的经验教训告诉我，思维的敏感度只有在早上表现最佳，到了晚上就变得一团糟。','7337-7376',NULL,1668484709,1782480565);
INSERT INTO highlights VALUES('24235906_6_7230-7308','24235906',6,'第2章 追求卓越','你曾经尝试过在深夜里做那些非常重要的事情吗？效果如何呢？如果你和我一样，你肯定是绞尽脑汁地拼命思考。当大脑处于疲劳的状态，想要清晰思考是比较困难而且痛苦的。','7230-7308',NULL,1668484696,1782480565);
INSERT INTO highlights VALUES('24235906_6_2609-2668','24235906',6,'第2章 追求卓越','在当今世界里，安逸或许是分心的最高境界，是成功的死敌。没有什么比安逸能让你更快束手就擒，更早放松警惕，更容易心不在焉。','2609-2668',NULL,1668482599,1782480565);
INSERT INTO highlights VALUES('24235906_6_2543-2556','24235906',6,'第2章 追求卓越','专注是21世纪最重要的技能','2543-2556',NULL,1668482591,1782480565);
INSERT INTO highlights VALUES('24235906_6_912-1018','24235906',6,'第2章 追求卓越',unistr('我错过了多少可能的机会去怀揣计划早起而不仅仅为了生存？\u000a曾经的我其实是现在很多人的真实写照。他们每天都从无序中开始，从自己造成的混乱中起床，甚至还置若罔闻。'),'912-1018',NULL,1668432953,1782480565);
INSERT INTO highlights VALUES('24235906_5_7880-8365','24235906',5,'第1章 凌晨5点',unistr('1．在纸上写下4条承诺，贴在你每天都能看到的地方：\u000a INSERT INTO highlights VALUES('24235906_5_6491-6505','24235906',5,'第1章 凌晨5点','计划，执行，反思。仅此而已。','6491-6505',NULL,1668412792,1782480565);
INSERT INTO highlights VALUES('24235906_5_6002-6043','24235906',5,'第1章 凌晨5点','高效能人士的修行之路是一场永无止境的旅程，它需要你每天醒来就下定决心好好利用今天。','6002-6043',NULL,1668412751,1782480565);
INSERT INTO highlights VALUES('24235906_5_4212-4275','24235906',5,'第1章 凌晨5点','把掌控当作一种准则就没那么困难了。事实上，你需要的仅仅是一个可靠的计划，一个先于他人起床的动机，一个对你来说意味着一切的目标。','4212-4275',NULL,1668412572,1782480565);
INSERT INTO highlights VALUES('24235906_5_4039-4091','24235906',5,'第1章 凌晨5点','如果每天早上都能花几小时在重要的任务上，那么就能节省出时间，也给心灵放个假，从而减轻接下来这一天的压力。','4039-4091',NULL,1668412558,1782480565);
INSERT INTO highlights VALUES('24235906_5_3185-3208','24235906',5,'第1章 凌晨5点','保证睡眠质量，合理优化你的一天是才是最关键的。','3185-3208',NULL,1668412365,1782480565);
INSERT INTO highlights VALUES('24235906_5_1906-2379','24235906',5,'第1章 凌晨5点',unistr('根据你在这段宝贵时间里所做的内容不同，你能取得的成效将远不止这些：\u000a1．持久而旺盛的精力。\u000a2．高质量的睡眠状态。\u000a3．瘦身健体。\u000a4．保持每天高效能。\u000a5．避免分心，尤其不受白天烦恼的影响。\u000a6．心情舒畅，对这一天充满向往。\u000a7．升级你的体质、力量和意志。\u000a8．在首要目标上取得非凡进展。\u000a9．思维清晰且具有创造性，尤其清晨时分，效果更佳。\u000a10．长期监测健康状况，并保持高效的习惯。'),'1906-2379',NULL,1668412269,1782480565);
INSERT INTO highlights VALUES('24235906_5_1017-1070','24235906',5,'第1章 凌晨5点','因此我要提前明确的是，在本书中，“凌晨5点奇迹”特指为了实现宏伟目标而早起、在早餐前掌控好一天的积极行动。','1017-1070',NULL,1668412174,1782480565);
INSERT INTO highlights VALUES('24235906_4_1434-1518','24235906',4,'引言 早起晨跑：双重磨炼','当时我认为自己这辈子都和晨型人（morning person）无缘，而且我还有个坏毛病：不到最后一分钟不起床，至少要摁两遍闹钟的贪睡按钮，直到捧上一杯热咖啡才笑得出来。','1434-1518',NULL,1668392038,1782480565);
INSERT INTO highlights VALUES('24235906_4_790-813','24235906',4,'引言 早起晨跑：双重磨炼','大多数好习惯的养成贵在持之以恒，而非一曝十寒。','790-813',NULL,1668391928,1782480565);
INSERT INTO highlights VALUES('24235906_7_4785-4842','24235906',7,'第3章 满怀激情地起床','行动：先尝试第一个“15分钟”的改变。制定明确的就寝时间和相应的早起时间，确保休息所需要的充足睡眠。','4785-4842',NULL,1598459779,1782480565);
INSERT INTO highlights VALUES('24235906_7_4433-4490','24235906',7,'第3章 满怀激情地起床','将明天的闹铃时间设置比平时早15分钟，今晚提前15分钟上床睡觉，这便是朝着在理想时间早起的远大目标迈出的小小一步。','4433-4490',NULL,1598114126,1782480565);
INSERT INTO highlights VALUES('24235906_7_2556-2632','24235906',7,'第3章 满怀激情地起床','翻开日程表，将以前的安排推倒重来。你的睡眠模式将发生变化，要未雨绸缪做好计划。你打算在清晨实现什么样的目标呢？有哪些原本制定在晚上的任务需要调整一下呢？','2556-2632',NULL,1598104608,1782480565);
INSERT INTO highlights VALUES('24235906_6_4715-4723','24235906',6,'第2章 追求卓越','早起的10大好处','4715-4723',NULL,1598025217,1782480565);
INSERT INTO highlights VALUES('24235906_6_5669-5673','24235906',6,'第2章 追求卓越','A型人格','5669-5673',NULL,1598024985,1782480565);
INSERT INTO highlights VALUES('24235906_6_3943-3999','24235906',6,'第2章 追求卓越','坚持训练“耐虐肌”，慢慢地你就能跳出自己的舒适区。当你下定决心要做一个更好的自己时，就会磨炼自己享受进步的过程。','3943-3999',NULL,1598024788,1782480565);
INSERT INTO highlights VALUES('24235906_5_7577-7765','24235906',5,'第1章 凌晨5点','1.“凌晨5点奇迹”特指为了实现宏伟目标而早起，在早餐前就掌控好一天的积极行动。2．早起能带来许多显著成效，不仅能令你变得更加高效，还能享受喧嚣之前的片刻宁静。3．想要达成凌晨5点奇迹，并不一定非得在5点钟起床！你可以选择适合自己的起床时间，并完美掌控这一天。','7595-7783',NULL,1598024288,1782480565);
INSERT INTO highlights VALUES('24235906_5_6329-6462','24235906',5,'第1章 凌晨5点','1．计划：行动之前先做好每天的计划安排。2．执行：花时间专注于最宏伟的目标，从而取得切实的进展。3．反思：每周一次，充分反思所做的事和接下来要做的事。','6329-6462',NULL,1598024214,1782480565);
INSERT INTO highlights VALUES('24235906_5_6254-6269','24235906',5,'第1章 凌晨5点','我把全书归纳成3个简单的步骤。','6254-6269',NULL,1598024210,1782480565);
INSERT INTO highlights VALUES('24235906_5_4672-4855','24235906',5,'第1章 凌晨5点','1．每天制订一个经过深思熟虑的书面计划。2．自始至终以健康的生活习惯来保持最佳的热情和活力。3．通过确立短期目标来帮助自己实现最宏伟的人生目标。4．追踪进展，必要时进行调整，对自己的行为负责。','4672-4855',NULL,1598020131,1782480565);
INSERT INTO highlights VALUES('24235906_5_4006-4033','24235906',5,'第1章 凌晨5点','早餐前掌控好这一天的本质就是先吃早起的苦，后享收获的甜','4006-4033',NULL,1598020067,1782480565);
INSERT INTO highlights VALUES('3300035991_11_10467-10512','3300035991',11,'第六章 管理情绪的关键，是更换你的情绪模式','共情的情绪逻辑和情绪表达的逻辑类似，可套用公式：Ta的预期+预期依据+现实落差+导致情绪。','10467-10512',5,1697376186,1782480562);
INSERT INTO highlights VALUES('3300035991_11_10545-10617','3300035991',11,'第六章 管理情绪的关键，是更换你的情绪模式','你可是孕妇（依据），他本该多迁就、照顾你不说（预期），居然为了这么小一件事跟你吵起来，还这么气你、吓你（现实），你应该受了很大委屈吧（情绪）”。','10545-10617',5,1697376179,1782480562);
INSERT INTO highlights VALUES('3300035991_11_8710-8744','3300035991',11,'第六章 管理情绪的关键，是更换你的情绪模式','学习共情，重点分四部分：他人情绪觉察、引导表达、倾听反馈和共情反馈。','8710-8744',5,1697375899,1782480562);
INSERT INTO highlights VALUES('3300035991_11_4259-4328','3300035991',11,'第六章 管理情绪的关键，是更换你的情绪模式','把自己分成两部分，一部分是无情绪的完全理性的我，另一部分是被情绪所折磨操控的我，且让“理性的我”凌驾于“情绪的我”之上，夺取身体的控制权。','4259-4328',5,1697361339,1782480562);
INSERT INTO highlights VALUES('3300035991_11_2848-2892','3300035991',11,'第六章 管理情绪的关键，是更换你的情绪模式','一方表达出自己的情绪后，另一方无视对方，甚至以排斥的态度攻击对方的情绪，这就是情绪漠视。','2848-2892',5,1697361129,1782480562);
INSERT INTO highlights VALUES('3300035991_10_19840-19893','3300035991',10,'第五章 让我们受困的不是现实本身，而是内在的认知方式','自证预言，又称“自我应验预言”或“自我实现预言”，指人会不自觉地按照自己认定的预言来行事，最终令预言发生。','19840-19893',5,1697360396,1782480562);
INSERT INTO highlights VALUES('3300035991_10_19045-19095','3300035991',10,'第五章 让我们受困的不是现实本身，而是内在的认知方式','我并不否定消极可能性的存在。我强调的是，在没有足够证据之前，先尽量带着善意去解读事物，往积极方面想。','19045-19095',5,1697360276,1782480562);
INSERT INTO highlights VALUES('3300035991_10_17588-17612','3300035991',10,'第五章 让我们受困的不是现实本身，而是内在的认知方式','ABC理论把情绪拆解成三部分：事实、看法、情绪。','17588-17612',4,1697360058,1782480562);
INSERT INTO highlights VALUES('3300035991_10_17440-17501','3300035991',10,'第五章 让我们受困的不是现实本身，而是内在的认知方式','明确自己当下的需求、敢作敢当的女生，比起没有明确诉求，也没考虑如何收场就跑去找男朋友吵闹的女生，更能得到男生的尊重和重视。','17440-17501',5,1697360038,1782480562);
INSERT INTO highlights VALUES('3300035991_9_19817-19895','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','因为你本身是匮乏的，是需要别人来照料的。要想影响别人，就要有自我照料的意识，把自己照顾好了，才能照顾他人或照顾关系。越懂得爱自己的人，在感情中才越可能被爱。','19817-19895',5,1697355031,1782480562);
INSERT INTO highlights VALUES('3300035991_9_16670-16721','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','一个人之所以会心甘情愿地为你付出、对你好，关键是两个因素，一个是他认可你的价值，另一个是你对他足够好。','16670-16721',5,1697354729,1782480562);
INSERT INTO highlights VALUES('3300035991_9_13603-13682','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','选择人生观相对稳定的伴侣，尊重他原有的人生观，放弃让对方为了你而改变人生观的愿望，变“改造”伴侣的人生为“融入”伴侣的人生，你的感情就能避免许多不必要的冲突。','13603-13682',5,1697354429,1782480562);
INSERT INTO highlights VALUES('3300035991_9_13527-13574','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','你以为这种人爱的是你，事实上他爱的只是这种为爱牺牲的自我感动、自我陶醉的感觉，他爱的是他自己。','13527-13574',5,1697354420,1782480562);
INSERT INTO highlights VALUES('3300035991_9_7963-8051','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','感情里反人性的期望越多，伴侣需要负担的责任就越沉重，对这段关系的排斥感也就越强。尊重人性不完美的客观事实，顺应人性的规律，协作配合，增强双方的自控程度，才是维护感情的正确思路。','7963-8051',1,1697339199,1782480562);
INSERT INTO highlights VALUES('3300035991_9_7584-7618','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','人自然也会本能地靠近那些让自己觉得舒服的人，远离那些让自己难受的人。','7584-7618',1,1697339094,1782480562);
INSERT INTO highlights VALUES('3300035991_9_7117-7223','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','不如后撤给他留出幻想的空间，甚至可以跟他讨论他的幻想对象有哪些地方吸引他。这既能帮助他更好地释放出轨冲动，又可以帮你了解他对伴侣的期望，从而确定自己调整的方向，还能防患于未然地确定有哪些特质的异性对你有真正威胁。','7117-7223',1,1697339041,1782480562);
INSERT INTO highlights VALUES('3300035991_9_7030-7055','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','因为能约束“人性”的，不是承诺，而是双方的共同努力','7030-7055',1,1697339020,1782480562);
INSERT INTO highlights VALUES('3300035991_9_4057-4156','3300035991',9,'第二部分 让你变成长期关系“绝缘体”的低情绪价值习惯','“懂”是一种默契，是需要长期相处才能培养出来的心照不宣的配合。在这种默契形成之前，你需要承担好该承担的沟通责任，至少把自己的行为解释出来，把自己的感受表达出来，帮助对方更好地理解你，更懂得如何去爱你','4057-4156',1,1697338788,1782480562);
INSERT INTO highlights VALUES('3300035991_8_1658-1732','3300035991',8,'第三章 能否为伴侣提供情绪价值，很大程度上决定了一段感情的成败','因此，维护长期关系的关键思路，就是在自己舒服的情况下，尽可能地让对方也舒服，而这种让伴侣感受舒服的价值，就是本书接下来要为你详细阐述的——情绪价值。','1658-1732',1,1697338447,1782480562);
INSERT INTO highlights VALUES('3300035991_8_1208-1229','3300035991',8,'第三章 能否为伴侣提供情绪价值，很大程度上决定了一段感情的成败','情绪=生理反应+大脑皮层对环境线索的解读。','1208-1229',1,1697338360,1782480562);
INSERT INTO highlights VALUES('3300035991_7_4258-4298','3300035991',7,'第二章 价值分类：你知道Ta需要你的哪些价值吗？','情绪价值可以分为认知、情绪、行为模式和人格完善度（情绪、乐观、责任、开放和宜人）','4258-4298',1,1697337937,1782480562);
INSERT INTO highlights VALUES('3300035991_7_1283-1317','3300035991',7,'第二章 价值分类：你知道Ta需要你的哪些价值吗？','对男性保护能力的要求象征性地变成了以对男性的身高要求为主的身材要求，','1283-1317',1,1697337674,1782480562);
INSERT INTO highlights VALUES('3300035991_4_3108-3190','3300035991',4,'前言 用情绪资源支撑他人，才能得到爱的犒赏','“情绪价值”这个词，原本并不是一个心理学概念，而是一个经济学概念。它指的是顾客购买产品后感知到的情绪收益和情绪成本之间的差值。','3108-3190',1,1697336540,1782480562);
INSERT INTO highlights VALUES('3300035991_4_1635-1735','3300035991',4,'前言 用情绪资源支撑他人，才能得到爱的犒赏','从潜意识层面来说，每一个当下的行为，都已经是我们的本能权衡利弊后，能够做出的最好的选择。本能不一定符合我们当下的利益，却一定有好处存在','1635-1735',1,1697335988,1782480562);
INSERT INTO highlights VALUES('3300035991_4_1512-1534','3300035991',4,'前言 用情绪资源支撑他人，才能得到爱的犒赏','所有无法改变的习惯，背后都有其未被觉知的获益','1512-1534',1,1697335957,1782480562);
INSERT INTO highlights VALUES('3300035991_4_1378-1464','3300035991',4,'前言 用情绪资源支撑他人，才能得到爱的犒赏','幸好，我很幸运地遇到了我的先生——彦宇老师，他也是一名咨询师。在跟他交流咨询难题的过程中，他为我打开了通往精神分析的大门，填补了我上述研究的最后一块拼图——原生家庭的桎梏。','1378-1464',1,1697335946,1782480562);
INSERT INTO highlights VALUES('3300035991_4_1140-1221','3300035991',4,'前言 用情绪资源支撑他人，才能得到爱的犒赏','但这样做也有弊端，来访者会觉得很累。因为这些改变并不自然，或者说有很大的阻力，仿佛是给他们嫁接了本就不属于他们的东西。要维持这些习惯，对他们来说是一种巨大的内耗。','1140-1221',1,1697335901,1782480562);
INSERT INTO highlights VALUES('3300035991_4_907-996','3300035991',4,'前言 用情绪资源支撑他人，才能得到爱的犒赏','因为沟通中一个人的情绪状态、肢体语言和表情传递了约70%的信息，语音和语调传递了约23%的信息，具体内容只占约7%。也就是说，行为只是表象，行为背后的态度和状态，才是沟通的核心。','907-996',1,1697335830,1782480562);
INSERT INTO highlights VALUES('42568675_33_500-522','42568675',33,'2.1 线程的基本管控','同样，当入口函数返回时，对应的线程随之终结。','500-522',0,1739116073,1782480553);
INSERT INTO highlights VALUES('42568675_32_652-697','42568675',32,'第2章 线程管控','如果给定一个线程，只要令std::thread对象与之关联，就能管控该线程的几乎每个细节。','652-697',0,1739115952,1782480553);
INSERT INTO highlights VALUES('42568675_30_1556-1725','42568675',30,'实例——“Hello Concurrent World”','如果起始线程不等待新线程结束，就会一路执行，直到main()结束，甚至很可能直接终止整个程序，新线程根本没有机会启动。这正是要调用join()的原因','1556-1725',0,1739052249,1782480553);
INSERT INTO highlights VALUES('42568675_30_1195-1244','42568675',30,'实例——“Hello Concurrent World”','这是因为每个线程都需要一个起始函数（initial function），新线程从这个函数开始执行。','1195-1244',0,1739052177,1782480553);
INSERT INTO highlights VALUES('42568675_27_905-920','42568675',27,'1.3.4 标准C++线程库的效率','为此，新标准带来了新的内存模型','905-920',0,1739049454,1782480553);
INSERT INTO highlights VALUES('42568675_27_828-869','42568675',27,'1.3.4 标准C++线程库的效率','总有开发者追求性能极限，恨不得下探最底层，亲手掌控半导体器件，以穷尽计算机的算力。','828-869',0,1739049441,1782480553);
INSERT INTO highlights VALUES('42568675_27_699-764','42568675',27,'1.3.4 标准C++线程库的效率','其中一项设计目标是，假定某些代码采用了C++标准库所提供的工具，如果改换为直接使用底层API，应该不会带来性能增益，或者收效甚微。','699-764',0,1739049426,1782480553);
INSERT INTO highlights VALUES('42568675_24_1366-1456','42568675',24,'1.3.1 C++多线程简史','通过资源获取即初始化（Resource Acquisition Is Initialization，RAII）的惯用手法进行锁操作，它确保了一旦脱离相关作用域，被锁的互斥就自行解开','1366-1456',0,1739049219,1782480553);
INSERT INTO highlights VALUES('42568675_21_1028-1184','42568675',21,'1.2.2 为性能而并发：任务并行和数据并行','易于采用上述并行方式的算法常常被称为尴尬并行算法。其含义是，将算法的代码并行化实在简单，甚至简单得会让我们尴尬，实际上这是好事。','1028-1184',0,1739048617,1782480553);
INSERT INTO highlights VALUES('42568675_21_733-782','42568675',21,'1.2.2 为性能而并发：任务并行和数据并行','所以程序员必须警觉，特别是那些踌躇不前、忽视并发技术的同业，有必要注意熟练掌握并发技术，储备技能。','733-782',0,1739048572,1782480553);
INSERT INTO highlights VALUES('42568675_20_1165-1222','42568675',20,'1.2.1 为分离关注点而并发','这样，线程的实际数量便与CPU既有的内核数量无关，因为用线程分离关注点的依据是设计理念，不以增加运算吞吐量为目的。','1165-1222',0,1739048503,1782480553);
INSERT INTO highlights VALUES('42568675_18_446-542','42568675',18,'1.1.3 并发与并行','两个术语都是指使用可调配的硬件资源同时运行多个任务，但并行更强调性能。当人们谈及并行时，主要关心的是利用可调配的硬件资源提升大规模数据处理的性能；当谈及并发时，主要关心的是分离关注点或响应能力','446-542',0,1739048227,1782480553);
INSERT INTO highlights VALUES('42568675_17_1618-1665','42568675',17,'1.1.2 并发的方式','运用独立的进程实现并发，还有一个额外优势——通过网络连接，独立的进程能够在不同的计算机上运行。','1618-1665',0,1739048002,1782480553);
INSERT INTO highlights VALUES('42568675_17_1116-1157','42568675',17,'1.1.2 并发的方式','因为操作系统往往要在进程之间提供大量防护措施，以免某进程意外改动另一个进程的数据；','1116-1157',0,1739047958,1782480553);
INSERT INTO highlights VALUES('42568675_17_1084-1115','42568675',17,'1.1.2 并发的方式','这种进程间通信普遍存在短处：或设置复杂，或速度慢，甚至二者兼有','1084-1115',0,1739047938,1782480553);
INSERT INTO highlights VALUES('42568675_17_1032-1075','42568675',17,'1.1.2 并发的方式','这些独立进程可以通过所有常规的进程间通信途径相互传递信息（信号、套接字、文件、管道等）','1032-1075',0,1739047924,1782480553);
INSERT INTO highlights VALUES('42568675_17_712-735','42568675',17,'1.1.2 并发的方式','位开发者代表一个线程，一间办公室代表一个进程。','712-735',0,1739047871,1782480553);
INSERT INTO highlights VALUES('42568675_16_1896-1932','42568675',16,'1.1.1 计算机系统中的并发','需要注意的关键因素是硬件支持的线程数（hardware threads）','1896-1932',0,1739047723,1782480553);
INSERT INTO highlights VALUES('42568675_16_1518-1574','42568675',16,'1.1.1 计算机系统中的并发','接着，CPU有可能需要将新任务的指令和数据从内存加载到缓存，这或许会妨碍CPU，令其无法执行任何指令，加剧延迟。','1518-1574',0,1739047700,1782480553);
INSERT INTO highlights VALUES('42568675_16_1377-1492','42568675',16,'1.1.1 计算机系统中的并发','则操作系统需保存当前任务的CPU状态和指令指针','1377-1492',0,1739047675,1782480553);
INSERT INTO highlights VALUES('42568675_16_1335-1356','42568675',16,'1.1.1 计算机系统中的并发','上下文切换（context switch）','1335-1356',0,1739047667,1782480553);
INSERT INTO highlights VALUES('42568675_16_803-828','42568675',16,'1.1.1 计算机系统中的并发','任务切换对使用者和应用软件自身都制造出并发的表象。','803-828',0,1739047550,1782480553);
INSERT INTO highlights VALUES('42568675_16_374-416','42568675',16,'1.1.1 计算机系统中的并发','若我们谈及计算机系统中的并发，则是指同一个系统中，多个独立活动同时进行，而非依次进行','374-416',0,1739047451,1782480553);
INSERT INTO highlights VALUES('42568675_15_382-412','42568675',15,'1.1 什么是并发','并发（concurrency）是两个或多个同时独立进行的活动','382-412',0,1739047403,1782480553);
INSERT INTO highlights VALUES('42568675_14_912-968','42568675',14,'第1章 你好，C++并发世界','C++11标准最重要的新特性之一是支持多线程。这是标准首次接纳原生语言层面的多线程应用，并在标准库中为之提供组件','912-968',0,1739047339,1782480553);
INSERT INTO highlights VALUES('42568675_11_780-787','42568675',11,'译者致谢','PureCPP','780-787',0,1739046660,1782480553);
INSERT INTO highlights VALUES('42568675_8_1156-1209','42568675',8,'作者序','从2007年到2011年，我担任了Boost线程库的主力开发者和维护者，不过后来我将这项工作移交他人负责。','1156-1209',0,1739046524,1782480553);
