INSERT INTO highlights VALUES('3300025707_9_1980-2050','3300025707',9,'01 闲暇','人类最高理想应该是人人能有闲暇，于必须的工作之余还能有闲暇去做人，有闲暇去做人的工作，去享受人的生活。我们应该希望人人都能属于“有闲阶级”。','1980-2050',1,1723595761,1782398561);
