INSERT INTO highlights VALUES('24129813_6_24558-24604','24129813',19,'第二章 六县大辩论','看来他在江夏县这几年，根本没有心灰意冷，仍旧在孜孜不倦地搜寻证据，还把视野扩散到了全国范围。','1980-2026',0,1677559282,1782480564);
INSERT INTO highlights VALUES('24129813_6_23192-23252','24129813',19,'第二章 六县大辩论','这个缉拿帅嘉谟的罪名，实在有点莫名其妙：你帅嘉谟有本事去两院告状，怎么没本事留下来配合调查？一直躲在外头，一定非奸即恶！','614-674',0,1677559158,1782480564);
