INSERT INTO highlights VALUES('24129813_6_19893-19935','24129813',36,'第一章 都是学霸惹的祸','帅嘉谟把一个战略性错误当成了战术性错误，一味钻牛角尖去查考细节，等于媚眼抛给了瞎子看','19030-19072',0,1677550981,1782480564);
INSERT INTO highlights VALUES('24129813_6_19167-19250','24129813',36,'第一章 都是学霸惹的祸','被收买的小吏，可以使用高超却卑鄙的手段，使得家有良田千亩的富家在官方记录中表现为无田，富家便可轻松逃避赋税；而根本没有田地的穷家却被登记为田产丰富，需要承担沉重的赋税','18305-18388',0,1677550910,1782480564);
INSERT INTO highlights VALUES('24129813_6_18766-18791','24129813',36,'第一章 都是学霸惹的祸','尤其是六房中的户房，分管钱粮，是胥吏管理的重灾区。','17917-17942',0,1677550857,1782480564);
INSERT INTO highlights VALUES('24129813_6_18561-18643','24129813',36,'第一章 都是学霸惹的祸','在大明府、县这两级的政府里面，具体政务的执行机构叫作“三班六房”，三班指皂班、壮班、快班，合称为衙役；六房分为吏房、户房、礼房、兵房、刑房、工房，与中央六部相对应。','17712-17794',0,1677550797,1782480564);
INSERT INTO highlights VALUES('24129813_6_18304-18319','24129813',36,'第一章 都是学霸惹的祸','做这个手脚的人，绝对是个高手。','17455-17470',0,1677550759,1782480564);
INSERT INTO highlights VALUES('24129813_6_17844-17891','24129813',36,'第一章 都是学霸惹的祸','南京承运库要徽州征发的科目，是“人丁丝绢”，而且没有指明由哪个县单独缴纳，一般默认是六县均摊。','16995-17042',0,1677550747,1782480564);
INSERT INTO highlights VALUES('24129813_6_16846-16949','24129813',36,'第一章 都是学霸惹的祸','大明地方官员一向的治政思路是以稳定为主，不出事什么都好说，至于讲不讲道理还在其次。下头老百姓们也明白这个逻辑，所以碰到什么纠纷，甭管有理没理，先闹一阵。闹成了，官府往往就会按闹分配；闹不成，也是法不责众嘛。','15997-16100',0,1677550613,1782480564);
INSERT INTO highlights VALUES('24129813_6_11232-11275','24129813',36,'第一章 都是学霸惹的祸','帅嘉谟之所以有这个底气，是因为这位巡抚太有名气，远非寻常官员可比——他叫海瑞，号刚峰。','10458-10501',0,1677549061,1782480564);
INSERT INTO highlights VALUES('24129813_6_8838-8864','24129813',36,'第一章 都是学霸惹的祸','因为大明税制不是统收统解，一个地方往往要向数处交税。','8070-8096',0,1677548974,1782480564);
INSERT INTO highlights VALUES('24129813_6_8129-8190','24129813',36,'第一章 都是学霸惹的祸','帅嘉谟偷偷加了这六个字，是想给上官造成一个先入为主的印象，方便行事——殊不知这一处小小的手脚，后来却成了聚讼的一个关键焦点','7374-7435',0,1677548925,1782480564);
INSERT INTO highlights VALUES('24129813_6_7442-7472','24129813',36,'第一章 都是学霸惹的祸','结果负责此事的官、吏，都是其他五县出身，敷衍塞责，推诿拖延。','6687-6717',0,1677548853,1782480564);
INSERT INTO highlights VALUES('24129813_6_6757-6797','24129813',36,'第一章 都是学霸惹的祸','如果从至正二十五年“乙巳改科”开始算起，到隆庆三年，这笔冤枉税足足交了两百多年！','6002-6042',0,1677506596,1782480564);
INSERT INTO highlights VALUES('24129813_6_3799-3888','24129813',36,'第一章 都是学霸惹的祸','《大明会典》是一本官方发布的资料集，里面收录了典章沿革以及各级政府税赋资料、行政法规，从弘治朝开始，每代都会进行修订，算是政府法令的一个汇编，亦勉强可以当作年鉴来用，权威性很高。','3059-3148',0,1677506385,1782480564);
INSERT INTO highlights VALUES('24129813_6_3270-3301','24129813',36,'第一章 都是学霸惹的祸','其他五县都没有“人丁丝绢”这么一笔支出，只有歙县的账簿上有记录','2543-2574',0,1677506353,1782480564);
INSERT INTO highlights VALUES('24129813_6_3118-3212','24129813',36,'第一章 都是学霸惹的祸','凭借着对数字的高度敏感，他注意到徽州的历年税赋里有一个疑点：徽州府每年向南京承运库缴纳的税粮中，除正税之外，还有一笔科目叫作“人丁丝绢”，须以实物缴纳，且数额颇大，每年要缴8780匹生绢。','2391-2485',0,1677506330,1782480564);
INSERT INTO highlights VALUES('24129813_6_1606-1609','24129813',37,'第四章 秋后算账','帅嘉谟','1495-1498',0,1677506184,1782480564);
INSERT INTO highlights VALUES('24129813_5_3676-3773','24129813',15,'序言','其实很多我们觉得惊艳或罕有的历史再发现，在学术界早就不新鲜了。比如徽州丝绢案，研究它的学者很多，并不是什么新奇的突破。只可惜学术与大众之间有高大的藩篱，彼此不通，这才让如此生动的故事被冷落良久。','3441-3538',0,1677505936,1782480564);
INSERT INTO highlights VALUES('24129813_5_2936-2975','24129813',15,'序言','真正的叙事高手从来不用定性或装饰性质的字眼，而是把得出结论的权利和快乐留给读者','2711-2750',0,1677463834,1782480564);
INSERT INTO highlights VALUES('24129813_5_1743-1816','24129813',15,'序言','普通老百姓的喜怒哀乐，社会底层民众的心思想法，往往会被史书忽略。即使提及，也只是诸如“民不聊生”“民怨鼎沸”之类的高度概括，很少会细致入微地描写。','1534-1607',0,1677463698,1782480564);
INSERT INTO highlights VALUES('24129813_4_762-801','24129813',14,'内容简介','这些档案是中国历史中绝无仅有的奇迹，它们着眼于平民的政治生活，而且记录极为详尽','479-518',0,1677462872,1782480564);
INSERT INTO highlights VALUES('3300089952_9_8474-8509','3300089952',9,'第六章 行动与不行动','我发现人类的一切不幸均来自一个原因：他们不知道如何安静地在家中休憩……','8474-8509',0,1730016993,1782480555);
