INSERT INTO highlights VALUES('3300089952_8_7007-7045','3300089952',8,'第五章 冥想与思考','正因为如此，我们常常沉溺在最大的主观之中无法跳脱，任由虚妄和执着统治着自我。','7007-7045',0,1729434108,1782480555);
