INSERT INTO highlights VALUES('3300089952_8_5605-5632','3300089952',8,'第五章 冥想与思考','接下来，我们就可以进入冥想训练的第二个重要阶段——辨识','5605-5632',0,1729433585,1782480555);
INSERT INTO highlights VALUES('3300089952_8_5470-5510','3300089952',8,'第五章 冥想与思考','因此离开杂念将是真正思考的第一步，这将让我们能够更好地思考那些对我们重要的事情。','5470-5510',0,1729433576,1782480555);
