INSERT INTO highlights VALUES('3300089952_8_2361-2373','3300089952',8,'第五章 冥想与思考','智力无须找寻，只需清理。','2361-2373',0,1729432899,1782480555);
INSERT INTO highlights VALUES('3300089952_8_2240-2263','3300089952',8,'第五章 冥想与思考','总而言之，相比于创造，思考更是一种选择的能力。','2240-2263',0,1729432885,1782480555);
INSERT INTO highlights VALUES('3300089952_8_2084-2118','3300089952',8,'第五章 冥想与思考','思考不只是指产生想法以及创造精神产物，而是“形成和组合想法与判断”。','2084-2118',0,1729432861,1782480555);
INSERT INTO highlights VALUES('3300089952_7_10765-10801','3300089952',7,'第四章 冥想、身体与健康','它使我们从唯一的精神和逻辑思维中解脱出来，并与我们所在的环境建立多重连接','10765-10801',0,1729432637,1782480555);
INSERT INTO highlights VALUES('3300089952_7_10074-10099','3300089952',7,'第四章 冥想、身体与健康','我们的生命就是生命，我们的身体是享受生活的美丽容器','10074-10099',0,1729432564,1782480555);
INSERT INTO highlights VALUES('3300089952_7_9413-9433','3300089952',7,'第四章 冥想、身体与健康','空闲的时候，不要沉迷于手机，而是要站起来','9413-9433',0,1729432481,1782480555);
INSERT INTO highlights VALUES('3300089952_7_9282-9318','3300089952',7,'第四章 冥想、身体与健康','无论你在哪里，都要定期检查身体的状态和潜在的紧张感，然后让身体进行深呼吸','9282-9318',0,1729432465,1782480555);
INSERT INTO highlights VALUES('3300089952_7_8722-8756','3300089952',7,'第四章 冥想、身体与健康','同样，积极的情绪不仅仅是令人愉悦的，它们也能够保护并且修复我们的身体','8722-8756',0,1729432408,1782480555);
INSERT INTO highlights VALUES('3300089952_7_8524-8544','3300089952',7,'第四章 冥想、身体与健康','定期冥想会有效减少压力并增加愉悦的情绪。','8524-8544',0,1729432369,1782480555);
INSERT INTO highlights VALUES('3300089952_7_7976-8006','3300089952',7,'第四章 冥想、身体与健康','不要试图避免痛苦，也不要努力减轻痛苦，而是要不被痛苦所影响。','7976-8006',0,1729403394,1782480555);
INSERT INTO highlights VALUES('3300089952_6_7520-7533','3300089952',6,'第三章 冥想与注意力','练习6 开放、流动的注意力','7520-7533',0,1729399086,1782480555);
INSERT INTO highlights VALUES('3300089952_6_6299-6373','3300089952',6,'第三章 冥想与注意力','前者（注意力吸引）是对新事件的定向反射，如对声音、想法、情感的反射；后者（注意力捕获）是对无法控制的图像、想法或情绪的持续性反应，如深思熟虑、沉思。','6299-6373',0,1728728247,1782480555);
INSERT INTO highlights VALUES('3300089952_6_6030-6099','3300089952',6,'第三章 冥想与注意力','手机和电脑上的情况更加糟糕，所有的设计都是为了奴役我们的注意力，以便我们可以持续不断地刷屏，直到精疲力尽（当然，还可能让我们刷爆信用卡）。','6030-6099',0,1728726450,1782480555);
INSERT INTO highlights VALUES('3300089952_6_5569-5627','3300089952',6,'第三章 冥想与注意力','有研究表明，睡前进行20分钟慢呼吸练习，可以显著改善睡眠质量（不仅能加快入睡速度，还可以减少夜间醒来的频率和时间）。','5569-5627',0,1728726413,1782480555);
INSERT INTO highlights VALUES('3300089952_6_4471-4517','3300089952',6,'第三章 冥想与注意力','为什么要依靠呼吸来培养我们的注意力呢？因为我们的注意力会自然而然地被运动着的物体吸引、捕获。','4471-4517',0,1728726264,1782480555);
INSERT INTO highlights VALUES('3300089952_6_3324-3348','3300089952',6,'第三章 冥想与注意力','对抗压力最好的武器就是，我们可以自由地选择想法。','3324-3348',0,1728726124,1782480555);
INSERT INTO highlights VALUES('3300069758_8_4452-4518','3300069758',8,'1 提高心性','宇宙具有这样的大趋势——决不停滞片刻，决不“安于现状”，而是不断推进万事万物向前发展进化。我觉得可以把这样的大趋势称作“宇宙的意志”','4452-4518',5,1716549424,1782480558);
INSERT INTO highlights VALUES('3300069758_8_915-940','3300069758',8,'1 提高心性','但我从年轻时起，就认为“人心”要比科学技术更为重要','915-940',5,1716548118,1782480558);
INSERT INTO highlights VALUES('3300069758_8_748-798','3300069758',8,'1 提高心性','我是理工科出身，大学的专业方向原本是有机化学，尤其是制造合成树脂等物质的石油化学，更是我的专攻科目。','748-798',5,1716548102,1782480558);
INSERT INTO highlights VALUES('3300069758_6_9751-9827','3300069758',6,'京瓷哲学是如何诞生的？','我们所追求的“物质和精神两方面”的幸福，是指追求经济的宽裕和收入的稳定，同时，通过工作实现自我，从中感觉到人生的意义和劳动的价值，从而获得精神上的幸福。','9751-9827',5,1716548046,1782480558);
INSERT INTO highlights VALUES('3300069758_6_8336-8391','3300069758',6,'京瓷哲学是如何诞生的？','正是因为员工们对这样的思维方式产生了共鸣，相信人具备无限的可能性，不断付出无尽的努力，这才有了京瓷今天的辉煌。','8336-8391',5,1716547488,1782480558);
INSERT INTO highlights VALUES('3300069758_6_8014-8061','3300069758',6,'京瓷哲学是如何诞生的？','如果说，最容易动摇、最难把握的是人心，那么，一旦互相信赖、心心相连，最坚牢、最可靠的还是人心。','8014-8061',5,1716547449,1782480558);
INSERT INTO highlights VALUES('3300069758_6_7447-7597','3300069758',6,'京瓷哲学是如何诞生的？','领导者所持有的人生观、哲学和思维方式决定了一切。企业的规模、品格超越不了领导人的器量，它与领导人的人格相匹配。俗话说：“螃蟹只会比照自己壳的大小打洞。”企业的发展超不出企业领导人的器量和人格。想让自己的企业发展壮大，想让自己的人生精彩纷呈，那就必须提升自己的心性，磨砺自己的人格。除此以外，别无他法。','7447-7597',5,1716547392,1782480558);
INSERT INTO highlights VALUES('3300069758_6_5135-5188','3300069758',6,'京瓷哲学是如何诞生的？','可以把人生比喻为登山。首先，重要的是决定自己准备攀登什么样的山。因为根据所登山的不同，要准备的东西也不同。','5135-5188',5,1716547100,1782480558);
INSERT INTO highlights VALUES('3300069758_6_3507-3557','3300069758',6,'京瓷哲学是如何诞生的？','这样的教育在战后遭到了全盘否定，因为当时的日本政府曾把修身和道德作为军国主义思想教育的内容加以利用。','3507-3557',5,1716546907,1782480558);
INSERT INTO highlights VALUES('3300069758_6_3464-3484','3300069758',6,'京瓷哲学是如何诞生的？','在战前的教育中就有修身和道德教育的课程，','3464-3484',5,1716546898,1782480558);
INSERT INTO highlights VALUES('3300069758_6_3146-3205','3300069758',6,'京瓷哲学是如何诞生的？','那个人为人不太好，那个人品格稍微有点问题，并不是说品格稍有问题，他的人生也只是稍有问题，而是他的整个人生都会成为负值。','3146-3205',5,1716546828,1782480558);
INSERT INTO highlights VALUES('3300069758_6_2989-3012','3300069758',6,'京瓷哲学是如何诞生的？','如果“思维方式”是负数，那么结果必然也是负数。','2989-3012',5,1716546795,1782480558);
INSERT INTO highlights VALUES('3300069758_6_2495-2515','3300069758',6,'京瓷哲学是如何诞生的？','但是“热情”这一项可以由自己的意志决定。','2495-2515',5,1716546714,1782480558);
INSERT INTO highlights VALUES('3300069758_6_2305-2324','3300069758',6,'京瓷哲学是如何诞生的？','人生·工作的结果=思维方式×热情×能力','2305-2324',5,1716546669,1782480558);
INSERT INTO highlights VALUES('3300069758_6_2029-2108','3300069758',6,'京瓷哲学是如何诞生的？','作为经营者，如果我自己缺乏正确的思想和高尚的人生观，就很难吸引大家，带动大家。要想经营企业，要想经营出色，经营者必须提高自己的思想水平、人生观以及哲学境界。”','2029-2108',5,1716546662,1782480558);
INSERT INTO highlights VALUES('3300069758_6_845-877','3300069758',6,'京瓷哲学是如何诞生的？','我在那家公司从事精密陶瓷的研究，精密陶瓷后来成了京瓷的主打产品。','845-877',5,1716546496,1782480558);
INSERT INTO highlights VALUES('3300069758_6_652-682','3300069758',6,'京瓷哲学是如何诞生的？','我出生在鹿儿岛，毕业于鹿儿岛大学，就职于京都的一家陶瓷企业。','652-682',5,1716546475,1782480558);
INSERT INTO highlights VALUES('3300069758_4_681-735','3300069758',4,'自序','经过苦苦思索，我得出了一个结论——首先要问自己“作为人，何谓正确？”一旦认定是正确的，就毫不动摇地贯彻到底。','681-735',5,1716546258,1782480558);
INSERT INTO highlights VALUES('3300069758_3_3554-3614','3300069758',3,'推荐序 人类社会需要利他哲学','现代文明的本质是“人类欲望的无限解放”。科技进步、经济发展与人的精神道德的衰退，是这个时代的一个巨大、深刻而尖锐的矛盾。','3554-3614',5,1716546137,1782480558);
INSERT INTO highlights VALUES('3300069758_3_2885-2934','3300069758',3,'推荐序 人类社会需要利他哲学','把这78条凝缩起来，再换句话说，就是以“利他之心”而不是以“利己之心”，对面临的一切事情做出判断。','2885-2934',5,1716515613,1782480558);
INSERT INTO highlights VALUES('3300069758_3_2705-2812','3300069758',3,'推荐序 人类社会需要利他哲学','判断事物不以得失为基准，而以是非为基准。而“是非之心，人皆有之”。所谓“是非之心”就是人本来就具备的良知。具体来说，就是做人应该正直，不应该虚伪；应该谦虚，不应该傲慢；应该勤奋，不应该懒惰；应该知足，不应该贪婪等。','2705-2812',5,1716515607,1782480558);
INSERT INTO highlights VALUES('3300069758_3_3065-3100','3300069758',3,'推荐序 人类社会需要利他哲学','在追求全体员工物质和精神两方面幸福的同时，为人类社会的进步发展做出贡献','3065-3100',5,1716515603,1782480558);
INSERT INTO highlights VALUES('3300069758_3_1616-1663','3300069758',3,'推荐序 人类社会需要利他哲学','京瓷56年来从未亏损，而且平均利润率保持在10%以上，这在日本乃至世界的大企业中恐怕绝无仅有吧','1616-1663',5,1716515437,1782480558);
INSERT INTO highlights VALUES('3300069758_3_1186-1273','3300069758',3,'推荐序 人类社会需要利他哲学','稻盛先生说：“在排除一切杂念，专注于一项研究的时候，我感到某种人生观在心里萌动，并以此为基础开始建立自己的哲学。我隐隐约约地意识到，这样的人生观或者说哲学是极其重要的东西。”','1186-1273',5,1716515382,1782480558);
INSERT INTO highlights VALUES('3300069758_3_673-712','3300069758',3,'推荐序 人类社会需要利他哲学','泰勒的科学管理、戴明的质量管理以及丰田的看板管理，乃至后来德鲁克强调的目标管理','673-712',5,1716515319,1782480558);
INSERT INTO highlights VALUES('44966312_6_5613-5687','44966312',6,'第一章 斯多葛哲学的意义','斯多葛学派认为，强烈的负面情感是我们最大的弱点，尤其是任由情绪支配我们的行为时，离理想自我会越来越远。强烈的情感会抹杀幸福，它是人类所有痛苦的根源。','5613-5687',5,1716439073,1782480558);
INSERT INTO highlights VALUES('44966312_6_4938-4988','44966312',6,'第一章 斯多葛哲学的意义','这就是生活—— 它就像拳击台，我们在赛前就签订好合同了，免不了受到拳打脚踢，这是我们必须经受的训练。','4938-4988',5,1716438624,1782480558);
INSERT INTO highlights VALUES('44966312_6_4074-4118','44966312',6,'第一章 斯多葛哲学的意义','幸福是一种快乐顺遂的生活，它来源于我们每时每刻的行为都与最高自我和谐相处带来的蓬勃发展。','4074-4118',5,1716438518,1782480558);
INSERT INTO highlights VALUES('44966312_6_3591-3602','44966312',6,'第一章 斯多葛哲学的意义','每时每刻都表达最高自我','3591-3602',5,1716432381,1782480558);
INSERT INTO highlights VALUES('44966312_6_3468-3531','44966312',6,'第一章 斯多葛哲学的意义','我们能够成为怎样的人（理想自我）？我们当下是怎样的人？我们应该去缩小这两者的差距。怎么才能做到这点？斯多葛学派有二字箴言：德性','3468-3531',5,1716432373,1782480558);
INSERT INTO highlights VALUES('44966312_6_2903-2971','44966312',6,'第一章 斯多葛哲学的意义','在希腊语中，最好的自己被称为内在精灵（daimon）','2903-2971',5,1716428109,1782480558);
INSERT INTO highlights VALUES('44966312_6_2702-2727','44966312',6,'第一章 斯多葛哲学的意义','向内探寻，善的源头在内心。向内探寻，善随时会出现。','2702-2727',5,1716428084,1782480558);
INSERT INTO highlights VALUES('44966312_6_2483-2557','44966312',6,'第一章 斯多葛哲学的意义','斯多葛主义实用的“生活艺术”有两大意义： 第一，教会我们如何才能幸福顺遂地生活；第二，教会我们如何保持情绪稳定，即便身处逆境，也能维持幸福顺遂的生活','2483-2557',5,1716428068,1782480558);
INSERT INTO highlights VALUES('44966312_6_2422-2454','44966312',6,'第一章 斯多葛哲学的意义','生活里有滚滚浪潮、无数的大理石坯，它就是我们日常训练的完美场所。','2422-2454',5,1716428054,1782480558);
INSERT INTO highlights VALUES('44966312_6_2294-2324','44966312',6,'第一章 斯多葛哲学的意义','哲学的真正意义在于懂得在少量理论的指导下，进行大量的实践练习','2294-2324',5,1716428024,1782480558);
INSERT INTO highlights VALUES('44966312_6_1827-1857','44966312',6,'第一章 斯多葛哲学的意义','只对着大理石坯思考而不动手实践，就无法熟练地使用凿子和锤子。','1827-1857',5,1716397874,1782480558);
INSERT INTO highlights VALUES('44966312_6_1607-1627','44966312',6,'第一章 斯多葛哲学的意义','哲学家就是知道本质之事，知道如何生活的人','1607-1627',5,1716397803,1782480558);
INSERT INTO highlights VALUES('44966312_6_1259-1289','44966312',6,'第一章 斯多葛哲学的意义','正如木头之于木匠，青铜之于石匠，我们的生活是生活艺术的原材料','1259-1289',5,1716397730,1782480558);
INSERT INTO highlights VALUES('44966312_6_1076-1102','44966312',6,'第一章 斯多葛哲学的意义','先告诉自己，你想成为怎样的人，然后去做你必须做的事。','1076-1102',5,1716397669,1782480558);
INSERT INTO highlights VALUES('44966312_6_623-657','44966312',6,'第一章 斯多葛哲学的意义','强大自己，在遭受同等强度的狂风暴雨时减少打击，让自己风雨不动安如山。','623-657',5,1716397616,1782480558);
INSERT INTO highlights VALUES('44966312_6_589-609','44966312',6,'第一章 斯多葛哲学的意义','我们不想被日常小事羁绊，就必须提高境界。','589-609',5,1716397605,1782480558);
INSERT INTO highlights VALUES('44966312_4_4910-4979','44966312',4,'前言 preface','第一部分讲述斯多葛哲学的意义、历史、主要的哲学家、核心原则（即斯多葛幸福三角论，the Stoic Happiness Triangle）','4910-4979',5,1716360050,1782480558);
INSERT INTO highlights VALUES('44966312_4_4292-4339','44966312',4,'前言 preface','成为最好的自己，你还要等多久？”你不再是孩子，而是成年人了，在成为最好的自己一事上别再拖延了。','4292-4339',5,1716359976,1782480558);
INSERT INTO highlights VALUES('44966312_4_2514-2628','44966312',4,'前言 preface','斯多葛主义认为，在既定的情形下，能否过上幸福生活取决于一个人的选择、行为以及品格养成，而非不可控的周遭世界。这就是斯多葛主义棘手但又极具魅力的原因所在—— 对自己的幸福生活负责，不让我们因为没有过上幸福生活而自怨自艾、颓废不前。','2514-2628',5,1716359757,1782480558);
INSERT INTO highlights VALUES('44966312_4_2193-2240','44966312',4,'前言 preface','与哲学人士共同学习的人，每天应该带走一样好东西：每天回家时应该更健康，或者朝着更健康的状态发展','2193-2240',5,1716359717,1782480558);
INSERT INTO highlights VALUES('44966312_4_1774-1851','44966312',4,'前言 preface','正因如此，有人剽窃了那篇文章的主要内容，整理出版了。这种盗版行为是在考验我的斯多葛心态啊！再者，那本书获得的五星好评让我知道，读者真的很想学习斯多葛哲学。','1774-1851',5,1716359340,1782480558);
INSERT INTO highlights VALUES('44966312_4_1723-1747','44966312',4,'前言 preface','所以我撰写了一篇长文，介绍了斯多葛哲学及其本质。','1723-1747',5,1716359325,1782480558);
INSERT INTO highlights VALUES('44966312_4_1645-1674','44966312',4,'前言 preface','从此以后，我贪婪地拜读着斯多葛哲学的著作，大量实践其知识。','1645-1674',5,1716359309,1782480558);
INSERT INTO highlights VALUES('44966312_4_1541-1557','44966312',4,'前言 preface','斯多葛主义”（Stoicism）','1541-1557',5,1716351457,1782480558);
INSERT INTO highlights VALUES('44966312_4_1217-1338','44966312',4,'前言 preface','在为期十五年半的在校生涯里，我学习了数学、物理、化学、生物等课程，但忽略了另外一些知识：如何处理棘手的状况？如何应对自己的恐惧与挣扎？如何处理失落的情绪？如何处理自己愤怒的情绪？如何变得更有自信？亲近的人去世了，该如何走出来？这些我都没学过，','1217-1338',5,1716351394,1782480558);
INSERT INTO highlights VALUES('834466_10_3695-3776','834466',117,'八','那时候宋凡平脸上挂着微笑，他不知道这是最后一眼看到自己的妻子，李兰留给他的最后印象就是抬起手擦着眼泪的侧影，李光头和宋钢当时的印象是长途客车远去时卷起了滚滚尘土。','3751-3832',5,1691313472,1782480563);
INSERT INTO highlights VALUES('834466_9_4526-4543','834466',116,'七','长凳硬绑绑的，硌得我小屌很不舒服。','4580-4597',5,1691312168,1782480563);
INSERT INTO highlights VALUES('834466_9_3931-3952','834466',116,'七','“这么动来动去，动得小屌硬绑绑的很舒服。”','3986-4007',5,1691312101,1782480563);
INSERT INTO highlights VALUES('834466_9_2846-2871','834466',116,'七','李光头继续神秘地说：“你爸吃我妈的，我妈吃你爸的。','2901-2926',5,1691312033,1782480563);
INSERT INTO highlights VALUES('834466_9_2405-2415','834466',116,'七','他们正在床上吃……”','2460-2470',5,1691311846,1782480563);
INSERT INTO highlights VALUES('834466_8_9839-9879','834466',115,'六','上午的时候他们就想着让自己的嘴甜起来，直到太阳快落山了他们的嘴巴刚刚开始甜起来。','9893-9933',5,1690984407,1782480563);
INSERT INTO highlights VALUES('834466_8_1725-1747','834466',115,'六','他们捧着一大把吃的，他们的嘴里却是空空荡荡。','1780-1802',5,1690981666,1782480563);
INSERT INTO highlights VALUES('834466_8_825-884','834466',115,'六','她一跃而起，一头撞过去似的打开了屋门，推着板车的宋凡平站在门外喜气洋洋，坐在板车上的宋钢看到李光头后咯咯笑着叫了一声：','880-939',5,1690981437,1782480563);
INSERT INTO highlights VALUES('834466_6_5805-5842','834466',113,'四','这些人里面他熟悉的只有宋凡平，他曾经在这个高大男人的肩上俯视过街上的世界。','5861-5898',5,1690973284,1782480563);
INSERT INTO highlights VALUES('834466_6_5089-5176','834466',113,'四','李光头觉得他母亲制作一个圆纸片的铜钱，比制作一个纸元宝困难得多，他不知道一片纸铜钱可以买多少幢房子？他问母亲是不是可以买下一排房子？他母亲拿起一长串纸铜钱说，只能买一件衣服。','5145-5232',5,1690973166,1782480563);
INSERT INTO highlights VALUES('834466_5_1778-1809','834466',112,'三','这个失声惊叫的男人就是宋钢的父亲宋凡平，后来成为了李光头的继父','1833-1864',5,1690972425,1782480563);
INSERT INTO highlights VALUES('834466_4_7122-7165','834466',111,'二','那时候李光头还不知道自己后来会成为亿万富翁，不知道自己后来会将世上的山珍海味吃遍吃腻。','7177-7220',5,1690967547,1782480563);
INSERT INTO highlights VALUES('834466_4_4201-4257','834466',111,'二','李光头吞着口水，得寸进尺地说：“我不吃九分钱一碗的阳春面，我要吃三角五分钱一碗的三鲜面，里面要有鱼有肉还有虾。”','4256-4312',5,1690967277,1782480563);
INSERT INTO highlights VALUES('834466_4_1993-2059','834466',111,'二','刘作家权衡利弊，觉得前途比婚姻更为重要，只好在女朋友面前低头认错。两个人立刻和好如初，并肩逛商店，并肩看电影，开始打造家具筹办婚事。','2048-2114',5,1690967082,1782480563);
INSERT INTO highlights VALUES('834466_4_1239-1272','834466',111,'二','李光头后来之所以能够成为我们刘镇的超级巨富，因为他是个天生的商人。','1294-1327',5,1690966936,1782480563);
