INSERT INTO highlights VALUES('834466_3_6176-6256','834466',110,'一','他们一点都不像是在审问，倒像是在向李光头打听，当李光头开始交待如何偷看林红的屁股，就是那个不胖不瘦圆得卷起来的屁股时，这五个民警就像是在听鬼故事，满脸的紧张神情','6230-6310',5,1690009659,1782480563);
