INSERT INTO highlights VALUES('834466_3_2425-2480','834466',110,'一','当时的赵胜利二十多岁，已经在我们县文化馆的油印杂志上发表了一首四行小诗，为此他拥有了一个名人的绰号——赵诗人。','2480-2535',5,1690009105,1782480563);
INSERT INTO highlights VALUES('834466_3_3179-3213','834466',110,'一','李光头看着她走去时屁股的扭动，就知道那个圆得卷起来的屁股是属于她的。','3233-3267',5,1690009064,1782480563);
