INSERT INTO highlights VALUES('3300074976_35_1344-1458','3300074976',35,'第2部分 实践应用','视觉里程计根据相邻图像的信息估计出粗略的相机运动，给后端提供较好的初始值。视觉里程计的算法主要分为两个大类：特征点法和直接法','1344-1458',0,1752571169,1782480549);
