INSERT INTO highlights VALUES('3300074976_35_2909-3557','3300074976',35,'第2部分 实践应用','角点的提取算法有很多，例如Harris角点￼、FAST角点￼、GFTT角点￼，','2909-3557',0,1751822930,1782480549);
