INSERT INTO highlights VALUES('3300074976_35_837-897','3300074976',35,'第2部分 实践应用','从本讲开始，我们结束基础知识的铺垫而步入正题：按照第2讲的顺序，分别介绍视觉里程计、后端优化、回环检测和地图构建4个模块','837-897',5,1718554231,1782480549);
INSERT INTO highlights VALUES('33091654_29_1861-1909','33091654',29,'第八章 明确目标——知道什么最重要才能全情投入','不幸的是，多数人从未踏上过英雄征途。原因说起来简单却令人难堪：我们太过忙碌，无暇追寻生命的意义。','1861-1909',5,1726567701,1782480556);
INSERT INTO highlights VALUES('33091654_29_1333-1438','33091654',29,'第八章 明确目标——知道什么最重要才能全情投入','哲学家和神话学者约瑟夫·坎贝尔将探寻使命和目标的过程称作“英雄之旅”，其基本元素在诸多文化和历史长河中熠熠发光。坎贝尔说，自我改造是人类最大的挑战。当改变的需求被唤醒，就成为英雄之旅的开端——启示、不适和痛苦。','1333-1438',5,1726567647,1782480556);
INSERT INTO highlights VALUES('33091654_29_1082-1112','33091654',29,'第八章 明确目标——知道什么最重要才能全情投入','每一种文化自诞生起，探寻使命和意义就是最广泛也最持久的主题。','1082-1112',5,1726567596,1782480556);
INSERT INTO highlights VALUES('33091654_25_11686-11717','33091654',25,'第五章 情感精力——把威胁转化为挑战','朱迪斯建立的第二个仪式习惯是为自己一直关心的某项事业付出时间。','11686-11717',5,1725688911,1782480556);
INSERT INTO highlights VALUES('33091654_25_1037-1133','33091654',25,'第五章 情感精力——把威胁转化为挑战','在我们看来，情商的意义在于有技巧地管控情感以保持正面积极的精力，并最终为全情投入服务。在实际应用中，自信、自控、社交技巧及共情能够牵动积极情感的“肌肉”。通俗来说，就是耐心、开放、信任和喜悦。','1037-1133',5,1724930401,1782480556);
INSERT INTO highlights VALUES('33091654_24_5818-5855','33091654',24,'第四章 体能精力——为身体添柴加火','在购物清单中加入能量棒、水果、葵花籽、全麦麦片、原味酸奶、蛋白粉和瓶装水。','5818-5855',5,1724826275,1782480556);
INSERT INTO highlights VALUES('33091654_24_3638-3705','33091654',24,'第四章 体能精力——为身体添柴加火','每天至少饮用1.8公斤水对维持体能有诸多好处。肌肉若缺水3%就会失去10%的力量和8%的速度。喝水不足也会损害大脑的注意力和协调能力。','3638-3705',5,1724766319,1782480556);
INSERT INTO highlights VALUES('33091654_24_2463-2487','33091654',24,'第四章 体能精力——为身体添柴加火','全麦食物、蛋白质和低糖水果——草莓、梨子和苹果等','2463-2487',5,1724766210,1782480556);
INSERT INTO highlights VALUES('33091654_24_2420-2437','33091654',24,'第四章 体能精力——为身体添柴加火','缓慢释放的糖分能够提供更稳定的精力','2420-2437',5,1724766174,1782480556);
INSERT INTO highlights VALUES('33091654_24_2338-2353','33091654',24,'第四章 体能精力——为身体添柴加火','选择升糖指数低的食物同样重要。','2338-2353',5,1724766168,1782480556);
INSERT INTO highlights VALUES('33091654_24_2046-2145','33091654',24,'第四章 体能精力——为身体添柴加火','长期过度进食则是过度“恢复”的典型代表，导致身体肥胖，损害精力。高糖高脂的食物和简单碳水化合物可以产生精力，但它们与低脂蛋白和蔬菜谷物等复合碳水化合物相比，不仅转化效率低，释放的能量也不如后者丰富。','2046-2145',5,1724766067,1782480556);
INSERT INTO highlights VALUES('33091654_24_1732-1850','33091654',24,'第四章 体能精力——为身体添柴加火','呼吸是自律的有力工具，既能集聚精力，又能带来深度放松。延长呼气时间有利于精力恢复。三次一组吸气、六次一组呼气可以使体能、思维和情感平复下来。深度、平静、有节奏地呼吸会激发精力、敏锐和专注，也能带来放松、宁静和安宁。这就是健康的终极脉动。','1732-1850',5,1724765483,1782480556);
INSERT INTO highlights VALUES('33091654_24_1194-1264','33091654',24,'第四章 体能精力——为身体添柴加火','他知道自己的饮食习惯称不上健康，但也没什么动机做出改变。他只是不让自己思考饥一顿饱一顿带来的后果。大部分时间，罗杰能感受到的只有忙碌和麻木。','1194-1264',5,1724636295,1782480556);
INSERT INTO highlights VALUES('33091654_24_447-492','33091654',24,'第四章 体能精力——为身体添柴加火','罗杰虽然也意识到如果睡眠充足、定期锻炼，身体可能会舒适些，但他表示就是没有时间睡眠和锻炼。','447-492',5,1724636158,1782480556);
INSERT INTO highlights VALUES('33091654_22_14891-14937','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','我们必须在四个层面都保持健康波动的节奏，即“效能金字塔”的组成部分：体能，情感，思维和意志。','14891-14937',5,1724636129,1782480556);
INSERT INTO highlights VALUES('33091654_22_13277-13300','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','是否愿意挑战舒适区有部分取决于我们潜在的安全感','13277-13300',5,1724635286,1782480556);
INSERT INTO highlights VALUES('33091654_22_13074-13112','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','“我们可以不投入任何意志精力就获得乐趣，但是只有在倾注关心时才谈得上享受。”','13074-13112',5,1724635112,1782480556);
INSERT INTO highlights VALUES('33091654_22_12428-12477','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','为了提升能力，我们需要系统性地增大压力，随后得到充分休息。提升肌肉极限，就要说到“超量补偿”的概念','12428-12477',5,1724634940,1782480556);
INSERT INTO highlights VALUES('33091654_22_11203-11246','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','”美国还没有类似的针对过劳影响的研究，但美国是全球唯一一个每周工作时间超过日本的国家。','11203-11246',5,1724589644,1782480556);
