INSERT INTO highlights VALUES('33091654_22_6179-6192','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','事情来得总比你的处理速度快','6179-6192',5,1724588789,1782480556);
INSERT INTO highlights VALUES('33091654_22_5951-6043','33091654',22,'第三章 高效表现有节奏——劳逸结合的平衡','我从来不会过度劳累，因为我不会让自己工作到那种程度。你必须要控制好自己的节奏，留出时间休息……时间是一种有限的资源，我们也应该有限度地索取。我将时间当作机遇，一个决定资源分配的机会。”','5951-6043',5,1724588742,1782480556);
