INSERT INTO highlights VALUES('CB_BOCFz6G1s6UD6cT6cK_7_6722-6833','CB_BOCFz6G1s6UD6cT6cK',7,'第1章　增长黑客的崛起','我们可以将增长目标拆分并概括为“AARRR”转化漏斗模型，即：Acquisition（获取用户）、Activation（激发活跃）、Retention（提高留存）、Revenue（增加收入）、Referral（传播推荐）。','6722-6833',NULL,1668060547,1782480565);
INSERT INTO highlights VALUES('CB_BOCFz6G1s6UD6cT6cK_7_6463-6486','CB_BOCFz6G1s6UD6cT6cK',7,'第1章　增长黑客的崛起','增长黑客是介于极客、发明家和广告狂人之间的角色','6463-6486',NULL,1667901541,1782480565);
