INSERT INTO highlights VALUES('CB_BOCFz6G1s6UD6cT6cK_7_5524-5605','CB_BOCFz6G1s6UD6cT6cK',7,'第1章　增长黑客的崛起','他们通常采用的手段包括A/B测试、搜索引擎优化、电子邮件召回、病毒营销等，而页面加载速度、注册转化率、E-mail到达水平、病毒因子这些指标成为他们日常关注的对象','5524-5605',NULL,1667892923,1782480565);
