INSERT INTO highlights VALUES('CB_BOCFz6G1s6UD6cT6cK_3_1892-1945','CB_BOCFz6G1s6UD6cT6cK',3,'推荐序','任何软件、网站、桌面程序、移动应用乃至未来的新异产品，无论是数字化的抑或通过实体介质，都应当参考黑客增长术','1892-1945',NULL,1667891363,1782480565);
INSERT INTO highlights VALUES('CB_BOCFz6G1s6UD6cT6cK_3_847-903','CB_BOCFz6G1s6UD6cT6cK',3,'推荐序','或许用户会允许我们在邮件底部写点什么来打个小广告，比如“附言：我爱你，你可以到Hotmail获得免费电子邮箱”。','847-903',NULL,1667891243,1782480565);
INSERT INTO highlights VALUES('3300075810_14_2945-2985','3300075810',14,'2.1 CPU眼里的main函数','(1)CPU面前，函数没有主次之分，main函数的实现方法，跟普通函数完全相同。','2945-2985',0,1747275985,1782480552);
INSERT INTO highlights VALUES('3300075810_14_2103-2132','3300075810',14,'2.1 CPU眼里的main函数','通过设置-efunc给它指定一个程序起点，即函数func，','2103-2132',0,1747275926,1782480552);
INSERT INTO highlights VALUES('3300075810_14_1087-1135','3300075810',14,'2.1 CPU眼里的main函数','从函数的实现上看，main函数与普通函数没有任何区别。能让main函数成为程序起点的一定另有原因','1087-1135',0,1747275854,1782480552);
INSERT INTO highlights VALUES('3300075810_13_913-969','3300075810',13,'第2章 基础语法','死记硬背，对本章节的学习，几乎没有任何意义。思考，哪怕是得出错误结果的思考，都是掌握本书知识的关键。祝阅读顺利！','913-969',0,1747275707,1782480552);
INSERT INTO highlights VALUES('3300075810_13_728-759','3300075810',13,'第2章 基础语法','请把自己想象成一个由世界上最慢的CPU、内存组成的计算机系统。','728-759',0,1747275671,1782480552);
INSERT INTO highlights VALUES('3300075810_12_6289-6349','3300075810',12,'1.3 CPU眼里的汇编语言','一些新的编程语言，例如RUST、SWIFT，编译器对代码封装得比较厉害，就不容易通过对应的汇编指令，了解语言的实现细节了','6289-6349',0,1747275647,1782480552);
INSERT INTO highlights VALUES('3300075810_12_6082-6097','3300075810',12,'1.3 CPU眼里的汇编语言','eax只是rax的低32位而已','6082-6097',0,1747275627,1782480552);
INSERT INTO highlights VALUES('3300075810_12_5474-5482','3300075810',12,'1.3 CPU眼里的汇编语言','寄存器间接寻址。','5474-5482',0,1747275506,1782480552);
INSERT INTO highlights VALUES('3300075810_12_5349-5383','3300075810',12,'1.3 CPU眼里的汇编语言','虽然完整的CPU寄存器和指令集比较庞大。但编译器只会用到很小的一部分','5349-5383',0,1747275493,1782480552);
INSERT INTO highlights VALUES('3300075810_12_5219-5318','3300075810',12,'1.3 CPU眼里的汇编语言',unistr('也是为什么苹果的M系列CPU，在没有显著提高CPU核心频率的情况下，也能产生秒杀同类的炸裂性能，因为它着重优化了CPU读、写内存的效率。\u000a'),'5219-5287',0,1747225806,1782480552);
INSERT INTO highlights VALUES('3300075810_12_5168-5193','3300075810',12,'1.3 CPU眼里的汇编语言','CPU的内存读写，占据了CPU 90%的工作负荷。','5168-5193',0,1747225790,1782480552);
INSERT INTO highlights VALUES('3300075810_12_1079-1146','3300075810',12,'1.3 CPU眼里的汇编语言','其中寄存器rax，一般用来存放数值，有点类似C语言的普通变量；而寄存器rbp，rsp，一般用来存放内存地址，有点类似C语言的指针变量。','1079-1146',0,1747223518,1782480552);
INSERT INTO highlights VALUES('3300075810_11_5681-5724','3300075810',11,'1.2 CPU眼里的程序运行','BSS段也叫未初始化的数据段，代码中没有初始化的全局变量、静态变量会被存储在这个区域，','5681-5724',0,1747223383,1782480552);
INSERT INTO highlights VALUES('3300075810_11_4497-4540','3300075810',11,'1.2 CPU眼里的程序运行','只有在真正读写这段内存时，操作系统才会为其映射真正的物理内存，而且是用多少，映射多少。','4497-4540',0,1747184300,1782480552);
INSERT INTO highlights VALUES('3300075810_11_4366-4392','3300075810',11,'1.2 CPU眼里的程序运行','在程序运行之前，“堆”和“堆栈”里面的内容是不确定的','4366-4392',0,1747184265,1782480552);
INSERT INTO highlights VALUES('3300075810_11_2141-2182','3300075810',11,'1.2 CPU眼里的程序运行','相反，现代操作系统，会基于物理内存和MMU协处理器，为给我们构建一个巨大的虚拟内存','2141-2182',0,1747183856,1782480552);
INSERT INTO highlights VALUES('3300075810_11_1969-1985','3300075810',11,'1.2 CPU眼里的程序运行','千万不要把密码写到你的代码里面了','1969-1985',0,1747183757,1782480552);
INSERT INTO highlights VALUES('3300075810_11_877-892','3300075810',11,'1.2 CPU眼里的程序运行','但它们的内存地址，却相隔很远！','877-892',0,1747180569,1782480552);
INSERT INTO highlights VALUES('3300075810_9_783-802','3300075810',9,'第1章 预备知识','90%的汇编指令的含义，都可以直接猜出','783-802',0,1747180132,1782480552);
INSERT INTO highlights VALUES('3300075810_8_1576-1598','3300075810',8,'前言','因为不可实践的工程技术，对工程师而言毫无意义','1576-1598',0,1747180012,1782480552);
INSERT INTO highlights VALUES('3300075810_8_708-719','3300075810',8,'前言','解释很多奇幻的语法规则','708-719',0,1747179950,1782480552);
INSERT INTO highlights VALUES('3300075810_8_539-586','3300075810',8,'前言','难道CPU也需要知道这么多的语法规则吗？CPU是如何遵守这些连人都觉得十分诡异的程序规则的呢？','539-586',0,1747179949,1782480552);
INSERT INTO highlights VALUES('3300075810_7_1737-1770','3300075810',7,'推荐序三','在量子计算领域，有类似Q#和Quipper这样量子专属的编程语言。','1737-1770',0,1747179948,1782480552);
INSERT INTO highlights VALUES('39136896_34_2389-2393','39136896',34,'译者序','Anki','2389-2393',5,1704384441,1782480562);
INSERT INTO highlights VALUES('39136896_34_2435-2465','39136896',34,'译者序','其实哪有什么惊人绝技，有的只是把简单有效的方法用到极致罢了。','2435-2465',5,1704384437,1782480562);
INSERT INTO highlights VALUES('39136896_34_2193-2258','39136896',34,'译者序','学习时，我们需要像剥洋葱一样，一层又一层地解构书中的原理；而运用时，则需要像在故宫修漆器类文物一样，分多次、分层地复原书中的原理。','2193-2258',5,1704384406,1782480562);
INSERT INTO highlights VALUES('39136896_33_1188-1210','39136896',33,'推荐序三 用卡片笔记积累你的知识复利','艾伦·凯说过：预测未来的最好方法就是发明它。','1188-1210',5,1704384094,1782480562);
INSERT INTO highlights VALUES('39136896_33_788-847','39136896',33,'推荐序三 用卡片笔记积累你的知识复利','从本质上讲，卡片笔记写作法不是一种“技巧”，而是一个“系统”，一种存储和组织知识、扩展记忆以及生成新连接和想法的系统。','788-847',5,1704384057,1782480562);
INSERT INTO highlights VALUES('39136896_32_1214-1243','39136896',32,'推荐序二 外脑思考，突破思维局限的写作法','。只有完全换另一种思维方式，才能心情愉悦地、安全地达成目标','1214-1243',5,1704383934,1782480562);
INSERT INTO highlights VALUES('39136896_31_3591-3610','39136896',31,'推荐序一 像卢曼一样写卡片','卡片盒笔记(Zettelkasten)','3591-3610',5,1704383783,1782480562);
INSERT INTO highlights VALUES('39136896_31_3268-3334','39136896',31,'推荐序一 像卢曼一样写卡片','第四类，也是最常用的索引形式，就是简单的“笔记-笔记”连接。两条笔记可能完全没有关系，把它们关联在一起，往往会产生出乎意料的新思路。','3268-3334',5,1704383724,1782480562);
INSERT INTO highlights VALUES('39136896_31_3180-3217','39136896',31,'推荐序一 像卢曼一样写卡片','第三类是在当前卡片上做索引，标明这条笔记逻辑上的前一条是什么、后一条是什么','3180-3217',5,1704383716,1782480562);
INSERT INTO highlights VALUES('39136896_31_3095-3149','39136896',31,'推荐序一 像卢曼一样写卡片','第二类与主题索引类似，只不过不是对某一主题的概览，而是针对盒子里相近位置的卡片所涉及的所有不同主题进行概览。','3095-3149',5,1704383709,1782480562);
INSERT INTO highlights VALUES('39136896_31_2947-2956','39136896',31,'推荐序一 像卢曼一样写卡片','第一类是主题索引。','2947-2956',5,1704383703,1782480562);
INSERT INTO highlights VALUES('39136896_31_2729-2774','39136896',31,'推荐序一 像卢曼一样写卡片','反之，如果我们略微增加写入难度，比如晚上回到宿舍或者第二天再写笔记，这样未来提取会更容易。','2729-2774',5,1704383445,1782480562);
INSERT INTO highlights VALUES('39136896_31_2550-2605','39136896',31,'推荐序一 像卢曼一样写卡片','“存储与提取负相关”，也就是说，存入记忆越容易，提取出来越困难；反之，如果你有些吃力地存入，知识提取会更方便。','2550-2605',5,1704383411,1782480562);
INSERT INTO highlights VALUES('39136896_31_2259-2303','39136896',31,'推荐序一 像卢曼一样写卡片','什么是必要难度理论？人类记忆存在广泛且普遍的元认知错觉，会误将“记住了”当成“学会了”。','2259-2303',5,1704383354,1782480562);
INSERT INTO highlights VALUES('39136896_31_2078-2105','39136896',31,'推荐序一 像卢曼一样写卡片','必要难度(Desirable Difficulty)。','2078-2105',5,1704383331,1782480562);
INSERT INTO highlights VALUES('39136896_31_1719-1810','39136896',31,'推荐序一 像卢曼一样写卡片','第二类是二阶操作，称之为“元认知”，即对自己当前的认知进行监控：“我当前感知到了什么？我当前在记忆什么？我当前在学习什么？我当前在思考什么？”这就是元感知、元记忆、元学习、元思考等。','1719-1810',5,1704383297,1782480562);
INSERT INTO highlights VALUES('39136896_31_1662-1719','39136896',31,'推荐序一 像卢曼一样写卡片','认知科学家将人的信息加工分为两大类，第一类是一阶操作，也就是“认知”本身，你感知的、你记忆的、你学习的、你思考的。','1662-1719',5,1704383288,1782480562);
INSERT INTO highlights VALUES('39136896_31_1500-1528','39136896',31,'推荐序一 像卢曼一样写卡片','而卢曼多了一个盒子，对自己卡片写作的内容进行索引和整理。','1500-1528',5,1704383190,1782480562);
INSERT INTO highlights VALUES('39136896_31_1378-1431','39136896',31,'推荐序一 像卢曼一样写卡片',unistr('卢曼与他们的最大区别是什么呢？\u000a——多了一个盒子。'),'1378-1431',5,1704383154,1782480562);
INSERT INTO highlights VALUES('39136896_31_1109-1149','39136896',31,'推荐序一 像卢曼一样写卡片','他将认知科学家F·瓦雷拉(F.Varela)开创的“自创生理论”率先应用到法律中','1109-1149',5,1704383104,1782480562);
INSERT INTO highlights VALUES('39136896_30_1160-1230','39136896',30,'中文版序','卡片盒笔记法——关联的、分散的、自下而上的方法不仅比一些教育者们所推崇的线性的、自上而下的方法更为自然，而且衍生出了诸多写作及笔记记录工具。','1160-1230',5,1704382947,1782480562);
INSERT INTO highlights VALUES('39136896_30_733-813','39136896',30,'中文版序','与柏拉图式的传统思维关注计划、目标、身份以及顿悟不同的是，卡片盒笔记依赖一种非线性的方式，即缓慢而稳定的改进，促进思维产生持续、微妙的变化，并且事物间相生相依。','733-813',5,1704382826,1782480562);
INSERT INTO highlights VALUES('39136896_30_633-657','39136896',30,'中文版序','其胆识则在于他采取了将最根本的差异进行比较的方式','633-657',5,1704382788,1782480562);
INSERT INTO highlights VALUES('23523085_10_7589-7682','23523085',10,'三 人生目的和自由','依照目前人類文化所已達到的境界，只有宗教、哲學、文學、藝術、科學，都在正面誘導人，感化人，都在為人類生活提供新目的，讓人有更廣更深的挑選之自由，都還是站在教育的地位上，那才能算是更好的。','16233-16326',1,1701244231,1782480562);
INSERT INTO highlights VALUES('23523085_10_7030-7198','23523085',10,'三 人生目的和自由','正因為，直到今天，眞眞夠得上更好的人生新目的的，提供得不夠多，宗教、哲學、藝術、文學、科學，種種文化人生中應有的幾塊大柱石，還未安放好，還未達到理想的程度，而且有好些前人早已提供的，後人又忘了，模糊了，忽略了，或是故意地輕蔑了，抛棄了，遂至於文化的人生有時要走上逆轉倒退的路。更好的消失了，只有挑選次好的。次好的沒有了，只有挑選不好的。','15019-15187',1,1701243666,1782480562);
INSERT INTO highlights VALUES('23523085_10_6799-6849','23523085',10,'三 人生目的和自由','最合理想的，只有在正面，積極方面，誘導人，指點人，讓人更自由地來選擇，並還容許人更自由地提供與創造。','14472-14522',1,1701243600,1782480562);
INSERT INTO highlights VALUES('23523085_10_6409-6457','23523085',10,'三 人生目的和自由','即佛家根本不承認人類本身有罪惡之存在，只教人類能有更高挑選之自由。一切宗教的最高精神都該如是的。','13599-13647',1,1701243461,1782480562);
INSERT INTO highlights VALUES('23523085_10_5040-5105','23523085',10,'三 人生目的和自由','殺人也是人類在沒有更好辦法之前所選擇的一種辦法呀！人類在無更好辦法時來選擇殺人之一法，這也已是人類之自由，所以那時也不算它是一種惡','10727-10792',1,1701242969,1782480562);
INSERT INTO highlights VALUES('23523085_10_4070-4121','23523085',10,'三 人生目的和自由','人類分別善惡的標準，也只有根據人類所希獲得的人生自由量之大小上發出。若捨棄這一個標準，便也無善惡可言。','8627-8678',1,1701242767,1782480562);
INSERT INTO highlights VALUES('23523085_10_3130-3197','23523085',10,'三 人生目的和自由','自殺是文化人生中的一件事，並非自然人生中的一件事。自然人生只求生，文化人生甚至有求死。求死也有一目的，即是從自然人生中求解放，求自由。','6619-6686',1,1701242441,1782480562);
INSERT INTO highlights VALUES('23523085_9_6155-6183','23523085',9,'二 適與神','人生如此般渺小，而居然能窺測無限宇宙之眞理，這已見人之神','13221-13249',1,1700904691,1782480562);
INSERT INTO highlights VALUES('23523085_9_5949-6002','23523085',9,'二 適與神','惟莊子同時又稱此曰「自然」。儒家並不推崇宗教，亦不尊信鬼神，但亦只有肯認此為神，惟同時又稱此神迹曰「性」。','12730-12783',1,1700904632,1782480562);
INSERT INTO highlights VALUES('23523085_9_4683-4747','23523085',9,'二 適與神','我們只有把「適」字的價値觀滲進舊有的眞、善、美的價値裏面去，於是主觀即成為客觀，相對即成為絕對，當下即便是終極，矛盾即成為和合。','10013-10077',1,1700904208,1782480562);
INSERT INTO highlights VALUES('23523085_9_2912-2986','23523085',9,'二 適與神','現在我們若為人生再安設一「適」的價値領域，而使此第四價値領域與前三價値領域，互相滲透，融為一體，使主觀與客觀並存，使相對與絕對等立，則局面自然改觀。','6135-6209',1,1700903960,1782480562);
INSERT INTO highlights VALUES('23523085_9_2353-2416','23523085',9,'二 適與神','其實，既稱客觀，便已含有主觀的成分。有所觀，必有其能觀者。「能」「所」一體，同時並立。觀必有主，宇宙間便不應有一種純粹的客觀。','4945-5008',1,1700903814,1782480562);
INSERT INTO highlights VALUES('23523085_8_5463-5513','23523085',8,'一 人生三路向','飛翔的遠離現實，將不是一種福；沉溺的迷醉於現實，也同樣不是一種福，有福的人生只要足踏實地，安穩向前。','12053-12103',1,1700903260,1782480562);
INSERT INTO highlights VALUES('23523085_8_3793-3869','23523085',8,'一 人生三路向','你若說向外尋求是「迷」，内明己心是「悟」，則向外的一切尋求完全祛除了，亦將無己心可明。因此禪宗說：「迷即是悟，煩惱即是湼槃，眾生即是佛，無明即是眞如。」','8281-8357',1,1700902466,1782480562);
INSERT INTO highlights VALUES('23523085_8_3709-3755','23523085',8,'一 人生三路向','你若將外面一切塗飾統統洗刷淨盡了，你若將外面一切建立統統拆卸淨盡了，你將見本來便沒有一個内。','8089-8135',1,1700902428,1782480562);
INSERT INTO highlights VALUES('23523085_8_3627-3671','23523085',8,'一 人生三路向','然而這裏同樣有一個基本的困難點，你若擺脫外面一切物，遺棄外面一切事，你便將覓不到你的心。','7858-7902',1,1700902419,1782480562);
INSERT INTO highlights VALUES('23523085_8_3360-3449','23523085',8,'一 人生三路向','外面一切沒有了，自然也不見有所謂内。「内」「外」倶泯，那樣的一個境界，究竟是無可言說的。倘你堅要我說，我只說是那樣的一個境界，而且將永遠是那樣的一個境界。佛家稱此為「一如不動」。','7319-7408',1,1700902396,1782480562);
INSERT INTO highlights VALUES('23523085_8_2781-2824','23523085',8,'一 人生三路向','說也奇怪，你要向外，便有無限的外展開在你的面前；你若要向内，又有無窮的内展開在你的面前','6041-6084',1,1700901252,1782480562);
INSERT INTO highlights VALUES('23523085_8_1083-1176','23523085',8,'一 人生三路向','近代西方人生，最足表明像上述的這一種人生之情態。然而這一種人生，有它本身内在的缺憾。生命自我之支撐點，並不在生命自身之内，而安放在生命自身之外，這就造成了這一種人生一項不可救藥的致命傷。','2213-2306',1,1700900844,1782480562);
INSERT INTO highlights VALUES('23523085_6_2465-2491','23523085',6,'自序','「問我何所有，山中惟白雲。只堪自怡悅，不堪持贈君。」','4905-4931',1,1700899918,1782480562);
