INSERT INTO highlights VALUES('621677_8_4218-4345','621677',46,'初版序','本书第三部分分析了情绪智力的关键作用：情绪智力如何维持我们最重视的人际关系，如果没有情绪智力，人际关系就会受到破坏；对事业成功起到关键作用的情绪智力，正在受到市场力量前所未有的重视；有害的情绪对身体健康的危害与二手烟无异，情绪平衡是我们健康和幸福的保证。','4090-4217',NULL,1614271239,1782480568);
