INSERT INTO highlights VALUES('621677_5_739-931','621677',43,'专家导读2','情商高的人会激励自己。在遭遇挫折、陷入低潮的时候，他会提醒自己要面对，要站起来，未来还大有可为，可能会变得更好。因为自己有这个优点、那个长处，因为自己做成过某件事、克服过某项困难，所以一定做得到。情商高的人通常积极向上。情商高的人也会激励他人。他会赞美周围的人，他会肯定他的家人、同事、朋友。别人跟他在一起常常会有一种重要感。','680-868',NULL,1614138727,1782480568);
INSERT INTO highlights VALUES('621677_4_1334-1454','621677',42,'专家导读1','戈尔曼把情商概括为以下五个方面的能力：（1）认识自身情绪的能力；（2）妥善管理情绪的能力；（3）自我激励的能力；（4）认识他人情绪的能力；（5）管理人际关系的能力。我把这五个能力简单归纳成：认识自己、管理自己、激励自己、认识别人、管理别人。','1271-1391',NULL,1614010337,1782480568);
INSERT INTO highlights VALUES('621677_4_1179-1190','621677',42,'专家导读1','情商就是管理情绪的能力','1120-1131',NULL,1614008962,1782480568);
INSERT INTO highlights VALUES('35679936_8_9483-9589','35679936',56,'第二章 拜伦式的不幸福','我想对所有富有才华却不知何去何从的年轻人说：“放弃写作的尝试吧，尽量不要写。走向大千世界，做个海盗，做个婆罗洲（Borneo）的王，做个苏联的劳动者，给自己那样一种生活，满足基本的生理需要几乎要耗费你全部精力。”','9052-9158',NULL,1661061159,1782480566);
INSERT INTO highlights VALUES('35679936_8_8928-9032','35679936',56,'第二章 拜伦式的不幸福','因此，诗人辛纳的死是喜剧的，而恺撒、布鲁图斯和卡西乌斯的死就是悲剧的。个人之死对于我们不再具有终极意义，因为我们不仅在外表上，而且在内心里早已成了民主主义者。所以在今天，高层次的悲剧更应该关注社会，而非个体。','8498-8602',NULL,1661061112,1782480566);
INSERT INTO highlights VALUES('35679936_8_8144-8279','35679936',56,'第二章 拜伦式的不幸福',unistr('真正的爱情是不熄的火焰，\u000a永远在心中燃烧，\u000a从不衰弱，从不死亡，从不冷却，\u000a从不偏离方向。'),'7764-7899',NULL,1661061014,1782480566);
INSERT INTO highlights VALUES('35679936_8_6657-6703','35679936',56,'第二章 拜伦式的不幸福','我所信仰的爱情是大胆的、清醒的，它告诉人们什么是善，且不忘记恶，也不假装“神圣”或“纯洁”。','6326-6372',NULL,1661060799,1782480566);
INSERT INTO highlights VALUES('35679936_8_6510-6562','35679936',56,'第二章 拜伦式的不幸福','对于这种夫妻之间完全放弃相互批评的做法，我实在不敢恭维。它密切关联的是恐惧感，是想逃避冷峻但公允的批评。','6179-6231',NULL,1661060773,1782480566);
INSERT INTO highlights VALUES('35679936_8_5437-5510','35679936',56,'第二章 拜伦式的不幸福','罗杰·培根的观点代表了他所属的那个时代文人的观点，他们都不喜欢自己所处的时代。我从不认为这种悲观论调有什么形而上的原因，原因就是战争、贫穷和暴力。','5139-5212',NULL,1661056787,1782480566);
INSERT INTO highlights VALUES('35679936_8_4414-4560','35679936',56,'第二章 拜伦式的不幸福','它们的困境犹如那些童年活在神话里、现在离开神话却还没学会如何自处的青少年，两者没有什么不同。”这番表述完全适用于一部分知识分子，他们接受过人文教育，却对现代社会一无所知，整个成长过程中接受的教导是要以情感作为信念的基础，因而一直无法摆脱寻求安全和保护的幼稚愿望，而科学世界却不能满足这种愿望。','4118-4264',NULL,1661056635,1782480566);
INSERT INTO highlights VALUES('35679936_8_4206-4281','35679936',56,'第二章 拜伦式的不幸福','对死亡感到愤怒是可以理解的，而对死亡的这种自然的态度也是合理的。所以，如果说情绪是由特定理由决定的，那么让人快乐的理由和让人绝望的理由同样多地存在着。','3910-3985',NULL,1661056180,1782480566);
INSERT INTO highlights VALUES('35679936_8_4024-4059','35679936',56,'第二章 拜伦式的不幸福','如果我长生不老，人生的乐趣迟早会失去魅力。唯其有限，生活才能历久弥新。','3761-3796',NULL,1661056081,1782480566);
INSERT INTO highlights VALUES('35679936_8_2885-2908','35679936',56,'第二章 拜伦式的不幸福','我憎恨我在太阳下的所有劳作，因为它会被后人享用','2640-2663',NULL,1661055874,1782480566);
INSERT INTO highlights VALUES('35679936_8_2636-2664','35679936',56,'第二章 拜伦式的不幸福','但他忘记了，保持对一些东西的渴望是幸福必不可少的一部分。','2407-2435',NULL,1661055832,1782480566);
INSERT INTO highlights VALUES('35679936_8_2325-2371','35679936',56,'第二章 拜伦式的不幸福','我自己时常会体验到“万事皆空”的情绪，我是靠着势在必行的行动而不是任何哲学来摆脱这种情绪的。','2096-2142',NULL,1661055740,1782480566);
INSERT INTO highlights VALUES('35679936_7_2303-2440','35679936',55,'第一章 什么使人不幸福？','我学会了对自己和自己的缺陷不再那么介意，而是把越来越多的注意力放到外部事物上：世界局势，各种学科知识，我喜欢的人。没错，对外部事物的关注也会带来各种痛苦：世界会陷入战争，某种知识很难掌握，喜爱的人会离我而去。但是这类痛苦不同于由自我憎恶而生发的那种痛苦，它不会摧毁生活的核心','2205-2342',NULL,1660882356,1782480566);
INSERT INTO highlights VALUES('35679936_7_2218-2238','35679936',55,'第一章 什么使人不幸福？','但更重要的原因在于，我不再过度专注于自我','2120-2140',NULL,1660882346,1782480566);
INSERT INTO highlights VALUES('35679936_7_1806-1927','35679936',55,'第一章 什么使人不幸福？','我认为，这些不幸福很大程度上归咎于错误的世界观、错误的伦理观、错误的生活习惯，它们毁掉了人们原本可能有的天然的兴致和胃口，而一切幸福，无论人或动物，皆基于此。观念与习惯都是个人可以掌控之事，我想就它们提些改进建议，佐以寻常运气，幸福或便可得。','1708-1829',NULL,1660882274,1782480566);
INSERT INTO highlights VALUES('35679936_7_1751-1805','35679936',55,'第一章 什么使人不幸福？','我的目标是消除那些文明社会中大多数人感受着的日复一日的生活烦恼，它们没有明确诱因，仿佛无处可逃，愈发难以忍受','1653-1707',NULL,1660882246,1782480566);
INSERT INTO highlights VALUES('35679936_7_1609-1657','35679936',55,'第一章 什么使人不幸福？','种种思考引领我们走向了这样的个人问题：此时此处，身在怀旧社会的男男女女，该怎样去为自己争取幸福感','1511-1559',NULL,1660882227,1782480566);
INSERT INTO highlights VALUES('35679936_7_1339-1390','35679936',55,'第一章 什么使人不幸福？','凡此种种不幸福，部分源于社会制度，部分在于个体心理——当然，个体心理本身很大程度上也是社会制度的产物。','1241-1292',NULL,1660870145,1782480566);
INSERT INTO highlights VALUES('35679936_7_579-620','35679936',55,'第一章 什么使人不幸福？','观察朋友的时候，你要让自己学会察言观色，让自己更善于感受日常生活中所遇之人的情绪。','514-555',NULL,1660870041,1782480566);
INSERT INTO highlights VALUES('35679936_7_4932-5017','35679936',55,'第一章 什么使人不幸福？','典型的不幸福的人都是年轻时被剥夺了一些正常的满足，他会因此更看重这些满足而不是别的，这让他的人生只有一个方向可走，同时，他过分强调了成功却将与成功相关的活动放到了对立面。','4833-4918',NULL,1656303258,1782480566);
INSERT INTO highlights VALUES('35679936_7_4808-4870','35679936',55,'第一章 什么使人不幸福？','被控制在适当范围内的权力可能会极大地增加人的幸福感，但若把它视为人生的唯一目的，它就会导致灾难，如果不是在外部，就是在内心。','4709-4771',NULL,1656303247,1782480566);
