INSERT INTO highlights VALUES('695233_53_33737-33863','695233',175,'广播纪元7年 云天明','看她的目光中充满喜悦，但那是一种很自然的喜悦，就像田间干活的小伙子看到同村的姑娘从城里回来时一样，仿佛三个世纪的岁月不存在，几光年的距离也不存在，他们一直在一起。这是程心完全没有想到的，云天明的目光像一双宽厚的手抚摸着她，让她极度紧张的精神放松了一些。','11433-11560',NULL,1550155802,1782480568);
