INSERT INTO highlights VALUES('31808219_7_1671-1714','31808219',142,'第一卷 一户人家的历史','阿黛拉伊达·伊万诺夫娜在私奔之后，立刻就明白，除了鄙视以外，自己对丈夫再也没有别的感情','1816-1859',NULL,1693849347,1782480563);
INSERT INTO highlights VALUES('31808219_13_1204-1345','31808219',143,'第二卷 不该举行的聚会','乞丐马上把我们的那几位客人围住，但没人给他们钱。只有彼得·卡尔甘诺夫从小钱包里取出一枚十戈比的硬币，天知道为什么显得很尴尬的样子，急急忙忙把它塞给一名女丐，很快地说了一句：“拿去平分吧。”同来的人谁也没有说他什么，所以他根本用不到难为情；然而他注意到这一点以后，反而更增添几分尴尬。','1333-1474',NULL,1674495810,1782480563);
INSERT INTO highlights VALUES('31808219_11_4434-4498','31808219',142,'第一卷 一户人家的历史','佐西马长老时年六十五岁上下，地主出身，少壮时当过军人，曾作为尉官在高加索服役。毋庸置疑，他以自己心灵的某种特殊素质征服了阿辽沙。','25550-25614',NULL,1674460255,1782480563);
INSERT INTO highlights VALUES('31808219_11_3155-3194','31808219',142,'第一卷 一户人家的历史','那么，究竟什么是长老呢？长老就是能把你的灵魂、你的意志纳入他的灵魂和意志的人。','24175-24214',NULL,1674459973,1782480563);
INSERT INTO highlights VALUES('31808219_11_1416-1565','31808219',142,'第一卷 一户人家的历史','不幸的是，这些青年并不懂得，在很多情况下，舍身也许是所有的牺牲中最轻而易举的，而从自己风华正茂的生命中拿出五六年来埋头苦学，做点学问，哪怕只是为了十倍地增强自己的力量，以便为他追求的真理服务，为他心向往之并且引为己任的大事业服务，——这样的牺牲对于他们中许多人来说几乎完全做不到，实际情况往往如此。','22211-22360',NULL,1674459730,1782480563);
INSERT INTO highlights VALUES('31808219_9_2965-3078','31808219',142,'第一卷 一户人家的历史','关于大的那一个——伊万——我只想交代一点：他长成了一个阴郁乖僻、性格内向的少年，虽然远非胆小怕羞，但好像从十岁左右开始便明白他们哥儿俩毕竟是寄人篱下，接受人家的恩惠，他们的父亲是个简直一提起来就让他们颜面蒙羞的人，等等，等等。','8933-9046',NULL,1674381947,1782480563);
INSERT INTO highlights VALUES('31808219_9_2390-2468','31808219',142,'第一卷 一户人家的历史','在这以后不久，将军夫人也告下世，不过她在遗嘱里给了两个娃娃每人一千卢布“供他们受教育，而且这些钱一定要完全花在他们身上，但必须细水长流，足以维持到他们成年，','8358-8436',NULL,1674381877,1782480563);
