INSERT INTO highlights VALUES('31808219_4_583-628','31808219',117,'作者的话','我实实在在的告诉你们：一粒麦子落在地里如若不死，仍旧是一粒；若是死了，就会结出许多子粒来。','2779-2824',NULL,1673755279,1782480563);
INSERT INTO highlights VALUES('39457314_61_2628-2816','39457314',61,'第一章 星海之滨','宇宙里星系的数量多达几千亿(1011)个，每一个都包含了几千亿恒星。如果星系中的行星数量和恒星差不多，那它们就有1011×1011=1022个，整整百万亿之多。','2628-2816',5,1714400247,1782480559);
INSERT INTO highlights VALUES('39457314_61_2409-2443','39457314',61,'第一章 星海之滨','我们已经来到了星云的王国，它距离地球80亿光年，位于已知宇宙的中央。','2409-2443',5,1714399924,1782480559);
INSERT INTO highlights VALUES('39457314_61_2295-2329','39457314',61,'第一章 星海之滨','如果位置合适，我们能在星系间的深空里看到无数微弱、纤细的须卷状光芒。','2295-2329',5,1714399868,1782480559);
INSERT INTO highlights VALUES('39457314_61_2169-2266','39457314',61,'第一章 星海之滨','如果我们被随机抛进宇宙某处，落在行星或者附近的概率会小于1/1033（1后面跟33个0）。这样的数字极难在日常生活中见到，可见星球多么稀少。','2169-2266',5,1714399827,1782480559);
INSERT INTO highlights VALUES('39457314_61_2078-2117','39457314',61,'第一章 星海之滨','实际上，没有哪个星球、恒星或者星系能够算作典型，因为宇宙的绝大多数地方都是空的','2078-2117',5,1714399815,1782480559);
INSERT INTO highlights VALUES('39457314_61_1696-1705','39457314',61,'第一章 星海之滨','地球位于星海边缘。','1696-1705',5,1714399726,1782480559);
INSERT INTO highlights VALUES('39457314_61_1568-1632','39457314',61,'第一章 星海之滨','探索宇宙，需要兼具想象力和怀疑精神。想象力能开启未知世界，少了它，我们将一事无成。怀疑精神则可以区分幻想和现实，检验我们的推测。','1568-1632',5,1714399715,1782480559);
INSERT INTO highlights VALUES('39457314_61_1458-1495','39457314',61,'第一章 星海之滨','还提醒我们，人类已经进化到了以学习为乐，并以获取知识为生存先决条件的地步。','1458-1495',5,1714399677,1782480559);
INSERT INTO highlights VALUES('39457314_61_1329-1368','39457314',61,'第一章 星海之滨','宇宙的规模和年龄远超常人想象。我们的行星家园只是迷失在永恒和无限间的小小一点。','1329-1368',5,1714399624,1782480559);
INSERT INTO highlights VALUES('39457314_40_4810-4849','39457314',40,'前言','美国“伽利略号”航天器计划于1988年抵达木星，首次将探测器送进木星大气层之内','4810-4849',5,1714365579,1782480559);
INSERT INTO highlights VALUES('39457314_40_4395-4440','39457314',40,'前言','“旅行者”一号和二号在飞跃土星时见证了这个行星系统的诸多奇迹，复杂的星环、成群结队的卫星，','4395-4440',5,1714365472,1782480559);
INSERT INTO highlights VALUES('39457314_40_3836-3876','39457314',40,'前言','埃及空军会在每天早上九点到十一点，把我们下榻的酒店当作扫射练习的目标来飞上一遭。','3836-3876',5,1714365268,1782480559);
INSERT INTO highlights VALUES('39457314_40_3770-3826','39457314',40,'前言','用等比例“海盗号”着陆器在莫哈维沙漠模拟火星探索时，拍摄活动数次遭到打断，因为美国空军要在附近靶场进行轰炸练习。','3770-3826',5,1714357386,1782480559);
INSERT INTO highlights VALUES('39457314_40_3550-3607','39457314',40,'前言','这样的安排，是因为我相信，只有在意识到古希腊人曾距离真知不过咫尺后，读者才能更深刻地理解他们完成的到底是何等伟业。','3550-3607',5,1714357349,1782480559);
INSERT INTO highlights VALUES('39457314_40_3099-3188','39457314',40,'前言','书本最大的优势在于，读者能反复阅读晦涩难懂的章节，而录像和影碟类似的功能刚起步研发；对作者来说，在书中深度拓展一个专题，比在时长58分30秒的非商业电视纪录片里把事情说清楚更方便','3099-3188',5,1714357256,1782480559);
INSERT INTO highlights VALUES('39457314_40_2771-2821','39457314',40,'前言','写这篇文章时，全世界范围内收看电视纪录片《宇宙》的观众已经突破了1.4亿，或者说，地球总人口的3%。','2771-2821',5,1714357239,1782480559);
INSERT INTO highlights VALUES('39457314_40_2544-2579','39457314',40,'前言','说我们不如合伙成立制片公司，用一种既受欢迎，又易于理解的方式传播科学。','2544-2579',5,1714357202,1782480559);
INSERT INTO highlights VALUES('39457314_40_2321-2344','39457314',40,'前言','然而实际上，火星上气势雄浑的景观美得令人震惊。','2321-2344',5,1714357174,1782480559);
INSERT INTO highlights VALUES('39457314_40_1949-2021','39457314',40,'前言','从本质上来说，人类诞生在宇宙一隅，命运早已注定与之紧密相连。我们最寻常、最琐碎的事务，都可以追溯到宇宙及其起源——这正是本书所致力于呈现的视角。','1949-2021',5,1714357101,1782480559);
INSERT INTO highlights VALUES('39457314_40_1911-1948','39457314',40,'前言','然而科学同样揭示出，宇宙不但有着令人头晕目眩的宏伟尺度，也可以为人类所理解','1911-1948',5,1714357096,1782480559);
INSERT INTO highlights VALUES('39888201_9_6273-6292','39888201',9,'第二类句型','感官动词后面需要接表语，表语是名代形。','6273-6292',5,1716947457,1782480558);
INSERT INTO highlights VALUES('39888201_9_2257-2293','39888201',9,'第二类句型','表语可由名词（代词）、形容词充当。副词、动词不可以作表语。','2257-2293',5,1716947334,1782480558);
INSERT INTO highlights VALUES('39888201_9_4363-4500','39888201',9,'第二类句型',unistr('God is everywhere.\u000a这个句子的意思是 “上帝无处不在”，不需要表语就已经是完整的句子了。所以这个句子属于由“主语+谓语”构成的第一类句型。'),'4363-4500',5,1716946959,1782480558);
INSERT INTO highlights VALUES('39888201_9_1794-1944','39888201',9,'第二类句型',unistr('英语中的10种词性\u000a词性是指单词的形式特征。英语中有10种词性，分别是名词、代词、动词、数词、形容词、副词、连词、介词、冠词和感叹词。'),'1794-1944',5,1716946769,1782480558);
INSERT INTO highlights VALUES('39888201_9_1360-1457','39888201',9,'第二类句型','这些补充说明的词句就被称为补语，','1360-1457',5,1716946755,1782480558);
INSERT INTO highlights VALUES('39888201_9_1106-1196','39888201',9,'第二类句型','这些动词后需要有补充说明主语的状态、情况及身份等内容的词句。','1106-1196',5,1716946737,1782480558);
INSERT INTO highlights VALUES('39888201_9_359-606','39888201',9,'第二类句型',unistr('第二类句型 INSERT INTO highlights VALUES('39888201_8_5084-5122','39888201',8,'第一类句型','修饰语除了包含简单形容词和副词之外，还包括介词短语及状语从句。','5084-5122',5,1716946564,1782480558);
INSERT INTO highlights VALUES('39888201_8_4869-4888','39888201',8,'第一类句型','副词、介词短语、状语从句都属于修饰语。','4869-4888',5,1716946512,1782480558);
INSERT INTO highlights VALUES('39888201_8_3352-3404','39888201',8,'第一类句型','构成句子的基本要素是主语、谓语、宾语、补语。','3352-3404',5,1716916803,1782480558);
INSERT INTO highlights VALUES('39888201_8_2451-2473','39888201',8,'第一类句型','另外，本书将介词短语也归为起副词作用的修饰语','2451-2473',5,1716916766,1782480558);
INSERT INTO highlights VALUES('39888201_7_5069-5070','39888201',7,'Part 01 句子的五种类型','[插图]','4889-4893',5,1716861816,1782480558);
INSERT INTO highlights VALUES('39888201_8_1082-1153','39888201',8,'第一类句型','因此，我们把第一类句型的动词称为不及物动词。即，可以单独使用，不需要宾语或补语的动词。','1082-1153',5,1716861638,1782480558);
INSERT INTO highlights VALUES('39888201_8_600-660','39888201',8,'第一类句型',unistr('第一类句型 = 主语+谓语\u000a'),'600-613',5,1716861635,1782480558);
INSERT INTO highlights VALUES('39888201_7_4100-4313','39888201',7,'Part 01 句子的五种类型',unistr('补语起补充说明的作用，除名词（代词）外，形容词也可以作补语。\u000a√ 因此，名词就作“主宾补”，补语就是“名代形”！'),'4100-4313',5,1716833116,1782480558);
INSERT INTO highlights VALUES('39888201_7_3321-3393','39888201',7,'Part 01 句子的五种类型','补充说明主语或宾语的补语（在第二类句型中称为“表语”，第五类句型中称为“宾语补足语”）。','3321-3393',5,1716833027,1782480558);
INSERT INTO highlights VALUES('39888201_7_2944-3042','39888201',7,'Part 01 句子的五种类型','但其实最常用的就是五类基本类型，所有英语句子都可以看成是五种基本句型的变化。','2944-3042',5,1716833015,1782480558);
INSERT INTO highlights VALUES('39888201_7_2762-2782','39888201',7,'Part 01 句子的五种类型','语法，就是为保证彼此能准确沟通而做的约定','2762-2782',5,1716832978,1782480558);
INSERT INTO highlights VALUES('39888201_7_2692-2731','39888201',7,'Part 01 句子的五种类型','英语表达如果不遵守特定的语法规则，就很难准确地表达出意思，甚至造成对句意的误解','2692-2731',5,1716832967,1782480558);
INSERT INTO highlights VALUES('39888201_4_507-535','39888201',4,'推荐序','到目前为止，我们接触到的大部分英语语法书都省略了前因后果','507-535',5,1716785599,1782480558);
INSERT INTO highlights VALUES('41588195_7_10324-10374','41588195',7,'第一站：架构、重构与建构','在这个意义上，上帝——真实的上帝——正是那个das Ding，他是任性、冷酷且毫无普遍正义感的主宰。','10324-10374',5,1719538365,1782480557);
INSERT INTO highlights VALUES('41588195_7_7938-7990','41588195',7,'第一站：架构、重构与建构','在压力极大的情况下，有抑郁症的人反倒比其他人表现地更加沉着冷静——因为他们对更好的结局早已没有任何期待。','7938-7990',5,1718037448,1782480557);
INSERT INTO highlights VALUES('41588195_7_4714-4744','41588195',7,'第一站：架构、重构与建构','在这叙事架构中，与外来物的遭遇是从属于有情人终成眷属的主题。','4714-4744',5,1718029702,1782480557);
INSERT INTO highlights VALUES('41588195_7_4541-4601','41588195',7,'第一站：架构、重构与建构','但这个生物恰恰是为了让这对恋人走到一起而存在的；更确切的说法是，外星生物构成了乔与艾莉丝为了在一起而必须面对的困难与挑战','4541-4601',5,1718029646,1782480557);
INSERT INTO highlights VALUES('41588195_7_2637-2701','41588195',7,'第一站：架构、重构与建构','在其最基础的意义上，并非任何在这个世界发生的事都能算是事件，相反，事件涉及的是我们藉以看待并介入世界的架构的变化。','2637-2701',5,1718029202,1782480557);
INSERT INTO highlights VALUES('41588195_7_1681-1857','41588195',7,'第一站：架构、重构与建构','“未知的已知”，也就是那些我们不知道自己已然知晓的东西——这正是弗洛伊德意义上的无意识，也是法国精神分析学家雅克·拉康（1901—81，拉康的著作是本书的主要参考[5]）所谓的“不自知的知识”。','1681-1857',5,1718029037,1782480557);
INSERT INTO highlights VALUES('41588195_7_1038-1129','41588195',7,'第一站：架构、重构与建构','在倡导常识，反对哲学的人们看来，哲学这个行当无异于精神上的西格马林根：哲学家不亦乐乎地虚构出天马行空的理论，仿佛有了看穿人类命运的洞见，然而真实的生活却与这些哲学巨擘的思想毫不相干。','1038-1129',5,1718028958,1782480557);
INSERT INTO highlights VALUES('41588195_6_3724-3917','41588195',6,'启程：转捩中的事件','接下来则依次是对称破缺、佛教里的“正等正觉”、破坏了日常生活的真相、具有纯粹事件性的对自我的体验、那些将真理本身事件化了的仿佛把握真理的幻觉、破坏了象征性的秩序之稳定的创伤经历、“主能指”（Master-Signifier）的出现（这种能指给出了整个意义之域的结构）、对纯粹的感觉/非感觉之流的经验……最后，我们还将提及取消事件性的成就（evental achievement）的问题。','3724-3917',5,1718028857,1782480557);
INSERT INTO highlights VALUES('41588195_6_3709-3723','41588195',6,'启程：转捩中的事件','第二站谈的是宗教里的“堕落”','3709-3723',5,1718028840,1782480557);
INSERT INTO highlights VALUES('41588195_6_3683-3708','41588195',6,'启程：转捩中的事件','我们在第一站将讨论世界向我们呈现的架构的变化与解体','3683-3708',5,1718028833,1782480557);
INSERT INTO highlights VALUES('41588195_6_3634-3683','41588195',6,'启程：转捩中的事件','这情形就如同坐在一列地铁列车上，其运行线路有许多的站点与分岔，每一站都代表着对事件的一个假定定义。','3634-3683',5,1718028829,1782480557);
INSERT INTO highlights VALUES('41588195_6_3385-3423','41588195',6,'启程：转捩中的事件','事件总是某种以出人意料的方式发生的新东西，它的出现会破坏任何既有的稳定架构。','3385-3423',5,1718028676,1782480557);
INSERT INTO highlights VALUES('41588195_6_3218-3246','41588195',6,'启程：转捩中的事件','事件究竟是世界向我们呈现方式的变化，还是世界自身的转变？','3218-3246',5,1718028615,1782480557);
INSERT INTO highlights VALUES('41588195_6_2700-2786','41588195',6,'启程：转捩中的事件','先验论思想在德国哲学家马丁·海德格尔（1889—1976）那里达到了巅峰；而存在论则转变为自然科学的领地：量子力学、脑科学与进化论，成为我们寻求宇宙起源变化问题答案的依据。','2700-2786',5,1718028531,1782480557);
INSERT INTO highlights VALUES('41588195_6_2528-2565','41588195',6,'启程：转捩中的事件','对科学自然主义者而言，只有位于时空中且遵循物理定律的物质现象才是真实存在的','2528-2565',5,1718028368,1782480557);
INSERT INTO highlights VALUES('41588195_6_2400-2455','41588195',6,'启程：转捩中的事件','先验论旨在揭示现实世界以怎样的普遍结构向我们呈现：它要回答的是实在物（the Real）的感知如何可能的问题。','2400-2455',5,1718028337,1782480557);
INSERT INTO highlights VALUES('41588195_6_2332-2399','41588195',6,'启程：转捩中的事件','自其诞生之日起，哲学似乎就始终徘徊在先验论（transcendental）与存在论（ontological，ontic）这两个进路之间','2332-2399',5,1718028311,1782480557);
INSERT INTO highlights VALUES('41588195_6_2195-2225','41588195',6,'启程：转捩中的事件','因果性正是哲学的基本问题之一：是否所有的事物都以因果链条相连','2195-2225',5,1718028287,1782480557);
INSERT INTO highlights VALUES('41588195_6_2084-2166','41588195',6,'启程：转捩中的事件','按照第一种界定事件的方法，我们可以将事件视作某种超出了原因的结果，而原因与结果之间的界限，便是事件所在的空间。','2084-2166',5,1718028268,1782480557);
INSERT INTO highlights VALUES('41588195_6_1399-1414','41588195',6,'启程：转捩中的事件','在循环结构中，若干事件互为因果','1399-1414',5,1718026169,1782480557);
INSERT INTO highlights VALUES('915288_16_1775-2021','915288',73,'偏差行为','四种主要的偏差行为：——引起注意（看看我！看看我！）——权力斗争（我不想做，你不能逼我！）——报复心理（你伤害了我多少我也要伤害你多少。）——自我放逐（努力有什么用呢？反正我一点也不重要。）','575-820',NULL,1624323809,1782480567);
INSERT INTO highlights VALUES('915288_16_1047-1064','915288',72,'第三章 幻灭','这个词的意思是——不再被错觉所迷惑','1463-1480',NULL,1624323728,1782480567);
