INSERT INTO highlights VALUES('915288_13_1450-1458','915288',70,'压力、失望和愤恨','期望=愤恨的前身','1217-1225',NULL,1624253333,1782480567);
INSERT INTO highlights VALUES('915288_12_3506-3545','915288',69,'通往地狱之路','骑士找不到圣杯，因为它的所在，正是骑士们认为最不可能的地方，那就是他们的心中。','3270-3309',NULL,1624252844,1782480567);
INSERT INTO highlights VALUES('915288_12_2686-2809','915288',69,'通往地狱之路','如果我感到失望、愤恨，一定是因为我对妻子有所期望，而在她做到之前，我无法快乐起来。在这样的亲密关系互动中，最悲哀的是，在“小小的我”得到满足之前，我们不愿意去爱我们的伴侣。紧抱着需求不肯放手，又不让自己去爱，就这样，我们把自己推向亲密关系的地狱。','2450-2573',NULL,1624252726,1782480567);
INSERT INTO highlights VALUES('915288_12_2285-2303','915288',69,'通往地狱之路','不开心的原因，往往是沉睡多年的需求。','2049-2067',NULL,1624252652,1782480567);
INSERT INTO highlights VALUES('915288_11_2056-2110','915288',68,'制造梦想的机器','我们会想，这不只是为我们自己好，也是为他们好。这种修饰或彻底改造伴侣的企图，很快就会让我们走上通往地狱之路。','1824-1878',NULL,1624252452,1782480567);
