INSERT INTO highlights VALUES('915288_5_2056-2143','915288',62,'前言 十六周年版作者序','这时你的伴侣将会依所需而扮演这三种角色之一：一面镜子，让你看见引发你关注的不舒服感；一名老师，在你探寻真实自我的时候，激励与启发你；一名“玩伴”，开启并陪伴你一段生命的旅程。','1824-1911',NULL,1623937642,1782480567);
