INSERT INTO highlights VALUES('3300071182_18_703-728','3300071182',18,'一','炎帝是种地的烈山氏的代表，黄帝是驾车的轩辕氏的代表','703-728',0,1731080448,1782480555);
INSERT INTO highlights VALUES('3300071182_16_2146-2197','3300071182',16,'四','所以这两个礼仪——男子割牛耳、主持杀生，女子献上鲜果、坚果——也未尝不是过去渔猎、采集时代生活的遗迹。','2146-2197',0,1731080383,1782480555);
INSERT INTO highlights VALUES('3300071182_16_1640-1701','3300071182',16,'四','狩猎的时候不管冷热，农耕却与天气关系极大；这位英雄射下九个太阳，使农耕民族的人们不受灾害，这似乎也是两个文化过渡期间的叙述','1640-1701',0,1731080276,1782480555);
INSERT INTO highlights VALUES('3300071182_16_544-616','3300071182',16,'四','当时古代神话传说里，存在三皇和五帝的对抗：三皇就是炎帝和黄帝结合起来的农耕集团，五帝所代表的是蚩尤领导的采集集团。最后的结果，是采集集团战败了。','544-616',0,1731080074,1782480555);
INSERT INTO highlights VALUES('3300071182_15_1328-1370','3300071182',15,'三','至今，大米的种植地区仍大致以淮河为界，南边基本上是米食，北边基本上以麦类与小米为食。','1328-1370',0,1731078434,1782480555);
INSERT INTO highlights VALUES('3300071182_15_569-597','3300071182',15,'三','小米后来逐渐分化为更多品种——粟、稷、粱，如今泛称为小米','569-597',0,1731078315,1782480555);
INSERT INTO highlights VALUES('3300071182_11_649-745','3300071182',11,'四','这些考虑，都是为了解答一个千古大问：为何到了近代两百年来，中国无法抗拒那些乘潮而来的欧洲人？在奔入世界大海洋这一关键性的时刻，为何中国文化的反应机制无法适当地感受变化，发展出应有的调节与更新？','649-745',0,1731070961,1782480555);
INSERT INTO highlights VALUES('3300071182_9_3700-3769','3300071182',9,'二','我盼望：中国能站起来，在世界上扮演一个大国应有的角色。然而，中国不能落入白人霸权的窠臼，中国不要做霸主，而是做许多国家之中互相帮助的一员。','3700-3769',0,1731065332,1782480555);
INSERT INTO highlights VALUES('3300071182_9_2944-3040','3300071182',9,'二','世界历史上的大帝国，如蒙古帝国、突厥帝国，以至于近来的“大不列颠世界”和苏维埃共和国，疆域都比中国大，但是其内部的充实和一致性，以及面临外部重压下的调节能力，都无法和中国历史上呈现的弹性相比。','2944-3040',0,1731065235,1782480555);
INSERT INTO highlights VALUES('3300071182_9_956-1001','3300071182',9,'二','而长江口以南，以南岭、武夷山为界的东南沿海，包括西南腹地的云贵，我们可以称其为第三核心区。','956-1001',0,1731003302,1782480555);
