INSERT INTO highlights VALUES('3300071182_7_2169-2212','3300071182',7,'致读者书','其经济模式无法转变成占地面积庞大的农业经济，他们必须四处掠夺，也掠夺邻近的中东、非洲。','2169-2212',0,1730643720,1782480555);
INSERT INTO highlights VALUES('3300071182_7_1514-1613','3300071182',7,'致读者书','西方文明自身的发展，总时长不超过两千年，这一群体行动力强，融合力弱。在上述变化以后，欧洲人才具有自身的“动能”。于是，他们通过海上活动掠夺了非洲和美洲的资源、劳力以及土地，迅速开展为支配世界的力量。','1514-1613',0,1730643608,1782480555);
INSERT INTO highlights VALUES('3300071182_7_1965-2028','3300071182',7,'致读者书','如果根据欧洲当年部落群的背景言之，他们是移动的群体，没有固定的农业可以维生，必须经历依赖草原上的牧草，养育牲口以维生计的阶段。','1965-2028',0,1730643549,1782480555);
