INSERT INTO highlights VALUES('3300071182_4_881-935','3300071182',4,'推荐序 经纬华夏，寻根明志','如果说《万古江河》还“大多是中国文化圈内部的演变”，那么《经纬华夏》则是要“从世界看中国，再从中国看世界”了','881-935',0,1728883270,1782480555);
INSERT INTO highlights VALUES('3300071182_1_56-112','3300071182',1,'封面','他以多元一体理论为框架，深入分析了华夏文明的起源、发展和扩张，并详细探讨了中国文化的包容特色和与西方文化的差异。','56-112',0,1728883088,1782480555);
INSERT INTO highlights VALUES('906847_13_5742-5758','906847',13,'自传','称他是一位虔诚而又博学的英国人。','5742-5758',5,1714744549,1782480559);
