INSERT INTO highlights VALUES('906847_13_5413-5419','906847',13,'自传','总共十七个。','5413-5419',5,1714744505,1782480559);
INSERT INTO highlights VALUES('906847_13_2024-2109','906847',13,'自传','人大多不喜欢他人爱慕虚荣，而自己的那颗虚荣心再大也安之若素，然而我无论在哪里遇到虚荣，总是以礼相待，因为我相信，虚荣对于爱慕者也好，对于他周围的人也好，往往都是有益无害的','2024-2109',5,1714743549,1782480559);
INSERT INTO highlights VALUES('906847_13_1716-1767','906847',13,'自传','最像再活一遍的事情似乎就是对这一生的一种反思了','1716-1767',5,1714742289,1782480559);
INSERT INTO highlights VALUES('906847_13_1398-1541','906847',13,'自传','何况，我这么做还有别的一些诱因。我生于贫寒之家，长于无名之户，如今不仅家境富裕，在世界上还小有名气，还有，我一辈子福星高照，我为人处世的种种手段，托上帝之福，取得了立竿见影的功效，对于这些，我的子孙后代也许愿意了解了解，因为他们或许会发现其中有些对他们的境遇也同样适用，因此也宜于效仿。','1398-1541',5,1714742245,1782480559);
INSERT INTO highlights VALUES('906847_12_9057-9097','906847',12,'译者导言','富兰克林的《自传》是美国的第一部杰作，至今仍然是美国著作中读者最多、影响最大的。','9057-9097',1,1714315023,1782480559);
INSERT INTO highlights VALUES('906847_12_6530-6582','906847',12,'译者导言','为什么要写这种场景呢？富兰克林说，“我将它作为又一个例证，说明维持一个人的生命和健康需要的收入微乎其微。','6530-6582',1,1714313376,1782480559);
INSERT INTO highlights VALUES('906847_12_5199-5252','906847',12,'译者导言','富兰克林的可贵之处就是他敢于亮丑，写年轻时犯的错误，而这些错误在我们中国人看来，是绝对不能曝光的“隐私”。','5199-5252',1,1714313122,1782480559);
INSERT INTO highlights VALUES('906847_12_3671-3780','906847',12,'译者导言','这个时代的作家注重秩序、逻辑、节制、精准、正确、雅趣、得体，主张文学艺术的实用价值，要为人服务，追求匀称、统一、和谐、优雅、明晰，避免晦涩、神秘，目的是愉悦、教导、匡正主要作为社会动物的人。它重理智，轻感情，讲究才智。','3671-3780',1,1714312868,1782480559);
INSERT INTO highlights VALUES('906847_12_3631-3671','906847',12,'译者导言','古典主义推崇古希腊罗马经典作家的创作规范，反对文艺复兴热情奔放、词藻浮华的风气。','3631-3671',1,1714312801,1782480559);
INSERT INTO highlights VALUES('906847_12_3401-3491','906847',12,'译者导言','1776年以《独立宣言》发表为标志的美国革命（我国一般称为“独立战争”）进入高潮，富兰克林是该宣言的起草委员会成员之一（《独立宣言》主要由杰斐逊起草，但经过富兰克林与亚当斯的修改）','3401-3491',1,1714312745,1782480559);
INSERT INTO highlights VALUES('906847_12_2681-2793','906847',12,'译者导言','既然宇宙按一定规律运转，那么人类社会一定也有规律可循，于是十八世纪的有识之士力图发现并运用这些规律来改良社会。由于对科学的尊重减弱了对神的尊崇，也减轻了人们对奇迹、对圣书、对国王教士的神圣不可侵犯的迷信，而更多地专注于人本身','2681-2793',1,1714312645,1782480559);
INSERT INTO highlights VALUES('906847_12_2805-2874','906847',12,'译者导言','正是在这种风气的影响下，富兰克林重视公益事业，从铺马路、清垃圾、设路灯、消防、巡夜等发展到办公共图书馆、办学校、办医院、建立民兵防御体系。','2805-2874',1,1714312640,1782480559);
INSERT INTO highlights VALUES('906847_12_2366-2421','906847',12,'译者导言','牛顿的宇宙论引起了宗教观的重大转变。牛顿的科学观并非把上帝打翻在地，而是仍然承认上帝创造了宇宙，是“第一动力”','2366-2421',1,1714312516,1782480559);
INSERT INTO highlights VALUES('906847_12_1403-1421','906847',12,'译者导言','美国有一种土生土长的哲学——实用主义','1403-1421',1,1714312364,1782480559);
INSERT INTO highlights VALUES('906847_12_1483-1532','906847',12,'译者导言','思想产生行为，行为必有效果，要研究思想的正确与否，与其从思想本身来辩论，倒不如看它行为的效果如何。','1483-1532',1,1714312359,1782480559);
INSERT INTO highlights VALUES('906847_12_1067-1188','906847',12,'译者导言','一路上也是千辛万苦，经纽约，再到费城，先从学徒工做起，靠自己的勤奋、智慧自立门户，成了成功的印刷商，于是又办报纸，又当邮政局长，从事公益事业，出任了殖民地议会议员，最后成了开国元勋之一。富兰克林乐观、宽容、积极进取的性格体现了整个民族的性格。','1067-1188',1,1714312308,1782480559);
INSERT INTO highlights VALUES('906847_12_504-531','906847',12,'译者导言','富兰克林的经历与美利坚民族的成长过程有着惊人的相似之处','504-531',1,1714312217,1782480559);
INSERT INTO highlights VALUES('3300112218_6_7894-7962','3300112218',6,'第三章 走出习惯性讨好他人的牢笼','越是活得没有自我，就越无法拥有安全感和爱，只有放弃讨好他人，勇敢做自己，才能找回自我，获得所期望的安全感和爱，这两样东西是自己给自己的。','7894-7962',0,1745626070,1782480552);
