INSERT INTO highlights VALUES('3300112218_4_9876-9932','3300112218',4,'第一章 别做被逃避裹挟的逃兵','拥有鸵鸟心态的人会让身边的亲人、朋友失望。因为他们逃避的不仅仅是自己认为的“危险”，还有他们身上应该承担的责任。','9876-9932',0,1745412829,1782480552);
