INSERT INTO highlights VALUES('3300112218_4_5976-6034','3300112218',4,'第一章 别做被逃避裹挟的逃兵','习惯性逃避的人会轻易被困难打倒，还自我安慰地说自己喜欢“摆烂”“躺平”，将自己“缩在套子里”，以致错失许多人生经历。','5976-6034',0,1745375680,1782480552);
