INSERT INTO thoughts VALUES('50873507_7P4IN2B55','3300022098',33,NULL,'一体是一种很高的境界，我很怀疑自己是否能够持续处于这种状态。如果切换为“凡人”的视角，我无私的奉献其实可能被别人利用，甚至在利益上产生很多冲突。这样，自己很有可能处于折磨之中。是否意味着，在无私奉献之前，需要确定自己真的具备了一体的条件？',NULL,'6556-6637',0,1708251319,1782480561);
