INSERT INTO thoughts VALUES('50873507_7j2mId416','25615385',NULL,NULL,'非常的reader-friendly，但蕴含着深刻的思想。现代人，或许古代人也是吧，都深受人际关系、家庭、工作等等潜在或直接的问题所困扰。这本书想帮助我们解开一个个枷锁，让我们不依赖别人的喜好而获得幸福。脚踏实地地做好今天的自己，从自己为世界带来的东西中获取满足，幸福其实很简单。',100,'',0,1595425825,1782480568);
