INSERT INTO thoughts VALUES('50873507_7XQXJWJwL','29971966',54,NULL,unistr('并不是Woz命名的，参考维基百科：\u000aAccording to Wozniak, Jobs proposed the name “Apple Computer” when he had just come back from Robert Friedland''s All-One Farm in Oregon. Jobs told Walter Isaacson that he was "on one of my fruitarian diets," when he conceived of the name and thought "it sounded fun, spirited and not intimidating ... plus, it would get us ahead of Atari in the phone book."'),NULL,'2746-2760',0,1739164344,1782480553);
