INSERT INTO reading_stats VALUES(11,'annually',0,'{"readTimes":{"1767196800":27640,"1769875200":11976,"1772294400":30162,"1774972800":14025,"1777564800":24162,"1780243200":24546,"1782835200":0,"1785513600":0,"1788192000":0,"1790784000":0,"1793462400":0,"1796054400":0},"readDays":108,"readDistributionWord":"点评分布","readLongest":[{"book":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":27189,"tags":["笔记最多"]},{"book":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":16708,"tags":["单日阅读最久"]},{"book":{"bookId":"38624707","title":"拖延心理学：越拖越慌？救急指南","author":"简·博克 莱诺拉·袁","translator":"蒋永强,陆正芳","intro":"从学生到科学家，从职场新人到商界大佬，从家庭主妇到艺术家，都会受到拖延的影响。简·博克和莱诺拉·袁基于他们备受好评和具有开创性的拖延工作坊以及从众多心理咨询领域汲取的丰富理论和经验，对拖延进行了一次详尽、仔细，有时也颇为幽默的探索。在这本书中，作者找出了4个最可能导致拖延的原因：对成功信心不足、讨厌被人委派任务、注意力分散和易冲动、目标和回报太过遥远。本书通过对拖延背后深层次的原因分析和对大脑神经科学方面的研究，让我们能够重新理解拖延并明白怎样以全新的方式采取行动。本书还为我们提供了达成目标、管理时间、谋求支持和处理压力等一系列克服拖延的方法，她们提供的方案非常实用并经受过实践的检验。此外，本书还考虑到工作和生活节奏不断加快的当代文化诉求，以及诸如注意缺陷障碍、执行功能障碍等问题对拖延的影响，甚至还为生活和工作在拖延者身边的人群提供了不少实用性建议。","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/707/38624707/s_38624707.jpg","version":404678432,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":42,"maxfreeChapterRatio":45},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4789723,"publishTime":"2021-06-01 00:00:00","lastChapterIdx":34,"paperBook":{"skuId":""},"centPrice":7191,"copyrightChapterUids":[35],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":16377,"tags":[]},{"book":{"bookId":"3300064086","title":"与塞涅卡共进早餐：斯多葛哲学的人生艺术","author":"大卫·菲德勒","translator":"谭新木 王蕾","intro":"当人生陷入困境，不妨问一句：哲学家塞涅卡会怎么做？\n如何处理和时间的关系\n如何克服担忧和焦虑\n如何战胜困境\n如何在困难和极端财富中生存\n如何保持真实并为社会做贡献\n给悲伤留一席之地 \n斯多葛主义是两千多年前古罗马时期最有影响力的哲学。斯多葛哲学崇尚理性，注重培养人的内在品格，以应对外部世界的不确定性。古罗马政治家、哲学家塞涅卡被认为是斯多葛学派最有才华、最人性化的作家，他教导人们自由而有目的地生活。他历久弥新的作品，是一百多封写给朋友的书信《斯多葛主义者来信》，阐述了如何应对逆境，如何克服悲伤、焦虑和愤怒，如何将挫折转化为成长机会，如何认识友谊的真正本质等重要人生议题。\n《与塞涅卡共进早餐》是第一本介绍塞涅卡哲学思想全貌的指南。在这本书中，大卫·菲德勒结合当代人的生活，深入阐释了塞涅卡的哲学思想对当下人生的重要指导作用。事实证明，在过去的两千多年里，人类本性并没有发生太大变化，针对我们今天面临的各种人生困境，斯多葛哲学依然能提供历经时间考验的实用建议。塞涅卡的哲学智慧并非遥不可及，它像每天早晨一杯提神的咖啡，可以融入生活作为一种日常仪式去享受。\n我为后代工作，写下一些可能对他们有益的想法。有一些健康的建议，此刻我正在把它们写下来，就像开处方列出有用的药……我正在为其他人指出正确的道路，它们是我因误入歧途而在晚年感到疲惫时才发现的。\n——【古罗马】塞涅卡\n塞涅卡的时代就是我们的时代。他是我们的同时代人，我们关切着同样的问题。\n——大卫·菲德勒","cover":"https://cdn.weread.qq.com/weread/cover/38/cpplatform_hixys3ymuudfmfkqvn6ata/s_cpplatform_hixys3ymuudfmfkqvn6ata1689243634.jpg","version":90724064,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":28},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":16030821,"publishTime":"2022-11-01 00:00:00","lastChapterIdx":21,"paperBook":{"skuId":""},"centPrice":5280,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":12230,"tags":[]},{"book":{"bookId":"25449864","title":"人人都懂设计模式：从生活中领悟设计模式（Python实现）","author":"罗伟富","intro":"设计模式（Design Pattern）是一套被反复使用、多数人知晓、无数工程师实践的代码设计经验的总结，它是面向对象思想的高度提炼和模板化。 本书带你一起从生活的角度思考设计模式，以轻松有趣的小故事开始，由浅入深地讲解每一种模式，思考每一种模式，总结每一种模式！力求用更通俗的语言阐述难懂的概念，用更简单的语法实现复杂的逻辑，用更短小的代码写出强悍的程序！ 使枯燥乏味的概念变得更有乐趣和意义，希望能带给读者一种全新的阅读体验和思考方式。 本书首先讲解了23种经典设计模式，其中19 种在现今的软件开发中常用的设计模式分别用单独的章节进行了详细讲解，剩余设计模式作为一个合集放在一章中进行了讲解；其次讲解了对基础设计模式的衍生，也是各大编程语言中非常重要而常见的各种编程机制，如过滤器模式、对象池技术、回调机制和MVC模式；最后作者结合自身的工作经验和项目积累，分享了他对设计模式、设计原则、项目重构的理解和看法。Python作为AI时代最重要的一种计算机语言，其在各大语言中的排名也逐年上升！本书所有示例代码均用Python编写，将会是国内不可多得的一本用Python来讲解设计模式的书。 本书适合的读者：一线互联网软件开发者、有一定编程基础的IT新人、对设计模式和编程思想感兴趣的人士。","cover":"https://cdn.weread.qq.com/weread/cover/68/YueWen_25449864/s_YueWen_25449864.jpg","version":176403712,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":59},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":48492,"publishTime":"2019-04-01 00:00:00","lastChapterIdx":36,"paperBook":{"skuId":""},"centPrice":5530,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":11310,"tags":[]},{"book":{"bookId":"3300200681","title":"Claude Code 源码解析：一份价值数十亿美元的AI工程蓝图","author":"花叔","intro":"2026年3月，Anthropic不小心把Claude Code的全部源码打包进了npm发布包。1902个TypeScript文件，51万行代码，所有设计决策一览无余。\n这本书不是教你怎么用Claude Code。市面上那本「从入门到精通」橙皮书已经做了这件事。\n这本书带你看发动机。\nClaude Code为什么好用？60%靠模型能力，40%靠围绕模型搭建的工程系统。这个系统叫harness。它包括一套精心拼装的system prompt、一个用第二AI做安全审查的四层权限系统、一个只记偏好不记代码的记忆系统、一套9段式结构化上下文压缩、以及一个像真实公司一样运转的多Agent协作框架。\n12个章节，从架构全景到方法论提炼。每章的结构是：这个系统做什么、源码里怎么实现的、为什么这么设计、你能学到什么。\n不逐行读代码。讲的是设计决策背后的Why。这些Why比代码本身更有价值，因为它们是可迁移的。不管你用什么语言、什么框架，这些设计思路都能直接借鉴。\n适合想做AI产品/AI Agent的开发者、产品经理，以及想理解底层原理的Claude Code重度用户。","cover":"https://cdn.weread.qq.com/weread/cover/70/cpplatform_9mpam2z9cb1hosnt1pjdvg/s_cpplatform_9mpam2z9cb1hosnt1pjdvg1775647383.jpg","version":893387428,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":5,"maxFreeInfo":{"maxfreeChapterIdx":5,"maxfreeChapterUid":20,"maxfreeChapterRatio":52},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2026-04-10 00:00:00","lastChapterIdx":16,"paperBook":{"skuId":""},"centPrice":2400,"copyrightChapterUids":[17],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":7223,"tags":[]},{"book":{"bookId":"3300116432","title":"重塑杏仁核：情绪修复脑科学","author":"[美]凯瑟琳·M. 皮特曼","translator":"王羽青 黄金德","intro":"本书通过追溯焦虑的根源一杏仁核，探讨\n了如何有效地管理焦虑。通过设定目标、了解\n焦虑产生的两种途径、学习杏仁核的语言以及\n以睡眠、运动和饮食等方式调节杏仁核的活\n动，读者可以学会控制焦虑。此外，书中还介\n绍了如何通过暴露疗法训练杏仁核，以及识别\n那些可能激活杏仁核的想法。重新训练你的大\n脑，有效地管理焦虑，不仅可以提高生活质\n量，还能让我们在面对困难时更加从容，重新\n掌握生活的主导权。","cover":"https://cdn.weread.qq.com/weread/cover/75/cpplatform_f8nqyjadruqecj4euuj6jj/s_cpplatform_f8nqyjadruqecj4euuj6jj1727434091.jpg","version":605592677,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":19},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5174518,"publishTime":"2024-06-01 00:00:00","lastChapterIdx":20,"paperBook":{"skuId":""},"centPrice":4830,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":4214,"tags":[]},{"book":{"bookId":"3300153006","title":"我，刀枪不入：掌控心智、力克万难的奇迹人生","author":"[美]大卫·戈金斯","translator":"嘉嘉","intro":"从认不得几个字的底层废柴到受邀至麻省理工学院、激励数十方青少年的演讲者命运从来不是既定的轨迹，而是可以被改写的脚本!写给手握烂牌的你，抛弃受害者心态教你如何将烂牌打成王炸！\n我们每个人，都有潜力成为更了不起的人！","cover":"https://cdn.weread.qq.com/weread/cover/19/cpplatform_6vrtpk2fwnjg87asbeuini/s_cpplatform_6vrtpk2fwnjg87asbeuini1752636387.jpg","version":1433710756,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":1},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-60041,"publishTime":"2025-04-08 00:00:00","lastChapterIdx":17,"paperBook":{"skuId":""},"centPrice":6800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":2748,"tags":[]},{"book":{"bookId":"3300189789","title":"金钱的艺术","author":"[美]摩根·豪泽尔","translator":"袁希","intro":"金钱不是公式里的学问， 而是现实中的艺术。 我们习惯于把投资理财当作一门科学，却忽视了其中复杂的心理与行为，导致我们要么把钱花在并不如预期那样带来快乐的事情上，要么错过真正有价值的投资。 在这本书中，摩根·豪泽尔以深刻的见解和温暖的笔触，向我们展示了学校里并不教的金钱的艺术， 总结了与钱有关的20 个智慧。比如普通人最 强大的理财技能，是用好静默复利策略；比如最宝贵的资产是不需要取悦任何人；比如多尝试各种花钱方式，找到最适合你个性、真正能让你快乐的事情。 你对金钱的认知有多高，人生就有多自由。即使没有接受过专业金融教育，没有投资理财技巧，你也可以凭借对金钱的良好认知，最终走向富裕，让金钱为你所用。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_vwgd8cbh166b18vky3wyjg/s_cpplatform_vwgd8cbh166b18vky3wyjg1767152651.jpg","version":629031897,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":63},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2025-09-01 00:00:00","lastChapterIdx":27,"paperBook":{"skuId":""},"centPrice":4060,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":2406,"tags":[]},{"book":{"bookId":"843544","title":"别独自用餐：85%的成功来自高效的社交能力","author":"基思·法拉奇 塔尔·雷兹","translator":"前十网","intro":"彻底颠覆思考人脉的固有方式。作为克林顿和希拉里智囊团中的人脉大师，基思·法拉奇经过20年的研究发现，一个人的成功，85%归功于他的人脉关系。在其代表作《别独自用餐》中，法拉奇提出了让人终身受益的社交法则。这些法则将彻底改变人们思考人脉的固有方式，通过持续地改变生活中看似不经意的行为，从而获得更有价值的人脉关系。《别独自用餐》自2005年出版，畅销至今。此十周年修订珍藏版，增加了社交媒体时代的社交技巧，更符合当下的社交需求。","cover":"https://cdn.weread.qq.com/weread/cover/94/YueWen_843544/s_YueWen_843544.jpg","version":1997142547,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":47,"maxfreeChapterRatio":57},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":14792401,"publishTime":"2016-0