的"},{"type":4,"title":"读到深夜"},{"type":7,"title":"第一本阅读","bookInfo":{"bookId":"3300189789","title":"金钱的艺术","author":"[美]摩根·豪泽尔","translator":"袁希","intro":"金钱不是公式里的学问， 而是现实中的艺术。 我们习惯于把投资理财当作一门科学，却忽视了其中复杂的心理与行为，导致我们要么把钱花在并不如预期那样带来快乐的事情上，要么错过真正有价值的投资。 在这本书中，摩根·豪泽尔以深刻的见解和温暖的笔触，向我们展示了学校里并不教的金钱的艺术， 总结了与钱有关的20 个智慧。比如普通人最 强大的理财技能，是用好静默复利策略；比如最宝贵的资产是不需要取悦任何人；比如多尝试各种花钱方式，找到最适合你个性、真正能让你快乐的事情。 你对金钱的认知有多高，人生就有多自由。即使没有接受过专业金融教育，没有投资理财技巧，你也可以凭借对金钱的良好认知，最终走向富裕，让金钱为你所用。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_vwgd8cbh166b18vky3wyjg/s_cpplatform_vwgd8cbh166b18vky3wyjg1767152651.jpg","version":629031897,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":63},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2025-09-01 00:00:00","lastChapterIdx":27,"paperBook":{"skuId":""},"centPrice":4060,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"2026/01/03/阅读"},{"type":6,"title":"最爱哲学宗教","bookInfo":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了8小时"},{"type":2,"title":"最爱分享"},{"type":12,"title":"共读最多"},{"type":10,"title":"欣赏小众"},{"type":8,"title":"总有一天读完"}]}',1782479250);
INSERT INTO reading_stats VALUES(12,'overall',0,'{"readTimes":{"1514736000":67841,"1546272000":186223,"1577808000":47981,"1609430400":42766,"1640966400":499251,"1672502400":379386,"1704038400":480259,"1735660800":264970,"1767196800":132511},"readDays":1430,"readLongest":[{"book":{"bookId":"695233","title":"三体全集（全三册）","author":"刘慈欣","intro":"【荣获世界科幻大奖“雨果奖”长篇小说奖，约翰·坎贝尔纪念奖，银河奖特别奖。】\n每个人的书架上都该有套《三体》！关于宇宙最狂野的想象！就是它！\n征服世界的中国科幻神作！包揽九项世界顶级科幻大奖！出版16个语种，横扫30国读者！奥巴马、雷军、马化腾、周鸿祎、潘石屹、扎克伯格……强推！\n刘慈欣获得2018年度克拉克想象力贡献社会奖！\n刘慈欣是中国科幻小说的最主要代表作家，亚洲首位世界科幻大奖“雨果奖”得主，被誉为中国科幻的领军人物。","cover":"https://cdn.weread.qq.com/weread/cover/80/yuewen_695233/s_yuewen_6952331740758482.jpg","version":1687693885,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":24,"maxFreeInfo":{"maxfreeChapterIdx":24,"maxfreeChapterUid":109,"maxfreeChapterRatio":92},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":2413,"publishTime":"2022-04-01 00:00:00","lastChapterIdx":109,"paperBook":{"skuId":""},"centPrice":8999,"copyrightChapterUids":[87,91,132,149],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":114554,"tags":["单日阅读最久"]},{"book":{"bookId":"CB_4S997B96qGVz6al6YD","title":"邓小平时代","author":"傅高义","cover":"https://res.weread.qq.com/wrepub/CB_2MWC9UC9NDE46Qu6Px_parsecover","version":1320043665,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":134217761,"finished":1,"free":1,"mcardDiscount":0,"ispub":0,"cpid":0,"publishTime":"","lastChapterIdx":33,"paperBook":{"skuId":""},"centPrice":0,"copyrightChapterUids":[],"hasKeyPoint":true,"limitShareChat":0,"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":92434,"tags":[]},{"book":{"bookId":"635722","title":"史蒂夫·乔布斯传（修订版）","author":"沃尔特·艾萨克森","translator":"魏群","intro":"    史蒂夫·乔布斯有如过山车般精彩的人生和炽热激越的性格成就了一个传奇，一个极具创造力的企业领袖，他追求完美和誓不罢休的激情使个人电脑、动画电影、音乐、手机、平板电脑以及数字出版等六大产业发生了颠覆性变革。2011年，《史蒂夫·乔布斯传》出版；在两年后的今天，我们又推出了修订版。在原有《乔布斯传》的基础上，修订了全部译文，采纳了读者对翻译的众多建议，使得整体译文更加完善，更加精良。此外，修订版一大亮点是新增补作者亲自撰写的后记，描述了乔布斯去世后的相关过程，包括葬礼等，对读者有新的吸引点，也更完美了此部经典著作。\n","cover":"https://cdn.weread.qq.com/weread/cover/39/YueWen_635722/s_YueWen_635722.jpg","version":1823127837,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":60,"maxfreeChapterRatio":52},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2014-03-01 00:00:00","lastChapterIdx":53,"paperBook":{"skuId":""},"centPrice":4070,"copyrightChapterUids":[53],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":83871,"tags":["笔记最多"]},{"book":{"bookId":"CB_5ep7mx7jk2bn6jn6kg8w54br","title":"埃隆·马斯克传","author":"【美】沃尔特·艾萨克森","cover":"https://res.weread.qq.com/wrepub/CB_1Pi80U81ABef6j76khDGtD5I_parsecover","version":1405063993,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":134217761,"finished":1,"free":1,"mcardDiscount":0,"ispub":0,"cpid":0,"publishTime":"","lastChapterIdx":99,"paperBook":{"skuId":""},"centPrice":0,"copyrightChapterUids":[],"hasKeyPoint":true,"limitShareChat":0,"inStoreBookId":"3300070929","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":53115,"tags":[]},{"book":{"bookId":"42689053","title":"原则：应对变化中的世界秩序","author":"瑞·达利欧","translator":"崔苹苹,刘波","intro":"自然界的发展是有规律的，而任何事物都按其固有的轨迹运行。人们能够用一定的方法去认识它、体验它、并按照客观规律改造它。从《原则》《债务危机》到《原则：应对变化中的世界秩序》，桥水投资公司创始人瑞·达利欧的研究角度涉及个体、组织、社会和世界。他想揭示的是个体的生活和工作原则、组织机构的运转原则、国家和社会的兴衰原则、世界秩序的变化原则。在这本书中，瑞·达利欧探究的是社会和世界的运行规律和原则，他考察了500年财富和权力的所有重大变化背后反复出现的模式和因果关系。他认为在这些变化背后存在着永恒普适的规律。通过考察许多相互关联的历史事件，可以看到这些变化的典型模式、规律、周期和因果关系，并以此为基础推断未来。达利欧认为，历史通常也是通过相对明确的生命周期、随着一代人向下一代人的过渡而逐步演进的。目前相对财富、权力和世界秩序正在发生典型的巨变，这将对所有国家的每个人都产生深远的影响……这本书的分析和探究建立在达利欧独创的债务大周期、历史大周期的基础之上，揭示的是变化背后的永恒和普遍的力量，以此展望未来，搞清世界的运行原理，总结出永恒普适的原则，从而妥善地应对当前形势。","cover":"https://cdn.weread.qq.com/weread/cover/53/YueWen_42689053/s_YueWen_42689053.jpg","version":1425727528,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":33,"maxfreeChapterRatio":90},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2022-01-01 00:00:00","lastChapterIdx":26,"paperBook":{"skuId":""},"centPrice":13500,"copyrightChapterUids":[27],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":51767,"tags":[]},{"book":{"bookId":"852290","title":"未来简史：从智人到智神","author":"尤瓦尔·赫拉利","translator":"林俊宏","intro":"进入21世纪后，曾经长期威胁人类生存、发展的饥荒和战争基本被攻克，智人面临着新的待办议题：永生不老、幸福快乐和成为具有“神性”的人类。在解决这些新问题的过程中，科学技术的发展将颠覆我们很多当下认为无需佐证的“常识”，比如人文主义所推崇的自由意志将面临严峻挑战，机器将会代替人类做出更明智的选择。 更重要的，当以大数据、人工智能为代表的科学技术发展的日益成熟，人类将面临着从进化到智人以来*的一次改变，绝大部分人将沦为“无价值的群体”，只有少部分人能进化成特质发生改变的“神人”。 未来，人类将面临着三大问题：生物本身就是算法，生命是不断处理数据的过程；意识与智能的分离；拥有大数据积累的外部环境将比我们自己更了解自己。如何看待这三大问题，以及如何采取应对措施，将直接影响着人类未来的发展。","cover":"https://cdn.weread.qq.com/weread/cover/44/YueWen_852290/s_YueWen_852290.jpg","version":771716074,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":23,"maxfreeChapterRatio":56},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2017-01-10 00:00:00","lastChapterIdx":21,"paperBook":{"skuId":""},"centPrice":4080,"copyrightChapterUids":[19],"inStoreBookId":"","blockSaveImg":0,"language":"zh-CN","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":41421,"tags":[]},{"book":{"bookId":"651358","title":"中国哲学简史","author":"冯友兰","intro":"《中国哲学简史》打通古今中外的相关知识，以宏观开阔的视野对中国哲学进行了深入浅出的、融会贯通的讲解。在有限的篇幅里融入了对中国传统思想、文化、精神、智慧等方面的理解，融会了史与思的智慧结晶，洋溢着人生的智慧与哲人的洞见，寄托着现实的人生关怀。它在世界各地有多种译本，拥有众多的读者，是许多大学中国哲学的通用教材；同样，它也是广大读者学习中国古代文化、借鉴中国传统智慧、启迪现实人生的入门书。它是一部名副其实的可以影响大众一生的文化经典。本书是北京大学出版社独家拥有版权的冯友兰先生亲自指导翻译并认可的唯一版本。","cover":"https://cdn.weread.qq.com/weread/cover/24/YueWen_651358/s_YueWen_651358.jpg","version":6867716,"format":"epub","type":0,"soldout":1,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":35,"maxfreeChapterRatio":31},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":0,"publishTime":"2013-01-01 00:00:00","lastChapterIdx":31,"paperBook":{"skuId":""},"centPrice":2899,"copyrightChapterUids":[31],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":true,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":40411,"tags":[]},{"book":{"bookId":"3300039741","title":"高效的无效：行家如何投资与市场如何定价","author":"拉瑟·海耶·佩德森","translator":"卢旸 余方","intro":"本书描述了对冲基金的关键交易策略，揭开了主动型投资的神秘面纱。作者将最新的研究成果与现实世界的经典案例以及对顶级对冲基金经理的采访相结合，展示了某些交易策略是如何盈利的，以及为什么有时会亏损。 作者认为市场既非完全高效，也非完全无效，相反，市场的无效足以让基金经理通过交易策略获取利润来补偿其成本，而市场的高效带来的利润不会鼓励额外的积极投资。了解如何在低效的市场中进行交易，为学习金融学提供了一种新的、引人入胜的方法。 本书深入探讨了几个不同的领域：投资管理的基本工具、股票投资策略、宏观投资策略和套利策略，并研究了投资组合选择、风险管理、股票估值和收益曲线逻辑等不同的主题。书中通过对知名对冲基金经理的采访进一步阐释了各类投资方法，他们包括李·安斯利三世、詹姆斯·查诺斯、克利夫·阿斯尼斯、戴维·哈丁、肯·格里芬、戴维·哈丁、约翰·A.保尔森、迈伦·斯科尔斯和乔治·索罗斯。","cover":"https://cdn.weread.qq.com/weread/cover/96/cpPlatform_wYodV7Yd3Fhnvjh5h6Hd2h/s_cpPlatform_wYodV7Yd3Fhnvjh5h6Hd2h.jpg","version":876999449,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":13,"maxFreeInfo":{"maxfreeChapterIdx":13,"maxfreeChapterUid":13,"maxfreeChapterRatio":28},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3382183,"publishTime":"2021-05-31 00:00:00","lastChapterIdx":117,"paperBook":{"skuId":""},"centPrice":6480,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":36738,"tags":[]},{"book":{"bookId":"3300022098","title":"聪明人的个人成长","author":"史蒂夫·帕弗利纳","translator":"一炜","intro":"本书作者史蒂夫是全球个人成长领域的知名导师，在全球150多个国家及地区拥有读者。本书第一部分介绍个人成长的七个原则，分别是：真实、爱、能量、一体、主导、勇气、清醒自主。在本书第二部分，介绍如何将这七个原则运用在生活中的各个方面，包括习惯、职业、金钱、健康、关系以及心灵。本书不仅让你拥有成长的系统理论，还带你切实解决人生遇到的很多重大问题。","cover":"https://cdn.weread.qq.com/weread/cover/98/3300022098/s_3300022098.jpg","version":1571802152,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":30,"maxfreeChapterRatio":50},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4157477,"publishTime":"2022-05-01 00:00:00","lastChapterIdx":25,"paperBook":{"skuId":""},"centPrice":4140,"copyrightChapterUids":[23],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":36208,"tags":[]},{"book":{"bookId":"23934823","title":"非对称风险","author":"纳西姆·尼古拉斯·塔勒布","translator":"周洛华","intro":"约3800年前，《汉谟拉比法典》就向我们传达出一条人类进化的法则——在人与人的交往中建立对称关系，以防止有人转嫁隐藏的“尾部风险”。古往今来，人类的任何一条法律、任何一项教谕，也都是基于“对称性”原则的，但实际上，非对称风险也一直存在于人类历史之中。塔勒布提出，人们在面对非对称风险和外部压力时，只有践行“风险共担”的原则，才能做出正确的决策，以应对现实世界中的不确定性。《非对称风险》这本书共包含四个主题：不确定性以及知识的可靠性；人类事务的对称性原则，包括公平、正义、责任感、相互性；交易中的信息共享；复杂系统中以及在现实世界中的理性。书中的内容可谓是包罗万象：主观动机分析、二手车买卖、道德伦理、契约理论、学术界以及现实世界的学习、康德法则、政府权力、风险科学、知识分子与现实世界的互动、政府责任、社会正义、期权理论、基本人权、狗屎的供应商、神学……","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/823/23934823/s_23934823.jpg","version":2130074522,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":44,"maxfreeChapterRatio":8},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2019-01-01 00:00:00","lastChapterIdx":43,"paperBook":{"skuId":""},"centPrice":4080,"copyrightChapterUids":[37],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":36177,"tags":[]}],"preferCategory":[{"categoryId":1100000,"categoryTitle":"经济理财","parentCategoryId":1100000,"parentCategoryTitle":"经济理财","readingCount":43,"readingTime":372345},{"categoryId":1000000,"categoryTitle":"个人成长","parentCategoryId":1000000,"parentCategoryTitle":"个人成长","readingCount":42,"readingTime":267863},{"categoryId":800000,"categoryTitle":"心理","parentCategoryId":800000,"parentCategoryTitle":"心理","readingCount":34,"readingTime":200857},{"categoryId":600000,"categoryTitle":"哲学宗教","parentCategoryId":600000,"parentCategoryTitle":"哲学宗教","readingCount":22,"readingTime":169671},{"categoryId":300000,"categoryTitle":"文学","parentCategoryId":300000,"parentCategoryTitle":"文学","readingCount":55,"readingTime":161800},{"categoryId":700000,"categoryTitle":"计算机","parentCategoryId":700000,"parentCategoryTitle":"计算机","readingCount":37,"readingTime":153403},{"categoryId":100012,"categoryTitle":"影视原著","parentCategoryId":100000,"parentCategoryTitle":"精品小说","readingCount":6,"readingTime":142326},{"categoryId":500000,"categoryTitle":"人物传记","parentCategoryId":