INSERT INTO reading_stats VALUES(18,'monthly',0,'{"readTimes":{"1780243200":532,"1780329600":5,"1780416000":1722,"1780502400":9180,"1780588800":502,"1780675200":732,"1780761600":250,"1780848000":206,"1780934400":455,"1781020800":529,"1781107200":649,"1781193600":643,"1781366400":505,"1781452800":1067,"1781539200":3165,"1781625600":83,"1781712000":314,"1781798400":1685,"1781884800":265,"1781971200":1118,"1782057600":498,"1782144000":377,"1782230400":64,"1782316800":0,"1782403200":1192,"1782489600":241},"readDays":24,"readLongest":[{"book":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":16708,"tags":["笔记最多","单日阅读最久"]},{"book":{"bookId":"3300209394","title":"图解Skill：AI提效实战指南","author":"宝玉","intro":"知名 AI 应用专家宝玉结合自身实战经验，撰写了这本技能实操指南，旨在帮助读者将个人经验转化为智能体可执行的技能，摆脱“AI 工具人”困境，真正实现工作自动化。  全书遵循“先实践后沉淀”的学习路径，带你从跑通第一个技能入手，逐步构建专属的多技能 AI 自动化工作流。作者手把手教你掌握：3 个单技能模板、1 条组合式写作工作流、1 套技能工程方法论、1 次从零开始完整迭代的技能项目实战。  本书不绑定平台，扣子、Claude Code、OpenClaw 均可使用；也不要求读者具备编程基础，只要你想用 AI 提效，就可以通过本书学会技能，并立刻投入使用。","cover":"https://cdn.weread.qq.com/weread/cover/82/cpplatform_wmaghz3junjyxd2lc1jqn5/s_cpplatform_wmaghz3junjyxd2lc1jqn51780656076.jpg","version":1098618653,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":11},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5256588,"publishTime":"2026-05-01 00:00:00","lastChapterIdx":48,"paperBook":{"skuId":""},"centPrice":3990,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":2110,"tags":[]},{"book":{"bookId":"3300177663","title":"财富的真相","author":"李笑来","intro":"《财富的真相》是李笑来向大众普及财富底层逻辑的书。作者指出，财富的独一正常来源是“生产”，而材料、知识等生产资料，溯源到底层都是“时间”的衍生物。因而，时间是我们每个人终生独一的生产资料，改变对时间的观念，才能根本上重塑我们的财富观，避免贱卖我们的时间，而是把时间花费在有复利效应的工作上。每天进步一点点，时间会帮你实现指数级的增长。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_dvldwkuhkesnhvbgpxcgdx/s_cpplatform_dvldwkuhkesnhvbgpxcgdx1763434911.jpg","version":48052399,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":43},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2023-12-01 00:00:00","lastChapterIdx":38,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1450,"tags":[]},{"book":{"bookId":"3300202721","title":"县乡生活：一场生活方式的巨变","author":"吕德文 胡晓映","intro":"中国正处于前所未有的城乡融合发展过程中，一种新型的城乡社会形态初见雏形。人们践行新生活方式，穿梭于乡土社会和都市社会两个生活系统中。新生活方式形成的同时，生活危机也在蔓延。 本书分“过日子”“流动生活““消费变迁”“婚难时代”“小镇青年”“老龄社会”六部分展开，细致描画县乡生活的新景象：数字生活兴起，单身现象增多，家庭观念变迁，老人自养秩序形成，伪中产生活陷阱频现。 本书以多位青年学者在全国各地的田野调查为基础，他们以细腻的情感、真实的笔触描写县乡生活的诸多细节，展现当代中国基层社会的真实图景。","cover":"https://cdn.weread.qq.com/weread/cover/43/cpplatform_gc31hydswgglcwoja8aak6/s_cpplatform_gc31hydswgglcwoja8aak61776935176.jpg","version":1210456338,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":78},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3382183,"publishTime":"2026-03-15 00:00:00","lastChapterIdx":47,"paperBook":{"skuId":""},"centPrice":4140,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1230,"tags":[]},{"book":{"bookId":"3300149579","title":"那些我希望自己二十出头就能明白的事","author":"弗兰克扬","intro":"给20-30岁年轻人的避坑指南。当你纠结“应届生身份有多重要？”“月薪一万要牺牲多少生活？”时，这本书用28个真实案例给你答案：教你用排除法筛选职业方向、拆穿职场四十万定律谎言、识破跳槽涨薪的隐形代价。作者以十年职场观察，直击“五千块工资困局”“学历贬值真相”“兴趣与职业的悖论”等扎心现实，给出“坑专业自救四步法”“对抗信息茧房实操指南”。没有鸡汤，只有血淋淋的规则拆解，如同过来人递给你一张避坑地图，告诉你哪些弯路不必走，哪些代价付不起。\n*同名纸书《那些我希望自己二十出头就能明白的事》已出版！","cover":"https://cdn.weread.qq.com/weread/cover/27/cpplatform_ojnqd7ae7wj86lgpakgt2m/s_cpplatform_ojnqd7ae7wj86lgpakgt2m1750325884.jpg","version":175200107,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":8,"maxfreeChapterRatio":66},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2025-06-24 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":3900,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1172,"tags":[]},{"book":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":639,"tags":[]},{"book":{"bookId":"3300206286","title":"以日为镜：经济下行期穿越指南","author":"王熙威","intro":"当经济增速放缓成为新常态，普通人如何守住生活底线、找到新的出路？关心自身财务安全、职业前景、婚姻关系、养老规划的普通人必读！\n作者王熙威，北大本科、东京大学硕士，近二十年深耕日本社会肌理。本书不写宏大叙事，只讲真实故事：泡沫破裂后买房套牢的渡边一家、从东大精英到网吧难民的田中、在废墟上开面包店的高桥……三十余个普通人的命运切片，还原日本“失去的三十年”的社会细节和心态变化。\n这不是一本预言未来的书，而是一面镜子——照见日本踩过的坑、走过的弯路，以及普通人在结构转型中咬牙支撑的韧性。当“内卷”“躺平”“消费降级”成为日常热词，转过头看看这面镜子，或许能获得一点面对当下生活的底气与启发。","cover":"https://cdn.weread.qq.com/weread/cover/64/cpplatform_psum2ddry7rjbeqdfztjjz/s_cpplatform_psum2ddry7rjbeqdfztjjz1779186519.jpg","version":2075593703,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":13,"maxFreeInfo":{"maxfreeChapterIdx":13,"maxfreeChapterUid":13,"maxfreeChapterRatio":6},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2026-05-21 00:00:00","lastChapterIdx":64,"paperBook":{"skuId":""},"centPrice":6200,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":403,"tags":[]},{"book":{"bookId":"3300207566","title":"十倍速开发：AI时代的Cursor编程手记","author":"王尧","intro":"本书是基于 Web 的博客系统 BlogN 的开发过程，采用人与 AI 工具对话的形式，记录 AI 辅助编程工具 Cursor 在实际项目开发中的应用过程。书中不仅展示 AI 工具在技术决策、代码生成和问题解决及优化方面的强大能力，还深入探讨 AI 工具的特性、最佳实践及 AI 技术对传统编程的冲击。通过具体的案例，本书揭示 AI 工具在编程中的优势，如快速生成高质量代码、处理复杂逻辑等，同时也指出其局限性，如对复杂问题理解不足、可能出现错误和幻觉问题等，还示范如何通过自然语言指令驱动 AI 工具完成任务，如何对生成的代码进行审查和优化，以及在 AI 工具失效时如何及时介入并解决问题。这些内容将为读者传达最新的 AI 辅助编程理念并提供宝贵的实战经验，帮助读者理解如何在实际开发中合理利用 AI 工具，提升开发效率。 全书共 15 章，详细描述从项目规划、技术选型、开发环境搭建，到各个功能模块的实现及最终的性能优化和测试的全过程，不仅涵盖后端服务的搭建、数据库设计与优化，还涉及前端界面的开发和用户体验的提升，全面展示与传统编程过程不同的人与 AI 工具协同的开发方式。 本书面向有经验的软件开发者，尤其是那些希望在 AI 时代提升开发效率、掌握新开发方法的专业人士。无论是在个人项目中寻求高效开发，还是在大型团队中探索新的协作模式，本书都能为读者提供实用的指导和启发。","cover":"https://cdn.weread.qq.com/weread/cover/17/cpplatform_cbrgew9mucjtgqv6b9wj3c/s_cpplatform_cbrgew9mucjtgqv6b9wj3c1779955090.jpg","version":177622253,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":25,"maxFreeInfo":{"maxfreeChapterIdx":25,"maxfreeChapterUid":25,"maxfreeChapterRatio":53},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5256588,"publishTime":"2026-04-01 00:00:00","lastChapterIdx":106,"paperBook":{"skuId":""},"centPrice":5747,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":383,"tags":[]}],"preferCategory":[{"categoryId":1000000,"categoryTitle":"个人成长","parentCategoryId":1000000,"parentCategoryTitle":"个人成长","readingCount":2,"readingTime":17884},{"categoryId":1500000,"categoryTitle":"科学技术","parentCategoryId":1500000,"parentCategoryTitle":"科学技术","readingCount":1,"readingTime":2110},{"categoryId":1100000,"categoryTitle":"经济理财","parentCategoryId":1100000,"parentCategoryTitle":"经济理财","readingCount":2,"readingTime":1623},{"categoryId":900000,"categoryTitle":"社会文化","parentCategoryId":900000,"parentCategoryTitle":"社会文化","readingCount":1,"readingTime":1230},{"categoryId":600000,"categoryTitle":"哲学宗教","parentCategoryId":600000,"parentCategoryTitle":"哲学宗教","readingCount":1,"readingTime":646},{"categoryId":700000,"categoryTitle":"计算机","parentCategoryId":700000,"parentCategoryTitle":"计算机","readingCount":1,"readingTime":383},{"categoryId":200000,"categoryTitle":"历史","parentCategoryId":200000,"parentCategoryTitle":"历史","readingCount":0,"readingTime":0},{"categoryId":300000,"categoryTitle":"文学","parentCategoryId":300000,"parentCategoryTitle":"文学","readingCount":0,"readingTime":0}],"preferCategoryWord":"偏好阅读个人成长","readStat":[{"stat":"读过","counts":"8本"},{"stat":"读完","counts":"1本"},{"stat":"阅读","counts":"24天"},{"stat":"笔记","counts":"70条"}],"registTime":1516801194,"readRate":70,"wrReadTime":18393,"wrListenTime":7586,"compare":0.2344897252189696,"dayAverageReadTime":962,"baseTime":1780243200,"totalReadTime":25979,"readDistributionWord":"点评分布","preferBooks":[{"type":13,"title":"我的最爱"},{"type":1,"title":"近期偏爱"},{"type":0,"title":"常读常新"},{"type":5,"title":"思考最多","bookInfo":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"笔记最多"},{"type":3,"title":"最沉浸的"},{"type":4,"title":"读到深夜"},{"type":7,"title":"第一本阅读","bookInfo":{"bookId":"3300206286","title":"以日为镜：经济下行期穿越指南","author":"王熙威","intro":"当经济增速放缓成为新常态，普通人如何守住生活底线、找到新的出路？关心自身财务安全、职业前景、婚姻关系、养老规划的普通人必读！\n作者王熙威，北大本科、东京大学硕士，近二十年深耕日本社会肌理。本书不写宏大叙事，只讲真实故事：泡沫破裂后买房套牢的渡边一家、从东大精英到网吧难民的田中、在废墟上开面包店的高桥……三十余个普通人的命运切片，还原日本“失去的三十年”的社会细节和心态变化。\n这不是一本预言未来的书，而是一面镜子——照见日本踩过的坑、走过的弯路，以及普通人在结构转型中咬牙支撑的韧性。当“内卷”“躺平”“消费降级”成为日常热词，转过头看看这面镜子，或许能获得一点面对当下生活的底气与启发。","cover":"https://cdn.weread.qq.com/weread/cover/64/cpplatform_psum2ddry7rjbeqdfztjjz/s_cpplatform_psum2ddry7rjbeqdfztjjz1779186519.jpg","version":2075593703,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":13,"maxFreeInfo":{"maxfreeChapterIdx":13,"maxfreeChapterUid":13,"maxfreeChapterRatio":6},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2026-05-21 00:00:00","lastChapterIdx":64,"paperBook":{"skuId":""},"centPrice":6200,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"2026/06/01/阅读"},{"type":6,"title":"最爱个人成长","bookInfo":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了4小时"},{"type":2,"title":"最爱分享"},{"type":12,"title":"共读最多"},{"type":10,"title":"欣赏小众"},{"type":8,"title":"总有一天读完"}],"readRecordsWord":"书籍分布"}',1782529842);
INSERT INTO reading_stats VALUES(19,'annually',0,'{"readTimes":{"1767196800":27640,"1769875200":11976,"1772294400":30162,"1774972800":14025,"1777564800":24162,"1780243200":25979,"1782835200":0,"1785513600":0,"1788192000":0,"1790784000":0,"1793462400":0,"1796054400":0},"readDays":110,"readDistributionWord":"点评分布","readLongest":[{"book":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":27189,"tags":["笔记最多"]},{"book":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":16708,"tags":["单日阅读最久"]},{"book":{"bookId":"38624707","title":"拖延心理学：越拖越慌？救急指南","author":"简·博克 莱诺拉·袁","translator":"蒋永强,陆正芳","intro":"从学生到科学家，从职场新人到商界大佬，从家庭主妇到艺术家，都会受到拖延的影响。简·博克和莱诺拉·袁基于他们备受好评和具有开创性的拖延工作坊以及从众多心理咨询领域汲取的丰富理论和经验，对拖延进行了一次详尽、仔细，有时也颇为幽默的探索。在这本书中，作者找出了4个最可能导致拖延的原因：对成功信心不足、讨厌被人委派任务、注意力分散和易冲动、目标和回报太过遥远。本书通过对拖延背后深层次的原因分析和对大脑神经科学方面的研究，让我们能够重新理解拖延并明白怎样以全新的方式采取行动。本书还为我们提供了达成目标、管理时间、谋求支持和处理压力等一系列克服拖延的方法，她们提供的方案非常实用并经受过实践的检验。此外，本书还考虑到工作和生活节奏不断加快的当代文化诉求，以及诸如注意缺陷障碍、执行功能障碍等问题对拖延的影响，甚至还为生活和工作在拖延者身边的人群提供了不少实用性建议。","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/707/38624707/s_38624707.jpg","version":404678432,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":9,"maxFreeInfo":{"maxfreeChapterIdx":9,"maxfreeChapterUid":42,"maxfreeChapterRatio":45},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4789723,"publishTime":"2021-06-01 00:00:00","lastChapterIdx":34,"paperBook":{"skuId":""},"centPrice":7191,"copyrightChapterUids":[35],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":16377,"tags":[]},{"book":{"bookId":"3300064086","title":"与塞涅卡共进早餐：斯多葛哲学的人生艺术","author":"大卫·菲德勒","translator":"谭新木 王蕾","intro":"当人生陷入困境，不妨问一句：哲学家塞涅卡会怎么做？\n如何处理和时间的关系\n如何克服担忧和焦虑\n如何战胜困境\n如何在困难和极端财富中生存\n如何保持真实并为社会做贡献\n给悲伤留一席之地 \n斯多葛主义是两千多年前古罗马时期最有影响力的哲学。斯多葛哲学崇尚理性，注重培养人的内在品格，以应对外部世界的不确定性。古罗马政治家、哲学家塞涅卡被认为是斯多葛学派最有才华、最人性化的作家，他教导人们自由而有目的地生活。他历久弥新的作品，是一百多封写给朋友的书信《斯多葛主义者来信》，阐述了如何应对逆境，如何克服悲伤、焦虑和愤怒，如何将挫折转化为成长机会，如何认识友谊的真正本质等重要人生议题。\n《与塞涅卡共进早餐》是第一本介绍塞涅卡哲学思想全貌的指南。在这本书中，大卫·菲德勒结合当代人的生活，深入阐释了塞涅卡的哲学思想对当下人生的重要指导作用。事实证明，在过去的两千多年里，人类本性并没有发生太大变化，针对我们今天面临的各种人生困境，斯多葛哲学依然能提供历经时间考验的实用建议。塞涅卡的哲学智慧并非遥不可及，它像每天早晨一杯提神的咖啡，可以融入生活作为一种日常仪式去享受。\n我为后代工作，写下一些可能对他们有益的想法。有一些健康的建议，此刻我正在把它们写下来，就像开处方列出有用的药……我正在为其他人指出正确的道路，它们是我因误入歧途而在晚年感到疲惫时才发现的。\n——【古罗马】塞涅卡\n塞涅卡的时代就是我们的时代。他是我们的同时代人，我们关切着同样的问题。\n——大卫·菲德勒","cover":"https://cdn.weread.qq.com/weread/cover/38/cpplatform_hixys3ymuudfmfkqvn6ata/s_cpplatform_hixys3ymuudfmfkqvn6ata1689243634.jpg","version":90724064,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":28},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":16030821,"publishTime":"2022-11-01 00:00:00","lastChapterIdx":21,"paperBook":{"skuId":""},"centPrice":5280,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":12230,"tags":[]},{"book":{"bookId":"25449864","title":"人人都懂设计模式：从生活中领悟设计模式（Python实现）","author":"罗伟富","intro":"设计模式（Design Pattern）是一套被反复使用、多数人知晓、无数工程师实践的代码设计经验的总结，它是面向对象思想的高度提炼和模板化。 本书带你一起从生活的角度思考设计模式，以轻松有趣的小故事开始，由浅入深地讲解每一种模式，思考每一种模式，总结每一种模式！力求用更通俗的语言阐述难懂的概念，用更简单的语法实现复杂的逻辑，用更短小的代码写出强悍的程序！ 使枯燥乏味的概念变得更有乐趣和意义，希望能带给读者一种全新的阅读体验和思考方式。 本书首先讲解了23种经典设计模式，其中19 种在现今的软件开发中常用的设计模式分别用单独的章节进行了详细讲解，剩余设计模式作为一个合集放在一章中进行了讲解；其次讲解了对基础设计模式的衍生，也是各大编程语言中非常重要而常见的各种编程机制，如过滤器模式、对象池技术、回调机制和MVC模式；最后作者结合自身的工作经验和项目积累，分享了他对设计模式、设计原则、项目重构的理解和看法。Python作为AI时代最重要的一种计算机语言，其在各大语言中的排名也逐年上升！本书所有示例代码均用Python编写，将会是国内不可多得的一本用Python来讲解设计模式的书。 本书适合的读者：一线互联网软件开发者、有一定编程基础的IT新人、对设计模式和编程思想感兴趣的人士。","cover":"https://cdn.weread.qq.com/weread/cover/68/YueWen_25449864/s_YueWen_25449864.jpg","version":176403712,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":59},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":48492,"publishTime":"2019-04-01 00:00:00","lastChapterIdx":36,"paperBook":{"skuId":""},"centPrice":5530,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":11310,"tags":[]},{"book":{"bookId":"3300200681","title":"Claude Code 源码解析：一份价值数十亿美元的AI工程蓝图","author":"花叔","intro":"2026年3月，Anthropic不小心把Claude Code的全部源码打包进了npm发布包。1902个TypeScript文件，51万行代码，所有设计决策一览无余。\n这本书不是教你怎么用Claude Code。市面上那本「从入门到精通」橙皮书已经做了这件事。\n这本书带你看发动机。\nClaude Code为什么好用？60%靠模型能力，40%靠围绕模型搭建的工程系统。这个系统叫harness。它包括一套精心拼装的system prompt、一个用第二AI做安全审查的四层权限系统、一个只记偏好不记代码的记忆系统、一套9段式结构化上下文压缩、以及一个像真实公司一样运转的多Agent协作框架。\n12个章节，从架构全景到方法论提炼。每章的结构是：这个系统做什么、源码里怎么实现的、为什么这么设计、你能学到什么。\n不逐行读代码。讲的是设计决策背后的Why。这些Why比代码本身更有价值，因为它们是可迁移的。不管你用什么语言、什么框架，这些设计思路都能直接借鉴。\n适合想做AI产品/AI Agent的开发者、产品经理，以及想理解底层原理的Claude Code重度用户。","cover":"https://cdn.weread.qq.com/weread/cover/70/cpplatform_9mpam2z9cb1hosnt1pjdvg/s_cpplatform_9mpam2z9cb1hosnt1pjdvg1775647383.jpg","version":893387428,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":5,"maxFreeInfo":{"maxfreeChapterIdx":5,"maxfreeChapterUid":20,"maxfreeChapterRatio":52},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2026-04-10 00:00:00","lastChapterIdx":16,"paperBook":{"skuId":""},"centPrice":2400,"copyrightChapterUids":[17],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":7223,"tags":[]},{"book":{"bookId":"3300116432","title":"重塑杏仁核：情绪修复脑科学","author":"[美]凯瑟琳·M. 皮特曼","translator":"王羽青 黄金德","intro":"本书通过追溯焦虑的根源一杏仁核，探讨\n了如何有效地管理焦虑。通过设定目标、了解\n焦虑产生的两种途径、学习杏仁核的语言以及\n以睡眠、运动和饮食等方式调节杏仁核的活\n动，读者可以学会控制焦虑。此外，书中还介\n绍了如何通过暴露疗法训练杏仁核，以及识别\n那些可能激活杏仁核的想法。重新训练你的大\n脑，有效地管理焦虑，不仅可以提高生活质\n量，还能让我们在面对困难时更加从容，重新\n掌握生活的主导权。","cover":"https://cdn.weread.qq.com/weread/cover/75/cpplatform_f8nqyjadruqecj4euuj6jj/s_cpplatform_f8nqyjadruqecj4euuj6jj1727434091.jpg","version":605592677,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":19},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5174518,"publishTime":"2024-06-01 00:00:00","lastChapterIdx":20,"paperBook":{"skuId":""},"centPrice":4830,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":4214,"tags":[]},{"book":{"bookId":"3300153006","title":"我，刀枪不入：掌控心智、力克万难的奇迹人生","author":"[美]大卫·戈金斯","translator":"嘉嘉","intro":"从认不得几个字的底层废柴到受邀至麻省理工学院、激励数十方青少年的演讲者命运从来不是既定的轨迹，而是可以被改写的脚本!写给手握烂牌的你，抛弃受害者心态教你如何将烂牌打成王炸！\n我们每个人，都有潜力成为更了不起的人！","cover":"https://cdn.weread.qq.com/weread/cover/19/cpplatform_6vrtpk2fwnjg87asbeuini/s_cpplatform_6vrtpk2fwnjg87asbeuini1752636387.jpg","version":1433710756,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":1},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-60041,"publishTime":"2025-04-08 00:00:00","lastChapterIdx":17,"paperBook":{"skuId":""},"centPrice":6800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":2748,"tags":[]},{"book":{"bookId":"3300189789","title":"金钱的艺术","author":"[美]摩根·豪泽尔","translator":"袁希","intro":"金钱不是公式里的学问， 而是现实中的艺术。 我们习惯于把投资理财当作一门科学，却忽视了其中复杂的心理与行为，导致我们要么把钱花在并不如预期那样带来快乐的事情上，要么错过真正有价值的投资。 在这本书中，摩根·豪泽尔以深刻的见解和温暖的笔触，向我们展示了学校里并不教的金钱的艺术， 总结了与钱有关的20 个智慧。比如普通人最 强大的理财技能，是用好静默复利策略；比如最宝贵的资产是不需要取悦任何人；比如多尝试各种花钱方式，找到最适合你个性、真正能让你快乐的事情。 你对金钱的认知有多高，人生就有多自由。即使没有接受过专业金融教育，没有投资理财技巧，你也可以凭借对金钱的良好认知，最终走向富裕，让金钱为你所用。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_vwgd8cbh166b18vky3wyjg/s_cpplatform_vwgd8cbh166b18vky3wyjg1767152651.jpg","version":629031897,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":63},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":4525313,"publishTime":"2025-09-01 00:00:00","lastChapterIdx":27,"paperBook":{"skuId":""},"centPrice":4060,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":2406,"tags":[]},{"book":{"bookId":"843544","title":"别独自用餐：85%的成功来自高效的社交能力","author":"基思·法拉奇 塔尔·雷兹","translator":"前十网","intro":"彻底颠覆思考人脉的固有方式。作为克林顿和希拉里智囊团中的人脉大师，基思·法拉奇经过20年的研究发现，一个人的成功，85%归功于他的人脉关系。在其代表作《别独自用餐》中，法拉奇提出了让人终身受益的社交法则。这些法则将彻底改变人们思考人脉的固有方式，通过持续地改变生活中看似不经意的行为，从而获得更有价值的人脉关系。《别独自用餐》自2005年出版，畅销至今。此十周年修订珍藏版，增加了社交媒体时代的社交技巧，更符合当下的社交需求。","cover":"https://cdn.weread.qq.com/weread/cover/94/YueWen_843544/s_YueWen_843544.jpg","version":1997142547,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":47,"maxfreeChapterRatio":57},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":14792401,"publishTime":"2016-0