{"stat":"阅读","counts":"110天"},{"stat":"笔记","counts":"301条"}],"registTime":1516801194,"readRate":62,"wrReadTime":121987,"wrListenTime":73745,"compare":0.03657187394120933,"dayAverageReadTime":752,"baseTime":1767196800,"totalReadTime":133944,"readRecordsWord":"书籍分布","preferBooks":[{"type":13,"title":"我的最爱"},{"type":1,"title":"近期偏爱"},{"type":0,"title":"常读常新"},{"type":5,"title":"思考最多","bookInfo":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"笔记最多"},{"type":3,"title":"最沉浸的"},{"type":4,"title":"读到深夜"},{"type":7,"title":"第一本阅读","bookInfo":{"bookId":"3300189789","title":"金钱的艺术","author":"[美]摩根·豪泽尔","translator":"袁希","intro":"金钱不是公式里的学问， 而是现实中的艺术。 我们习惯于把投资理财当作一门科学，却忽视了其中复杂的心理与行为，导致我们要么把钱花在并不如预期那样带来快乐的事情上，要么错过真正有价值的投资。 在这本书中，摩根·豪泽尔以深刻的见解和温暖的笔触，向我们展示了学校里并不教的金钱的艺术， 总结了与钱有关的20 个智慧。比如普通人最 强大的理财技能，是用好静默复利策略；比如最宝贵的资产是不需要取悦任何人；比如多尝试各种花钱方式，找到最适合你个性、真正能让你快乐的事情。 你对金钱的认知有多高，人生就有多自由。即使没有接受过专业金融教育，没有投资理财技巧，你也可以凭借对金钱的良好认知，最终走向富裕，让金钱为你所用。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_vwgd8cbh166b18vky3wyjg/s_cpplatform_vwgd8cbh166b18vky3w