:76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了4小时"},{"type":2,"title":"最爱分享","bookInfo":{"bookId":"3300072235","title":"癌症病人怎么吃？（译文科学）","author":"王兴","intro":"上海三甲医院医生，为中国癌症病人量身定做的饮食指导。\u000b作者王兴从事科普工作多年，是头条、知乎签约作者，拥有众多粉丝，长期受邀担任中央电视台《健康之路》节目明星演示嘉宾。陶勇、罗翔、郑兴东、庞颖、梁文道、刘润联袂推荐！\u000b要做手术，平时吃的药还吃不吃？喝汤真的能大补吗？化疗吃不下东西怎么办？化疗时吃什么才能不脱发？镇痛药会影响伤口愈合吗？怎么吃才能不得癌？\r\n《癌症病人怎么吃？》希望解决两个问题：怎么吃能少得癌？得了癌应该怎么吃？\r\n我国每年有450万新发癌症病人，“怎么吃”，是我们在对抗癌症路上最重要的一件事情。不科学的传统饮食观念和民间的谣言使很多患者明明治疗得很成功，却因为饮食出现各种状况。《癌症病人怎么吃？》是上海第一人民医院胸外科主治医生王兴为中国的癌症病人量身定做的饮食指导，它用通俗的语言、真实的病例，帮助癌症病人及家人“吃”过这段晦暗的时光。一日三餐，请好好吃饭！","cover":"https://cdn.weread.qq.com/weread/cover/53/cpplatform_wm3aekn4fhyzqdkod8n16s/s_cpplatform_wm3aekn4fhyzqdkod8n16s1695698283.jpg","version":2062134691,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":3},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":7,"cpid":9030183,"publishTime":"2023-09-01 00:00:00","lastChapterIdx":38,"paperBook":{"skuId":""},"centPrice":5599,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"分享8次"},{"type":12,"title":"共读最多","bookInfo":{"bookId":"695233","title":"三体全集（全三册）","author":"刘慈欣","intro":"【荣获世界科幻大奖“雨果奖”长篇小说奖，约翰·坎贝尔纪念奖，银河奖特别奖。】\n每个人的书架上都该有套《三体》！关于宇宙最狂野的想象！就是它！\n征服世界的中国科幻神作！包揽九项世界顶级科幻大奖！出版16个语种，横扫30国读者！奥巴马、雷军、马化腾、周鸿祎、潘石屹、扎克伯格……强推！\n刘慈欣获得2018年度克拉克想象力贡献社会奖！\n刘慈欣是中国科幻小说的最主要代表作家，亚洲首位世界科幻大奖“雨果奖”得主，被誉为中国科幻的领军人物。","cover":"https://cdn.weread.qq.com/weread/cover/80/yuewen_695233/s_yuewen_6952331740758482.jpg","version":1687693885,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":24,"maxFreeInfo":{"maxfreeChapterIdx":24,"maxfreeChapterUid":109,"maxfreeChapterRatio":92},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":2413,"publishTime":"2022-04-01 00:00:00","lastChapterIdx":109,"paperBook":{"skuId":""},"centPrice":8999,"copyrightChapterUids":[87,91,132,149],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"42位好友也爱读"},{"type":10,"title":"欣赏小众","bookInfo":{"bookId":"3300095033","title":"别对企鹅发火","author":"[美]盖比·卡普","translator":"靳婷婷","intro":"在冲突中剔除情绪就能处理好冲突！帮助你控制自己的情绪，马上成为人际高手高手高高手！轻松又好读\n冲突发生时，有的人保持沉默，为了避免矛盾放弃自己的立场；有的人情绪上头，不管对错，就是要吵个你输我赢。本书提供了如何处理冲突的系统性方法，助你控制自己的情绪，处理好冲突：\n方法一：别对企鹅发火\n企鹅有翅膀，但它不会飞。因为企鹅不会飞而生气是没有用的。我们都有一些比别人进化得慢的领域，你不必为此生气。接受他人本来的样子，包括各种缺点和局限，我们就能掌握主动权，减少冲突。\n方法二：使用购物清单语气\n在说话时只陈述事实，不要激动、不带情绪、语气平和，就像你让朋友到商店帮你买东西一样。这样你就能专注于传达信息，对方也能够接受你的反馈并理解信息。\n方法三：学会倾听\n让人感到自己被倾听，是成功化解一切冲突的关键。比对方更准确地重述他们的观点，一旦对方感觉自己被理解了，他们也就能理解你的立场。","cover":"https://cdn.weread.qq.com/weread/cover/76/cpplatform_kppbxavyxwidksjunc481a/s_cpplatform_kppbxavyxwidksjunc481a1712890394.jpg","version":1204454500,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":5,"maxFreeInfo":{"maxfreeChapterIdx":5,"maxfreeChapterUid":29,"maxfreeChapterRatio":36},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":14792401,"publishTime":"2024-04-01 00:00:00","lastChapterIdx":14,"paperBook":{"skuId":""},"centPrice":4990,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"仅有7106人读过"},{"type":8,"title":"总有一天读完","bookInfo":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"19天只读了44%"}]}',1782529843);
INSERT INTO reading_stats VALUES(21,'weekly',0,'{"readTimes":{"1782057600":498,"1782144000":377,"1782230400":64,"1782316800":0,"1782403200":1192,"1782489600":241},"readDays":5,"readLongest":[{"book":{"bookId":"3300149579","title":"那些我希望自己二十出头就能明白的事","author":"弗兰克扬","intro":"给20-30岁年轻人的避坑指南。当你纠结“应届生身份有多重要？”“月薪一万要牺牲多少生活？”时，这本书用28个真实案例给你答案：教你用排除法筛选职业方向、拆穿职场四十万定律谎言、识破跳槽涨薪的隐形代价。作者以十年职场观察，直击“五千块工资困局”“学历贬值真相”“兴趣与职业的悖论”等扎心现实，给出“坑专业自救四步法”“对抗信息茧房实操指南”。没有鸡汤，只有血淋淋的规则拆解，如同过来人递给你一张避坑地图，告诉你哪些弯路不必走，哪些代价付不起。\n*同名纸书《那些我希望自己二十出头就能明白的事》已出版！","cover":"https://cdn.weread.qq.com/weread/cover/27/cpplatform_ojnqd7ae7wj86lgpakgt2m/s_cpplatform_ojnqd7ae7wj86lgpakgt2m1750325884.jpg","version":175200107,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":8,"maxfreeChapterRatio":66},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2025-06-24 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":3900,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1172,"tags":["单日阅读最久"]},{"book":{"bookId":"3300177663","title":"财富的真相","author":"李笑来","intro":"《财富的真相》是李笑来向大众普及财富底层逻辑的书。作者指出，财富的独一正常来源是“生产”，而材料、知识等生产资料，溯源到底层都是“时间”的衍生物。因而，时间是我们每个人终生独一的生产资料，改变对时间的观念，才能根本上重塑我们的财富观，避免贱卖我们的时间，而是把时间花费在有复利效应的工作上。每天进步一点点，时间会帮你实现指数级的增长。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_dvldwkuhkesnhvbgpxcgdx/s_cpplatform_dvldwkuhkesnhvbgpxcgdx1763434911.jpg","version":48052399,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":43},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2023-12