INSERT INTO reading_stats VALUES(22,'monthly',0,'{"readTimes":{"1780243200":532,"1780329600":5,"1780416000":1722,"1780502400":9180,"1780588800":502,"1780675200":732,"1780761600":250,"1780848000":206,"1780934400":455,"1781020800":529,"1781107200":649,"1781193600":643,"1781366400":505,"1781452800":1067,"1781539200":3165,"1781625600":83,"1781712000":314,"1781798400":1685,"1781884800":265,"1781971200":1118,"1782057600":498,"1782144000":377,"1782230400":64,"1782316800":0,"1782403200":1192,"1782489600":241},"readDays":24,"readLongest":[{"book":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":16708,"tags":["笔记最多","单日阅读最久"]},{"book":{"bookId":"3300209394","title":"图解Skill：AI提效实战指南","author":"宝玉","intro":"知名 AI 应用专家宝玉结合自身实战经验，撰写了这本技能实操指南，旨在帮助读者将个人经验转化为智能体可执行的技能，摆脱“AI 工具人”困境，真正实现工作自动化。  全书遵循“先实践后沉淀”的学习路径，带你从跑通第一个技能入手，逐步构建专属的多技能 AI 自动化工作流。作者手把手教你掌握：3 个单技能模板、1 条组合式写作工作流、1 套技能工程方法论、1 次从零开始完整迭代的技能项目实战。  本书不绑定平台，扣子、Claude Code、OpenClaw 均可使用；也不要求读者具备编程基础，只要你想用 AI 提效，就可以通过本书学会技能，并立刻投入使用。","cover":"https://cdn.weread.qq.com/weread/cover/82/cpplatform_wmaghz3junjyxd2lc1jqn5/s_cpplatform_wmaghz3junjyxd2lc1jqn51780656076.jpg","version":1098618653,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":11},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5256588,"publishTime":"2026-05-01 00:00:00","lastChapterIdx":48,"paperBook":{"skuId":""},"centPrice":3990,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":2110,"tags":[]},{"book":{"bookId":"3300177663","title":"财富的真相","author":"李笑来","intro":"《财富的真相》是李笑来向大众普及财富底层逻辑的书。作者指出，财富的独一正常来源是“生产”，而材料、知识等生产资料，溯源到底层都是“时间”的衍生物。因而，时间是我们每个人终生独一的生产资料，改变对时间的观念，才能根本上重塑我们的财富观，避免贱卖我们的时间，而是把时间花费在有复利效应的工作上。每天进步一点点，时间会帮你实现指数级的增长。","cover":"https://cdn.weread.qq.com/weread/cover/60/cpplatform_dvldwkuhkesnhvbgpxcgdx/s_cpplatform_dvldwkuhkesnhvbgpxcgdx1763434911.jpg","version":48052399,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":43},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2023-12-01 00:00:00","lastChapterIdx":38,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1450,"tags":[]},{"book":{"bookId":"3300202721","title":"县乡生活：一场生活方式的巨变","author":"吕德文 胡晓映","intro":"中国正处于前所未有的城乡融合发展过程中，一种新型的城乡社会形态初见雏形。人们践行新生活方式，穿梭于乡土社会和都市社会两个生活系统中。新生活方式形成的同时，生活危机也在蔓延。 本书分“过日子”“流动生活““消费变迁”“婚难时代”“小镇青年”“老龄社会”六部分展开，细致描画县乡生活的新景象：数字生活兴起，单身现象增多，家庭观念变迁，老人自养秩序形成，伪中产生活陷阱频现。 本书以多位青年学者在全国各地的田野调查为基础，他们以细腻的情感、真实的笔触描写县乡生活的诸多细节，展现当代中国基层社会的真实图景。","cover":"https://cdn.weread.qq.com/weread/cover/43/cpplatform_gc31hydswgglcwoja8aak6/s_cpplatform_gc31hydswgglcwoja8aak61776935176.jpg","version":1210456338,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":78},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3382183,"publishTime":"2026-03-15 00:00:00","lastChapterIdx":47,"paperBook":{"skuId":""},"centPrice":4140,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1230,"tags":[]},{"book":{"bookId":"3300149579","title":"那些我希望自己二十出头就能明白的事","author":"弗兰克扬","intro":"给20-30岁年轻人的避坑指南。当你纠结“应届生身份有多重要？”“月薪一万要牺牲多少生活？”时，这本书用28个真实案例给你答案：教你用排除法筛选职业方向、拆穿职场四十万定律谎言、识破跳槽涨薪的隐形代价。作者以十年职场观察，直击“五千块工资困局”“学历贬值真相”“兴趣与职业的悖论”等扎心现实，给出“坑专业自救四步法”“对抗信息茧房实操指南”。没有鸡汤，只有血淋淋的规则拆解，如同过来人递给你一张避坑地图，告诉你哪些弯路不必走，哪些代价付不起。\n*同名纸书《那些我希望自己二十出头就能明白的事》已出版！","cover":"https://cdn.weread.qq.com/weread/cover/27/cpplatform_ojnqd7ae7wj86lgpakgt2m/s_cpplatform_ojnqd7ae7wj86lgpakgt2m1750325884.jpg","version":175200107,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":8,"maxfreeChapterRatio":66},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2025-06-24 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":3900,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":1172,"tags":[]},{"book":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":639,"tags":[]},{"book":{"bookId":"3300206286","title":"以日为镜：经济下行期穿越指南","author":"王熙威","intro":"当经济增速放缓成为新常态，普通人如何守住生活底线、找到新的出路？关心自身财务安全、职业前景、婚姻关系、养老规划的普通人必读！\n作者王熙威，北大本科、东京大学硕士，近二十年深耕日本社会肌理。本书不写宏大叙事，只讲真实故事：泡沫破裂后买房套牢的渡边一家、从东大精英到网吧难民的田中、在废墟上开面包店的高桥……三十余个普通人的命运切片，还原日本“失去的三十年”的社会细节和心态变化。\n这不是一本预言未来的书，而是一面镜子——照见日本踩过的坑、走过的弯路，以及普通人在结构转型中咬牙支撑的韧性。当“内卷”“躺平”“消费降级”成为日常热词，转过头看看这面镜子，或许能获得一点面对当下生活的底气与启发。","cover":"https://cdn.weread.qq.com/weread/cover/64/cpplatform_psum2ddry7rjbeqdfztjjz/s_cpplatform_psum2ddry7rjbeqdfztjjz1779186519.jpg","version":2075593703,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":13,"maxFreeInfo":{"maxfreeChapterIdx":13,"maxfreeChapterUid":13,"maxfreeChapterRatio":6},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":1000000190,"publishTime":"2026-05-21 00:00:00","lastChapterIdx":64,"paperBook":{"skuId":""},"centPrice":6200,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":403,"tags":[]},{"book":{"bookId":"3300207566","title":"十倍速开发：AI时代的Cursor编程手记","author":"王尧","intro":"本书是基于 Web 的博客系统 BlogN 的开发过程，采用人与 AI 工具对话的形式，记录 AI 辅助编程工具 Cursor 在实际项目开发中的应用过程。书中不仅展示 AI 工具在技术决策、代码生成和问题解决及优化方面的强大能力，还深入探讨 AI 工具的特性、最佳实践及 AI 技术对传统编程的冲击。通过具体的案例，本书揭示 AI 工具在编程中的优势，如快速生成高质量代码、处理复杂逻辑等，同时也指出其局限性，如对复杂问题理解不足、可能出现错误和幻觉问题等，还示范如何通过自然语言指令驱动 AI 工具完成任务，如何对生成的代码进行审查和优化，以及在 AI 工具失效时如何及时介入并解决问题。这些内容将为读者传达最新的 AI 辅助编程理念并提供宝贵的实战经验，帮助读者理解如何在实际开发中合理利用 AI 工具，提升开发效率。 全书共 15 章，详细描述从项目规划、技术选型、开发环境搭建，到各个功能模块的实现及最终的性能优化和测试的全过程，不仅涵盖后端服务的搭建、数据库设计与优化，还涉及前端界面的开发和用户体验的提升，全面展示与传统编程过程不同的人与 AI 工具协同的开发方式。 本书面向有经验的软件开发者，尤其是那些希望在 AI 时代提升开发效率、掌握新开发方法的专业人士。无论是在个人项目中寻求高效开发，还是在大型团队中探索新的协作模式，本书都能为读者提供实用的指导和启发。","cover":"https://cdn.weread.qq.com/weread/cover/17/cpplatform_cbrgew9mucjtgqv6b9wj3c/s_cpplatform_cbrgew9mucjtgqv6b9wj3c1779955090.jpg","version":177622253,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":25,"maxFreeInfo":{"maxfreeChapterIdx":25,"maxfreeChapterUid":25,"maxfreeChapterRatio":53},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":5256588,"publishTime":"2026-04-01 00:00:00","lastChapterIdx":106,"paperBook":{"skuId":""},"centPrice":5747,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"readTime":383,"tags":[]}],"preferCategory":[{"categoryId":1000000,"categoryTitle":"个人成长","parentCategoryId":1000000,"parentCategoryTitle":"个人成长","readingCount":2,"readingTime":17884},{"categoryId":1500000,"categoryTitle":"科学技术","parentCategoryId":1500000,"parentCategoryTitle":"科学技术","readingCount":1,"readingTime":2110},{"categoryId":1100000,"categoryTitle":"经济理财","parentCategoryId":1100000,"parentCategoryTitle":"经济理财","readingCount":2,"readingTime":1623},{"categoryId":900000,"categoryTitle":"社会文化","parentCategoryId":900000,"parentCategoryTitle":"社会文化","readingCount":1,"readingTime":1230},{"categoryId":600000,"categoryTitle":"哲学宗教","parentCategoryId":600000,"parentCategoryTitle":"哲学宗教","readingCount":1,"readingTime":646},{"categoryId":700000,"categoryTitle":"计算机","parentCategoryId":700000,"parentCategoryTitle":"计算机","readingCount":1,"readingTime":383},{"categoryId":200000,"categoryTitle":"历史","parentCategoryId":200000,"parentCategoryTitle":"历史","readingCount":0,"readingTime":0},{"categoryId":300000,"categoryTitle":"文学","parentCategoryId":300000,"parentCategoryTitle":"文学","readingCount":0,"readingTime":0}],"preferCategoryWord":"偏好阅读个人成长","readStat":[{"stat":"读过","counts":"8本"},{"stat":"读完","counts":"1本"},{"stat":"阅读","counts":"24天"},{"stat":"笔记","counts":"70条"}],"registTime":1516801194,"readRate":70,"wrReadTime":18393,"wrListenTime":7586,"compare":0.2344897252189696,"dayAverageReadTime":962,"baseTime":1780243200,"totalReadTime":25979,"readDistributionWord":"点评分布","preferBooks":[{"type":13,"title":"我的最爱"},{"type":1,"title":"近期偏爱"},{"type":0,"title":"常读常新"},{"type":5,"title":"思考最多","bookInfo":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cp