d":5256588,"publishTime":"2021-09-01 00:00:00","lastChapterIdx":293,"paperBook":{"skuId":""},"centPrice":7674,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":1,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读至04:59"},{"type":7,"title":"第一本阅读","bookInfo":{"bookId":"839212","title":"月亮与六便士","author":"威廉·萨默塞特·毛姆","translator":"陶然","intro":"    《月亮和六便士》的情节以法国后印象派画家高更的生平为基础，主人公原是位证券经纪人，人到中年后突然响应内心的呼唤，舍弃一切到南太平洋的塔希提岛与土著人一起生活，获得灵感，创作出许多艺术杰作。毛姆在小说中深入探讨了生活和艺术两者的矛盾和相互作用。\n","cover":"https://wfqqreader-1252317822.image.myqcloud.com/cover/212/839212/s_839212.jpg","version":1541544787,"format":"epub","type":0,"soldout":1,"bookStatus":1,"payType":1,"finished":1,"maxFreeChapter":10,"maxFreeInfo":{"maxfreeChapterIdx":10,"maxfreeChapterUid":10,"maxfreeChapterRatio":48},"free":0,"mcardDiscount":0,"ispub":1,"cpid":0,"publishTime":"2016-07-01 00:00:00","lastChapterIdx":61,"paperBook":{"skuId":""},"centPrice":800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":true,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"2018/05/12/阅读"},{"type":6,"title":"最爱个人成长","bookInfo":{"bookId":"3300177660","title":"专注的真相","author":"李笑来","intro":"中国财富自由概念启蒙者——李笑来最新力作，本书传达了一个基本认知：能够长期持续专注的人，无论做什么，都从根基上具备更强的竞争力。\r\n有证据表明，注意力不足源自大脑的器质性损伤。看一眼四周，你一定不难得出“手机对大脑的劫持将愈演愈烈”这一结论。本书先为你拆解清楚大脑保持专注的工作原理，再给出简单（但不容易）的解决方案，例如，孩子长到一定年龄前不能长时间看手机，最好能养成运动、朗读、音乐等爱好，为未来打好基础，做天生赢家。","cover":"https://cdn.weread.qq.com/weread/cover/4/cpplatform_v6rotsdw578bplfggz32pk/s_cpplatform_v6rotsdw578bplfggz32pk1763434329.jpg","version":1981423803,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":6,"maxFreeInfo":{"maxfreeChapterIdx":6,"maxfreeChapterUid":6,"maxfreeChapterRatio":76},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":-3319053,"publishTime":"2024-11-01 00:00:00","lastChapterIdx":23,"paperBook":{"skuId":""},"centPrice":5800,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"阅读了4小时"},{"type":2,"title":"最爱分享","bookInfo":{"bookId":"3300072235","title":"癌症病人怎么吃？（译文科学）","author":"王兴","intro":"上海三甲医院医生，为中国癌症病人量身定做的饮食指导。\u000b作者王兴从事科普工作多年，是头条、知乎签约作者，拥有众多粉丝，长期受邀担任中央电视台《健康之路》节目明星演示嘉宾。陶勇、罗翔、郑兴东、庞颖、梁文道、刘润联袂推荐！\u000b要做手术，平时吃的药还吃不吃？喝汤真的能大补吗？化疗吃不下东西怎么办？化疗时吃什么才能不脱发？镇痛药会影响伤口愈合吗？怎么吃才能不得癌？\r\n《癌症病人怎么吃？》希望解决两个问题：怎么吃能少得癌？得了癌应该怎么吃？\r\n我国每年有450万新发癌症病人，“怎么吃”，是我们在对抗癌症路上最重要的一件事情。不科学的传统饮食观念和民间的谣言使很多患者明明治疗得很成功，却因为饮食出现各种状况。《癌症病人怎么吃？》是上海第一人民医院胸外科主治医生王兴为中国的癌症病人量身定做的饮食指导，它用通俗的语言、真实的病例，帮助癌症病人及家人“吃”过这段晦暗的时光。一日三餐，请好好吃饭！","cover":"https://cdn.weread.qq.com/weread/cover/53/cpplatform_wm3aekn4fhyzqdkod8n16s/s_cpplatform_wm3aekn4fhyzqdkod8n16s1695698283.jpg","version":2062134691,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":7,"maxFreeInfo":{"maxfreeChapterIdx":7,"maxfreeChapterUid":7,"maxfreeChapterRatio":3},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":7,"cpid":9030183,"publishTime":"2023-09-01 00:00:00","lastChapterIdx":38,"paperBook":{"skuId":""},"centPrice":5599,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"分享8次"},{"type":12,"title":"共读最多","bookInfo":{"bookId":"695233","title":"三体全集（全三册）","author":"刘慈欣","intro":"【荣获世界科幻大奖“雨果奖”长篇小说奖，约翰·坎贝尔纪念奖，银河奖特别奖。】\n每个人的书架上都该有套《三体》！关于宇宙最狂野的想象！就是它！\n征服世界的中国科幻神作！包揽九项世界顶级科幻大奖！出版16个语种，横扫30国读者！奥巴马、雷军、马化腾、周鸿祎、潘石屹、扎克伯格……强推！\n刘慈欣获得2018年度克拉克想象力贡献社会奖！\n刘慈欣是中国科幻小说的最主要代表作家，亚洲首位世界科幻大奖“雨果奖”得主，被誉为中国科幻的领军人物。","cover":"https://cdn.weread.qq.com/weread/cover/80/yuewen_695233/s_yuewen_6952331740758482.jpg","version":1687693885,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":4097,"finished":1,"maxFreeChapter":24,"maxFreeInfo":{"maxfreeChapterIdx":24,"maxfreeChapterUid":109,"maxfreeChapterRatio":92},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":2413,"publishTime":"2022-04-01 00:00:00","lastChapterIdx":109,"paperBook":{"skuId":""},"centPrice":8999,"copyrightChapterUids":[87,91,132,149],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"42位好友也爱读"},{"type":10,"title":"欣赏小众","bookInfo":{"bookId":"3300095033","title":"别对企鹅发火","author":"[美]盖比·卡普","translator":"靳婷婷","intro":"在冲突中剔除情绪就能处理好冲突！帮助你控制自己的情绪，马上成为人际高手高手高高手！轻松又好读\n冲突发生时，有的人保持沉默，为了避免矛盾放弃自己的立场；有的人情绪上头，不管对错，就是要吵个你输我赢。本书提供了如何处理冲突的系统性方法，助你控制自己的情绪，处理好冲突：\n方法一：别对企鹅发火\n企鹅有翅膀，但它不会飞。因为企鹅不会飞而生气是没有用的。我们都有一些比别人进化得慢的领域，你不必为此生气。接受他人本来的样子，包括各种缺点和局限，我们就能掌握主动权，减少冲突。\n方法二：使用购物清单语气\n在说话时只陈述事实，不要激动、不带情绪、语气平和，就像你让朋友到商店帮你买东西一样。这样你就能专注于传达信息，对方也能够接受你的反馈并理解信息。\n方法三：学会倾听\n让人感到自己被倾听，是成功化解一切冲突的关键。比对方更准确地重述他们的观点，一旦对方感觉自己被理解了，他们也就能理解你的立场。","cover":"https://cdn.weread.qq.com/weread/cover/76/cpplatform_kppbxavyxwidksjunc481a/s_cpplatform_kppbxavyxwidksjunc481a1712890394.jpg","version":1204454500,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":5,"maxFreeInfo":{"maxfreeChapterIdx":5,"maxfreeChapterUid":29,"maxfreeChapterRatio":36},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":5,"cpid":14792401,"publishTime":"2024-04-01 00:00:00","lastChapterIdx":14,"paperBook":{"skuId":""},"centPrice":4990,"copyrightChapterUids":[2],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"仅有7106人读过"},{"type":8,"title":"总有一天读完","bookInfo":{"bookId":"22791651","title":"《金刚经》说什么","author":"南怀瑾","intro":"本书是南怀瑾先生有关《金刚经》的讲课记录。作者依据梁代昭明太子的分法，将《金刚经》分为三十二品（相当于章），然后逐品作了讲解。每一品均以一首偈颂作总结，以阐发自己的心得。《金刚经》是初期大乘佛教的代表作之一，也是般若类佛经的纲要书，它全称《金刚般若波罗蜜经》一卷，由姚秦鸠摩罗什于弘始祥译出，问世之后，即在社会上广泛流传，篡要、注解、类颂、重演、义记、采微、集解、科释、宗通、决疑、大意、直说等注释达一百多种。","cover":"https://cdn.weread.qq.com/weread/cover/87/YueWen_22791651/s_YueWen_22791651.jpg","version":625271991,"format":"epub","type":0,"soldout":0,"bookStatus":1,"payType":1048577,"finished":1,"maxFreeChapter":8,"maxFreeInfo":{"maxfreeChapterIdx":8,"maxfreeChapterUid":227,"maxfreeChapterRatio":35},"free":0,"mcardDiscount":0,"ispub":1,"extra_type":1,"cpid":3795111,"publishTime":"2016-04-01 00:00:00","lastChapterIdx":40,"paperBook":{"skuId":""},"centPrice":2730,"copyrightChapterUids":[221],"inStoreBookId":"","blockSaveImg":0,"language":"zh-wr","isTraditionalChinese":false,"hideUpdateTime":false,"isEPUBComics":0,"isVerticalLayout":0,"isShowTTS":1,"selfProduceIncentive":false,"webBookControl":0,"isAutoDownload":1},"reason":"19天只读了44%"}]}',1782532958);
INSERT INTO popular_highlights VALUES('635722',57,'第一章 童年：被遗弃与被选择','老乔布斯说，把柜子和栅栏的背面制作好也十分重要，尽管这些地方人们看不到。“他喜欢追求完美，即使别人看不到的地方他也会很关心。”','5523-5586',5094,1782613083);
INSERT INTO popular_highlights VALUES('635722',56,'前言 本书是如何诞生的','他们所做的并非是针对目标人群的普通产品改进，而是在消费者还没有意识到其需求的时候，就为其提供全新的设备和服务。','4626-4681',4816,1782613083);
INSERT INTO popular_highlights VALUES('635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我教他，如果你表现得好像你能做某件事，那就能起作用。我告诉他，你装得好像自己掌控了一切，别人就会以为你真的掌控了一切。”','12263-12323',4158,1782613083);
INSERT INTO popular_highlights VALUES('635722',54,'引言','那些疯狂到以为自己能够改变世界的人，才能真正改变世界。','546-573',3892,1782613083);
INSERT INTO popular_highlights VALUES('635722',59,'第三章 出离：觉悟，修行……','它让我更清楚什么是重要的——创造伟大的发明，而不是赚钱。我应该尽我所能，在历史和人类思想的长河中留下一些东西。”','10682-10738',1989,1782613083);
INSERT INTO popular_highlights VALUES('635722',66,'第十章 Mac诞生了：你说你想要一场革命……','他在厌倦了教书之后，就租了一只热气球，飞到校长家上空，大声喊出了自己的辞职决定。','922-962',1896,1782613083);
INSERT INTO popular_highlights VALUES('635722',81,'第二十五章 非同凡想：iCEO乔布斯','乔布斯的一个过人之处是知道如何做到专注。“决定不做什么跟决定做什么同样重要。”他说，“对公司来说是这样，对产品来说也是这样。”','9085-9148',1885,1782613083);
INSERT INTO popular_highlights VALUES('635722',76,'第二十章 凡人：爱就那么回事','还在很小的年纪，莉萨就开始意识到他的饮食癖好反映了一种人生哲学：苦行和极简将会让人更加敏锐。“他相信匮乏即是富足，自律产生喜悦。”她说，“他知道一个大多数人不知道的道理：物极必反。”','9266-9357',1776,1782613083);
INSERT INTO popular_highlights VALUES('635722',73,'第十七章 伊卡洛斯： 凡升起的……','如果你想让自己的生活过得富有创造性，像艺术家一样，就不能常常回顾过去。不管你做过什么，以前是怎么样，你都必须心甘情愿地接受一切，并将一切抛诸脑后。','10465-10538',1704,1782613083);
INSERT INTO popular_highlights VALUES('635722',71,'第十五章 Mac电脑的发布：在宇宙中留下印迹','Mac发布当天，来自《大众科学》(Popular Science)的一位记者问乔布斯做过什么类型的市场调研工作。乔布斯语带嘲讽地回应：“亚历山大·格雷厄姆·贝尔在发明电话之前做过任何市场调研吗？”','11691-11817',1610,1782613083);
INSERT INTO popular_highlights VALUES('635722',97,'第四十一章 第三回合：暮色下的抗争','“我有过很幸运的事业，有过很幸运的人生。”他回答说，“我已经做了我能做的一切。”','18472-18512',1536,1782613083);
INSERT INTO popular_highlights VALUES('635722',99,'后记','“或许他们是别人眼中的疯子，但他们却是我们眼中的天才。因为只有那些疯狂到以为自己能够改变世界的人，才能真正改变世界。”','4950-5009',1529,1782613083);
INSERT INTO popular_highlights VALUES('635722',70,'第十四章 斯卡利来了：百事挑战','‘你是想卖一辈子糖水呢，还是想抓住机会来改变世界？’”','6266-6293',1425,1782613083);
INSERT INTO popular_highlights VALUES('635722',56,'前言 本书是如何诞生的','一个具有强烈个性的人身上集合了人文和科学的天赋后所能产生的那种创造力，我相信这种创造力也是在21世纪建立创新型经济的关键因素。','2770-2833',1417,1782613083);
INSERT INTO popular_highlights VALUES('635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','但如果你平静而自信，如果乔布斯审视你一番后认为你清楚自己在干什么，他就会很尊重你。多年来，无论是在他的私人生活还是职业生涯中，他的核心圈子里聚集的都是真正的强者，而不是谄媚者。','5304-5392',1404,1782613083);
INSERT INTO popular_highlights VALUES('635722',60,'第四章 雅达利与印度：禅宗与游戏设计艺术','我从禅中学到的真理就是，如果你愿意跋山涉水去见一位导师的话，往往你的身边就会出现一位。','6847-6890',1358,1782613083);
INSERT INTO popular_highlights VALUES('635722',78,'第二十二章 玩具总动员：巴斯和胡迪救场','产品是有灵魂的，是为了一个使命才被生产出来的。如果物体也有情感，它的情感应该是基于它渴望实现自己的价值。','1852-1904',1232,1782613083);
INSERT INTO popular_highlights VALUES('635722',85,'第二十九章 苹果零售店：天才吧和锡耶纳沙石','如果你发现有些事做得不对，你不能只是忽略它，然后说‘以后再处理’，这是其他公司的做法。”','5274-5318',1215,1782613083);
INSERT INTO popular_highlights VALUES('635722',57,'第一章 童年：被遗弃与被选择','我认为，他想完全掌控自己制造的每一样东西的那种强烈欲望，就来源于他的性格以及刚出生就被抛弃这件事。','4079-4128',1170,1782613083);
INSERT INTO popular_highlights VALUES('635722',67,'第十一章 现实扭曲力场：以自己的游戏规则行事','现实扭曲力场是几种因素的混合物，其中包含了极富魅力的措辞风格、不屈的意志和让现实屈从于自己意图的热切渴望。','1289-1342',1156,1782613083);
INSERT INTO popular_highlights VALUES('3300037073',27,'22 T细胞和B细胞的共舞','很遗憾，免疫系统乃至整个宇宙都不是为了让玩智能手机的巨猿能轻松理解而生的，有时候深入学习很困难，哪怕是学习很重要的主题。你并不需要记住读过的所有细节。','2827-2902',1248,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',8,'3 细胞是什么样的？','自然界中这种现象很常见，叫“涌现”(emergence)，指的是实体拥有它的组成部分所没有的属性和能力。','6809-6861',1056,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',13,'8 先天性免疫士兵：巨噬细胞和中性粒细胞','细胞觉得自己寿命已到的时候，会释放特殊信号，告诉大家它准备离开了。随后，细胞进入凋亡过程，自行分解成碎片，整齐地打包成废弃物。巨噬细胞被信号吸引过来，清理细胞碎片，回收零件。','1484-1571',1054,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',53,'致谢','如果你读了这本书，并且读到了这里，我也要说：你本有很多别的东西可读，但却读了这一本，所以，谢谢你。','1967-2016',1036,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',37,'32 天生杀手','要是发现了太多的压力信号，自然杀伤细胞会把已经承受不住的可怜细胞直接爆头。要是有人形自然杀伤细胞的话，在他们身边你一定要多笑！','3006-3069',954,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',7,'2 守卫每一寸身体','在你的一生中，免疫系统已经消灭了十亿百亿的敌人，而且依然时刻准备着为你而战。','4061-4099',858,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',5,'前言','你不是一个爱抱怨的宝宝，而你的免疫系统更加任劳任怨，默默无闻。它们时刻都在辛勤地工作，确保你能活着，继续哀叹人生的不幸。','448-508',855,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',24,'19 信息盛宴：抗原呈递','不同类型的MHC会更擅长或更不擅长呈递不同的抗原，比如有的类型会特别擅长呈递特定的病毒抗原，而另一种会擅长呈递某种细菌抗原。这对人类这一物种来说非常有用，使得人类很难被单一种病原体消灭。','4986-5079',825,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',11,'6 荒漠之国：皮肤','你甚至可以说，皮肤细胞活着就是为了在合适的地方变成齐整的尸体。融合后的死亡皮肤细胞会被不断推向表层。足足有50层死细胞叠在一起，形成皮肤那“死去”的表层，覆盖整个身体。','1672-1756',816,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',7,'2 守卫每一寸身体','你可能会误以为黏膜属于身体内部。但其实，它们属于外部。仔细想想，其实从某种意义上说，人体不过是一根复杂的管道。没错，一根两端可闭合的管道，只不过更加湿漉漉、滑溜溜、乱糟糟一些。','1558-1646',810,1782613085);
