INSERT INTO popular_highlights VALUES('3300037073',50,'45 新冠疫情','这一章我们就讲到这儿吧。当我写这句话的时候，全世界的人已经开始接种新冠疫苗。要是走运的话，在你读到这句话时，我们的生活应该开始恢复正常了。','4655-4724',810,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',6,'第1部分 认识免疫系统','它们必须想办法把周围的化学物质转化成能为己所用的东西，同时获取生存必需的能量，而其中有些细胞就盯上了“捷径”。如果能偷别人的，干吗还要自己干呢？','598-670',799,1782613085);
