INSERT INTO popular_highlights VALUES('3300037073',10,'第2部分 惨重损伤','另一些微小生命，比如引发COVID-19的新型冠状病毒，是偶然传播到人类中间的，连它们自己都不信能这么走运。','805-859',640,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',5,'前言','生病让人恐慌不安，我也尝够了生病的苦。但是知道我的免疫细胞——我这不可或缺的一部分——正守卫着“我”这个存在，知道它们冲锋陷阵、英勇牺牲、疗愈并重建我所栖居的身体，总是会带给我极大的安慰。','2443-2537',637,1782613085);
INSERT INTO popular_highlights VALUES('3300037073',47,'42 如何强化免疫系统','你可能已经明白我的意思了：强化免疫系统不是好主意，都是那些骗你买没用东西的人想出来的！','986-1060',630,1782613085);
INSERT INTO popular_highlights VALUES('3300039741',3,'序言','如果没有见识过炮弹从头顶上飞过，你就不能说自己亲历了战争。我想这些道理也同样适用于金融危机。就在这一刻，我开始领悟到我访谈过的那些成功的基金经理所强调的自律的重要性。','2141-2224',36,1782613097);
