INSERT INTO popular_highlights VALUES('3300039741',25,'3.3　如何回测检验投资策略','例如，如果黄金价格超过过去20天内的最高值（即商品交易顾问（CTA）和管理期货基金经理所称的突破），就买入黄金期货。持有这个仓位，直到黄金价格跌破其10天内的最低值。','2242-2325',30,1782613097);
