INSERT INTO popular_highlights VALUES('3300039741',22,'第3章　开发和回测交易策略：在高效的无效市场中获利','你需要知道你的交易对手是谁，他为什么和你交易。如果你经常赚得多、亏得少，那么是什么促使你的交易对手来和你交易？今后他们还将继续这样做吗？要记住，有买家就有卖家，所以你的交易总有对手方。','761-853',22,1782613097);
