INSERT INTO popular_highlights VALUES('27256052',81,'世界的本质：混乱和秩序','你需要一边依赖已知和已掌握的事物，一边探索和学习新的东西。这样你既可以平衡对未知的恐惧，同时又能保持兴奋和投入的状态。如此一来，你便可以掌握新的，提升旧的，并且发现意义所在。','11356-11443',6266,1782613100);
