INSERT INTO popular_highlights VALUES('27256052',72,'推荐序 最重要的法则：为自己的人生负责','最重要的法则是你必须为自己的人生负责，就这么简单。','8968-8993',3201,1782613100);
INSERT INTO popular_highlights VALUES('27256052',140,'法则二 像照顾生病的宠物一样关心自己：待己如助人','待己如助人， 这意味着你需要选择 对自己真正有好处的事物， 即使这些事物不一定是你想要的 或是令你快乐的。','1314-1583',3066,1782613100);
INSERT INTO popular_highlights VALUES('27256052',78,'建立你的自我觉察','金钱会因为你的无知而变得无用，对于不熟悉金钱的人来说，要正确地使用它是很难的。','4682-4721',3030,1782613100);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','一个人预测和应对未来的能力，取决于他对事物变化背后的因果关系的理解；一个人理解这些因果关系的能力，来自他对以往变化的发生机制的研究。','4568-4648',12597,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','未来的时代将与我们有生之年所经历的时代完全不同，但与历史上的许多时代有着相似之处。','390-431',3984,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','人类本性不会随着时间的推移而发生太大变化。例如，恐惧、贪婪、嫉妒和其他基本情感始终没有改变，它们是驱动周期发展的重要因素。','3226-3287',3201,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','尽管如此，从我的经验来看，如果等到学至自己很满意的程度才肯采取行动或进行分享，我就永远无法运用和传述所学到的东西。','13234-13291',3096,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','没有任何一个政治体制、经济体系、货币或帝国可以永远存在。但当它们失灵时，几乎所有人都会感到惊讶，并受到毁灭性打击。','3908-3965',3075,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','只要大多数人的生活水平仍在提高，这些分歧和怨恨就不会酿成冲突。','20575-20606',2955,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','在一个周期中，从一个极端到另一个极端的变化是常态，而不是例外。','2880-2925',2827,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','萧条、革命与战争时期造成大量破坏，但就像净化风暴一样，它也清除了弱点和过度（如过度债务），以回归本质的方式，打造更坚固的基础，迎来新的开端（尽管这个过程很痛苦）。','2377-2458',2544,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','拥有大量储蓄、低债务和强大储备货币的国家能更好地抵御经济和信贷崩溃；储蓄少、大量负债，没有强大储备货币的国家抵御能力则较弱。','7871-7933',2448,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','朝着一个方向的走势中，潜藏着导致反向走势的要素。','3118-3142',2360,1782613112);
INSERT INTO popular_highlights VALUES('42689053',34,'2 决定因素','虽然许多国家都可以利用自己的自然资源，但人力资本是最可持续的资本，因为继承下来的资产最终会消失，而人力资本可以永远存在。','10178-10238',2310,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','我也发现古往今来，所有国家的财富拥有者都具备创造财富的手段。为了维持和增加财富，他们与政权掌控者合作，一起建立共生关系，制定和执行规则。我看到类似的情况发生在不同国家和不同时期。','1461-1550',2220,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','要想把握全局，就不能着眼于细节。','11420-11450',2208,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','进化是走向进步的上行轨迹，而进步源于适应和学习。周期围绕着上行轨迹而反复出现。在我看来，大多数事物是沿着一条具有周期性的上行轨迹发生的。这条轨迹就像一个上行的螺丝锥：','4016-4099',2208,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','随着领先大国的人民变得更富有，他们往往不会像以前那样努力工作，而更享受悠闲生活，追求生活中更精美但经济效益较低的东西，在极端的情况下，人们会变得颓废。','19969-20044',2198,1782613112);
INSERT INTO popular_highlights VALUES('42689053',31,'引言','就像许多事物一样，在人的一生中，重大的繁荣时期和重大的萧条时期只会出现一次，除非我们研究几代人的历史模式，否则很难预料到这些时期的到来。','3097-3179',2128,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','一个国家的财富和权力与国民的幸福几乎没有关联','14552-14574',2096,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','很小部分的人获得并控制了大部分财富和权力，之后国家变得过度扩张，陷入困难时期，使最贫困且最没权势的群体遭受最大的重创，进而引发冲突，酿成革命和/或内战。冲突结束后，新的秩序建立，新的周期重新开启。','1778-1876',2074,1782613112);
INSERT INTO popular_highlights VALUES('42689053',45,'12 中国和人民币的大周期兴起','广泛的媒体扭曲以及盲目和近乎暴力的忠诚，阻碍了我们深入思考不同观点，这是我们这个时代的一个可怕病症。','1962-2012',2000,1782613112);
INSERT INTO popular_highlights VALUES('42689053',33,'1 大周期简述','新的斗争随之而来，这些斗争围绕着谁能获得数据，以及如何利用这些数据获取财富和权力。','7027-7068',1980,1782613112);
INSERT INTO popular_highlights VALUES('907574',4,'引言 全国性饮食失调','我们吃下去的东西以及吃东西的方式，都会决定我们成为怎样的人。','4398-4428',390,1782613114);
INSERT INTO popular_highlights VALUES('907574',3,'推荐序 饭桌的宽度','拿中国的饭局文化举例，从古至今，这哪是一桌子的菜，这明明就是一桌子的人情世故，你来我往。房内人话天下事，由眼前美食引发心中感悟，一顿饭下来，吃没吃饱没关系，重要的是食者的关系。','434-522',357,1782613114);
INSERT INTO popular_highlights VALUES('907574',7,'02 农场：一个农民养活129个人','基本上，现代杂交改良玉米能够忍受玉米的“都市化生活”，和众多同类一起生长，而不会被拥挤的生长环境压垮。','5398-5449',285,1782613114);
INSERT INTO popular_highlights VALUES('907574',5,'第一部分 产业化的玉米','地球上万物的故事，从最基本的角度来看，就是物种间收集与储存能量的竞争。植物间彼此竞逐阳光，动物之间则争夺其他植物或动物身上所含有的能量。','5751-5819',238,1782613114);
INSERT INTO popular_highlights VALUES('907574',5,'第一部分 产业化的玉米','事实上，我们有很好的理由认为是玉米成功驯化了人类。','7272-7297',204,1782613114);
INSERT INTO popular_highlights VALUES('907574',3,'推荐序 饭桌的宽度','“今天去哪儿吃，吃什么”一定是一个哲学问题，我没有开玩笑。','928-957',192,1782613114);
INSERT INTO popular_highlights VALUES('907574',4,'引言 全国性饮食失调','由于缺乏坚实的饮食文化，我们非常容易受到食品科学家与商人的诱骗。对这些人而言，杂食者的两难反而是个机会。食品工业为了自身利益，先以各种方式加深消费者对于吃的焦虑，然后再塞给我们新产品来化解这种焦虑。','3258-3357',182,1782613114);
INSERT INTO popular_highlights VALUES('907574',4,'引言 全国性饮食失调','许多人类学家坚信，人类会演化出如此大而精密的脑，就是为了解决杂食者的两难问题。','2514-2553',169,1782613114);
INSERT INTO popular_highlights VALUES('907574',5,'第一部分 产业化的玉米','对于培育者而言，杂交玉米等于提供了一项史无前例的特质：生物学上的专利。现在农民每年春天都必须购买新种子，而无法从自己的作物生产种子，因此不得不依赖商业机构。','13731-13809',169,1782613114);
INSERT INTO popular_highlights VALUES('907574',24,'17 吃动物合乎道德吗？','人类、猪以及其他有感觉的动物，都共享一项非常重要的权益：免于痛苦。','3391-3424',162,1782613114);
INSERT INTO popular_highlights VALUES('907574',5,'第一部分 产业化的玉米','这就是美国人：会走路的加工玉米。','6978-6994',160,1782613114);
INSERT INTO popular_highlights VALUES('907574',8,'03 大谷仓：粮食玉米和原材料玉米','把牛纳入这条产业链特别费力，因为牛并不是天生就吃玉米。但是自然憎恶任何过剩，因此牛必须吃玉米。','6074-6121',154,1782613114);
INSERT INTO popular_highlights VALUES('907574',24,'17 吃动物合乎道德吗？','对任何动物而言，所谓幸福，就是有机会展现自己的动物天性：猪过得像猪、狼过得像狼、鸡过得像鸡。','13043-13089',154,1782613114);
INSERT INTO popular_highlights VALUES('907574',9,'04 饲养场：制造肉类','梅钦医生为它的体型及体态而向我恭喜：“你在这里有一块漂亮的牛肉。”（我呸！）','13132-13170',153,1782613114);
INSERT INTO popular_highlights VALUES('907574',9,'04 饲养场：制造肉类','像是液化脂肪（今天的原料是从附近屠宰场运来的牛油）和蛋白质补充物（褐色的黏稠物，含有糖浆和尿素）','8172-8220',144,1782613114);
INSERT INTO popular_highlights VALUES('907574',15,'09 大型有机：超市中的田园诗','一旦科学把某个现象简化成一些变量，不论这些变量有多么重要，人类都会把变量以外的事情忽略掉，然后假定所有要纳入考虑（或至少是重要的）的东西都在这些变量中。','11716-11792',144,1782613114);
INSERT INTO popular_highlights VALUES('907574',7,'02 农场：一个农民养活129个人','政府现在做的，不是维持玉米价格，而是补贴玉米的差价。如此一来，美国农民就拼命去种玉米了。','17659-17703',143,1782613114);
INSERT INTO popular_highlights VALUES('907574',5,'第一部分 产业化的玉米','墨西哥人的身体就像是玉米的另一种生命形式。','4378-4399',140,1782613114);
INSERT INTO popular_highlights VALUES('907574',4,'引言 全国性饮食失调','而现在，全民畏惧的对象改为碳水化合物，此症状如同痉挛发作，席卷全国。','795-829',136,1782613114);
INSERT INTO popular_highlights VALUES('907574',4,'引言 全国性饮食失调','一种文化若有根深蒂固的饮食传统，不但不会出现这种现象，也无须劳驾国会来说明国家的“饮食方针”；甚至不需要每隔几年就发动一次政治战争，只为了制定出“营养金字塔”这种官方的详细饮食设计方案。','1338-1431',136,1782613114);
INSERT INTO popular_highlights VALUES('3300095033',3,'文前','企鹅不会飞，你发什么火呢？','396-409',285,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','关心他人并不意味着要一脸微笑和善，只说对方想听的话，而是需要你给出不那么容易被接受的反馈，帮助对方成长。','3586-3638',105,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','你是否也曾在冲突结束几小时后才想到完美的应对方法？之所以会这样，是因为你的前额叶皮质在暴怒状态之下停止了运转，而一旦它重新上线，你就能够对冲突加以分析并运用创造力想出解决方案了。','8471-8560',105,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','他真诚地看着梅根说：“对不起，是我的错。我要向你的团队成员道歉，我不该还没跟你商量就把他从项目里拽出来，我还要告诉他，如果下次我再犯这种错误，他可以随时问我有没有征得你的同意','2797-2884',102,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','人们只说他们觉得别人想听的话。这种心态剥夺了我们纠正错误、改善行为和发挥自己最大潜能的机会。','3309-3355',90,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','别往心里去，也别以为你能说服这种人改变。越早消除对米尔顿的期望和其本性之间的差距，我们就能越早消除冲突。','2547-2599',90,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','接受：“他就是这样一个人，在这种情况下是没法儿改变的。要想让事态有所改变，全都要靠我，我必须得成为那个先做点儿什么的人。”','7555-7616',85,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',30,'第二章 霸凌陷阱','但路易斯表示，当你和另一名司机之间隔着两块玻璃和一些距离的时候，嘴巴就突然没有把门的了。','9087-9131',72,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',33,'第五章 评判陷阱','下次听到别人对你评判时，请克制住为自己辩护的本能。相反，努力去理解别人为什么会对你如此评价，你可能会意识到自己犯了错，从而纠正自己的行为。','5986-6055',72,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',34,'第六章 学会倾听','对抗确认偏误的一个好方法是接受这样一种心态：对于任何问题，你的观点中都存在你没有留意到的瑕疵，而与你相反的观点中也存在你还没有意识到的合理性。','4714-4785',72,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',35,'第七章 企鹅不会飞，你发什么火呢？','当你与某人重复陷入恶性冲突的模式时，最好假设这个人并不是有意与你针锋相对的。这个世界没有故意与你作对，不要允许自己这样看待世界了。','8299-8364',72,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','我发现，团队成员之间的冲突越多，公司的发展速度就越快','627-653',70,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',33,'第五章 评判陷阱','所以在评价某人时，我们可以使用不带指责的语言进行交流，不把评判之心传达给对方。一种有效的方法就是专注于描述而不是评价。','7777-7836',68,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',4,'序言','当然，并非所有冲突都是有益的。除了有益的冲突，也存在有害的冲突。','974-1006',64,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','评判和自尊也是冲突中两大主要的毒素，在这两个问题上，社会也向我们传输着自相矛盾的理念。','9929-9972',64,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','在同一时间，还有一些人会漫不经心地看着这只剑齿虎，心想：管它呢。这些漫不经心的人不是我们的祖先，官方科学术语应该称这些人为“午餐”，他们活得不够长，无法将自己脆弱的杏仁核基因遗传给后代','8885-8977',60,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',31,'第三章 必胜陷阱','如果能在现实的冲突中熟练地提出这些问题，你就能把对方的自尊视为可以利用的资源并为己所用。','11948-11992',56,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',29,'第一章 冲突，是拥抱还是抗拒','坦然接受冲突，不过度情绪化或强加指责，这种做法不仅对律师和科学家有利，也可以惠及所有人生活的方方面面','15589-15639',54,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',30,'第二章 霸凌陷阱','他虽然不愿表现得像个霸凌者一样，但他可能会通过贬低、威胁或责骂来发泄自己的沮丧之情。这种行为是缺乏领导力的标志，然而遗憾的是，这种行为在商界十分常见。','3416-3491',54,1782613116);
INSERT INTO popular_highlights VALUES('3300095033',30,'第二章 霸凌陷阱','如果情况可以稍缓一缓，那就最好睡一觉，让怒气散去再去解决问题。','13218-13249',54,1782613116);
INSERT INTO popular_highlights VALUES('3300046899',106,'前言 过好生活的基本功','请赐给我雅量，平静接受不可改变的事；赐给我勇气，去改变应该改变的事；并赐给我智慧，去分辨什么是可以改变的、什么是不可改变的事。','2549-2612',3162,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',110,'4 小善意，大帮助','余华说：“没有什么比活着更快乐，也没有什么比活着更艰辛。”','867-896',2214,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',126,'20 你有什么缺点？','所有长久的关系中，唯有真诚才是最短的路。','1091-1111',1872,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',107,'第一章 自主','主动不是莽撞啊，在我的理解中，主动思考、主动行动、主动复盘、主动解决问题，这才是真主动。','1424-1468',1729,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',113,'7 世俗的成功给人自由','叔本华说：“财富和地位，可以保护智者免受小人的伤害。”','1525-1552',1674,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',177,'第八章 自愈','那段经历让我明白，如果想获得温暖，就去找一个天性温暖的人，不要试图捂热一块冰；如果想收获爱，就去找一个内心有爱的人，不要试图在一颗冷漠的心里，培育出爱。','1168-1244',1584,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',181,'75 付出越多，越难被爱','人最底线的爱，是自爱；只要你依然爱着自己，世界上就不会缺少爱你的人。','1368-1402',1568,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',147,'第五章 自洽','请你相信，假如某人看上去可以很轻松地胜任一件事，那一定是因为ta之前付出了很多努力，只是没有被别人看到而已。','1772-1826',1548,1782613117);
INSERT INTO popular_highlights VALUES('3300046899',108,'2 与其“被喜欢”，不如“被需要”','与其“被喜欢”，不如“被需要”“被尊重”“被信任”。','947-973',1420,1782613117);
