INSERT INTO popular_highlights VALUES('3300046899',160,'54 健康人际关系的6个特点','稻盛和夫说：“学会用离开的方式善待自己。离开某些人不是因为他们不好，而是因为跟他们在一起，我的状态不好。如果对方很容易激发我的脆弱、焦虑和不安，而我又无法改变，离开才是最好的选择。”','2213-2304',1365,1782613117);
