INSERT INTO popular_highlights VALUES('3300046899',119,'13 被生活逼急了','从容不仅是心态和礼貌，更需要物质条件的宽裕。假如那些不从容的人，并未对我们的生活造成任何实质伤害，假如那些板着脸的人，确实是来不及微笑，那我愿意先对ta们笑。','1465-1544',1183,1782613117);
