INSERT INTO popular_highlights VALUES('35138325',26,'带团队的四条铁律','带团队的四条铁律：“勤”字为先；该放手的时候放手；维持好势能，不要让团队势穷力竭；最后不仅用钱激励团队，还要讲理想、讲精神。','4418-4480',2992,1782613119);
INSERT INTO popular_highlights VALUES('35138325',14,'真正的高手都有破局思维','所以要处理两个误区：一、多数我们不舒服的时候是逆境而不是绝境。二、过分夸大逆境，太被动，对于成事的修行者是不对的。天会留机会给人，当大家都恐慌的时候，你应该想，在这种状态下，我能有什么样的机会。','1285-1382',2954,1782613119);
